# ===========================================================================
# MANIFEST SYNC - keeps fal_prompt_manifest.xlsx in sync with shot_plan.json
# Auto-called after every shot edit via UI or API
# ===========================================================================
def sync_manifest_to_xlsx(project_path):
    try:
        import openpyxl
        from openpyxl.styles import Font, PatternFill, Alignment
        import json as _j, hashlib as _h
        sp = _sp_guard(_j.load(open(project_path / 'shot_plan.json')))
        shots = sp.get('shots', [])
        COLS = ['scene_id','shot_id','chain_id','is_chain_first','nano_mode',
                'characters_present','character_reference_url','wardrobe_tags',
                'nano_prompt','delta_prompt_nano','negative_prompt','ltx_prompt',
                'delta_prompt_ltx','duration_s','fps','resolution',
                'composition_hash','actor_intent','coverage_role','shot_type',
                'first_frame_path','video_path']
        wb = openpyxl.Workbook(); ws = wb.active; ws.title = 'Shots'
        hf = PatternFill('solid', start_color='BDD7EE')
        for ci,col in enumerate(COLS,1):
            c = ws.cell(row=1,column=ci,value=col)
            c.font = Font(bold=True,name='Arial',size=10); c.fill = hf
            c.alignment = Alignment(horizontal='center')
        for ri,s in enumerate(shots,2):
            chars = ', '.join(s.get('characters',[])) or '(no characters)'
            w = s.get('wardrobe',s.get('wardrobe_tags',''))
            if isinstance(w,list): w = ', '.join(w)
            dur = s.get('duration') or s.get('duration_seconds') or 10
            nano = s.get('nano_prompt','')
            sid = s.get('shot_id','')
            row = [s.get('scene_id',''),sid,s.get('chain_id'),s.get('is_chain_first'),
                   s.get('nano_mode','text2img'),chars,s.get('character_reference_url'),
                   w or None,nano,s.get('delta_prompt_nano'),s.get('negative_prompt'),
                   s.get('ltx_motion_prompt',''),s.get('delta_prompt_ltx'),
                   dur,s.get('fps',24),s.get('resolution','768x512'),
                   _h.md5(nano.encode()).hexdigest()[:12],s.get('actor_intent'),
                   s.get('coverage_role',''),s.get('type',s.get('shot_type','')),
                   'first_frames/'+sid+'.jpg','videos/'+sid+'.mp4']
            for ci,v in enumerate(row,1):
                ws.cell(row=ri,column=ci,value=v).font = Font(name='Arial',size=9)
        cw = {'nano_prompt':60,'ltx_prompt':60,'shot_id':14,'scene_id':10,
              'characters_present':25,'wardrobe_tags':30,'coverage_role':18}
        for ci,col in enumerate(COLS,1):
            ws.column_dimensions[openpyxl.utils.get_column_letter(ci)].width = cw.get(col,15)
        ws.freeze_panes = 'A2'
        out = project_path / 'fal_prompt_manifest.xlsx'
        wb.save(str(out))
        logger.info(f'[MANIFEST SYNC] {len(shots)} shots -> {out}')
        return True
    except Exception as e:
        logger.warning(f'[MANIFEST SYNC] Failed: {e}')
        return False



