import fal_client

# V18.2: NON-BLOCKING FAL WRAPPER — prevents fal_client.run() from starving the event loop
# Monkey-patches fal_client.run to use a thread pool with GIL-releasing polling
_fal_original_run = fal_client.run
_fal_thread_pool = None

def _fal_nonblocking_run(model_id, *, arguments=None, **kwargs):
    """Drop-in replacement for fal_client.run that releases the GIL during HTTP waits.
    V21.10 FIX: Added 300s timeout + exception handling to prevent server hangs/crashes.
    V26: Added pre-FAL payload audit — logs EXACTLY what reaches FAL for post-run analysis."""
    import time as _t
    from concurrent.futures import ThreadPoolExecutor, TimeoutError as FuturesTimeout
    global _fal_thread_pool
    if _fal_thread_pool is None:
        _fal_thread_pool = ThreadPoolExecutor(max_workers=6, thread_name_prefix="fal_nb")

    # V26: PRE-FAL PAYLOAD AUDIT — captures what actually goes to FAL
    try:
        _audit_dir = os.path.join(os.path.dirname(os.path.abspath(__file__)), "reports")
        os.makedirs(_audit_dir, exist_ok=True)
        _audit_file = os.path.join(_audit_dir, "fal_payload_audit.jsonl")
        _audit_entry = {
            "timestamp": __import__("datetime").datetime.utcnow().isoformat(),
            "model": model_id,
            "prompt": (arguments or {}).get("prompt", "")[:500],
            "prompt_length": len((arguments or {}).get("prompt", "")),
            "image_urls_count": len((arguments or {}).get("image_urls", [])),
            "resolution": (arguments or {}).get("resolution", ""),
            "has_locked_flag": "_prompt_locked" in str(arguments),
        }
        with open(_audit_file, "a") as _af:
            _af.write(json.dumps(_audit_entry) + "\n")
    except Exception:
        pass  # Audit is non-blocking

    # Capture current FAL_KEY so the worker thread uses the same one
    _current_key = os.environ.get("FAL_KEY", "")
    _FAL_TIMEOUT = 600 if "kling" in model_id else 300  # Kling V3 Pro + elements needs up to 10min

    def _worker():
        os.environ["FAL_KEY"] = _current_key
        return _fal_original_run(model_id, arguments=arguments, **kwargs)

    future = _fal_thread_pool.submit(_worker)
    # Poll with GIL releases — allows uvicorn event loop to serve requests
    _elapsed = 0.0
    while not future.done():
        _t.sleep(0.05)  # 50ms yield — responsive enough for UI polling
        _elapsed += 0.05
        if _elapsed > _FAL_TIMEOUT:
            future.cancel()
            raise TimeoutError(f"FAL API call to {model_id} timed out after {_FAL_TIMEOUT}s")
    try:
        return future.result(timeout=10)
    except FuturesTimeout:
        raise TimeoutError(f"FAL API result retrieval for {model_id} timed out")
    except Exception as _fal_err:
        logger.error(f"[FAL-NB] {model_id} error: {_fal_err}")
        raise

# Also wrap fal_client.subscribe for non-blocking behavior
_fal_original_subscribe = getattr(fal_client, 'subscribe', None)

def _fal_nonblocking_subscribe(model_id, *, arguments=None, **kwargs):
    """Drop-in replacement for fal_client.subscribe that releases the GIL.
    V21.10 FIX: Added 300s timeout + exception handling."""
    import time as _t
    from concurrent.futures import ThreadPoolExecutor, TimeoutError as FuturesTimeout
    global _fal_thread_pool
    if _fal_thread_pool is None:
        _fal_thread_pool = ThreadPoolExecutor(max_workers=6, thread_name_prefix="fal_nb")
    _current_key = os.environ.get("FAL_KEY", "")
    _FAL_TIMEOUT = 600 if "kling" in model_id else 300  # Kling V3 Pro + elements needs more time

    def _worker():
        os.environ["FAL_KEY"] = _current_key
        return _fal_original_subscribe(model_id, arguments=arguments, **kwargs)

    future = _fal_thread_pool.submit(_worker)
    _elapsed = 0.0
    while not future.done():
        _t.sleep(0.05)
        _elapsed += 0.05
        if _elapsed > _FAL_TIMEOUT:
            future.cancel()
            raise TimeoutError(f"FAL subscribe to {model_id} timed out after {_FAL_TIMEOUT}s")
    try:
        return future.result(timeout=10)
    except FuturesTimeout:
        raise TimeoutError(f"FAL subscribe result for {model_id} timed out")
    except Exception as _fal_err:
        logger.error(f"[FAL-NB-SUB] {model_id} error: {_fal_err}")
        raise

# Apply monkey-patches globally — ALL fal_client calls become non-blocking
fal_client.run = _fal_nonblocking_run
if _fal_original_subscribe:
    fal_client.subscribe = _fal_nonblocking_subscribe

