# Golden log markers for debugging (grep these in logs)
LOG_MARKERS = {
    "MEDIA": "[MEDIA]",
    "AUTO_CAST": "[AUTO_CAST]",
    "FIRST_FRAME": "[FIRST_FRAME]",
    "VIDEO_RENDER": "[VIDEO_RENDER]",
    "STITCH": "[STITCH]",
    "REHYDRATE": "[REHYDRATE]",
    "VALIDATION": "[VALIDATION]",
}

def log_marker(marker: str, msg: str, level: str = "info"):
    """Structured logging with golden markers for grep."""
    prefix = LOG_MARKERS.get(marker, f"[{marker}]")
    full_msg = f"{prefix} {msg}"
    if level == "error":
        logger.error(full_msg)
    elif level == "warning":
        logger.warning(full_msg)
    else:
        logger.info(full_msg)

def validate_generation_request(project: str, shot: dict, stage: str) -> tuple:
    """
    Defensive validation before FAL API calls.
    Returns (is_valid: bool, error_msg: str)
    """
    if not project:
        return False, "Project name is required"

    project_path = Path(__file__).resolve().parent / "pipeline_outputs" / project
    if not project_path.exists():
        return False, f"Project directory does not exist: {project_path}"

    shot_plan = project_path / "shot_plan.json"
    if not shot_plan.exists():
        return False, f"shot_plan.json not found for project: {project}"

    if stage == "first_frame":
        if not shot.get("nano_prompt"):
            return False, f"Shot {shot.get('shot_id')} missing nano_prompt"

    elif stage == "video":
        shot_id = shot.get("shot_id", "unknown")
        first_frame_path = project_path / "first_frames" / f"{shot_id}.jpg"
        if not first_frame_path.exists():
            return False, f"First frame missing for {shot_id}: {first_frame_path}"
        if not shot.get("ltx_motion_prompt") and not shot.get("nano_prompt"):
            return False, f"Shot {shot_id} missing motion prompt"

    return True, ""

