# V18.2: In-memory dirty set as fallback when filesystem dirty flag fails (e.g., mounted FS permission issues)
_BUNDLE_DIRTY_MEMORY = set()

# ═══════════════════════════════════════════════════════════════
# V18.4: PROJECT FILE CACHE — Prevents loading same JSON 7-9 times per request
# TTL-based cache for story_bible, shot_plan, cast_map per project.
# Saves 50-100MB per generation by deduplicating reads.
# ═══════════════════════════════════════════════════════════════
import time as _time_module
_PROJECT_FILE_CACHE = {}  # {project: {filename: (data, mtime, cached_at)}}
_FILE_CACHE_TTL = 30      # seconds — short TTL so edits are picked up quickly
_FILE_CACHE_MAX_PROJECTS = 10  # max projects cached at once

def _cached_json_load(project_path, filename):
    """V18.4: Load a JSON file with TTL cache. Returns parsed dict/list.
    Cache is invalidated if file mtime changes OR TTL expires.
    Prevents the same file from being loaded 7-9 times in a single request."""
    project_name = project_path.name if hasattr(project_path, 'name') else str(project_path).split('/')[-1]
    filepath = Path(project_path) / filename
    now = _time_module.time()

    if project_name in _PROJECT_FILE_CACHE:
        entry = _PROJECT_FILE_CACHE[project_name].get(filename)
        if entry:
            data, cached_mtime, cached_at = entry
            # Check TTL
            if (now - cached_at) < _FILE_CACHE_TTL:
                # Check mtime hasn't changed
                try:
                    current_mtime = filepath.stat().st_mtime
                    if current_mtime == cached_mtime:
                        return data
                except Exception:
                    pass

    # Load fresh
    try:
        with open(filepath) as f:
            data = json.load(f)
        mtime = filepath.stat().st_mtime

        # Evict oldest project if at capacity
        if project_name not in _PROJECT_FILE_CACHE and len(_PROJECT_FILE_CACHE) >= _FILE_CACHE_MAX_PROJECTS:
            oldest = min(_PROJECT_FILE_CACHE.keys(),
                        key=lambda p: min(e[2] for e in _PROJECT_FILE_CACHE[p].values()) if _PROJECT_FILE_CACHE[p] else 0)
            del _PROJECT_FILE_CACHE[oldest]

        if project_name not in _PROJECT_FILE_CACHE:
            _PROJECT_FILE_CACHE[project_name] = {}
        _PROJECT_FILE_CACHE[project_name][filename] = (data, mtime, now)
        return data
    except Exception:
        return None

def _invalidate_file_cache(project_name, filename=None):
    """V18.4: Clear file cache for a project (all files or specific file)."""
    if project_name in _PROJECT_FILE_CACHE:
        if filename:
            _PROJECT_FILE_CACHE[project_name].pop(filename, None)
        else:
            del _PROJECT_FILE_CACHE[project_name]

def _invalidate_bundle_cache(project_name: str):
    """V17.7.4: Invalidate UI bundle cache for a project by touching the dirty flag.
    V18.2: Also sets in-memory dirty flag as fallback when filesystem fails.
    V18.4: Also clears in-memory bundle cache."""
    _BUNDLE_DIRTY_MEMORY.add(project_name)
    _BUNDLE_MEMORY_CACHE.pop(project_name, None)  # V18.4: Clear memory cache
    _invalidate_file_cache(project_name)           # V18.4: Clear file cache
    try:
        cache_dir = PIPELINE_OUTPUTS_DIR / project_name / "ui_cache"
        cache_dir.mkdir(parents=True, exist_ok=True)
        (cache_dir / "bundle.dirty").touch()
    except Exception as e:
        logger.warning(f"[CACHE] Filesystem dirty flag failed for {project_name}: {e} — using in-memory fallback")


def _sp_guard(shot_plan) -> dict:
    """T2-OR-18: shot_plan.json may be a bare list. Normalize to {"shots": [...]} always."""
    if isinstance(shot_plan, list):
        return {"shots": shot_plan}
    return shot_plan if isinstance(shot_plan, dict) else {"shots": []}


def _media_url(path_obj) -> str:
    """V17.7.5: Generate /api/media URL with RELATIVE path (never absolute).
    Prevents stale /Users/quantum/... paths from leaking into bundles."""
    p = Path(path_obj) if not isinstance(path_obj, Path) else path_obj
    try:
        rel = str(p.relative_to(BASE_DIR))
    except ValueError:
        # If path isn't under BASE_DIR, try stripping common prefixes
        s = str(p)
        marker = "ATLAS_CONTROL_SYSTEM/"
        idx = s.find(marker)
        if idx >= 0:
            rel = s[idx + len(marker):]
        else:
            rel = s
    return f"/api/media?path={rel}"


# =============================================================================
# V17.6 FIELD REGISTRY — Single source of truth for field names
# =============================================================================
# Problem: The same concept uses different field names across the codebase.
# Example: character reference URL stored as reference_url, character_reference_url,
#          locked_reference_url, or headshot_url depending on which code wrote it.
# Solution: Registry defines canonical names; normalization functions standardize data.

FIELD_REGISTRY = {
    "character_reference_url": {
        "canonical": "character_reference_url",
        "aliases": ["reference_url", "locked_reference_url"],
    },
    "characters_lock": {
        "canonical": "characters",
        "aliases": ["characters_locked", "_casting_finalized"],
    },
    "locations_lock": {
        "canonical": "locations",
        "aliases": ["locations_locked"],
    },
    "casting_lock": {
        "canonical": "casting",
        "aliases": ["casting_locked"],
    },
}

def normalize_cast_entry(entry: dict) -> dict:
    """
    Normalize a cast_map entry to use ONLY canonical field names.
    Converts reference_url → character_reference_url, etc.
    """
    if not isinstance(entry, dict):
        return entry
    normalized = {}
    for key, value in entry.items():
        # Check if this key is an alias for a canonical field
        canonical_key = key
        for field_config in FIELD_REGISTRY.values():
            if key in field_config["aliases"]:
                canonical_key = field_config["canonical"]
                break
        # Keep first non-empty value for canonical key
        if canonical_key in normalized:
            if not normalized[canonical_key] and value:
                normalized[canonical_key] = value
        else:
            normalized[canonical_key] = value
    # Ensure critical fields have defaults
    normalized.setdefault("character_reference_url", "")
    normalized.setdefault("fit_score", 0)
    normalized.setdefault("is_extras_pool", False)
    return normalized

def normalize_locks(locks_data: dict) -> dict:
    """
    Normalize master_locks.json to canonical lock field names.
    Reads both old (characters_locked) and new (characters) formats.
    """
    if not isinstance(locks_data, dict):
        return {"characters": False, "locations": False, "casting": False}
    return {
        "characters": bool(locks_data.get("characters") or locks_data.get("characters_locked")),
        "locations": bool(locks_data.get("locations") or locks_data.get("locations_locked")),
        "casting": bool(locks_data.get("casting") or locks_data.get("casting_locked")),
    }

# =============================================================================
# V17.6 SCORED NAME MATCHING — Replaces ALL loose .includes() / "in" checks
# =============================================================================
# Problem: Substring matching causes false positives.
#   "OFFICE" matches both "LAW OFFICE" and "CITY APARTMENT" (if office appears anywhere)
#   "ARRI" matches both "ARRI Alexa 35" and "ARRI Mini LF"
# Solution: Scored matching with thresholds. Each match gets a 0-100 score.

def _normalize_name(s: str) -> str:
    """Normalize name for comparison: strip, lowercase, collapse spaces."""
    if not isinstance(s, str):
        return ""
    return " ".join(s.lower().split())

def score_name_match(a: str, b: str, threshold: int = 65) -> Tuple[int, bool]:
    """
    Score how well name 'a' matches name 'b'. Returns (score, passes_threshold).

    Scoring:
      exact=100, long_substring(8+)=50+len, word_overlap=30+15*count, short_sub=40
    """
    na, nb = _normalize_name(a), _normalize_name(b)
    if not na or not nb:
        return 0, False
    # Exact
    if na == nb:
        return 100, True
    # Compute max score across all strategies (don't early-return — overlapping rules)
    best = 0
    # Long substring (8+ chars)
    if len(na) >= 8 and na in nb:
        best = max(best, min(100, 50 + len(na)))
    if len(nb) >= 8 and nb in na:
        best = max(best, min(100, 50 + len(nb)))
    # Word overlap — coverage-aware
    wa, wb = set(na.split()), set(nb.split())
    overlap = len(wa & wb)
    if overlap > 0:
        shorter = min(len(wa), len(wb))
        coverage = overlap / shorter  # 1.0 = all words of shorter name found in longer
        if coverage >= 1.0 and shorter >= 2:
            # Multi-word full coverage: strong match (90+ for 2 words)
            best = max(best, min(100, 70 + overlap * 10))
        elif coverage >= 1.0 and shorter == 1:
            # Single-word full coverage: gated by word length to prevent generic matches
            word = list(wa & wb)[0]
            if len(word) >= 5:
                best = max(best, 65 + (len(word) - 5) * 3)  # 5-char=65, 6-char=68, 7-char=71
            else:
                best = max(best, 40)  # Short single words (ARRI, etc) = low confidence
        else:
            best = max(best, min(100, 30 + overlap * 15))
    # Short substring (4-7 chars) — low confidence
    if 4 <= len(na) <= 7 and na in nb:
        best = max(best, 40)
    if 4 <= len(nb) <= 7 and nb in na:
        best = max(best, 40)
    return best, best >= threshold

def find_best_name_match(name: str, candidates: list, min_score: int = 65) -> Optional[str]:
    """Find the best matching name from candidates list. Returns None if no match >= min_score."""
    best, best_score = None, 0
    for c in candidates:
        score, _ = score_name_match(name, c, min_score)
        if score > best_score:
            best, best_score = c, score
    return best if best_score >= min_score else None

def find_character_match(name: str, cast_map: dict, min_score: int = 65) -> Optional[str]:
    """
    Find the best matching character key in cast_map.
    V21.9.1 UNIVERSAL: Checks _character_aliases FIRST (exact match, O(1)),
    then falls back to fuzzy scoring. Prevents surname-stripping edge cases
    like CLARA BYRNE → CLARA being missed.
    """
    if not name or not cast_map:
        return None
    name_upper = name.upper().strip()
    # ── STEP 1: Exact match on cast_map keys ──
    if name_upper in cast_map:
        return name_upper
    # ── STEP 2: Check _character_aliases (deterministic, no fuzzy) ──
    aliases = cast_map.get("_character_aliases", {})
    if isinstance(aliases, dict):
        for alias_key, canonical_val in aliases.items():
            if name_upper == alias_key.upper().strip():
                # Alias found — return the canonical cast_map key
                canonical_upper = canonical_val.upper().strip()
                if canonical_upper in cast_map:
                    return canonical_upper
                # Try case-insensitive fallback on cast_map keys
                for k in cast_map:
                    if isinstance(k, str) and k.upper().strip() == canonical_upper:
                        return k
    # ── STEP 3: Fuzzy matching (existing logic, unchanged) ──
    return find_best_name_match(name, [k for k in cast_map.keys() if not k.startswith("_")], min_score)

def find_location_match(name: str, locations: list, min_score: int = 65) -> Optional[str]:
    """Find the best matching location name from a list. Handles partial name matching."""
    return find_best_name_match(name, locations, min_score)

# =============================================================================
# V17.6 SAFE MERGE WRITE — Protects canonical files from data loss
# =============================================================================
# Problem: Multiple endpoints overwrite entire JSON files, losing unrelated data.
# Solution: Read existing → merge → atomic write (tempfile + os.replace).

import tempfile
import threading

_file_write_locks: Dict[str, threading.Lock] = {}

def _get_file_lock(path: str) -> threading.Lock:
    """Get or create a thread lock for a given file path."""
    if path not in _file_write_locks:
        _file_write_locks[path] = threading.Lock()
    return _file_write_locks[path]

def safe_merge_json(file_path: str, updates: dict, preserve_keys: List[str] = None) -> bool:
    """
    Merge updates into existing JSON file with atomic write.
    Existing keys NOT in updates are preserved. Protected keys are never overwritten.
    """
    preserve_keys = preserve_keys or []
    lock = _get_file_lock(file_path)
    with lock:
        try:
            existing = {}
            if os.path.exists(file_path):
                with open(file_path, "r") as f:
                    try:
                        existing = json.load(f)
                    except json.JSONDecodeError:
                        logger.warning(f"[SAFE_IO] {file_path} corrupted, starting fresh")
            # Merge: existing + updates, respecting preserve_keys
            merged = dict(existing)
            for key, value in updates.items():
                if key not in preserve_keys:
                    merged[key] = value
            # Atomic write
            dir_path = os.path.dirname(file_path) or "."
            os.makedirs(dir_path, exist_ok=True)
            fd, tmp_path = tempfile.mkstemp(suffix=".tmp", dir=dir_path)
            try:
                with os.fdopen(fd, "w") as tmp:
                    json.dump(merged, tmp, indent=2)
                os.replace(tmp_path, file_path)
                return True
            except Exception:
                if os.path.exists(tmp_path):
                    os.remove(tmp_path)
                raise
        except Exception as e:
            logger.error(f"[SAFE_IO] safe_merge_json failed for {file_path}: {e}")
            return False

def safe_write_shot_plan(file_path: str, data: dict) -> bool:
    """
    V17.6: PROTECTED shot_plan.json writer.
    1. Validates data has shots (refuses to write empty plans)
    2. Auto-backs up current file before overwriting
    3. Uses atomic write (tempfile + os.replace)

    DO NOT RE-BREAK: This function prevents shot plan wipes.
    ALL shot_plan.json writes should go through this function.
    """
    shots = data.get("shots", [])
    # GUARD: Never overwrite a populated plan with an empty one
    if not shots and os.path.exists(file_path):
        existing_size = os.path.getsize(file_path)
        if existing_size > 100:  # Existing file has real data
            logger.error(f"[SAFE_IO] BLOCKED empty shot_plan write to {file_path} (existing file has {existing_size} bytes)")
            return False

    # Auto-backup before write (keep last 5 rolling backups)
    if os.path.exists(file_path) and os.path.getsize(file_path) > 100:
        from datetime import datetime
        timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")
        backup_path = f"{file_path}.autobackup_{timestamp}"
        try:
            import shutil
            shutil.copy2(file_path, backup_path)
            # Prune old autobackups (keep last 5)
            dir_path = os.path.dirname(file_path) or "."
            autobackups = sorted([
                f for f in os.listdir(dir_path)
                if f.startswith("shot_plan.json.autobackup_")
            ])
            while len(autobackups) > 5:
                old = os.path.join(dir_path, autobackups.pop(0))
                try:
                    os.remove(old)
                except Exception:
                    pass
        except Exception as e:
            logger.warning(f"[SAFE_IO] Backup failed (proceeding anyway): {e}")

    return safe_write_json(file_path, data)


def safe_write_json(file_path: str, data: dict) -> bool:
    """Atomic JSON write (full replacement). Use safe_merge_json when possible."""
    lock = _get_file_lock(file_path)
    with lock:
        try:
            dir_path = os.path.dirname(file_path) or "."
            os.makedirs(dir_path, exist_ok=True)
            fd, tmp_path = tempfile.mkstemp(suffix=".tmp", dir=dir_path)
            try:
                with os.fdopen(fd, "w") as tmp:
                    json.dump(data, tmp, indent=2)
                os.replace(tmp_path, file_path)
                return True
            except Exception:
                if os.path.exists(tmp_path):
                    os.remove(tmp_path)
                raise
        except Exception as e:
            logger.error(f"[SAFE_IO] safe_write_json failed for {file_path}: {e}")
            return False

