# V17.3 PROFILE LOADER HELPERS — Central director/writer resolution for all endpoints
# =============================================================================
def _resolve_genre_from_story_bible(story_bible: dict) -> str:
    """Extract a clean genre string from story_bible, normalised for mapping lookups."""
    genre = story_bible.get("genre") or "drama"
    if isinstance(genre, list):
        genre = genre[0] if genre else "drama"
    if isinstance(genre, dict):
        genre = genre.get("primary") or genre.get("name") or str(next(iter(genre.values()), "drama"))
    if not isinstance(genre, str):
        genre = str(genre) if genre else "drama"
    return genre.lower().replace(" ", "_").replace("-", "_")


def load_director_for_project(project_path: Path, story_bible: dict = None) -> Optional[dict]:
    """
    Load the best-matching director profile for a project.

    Resolution order:
      1. story_bible.director_id  → exact director ID lookup
      2. genre_to_director_mapping → auto-match via story_bible genre
      3. Fallback → D001 (Helena Blackwood)

    Returns the full director profile dict or None on failure.
    """
    try:
        directors_path = BASE_DIR / "directors_library.json"
        if not directors_path.exists():
            logging.warning("[V17.3] directors_library.json not found")
            return None

        with open(directors_path) as f:
            directors_data = json.load(f)

        directors_list = directors_data.get("directors", [])

        # Load story_bible from disk if not provided
        if story_bible is None:
            sb_path = project_path / "story_bible.json"
            if sb_path.exists():
                with open(sb_path) as f:
                    story_bible = json.load(f)
            else:
                story_bible = {}

        # Priority 1: Explicit director_id in story_bible
        explicit_id = story_bible.get("director_id")
        if explicit_id:
            for d in directors_list:
                if d.get("id") == explicit_id or d.get("name", "").lower().replace(" ", "_") == explicit_id.lower():
                    logging.info(f"[V17.3] Director loaded (explicit): {d.get('name')} (id={d.get('id')})")
                    return d

        # Priority 2: Genre-based auto-match
        genre = _resolve_genre_from_story_bible(story_bible)
        genre_mapping = directors_data.get("genre_to_director_mapping", {})
        director_id = genre_mapping.get(genre) or genre_mapping.get("drama", "D001")

        for d in directors_list:
            if d.get("id") == director_id:
                logging.info(f"[V17.3] Director loaded (genre={genre}): {d.get('name')} (id={d.get('id')})")
                return d

        # Priority 3: Absolute fallback — first director
        if directors_list:
            logging.info(f"[V17.3] Director loaded (fallback): {directors_list[0].get('name')}")
            return directors_list[0]

        return None
    except Exception as e:
        logging.warning(f"[V17.3] Director load failed: {e}")
        return None


def load_writer_for_project(project_path: Path, story_bible: dict = None) -> Optional[dict]:
    """
    Load the best-matching writer profile for a project.

    Resolution order:
      1. story_bible.writer_id  → exact writer ID lookup
      2. genre_to_writer_mapping → auto-match via story_bible genre
      3. Fallback → W001 (Thomas Ashworth)

    Returns the full writer profile dict or None on failure.
    """
    try:
        writers_path = BASE_DIR / "writers_library.json"
        if not writers_path.exists():
            logging.warning("[V17.3] writers_library.json not found")
            return None

        with open(writers_path) as f:
            writers_data = json.load(f)

        writers_list = writers_data.get("writers", [])

        # Load story_bible from disk if not provided
        if story_bible is None:
            sb_path = project_path / "story_bible.json"
            if sb_path.exists():
                with open(sb_path) as f:
                    story_bible = json.load(f)
            else:
                story_bible = {}

        # Priority 1: Explicit writer_id in story_bible
        explicit_id = story_bible.get("writer_id")
        if explicit_id:
            for w in writers_list:
                if w.get("id") == explicit_id or w.get("name", "").lower().replace(" ", "_") == explicit_id.lower():
                    logging.info(f"[V17.3] Writer loaded (explicit): {w.get('name')} (id={w.get('id')})")
                    return w

        # Priority 2: Genre-based auto-match
        genre = _resolve_genre_from_story_bible(story_bible)
        genre_mapping = writers_data.get("genre_to_writer_mapping", {})
        writer_id = genre_mapping.get(genre) or genre_mapping.get("drama", "W001")

        for w in writers_list:
            if w.get("id") == writer_id:
                logging.info(f"[V17.3] Writer loaded (genre={genre}): {w.get('name')} (id={w.get('id')})")
                return w

        # Priority 3: Absolute fallback — first writer
        if writers_list:
            logging.info(f"[V17.3] Writer loaded (fallback): {writers_list[0].get('name')}")
            return writers_list[0]

        return None
    except Exception as e:
        logging.warning(f"[V17.3] Writer load failed: {e}")
        return None


