# V18.0 CLOUDFLARE R2 STORAGE INTEGRATION (S3-compatible)
# =============================================================================
# R2 replaces GCS for Kling image hosting — uses existing rumble-fanz bucket
# Public URL pattern: https://pub-{hash}.r2.dev/atlas-frames/{key}
# Or custom domain if configured on the R2 bucket
#
# Required env vars:
#   ATLAS_R2_ACCOUNT_ID      — Cloudflare account ID
#   ATLAS_R2_ACCESS_KEY_ID   — R2 API token Access Key ID
#   ATLAS_R2_SECRET_KEY      — R2 API token Secret Access Key
#   ATLAS_R2_BUCKET          — Bucket name (default: rumble-fanz)
#   ATLAS_R2_PUBLIC_URL      — Public URL base (from R2 bucket settings)
# =============================================================================
R2_ACCOUNT_ID = os.environ.get("ATLAS_R2_ACCOUNT_ID", "")
R2_ACCESS_KEY_ID = os.environ.get("ATLAS_R2_ACCESS_KEY_ID", "")
R2_SECRET_KEY = os.environ.get("ATLAS_R2_SECRET_KEY", "")
R2_BUCKET_NAME = os.environ.get("ATLAS_R2_BUCKET", "rumble-fanz")
R2_PUBLIC_URL = os.environ.get("ATLAS_R2_PUBLIC_URL", "")  # e.g. https://pub-xxx.r2.dev
R2_PREFIX = "atlas-frames"  # Folder prefix inside bucket

# V18.3: Direct boto3 R2 upload (replaces wrangler subprocess — no timeouts, no Node.js)
# boto3 talks directly to R2's S3-compatible API over HTTPS.
# Previous wrangler approach spawned Node.js per upload causing 25+ timeouts per run.
R2_ENABLED = False
_R2_CLIENT = None  # boto3 S3 client for R2

if R2_PUBLIC_URL and R2_ACCESS_KEY_ID and R2_SECRET_KEY and R2_ACCOUNT_ID:
    try:
        import boto3
        from botocore.config import Config as BotoConfig
        # V18.3: Bypass any system proxy for R2 connections (sandbox sets HTTP_PROXY)
        _r2_config = BotoConfig(
            retries={"max_attempts": 3, "mode": "adaptive"},
            connect_timeout=10,
            read_timeout=120,
            max_pool_connections=10,
            proxies={},  # Empty dict = bypass all proxies
        )
        _R2_CLIENT = boto3.client(
            "s3",
            endpoint_url=f"https://{R2_ACCOUNT_ID}.r2.cloudflarestorage.com",
            aws_access_key_id=R2_ACCESS_KEY_ID,
            aws_secret_access_key=R2_SECRET_KEY,
            config=_r2_config,
            region_name="auto",
        )
        R2_ENABLED = True
        logging.info(f"[R2] Initialized via boto3 — bucket: {R2_BUCKET_NAME}, prefix: {R2_PREFIX}")
    except ImportError:
        logging.warning("[R2] boto3 not installed — run: pip install boto3 --break-system-packages")
    except Exception as e:
        logging.error(f"[R2] Failed to initialize boto3 client: {e}")
elif R2_PUBLIC_URL:
    logging.warning("[R2] Missing credentials (need ATLAS_R2_ACCESS_KEY_ID + ATLAS_R2_SECRET_KEY + ATLAS_R2_ACCOUNT_ID)")
else:
    logging.info("[R2] Not configured (missing ATLAS_R2_PUBLIC_URL env var)")


def r2_upload_file(local_path: Path, r2_key: str) -> Optional[str]:
    """Upload a local file to Cloudflare R2 via boto3 and return the public URL."""
    if not R2_ENABLED or not _R2_CLIENT or not R2_PUBLIC_URL:
        return None
    try:
        local_path = Path(local_path)
        if not local_path.exists():
            logger.error(f"[R2] File not found: {local_path}")
            return None

        content_type = "image/jpeg"
        if str(local_path).endswith(".png"):
            content_type = "image/png"
        elif str(local_path).endswith(".mp4"):
            content_type = "video/mp4"
        elif str(local_path).endswith(".webp"):
            content_type = "image/webp"

        full_key = f"{R2_PREFIX}/{r2_key}"

        _R2_CLIENT.upload_file(
            str(local_path),
            R2_BUCKET_NAME,
            full_key,
            ExtraArgs={"ContentType": content_type},
        )

        public_url = f"{R2_PUBLIC_URL.rstrip('/')}/{full_key}"
        # V26.1: Verify URL is accessible — R2 bucket may have public access disabled (401)
        try:
            import urllib.request as _ur
            _hr = _ur.Request(public_url, method="HEAD")
            _resp = _ur.urlopen(_hr, timeout=5)
            if _resp.status != 200:
                logger.warning(f"[R2] Uploaded but URL returned {_resp.status} — returning None for base64 fallback")
                return None
        except Exception as _ve:
            logger.warning(f"[R2] Uploaded but URL not accessible ({_ve}) — returning None for base64 fallback")
            return None
        logger.info(f"[R2] ✅ Uploaded + verified {local_path.name} ({local_path.stat().st_size // 1024}KB) → {public_url}")
        return public_url
    except Exception as e:
        logger.error(f"[R2] Upload failed for {local_path}: {e}")
        return None


def r2_upload_bytes(data: bytes, r2_key: str, content_type: str = "image/jpeg") -> Optional[str]:
    """Upload bytes directly to R2 via boto3 (no temp file needed)."""
    if not R2_ENABLED or not _R2_CLIENT or not R2_PUBLIC_URL:
        return None
    try:
        import io
        full_key = f"{R2_PREFIX}/{r2_key}"

        _R2_CLIENT.upload_fileobj(
            io.BytesIO(data),
            R2_BUCKET_NAME,
            full_key,
            ExtraArgs={"ContentType": content_type},
        )

        public_url = f"{R2_PUBLIC_URL.rstrip('/')}/{full_key}"
        logger.info(f"[R2] ✅ Uploaded bytes ({len(data) // 1024}KB) → {public_url}")
        return public_url
    except Exception as e:
        logger.error(f"[R2] Bytes upload failed: {e}")
        return None




def r2_sync_project_media(project: str) -> dict:
    """
    Sync all first frames + videos for a project to R2.
    Returns {uploaded: N, skipped: N, failed: N, urls: {shot_id: url}}.
    This enables the UI to work from anywhere (mobile, remote).
    """
    if not R2_ENABLED:
        return {"error": "R2 not configured", "uploaded": 0}

    project_path = PIPELINE_OUTPUTS_DIR / project
    uploaded = 0
    skipped = 0
    failed = 0
    urls = {}

    # Sync first frames
    ff_dir = project_path / "first_frames"
    if ff_dir.exists():
        for img in sorted(ff_dir.glob("*.jpg")):
            r2_key = f"{project}/first_frames/{img.name}"
            try:
                url = r2_upload_file(img, r2_key)
                if url:
                    shot_id = img.stem
                    urls[f"ff_{shot_id}"] = url
                    uploaded += 1
                else:
                    failed += 1
            except Exception:
                failed += 1

    # Sync first frame variants
    var_dir = project_path / "first_frame_variants"
    if var_dir.exists():
        for img in sorted(var_dir.glob("*.jpg")):
            r2_key = f"{project}/variants/{img.name}"
            try:
                url = r2_upload_file(img, r2_key)
                if url:
                    urls[f"var_{img.stem}"] = url
                    uploaded += 1
                else:
                    failed += 1
            except Exception:
                failed += 1

    # Sync videos (LTX)
    vid_dir = project_path / "videos"
    if vid_dir.exists():
        for vid in sorted(vid_dir.glob("*.mp4")):
            r2_key = f"{project}/videos/{vid.name}"
            try:
                url = r2_upload_file(vid, r2_key)
                if url:
                    urls[f"vid_{vid.stem}"] = url
                    uploaded += 1
                else:
                    failed += 1
            except Exception:
                failed += 1

    # Sync Kling videos
    kling_dir = project_path / "videos_kling"
    if kling_dir.exists():
        for vid in sorted(kling_dir.glob("*.mp4")):
            r2_key = f"{project}/videos_kling/{vid.name}"
            try:
                url = r2_upload_file(vid, r2_key)
                if url:
                    urls[f"kling_{vid.stem}"] = url
                    uploaded += 1
                else:
                    failed += 1
            except Exception:
                failed += 1

    # Sync location masters
    loc_dir = project_path / "location_masters"
    if loc_dir.exists():
        for img in sorted(loc_dir.glob("*.*")):
            r2_key = f"{project}/location_masters/{img.name}"
            try:
                url = r2_upload_file(img, r2_key)
                if url:
                    urls[f"loc_{img.stem}"] = url
                    uploaded += 1
                else:
                    failed += 1
            except Exception:
                failed += 1

    # V18.1: Sync AI actor headshots + locked refs (shared across projects, sync once)
    headshots_dir = BASE_DIR / "ai_actor_headshots"
    if headshots_dir.exists():
        for img in sorted(headshots_dir.glob("*.jpg")):
            r2_key = f"_shared/ai_actor_headshots/{img.name}"
            try:
                url = r2_upload_file(img, r2_key)
                if url:
                    urls[f"hs_{img.stem}"] = url
                    uploaded += 1
                else:
                    failed += 1
            except Exception:
                failed += 1

    actors_dir = BASE_DIR / "character_library_locked" / "ai_actors"
    if actors_dir.exists():
        for img in sorted(actors_dir.glob("*.jpg")):
            r2_key = f"_shared/ai_actors/{img.name}"
            try:
                url = r2_upload_file(img, r2_key)
                if url:
                    urls[f"actor_{img.stem}"] = url
                    uploaded += 1
                else:
                    failed += 1
            except Exception:
                failed += 1

    # Sync project character refs
    char_ref_dir = project_path / "character_library_locked"
    if char_ref_dir.exists():
        for img in sorted(char_ref_dir.glob("*.jpg")):
            r2_key = f"{project}/character_refs/{img.name}"
            try:
                url = r2_upload_file(img, r2_key)
                if url:
                    urls[f"cref_{img.stem}"] = url
                    uploaded += 1
                else:
                    failed += 1
            except Exception:
                failed += 1

    logger.info(f"[R2-SYNC] {project}: uploaded={uploaded} skipped={skipped} failed={failed}")
    return {"uploaded": uploaded, "skipped": skipped, "failed": failed, "urls": urls}


# =============================================================================
# V16.7.1 MEDIA PATH NORMALIZATION - Single source of truth
# =============================================================================
def normalize_media_path(path: str) -> str:
    """
    Canonicalize media paths to use /api/media?path= format with ABSOLUTE paths.
    This is the single source of truth for all media URLs in the system.

    Rules:
    - Empty/None paths return ""
    - Already-formatted /api/media?path= URLs are validated for absolute paths
    - Relative paths are rejected (return "")
    - Absolute paths are wrapped in /api/media?path=
    """
    if not path:
        return ""

    path = str(path).strip()

    # Already formatted - validate it has absolute path
    if path.startswith("/api/media?path="):
        inner_path = path.split("path=", 1)[1] if "path=" in path else ""
        if inner_path.startswith("/Users/") or inner_path.startswith("/tmp/"):
            return path
        # Invalid - relative path inside /api/media?path=
        return ""

    # Assets path - pass through
    if path.startswith("/assets/"):
        return path

    # Absolute path - wrap it
    if path.startswith("/Users/") or path.startswith("/tmp/"):
        return f"/api/media?path={path}"

    # Relative paths are ILLEGAL - never trust them
    if not path.startswith("/"):
        logger.warning(f"[MEDIA] Rejecting relative path: {path}")
        return ""

    # Other absolute paths (e.g., /some/other/path) - wrap them
    return f"/api/media?path={path}"


def sync_ltx_duration(shot: dict) -> bool:
    """
    V16.7.1: Ensure LTX motion prompt duration matches shot duration.
    Called AFTER any shot duration modification to maintain consistency.

    Returns True if a fix was applied, False otherwise.
    """
    import re
    duration = int(shot.get("duration_seconds", shot.get("duration", 0)))
    ltx_prompt = shot.get("ltx_motion_prompt", "")

    if not ltx_prompt or duration <= 0:
        return False

    # Find any duration marker in the prompt
    match = re.search(r'\b(\d+)s\b', ltx_prompt)
    if match:
        prompt_duration = int(match.group(1))
        if prompt_duration != duration:
            # Fix mismatch
            fixed = re.sub(r'\b\d+s\b', f'{duration}s', ltx_prompt)
            shot["ltx_motion_prompt"] = fixed
            return True
    else:
        # No duration marker - add one
        shot["ltx_motion_prompt"] = ltx_prompt.rstrip(", ") + f", {duration}s"
        return True

    return False




# =============================================================================
# V16.7 LIVE GENERATION TRACKER - Real-time UI updates
# =============================================================================
from collections import deque
from threading import Lock
import time

class LiveGenerationTracker:
    """Thread-safe tracker for live generation status updates."""

    def __init__(self, max_entries=50):
        self._generations = deque(maxlen=max_entries)
        self._lock = Lock()
        self._active_count = 0

    def add(self, project: str, shot_id: str, status: str, asset_type: str = "image",
            url: str = None, prompt: str = None, model: str = None):
        """Add a new generation entry."""
        with self._lock:
            entry = {
                "project": project,
                "shot_id": shot_id,
                "status": status,
                "asset_type": asset_type,
                "url": url,
                "prompt": prompt[:200] if prompt else None,
                "model": model,
                "timestamp": datetime.now().isoformat(),
                "timestamp_ms": int(time.time() * 1000)
            }
            self._generations.appendleft(entry)
            if status in ["running", "pending", "queued"]:
                self._active_count += 1
            logger.info(f"[LIVE_GEN] {status}: {shot_id} ({asset_type})")

    def update(self, shot_id: str, status: str, url: str = None,
               variants: list = None, selected_variant: str = None,
               progress: float = None, step: str = None):
        """Update an existing entry's status with optional variant/progress info."""
        with self._lock:
            for entry in self._generations:
                if entry["shot_id"] == shot_id:
                    old_status = entry["status"]
                    entry["status"] = status
                    if url:
                        entry["url"] = url
                    if variants:
                        entry["variants"] = variants
                    if selected_variant:
                        entry["selected_variant"] = selected_variant
                    if progress is not None:
                        entry["progress"] = progress
                    if step:
                        entry["step"] = step
                    entry["timestamp"] = datetime.now().isoformat()
                    # Update active count
                    if old_status in ["running", "pending", "queued"] and status in ["completed", "done", "error"]:
                        self._active_count = max(0, self._active_count - 1)
                    break

    def get_all(self):
        """Get all generations for UI."""
        with self._lock:
            completed = sum(1 for g in self._generations if g["status"] in ["completed", "done", "success"])
            return {
                "generations": list(self._generations),
                "active": self._active_count,
                "completed": completed
            }

    def clear(self):
        """Clear all generations."""
        with self._lock:
            count = len(self._generations)
            self._generations.clear()
            self._active_count = 0
            return count

    def clear_scene(self, scene_id: str):
        """Clear all generations for a specific scene (by shot_id prefix or scene tag)."""
        with self._lock:
            prefix = f"{scene_id}_"
            before = len(self._generations)
            kept = deque(maxlen=self._generations.maxlen)
            active_removed = 0
            for entry in self._generations:
                sid = entry.get("shot_id", "")
                if sid.startswith(prefix) or sid == f"KLING_{scene_id}" or sid == f"CHAIN_{scene_id}" or sid == f"R2_SYNC_{scene_id}":
                    if entry["status"] in ["running", "pending", "queued"]:
                        active_removed += 1
                else:
                    kept.append(entry)
            self._generations = kept
            self._active_count = max(0, self._active_count - active_removed)
            removed = before - len(self._generations)
            logger.info(f"[LIVE_GEN] Cleared {removed} entries for scene {scene_id}")
            return removed

# Global tracker instance
LIVE_GEN_TRACKER = LiveGenerationTracker()


class TaskType(str, Enum):
    """Types of rendering tasks - V16 MODEL LOCK"""
    # V16 APPROVED MODELS ONLY
    NANO_BANANA_IMAGE = "nano_banana_image"  # fal-ai/nano-banana-pro (no refs)
    NANO_BANANA_EDIT = "nano_banana_edit"    # fal-ai/nano-banana-pro/edit (with refs)
    LTX_VIDEO = "ltx_video"                  # fal-ai/ltxv-2/image-to-video/fast
    OMNIHUMAN_LIPSYNC = "omnihuman_lipsync"  # Dialogue with lip sync
    ELEVENLABS_AUDIO = "elevenlabs_audio"    # Voice generation
    # DEPRECATED - DO NOT USE: minimax_image, flux_angles, runway_env, wan_motion, upload_gcs (GCS removed in V18)


class TaskStatus(str, Enum):
    """Task lifecycle states"""
    QUEUED = "queued"
    ASSIGNED = "assigned"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"
    FAILED = "failed"
    RETRYING = "retrying"


@dataclass
class Task:
    """Rendering task"""
    id: str
    type: TaskType
    status: TaskStatus
    params: Dict
    assigned_to: Optional[str] = None
    result: Optional[Dict] = None
    error: Optional[str] = None
    created_at: str = None
    started_at: Optional[str] = None
    completed_at: Optional[str] = None
    retry_count: int = 0

    def __post_init__(self):
        if self.created_at is None:
            self.created_at = datetime.now().isoformat()


@dataclass
class TabWorker:
    """Browser tab worker"""
    id: str
    websocket: WebSocket
    status: str = "idle"  # idle, busy, disconnected
    current_task: Optional[str] = None
    completed_tasks: int = 0
    failed_tasks: int = 0
    connected_at: str = None

    def __post_init__(self):
        if self.connected_at is None:
            self.connected_at = datetime.now().isoformat()


class AtlasOrchestrator:
    """
    Central orchestrator for multi-tab Atlas rendering
    Manages task queue, worker tabs, and inter-tab communication
    """

    def __init__(self):
        self.tasks: Dict[str, Task] = {}
        self.workers: Dict[str, TabWorker] = {}
        self.task_queue: asyncio.Queue = asyncio.Queue()
        self.results: Dict[str, Dict] = {}
        # V18.4: Memory stability — max sizes + auto-cleanup
        self._MAX_TASKS = 500       # Keep at most 500 completed tasks
        self._MAX_RESULTS = 200     # Keep at most 200 results
        self._TASK_TTL_HOURS = 2    # Purge tasks older than 2 hours
        self._cleanup_counter = 0   # Run cleanup every 10th task completion

        # API key rotation - Replicate (7 keys)
        self.replicate_keys = [
            os.environ.get("REPLICATE_TOKEN_1", ""),
            os.environ.get("REPLICATE_TOKEN_2", ""),
            os.environ.get("REPLICATE_TOKEN_3", ""),
            os.environ.get("REPLICATE_TOKEN_4", ""),
            os.environ.get("REPLICATE_TOKEN_5", ""),
            os.environ.get("REPLICATE_TOKEN_6", ""),
            os.environ.get("REPLICATE_TOKEN_7", "")
        ]
        self.current_key_index = 0

        # FAL.ai API keys (10 keys for rotation)
        self.fal_keys = [
            "6c394797-d2ed-4238-a303-7b1179a0aaf5:ccce2ccede50e31794c205aad4439ccc",
            "5fe81578-ca41-418e-aa1a-1d62ada97f0e:4894e489d4230008f1c2ad482882a29f",
            "d6d674e6-a090-403e-b6e8-24334394290f:d4e68a53c7881707e3815eb75bb76dc2",
            "12cd8bf8-1599-4d40-80d5-bdd16d09edbf:e1308c1a518cfdf1b95c6cc7e8ca529a",
            "ef03d641-1122-422a-9d27-27158cc88ae6:43f285f4e5984b775a950eb0deaebc05",
            "8d1ca2fc-9064-4ba9-bd22-6f84ded1e6db:edd366cdb950b14a522da2268be6d423",
            "c7830c0c-4635-43c3-b2ee-23525cc5cc17:eeef1b4f196f366253931b41e78a19fe",
            "582c0d2b-b266-45ab-ba8b-b5e89f03acac:119a80ff6e56e84ccd74acd1350c26b7",
            "7e489f09-3797-4113-a5d4-386a2841eebc:be9498651dfc76373cc26b5a7d1f4daa",
            "aaa9e8a3-af55-4aca-8687-ffd1411deea7:71b92029c9bc960abe468fcc12501016"
        ]
        self.current_fal_key_index = 0

        # ElevenLabs API key — prefer .env, fallback to hardcoded
        self.elevenlabs_key = os.environ.get("ELEVENLABS_API_KEY", os.environ.get("ELEVENLABS_API_KEY", ""))

        # Statistics
        self.stats = {
            "total_tasks": 0,
            "completed_tasks": 0,
            "failed_tasks": 0,
            "total_workers": 0,
            "active_workers": 0
        }

    def get_next_api_key(self) -> str:
        """Rotate through Replicate API keys"""
        key = self.replicate_keys[self.current_key_index]
        self.current_key_index = (self.current_key_index + 1) % len(self.replicate_keys)
        return key

    def get_next_fal_key(self) -> str:
        """Rotate through FAL.ai API keys"""
        key = self.fal_keys[self.current_fal_key_index]
        self.current_fal_key_index = (self.current_fal_key_index + 1) % len(self.fal_keys)
        return key

    async def register_worker(self, websocket: WebSocket) -> TabWorker:
        """Register a new browser tab worker"""
        worker_id = str(uuid.uuid4())[:8]
        worker = TabWorker(id=worker_id, websocket=websocket)
        self.workers[worker_id] = worker
        self.stats["total_workers"] += 1
        self.stats["active_workers"] = len([w for w in self.workers.values() if w.status != "disconnected"])

        logger.info(f"✅ Worker {worker_id} connected. Total workers: {self.stats['active_workers']}")
        return worker

    async def unregister_worker(self, worker_id: str):
        """Remove a disconnected worker"""
        if worker_id in self.workers:
            worker = self.workers[worker_id]
            worker.status = "disconnected"

            # Re-queue any assigned task
            if worker.current_task and worker.current_task in self.tasks:
                task = self.tasks[worker.current_task]
                if task.status == TaskStatus.IN_PROGRESS:
                    task.status = TaskStatus.QUEUED
                    task.assigned_to = None
                    await self.task_queue.put(task)
                    logger.info(f"♻️  Re-queued task {task.id} from disconnected worker")

            self.stats["active_workers"] = len([w for w in self.workers.values() if w.status != "disconnected"])
            logger.info(f"❌ Worker {worker_id} disconnected. Active workers: {self.stats['active_workers']}")

    async def add_task(self, task_type: TaskType, params: Dict) -> str:
        """Add a new task to the queue"""
        task_id = str(uuid.uuid4())[:12]
        task = Task(
            id=task_id,
            type=task_type,
            status=TaskStatus.QUEUED,
            params=params
        )

        self.tasks[task_id] = task
        await self.task_queue.put(task)
        self.stats["total_tasks"] += 1

        logger.info(f"📋 Task {task_id} ({task_type}) added to queue. Queue size: {self.task_queue.qsize()}")
        return task_id

    async def add_batch_tasks(self, tasks: List[Dict]) -> List[str]:
        """Add multiple tasks at once"""
        task_ids = []
        for task_spec in tasks:
            task_id = await self.add_task(
                TaskType(task_spec["type"]),
                task_spec["params"]
            )
            task_ids.append(task_id)
        return task_ids

    async def assign_task_to_worker(self, worker_id: str) -> Optional[Task]:
        """Assign next task from queue to a worker"""
        if self.task_queue.empty():
            return None

        try:
            task = await asyncio.wait_for(self.task_queue.get(), timeout=0.1)
            task.status = TaskStatus.ASSIGNED
            task.assigned_to = worker_id
            task.started_at = datetime.now().isoformat()

            worker = self.workers[worker_id]
            worker.status = "busy"
            worker.current_task = task.id

            logger.info(f"📤 Task {task.id} assigned to worker {worker_id}")
            return task

        except asyncio.TimeoutError:
            return None

    async def complete_task(self, task_id: str, result: Dict):
        """Mark task as completed with result"""
        if task_id not in self.tasks:
            logger.error(f"❌ Unknown task {task_id}")
            return

        task = self.tasks[task_id]
        task.status = TaskStatus.COMPLETED
        task.result = result
        task.completed_at = datetime.now().isoformat()

        # Update worker
        if task.assigned_to and task.assigned_to in self.workers:
            worker = self.workers[task.assigned_to]
            worker.status = "idle"
            worker.current_task = None
            worker.completed_tasks += 1

        self.stats["completed_tasks"] += 1
        self.results[task_id] = result

        logger.info(f"✅ Task {task_id} completed by worker {task.assigned_to}")

        # V18.4: Memory cleanup — prevent unbounded growth
        self._cleanup_counter += 1
        if self._cleanup_counter >= 10:
            self._cleanup_counter = 0
            self._purge_old_entries()

    def _purge_old_entries(self):
        """V18.4: Prevent memory leaks by purging old tasks/results/workers."""
        now = datetime.now()
        purged_tasks = 0
        purged_results = 0
        purged_workers = 0

        # Purge completed tasks older than TTL
        stale_task_ids = []
        for tid, task in self.tasks.items():
            if task.status in (TaskStatus.COMPLETED, TaskStatus.FAILED):
                try:
                    if task.completed_at:
                        completed = datetime.fromisoformat(str(task.completed_at))
                        if (now - completed).total_seconds() > self._TASK_TTL_HOURS * 3600:
                            stale_task_ids.append(tid)
                except Exception:
                    pass
        for tid in stale_task_ids:
            del self.tasks[tid]
            purged_tasks += 1

        # Cap tasks dict size
        if len(self.tasks) > self._MAX_TASKS:
            completed = [(tid, t) for tid, t in self.tasks.items()
                         if t.status in (TaskStatus.COMPLETED, TaskStatus.FAILED)]
            completed.sort(key=lambda x: x[1].completed_at or "")
            for tid, _ in completed[:len(completed) // 2]:
                del self.tasks[tid]
                purged_tasks += 1

        # Cap results dict size
        if len(self.results) > self._MAX_RESULTS:
            to_remove = list(self.results.keys())[:len(self.results) - self._MAX_RESULTS]
            for rid in to_remove:
                del self.results[rid]
                purged_results += 1

        # Purge disconnected workers
        stale_workers = [wid for wid, w in self.workers.items() if w.status == "disconnected"]
        for wid in stale_workers:
            del self.workers[wid]
            purged_workers += 1

        if purged_tasks or purged_results or purged_workers:
            logger.info(f"[V18.4 MEMORY] Purged {purged_tasks} tasks, {purged_results} results, {purged_workers} workers")

    async def fail_task(self, task_id: str, error: str, retry: bool = True):
        """Mark task as failed"""
        if task_id not in self.tasks:
            return

        task = self.tasks[task_id]
        task.error = error

        # Retry logic
        if retry and task.retry_count < 3:
            task.retry_count += 1
            task.status = TaskStatus.RETRYING
            task.assigned_to = None
            await self.task_queue.put(task)
            logger.warning(f"⚠️  Task {task_id} failed, retrying ({task.retry_count}/3)")
        else:
            task.status = TaskStatus.FAILED
            self.stats["failed_tasks"] += 1
            logger.error(f"❌ Task {task_id} failed: {error}")

        # Update worker
        if task.assigned_to and task.assigned_to in self.workers:
            worker = self.workers[task.assigned_to]
            worker.status = "idle"
            worker.current_task = None
            worker.failed_tasks += 1

    async def broadcast_status(self):
        """Broadcast current status to all connected workers"""
        status = {
            "type": "status_update",
            "stats": self.stats,
            "queue_size": self.task_queue.qsize(),
            "workers": {
                wid: {
                    "id": w.id,
                    "status": w.status,
                    "completed": w.completed_tasks,
                    "failed": w.failed_tasks
                }
                for wid, w in self.workers.items()
                if w.status != "disconnected"
            }
        }

        disconnected = []
        for worker_id, worker in self.workers.items():
            if worker.status != "disconnected":
                try:
                    await worker.websocket.send_json(status)
                except Exception:
                    disconnected.append(worker_id)

        # Clean up disconnected workers
        for worker_id in disconnected:
            await self.unregister_worker(worker_id)

    def get_status(self) -> Dict:
        """Get current orchestrator status"""
        return {
            "stats": self.stats,
            "queue_size": self.task_queue.qsize(),
            "active_workers": [
                {
                    "id": w.id,
                    "status": w.status,
                    "current_task": w.current_task,
                    "completed": w.completed_tasks,
                    "failed": w.failed_tasks
                }
                for w in self.workers.values()
                if w.status != "disconnected"
            ],
            "recent_results": list(self.results.keys())[-10:]
        }


