# =============================================================================
# V17.3: AAA INDUSTRIAL ERROR HANDLING
# Every error returns JSON with trace_id — NO uncaught exceptions, NO HTML errors
# =============================================================================
import uuid as _uuid

@app.middleware("http")
async def trace_id_middleware(request, call_next):
    """Attach trace_id to every request. On unhandled error, return JSON with trace + suggested action."""
    trace_id = f"ATLAS-{_uuid.uuid4().hex[:8].upper()}"
    request.state.trace_id = trace_id
    try:
        response = await call_next(request)
        response.headers["X-Trace-ID"] = trace_id
        return response
    except Exception as e:
        import traceback
        _tb = traceback.format_exc()
        print(f"[MIDDLEWARE EXCEPTION] [{trace_id}] path={request.url.path} error={e!r}\n{_tb}", flush=True)
        logger.error(f"[{trace_id}] Unhandled: {e}\n{_tb}")
        return JSONResponse(
            status_code=500,
            content={
                "success": False,
                "error": str(e)[:300],
                "trace_id": trace_id,
                "suggested_action": "retry" if "timeout" in str(e).lower() else "check server logs"
            },
            headers={"X-Trace-ID": trace_id}
        )

# V17.3: Sentry initialization (graceful — uses DSN from env if available)
# V26: instrument.py (imported at line 33) sets traces_sample_rate=1.0 (100%).
# This fallback ONLY fires if instrument.py failed to import.
try:
    import sentry_sdk as _sentry
    _sentry_hub = _sentry.Hub.current
    if _sentry_hub.client is not None and _sentry_hub.client.dsn is not None:
        logger.info("[SENTRY] Already initialized by instrument.py at 100% sampling — skipping fallback")
    else:
        _sentry_dsn = os.environ.get("SENTRY_DSN")
        if _sentry_dsn:
            _sentry.init(dsn=_sentry_dsn, traces_sample_rate=1.0, environment="production")
            logger.info("[SENTRY] Initialized via fallback at 100% sampling")
        else:
            logger.info("[SENTRY] No SENTRY_DSN in env — running without Sentry")
except Exception as _se:
    logger.warning(f"[SENTRY] Init failed (non-blocking): {_se}")

