@app.get("/atlas-login", response_class=HTMLResponse)
async def login_page():
    return HTMLResponse(_LOGIN_PAGE_HTML)

@app.post("/api/auth/login")
async def auth_login(request: Dict = Body(...)):
    pw = request.get("password", "")
    if pw == _ATLAS_PASSWORD:
        return {"success": True, "token": _ATLAS_AUTH_TOKEN}
    return {"success": False, "error": "Invalid password"}

@app.middleware("http")
async def password_gate(request: Request, call_next):
    path = request.url.path
    # Skip auth for login page and login API
    if path in _AUTH_OPEN_PATHS or path.startswith("/api/auth/"):
        return await call_next(request)
    # Skip auth for localhost (local dev)
    client_host = request.client.host if request.client else ""
    if client_host in ("127.0.0.1", "::1", "localhost"):
        return await call_next(request)
    # Check cookie
    token = request.cookies.get("atlas_auth", "")
    if token == _ATLAS_AUTH_TOKEN:
        return await call_next(request)
    # Not authenticated
    # V18.1: API calls get 401 JSON (so fetch() can handle it), browser pages get redirect
    if path.startswith("/api/"):
        from starlette.responses import JSONResponse
        return JSONResponse({"success": False, "error": "Authentication required", "redirect": "/atlas-login"}, status_code=401)
    from starlette.responses import RedirectResponse
    return RedirectResponse("/atlas-login", status_code=302)


