# =============================================================================
# V17.3: AAA DATA TRUTH LAYER
# Schema versioning, run manifest, runtime contract
# =============================================================================
ATLAS_SCHEMA_VERSION = "22.0.0"

def stamp_metadata(data: dict, action: str = "unknown") -> dict:
    """Add AAA metadata stamps to any canonical file before persist."""
    data["_schema_version"] = ATLAS_SCHEMA_VERSION
    data["_project_version"] = data.get("_project_version", 0) + 1
    data["_generated_by"] = f"atlas-orchestrator/{ATLAS_SCHEMA_VERSION}"
    data["_timestamp"] = datetime.now().isoformat()
    data["_last_action"] = action
    return data

def append_run_manifest(project_path: Path, entry: dict):
    """Append to run_manifest.json — every generation run is logged and diffable."""
    manifest_path = project_path / "run_manifest.json"
    manifest = []
    if manifest_path.exists():
        try:
            with open(manifest_path) as f:
                manifest = json.load(f)
        except Exception:
            manifest = []
    entry["_timestamp"] = datetime.now().isoformat()
    entry["_schema_version"] = ATLAS_SCHEMA_VERSION
    entry["_trace_id"] = f"RUN-{_uuid.uuid4().hex[:8].upper()}"
    manifest.append(entry)
    # Keep last 500 entries
    manifest = manifest[-500:]
    with open(manifest_path, 'w') as f:
        json.dump(manifest, f, indent=2)
    return entry["_trace_id"]

def get_or_create_runtime_contract(project_path: Path, story_bible: dict = None) -> dict:
    """Load or create runtime_contract.json — minutes always right."""
    contract_path = project_path / "runtime_contract.json"
    if contract_path.exists():
        try:
            with open(contract_path) as f:
                return json.load(f)
        except Exception:
            pass
    # Build from story_bible or shot_plan
    target_seconds = 0
    scene_allocations = {}
    if story_bible:
        scenes = story_bible.get("scenes", [])
        for scene in scenes:
            sid = scene.get("scene_id", scene.get("id", "?"))
            dur = scene.get("estimated_duration_seconds", 180)
            scene_allocations[str(sid)] = {"target_seconds": dur, "min_seconds": max(60, dur // 2)}
            target_seconds += dur
    contract = {
        "_schema_version": ATLAS_SCHEMA_VERSION,
        "_generated_by": f"atlas-orchestrator/{ATLAS_SCHEMA_VERSION}",
        "_timestamp": datetime.now().isoformat(),
        "target_seconds": target_seconds,
        "target_minutes": round(target_seconds / 60, 1),
        "scene_allocations": scene_allocations,
        "dialogue_protected": True,
        "min_dialogue_beat_seconds": 8,
        "max_shot_seconds": 60,
        "internal_unit": "seconds",
        "display_unit": "minutes"
    }
    with open(contract_path, 'w') as f:
        json.dump(contract, f, indent=2)
    logger.info(f"[RUNTIME-CONTRACT] Created: {target_seconds}s ({round(target_seconds/60,1)}m)")
    return contract


