def slugify_identifier(raw: str) -> str:
    """Convert a free-form label into an uppercase slug suitable for matching."""
    if not raw:
        return ""
    return re.sub(r"[^A-Z0-9]+", "_", raw.upper()).strip("_")


def load_story_bible_characters() -> Dict[str, Dict[str, Any]]:
    """Return character definitions from every story bible."""
    characters: Dict[str, Dict[str, Any]] = {}
    for bible_path in BASE_DIR.glob("*story_bible*.json"):
        try:
            with open(bible_path) as handle:
                data = json.load(handle)
        except (OSError, json.JSONDecodeError):
            continue

        project_title = data.get("title") or bible_path.stem.replace("_", " ").title()
        for character in data.get("characters", []):
            slug = slugify_identifier(character.get("name", ""))
            if not slug:
                continue
            characters[slug] = {
                "name": character.get("name", slug.replace("_", " ").title()),
                "project": project_title,
                "description": character.get("description", ""),
                "visual_markers": character.get("visual_markers", {}),
                "bible_path": bible_path.name,
            }
    return characters


def load_story_project_details() -> Dict[str, Dict[str, Any]]:
    """
    Build a catalogue of projects → episodes → scenes from completed manifests.
    Ensures gallery dropdowns surface scenes even before renders exist.
    """
    projects: Dict[str, Dict[str, Any]] = {}
    for manifest_path in BASE_DIR.glob("*EPISODE*_COMPLETE.json"):
        try:
            with open(manifest_path) as handle:
                manifest = json.load(handle)
        except (OSError, json.JSONDecodeError):
            continue

        project_name = (
            manifest.get("project_title")
            or manifest.get("series_title")
            or manifest.get("project")
        )

        story_bible_ref = manifest.get("story_bible_reference")
        if not project_name and story_bible_ref:
            bible_candidate = BASE_DIR / story_bible_ref
            if bible_candidate.exists():
                try:
                    with open(bible_candidate) as bible_handle:
                        bible_data = json.load(bible_handle)
                        project_name = bible_data.get("title")
                except (OSError, json.JSONDecodeError):
                    pass

        if not project_name:
            project_name = manifest_path.stem.split("_EPISODE")[0].replace("_", " ").title()

        episode_number = manifest.get("episode_number")
        episode_title = manifest.get("episode_title")
        if episode_number is not None:
            try:
                episode_index = int(episode_number)
                episode_label = f"EP{episode_index:02d}"
            except (TypeError, ValueError):
                episode_label = str(episode_number)
        else:
            episode_label = ""

        if episode_title:
            episode_label = f"{episode_label} – {episode_title}" if episode_label else episode_title
        elif not episode_label:
            episode_label = manifest_path.stem

        entry = projects.setdefault(
            project_name,
            {"scenes": set(), "episodes": set(), "scene_details": {}},
        )
        entry["episodes"].add(episode_label)

        for scene in manifest.get("scenes", []):
            scene_id = scene.get("scene_id")
            if not scene_id:
                continue
            entry["scenes"].add(scene_id)
            entry["scene_details"][scene_id] = {
                "scene_id": scene_id,
                "scene_title": scene.get("scene_title"),
                "episode": episode_label,
                "scene_number": scene.get("scene_number"),
            }
    return projects


def discover_cast_entries() -> List[Dict[str, Any]]:
    """
    Discover available cast headshots by aligning story bible characters with
    reference renders on disk.
    """
    story_characters = load_story_bible_characters()
    discovered: Dict[str, Dict[str, Any]] = {}

    search_targets = [
        ("blackwood", BLACKWOOD_OUTPUT_DIR),
        ("nano_banana", ASSET_DIR),
        ("character_library", CHARACTER_DIR),
    ]

    for root_key, root_path in search_targets:
        if not root_path.exists():
            continue
        for image_path in root_path.rglob("*LOCKED_REFERENCE*.jpg"):
            slug = slugify_identifier(image_path.stem.replace("_LOCKED_REFERENCE", ""))
            if slug not in story_characters:
                continue
            entry = discovered.setdefault(slug, {"images": []})
            try:
                relative_path = image_path.relative_to(root_path)
            except ValueError:
                continue
            entry["images"].append(
                {
                    "root": root_key,
                    "relative_path": relative_path.as_posix(),
                    "full_path": str(image_path),
                }
            )

    cast_entries: List[Dict[str, Any]] = []
    for slug, character in story_characters.items():
        image_record = discovered.get(slug, {}).get("images", [])
        image_url = None
        image_status = "missing"
        source_path = None
        if image_record:
            # Prefer locked library (stable), fall back to newest output.
            priority_order = {"character_library": 0, "blackwood": 1, "nano_banana": 2}
            chosen = sorted(
                image_record,
                key=lambda item: priority_order.get(item["root"], 99)
            )[0]
            encoded_path = urllib.parse.quote(chosen["relative_path"])
            image_url = f"/api/gallery/cast/image?root={chosen['root']}&path={encoded_path}"
            image_status = "available"
            source_path = chosen["full_path"]

        cast_entries.append(
            {
                "name": character["name"],
                "project": character["project"],
                "description": character.get("description", ""),
                "visual_markers": character.get("visual_markers", {}),
                "image_url": image_url,
                "image_status": image_status,
                "source_file": source_path,
            }
        )

    cast_entries.sort(key=lambda item: (item["project"], item["name"]))
    return cast_entries


def build_shot_payload(manager: RenderGalleryManager, shot_id: str, order_index: Optional[int] = None) -> Dict:
    shot_entry = manager.get_shot(shot_id)
    if not shot_entry:
        return {}
    metadata_path = shot_entry.get('metadata', {}).get('metadata_path')
    meta = manager.load_image_metadata(shot_id)
    if meta and meta.get('image_url'):
        meta['image_url'] = f"{meta['image_url']}?t={shot_entry.get('timestamp') or datetime.utcnow().isoformat()}"
    image_path = shot_entry.get('image_path')
    video_path = shot_entry.get('video_path')
    timestamp = shot_entry.get('timestamp') or datetime.utcnow().isoformat()
    media_name = Path(image_path).name if image_path else None
    video_name = Path(video_path).name if video_path else None
    cache_token = f"?t={timestamp}"
    return {
        "shot_id": shot_id,
        "order_index": order_index,
        "status": shot_entry.get('status'),
        "scene_id": shot_entry.get('scene_id'),
        "project": shot_entry.get('project') or (meta or {}).get("project"),
        "timestamp": shot_entry.get('timestamp'),
        "image_path": image_path,
        "image_media_url": f"/media/{media_name}{cache_token}" if media_name else None,
        "video_path": video_path,
        "video_media_url": f"/media/{video_name}{cache_token}" if video_name else None,
        "metadata_path": metadata_path,
        "metadata": meta,
        "script_line": (meta or {}).get("dialogue_text")
    }


async def launch_parallel_run(mode: str, shots: List[str], force_regen: bool = False, scene_id: str = "004") -> str:
    if mode not in {"images", "videos"}:
        raise ValueError("mode must be 'images' or 'videos'")
    run_id = str(uuid.uuid4())[:8]
    cmd = ["python3", "run_scene_004_PARALLEL.py"]
    if mode == "images":
        if force_regen:
            cmd.append("--force-regenerate")
        cmd.append("--images-only")
    else:
        cmd.append("--videos-only")

    if mode == "videos" and shots:
        manager = refresh_gallery_state()
        scene_total = 0.0
        for shot_id in manager.tracking['shots'].keys():
            meta = manager.load_image_metadata(shot_id)
            if meta:
                scene_total += float(meta.get("video_cost_total_usd", 0.0))
        projected = scene_total + len(shots) * VIDEO_COST_USD
        if projected > BUDGET_USD:
            raise ValueError(f"Budget exceeded: projected ${projected:.2f} > limit ${BUDGET_USD:.2f}")
    if shots:
        cmd += ["--shots", ",".join(shots)]

    log_lines: List[str] = []
    active_runs[run_id] = {
        "mode": mode,
        "shots": shots,
        "scene_id": scene_id,
        "status": "running",
        "started_at": datetime.now().isoformat(),
        "log": log_lines
    }

    async def reader(proc):
        try:
            while True:
                line = await proc.stdout.readline()
                if not line:
                    break
                text = line.decode(errors='ignore').rstrip()
                log_lines.append(text)
                if len(log_lines) > 200:
                    del log_lines[:-200]
        finally:
            returncode = await proc.wait()
            active_runs[run_id]["returncode"] = returncode
            active_runs[run_id]["finished_at"] = datetime.now().isoformat()
            active_runs[run_id]["status"] = "completed" if returncode == 0 else "failed"
            refresh_gallery_state()

    proc = await asyncio.create_subprocess_exec(
        *cmd,
        cwd=str(BASE_DIR),
        stdout=asyncio.subprocess.PIPE,
        stderr=asyncio.subprocess.STDOUT
    )

    asyncio.create_task(reader(proc))
    return run_id


def _load_scene_manifest(scene_id: str) -> Optional[Dict]:
    candidates = [
        MANIFEST_DIR / f"marcus_scene_{scene_id}_dialogue.json",
        MANIFEST_DIR / f"marcus_scene_{scene_id}_manifest.json",
    ]
    for path in candidates:
        if path.exists():
            try:
                return json.loads(path.read_text())
            except json.JSONDecodeError as exc:
                logger.warning(f"⚠️  Failed to decode manifest {path}: {exc}")
    return None


SCENE_REHYDRATE_CARRYOVER_FIELDS: Set[str] = {
    "ai_actor_cast",
    "character_reference_url",
    "location_master_url",
    "wardrobe_reference_url",
    "extras_reference_url",
    "grid_location_hint",
    "project",
    "quality_anchor",
    "use_pro_model",
    "use_asset_grid",
    "reference_assets",
    "wardrobe_notes",
    "extras_notes",
    "sound_cues",
    "props",
    # V27.6: Beat enrichment fields — IMMUTABLE after beat_enrichment.py runs
    "_beat_enriched",
    "_beat_ref",
    "_beat_index",
    "_beat_description",
    "_beat_action",
    "_beat_dialogue",
    "_beat_atmosphere",
    "_eye_line_target",
    "_body_direction",
    "_cut_motivation",
}


def _rehydrate_shots_from_scene_manifest(shot_plan: Dict) -> Tuple[bool, int]:
    """
    V21.9: BIDIRECTIONAL sync between shots[] and scenes[].

    Direction depends on which is more authoritative:
    - If scenes[] was explicitly marked dirty (_scenes_dirty=True), rebuild shots[] from scenes[].
    - Otherwise, sync scenes[] FROM shots[] (the hand-fixed authoritative source).

    This prevents the destructive case where stale scenes[] overwrites carefully
    fixed shots[] data (e.g., Scene 010 rewrite from 31→11 shots, character fixes).
    """
    scenes = shot_plan.get("scenes") or []
    shots = shot_plan.get("shots") or []

    if not isinstance(scenes, list) or not scenes:
        return False, 0
    if not isinstance(shots, list) or not shots:
        return False, 0

    # Only rebuild shots[] from scenes[] if explicitly marked
    if shot_plan.get("_scenes_dirty"):
        # Forward direction: scenes → shots (when scenes were intentionally edited)
        existing_by_id = {
            s.get("shot_id"): s for s in shots
            if isinstance(s, dict) and s.get("shot_id")
        }
        rehydrated: List[Dict] = []
        for scene in scenes:
            if not isinstance(scene, dict):
                continue
            scene_shots = scene.get("shots") or []
            if not scene_shots:
                continue
            scene_id = scene.get("scene_id")
            scene_location = scene.get("location")
            scene_time = scene.get("time_of_day")
            for shot in scene_shots:
                if not isinstance(shot, dict):
                    continue
                shot_copy = copy.deepcopy(shot)
                if scene_id:
                    shot_copy["scene_id"] = shot_copy.get("scene_id") or scene_id
                if scene_location:
                    shot_copy["location"] = scene_location
                if scene_time and not shot_copy.get("time_of_day"):
                    shot_copy["time_of_day"] = scene_time
                existing = existing_by_id.get(shot_copy.get("shot_id"))
                if existing:
                    for key in SCENE_REHYDRATE_CARRYOVER_FIELDS:
                        if key in existing and key not in shot_copy:
                            shot_copy[key] = existing[key]
                    # V27.6: If beat-enriched, carry ALL _beat_* fields (immutability protection)
                    if existing.get("_beat_enriched"):
                        for key, val in existing.items():
                            if key.startswith("_beat_") or key in ("_eye_line_target", "_body_direction", "_cut_motivation"):
                                shot_copy[key] = val
                rehydrated.append(shot_copy)
        if rehydrated:
            shot_plan["shots"] = rehydrated
            shot_plan.pop("_scenes_dirty", None)
            shot_plan["_rehydrated_from_scenes"] = True
            return True, len(rehydrated)
        return False, 0

    # Reverse direction: shots[] → scenes[] (default — keep scenes in sync)
    # Group shots by scene_id prefix and update scenes[].shots
    shots_by_scene: Dict[str, List[Dict]] = {}
    for shot in shots:
        if not isinstance(shot, dict):
            continue
        sid = shot.get("shot_id", "")[:3]
        shots_by_scene.setdefault(sid, []).append(shot)

    synced = 0
    for scene in scenes:
        if not isinstance(scene, dict):
            continue
        scene_id = scene.get("scene_id", "")
        matching_shots = shots_by_scene.get(scene_id, [])
        if matching_shots:
            scene["shots"] = matching_shots
            synced += len(matching_shots)

    if synced > 0:
        shot_plan["_scenes_synced_from_shots"] = True
        return True, synced
    return False, 0


def _format_dialogue(entry) -> str:
    if isinstance(entry, dict):
        speaker = entry.get("character", "narrator")
        speaker_name = speaker.replace("_", " ").title()
        line = entry.get("line", "").strip()
        return f"{speaker_name}: {line}" if line else speaker_name
    if isinstance(entry, str):
        return entry.strip()
    return ""


def build_scene_overview(scene_id: str) -> Optional[Dict]:
    manifest = _load_scene_manifest(scene_id)
    if not manifest:
        return None

    shots = []
    for shot in manifest.get("shots", []):
        shot_id = shot.get("shot_id", "unknown")
        duration = shot.get("duration")
        description = shot.get("description", "")
        dialogue_entries = shot.get("dialogue", [])
        if isinstance(dialogue_entries, dict):
            dialogue_entries = [dialogue_entries]
        dialogue_lines = [line for line in map(_format_dialogue, dialogue_entries) if line]
        audio_note = shot.get("audio_note")

        video_path = ASSET_DIR / f"{shot_id}.mp4"
        image_path = ASSET_DIR / f"{shot_id}.jpg"

        shots.append({
            "shot_id": shot_id,
            "description": description,
            "duration": duration,
            "dialogue": dialogue_entries,
            "dialogue_lines": dialogue_lines,
            "audio_note": audio_note,
            "video_url": f"/media/{shot_id}.mp4" if video_path.exists() else None,
            "image_url": f"/media/{shot_id}.jpg" if image_path.exists() else None,
            "camera_angle": shot.get("camera_angle"),
        })

    return {
        "scene_id": scene_id,
        "title": manifest.get("scene_title", f"Scene {scene_id}"),
        "description": manifest.get("description", ""),
        "location": manifest.get("location", {}),
        "shots": shots,
    }


def build_character_gallery() -> List[Dict]:
    gallery: List[Dict] = []
    if not CHARACTER_DIR.exists():
        return gallery

    for file in sorted(CHARACTER_DIR.glob("*")):
        if file.suffix.lower() not in {".jpg", ".jpeg", ".png", ".gif"}:
            continue
        name = file.stem.replace("_", " ").title()
        gallery.append({
            "name": name,
            "image_url": f"/characters/{file.name}",
        })
    return gallery


def build_project_overview() -> Dict:
    scenes: List[Dict] = []
    for scene_id in SCENE_ORDER:
        overview = build_scene_overview(scene_id)
        if overview:
            scenes.append(overview)

    return {
        "scenes": scenes,
        "characters": build_character_gallery(),
        "timestamp": datetime.utcnow().isoformat(),
    }


