# =============================================================================
# V16.7 CANONICAL MEDIA KEY SYSTEM
# =============================================================================
# All media URLs should use /assets/<key> format
# Key format: projects/<project>/<type>/<filename>
# Types: headshots, locations, first_frames, videos, misc

MEDIA_TYPE_MAP = {
    '.jpg': 'image/jpeg',
    '.jpeg': 'image/jpeg',
    '.png': 'image/png',
    '.gif': 'image/gif',
    '.webp': 'image/webp',
    '.mp4': 'video/mp4',
    '.mov': 'video/quicktime',
    '.webm': 'video/webm',
}

def resolve_media_key(key: str) -> Optional[Path]:
    """
    V16.7: Resolve a media key to a local file path.
    Key format: projects/<project>/<type>/<filename>
    V16.7.1: Added path traversal protection.
    """
    # V16.7.1: Block path traversal attempts
    if ".." in key or key.startswith("/"):
        logger.warning(f"[SECURITY] Blocked path traversal attempt: {key}")
        return None

    # V16.7.1: Only allow media file extensions
    ALLOWED_EXTENSIONS = {'.jpg', '.jpeg', '.png', '.gif', '.webp', '.mp4', '.mov', '.webm'}
    key_ext = Path(key).suffix.lower()
    if key_ext and key_ext not in ALLOWED_EXTENSIONS:
        logger.warning(f"[SECURITY] Blocked non-media extension: {key}")
        return None

    parts = key.split("/")

    # Handle projects/<project>/<type>/<filename> format
    if len(parts) >= 4 and parts[0] == "projects":
        project = parts[1]
        media_type = parts[2]
        filename = "/".join(parts[3:])

        # Type to directory mapping
        type_dirs = {
            "headshots": [
                BASE_DIR / "ai_actor_headshots",
                PIPELINE_OUTPUTS_DIR / project / "headshots",
            ],
            "locations": [
                PIPELINE_OUTPUTS_DIR / project / "locations",
                PIPELINE_OUTPUTS_DIR / project / "location_masters",
            ],
            "first_frames": [
                PIPELINE_OUTPUTS_DIR / project / "first_frames",
                BASE_DIR / "fal_cache" / project,
            ],
            "videos": [
                PIPELINE_OUTPUTS_DIR / project / "videos",
                BASE_DIR / "fal_cache" / project,
            ],
            "misc": [
                PIPELINE_OUTPUTS_DIR / project,
            ],
        }

        for search_dir in type_dirs.get(media_type, []):
            file_path = (search_dir / filename).resolve()
            # V16.7.1: Verify file is within allowed directory
            try:
                file_path.relative_to(search_dir.resolve())
                if file_path.exists():
                    return file_path
            except ValueError:
                logger.warning(f"[SECURITY] File escaped allowed directory: {file_path}")
                continue

        return None

    # Fallback: try as direct path under pipeline_outputs (media only)
    direct_path = (PIPELINE_OUTPUTS_DIR / key).resolve()
    try:
        direct_path.relative_to(PIPELINE_OUTPUTS_DIR.resolve())
        if direct_path.exists() and direct_path.suffix.lower() in ALLOWED_EXTENSIONS:
            return direct_path
    except ValueError:
        pass

    # Fallback: try under fal_cache
    fal_path = BASE_DIR / "fal_cache" / key
    if fal_path.exists():
        return fal_path

    return None


def to_asset_url(file_path: str, project: str = None, asset_type: str = "misc") -> str:
    """
    V16.7: Convert a file path to canonical /assets/<key> URL.
    """
    if not file_path:
        return ""

    path = Path(file_path) if isinstance(file_path, str) else file_path

    # If it's already an asset URL, return as-is
    if isinstance(file_path, str) and file_path.startswith("/assets/"):
        return file_path

    # Try to extract project from path
    if not project:
        if "pipeline_outputs" in str(path):
            parts = str(path).split("pipeline_outputs/")
            if len(parts) > 1:
                project = parts[1].split("/")[0]
        elif "fal_cache" in str(path):
            parts = str(path).split("fal_cache/")
            if len(parts) > 1:
                project = parts[1].split("/")[0]

    if project:
        filename = path.name
        return f"/assets/projects/{project}/{asset_type}/{filename}"

    # Fallback to /api/media?path= for unknown paths
    return f"/api/media?path={file_path}"


@app.get("/assets/{key:path}")
async def get_asset_by_key(key: str):
    """
    V16.7: Canonical media endpoint using keys.
    V18.0: Uses R2 for cloud storage (GCS removed).
    Key format: projects/<project>/<type>/<filename>

    Examples:
      /assets/projects/casino_escape/headshots/MAYA_CHEN_HEADSHOT.jpg
      /assets/projects/Ravencroft_V6_upload/locations/GRAND_HALL.jpg
      /assets/projects/casino_escape/first_frames/001_000A.jpg
    """
    # 1. Try local file first
    file_path = resolve_media_key(key)
    if file_path and file_path.exists():
        suffix = file_path.suffix.lower()
        media_type = MEDIA_TYPE_MAP.get(suffix)
        return FileResponse(str(file_path), media_type=media_type)

    # 2. V18.0: Try R2 public URL redirect (GCS removed)
    if R2_ENABLED and R2_PUBLIC_URL:
        r2_url = f"{R2_PUBLIC_URL.rstrip('/')}/{R2_PREFIX}/{key}"
        from starlette.responses import RedirectResponse
        return RedirectResponse(url=r2_url, status_code=302)

    return JSONResponse({"error": "Asset not found", "key": key}, status_code=404)


@app.post("/api/v16/assets/preload")
async def preload_assets(request: Dict = Body(...)):
    """
    V18.0: Preload assets to R2 (legacy endpoint — redirected to R2).
    Body: {"project": "optional_project_name"}
    Recommended: Use POST /api/v18/r2/sync instead.
    """
    project = request.get("project")
    if not R2_ENABLED:
        return {"success": False, "error": "R2 not configured — use /api/v18/r2/sync or set ATLAS_R2_* env vars"}
    if project:
        return r2_sync_project_media(project)
    return {"success": False, "error": "Specify project — use POST /api/v18/r2/sync for full sync"}


@app.get("/api/v16/contracts/verify/{project}")
async def verify_contracts(project: str):
    """
    V16.7: Verify all 5 contract invariants for a project.
    Returns PASS/FAIL for each invariant.
    """
    project_path = get_project_path(project)
    results = {
        "project": project,
        "invariants": {},
        "all_passed": True
    }

    # 1. Media URLs are canonical (/assets/ or /api/media)
    cast_map_path = project_path / "cast_map.json"
    if cast_map_path.exists():
        with open(cast_map_path) as f:
            cast_map = json.load(f)
        bad_urls = []
        for char, data in cast_map.items():
            if char.startswith("_"):
                continue
            url = data.get("headshot_url", "") if isinstance(data, dict) else ""
            if url and not url.startswith("/assets/") and not url.startswith("/api/media"):
                bad_urls.append(f"{char}: {url[:50]}")
        results["invariants"]["media_urls_canonical"] = {
            "passed": len(bad_urls) == 0,
            "detail": f"{len(bad_urls)} non-canonical URLs" if bad_urls else "All URLs canonical"
        }
    else:
        results["invariants"]["media_urls_canonical"] = {"passed": True, "detail": "No cast_map"}

    # 2. Casting panel reads from bundle (can't verify from server, just check bundle exists)
    bundle_exists = (project_path / "cast_map.json").exists()
    results["invariants"]["casting_from_bundle"] = {
        "passed": bundle_exists,
        "detail": "cast_map.json exists" if bundle_exists else "No cast_map.json"
    }

    # 3. Segments normalized in shots
    shot_plan_path = project_path / "shot_plan.json"
    if shot_plan_path.exists():
        with open(shot_plan_path) as f:
            shot_plan = _sp_guard(json.load(f))
        shots = shot_plan.get("shots", shot_plan) if isinstance(shot_plan, dict) else shot_plan
        extended_without_segments = []
        for shot in shots:
            dur = shot.get("duration_seconds", shot.get("duration", 0))
            has_segments = bool(shot.get("segments")) or bool(shot.get("render_plan", {}).get("segments"))
            if dur > 20 and not has_segments:
                extended_without_segments.append(shot.get("shot_id", "?"))
        results["invariants"]["segments_normalized"] = {
            "passed": len(extended_without_segments) == 0,
            "detail": f"{len(extended_without_segments)} extended shots missing segments" if extended_without_segments else "All extended shots have segments"
        }
    else:
        results["invariants"]["segments_normalized"] = {"passed": False, "detail": "No shot_plan.json"}

    # 4. Project name consistency
    results["invariants"]["project_name_consistent"] = {
        "passed": project_path.exists(),
        "detail": f"Project folder exists at {project_path}" if project_path.exists() else "Project not found"
    }

    # 5. Autopilot idempotent (can't fully verify, just check key files exist)
    required_files = ["shot_plan.json", "story_bible.json"]
    missing = [f for f in required_files if not (project_path / f).exists()]
    results["invariants"]["autopilot_ready"] = {
        "passed": len(missing) == 0,
        "detail": f"Missing: {missing}" if missing else "All required files present"
    }

    # Overall pass/fail
    results["all_passed"] = all(inv["passed"] for inv in results["invariants"].values())

    return results


# =============================================================================
# V16.7.1 QA ANALYSIS & REGENERATION (Closed-Loop)
# =============================================================================

@app.post("/api/v16/qa/analyze")
async def qa_analyze_shot(request: Dict = Body(...)):
    """
    V16.7.1: Analyze a shot/scene and return patch suggestions.
    Uses heuristic analysis (coverage, blocking, prompt quality).
    Schema designed for future DINO/CLIP/BLIP integration.
    """
    project = request.get("project")
    scope = request.get("scope", "shot")  # "shot" or "scene"
    shot_id = request.get("shot_id")
    scene_id = request.get("scene_id")
    mode = request.get("mode", "heuristic")  # "heuristic" or "vision+cine"

    if not project:
        return {"success": False, "error": "project required"}

    project_path = get_project_path(project)
    shot_plan_path = project_path / "shot_plan.json"

    if not shot_plan_path.exists():
        return {"success": False, "error": f"Project '{project}' not found"}

    with open(shot_plan_path) as f:
        data = json.load(f)

    # V27.1: Handle both list format [shots...] and dict format {"shots": [...]}
    if isinstance(data, list):
        shots = data
        data = {"shots": data}
    else:
        shots = data.get("shots", [])

    # Find target shot(s)
    if scope == "shot" and shot_id:
        target_shots = [s for s in shots if s.get("shot_id") == shot_id]
    elif scope == "scene" and scene_id:
        target_shots = [s for s in shots if s.get("scene_id") == scene_id]
    else:
        return {"success": False, "error": "shot_id or scene_id required"}

    if not target_shots:
        return {"success": False, "error": f"No shots found for {scope}={shot_id or scene_id}"}

    # Analyze each shot
    results = []
    for shot in target_shots:
        sid = shot.get("shot_id", "?")
        nano = shot.get("nano_prompt", "")
        ltx = shot.get("ltx_motion_prompt", "")
        shot_type = shot.get("type", shot.get("shot_type", "medium"))
        duration = shot.get("duration", shot.get("duration_seconds", 10))
        chars = shot.get("characters", [])

        issues = []
        patch = {"shot_id": sid}

        # Check blocking (verbs like enter/turn/grab/lean)
        blocking_verbs = ["enter", "turn", "grab", "lean", "reach", "step", "move", "walk", "run", "sit", "stand"]
        has_blocking = any(v in nano.lower() for v in blocking_verbs)
        if not has_blocking:
            issues.append("no blocking verbs (enter/turn/grab/lean)")
            patch["nano_prompt_delta"] = "ADD: blocking action (character enters/turns/reaches)"

        # Check eye-line
        eyeline_words = ["look", "gaze", "eye", "stare", "watch", "glance"]
        has_eyeline = any(w in nano.lower() for w in eyeline_words)
        if not has_eyeline and chars:
            issues.append("no eye-line direction")
            if "nano_prompt_delta" in patch:
                patch["nano_prompt_delta"] += ", eye-line direction"
            else:
                patch["nano_prompt_delta"] = "ADD: eye-line direction"

        # Check coverage type
        coverage_tags = ["MASTER", "OTS", "SINGLE", "INSERT", "REACTION", "ECU", "CU", "MS", "WS"]
        has_coverage_tag = any(tag in nano.upper() for tag in coverage_tags)
        if not has_coverage_tag:
            # Suggest based on shot_type
            suggested = "MASTER" if shot_type in ["wide", "establishing"] else "MS"
            if shot_type in ["close", "closeup", "cu"]:
                suggested = "CU"
            patch["recommended_shot_type"] = suggested
            issues.append(f"no coverage tag (suggest: {suggested})")

        # Check LTX motion quality
        has_stability = False  # V17.3: Initialize before conditional to prevent UnboundLocalError
        if ltx:
            stability_words = ["stable", "face stable", "no morphing", "consistent"]
            has_stability = any(w in ltx.lower() for w in stability_words)
            if chars and not has_stability:
                issues.append("LTX missing face stability clause")
                patch["ltx_motion_delta"] = "ADD: face stable, no morphing, identity consistent"

            # Check duration marker
            if f"{duration}s" not in ltx:
                issues.append(f"LTX duration marker mismatch (should be {duration}s)")

        # Check first frame exists
        first_frame_path = project_path / "first_frames" / f"{sid}.jpg"
        has_first_frame = first_frame_path.exists()

        # V17 FIX: Add vision scores when mode="vision+cine" and frame exists
        vision_scores = {}
        if mode == "vision+cine" and has_first_frame:
            try:
                from dino_clip_analyzer import get_hybrid_analyzer
                v_analyzer = get_hybrid_analyzer()

                # Get character reference
                char_ref_url = shot.get("character_reference_url")
                if not char_ref_url and chars:
                    # Cast_map fallback
                    cm_path = project_path / "cast_map.json"
                    if cm_path.exists():
                        with open(cm_path) as cmf:
                            cm = json.load(cmf)
                        c_name = chars[0] if isinstance(chars[0], str) else chars[0].get("name", "")
                        c_entry = cm.get(c_name) or cm.get(c_name.upper())
                        if c_entry and isinstance(c_entry, dict):
                            # V17.7: Try locked reference first
                            _actor = c_entry.get("ai_actor", "")
                            if _actor:
                                _afn = _actor.upper().replace(" ", "_") + "_LOCKED_REFERENCE.jpg"
                                _lp = BASE_DIR / "character_library_locked" / "ai_actors" / _afn
                                if _lp.exists():
                                    char_ref_url = f"/api/media?path={_lp}"
                            if not char_ref_url:
                                char_ref_url = c_entry.get("character_reference_url") or c_entry.get("reference_url")

                if char_ref_url:
                    ref_path = char_ref_url.split("path=")[-1] if "path=" in char_ref_url else char_ref_url
                    if Path(ref_path).exists():
                        v_result = v_analyzer.analyze_comprehensive(str(first_frame_path), ref_path, nano)
                        vision_scores = {
                            "face_consistency": round(v_result.get("dino_face", 0), 3),
                            "hybrid_score": round(v_result.get("hybrid_score", 0), 3),
                            "clip_alignment": round(v_result.get("clip_alignment", 0), 3),
                            "face_sharpness": round(v_result.get("face_sharpness", 0), 3),
                            "is_blurred": v_result.get("is_face_blurred", False),
                            "needs_regen": v_result.get("dino_face", 0) < 0.70 or v_result.get("is_face_blurred", False)
                        }
                        if vision_scores["needs_regen"]:
                            issues.append(f"VISION: face consistency {vision_scores['face_consistency']:.0%} below 70% threshold")
                            patch["vision_regen"] = True
                    else:
                        vision_scores = {"error": "reference_not_found"}
                else:
                    vision_scores = {"error": "no_character_reference"}
            except ImportError:
                vision_scores = {"error": "dino_clip_analyzer_not_available"}
            except Exception as ve:
                vision_scores = {"error": str(ve)}

        # V17.5.2: Run blocking intelligence for richer scores
        try:
            blocking_detail = _analyze_blocking_intelligence([shot], {})[0]
            blocking_score = blocking_detail["blocking_score"]
            blocking_components = blocking_detail["components"]
        except Exception:
            blocking_score = 1.0 if has_blocking else 0.3
            blocking_components = {}

        results.append({
            "shot_id": sid,
            "has_first_frame": has_first_frame,
            "patch": patch if issues else None,
            "why": issues,
            "risk_flags": ["identity_drift"] if not has_stability and chars else [],
            "scores": {
                "blocking": round(blocking_score, 3),
                "eyeline": 1.0 if has_eyeline else 0.5,
                "coverage": 1.0 if has_coverage_tag else 0.4,
                "ltx_quality": 0.8 if ltx and has_stability else 0.5
            },
            "blocking_detail": blocking_components,
            "vision_scores": vision_scores if vision_scores else None
        })

    # V17.5.2: Include viewership data for scene-scope analysis
    viewership_data = None
    if scope == "scene" and len(target_shots) >= 2:
        try:
            viewership_data = _analyze_viewership_intelligence(target_shots)
        except Exception:
            pass

    return {
        "success": True,
        "project": project,
        "scope": scope,
        "mode": mode,
        "analysis": results[0] if len(results) == 1 else results,
        "patch": results[0].get("patch") if len(results) == 1 else None,
        "why": results[0].get("why", []) if len(results) == 1 else [],
        "viewership": viewership_data
    }


# =============================================================================
# V17.5.2 DIRECTOR ANALYSIS — Blocking Intelligence + Viewership Intelligence
# =============================================================================

def _analyze_blocking_intelligence(shots, cast_map, scene_beats_index=None):
    """
    V17.6: Stage blocking analysis — character positioning, movement, spatial relationships.
    Now enriched with story_bible beats for narrative-aware scoring.
    Returns per-shot blocking scores and scene-level blocking report.
    """
    scene_beats_index = scene_beats_index or {}
    results = []
    scene_shots = {}

    # Group shots by scene
    for s in shots:
        sid = s.get("shot_id", "")
        scene = sid[:3] if len(sid) >= 3 else "000"
        scene_shots.setdefault(scene, []).append(s)

    for shot in shots:
        sid = shot.get("shot_id", "")
        nano = shot.get("nano_prompt", "").lower()
        ltx = shot.get("ltx_motion_prompt", "").lower()
        combined = f"{nano} {ltx}"
        chars = shot.get("characters", [])
        shot_type = shot.get("type", shot.get("shot_type", "medium"))
        duration = shot.get("duration", 10)
        blocking_role = shot.get("blocking_role", "")
        eyeline_target = shot.get("eyeline_target", "")
        screen_dir = shot.get("screen_direction", "")

        # V17.6: Get story beat context for this shot
        scene_id_3 = sid[:3] if len(sid) >= 3 else "000"
        scene_data = scene_beats_index.get(scene_id_3, {})
        beat_id = shot.get("beat_id", "")
        intent_tags = shot.get("intent_tags", [])
        beat_text = shot.get("beat_text", shot.get("dialogue_text", ""))

        # Find matching beat from story_bible
        story_beat = {}
        if scene_data.get("beats"):
            beat_num = shot.get("beat_number", 0)
            for b in scene_data["beats"]:
                if b.get("beat_number") == beat_num:
                    story_beat = b
                    break

        # Enrich combined text with story beat description + dialogue
        story_context = ""
        if story_beat:
            story_context = f" {story_beat.get('description', '')} {story_beat.get('dialogue', '')} {story_beat.get('emotional_tone', '')}".lower()
        if beat_text:
            story_context += f" {beat_text}".lower()
        combined_enriched = f"{combined} {story_context}"

        issues = []
        score_components = {}

        # 1. CHARACTER POSITIONING — where are characters placed in frame?
        position_words = ["center", "left", "right", "foreground", "background",
                         "frame left", "frame right", "off-center", "silhouette",
                         "doorway", "window", "desk", "chair", "table", "bed"]
        has_position = any(w in combined_enriched for w in position_words)
        score_components["positioning"] = 1.0 if has_position else 0.3
        if not has_position and chars:
            issues.append("No character positioning (add: frame left/center/foreground)")

        # 2. MOVEMENT PATTERNS — purposeful character movement
        movement_verbs = ["enter", "exit", "cross", "approach", "retreat", "turn",
                         "lean", "reach", "gesture", "pace", "rise", "descend",
                         "collapse", "embrace", "push", "pull", "circle", "stop",
                         "step", "walk", "run", "stumble", "stagger", "spin"]
        movement_count = sum(1 for v in movement_verbs if v in combined_enriched)
        has_movement = movement_count >= 1
        # Long shots need more movement than short ones
        needs_movement = duration > 8 or shot_type in ["action", "wide", "establishing"]
        score_components["movement"] = min(1.0, 0.3 + movement_count * 0.25)
        if needs_movement and not has_movement:
            issues.append(f"Static {duration}s shot needs movement verb (enter/cross/approach/turn)")

        # 3. PROXEMICS — spatial relationships between characters
        proxemic_words = ["intimate", "close", "arm's length", "across the room",
                         "face to face", "side by side", "behind", "over shoulder",
                         "between", "crowded", "distance", "apart", "together",
                         "opposite", "confronting", "hovering"]
        has_proxemics = any(w in combined_enriched for w in proxemic_words)
        multi_char = len(chars) > 1
        score_components["proxemics"] = 1.0 if has_proxemics or not multi_char else 0.3
        if multi_char and not has_proxemics:
            issues.append("Multi-character shot needs spatial relationship (face to face/side by side/across)")

        # 4. ENTRANCE/EXIT LOGIC
        entrance_exit = ["enter", "exit", "arrive", "leave", "appear", "disappear",
                        "through door", "into room", "out of frame"]
        has_entrance = any(w in combined_enriched for w in entrance_exit)
        score_components["entrances"] = 1.0 if has_entrance else 0.6  # Not always needed

        # 5. EYELINE CONSISTENCY
        eyeline_words = ["look", "gaze", "stare", "watch", "glance", "eye",
                        "regard", "fixed on", "turn to", "face", "peer"]
        has_eyeline = any(w in combined_enriched for w in eyeline_words)
        has_eyeline_meta = bool(eyeline_target)
        score_components["eyeline"] = 1.0 if (has_eyeline or has_eyeline_meta) else (0.5 if not chars else 0.3)
        if chars and not has_eyeline and not has_eyeline_meta:
            issues.append("No eyeline direction (add: looks at/gazes toward/eyes fixed on)")

        # 6. SCREEN DIRECTION
        has_screen_dir = bool(screen_dir) or any(d in combined_enriched for d in ["screen left", "screen right", "camera left", "camera right"])
        score_components["screen_direction"] = 1.0 if has_screen_dir else 0.6

        # 7. PHYSICAL INTERACTION
        interaction_words = ["touch", "grab", "hold", "shake", "slap", "embrace",
                           "kiss", "push", "hand", "finger", "point", "gesture"]
        has_interaction = any(w in combined_enriched for w in interaction_words)
        # Only relevant for multi-character or dialogue shots
        if multi_char or shot.get("dialogue"):
            score_components["interaction"] = 1.0 if has_interaction else 0.5
        else:
            score_components["interaction"] = 0.8  # N/A

        # V17.6: NARRATIVE FIDELITY — does the shot match story beat intent?
        narrative_score = 0.5  # default
        if story_beat:
            beat_type = story_beat.get("beat_type", "")
            emotional_tone = story_beat.get("emotional_tone", "")
            # Check if shot type matches beat type expectations
            if beat_type == "establishing" and shot_type in ["establishing", "wide", "aerial"]:
                narrative_score = 1.0
            elif beat_type == "dialogue" and (shot.get("dialogue") or shot.get("dialogue_text")):
                narrative_score = 1.0
            elif beat_type == "action" and shot_type in ["action", "wide", "medium"]:
                narrative_score = 1.0
            elif beat_type:
                narrative_score = 0.6  # Beat exists but shot type doesn't perfectly match
            # Check emotional tone alignment
            if emotional_tone and emotional_tone.lower() in combined_enriched:
                narrative_score = min(1.0, narrative_score + 0.2)
        elif intent_tags:
            narrative_score = 0.7  # Has intent tags but no full beat

        score_components["narrative_fidelity"] = narrative_score

        # Composite blocking score — now includes narrative fidelity
        weights = {"positioning": 0.17, "movement": 0.17, "proxemics": 0.13,
                   "entrances": 0.08, "eyeline": 0.13, "screen_direction": 0.08,
                   "interaction": 0.09, "narrative_fidelity": 0.15}
        blocking_score = sum(score_components[k] * weights[k] for k in weights)

        results.append({
            "shot_id": sid,
            "blocking_score": round(blocking_score, 3),
            "components": {k: round(v, 2) for k, v in score_components.items()},
            "issues": issues,
            "blocking_role": blocking_role,
            "eyeline_target": eyeline_target,
            "screen_direction": screen_dir,
            "beat_id": beat_id,
            "intent_tags": intent_tags,
            "story_beat": story_beat.get("description", "") if story_beat else "",
        })

    return results


def _analyze_viewership_intelligence(shots, scene_beats_index=None):
    """
    V17.6: Audience engagement analysis — pacing, tension, variety, rhythm.
    Now enriched with story_bible beats for narrative-aware scoring.
    Returns scene-level viewership scores and per-scene reports.
    """
    scene_beats_index = scene_beats_index or {}
    scene_shots = {}
    for s in shots:
        sid = s.get("shot_id", "")
        scene = sid[:3] if len(sid) >= 3 else "000"
        scene_shots.setdefault(scene, []).append(s)

    scene_reports = {}
    for scene_id, s_shots in scene_shots.items():
        issues = []
        score_components = {}

        # V17.6: Get story bible context for this scene
        scene_data = scene_beats_index.get(scene_id, {})
        scene_desc = scene_data.get("description", "")
        scene_arc = scene_data.get("emotional_arc", "")
        scene_beats = scene_data.get("beats", [])

        durations = [s.get("duration", 10) for s in s_shots]
        types = [s.get("type", s.get("shot_type", "medium")) for s in s_shots]
        has_dialogue_list = [bool(s.get("dialogue") or s.get("dialogue_text")) for s in s_shots]
        char_counts = [len(s.get("characters", [])) for s in s_shots]

        # 1. PACING — shot duration variety (avoid monotonous same-length cutting)
        if len(durations) >= 3:
            duration_stdev = (sum((d - sum(durations)/len(durations))**2 for d in durations) / len(durations)) ** 0.5
            avg_dur = sum(durations) / len(durations)
            coeff_variation = duration_stdev / max(avg_dur, 1)
            # Good pacing has variation (CV 0.2-0.5)
            if coeff_variation < 0.1:
                score_components["pacing"] = 0.3
                issues.append(f"Monotonous pacing — all shots ~{avg_dur:.0f}s, add variety (mix 6-20s)")
            elif coeff_variation < 0.2:
                score_components["pacing"] = 0.6
                issues.append("Low pacing variety — try contrasting long/short shots")
            elif coeff_variation > 0.8:
                score_components["pacing"] = 0.6
                issues.append("Erratic pacing — very inconsistent durations may feel disjointed")
            else:
                score_components["pacing"] = min(1.0, 0.5 + coeff_variation)
        else:
            score_components["pacing"] = 0.7  # Too few shots to judge

        # 2. TENSION CURVE — does the scene build and release?
        # Heuristic: look for emotional progression in prompts
        tension_openers = ["quiet", "still", "peaceful", "calm", "gentle", "slow"]
        tension_builders = ["sudden", "sharp", "intense", "dark", "ominous", "tense",
                          "fear", "danger", "scream", "shock", "discover", "reveal"]
        tension_resolvers = ["exhale", "relief", "calm after", "aftermath", "settle",
                           "resolve", "peace", "silence", "alone"]

        has_opener = any(any(w in (s.get("nano_prompt", "") + " " + s.get("emotional_beat", "")).lower()
                            for w in tension_openers) for s in s_shots[:len(s_shots)//3+1])
        has_builder = any(any(w in (s.get("nano_prompt", "") + " " + s.get("emotional_beat", "")).lower()
                             for w in tension_builders) for s in s_shots)
        has_resolver = any(any(w in (s.get("nano_prompt", "") + " " + s.get("emotional_beat", "")).lower()
                              for w in tension_resolvers) for s in s_shots[-max(len(s_shots)//3, 1):])

        tension_elements = sum([has_opener, has_builder, has_resolver])
        if len(s_shots) >= 5:
            score_components["tension_curve"] = [0.3, 0.5, 0.7, 1.0][min(tension_elements, 3)]
            if not has_builder:
                issues.append("Scene lacks tension/conflict — add dramatic verbs (discover/reveal/shock)")
            if not has_resolver and len(s_shots) >= 8:
                issues.append("Scene lacks resolution — final shots should release tension")
        else:
            score_components["tension_curve"] = 0.6  # Short scenes don't need full arc

        # 3. SHOT TYPE VARIETY — avoiding visual monotony
        type_set = set(types)
        type_variety = len(type_set) / max(len(types), 1)
        score_components["shot_variety"] = min(1.0, type_variety * 2)

        # Check for back-to-back identical types
        consecutive_same = 0
        for i in range(1, len(types)):
            if types[i] == types[i-1]:
                consecutive_same += 1
        if consecutive_same > 1:
            issues.append(f"{consecutive_same} back-to-back identical shot types — vary between wide/medium/close")

        # Must have establishing + close-up for proper coverage
        has_wide = any(t in ["establishing", "wide", "aerial"] for t in types)
        has_close = any(t in ["close-up", "close", "cu", "extreme_close", "ecu"] for t in types)
        if not has_wide and len(s_shots) >= 3:
            issues.append("Missing establishing/wide shot — scene needs spatial context")
            score_components["shot_variety"] = max(score_components["shot_variety"] - 0.2, 0.2)
        if not has_close and len(s_shots) >= 3 and any(c > 0 for c in char_counts):
            issues.append("Missing close-up — add intimate character moment")
            score_components["shot_variety"] = max(score_components["shot_variety"] - 0.15, 0.2)

        # 4. VISUAL RHYTHM — alternation pattern of long/short
        if len(durations) >= 4:
            avg = sum(durations) / len(durations)
            pattern = ["L" if d > avg else "S" for d in durations]
            transitions = sum(1 for i in range(1, len(pattern)) if pattern[i] != pattern[i-1])
            rhythm_score = transitions / max(len(pattern) - 1, 1)
            score_components["rhythm"] = min(1.0, 0.3 + rhythm_score * 0.7)
            if rhythm_score < 0.2:
                issues.append("No visual rhythm — alternate long/short shots for better cadence")
        else:
            score_components["rhythm"] = 0.7

        # 5. DIALOGUE ENGAGEMENT — scenes with dialogue need reaction shots
        dialogue_count = sum(has_dialogue_list)
        if dialogue_count >= 2:
            reaction_types = ["reaction", "rxn", "close-up", "close", "cu"]
            has_reaction = any(t in reaction_types for t in types)
            score_components["dialogue_engagement"] = 1.0 if has_reaction else 0.4
            if not has_reaction:
                issues.append("Dialogue scene lacks reaction shots — add CU reactions for listener")
        else:
            score_components["dialogue_engagement"] = 0.8  # N/A

        # 6. HOOK — first shot should grab attention
        if s_shots:
            first = s_shots[0]
            first_type = first.get("type", first.get("shot_type", "medium"))
            first_nano = (first.get("nano_prompt", "") + " " + first.get("emotional_beat", "")).lower()
            hook_words = ["dramatic", "striking", "mysterious", "eerie", "grand", "vast",
                         "silhouette", "shadow", "fog", "storm", "reveal", "burst"]
            has_hook = first_type in ["establishing", "wide", "aerial"] or any(w in first_nano for w in hook_words)
            score_components["opening_hook"] = 1.0 if has_hook else 0.4
            if not has_hook:
                issues.append("Opening shot lacks visual hook — use establishing/wide or dramatic imagery")

        # V17.6: NARRATIVE COVERAGE — does scene cover all story beats?
        if scene_beats:
            beats_covered = 0
            for beat in scene_beats:
                beat_desc = (beat.get("description", "") or "").lower()
                beat_chars = beat.get("characters", [])
                # Check if any shot addresses this beat
                for s in s_shots:
                    s_nano = (s.get("nano_prompt", "") or "").lower()
                    s_chars = s.get("characters", [])
                    # Beat covered if characters overlap or description keywords match
                    char_overlap = bool(set(beat_chars) & set(s_chars)) if beat_chars and s_chars else True
                    desc_words = [w for w in beat_desc.split() if len(w) > 4][:5]
                    keyword_match = any(w in s_nano for w in desc_words) if desc_words else True
                    if char_overlap and keyword_match:
                        beats_covered += 1
                        break
            beat_coverage = beats_covered / max(len(scene_beats), 1)
            score_components["narrative_coverage"] = min(1.0, beat_coverage)
            if beat_coverage < 0.7:
                issues.append(f"Only {beats_covered}/{len(scene_beats)} story beats covered — add shots for missing beats")
        else:
            score_components["narrative_coverage"] = 0.5  # No beats to check

        # Recompute with narrative_coverage included
        weights = {"pacing": 0.17, "tension_curve": 0.17, "shot_variety": 0.17,
                   "rhythm": 0.12, "dialogue_engagement": 0.12, "opening_hook": 0.1,
                   "narrative_coverage": 0.15}
        viewership_score = sum(score_components.get(k, 0.5) * weights.get(k, 0) for k in weights)

        # Grade
        if viewership_score >= 0.85:
            grade = "A"
        elif viewership_score >= 0.7:
            grade = "B"
        elif viewership_score >= 0.55:
            grade = "C"
        elif viewership_score >= 0.4:
            grade = "D"
        else:
            grade = "F"

        scene_reports[scene_id] = {
            "scene_id": scene_id,
            "shot_count": len(s_shots),
            "total_duration": sum(durations),
            "viewership_score": round(viewership_score, 3),
            "grade": grade,
            "components": {k: round(v, 2) for k, v in score_components.items()},
            "issues": issues,
            "shot_types": types,
            "has_dialogue": dialogue_count > 0,
            "story_bible_connected": bool(scene_data),
            "scene_description": scene_desc[:200] if scene_desc else "",
            "beat_count": len(scene_beats),
        }

    return scene_reports


