@app.post("/api/v17/apply/cast")
async def apply_cast_to_shots(request: Dict = Body(...)):
    """
    V17.5.2: Apply a character (+ reference) to specific shots or an entire scene.
    Used by drag-drop from Character Bank.
    """
    project = request.get("project")
    shot_ids = request.get("shot_ids", [])
    scene_id = request.get("scene_id", "")
    character_name = request.get("character_name", "")
    character_reference_url = request.get("character_reference_url", "")

    if not project or not character_name:
        return {"success": False, "error": "project and character_name required"}

    project_path = get_project_path(project)
    shot_plan_path = project_path / "shot_plan.json"
    if not shot_plan_path.exists():
        return {"success": False, "error": f"Project '{project}' not found"}

    with open(shot_plan_path) as f:
        data = json.load(f)

    # V27.1: Handle both list format [shots...] and dict format {"shots": [...]}
    if isinstance(data, list):
        shots = data
        data = {"shots": data}
    else:
        shots = data.get("shots", [])
    updated = 0

    for shot in shots:
        sid = shot.get("shot_id", "")
        # Match by shot_ids or scene_id
        if shot_ids and sid not in shot_ids:
            continue
        if scene_id and not sid.startswith(scene_id):
            continue
        if not shot_ids and not scene_id:
            continue

        # Add character if not present
        chars = shot.get("characters", [])
        if character_name not in chars:
            chars.append(character_name)
            shot["characters"] = chars

        # Set character reference URL (normalize to raw path for generation)
        if character_reference_url:
            # Store raw path for generation, the bundle builder normalizes for UI
            raw_path = character_reference_url
            if "/api/media?path=" in raw_path:
                raw_path = raw_path.split("path=")[1]
            shot["character_reference_url"] = raw_path

        updated += 1

    if updated > 0:
        # Atomic write
        try:
            from tools.safe_io import atomic_write_json
            atomic_write_json(shot_plan_path, data)
        except ImportError:
            import tempfile
            tmp = tempfile.NamedTemporaryFile(mode='w', dir=str(project_path), suffix='.json', delete=False)
            json.dump(data, tmp, indent=2)
            tmp.close()
            os.replace(tmp.name, str(shot_plan_path))

        # Invalidate cache
        dirty_flag = project_path / "ui_cache" / "bundle.dirty"
        dirty_flag.parent.mkdir(parents=True, exist_ok=True)
        dirty_flag.touch()

        logger.info(f"[V17.5.2] Applied character '{character_name}' to {updated} shots")

    return {
        "success": True,
        "character_name": character_name,
        "shots_updated": updated,
        "has_reference": bool(character_reference_url)
    }


