@app.post("/api/v17/director-analysis")
async def director_analysis(request: Dict = Body(...)):
    """
    V17.5.2: Comprehensive Director Analysis with blocking + viewership intelligence.
    Analyzes shots for:
    - Blocking: character positioning, movement, proxemics, eyeline, screen direction
    - Viewership: pacing, tension curve, shot variety, rhythm, dialogue engagement, hooks

    Body:
    {
        "project": "ravencroft_v17",
        "scene_filter": "003",       // optional, analyze specific scene
        "shot_id": "003_001A",       // optional, analyze single shot
        "include_suggestions": true  // generate fix suggestions
    }
    """
    project = request.get("project")
    scene_filter = request.get("scene_filter", "")
    shot_id = request.get("shot_id", "")
    include_suggestions = request.get("include_suggestions", True)

    if not project:
        return {"success": False, "error": "project required"}

    project_path = get_project_path(project)
    shot_plan_path = project_path / "shot_plan.json"
    if not shot_plan_path.exists():
        return {"success": False, "error": f"Project '{project}' not found"}

    with open(shot_plan_path) as f:
        data = json.load(f)
    shots = data.get("shots", [])

    # Filter
    if shot_id:
        shots = [s for s in shots if s.get("shot_id") == shot_id]
    elif scene_filter:
        scene_list = [s.strip() for s in scene_filter.split(",")]
        shots = [s for s in shots if s.get("shot_id", "")[:3] in scene_list]

    if not shots:
        return {"success": False, "error": "No shots found for filter"}

    # Load cast_map
    cast_map = {}
    cm_path = project_path / "cast_map.json"
    if cm_path.exists():
        try:
            with open(cm_path) as f:
                cast_map = json.load(f)
        except Exception:
            pass

    # V17.6: Load story_bible for narrative-aware analysis
    story_bible = {}
    sb_path = project_path / "story_bible.json"
    if sb_path.exists():
        try:
            with open(sb_path) as f:
                story_bible = json.load(f)
        except Exception:
            pass

    # Build scene beat index from story_bible for narrative context
    scene_beats_index = {}
    for scene in story_bible.get("scenes", []):
        sid = scene.get("scene_id", scene.get("scene_number", ""))
        if sid:
            scene_beats_index[str(sid).zfill(3)] = {
                "beats": scene.get("beats", []),
                "location": scene.get("location", scene.get("setting", "")),
                "emotional_arc": scene.get("emotional_arc", ""),
                "characters": scene.get("characters", []),
                "description": scene.get("description", ""),
            }

    # Run analyses — now with story_bible context
    blocking_results = _analyze_blocking_intelligence(shots, cast_map, scene_beats_index)
    viewership_results = _analyze_viewership_intelligence(shots, scene_beats_index)

    # Compute overall scores
    avg_blocking = sum(r["blocking_score"] for r in blocking_results) / max(len(blocking_results), 1)
    avg_viewership = sum(v["viewership_score"] for v in viewership_results.values()) / max(len(viewership_results), 1)
    overall_score = (avg_blocking * 0.5 + avg_viewership * 0.5)

    # Determine overall grade
    if overall_score >= 0.85:
        grade = "A"
    elif overall_score >= 0.7:
        grade = "B"
    elif overall_score >= 0.55:
        grade = "C"
    elif overall_score >= 0.4:
        grade = "D"
    else:
        grade = "F"

    # Collect all suggestions from issues
    all_blocking_issues = []
    for r in blocking_results:
        for issue in r.get("issues", []):
            all_blocking_issues.append({"shot_id": r["shot_id"], "issue": issue})

    all_viewership_issues = []
    for scene_id, report in viewership_results.items():
        for issue in report.get("issues", []):
            all_viewership_issues.append({"scene_id": scene_id, "issue": issue})

    # Generate fix suggestions if requested
    suggestions = []
    if include_suggestions:
        # Top blocking fixes (shots with lowest scores)
        worst_blocking = sorted(blocking_results, key=lambda r: r["blocking_score"])[:5]
        for r in worst_blocking:
            if r["blocking_score"] < 0.7 and r["issues"]:
                suggestions.append({
                    "type": "blocking",
                    "shot_id": r["shot_id"],
                    "priority": "high" if r["blocking_score"] < 0.5 else "medium",
                    "fix": r["issues"][0],
                    "current_score": r["blocking_score"]
                })

        # Top viewership fixes (scenes with lowest scores)
        worst_viewership = sorted(viewership_results.values(), key=lambda v: v["viewership_score"])[:3]
        for v in worst_viewership:
            if v["viewership_score"] < 0.7 and v["issues"]:
                suggestions.append({
                    "type": "viewership",
                    "scene_id": v["scene_id"],
                    "priority": "high" if v["viewership_score"] < 0.5 else "medium",
                    "fix": v["issues"][0],
                    "current_score": v["viewership_score"]
                })

    return {
        "success": True,
        "project": project,
        "overall_score": round(overall_score, 3),
        "grade": grade,
        "blocking_avg": round(avg_blocking, 3),
        "viewership_avg": round(avg_viewership, 3),
        "shots_analyzed": len(shots),
        "scenes_analyzed": len(viewership_results),
        "blocking": blocking_results,
        "viewership": viewership_results,
        "blocking_issues": all_blocking_issues[:20],
        "viewership_issues": all_viewership_issues[:15],
        "suggestions": suggestions[:10] if include_suggestions else [],
        "summary": {
            "blocking_health": "healthy" if avg_blocking >= 0.7 else ("needs_work" if avg_blocking >= 0.5 else "critical"),
            "viewership_health": "healthy" if avg_viewership >= 0.7 else ("needs_work" if avg_viewership >= 0.5 else "critical"),
            "top_issues": (all_blocking_issues[:3] + all_viewership_issues[:3])
        }
    }


