# =============================================================================
# V17 VISION CONSISTENCY ANALYZER - Restores Marcus/Chen-era quality
# =============================================================================

@app.post("/api/v17/qa/vision-consistency")
async def vision_consistency_check(request: Dict = Body(...)):
    """
    V17 FIX: Vision-based consistency analysis using DINO+CLIP.
    Checks generated first frames against locked character references.
    Returns per-shot face/hybrid scores and flags shots needing regeneration.

    Body:
    {
        "project": "ravencroft_v17",
        "shot_ids": ["001_001A"],  // optional, if empty = all shots with frames
        "threshold": 0.70,         // min face consistency score
        "auto_regen": false        // if true, queue failing shots for regeneration
    }
    """
    project = request.get("project")
    shot_ids = request.get("shot_ids", [])
    threshold = request.get("threshold", 0.70)
    auto_regen = request.get("auto_regen", False)

    if not project:
        return {"success": False, "error": "project required"}

    project_path = get_project_path(project)
    shot_plan_path = project_path / "shot_plan.json"
    cast_map_path = project_path / "cast_map.json"
    first_frames_dir = project_path / "first_frames"

    if not shot_plan_path.exists():
        return {"success": False, "error": f"Project '{project}' not found"}

    with open(shot_plan_path) as f:
        data = json.load(f)

    cast_map = {}
    if cast_map_path.exists():
        with open(cast_map_path) as f:
            cast_map = json.load(f)

    shots = data.get("shots", [])
    if shot_ids:
        shots = [s for s in shots if s.get("shot_id") in shot_ids]

    # Try to load vision analyzer
    analyzer = None
    try:
        from dino_clip_analyzer import get_hybrid_analyzer
        analyzer = get_hybrid_analyzer()
        logger.info("[V17 VISION] DINO+CLIP Hybrid Analyzer loaded")
    except Exception as e:
        logger.warning(f"[V17 VISION] Analyzer unavailable: {e}")
        return {"success": False, "error": f"Vision analyzer unavailable: {e}"}

    results = []
    shots_failing = []

    for shot in shots:
        shot_id = shot.get("shot_id", "unknown")
        frame_path = first_frames_dir / f"{shot_id}.jpg"

        if not frame_path.exists():
            results.append({"shot_id": shot_id, "status": "no_frame", "skipped": True})
            continue

        # Resolve character reference
        char_ref_url = shot.get("character_reference_url")
        if not char_ref_url:
            chars = shot.get("characters", [])
            if chars:
                first_char = chars[0] if isinstance(chars[0], str) else chars[0].get("name", "")
                char_entry = cast_map.get(first_char) or cast_map.get(first_char.upper())
                if char_entry and isinstance(char_entry, dict):
                    # V17.7: Try locked reference first
                    _actor = char_entry.get("ai_actor", "")
                    if _actor:
                        _afn = _actor.upper().replace(" ", "_") + "_LOCKED_REFERENCE.jpg"
                        _lp = BASE_DIR / "character_library_locked" / "ai_actors" / _afn
                        if _lp.exists():
                            char_ref_url = f"/api/media?path={_lp}"
                    if not char_ref_url:
                        char_ref_url = char_entry.get("character_reference_url") or char_entry.get("reference_url")

        if not char_ref_url:
            results.append({"shot_id": shot_id, "status": "no_reference", "skipped": True})
            continue

        # Extract local path from API URL
        ref_path = char_ref_url.split("path=")[-1] if "path=" in char_ref_url else char_ref_url

        if not Path(ref_path).exists():
            results.append({"shot_id": shot_id, "status": "ref_not_found", "ref_path": ref_path, "skipped": True})
            continue

        # Run vision analysis
        try:
            scores = analyzer.analyze_comprehensive(
                str(frame_path), ref_path, shot.get("nano_prompt", "")
            )
            face_score = scores.get("dino_face", 0)
            hybrid_score = scores.get("hybrid_score", 0)
            clip_score = scores.get("clip_alignment", 0)
            face_sharp = scores.get("face_sharpness", 0)
            is_blurred = scores.get("is_face_blurred", False)

            passed = face_score >= threshold and not is_blurred

            entry = {
                "shot_id": shot_id,
                "face_score": round(face_score, 3),
                "hybrid_score": round(hybrid_score, 3),
                "clip_score": round(clip_score, 3),
                "face_sharpness": round(face_sharp, 3),
                "is_blurred": is_blurred,
                "passed": passed,
                "threshold": threshold,
                "reference": Path(ref_path).name,
                "character": shot.get("characters", ["unknown"])[0] if shot.get("characters") else "unknown"
            }
            results.append(entry)

            if not passed:
                shots_failing.append(shot_id)
                logger.warning(f"[V17 VISION] {shot_id} FAILED: face={face_score:.2%} (threshold={threshold:.2%})")
            else:
                logger.info(f"[V17 VISION] {shot_id} PASSED: face={face_score:.2%}")

        except Exception as e:
            logger.error(f"[V17 VISION] Error analyzing {shot_id}: {e}")
            results.append({"shot_id": shot_id, "status": "error", "error": str(e)})

    # Auto-regen failing shots if requested
    regen_result = None
    if auto_regen and shots_failing:
        try:
            import httpx
            async with httpx.AsyncClient(timeout=300.0) as client:
                # V17.3: Use turbo endpoint for parallel regen
                regen_response = await client.post(
                    "http://localhost:9999/api/auto/generate-first-frames-turbo",
                    json={"project": project, "shot_ids": shots_failing, "force": True, "max_workers": 15}
                )
                regen_result = regen_response.json()
                logger.info(f"[V17 VISION] Auto-regen triggered for {len(shots_failing)} failing shots")
        except Exception as e:
            regen_result = {"error": str(e)}

    # Summary
    total = len(results)
    passed = len([r for r in results if r.get("passed") == True])
    failed = len([r for r in results if r.get("passed") == False])
    skipped = len([r for r in results if r.get("skipped")])
    avg_face = sum(r.get("face_score", 0) for r in results if "face_score" in r) / max(1, passed + failed)

    return {
        "success": True,
        "project": project,
        "threshold": threshold,
        "summary": {
            "total": total,
            "passed": passed,
            "failed": failed,
            "skipped": skipped,
            "avg_face_score": round(avg_face, 3),
            "consistency_grade": "A" if avg_face >= 0.85 else "B" if avg_face >= 0.75 else "C" if avg_face >= 0.65 else "F"
        },
        "shots_failing": shots_failing,
        "results": results,
        "auto_regen": regen_result
    }


# =============================================================================
# V17.3 COVERAGE SOLVER — CINEMATIC GRAMMAR ENFORCEMENT ENGINE
# Rule-based validation: per-beat coverage, shot sequence variety,
# screen direction consistency, and scene-level completeness.
# =============================================================================


def auto_assign_blocking_roles(shots: list) -> int:
    """
    V17.3: Intelligently assign blocking_role to shots based on:
    - shot_type (establishing/wide → master, close-up → reaction, etc.)
    - character count (2+ chars dialogue → OTS-A/OTS-B)
    - position in scene (first shot → establishing, emotional beats → reaction)
    - dialogue presence → coverage or OTS
    Mutates shots in-place. Returns count of shots reassigned.
    """
    reassigned = 0
    chars_seen = set()  # Track characters for OTS assignment

    for i, shot in enumerate(shots):
        current_role = shot.get('blocking_role', 'coverage')
        shot_type = (shot.get('shot_type') or shot.get('type') or '').lower()

        # V17.3: Override generic roles (coverage/master) based on shot_type intelligence
        # Only skip if role is SPECIFIC (OTS-A, OTS-B, reaction, establishing, close_coverage)
        specific_roles = ('OTS-A', 'OTS-B', 'reaction', 'establishing', 'close_coverage')
        if current_role in specific_roles:
            continue
        chars = shot.get('characters') or []
        has_dialogue = bool(shot.get('dialogue_text') or shot.get('dialogue'))
        nano = (shot.get('nano_prompt') or '').lower()

        new_role = 'coverage'

        # Rule 1: First shot in scene or establishing/wide → master
        if i == 0 or shot_type in ('establishing', 'wide', 'master'):
            new_role = 'master'

        # Rule 2: Reaction shots → reaction
        elif shot_type == 'reaction':
            new_role = 'reaction'

        # Rule 3: Close-up with emotional content → reaction
        elif shot_type in ('close-up', 'closeup', 'cu', 'ecu', 'extreme_close'):
            new_role = 'reaction'

        # Rule 4: Dialogue with 2+ characters → OTS-A or OTS-B
        elif has_dialogue and len(chars) >= 2:
            # Alternate OTS-A/OTS-B based on which character is speaking
            primary_char = chars[0] if isinstance(chars[0], str) else (chars[0].get('name', '') if isinstance(chars[0], dict) else '')
            if primary_char not in chars_seen:
                new_role = 'OTS-A'
                chars_seen.add(primary_char)
            else:
                new_role = 'OTS-B'

        # Rule 5: Dialogue with single character → medium/coverage
        elif has_dialogue and len(chars) == 1:
            new_role = 'OTS-A'

        # Rule 6: B-roll / insert → coverage (keep as is)
        elif shot_type in ('b-roll', 'insert', 'cutaway'):
            new_role = 'coverage'

        # Rule 7: Action → coverage
        elif shot_type == 'action':
            new_role = 'coverage'

        # Rule 8: Check nano_prompt for clues
        elif 'over the shoulder' in nano or 'over-the-shoulder' in nano:
            new_role = 'OTS-A'
        elif 'close' in nano and ('face' in nano or 'eyes' in nano):
            new_role = 'reaction'
        elif 'wide' in nano or 'establishing' in nano:
            new_role = 'master'

        if new_role != current_role:
            shot['blocking_role'] = new_role
            reassigned += 1

    return reassigned


def auto_assign_screen_direction(shots: list) -> int:
    """
    V17.3: Assign screen_direction to shots that lack it.
    Uses 180-degree rule: OTS-A faces right, OTS-B faces left.
    """
    assigned = 0
    for shot in shots:
        if shot.get('screen_direction') and shot['screen_direction'] != 'unknown':
            continue

        role = shot.get('blocking_role', 'coverage')
        if role == 'OTS-A':
            shot['screen_direction'] = 'right'
            assigned += 1
        elif role == 'OTS-B':
            shot['screen_direction'] = 'left'
            assigned += 1
        elif role in ('master', 'establishing'):
            shot['screen_direction'] = 'center'
            assigned += 1
        elif role == 'reaction':
            shot['screen_direction'] = 'neutral'
            assigned += 1

    return assigned


def solve_scene_coverage(scene_id: str, shots: list, story_bible_scene: dict = None) -> dict:
    """
    V17.3 Coverage Solver: Cinematic grammar enforcement engine.
    Validates per-beat coverage (master/OTS/reaction), consecutive framing variety,
    screen direction consistency, and scene-level establishing/close-up requirements.
    Returns coverage_report with grade, gaps, warnings, and auto_fix_suggestions.
    """
    from collections import defaultdict

    report = {
        'scene_id': scene_id, 'grade': 'F', 'score': 0,
        'gaps': [], 'warnings': [], 'auto_fix_suggestions': [],
        'coverage_breakdown': {}, 'dialogue_beat_coverage': {},
        'screen_direction_consistency': {'violations': [], 'is_consistent': True},
        'shot_sequence_variety': {'consecutive_duplicates': [], 'variety_score': 0},
        'total_shots': len(shots), 'passing': False
    }

    if not shots:
        report['gaps'].append({'type': 'no_shots', 'severity': 'critical',
                               'description': f'Scene {scene_id} has no shots'})
        return report

    # ===== 1. BLOCKING ROLE DISTRIBUTION =====
    blocking_role_counts = defaultdict(int)
    blocking_roles_by_beat = defaultdict(lambda: defaultdict(int))
    dialogue_beats = set()

    for shot in shots:
        role = shot.get('blocking_role', 'coverage')
        blocking_role_counts[role] += 1
        beat_id = shot.get('beat_id', 'unassigned')
        if beat_id != 'unassigned':
            dialogue_beats.add(beat_id)
            blocking_roles_by_beat[beat_id][role] += 1

    report['coverage_breakdown'] = dict(blocking_role_counts)

    # ===== V21.2: SCENE TYPE AWARENESS =====
    # Read scene type from shots (set by CHECK 6: Scene Type Classification)
    scene_type = None
    if shots:
        scene_type = shots[0].get('_scene_type', '')

    # Scene types with special coverage rules
    skip_dialogue_coverage_rules = scene_type in ('PHONE_DIALOGUE', 'INTERCUT', 'RITUAL', 'MONTAGE', 'VOICEOVER', 'SOLO_ATMOSPHERE')

    # For PHONE_DIALOGUE/INTERCUT: downgrade 2-shots to single-character framing
    if scene_type in ('PHONE_DIALOGUE', 'INTERCUT'):
        for shot in shots:
            shot_type_str = (shot.get('type', '') + shot.get('shot_type', '')).lower()
            if any(t in shot_type_str for t in ['two_shot', 'two-shot', '2-shot']):
                logger.info(f"[COVERAGE] {shot.get('shot_id', '?')}: Downgrading 2-shot to MCU ({scene_type} scene)")
                shot['type'] = 'medium_close'
                shot['blocking_role'] = 'coverage'

    report['scene_type'] = scene_type
    report['skip_dialogue_rules'] = skip_dialogue_coverage_rules

    # ===== 2. SCENE-LEVEL ROLE DISTRIBUTION =====
    # V17.3: Grade on scene-level coverage mix rather than per-beat ABC requirements.
    # Single-shot-per-beat plans (common in initial generation) get graded on whether
    # the scene has a good distribution of role types, not per-beat completeness.
    total = len(shots)
    n_master = blocking_role_counts.get('master', 0) + blocking_role_counts.get('establishing', 0)
    n_ots = blocking_role_counts.get('OTS-A', 0) + blocking_role_counts.get('OTS-B', 0)
    n_reaction = blocking_role_counts.get('reaction', 0) + blocking_role_counts.get('close_coverage', 0)
    n_coverage = blocking_role_counts.get('coverage', 0)

    # Good distribution: at least 10% master, 20% OTS, 15% reaction for dialogue scenes
    has_dialogue_beats = len(dialogue_beats) > 0
    # V21.2: Skip dialogue coverage rules for special scene types
    if has_dialogue_beats and total > 3 and not skip_dialogue_coverage_rules:
        master_pct = n_master / total
        ots_pct = n_ots / total
        reaction_pct = n_reaction / total

        if master_pct < 0.05:
            report['gaps'].append({'type': 'low_master_coverage', 'severity': 'high',
                                   'description': f'Only {master_pct:.0%} master shots (need ~10%)'})
        if ots_pct < 0.10:
            report['gaps'].append({'type': 'low_ots_coverage', 'severity': 'medium',
                                   'description': f'Only {ots_pct:.0%} OTS shots (need ~20%)'})
        if reaction_pct < 0.10:
            report['gaps'].append({'type': 'low_reaction_coverage', 'severity': 'medium',
                                   'description': f'Only {reaction_pct:.0%} reaction shots (need ~15%)'})

        report['role_distribution'] = {
            'master_pct': round(master_pct * 100, 1),
            'ots_pct': round(ots_pct * 100, 1),
            'reaction_pct': round(reaction_pct * 100, 1),
            'coverage_pct': round((n_coverage / total) * 100, 1)
        }

    # ===== 3. SCENE-LEVEL REQUIREMENTS =====
    has_establishing = blocking_role_counts.get('master', 0) > 0 or \
                       blocking_role_counts.get('establishing', 0) > 0
    # Also check shot types as fallback
    if not has_establishing:
        for s in shots:
            st = (s.get('shot_type') or s.get('type') or '').lower()
            if st in ('establishing', 'wide', 'master'):
                has_establishing = True; break

    if not has_establishing:
        report['gaps'].append({'type': 'no_establishing_shot', 'severity': 'critical',
                               'description': f'Scene {scene_id} lacks establishing/master/wide shot'})

    has_close = blocking_role_counts.get('close_coverage', 0) > 0 or \
                blocking_role_counts.get('reaction', 0) > 0
    if not has_close:
        for s in shots:
            st = (s.get('shot_type') or s.get('type') or '').lower()
            if st in ('close', 'closeup', 'cu', 'ecu', 'extreme_close'):
                has_close = True; break

    if dialogue_beats and not has_close:
        report['gaps'].append({'type': 'no_close_for_dialogue', 'severity': 'high',
                               'description': f'Scene {scene_id} has dialogue but no close-ups'})

    # ===== 4. NO BACK-TO-BACK IDENTICAL FRAMING =====
    consecutive_same = []
    for i in range(1, len(shots)):
        t1 = (shots[i-1].get('shot_type') or shots[i-1].get('type') or 'unknown').lower()
        t2 = (shots[i].get('shot_type') or shots[i].get('type') or 'unknown').lower()
        if t1 == t2 and t1 != 'unknown':
            consecutive_same.append({
                'position': i,
                'shot_type': t2,
                'shot_ids': [shots[i-1].get('shot_id', '?'), shots[i].get('shot_id', '?')]
            })
    if consecutive_same:
        report['gaps'].append({
            'type': 'back_to_back_framing', 'severity': 'medium',
            'description': f'{len(consecutive_same)} consecutive identical shot type(s)',
            'instances': consecutive_same[:5]  # Cap for readability
        })
    report['shot_sequence_variety'] = {
        'consecutive_duplicates': consecutive_same,
        'variety_score': max(0, 100 - len(consecutive_same) * 15)
    }

    # ===== 5. SCREEN DIRECTION CONSISTENCY =====
    direction_violations = []
    for role_check in ['OTS-A', 'OTS-B']:
        role_shots = [s for s in shots if s.get('blocking_role') == role_check]
        if len(role_shots) > 1:
            dirs = [s.get('screen_direction', 'unknown') for s in role_shots]
            main_dir = max(set(dirs), key=dirs.count)
            for s in role_shots:
                d = s.get('screen_direction', 'unknown')
                if d != main_dir and d not in ('neutral', 'center', 'unknown'):
                    direction_violations.append({
                        'shot_id': s.get('shot_id', '?'), 'role': role_check,
                        'expected': main_dir, 'actual': d
                    })
    if direction_violations:
        report['warnings'].append({
            'type': 'screen_direction_inconsistency',
            'description': f'{len(direction_violations)} screen direction violation(s)',
            'violations': direction_violations
        })
        report['screen_direction_consistency']['is_consistent'] = False
    report['screen_direction_consistency']['violations'] = direction_violations

    # ===== 6. AUTO-FIX SUGGESTIONS =====
    if not has_establishing:
        report['auto_fix_suggestions'].append({
            'action': 'reclassify_first_as_establishing',
            'reason': 'Scene needs establishing shot; promote first wide/medium', 'severity': 'high'
        })
    if has_dialogue_beats and n_ots < 2:
        report['auto_fix_suggestions'].append({
            'action': 'expand_beat_coverage',
            'reason': f'Dialogue scene needs more OTS/reverse shots for coverage', 'severity': 'high'
        })
    if consecutive_same:
        report['auto_fix_suggestions'].append({
            'action': 'intercut_variety',
            'reason': 'Insert cutaway/reaction between consecutive identical types', 'severity': 'medium'
        })

    # ===== 7. CALCULATE GRADE =====
    penalty = 0
    for gap in report['gaps']:
        penalty += {'critical': 20, 'high': 10, 'medium': 5}.get(gap['severity'], 3)
    penalty += len(report['warnings']) * 3
    variety_bonus = report['shot_sequence_variety']['variety_score'] // 7
    score = max(0, min(100, 100 - penalty + variety_bonus))

    report['score'] = score
    report['grade'] = 'A' if score >= 90 else 'B' if score >= 75 else 'C' if score >= 60 else 'D' if score >= 45 else 'F'
    report['passing'] = report['grade'] in ('A', 'B')
    return report


def run_coverage_solver(shots: list, story_bible: dict = None) -> dict:
    """
    V17.3 Coverage Solver: Run cinematic grammar enforcement across all scenes.
    Called from fix_v16_issues after all shot enrichment is complete.
    Auto-assigns blocking roles and screen direction before grading.
    Returns overall grade + per-scene reports.
    """
    from collections import defaultdict
    import time
    start = time.time()

    # V17.3: Auto-assign blocking roles before grading
    roles_assigned = auto_assign_blocking_roles(shots)
    dirs_assigned = auto_assign_screen_direction(shots)
    logger.info(f"[COVERAGE] Auto-assigned {roles_assigned} blocking roles, {dirs_assigned} screen directions")

    by_scene = defaultdict(list)
    for shot in shots:
        by_scene[shot.get('scene_id', 'unknown')].append(shot)

    per_scene = {}
    scores = []
    for sid in sorted(by_scene.keys()):
        sb_scene = None
        if story_bible and 'scenes' in story_bible:
            for sc in story_bible['scenes']:
                if sc.get('scene_id') == sid:
                    sb_scene = sc; break
        report = solve_scene_coverage(sid, by_scene[sid], sb_scene)
        per_scene[sid] = report
        scores.append(report['score'])

    avg = int(sum(scores) / len(scores)) if scores else 0
    passing = sum(1 for r in per_scene.values() if r['passing'])

    critical = []
    for sid, r in per_scene.items():
        for g in r['gaps']:
            if g['severity'] == 'critical':
                critical.append({'scene_id': sid, 'issue': g['description']})

    return {
        'overall_grade': 'A' if avg >= 90 else 'B' if avg >= 75 else 'C' if avg >= 60 else 'D' if avg >= 45 else 'F',
        'overall_score': avg,
        'total_scenes': len(per_scene),
        'passing_scenes': passing,
        'failing_scenes': len(per_scene) - passing,
        'per_scene_reports': per_scene,
        'critical_issues': critical,
        'execution_time_ms': round((time.time() - start) * 1000, 2)
    }


# =============================================================================
# V17 SCENE COVERAGE ANALYZER - Director Intelligence Layer
# =============================================================================

@app.post("/api/v17/scene/analyze-coverage")
async def analyze_scene_coverage(request: Dict = Body(...)):
    """
    V17: Comprehensive scene coverage analyzer with story bible references.
    Returns:
    - Coverage grade (A-F)
    - Missing shot types (establishing, B-roll, inserts, reactions)
    - Prompt quality scores (BASIC/ADEQUATE/CINEMATIC)
    - Story bible context for improvements
    - Recommended additions
    """
    project = request.get("project")
    scene_id = request.get("scene_id")  # Optional: analyze specific scene

    if not project:
        return {"success": False, "error": "project required"}

    project_path = get_project_path(project)
    shot_plan_path = project_path / "shot_plan.json"
    story_bible_path = project_path / "story_bible.json"

    if not shot_plan_path.exists():
        return {"success": False, "error": f"Project '{project}' not found"}

    # Load data
    with open(shot_plan_path) as f:
        shot_plan = _sp_guard(json.load(f))

    story_bible = {}
    if story_bible_path.exists():
        with open(story_bible_path) as f:
            story_bible = json.load(f)

    shots = shot_plan.get("shots", [])

    # Group shots by scene
    from collections import defaultdict
    scenes = defaultdict(list)
    for shot in shots:
        sid = shot.get("scene_id", "unknown")
        scenes[sid].append(shot)

    # If specific scene requested, filter
    if scene_id:
        if scene_id not in scenes:
            return {"success": False, "error": f"Scene '{scene_id}' not found"}
        scenes = {scene_id: scenes[scene_id]}

    # Analysis results
    scene_analyses = []

    for sid, scene_shots in scenes.items():
        analysis = analyze_single_scene(sid, scene_shots, story_bible)
        scene_analyses.append(analysis)

    # Calculate overall grade
    total_score = sum(a["coverage_score"] for a in scene_analyses)
    avg_score = total_score / max(1, len(scene_analyses))

    if avg_score >= 85:
        overall_grade = "A"
    elif avg_score >= 70:
        overall_grade = "B"
    elif avg_score >= 55:
        overall_grade = "C"
    elif avg_score >= 40:
        overall_grade = "D"
    else:
        overall_grade = "F"

    return {
        "success": True,
        "project": project,
        "overall_grade": overall_grade,
        "overall_score": round(avg_score, 1),
        "scenes_analyzed": len(scene_analyses),
        "scene_analyses": scene_analyses,
        "story_bible_loaded": bool(story_bible)
    }


@app.post("/api/v17/coverage/solve")
async def api_coverage_solver(request: Dict = Body(...)):
    """
    V17.3: Run the Coverage Solver across all scenes (or a specific scene).
    Returns cinematic grammar enforcement report with grades, gaps, and auto-fix suggestions.
    Body: {"project": "my_movie", "scene_id": "003"}  // scene_id optional
    """
    project = request.get("project")
    scene_id = request.get("scene_id")
    if not project:
        return {"success": False, "error": "project required"}
    project_path = get_project_path(project)
    shot_plan_path = project_path / "shot_plan.json"
    if not shot_plan_path.exists():
        return {"success": False, "error": f"No shot_plan.json for '{project}'"}
    try:
        with open(shot_plan_path) as f:
            data = json.load(f)
        shots = data.get("shots", [])
        if scene_id:
            shots = [s for s in shots if s.get("scene_id") == scene_id]
            if not shots:
                return {"success": False, "error": f"Scene '{scene_id}' not found"}
        story_bible = {}
        sb_path = project_path / "story_bible.json"
        if sb_path.exists():
            with open(sb_path) as f:
                story_bible = json.load(f)
        report = run_coverage_solver(shots, story_bible)

        # V17.3: Persist updated blocking_role and screen_direction back to shot_plan.json
        # The auto_assign functions mutate shots in-place; save changes
        import tempfile
        data["_coverage_report"] = {
            "overall_grade": report["overall_grade"],
            "overall_score": report["overall_score"],
            "checked_at": datetime.now(timezone.utc).isoformat()
        }
        tmp = tempfile.NamedTemporaryFile(mode='w', dir=project_path, suffix='.tmp', delete=False)
        json.dump(data, tmp, indent=2)
        tmp.flush()
        os.fsync(tmp.fileno())
        tmp.close()
        os.replace(tmp.name, shot_plan_path)
        logger.info(f"[COVERAGE] Persisted updated roles to {shot_plan_path}")

        # Invalidate UI cache
        cache_dir = project_path / "ui_cache"
        if cache_dir.exists():
            (cache_dir / "bundle.dirty").touch()

        return {"success": True, "project": project, "scene_id": scene_id, **report}
    except Exception as e:
        return {"success": False, "error": str(e)[:300]}


def analyze_single_scene(scene_id: str, shots: list, story_bible: dict) -> dict:
    """Analyze a single scene for coverage, prompt quality, and gaps."""

    # Coverage type detection
    has_establishing = False
    has_wide = False
    has_medium = False
    has_closeup = False
    has_insert = False
    has_reaction = False
    has_broll = False
    has_atmosphere = False

    prompt_scores = []
    shot_details = []

    # Story bible context
    scene_bible = None
    location_desc = ""
    mood_desc = ""

    # Find scene in story bible
    if story_bible:
        for scene in story_bible.get("scenes", []):
            if scene.get("scene_id") == scene_id or scene.get("id") == scene_id:
                scene_bible = scene
                break

        # Get location description
        if scene_bible:
            loc_name = scene_bible.get("location", "")
            for loc in story_bible.get("locations", story_bible.get("setting", {}).get("locations", [])):
                loc_n = loc.get("name", "") if isinstance(loc, dict) else loc
                _score, _passes = score_name_match(loc_n, loc_name, threshold=50) if loc_n else (0, False)
                if _passes:
                    location_desc = loc.get("description", "") if isinstance(loc, dict) else ""
                    break
            mood_desc = scene_bible.get("mood", scene_bible.get("emotional_tone", ""))

    # Analyze each shot
    for shot in shots:
        nano = shot.get("nano_prompt", "").lower()
        shot_type = shot.get("shot_type", shot.get("type", "")).lower()

        # Coverage type detection
        if "establishing" in nano or "exterior" in nano:
            has_establishing = True
        if shot_type == "wide" or "wide" in nano:
            has_wide = True
        if shot_type == "medium" or "medium" in nano:
            has_medium = True
        if shot_type in ["close", "closeup", "cu"] or "close-up" in nano or "closeup" in nano:
            has_closeup = True
        if "insert" in shot_type or "detail" in nano or "hand" in nano:
            has_insert = True
        if "reaction" in nano or "reacts" in nano:
            has_reaction = True

        # B-roll / atmosphere detection
        broll_keywords = ["candle", "flame", "shadow", "dust", "light beam", "window",
                        "fireplace", "clock", "portrait", "fog", "rain", "smoke"]
        if any(kw in nano for kw in broll_keywords):
            has_broll = True

        atmosphere_keywords = ["atmospheric", "mood", "ambient", "texture", "grain",
                             "silhouette", "backlit", "rim light"]
        if any(kw in nano for kw in atmosphere_keywords):
            has_atmosphere = True

        # Score prompt quality
        prompt_score = score_prompt_quality(shot.get("nano_prompt", ""))
        prompt_scores.append(prompt_score)

        shot_details.append({
            "shot_id": shot.get("shot_id"),
            "type": shot_type,
            "prompt_quality": prompt_score["grade"],
            "prompt_score": prompt_score["score"],
            "issues": prompt_score["issues"]
        })

    # Calculate coverage score
    coverage_points = 0
    coverage_max = 100
    missing = []

    # Mandatory coverage (70 points)
    if has_wide:
        coverage_points += 20
    else:
        missing.append({"type": "wide", "priority": "HIGH", "reason": "No wide/establishing shot"})

    if has_medium:
        coverage_points += 20
    else:
        missing.append({"type": "medium", "priority": "HIGH", "reason": "No medium shot for dialogue"})

    if has_closeup:
        coverage_points += 20
    else:
        missing.append({"type": "closeup", "priority": "MEDIUM", "reason": "No close-up for emotion"})

    if has_establishing:
        coverage_points += 10
    else:
        missing.append({"type": "establishing", "priority": "HIGH", "reason": "No establishing shot for location"})

    # Optional but recommended (30 points)
    if has_insert:
        coverage_points += 10
    else:
        missing.append({"type": "insert", "priority": "LOW", "reason": "No detail/insert shots"})

    if has_broll:
        coverage_points += 10
    else:
        missing.append({"type": "b-roll", "priority": "MEDIUM", "reason": "No atmosphere B-roll (candles, shadows, etc.)"})

    if has_reaction:
        coverage_points += 10
    else:
        if len([s for s in shots if len(s.get("characters", [])) > 1]) > 0:
            missing.append({"type": "reaction", "priority": "MEDIUM", "reason": "Multi-character scene needs reaction shots"})

    # Average prompt quality bonus
    avg_prompt_score = sum(p["score"] for p in prompt_scores) / max(1, len(prompt_scores))
    if avg_prompt_score >= 70:
        coverage_points = min(100, coverage_points + 10)

    # Build recommendations based on story bible
    recommendations = []
    for m in missing:
        rec = build_recommendation(m, scene_bible, location_desc, mood_desc, shots)
        if rec:
            recommendations.append(rec)

    # Prompt enhancement suggestions
    weak_prompts = [s for s in shot_details if s["prompt_quality"] == "BASIC"]
    if weak_prompts:
        recommendations.append({
            "type": "prompt_enhancement",
            "priority": "MEDIUM",
            "shots": [s["shot_id"] for s in weak_prompts],
            "action": "Enhance basic prompts with atmosphere, lighting, and emotional context"
        })

    return {
        "scene_id": scene_id,
        "shot_count": len(shots),
        "coverage_score": coverage_points,
        "coverage_grade": "A" if coverage_points >= 85 else "B" if coverage_points >= 70 else "C" if coverage_points >= 55 else "D" if coverage_points >= 40 else "F",
        "coverage_breakdown": {
            "has_establishing": has_establishing,
            "has_wide": has_wide,
            "has_medium": has_medium,
            "has_closeup": has_closeup,
            "has_insert": has_insert,
            "has_broll": has_broll,
            "has_atmosphere": has_atmosphere,
            "has_reaction": has_reaction
        },
        "prompt_quality_avg": round(avg_prompt_score, 1),
        "prompt_breakdown": {
            "cinematic": len([p for p in prompt_scores if p["grade"] == "CINEMATIC"]),
            "adequate": len([p for p in prompt_scores if p["grade"] == "ADEQUATE"]),
            "basic": len([p for p in prompt_scores if p["grade"] == "BASIC"])
        },
        "missing": missing,
        "recommendations": recommendations,
        "story_bible_context": {
            "location": location_desc[:200] if location_desc else None,
            "mood": mood_desc if mood_desc else None
        },
        "shot_details": shot_details
    }


def score_prompt_quality(prompt: str) -> dict:
    """
    Score a prompt's cinematic quality.
    Returns: {"grade": "BASIC"|"ADEQUATE"|"CINEMATIC", "score": 0-100, "issues": []}
    """
    if not prompt:
        return {"grade": "BASIC", "score": 0, "issues": ["No prompt"]}

    prompt_lower = prompt.lower()
    score = 20  # Base score for having any prompt
    issues = []

    # Atmosphere indicators (+15 each, max 30)
    atmosphere_words = ["dust", "light", "shadow", "glow", "ambient", "haze", "mist",
                       "beam", "flicker", "warm", "cool", "golden", "silver"]
    atmo_count = sum(1 for w in atmosphere_words if w in prompt_lower)
    score += min(30, atmo_count * 15)
    if atmo_count == 0:
        issues.append("No atmosphere/lighting descriptors")

    # Emotion indicators (+10 each, max 20)
    emotion_words = ["tension", "grief", "authority", "fear", "hope", "dread",
                    "melancholy", "warmth", "coldness", "determination"]
    emo_count = sum(1 for w in emotion_words if w in prompt_lower)
    score += min(20, emo_count * 10)
    if emo_count == 0:
        issues.append("No emotional tone")

    # Camera/composition indicators (+10 each, max 20)
    camera_words = ["dolly", "push", "crane", "track", "tilt", "pan", "rack focus",
                   "shallow depth", "deep focus", "silhouette", "backlit"]
    cam_count = sum(1 for w in camera_words if w in prompt_lower)
    score += min(20, cam_count * 10)

    # Detail/texture indicators (+5 each, max 10)
    detail_words = ["texture", "fabric", "grain", "surface", "weathered", "ornate",
                   "delicate", "rough", "polished"]
    det_count = sum(1 for w in detail_words if w in prompt_lower)
    score += min(10, det_count * 5)

    # Length bonus (longer prompts usually more detailed)
    if len(prompt) > 200:
        score += 10
    elif len(prompt) > 100:
        score += 5
    elif len(prompt) < 50:
        issues.append("Prompt too short for rich generation")

    # Determine grade
    if score >= 70:
        grade = "CINEMATIC"
    elif score >= 45:
        grade = "ADEQUATE"
    else:
        grade = "BASIC"

    return {"grade": grade, "score": min(100, score), "issues": issues}


def build_recommendation(missing: dict, scene_bible: dict, location_desc: str, mood_desc: str, existing_shots: list) -> dict:
    """Build a specific recommendation for a missing shot type using story bible context."""

    missing_type = missing["type"]
    priority = missing["priority"]

    # Get character names from existing shots
    characters = []
    for shot in existing_shots:
        characters.extend(shot.get("characters", []))
    characters = list(set(characters))[:3]
    char_str = characters[0] if characters else "the subject"

    # Get location from existing shots
    location = ""
    for shot in existing_shots:
        loc = shot.get("location", "")
        if loc:
            location = loc
            break

    # Build suggested prompt based on type and context
    if missing_type == "establishing":
        suggested_prompt = f"Establishing wide shot of {location or 'the location'}. "
        if location_desc:
            suggested_prompt += f"{location_desc[:100]}. "
        if mood_desc:
            suggested_prompt += f"Atmosphere: {mood_desc}. "
        suggested_prompt += "Slow reveal, atmospheric lighting."

    elif missing_type == "wide":
        suggested_prompt = f"Wide shot of the scene. {char_str} visible in frame. "
        if location_desc:
            suggested_prompt += f"Setting: {location_desc[:80]}. "
        suggested_prompt += "Full environment context, establishing geography."

    elif missing_type == "medium":
        suggested_prompt = f"Medium shot of {char_str}. "
        if scene_bible and scene_bible.get("action"):
            suggested_prompt += f"{scene_bible['action'][:80]}. "
        suggested_prompt += "Clear framing for dialogue and expression."

    elif missing_type == "closeup":
        suggested_prompt = f"Close-up of {char_str}'s face. "
        if mood_desc:
            suggested_prompt += f"Conveying {mood_desc}. "
        suggested_prompt += "Shallow depth of field, emotional intensity."

    elif missing_type == "insert":
        # Suggest contextual inserts based on location
        if "manor" in location.lower() or "study" in location.lower():
            suggested_prompt = "Insert shot: candles flickering on mahogany desk, warm amber glow"
        elif "grave" in location.lower() or "cemetery" in location.lower():
            suggested_prompt = "Insert shot: weathered headstone, moss-covered letters"
        else:
            suggested_prompt = f"Insert shot: detail of hands or significant object in scene"

    elif missing_type == "b-roll":
        # Suggest atmosphere based on location
        if "manor" in location.lower() or "interior" in location.lower():
            suggested_prompt = "B-roll: dust motes floating in shaft of light through tall window"
        elif "night" in mood_desc.lower() or "dark" in mood_desc.lower():
            suggested_prompt = "B-roll: shadows dancing on wall from flickering candlelight"
        else:
            suggested_prompt = "B-roll: atmospheric detail shot establishing mood and texture"

    elif missing_type == "reaction":
        other_chars = [c for c in characters if c != char_str]
        react_char = other_chars[0] if other_chars else "secondary character"
        suggested_prompt = f"Reaction shot: {react_char} responds, subtle facial expression"

    else:
        suggested_prompt = f"Additional {missing_type} shot needed"

    return {
        "type": missing_type,
        "priority": priority,
        "suggested_shot": {
            "shot_type": missing_type,
            "nano_prompt": suggested_prompt,
            "duration": 8 if missing_type in ["insert", "b-roll", "reaction"] else 12,
            "characters": characters if missing_type not in ["insert", "b-roll", "establishing"] else []
        },
        "reason": missing["reason"]
    }


@app.post("/api/v17/coverage/auto-inject")
async def auto_inject_coverage_shots(request: Dict = Body(...)):
    """
    V17 COVERAGE CRITIC: Auto-inject missing establishing, B-roll, insert,
    and reaction shots based on DirectorCritic gap analysis.

    Runs analyze-coverage per scene, then CREATES the missing shots
    and inserts them into the shot plan at the correct positions.

    Body:
    {
        "project": "ravencroft_v17",
        "scene_ids": [],          // optional, empty = all scenes
        "dry_run": true,          // if true, just show what would be injected
        "min_priority": "MEDIUM", // only inject HIGH, or also MEDIUM and LOW
        "use_scene_anchors": true // apply scene anchor system to new shots
    }
    """
    project = request.get("project")
    scene_ids_filter = request.get("scene_ids", [])
    dry_run = request.get("dry_run", True)
    min_priority = request.get("min_priority", "MEDIUM").upper()
    use_anchors = request.get("use_scene_anchors", True)

    if not project:
        return {"success": False, "error": "project required"}

    project_path = get_project_path(project)
    shot_plan_path = project_path / "shot_plan.json"
    story_bible_path = project_path / "story_bible.json"

    if not shot_plan_path.exists():
        return {"success": False, "error": f"Project '{project}' not found"}

    with open(shot_plan_path) as f:
        shot_plan = _sp_guard(json.load(f))

    story_bible = {}
    if story_bible_path.exists():
        with open(story_bible_path) as f:
            story_bible = json.load(f)

    shots = shot_plan.get("shots", [])
    original_count = len(shots)

    # Priority filter
    priority_levels = {"HIGH": 3, "MEDIUM": 2, "LOW": 1}
    min_level = priority_levels.get(min_priority, 2)

    # Group shots by scene
    from collections import defaultdict
    scenes = defaultdict(list)
    for shot in shots:
        sid = shot.get("scene_id", "unknown")
        scenes[sid].append(shot)

    if scene_ids_filter:
        scenes = {k: v for k, v in scenes.items() if k in scene_ids_filter}

    # Load scene anchor system if available
    scene_anchor_system = None
    if use_anchors:
        try:
            from tools.scene_anchor_system import SceneAnchorSystem
            scene_anchor_system = SceneAnchorSystem(project_path)
            logger.info(f"[COVERAGE] Scene Anchor System loaded: {len(scene_anchor_system.scene_anchors)} scenes")
        except Exception as e:
            logger.warning(f"[COVERAGE] Scene Anchor System unavailable: {e}")

    # Analyze each scene and collect injections
    all_injections = []
    scene_reports = []

    for scene_id, scene_shots in scenes.items():
        analysis = analyze_single_scene(scene_id, scene_shots, story_bible)

        # Get recommendations (missing shot types)
        missing = []
        coverage = analysis.get("coverage_breakdown", {})

        # Check what's missing
        location = scene_shots[0].get("location", "") if scene_shots else ""
        chars = list(set(c for s in scene_shots for c in s.get("characters", [])))[:3]
        time_of_day = scene_shots[0].get("time_of_day", "DAY") if scene_shots else "DAY"

        # Get scene bible context
        scene_bible = None
        mood_desc = ""
        location_desc = ""
        if story_bible:
            for sc in story_bible.get("scenes", []):
                if sc.get("scene_id") == scene_id:
                    scene_bible = sc
                    mood_desc = sc.get("mood", sc.get("emotional_tone", ""))
                    break
            for loc in story_bible.get("locations", story_bible.get("setting", {}).get("locations", [])):
                if isinstance(loc, dict) and loc.get("name", "").upper() in location.upper():
                    location_desc = loc.get("description", "")
                    break

        # Determine atmosphere from scene anchors or story bible
        atmosphere = mood_desc or "cinematic lighting"
        if scene_anchor_system and scene_id in getattr(scene_anchor_system, 'scene_anchors', {}):
            anchor = scene_anchor_system.scene_anchors[scene_id]
            atmosphere = anchor.get("lighting", atmosphere)

        injections_for_scene = []

        # --- ESTABLISHING SHOT ---
        if not coverage.get("has_establishing") and not coverage.get("has_wide"):
            if priority_levels.get("HIGH", 3) >= min_level:
                # Insert BEFORE all other shots in scene
                est_shot = {
                    "shot_id": f"{scene_id}_000A",
                    "scene_id": scene_id,
                    "type": "wide",
                    "shot_type": "establishing",
                    "coverage_angle": "A",
                    "location": location,
                    "time_of_day": time_of_day,
                    "characters": [],
                    "duration": 8,
                    "duration_seconds": 8,
                    "nano_prompt": f"Establishing wide shot. {location}. {location_desc[:80] if location_desc else atmosphere}. Cinematic composition, no characters in frame, environmental mood.",
                    "ltx_motion_prompt": f"Slow atmospheric camera reveal, {atmosphere}, 8s establishing",
                    "is_establishing": True,
                    "is_broll": False,
                    "_injected_by": "coverage_critic",
                    "_injection_reason": "missing_establishing"
                }
                if scene_anchor_system:
                    try:
                        est_shot["nano_prompt"] = scene_anchor_system.enhance_prompt(est_shot)
                    except Exception:
                        pass
                injections_for_scene.append({"position": "before_first", "shot": est_shot})

        # --- B-ROLL / ATMOSPHERE ---
        if not coverage.get("has_broll"):
            if priority_levels.get("MEDIUM", 2) >= min_level:
                # Contextual B-roll based on location
                broll_prompt = "Detail/insert shot: atmospheric texture."
                loc_lower = location.lower()
                if any(w in loc_lower for w in ["manor", "house", "room", "study", "library", "hall"]):
                    broll_prompt = "Insert shot: dust motes floating in shaft of light through tall window. Candlelight flickers on dark wood paneling."
                elif any(w in loc_lower for w in ["grave", "cemetery", "crypt", "tomb"]):
                    broll_prompt = "Insert shot: weathered headstone, moss-covered letters, mist curling around iron gates."
                elif any(w in loc_lower for w in ["forest", "wood", "garden", "path", "road"]):
                    broll_prompt = "Insert shot: twisted branches against sky, leaves rustling, atmospheric light filtering through canopy."
                elif any(w in loc_lower for w in ["church", "chapel", "ritual", "altar"]):
                    broll_prompt = "Insert shot: candles burning on stone altar, chalk symbols on floor, flickering shadows on vaulted ceiling."
                elif any(w in loc_lower for w in ["village", "town", "street", "market"]):
                    broll_prompt = "Insert shot: cobblestone detail, lantern light on wet stone, period-appropriate environmental texture."
                else:
                    broll_prompt = f"Insert shot: environmental detail of {location}. {atmosphere}. No faces, texture and mood."

                broll_shot = {
                    "shot_id": f"{scene_id}_000B",
                    "scene_id": scene_id,
                    "type": "insert",
                    "shot_type": "b-roll",
                    "coverage_angle": "B",
                    "location": location,
                    "time_of_day": time_of_day,
                    "characters": [],
                    "duration": 5,
                    "duration_seconds": 5,
                    "nano_prompt": broll_prompt,
                    "ltx_motion_prompt": f"Subtle movement, atmospheric detail, no faces, {atmosphere}, 5s",
                    "is_establishing": False,
                    "is_broll": True,
                    "_injected_by": "coverage_critic",
                    "_injection_reason": "missing_broll"
                }
                if scene_anchor_system:
                    try:
                        broll_shot["nano_prompt"] = scene_anchor_system.enhance_prompt(broll_shot)
                    except Exception:
                        pass
                injections_for_scene.append({"position": "after_establishing", "shot": broll_shot})

        # --- REACTION SHOT ---
        if not coverage.get("has_reaction") and len(chars) > 1:
            if priority_levels.get("MEDIUM", 2) >= min_level:
                reactor = chars[1] if len(chars) > 1 else chars[0]
                key_moment = "the scene's emotional peak"
                if scene_bible:
                    key_moment = scene_bible.get("key_moment", scene_bible.get("action", key_moment))[:200]

                reaction_shot = {
                    "shot_id": f"{scene_id}_999C",
                    "scene_id": scene_id,
                    "type": "close",
                    "shot_type": "reaction",
                    "coverage_angle": "C",
                    "location": location,
                    "time_of_day": time_of_day,
                    "characters": [reactor],
                    "duration": 6,
                    "duration_seconds": 6,
                    "nano_prompt": f"Close-up reaction shot of {reactor}. Responding to {key_moment}. {atmosphere}. Emotional, off-axis camera angle, face stable.",
                    "ltx_motion_prompt": f"Subtle facial reaction: eyes shift slightly, breath draws in, micro-expression of concern crosses face. Natural breathing visible, slight weight shift. FACE IDENTITY LOCK: features unchanged. 6s",
                    "is_establishing": False,
                    "is_broll": False,
                    "_injected_by": "coverage_critic",
                    "_injection_reason": "missing_reaction"
                }
                if scene_anchor_system:
                    try:
                        reaction_shot["nano_prompt"] = scene_anchor_system.enhance_prompt(reaction_shot)
                    except Exception:
                        pass
                injections_for_scene.append({"position": "before_last", "shot": reaction_shot})

        # --- INSERT / DETAIL SHOT ---
        if not coverage.get("has_insert"):
            if priority_levels.get("LOW", 1) >= min_level:
                insert_prompt = f"Extreme close-up detail shot. Significant object or hand gesture in scene. {atmosphere}."
                if any(w in location.lower() for w in ["study", "desk", "library"]):
                    insert_prompt = f"Insert: hand turning page of ancient book, candlelight catching gilt edges. {atmosphere}."
                elif any(w in location.lower() for w in ["ritual", "altar", "ceremony"]):
                    insert_prompt = f"Insert: fingers tracing chalk symbols on stone, candle wax pooling. {atmosphere}."

                insert_shot = {
                    "shot_id": f"{scene_id}_998B",
                    "scene_id": scene_id,
                    "type": "insert",
                    "shot_type": "insert",
                    "coverage_angle": "B",
                    "location": location,
                    "time_of_day": time_of_day,
                    "characters": [],
                    "duration": 4,
                    "duration_seconds": 4,
                    "nano_prompt": insert_prompt,
                    "ltx_motion_prompt": f"Minimal movement, sharp focus pull, detail texture, 4s",
                    "is_establishing": False,
                    "is_broll": True,
                    "_injected_by": "coverage_critic",
                    "_injection_reason": "missing_insert"
                }
                injections_for_scene.append({"position": "mid_scene", "shot": insert_shot})

        if injections_for_scene:
            all_injections.extend(injections_for_scene)
            scene_reports.append({
                "scene_id": scene_id,
                "location": location,
                "existing_shots": len(scene_shots),
                "injections": len(injections_for_scene),
                "types_injected": [inj["shot"]["shot_type"] for inj in injections_for_scene],
                "coverage_before": analysis.get("coverage_grade", "?"),
                "coverage_score_before": analysis.get("coverage_score", 0)
            })

    # If dry run, just return what would be injected
    if dry_run:
        return {
            "success": True,
            "project": project,
            "dry_run": True,
            "original_shot_count": original_count,
            "injections_planned": len(all_injections),
            "scenes_affected": len(scene_reports),
            "scene_reports": scene_reports,
            "injection_details": [{"scene_id": inj["shot"]["scene_id"], "type": inj["shot"]["shot_type"], "prompt": inj["shot"]["nano_prompt"][:100]} for inj in all_injections]
        }

    # APPLY INJECTIONS to shot plan
    if all_injections:
        # Group injections by scene
        injections_by_scene = defaultdict(list)
        for inj in all_injections:
            injections_by_scene[inj["shot"]["scene_id"]].append(inj)

        # Build new shots list with injections
        new_shots = []
        current_scene_id = None
        scene_shots_buffer = []

        for shot in shots:
            sid = shot.get("scene_id", "unknown")

            # When scene changes, flush previous scene with injections
            if sid != current_scene_id:
                if current_scene_id and current_scene_id in injections_by_scene:
                    # Insert shots at correct positions
                    scene_injections = injections_by_scene[current_scene_id]
                    for inj in scene_injections:
                        pos = inj["position"]
                        if pos == "before_first":
                            new_shots.insert(len(new_shots) - len(scene_shots_buffer), inj["shot"])
                        elif pos == "after_establishing":
                            # After the first shot
                            insert_idx = len(new_shots) - len(scene_shots_buffer) + 1
                            new_shots.insert(insert_idx, inj["shot"])
                        elif pos == "before_last":
                            new_shots.append(inj["shot"])
                        elif pos == "mid_scene":
                            mid = len(new_shots) - len(scene_shots_buffer) // 2
                            new_shots.insert(mid, inj["shot"])
                else:
                    pass  # No injections for this scene

                current_scene_id = sid
                scene_shots_buffer = []

            new_shots.append(shot)
            scene_shots_buffer.append(shot)

        # Handle last scene
        if current_scene_id and current_scene_id in injections_by_scene:
            scene_injections = injections_by_scene[current_scene_id]
            for inj in scene_injections:
                pos = inj["position"]
                if pos == "before_first":
                    new_shots.insert(len(new_shots) - len(scene_shots_buffer), inj["shot"])
                elif pos == "after_establishing":
                    insert_idx = len(new_shots) - len(scene_shots_buffer) + 1
                    new_shots.insert(insert_idx, inj["shot"])
                elif pos == "before_last":
                    new_shots.append(inj["shot"])
                elif pos == "mid_scene":
                    mid = len(new_shots) - len(scene_shots_buffer) // 2
                    new_shots.insert(mid, inj["shot"])

        # Save updated shot plan
        shot_plan["shots"] = new_shots
        shot_plan["_coverage_injected_at"] = datetime.now().isoformat()
        shot_plan["_coverage_injection_count"] = len(all_injections)

        with open(shot_plan_path, 'w') as f:
            json.dump(shot_plan, f, indent=2)

        # Invalidate UI cache
        cache_dir = project_path / "ui_cache"
        if cache_dir.exists():
            (cache_dir / "bundle.dirty").touch()

        logger.info(f"[COVERAGE CRITIC] Injected {len(all_injections)} shots into {project} ({original_count} → {len(new_shots)})")

    return {
        "success": True,
        "project": project,
        "dry_run": False,
        "original_shot_count": original_count,
        "new_shot_count": len(shot_plan.get("shots", [])),
        "injections_applied": len(all_injections),
        "scenes_affected": len(scene_reports),
        "scene_reports": scene_reports,
        "types_summary": {
            "establishing": len([i for i in all_injections if i["shot"].get("shot_type") == "establishing"]),
            "b-roll": len([i for i in all_injections if i["shot"].get("shot_type") == "b-roll"]),
            "reaction": len([i for i in all_injections if i["shot"].get("shot_type") == "reaction"]),
            "insert": len([i for i in all_injections if i["shot"].get("shot_type") == "insert"]),
        }
    }


@app.post("/api/v17/upgrade-project")
async def universal_v17_upgrade(request: Dict = Body(...)):
    """
    V17 UNIVERSAL UPGRADE: Retrofit ANY existing project to full V17 feature parity.

    This is the single endpoint that ensures any project — regardless of when it was
    created or which pipeline version produced it — gets all V17 features:

    1. Scene manifest validation (build from shots if missing)
    2. Coverage injection (establishing, B-roll, reaction, insert shots)
    3. Dialogue extraction from story bible beats
    4. Duration category normalization
    5. Auto-cast if no cast_map exists
    6. Shot role classification fix
    7. Metadata versioning

    Body: {"project": "kord", "dry_run": true, "skip_cast": false}
    """
    project = request.get("project")
    dry_run = request.get("dry_run", True)
    skip_cast = request.get("skip_cast", False)
    min_priority = request.get("min_priority", "MEDIUM")

    if not project:
        return {"success": False, "error": "Project name required"}

    project_path = get_project_path(project)
    if not project_path.exists():
        return {"success": False, "error": f"Project '{project}' not found"}

    shot_plan_path = project_path / "shot_plan.json"
    if not shot_plan_path.exists():
        return {"success": False, "error": f"No shot_plan.json found for '{project}'"}

    with open(shot_plan_path) as f:
        shot_plan = _sp_guard(json.load(f))

    # Load story bible if available
    story_bible = {}
    story_bible_path = project_path / "story_bible.json"
    if story_bible_path.exists():
        with open(story_bible_path) as f:
            story_bible = json.load(f)

    upgrade_report = {
        "project": project,
        "dry_run": dry_run,
        "upgrades": [],
        "before": {},
        "after": {},
        "warnings": []
    }

    shots = shot_plan.get("shots", [])
    scenes = shot_plan.get("scenes", [])
    scene_manifest = shot_plan.get("scene_manifest", [])

    # ── BEFORE SNAPSHOT ──
    def count_shot_types(shot_list):
        types = {"establishing": 0, "b_roll": 0, "reaction": 0, "insert": 0, "dialogue": 0, "action": 0, "other": 0}
        for s in shot_list:
            if not isinstance(s, dict):
                continue
            role = s.get("shot_role", s.get("shot_type", "other"))
            b_roll = s.get("b_roll", False)
            if b_roll or role in ("b-roll", "b_roll", "broll"):
                types["b_roll"] += 1
            elif role == "establishing":
                types["establishing"] += 1
            elif role == "reaction":
                types["reaction"] += 1
            elif role in ("insert", "detail"):
                types["insert"] += 1
            elif role == "dialogue":
                types["dialogue"] += 1
            elif role in ("action", "action_beat"):
                types["action"] += 1
            else:
                types["other"] += 1
        return types

    def count_dialogue(shot_list):
        count = 0
        for s in shot_list:
            if not isinstance(s, dict):
                continue
            d = s.get("dialogue", "") or s.get("dialogue_text", "")
            if d and len(str(d).strip()) > 0:
                count += 1
        return count

    def count_shot_sizes(shot_list):
        sizes = {}
        for s in shot_list:
            if not isinstance(s, dict):
                continue
            size = s.get("shot_size", s.get("type", "unknown")).upper()
            sizes[size] = sizes.get(size, 0) + 1
        return sizes

    upgrade_report["before"] = {
        "total_shots": len(shots),
        "total_scenes": len(scenes) if scenes else len(set(s.get("scene_id", "?") for s in shots if isinstance(s, dict))),
        "has_scene_manifest": len(scene_manifest) > 0,
        "shot_types": count_shot_types(shots),
        "dialogue_shots": count_dialogue(shots),
        "shot_sizes": count_shot_sizes(shots),
        "has_cast_map": (project_path / "cast_map.json").exists()
    }

    # ── PHASE 1: SCENE MANIFEST VALIDATION ──
    if not scene_manifest or len(scene_manifest) == 0:
        # Build scene_manifest from shots by grouping by scene_id
        scene_groups = {}
        for shot in shots:
            if not isinstance(shot, dict):
                continue
            sid = shot.get("scene_id", "000")
            if sid not in scene_groups:
                scene_groups[sid] = {
                    "scene_id": sid,
                    "title": shot.get("location", f"Scene {sid}"),
                    "location": shot.get("location", "UNKNOWN"),
                    "time_of_day": shot.get("time_of_day", "DAY"),
                    "int_ext": shot.get("int_ext", "EXT"),
                    "beats": [],
                    "estimated_duration_seconds": 0
                }
            scene_groups[sid]["estimated_duration_seconds"] += shot.get("duration", 10)

        built_manifest = list(scene_groups.values())
        built_manifest.sort(key=lambda x: x["scene_id"])

        if not dry_run:
            shot_plan["scene_manifest"] = built_manifest

        upgrade_report["upgrades"].append({
            "phase": "scene_manifest",
            "action": "BUILT" if not dry_run else "WOULD_BUILD",
            "scenes_created": len(built_manifest),
            "note": "Built scene_manifest from shot scene_id grouping"
        })
    else:
        upgrade_report["upgrades"].append({
            "phase": "scene_manifest",
            "action": "ALREADY_EXISTS",
            "scene_count": len(scene_manifest)
        })

    # ── PHASE 2: COVERAGE ANALYSIS & INJECTION ──
    # Group shots by scene_id
    scene_shot_map = {}
    for shot in shots:
        if not isinstance(shot, dict):
            continue
        sid = shot.get("scene_id", "000")
        if sid not in scene_shot_map:
            scene_shot_map[sid] = []
        scene_shot_map[sid].append(shot)

    all_injections = []
    scene_reports = []

    for scene_id, scene_shots in sorted(scene_shot_map.items()):
        analysis = analyze_single_scene(scene_id, scene_shots, story_bible)

        if analysis["coverage_score"] >= 85:
            scene_reports.append({
                "scene_id": scene_id,
                "coverage_score": analysis["coverage_score"],
                "grade": analysis["grade"],
                "action": "SKIP_ADEQUATE",
                "injections": 0
            })
            continue

        # Build injections for missing types
        missing = analysis.get("missing_types", [])
        scene_location = scene_shots[0].get("location", "UNKNOWN") if scene_shots else "UNKNOWN"
        scene_chars = []
        for s in scene_shots:
            for c in s.get("characters", []):
                if isinstance(c, str) and c not in scene_chars:
                    scene_chars.append(c)

        # Get scene info from story bible or manifest
        scene_info = {}
        for sc in (scene_manifest or scenes):
            if sc.get("scene_id") == scene_id:
                scene_info = sc
                break

        location_desc = scene_info.get("title", scene_location)
        mood_desc = ""

        # Try to get mood from story bible scenes
        for sb_scene in story_bible.get("scenes", []):
            if sb_scene.get("scene_id") == scene_id:
                mood_desc = sb_scene.get("mood", sb_scene.get("atmosphere", ""))
                break

        injected_for_scene = []

        for missing_type in missing:
            mt = missing_type.get("type", "")
            priority = missing_type.get("priority", "LOW")
            priority_levels = {"HIGH": 3, "MEDIUM": 2, "LOW": 1}
            min_level = priority_levels.get(min_priority, 2)
            if priority_levels.get(priority, 0) < min_level:
                continue

            # Build shot based on type
            new_shot = None

            if mt == "establishing" and not any(s.get("shot_role") == "establishing" for s in scene_shots):
                new_shot = {
                    "shot_id": f"{scene_id}_000A",
                    "scene_id": scene_id,
                    "type": "wide",
                    "shot_size": "EWS",
                    "shot_role": "establishing",
                    "shot_type": "establishing",
                    "b_roll": False,
                    "duration": 8,
                    "duration_seconds": 8,
                    "ltx_duration_seconds": 8,
                    "duration_category": "ShotCategory.ESTABLISHING",
                    "location": scene_location,
                    "characters": [],
                    "nano_prompt": f"Establishing wide shot of {location_desc}. {mood_desc}. Cinematic atmosphere, rich environmental detail. No characters visible, pure location establishment.",
                    "ltx_motion_prompt": "smooth slow_pan, subtle environmental motion, atmospheric particles, gentle lighting shifts",
                    "nano_aspect_ratio": "16:9",
                    "ltx_aspect_ratio": "16:9",
                    "use_pro_model": True,
                    "ltx_compliant": True,
                    "ltx_ready": True,
                    "_injected_by": "v17_universal_upgrade",
                    "_injection_reason": "missing_establishing_shot",
                    "position": "before_first"
                }

            elif mt == "b-roll":
                # Find best position for B-roll (mid-scene transition)
                broll_idx = len(scene_shots) // 2
                ref_shot = scene_shots[min(broll_idx, len(scene_shots)-1)]
                new_shot = {
                    "shot_id": f"{scene_id}_{str(len(scene_shots) + len(injected_for_scene)).zfill(3)}B",
                    "scene_id": scene_id,
                    "type": "medium",
                    "shot_size": "MS",
                    "shot_role": "b_roll",
                    "shot_type": "b-roll",
                    "b_roll": True,
                    "duration": 5,
                    "duration_seconds": 5,
                    "ltx_duration_seconds": 5,
                    "duration_category": "ShotCategory.BROLL",
                    "location": scene_location,
                    "characters": [],
                    "nano_prompt": f"B-roll detail shot at {location_desc}. Environmental texture and atmosphere. {mood_desc}. Cinematic detail, shallow depth of field on environmental element.",
                    "ltx_motion_prompt": "subtle slow_dolly, rack focus, atmospheric detail motion",
                    "nano_aspect_ratio": "16:9",
                    "ltx_aspect_ratio": "16:9",
                    "use_pro_model": True,
                    "ltx_compliant": True,
                    "ltx_ready": True,
                    "_injected_by": "v17_universal_upgrade",
                    "_injection_reason": "missing_broll",
                    "position": "mid_scene"
                }

            elif mt == "reaction" and len(scene_chars) >= 2:
                # Reaction shot for secondary character
                react_char = scene_chars[1] if len(scene_chars) > 1 else scene_chars[0]
                new_shot = {
                    "shot_id": f"{scene_id}_{str(len(scene_shots) + len(injected_for_scene)).zfill(3)}R",
                    "scene_id": scene_id,
                    "type": "close-up",
                    "shot_size": "CU",
                    "shot_role": "reaction",
                    "shot_type": "reaction",
                    "b_roll": False,
                    "duration": 6,
                    "duration_seconds": 6,
                    "ltx_duration_seconds": 6,
                    "duration_category": "ShotCategory.REACTION",
                    "location": scene_location,
                    "characters": [react_char],
                    "nano_prompt": f"Close-up reaction shot of {react_char}. Emotional response, subtle facial expression conveying inner conflict. Shallow depth of field, intimate framing. {mood_desc}.",
                    "ltx_motion_prompt": "static or subtle_drift, micro-expression motion, shallow dof breathing",
                    "nano_aspect_ratio": "16:9",
                    "ltx_aspect_ratio": "16:9",
                    "use_pro_model": True,
                    "ltx_compliant": True,
                    "ltx_ready": True,
                    "_injected_by": "v17_universal_upgrade",
                    "_injection_reason": "missing_reaction_shot",
                    "position": "after_dialogue"
                }

            elif mt == "insert":
                new_shot = {
                    "shot_id": f"{scene_id}_{str(len(scene_shots) + len(injected_for_scene)).zfill(3)}I",
                    "scene_id": scene_id,
                    "type": "close-up",
                    "shot_size": "ECU",
                    "shot_role": "insert",
                    "shot_type": "insert",
                    "b_roll": False,
                    "duration": 4,
                    "duration_seconds": 4,
                    "ltx_duration_seconds": 4,
                    "duration_category": "ShotCategory.INSERT",
                    "location": scene_location,
                    "characters": [],
                    "nano_prompt": f"Extreme close-up insert shot. Detail of key prop or environmental element at {location_desc}. Shallow depth of field, dramatic lighting, textural detail.",
                    "ltx_motion_prompt": "static, subtle rack_focus, atmospheric dust particles",
                    "nano_aspect_ratio": "16:9",
                    "ltx_aspect_ratio": "16:9",
                    "use_pro_model": True,
                    "ltx_compliant": True,
                    "ltx_ready": True,
                    "_injected_by": "v17_universal_upgrade",
                    "_injection_reason": "missing_insert_shot",
                    "position": "mid_scene"
                }

            if new_shot:
                injected_for_scene.append(new_shot)
                all_injections.append({
                    "scene_id": scene_id,
                    "shot": new_shot,
                    "reason": new_shot["_injection_reason"]
                })

        scene_reports.append({
            "scene_id": scene_id,
            "coverage_before": analysis["coverage_score"],
            "grade_before": analysis["grade"],
            "missing_types": [m["type"] for m in missing],
            "injections": len(injected_for_scene),
            "injected_types": [s["shot_type"] for s in injected_for_scene]
        })

    # ── PHASE 3: DIALOGUE EXTRACTION FROM BEATS ──
    # V21.7: Track assigned dialogue per scene to prevent duplicates
    _p3_dlg_assigned = {}  # scene_id → set of normalized dialogue strings
    # Pre-populate with existing dialogue
    for _p3s in shots:
        if not isinstance(_p3s, dict):
            continue
        _p3d = (_p3s.get("dialogue", "") or _p3s.get("dialogue_text", "") or "").strip()
        if _p3d:
            _p3sid = _p3s.get("scene_id", "")
            if _p3sid not in _p3_dlg_assigned:
                _p3_dlg_assigned[_p3sid] = set()
            _p3_dlg_assigned[_p3sid].add(_p3d.lower()[:80])

    dialogue_fixes = 0
    dialogue_dups_prevented = 0
    for shot in shots:
        if not isinstance(shot, dict):
            continue
        # If shot has no dialogue but references a beat with dialogue
        current_dialogue = shot.get("dialogue", "") or shot.get("dialogue_text", "")
        if current_dialogue:
            continue

        # Check scene_manifest beats for dialogue
        sid = shot.get("scene_id", "")
        beat_num = shot.get("beat_number", -1)

        for scene in (scene_manifest or []):
            if scene.get("scene_id") != sid:
                continue
            beats = scene.get("beats", [])
            if not isinstance(beats, list):
                continue
            for beat in beats:
                if not isinstance(beat, dict):
                    continue
                if beat.get("beat_number") == beat_num:
                    beat_dialogue = beat.get("dialogue", "")
                    if beat_dialogue and len(str(beat_dialogue).strip()) > 0:
                        # V21.7: DEDUP — skip if this dialogue was already assigned
                        _norm_dlg = beat_dialogue.strip().lower()[:80]
                        _assigned_set = _p3_dlg_assigned.get(sid, set())
                        if _norm_dlg in _assigned_set:
                            dialogue_dups_prevented += 1
                            break  # Skip — already assigned to another shot
                        if not dry_run:
                            shot["dialogue"] = beat_dialogue
                            shot["dialogue_text"] = beat_dialogue
                            if sid not in _p3_dlg_assigned:
                                _p3_dlg_assigned[sid] = set()
                            _p3_dlg_assigned[sid].add(_norm_dlg)
                        dialogue_fixes += 1
                    break

    upgrade_report["upgrades"].append({
        "phase": "dialogue_extraction",
        "action": f"{'FIXED' if not dry_run else 'WOULD_FIX'} {dialogue_fixes} shots",
        "shots_with_dialogue_added": dialogue_fixes
    })

    # ── PHASE 4: DURATION CATEGORY NORMALIZATION ──
    category_fixes = 0
    for shot in shots:
        if not isinstance(shot, dict):
            continue
        role = shot.get("shot_role", "")
        current_cat = shot.get("duration_category", "")

        # Map role to correct duration category
        role_to_category = {
            "establishing": "ShotCategory.ESTABLISHING",
            "action": "ShotCategory.ACTION",
            "action_beat": "ShotCategory.ACTION",
            "dialogue": "ShotCategory.DIALOGUE",
            "reaction": "ShotCategory.REACTION",
            "b_roll": "ShotCategory.BROLL",
            "b-roll": "ShotCategory.BROLL",
            "insert": "ShotCategory.INSERT",
            "closing": "ShotCategory.CLOSING",
            "transition": "ShotCategory.TRANSITION",
        }

        expected = role_to_category.get(role, "")
        if expected and current_cat != expected:
            if not dry_run:
                shot["duration_category"] = expected
            category_fixes += 1

    upgrade_report["upgrades"].append({
        "phase": "duration_categories",
        "action": f"{'FIXED' if not dry_run else 'WOULD_FIX'} {category_fixes} shots",
        "categories_corrected": category_fixes
    })

    # ── PHASE 5: INJECT NEW SHOTS INTO SHOT PLAN ──
    if all_injections and not dry_run:
        for injection in all_injections:
            shot = injection["shot"]
            sid = injection["scene_id"]
            position = shot.pop("position", "mid_scene")

            # Find insertion index
            scene_start_idx = None
            scene_end_idx = None
            for i, existing in enumerate(shots):
                if not isinstance(existing, dict):
                    continue
                if existing.get("scene_id") == sid:
                    if scene_start_idx is None:
                        scene_start_idx = i
                    scene_end_idx = i

            if scene_start_idx is None:
                shots.append(shot)
            elif position == "before_first":
                shots.insert(scene_start_idx, shot)
            elif position == "after_dialogue":
                # Insert after first dialogue shot in scene
                insert_idx = scene_end_idx
                for i in range(scene_start_idx, scene_end_idx + 1):
                    if isinstance(shots[i], dict) and (shots[i].get("dialogue") or shots[i].get("dialogue_text")):
                        insert_idx = i + 1
                        break
                shots.insert(insert_idx, shot)
            else:  # mid_scene
                mid = (scene_start_idx + scene_end_idx) // 2
                shots.insert(mid + 1, shot)

            # Also inject into scenes[].shots if scenes structure exists
            for scene in scenes:
                if scene.get("scene_id") == sid:
                    scene_shots_list = scene.get("shots", [])
                    if position == "before_first":
                        scene_shots_list.insert(0, shot)
                    elif position == "after_dialogue":
                        inserted = False
                        for j, ss in enumerate(scene_shots_list):
                            if isinstance(ss, dict) and (ss.get("dialogue") or ss.get("dialogue_text")):
                                scene_shots_list.insert(j + 1, shot)
                                inserted = True
                                break
                        if not inserted:
                            scene_shots_list.append(shot)
                    else:
                        mid = len(scene_shots_list) // 2
                        scene_shots_list.insert(mid, shot)
                    break

        shot_plan["shots"] = shots
        if scenes:
            shot_plan["scenes"] = scenes

    upgrade_report["upgrades"].append({
        "phase": "coverage_injection",
        "action": f"{'INJECTED' if not dry_run else 'WOULD_INJECT'} {len(all_injections)} shots",
        "total_injections": len(all_injections),
        "types_summary": {
            "establishing": len([i for i in all_injections if i["shot"].get("shot_type") == "establishing"]),
            "b-roll": len([i for i in all_injections if i["shot"].get("shot_type") == "b-roll"]),
            "reaction": len([i for i in all_injections if i["shot"].get("shot_type") == "reaction"]),
            "insert": len([i for i in all_injections if i["shot"].get("shot_type") == "insert"]),
        },
        "scene_reports": scene_reports
    })

    # ── PHASE 6: AUTO-CAST CHECK ──
    cast_status = "SKIP"
    cast_map_path = project_path / "cast_map.json"
    if not cast_map_path.exists() and not skip_cast and not dry_run:
        # Trigger auto-cast internally
        try:
            cast_result = await auto_cast_project({"project": project})
            if cast_result.get("success"):
                cast_status = f"CAST {cast_result.get('characters_cast', 0)} characters"
            else:
                cast_status = f"CAST_FAILED: {cast_result.get('error', 'unknown')}"
        except Exception as e:
            cast_status = f"CAST_ERROR: {str(e)}"
    elif cast_map_path.exists():
        cast_status = "ALREADY_CAST"
    elif skip_cast:
        cast_status = "SKIPPED_BY_REQUEST"
    elif dry_run:
        cast_status = "WOULD_CAST" if not cast_map_path.exists() else "ALREADY_CAST"

    upgrade_report["upgrades"].append({
        "phase": "auto_cast",
        "action": cast_status
    })

    # ── PHASE 7: METADATA VERSIONING ──
    if not dry_run:
        if "metadata" not in shot_plan:
            shot_plan["metadata"] = {}
        shot_plan["metadata"]["v17_upgraded"] = True
        shot_plan["metadata"]["v17_upgrade_at"] = datetime.now().isoformat()
        shot_plan["metadata"]["v17_upgrade_version"] = "17.1.0"
        shot_plan["metadata"]["v17_shots_injected"] = len(all_injections)
        shot_plan["metadata"]["v17_dialogue_fixes"] = dialogue_fixes
        shot_plan["metadata"]["v17_category_fixes"] = category_fixes
        shot_plan["metadata"]["total_shots"] = len(shots)

        # Write updated shot plan
        with open(shot_plan_path, 'w') as f:
            json.dump(shot_plan, f, indent=2)

        # Invalidate UI cache
        cache_dir = project_path / "ui_cache"
        if cache_dir.exists():
            (cache_dir / "bundle.dirty").touch()

        logger.info(f"[V17 UPGRADE] Project '{project}' upgraded: +{len(all_injections)} shots, {dialogue_fixes} dialogue fixes, {category_fixes} category fixes")

    # ── AFTER SNAPSHOT ──
    final_shots = shot_plan.get("shots", shots)
    upgrade_report["after"] = {
        "total_shots": len(final_shots),
        "shot_types": count_shot_types(final_shots),
        "dialogue_shots": count_dialogue(final_shots),
        "shot_sizes": count_shot_sizes(final_shots),
        "has_scene_manifest": len(shot_plan.get("scene_manifest", [])) > 0,
        "has_cast_map": cast_map_path.exists()
    }

    upgrade_report["success"] = True
    upgrade_report["summary"] = (
        f"V17 Upgrade {'(DRY RUN) ' if dry_run else ''}for {project}: "
        f"{len(all_injections)} shots injected, "
        f"{dialogue_fixes} dialogue fixes, "
        f"{category_fixes} category fixes, "
        f"cast: {cast_status}"
    )

    return upgrade_report


@app.post("/api/v17/upgrade-all")
async def universal_v17_upgrade_all(request: Dict = Body(...)):
    """
    V17 UNIVERSAL UPGRADE ALL: Apply V17 upgrade to multiple projects at once.

    Body: {"projects": ["kord", "kord_v17"], "dry_run": true}
    If projects is empty or missing, upgrades ALL projects with shot_plan.json.
    """
    projects = request.get("projects", [])
    dry_run = request.get("dry_run", True)
    min_priority = request.get("min_priority", "MEDIUM")

    # If no projects specified, find all with shot_plan.json
    if not projects:
        outputs_dir = PIPELINE_OUTPUTS_DIR
        if outputs_dir.exists():
            for d in sorted(outputs_dir.iterdir()):
                if d.is_dir() and (d / "shot_plan.json").exists():
                    projects.append(d.name)

    results = {}
    success_count = 0
    fail_count = 0
    total_injections = 0

    for project in projects:
        try:
            result = await universal_v17_upgrade({
                "project": project,
                "dry_run": dry_run,
                "min_priority": min_priority
            })
            results[project] = {
                "success": result.get("success", False),
                "summary": result.get("summary", ""),
                "injections": result.get("upgrades", [{}])[-3].get("total_injections", 0) if len(result.get("upgrades", [])) >= 3 else 0
            }
            if result.get("success"):
                success_count += 1
                # Find coverage injection phase
                for upgrade in result.get("upgrades", []):
                    if upgrade.get("phase") == "coverage_injection":
                        total_injections += upgrade.get("total_injections", 0)
            else:
                fail_count += 1
        except Exception as e:
            results[project] = {"success": False, "error": str(e)}
            fail_count += 1

    return {
        "success": True,
        "dry_run": dry_run,
        "projects_processed": len(projects),
        "success_count": success_count,
        "fail_count": fail_count,
        "total_injections": total_injections,
        "results": results
    }


@app.post("/api/v17/prompt/enhance")
async def enhance_prompt(request: Dict = Body(...)):
    """
    V17: Enhance a basic prompt to cinematic quality.
    Uses story bible context for atmosphere and character details.
    """
    project = request.get("project")
    shot_id = request.get("shot_id")
    current_prompt = request.get("prompt", "")
    prompt_type = request.get("type", "nano")  # nano or ltx

    if not project or not current_prompt:
        return {"success": False, "error": "project and prompt required"}

    project_path = get_project_path(project)
    story_bible_path = project_path / "story_bible.json"
    shot_plan_path = project_path / "shot_plan.json"

    # Load context
    story_bible = {}
    if story_bible_path.exists():
        with open(story_bible_path) as f:
            story_bible = json.load(f)

    shot_context = {}
    if shot_plan_path.exists() and shot_id:
        with open(shot_plan_path) as f:
            data = json.load(f)
        for shot in data.get("shots", []):
            if shot.get("shot_id") == shot_id:
                shot_context = shot
                break

    # Score current prompt
    current_score = score_prompt_quality(current_prompt)

    # Build enhanced prompt
    enhanced = current_prompt
    additions = []

    # Add atmosphere if missing
    if "atmosphere" in current_score.get("issues", []) or "lighting" in " ".join(current_score.get("issues", [])).lower():
        location = shot_context.get("location", "")
        if "manor" in location.lower() or "interior" in location.lower():
            additions.append("warm candlelight, rich shadows, dust motes visible in light shafts")
        elif "exterior" in location.lower() or "outside" in location.lower():
            additions.append("natural lighting, atmospheric haze, depth and dimension")
        else:
            additions.append("atmospheric lighting, rich texture and mood")

    # Add emotion if missing
    if "emotion" in " ".join(current_score.get("issues", [])).lower():
        mood = shot_context.get("emotional_tone", "")
        if mood:
            additions.append(f"emotional tone: {mood}")
        else:
            additions.append("subtle emotional weight in composition")

    # Combine basic additions
    if additions:
        enhanced = f"{current_prompt.rstrip('.')}. {', '.join(additions)}."

    # V17.3: Load director + writer profiles via central helpers
    director_profile = load_director_for_project(project_path, story_bible)
    writer_profile = load_writer_for_project(project_path, story_bible)

    # V17.1: Apply full cinematic enricher on top
    try:
        from tools.cinematic_enricher import get_enricher
        genre = _resolve_genre_from_story_bible(story_bible)
        enricher = get_enricher(
            genre=genre,
            director_profile=director_profile,
            writer_profile=writer_profile,
            story_bible=story_bible,
            force_new=True
        )
        if prompt_type == "ltx":
            enhanced = enricher.enrich_ltx_prompt(enhanced, shot_context)
        else:
            enhanced = enricher.enrich_nano_prompt(enhanced, shot_context)
    except Exception as e:
        logger.warning(f"[V17.1] Enricher in prompt/enhance failed: {e}")

    # Score enhanced
    enhanced_score = score_prompt_quality(enhanced)

    return {
        "success": True,
        "original": {
            "prompt": current_prompt,
            "grade": current_score["grade"],
            "score": current_score["score"]
        },
        "enhanced": {
            "prompt": enhanced,
            "grade": enhanced_score["grade"],
            "score": enhanced_score["score"]
        },
        "additions": additions,
        "improvement": enhanced_score["score"] - current_score["score"]
    }


# =============================================================================
# V17 DIRECTOR TOOLS - Nano-Pro Reframe, Kling Upgrade, Blocking Helper
# =============================================================================

def normalize_segments(shot: Dict) -> List[Dict]:
    """
    V17: Safely normalize segments from any shot structure.
    Prevents NoneType crashes throughout the system.

    V17 FIX: Now handles segment cleanup when duration decreases.
    - If duration <= 20s: CLEAR all segments (single-segment shot)
    - If duration > 20s but segment sum mismatches: REGENERATE segments
    - If no segments and duration > 20s: AUTO-GENERATE segments
    """
    segs = shot.get("segments") or shot.get("render_plan", {}).get("segments") or []
    if segs is None:
        segs = []

    duration = shot.get("duration") or shot.get("duration_seconds") or 10

    # V17 FIX: Clear segments for short shots (they don't need segments)
    if duration <= 20:
        if segs:
            logger.info(f"[V17 FIX] Clearing {len(segs)} stale segments for {duration}s shot")
        return []  # Short shots never need segments

    # V17 FIX: Check if existing segments are valid (sum matches duration)
    if segs:
        seg_total = sum(s.get("duration", 0) for s in segs if isinstance(s.get("duration"), (int, float)))
        num_expected = max(1, (duration + 19) // 20)
        # Regenerate if: wrong count, or sum deviates > 2s from shot duration
        if len(segs) != num_expected or abs(seg_total - duration) > 2.0:
            logger.info(f"[V17 FIX] Regenerating segments: {len(segs)} segs totaling {seg_total}s for {duration}s shot (expected {num_expected} segs)")
            segs = []  # Force regeneration below

    # Auto-generate segment structure for extended shots without segments
    if not segs and duration > 20:
        num_segs = max(1, (duration + 19) // 20)
        seg_dur = duration / num_segs
        segs = []
        for i in range(num_segs):
            # Last segment gets remainder to ensure exact sum
            if i == num_segs - 1:
                this_dur = round(duration - (seg_dur * i), 1)
            else:
                this_dur = round(seg_dur, 1)
            segs.append({
                "segment_index": i,
                "duration": this_dur,
                "type": "base" if i == 0 else "continuation",
                "stitch_method": "first_frame" if i == 0 else "last_frame_to_first",
                "ltx_motion_prompt": shot.get("ltx_motion_prompt", "")
            })

    # Normalize each segment
    for i, seg in enumerate(segs):
        if "segment_index" not in seg:
            seg["segment_index"] = i
        if not seg.get("type"):
            seg["type"] = "base" if i == 0 else "continuation"
        if not seg.get("stitch_method"):
            seg["stitch_method"] = "first_frame" if i == 0 else "last_frame_to_first"
        if not seg.get("ltx_motion_prompt"):
            seg["ltx_motion_prompt"] = shot.get("ltx_motion_prompt", "")

    return segs


def get_director_overrides(project: str) -> Dict:
    """Load or create director_overrides.json for a project."""
    project_path = get_project_path(project)
    overrides_path = project_path / "director_overrides.json"

    if overrides_path.exists():
        with open(overrides_path) as f:
            return json.load(f)

    return {
        "_created": datetime.now().isoformat(),
        "shots": {}
    }


def save_director_overrides(project: str, overrides: Dict):
    """Save director_overrides.json for a project."""
    project_path = get_project_path(project)
    overrides_path = project_path / "director_overrides.json"

    overrides["_updated"] = datetime.now().isoformat()
    with open(overrides_path, 'w') as f:
        json.dump(overrides, f, indent=2)


def ensure_director_tools_dir(project: str, shot_id: str) -> Path:
    """Create director_tools directory structure for a shot."""
    project_path = get_project_path(project)
    tools_dir = project_path / "director_tools" / shot_id
    (tools_dir / "frames").mkdir(parents=True, exist_ok=True)
    (tools_dir / "videos").mkdir(parents=True, exist_ok=True)
    return tools_dir


def ensure_performance_marker(shot: dict, ltx_prompt: str) -> str:
    """
    V23 FIX: Ensure character shots have performance markers in LTX prompt.
    Called JUST BEFORE sending to FAL for video generation.

    Without performance markers, LTX-2 generates static faces and robot-like
    movement. This function guarantees every character shot has one of:
      - "character speaks:" (for dialogue)
      - "character performs:" (for action)
      - "character reacts:" (for reaction shots)

    Args:
        shot: Shot dict with characters, dialogue_text, beat info
        ltx_prompt: Current LTX motion prompt

    Returns:
        LTX prompt with performance marker guaranteed (or original if no chars)
    """
    characters = shot.get("characters", [])
    if isinstance(characters, str):
        characters = [c.strip() for c in characters.split(",") if c.strip()]

    # Skip if no characters (establishing, B-roll, environment shots)
    if not characters:
        return ltx_prompt

    ltx_lower = ltx_prompt.lower()

    # Check if already has a performance marker
    if any(m in ltx_lower for m in ["character speaks:", "character performs:", "character reacts:"]):
        return ltx_prompt

    # Build appropriate marker based on shot content
    primary_char = characters[0] if characters else "Character"
    dialogue = (shot.get("dialogue_text") or shot.get("dialogue") or "").strip()
    beat_action = (shot.get("_beat_action") or shot.get("beat_text") or shot.get("beat") or "").strip()
    emotion = (shot.get("emotion") or shot.get("emotion_state") or "").strip()
    subtext = (shot.get("subtext") or "").strip()

    if dialogue:
        # Dialogue shot
        dlg_clip = dialogue[:200]
        marker = (
            f"{primary_char} speaks: \"{dlg_clip}\". "
            f"Performance: {emotion or 'controlled intensity'}. "
            f"Subtext: {subtext or 'the words carry weight'}. "
        )
    elif beat_action:
        # Action shot
        marker = (
            f"{primary_char} performs: {beat_action[:150]}. "
            f"Emotion: {emotion or 'quiet tension'}. "
        )
    else:
        # Fallback — character present but no specific action
        marker = (
            f"{primary_char} performs: observes intently, subtle reaction. "
            f"Emotion: {emotion or 'engaged awareness'}. "
        )

    # PREPEND marker — performance direction takes priority
    result = f"PERFORMANCE MANDATORY: {marker}{ltx_prompt}"
    logger.info(f"[V23 PERFORMANCE GATE] Injected marker for {shot.get('shot_id', '?')}: {marker[:80]}...")
    return result


@app.post("/api/v17/shot/qwen-reframe")
async def qwen_reframe_shot(request: Dict = Body(...)):
    """
    V21 DIRECTOR TOOL: Nano-Pro-Edit for angle changes (Rule 123: Qwen REMOVED).

    Takes current first frame and generates a new angle/composition
    via fal-ai/nano-banana-pro/edit with REFRAME ONLY prompt.
    Saves as alternate frame, optionally sets as active.

    Body:
    {
        "project": "ravencroft_v17",
        "shot_id": "E011_S01_000A",
        "instruction": "Change to over-the-shoulder angle from behind Lady Margaret",
        "angle_preset": "ots_left",
        "set_active": true
    }
    """
    project = request.get("project")
    shot_id = request.get("shot_id")
    instruction = request.get("instruction", "")
    angle_preset = request.get("angle_preset")
    set_active = request.get("set_active", True)

    if not project or not shot_id:
        return {"success": False, "error": "project and shot_id required"}

    # Build instruction from preset if not provided
    ANGLE_PRESETS = {
        "ots_left": "Change camera angle to over-the-shoulder from behind, camera positioned left. Maintain character identity, wardrobe, and lighting.",
        "ots_right": "Change camera angle to over-the-shoulder from behind, camera positioned right. Maintain character identity, wardrobe, and lighting.",
        "low_angle": "Change to low angle camera looking up at subject. Creates dramatic, powerful perspective. Maintain all character details.",
        "high_angle": "Change to high angle camera looking down at subject. Creates vulnerable, exposed perspective. Maintain all character details.",
        "profile_left": "Change to side profile view from the left. Cinematic composition. Maintain character identity and lighting.",
        "profile_right": "Change to side profile view from the right. Cinematic composition. Maintain character identity and lighting.",
        "wider": "Pull camera back for wider shot. Show more environment while keeping subject as focal point. Maintain all details.",
        "tighter": "Push camera in for tighter framing. More intimate, focus on facial expression. Maintain character identity.",
        "reverse": "Reverse angle - show the scene from the opposite perspective. Maintain spatial relationships and lighting.",
        "dutch": "Add slight dutch angle (tilted horizon) for tension. Keep composition balanced. Maintain all details."
    }

    if angle_preset and angle_preset in ANGLE_PRESETS:
        instruction = ANGLE_PRESETS[angle_preset]
    elif not instruction:
        return {"success": False, "error": "instruction or angle_preset required"}

    project_path = get_project_path(project)

    # Find the current first frame
    overrides = get_director_overrides(project)
    shot_overrides = overrides.get("shots", {}).get(shot_id, {})

    # Priority: override > first_frames folder > none
    current_frame = None
    if shot_overrides.get("selected_first_frame"):
        current_frame = project_path / shot_overrides["selected_first_frame"]
    else:
        first_frames_dir = project_path / "first_frames"
        for ext in [".jpg", ".png", ".jpeg"]:
            candidate = first_frames_dir / f"{shot_id}{ext}"
            if candidate.exists():
                current_frame = candidate
                break

    if not current_frame or not current_frame.exists():
        return {"success": False, "error": f"No first frame found for {shot_id}. Generate first frame first."}

    # Create director tools directory
    tools_dir = ensure_director_tools_dir(project, shot_id)

    # Generate version number
    existing_frames = list((tools_dir / "frames").glob("reframe_*.png"))
    version = len(existing_frames) + 1
    output_filename = f"reframe_{angle_preset or 'custom'}_v{version:03d}.png"
    output_path = tools_dir / "frames" / output_filename

    try:
        # V21: Call nano-pro-edit for reframing (Rule 123: Qwen REMOVED)
        import fal_client

        # Upload source frame to FAL
        image_url = fal_client.upload(current_frame, "image/png")

        # Build REFRAME ONLY prompt with anti-morphing protection
        reframe_prompt = (
            "REFRAME ONLY. Use the provided image as the single source of truth. "
            "Do NOT change environment, room, props, objects, lighting, shadows, or color grade. "
            "Do NOT add or remove anything. Do NOT relocate characters. "
            "Preserve exact face identity, hairstyle, wardrobe, skin tone. "
            "NO morphing faces, NO grid, NO collage, face stable, identity locked. "
            f"{instruction}"
        )

        # Build image_urls — source frame first, then character refs if available
        _image_urls = [image_url]

        # V21 FIX: DO NOT add character reference headshots to reframe calls.
        # They bleed into the output and overtake the reframe — close_detail
        # becomes a headshot portrait instead of a reframed scene.
        # The character is already IN the source frame — Rule 135.

        result = fal_client.run(
            "fal-ai/nano-banana-pro/edit",
            arguments={
                "image_urls": _image_urls,
                "prompt": reframe_prompt,
                "seed": int(datetime.now().timestamp()) % 1000000
            }
        )

        # Download result
        if result and result.get("images") and len(result["images"]) > 0:
            import urllib.request
            result_url = result["images"][0]["url"] if isinstance(result["images"][0], dict) else result["images"][0]
            urllib.request.urlretrieve(result_url, output_path)
            logger.info(f"[NANO-REFRAME] Generated {output_path}")
        elif result and result.get("image"):
            import urllib.request
            result_url = result["image"]["url"] if isinstance(result["image"], dict) else result["image"]
            urllib.request.urlretrieve(result_url, output_path)
            logger.info(f"[NANO-REFRAME] Generated {output_path}")
        else:
            return {"success": False, "error": "Nano-pro-edit returned no image"}

    except Exception as e:
        logger.error(f"[NANO-REFRAME] Error: {e}")
        return {"success": False, "error": str(e)}

    # Update director overrides
    relative_path = f"director_tools/{shot_id}/frames/{output_filename}"

    if shot_id not in overrides.get("shots", {}):
        overrides.setdefault("shots", {})[shot_id] = {}

    shot_data = overrides["shots"][shot_id]
    shot_data.setdefault("alt_first_frames", [])

    if relative_path not in shot_data["alt_first_frames"]:
        shot_data["alt_first_frames"].append(relative_path)

    if set_active:
        shot_data["selected_first_frame"] = relative_path
        shot_data["_last_reframe"] = datetime.now().isoformat()
        shot_data["_last_reframe_instruction"] = instruction

    save_director_overrides(project, overrides)

    # Invalidate UI cache
    cache_dir = project_path / "ui_cache"
    if cache_dir.exists():
        (cache_dir / "bundle.dirty").touch()

    return {
        "success": True,
        "project": project,
        "shot_id": shot_id,
        "output_path": str(output_path),
        "relative_path": relative_path,
        "set_as_active": set_active,
        "instruction": instruction,
        "version": version
    }


# ── V18.4 KLING JOB TRACKER ──
_KLING_JOBS = {}  # job_id → {status, shot_id, project, started, progress, ...}
_KLING_JOBS_LOCK = Lock()

def _kling_background_worker(job_id, project, shot_id, prompt, duration, aspect_ratio,
                              frame_path, output_path, output_filename, version,
                              char_ref_urls=None, negative_prompt=None):
    """Background worker for Kling I2V — runs in thread with live status updates.

    V27.2: Now accepts char_ref_urls for Kling Elements identity lock.
    Kling v3 Pro supports up to 2 elements with frontal_image_url + reference_image_urls.
    This is the FIX for the young-man-instead-of-62yo identity drift incident.
    """
    import time as _time
    try:
        with _KLING_JOBS_LOCK:
            _KLING_JOBS[job_id]["status"] = "uploading"
            _KLING_JOBS[job_id]["progress"] = "Uploading frame to cloud..."
        LIVE_GEN_TRACKER.update(f"KLING_{shot_id}", "running")

        import fal_client

        # Upload first frame
        r2_key = f"{project}/{shot_id}_{int(_time.time())}.jpg"
        image_url = None
        if R2_ENABLED:
            image_url = r2_upload_file(Path(frame_path), r2_key)
            if image_url:
                logger.info(f"[KLING-I2V] R2 upload: {image_url}")
        if not image_url:
            try:
                image_url = fal_client.upload_file(frame_path)
            except AttributeError:
                with open(frame_path, "rb") as f:
                    image_url = fal_client.upload(f, "image/jpeg")
            logger.info(f"[KLING-I2V] FAL fallback: {image_url}")

        # V27.2: Upload character refs for Kling Elements identity lock
        elements = []
        if char_ref_urls:
            for ci, ref_path in enumerate(char_ref_urls[:2]):  # Max 2 elements
                if not ref_path or not Path(ref_path).exists():
                    continue
                ref_url = None
                if R2_ENABLED:
                    _ref_r2_key = f"{project}/refs/{Path(ref_path).name}"
                    ref_url = r2_upload_file(Path(ref_path), _ref_r2_key)
                if not ref_url:
                    try:
                        ref_url = fal_client.upload_file(str(ref_path))
                    except Exception:
                        try:
                            with open(ref_path, "rb") as rf:
                                ref_url = fal_client.upload(rf, "image/jpeg")
                        except Exception as _ue:
                            logger.warning(f"[KLING-I2V] Ref upload failed for {ref_path}: {_ue}")
                            continue
                if ref_url:
                    elements.append({"frontal_image_url": ref_url, "reference_image_urls": [ref_url]})
                    logger.info(f"[KLING-I2V] Character ref {ci+1} uploaded for identity lock: {Path(ref_path).name}")

        output_path_obj = Path(output_path)
        output_path_obj.parent.mkdir(parents=True, exist_ok=True)

        with _KLING_JOBS_LOCK:
            _KLING_JOBS[job_id]["status"] = "generating"
            _el_count = len(elements)
            _KLING_JOBS[job_id]["progress"] = f"Kling rendering {duration}s video ({_el_count} identity elements)..."

        # V27.2: Build Kling API arguments with identity lock
        kling_args = {
            "prompt": prompt,
            "start_image_url": image_url,
            "duration": str(duration),
            "aspect_ratio": aspect_ratio,
            "negative_prompt": negative_prompt or "blur, distort, low quality, morphing faces, identity drift, grid pattern, split screen",
            "cfg_scale": 0.5,
        }

        # Add identity elements if we have character refs
        if elements:
            kling_args["elements"] = elements
            # Inject @Element tags into prompt so Kling binds identity
            if "@Element1" not in prompt:
                kling_args["prompt"] = f"@Element1 {prompt}"
                if len(elements) > 1 and "@Element2" not in prompt:
                    kling_args["prompt"] = f"@Element1 @Element2 {prompt}"
            logger.info(f"[KLING-I2V] {shot_id}: {len(elements)} identity elements bound to video generation")
        else:
            logger.warning(f"[KLING-I2V] {shot_id}: NO character refs — identity lock UNAVAILABLE (drift risk)")

        # Call Kling — with elements this can take 5-8 minutes
        # Use fal_client.run() which goes through our non-blocking wrapper (now 600s for Kling)
        result = fal_client.run(
            "fal-ai/kling-video/v3/pro/image-to-video",
            arguments=kling_args
        )

        if result and result.get("video"):
            with _KLING_JOBS_LOCK:
                _KLING_JOBS[job_id]["status"] = "downloading"
                _KLING_JOBS[job_id]["progress"] = "Downloading video..."

            import urllib.request
            video_data = result["video"]
            video_url = video_data["url"] if isinstance(video_data, dict) else video_data
            urllib.request.urlretrieve(video_url, str(output_path_obj))
            logger.info(f"[KLING-I2V] Generated {output_path}")

            # Update director overrides
            relative_path = f"director_tools/{shot_id}/videos/{output_filename}"
            overrides = get_director_overrides(project)
            if shot_id not in overrides.get("shots", {}):
                overrides.setdefault("shots", {})[shot_id] = {}
            shot_data = overrides["shots"][shot_id]
            shot_data.setdefault("video_variants", {})
            shot_data["video_variants"][f"kling_v{version}"] = relative_path
            shot_data["_last_kling_gen"] = datetime.now().isoformat()
            save_director_overrides(project, overrides)

            # Also save to main videos_kling/ for bundle discovery
            project_path = get_project_path(project)
            kling_dir = project_path / "videos_kling"
            kling_dir.mkdir(parents=True, exist_ok=True)
            main_kling_path = kling_dir / f"{shot_id}.mp4"
            import shutil
            shutil.copy2(str(output_path_obj), str(main_kling_path))

            with _KLING_JOBS_LOCK:
                _KLING_JOBS[job_id]["status"] = "completed"
                _KLING_JOBS[job_id]["progress"] = "Done!"
                _KLING_JOBS[job_id]["output_path"] = str(output_path_obj)
                _KLING_JOBS[job_id]["relative_path"] = relative_path
                _KLING_JOBS[job_id]["completed_at"] = datetime.now().isoformat()

            LIVE_GEN_TRACKER.update(f"KLING_{shot_id}", "completed",
                url=f"/api/media?path={relative_path}")

            # Invalidate bundle cache so UI picks up new video
            _invalidate_bundle_cache(project)
        else:
            with _KLING_JOBS_LOCK:
                _KLING_JOBS[job_id]["status"] = "error"
                _KLING_JOBS[job_id]["progress"] = f"No video returned: {result}"
            LIVE_GEN_TRACKER.update(f"KLING_{shot_id}", "error")

    except Exception as e:
        logger.error(f"[KLING-I2V] Error: {e}", exc_info=True)
        with _KLING_JOBS_LOCK:
            _KLING_JOBS[job_id]["status"] = "error"
            _KLING_JOBS[job_id]["progress"] = str(e)
        LIVE_GEN_TRACKER.update(f"KLING_{shot_id}", "error")


@app.post("/api/v17/shot/kling-i2v")
async def kling_image_to_video(request: Dict = Body(...)):
    """
    V18.4 DIRECTOR TOOL: Kling Image-to-Video — ASYNC with live status tracking.

    Launches Kling generation in background thread. Returns immediately with job_id.
    Poll /api/v18/kling/status/{job_id} for progress updates.

    Body:
    {
        "project": "ravencroft_v17",
        "shot_id": "E011_S01_000A",
        "prompt": "Subtle facial movement, speaking dialogue",
        "duration": 8,
        "aspect_ratio": "16:9"
    }
    """
    project = request.get("project")
    shot_id = request.get("shot_id")
    prompt = request.get("prompt")  # None if not provided — will pull from shot_plan
    duration = request.get("duration", 5)
    aspect_ratio = request.get("aspect_ratio", "16:9")

    if not project or not shot_id:
        return {"success": False, "error": "project and shot_id required"}

    project_path = get_project_path(project)

    # V27.2: If no prompt provided, compile Kling-optimized VIDEO prompt from shot data
    # OLD BUG: Was pulling nano_prompt (first-frame visual) and sending it as video prompt.
    # Kling video needs directorial language: dialogue, emotion, camera behavior, character tags.
    _shot_data = None
    _cast_map = None
    if not prompt:
        try:
            sp_path = project_path / "shot_plan.json"
            cm_path = project_path / "cast_map.json"
            if sp_path.exists():
                import json as _json
                with open(sp_path) as _f:
                    _sp = _json.load(_f)
                # T2-OR-18: Handle bare-list format
                if isinstance(_sp, list):
                    _sp = {"shots": _sp}
                _shots = _sp.get("shots", _sp.get("shot_gallery_rows", []))
                for _s in _shots:
                    if _s.get("shot_id") == shot_id:
                        _shot_data = _s
                        # Pull duration from shot if not overridden
                        if request.get("duration") is None:
                            duration = _s.get("duration", _s.get("duration_seconds", 5))
                        break
            # Load cast_map for character appearances
            if cm_path.exists():
                with open(cm_path) as _f:
                    _cast_map = _json.load(_f)
        except Exception as e:
            logger.warning(f"[KLING-I2V] Could not load shot data: {e}")

        if _shot_data:
            # Use the Kling prompt compiler — produces directorial video prompts
            try:
                from tools.kling_prompt_compiler import compile_video_for_kling
                prompt = compile_video_for_kling(_shot_data, _cast_map)
                logger.info(f"[KLING-I2V] Compiled Kling video prompt for {shot_id}: {len(prompt)} chars — {prompt[:100]}...")
            except Exception as _ce:
                logger.warning(f"[KLING-I2V] Kling compiler failed, falling back to ltx_motion_prompt: {_ce}")
                prompt = _shot_data.get("ltx_motion_prompt") or _shot_data.get("nano_prompt") or ""

        if not prompt:
            prompt = "Subtle movement, cinematic quality"

    # Find the active first frame
    overrides = get_director_overrides(project)
    shot_overrides = overrides.get("shots", {}).get(shot_id, {})

    current_frame = None
    if shot_overrides.get("selected_first_frame"):
        current_frame = project_path / shot_overrides["selected_first_frame"]
    else:
        first_frames_dir = project_path / "first_frames"
        for ext in [".jpg", ".png", ".jpeg"]:
            candidate = first_frames_dir / f"{shot_id}{ext}"
            if candidate.exists():
                current_frame = candidate
                break

    if not current_frame or not current_frame.exists():
        return {"success": False, "error": f"No first frame found for {shot_id}"}

    # V27.2: RESOLVE CHARACTER REFS for Kling Elements identity lock
    # This is the fix for identity drift (young man instead of 62yo Thomas)
    _kling_char_refs = []
    try:
        if _shot_data and _cast_map:
            _shot_chars = _shot_data.get("characters") or []
            if isinstance(_shot_chars, str):
                _shot_chars = [c.strip() for c in _shot_chars.split(",") if c.strip()]
            for _char_name in _shot_chars[:2]:  # Max 2 elements
                _cn = _char_name if isinstance(_char_name, str) else str(_char_name)
                # Search cast_map for character ref (case-insensitive)
                for _cm_key, _cm_val in _cast_map.items():
                    if _cm_key.upper() == _cn.upper() and isinstance(_cm_val, dict):
                        # Priority: headshot → character_reference_url → ref_pack
                        _ref = None
                        _ref_pack_hs = _cm_val.get("_ref_pack_headshot", {})
                        if isinstance(_ref_pack_hs, dict) and _ref_pack_hs.get("path"):
                            _ref = project_path / _ref_pack_hs["path"]
                        if not _ref or not _ref.exists():
                            _cru = _cm_val.get("character_reference_url", "")
                            if _cru:
                                _ref = project_path / _cru if not Path(_cru).is_absolute() else Path(_cru)
                        if not _ref or not _ref.exists():
                            # Fallback: search character_library_locked
                            _cll = project_path / "character_library_locked"
                            if _cll.exists():
                                _cn_upper = _cn.upper().replace(" ", "_")
                                for _f in _cll.iterdir():
                                    if _cn_upper in _f.stem.upper() and _f.suffix in (".jpg", ".png"):
                                        _ref = _f
                                        break
                        if _ref and _ref.exists():
                            _kling_char_refs.append(str(_ref))
                            logger.info(f"[KLING-I2V] {shot_id}: Character ref for {_cn}: {_ref.name}")
                        else:
                            logger.warning(f"[KLING-I2V] {shot_id}: NO ref found for {_cn} — identity at risk")
                        break
    except Exception as _ref_err:
        logger.warning(f"[KLING-I2V] {shot_id}: Ref resolution non-blocking error: {_ref_err}")

    if _kling_char_refs:
        logger.info(f"[KLING-I2V] {shot_id}: {len(_kling_char_refs)} character refs resolved for identity lock")
    elif _shot_data and (_shot_data.get("characters") or []):
        logger.warning(f"[KLING-I2V] {shot_id}: Character shot with ZERO refs — Kling identity lock UNAVAILABLE")

    # Create director tools directory
    tools_dir = ensure_director_tools_dir(project, shot_id)

    # Generate version number
    existing_videos = list((tools_dir / "videos").glob("kling_*.mp4"))
    version = len(existing_videos) + 1
    output_filename = f"kling_v{version:03d}.mp4"
    output_path = tools_dir / "videos" / output_filename

    # Get negative prompt from shot data
    _kling_neg = None
    if _shot_data:
        _kling_neg = _shot_data.get("negative_prompt") or _shot_data.get("_negative_prompt")

    # Create job tracking entry
    job_id = f"kling_{shot_id}_{int(time.time())}"
    with _KLING_JOBS_LOCK:
        # Cap old jobs
        if len(_KLING_JOBS) > 50:
            old_keys = sorted(_KLING_JOBS.keys())[:25]
            for k in old_keys:
                _KLING_JOBS.pop(k, None)
        _KLING_JOBS[job_id] = {
            "status": "queued",
            "shot_id": shot_id,
            "project": project,
            "prompt": prompt[:200],
            "duration": duration,
            "progress": "Queued...",
            "started_at": datetime.now().isoformat(),
            "completed_at": None,
            "output_path": None,
            "relative_path": None,
            "identity_elements": len(_kling_char_refs),
        }

    # Register in LIVE_GEN_TRACKER so generation monitor picks it up
    LIVE_GEN_TRACKER.add(project, f"KLING_{shot_id}", "queued", "kling_video",
        prompt=prompt[:200], model="kling-o3-pro")

    # Launch in background thread — V27.2: now passes char refs for identity lock
    threading.Thread(
        target=_kling_background_worker,
        args=(job_id, project, shot_id, prompt, duration, aspect_ratio,
              str(current_frame), str(output_path), output_filename, version),
        kwargs={"char_ref_urls": _kling_char_refs, "negative_prompt": _kling_neg},
        daemon=True,
        name=f"kling_{shot_id}"
    ).start()

    return {
        "success": True,
        "async": True,
        "job_id": job_id,
        "project": project,
        "shot_id": shot_id,
        "status": "queued",
        "message": f"Kling video generation started for {shot_id} ({duration}s). Poll /api/v18/kling/status/{job_id} for updates."
    }


@app.get("/api/v18/kling/status/{job_id}")
async def kling_job_status(job_id: str):
    """V18.4: Poll Kling job status."""
    with _KLING_JOBS_LOCK:
        job = _KLING_JOBS.get(job_id)
    if not job:
        return {"success": False, "error": f"Job {job_id} not found"}
    return {"success": True, **job}


@app.get("/api/v18/kling/jobs")
async def kling_all_jobs():
    """V18.4: List all Kling jobs (recent)."""
    with _KLING_JOBS_LOCK:
        jobs = dict(_KLING_JOBS)
    active = [j for j in jobs.values() if j["status"] in ("queued", "uploading", "generating", "downloading")]
    completed = [j for j in jobs.values() if j["status"] == "completed"]
    failed = [j for j in jobs.values() if j["status"] == "error"]
    return {
        "total": len(jobs),
        "active": len(active),
        "completed": len(completed),
        "failed": len(failed),
        "jobs": jobs
    }


# =============================================================================
# V18.1 MASTER CHAIN — BACKGROUND RUN TRACKING
# =============================================================================
_CHAIN_RUNS = {}  # run_id → {status, progress, results, ...}
_CHAIN_RUNS_LOCK = Lock()
_CHAIN_STOP_FLAGS = {}  # run_id → True (signals chain to abort gracefully)
_CHAIN_RUNS_MAX = 20  # V18.3: Cap stored runs to prevent memory leak

@app.get("/api/v18/chain/status/{run_id}")
async def chain_run_status(run_id: str):
    """Poll status of a running master chain pipeline."""
    with _CHAIN_RUNS_LOCK:
        run = _CHAIN_RUNS.get(run_id)
    if not run:
        return {"success": False, "error": "Run not found"}
    return {"success": True, **run}

@app.post("/api/v18/chain/stop")
async def chain_stop(request: Dict = Body(...)):
    """V18.2: Gracefully stop a running chain pipeline.
    Takes {run_id} or {scene_id} — sets stop flag so next shot iteration aborts.
    """
    run_id = request.get("run_id")
    scene_id = request.get("scene_id")
    if not run_id and not scene_id:
        return {"success": False, "error": "run_id or scene_id required"}
    # Find by scene_id if no run_id
    if not run_id and scene_id:
        with _CHAIN_RUNS_LOCK:
            for rid, rdata in _CHAIN_RUNS.items():
                if rdata.get("scene_id") == scene_id and rdata.get("status") == "running":
                    run_id = rid
                    break
    if not run_id:
        return {"success": False, "error": f"No running chain found for scene {scene_id}"}
    _CHAIN_STOP_FLAGS[run_id] = True
    with _CHAIN_RUNS_LOCK:
        run = _CHAIN_RUNS.get(run_id, {})
        run["status"] = "stopping"
        _CHAIN_RUNS[run_id] = run
    logger.warning(f"[CHAIN] 🛑 Stop flag set for {run_id}")
    return {"success": True, "run_id": run_id, "message": f"Stop signal sent — chain will halt after current shot"}

@app.post("/api/v18/chain/rerun-failed")
async def chain_rerun_failed(request: Dict = Body(...)):
    """V18.2: Rerun only the failed shots from a previous chain run.
    Takes {project, scene_id, failed_shot_ids: [...], video_model}.
    """
    project = request.get("project")
    scene_id = request.get("scene_id")
    failed_ids = request.get("failed_shot_ids", [])
    video_model = request.get("video_model", "kling")
    if not project or not scene_id or not failed_ids:
        return {"success": False, "error": "project, scene_id, and failed_shot_ids required"}
    # Load shot plan and filter to only the failed shots
    project_path = get_project_path(project)
    shot_plan_path = project_path / "shot_plan.json"
    if not shot_plan_path.exists():
        return {"success": False, "error": "shot_plan.json not found"}
    with open(shot_plan_path) as f:
        data = json.load(f)
    all_shots = data.get("shots", data) if isinstance(data, dict) else data
    retry_shots = [s for s in all_shots if s.get("shot_id") in failed_ids]
    if not retry_shots:
        return {"success": False, "error": f"No matching shots for IDs: {failed_ids}"}
    # Re-dispatch to the main render endpoint with just these shots
    # Build a fake request for the main endpoint
    return await kling_render_scene_batch({
        "project": project, "scene_id": scene_id,
        "duration": request.get("duration", 5),
        "video_model": video_model,
        "enable_chain": False,  # No chaining for retries — independent renders
        "generate_audio": request.get("generate_audio", False),
    })

@app.post("/api/v18/kling/render-scene")
async def kling_render_scene_batch(request: Dict = Body(...)):
    """
    V18.1: FULL Master Shot Chain pipeline (ASYNC — returns immediately).

    Pipeline per shot:
      1. NANO-BANANA generates first frame (with character/location refs from cast_map)
      2. Video generation (Kling or LTX based on video_model param)
      3. FFMPEG extracts last frame from video
      4. nano-pro-edit reframes last frame into 3 angle variants
      5. Best variant becomes first frame of NEXT shot (chain)
      6. B-roll/inserts are INDEPENDENT (no chain)

    Returns {run_id} immediately. Poll /api/v18/chain/status/{run_id} for progress.
    """
    project = request.get("project")
    scene_id = request.get("scene_id")
    duration = request.get("duration", 5)
    generate_audio = request.get("generate_audio", False)  # V24.2: Default OFF — audio prompt injection confused LTX action model
    enable_chain = request.get("enable_chain", True)
    lite_mode = request.get("lite_mode", False)  # V22: Skip ALL prompt enrichment — prompts go to FAL as-is

    if not project or not scene_id:
        return {"success": False, "error": "project and scene_id required"}

    project_path = get_project_path(project)
    shot_plan_path = project_path / "shot_plan.json"
    if not shot_plan_path.exists():
        return {"success": False, "error": "shot_plan.json not found"}

    with open(shot_plan_path) as f:
        data = json.load(f)
    all_shots = data.get("shots", data) if isinstance(data, dict) else data
    scene_shots = [s for s in all_shots if s.get("shot_id", "").startswith(scene_id)]

    if not scene_shots:
        return {"success": False, "error": f"No shots for scene {scene_id}"}

    # V18.1: Extract ALL parameters before thread launch (thread can't access request reliably)
    video_model = request.get("video_model", "kling")  # Default to kling (Seedance + LTX both retired)
    import uuid as _uuid
    run_id = f"chain_{scene_id}_{_uuid.uuid4().hex[:8]}"

    # Capture everything the thread needs
    _thread_data = data
    _thread_scene_shots = list(scene_shots)  # Copy to avoid mutation issues
    _thread_project = project
    _thread_project_path = project_path
    _thread_shot_plan_path = shot_plan_path
    _thread_video_model = video_model
    _thread_duration = duration
    _thread_generate_audio = generate_audio
    _thread_enable_chain = enable_chain
    _thread_lite_mode = lite_mode

    with _CHAIN_RUNS_LOCK:
        _CHAIN_RUNS[run_id] = {
            "status": "starting",
            "project": project,
            "scene_id": scene_id,
            "total_shots": len(scene_shots),
            "completed_shots": 0,
            "current_shot": None,
            "current_step": "initializing",
            "results": [],
            "errors": [],
            "elapsed": 0,
            "started_at": datetime.now().isoformat(),
            "video_model": video_model,
        }

    def _run_chain_pipeline():
        """Background thread: runs the full master chain pipeline."""
        # Use thread-local copies of all variables (no closure dependencies)
        data = _thread_data
        scene_shots = _thread_scene_shots
        project = _thread_project
        project_path = _thread_project_path
        shot_plan_path = _thread_shot_plan_path
        video_model = _thread_video_model
        duration = _thread_duration
        generate_audio = _thread_generate_audio
        enable_chain = _thread_enable_chain
        lite_mode = _thread_lite_mode

        # V18.2: RUN NUMBERING — increment run counter, archive previous frames
        try:
            _run_counter_path = project_path / "run_counter.json"
            _run_data = {"run_number": 0, "runs": []}
            if _run_counter_path.exists():
                with open(_run_counter_path) as _rcf:
                    _run_data = json.load(_rcf)
            _run_data["run_number"] = _run_data.get("run_number", 0) + 1
            _current_run = _run_data["run_number"]
            _run_entry = {
                "run": _current_run,
                "run_id": run_id,
                "scene_id": scene_id,
                "video_model": video_model,
                "shots": len(scene_shots),
                "started_at": datetime.now().isoformat(),
                "type": "chain_full"
            }
            _run_data["runs"] = _run_data.get("runs", [])[-99:]  # Keep last 100 runs
            _run_data["runs"].append(_run_entry)
            with open(_run_counter_path, "w") as _rcf:
                json.dump(_run_data, _rcf, indent=2)
            logger.info(f"[CHAIN] ═══ RUN #{_current_run} ═══ Scene {scene_id}, {len(scene_shots)} shots, model={video_model}")

            # Archive previous frames for this scene to runs/run_N/
            _archive_dir = project_path / "runs" / f"run_{_current_run - 1}" / scene_id
            _ff_dir = project_path / "first_frames"
            _vid_dir = project_path / "videos"
            _var_dir = project_path / "first_frame_variants"
            _scene_prefix = f"{scene_id}_"
            if _current_run > 1 and _ff_dir.exists():
                _archive_dir.mkdir(parents=True, exist_ok=True)
                import shutil
                _archived = 0
                for _ff in _ff_dir.glob(f"{_scene_prefix}*"):
                    try:
                        shutil.copy2(str(_ff), str(_archive_dir / _ff.name))
                        _archived += 1
                    except Exception:
                        pass
                if _var_dir.exists():
                    (_archive_dir / "variants").mkdir(exist_ok=True)
                    for _vf in _var_dir.glob(f"{_scene_prefix}*"):
                        try:
                            shutil.copy2(str(_vf), str(_archive_dir / "variants" / _vf.name))
                        except Exception:
                            pass
                if _vid_dir.exists():
                    (_archive_dir / "videos").mkdir(exist_ok=True)
                    for _vf in _vid_dir.glob(f"{_scene_prefix}*"):
                        try:
                            shutil.copy2(str(_vf), str(_archive_dir / "videos" / _vf.name))
                        except Exception:
                            pass
                logger.info(f"[CHAIN] Archived {_archived} previous frames to runs/run_{_current_run - 1}/{scene_id}/")

            # Update chain run status with run number
            with _CHAIN_RUNS_LOCK:
                if run_id in _CHAIN_RUNS:
                    _CHAIN_RUNS[run_id]["run_number"] = _current_run
        except Exception as _rn_err:
            _current_run = 0
            logger.warning(f"[CHAIN] Run numbering non-blocking error: {_rn_err}")

        # V18.2: FAL key rotation — try .env key FIRST, then rotate through pool on 403
        # The .env key (or current os.environ FAL_KEY) is the primary key.
        # Pool keys are fallbacks only.
        _env_fal_key = os.environ.get("FAL_KEY", "")
        _chain_fal_idx = [0]

        def _fal_run_with_retry(model, arguments, max_retries=10):
            """Run fal_client.run — tries .env key first, rotates pool on 403.
            V18.2: fal_client.run is globally monkey-patched to be non-blocking."""
            # FIRST: try the .env / environment key (the one the user actually has credits on)
            if _env_fal_key:
                os.environ["FAL_KEY"] = _env_fal_key
                try:
                    result = fal_client.run(model, arguments=arguments)
                    return result
                except Exception as e:
                    err_str = str(e)
                    if "403" in err_str or "Forbidden" in err_str or "unauthorized" in err_str.lower() or "authentication" in err_str.lower():
                        logger.warning(f"[CHAIN-FAL] Primary .env key got 403, trying pool keys...")
                    else:
                        logger.error(f"[CHAIN-FAL] Non-auth error with .env key: {err_str}")
                        raise

            # FALLBACK: rotate through hardcoded key pool
            for attempt in range(max_retries):
                try:
                    key = orchestrator.fal_keys[_chain_fal_idx[0] % len(orchestrator.fal_keys)]
                    os.environ["FAL_KEY"] = key
                    _chain_fal_idx[0] += 1
                    result = fal_client.run(model, arguments=arguments)
                    return result
                except Exception as e:
                    err_str = str(e)
                    if "403" in err_str or "Forbidden" in err_str or "unauthorized" in err_str.lower() or "authentication" in err_str.lower():
                        logger.warning(f"[CHAIN-FAL] Pool key #{_chain_fal_idx[0]} got 403, trying next (attempt {attempt+1}/{max_retries})")
                        continue
                    else:
                        logger.error(f"[CHAIN-FAL] Non-auth error: {err_str}")
                        raise
            # Restore .env key before giving up
            if _env_fal_key:
                os.environ["FAL_KEY"] = _env_fal_key
            logger.error(f"[CHAIN-FAL] All keys failed with 403 for {model}")
            raise Exception(f"403 Forbidden - all FAL keys exhausted for {model}")

        # Create output directories
        kling_dir = project_path / "videos_kling"
        kling_dir.mkdir(exist_ok=True)
        first_frames_dir = project_path / "first_frames"
        first_frames_dir.mkdir(exist_ok=True)
        variants_dir = project_path / "first_frame_variants"
        variants_dir.mkdir(exist_ok=True)
        chain_frames_dir = project_path / "frame_chains"

        # V18.2: AUTO-ARCHIVE old scene media before fresh run
        # Moves old frames/variants/videos/chain_frames to timestamped archive folder
        try:
            _archive_ts = datetime.now().strftime("%Y%m%d_%H%M%S")
            _archive_dir = project_path / "archive" / f"scene_{scene_id}_{_archive_ts}"
            _archived_count = 0
            _prefix = f"{scene_id}_"

            for _src_dir, _subdir in [
                (first_frames_dir, "first_frames"),
                (variants_dir, "first_frame_variants"),
                (project_path / "videos", "videos"),
                (chain_frames_dir, "frame_chains"),
            ]:
                if not _src_dir.exists():
                    continue
                _old_files = [f for f in _src_dir.iterdir() if f.name.startswith(_prefix)]
                if _old_files:
                    _dest = _archive_dir / _subdir
                    _dest.mkdir(parents=True, exist_ok=True)
                    for _f in _old_files:
                        import shutil
                        shutil.move(str(_f), str(_dest / _f.name))
                        _archived_count += 1

            # Also clear ALL stale metadata from shot_plan (variants, video paths, frame paths)
            if _archived_count > 0:
                try:
                    with open(shot_plan_path, 'r') as _sp_f:
                        _sp_data = json.load(_sp_f)
                    for _sp_shot in _sp_data.get("shots", []):
                        if _sp_shot.get("shot_id", "").startswith(_prefix):
                            for _k in ["_variants", "_chain_variants", "_chain_selected",
                                       "_chain_source", "_chain_first_frame_url", "_chain_next_frame",
                                       "first_frame_path", "first_frame_url", "video_path",
                                       "video_url", "video_url_kling", "stitched_video_path",
                                       "_selected_angle", "_variant_override", "_variant_source_path",
                                       "_chain_master_shot", "generation_status"]:
                                _sp_shot.pop(_k, None)
                    with open(shot_plan_path, 'w') as _sp_f:
                        json.dump(_sp_data, _sp_f, indent=2, default=str)
                    logger.info(f"[CHAIN] 🧹 Cleared stale metadata from {_archived_count} shots in shot_plan.json")
                except Exception:
                    pass
                # Invalidate bundle cache
                _cache_dir = project_path / "ui_cache"
                if _cache_dir.exists():
                    (_cache_dir / "bundle.dirty").touch()

            if _archived_count > 0:
                logger.info(f"[CHAIN] 📦 Auto-archived {_archived_count} old scene {scene_id} files → {_archive_dir.name}")
                _update_run(archived_files=_archived_count, archive_path=str(_archive_dir))
            else:
                logger.info(f"[CHAIN] Scene {scene_id} is clean — no old files to archive")
        except Exception as _arch_err:
            logger.warning(f"[CHAIN] Auto-archive non-blocking error: {_arch_err}")
        chain_frames_dir.mkdir(exist_ok=True)

        import time as _time
        start = _time.time()
        results = []
        prev_video_path = None
        prev_shot = None
        chain_frame_for_next = None

        def _update_run(**kwargs):
            with _CHAIN_RUNS_LOCK:
                run = _CHAIN_RUNS.get(run_id, {})
                run.update(kwargs)
                run["elapsed"] = round(_time.time() - start, 1)
                _CHAIN_RUNS[run_id] = run
                # V18.3: Evict oldest completed runs to prevent memory leak
                if len(_CHAIN_RUNS) > _CHAIN_RUNS_MAX:
                    _completed = [k for k, v in _CHAIN_RUNS.items() if v.get("status") in ("completed", "error") and k != run_id]
                    for _old_id in _completed[:len(_CHAIN_RUNS) - _CHAIN_RUNS_MAX]:
                        del _CHAIN_RUNS[_old_id]

        # =======================================================================
        # GLOBAL TRY/EXCEPT — thread MUST NOT crash silently
        # =======================================================================
        try:
            import fal_client
        except ImportError:
            _update_run(status="error", error="fal_client not installed")
            return

        # Load cast_map for character references
        cast_map = {}
        cast_map_path = project_path / "cast_map.json"
        if cast_map_path.exists():
            try:
                cast_map = json.load(open(cast_map_path))
            except Exception:
                pass

        # V24.2 FIX: Load scene_manifest for B-roll continuity + LOA cross-check
        scene_manifest = {}
        try:
            with open(shot_plan_path, 'r') as _sp_f:
                _sp_full = json.load(_sp_f)
            _sm_raw = _sp_full.get("scene_manifest", _sp_full.get("scenes", []))
            if isinstance(_sm_raw, list):
                scene_manifest = {s.get("scene_id", s.get("id", "")): s for s in _sm_raw if isinstance(s, dict)}
            elif isinstance(_sm_raw, dict):
                scene_manifest = _sm_raw
        except Exception as _sm_err:
            logger.warning(f"[CHAIN] scene_manifest load non-blocking error: {_sm_err}")

        # V24.2 FIX: Load wardrobe data for runtime injection
        wardrobe_data = {}
        wardrobe_path = project_path / "wardrobe.json"
        if wardrobe_path.exists():
            try:
                wardrobe_data = json.load(open(wardrobe_path))
            except Exception:
                pass

        # Load location masters
        location_masters = {}
        loc_dir = project_path / "location_masters"
        if loc_dir.exists():
            for lf in loc_dir.glob("*.jpg"):
                location_masters[lf.stem.upper()] = str(lf)
            for lf in loc_dir.glob("*.png"):
                location_masters[lf.stem.upper()] = str(lf)

        # =========================================================================
        # V24.2: ALL enrichment removed — lite_mode distinction no longer needed.
        # V24.2 compiler handles: negatives, face stable, identity lock, gold standard.
        # =========================================================================

        # V24.2.3: Load story_bible + actor_lib for DirectorEditPass (non-blocking)
        story_bible = {}
        try:
            _sb_path = project_path / "story_bible.json"
            if _sb_path.exists():
                story_bible = json.load(open(_sb_path))
        except Exception:
            pass
        _actor_lib = {}  # No longer used — AI actor lib replaced by canonical characters
        try:
            _alib_path = Path(__file__).resolve().parent / "ai_actors_library.json"
            if _alib_path.exists():
                _actor_lib = json.load(open(_alib_path))
        except Exception:
            pass

        # ═══════════════════════════════════════════════════════════════════════
        # V24.2: CHAIN PIPELINE — ZERO ENRICHMENT (2026-03-10)
        #
        # The V24.2 compiler already ran at compile time and set all prompts
        # in shot_plan.json. The chain pipeline reads them directly.
        # What you see in the shot plan = what FAL gets.
        #
        # OLD 7-LAYER ENRICHMENT SYSTEM REMOVED:
        #   ❌ 1. Wardrobe + extras injection     → V24.2 compiler handles wardrobe
        #   ❌ 2. Emotion layer injection          → V24.2 compiler handles emotion via physical descriptions
        #   ❌ 3. Location description injection   → V24.2 compiler handles scene/location
        #   ❌ 4. Scene anchor system              → V24.2 compiler handles color grade
        #   ❌ 5. Cinematic enricher + cast traits  → V24.2 uses cast_map canonical (no AI actor lib!)
        #   ❌ 6. Gold standard negatives          → V24.2 compiler includes QUALITY_ULTRA + IDENTITY_LOCK
        #   ❌ 7. Face-lock text injection         → V24.2 compiler handles in compile_nano_prompt()
        #   ❌ Authority gate cleanup              → V24.2 is clean from source — nothing to strip
        #   ❌ Persist gate-cleaned to shot_plan   → No mutations = nothing to persist
        #
        # KEPT: Dialogue duration clamp (prevents LTX face morphing on long holds)
        # RESTORED V24.2.1: Wardrobe runtime injection (was missing from V24.2 compiler)
        # ═══════════════════════════════════════════════════════════════════════

        # V24.2.1: WARDROBE RUNTIME INJECTION — inject wardrobe tags into prompts at chain time
        # The V24.2 compiler used nano_prompt as-is, which didn't have wardrobe tags.
        # This restores wardrobe consistency for character shots.
        _ward_injected = 0
        if wardrobe_data:
            _looks = wardrobe_data.get("looks", {})
            for _shot in scene_shots:
                _chars = _shot.get("characters", [])
                if not _chars:
                    continue
                _sid = _shot.get("scene_id", scene_id)
                _nano = _shot.get("nano_prompt_final") or _shot.get("nano_prompt", "")
                _ltx = _shot.get("ltx_motion_prompt_final") or _shot.get("ltx_motion_prompt", "")
                # Skip if wardrobe already present
                if "wearing:" in _nano.lower() or "wearing " in _nano.lower():
                    continue
                # Find wardrobe for primary character in this scene
                for _ch in _chars:
                    _look_key = f"{_ch}::{_sid}"
                    _look = _looks.get(_look_key)
                    if _look and isinstance(_look, dict):
                        _tag = _look.get("wardrobe_tag", "")
                        if _tag:
                            _nano = _nano.rstrip(". ") + f". {_ch} wearing: {_tag}."
                            _ltx = _ltx.rstrip(". ") + f". wardrobe continuity: {_ch} same outfit throughout."
                            if _look.get("locked"):
                                _nano += f" NO outfit change for {_ch}."
                            _shot["nano_prompt_final"] = _nano
                            _shot["nano_prompt"] = _nano
                            _shot["ltx_motion_prompt_final"] = _ltx
                            _shot["ltx_motion_prompt"] = _ltx
                            _ward_injected += 1
                            break
            if _ward_injected:
                logger.info(f"[V24.2.1] Wardrobe injected into {_ward_injected} shots for scene {scene_id}")

        # V19: DIALOGUE DURATION CLAMP — still needed (prevents LTX face morphing on long holds)
        _DIALOGUE_DURATION_CLAMP = {
            "close_up": (5, 8), "medium_close_up": (5, 8), "extreme_close_up": (4, 6),
            "medium": (6, 10), "over_the_shoulder": (6, 10), "two_shot": (8, 12),
            "wide": (8, 14), "insert": (3, 5), "detail": (3, 5), "reaction": (4, 6),
        }
        _dc_count = 0
        for _shot in scene_shots:
            _has_dialogue = bool(_shot.get("dialogue_text") or _shot.get("dialogue"))
            if _has_dialogue:
                _stype = (_shot.get("type") or _shot.get("shot_type") or "medium").lower()
                _clamp = _DIALOGUE_DURATION_CLAMP.get(_stype, (5, 10))
                _cur_dur = _shot.get("duration", 10)
                _clamped = max(_clamp[0], min(_cur_dur, _clamp[1]))
                if _clamped != _cur_dur:
                    _shot["duration"] = _clamped
                    _shot["duration_seconds"] = _clamped
                    _shot["ltx_duration_seconds"] = _clamped
                    _shot["_v19_dialogue_clamped"] = True
                    _dc_count += 1

        logger.info(f"[V24.2 CHAIN] ✅ {len(scene_shots)} shots — ZERO enrichment (prompts compiled at source), {_dc_count} dialogue-clamped")

        # =========================================================================
        # V25.1: FILM ENGINE MODEL-AWARE TRANSLATION
        # When video_model is NOT ltx, translate prompts to model-specific format.
        # The V24.2 compiler outputs LTX-optimized prompts. Film Engine transforms
        # them for Kling 3.0 (6-zone, natural emotion, ++emphasis++, no anti-CGI needed).
        # Non-blocking: if translation fails, original LTX prompts still work on Kling.
        # =========================================================================
        _fe_translated = 0
        if video_model == "kling":
            try:
                from tools.film_engine import (
                    translate_camera_tokens as _fe_translate_cam,
                    translate_emotion_for_model as _fe_translate_emo,
                    build_camera_zone as _fe_build_cam,
                    COLOR_SCIENCE_TOKENS as _fe_color_sci,
                )

                _fe_cast_map = {}
                _cm_path = project_path / "cast_map.json"
                if _cm_path.exists():
                    try:
                        with open(_cm_path) as f:
                            _fe_cast_map = json.load(f)
                    except Exception:
                        pass

                for _fe_shot in scene_shots:
                    try:
                        _fe_nano = _fe_shot.get("nano_prompt_final") or _fe_shot.get("nano_prompt", "")
                        _fe_ltx = _fe_shot.get("ltx_motion_prompt_final") or _fe_shot.get("ltx_motion_prompt", "")
                        _fe_chars = _fe_shot.get("characters") or []

                        # Strip camera brand tokens (Law 235)
                        _fe_nano = _fe_translate_cam(_fe_nano, "gothic_horror")

                        # Build Kling 6-zone structure
                        _fe_parts = []

                        # Z1: Camera (focal + movement)
                        _fe_lens = _fe_shot.get("lens_specs", "50mm")
                        _fe_style = _fe_shot.get("camera_style", "handheld")
                        _fe_stype = (_fe_shot.get("type") or _fe_shot.get("shot_type") or "medium").lower()
                        _fe_crole = _fe_shot.get("coverage_role", "")
                        _fe_cam = _fe_build_cam(_fe_lens, _fe_style, _fe_stype, _fe_crole)
                        _fe_parts.append(_fe_cam)

                        # Z2: Subject (Kling character tags)
                        for _ci, _cname in enumerate(_fe_chars[:3]):
                            _c_data = _fe_cast_map.get(_cname, {})
                            _c_app = _c_data.get("appearance", "")[:80]
                            _c_tag = f"[Character {'ABC'[_ci]}: {_cname}"
                            if _c_app:
                                _c_tag += f", {_c_app}"
                            _c_tag += "]"
                            _fe_parts.append(_c_tag)

                        # Z3: Environment
                        _fe_loc = _fe_shot.get("location", "")
                        if _fe_loc:
                            _fe_parts.append(_fe_loc)

                        # Z4: Lighting (from atmosphere or narrative)
                        _fe_atmo = _fe_shot.get("atmosphere", "")
                        if _fe_atmo:
                            _fe_parts.append(_fe_atmo[:80])

                        # Z5: Color science (genre-matched film stock)
                        _fe_genre = "gothic_horror"
                        _fe_csci = _fe_color_sci.get(_fe_genre, "Kodak 2383 print look")
                        _fe_parts.append(_fe_csci)

                        # Z6: Emotion (natural language for Kling — NOT physical descriptions)
                        _fe_emo = _fe_shot.get("emotion", "") or _fe_shot.get("emotion_choice", "")
                        if _fe_emo and _fe_chars:
                            _fe_emo_text = _fe_translate_emo(_fe_emo, "kling", _fe_chars[0])
                            _fe_parts.append(_fe_emo_text)

                        # Action/dialogue from beat
                        _fe_action = _fe_shot.get("action_description", "") or _fe_shot.get("character_action", "")
                        if _fe_action:
                            _fe_parts.append(_fe_action[:120])

                        # Dialogue direction
                        _fe_dlg = _fe_shot.get("dialogue_text") or _fe_shot.get("dialogue", "")
                        if _fe_dlg and _fe_chars:
                            _fe_parts.append(f"{_fe_chars[0]} speaks: {_fe_dlg[:100]}")

                        # Identity emphasis for character shots
                        if _fe_chars:
                            _fe_parts.append(f"++{_fe_chars[0]} identity consistent++")

                        # Assemble Kling prompt (30-100 words, max 2500 chars)
                        _fe_kling = ". ".join(p.strip().rstrip(".") for p in _fe_parts if p.strip())
                        _fe_words = _fe_kling.split()
                        if len(_fe_words) > 100:
                            _fe_kling = " ".join(_fe_words[:100])
                        _fe_kling = _fe_kling[:2500]

                        # Kling structural negatives only (native photorealism)
                        _fe_kling += ". NO grid, NO collage, NO split screen, NO morphing faces"

                        # Apply translated prompt
                        _fe_shot["nano_prompt_final"] = _fe_kling
                        _fe_shot["nano_prompt"] = _fe_kling
                        _fe_shot["_kling_translated"] = True
                        _fe_translated += 1

                    except Exception as _fe_shot_err:
                        logger.warning(f"[V25.1 FILM-ENGINE] Shot {_fe_shot.get('shot_id', '?')} translation error (non-blocking): {_fe_shot_err}")

                logger.info(f"[V25.1 FILM-ENGINE] ✅ Kling 3.0 translation: {_fe_translated}/{len(scene_shots)} shots → 6-zone format, natural emotion, camera tokens stripped")
            except Exception as _fe_err:
                logger.warning(f"[V25.1 FILM-ENGINE] Model translation non-blocking error: {_fe_err} — LTX prompts will be used as-is for Kling")

        # =========================================================================
        # V24.1: CONTINUITY MEMORY INITIALIZATION — spatial state for this scene
        # Non-blocking: if continuity memory fails, chain proceeds without it.
        # Stores per-shot spatial state after end-frame extraction for next shot.
        # =========================================================================
        _continuity_memory = None
        _basal_ganglia = None
        _meta_director = None
        try:
            from tools.continuity_memory import (
                ContinuityMemory as _CM,
                extract_spatial_state_from_metadata as _extract_spatial,
                generate_reframe_candidates as _gen_reframe_candidates,
                compile_continuity_delta as _compile_delta,
                should_chain_broll as _should_chain_broll,
                extract_broll_continuity as _extract_broll_cont,
                compile_broll_continuity_prompt as _compile_broll_prompt,
            )
            _pp = str(project_path) if not isinstance(project_path, str) else project_path
            _continuity_memory = _CM(_pp)
            logger.info(f"[V24.1] ✅ ContinuityMemory initialized for {scene_id} ({_continuity_memory.get_statistics().get('total_states', 0)} prior states)")
        except Exception as _cm_init_err:
            logger.warning(f"[V24.1] ContinuityMemory init non-blocking error: {_cm_init_err}")
            _continuity_memory = None

        # =========================================================================
        # V24.2: BASAL GANGLIA + META DIRECTOR INITIALIZATION
        # Basal Ganglia: scores reframe candidates across 6 dimensions (identity,
        # blocking, rhythm, emotion, environment, prompt fidelity). Replaces blind
        # _candidates[0] pick with proper Go/No-Go evaluation.
        # Meta Director: pre-render readiness check per shot — validates prompt,
        # gold standard, performance markers, duration. Non-blocking advisory.
        # =========================================================================
        try:
            from tools.basal_ganglia_engine import BasalGangliaEngine as _BGEngine
            _basal_ganglia = _BGEngine(_pp)
            logger.info(f"[V24.2] ✅ BasalGanglia initialized (reward memory: {len(_basal_ganglia.reward_memory)} entries)")
        except Exception as _bg_init_err:
            logger.warning(f"[V24.2] BasalGanglia init non-blocking: {_bg_init_err}")
            _basal_ganglia = None

        try:
            from tools.meta_director import MetaDirector as _MDDirector
            _meta_director = _MDDirector(_pp)
            logger.info(f"[V24.2] ✅ MetaDirector initialized")
        except Exception as _md_init_err:
            logger.warning(f"[V24.2] MetaDirector init non-blocking: {_md_init_err}")
            _meta_director = None

        # =========================================================================
        # V24.2.3: SMART REGEN — Vision-guided post-gen QA + delta reprompting
        # Scores every generated frame BEFORE video generation.
        # On failure: diagnoses the issue → builds corrective prompt → regenerates.
        # Bounded by RegenBudget (max 2 per shot, 30% of scene).
        # =========================================================================
        _smart_regen_available = False
        _regen_budget = None
        try:
            from tools.smart_regen import (
                chain_post_gen_qa as _sr_chain_qa,
                escalate_correction as _sr_escalate,
                resolve_shot_refs as _sr_resolve_refs,
                RegenBudget as _SRBudget,
                FEATURE_SMART_REGEN as _sr_enabled,
            )
            if _sr_enabled:
                _regen_budget = _SRBudget(scene_shots)
                _smart_regen_available = True
                logger.info(f"[V24.2.3] ✅ SmartRegen initialized (budget: {_regen_budget.max_per_shot}/shot, "
                           f"{_regen_budget.max_scene_regens}/{len(scene_shots)} scene)")
            else:
                logger.info(f"[V24.2.3] SmartRegen disabled via FEATURE_SMART_REGEN=false")
        except Exception as _sr_init_err:
            logger.warning(f"[V24.2.3] SmartRegen init non-blocking: {_sr_init_err}")

        # =========================================================================
        # V37-parity: CHAIN INTELLIGENCE GATE — pre/post-gen quality enforcement
        # Mirrors atlas_universal_runner.py lines 69-80. NON-BLOCKING import.
        # Pre-gen gate fires before Kling spend. Post-gen gate fires after download.
        # =========================================================================
        _cig_available = False
        _cig_pre = _cig_post = None
        try:
            from tools.chain_intelligence_gate import (
                validate_pre_generation as _cig_pre,
                validate_post_generation as _cig_post,
            )
            _cig_available = True
            logger.info(f"[V37-CIG] ✅ ChainIntelligenceGate loaded for scene {scene_id}")
        except Exception as _cig_err:
            logger.warning(f"[V37-CIG] ChainIntelligenceGate unavailable (non-blocking): {_cig_err}")

        # =========================================================================
        # V24.2.3: SHOT AUTHORITY CONTRACT — Pre-generation parameter dictation
        # Dictates EXACT FAL params per shot type BEFORE generation.
        # Close-ups get guidance 8.0 + 35 steps (strict identity).
        # B-roll gets guidance 5.0 + 20 steps (creative freedom).
        # Dialogue shots boost guidance +0.5 and mandate refs.
        # pre_authorize_scene() runs ONCE to flag violations before spending $.
        # =========================================================================
        _shot_authority_available = False
        _scene_authority_report = None
        try:
            from tools.shot_authority import (
                build_shot_contract as _sa_build_contract,
                pre_authorize_scene as _sa_pre_authorize,
            )
            _scene_authority_report = _sa_pre_authorize(scene_shots, cast_map)
            _shot_authority_available = True
            _sa_avg = _scene_authority_report.get("avg_authority_score", 0)
            _sa_viol = _scene_authority_report.get("total_violations", 0)
            _sa_warn = _scene_authority_report.get("total_warnings", 0)
            _sa_hero = _scene_authority_report.get("hero_shots", 0)
            _sa_prod = _scene_authority_report.get("production_shots", 0)
            _sa_prev = _scene_authority_report.get("preview_shots", 0)
            _sa_missing = _scene_authority_report.get("missing_refs", [])
            logger.info(f"[V24.2.3-AUTHORITY] ✅ Scene pre-authorized: "
                       f"authority={_sa_avg:.2f}, violations={_sa_viol}, warnings={_sa_warn}, "
                       f"hero={_sa_hero}/production={_sa_prod}/preview={_sa_prev}")
            if _sa_missing:
                logger.warning(f"[V24.2.3-AUTHORITY] ⚠️ Missing refs for: {', '.join(_sa_missing[:5])}")
            if _sa_viol > 0:
                logger.warning(f"[V24.2.3-AUTHORITY] ⚠️ {_sa_viol} violations detected — generation proceeds but quality may be degraded")
        except Exception as _sa_init_err:
            logger.warning(f"[V24.2.3-AUTHORITY] Shot Authority init non-blocking: {_sa_init_err}")

        # =========================================================================
        # V19: DIRECTOR EDIT PASS — Hard enforcement before render
        # Validates edit rhythm, inserts missing story moments, upgrades B-roll,
        # injects character micro-expressions. MUST PASS before chain proceeds.
        # =========================================================================
        _dep_ok = True
        try:
            from atlas_agents.director_edit_pass import DirectorEditPass, normalize_shot_type
            _dep_agent = DirectorEditPass(
                project_path=project_path,
                story_bible=story_bible if isinstance(story_bible, dict) else {},
                cast_map=cast_map if isinstance(cast_map, dict) else {},
                ai_actors_lib=_actor_lib if _actor_lib else {},
            )
            _dep_result = _dep_agent.run(scene_id=scene_id, auto_fix=False)
            _dep_violations = _dep_result.get("rhythm_violations", [])
            _dep_moments = _dep_result.get("missing_moments", [])
            _dep_microexp = _dep_result.get("microexpressions", {})

            # Inject micro-expressions into shot prompts
            for _shot in scene_shots:
                _shot_chars = _shot.get("characters", [])
                if isinstance(_shot_chars, str):
                    _shot_chars = [c.strip() for c in _shot_chars.split(",") if c.strip()]
                for _sc_name in _shot_chars:
                    _sc_expr = _dep_microexp.get(_sc_name, "")
                    if _sc_expr and _sc_expr != "subtle, natural micro-expression":
                        _lp = _shot.get("ltx_motion_prompt", "")
                        if _sc_name.lower() not in _lp.lower():
                            _shot["ltx_motion_prompt"] = f"{_sc_name} {_sc_expr}, " + _lp
                            _shot["_v19_microexpression"] = True
                        break  # One character direction per shot to avoid prompt bloat

            # Log stats
            _me_count = sum(1 for s in scene_shots if s.get("_v19_microexpression"))
            logger.info(f"[V19-DIRECTOR] Edit pass: {len(_dep_violations)} rhythm violations, "
                        f"{len(_dep_moments)} missing moments, {_me_count} micro-expressions injected")

            # Hard enforcement: block if excessive rhythm violations (>80% of transitions)
            _transition_count = max(len(scene_shots) - 1, 1)
            _violation_rate = len(_dep_violations) / _transition_count
            if _violation_rate > 0.80:
                logger.warning(f"[V19-DIRECTOR] ⚠️ High violation rate ({_violation_rate:.0%}) — "
                               f"shot variety is poor. Consider running fix-v16 to diversify shot types.")
                # Advisory warning, not blocking — shot variety is a pre-existing data issue
                # The pipeline still benefits from face-lock, duration clamp, and micro-expressions

            _update_run(director_edit_pass={
                "rhythm_violations": len(_dep_violations),
                "missing_moments": len(_dep_moments),
                "microexpressions_injected": _me_count,
                "violation_rate": round(_violation_rate, 3),
                "characters_with_direction": list(_dep_microexp.keys()),
            })
        except Exception as _dep_err:
            logger.warning(f"[V19-DIRECTOR] Non-blocking error: {_dep_err}")
            _dep_ok = False

        # =========================================================================
        # V18.2: CONTINUITY GATE — Director Brain pre-render validator
        # Validates state transitions, assigns coverage roles, inserts connectors
        # =========================================================================
        try:
            from atlas_agents.continuity_gate import run_continuity_gate, enrich_shots_with_state

            # Step 1: Enrich all shots with state_in/state_out + coverage_role + shot_role
            _state_count = enrich_shots_with_state(scene_shots, scene_id)
            logger.info(f"[CONTINUITY-GATE] Enriched {_state_count} shots with state fields")

            # Step 2: Run continuity gate — validates pose/emotion transitions, bridge scores
            # auto_fix=True will auto-insert connector shots where violations occur
            _gate_result = run_continuity_gate(
                scene_shots, scene_id=scene_id, auto_fix=enable_chain
            )
            _gate_passed = _gate_result.get("passed", 0)
            _gate_failed = _gate_result.get("failed", 0)
            _gate_connectors = _gate_result.get("connectors_inserted", 0)
            _gate_bridge = _gate_result.get("avg_bridge_score", 0)

            if _gate_connectors > 0:
                logger.info(f"[CONTINUITY-GATE] Inserted {_gate_connectors} connector shots (total now {len(scene_shots)})")

            logger.info(f"[CONTINUITY-GATE] ✅ Gate complete: {_gate_passed}/{_gate_passed + _gate_failed} passed, "
                        f"bridge={_gate_bridge:.2f}, connectors={_gate_connectors}")

            # Store gate result in run metadata
            _update_run(continuity_gate={
                "passed": _gate_passed,
                "failed": _gate_failed,
                "connectors_inserted": _gate_connectors,
                "avg_bridge_score": _gate_bridge,
                "violations": _gate_result.get("violations", []),
            })
        except Exception as _cg_err:
            logger.warning(f"[CONTINUITY-GATE] Non-blocking error: {_cg_err}")

        # V22.0: CONTINUITY STORE — persist state snapshots to disk for crash recovery
        try:
            if CONTINUITY_STORE_AVAILABLE:
                _chain_cont_store = ContinuityStore(str(project_path))
                for _cs_shot in scene_shots:
                    if _cs_shot.get("state_out") and any(v for v in _cs_shot["state_out"].values() if v):
                        _chain_cont_store.update_from_shot(_cs_shot)
                _chain_cont_store.save()
                logger.info(f"[CHAIN V22.0] Continuity Store: persisted state for scene {scene_id}")
        except Exception as _cs_chain_err:
            logger.warning(f"[CHAIN V22.0] Continuity Store non-blocking error: {_cs_chain_err}")

        # V22.0: ACTOR INTENT — enrich chain shots with character intent
        try:
            if ACTOR_INTENT_AVAILABLE:
                _chain_sb = data.get("story_bible") or {}
                _chain_cm = data.get("cast_map") or {}
                if isinstance(_chain_cm, list):
                    _chain_cm = {}
                _chain_intent = enrich_shot_plan_with_intent(scene_shots, _chain_sb, _chain_cm)
                logger.info(f"[CHAIN V22.0] Actor Intent: enriched {_chain_intent.get('enriched_count', 0)} shots")
        except Exception as _ai_chain_err:
            logger.warning(f"[CHAIN V22.0] Actor Intent non-blocking error: {_ai_chain_err}")

        # =========================================================================
        # V24.2 REMOVED: Lite restore block — was dead code since V24.2 removed
        # the 7-layer enrichment system. _lite_saved_prompts was never populated
        # (the code that saved pre-enrichment prompts was removed with the
        # enrichment stack). This block caused NameError crashes when lite_mode
        # was truthy. All prompts are now pre-compiled at source — no enrichment
        # to "restore" from. Removed entirely as origin fix per V24.2.3.
        # =========================================================================

        # Nano-banana models (locked)
        NANO_MODEL_REF = "fal-ai/nano-banana-pro/edit"
        NANO_MODEL_T2I = "fal-ai/nano-banana-pro"

        # V18.2/V21: NANO MULTI-ANGLE — character-consistent angle variants via nano-pro-edit
        # Uses nano-banana-pro/edit with character refs for face consistency + different framing prompts
        NANO_ANGLES = [
            {"name": "wide_master", "prefix": "24mm ultra-wide establishing shot, full room visible, characters small in frame, wide environmental context,"},
            {"name": "medium_tight", "prefix": "85mm medium close-up, waist-up framing on main character, intimate portrait composition,"},
            {"name": "close_detail", "prefix": "135mm extreme close-up, face filling entire frame, only face and shoulders visible, dramatic emotional detail,"},
        ]

        # Import should_chain from master chain agent if available
        _should_chain_fn = None
        try:
            from atlas_agents.master_shot_chain_agent import should_chain as _sc
            _should_chain_fn = _sc
        except Exception:
            pass

        def _should_chain_shots(prev_s, curr_s):
            """Check if two adjacent shots should chain (end-frame → first-frame)."""
            if not enable_chain or not prev_s:
                return False
            if _should_chain_fn:
                return _should_chain_fn(prev_s, curr_s)
            # Fallback inline check
            sid = curr_s.get("shot_id", "")
            stype = (curr_s.get("type") or curr_s.get("shot_type", "")).lower()

            # V21.2: Scene-type chain behavior
            scene_type = curr_s.get('_scene_type', '')
            if scene_type:
                try:
                    from tools.scene_type_classifier import get_micro_template
                    _tmpl = get_micro_template(scene_type)
                    chain_behavior = _tmpl.get('chain_behavior', 'chain_blocking')
                    if chain_behavior == 'no_chain':
                        return False  # Montage, intercut = no chaining
                    if chain_behavior == 'chain_per_location':
                        # Phone: chain within same location, break between locations
                        prev_loc = (prev_s.get('location', '') or '').upper()
                        curr_loc = (curr_s.get('location', '') or '').upper()
                        if prev_loc and curr_loc and prev_loc != curr_loc:
                            return False
                except Exception:
                    pass  # Non-blocking — continue with default checks

            # V21: Intercut shots NEVER chain — different locations in same scene
            if curr_s.get("_intercut"):
                return False
            # V22 FIX: B-roll/inserts don't chain — use explicit flags, NOT shot_id suffix
            # The suffix "B" in shot IDs like 001_005B means ANGLE B, not B-roll!
            _is_explicit_broll = curr_s.get("_broll", False) or curr_s.get("_no_chain", False)
            _is_broll_type = stype in ("b-roll", "b_roll", "broll")
            if _is_explicit_broll or _is_broll_type:
                return False
            if any(t in stype for t in ["insert", "detail", "cutaway"]):
                return False
            # V18.2: Establishing/master — smart chain: interior + characters + dialogue = chain
            if "establishing" in stype or "master" in stype:
                _ec = curr_s.get("characters", [])
                _ed = (curr_s.get("dialogue_text") or curr_s.get("dialogue") or "").strip()
                _eloc = (curr_s.get("location") or "").upper()
                if _eloc.startswith("EXT.") or not _ec or len(_ed) < 10:
                    return False  # Pure location-setter or exterior — don't chain
                # Interior establishing with characters + dialogue — allow chain
            # No characters = atmospheric/detail, don't chain
            if not curr_s.get("characters"):
                return False
            # V.O. / intercut / phone = cross-location, don't chain
            prompt = (curr_s.get("ltx_motion_prompt", "") + curr_s.get("nano_prompt", "")).lower()
            if any(kw in prompt for kw in ["voice over", "v.o.", "intercut", "phone call", "cross-cut"]):
                return False
            return True

        def _extract_last_frame(video_path, output_path):
            """Extract last frame from video using FFmpeg."""
            try:
                # Get duration
                dur_cmd = f'ffprobe -v error -show_entries format=duration -of csv=p=0 "{video_path}"'
                dur_result = subprocess.run(dur_cmd, shell=True, capture_output=True, text=True, timeout=10)
                vid_duration = float(dur_result.stdout.strip())
                # Seek to near end and extract frame
                seek_time = max(0, vid_duration - 0.1)
                cmd = f'ffmpeg -y -ss {seek_time} -i "{video_path}" -vframes 1 -q:v 2 "{output_path}"'
                subprocess.run(cmd, shell=True, capture_output=True, timeout=15)
                return Path(output_path).exists()
            except Exception as e:
                logger.error(f"[KLING-CHAIN] Last frame extraction failed: {e}")
                return False

        logger.info(f"[CHAIN] Scene {scene_id}: {len(scene_shots)} shots, chain={enable_chain}, model={video_model}")

        # V18.2: System health check (non-blocking — log warnings, don't block)
        _sentry_ok = bool(os.environ.get("SENTRY_DSN", ""))
        try:
            _temporal_ok = _TEMPORAL_AVAILABLE
        except NameError:
            _temporal_ok = False
        if not _sentry_ok:
            logger.warning(f"[CHAIN] ⚠️ Sentry not configured — monitoring disabled")
        if not _temporal_ok:
            logger.warning(f"[CHAIN] ⚠️ Temporal not available — workflow tracking disabled")

        # V21.5: Temporal workflow tracking for chain pipeline (was MISSING — only checked availability)
        _chain_wf_id = None
        try:
            _chain_wf_id = temporal_start_workflow(project, f"chain_render_{scene_id}")
            temporal_run_activity(_chain_wf_id, f"chain_render_{scene_id}")
        except Exception:
            pass  # Temporal tracking is non-blocking

        # V18.2: Clear stale tracker entries for this scene before adding fresh ones
        LIVE_GEN_TRACKER.clear_scene(scene_id)

        # V18.2: Use actual video_model label (was hardcoded "kling")
        _model_label = video_model if video_model else "kling"
        LIVE_GEN_TRACKER.add(project, f"CHAIN_{scene_id}", "running", f"{_model_label}_chain",
                             prompt=f"Chain S{scene_id}: {len(scene_shots)} shots ({_model_label})...")
        for _s in scene_shots:
            # V22 FIX: Use explicit flags, NOT shot_id suffix (B = angle, not B-roll)
            _s_type = (_s.get("type") or _s.get("shot_type") or "").lower()
            _is_broll = _s.get("_broll", False) or _s.get("_no_chain", False) or _s_type in ("b-roll", "b_roll", "broll")
            LIVE_GEN_TRACKER.add(project, _s["shot_id"], "pending", _model_label,
                                 prompt=f"{'📦' if _is_broll else '🔗'} waiting...")

        # =========================================================================
        # V18.1 FULL MASTER CHAIN PIPELINE
        # Per shot: nano-banana frame → video (Kling/LTX) → FFmpeg last frame
        #           → nano-pro-edit 3 angles → best variant = next shot's first frame
        # B-roll/inserts: nano-banana frame → video only (no chain)
        # =========================================================================
        # video_model already set from thread parameters above

        def _upload_frame_for_api(local_path):
            """Upload a local frame for FAL API consumption.
            V24.2: R2 permanent URL preferred (works with ALL APIs including Kling).
            Falls back to base64 data URI, then FAL upload as last resort."""
            local_path = str(local_path)
            _p = Path(local_path)
            if not _p.exists():
                logger.error(f"[CHAIN] Frame file not found: {_p.name}")
                return None
            # Method 1: R2 public URL (permanent, works with Kling + LTX + nano, no size limit)
            # V26.1: VERIFY URL is actually accessible before returning — R2 bucket may return 401
            if R2_ENABLED:
                try:
                    _rk = f"{project}/chain/{_p.stem}_{int(_time.time())}.jpg"
                    url = r2_upload_file(_p, _rk)
                    if url and url.startswith("http"):
                        # V26.1: Quick HEAD check — if R2 public access is broken, fall through to base64
                        import urllib.request as _urllib_req
                        try:
                            _head_req = _urllib_req.Request(url, method="HEAD")
                            _head_resp = _urllib_req.urlopen(_head_req, timeout=5)
                            if _head_resp.status == 200:
                                logger.info(f"[CHAIN] Frame → R2 permanent URL (verified): {_p.name} → {url[:80]}")
                                return url
                            else:
                                logger.warning(f"[CHAIN] R2 URL returned {_head_resp.status} — falling through to base64")
                        except Exception as _head_err:
                            logger.warning(f"[CHAIN] R2 URL not accessible ({_head_err}) — falling through to base64")
                except Exception as _r2_err:
                    logger.warning(f"[CHAIN] R2 upload failed: {_r2_err}")
            # Method 2: DIRECT base64 (reliable for nano/LTX but large payload)
            try:
                with open(local_path, "rb") as _f:
                    import base64 as _b64
                    data = _f.read()
                    _ext = _p.suffix.lower()
                    _mime = "image/png" if _ext == ".png" else "image/jpeg"
                    b64_url = f"data:{_mime};base64,{_b64.b64encode(data).decode('utf-8')}"
                    logger.info(f"[CHAIN] Frame → base64 fallback: {_p.name} ({len(data):,} bytes)")
                    return b64_url
            except Exception as _b64_err:
                logger.warning(f"[CHAIN] base64 failed for {_p.name}: {_b64_err}")
            # Method 3: FAL upload (last resort — temp URLs expire in ~1hr)
            try:
                _rotate_fal_key()
                url = fal_client.upload_file(local_path)
                if url:
                    logger.warning(f"[CHAIN] Frame → FAL temp URL (may expire): {_p.name}")
                    return url
            except Exception as _fal_err:
                logger.warning(f"[CHAIN] FAL upload failed: {_fal_err}")
            logger.error(f"[CHAIN] ALL upload methods failed for {_p.name}")
            return None

        def _build_video_prompt(shot_data, is_chained=False):
            """Build video generation prompt from shot metadata.
            V27.1.4e: For dialogue shots, ALWAYS compile clean from OTS enforcer.
            V18.3: When chained, strip environment/location to prevent set rebuild."""
            # V27.1.4e: DIALOGUE SHOTS — always compile clean (disk prompt is contaminated)
            _bvp_chars = shot_data.get("characters") or []
            _bvp_dialogue = shot_data.get("dialogue_text", "")
            if _bvp_dialogue and _bvp_chars:
                try:
                    from tools.ots_enforcer import OTSEnforcer
                    _bvp_enforcer = OTSEnforcer(cast_map)
                    _bvp_clean = _bvp_enforcer.compile_universal_video_prompt(shot_data)
                    if _bvp_clean and len(_bvp_clean) > 50:
                        logger.info(f"[V27.1.4e] {shot_data.get('shot_id','')}: clean video prompt compiled ({len(_bvp_clean)} chars)")
                        return _bvp_clean
                except Exception as _bvp_err:
                    logger.warning(f"[V27.1.4e] {shot_data.get('shot_id','')}: clean compile failed, using legacy: {_bvp_err}")

            # V24.1: Prefer Film Engine compiled LTX prompt if available (non-dialogue path)
            ltx_prompt = shot_data.get("ltx_prompt_v24") or shot_data.get("ltx_motion_prompt", "")
            vp = ltx_prompt
            for marker in ["face stable, NO morphing, NO grid, identity locked, single continuous shot.",
                           "face stable NO morphing"]:
                vp = vp.replace(marker, "")
            vp = vp.strip()
            if not vp:
                # V27.1.5: nano_prompt_v24 fallback REMOVED — stale V24 field could override baked prompts
                vp = shot_data.get("nano_prompt", "Cinematic scene, subtle movement")

            # V27.1.5: VIDEO PROMPT ENVIRONMENT STRIPPER REMOVED (was V18.3)
            # REASON: Timed choreography is now baked into ltx_motion_prompt. The old
            # stripper would remove spatial context that our per-second actions reference.
            # With baked prompts, environment descriptions in video prompts are INTENTIONAL.
            # Original code: atlas_continuity_tightener.strip_env_from_prompt()
            # Removed: 2026-03-17 — outgrown by timed choreography system

            # V21.8: BLOCKING/ACTION INJECTION — end-frame locks environment, but TEXT
            # must carry the character action so LTX-2 knows WHAT the character does.
            # Without this, chained shots get "subtle movement" instead of "kneels at altar".
            _shot_action = (shot_data.get("_beat_character_action") or "").strip()
            if not _shot_action:
                # Fallback: extract from nano_prompt "Character action:" marker
                _nano_for_action = shot_data.get("nano_prompt", "") or ""
                _ca_idx = _nano_for_action.lower().find("character action:")
                if _ca_idx >= 0:
                    _ca_text = _nano_for_action[_ca_idx + len("character action:"):].strip()
                    _ca_end = _ca_text.find(". ")
                    _shot_action = _ca_text[:_ca_end] if _ca_end > 0 else _ca_text[:150]
            if _shot_action and "character performs:" not in vp.lower():
                # Extract action verbs for motion guidance
                _chain_verbs = []
                for _cv in ["kneels", "walks", "sits", "stands", "enters", "reads",
                            "speaks", "holds", "opens", "turns", "reaches", "places",
                            "picks", "runs", "watches", "listens", "discovers", "examines"]:
                    if _cv in _shot_action.lower():
                        _chain_verbs.append(_cv)
                _motion_clause = f"character performs: {_shot_action[:150]}"
                if _chain_verbs:
                    _motion_clause += f", key motion: {', '.join(_chain_verbs[:4])}"
                vp = f"{_motion_clause}. {vp}"
                logger.info(f"[CHAIN-ACTION] {shot_data.get('shot_id','')}: injected blocking action into video prompt")

            # V21.8: COVERAGE ROLE CONSTRAINT — tell LTX what kind of shot this is
            _cov_role = shot_data.get("coverage_role", "")
            _shot_role = shot_data.get("shot_role", "")
            if _cov_role and _cov_role not in vp:
                # V21.9.1: Ensure proper sentence separator before coverage role injection
                # Was: "time: evening Medium action framing" (concatenation bug)
                # Now: "time: evening. Medium action framing, character blocking clear."
                _sep = ". " if vp and not vp.rstrip().endswith(".") else " "
                if "GEOGRAPHY" in _cov_role:
                    vp += f"{_sep}Wide establishing framing, full environment visible."
                elif "EMOTION" in _cov_role:
                    vp += f"{_sep}Close intimate framing, face detail and micro-expressions."
                elif "ACTION" in _cov_role:
                    vp += f"{_sep}Medium action framing, character blocking and movement clear."

            # V24.2.3: DIALOGUE INJECTION — visual acting direction, NOT raw dialogue text
            # LTX-2 is a VIDEO model — feeding it raw dialogue like "I'm Eleanor Voss" makes
            # it try to render text on screen. Instead inject HOW the character speaks visually.
            _dlg = (shot_data.get("dialogue_text") or shot_data.get("dialogue") or "").strip()
            if _dlg and "character speaks:" not in vp.lower():
                _chars = shot_data.get("characters", [])
                _speaker = _chars[0].split()[0].title() if isinstance(_chars, list) and _chars else "Character"
                _num_chars = len(_chars) if isinstance(_chars, list) else 1
                # Detect speaking tone from dialogue keywords
                _dlg_lower = _dlg.lower()
                _speak_style = "speaks with natural cadence, subtle gestures, attentive expression"
                if any(w in _dlg_lower for w in ["?", "believe", "do you", "really"]):
                    _speak_style = "asks with raised eyebrows, slight head tilt, searching eyes"
                elif any(w in _dlg_lower for w in ["estate", "agency", "agreement", "sale", "office"]):
                    _speak_style = "speaks with measured professionalism, controlled gestures, direct eye contact"
                elif any(w in _dlg_lower for w in ["remember", "died", "love", "heart", "important"]):
                    _speak_style = "speaks with visible emotion, eyes glistening, genuine feeling"
                elif any(w in _dlg_lower for w in ["need you to", "must", "demand", "I suggest"]):
                    _speak_style = "speaks with authority, chin raised, deliberate enunciation"
                elif any(w in _dlg_lower for w in ["didn't know", "wasn't", "nobody"]):
                    _speak_style = "speaks guardedly, slight withdrawal, defensive posture"
                _visual_dir = f"{_speaker} {_speak_style}"
                if _num_chars >= 2:
                    _visual_dir += ", counterpart listens with attentive stillness"
                vp = f'character speaks: {_visual_dir}, lips moving naturally with emotion. {vp}'
                logger.info(f"[CHAIN-DLG] {shot_data.get('shot_id','')}: injected visual dialogue direction into video prompt")

            # V18.3.1: Also inject beat action if present and not already in prompt
            _beat_action = shot_data.get("_beat_action", "")
            if _beat_action and "character performs:" not in vp.lower() and "character action:" not in vp.lower():
                _action_clip = _beat_action[:150]
                vp = f'character performs: {_action_clip}. {vp}'
                logger.info(f"[CHAIN-ACT] {shot_data.get('shot_id','')}: injected beat action into video prompt")

            # V24.2: Audio prompt injection ONLY for Kling (native audio model).
            # LTX has no audio — injecting audio language confused the action model and caused
            # heavy fake sound undertones when audio was processed downstream.
            if generate_audio and video_model == "kling":
                vp = f"{vp}, realistic sound effects, foley audio, natural environment sounds"

            # V22.3 CAMERA EMBEDDING — REMOVED BY V24.2 (2026-03-10)
            # V24.2 compiler already includes focal length + aperture in LTX prompts.
            # This block was appending redundant camera language to chain video prompts.

            # V23 HARD GATE: Performance marker enforcement for chain pipeline
            # Ensure every character shot has a performance marker
            vp = ensure_performance_marker(shot_data, vp)

            # V24.1/V26.1: CONTINUITY MEMORY DELTA — append spatial state + reframe plan
            # V26.1: Also inject for BLOCKING_AWARE shots (dialogue cuts), not just REFRAME chains
            _v24_delta = shot_data.get("_v24_continuity_delta", "")
            _is_blocking_aware = shot_data.get("_blocking_aware_gen", False)
            if _v24_delta and (is_chained or _is_blocking_aware):
                vp = vp.rstrip(". ,") + ". " + _v24_delta
                _mode = "blocking-aware" if _is_blocking_aware else "chained"
                logger.info(f"[V24.1] {shot_data.get('shot_id','')}: continuity delta appended to video prompt ({_mode})")

            # V18.3.1: Raised from 500 to 1400 chars — dialogue + action + camera + continuity delta
            # LTX-2 handles long prompts well; need room for V24.1 spatial delta
            if len(vp) > 1400:
                vp = vp[:1397] + "..."
            return vp

        # ═══ V27.3: RESILIENT DOWNLOAD — Retry URL downloads with backoff ═══
        def _download_with_retry(url, dest_path, max_retries=2, label=""):
            """Download URL to file with retry on failure. Returns True on success."""
            import urllib.request
            for _dl_attempt in range(max_retries + 1):
                try:
                    urllib.request.urlretrieve(url, str(dest_path))
                    if Path(dest_path).exists() and Path(dest_path).stat().st_size > 0:
                        return True
                    logger.warning(f"[DOWNLOAD] {label}: empty file on attempt {_dl_attempt + 1}")
                except Exception as _dl_err:
                    logger.warning(f"[DOWNLOAD] {label}: attempt {_dl_attempt + 1}/{max_retries + 1} failed: {_dl_err}")
                    if _dl_attempt < max_retries:
                        time.sleep(2 * (_dl_attempt + 1))  # Backoff: 2s, 4s
            return False

        # ═══ V27.3: MAX 2 RETRIES CONSTANT — Strict across all gen paths ═══
        _V273_MAX_GEN_RETRIES = 2

        def _generate_video_kling(frame_url, prompt, dur, out_path, shot_id_label,
                                   char_ref_urls=None, negative_prompt=None):
            """Generate video via Kling V3 Pro. Returns True on success.
            V27.2: Accepts char_ref_urls for Kling Elements identity lock.
            V27.3: Strict 2-retry with prompt simplification on failure.
            """
            KLING_MAX_SEG = 15
            capped = min(dur, 15)
            if capped <= KLING_MAX_SEG:
                segs = [capped]
            else:
                n = max(1, (capped + KLING_MAX_SEG - 1) // KLING_MAX_SEG)
                sd = capped // n
                segs = [sd] * n
                for ri in range(capped - sd * n):
                    segs[ri] += 1

            # V27.2: Build Kling Elements array from character refs (max 2)
            _kling_elements = []
            _kling_prompt = prompt
            if char_ref_urls:
                for _ei, _ref_url in enumerate(char_ref_urls[:2]):
                    try:
                        _uploaded = _upload_frame_for_api(Path(_ref_url)) if not _ref_url.startswith("http") else _ref_url
                        if _uploaded:
                            _kling_elements.append({"frontal_image_url": _uploaded, "reference_image_urls": [_uploaded]})
                    except Exception as _eup:
                        logger.warning(f"[CHAIN-KLING] {shot_id_label}: element {_ei} upload failed: {_eup}")
                # Inject @Element tags into prompt if not already present
                for _ti in range(len(_kling_elements)):
                    _tag = f"@Element{_ti + 1}"
                    if _tag not in _kling_prompt:
                        _kling_prompt = f"{_tag} " + _kling_prompt
                logger.info(f"[CHAIN-KLING] {shot_id_label}: {len(_kling_elements)} identity elements wired")
            else:
                logger.warning(f"[CHAIN-KLING] {shot_id_label}: NO character refs — identity may drift!")

            _neg = negative_prompt or "blur, distort, low quality, morphing, grid pattern, split screen, background music, ambient tones, soundscape, musical score, drone sounds"

            # V27.3: 2-RETRY LOOP — attempt 0 = full prompt, attempt 1 = simplified, attempt 2 = minimal
            for _gen_attempt in range(_V273_MAX_GEN_RETRIES + 1):
                _attempt_prompt = _kling_prompt
                if _gen_attempt == 1:
                    # Simplify: strip complex injection blocks
                    for _strip in ["[ROOM DNA:", "[LIGHTING RIG:", "[TIGHT FRAMING:", "[CINEMATIC OVERRIDE:", "[COLOR MATCH:"]:
                        if _strip in _attempt_prompt:
                            _se = _attempt_prompt.find("]", _attempt_prompt.find(_strip))
                            if _se > 0:
                                _attempt_prompt = _attempt_prompt[:_attempt_prompt.find(_strip)] + _attempt_prompt[_se + 1:]
                    _attempt_prompt = _attempt_prompt.strip()
                    logger.info(f"[KLING-RETRY] {shot_id_label}: attempt {_gen_attempt + 1} — simplified prompt ({len(_attempt_prompt)} chars)")
                elif _gen_attempt == 2:
                    # Minimal: first 400 chars + core identity
                    _attempt_prompt = _attempt_prompt[:400].strip()
                    logger.info(f"[KLING-RETRY] {shot_id_label}: attempt {_gen_attempt + 1} — minimal prompt ({len(_attempt_prompt)} chars)")

                logger.info(f"[CHAIN] {shot_id_label}: Kling {capped}s → {segs} (attempt {_gen_attempt + 1}/{_V273_MAX_GEN_RETRIES + 1})")
                seg_vids = []
                seg_url = frame_url
                _seg_failed = False
                for si, sdur in enumerate(segs):
                    _payload = {
                        "prompt": _attempt_prompt, "start_image_url": seg_url, "duration": str(sdur),
                        "aspect_ratio": "16:9", "generate_audio": generate_audio,
                        "negative_prompt": _neg, "cfg_scale": 0.5,
                    }
                    if _kling_elements:
                        _payload["elements"] = _kling_elements
                    try:
                        res = _fal_run_with_retry("fal-ai/kling-video/v3/pro/image-to-video", _payload)
                    except Exception as _fal_err:
                        logger.error(f"[CHAIN] {shot_id_label} seg{si}: FAL error: {_fal_err}")
                        _seg_failed = True
                        break
                    if res and res.get("video"):
                        vd = res["video"]
                        vu = vd["url"] if isinstance(vd, dict) else vd
                        sp = kling_dir / (f"{shot_id_label}_seg{si}.mp4" if len(segs) > 1 else f"{shot_id_label}.mp4")
                        if not _download_with_retry(vu, sp, max_retries=2, label=f"{shot_id_label}_seg{si}"):
                            logger.error(f"[CHAIN] {shot_id_label} seg{si}: video download failed after retries")
                            _seg_failed = True
                            break
                        seg_vids.append(str(sp))
                        if si < len(segs) - 1:
                            lf = kling_dir / f"{shot_id_label}_seg{si}_last.jpg"
                            if _extract_last_frame(sp, lf) and lf.exists():
                                seg_url = _upload_frame_for_api(lf)
                    else:
                        logger.error(f"[CHAIN] {shot_id_label} seg{si}: no video returned (attempt {_gen_attempt + 1})")
                        _seg_failed = True
                        break

                if not _seg_failed and seg_vids:
                    # Success — assemble final video
                    if len(segs) > 1 and len(seg_vids) == len(segs):
                        cl = kling_dir / f"{shot_id_label}_concat.txt"
                        with open(cl, "w") as cf:
                            for sv in seg_vids:
                                cf.write(f"file '{sv}'\n")
                        # Audio preserved — removed -an strip flag (V37.1)
                        subprocess.run(f'ffmpeg -y -f concat -safe 0 -i "{cl}" -c copy "{out_path}"',
                                       shell=True, capture_output=True, timeout=120)
                    elif len(segs) == 1 and seg_vids:
                        if str(seg_vids[0]) != str(out_path):
                            shutil.copy2(seg_vids[0], str(out_path))
                    if out_path.exists():
                        if _gen_attempt > 0:
                            logger.info(f"[KLING-RETRY] {shot_id_label}: ✅ succeeded on attempt {_gen_attempt + 1}")
                        return True

                # Failed this attempt — retry if attempts remain
                if _gen_attempt < _V273_MAX_GEN_RETRIES:
                    logger.warning(f"[KLING-RETRY] {shot_id_label}: attempt {_gen_attempt + 1} failed — retrying ({_gen_attempt + 2}/{_V273_MAX_GEN_RETRIES + 1})")
                    time.sleep(3)  # Brief cooldown before retry

            logger.error(f"[CHAIN] {shot_id_label}: Kling FAILED after {_V273_MAX_GEN_RETRIES + 1} attempts — manual review needed")
            return False

        def _generate_video_ltx(frame_url, prompt, dur, out_path, shot_id_label):
            """Generate video via LTX-2 image-to-video. Returns True on success.
            V17.8.2: LTX Fast uses 'duration' (even seconds), NOT num_frames.
            V27.3: Strict 2-retry with prompt simplification on failure.
            """
            # LTX Fast only accepts EVEN durations: 6, 8, 10, 12, 14, 16, 18, 20
            LTX_VALID_DURATIONS = [6, 8, 10, 12, 14, 16, 18, 20]
            raw_dur = min(dur, 20)
            api_duration = min((d for d in LTX_VALID_DURATIONS if d >= raw_dur), default=20)
            _chain_neg = (_shot.get("negative_prompt") or "blurry, distorted face, morphing, low quality, text, watermark, extra limbs")

            for _gen_attempt in range(_V273_MAX_GEN_RETRIES + 1):
                _attempt_prompt = prompt
                if _gen_attempt == 1:
                    # Simplify prompt on retry
                    if len(_attempt_prompt) > 600:
                        _attempt_prompt = _attempt_prompt[:600].strip()
                    logger.info(f"[LTX-RETRY] {shot_id_label}: attempt {_gen_attempt + 1} — simplified prompt")
                elif _gen_attempt == 2:
                    _attempt_prompt = _attempt_prompt[:400].strip()
                    logger.info(f"[LTX-RETRY] {shot_id_label}: attempt {_gen_attempt + 1} — minimal prompt")

                logger.info(f"[CHAIN] {shot_id_label}: LTX {dur}s → {api_duration}s (attempt {_gen_attempt + 1}/{_V273_MAX_GEN_RETRIES + 1})")
                try:
                    res = _fal_run_with_retry("fal-ai/ltx-2.3/image-to-video/fast", {
                        "prompt": _attempt_prompt,
                        "image_url": frame_url,
                        "negative_prompt": _chain_neg,
                        "duration": api_duration,
                        "aspect_ratio": "16:9"
                    })
                except Exception as _fal_err:
                    logger.error(f"[CHAIN] {shot_id_label}: LTX FAL error: {_fal_err}")
                    if _gen_attempt < _V273_MAX_GEN_RETRIES:
                        time.sleep(3)
                        continue
                    return False

                video_url = None
                if isinstance(res, dict):
                    video_url = res.get("video", {}).get("url") or res.get("url")
                if video_url:
                    if _download_with_retry(video_url, out_path, max_retries=2, label=shot_id_label):
                        if _gen_attempt > 0:
                            logger.info(f"[LTX-RETRY] {shot_id_label}: ✅ succeeded on attempt {_gen_attempt + 1}")
                        return True
                    logger.warning(f"[CHAIN] {shot_id_label}: LTX download failed on attempt {_gen_attempt + 1}")
                else:
                    logger.warning(f"[CHAIN] {shot_id_label}: LTX no video URL on attempt {_gen_attempt + 1}. Keys: {list(res.keys()) if res else 'None'}")

                if _gen_attempt < _V273_MAX_GEN_RETRIES:
                    time.sleep(3)

            logger.error(f"[CHAIN] {shot_id_label}: LTX FAILED after {_V273_MAX_GEN_RETRIES + 1} attempts — manual review needed")
            return False

        def _generate_video_seeddance(frame_url, prompt, dur, out_path, shot_id_label):
            """Generate video via SeedDance 2.0 image-to-video (ByteDance via FAL).
            V21.10: Added for SeedDance 2.0 support — fast ~1.5min/shot, high quality.
            V27.3: Strict 2-retry, then falls back to LTX (which also has 2-retry).
            """
            SEEDDANCE_MODEL = "fal-ai/bytedance/seedance/v2/image-to-video"
            api_duration = max(4, min(int(dur), 20))
            _chain_neg = (_shot.get("negative_prompt") or "blurry, distorted face, morphing, low quality, text, watermark, extra limbs")

            for _gen_attempt in range(_V273_MAX_GEN_RETRIES + 1):
                _attempt_prompt = prompt
                if _gen_attempt >= 1 and len(_attempt_prompt) > 500:
                    _attempt_prompt = _attempt_prompt[:500].strip()

                logger.info(f"[CHAIN] {shot_id_label}: SeedDance 2.0 {dur}s → {api_duration}s (attempt {_gen_attempt + 1})")
                try:
                    res = _fal_run_with_retry(SEEDDANCE_MODEL, {
                        "prompt": _attempt_prompt,
                        "image_url": frame_url,
                        "negative_prompt": _chain_neg,
                        "duration": api_duration,
                        "aspect_ratio": "16:9"
                    })
                    video_url = None
                    if isinstance(res, dict):
                        video_url = res.get("video", {}).get("url") or res.get("url")
                    if video_url:
                        if _download_with_retry(video_url, out_path, max_retries=2, label=shot_id_label):
                            if _gen_attempt > 0:
                                logger.info(f"[SD-RETRY] {shot_id_label}: ✅ succeeded on attempt {_gen_attempt + 1}")
                            return True
                except Exception as _sd_err:
                    logger.warning(f"[CHAIN] {shot_id_label}: SeedDance attempt {_gen_attempt + 1} error: {_sd_err}")
                    if _gen_attempt < _V273_MAX_GEN_RETRIES:
                        time.sleep(3)
                        continue
                    # Final fallback: try LTX (which also has its own 2-retry)
                    logger.warning(f"[CHAIN] {shot_id_label}: SeedDance exhausted {_V273_MAX_GEN_RETRIES + 1} attempts — falling back to LTX")
                    return _generate_video_ltx(frame_url, prompt, dur, out_path, shot_id_label)

                if _gen_attempt < _V273_MAX_GEN_RETRIES:
                    time.sleep(3)

            # All SeedDance attempts failed — fall back to LTX (with its own 2-retry)
            logger.warning(f"[CHAIN] {shot_id_label}: SeedDance FAILED after {_V273_MAX_GEN_RETRIES + 1} attempts — falling back to LTX")
            return _generate_video_ltx(frame_url, prompt, dur, out_path, shot_id_label)

        def _nano_angle_variant(shot_data, angle_prefix, output_path, char_ref_urls):
            """V18.2: Generate angle variant via nano-banana with character refs.
            V21: nano-pro-edit with character refs for identity-consistent angles."""
            try:
                base_prompt = shot_data.get("nano_prompt", "")
                # Strip existing lens/camera prefixes to avoid conflict
                for strip_prefix in ["24mm", "50mm", "85mm", "100mm", "135mm"]:
                    if base_prompt.startswith(strip_prefix):
                        base_prompt = base_prompt[len(strip_prefix):].lstrip(" ,")
                        break
                # Build angle-specific prompt
                angle_prompt = f"{angle_prefix} {base_prompt}"
                # Truncate to model limit
                if len(angle_prompt) > 900:
                    angle_prompt = angle_prompt[:897] + "..."

                logger.info(f"[CHAIN-NANO-ANGLE] {Path(output_path).name}: {angle_prompt[:80]}...")

                # V24.2.4: Shot Authority — corrected API params (no guidance_scale/steps)
                _av_res = "1K"
                _av_max_refs = 5
                if _shot_authority_available:
                    try:
                        _av_contract = _sa_build_contract(shot_data, cast_map, char_ref_urls or [])
                        _av_res = _av_contract.profile.resolution
                        _av_max_refs = _av_contract.profile.max_refs
                    except Exception:
                        pass

                if char_ref_urls:
                    fal_ready = convert_refs_for_fal(char_ref_urls[:_av_max_refs])
                    fal_result = _fal_run_with_retry(NANO_MODEL_REF, {
                        "prompt": angle_prompt, "image_urls": fal_ready,
                        "aspect_ratio": "16:9", "resolution": _av_res,
                        "output_format": "jpeg", "num_outputs": 1
                    })
                else:
                    fal_result = _fal_run_with_retry(NANO_MODEL_T2I, {
                        "prompt": angle_prompt, "aspect_ratio": "16:9",
                        "resolution": _av_res, "output_format": "jpeg", "num_images": 1
                    })

                _yield_gil()

                # Extract image URL
                img_url = None
                if fal_result.get("images") and len(fal_result["images"]) > 0:
                    img_url = fal_result["images"][0].get("url")
                elif fal_result.get("image"):
                    img_url = fal_result["image"]["url"] if isinstance(fal_result["image"], dict) else fal_result["image"]

                if img_url:
                    import urllib.request
                    urllib.request.urlretrieve(img_url, str(output_path))
                    if output_path.exists():
                        logger.info(f"[CHAIN-NANO-ANGLE] ✅ Variant saved: {output_path.name}")
                        return True
                logger.error(f"[CHAIN-NANO-ANGLE] No image in response")
            except Exception as qe:
                logger.error(f"[CHAIN-NANO-ANGLE] Variant failed: {qe}")
            return False

        _update_run(status="running", current_step="generating shots")

        # V18.2: GIL yield helper — releases GIL so uvicorn can process HTTP requests
        def _yield_gil():
            """Short sleep to release GIL and let event loop process requests."""
            _time.sleep(0.05)

        # =====================================================================
        # V18.2: PARALLEL PIPELINE — pre-generate frames for independent shots
        # While LTX renders video for shot N, nano generates frame for shot N+1
        # Independent = B-roll, establishing, or won't chain from previous
        # =====================================================================
        from concurrent.futures import ThreadPoolExecutor, as_completed
        _prefetch_frames = {}  # shot_id → (frame_path, frame_source)  pre-generated frames
        _video_executor = ThreadPoolExecutor(max_workers=2, thread_name_prefix="atlas_video")

        def _prefetch_frame(shot_data, shot_idx):
            """Pre-generate a frame for an independent shot in background."""
            _pf_sid = shot_data["shot_id"]
            try:
                nano_prompt = shot_data.get("nano_prompt", shot_data.get("ltx_motion_prompt", "Cinematic scene"))
                characters = shot_data.get("characters", [])
                if isinstance(characters, str):
                    characters = [c.strip() for c in characters.split(",") if c.strip()]

                pf_ref_urls = []
                for char_name in characters:
                    for cname, cdata in cast_map.items():
                        if char_name.upper() in cname.upper() or cname.upper() in char_name.upper():
                            # V21.10: ALWAYS prefer character_reference_url (CHAR_REFERENCE) over headshot_url (AI actor)
                            hr = cdata.get("character_reference_url") or cdata.get("reference_url") or cdata.get("headshot_url", "")
                            if hr:
                                if hr.startswith("/api/media?path="):
                                    hr = hr.split("path=", 1)[1]
                                if not Path(hr).exists():
                                    fname = Path(hr).name
                                    for search_dir in [project_path / "character_library_locked",
                                                       BASE_DIR / "character_library_locked" / "ai_actors",
                                                       BASE_DIR / "ai_actor_headshots"]:
                                        candidate = search_dir / fname
                                        if candidate.exists():
                                            hr = str(candidate)
                                            break
                                if Path(hr).exists():
                                    pf_ref_urls.append(hr)
                            break

                # Location ref (skip for exterior)
                _pf_shot_type = (shot_data.get("type") or shot_data.get("shot_type") or "").lower()
                _pf_is_ext = "ext" in (shot_data.get("location") or "").upper()[:5] or _pf_shot_type in ("establishing", "master")
                if not _pf_is_ext:
                    pf_location = (shot_data.get("location") or "").strip().upper()
                    for loc_key, loc_path in location_masters.items():
                        if loc_key in pf_location or pf_location in loc_key:
                            pf_ref_urls.append(loc_path)
                            break

                pf_output = first_frames_dir / f"{_pf_sid}.jpg"

                # V24.2.4: Shot Authority — resolution + ref cap (corrected API params)
                _pf_res = "1K"
                _pf_max_refs = 5
                if _shot_authority_available:
                    try:
                        _pf_contract = _sa_build_contract(shot_data, cast_map, pf_ref_urls)
                        _pf_res = _pf_contract.profile.resolution
                        _pf_max_refs = _pf_contract.profile.max_refs
                    except Exception:
                        pass

                if pf_ref_urls:
                    fal_ready = convert_refs_for_fal(pf_ref_urls[:_pf_max_refs])
                    fal_result = _fal_run_with_retry(NANO_MODEL_REF, {
                        "prompt": nano_prompt, "image_urls": fal_ready,
                        "aspect_ratio": "16:9", "resolution": _pf_res,
                        "output_format": "jpeg", "num_outputs": 1
                    })
                else:
                    fal_result = _fal_run_with_retry(NANO_MODEL_T2I, {
                        "prompt": nano_prompt, "aspect_ratio": "16:9",
                        "resolution": _pf_res, "output_format": "jpeg", "num_images": 1
                    })

                img_url = None
                if fal_result.get("images") and len(fal_result["images"]) > 0:
                    img_url = fal_result["images"][0].get("url")
                elif fal_result.get("image"):
                    img_url = fal_result["image"].get("url") if isinstance(fal_result["image"], dict) else fal_result["image"]

                if img_url:
                    import urllib.request
                    urllib.request.urlretrieve(img_url, str(pf_output))
                    if pf_output.exists():
                        logger.info(f"[CHAIN-PREFETCH] {_pf_sid}: ⚡ frame pre-generated ({len(pf_ref_urls)} refs)")
                        return (pf_output, "nano_prefetched")
                logger.warning(f"[CHAIN-PREFETCH] {_pf_sid}: no image returned")
            except Exception as pf_err:
                logger.warning(f"[CHAIN-PREFETCH] {_pf_sid}: prefetch failed: {pf_err}")
            return None

        def _generate_video_async(frame_path_in, video_prompt_in, total_dur_in, output_video_in, sid_in, video_model_in,
                                    char_ref_urls_in=None, negative_prompt_in=None):
            """Run video generation in thread pool — returns (vid_ok, output_path).
            V27.2: Passes char_ref_urls for Kling identity lock elements."""
            try:
                frame_url = _upload_frame_for_api(frame_path_in)
                if not frame_url:
                    return (False, output_video_in)
                if video_model_in == "kling":
                    vid_ok = _generate_video_kling(frame_url, video_prompt_in, total_dur_in, output_video_in, sid_in,
                                                   char_ref_urls=char_ref_urls_in, negative_prompt=negative_prompt_in)
                elif video_model_in == "seeddance":
                    vid_ok = _generate_video_seeddance(frame_url, video_prompt_in, total_dur_in, output_video_in, sid_in)
                else:
                    vid_ok = _generate_video_ltx(frame_url, video_prompt_in, total_dur_in, output_video_in, sid_in)
                return (vid_ok, output_video_in)
            except Exception as ve:
                logger.error(f"[CHAIN-VIDEO-ASYNC] {sid_in}: {ve}")
                return (False, output_video_in)

        # Pre-identify which shots are independent (can be pre-generated)
        # V22 FIX: shot_id suffix "B" is ANGLE not B-roll! Check _broll/_no_chain flags instead
        _independent_shots = set()
        for _pi, _ps in enumerate(scene_shots):
            _ps_id = _ps["shot_id"]
            _ps_type = (_ps.get("type") or _ps.get("shot_type") or "").lower()
            # V22: Correct B-roll detection - use explicit flags, NOT shot_id suffix
            _ps_is_broll = _ps.get("_broll", False) or _ps.get("_no_chain", False) or _ps_type in ("b-roll", "b_roll", "broll")
            _ps_is_independent = _ps_is_broll or _ps_type in ("establishing", "master", "title_card", "montage") or not _ps.get("characters")
            if _ps_is_independent:
                _independent_shots.add(_ps_id)
        logger.info(f"[CHAIN] ⚡ Parallel pipeline: {len(_independent_shots)}/{len(scene_shots)} independent shots identified for prefetch")

        _pending_video_future = None  # Future for async video generation
        _pending_video_sid = None     # Which shot's video is running

        for i, shot in enumerate(scene_shots):
            _yield_gil()  # Let server respond between shots

            # V18.2: Check stop flag before each shot
            if _CHAIN_STOP_FLAGS.get(run_id):
                logger.warning(f"[CHAIN] 🛑 Stop flag detected at shot {i+1}/{len(scene_shots)} — aborting gracefully")
                _update_run(status="stopped", current_step=f"stopped at shot {i+1}/{len(scene_shots)}")
                LIVE_GEN_TRACKER.update(f"CHAIN_{scene_id}", "completed")
                # Mark remaining shots as skipped
                for remaining in scene_shots[i:]:
                    LIVE_GEN_TRACKER.update(remaining["shot_id"], "error")
                _CHAIN_STOP_FLAGS.pop(run_id, None)
                break

            sid = shot["shot_id"]
            LIVE_GEN_TRACKER.update(sid, "running", step="generating_frame", progress=0.1)
            _update_run(current_shot=sid, current_step=f"shot {i+1}/{len(scene_shots)}: {sid}", completed_shots=i)

            # V24.2: META DIRECTOR — pre-render readiness check (non-blocking advisory)
            if _meta_director:
                try:
                    _scene_ctx = {"scene_id": scene_id, "total_shots": len(scene_shots), "shot_index": i}
                    _md_decision = _meta_director.check_shot_readiness(shot, _scene_ctx)
                    shot["_meta_director_verdict"] = _md_decision.decision_type
                    if _md_decision.decision_type == "approve":
                        logger.info(f"[V24.2 META] {sid}: ✅ readiness APPROVED (confidence={_md_decision.confidence:.2f})")
                    else:
                        logger.info(f"[V24.2 META] {sid}: ⚠️ {_md_decision.decision_type} — {_md_decision.reason} (action={_md_decision.action})")
                except Exception as _md_err:
                    logger.warning(f"[V24.2 META] {sid}: readiness check non-blocking error: {_md_err}")

            # V22 FIX: Use explicit _broll/_no_chain flags, NOT shot_id suffix (B = angle, not B-roll)
            _shot_type = (shot.get("type") or shot.get("shot_type") or "").lower()
            is_broll = shot.get("_broll", False) or shot.get("_no_chain", False) or _shot_type in ("b-roll", "b_roll", "broll")
            should_chain_decision = _should_chain_shots(prev_shot, shot)

            # V26.1: SMART CHAIN CLASSIFICATION — 3 modes replace binary chain/no-chain
            # REFRAME: same character, different angle → end-frame reframe (env locked by image)
            # BLOCKING_AWARE: different character (dialogue cut) → fresh gen WITH spatial delta
            # INDEPENDENT: b-roll, establishing, no characters → standard gen, no chain
            _chain_mode = "INDEPENDENT"
            try:
                from tools.continuity_memory import classify_chain_transition
                _chain_mode = classify_chain_transition(prev_shot, shot)
            except Exception as _cm_cls_err:
                logger.warning(f"[V26.1] {sid}: chain classification non-blocking error: {_cm_cls_err}")
                # Fallback to old binary logic
                _chain_mode = "REFRAME" if should_chain_decision else "INDEPENDENT"

            do_chain = _chain_mode == "REFRAME" and chain_frame_for_next is not None
            do_blocking_aware = _chain_mode == "BLOCKING_AWARE"
            frame_path = None
            frame_source = "nano_generated"
            shot["_chain_mode"] = _chain_mode
            logger.info(f"[CHAIN] {sid}: chain_mode={_chain_mode}, should_chain={should_chain_decision}, "
                        f"chain_frame_exists={chain_frame_for_next is not None}, do_chain={do_chain}, "
                        f"do_blocking_aware={do_blocking_aware}, is_broll={is_broll}")

            try:
                # ==============================================================
                # STEP 1: FIRST FRAME (chained = end-frame reframe from prev shot)
                # V18.3: Chained shots use the selected end-frame reframe variant.
                # The environment is LOCKED by the image — no text rebuilds the room.
                # ==============================================================
                if do_chain and chain_frame_for_next and Path(chain_frame_for_next).exists():
                    # Chained: use the end-frame reframe variant from previous shot
                    frame_path = Path(chain_frame_for_next)
                    frame_source = "chained_endframe_reframe"
                    logger.info(f"[CHAIN] {sid}: 🔗 using end-frame reframe from {prev_shot['shot_id']} (env locked by image)")
                else:
                    # V18.2: Check if frame was pre-generated by parallel pipeline
                    _prefetched = _prefetch_frames.pop(sid, None)
                    if _prefetched and _prefetched[0].exists():
                        frame_path = _prefetched[0]
                        frame_source = _prefetched[1]
                        logger.info(f"[CHAIN] {sid}: ⚡ using pre-fetched frame (saved ~5s)")
                    else:
                        # V21.1: Real-time edit pickup — check if user edited via UI mid-generation
                        try:
                            _rt_sp_path = project_path / "shot_plan.json" if isinstance(project_path, Path) else Path(project_path) / "shot_plan.json"
                            _rt_mtime = _rt_sp_path.stat().st_mtime if _rt_sp_path.exists() else 0
                            if not hasattr(_extract_last_frame, '_sp_mtime'):
                                _extract_last_frame._sp_mtime = _rt_mtime
                            if _rt_mtime > _extract_last_frame._sp_mtime:
                                # shot_plan.json was modified — reload this shot's prompts
                                with open(_rt_sp_path) as _rt_f:
                                    _rt_data = json.load(_rt_f)
                                for _rt_s in _rt_data.get("shots", []):
                                    if _rt_s.get("shot_id") == sid:
                                        _rt_nano = _rt_s.get("nano_prompt", "")
                                        if _rt_nano and _rt_nano != shot.get("nano_prompt", ""):
                                            shot["nano_prompt"] = _rt_nano
                                            logger.info(f"[CHAIN-LIVE] {sid}: ✏️ picked up real-time prompt edit from UI")
                                        _rt_ltx = _rt_s.get("ltx_motion_prompt", "")
                                        if _rt_ltx:
                                            shot["ltx_motion_prompt"] = _rt_ltx
                                        break
                                _extract_last_frame._sp_mtime = _rt_mtime
                        except Exception:
                            pass  # Non-blocking — continue with existing prompt

                        # Generate fresh frame via nano-banana
                        # V24.1: Prefer Film Engine compiled prompt if available
                        # V27.1.5: nano_prompt_v24 fallback REMOVED — all prompts now in nano_prompt
                        # The old V24 field could override our baked prompt with stale content
                        nano_prompt = shot.get("nano_prompt", "")
                        if not nano_prompt:
                            nano_prompt = shot.get("ltx_motion_prompt", "Cinematic scene")

                        # V26.1: BLOCKING-AWARE GENERATION — inject spatial continuity delta
                        # into nano prompt for dialogue cuts (different character than prev shot).
                        # The delta describes WHERE characters were, camera state, and lighting
                        # so the fresh generation maintains spatial consistency without reframing.
                        if do_blocking_aware and _continuity_memory and prev_shot:
                            try:
                                _prev_state = _continuity_memory.get_shot_state(prev_shot.get("shot_id", ""))
                                if _prev_state:
                                    from tools.continuity_memory import generate_reframe_candidates, compile_continuity_delta
                                    _ba_candidates = generate_reframe_candidates(
                                        shot, _prev_state,
                                        beat_intent=shot.get("_beat_character_action", ""),
                                        emotion_trajectory=shot.get("emotion", "stable"),
                                    )
                                    if _ba_candidates:
                                        # Pick reaction_cut for dialogue cuts, otherwise first candidate
                                        _ba_best = _ba_candidates[0]
                                        for _bac in _ba_candidates:
                                            if _bac.strategy == "reaction_cut":
                                                _ba_best = _bac
                                                break
                                        _ba_delta = compile_continuity_delta(_ba_best, _prev_state, shot)
                                        if _ba_delta:
                                            # Prepend delta to nano prompt — spatial memory FIRST, then shot content
                                            nano_prompt = _ba_delta + "\n\n" + nano_prompt
                                            shot["_v24_continuity_delta"] = _ba_delta
                                            shot["_v24_reframe_strategy"] = _ba_best.strategy
                                            shot["_blocking_aware_gen"] = True
                                            logger.info(f"[V26.1-BA] {sid}: 🧠 blocking-aware delta injected into NANO prompt "
                                                       f"({_ba_best.strategy}, {len(_ba_delta)} chars)")
                            except Exception as _ba_err:
                                logger.warning(f"[V26.1-BA] {sid}: blocking-aware delta non-blocking error: {_ba_err}")

                        # V27.1.5: ENVIRONMENT STRIPPER REMOVED (was V18.3)
                        # REASON: Room DNA is now baked into nano_prompt. The old stripper
                        # would REMOVE our [ROOM DNA:] block thinking it's "environment drift".
                        # With baked prompts, environment is INTENTIONAL, not drift.
                        # Original code: atlas_continuity_tightener.strip_env_from_prompt()
                        # Removed: 2026-03-17 — outgrown by Scene Visual DNA system

                        # V19: CHARACTER_FIRST ref ordering (V9 parity)
                        # Character headshots go FIRST in image_urls (position 1+)
                        # Location master goes LAST (weakest influence)
                        characters = shot.get("characters", [])
                        if isinstance(characters, str):
                            characters = [c.strip() for c in characters.split(",") if c.strip()]

                        _char_ref_urls = []  # V19: Separate lists for ordering
                        _loc_ref_urls = []

                        for char_name in characters:
                            for cname, cdata in cast_map.items():
                                if char_name.upper() in cname.upper() or cname.upper() in char_name.upper():
                                    # V21.10: character_reference_url FIRST — never AI actor headshots
                                    hr = cdata.get("character_reference_url") or cdata.get("reference_url") or cdata.get("headshot_url", "")
                                    if hr:
                                        if hr.startswith("/api/media?path="):
                                            hr = hr.split("path=", 1)[1]
                                        if not Path(hr).exists():
                                            fname = Path(hr).name
                                            for search_dir in [
                                                project_path / "character_library_locked",
                                                BASE_DIR / "character_library_locked" / "ai_actors",
                                                BASE_DIR / "ai_actor_headshots",
                                            ]:
                                                candidate = search_dir / fname
                                                if candidate.exists():
                                                    hr = str(candidate)
                                                    break
                                        if Path(hr).exists():
                                            _char_ref_urls.append(hr)
                                            logger.info(f"[CHAIN] {sid}: ref for {char_name} → {Path(hr).name}")
                                        else:
                                            logger.warning(f"[CHAIN] {sid}: ref NOT FOUND for {char_name}: {Path(hr).name}")
                                    break

                        # Add location master ref — but NOT for establishing/exterior shots
                        _shot_type = (shot.get("type") or shot.get("shot_type") or "").lower()
                        _is_exterior = "ext" in (shot.get("location") or "").upper()[:5] or _shot_type in ("establishing", "master")
                        if not _is_exterior:
                            location = (shot.get("location") or shot.get("setting", "")).strip().upper()
                            for loc_key, loc_path in location_masters.items():
                                if loc_key in location or location in loc_key:
                                    _loc_ref_urls.append(loc_path)
                                    break
                        else:
                            logger.info(f"[CHAIN] {sid}: 🌙 exterior/establishing — skipping interior location ref")

                        # V19: CHARACTER_FIRST — chars always before location in image_urls
                        ref_urls = _char_ref_urls + _loc_ref_urls
                        if _char_ref_urls:
                            logger.info(f"[V19-REFORDER] {sid}: {len(_char_ref_urls)} char refs FIRST, {len(_loc_ref_urls)} loc refs SECOND")

                        output_frame = first_frames_dir / f"{sid}.jpg"

                        # V24.2.4: SHOT AUTHORITY CONTRACT — CORRECTED to actual FAL API params
                        # nano-banana-pro does NOT accept guidance_scale or num_inference_steps.
                        # Real levers: resolution (1K/2K), ref count/order, prompt composition.
                        _sa_resolution = "1K"
                        _sa_max_refs = 5
                        _sa_authority_score = None
                        _sa_prompt = nano_prompt  # May be modified by authority composition prefix
                        if _shot_authority_available:
                            try:
                                _sa_contract = _sa_build_contract(shot, cast_map, ref_urls)
                                _sa_resolution = _sa_contract.profile.resolution
                                _sa_max_refs = _sa_contract.profile.max_refs
                                _sa_authority_score = _sa_contract.authority_score
                                # Use authority-composed prompt (has composition prefix + negative suffix)
                                _sa_prompt = _sa_contract.fal_params.get("prompt", nano_prompt)
                                if _sa_contract.violations:
                                    logger.warning(f"[AUTHORITY] {sid}: {len(_sa_contract.violations)} violations: {_sa_contract.violations[0][:80]}")
                                logger.info(f"[AUTHORITY] {sid}: res={_sa_resolution}, refs={len(ref_urls)}/{_sa_max_refs}, "
                                           f"tier={_sa_contract.profile.quality_tier}, authority={_sa_authority_score}")
                                shot["_authority_score"] = _sa_authority_score
                                shot["_authority_tier"] = _sa_contract.profile.quality_tier
                            except Exception as _sa_err:
                                logger.warning(f"[AUTHORITY] {sid}: contract build failed (non-blocking): {_sa_err}")

                        if ref_urls:
                            fal_ready = convert_refs_for_fal(ref_urls[:_sa_max_refs])
                            fal_result = _fal_run_with_retry(NANO_MODEL_REF, {
                                "prompt": _sa_prompt,
                                "image_urls": fal_ready,
                                "aspect_ratio": "16:9",
                                "resolution": _sa_resolution,
                                "output_format": "jpeg",
                                "num_outputs": 1
                            })
                        else:
                            fal_result = _fal_run_with_retry(NANO_MODEL_T2I, {
                                "prompt": _sa_prompt,
                                "aspect_ratio": "16:9",
                                "resolution": _sa_resolution,
                                "output_format": "jpeg",
                                "num_images": 1
                            })

                        _yield_gil()

                        img_url = None
                        if fal_result.get("images") and len(fal_result["images"]) > 0:
                            img_url = fal_result["images"][0].get("url")
                        elif fal_result.get("image"):
                            img_url = fal_result["image"].get("url") if isinstance(fal_result["image"], dict) else fal_result["image"]

                        if img_url:
                            import urllib.request
                            urllib.request.urlretrieve(img_url, str(output_frame))
                            _yield_gil()
                            frame_path = output_frame
                            frame_source = "nano_generated"
                            logger.info(f"[CHAIN] {sid}: 🎨 nano-banana frame generated ({len(ref_urls)} refs)")
                            _update_run(current_step=f"{sid}: frame generated, starting video...")
                        else:
                            logger.error(f"[CHAIN] {sid}: nano-banana returned no image")
                            results.append({"shot_id": sid, "status": "error", "error": "nano-banana no image",
                                           "frame_source": "none", "chained": False})
                            LIVE_GEN_TRACKER.update(sid, "error")
                            prev_shot = shot
                            chain_frame_for_next = None
                            continue

                if not frame_path or not frame_path.exists():
                    # Last fallback: check for existing first frame
                    for ext in [".jpg", ".png", ".jpeg"]:
                        candidate = first_frames_dir / f"{sid}{ext}"
                        if candidate.exists():
                            frame_path = candidate
                            frame_source = "existing"
                            break
                    if not frame_path:
                        results.append({"shot_id": sid, "status": "skipped", "error": "no frame available",
                                       "frame_source": "none", "chained": False})
                        prev_shot = shot
                        chain_frame_for_next = None
                        continue

                # ==============================================================
                # V24.2.3: SMART REGEN — Vision-guided post-gen QA + delta reprompting
                # Scores the generated frame BEFORE spending money on video.
                # If identity/location/presence/quality fails, builds corrective
                # prompt and regenerates (bounded by regen budget).
                # ==============================================================
                if _smart_regen_available and frame_source == "nano_generated":
                    try:
                        _sr_ref, _sr_loc = _sr_resolve_refs(shot, cast_map, project_path)
                        _sr_result = _sr_chain_qa(
                            frame_path=str(frame_path),
                            shot=shot,
                            cast_map=cast_map,
                            scene_manifest=scene_manifest,
                            ref_path=_sr_ref,
                            location_master_path=_sr_loc,
                        )
                        shot["_smart_regen_scores"] = _sr_result.get("scores", {})

                        if not _sr_result["passed"] and _sr_result.get("needs_regen") and _regen_budget.can_regen(sid):
                            _regen_budget.record_attempt(sid)
                            _sr_failures = _sr_result.get("diagnosis", {})
                            _sr_failures_list = _sr_failures.failures if hasattr(_sr_failures, 'failures') else []
                            logger.warning(f"[SMART-REGEN] {sid}: ❌ frame failed QA — {_sr_failures_list}. "
                                         f"Regenerating with corrective prompt (attempt {_regen_budget.get_attempt(sid)})")
                            _update_run(current_step=f"{sid}: QA failed ({', '.join(_sr_failures_list)}), regenerating...")

                            # Apply corrective prompt
                            _sr_nano = _sr_result.get("corrective_nano", "")
                            _sr_ltx = _sr_result.get("corrective_ltx", "")
                            if _sr_nano:
                                shot["nano_prompt"] = _sr_nano
                            if _sr_ltx:
                                shot["ltx_motion_prompt"] = _sr_ltx

                            # Regenerate frame with corrected prompt + Shot Authority params
                            _sr_output = first_frames_dir / f"{sid}.jpg"
                            try:
                                _sr_prompt = shot.get("nano_prompt_final") or shot.get("nano_prompt", "")
                                if _sr_nano:
                                    _sr_prompt = _sr_nano
                                # V24.2.4: Use authority-dictated resolution + ref cap for regen
                                # Regen bumps to 2K for corrective tightness (hero-tier)
                                _sr_res = "2K" if _sa_resolution == "1K" else _sa_resolution
                                _sr_max = _sa_max_refs
                                if ref_urls:
                                    _sr_refs_capped = convert_refs_for_fal(ref_urls[:_sr_max])
                                    _sr_fal = _fal_run_with_retry(NANO_MODEL_REF, {
                                        "prompt": _sr_prompt, "image_urls": _sr_refs_capped,
                                        "aspect_ratio": "16:9", "resolution": _sr_res,
                                        "output_format": "jpeg", "num_outputs": 1,
                                    })
                                else:
                                    _sr_fal = _fal_run_with_retry(NANO_MODEL_T2I, {
                                        "prompt": _sr_prompt,
                                        "aspect_ratio": "16:9", "resolution": _sr_res,
                                        "output_format": "jpeg", "num_images": 1,
                                    })
                                _sr_img_url = None
                                if _sr_fal.get("images") and len(_sr_fal["images"]) > 0:
                                    _sr_img_url = _sr_fal["images"][0].get("url")
                                elif _sr_fal.get("image"):
                                    _sr_img_url = _sr_fal["image"].get("url") if isinstance(_sr_fal["image"], dict) else _sr_fal["image"]

                                if _sr_img_url:
                                    import urllib.request
                                    urllib.request.urlretrieve(_sr_img_url, str(_sr_output))
                                    frame_path = _sr_output
                                    frame_source = "smart_regen"
                                    shot["_smart_regen_attempt"] = _regen_budget.get_attempt(sid)
                                    shot["_smart_regen_actions"] = _sr_result.get("corrective_actions", [])
                                    logger.info(f"[SMART-REGEN] {sid}: 🔄 regenerated frame (attempt {_regen_budget.get_attempt(sid)})")
                                    _update_run(current_step=f"{sid}: regen frame done, proceeding to video...")

                                    # Score the regen'd frame (for logging only — don't loop further here)
                                    try:
                                        _sr2 = _sr_chain_qa(str(frame_path), shot, cast_map, scene_manifest, _sr_ref, _sr_loc)
                                        shot["_smart_regen_scores_after"] = _sr2.get("scores", {})
                                        _sr2_passed = _sr2.get("passed", True)
                                        logger.info(f"[SMART-REGEN] {sid}: regen QA {'✅ PASS' if _sr2_passed else '⚠️ still failing'} — {_sr2.get('scores', {})}")

                                        # Second attempt if still failing and budget allows
                                        if not _sr2_passed and _regen_budget.can_regen(sid):
                                            _regen_budget.record_attempt(sid)
                                            _sr_esc_nano, _sr_esc_ltx = _sr_escalate(
                                                _sr_result["diagnosis"], shot, cast_map, scene_manifest, attempt=2
                                            )
                                            shot["nano_prompt"] = _sr_esc_nano
                                            _sr_prompt2 = _sr_esc_nano
                                            # V24.2.4: Escalation uses max resolution + full ref budget
                                            _sr2_res = "2K"  # Escalation always hero-tier
                                            _sr2_max = _sa_max_refs
                                            if ref_urls:
                                                _sr2_refs_capped = convert_refs_for_fal(ref_urls[:_sr2_max])
                                                _sr_fal2 = _fal_run_with_retry(NANO_MODEL_REF, {
                                                    "prompt": _sr_prompt2, "image_urls": _sr2_refs_capped,
                                                    "aspect_ratio": "16:9", "resolution": _sr2_res,
                                                    "output_format": "jpeg", "num_outputs": 1,
                                                })
                                            else:
                                                _sr_fal2 = _fal_run_with_retry(NANO_MODEL_T2I, {
                                                    "prompt": _sr_prompt2,
                                                    "aspect_ratio": "16:9", "resolution": _sr2_res,
                                                    "output_format": "jpeg", "num_images": 1,
                                                })
                                            _sr_img2 = None
                                            if _sr_fal2.get("images") and len(_sr_fal2["images"]) > 0:
                                                _sr_img2 = _sr_fal2["images"][0].get("url")
                                            elif _sr_fal2.get("image"):
                                                _sr_img2 = _sr_fal2["image"].get("url") if isinstance(_sr_fal2["image"], dict) else _sr_fal2["image"]
                                            if _sr_img2:
                                                urllib.request.urlretrieve(_sr_img2, str(_sr_output))
                                                frame_path = _sr_output
                                                frame_source = "smart_regen_v2"
                                                shot["_smart_regen_attempt"] = 2
                                                logger.info(f"[SMART-REGEN] {sid}: 🔄🔄 second regen attempt complete")
                                    except Exception as _sr2_err:
                                        logger.warning(f"[SMART-REGEN] {sid}: regen QA non-blocking: {_sr2_err}")
                                else:
                                    logger.warning(f"[SMART-REGEN] {sid}: regen FAL returned no image — using original")
                            except Exception as _sr_regen_err:
                                logger.warning(f"[SMART-REGEN] {sid}: regen failed ({_sr_regen_err}) — using original frame")
                        elif _sr_result["passed"]:
                            logger.info(f"[SMART-REGEN] {sid}: ✅ frame passed QA on first try")
                        else:
                            logger.warning(f"[SMART-REGEN] {sid}: ⚠️ frame failed but regen budget exhausted — accepting as-is")
                    except Exception as _sr_err:
                        logger.warning(f"[SMART-REGEN] {sid}: non-blocking error: {_sr_err}")

                # ==============================================================
                # V24.1: CONTINUITY MEMORY — inject spatial delta before video prompt
                # Reads previous shot's spatial state and compiles a structured
                # delta prompt that replaces vague "continue naturally" with
                # concrete character positions, camera geometry, and constraints.
                # ==============================================================
                _v24_delta = ""
                if _continuity_memory and do_chain and prev_shot:
                    try:
                        _prev_state = _continuity_memory.get_shot_state(prev_shot.get("shot_id", ""))
                        if _prev_state:
                            _candidates = _gen_reframe_candidates(
                                shot, _prev_state,
                                beat_intent=shot.get("_beat_character_action", ""),
                                emotion_trajectory=shot.get("emotion", "stable"),
                            )
                            if _candidates:
                                # V24.2: BASAL GANGLIA — score candidates across 6 dimensions
                                # Replaces blind _candidates[0] with proper Go/No-Go evaluation
                                _best = _candidates[0]  # fallback
                                if _basal_ganglia and len(_candidates) > 1:
                                    try:
                                        _bg_candidates = [
                                            {"variant_id": f"{sid}_reframe_{c.strategy}",
                                             "strategy": c.strategy, "delta_prompt": c.delta_prompt,
                                             "nano_prompt": shot.get("nano_prompt_final", ""),
                                             "shot_type": shot.get("shot_type", "medium"),
                                             "characters": shot.get("characters", []),
                                             "emotion": shot.get("emotion", "stable")}
                                            for c in _candidates
                                        ]
                                        _bg_winner, _bg_result = _basal_ganglia.select_best_candidate(
                                            _bg_candidates, shot, cast_map=cast_map,
                                            previous_shot=prev_shot,
                                            previous_shots=scene_shots[:i],
                                        )
                                        # Map winner back to ReframeCandidate
                                        _winner_strategy = _bg_winner.get("strategy", "")
                                        for _rc in _candidates:
                                            if _rc.strategy == _winner_strategy:
                                                _best = _rc
                                                break
                                        shot["_bg_score"] = round(_bg_result.composite_score, 3)
                                        shot["_bg_verdict"] = _bg_result.verdict
                                        logger.info(f"[V24.2 BG] {sid}: 🧠 {_bg_result.verdict} — strategy={_winner_strategy} "
                                                   f"(score={_bg_result.composite_score:.2f}, {len(_candidates)} candidates)")
                                    except Exception as _bg_err:
                                        logger.warning(f"[V24.2 BG] {sid}: scoring non-blocking error: {_bg_err}")
                                elif len(_candidates) == 1:
                                    logger.info(f"[V24.2 BG] {sid}: single candidate ({_candidates[0].strategy}) — skipping BG scoring")

                                _v24_delta = _compile_delta(_best, _prev_state, shot)
                                if _v24_delta:
                                    # Inject delta into shot's LTX prompt for _build_video_prompt
                                    shot["_v24_continuity_delta"] = _v24_delta
                                    shot["_v24_reframe_strategy"] = _best.strategy
                                    logger.info(f"[V24.1] {sid}: 🧠 continuity delta injected ({_best.strategy}, {len(_v24_delta)} chars)")
                    except Exception as _v24_err:
                        logger.warning(f"[V24.1] {sid}: delta injection non-blocking error: {_v24_err}")

                # ==============================================================
                # STEP 2: VIDEO GENERATION (Kling or LTX based on toggle)
                # ==============================================================
                # V27.2: Route video prompt through model-appropriate compiler
                if video_model == "kling":
                    # Kling gets directorial language: dialogue, character tags, emotion, camera behavior
                    try:
                        from tools.kling_prompt_compiler import compile_video_for_kling
                        video_prompt = compile_video_for_kling(shot, cast_map)
                        logger.info(f"[CHAIN-KLING] {sid}: Kling video prompt compiled ({len(video_prompt)} chars)")
                    except Exception as _kling_compile_err:
                        logger.warning(f"[CHAIN-KLING] {sid}: Kling compile failed, falling back to LTX prompt: {_kling_compile_err}")
                        video_prompt = _build_video_prompt(shot, is_chained=do_chain)
                else:
                    # LTX gets dense performance-driven prompt
                    video_prompt = _build_video_prompt(shot, is_chained=do_chain)

                total_dur = int(shot.get("duration", duration))
                vid_dir = kling_dir if video_model == "kling" else (project_path / "videos")
                vid_dir.mkdir(exist_ok=True)
                output_video = vid_dir / f"{sid}.mp4"

                frame_url = _upload_frame_for_api(frame_path)
                if not frame_url:
                    results.append({"shot_id": sid, "status": "error", "error": "frame upload failed",
                                   "frame_source": frame_source, "chained": False})
                    LIVE_GEN_TRACKER.update(sid, "error")
                    prev_shot = shot
                    chain_frame_for_next = None
                    continue

                # V18.2: PARALLEL PREFETCH — while video renders, pre-generate next independent shot's frame
                _prefetch_future = None
                if i + 1 < len(scene_shots):
                    _next_shot = scene_shots[i + 1]
                    _next_sid = _next_shot["shot_id"]
                    if _next_sid in _independent_shots and _next_sid not in _prefetch_frames:
                        logger.info(f"[CHAIN] ⚡ Prefetching frame for {_next_sid} while {sid} video renders...")
                        _prefetch_future = _video_executor.submit(_prefetch_frame, _next_shot, i + 1)

                LIVE_GEN_TRACKER.update(sid, "running", step="generating_video", progress=0.4)
                if video_model == "kling":
                    # V27.2: Resolve character refs for Kling identity lock (elements)
                    _kling_chain_refs = []
                    # ── E-SHOT GUARD (V37-parity): environment-only shots MUST NOT get char refs ──
                    # Mirrors atlas_universal_runner.py line 3172. If _no_char_ref or _is_broll is
                    # set, passing elements causes Kling to render characters in empty-room shots.
                    _is_e_shot_video = bool(shot.get("_no_char_ref") or shot.get("_is_broll"))
                    if _is_e_shot_video:
                        logger.info(f"[E-SHOT GUARD] {sid}: environment-only shot — char refs withheld from Kling elements")
                    _shot_chars = [] if _is_e_shot_video else (shot.get("characters") or [])
                    for _cc in _shot_chars:
                        _cn = _cc if isinstance(_cc, str) else str(_cc)
                        _cm_key = find_character_match(_cn, cast_map) if cast_map else None
                        if _cm_key and _cm_key in cast_map:
                            _cm_entry = cast_map[_cm_key]
                            # 3-tier priority: ref_pack headshot → character_reference_url → library search
                            _rp = _cm_entry.get("_ref_pack_headshot", {})
                            _ref_path = _rp.get("path") if isinstance(_rp, dict) else None
                            if not _ref_path:
                                _ref_path = _cm_entry.get("character_reference_url") or _cm_entry.get("reference_url")
                            if _ref_path and os.path.isfile(str(_ref_path)):
                                _kling_chain_refs.append(str(_ref_path))
                            elif _ref_path and str(_ref_path).startswith("http"):
                                _kling_chain_refs.append(str(_ref_path))
                            else:
                                # Fallback: search character_library_locked
                                _lib_dir = project_path / "character_library_locked"
                                if _lib_dir.is_dir():
                                    for _lf in sorted(_lib_dir.glob(f"*{_cn.split()[0].upper()}*CHAR_REFERENCE*")):
                                        _kling_chain_refs.append(str(_lf))
                                        break
                    _kling_chain_neg = shot.get("negative_prompt") or "morphing faces, identity drift, blur, distort, low quality, grid pattern, split screen"
                    logger.info(f"[CHAIN-KLING] {sid}: {len(_kling_chain_refs)} char refs resolved for identity lock")

                    # ── V37-parity: PRE-GEN GATE (chain_intelligence_gate) ──────────────────
                    # Zero-cost protection: validate shot before spending on Kling API.
                    # Mirrors atlas_universal_runner.py lines 3183-3212. NON-BLOCKING.
                    _cig_pre_blocked = False
                    if _cig_available:
                        try:
                            _pre_result = _cig_pre(shot, scene_shots)
                            if not _pre_result.passed:
                                logger.warning(
                                    f"[V37-CIG PRE] {sid}: gate BLOCKED — {_pre_result.errors}. "
                                    f"Skipping Kling call to prevent wasted spend."
                                )
                                _cig_pre_blocked = True
                                shot["_cig_pre_blocked"] = True
                                shot["_cig_pre_errors"] = _pre_result.errors
                        except Exception as _cig_pre_err:
                            logger.warning(f"[V37-CIG PRE] {sid}: non-blocking: {_cig_pre_err}")

                    if _cig_pre_blocked:
                        vid_ok = False
                    else:
                        vid_ok = _generate_video_kling(frame_url, video_prompt, total_dur, output_video, sid,
                                                       char_ref_urls=_kling_chain_refs, negative_prompt=_kling_chain_neg)
                else:
                    vid_ok = _generate_video_ltx(frame_url, video_prompt, total_dur, output_video, sid)

                _yield_gil()  # Let server respond after video generation

                # ── V37-parity: POST-GEN GATE (chain_intelligence_gate) ─────────────────
                # After video downloads, validate before propagating the end-frame chain.
                # Mirrors atlas_universal_runner.py lines 3252-3284. NON-BLOCKING.
                if vid_ok and _cig_available and output_video.exists():
                    try:
                        _post_result = _cig_post(shot, str(output_video))
                        if not _post_result.passed:
                            logger.warning(
                                f"[V37-CIG POST] {sid}: post-gen gate FAILED — {_post_result.errors}. "
                                f"Marking shot contaminated; chain end-frame will not propagate."
                            )
                            shot["_cig_post_failed"] = True
                            shot["_cig_post_errors"] = _post_result.errors
                            chain_frame_for_next = None  # Block chain propagation on quality failure
                        else:
                            logger.info(f"[V37-CIG POST] {sid}: ✅ post-gen gate passed")
                    except Exception as _cig_post_err:
                        logger.warning(f"[V37-CIG POST] {sid}: non-blocking: {_cig_post_err}")

                # Collect prefetch result if it ran
                if _prefetch_future:
                    try:
                        _pf_result = _prefetch_future.result(timeout=30)
                        if _pf_result:
                            _prefetch_frames[scene_shots[i + 1]["shot_id"]] = _pf_result
                            logger.info(f"[CHAIN] ⚡ Prefetch complete for {scene_shots[i + 1]['shot_id']}")
                    except Exception as _pfe:
                        logger.warning(f"[CHAIN] Prefetch failed (non-blocking): {_pfe}")

                if not vid_ok:
                    # ═══ V27.3: SMART REGEN — Retry failed video with escalation ═══
                    _vid_retried = False
                    if video_model == "kling":
                        logger.warning(f"[SMART-REGEN] {sid}: Kling video failed — retrying with simplified prompt + higher cfg")
                        try:
                            # Simplify prompt: strip complex directions, keep core action
                            _retry_prompt = video_prompt
                            if len(_retry_prompt) > 600:
                                _retry_prompt = _retry_prompt[:600]  # Truncate long prompts
                            # Remove potential problematic instructions
                            for _strip_tag in ["[ROOM DNA:", "[LIGHTING RIG:", "[TIGHT FRAMING:", "[CINEMATIC OVERRIDE:"]:
                                if _strip_tag in _retry_prompt:
                                    _strip_end = _retry_prompt.find("]", _retry_prompt.find(_strip_tag))
                                    if _strip_end > 0:
                                        _retry_prompt = _retry_prompt[:_retry_prompt.find(_strip_tag)] + _retry_prompt[_strip_end + 1:]
                            _retry_prompt = _retry_prompt.strip()

                            vid_ok = _generate_video_kling(frame_url, _retry_prompt, total_dur, output_video, sid,
                                                           char_ref_urls=_kling_chain_refs if '_kling_chain_refs' in dir() else None,
                                                           negative_prompt=_kling_chain_neg if '_kling_chain_neg' in dir() else None)
                            if vid_ok:
                                _vid_retried = True
                                logger.info(f"[SMART-REGEN] {sid}: Retry succeeded with simplified prompt")
                        except Exception as _retry_err:
                            logger.warning(f"[SMART-REGEN] {sid}: Retry also failed: {_retry_err}")
                    # ═══════════════════════════════════════════════════════════════

                    if not vid_ok:
                        results.append({"shot_id": sid, "status": "error", "error": f"{video_model} video failed" + (" (retried)" if _vid_retried else ""),
                                       "frame_source": frame_source, "chained": False})
                        LIVE_GEN_TRACKER.update(sid, "error")
                        prev_video_path = None
                        chain_frame_for_next = None
                        prev_shot = shot
                        continue

                logger.info(f"[CHAIN] {sid}: 🎬 {video_model} video OK → {output_video}")
                _update_run(current_step=f"{sid}: video done, extracting end frame...")
                prev_video_path = output_video

                # V24.1: Store spatial state for this shot in ContinuityMemory
                if _continuity_memory:
                    try:
                        _spatial = _extract_spatial(shot, cast_map)
                        _continuity_memory.store_shot_state(sid, _spatial)
                        logger.info(f"[V24.1] {sid}: 🧠 spatial state stored ({len(_spatial.characters)} chars, cam={_spatial.camera.shot_scale})")
                    except Exception as _cm_store_err:
                        logger.warning(f"[V24.1] {sid}: spatial store non-blocking error: {_cm_store_err}")

                # ==============================================================
                # STEP 3 + 4 + 5: END-FRAME → NANO 3 ANGLES → BEST VARIANT
                # Only for chainable shots (not B-roll/inserts)
                # ==============================================================
                # V18.3: CONTINUITY TIGHTENER — variants from END FRAME, not first frame
                # Flow: first_frame → video → extract END FRAME → 3 angles from END FRAME
                #       → pick best angle → THAT becomes next shot's first frame
                # This locks the environment because reframe edits the actual video result,
                # not a fresh generation from text.
                # ==============================================================
                variant_paths = []
                selected_variant = None

                if not is_broll and enable_chain:
                  try:  # V18.3: Broad try/except — reframe crash must NOT kill the pipeline
                    LIVE_GEN_TRACKER.update(sid, "running", step="extracting_endframe", progress=0.55)
                    # Step 3: Extract last frame from video
                    last_frame_path = chain_frames_dir / f"{sid}_last_frame.jpg"
                    _last_frame_ok = _extract_last_frame(output_video, last_frame_path)

                    if _last_frame_ok and last_frame_path.exists():
                        logger.info(f"[CHAIN] {sid}: 📸 END FRAME extracted → generating 3 angle variants from it")
                    else:
                        logger.warning(f"[CHAIN] {sid}: end frame extraction failed — chain may break")

                    # V26.1: BLOCKING-AWARE shots extract end frame for next shot's spatial memory
                    # but do NOT generate reframe variants (they generated fresh, reframing is wrong).
                    # The end frame feeds the NEXT shot's continuity delta regardless of chain mode.
                    if do_blocking_aware and _last_frame_ok:
                        # Store raw end frame as chain source for potential REFRAME of next shot
                        chain_frame_for_next = str(last_frame_path)
                        logger.info(f"[V26.1-BA] {sid}: 🧠 blocking-aware shot — end frame stored for next shot's spatial memory (no reframe variants)")
                        # Store spatial state from the actual generated frame
                        if _continuity_memory:
                            try:
                                _spatial = _extract_spatial(shot, cast_map)
                                _continuity_memory.store_shot_state(sid, _spatial)
                            except Exception:
                                pass

                    # Step 4: NANO-PRO-EDIT 3 ANGLES FROM END FRAME (not first frame!)
                    # Only for REFRAME chain mode — same character, different angle
                    # The end frame captures actual blocking/movement from the video.
                    # Reframing it gives us the next shot's first frame with correct continuity.
                    elif _last_frame_ok and last_frame_path.exists():
                        # V19: Resolve character refs for NEXT shot (reframe produces next shot's frame)
                        _variant_ref_urls = []
                        _next_idx = i + 1
                        _next_shot_for_refs = scene_shots[_next_idx] if _next_idx < len(scene_shots) else shot
                        _shot_chars = _next_shot_for_refs.get("characters", [])
                        if isinstance(_shot_chars, str):
                            _shot_chars = [c.strip() for c in _shot_chars.split(",") if c.strip()]
                        if not _shot_chars:  # Fallback to current shot's characters
                            _shot_chars = shot.get("characters", [])
                            if isinstance(_shot_chars, str):
                                _shot_chars = [c.strip() for c in _shot_chars.split(",") if c.strip()]
                        for _vchar in _shot_chars:
                            for _vcname, _vcdata in cast_map.items():
                                if _vchar.upper() in _vcname.upper() or _vcname.upper() in _vchar.upper():
                                    # V21.10: character_reference_url FIRST — never AI actor headshots
                                    _vhr = _vcdata.get("character_reference_url") or _vcdata.get("reference_url") or _vcdata.get("headshot_url", "")
                                    if _vhr:
                                        if _vhr.startswith("/api/media?path="):
                                            _vhr = _vhr.split("path=", 1)[1]
                                        if not Path(_vhr).exists():
                                            _vfname = Path(_vhr).name
                                            for _vsd in [project_path / "character_library_locked",
                                                         BASE_DIR / "character_library_locked" / "ai_actors",
                                                         BASE_DIR / "ai_actor_headshots"]:
                                                _vc = _vsd / _vfname
                                                if _vc.exists():
                                                    _vhr = str(_vc)
                                                    break
                                        if Path(_vhr).exists():
                                            _variant_ref_urls.append(_vhr)
                                    break

                        # V27.1.5: REFRAME SYSTEM DISABLED — user-requested kill switch
                        # Reframing was generating 3 angle variants per chained shot using custom prompts
                        # that IGNORED shot_plan.json baked prompts. This caused regression by overriding
                        # carefully crafted DNA + timed action prompts with generic "REFRAME ONLY" text.
                        # To re-enable: set _V27_REFRAME_DISABLED = False
                        _V27_REFRAME_DISABLED = True
                        if _V27_REFRAME_DISABLED:
                            logger.info(f"[CHAIN] {sid}: ⏭️ REFRAME DISABLED (V27.1.5) — using first frame directly, no angle variants")
                            _do_reframe = False
                        else:
                            # ORIGINAL: V18.3: REFRAME END FRAME — nano-pro-edit uses last_frame as input image
                            # The end frame IS the environment truth. We only change camera angle.
                            _update_run(current_step=f"{sid}: reframing END FRAME → 3 angles (parallel)...")

                        # Convert end frame to base64 for FAL input
                        _end_frame_b64 = _upload_frame_for_api(last_frame_path)
                        _do_reframe = bool(_end_frame_b64)
                        if not _do_reframe:
                            logger.warning(f"[CHAIN] {sid}: end frame base64 failed — skipping reframe, using raw end frame")

                        from concurrent.futures import ThreadPoolExecutor, as_completed

                        def _reframe_end_frame(angle_data, end_frame_b64_url, char_refs, out_path):
                            """Reframe the END FRAME to a different camera angle via nano-pro-edit.
                            Environment stays locked — only camera changes."""
                            try:
                                # V21: Use CANONICAL character descriptions for reframe prompts
                                # NEVER use _build_face_lock_text() — it injects AI actor descriptions
                                # (e.g., Isabella Moretti's "dark hair with silver streaks" for Lady Margaret)
                                # The canonical registry has the SCRIPT-ACCURATE appearance.
                                # V26.1: Use PROJECT-AWARE canonical characters (not hardcoded Ravencroft defaults)
                                _reframe_face_text = ""
                                try:
                                    from tools.prompt_authority_gate import load_project_authority_config, _get_canonical_characters
                                    load_project_authority_config(_chain_project_path if '_chain_project_path' in dir() else project_path)
                                    _project_canon = _get_canonical_characters()
                                    for _rfc in _shot_chars:
                                        _canon = _project_canon.get(_rfc.upper().strip())
                                        if _canon:
                                            _reframe_face_text += f" {_rfc}: {_canon['appearance']}."
                                        else:
                                            # Fallback for non-canonical characters: brief name only
                                            _reframe_face_text += f" Keep {_rfc} in frame."
                                except (ImportError, Exception):
                                    # Fallback: just reference characters by name (safe, no AI actor contamination)
                                    for _rfc in _shot_chars:
                                        _reframe_face_text += f" Keep {_rfc} in frame with same pose and expression."

                                # Build reframe-only prompt: NO environment, NO room description
                                # Just camera angle + canonical character appearance + appearance lock
                                # V21 FIX: Added NO morphing / face stable / identity locked to prevent face drift
                                _reframe_prompt = (
                                    "REFRAME ONLY. Use the provided image as the single source of truth. "
                                    "Do NOT change environment, room, props, objects, lighting, shadows, or color grade. "
                                    "Do NOT add or remove anything. Do NOT relocate characters. "
                                    f"Preserve exact face identity, hairstyle, wardrobe, skin tone.{_reframe_face_text} "
                                    "NO morphing faces, NO grid, NO collage, face stable, identity locked. "
                                    f"{angle_data['prefix']} "
                                    "Maintain identical scene composition except camera distance and framing."
                                )
                                if len(_reframe_prompt) > 900:
                                    _reframe_prompt = _reframe_prompt[:897] + "..."

                                logger.info(f"[CHAIN-REFRAME] {out_path.name}: reframing end frame → {angle_data['name']}")

                                # V21 FIX: REFRAME uses ONLY the end frame as input image.
                                # DO NOT add character reference headshots — they bleed into the output
                                # and overtake the reframe (close_detail becomes a headshot portrait).
                                # The character is already IN the end frame — that IS the identity source.
                                _reframe_refs = [end_frame_b64_url]
                                # char_refs intentionally NOT added — Rule 135: reframe = source frame ONLY

                                fal_result = _fal_run_with_retry(NANO_MODEL_REF, {
                                    "prompt": _reframe_prompt,
                                    "image_urls": _reframe_refs,
                                    "aspect_ratio": "16:9",
                                    "output_format": "jpeg",
                                    "num_outputs": 1
                                })

                                _yield_gil()

                                img_url = None
                                if fal_result.get("images") and len(fal_result["images"]) > 0:
                                    img_url = fal_result["images"][0].get("url")
                                elif fal_result.get("image"):
                                    img_url = fal_result["image"]["url"] if isinstance(fal_result["image"], dict) else fal_result["image"]

                                if img_url:
                                    import urllib.request
                                    urllib.request.urlretrieve(img_url, str(out_path))
                                    if out_path.exists():
                                        logger.info(f"[CHAIN-REFRAME] ✅ {out_path.name} saved (reframed from end frame)")
                                        return True
                                logger.error(f"[CHAIN-REFRAME] No image in reframe response")
                            except Exception as re_err:
                                logger.error(f"[CHAIN-REFRAME] Reframe failed: {re_err}")
                            return False

                        if _do_reframe:
                            LIVE_GEN_TRACKER.update(sid, "running", step="reframing_3_angles", progress=0.6)
                            _angle_futures = {}
                            with ThreadPoolExecutor(max_workers=3) as _angle_pool:
                                for angle in NANO_ANGLES:
                                    variant_out = variants_dir / f"{sid}_{angle['name']}.jpg"
                                    future = _angle_pool.submit(
                                        _reframe_end_frame, angle, _end_frame_b64, _variant_ref_urls, variant_out
                                    )
                                    _angle_futures[future] = angle
                                for future in as_completed(_angle_futures):
                                    angle = _angle_futures[future]
                                    variant_out = variants_dir / f"{sid}_{angle['name']}.jpg"
                                    try:
                                        ok = future.result(timeout=60)
                                    except Exception as _fut_err:
                                        ok = False
                                        logger.warning(f"[CHAIN] {sid}: reframe '{angle['name']}' future error: {_fut_err}")
                                    if ok:
                                        try:
                                            _rel_var_path = str(variant_out.relative_to(BASE_DIR))
                                        except ValueError:
                                            _rel_var_path = str(variant_out)
                                        variant_paths.append({
                                            "name": angle["name"],
                                            "path": _rel_var_path,
                                            "prefix": angle["prefix"]
                                        })
                                        logger.info(f"[CHAIN] {sid}: 🎬 end-frame reframe '{angle['name']}' OK")
                                    else:
                                        logger.warning(f"[CHAIN] {sid}: reframe '{angle['name']}' failed")
                            _yield_gil()
                        else:
                            logger.info(f"[CHAIN] {sid}: skipped reframe (no base64) — raw end frame for chain")

                    # V25.1: Push variant data to live tracker so UI can show them during render
                    if variant_paths:
                        try:
                            _var_urls = [
                                {"name": v["name"], "url": f"/api/media?path={v['path']}"}
                                for v in variant_paths
                            ]
                            LIVE_GEN_TRACKER.update(sid, "running", variants=_var_urls,
                                                    step="selecting_variant", progress=0.7)
                        except Exception:
                            pass

                    # Step 5: Select best variant with VISION + CINEMATIC FLOW
                    # V21.6: Score variants with DINO (identity) when available, use cinematic flow as tiebreaker
                    if variant_paths and _last_frame_ok:
                        # V21.6: DINO scoring for chain variants — pick highest identity match
                        _chain_dino_scores = {}
                        try:
                            if FEATURE_FLAGS.get("FEATURE_VISION_SERVICE", True):
                                from dino_clip_analyzer import get_hybrid_analyzer
                                _chain_analyzer = get_hybrid_analyzer()
                                # Get character ref for DINO comparison
                                _chain_char_ref = None
                                if _shot_chars:
                                    _cm = cast_map or {}
                                    for _cc in _shot_chars:
                                        for _ce in _cm.values():
                                            if isinstance(_ce, dict) and _ce.get("character","").upper() == _cc.upper():
                                                # V21.10: character_reference_url FIRST
                                                _chain_char_ref = _ce.get("character_reference_url") or _ce.get("reference_url") or _ce.get("headshot_url")
                                                if _chain_char_ref and "/api/media" in _chain_char_ref:
                                                    _chain_char_ref = _chain_char_ref.split("path=",1)[1] if "path=" in _chain_char_ref else _chain_char_ref
                                                break
                                    if _chain_char_ref and Path(_chain_char_ref).exists():
                                        for _vp in variant_paths:
                                            _vfull = str(BASE_DIR / _vp["path"]) if not Path(_vp["path"]).is_absolute() else _vp["path"]
                                            try:
                                                _dscores = _chain_analyzer.analyze_comprehensive(_vfull, _chain_char_ref, "")
                                                _chain_dino_scores[_vp["name"]] = _dscores.get("dino_face", 0.0)
                                            except Exception:
                                                _chain_dino_scores[_vp["name"]] = 0.0
                                        logger.info(f"[CHAIN-DINO] {sid}: variant scores = {_chain_dino_scores}")
                                        # V25.4 BUG 05: Write DINO scores to doctrine ledger
                                        try:
                                            _dino_ledger = project_path / "reports" / "doctrine_ledger.jsonl"
                                            _dino_ledger.parent.mkdir(exist_ok=True, parents=True)
                                            import json as _dj
                                            _dino_entry = {
                                                "timestamp": datetime.now().isoformat(),
                                                "event_type": "dino_identity_scores",
                                                "severity": "INFO",
                                                "shot_id": sid,
                                                "detail": f"DINO variant scores: {_chain_dino_scores}",
                                                "scores": {k: round(v, 4) for k, v in _chain_dino_scores.items()},
                                                "best_score": round(max(_chain_dino_scores.values()), 4) if _chain_dino_scores else 0.0,
                                                "source": "chain_pipeline_dino",
                                                "pipeline_stage": "variant_selection"
                                            }
                                            with open(_dino_ledger, "a") as _dlf:
                                                _dlf.write(_dj.dumps(_dino_entry) + "\n")
                                        except Exception:
                                            pass  # Ledger write is non-blocking
                        except Exception as _dino_err:
                            logger.debug(f"[CHAIN-DINO] {sid}: scoring unavailable ({_dino_err}) — using cinematic flow only")
                            # V25.4 BUG 05: Log DINO unavailability to doctrine ledger
                            try:
                                _dino_ledger = project_path / "reports" / "doctrine_ledger.jsonl"
                                _dino_ledger.parent.mkdir(exist_ok=True, parents=True)
                                import json as _dj2
                                _dino_miss_entry = {
                                    "timestamp": datetime.now().isoformat(),
                                    "event_type": "dino_score_missing",
                                    "severity": "WARNING",
                                    "shot_id": sid,
                                    "detail": f"DINO scoring unavailable: {_dino_err}",
                                    "fallback_taken": "cinematic_flow_only",
                                    "source": "chain_pipeline_dino",
                                    "pipeline_stage": "variant_selection"
                                }
                                with open(_dino_ledger, "a") as _dlf2:
                                    _dlf2.write(_dj2.dumps(_dino_miss_entry) + "\n")
                            except Exception:
                                pass  # Ledger write is non-blocking

                        # Cinematic flow priority (round-robin for variety)
                        _ANGLE_FLOW_PRIORITY = {
                            "wide_master": ["medium_tight", "close_detail", "wide_master"],
                            "medium_tight": ["close_detail", "wide_master", "medium_tight"],
                            "close_detail": ["wide_master", "medium_tight", "close_detail"],
                        }
                        _prev_angle = _chain_prev_angle if '_chain_prev_angle' in dir() else None
                        selected_variant = None

                        if _chain_dino_scores:
                            # V21.6: VISION-GUIDED selection — highest DINO score wins,
                            # but penalize repeating the same angle (flow tiebreaker)
                            _scored = []
                            for _vp in variant_paths:
                                _dscore = _chain_dino_scores.get(_vp["name"], 0.0)
                                _flow_bonus = 0.0
                                if _prev_angle and _prev_angle in _ANGLE_FLOW_PRIORITY:
                                    _prefs = _ANGLE_FLOW_PRIORITY[_prev_angle]
                                    if _vp["name"] in _prefs:
                                        _flow_bonus = (len(_prefs) - _prefs.index(_vp["name"])) * 0.05
                                _scored.append((_vp, _dscore + _flow_bonus))
                            _scored.sort(key=lambda x: x[1], reverse=True)
                            selected_variant = _scored[0][0]
                            logger.info(f"[CHAIN] {sid}: VISION+FLOW selected '{selected_variant['name']}' (DINO={_chain_dino_scores.get(selected_variant['name'],0):.2f}, prev={_prev_angle})")
                        elif _prev_angle and _prev_angle in _ANGLE_FLOW_PRIORITY:
                            # Fallback: cinematic flow only (no DINO available)
                            for _preferred in _ANGLE_FLOW_PRIORITY[_prev_angle]:
                                _match = next((v for v in variant_paths if v["name"] == _preferred), None)
                                if _match:
                                    selected_variant = _match
                                    break

                        if not selected_variant:
                            selected_variant = variant_paths[0]  # Fallback: first available

                        _chain_prev_angle = selected_variant["name"]  # Track for next iteration
                        chain_frame_for_next = selected_variant["path"]
                        logger.info(f"[CHAIN] {sid}: ✅ selected '{selected_variant['name']}' (prev: {_prev_angle}) → feeds next shot")
                        # V25.1: Push selected variant to live tracker for real-time UI update
                        try:
                            _sel_url = f"/api/media?path={selected_variant['path']}"
                            LIVE_GEN_TRACKER.update(sid, "completed", url=_sel_url,
                                                    selected_variant=selected_variant["name"],
                                                    step="variant_selected", progress=0.85)
                        except Exception:
                            pass
                    elif _last_frame_ok:
                        # No reframe variants but end frame exists — use raw end frame for chain
                        chain_frame_for_next = str(last_frame_path)
                        logger.warning(f"[CHAIN] {sid}: no reframe variants — using raw end frame for chain")
                    else:
                        chain_frame_for_next = None
                        logger.warning(f"[CHAIN] {sid}: no end frame, no variants — chain breaks")
                  except Exception as _reframe_crash:
                    # V18.3: If reframe crashes, use raw end frame and continue
                    logger.error(f"[CHAIN] {sid}: ⚠️ reframe section crashed: {_reframe_crash} — continuing with fallback")
                    try:
                        _lfp = chain_frames_dir / f"{sid}_last_frame.jpg"
                        if _lfp.exists():
                            chain_frame_for_next = str(_lfp)
                        else:
                            chain_frame_for_next = None
                    except Exception:
                        chain_frame_for_next = None
                    variant_paths = variant_paths if 'variant_paths' in dir() else []
                    selected_variant = selected_variant if 'selected_variant' in dir() else None
                else:
                    # B-roll/insert: no chaining, no angle variants
                    chain_frame_for_next = None
                    logger.info(f"[CHAIN] {sid}: 📦 independent (B-roll/insert) — no chain")

                    # V24.1: B-roll continuity — match scene texture/color/atmosphere
                    if _continuity_memory and is_broll:
                        try:
                            _broll_state = _extract_broll_cont(scene_shots, scene_manifest.get(scene_id, {}))
                            _broll_prompt = _compile_broll_prompt(_broll_state, shot)
                            if _broll_prompt:
                                shot["_v24_broll_continuity"] = _broll_prompt
                                logger.info(f"[V24.1] {sid}: 🎬 B-roll continuity injected ({len(_broll_prompt)} chars)")
                        except Exception as _broll_err:
                            logger.warning(f"[V24.1] {sid}: B-roll continuity non-blocking error: {_broll_err}")

                # Save variant metadata to shot for UI — use _variants key (same as multi-angle endpoint)
                # so the bundle builder + UI multi-angle panel can see them
                shot["_variants"] = [
                    {"angle_name": v["name"], "path": v["path"], "url": f"/api/media?path={v['path']}"}
                    for v in variant_paths
                ]
                shot["_chain_variants"] = variant_paths  # Keep chain-specific format too
                shot["_chain_selected"] = selected_variant["name"] if selected_variant else None
                shot["_chain_source"] = frame_source
                # V18.2: Use relative path for frame reference
                try:
                    shot["_chain_first_frame_url"] = str(Path(frame_path).relative_to(BASE_DIR))
                except (ValueError, TypeError):
                    shot["_chain_first_frame_url"] = str(frame_path)
                if selected_variant:
                    shot["_chain_next_frame"] = selected_variant["path"]

                # V18.2: PERSIST all metadata to shot_plan.json — variants, frame path, video path
                # Uses file locking (fcntl) to prevent race condition when multiple chains run
                try:
                    import fcntl
                    with open(shot_plan_path, 'r+') as _sp_f:
                        fcntl.flock(_sp_f.fileno(), fcntl.LOCK_EX)  # Exclusive lock
                        _sp_data = json.load(_sp_f)
                        for _sp_shot in _sp_data.get("shots", []):
                            if _sp_shot.get("shot_id") == sid:
                                _sp_shot["_variants"] = shot["_variants"]
                                _sp_shot["_chain_selected"] = shot.get("_chain_selected")
                                _sp_shot["_chain_source"] = frame_source
                                # V18.2: Save frame and video paths as relative
                                if frame_path:
                                    try:
                                        _rel_frame = str(Path(frame_path).relative_to(BASE_DIR))
                                    except (ValueError, TypeError):
                                        _rel_frame = str(frame_path)
                                    _sp_shot["first_frame_path"] = _rel_frame
                                    _sp_shot["first_frame_url"] = f"/api/media?path={_rel_frame}"
                                if output_video and output_video.exists():
                                    try:
                                        _rel_vid = str(output_video.relative_to(BASE_DIR))
                                    except (ValueError, TypeError):
                                        _rel_vid = str(output_video)
                                    _sp_shot["video_path"] = _rel_vid
                                    # V22.2: Set model-specific URL so UI can find both LTX and Kling videos
                                    if video_model == "kling":
                                        _sp_shot["video_url_kling"] = f"/api/media?path={_rel_vid}"
                                    else:
                                        _sp_shot["video_url"] = f"/api/media?path={_rel_vid}"
                                # V24.2.3: Persist smart regen QA scores
                                if shot.get("_smart_regen_scores"):
                                    _sp_shot["_smart_regen_scores"] = shot["_smart_regen_scores"]
                                if shot.get("_smart_regen_scores_after"):
                                    _sp_shot["_smart_regen_scores_after"] = shot["_smart_regen_scores_after"]
                                if shot.get("_smart_regen_attempt"):
                                    _sp_shot["_smart_regen_attempt"] = shot["_smart_regen_attempt"]
                                    _sp_shot["_smart_regen_actions"] = shot.get("_smart_regen_actions", [])
                                break
                        _sp_f.seek(0)
                        _sp_f.truncate()
                        json.dump(_sp_data, _sp_f, indent=2, default=str)
                        fcntl.flock(_sp_f.fileno(), fcntl.LOCK_UN)
                    logger.info(f"[CHAIN] {sid}: 📝 Metadata persisted to shot_plan.json ({len(variant_paths)} angles)")
                except Exception as _sp_err:
                    logger.warning(f"[CHAIN] {sid}: persist non-blocking error: {_sp_err}")

                _yield_gil()  # After file I/O persist

                # V18.2: Per-shot cache invalidation — UI refreshes after EACH shot, not end-of-run
                try:
                    _invalidate_bundle_cache(project)
                except Exception:
                    pass

                # V18.2: Update live tracker for this shot
                try:
                    LIVE_GEN_TRACKER.update(sid, "completed", url=f"/api/media?path={str(Path(frame_path).relative_to(BASE_DIR))}" if frame_path else None)
                except Exception:
                    pass

                # V18.2: Convert paths to relative for UI /api/media?path= serving
                try:
                    _rel_nano = str(Path(frame_path).relative_to(BASE_DIR)) if frame_path else ""
                except (ValueError, TypeError):
                    _rel_nano = str(frame_path) if frame_path else ""
                try:
                    _rel_video = str(Path(output_video).relative_to(BASE_DIR)) if output_video else ""
                except (ValueError, TypeError):
                    _rel_video = str(output_video) if output_video else ""
                results.append({
                    "shot_id": sid, "status": "success", "path": _rel_video,
                    "frame_source": frame_source, "chained": do_chain,
                    "video_model": video_model,
                    "duration": total_dur, "audio": generate_audio,
                    "nano_frame": _rel_nano,
                    "variants": [{"name": v["name"], "path": v["path"]} for v in variant_paths],
                    "selected_variant": selected_variant["name"] if selected_variant else None,
                    "unselected_variants": [
                        {"name": v["name"], "path": v["path"]}
                        for v in variant_paths if v != selected_variant
                    ]
                })
                logger.info(f"[CHAIN] {sid}: ✅ COMPLETE ({frame_source}, {video_model}, {len(variant_paths)} variants)")
                LIVE_GEN_TRACKER.update(sid, "completed")
                _update_run(completed_shots=i+1, results=results, current_step=f"{sid}: done ✅")

                # V18.2: LIVE HYDRATION — invalidate bundle so desktop filmstrip refreshes
                try:
                    _invalidate_bundle_cache(project)
                except Exception:
                    pass

                # V18.2: CHECKPOINT — save progress every 3 shots for resume on crash
                if (i + 1) % 3 == 0 or (i + 1) == len(scene_shots):
                    try:
                        _ckpt = {
                            "run_id": run_id, "project": project, "scene_id": scene_id,
                            "completed_idx": i, "total_shots": len(scene_shots),
                            "results": results, "video_model": video_model,
                            "timestamp": datetime.now().isoformat(),
                        }
                        _ckpt_path = project_path / f"chain_checkpoint_{scene_id}.json"
                        with open(_ckpt_path, "w") as _cf:
                            json.dump(_ckpt, _cf, indent=2, default=str)
                        logger.info(f"[CHAIN] 💾 Checkpoint saved: {i+1}/{len(scene_shots)} shots")
                    except Exception:
                        pass

            except Exception as e:
                results.append({"shot_id": sid, "status": "error", "error": str(e)[:200],
                               "frame_source": frame_source if frame_path else "none", "chained": False})
                logger.error(f"[CHAIN] {sid}: ❌ {e}")
                LIVE_GEN_TRACKER.update(sid, "error")
                prev_video_path = None
                chain_frame_for_next = None

            # V18.3: MEMORY CLEANUP — prevent OOM by releasing large objects after each shot
            # Base64 strings are ~5.3MB each, FAL responses hold metadata, variant dicts accumulate
            try:
                # Clear base64 strings (biggest memory hog)
                _end_frame_b64 = None
                _reframe_refs = None
                fal_result = None
                variant_paths = []
                selected_variant = None
                # Force garbage collection every 3 shots to reclaim memory
                if (i + 1) % 3 == 0:
                    _collected = gc.collect()
                    logger.info(f"[CHAIN] 🧹 Memory cleanup after shot {i+1}: gc collected {_collected} objects")
            except Exception:
                pass

            prev_shot = shot

        # V18.2: Shutdown parallel executor
        try:
            _video_executor.shutdown(wait=False)
        except Exception:
            pass

        # Persist variant metadata back to shot_plan for UI access
        try:
            with open(shot_plan_path, "w") as f:
                json.dump(data, f, indent=2)
            logger.info(f"[CHAIN] Shot plan updated with chain variant metadata")
        except Exception as sp_err:
            logger.warning(f"[CHAIN] Could not persist variant metadata: {sp_err}")

        # Invalidate UI bundle cache so next load shows fresh data
        try:
            _invalidate_bundle_cache(project)
            logger.info(f"[CHAIN] Bundle cache invalidated for {project}")
        except Exception:
            pass

        elapsed = round(_time.time() - start, 1)
        success_count = sum(1 for r in results if r["status"] == "success")
        chained_count = sum(1 for r in results if r.get("chained"))

        # Auto-stitch scene videos
        stitch_path = None
        vid_search_dir = kling_dir if video_model == "kling" else (project_path / "videos")
        if success_count > 0:
            try:
                # Find all shot videos (exclude segment files)
                scene_vids = sorted([
                    v for v in vid_search_dir.glob(f"{scene_id}_*.mp4")
                    if "_seg" not in v.stem and "_concat" not in v.stem
                ])
                if scene_vids:
                    stitch_dir = project_path / "stitched_scenes"
                    stitch_dir.mkdir(exist_ok=True)
                    stitch_path = stitch_dir / f"scene_{scene_id}_{video_model}.mp4"
                    concat_file = vid_search_dir / "concat_list.txt"
                    with open(concat_file, "w") as f:
                        for v in scene_vids:
                            f.write(f"file '{v}'\n")
                    subprocess.run(
                        f"ffmpeg -y -f concat -safe 0 -i '{concat_file}' -c copy '{stitch_path}'",
                        shell=True, capture_output=True, timeout=120
                    )
                    logger.info(f"[CHAIN] Stitched {len(scene_vids)} → {stitch_path}")
            except Exception as e:
                logger.error(f"[CHAIN] Stitch error: {e}")

        LIVE_GEN_TRACKER.update(f"CHAIN_{scene_id}", "completed")

        # Clean up stop flag if set
        _CHAIN_STOP_FLAGS.pop(run_id, None)

        # Count variants generated
        total_variants = sum(len(r.get("variants", [])) for r in results if r.get("status") == "success")

        # =========================================================================
        # V18.1: AUTO-SYNC TO R2 — permanent public URLs for mobile access
        # Non-blocking — if R2 fails, tunnel URLs still work
        # =========================================================================
        r2_sync_result = None
        r2_urls = {}
        if R2_ENABLED and success_count > 0:
            try:
                logger.info(f"[CHAIN] ☁️ Auto-syncing scene {scene_id} assets to R2 for mobile...")
                LIVE_GEN_TRACKER.add(project, f"R2_SYNC_{scene_id}", "running", "r2_sync",
                                     prompt=f"Syncing S{scene_id} to Cloudflare R2...")

                # Sync scene-specific assets (frames, variants, videos)
                sync_count = 0
                sync_failed = 0

                # Sync nano-banana frames for this scene
                for img in sorted(first_frames_dir.glob(f"{scene_id}_*.jpg")):
                    r2_key = f"{project}/first_frames/{img.name}"
                    url = r2_upload_file(img, r2_key)
                    if url:
                        r2_urls[f"ff_{img.stem}"] = url
                        sync_count += 1
                    else:
                        sync_failed += 1

                # Sync angle variants for this scene
                for img in sorted(variants_dir.glob(f"{scene_id}_*.jpg")):
                    r2_key = f"{project}/variants/{img.name}"
                    url = r2_upload_file(img, r2_key)
                    if url:
                        r2_urls[f"var_{img.stem}"] = url
                        sync_count += 1
                    else:
                        sync_failed += 1

                # Sync videos for this scene (skip segment files)
                for vid in sorted(vid_search_dir.glob(f"{scene_id}_*.mp4")):
                    if "_seg" in vid.stem or "_concat" in vid.stem:
                        continue
                    r2_key = f"{project}/{'videos_kling' if video_model == 'kling' else 'videos'}/{vid.name}"
                    url = r2_upload_file(vid, r2_key)
                    if url:
                        r2_urls[f"vid_{vid.stem}"] = url
                        sync_count += 1
                    else:
                        sync_failed += 1

                # Sync stitched scene video
                if stitch_path and stitch_path.exists():
                    r2_key = f"{project}/stitched/{stitch_path.name}"
                    url = r2_upload_file(stitch_path, r2_key)
                    if url:
                        r2_urls["stitch"] = url
                        sync_count += 1

                r2_sync_result = {"uploaded": sync_count, "failed": sync_failed}
                logger.info(f"[CHAIN] ☁️ R2 sync: {sync_count} uploaded, {sync_failed} failed")
                LIVE_GEN_TRACKER.update(f"R2_SYNC_{scene_id}", "completed")

                # Inject R2 URLs into shot results for mobile UI
                for r in results:
                    sid = r.get("shot_id", "")
                    if r2_urls.get(f"ff_{sid}"):
                        r["r2_frame_url"] = r2_urls[f"ff_{sid}"]
                    if r2_urls.get(f"vid_{sid}"):
                        r["r2_video_url"] = r2_urls[f"vid_{sid}"]
                    # Add R2 URLs for variants
                    r2_variants = []
                    for v in r.get("variants", []):
                        vkey = f"var_{sid}_{v['name']}"
                        if r2_urls.get(vkey):
                            v["r2_url"] = r2_urls[vkey]
                            r2_variants.append(v)

            except Exception as r2_err:
                logger.warning(f"[CHAIN] ☁️ R2 auto-sync failed (non-blocking): {r2_err}")
                r2_sync_result = {"uploaded": 0, "failed": 0, "error": str(r2_err)}

            # V18.2: Build failed shots report for one-click rerun
            _failed_shots = [
                {"shot_id": r["shot_id"], "error": r.get("error", "unknown"), "frame_source": r.get("frame_source", "none")}
                for r in results if r["status"] in ("error", "skipped")
            ]

            _update_run(
                status="completed",
                success=True,
                video_model=video_model,
                chain_enabled=enable_chain,
                audio_enabled=generate_audio,
                results=results,
                summary={
                    "total": len(results),
                    "success": success_count,
                    "chained": chained_count,
                    "independent": success_count - chained_count,
                    "skipped": sum(1 for r in results if r["status"] == "skipped"),
                    "errors": sum(1 for r in results if r["status"] == "error"),
                    "variants_generated": total_variants,
                },
                failed_shots=_failed_shots,  # V18.2: For one-click rerun UI
                stitch_path=str(stitch_path) if stitch_path else None,
                r2_sync=r2_sync_result,
                r2_urls=r2_urls if r2_urls else None,
                r2_stitch_url=r2_urls.get("stitch") if r2_urls else None,
                cost_estimate_usd=round(
                    success_count * (0.10 if video_model == "kling" else 0.05) +
                    total_variants * 0.02, 2
                ),
                completed_shots=len(scene_shots),
                elapsed_seconds=elapsed,
            )
            # V24.2.3: Log smart regen budget summary
            if _regen_budget:
                _rb_summary = _regen_budget.summary()
                logger.info(f"[SMART-REGEN] 📊 Budget summary: {_rb_summary['shots_retried']} shots retried, "
                           f"{_rb_summary['total_retries']} total attempts, budget {'EXHAUSTED' if _rb_summary['budget_exhausted'] else 'OK'}")
                run["smart_regen_summary"] = _rb_summary

            logger.info(f"[CHAIN] ✅ Pipeline COMPLETE for scene {scene_id} — {success_count}/{len(results)} shots, {elapsed}s")

            # V21.5: Complete Temporal workflow tracking for chain pipeline
            try:
                if _chain_wf_id:
                    _chain_summary = {"success": success_count, "total": len(results), "chained": chained_count, "elapsed": elapsed}
                    temporal_complete_activity(_chain_wf_id, f"chain_render_{scene_id}", result=_chain_summary)
                    temporal_complete_workflow(_chain_wf_id, result=_chain_summary)
                    _temporal_persist()
            except Exception:
                pass  # Temporal tracking is non-blocking

    # End of _run_chain_pipeline()

    def _safe_chain_pipeline():
        """Wrapper that catches ALL exceptions so thread never crashes silently."""
        try:
            _run_chain_pipeline()
        except Exception as _global_err:
            import traceback
            tb = traceback.format_exc()
            logger.error(f"[CHAIN] 💥 PIPELINE CRASHED: {_global_err}\n{tb}")
            # V21.5: Track chain crash in Temporal + Sentry
            try:
                if _chain_wf_id:
                    temporal_fail_activity(_chain_wf_id, f"chain_render_{scene_id}", str(_global_err)[:300], should_retry=False)
                    _temporal_persist()
                _sentry_capture_exception(_global_err)
            except Exception:
                pass
            import time as _t2
            with _CHAIN_RUNS_LOCK:
                run = _CHAIN_RUNS.get(run_id, {})
                run["status"] = "error"
                run["error"] = f"Pipeline crashed: {str(_global_err)[:300]}"
                run["traceback"] = tb[-500:] if tb else ""
                run["elapsed"] = round(_t2.time() - (run.get("_start_ts", _t2.time())), 1)
                _CHAIN_RUNS[run_id] = run

    # Launch pipeline in background thread
    import threading
    t = threading.Thread(target=_safe_chain_pipeline, daemon=True, name=f"chain_{scene_id}")
    t.start()
    logger.info(f"[CHAIN] 🚀 Background pipeline started: {run_id} ({len(scene_shots)} shots)")

    # Return immediately with run_id for polling
    return {
        "success": True,
        "async": True,
        "run_id": run_id,
        "project": project,
        "scene_id": scene_id,
        "video_model": video_model,
        "total_shots": len(scene_shots),
        "poll_url": f"/api/v18/chain/status/{run_id}",
        "message": f"Pipeline started for scene {scene_id} ({len(scene_shots)} shots, model={video_model}). Poll status at /api/v18/chain/status/{run_id}"
    }


@app.post("/api/v17/shot/hybrid-motion")
async def hybrid_ltx_to_kling(request: Dict = Body(...)):
    """
    V17 DIRECTOR TOOL: Hybrid Motion Pipeline (LTX → Kling).

    1. Generates LTX video from first frame (or uses existing)
    2. Extracts last frame from LTX video
    3. Feeds that frame into Kling for enhanced motion continuation

    This creates a seamless bridge: stable LTX continuity → expressive Kling motion.

    Body:
    {
        "project": "ravencroft_v17",
        "shot_id": "E011_S01_000A",
        "ltx_prompt": "Character speaking, subtle movement",
        "kling_prompt": "Dramatic gesture, emotional peak",
        "ltx_duration": 6,
        "kling_duration": 5,
        "use_existing_ltx": false  // If true, skip LTX gen and use existing video
    }
    """
    project = request.get("project")
    shot_id = request.get("shot_id")
    ltx_prompt = request.get("ltx_prompt", "Subtle movement, cinematic quality")
    kling_prompt = request.get("kling_prompt", "Expressive continuation, natural motion")
    ltx_duration = request.get("ltx_duration", 6)
    kling_duration = request.get("kling_duration", 5)
    use_existing_ltx = request.get("use_existing_ltx", False)

    if not project or not shot_id:
        return {"success": False, "error": "project and shot_id required"}

    project_path = get_project_path(project)
    tools_dir = ensure_director_tools_dir(project, shot_id)

    # Step 1: Get or generate LTX video
    ltx_video_path = None

    if use_existing_ltx:
        # Check for existing video
        videos_dir = project_path / "videos"
        for ext in [".mp4", ".webm"]:
            candidate = videos_dir / f"{shot_id}{ext}"
            if candidate.exists():
                ltx_video_path = candidate
                break

        # Also check director tools
        if not ltx_video_path:
            for v in (tools_dir / "videos").glob("ltx_*.mp4"):
                ltx_video_path = v
                break

    if not ltx_video_path or not use_existing_ltx:
        # Generate LTX video first
        logger.info(f"[HYBRID] Generating LTX video for {shot_id}...")

        # Find first frame
        overrides = get_director_overrides(project)
        shot_overrides = overrides.get("shots", {}).get(shot_id, {})

        first_frame = None
        if shot_overrides.get("selected_first_frame"):
            first_frame = project_path / shot_overrides["selected_first_frame"]
        else:
            first_frames_dir = project_path / "first_frames"
            for ext in [".jpg", ".png", ".jpeg"]:
                candidate = first_frames_dir / f"{shot_id}{ext}"
                if candidate.exists():
                    first_frame = candidate
                    break

        if not first_frame or not first_frame.exists():
            return {"success": False, "error": f"No first frame found for {shot_id}"}

        try:
            import fal_client

            # Upload first frame
            image_url = fal_client.upload(first_frame, "image/png")

            # Generate LTX video
            result = fal_client.run(
                "fal-ai/ltx-video/image-to-video",
                arguments={
                    "prompt": ltx_prompt,
                    "image_url": image_url,
                    "num_frames": ltx_duration * 24,  # 24fps
                    "fps": 24,
                    "aspect_ratio": "16:9"
                }
            )

            if result and result.get("video"):
                import urllib.request
                video_url = result["video"]["url"] if isinstance(result["video"], dict) else result["video"]
                ltx_video_path = tools_dir / "videos" / f"hybrid_ltx_step1.mp4"
                urllib.request.urlretrieve(video_url, ltx_video_path)
                logger.info(f"[HYBRID] LTX video generated: {ltx_video_path}")
            else:
                return {"success": False, "error": "LTX generation failed"}

        except Exception as e:
            logger.error(f"[HYBRID] LTX generation error: {e}")
            return {"success": False, "error": f"LTX generation failed: {e}"}

    # Step 2: Extract last frame from LTX video
    logger.info(f"[HYBRID] Extracting last frame from LTX video...")

    bridge_frame = tools_dir / "frames" / f"hybrid_bridge_{datetime.now().strftime('%H%M%S')}.png"

    try:
        import subprocess
        subprocess.run([
            "ffmpeg", "-y", "-sseof", "-0.1", "-i", str(ltx_video_path),
            "-frames:v", "1", "-q:v", "2", str(bridge_frame)
        ], check=True, capture_output=True)
        logger.info(f"[HYBRID] Bridge frame extracted: {bridge_frame}")
    except subprocess.CalledProcessError as e:
        return {"success": False, "error": f"Failed to extract last frame: {e}"}

    if not bridge_frame.exists():
        return {"success": False, "error": "Bridge frame extraction failed"}

    # Step 3: Feed into Kling for expressive motion
    logger.info(f"[HYBRID] Generating Kling video from bridge frame...")

    existing_hybrid = list((tools_dir / "videos").glob("hybrid_kling_*.mp4"))
    version = len(existing_hybrid) + 1
    kling_output = tools_dir / "videos" / f"hybrid_kling_v{version:03d}.mp4"

    try:
        import fal_client

        # Upload bridge frame
        image_url = fal_client.upload(bridge_frame, "image/png")

        # Generate Kling v3 video
        result = fal_client.run(
            "fal-ai/kling-video/v3/pro/image-to-video",
            arguments={
                "prompt": kling_prompt,
                "image_url": image_url,
                "duration": kling_duration,
                "aspect_ratio": "16:9"
            }
        )

        if result and result.get("video"):
            import urllib.request
            video_url = result["video"]["url"] if isinstance(result["video"], dict) else result["video"]
            urllib.request.urlretrieve(video_url, kling_output)
            logger.info(f"[HYBRID] Kling video generated: {kling_output}")
        else:
            return {"success": False, "error": "Kling generation failed"}

    except Exception as e:
        logger.error(f"[HYBRID] Kling generation error: {e}")
        return {"success": False, "error": f"Kling generation failed: {e}"}

    # Step 4: Optionally stitch LTX + Kling
    final_hybrid = tools_dir / "videos" / f"hybrid_final_v{version:03d}.mp4"

    try:
        import subprocess
        # Create concat file
        concat_file = tools_dir / "videos" / "hybrid_concat.txt"
        with open(concat_file, 'w') as f:
            f.write(f"file '{ltx_video_path}'\n")
            f.write(f"file '{kling_output}'\n")

        subprocess.run([
            "ffmpeg", "-y", "-f", "concat", "-safe", "0",
            "-i", str(concat_file),
            "-c", "copy", str(final_hybrid)
        ], check=True, capture_output=True)

        logger.info(f"[HYBRID] Final hybrid video: {final_hybrid}")
    except subprocess.CalledProcessError as e:
        logger.warning(f"[HYBRID] Stitch failed, returning separate videos: {e}")
        final_hybrid = None

    # Update director overrides
    overrides = get_director_overrides(project)
    if shot_id not in overrides.get("shots", {}):
        overrides.setdefault("shots", {})[shot_id] = {}

    shot_data = overrides["shots"][shot_id]
    shot_data.setdefault("video_variants", {})
    shot_data["video_variants"][f"hybrid_kling_v{version}"] = f"director_tools/{shot_id}/videos/hybrid_kling_v{version:03d}.mp4"

    if final_hybrid and final_hybrid.exists():
        shot_data["video_variants"][f"hybrid_final_v{version}"] = f"director_tools/{shot_id}/videos/hybrid_final_v{version:03d}.mp4"

    shot_data["_last_hybrid"] = {
        "created_at": datetime.now().isoformat(),
        "ltx_prompt": ltx_prompt,
        "kling_prompt": kling_prompt,
        "ltx_duration": ltx_duration,
        "kling_duration": kling_duration
    }

    save_director_overrides(project, overrides)

    return {
        "success": True,
        "project": project,
        "shot_id": shot_id,
        "ltx_video": str(ltx_video_path),
        "bridge_frame": str(bridge_frame),
        "kling_video": str(kling_output),
        "final_hybrid": str(final_hybrid) if final_hybrid and final_hybrid.exists() else None,
        "version": version,
        "total_duration": ltx_duration + kling_duration
    }


@app.post("/api/v17/shot/promote-to-kling")
async def promote_ltx_to_kling(request: Dict = Body(...)):
    """
    V17 DIRECTOR TOOL: Promote existing LTX video to Kling.

    Takes an existing LTX video, extracts its last frame,
    and generates a Kling continuation.

    Body:
    {
        "project": "ravencroft_v17",
        "shot_id": "E011_S01_000A",
        "kling_prompt": "Continue with more expressive motion",
        "kling_duration": 5
    }
    """
    project = request.get("project")
    shot_id = request.get("shot_id")
    kling_prompt = request.get("kling_prompt", "Continue motion, expressive, cinematic")
    kling_duration = request.get("kling_duration", 5)

    if not project or not shot_id:
        return {"success": False, "error": "project and shot_id required"}

    project_path = get_project_path(project)

    # Find existing LTX video
    ltx_video = None
    videos_dir = project_path / "videos"
    for ext in [".mp4", ".webm"]:
        candidate = videos_dir / f"{shot_id}{ext}"
        if candidate.exists():
            ltx_video = candidate
            break

    if not ltx_video:
        return {"success": False, "error": f"No existing video found for {shot_id}. Generate LTX video first."}

    # Use hybrid motion with existing LTX
    return await hybrid_ltx_to_kling({
        "project": project,
        "shot_id": shot_id,
        "kling_prompt": kling_prompt,
        "kling_duration": kling_duration,
        "use_existing_ltx": True
    })


# ═══════════════════════════════════════════════════════════════════
# V17.8: KLING O3 STANDARD — QUALITY BOOST + MULTI-SHOT ENGINE
# ═══════════════════════════════════════════════════════════════════

@app.post("/api/v17/shot/kling-regen")
async def kling_regen_video(request: Dict = Body(...)):
    """
    V17.8: Regenerate a shot's video using Kling O3 Standard.

    Uses the first frame as start_image and the shot's LTX motion prompt
    to generate a higher-quality Kling video (replaces LTX output).

    Supports 3-15 second durations, native audio generation,
    and optional end_image for shot-to-shot continuity.

    Body:
    {
        "project": "ravencroft_v17",
        "shot_id": "001_001A",
        "prompt": null,            // Override prompt (null = use ltx_motion_prompt)
        "duration": 10,            // 3-15 seconds
        "generate_audio": false,   // Native Kling audio
        "replace_ltx": false,      // If true, overwrite the LTX video
        "end_image_shot": null     // shot_id to use as end frame (continuity)
    }
    """
    project = request.get("project")
    shot_id = request.get("shot_id")
    custom_prompt = request.get("prompt")
    duration = min(max(int(request.get("duration", 5)), 3), 15)
    generate_audio = request.get("generate_audio", True)   # V18: Default ON — Kling native audio (SFX/foley only)
    replace_ltx = request.get("replace_ltx", False)
    end_image_shot = request.get("end_image_shot")

    if not project or not shot_id:
        return {"success": False, "error": "project and shot_id required"}

    project_path = get_project_path(project)

    # Load shot data for prompt
    shot_plan_path = project_path / "shot_plan.json"
    if not shot_plan_path.exists():
        return {"success": False, "error": "shot_plan.json not found"}

    with open(shot_plan_path) as f:
        data = json.load(f)
    all_shots = data.get("shots", data) if isinstance(data, dict) else data
    shot = next((s for s in all_shots if s.get("shot_id") == shot_id), None)
    if not shot:
        return {"success": False, "error": f"Shot {shot_id} not found"}

    # Get first frame as start image
    first_frame = None
    ff_dir = project_path / "first_frames"
    for ext in [".jpg", ".png", ".jpeg"]:
        candidate = ff_dir / f"{shot_id}{ext}"
        if candidate.exists():
            first_frame = candidate
            break

    if not first_frame:
        return {"success": False, "error": f"No first frame for {shot_id}. Generate frames first."}

    # Build prompt: use custom or fall back to LTX motion prompt
    prompt = custom_prompt or shot.get("ltx_motion_prompt", "") or shot.get("nano_prompt", "Cinematic shot, atmospheric")
    # Enhance prompt for Kling (more descriptive than LTX format)
    if not custom_prompt:
        # Strip LTX-specific timing clauses and add Kling-friendly language
        prompt = prompt.replace("face stable NO morphing", "").replace("NO grid, NO morphing", "")
        prompt = f"Cinematic film quality, {prompt.strip()}, natural lighting, professional cinematography"

    # Optional end image for shot-to-shot continuity
    end_image_url = None
    if end_image_shot:
        for ext in [".jpg", ".png", ".jpeg"]:
            candidate = ff_dir / f"{end_image_shot}{ext}"
            if candidate.exists():
                end_image_url = str(candidate)
                break

    # Generate version number
    tools_dir = ensure_director_tools_dir(project, shot_id)
    existing = list((tools_dir / "videos").glob("kling_o3_*.mp4"))
    version = len(existing) + 1
    output_filename = f"kling_o3_v{version:03d}.mp4"
    output_path = tools_dir / "videos" / output_filename

    try:
        import fal_client

        # Upload start frame
        image_url = fal_client.upload(first_frame, "image/jpeg")

        # Build Kling O3 Standard arguments
        # Audio preference: SFX/foley only — no soundscapes, no ambient tones, no music
        audio_enhanced_prompt = prompt
        if generate_audio:
            audio_enhanced_prompt = f"{prompt}, realistic sound effects, foley audio, natural environment sounds"
        kling_args = {
            "prompt": audio_enhanced_prompt,
            "image_url": image_url,
            "duration": str(duration),
            "generate_audio": generate_audio,
            "negative_prompt": "blur, distort, low quality, morphing, grid pattern, split screen, background music, ambient tones, soundscape, musical score, drone sounds"
        }

        # Add end frame for shot continuity
        if end_image_url:
            kling_args["end_image_url"] = fal_client.upload(end_image_url, "image/jpeg")

        logger.info(f"[KLING-O3] Generating {shot_id} via O3 Standard ({duration}s, audio={generate_audio})")

        # Call Kling O3 Standard via FAL
        result = fal_client.subscribe(
            "fal-ai/kling-video/v3/standard/image-to-video",
            arguments=kling_args,
            with_logs=True
        )

        # Download result
        if result and result.get("video"):
            import urllib.request
            video_url = result["video"]["url"] if isinstance(result["video"], dict) else result["video"]
            urllib.request.urlretrieve(video_url, output_path)
            logger.info(f"[KLING-O3] Generated {output_path} ({result['video'].get('file_size', 0)} bytes)")

            # Optionally replace the LTX video
            if replace_ltx:
                ltx_path = project_path / "videos" / f"{shot_id}.mp4"
                import shutil
                shutil.copy2(output_path, ltx_path)
                logger.info(f"[KLING-O3] Replaced LTX video: {ltx_path}")
        else:
            return {"success": False, "error": "Kling O3 returned no video"}

    except Exception as e:
        logger.error(f"[KLING-O3] Error: {e}")
        return {"success": False, "error": str(e)}

    # Track as video variant
    overrides = get_director_overrides(project)
    overrides.setdefault("shots", {}).setdefault(shot_id, {})
    overrides["shots"][shot_id].setdefault("video_variants", {})
    relative_path = f"director_tools/{shot_id}/videos/{output_filename}"
    overrides["shots"][shot_id]["video_variants"][f"kling_o3_v{version}"] = relative_path
    overrides["shots"][shot_id]["_last_kling_o3_gen"] = datetime.now().isoformat()
    save_director_overrides(project, overrides)

    # Invalidate cache
    (project_path / "ui_cache" / "bundle.dirty").touch(exist_ok=True)

    return {
        "success": True,
        "project": project,
        "shot_id": shot_id,
        "model": "fal-ai/kling-video/v3/standard/image-to-video",
        "output_path": str(output_path),
        "output_url": f"/api/media?path={output_path}",
        "relative_path": relative_path,
        "duration": duration,
        "version": version,
        "replaced_ltx": replace_ltx,
        "generate_audio": generate_audio
    }


@app.post("/api/v17/scene/kling-multishot")
async def kling_multishot_scene(request: Dict = Body(...)):
    """
    V17.8: Generate multi-shot scene video using Kling O3 multi_prompt.

    Takes the first frame of the first shot in the scene and generates
    a multi-shot video with Kling's built-in shot transitions.
    Total duration up to 15s, split across shots.

    Body:
    {
        "project": "ravencroft_v17",
        "scene_id": "001",
        "max_duration": 15,        // Total duration cap (3-15s)
        "shot_ids": null,          // Specific shots (null = all scene shots)
        "generate_audio": false
    }
    """
    project = request.get("project")
    scene_id = request.get("scene_id")
    max_duration = min(max(int(request.get("max_duration", 15)), 3), 15)
    shot_ids = request.get("shot_ids")
    generate_audio = request.get("generate_audio", True)   # V18: Default ON — Kling native audio (SFX/foley only)

    if not project or not scene_id:
        return {"success": False, "error": "project and scene_id required"}

    project_path = get_project_path(project)
    shot_plan_path = project_path / "shot_plan.json"
    if not shot_plan_path.exists():
        return {"success": False, "error": "shot_plan.json not found"}

    with open(shot_plan_path) as f:
        data = json.load(f)
    all_shots = data.get("shots", data) if isinstance(data, dict) else data

    # Get scene shots
    if shot_ids:
        scene_shots = [s for s in all_shots if s.get("shot_id") in shot_ids]
    else:
        scene_shots = [s for s in all_shots if s.get("shot_id", "").startswith(scene_id)]

    if not scene_shots:
        return {"success": False, "error": f"No shots found for scene {scene_id}"}

    # Build multi-prompt: distribute duration across shots (max 15s total)
    n_shots = min(len(scene_shots), 5)  # Kling practical limit
    per_shot_dur = max(3, max_duration // n_shots)
    remaining = max_duration

    multi_prompt = []
    for shot in scene_shots[:n_shots]:
        shot_dur = min(per_shot_dur, remaining)
        if shot_dur < 3:
            break
        remaining -= shot_dur

        prompt = shot.get("ltx_motion_prompt", "") or shot.get("nano_prompt", "Cinematic shot")
        prompt = prompt.replace("face stable NO morphing", "").replace("NO grid, NO morphing", "")
        prompt = f"Cinematic quality, {prompt.strip()}"
        if generate_audio:
            prompt = f"{prompt}, realistic sound effects, foley audio, natural environment sounds"

        multi_prompt.append({
            "prompt": prompt[:500],
            "duration": str(shot_dur)
        })

    if not multi_prompt:
        return {"success": False, "error": "Could not build multi-prompt (duration too short)"}

    # Get first frame of first shot as start image
    first_frame = None
    ff_dir = project_path / "first_frames"
    first_shot_id = scene_shots[0]["shot_id"]
    for ext in [".jpg", ".png", ".jpeg"]:
        candidate = ff_dir / f"{first_shot_id}{ext}"
        if candidate.exists():
            first_frame = candidate
            break

    if not first_frame:
        return {"success": False, "error": f"No first frame for {first_shot_id}"}

    # Output path
    kling_scenes_dir = project_path / "kling_scenes"
    kling_scenes_dir.mkdir(exist_ok=True)
    output_path = kling_scenes_dir / f"scene_{scene_id}_kling.mp4"

    try:
        import fal_client
        image_url = fal_client.upload(first_frame, "image/jpeg")

        logger.info(f"[KLING-MULTISHOT] Scene {scene_id}: {len(multi_prompt)} shots, {sum(int(p['duration']) for p in multi_prompt)}s total")

        result = fal_client.subscribe(
            "fal-ai/kling-video/v3/standard/image-to-video",
            arguments={
                "image_url": image_url,
                "multi_prompt": multi_prompt,
                "shot_type": "customize",
                "generate_audio": generate_audio,
                "negative_prompt": "blur, distort, low quality, background music, ambient tones, soundscape, musical score, drone sounds"
            },
            with_logs=True
        )

        if result and result.get("video"):
            import urllib.request
            video_url = result["video"]["url"] if isinstance(result["video"], dict) else result["video"]
            urllib.request.urlretrieve(video_url, output_path)
            logger.info(f"[KLING-MULTISHOT] Generated {output_path}")
        else:
            return {"success": False, "error": "Kling multishot returned no video"}

    except Exception as e:
        logger.error(f"[KLING-MULTISHOT] Error: {e}")
        return {"success": False, "error": str(e)}

    # Invalidate cache
    (project_path / "ui_cache" / "bundle.dirty").touch(exist_ok=True)

    return {
        "success": True,
        "project": project,
        "scene_id": scene_id,
        "model": "fal-ai/kling-video/v3/standard/image-to-video",
        "mode": "multi_prompt",
        "shots_used": len(multi_prompt),
        "total_duration": sum(int(p["duration"]) for p in multi_prompt),
        "multi_prompt": multi_prompt,
        "output_path": str(output_path),
        "output_url": f"/api/media?path={output_path}",
        "generate_audio": generate_audio
    }


@app.post("/api/v17/shot/set-active-video")
async def set_active_video(request: Dict = Body(...)):
    """
    V17: Set which video variant to use for a shot.

    Body:
    {
        "project": "ravencroft_v17",
        "shot_id": "E011_S01_000A",
        "video_key": "kling_v1"  // Key from video_variants
    }
    """
    project = request.get("project")
    shot_id = request.get("shot_id")
    video_key = request.get("video_key")

    if not all([project, shot_id, video_key]):
        return {"success": False, "error": "project, shot_id, and video_key required"}

    overrides = get_director_overrides(project)
    shot_data = overrides.get("shots", {}).get(shot_id, {})
    video_variants = shot_data.get("video_variants", {})

    if video_key not in video_variants and video_key != "base":
        return {"success": False, "error": f"Video variant '{video_key}' not found"}

    if shot_id not in overrides.get("shots", {}):
        overrides.setdefault("shots", {})[shot_id] = {}

    overrides["shots"][shot_id]["selected_video"] = video_key
    overrides["shots"][shot_id]["_video_set_at"] = datetime.now().isoformat()

    save_director_overrides(project, overrides)

    return {
        "success": True,
        "project": project,
        "shot_id": shot_id,
        "active_video": video_key
    }


@app.post("/api/v17/shot/set-active-frame")
async def set_active_frame(request: Dict = Body(...)):
    """
    V17: Set which first frame variant to use for a shot.

    Body:
    {
        "project": "ravencroft_v17",
        "shot_id": "E011_S01_000A",
        "frame_path": "director_tools/E011_S01_000A/frames/reframe_ots_left_v001.png"
    }
    """
