@app.post("/api/v17/generate-scene-cards")
async def generate_scene_cards(request: Dict = Body(...)):
    """
    V17 FIX: Auto-generate scene_cards from shot_plan when story_bible has none.
    Groups shots by scene_id and creates a summary card for each scene.
    """
    project = request.get("project")
    if not project:
        return {"success": False, "error": "project required"}

    project_path = get_project_path(project)
    story_bible_path = project_path / "story_bible.json"
    shot_plan_path = project_path / "shot_plan.json"

    if not story_bible_path.exists():
        return {"success": False, "error": "story_bible.json not found"}
    if not shot_plan_path.exists():
        return {"success": False, "error": "shot_plan.json not found"}

    with open(story_bible_path) as f:
        sb = json.load(f)

    with open(shot_plan_path) as f:
        sp = _sp_guard(json.load(f))

    # Check if scene cards already exist
    existing_cards = sb.get("scene_cards", [])
    if existing_cards and not request.get("force", False):
        return {"success": True, "message": f"Scene cards already exist ({len(existing_cards)} cards)", "scene_cards": existing_cards}

    # Group shots by scene_id
    from collections import OrderedDict
    scene_groups = OrderedDict()
    for shot in sp.get("shots", []):
        scene_id = shot.get("scene_id", "unknown")
        if scene_id not in scene_groups:
            scene_groups[scene_id] = {
                "scene_id": scene_id,
                "shots": [],
                "characters": set(),
                "location": shot.get("location", ""),
                "total_duration": 0,
            }
        scene_groups[scene_id]["shots"].append(shot)
        scene_groups[scene_id]["total_duration"] += shot.get("duration", 10)
        for char in shot.get("characters", []):
            char_name = char if isinstance(char, str) else char.get("name", "")
            if char_name:
                scene_groups[scene_id]["characters"].add(char_name)
        if not scene_groups[scene_id]["location"] and shot.get("location"):
            scene_groups[scene_id]["location"] = shot["location"]

    # Also check story_bible scenes for intent/stakes
    sb_scenes = {s.get("scene_id", s.get("id", "")): s for s in sb.get("scenes", [])}

    # Generate scene cards
    scene_cards = []
    for scene_id, data in scene_groups.items():
        sb_scene = sb_scenes.get(scene_id, {})
        num_shots = len(data["shots"])
        chars = sorted(data["characters"])
        duration_min = data["total_duration"] // 60
        duration_sec = data["total_duration"] % 60

        # Get scene intent from story bible if available
        intent = sb_scene.get("intent", sb_scene.get("description", ""))
        stakes = sb_scene.get("stakes", "")
        tone = sb_scene.get("tone", "")

        # Build card text
        card_parts = [f"Scene {scene_id}"]
        if data["location"]:
            card_parts.append(f"Location: {data['location']}")
        if chars:
            card_parts.append(f"Characters: {', '.join(chars[:5])}")
        card_parts.append(f"{num_shots} shots, {duration_min}:{str(duration_sec).zfill(2)} runtime")
        if intent:
            card_parts.append(f"Intent: {intent[:200]}")
        if stakes:
            card_parts.append(f"Stakes: {stakes[:100]}")
        if tone:
            card_parts.append(f"Tone: {tone}")

        scene_cards.append(" | ".join(card_parts))

    # Save to story bible
    sb["scene_cards"] = scene_cards
    sb["_scene_cards_generated"] = datetime.now().isoformat()

    with open(story_bible_path, "w") as f:
        json.dump(sb, f, indent=2)

    logger.info(f"[V17 FIX] Generated {len(scene_cards)} scene cards for {project}")

    return {
        "success": True,
        "project": project,
        "scene_cards_count": len(scene_cards),
        "scene_cards": scene_cards,
        "message": f"Generated {len(scene_cards)} scene cards from {len(sp.get('shots', []))} shots"
    }


