def get_voice_for_character(char_name, cast_map, story_bible):
    """Determine ElevenLabs voice_id for a character based on cast/story bible data."""
    # Check if cast_map has voice assignment
    if char_name in cast_map:
        char_data = cast_map[char_name]
        if isinstance(char_data, dict):
            if char_data.get("voice_id"):
                return char_data["voice_id"]
            # Infer from role
            role = char_data.get("role", "supporting")
            gender = char_data.get("gender", "").lower()
            if "lead" in role:
                return DEFAULT_VOICE_MAP.get(f"{gender}_lead", DEFAULT_VOICE_MAP["male_lead"])
            return DEFAULT_VOICE_MAP.get(f"{gender}_supporting", DEFAULT_VOICE_MAP["male_supporting"])

    # Check story bible characters
    for char in story_bible.get("characters", []):
        if isinstance(char, dict) and char.get("name", "").upper() == char_name.upper():
            role = char.get("role", "supporting")
            desc = char.get("description", "").lower()
            if "female" in desc or "woman" in desc or "she " in desc:
                gender = "female"
            elif "child" in desc or "boy" in desc or "girl" in desc:
                return DEFAULT_VOICE_MAP["child"]
            else:
                gender = "male"
            if "elderly" in desc or "old" in desc or "aged" in desc:
                return DEFAULT_VOICE_MAP.get(f"{gender}_elderly", DEFAULT_VOICE_MAP["male_elderly"])
            if role == "lead":
                return DEFAULT_VOICE_MAP.get(f"{gender}_lead", DEFAULT_VOICE_MAP["male_lead"])
            return DEFAULT_VOICE_MAP.get(f"{gender}_supporting", DEFAULT_VOICE_MAP["male_supporting"])

    return DEFAULT_VOICE_MAP["male_supporting"]


@app.post("/api/v17/audio/generate-dialogue")
async def generate_dialogue_audio(request: Dict = Body(...)):
    """
    V17.2: Generate TTS audio for shot dialogue using ElevenLabs.

    Body: {"project": "NAME", "shot_id": "001_001A", "dry_run": false}
    Or batch: {"project": "NAME", "all": true, "dry_run": false}
    """
    project = request.get("project")
    shot_id = request.get("shot_id")
    generate_all = request.get("all", False)
    dry_run = request.get("dry_run", True)
    voice_override = request.get("voice_id")

    if not project:
        return {"success": False, "error": "project required"}

    project_path = get_project_path(project)
    shot_plan_path = project_path / "shot_plan.json"
    if not shot_plan_path.exists():
        return {"success": False, "error": "No shot_plan.json"}

    with open(shot_plan_path) as f:
        shot_plan = _sp_guard(json.load(f))

    # Load cast and story bible for voice mapping
    cast_map = {}
    cast_path = project_path / "cast_map.json"
    if cast_path.exists():
        with open(cast_path) as f:
            cast_map = json.load(f)

    story_bible = {}
    sb_path = project_path / "story_bible.json"
    if sb_path.exists():
        with open(sb_path) as f:
            story_bible = json.load(f)

    # Find shots with dialogue
    shots = shot_plan.get("shots", [])
    dialogue_shots = []
    for shot in shots:
        if not isinstance(shot, dict):
            continue
        if shot_id and shot.get("shot_id") != shot_id:
            continue
        dialogue = shot.get("dialogue", "") or shot.get("dialogue_text", "")
        if dialogue and len(str(dialogue).strip()) > 3:
            dialogue_shots.append(shot)
        if shot_id:
            break

    if not dialogue_shots:
        return {"success": True, "project": project, "message": "No dialogue shots found", "generated": 0}

    # Create audio output directory
    audio_dir = project_path / "audio"
    audio_dir.mkdir(exist_ok=True)

    results = []
    generated = 0
    skipped = 0

    for shot in dialogue_shots:
        sid = shot.get("shot_id", "unknown")
        dialogue = shot.get("dialogue", "") or shot.get("dialogue_text", "")

        # Parse character from dialogue (format: "CHARACTER: text" or just text)
        char_name = ""
        speak_text = str(dialogue).strip()
        if ":" in speak_text:
            parts = speak_text.split(":", 1)
            char_name = parts[0].strip().strip('"').strip("'")
            speak_text = parts[1].strip().strip('"').strip("'")

        # Get voice
        voice_id = voice_override or get_voice_for_character(char_name, cast_map, story_bible)

        audio_path = audio_dir / f"{sid}_dialogue.mp3"

        if dry_run:
            results.append({
                "shot_id": sid,
                "character": char_name,
                "text": speak_text[:100] + "..." if len(speak_text) > 100 else speak_text,
                "voice_id": voice_id,
                "audio_path": str(audio_path),
                "status": "WOULD_GENERATE"
            })
            continue

        # Check if already generated
        if audio_path.exists() and not request.get("overwrite", False):
            results.append({"shot_id": sid, "status": "ALREADY_EXISTS", "path": str(audio_path)})
            skipped += 1
            continue

        # Call ElevenLabs API
        try:
            import httpx
            async with httpx.AsyncClient(timeout=30.0) as client:
                resp = await client.post(
                    f"https://api.elevenlabs.io/v1/text-to-speech/{voice_id}",
                    headers={
                        "xi-api-key": orchestrator.elevenlabs_key,
                        "Content-Type": "application/json"
                    },
                    json={
                        "text": speak_text,
                        "model_id": "eleven_monolingual_v1",
                        "voice_settings": {
                            "stability": 0.5,
                            "similarity_boost": 0.75,
                            "style": 0.3,
                            "use_speaker_boost": True
                        }
                    }
                )

                if resp.status_code == 200:
                    with open(audio_path, "wb") as f:
                        f.write(resp.content)

                    # Update shot with audio path
                    shot["audio_path"] = str(audio_path)
                    shot["audio_voice_id"] = voice_id
                    shot["audio_character"] = char_name

                    results.append({
                        "shot_id": sid, "status": "GENERATED",
                        "path": str(audio_path), "size": len(resp.content),
                        "character": char_name, "voice_id": voice_id
                    })
                    generated += 1
                else:
                    results.append({
                        "shot_id": sid, "status": "API_ERROR",
                        "error": f"HTTP {resp.status_code}: {resp.text[:200]}"
                    })
        except Exception as e:
            results.append({"shot_id": sid, "status": "ERROR", "error": str(e)})

    # Save updated shot plan with audio paths
    if not dry_run and generated > 0:
        with open(shot_plan_path, "w") as f:
            json.dump(shot_plan, f, indent=2)
        cache_dir = project_path / "ui_cache"
        if cache_dir.exists():
            (cache_dir / "bundle.dirty").touch()

    return {
        "success": True,
        "project": project,
        "dry_run": dry_run,
        "dialogue_shots_found": len(dialogue_shots),
        "generated": generated,
        "skipped": skipped,
        "results": results
    }


@app.post("/api/v17/audio/assign-voices")
async def assign_character_voices(request: Dict = Body(...)):
    """
    V17.2: Assign or update voice IDs for characters in cast_map.

    Body: {"project": "NAME", "assignments": {"EVELYN": "voice_id_here", "ARTHUR": "voice_id_here"}}
    Or auto-assign: {"project": "NAME", "auto": true}
    """
    project = request.get("project")
    auto_assign = request.get("auto", False)
    assignments = request.get("assignments", {})

    if not project:
        return {"success": False, "error": "project required"}

    project_path = get_project_path(project)
    cast_path = project_path / "cast_map.json"
    sb_path = project_path / "story_bible.json"

    cast_map = {}
    if cast_path.exists():
        with open(cast_path) as f:
            cast_map = json.load(f)

    story_bible = {}
    if sb_path.exists():
        with open(sb_path) as f:
            story_bible = json.load(f)

    assigned = 0
    if auto_assign:
        for char_name, char_data in cast_map.items():
            if char_name.startswith("_"):
                continue
            if not isinstance(char_data, dict):
                continue
            voice_id = get_voice_for_character(char_name, cast_map, story_bible)
            char_data["voice_id"] = voice_id
            assigned += 1
    else:
        for char_name, voice_id in assignments.items():
            if char_name in cast_map and isinstance(cast_map[char_name], dict):
                cast_map[char_name]["voice_id"] = voice_id
                assigned += 1

    with open(cast_path, "w") as f:
        json.dump(cast_map, f, indent=2)

    return {"success": True, "project": project, "assigned": assigned, "cast_map_updated": True}


@app.post("/api/v17/audio/mix-scene")
async def mix_scene_audio(request: Dict = Body(...)):
    """
    V17.2: Mix dialogue audio with video for a scene using FFmpeg.

    Body: {"project": "NAME", "scene_id": "001", "dry_run": false}
    Creates a mixed video+audio output per shot.
    """
    project = request.get("project")
    scene_id = request.get("scene_id")
    dry_run = request.get("dry_run", True)

    if not project:
        return {"success": False, "error": "project required"}

    project_path = get_project_path(project)
    shot_plan_path = project_path / "shot_plan.json"
    with open(shot_plan_path) as f:
        shot_plan = _sp_guard(json.load(f))

    shots = shot_plan.get("shots", [])
    scene_shots = [s for s in shots if isinstance(s, dict) and s.get("scene_id") == scene_id]

    mixed_dir = project_path / "mixed"
    mixed_dir.mkdir(exist_ok=True)

    results = []
    for shot in scene_shots:
        sid = shot.get("shot_id", "")
        video_path = shot.get("video_path", "")
        audio_path = shot.get("audio_path", "")

        if not video_path or not audio_path:
            results.append({"shot_id": sid, "status": "SKIP", "reason": "missing video or audio"})
            continue

        if not Path(video_path).exists():
            # Try standard location
            video_path = str(project_path / "videos" / f"{sid}.mp4")
        if not Path(audio_path).exists():
            audio_path = str(project_path / "audio" / f"{sid}_dialogue.mp3")

        output_path = mixed_dir / f"{sid}_mixed.mp4"

        if dry_run:
            results.append({"shot_id": sid, "status": "WOULD_MIX", "video": video_path, "audio": audio_path})
            continue

        # FFmpeg mix command: overlay audio on video
        cmd = (
            f'ffmpeg -y -i "{video_path}" -i "{audio_path}" '
            f'-c:v copy -c:a aac -shortest '
            f'-map 0:v:0 -map 1:a:0 '
            f'"{output_path}"'
        )
        try:
            import subprocess
            proc = await asyncio.get_event_loop().run_in_executor(
                None, lambda: subprocess.run(cmd, shell=True, capture_output=True, text=True, timeout=120)
            )
            if proc.returncode == 0 and output_path.exists():
                shot["mixed_path"] = str(output_path)
                results.append({"shot_id": sid, "status": "MIXED", "path": str(output_path)})
            else:
                logger.error(f"[FFMPEG] Audio mix failed for {sid}: {proc.stderr[:200] if proc.stderr else 'unknown'}")
                results.append({"shot_id": sid, "status": "FFMPEG_ERROR", "stderr": (proc.stderr or "")[:200]})
        except Exception as e:
            results.append({"shot_id": sid, "status": "ERROR", "error": str(e)})

    # Save
    if not dry_run:
        with open(shot_plan_path, "w") as f:
            json.dump(shot_plan, f, indent=2)

    return {"success": True, "project": project, "scene_id": scene_id, "dry_run": dry_run, "results": results}


# ── V17.3: STEMS-FIRST AUDIO ARCHITECTURE ──

async def _extract_single_stem(project: str, shot_id: str, normalize: bool = True) -> dict:
    """
    V17.3: Core stem extraction logic — called by both the HTTP endpoint and batch extraction.
    Extract dialogue stem from LTX-rendered video.
    Produces: dialogue_raw.wav (extracted) + dialogue_norm.wav (loudness-normalized)
    This preserves LTX lip sync while isolating the dialogue track.
    """
    project_path = get_project_path(project)
    shot_plan_path = project_path / "shot_plan.json"
    audio_dir = project_path / "audio" / "stems"
    audio_dir.mkdir(parents=True, exist_ok=True)

    if not shot_plan_path.exists():
        return {"error": "shot_plan.json not found"}

    with open(shot_plan_path) as f:
        shot_plan = _sp_guard(json.load(f))

    shots = shot_plan.get("shots", [])
    target = [s for s in shots if s.get("shot_id") == shot_id]
    if not target:
        return {"error": f"Shot {shot_id} not found"}

    shot = target[0]
    video_path = shot.get("video_path")
    if not video_path or not Path(video_path).exists():
        return {"error": f"No video file for {shot_id}"}

    results = {}

    # Step 1: Extract raw audio from video
    raw_path = audio_dir / f"{shot_id}_dialogue_raw.wav"
    cmd_extract = (
        f'ffmpeg -y -i "{video_path}" '
        f'-vn -acodec pcm_s16le -ar 44100 -ac 1 '
        f'"{raw_path}"'
    )
    try:
        proc = await asyncio.get_event_loop().run_in_executor(
            None, lambda: subprocess.run(cmd_extract, shell=True, capture_output=True, text=True, timeout=60)
        )
        if proc.returncode == 0 and raw_path.exists():
            results["dialogue_raw"] = str(raw_path)
            logger.info(f"[V17.3] Extracted dialogue stem: {shot_id} → {raw_path.name}")
        else:
            return {"error": f"FFmpeg extract failed: {(proc.stderr or '')[:200]}"}
    except Exception as e:
        return {"error": f"Extract failed: {str(e)}"}

    # Step 2: Normalize loudness (EBU R128 target: -16 LUFS for dialogue)
    norm_path = audio_dir / f"{shot_id}_dialogue_norm.wav"
    if normalize:
        cmd_norm = (
            f'ffmpeg -y -i "{raw_path}" '
            f'-af "loudnorm=I=-16:LRA=11:TP=-1.5" '
            f'-ar 44100 -ac 1 '
            f'"{norm_path}"'
        )
        try:
            proc = await asyncio.get_event_loop().run_in_executor(
                None, lambda: subprocess.run(cmd_norm, shell=True, capture_output=True, text=True, timeout=60)
            )
            if proc.returncode == 0 and norm_path.exists():
                results["dialogue_norm"] = str(norm_path)
                logger.info(f"[V17.3] Normalized dialogue: {shot_id} → -16 LUFS")
            else:
                logger.warning(f"[V17.3] Normalization failed for {shot_id}, using raw")
                results["dialogue_norm"] = str(raw_path)
        except Exception as e:
            logger.warning(f"[V17.3] Normalization error: {e}")
            results["dialogue_norm"] = str(raw_path)
    else:
        results["dialogue_norm"] = str(raw_path)

    # Step 3: High-pass filter to isolate dialogue (remove low rumble/ambience bleed)
    clean_path = audio_dir / f"{shot_id}_dialogue_clean.wav"
    cmd_clean = (
        f'ffmpeg -y -i "{results["dialogue_norm"]}" '
        f'-af "highpass=f=80,lowpass=f=8000,afftdn=nf=-25" '
        f'-ar 44100 -ac 1 '
        f'"{clean_path}"'
    )
    try:
        proc = await asyncio.get_event_loop().run_in_executor(
            None, lambda: subprocess.run(cmd_clean, shell=True, capture_output=True, text=True, timeout=60)
        )
        if proc.returncode == 0 and clean_path.exists():
            results["dialogue_clean"] = str(clean_path)
            logger.info(f"[V17.3] Cleaned dialogue (noise reduced): {shot_id}")
        else:
            results["dialogue_clean"] = results["dialogue_norm"]
    except Exception:
        results["dialogue_clean"] = results["dialogue_norm"]

    # Update shot_plan with stem paths
    if not shot.get("audio_stems"):
        shot["audio_stems"] = {}
    shot["audio_stems"]["dialogue"] = results.get("dialogue_clean") or results.get("dialogue_norm")

    with open(shot_plan_path, "w") as f:
        json.dump(shot_plan, f, indent=2)

    return {"success": True, "shot_id": shot_id, "stems": results}


@app.post("/api/v17/audio/extract-stem")
async def extract_audio_stem(request: Dict = Body(...)):
    """HTTP endpoint for single stem extraction — delegates to _extract_single_stem."""
    return await _extract_single_stem(
        project=request.get("project", ""),
        shot_id=request.get("shot_id", ""),
        normalize=request.get("normalize", True)
    )


@app.post("/api/v17/audio/extract-all-stems")
async def extract_all_stems(request: Dict = Body(...)):
    """Extract dialogue stems from ALL shots that have video files."""
    project = request.get("project", "")
    dry_run = request.get("dry_run", True)
    project_path = get_project_path(project)
    shot_plan_path = project_path / "shot_plan.json"

    if not shot_plan_path.exists():
        return {"error": "shot_plan.json not found"}

    with open(shot_plan_path) as f:
        shot_plan = _sp_guard(json.load(f))

    shots = shot_plan.get("shots", [])
    eligible = [s for s in shots if s.get("video_path") and Path(s["video_path"]).exists()]

    if dry_run:
        return {
            "success": True, "project": project, "dry_run": True,
            "total_shots": len(shots), "eligible": len(eligible),
            "shot_ids": [s["shot_id"] for s in eligible]
        }

    results = []
    for shot in eligible:
        try:
            res = await _extract_single_stem(project=project, shot_id=shot["shot_id"], normalize=True)
            results.append({"shot_id": shot["shot_id"], "status": "ok" if res.get("success") else "error", "detail": res})
        except Exception as e:
            results.append({"shot_id": shot["shot_id"], "status": "error", "detail": str(e)})

    return {"success": True, "project": project, "extracted": len([r for r in results if r["status"] == "ok"]), "results": results}


@app.post("/api/v17/audio/smart-mix")
async def smart_mix_stems(request: Dict = Body(...)):
    """
    V17.3 Smart Stitch Audio Mix — combines stems at stitch time.
    FinalAudio = Dialogue(LTX/TTS) + SFX + Ambience + Music
    Each stem has independent gain control.
    """
    project = request.get("project", "")
    scene_id = request.get("scene_id")
    gains = request.get("gains", {"dialogue": 1.0, "sfx": 0.7, "ambience": 0.3, "music": 0.5})
    project_path = get_project_path(project)
    shot_plan_path = project_path / "shot_plan.json"
    mix_dir = project_path / "audio" / "mixed"
    mix_dir.mkdir(parents=True, exist_ok=True)

    if not shot_plan_path.exists():
        return {"error": "shot_plan.json not found"}

    with open(shot_plan_path) as f:
        shot_plan = _sp_guard(json.load(f))

    shots = shot_plan.get("shots", [])
    if scene_id:
        shots = [s for s in shots if s.get("shot_id", "").startswith(scene_id)]

    results = []
    for shot in shots:
        sid = shot.get("shot_id", "unknown")
        video_path = shot.get("video_path")
        if not video_path or not Path(video_path).exists():
            results.append({"shot_id": sid, "status": "skip", "reason": "no video"})
            continue

        stems = shot.get("audio_stems", {})
        dialogue_stem = stems.get("dialogue") or shot.get("audio_path")

        if not dialogue_stem or not Path(dialogue_stem).exists():
            results.append({"shot_id": sid, "status": "skip", "reason": "no dialogue stem"})
            continue

        # Mix: replace video audio with dialogue stem at specified gain
        output_path = mix_dir / f"{sid}_mixed.mp4"
        dlg_gain = gains.get("dialogue", 1.0)

        cmd = (
            f'ffmpeg -y -i "{video_path}" -i "{dialogue_stem}" '
            f'-filter_complex "[1:a]volume={dlg_gain}[dlg]; [dlg]aformat=sample_fmts=fltp:sample_rates=44100:channel_layouts=stereo[aout]" '
            f'-map 0:v:0 -map "[aout]" '
            f'-c:v copy -c:a aac -b:a 192k -shortest '
            f'"{output_path}"'
        )

        try:
            proc = await asyncio.get_event_loop().run_in_executor(
                None, lambda: subprocess.run(cmd, shell=True, capture_output=True, text=True, timeout=120)
            )
            if proc.returncode == 0 and output_path.exists():
                shot["mixed_video_path"] = str(output_path)
                results.append({"shot_id": sid, "status": "mixed", "path": str(output_path)})
            else:
                results.append({"shot_id": sid, "status": "error", "stderr": (proc.stderr or "")[:200]})
        except Exception as e:
            results.append({"shot_id": sid, "status": "error", "error": str(e)})

    # Save updated shot plan
    with open(shot_plan_path, "w") as f:
        json.dump(shot_plan, f, indent=2)

    return {
        "success": True, "project": project, "scene_id": scene_id,
        "gains": gains,
        "mixed": len([r for r in results if r["status"] == "mixed"]),
        "results": results
    }


@app.get("/api/v17/audio/shot-mode/{project}/{shot_id}")
async def get_shot_audio_mode(project: str, shot_id: str):
    """Get audio mode and stem info for a specific shot."""
    project_path = get_project_path(project)
    shot_plan_path = project_path / "shot_plan.json"
    if not shot_plan_path.exists():
        return {"error": "shot_plan.json not found"}
    with open(shot_plan_path) as f:
        data = json.load(f)
    shot = next((s for s in data.get("shots", []) if s.get("shot_id") == shot_id), None)
    if not shot:
        return {"error": f"Shot {shot_id} not found"}
    return {
        "success": True, "shot_id": shot_id,
        "audio_mode": shot.get("audio_mode", "none"),
        "audio_stems": shot.get("audio_stems", {}),
        "audio_gain": shot.get("audio_gain", {}),
        "audio_path": shot.get("audio_path"),
        "mixed_video_path": shot.get("mixed_video_path")
    }


@app.post("/api/v17/audio/set-mode")
async def set_shot_audio_mode(request: Dict = Body(...)):
    """Set audio mode for one or more shots."""
    project = request.get("project", "")
    shot_ids = request.get("shot_ids", [])
    audio_mode = request.get("audio_mode", "ltx_dialogue_only")
    valid_modes = ["none", "ltx_dialogue_only", "external_tts", "final_mix_disabled"]
    if audio_mode not in valid_modes:
        return {"error": f"Invalid audio_mode. Valid: {valid_modes}"}

    project_path = get_project_path(project)
    shot_plan_path = project_path / "shot_plan.json"
    if not shot_plan_path.exists():
        return {"error": "shot_plan.json not found"}

    with open(shot_plan_path) as f:
        data = json.load(f)

    updated = 0
    for shot in data.get("shots", []):
        if not shot_ids or shot.get("shot_id") in shot_ids:
            shot["audio_mode"] = audio_mode
            updated += 1

    with open(shot_plan_path, "w") as f:
        json.dump(data, f, indent=2)

    return {"success": True, "project": project, "audio_mode": audio_mode, "updated": updated}


