@app.websocket("/ws/dashboard")
async def dashboard_websocket(websocket: WebSocket):
    """WebSocket for dashboard updates"""
    await websocket.accept()

    try:
        while True:
            data = await websocket.receive_json()
            if data.get("type") == "ping":
                await orchestrator.broadcast_status()
    except WebSocketDisconnect:
        pass


@app.websocket("/ws/worker/{worker_id}")
async def worker_websocket(websocket: WebSocket, worker_id: str = None):
    """WebSocket for worker tab communication"""
    await websocket.accept()

    # Register worker
    worker = await orchestrator.register_worker(websocket)

    try:
        # Send initial config with rotated API keys
        await websocket.send_json({
            "type": "init",
            "worker_id": worker.id,
            "config": {
                "replicate_key": orchestrator.get_next_api_key(),
                "elevenlabs_key": orchestrator.elevenlabs_key,
                "fal_key": orchestrator.get_next_fal_key()
            }
        })

        # Main worker loop
        while True:
            try:
                # Check for incoming messages
                message = await asyncio.wait_for(websocket.receive_json(), timeout=0.1)

                if message["type"] == "request_task":
                    # Worker is requesting work
                    task = await orchestrator.assign_task_to_worker(worker.id)
                    if task:
                        await websocket.send_json({
                            "type": "task_assigned",
                            "task": asdict(task)
                        })
                    else:
                        await websocket.send_json({"type": "no_tasks"})

                elif message["type"] == "task_complete":
                    await orchestrator.complete_task(
                        message["task_id"],
                        message["result"]
                    )
                    await orchestrator.broadcast_status()

                elif message["type"] == "task_failed":
                    await orchestrator.fail_task(
                        message["task_id"],
                        message["error"]
                    )
                    await orchestrator.broadcast_status()

                elif message["type"] == "progress":
                    # Update progress (broadcast to dashboard)
                    pass

            except asyncio.TimeoutError:
                # No message, check if we should assign work
                if worker.status == "idle":
                    task = await orchestrator.assign_task_to_worker(worker.id)
                    if task:
                        await websocket.send_json({
                            "type": "task_assigned",
                            "task": asdict(task)
                        })

            await asyncio.sleep(0.1)

    except WebSocketDisconnect:
        await orchestrator.unregister_worker(worker.id)
        await orchestrator.broadcast_status()


