@app.post("/api/load-manifest")
async def load_manifest(manifest: Dict):
    """Load a complete manifest and queue all tasks"""
    tasks = []

    # Parse manifest and create tasks - V16 MODEL LOCK
    for scene in manifest.get("scenes", []):
        for shot in scene.get("shots", []):
            # V16: Default to nano_banana_edit (with refs) or nano_banana_image (no refs)
            has_ref = shot.get("reference_image") or shot.get("character_reference_url")
            default_type = "nano_banana_edit" if has_ref else "nano_banana_image"
            task_type = shot.get("rendering_method", default_type)
            tasks.append({
                "type": task_type,
                "params": shot
            })

    task_ids = await orchestrator.add_batch_tasks(tasks)
    return {"task_ids": task_ids, "total": len(task_ids)}


@app.post("/api/clear-queue")
async def clear_queue():
    """Clear all queued tasks"""
    # Create new queue
    orchestrator.task_queue = asyncio.Queue()
    # Reset queued tasks
    for task in orchestrator.tasks.values():
        if task.status == TaskStatus.QUEUED:
            task.status = TaskStatus.FAILED
            task.error = "Queue cleared"
    return {"status": "cleared"}


