@app.get("/api/gallery/projects")
async def get_gallery_projects():
    """Return available projects and their scenes for gallery navigation."""
    manager = refresh_gallery_state()
    combined_index: Dict[str, Dict[str, Any]] = {}

    # Seed with tracked renders
    for project_name, data in manager.list_projects().items():
        combined_index[project_name] = {
            "scenes": set(data.get("scenes", set())),
            "episodes": set(data.get("episodes", set())),
            "scene_details": {},
        }

    # Merge in episode manifests so dropdowns work before renders exist
    for project_name, data in load_story_project_details().items():
        entry = combined_index.setdefault(
            project_name, {"scenes": set(), "episodes": set(), "scene_details": {}}
        )
        entry["scenes"].update(data.get("scenes", set()))
        entry["episodes"].update(data.get("episodes", set()))
        entry["scene_details"].update(data.get("scene_details", {}))

    projects = []
    for project_name, data in sorted(combined_index.items(), key=lambda item: item[0].lower()):
        scene_details = []
        detail_map = data.get("scene_details", {})
        for scene_id in sorted(detail_map.keys()):
            detail = detail_map[scene_id]
            scene_details.append(
                {
                    "scene_id": scene_id,
                    "scene_title": detail.get("scene_title"),
                    "label": f"{scene_id} – {detail.get('scene_title')}"
                    if detail.get("scene_title")
                    else scene_id,
                    "episode": detail.get("episode"),
                    "scene_number": detail.get("scene_number"),
                }
            )
        projects.append({
            "project": project_name,
            "scenes": sorted(data.get("scenes", [])),
            "episodes": sorted(data.get("episodes", [])),
            "scene_details": scene_details,
        })
    return {"projects": projects}


