@app.get("/api/gallery/cast/image")
async def get_gallery_cast_image(root: str, path: str):
    """Serve casting reference images while constraining allowed directories."""
    base = CAST_ASSET_ROOTS.get(root)
    if not base:
        raise HTTPException(status_code=404, detail="Unknown cast image root")

    target = (base / Path(path)).resolve()
    try:
        target.relative_to(base.resolve())
    except ValueError:
        raise HTTPException(status_code=403, detail="Invalid cast image path")

    if not target.exists():
        raise HTTPException(status_code=404, detail="Cast image not found")

    return FileResponse(target)


@app.get("/api/gallery/quantum-log")
async def get_gallery_quantum_log(limit: int = 50):
    """Expose recent quantum enhancement entries for the dashboard."""
    if not QUANTUM_LOG_PATH.exists():
        return {"enhancements": []}
    try:
        log_data = json.loads(QUANTUM_LOG_PATH.read_text())
    except Exception as exc:  # pragma: no cover - malformed file
        logger.warning(f"[QUANTUM] Unable to read log: {exc}")
        return {"enhancements": [], "error": "log_unreadable"}

    enhancements = log_data.get("enhancements", [])
    if not isinstance(enhancements, list):
        enhancements = []

    slice_limit = max(1, min(limit, 200))
    subset = enhancements[-slice_limit:]
    subset.reverse()

    return {
        "enhancements": subset,
        "path": str(QUANTUM_LOG_PATH)
    }


@app.get("/api/gallery/shots")
async def get_gallery_shots(scene_id: Optional[str] = None, project: Optional[str] = None):
    """Return gallery tracking information with metadata for review UI."""
    manager = refresh_gallery_state()
    payload: List[Dict] = []
    project_filter = project.lower() if project else None

    def matches_filters(shot_identifier: str) -> bool:
        shot_entry = manager.get_shot(shot_identifier)
        if not shot_entry:
            return False
        if scene_id and shot_entry.get('scene_id') != scene_id:
            return False
        if project_filter:
            shot_project = (
                (shot_entry.get('project') or shot_entry.get('metadata', {}).get('project') or "")
                .lower()
            )
            if shot_project != project_filter:
                return False
        return True

    if scene_id:
        ordered = manager.get_scene_shots(scene_id)
        for idx, shot_id in enumerate(ordered, start=1):
            if not matches_filters(shot_id):
                continue
            shot_info = build_shot_payload(manager, shot_id, order_index=idx)
            if shot_info:
                payload.append(shot_info)
    else:
        for shot_id in sorted(manager.tracking['shots'].keys()):
            if not matches_filters(shot_id):
                continue
            shot_info = build_shot_payload(manager, shot_id)
            if shot_info:
                payload.append(shot_info)
    return {
        "shots": payload,
        "scene_id": scene_id,
        "project": project
    }


def calculate_scene_costs(scene_id: Optional[str] = None, project: Optional[str] = None) -> Dict[str, float]:
    totals = {
        "image_generations": 0,
        "image_cost_total_usd": 0.0,
        "video_generations": 0,
        "video_cost_total_usd": 0.0,
    }

    meta_dir = BASE_DIR / "render_gallery" / "image_metadata"
    if not meta_dir.exists():
        return totals

    for meta_file in meta_dir.glob("*.json"):
        try:
            meta = json.loads(meta_file.read_text())
        except json.JSONDecodeError:
            continue

        shot_id = meta_file.stem
        if scene_id:
            meta_scene = meta.get("scene_id")
            if meta_scene:
                if meta_scene != scene_id:
                    continue
            elif not shot_id.startswith(scene_id):
                continue
        if project:
            shot_project = meta.get("project")
            if not shot_project or shot_project.lower() != project.lower():
                continue

        totals["image_generations"] += int(meta.get("image_generations", 0))
        totals["video_generations"] += int(meta.get("video_generations", 0))
        totals["image_cost_total_usd"] += float(meta.get("image_cost_total_usd", 0.0))
        totals["video_cost_total_usd"] += float(meta.get("video_cost_total_usd", 0.0))

    totals["image_cost_total_usd"] = round(totals["image_cost_total_usd"], 2)
    totals["video_cost_total_usd"] = round(totals["video_cost_total_usd"], 2)
    return totals


@app.get("/api/gallery/costs")
async def gallery_costs(scene_id: Optional[str] = None, project: Optional[str] = None):
    return calculate_scene_costs(scene_id, project)


