@app.post("/api/gallery/shots/{shot_id}/swap-image")
async def swap_gallery_shot_image(shot_id: str, request: Dict = Body(...)):
    """Replace the hero still with an alternate Fal candidate or manual URL."""
    image_url = request.get("url")
    if not image_url:
        return JSONResponse({"error": "Missing 'url' in request body"}, status_code=400)

    manager = refresh_gallery_state()
    shot_entry = manager.get_shot(shot_id)
    if not shot_entry:
        return JSONResponse({"error": f"Shot {shot_id} not found"}, status_code=404)

    metadata_info = shot_entry.get("metadata", {}) or {}
    metadata_path = metadata_info.get("metadata_path")
    if metadata_path:
        metadata_path = Path(metadata_path)
    else:
        metadata_path = BASE_DIR / "render_gallery" / "image_metadata" / f"{shot_id}.json"
        shot_entry.setdefault("metadata", {})["metadata_path"] = str(metadata_path)

    image_path = shot_entry.get("image_path")
    if not image_path:
        image_path = str(ASSET_DIR / f"{shot_id}.jpg")
        shot_entry["image_path"] = image_path
    dest_path = Path(image_path)
    dest_path.parent.mkdir(parents=True, exist_ok=True)

    try:
        response = requests.get(image_url, timeout=30)
        response.raise_for_status()
        dest_path.write_bytes(response.content)
    except Exception as exc:
        logger.error("Failed to download replacement image: %s", exc)
        return JSONResponse({"error": f"Download failed: {exc}"}, status_code=502)

    hero_dir = BASE_DIR / "hero_refs"
    hero_dir.mkdir(parents=True, exist_ok=True)
    hero_lock_path = hero_dir / f"{shot_id}_LOCK.jpg"
    try:
        hero_lock_path.write_bytes(dest_path.read_bytes())
    except Exception as exc:
        logger.warning("Failed to update hero lock for %s: %s", shot_id, exc)

    meta = {}
    if metadata_path.exists():
        try:
            meta = json.loads(metadata_path.read_text())
        except json.JSONDecodeError:
            logger.warning("Corrupted metadata for %s; recreating", shot_id)
            meta = {}

    timestamp = datetime.utcnow().isoformat()
    meta["image_url"] = image_url
    meta["hero_image"] = str(dest_path)
    meta["timestamp"] = timestamp
    candidates = meta.get("candidate_urls") or []
    if isinstance(candidates, list) and image_url not in candidates:
        candidates.append(image_url)
        meta["candidate_urls"] = candidates
    metadata_path.parent.mkdir(parents=True, exist_ok=True)
    metadata_path.write_text(json.dumps(meta, indent=2))

    shot_entry["timestamp"] = timestamp
    manager.tracking["shots"][shot_id] = shot_entry
    manager._save_tracking()

    manager = refresh_gallery_state()
    payload = build_shot_payload(manager, shot_id)
    return {"status": "updated", "shot": payload}


