@app.post("/api/analyze-render")
async def analyze_render_endpoint(request: Dict = Body(...)):
    """Atlas analyzes its own render using DINO-v3 and logs findings"""
    render_id = request.get('render_id')
    image_path = request.get('image_path')
    reference_path = request.get('reference_path')  # Optional reference image

    logger.info(f"🤖 Atlas analyzing: {render_id}")

    analysis = {
        'render_id': render_id,
        'timestamp': datetime.now().isoformat(),
        'image_path': image_path,
        'reference_path': reference_path,
        'consistency_checks': {},
        'issues': [],
        'recommendations': [],
        'dino_enabled': False
    }

    try:
        # Import Phase-6 systems
        from dinov3_analyzer import get_analyzer
        from reference_manager import get_reference_manager
        from retry_manager import get_retry_manager

        analyzer = get_analyzer()
        ref_manager = get_reference_manager()
        retry_manager = get_retry_manager()

        analysis['dino_enabled'] = True
        analysis['phase6_enabled'] = True

        # Detect project from image path
        project = None
        if 'the_ledge_v2' in image_path:
            project = 'the_ledge_v2'
        elif 'the_ledge' in image_path:
            project = 'the_ledge'
        elif 'juice' in image_path:
            project = 'juice_ledger_test'

        # Try multi-reference analysis first
        if project:
            references = ref_manager.get_references(project)
            if references:
                logger.info(f"Running Phase-6 multi-reference analysis for {project}")
                logger.info(f"  Using {len(references)} reference types: {list(references.keys())}")
                scores = analyzer.analyze_multi_reference(image_path, references)
                analysis['consistency_checks'] = scores
                analysis['reference_type'] = 'multi-reference'
                analysis['references_used'] = list(references.keys())
            else:
                # Fallback to single reference
                logger.info(f"No multi-references found for {project}, using single reference")
                if reference_path and Path(reference_path).exists():
                    scores = analyzer.analyze_consistency(image_path, reference_path)
                    analysis['consistency_checks'] = scores
                    analysis['reference_type'] = 'single-reference'
                else:
                    # No references at all
                    analysis['consistency_checks'] = {
                        'character_face': 0.75,
                        'clothing': 0.75,
                        'location': 0.75,
                        'lighting': 0.75,
                        'overall': 0.75
                    }
                    analysis['reference_type'] = 'none'
        elif reference_path and Path(reference_path).exists():
            # Single reference fallback
            logger.info(f"Running single-reference analysis")
            scores = analyzer.analyze_consistency(image_path, reference_path)
            analysis['consistency_checks'] = scores
            analysis['reference_type'] = 'single-reference'
        else:
            # No references
            analysis['consistency_checks'] = {
                'character_face': 0.75,
                'clothing': 0.75,
                'location': 0.75,
                'lighting': 0.75,
                'overall': 0.75
            }
            analysis['reference_type'] = 'none'

        # Always add quality metrics
        logger.info("Running quality metrics analysis")
        quality = analyzer.analyze_quality(image_path)
        analysis['quality_metrics'] = quality

    except Exception as e:
        logger.warning(f"Phase-6 analysis failed: {e}, using placeholder scores")
        analysis['dino_error'] = str(e)
        analysis['phase6_enabled'] = False
        # Fallback to placeholder scores
        analysis['consistency_checks'] = {
            'character_face': 0.80,
            'clothing': 0.75,
            'location': 0.80,
            'lighting': 0.75,
            'overall': 0.77
        }

    analysis['status'] = 'analysis_complete'

    # Phase-6 thresholds (stricter than Phase-5)
    thresholds = {
        'character_face': 0.90,  # Phase-6: 90% (was 85%)
        'clothing': 0.85,  # Phase-6: 85% (was 80%)
        'location': 0.80,  # Phase-6: 80% (was 75%)
        'lighting': 0.75  # Phase-6: 75% (was 70%)
    }
    analysis['thresholds'] = thresholds

    # Check for issues and generate Phase-6 recommendations
    for key, threshold in thresholds.items():
        if key in analysis['consistency_checks']:
            score = analysis['consistency_checks'][key]
            if score < threshold:
                analysis['issues'].append(f"{key.replace('_', ' ').title()} below threshold: {score:.2%} < {threshold:.2%}")

                # Generate Phase-6 specific recommendations
                if key == 'character_face' or key == 'face':
                    analysis['recommendations'].append('Phase-6: Use dedicated face_reference.jpg with frontal angle')
                    analysis['recommendations'].append('Retry: Use 2K resolution and add face detail prompts')
                elif key == 'clothing':
                    analysis['recommendations'].append('Phase-6: Use dedicated clothing_reference.jpg showing full outfit')
                    analysis['recommendations'].append('Retry: Add "exact clothing from reference" to prompt')
                elif key == 'location' or key == 'background':
                    analysis['recommendations'].append('Phase-6: Use dedicated background_reference.jpg')
                    analysis['recommendations'].append('Retry: Add "matching environment and background" to prompt')
                elif key == 'lighting':
                    analysis['recommendations'].append('Phase-6: Use dedicated lighting_reference.jpg')
                    analysis['recommendations'].append('Retry: Lock time of day and lighting direction explicitly')

    # Check if retry needed (Phase-6)
    if analysis.get('phase6_enabled'):
        try:
            should_retry, failed_metrics = retry_manager.should_retry(
                render_id,
                analysis['consistency_checks'],
                thresholds
            )
            analysis['should_retry'] = should_retry
            analysis['failed_metrics'] = failed_metrics
            analysis['retry_attempts'] = len(retry_manager.get_retry_history(render_id))

            if should_retry:
                logger.info(f"🔄 Retry recommended for {render_id}: {len(failed_metrics)} metrics failed")
        except Exception as e:
            logger.warning(f"Retry check failed: {e}")
            analysis['should_retry'] = False

    # Auto-log
    log_dir = Path(str(BASE_DIR) + "/learning_memory/analyses")
    log_dir.mkdir(parents=True, exist_ok=True)

    log_file = log_dir / f"analysis_{render_id}_{datetime.now().strftime('%Y%m%d_%H%M%S')}.json"
    with open(log_file, 'w') as f:
        json.dump(analysis, f, indent=2)

    logger.info(f"✅ Analysis logged: {log_file}")

    # Auto-update master knowledge if issues found
    if analysis['issues']:
        await update_master_knowledge(analysis)

    return analysis


async def update_master_knowledge(analysis: Dict):
    """Auto-update master_knowledge.md with new findings"""
    try:
        knowledge_file = Path(str(BASE_DIR) + "/learning_memory/master_knowledge.md")

        # Read existing knowledge
        if knowledge_file.exists():
            with open(knowledge_file, 'r') as f:
                existing = f.read()
        else:
            existing = "# 🧠 MASTER KNOWLEDGE BASE - Autonomous Learning\n\n"

        # Create update entry
        timestamp = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
        update = f"\n## 🔬 DINO-v3 Analysis Update - {timestamp}\n"
        update += f"**Render:** {analysis['render_id']}\n"
        update += f"**Issues Found:** {len(analysis['issues'])}\n\n"

        for issue in analysis['issues']:
            update += f"- ⚠️ {issue}\n"

        update += f"\n**Recommendations:**\n"
        for rec in analysis['recommendations']:
            update += f"- 💡 {rec}\n"

        update += f"\n**Consistency Scores:**\n"
        for key, value in analysis['consistency_checks'].items():
            status = "✅" if value >= 0.80 else "⚠️" if value >= 0.70 else "❌"
            update += f"- {status} {key}: {value:.2%}\n"

        update += "\n---\n"

        # Append to knowledge base
        with open(knowledge_file, 'a') as f:
            f.write(update)

        logger.info(f"✅ Updated master_knowledge.md with {len(analysis['issues'])} new findings")

    except Exception as e:
        logger.error(f"Failed to update master_knowledge.md: {e}")



