@app.post("/api/trigger-autonomous-loop")
async def trigger_autonomous_loop(data: dict = Body(...)):
    """
    🔄 MASTER AUTONOMY RUNNER 2.0 TRIGGER
    Launches autonomous agent loop for concept-to-render pipeline
    """
    try:
        max_iterations = data.get('max_iterations', 10)
        background = data.get('background', True)

        logger.info(f"🚀 Triggering autonomous loop (max iterations: {max_iterations})")

        runner_script = Path(str(BASE_DIR) + "/master_autonomy_runner.py")

        if not runner_script.exists():
            return {
                "success": False,
                "error": "Master Autonomy Runner script not found"
            }

        if background:
            # Launch in background
            import subprocess
            process = subprocess.Popen(
                [sys.executable, str(runner_script)],
                stdout=subprocess.PIPE,
                stderr=subprocess.PIPE,
                text=True
            )

            return {
                "success": True,
                "message": f"Autonomous loop launched in background (PID: {process.pid})",
                "pid": process.pid,
                "max_iterations": max_iterations
            }
        else:
            # Run synchronously (blocks until complete)
            import subprocess
            result = subprocess.run(
                [sys.executable, str(runner_script)],
                capture_output=True,
                text=True,
                timeout=7200  # 2 hour timeout
            )

            return {
                "success": result.returncode == 0,
                "message": "Autonomous loop completed",
                "output": result.stdout,
                "errors": result.stderr if result.returncode != 0 else None
            }

    except Exception as e:
        logger.error(f"Failed to trigger autonomous loop: {e}")
        return {
            "success": False,
            "error": str(e)
        }


@app.get("/api/autonomous-loop-status")
async def get_autonomous_loop_status():
    """Check status of autonomous loop execution"""
    try:
        state_file = Path(str(BASE_DIR) + "/atlas_state.json")

        if not state_file.exists():
            return {
                "status": "never_run",
                "message": "Autonomous loop has not been executed yet"
            }

        with open(state_file, 'r') as f:
            state = json.load(f)

        return {
            "status": "available",
            "current_concept": state.get('current_concept'),
            "completed_concepts": state.get('completed_concepts', []),
            "loop_count": state.get('loop_count', 0),
            "last_run": state.get('last_run')
        }

    except Exception as e:
        logger.error(f"Failed to get autonomous loop status: {e}")
        return {
            "status": "error",
            "error": str(e)
        }


# ============================================================================
# AUTO STUDIO PROJECT ENDPOINTS (V15.4)
# ============================================================================

# V30.1: Cache projects list — avoids re-parsing 5MB ravencroft shot_plan on every poll
_PROJECTS_LIST_CACHE: dict = {}  # {"data": [...], "ts": float}
_PROJECTS_LIST_TTL = 30  # seconds

@app.get("/api/auto/projects")
async def list_auto_projects():
    """List all projects available for Auto Studio."""
    import time as _ptime
    _cached = _PROJECTS_LIST_CACHE.get("data")
    if _cached and (_ptime.time() - _PROJECTS_LIST_CACHE.get("ts", 0)) < _PROJECTS_LIST_TTL:
        return {"projects": _cached, "from_cache": True}

    projects = []
    pipeline_dir = PIPELINE_OUTPUTS_DIR

    for project_path in sorted(pipeline_dir.iterdir()):
        if not project_path.is_dir():
            continue
        if project_path.name.startswith(('.', '_')):
            continue

        shot_plan = project_path / "shot_plan.json"
        story_bible = project_path / "story_bible.json"

        project_info = {
            "name": project_path.name,
            "project": project_path.name,  # UI expects 'project' field
            "has_shot_plan": shot_plan.exists(),
            "has_story_bible": story_bible.exists(),
            "modified": project_path.stat().st_mtime if project_path.exists() else 0
        }

        # Load basic metadata if shot_plan exists
        if shot_plan.exists():
            try:
                with open(shot_plan) as f:
                    data = json.load(f)
                # Bare-list guard: shot_plan.json may be a bare list
                if isinstance(data, list):
                    shots_list = data
                    meta = {}
                else:
                    shots_list = data.get("shots", [])
                    meta = data.get("metadata", {})
                project_info["shot_count"] = len(shots_list)
                # Count unique scene IDs from shot_ids (e.g. "001_M01" → scene "001")
                scene_ids = set(s.get("shot_id", "")[:3] for s in shots_list if s.get("shot_id", "")[:3].isdigit())
                project_info["scene_count"] = len(scene_ids) if scene_ids else len(data.get("scenes", data.get("scene_manifest", [])) if isinstance(data, dict) else [])
                project_info["title"] = meta.get("title", project_path.name)
                project_info["genre"] = meta.get("genre", "unknown")
                project_info["total_duration"] = meta.get("total_duration_seconds", 0)
            except Exception:
                pass

        projects.append(project_info)

    # Sort by modification time (newest first)
    projects.sort(key=lambda x: x.get("modified", 0), reverse=True)

    # V30.1: Cache result to avoid re-parsing large shot_plans on every poll
    import time as _ptime2
    _PROJECTS_LIST_CACHE["data"] = projects
    _PROJECTS_LIST_CACHE["ts"] = _ptime2.time()

    return {"projects": projects}


@app.get("/api/auto/projects/")
async def list_auto_projects_trailing():
    return await list_auto_projects()


@app.get("/api/auto/projects/load/{project_name}")
async def load_auto_project(project_name: str):
    """Load a specific project's shot plan and metadata."""
    pipeline_dir = PIPELINE_OUTPUTS_DIR
    project_path = pipeline_dir / project_name

    if not project_path.exists():
        return {"error": f"Project '{project_name}' not found"}

    result = {
        "project": project_name,
        "source": "pipeline_outputs"
    }

    # Load shot plan (also serves as manifest)
    shot_plan_path = project_path / "shot_plan.json"
    if shot_plan_path.exists():
        try:
            with open(shot_plan_path) as f:
                shot_plan_data = json.load(f)
                result["shot_plan"] = shot_plan_data
                # UI also expects 'manifest' which is the same as shot_plan
                result["manifest"] = shot_plan_data
        except Exception as e:
            result["shot_plan_error"] = str(e)

    # Load story bible
    story_bible_path = project_path / "story_bible.json"
    if story_bible_path.exists():
        try:
            with open(story_bible_path) as f:
                story_bible_data = json.load(f)
                result["story_bible"] = story_bible_data
                # Add scene count to story bible if not present
                if "scene_count" not in story_bible_data:
                    scenes = story_bible_data.get("scenes", [])
                    story_bible_data["scene_count"] = len(scenes) if isinstance(scenes, list) else 0
                # V16.7.1 FIX: Normalize locations - populate from setting.locations or scenes if empty
                if not story_bible_data.get("locations"):
                    # Fallback 1: setting.locations
                    if story_bible_data.get("setting", {}).get("locations"):
                        story_bible_data["locations"] = [
                            {"name": loc, "source": "setting"} if isinstance(loc, str) else loc
                            for loc in story_bible_data["setting"]["locations"]
                        ]
                    # Fallback 2: Extract from scenes
                    elif story_bible_data.get("scenes"):
                        seen_locs = set()
                        for scene in story_bible_data["scenes"]:
                            if scene.get("location"):
                                seen_locs.add(scene["location"])
                        story_bible_data["locations"] = [
                            {"name": loc, "source": "scenes"} for loc in sorted(seen_locs)
                        ]
        except Exception as e:
            result["story_bible_error"] = str(e)

    # Load character library
    char_lib_path = project_path / "character_library.json"
    if char_lib_path.exists():
        try:
            with open(char_lib_path) as f:
                result["character_library"] = json.load(f)
        except Exception as e:
            pass

    # V16.2.1: Load cast_map.json (critical for UI casting display)
    # V16.5: Auto-trigger casting if no cast_map exists
    cast_map_path = project_path / "cast_map.json"
    if cast_map_path.exists():
        try:
            with open(cast_map_path) as f:
                cast_data = json.load(f)
                # Filter out metadata keys starting with _
                result["cast"] = {k: v for k, v in cast_data.items() if not k.startswith("_")}
        except Exception as e:
            result["cast_error"] = str(e)
    else:
        # V16.5: No cast_map exists - auto-trigger casting
        result["cast"] = {}
        try:
            logger.info(f"[LOAD] No cast_map found for {project_name}, triggering auto-cast...")
            cast_result = await auto_cast_project({"project": project_name})
            if cast_result.get("success"):
                # Reload cast_map after auto-cast
                if cast_map_path.exists():
                    with open(cast_map_path) as f:
                        cast_data = json.load(f)
                        result["cast"] = {k: v for k, v in cast_data.items() if not k.startswith("_")}
                result["auto_cast_triggered"] = True
                logger.info(f"[LOAD] Auto-cast completed: {len(result['cast'])} characters cast")
        except Exception as e:
            logger.warning(f"[LOAD] Auto-cast failed: {e}")

    # Load renders if available
    renders = []
    for img_dir in ["first_frames", "renders", "images"]:
        img_path = project_path / img_dir
        if img_path.exists():
            for img_file in [f for ext in ["*.jpg","*.jpeg","*.png","*.webp"] for f in img_path.glob(ext)]:
                renders.append({
                    "path": str(img_file),
                    "filename": img_file.name,
                    "shot_id": img_file.stem
                })
    result["renders"] = renders

    # Load videos if available
    videos = []
    for vid_dir in ["videos", "rendered"]:
        vid_path = project_path / vid_dir
        if vid_path.exists():
            for vid_file in [f for ext in ["*.mp4","*.mov","*.webm"] for f in vid_path.glob(ext)]:
                videos.append({
                    "path": str(vid_file),
                    "filename": vid_file.name,
                    "shot_id": vid_file.stem
                })
    result["videos"] = videos

    return result


@app.get("/api/auto/projects/load/")
async def load_auto_project_missing(project: str = Query("")):
    if not project:
        return {"error": "project parameter required"}
    return await load_auto_project(project)


@app.post("/api/auto/projects/save")
async def save_auto_project(request: Dict = Body(...)):
    """Save project data to shot_plan.json."""
    project_name = request.get("project")
    data = request.get("data", {})

    if not project_name:
        return {"error": "Project name required"}

    pipeline_dir = PIPELINE_OUTPUTS_DIR
    project_path = pipeline_dir / project_name
    project_path.mkdir(parents=True, exist_ok=True)

    shot_plan_path = project_path / "shot_plan.json"

    # Backup existing
    if shot_plan_path.exists():
        backup_path = shot_plan_path.with_suffix(f".json.backup_{datetime.now().strftime('%Y%m%d_%H%M%S')}")
        import shutil
        shutil.copy(shot_plan_path, backup_path)

    # Save new data
    with open(shot_plan_path, 'w') as f:
        json.dump(data, f, indent=2)

    return {"success": True, "project": project_name, "path": str(shot_plan_path)}


@app.delete("/api/auto/projects/{project_name}")
async def delete_project(project_name: str):
    """Delete entire project folder."""
    import shutil

    if not project_name or project_name in ['', '.', '..']:
        return {"error": "Invalid project name"}

    project_path = get_project_path(project_name)

    if not project_path.exists():
        return {"error": f"Project '{project_name}' not found", "success": False}

    # Safety check - ensure it's under pipeline_outputs
    if PIPELINE_OUTPUTS_DIR not in project_path.parents and project_path.parent != PIPELINE_OUTPUTS_DIR:
        return {"error": "Invalid project path", "success": False}

    try:
        shutil.rmtree(project_path)
        return {"success": True, "deleted": project_name, "message": f"Project '{project_name}' deleted"}
    except Exception as e:
        return {"error": str(e), "success": False}


@app.post("/api/auto/projects/{project_name}/clear-verification")
async def clear_project_verification(project_name: str):
    """Clear verification state for a project."""
    project_path = get_project_path(project_name)

    if not project_path.exists():
        return {"error": f"Project '{project_name}' not found"}

    # Clear verification files
    cleared = []
    for vfile in ['cast_map.json', 'verification_state.json', 'character_refs.json', 'location_masters.json']:
        vpath = project_path / vfile
        if vpath.exists():
            vpath.unlink()
            cleared.append(vfile)

    return {"success": True, "project": project_name, "cleared": cleared}


@app.post("/api/auto/projects/{project_name}/reset")
async def reset_project(project_name: str):
    """Reset project - keep story bible but clear shots, verification, renders."""
    import shutil

    project_path = get_project_path(project_name)

    if not project_path.exists():
        return {"error": f"Project '{project_name}' not found"}

    cleared = []

    # Clear shot plan
    shot_plan = project_path / "shot_plan.json"
    if shot_plan.exists():
        shot_plan.unlink()
        cleared.append("shot_plan.json")

    # Clear verification files
    for vfile in ['cast_map.json', 'verification_state.json', 'character_refs.json', 'location_masters.json']:
        vpath = project_path / vfile
        if vpath.exists():
            vpath.unlink()
            cleared.append(vfile)

    # Clear render directories
    for render_dir in ['renders', 'videos', 'first_frames', 'thumbnails']:
        rpath = project_path / render_dir
        if rpath.exists():
            shutil.rmtree(rpath)
            cleared.append(f"{render_dir}/")

    return {"success": True, "project": project_name, "cleared": cleared, "kept": ["story_bible.json"]}


@app.post("/api/v21/fumigation/{project_name}")
async def fumigate_project(project_name: str, request: Dict = Body(default={})):
    """V21.9: FULL FUMIGATION PROTOCOL — Clean room for fresh pipeline run.

    Archives ALL pipeline artifacts to timestamped archive folder, then provides
    a pristine environment. Story bible is preserved (it's the source of truth).

    Options:
        keep_story_bible: bool (default True) — preserve story_bible.json
        keep_cast: bool (default False) — preserve cast_map.json + character refs
        keep_locations: bool (default False) — preserve location_masters/
        archive: bool (default True) — archive old data (vs delete)

    This is the "no old anything" button.
    """
    import shutil
    from datetime import datetime

    project_path = get_project_path(project_name)
    if not project_path.exists():
        return {"error": f"Project '{project_name}' not found"}

    keep_story_bible = request.get("keep_story_bible", True)
    keep_cast = request.get("keep_cast", False)
    keep_locations = request.get("keep_locations", False)
    do_archive = request.get("archive", True)

    timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")
    archive_dir = project_path / f"archive_fumigation_{timestamp}"

    archived = []
    cleared = []
    kept = []

    # Files that get fumigated (pipeline artifacts that can contaminate)
    FUMIGATE_FILES = [
        "shot_plan.json", "wardrobe.json", "extras.json",
        "emotion_layer.json", "scene_classifications.json",
        "chain_metadata.json", "stitch_manifest.json", "stitch_ready.json",
        "edit_decisions.json", "edit_timeline.json", "freeze_verdict.json",
        "verification_state.json", "dry_run_manifest.json",
        "director_overrides.json", "character_locks.json", "master_locks.json",
        "run_manifest.json", "regression_history.json",
        "_agent_status.json", "_live_jobs.json",
    ]

    # Optionally fumigate cast
    if not keep_cast:
        FUMIGATE_FILES.extend(["cast_map.json", "cast_report.json", "character_library.json", "character_profiles.json"])
    else:
        kept.extend(["cast_map.json", "cast_report.json"])

    # Always keep story bible (it's the canonical source)
    if keep_story_bible:
        kept.append("story_bible.json")
    else:
        FUMIGATE_FILES.append("story_bible.json")

    # Directories that get fumigated
    FUMIGATE_DIRS = [
        "ui_cache", "first_frame_variants", "videos", "videos_kling",
        "stitched_scenes", ".vision_cache",
    ]

    if not keep_locations:
        FUMIGATE_DIRS.append("location_masters")
    else:
        kept.append("location_masters/")

    if not keep_cast:
        FUMIGATE_DIRS.append("character_library_locked")
    else:
        kept.append("character_library_locked/")

    # Archive if requested
    if do_archive:
        archive_dir.mkdir(parents=True, exist_ok=True)

    # Fumigate files
    for fname in FUMIGATE_FILES:
        fpath = project_path / fname
        if fpath.exists():
            if do_archive:
                shutil.copy2(str(fpath), str(archive_dir / fname))
                archived.append(fname)
            fpath.unlink()
            cleared.append(fname)

    # Fumigate chain checkpoints
    for cp in project_path.glob("chain_checkpoint_*.json"):
        if do_archive:
            shutil.copy2(str(cp), str(archive_dir / cp.name))
            archived.append(cp.name)
        cp.unlink()
        cleared.append(cp.name)

    # Fumigate shot_plan backups (legacy contamination source)
    for bk in project_path.glob("shot_plan*.json"):
        if bk.name == "shot_plan.json":
            continue  # Already handled above
        if do_archive:
            shutil.copy2(str(bk), str(archive_dir / bk.name))
            archived.append(bk.name)
        bk.unlink()
        cleared.append(bk.name)

    # Fumigate directories
    for dname in FUMIGATE_DIRS:
        dpath = project_path / dname
        if dpath.exists():
            if do_archive:
                shutil.copytree(str(dpath), str(archive_dir / dname), dirs_exist_ok=True)
                archived.append(f"{dname}/")
            shutil.rmtree(str(dpath))
            cleared.append(f"{dname}/")

    # First frames: archive but DON'T delete (user may want to keep approved frames)
    ff_path = project_path / "first_frames"
    if ff_path.exists():
        if do_archive:
            shutil.copytree(str(ff_path), str(archive_dir / "first_frames"), dirs_exist_ok=True)
            archived.append("first_frames/ (archived, kept in place)")
        # Don't delete first_frames — they're expensive to regenerate
        kept.append("first_frames/")

    logger.info(f"[V21.9 FUMIGATION] {project_name}: cleared {len(cleared)} artifacts, archived {len(archived)}, kept {len(kept)}")

    return {
        "success": True,
        "project": project_name,
        "fumigation_timestamp": timestamp,
        "archive_dir": str(archive_dir) if do_archive else None,
        "cleared": cleared,
        "archived": archived,
        "kept": kept,
        "next_steps": [
            "POST /api/v6/script/full-import (re-import script)",
            "POST /api/auto/generate-story-bible (regenerate beats)",
            "POST /api/shot-plan/fix-v16 (rebuild shot metadata)",
            "POST /api/v6/casting/auto-cast (re-cast characters)",
            "POST /api/auto/generate-first-frames (generate frames)",
        ]
    }


