# ═══════════════════════════════════════════════════════════════════════════════
# V22.5: SAFE-ONLY CHECK 7 — Non-destructive metadata fixes
# Does: name normalization, CHILD V.O., intercut separation, scene alignment,
#       character population, camera defaults, character/location ref attachment
# Does NOT: touch nano_prompt text, ltx_motion_prompt text, durations, or segments
# ═══════════════════════════════════════════════════════════════════════════════
@app.post("/api/v22/safe-fix/{project}")
async def safe_fix_v22(project: str):
    """
    V22.5 SAFE FIX — Runs ONLY non-destructive checks from fix-v16.
    Your prompts, durations, and LTX motion are LEFT UNTOUCHED.

    What it does:
    - CHECK 7A: Character name normalization (EVELYN → EVELYN RAVENCROFT)
    - CHECK 7B: CHILD V.O. tagging (strip from characters, mark _child_vo)
    - CHECK 7C: Intercut separation (1 character per phone call shot)
    - CHECK 7D: Scene alignment (manifest stubs for orphan scenes)
    - CHECK 7E: Character population from dialogue + landscape safety flags
    - Camera defaults (ARRI Alexa + Cooke S7/i per shot type)
    - Character reference URL from cast_map
    - Location master URL attachment
    - Wardrobe auto-assign (if not already done)

    What it does NOT do:
    - Does NOT rewrite nano_prompt or ltx_motion_prompt text
    - Does NOT change durations or segments
    - Does NOT run duration rebalancer or ABC expansion
    - Does NOT run INTELLIGENT_PROMPT_ENHANCER
    - Does NOT inject cinematic prefixes/suffixes
    - Does NOT inject humanism/breathing/micro-expressions
    - Does NOT rebuild LTX timing
    """
    project_path = get_project_path(project)
    shot_plan_path = project_path / "shot_plan.json"
    if not shot_plan_path.exists():
        return {"success": False, "error": f"Project '{project}' not found"}

    with open(shot_plan_path) as f:
        data = json.load(f)
    shots = data.get("shots", [])
    fixes = []

    # Load cast_map
    cast_map = {}
    cast_map_path = project_path / "cast_map.json"
    if cast_map_path.exists():
        try:
            with open(cast_map_path) as f:
                cast_map = json.load(f)
        except Exception:
            pass

    # Load AI actors
    ai_actors = {}
    ai_actors_path = BASE_DIR / "ai_actors_library.json"
    if ai_actors_path.exists():
        try:
            with open(ai_actors_path) as f:
                actors_data = json.load(f)
                for actor in actors_data.get("actors", []):
                    ai_actors[actor.get("name", "").upper()] = actor
                    if actor.get("id"):
                        ai_actors[str(actor.get("id"))] = actor
        except Exception:
            pass

    # Load location masters
    location_masters = {}
    loc_masters_dir = project_path / "location_masters"
    if loc_masters_dir.exists():
        for img in loc_masters_dir.glob("*.*"):
            if img.suffix.lower() in [".jpg", ".jpeg", ".png", ".webp"]:
                loc_name = img.stem.upper().replace("_", " ")
                location_masters[loc_name] = f"/api/media?path={img}"

    # ── CHECK 7A: NAME NORMALIZATION ──
    try:
        _config = get_project_config(project_name)
        _NAME_NORM = _config.name_norm_map
    except Exception:
        _NAME_NORM = {}

    _name_fixes = 0
    for shot in shots:
        chars = shot.get("characters", [])
        new_chars = []
        changed = False
        for c in chars:
            cu = c.upper().strip()
            if cu in _NAME_NORM:
                new_chars.append(_NAME_NORM[cu])
                changed = True
            else:
                new_chars.append(c)
        if changed:
            shot["characters"] = new_chars
            _name_fixes += 1
    if _name_fixes:
        fixes.append(f"CHECK_7A: {_name_fixes} shots — character names normalized")

    # ── CHECK 7B: CHILD V.O. TAGGING ──
    _child_fixes = 0
    for shot in shots:
        chars = shot.get("characters", [])
        has_child = any("CHILD" in c.upper() for c in chars)
        if has_child:
            shot["characters"] = [c for c in chars if "CHILD" not in c.upper()]
            dlg = shot.get("dialogue_text", "") or ""
            if dlg and "CHILD" in dlg.upper():
                shot["_child_vo"] = True
                shot["_vo_character"] = "CHILD"
            _child_fixes += 1
    if _child_fixes:
        fixes.append(f"CHECK_7B: {_child_fixes} shots — CHILD stripped, marked V.O.")

    # ── CHECK 7C: INTERCUT SEPARATION ──
    _intercut_fixes = 0
    manifest_list = data.get("scene_manifest", [])
    intercut_scenes = {}
    for sc in manifest_list:
        if not isinstance(sc, dict):
            continue
        if not (sc.get("_intercut") or sc.get("is_intercut")):
            continue
        sid = sc.get("scene_id", "")
        secondary_loc = sc.get("secondary_location", "")
        if not sid or not secondary_loc:
            continue
        raw_map = sc.get("intercut_location_map", {})
        full_map = {}
        for cn, loc in raw_map.items():
            full_name = _NAME_NORM.get(cn.upper().strip(), cn.upper().strip())
            full_map[full_name] = loc
        # Auto-assign from dialogue order
        all_scene_chars = set()
        first_speaker = None
        second_speaker = None
        for shot in shots:
            if shot.get("scene_id") == sid:
                for c in shot.get("characters", []):
                    cu = c.upper().strip()
                    all_scene_chars.add(cu)
                    if shot.get("dialogue_text") or shot.get("dialogue_beats"):
                        if first_speaker is None:
                            first_speaker = cu
                        elif cu != first_speaker and second_speaker is None:
                            second_speaker = cu
        primary_loc = sc.get("location", "")
        for asc in all_scene_chars:
            if asc not in full_map:
                if second_speaker and asc == second_speaker:
                    full_map[asc] = secondary_loc
                else:
                    full_map[asc] = primary_loc
        if full_map:
            intercut_scenes[sid] = full_map
            sc["intercut_location_map"] = full_map

    for shot in shots:
        sid = shot.get("scene_id", "")
        if sid not in intercut_scenes:
            continue
        ic_map = intercut_scenes[sid]
        chars = shot.get("characters", [])
        if len(chars) > 1:
            # Pick primary from first character mentioned
            vis_char = chars[0].upper().strip()
            shot["characters"] = [c for c in chars if c.upper().strip() == vis_char]
            vo_chars = [c for c in chars if c.upper().strip() != vis_char]
            if vo_chars:
                shot["_intercut_vo_characters"] = vo_chars
                shot["_intercut"] = True
            new_loc = ic_map.get(vis_char)
            if new_loc and shot.get("location") != new_loc:
                shot["location"] = new_loc
                _intercut_fixes += 1
    if _intercut_fixes:
        fixes.append(f"CHECK_7C: {_intercut_fixes} shots — intercut locations assigned")

    # ── CHECK 7D: SCENE ALIGNMENT ──
    shot_scenes = set(s.get("scene_id", "") for s in shots if s.get("scene_id"))
    manifest_scenes = set(sc.get("scene_id", "") for sc in manifest_list if isinstance(sc, dict))
    missing = shot_scenes - manifest_scenes
    if missing:
        for ms in sorted(missing):
            first_shot = next((s for s in shots if s.get("scene_id") == ms), None)
            manifest_list.append({
                "scene_id": ms,
                "location": first_shot.get("location", "UNKNOWN") if first_shot else "UNKNOWN",
                "characters": list(set(c for s in shots if s.get("scene_id") == ms for c in s.get("characters", []))),
                "_auto_created": True,
                "_created_by": "safe-fix-v22"
            })
        data["scene_manifest"] = manifest_list
        fixes.append(f"CHECK_7D: {len(missing)} missing scenes added to manifest")

    # ── CHECK 7E: POPULATE CHARACTERS FROM DIALOGUE ──
    import re as _re_7e
    _char_pop = 0
    for shot in shots:
        chars = shot.get("characters", [])
        dlg = (shot.get("dialogue_text", "") or shot.get("dialogue", "") or "").strip()
        if (not chars or len(chars) == 0) and dlg and not shot.get("_child_vo"):
            dlg_chars = _re_7e.findall(r'^([A-Z][A-Z\s.]+?):', dlg, _re_7e.MULTILINE)
            resolved = []
            seen = set()
            for dc in dlg_chars:
                dc_clean = dc.strip().upper()
                dc_full = _NAME_NORM.get(dc_clean, dc_clean)
                if dc_full not in seen:
                    seen.add(dc_full)
                    resolved.append(dc_full)
            if resolved:
                shot["characters"] = resolved
                _char_pop += 1
    if _char_pop:
        fixes.append(f"CHECK_7E: {_char_pop} shots — characters populated from dialogue")

    # ── CAMERA DEFAULTS (metadata only, no prompt changes) ──
    CAMERA_DEFAULTS_BY_TYPE = {
        "wide":          {"camera_body": "ARRI Alexa 35", "lens_specs": "24mm", "camera_style": "static", "lens_type": "Cooke S7/i Prime"},
        "establishing":  {"camera_body": "ARRI Alexa 35", "lens_specs": "14mm", "camera_style": "slow_crane", "lens_type": "Anamorphic 2x"},
        "medium":        {"camera_body": "ARRI Alexa 35", "lens_specs": "50mm", "camera_style": "static", "lens_type": "Cooke S7/i Prime"},
        "close":         {"camera_body": "ARRI Alexa 35", "lens_specs": "85mm", "camera_style": "static", "lens_type": "Cooke S7/i Prime"},
        "reaction":      {"camera_body": "ARRI Alexa 35", "lens_specs": "85mm", "camera_style": "static", "lens_type": "Cooke S7/i Prime"},
        "insert":        {"camera_body": "ARRI Alexa 35", "lens_specs": "100mm", "camera_style": "static", "lens_type": "Cooke S7/i Prime"},
    }
    _cam_fixes = 0
    for shot in shots:
        st = (shot.get("shot_type") or shot.get("type") or "medium").lower()
        defaults = CAMERA_DEFAULTS_BY_TYPE.get(st, CAMERA_DEFAULTS_BY_TYPE["medium"])
        applied = False
        for field, val in defaults.items():
            if shot.get(field) != val:
                shot[field] = val
                applied = True
        if applied:
            _cam_fixes += 1
    if _cam_fixes:
        fixes.append(f"CAMERA_DEFAULTS: {_cam_fixes} shots — ARRI Alexa + Cooke S7/i applied")

    # ── CHARACTER REFERENCE URLs from cast_map ──
    _ref_fixes = 0
    for shot in shots:
        chars = shot.get("characters", [])
        if not chars or not cast_map:
            continue
        first_char = chars[0].upper().strip() if isinstance(chars[0], str) else chars[0].get("name", "").upper().strip()
        actor_data = None
        for char_key, actor_val in cast_map.items():
            if char_key.startswith("_"):
                continue
            if first_char in char_key.upper() or char_key.upper() in first_char:
                actor_data = actor_val
                break
        if actor_data and isinstance(actor_data, dict):
            headshot_url = (
                actor_data.get("reference_url") or
                actor_data.get("headshot_url") or
                actor_data.get("locked_reference_url")
            )
            if not headshot_url:
                actor_id = actor_data.get("ai_actor_id") or actor_data.get("id")
                if actor_id:
                    actor = ai_actors.get(str(actor_id))
                    if actor:
                        headshot_url = actor.get("headshot_url") or actor.get("headshot")
            if headshot_url and shot.get("character_reference_url") != headshot_url:
                shot["character_reference_url"] = headshot_url
                _ref_fixes += 1
    if _ref_fixes:
        fixes.append(f"CHAR_REFS: {_ref_fixes} shots — character reference URLs attached")

    # ── LOCATION MASTER URLs ──
    _loc_fixes = 0
    if location_masters:
        import re as _re_loc
        for shot in shots:
            shot_loc = shot.get("location", "")
            if not shot_loc or shot.get("location_master_url"):
                continue
            shot_loc_clean = _re_loc.sub(
                r'\s*[-–]\s*(NIGHT|DAY|EVENING|MORNING|AFTERNOON|DAWN|DUSK).*$', '',
                shot_loc.upper(), flags=_re_loc.IGNORECASE
            ).strip()
            best_match = None
            best_score = 0
            for loc_name, loc_url in location_masters.items():
                loc_clean = loc_name.replace(" MASTER", "").strip().upper()
                if loc_clean == shot_loc_clean:
                    best_match = loc_url
                    best_score = 100
                    break
                if len(loc_clean) >= 8 and loc_clean in shot_loc_clean:
                    score = 50 + len(loc_clean)
                    if score > best_score:
                        best_match = loc_url
                        best_score = score
            if best_match and best_score >= 45:
                shot["location_master_url"] = best_match
                _loc_fixes += 1
    if _loc_fixes:
        fixes.append(f"LOC_MASTERS: {_loc_fixes} shots — location master URLs attached")

    # ── WARDROBE AUTO-ASSIGN (if not done) ──
    wardrobe_path = project_path / "wardrobe.json"
    _wardrobe_status = "already_exists"
    if not wardrobe_path.exists():
        try:
            from atlas_agents.wardrobe_extras_agent import auto_assign_wardrobe, auto_assign_extras
            story_bible = {}
            sb_path = project_path / "story_bible.json"
            if sb_path.exists():
                with open(sb_path) as f:
                    story_bible = json.load(f)
            wardrobe = auto_assign_wardrobe(project_path, shots, story_bible, cast_map)
            extras = auto_assign_extras(project_path, shots, story_bible)
            _wardrobe_status = f"created ({len(wardrobe.get('looks', {}))} looks, {len(extras.get('scene_extras', {}))} scenes)"
            fixes.append(f"WARDROBE: Auto-assigned — {_wardrobe_status}")
        except Exception as e:
            _wardrobe_status = f"error: {e}"
            fixes.append(f"WARDROBE: Error — {e}")

    # ── SAVE ──
    data["shots"] = shots
    stamp_metadata(data, action="safe_fix_v22")

    # Invalidate cache
    cache_dir = project_path / "ui_cache"
    dirty_file = cache_dir / ".dirty"
    if cache_dir.exists():
        dirty_file.touch()

    # Atomic save
    import tempfile as _tf
    tmp = _tf.NamedTemporaryFile(mode='w', dir=str(project_path), suffix='.tmp', delete=False)
    json.dump(data, tmp, indent=2)
    tmp.close()
    os.replace(tmp.name, str(shot_plan_path))

    logger.info(f"[SAFE-FIX V22] {project}: {len(fixes)} fixes applied — prompts/durations UNTOUCHED")

    return {
        "success": True,
        "project": project,
        "fixes_applied": len(fixes),
        "fixes": fixes,
        "shots_total": len(shots),
        "prompts_modified": 0,
        "durations_modified": 0,
        "note": "Prompts and durations were NOT touched. Only metadata, refs, and CHECK 7 normalization."
    }


@app.post("/api/v21/audit/{project_name}")
async def run_audit_endpoint(project_name: str):
    """
    Run full Movie Lock audit — checks ALL contracts.
    Returns PASS/FAIL with detailed violations per contract.
    Generation should be BLOCKED if any critical violations exist.
    """
    from tools.movie_lock_mode import run_full_audit
    project_path = get_project_path(project_name)
    if not project_path.exists():
        return {"error": f"Project '{project_name}' not found"}

    shot_plan_path = project_path / "shot_plan.json"
    if not shot_plan_path.exists():
        return {"error": "No shot_plan.json found"}

    with open(shot_plan_path) as f:
        data = json.load(f)
    shots = data.get("shots", data) if isinstance(data, dict) else data
    manifest = data.get("scene_manifest", []) if isinstance(data, dict) else []

    report = run_full_audit(shots, manifest, project_path, project_name)
    return report


@app.post("/api/v25/creative-audit/{project_name}")
async def creative_audit_endpoint(project_name: str, request: Dict = Body(default={})):
    """
    V25.1 Creative Prompt Compiler audit — scores EVERY shot on 6 disciplines.
    Returns per-shot scores, contamination rate, and batch decontamination option.

    Options:
        scene_filter: list of scene_ids to audit (default: all)
        auto_fix: if true, decontaminates generic prompts in-place (default: false)
    """
    project_path = get_project_path(project_name)
    if not project_path.exists():
        return {"error": f"Project '{project_name}' not found"}

    shot_plan_path = project_path / "shot_plan.json"
    if not shot_plan_path.exists():
        return {"error": "No shot_plan.json found"}

    with open(shot_plan_path) as f:
        data = json.load(f)
    shots = data.get("shots", data) if isinstance(data, dict) else data

    scene_filter = request.get("scene_filter", [])
    auto_fix = request.get("auto_fix", False)

    if scene_filter:
        shots = [s for s in shots if str(s.get("scene_id", s.get("shot_id", "").split("_")[0])) in [str(sf) for sf in scene_filter]]

    try:
        from tools.creative_prompt_compiler import audit_all_prompts, decontaminate_all_prompts
        audit_report = audit_all_prompts(shots)

        if auto_fix:
            # Load story bible for decontamination
            sb_path = project_path / "story_bible.json"
            story_bible = {}
            if sb_path.exists():
                with open(sb_path) as f:
                    story_bible = json.load(f)

            fix_count = decontaminate_all_prompts(shots, story_bible)
            audit_report["auto_fix_applied"] = True
            audit_report["shots_decontaminated"] = fix_count

            # Persist if fixes were made
            if fix_count > 0:
                import tempfile as _tf_cpc
                _cpc_tmp = _tf_cpc.NamedTemporaryFile(mode='w', dir=str(project_path), suffix='.json', delete=False)
                if isinstance(data, dict):
                    data["shots"] = shots
                    json.dump(data, _cpc_tmp, indent=2)
                else:
                    json.dump(shots, _cpc_tmp, indent=2)
                _cpc_tmp.close()
                os.replace(_cpc_tmp.name, str(shot_plan_path))
                # Invalidate bundle cache
                dirty_path = project_path / "ui_cache" / ".dirty"
                dirty_path.parent.mkdir(exist_ok=True)
                dirty_path.touch()

        return audit_report

    except ImportError:
        return {"error": "Creative Prompt Compiler not available — install tools/creative_prompt_compiler.py"}
    except Exception as e:
        logger.error(f"[V25] Creative audit failed: {e}")
        return {"error": str(e)}


@app.post("/api/v25/editorial-plan/{project_name}")
async def editorial_plan_endpoint(project_name: str, request: Dict = Body(default={})):
    """
    V25.2 Editorial Intelligence — analyze shots for frame reuse, B-roll overlays, and hold opportunities.

    Options:
        scene_filter: list of scene_ids to analyze (default: all)
        apply_tags: if true, tags shots with editorial metadata (default: false)
    """
    project_path = get_project_path(project_name)
    if not project_path.exists():
        return {"error": f"Project '{project_name}' not found"}

    shot_plan_path = project_path / "shot_plan.json"
    if not shot_plan_path.exists():
        return {"error": "No shot_plan.json found"}

    with open(shot_plan_path) as f:
        data = json.load(f)
    shots = data.get("shots", data) if isinstance(data, dict) else data

    scene_filter = request.get("scene_filter", [])
    apply_tags_flag = request.get("apply_tags", False)

    try:
        from tools.editorial_intelligence import (
            build_editorial_plan, apply_editorial_tags, editorial_report,
            filter_shots_for_generation
        )
        from collections import defaultdict

        # Group by scene
        scenes = defaultdict(list)
        for s in shots:
            sid = s.get("scene_id", s.get("shot_id", "").split("_")[0])
            scenes[sid].append(s)

        if scene_filter:
            scenes = {k: v for k, v in scenes.items() if str(k) in [str(sf) for sf in scene_filter]}

        all_plans = []
        total_reuse = 0
        total_overlay = 0
        total_hold = 0
        total_saved = 0

        for scene_id in sorted(scenes.keys()):
            scene_shots = scenes[scene_id]
            plan = build_editorial_plan(scene_shots, scene_id)
            all_plans.append(plan)
            total_reuse += plan.reuse_count
            total_overlay += plan.overlay_count
            total_hold += plan.hold_count
            total_saved += plan.frames_saved

            if apply_tags_flag:
                apply_editorial_tags(scene_shots, plan)

        # Save if tags applied
        if apply_tags_flag and total_saved > 0:
            import tempfile as _tf_ed
            _ed_tmp = _tf_ed.NamedTemporaryFile(mode='w', dir=str(project_path), suffix='.json', delete=False)
            if isinstance(data, dict):
                json.dump(data, _ed_tmp, indent=2)
            else:
                json.dump(shots, _ed_tmp, indent=2)
            _ed_tmp.close()
            os.replace(_ed_tmp.name, str(shot_plan_path))
            dirty_path = project_path / "ui_cache" / ".dirty"
            dirty_path.parent.mkdir(exist_ok=True)
            dirty_path.touch()

        # Build report
        need_gen, skip_gen = filter_shots_for_generation(shots)

        return {
            "total_shots": len(shots),
            "total_scenes": len(scenes),
            "frame_reuse": total_reuse,
            "broll_overlays": total_overlay,
            "hold_opportunities": total_hold,
            "fal_calls_saved": total_saved,
            "shots_needing_generation": len(need_gen),
            "shots_skippable": len(skip_gen),
            "tags_applied": apply_tags_flag,
            "per_scene": [
                {
                    "scene_id": p.scene_id,
                    "total_shots": p.total_shots,
                    "reuse": p.reuse_count,
                    "overlays": p.overlay_count,
                    "holds": p.hold_count,
                    "decisions": [
                        {"shot_id": d.shot_id, "decision": d.decision,
                         "reason": d.reason, "confidence": d.confidence}
                        for d in p.decisions
                    ],
                }
                for p in all_plans if p.decisions
            ],
        }

    except ImportError:
        return {"error": "Editorial Intelligence not available — install tools/editorial_intelligence.py"}
    except Exception as e:
        logger.error(f"[V25] Editorial plan failed: {e}")
        return {"error": str(e)}


