# ════════════════════════════════════════════════════════════
# V26 CONTROLLED RENDER — UI-Triggerable with Per-Shot Control
# ════════════════════════════════════════════════════════════
#
# 3 endpoints:
#   POST /api/v26/prepare/{project}/{scene_id}  — lock plan, show what will happen
#   POST /api/v26/generate-shot/{project}        — generate ONE shot, halt on failure
#   POST /api/v26/edit-shot/{project}             — edit ONE shot's prompt mid-run
#
# The UI calls prepare → sees the plan → clicks generate per shot (or auto-run)
# → can edit any shot between generates → edits affect ONLY that shot

_v26_active_plans = {}  # project_scene → {controller, plan, snapshots, current_index}

@app.post("/api/v26/prepare/{project_name}/{scene_id}")
async def v26_prepare(project_name: str, scene_id: str, request: Dict = Body(default={})):
    """
    V26 PREPARE + LOCK — Preview what will happen before generating.

    Returns the locked plan: which shots generate, which halt, which reuse.
    The UI can display this as a checklist. User can edit individual shots
    before triggering generation.

    Body: {} (no params needed)

    Returns:
    {
        "locked": true,
        "scene_id": "001",
        "shots": [
            {"shot_id": "001_001A", "action": "generate", "nano_preview": "...", "characters": [...]},
            ...
        ],
        "generate_count": 8,
        "halt_count": 0,
        "conditions": {...}
    }
    """
    try:
        import sys as _sys_v26
        _sys_v26.path.insert(0, str(BASE_DIR))
        from atlas_v26_controller import V26Controller

        project_path = get_project_path(project_name)
        controller = V26Controller(str(project_path))

        # Auto-sanitize before locking
        try:
            from tools.post_fixv16_sanitizer import sanitize_shot
            scene_shots = [s for s in controller.shots
                if (s.get("scene_id") or s.get("shot_id", "")[:3]) == scene_id]
            _san = 0
            for _ss in scene_shots:
                changes = sanitize_shot(_ss, scene_id)
                if changes:
                    _san += changes
            logger.info(f"[V26 UI] Auto-sanitized {_san} contaminants")
        except Exception:
            _san = 0

        # Prepare and lock
        plan = controller.prepare_and_lock_scene(scene_id)

        if not plan.locked:
            return {"success": False, "error": "Scene plan could not be locked", "locked": False}

        # Persist to disk so orchestrator reads locked prompts
        controller.persist_locked_plan(scene_id)

        # Build shot list for UI display
        shot_list = []
        for d in plan.shots:
            orig = next((s for s in controller.shots if s.get("shot_id") == d.shot_id), None)
            shot_list.append({
                "shot_id": d.shot_id,
                "action": d.action,
                "reason": d.reason or "",
                "doctrine_gate": d.doctrine_gate,
                "nano_preview": (d.nano_prompt or "")[:200],
                "ltx_preview": (d.ltx_prompt or "")[:200],
                "characters": (orig or {}).get("characters", []),
                "shot_type": (orig or {}).get("shot_type", ""),
                "coverage_role": (orig or {}).get("coverage_role", ""),
                "gaze_direction": (orig or {}).get("gaze_direction", ""),
                "state_in": (orig or {}).get("state_in", {}),
                "editable": d.action == "generate",  # Only generate shots are editable
            })

        # Store active plan for generate-shot to use
        plan_key = f"{project_name}_{scene_id}"
        _v26_active_plans[plan_key] = {
            "controller": controller,
            "plan": plan,
            "current_index": 0,
            "results": [],
            "locked_at": __import__("datetime").datetime.utcnow().isoformat(),
        }

        return {
            "success": True,
            "locked": True,
            "scene_id": scene_id,
            "lock_hash": plan.lock_hash[:16],
            "shots": shot_list,
            "generate_count": sum(1 for d in plan.shots if d.action == "generate"),
            "halt_count": sum(1 for d in plan.shots if d.action == "halt"),
            "reuse_count": sum(1 for d in plan.shots if d.action == "reuse"),
            "sanitized": _san,
            "conditions": {
                "cast_verified": plan.cast_verified,
                "coverage_verified": plan.coverage_verified,
                "doctrine_cleared": plan.doctrine_cleared,
            }
        }
    except Exception as e:
        logger.error(f"[V26 UI] Prepare failed: {e}")
        return {"success": False, "error": str(e)}


@app.post("/api/v26/generate-shot/{project_name}")
async def v26_generate_shot(project_name: str, request: Dict = Body(...)):
    """
    V26 GENERATE ONE SHOT — The UI calls this per shot, or in auto-run mode.

    Body:
    {
        "scene_id": "001",
        "shot_id": "001_001A",       // optional — if omitted, generates next in sequence
        "auto_continue": false        // if true, generates ALL remaining shots (halt on failure)
    }

    Returns per-shot result including frame path, lock integrity, identity score.
    If the shot fails, returns error and STOPS (doesn't continue).
    """
    import httpx as _httpx_v26

    scene_id = request.get("scene_id", "")
    shot_id = request.get("shot_id", "")
    auto_continue = request.get("auto_continue", False)
    render_mode = request.get("render_mode", "normal")  # V26.1: "normal" or "turbo"

    plan_key = f"{project_name}_{scene_id}"
    active = _v26_active_plans.get(plan_key)

    if not active:
        return {"success": False, "error": f"No active plan for {plan_key}. Call /api/v26/prepare first."}

    controller = active["controller"]
    plan = active["plan"]
    generate_shots = [d for d in plan.shots if d.action == "generate"]

    if not generate_shots:
        return {"success": False, "error": "No shots to generate in this plan"}

    # Determine which shot(s) to generate
    if shot_id:
        # Specific shot requested
        targets = [d for d in generate_shots if d.shot_id == shot_id]
        if not targets:
            return {"success": False, "error": f"Shot {shot_id} not in generate list"}
    elif auto_continue:
        # All remaining from current index
        idx = active["current_index"]
        targets = generate_shots[idx:]
    else:
        # Next single shot
        idx = active["current_index"]
        if idx >= len(generate_shots):
            return {"success": False, "error": "All shots already generated", "complete": True}
        targets = [generate_shots[idx]]

    results = []
    project_path = get_project_path(project_name)

    for decision in targets:
        shot_result = {
            "shot_id": decision.shot_id,
            "action": decision.action,
        }

        try:
            # V26.1: Route through governed internal call
            # render_mode selects speed (turbo = parallel workers) but ALL governance already passed
            gen_request = {
                "project": project_name,
                "shot_ids": [decision.shot_id],
                "dry_run": False,
            }

            # V26.1: Choose endpoint based on render_mode — turbo uses parallel workers
            if render_mode == "turbo":
                gen_endpoint = "http://localhost:9999/api/auto/generate-first-frames-turbo"
                gen_request["max_workers"] = 1  # Single shot, still use turbo infra
                gen_request["force"] = True
                gen_request["scene_filter"] = scene_id
            else:
                gen_endpoint = "http://localhost:9999/api/auto/generate-first-frames"

            # Internal call with governed header — bypasses the UI guard on turbo
            resp = _httpx_v26.post(
                gen_endpoint,
                json=gen_request,
                headers={"X-ATLAS-GOVERNED": "1"},
                timeout=120.0,
            )

            if resp.status_code == 200:
                gen_result = resp.json()
                shot_result["generated"] = gen_result.get("success", False)

                # Check frame exists
                frame_path = project_path / "first_frames" / f"{decision.shot_id}.jpg"
                shot_result["frame_exists"] = frame_path.exists()
                if frame_path.exists():
                    shot_result["frame_url"] = f"/api/media?path={frame_path}"
                    shot_result["frame_size"] = frame_path.stat().st_size

                # Check prompt lock integrity
                with open(project_path / "shot_plan.json") as f:
                    check_data = json.load(f)
                current_shot = next(
                    (s for s in check_data.get("shots", []) if s.get("shot_id") == decision.shot_id),
                    None
                )
                if current_shot:
                    import hashlib
                    current_nano = current_shot.get("nano_prompt", "") or ""
                    locked_nano = current_shot.get("_locked_nano_prompt", "") or ""
                    if locked_nano:
                        shot_result["lock_intact"] = (
                            hashlib.sha256(current_nano.encode()).hexdigest()[:16] ==
                            hashlib.sha256(locked_nano.encode()).hexdigest()[:16]
                        )
                    else:
                        shot_result["lock_intact"] = "no_snapshot"

                shot_result["success"] = True
            else:
                try:
                    err = resp.json()
                    shot_result["error"] = err.get("error", err.get("detail", str(err)[:300]))
                except Exception:
                    shot_result["error"] = resp.text[:300]
                shot_result["success"] = False

                # HALT on failure — don't continue
                results.append(shot_result)
                active["results"].extend(results)
                return {
                    "success": False,
                    "halted": True,
                    "halted_at": decision.shot_id,
                    "error": shot_result.get("error", "Generation failed"),
                    "results": results,
                    "remaining": len(generate_shots) - active["current_index"] - len(results),
                }

        except _httpx_v26.ConnectError:
            shot_result["error"] = "Orchestrator connection lost"
            shot_result["success"] = False
            results.append(shot_result)
            active["results"].extend(results)
            return {"success": False, "halted": True, "error": "Connection lost", "results": results}

        except Exception as e:
            shot_result["error"] = str(e)[:200]
            shot_result["success"] = False
            results.append(shot_result)
            active["results"].extend(results)
            return {"success": False, "halted": True, "error": str(e)[:200], "results": results}

        results.append(shot_result)
        active["current_index"] += 1

    active["results"].extend(results)

    complete = active["current_index"] >= len(generate_shots)

    return {
        "success": True,
        "complete": complete,
        "results": results,
        "generated_so_far": active["current_index"],
        "total": len(generate_shots),
        "remaining": len(generate_shots) - active["current_index"],
    }


@app.post("/api/v26/render")
async def v26_render_body(request: Dict = Body(...)):
    """
    V26 RENDER via Request Body — Wrapper for UI compatibility.

    Accepts POST with body containing {project, scene_id, mode}.
    Routes to the path-parameter version internally.

    Body:
    {
        "project": "victorian_shadows_ep1",
        "scene_id": "001",
        "mode": "frames" | "full"
    }
    """
    project = request.get("project", "")
    scene_id = request.get("scene_id", "")
    mode = request.get("mode", "frames")

    if not project or not scene_id:
        return {"success": False, "error": "project and scene_id required"}

    # Delegate to the path-parameter version
    return await v26_render_scene(project, scene_id)


@app.post("/api/v26/render/{project_name}/{scene_id}")
async def v26_render_scene(project_name: str, scene_id: str):
    """
    V26 FULL PARALLEL RENDER — Intent Verified + Film Engine + Parallel FAL.

    Uses V26Controller.render_scene() which:
    1. Scene Intent Verifier (V27.4) — story conscience pre-check
    2. Auto-sanitize contaminants
    3. Prepare + lock scene plan
    4. Shot Authority (FAL params)
    5. Editorial Intelligence (advisory)
    6. Film Engine compile (prompt authority)
    7. Dialogue Cinematography Enforcer (OTS/two-shot/close-up)
    8. Scene Visual DNA + Lighting Rig + Focal Enforcement
    9. PARALLEL FAL execution via ThreadPoolExecutor (Wave 0 all at once)
    10. Post-gen scoring + cache invalidation

    This is 5-10x faster than the legacy sequential endpoint.
    """
    try:
        import sys as _sys_v26r
        _sys_v26r.path.insert(0, str(BASE_DIR))
        from atlas_v26_controller import V26Controller

        project_path = get_project_path(project_name)
        if not (project_path / "shot_plan.json").exists():
            return {"success": False, "error": "Project not found"}

        controller = V26Controller(str(project_path))

        # Archive existing frames before regeneration
        import shutil
        ff_dir = project_path / "first_frames"
        if ff_dir.exists():
            scene_frames = list(ff_dir.glob(f"{scene_id}_*.jpg"))
            if scene_frames:
                archive_dir = project_path / "first_frames_archive"
                archive_dir.mkdir(parents=True, exist_ok=True)
                _ts = datetime.now().strftime("%Y%m%d_%H%M%S")
                for f in scene_frames:
                    try:
                        shutil.copy2(str(f), str(archive_dir / f"{f.stem}_{_ts}.jpg"))
                    except Exception:
                        pass
                logger.info(f"[V26 RENDER] Archived {len(scene_frames)} existing frames for scene {scene_id}")

        # Run the full parallel pipeline
        render_result = controller.render_scene(scene_id, skip_probe=True)

        # Invalidate UI cache
        try:
            _invalidate_bundle_cache(project_name)
        except Exception:
            pass

        return {
            "success": not render_result.get("halted", False),
            "parallel": True,
            "scene_id": scene_id,
            "conditions": render_result.get("conditions", {}),
            "phases": render_result.get("phases", {}),
            "plan": render_result.get("plan", {}),
            "render_results": render_result.get("render_results", {}),
            "doctrine_compliance": render_result.get("doctrine_compliance", 0),
        }
    except Exception as e:
        logger.error(f"[V26 RENDER] Scene {scene_id} failed: {e}")
        import traceback
        traceback.print_exc()
        return {"success": False, "error": str(e)[:500]}


@app.post("/api/v26/edit-shot/{project_name}")
async def v26_edit_shot(project_name: str, request: Dict = Body(...)):
    """
    V26 EDIT ONE SHOT — Change a single shot's prompt mid-run.

    This edits ONLY the specified shot. Does NOT re-lock, does NOT change
    other shots, does NOT re-run fix-v16 or any enrichment pipeline.

    Body:
    {
        "scene_id": "001",
        "shot_id": "001_003B",
        "nano_prompt": "new prompt text...",     // optional — only changes if provided
        "ltx_prompt": "new ltx text...",          // optional — only changes if provided
        "characters": ["LADY MARGARET"],          // optional
        "gaze_direction": "toward_altar",         // optional
        "regenerate": false                       // if true, immediately regenerate after edit
    }

    Returns: the updated shot data.
    """
    scene_id = request.get("scene_id", "")
    shot_id = request.get("shot_id", "")
    regenerate = request.get("regenerate", False)

    if not shot_id:
        return {"success": False, "error": "shot_id required"}

    project_path = get_project_path(project_name)
    shot_plan_path = project_path / "shot_plan.json"

    if not shot_plan_path.exists():
        return {"success": False, "error": "Shot plan not found"}

    # Load current plan
    with open(shot_plan_path) as f:
        data = json.load(f)

    # V27.1: Handle both list format [shots...] and dict format {"shots": [...]}
    if isinstance(data, list):
        shots = data
        data = {"shots": data}
    else:
        shots = data.get("shots", [])
    target = None
    target_idx = None
    for i, s in enumerate(shots):
        if s.get("shot_id") == shot_id:
            target = s
            target_idx = i
            break

    if not target:
        return {"success": False, "error": f"Shot {shot_id} not found"}

    # Track what changed
    changes = {}

    # Apply edits — ONLY fields that were provided
    if "nano_prompt" in request:
        old = target.get("nano_prompt", "")[:80]
        target["nano_prompt"] = request["nano_prompt"]
        target["nano_prompt_final"] = request["nano_prompt"]  # Also update final
        # Update locked snapshot so lock check doesn't false-alarm
        target["_locked_nano_prompt"] = request["nano_prompt"]
        target["_prompt_locked"] = True  # Re-lock with new content
        changes["nano_prompt"] = {"old": old, "new": request["nano_prompt"][:80]}

    if "ltx_prompt" in request:
        old = target.get("ltx_motion_prompt", "")[:80]
        target["ltx_motion_prompt"] = request["ltx_prompt"]
        target["_locked_ltx_prompt"] = request["ltx_prompt"]
        changes["ltx_prompt"] = {"old": old, "new": request["ltx_prompt"][:80]}

    if "characters" in request:
        target["characters"] = request["characters"]
        changes["characters"] = request["characters"]

    if "gaze_direction" in request:
        target["gaze_direction"] = request["gaze_direction"]
        changes["gaze_direction"] = request["gaze_direction"]

    if "state_in" in request:
        target["state_in"] = request["state_in"]
        changes["state_in"] = "updated"

    # Save — atomic write
    import tempfile
    with tempfile.NamedTemporaryFile(mode='w', dir=str(project_path),
                                      suffix='.json', delete=False) as tmp:
        json.dump(data, tmp, indent=2)
        tmp_path = tmp.name
    os.replace(tmp_path, str(shot_plan_path))

    # Also update the active plan if one exists
    plan_key = f"{project_name}_{scene_id}"
    active = _v26_active_plans.get(plan_key)
    if active:
        # Update the decision in the active plan
        for d in active["plan"].shots:
            if d.shot_id == shot_id:
                if "nano_prompt" in request:
                    d.nano_prompt = request["nano_prompt"]
                if "ltx_prompt" in request:
                    d.ltx_prompt = request["ltx_prompt"]
                break

    # Invalidate bundle cache
    cache_file = project_path / "ui_cache" / "bundle.json.dirty"
    cache_file.parent.mkdir(parents=True, exist_ok=True)
    cache_file.touch()

    result = {
        "success": True,
        "shot_id": shot_id,
        "changes": changes,
        "shot": {
            "shot_id": target.get("shot_id"),
            "nano_preview": (target.get("nano_prompt", "") or "")[:200],
            "ltx_preview": (target.get("ltx_motion_prompt", "") or "")[:200],
            "characters": target.get("characters", []),
            "gaze_direction": target.get("gaze_direction", ""),
            "shot_type": target.get("shot_type", ""),
        }
    }

    # Optional: regenerate immediately after edit
    if regenerate:
        import httpx as _httpx_edit
        try:
            resp = _httpx_edit.post(
                "http://localhost:9999/api/auto/generate-first-frames",
                json={"project": project_name, "shot_ids": [shot_id], "dry_run": False},
                timeout=120.0,
            )
            if resp.status_code == 200:
                gen_result = resp.json()
                result["regenerated"] = gen_result.get("success", False)
                frame_path = project_path / "first_frames" / f"{shot_id}.jpg"
                if frame_path.exists():
                    result["frame_url"] = f"/api/media?path={frame_path}"
            else:
                result["regenerated"] = False
                result["regen_error"] = resp.text[:200]
        except Exception as e:
            result["regenerated"] = False
            result["regen_error"] = str(e)[:200]

    return result


@app.get("/api/v26/status/{project_name}/{scene_id}")
async def v26_status(project_name: str, scene_id: str):
    """
    V26 RUN STATUS — Check progress of a controlled render.

    Returns current shot index, results so far, remaining count.
    The UI can poll this to update progress display.
    """
    plan_key = f"{project_name}_{scene_id}"
    active = _v26_active_plans.get(plan_key)

    if not active:
        return {"active": False, "message": "No active plan. Call /api/v26/prepare first."}

    plan = active["plan"]
    generate_shots = [d for d in plan.shots if d.action == "generate"]

    return {
        "active": True,
        "scene_id": scene_id,
        "locked_at": active.get("locked_at", ""),
        "current_index": active["current_index"],
        "total_generate": len(generate_shots),
        "remaining": len(generate_shots) - active["current_index"],
        "complete": active["current_index"] >= len(generate_shots),
        "results": active["results"],
        "lock_hash": plan.lock_hash[:16],
    }


