@app.post("/api/v21/gate-snapshot/{project_name}")
async def create_gate_snapshot_endpoint(project_name: str, request: Dict = Body(default={})):
    """
    Create immutable gate snapshot — this is EXACTLY what FAL will see.
    Must be created before generation. Generation reads ONLY from snapshot.

    Options:
        scene_filter: list of scene_ids to include (default: all)
    """
    from tools.movie_lock_mode import gate_snapshot_create
    project_path = get_project_path(project_name)
    if not project_path.exists():
        return {"error": f"Project '{project_name}' not found"}

    shot_plan_path = project_path / "shot_plan.json"
    if not shot_plan_path.exists():
        return {"error": "No shot_plan.json found"}

    with open(shot_plan_path) as f:
        data = json.load(f)
    shots = data.get("shots", data) if isinstance(data, dict) else data
    scene_filter = request.get("scene_filter")

    result = gate_snapshot_create(shots, project_path, scene_filter)
    return result


