@app.post("/api/v21/shot/lock/{project_name}")
async def lock_shot_endpoint(project_name: str, request: Dict = Body(default={})):
    """Lock a shot's creative fields — prevents ANY automatic modification."""
    from tools.movie_lock_mode import lock_shot
    project_path = get_project_path(project_name)
    shot_plan_path = project_path / "shot_plan.json"
    if not shot_plan_path.exists():
        return {"error": "No shot_plan.json found"}

    shot_id = request.get("shot_id", "")
    if not shot_id:
        return {"error": "shot_id required"}

    with open(shot_plan_path) as f:
        data = json.load(f)
    shots = data.get("shots", data) if isinstance(data, dict) else data

    locked = False
    for shot in shots:
        if shot.get("shot_id") == shot_id:
            lock_shot(shot)
            locked = True
            break

    if not locked:
        return {"error": f"Shot {shot_id} not found"}

    with open(shot_plan_path, "w") as f:
        json.dump(data, f, indent=2)

    return {"success": True, "shot_id": shot_id, "user_locked": True}


