@app.get("/api/v6/profiles/directors")
async def get_all_directors():
    """Get all director profiles for Auto Studio."""
    directors_path = Path(str(BASE_DIR) + "/directors_library.json")

    if not directors_path.exists():
        return {"success": True, "directors": [], "total": 0}

    with open(directors_path) as f:
        data = json.load(f)

    directors = data.get("directors", data) if isinstance(data, dict) else data
    return {"success": True, "directors": directors, "total": len(directors)}


