@app.post("/api/v6/casting/fit-score")
async def get_fit_score_recommendations(request: Dict = Body(...)):
    """
    Get FIT SCORE recommendations for casting a character.
    Uses character traits to match against AI actor library with intelligent scoring.
    """
    character = request.get("character", {})
    project = request.get("project", "")
    genre = request.get("genre", "fantasy")
    top_n = request.get("top_n", 10)
    traits = request.get("traits", [])

    # Handle both dict and string character input
    import re
    if isinstance(character, str):
        char_name_full = character.upper()
        char_desc = ""
        char_archetype = "supporting"
        char_age = ""
        char_traits = traits if traits else []

        # Extract age from input like "KEENE THE PRIEST-KING (64)"
        age_match = re.search(r'\((\d+)\)', char_name_full)
        if age_match:
            char_age = age_match.group(1)
        else:
            # V16.6: Extract age from description keywords
            AGE_KEYWORDS = {
                'child': (5, 12), 'teenager': (13, 19), 'young': (20, 35), 'youthful': (20, 35),
                'middle-aged': (40, 55), 'middle aged': (40, 55), 'mature': (45, 60),
                'elderly': (60, 85), 'old': (60, 85), 'ancient': (70, 100), 'aged': (60, 80),
                'senior': (55, 75), 'early 20s': (20, 25), 'late 20s': (25, 30),
                'early 30s': (30, 35), 'mid 30s': (33, 38), 'late 30s': (35, 40),
                'early 40s': (40, 45), 'mid 40s': (43, 48), 'late 40s': (45, 50),
                'early 50s': (50, 55), 'mid 50s': (53, 58), 'late 50s': (55, 60),
                'early 60s': (60, 65), 'mid 60s': (63, 68), 'late 60s': (65, 70),
            }
            combined_input = char_name_full.lower()
            for keyword, (min_a, max_a) in AGE_KEYWORDS.items():
                if keyword in combined_input:
                    char_age = str((min_a + max_a) // 2)  # Use midpoint
                    break

        # Get first word as base name for matching
        char_name_base = char_name_full.split()[0] if char_name_full else char_name_full

        # Try to load character info from project shot_plan
        if project:
            project_path = get_project_path(project) / "shot_plan.json"
            if project_path.exists():
                try:
                    with open(project_path) as f:
                        shot_plan = _sp_guard(json.load(f))
                    # Search for character in shot_plan (partial match)
                    for char in shot_plan.get("characters", []):
                        char_stored = char.get("name", "").upper()
                        # V17.6: Scored matching replaces loose substring
                        _cs, _cp = score_name_match(char_name_base, char_stored, threshold=65)
                        if not _cp and char_name_full != char_name_base:
                            _cs, _cp = score_name_match(char_name_full, char_stored, threshold=65)
                        if _cp:
                            char_desc = char.get("description", "")
                            char_archetype = char.get("role", "supporting")
                            break
                    # Also search scene beats for character context
                    for scene in shot_plan.get("scene_manifest", []):
                        for beat in scene.get("beats", []):
                            beat_chars = [c.upper() for c in beat.get("characters", [])]
                            if any(score_name_match(char_name_base, bc, 65)[1] for bc in beat_chars):
                                if beat.get("emotional_tone"):
                                    char_traits.append(beat.get("emotional_tone"))
                                if beat.get("beat_type"):
                                    char_traits.append(beat.get("beat_type"))
                except Exception as e:
                    logger.warning(f"Could not load character info from project: {e}")

        char_name = char_name_full
    else:
        char_name = character.get("name", "Unknown")
        char_desc = character.get("description", "")
        char_archetype = character.get("archetype", "supporting")
        char_age = character.get("age_hints", "")
        char_traits = character.get("traits", [])

    # Deduplicate traits
    char_traits = list(set(char_traits))

    # Load AI actors library
    actors_path = Path(str(BASE_DIR) + "/ai_actors_library.json")
    actors = []
    if actors_path.exists():
        with open(actors_path) as f:
            actors_data = json.load(f)
            actors = actors_data.get("actors", actors_data) if isinstance(actors_data, dict) else actors_data

    if not actors:
        return {
            "success": True,
            "character": char_name,
            "recommendations": []
        }

    # Map headshots directory
    headshots_dir = Path(str(BASE_DIR) + "/ai_actor_headshots")
    headshot_files = {}
    if headshots_dir.exists():
        for f in headshots_dir.glob("*.jpg"):
            # MAYA_CHEN_HEADSHOT.jpg -> MAYA_CHEN
            name_key = f.stem.replace("_HEADSHOT", "").upper()
            headshot_files[name_key] = f"/ai_actor_headshots/{f.name}"

    # Intelligent matching for fit score
    recommendations = []
    char_name_lower = char_name.lower()
    char_desc_lower = char_desc.lower()

    for actor in actors[:50]:
        actor_name = actor.get("name", "Unknown")
        actor_id = actor.get("id", actor_name.lower().replace(" ", "_"))

        # Build searchable actor profile
        actor_specialty = [s.lower() for s in actor.get("specialty", [])]
        actor_genres = [g.lower() for g in actor.get("genres", [])]
        actor_age_range = actor.get("age_range", "")
        actor_appearance = actor.get("appearance", {})
        actor_image_prompt = actor.get("image_prompt", "").lower()

        # Calculate intelligent fit score
        score = 40  # Base score
        reasons = []

        # Genre matching (strong signal)
        if genre.lower() in actor_genres:
            score += 20
            reasons.append(f"genre match: {genre}")
        elif any(g in genre.lower() for g in actor_genres):
            score += 10
            reasons.append("partial genre match")

        # Specialty matching
        for spec in actor_specialty:
            if spec.lower() in char_desc_lower or spec.lower() in char_name_lower:
                score += 15
                reasons.append(f"specialty: {spec}")
                break

        # Age matching - V16.6: Enhanced with mismatch penalty
        if char_age:
            try:
                char_age_int = int(char_age)
                if actor_age_range:
                    age_parts = actor_age_range.replace("+", "-100").split("-")
                    if len(age_parts) == 2:
                        min_age, max_age = int(age_parts[0]), int(age_parts[1])
                        if min_age <= char_age_int <= max_age:
                            score += 25
                            reasons.append(f"age match: {char_age} in {actor_age_range}")
                        elif abs(char_age_int - min_age) <= 10 or abs(char_age_int - max_age) <= 10:
                            score += 10
                            reasons.append(f"age close: {char_age} near {actor_age_range}")
                        else:
                            # V16.6: Age mismatch penalty
                            age_diff = min(abs(char_age_int - min_age), abs(char_age_int - max_age))
                            if age_diff > 20:
                                score -= 20
                                reasons.append(f"AGE MISMATCH: need ~{char_age}, actor is {actor_age_range}")
            except Exception:
                pass

        # Character type matching
        char_type_keywords = {
            "king": ["Drama", "Historical", "period"],
            "priest": ["Drama", "Historical"],
            "warrior": ["Action", "martial_arts"],
            "elf": ["Fantasy", "Sci-Fi"],
            "dwarf": ["Fantasy", "Action"],
            "council": ["Drama", "Political"],
            "leader": ["Drama", "Political", "leadership"],
            "guard": ["Action", "military"],
            "miner": ["Drama", "Action"]
        }

        for keyword, matching_specs in char_type_keywords.items():
            if keyword in char_name_lower or keyword in char_desc_lower:
                for match_spec in matching_specs:
                    if match_spec.lower() in [s.lower() for s in actor_specialty + actor_genres]:
                        score += 15
                        reasons.append(f"type match: {keyword}")
                        break
                break

        # Trait matching
        for trait in char_traits:
            trait_lower = trait.lower()
            if trait_lower in actor_image_prompt:
                score += 5
            if trait_lower in actor_specialty or trait_lower in actor_genres:
                score += 8
                reasons.append(f"trait: {trait}")

        # Emotional tone matching
        emotional_map = {
            "tension": ["Thriller", "Drama", "Action"],
            "confrontation": ["Action", "Drama"],
            "dread": ["Horror", "Thriller"],
            "determination": ["Action", "Drama"],
            "authority": ["Drama", "Political"],
            "diplomatic": ["Drama", "Political"]
        }

        for trait in char_traits:
            if trait.lower() in emotional_map:
                for match_genre in emotional_map[trait.lower()]:
                    if match_genre.lower() in actor_genres or match_genre in actor_specialty:
                        score += 8
                        break

        score = min(98, score)  # Cap at 98 (leave room for perfect match)

        # Get headshot
        actor_name_key = actor_name.upper().replace(" ", "_")
        headshot = headshot_files.get(actor_name_key, actor.get("reference_image", ""))

        reason_text = ", ".join(reasons[:3]) if reasons else "Available actor"

        recommendations.append({
            "actor_id": actor_id,
            "actor_name": actor_name,
            "fit_score": score,
            "reason": reason_text,
            "headshot_url": headshot,
            "specialty": actor_specialty,
            "age_range": actor_age_range
        })

    # Sort by fit score
    recommendations.sort(key=lambda x: x["fit_score"], reverse=True)

    return {
        "success": True,
        "status": "success",  # V16.4: UI compatibility
        "character": char_name,
        "character_traits": char_traits[:10],
        "recommendations": recommendations[:top_n],
        "tests": [],
        "issues": [],
        "health": 100
    }


