@app.post("/api/v6/approve/casting")
async def approve_casting(request: Dict = Body(...)):
    """
    V16.5: Approve and save casting assignments with FULL actor details.
    Enriches simplified cast_map with headshots, fit_scores for proper UI display.
    """
    project = request.get("project")
    incoming_cast = request.get("cast_map", {})

    if not project:
        return {"success": False, "error": "Project name required"}

    # Save cast_map to project directory
    project_path = get_project_path(project)
    if not project_path.exists():
        project_path.mkdir(parents=True, exist_ok=True)

    cast_map_path = project_path / "cast_map.json"

    # Load existing cast_map if available (to preserve enriched data)
    existing_cast = {}
    if cast_map_path.exists():
        try:
            with open(cast_map_path) as f:
                existing_cast = json.load(f)
        except Exception:
            pass

    # Load AI actors library for enrichment
    actors_by_id = {}
    actors_by_name = {}
    actors_path = BASE_DIR / "ai_actors_library.json"
    if actors_path.exists():
        try:
            with open(actors_path) as f:
                actors_data = json.load(f)
            actors_list = actors_data.get("actors", actors_data) if isinstance(actors_data, dict) else actors_data
            for actor in actors_list:
                if actor.get("id"):
                    actors_by_id[actor["id"]] = actor
                if actor.get("name"):
                    actors_by_name[actor["name"].upper()] = actor
        except Exception as e:
            logger.warning(f"[CASTING] Could not load actors library: {e}")

    # V17.6 FIX: If no incoming cast_map provided, PRESERVE existing cast entries
    # This prevents approve/casting from wiping out cast_map when called without cast_map body
    if not incoming_cast and existing_cast:
        enriched_cast = {k: v for k, v in existing_cast.items() if not k.startswith("_")}
        logger.info(f"[CASTING] No incoming cast_map — preserving {len(enriched_cast)} existing entries")
    else:
        enriched_cast = {}

    # Build enriched cast_map from incoming (only if incoming has entries)
    for char_name, actor_ref in incoming_cast.items():
        if char_name.startswith("_"):
            continue  # Skip metadata keys

        # Find actor by ID or name
        actor = None
        if isinstance(actor_ref, str):
            actor = actors_by_id.get(actor_ref) or actors_by_name.get(actor_ref.upper())
        elif isinstance(actor_ref, dict):
            # Already enriched format
            enriched_cast[char_name] = actor_ref
            continue

        if actor:
            # Build headshot URL
            actor_name = actor.get("name", "Unknown")
            actor_filename = actor_name.upper().replace(" ", "_") + "_LOCKED_REFERENCE.jpg"
            headshot_url = f"/api/media?path={BASE_DIR}/character_library_locked/ai_actors/{actor_filename}"

            # Check if headshot exists, fallback to ai_actor_headshots
            if not (BASE_DIR / "character_library_locked/ai_actors" / actor_filename).exists():
                alt_filename = actor_name.upper().replace(" ", "_") + "_HEADSHOT.jpg"
                if (BASE_DIR / "ai_actor_headshots" / alt_filename).exists():
                    headshot_url = f"/api/media?path={BASE_DIR}/ai_actor_headshots/{alt_filename}"

            # V17.6: Preserve character_reference_url + other fields from existing cast
            existing_entry = existing_cast.get(char_name, {})
            enriched_cast[char_name] = {
                "ai_actor": actor_name,
                "ai_actor_id": actor.get("id", ""),
                "headshot_url": headshot_url,
                "auto_cast": True,
                "fit_score": existing_entry.get("fit_score", 50),
                "fit_reasons": existing_entry.get("fit_reasons", []),
                "character_reference_url": existing_entry.get("character_reference_url", ""),
                "is_extras_pool": existing_entry.get("is_extras_pool", False)
            }
        else:
            # Actor not found - preserve what we have
            enriched_cast[char_name] = {
                "ai_actor": str(actor_ref) if actor_ref else "Uncast",
                "ai_actor_id": "",
                "headshot_url": "",
                "auto_cast": False,
                "fit_score": 0,
                "fit_reasons": []
            }

    # Add metadata (preserve existing metadata too)
    enriched_cast["_approved_at"] = datetime.now().isoformat()
    enriched_cast["_approved"] = True
    enriched_cast["_auto_cast"] = True
    enriched_cast["_casting_finalized"] = True
    # V17.6: Preserve character aliases from existing cast
    if existing_cast.get("_character_aliases"):
        enriched_cast["_character_aliases"] = existing_cast["_character_aliases"]

    # V17.6: Use safe_merge_json for lock writes
    locks_path = project_path / "master_locks.json"
    safe_merge_json(str(locks_path), {
        "casting": True,
        "casting_approved_at": datetime.now().isoformat()
    })

    # V17.6: Use safe_write_json for atomic cast_map write
    safe_write_json(str(cast_map_path), enriched_cast)

    # V16.6: Propagate cast to shot ai_actor_cast (required for critics/renders)
    try:
        from propagate_cast_v16 import propagate_cast_to_shots
        prop_result = propagate_cast_to_shots(project_path)
        logger.info(f"[CASTING] Propagated cast to {prop_result.get('shots_updated', 0)} shots")
    except Exception as e:
        logger.warning(f"[CASTING] Cast propagation failed: {e}")

    char_count = len([k for k in enriched_cast.keys() if not k.startswith("_")])
    logger.info(f"[CASTING] Approved casting for {project}: {char_count} characters with enriched data")

    return {
        "success": True,
        "project": project,
        "cast_count": char_count,
        "path": str(cast_map_path),
        "persisted": True,
        "cast_propagated": True
    }


async def llm_oversight_validation(project_slug: str, api_key: str, target_runtime_seconds: int) -> Dict:
    """
    V16.4: LLM Oversight - Validates project completeness and fixes issues.

    This function:
    1. Reviews the script/story_bible for consistency
    2. Validates decision logic (duration, casting, shot expansion)
    3. Applies intelligent fixes based on LLM recommendations
    """
    import httpx

    project_path = get_project_path(project_slug)

    # Load all project data
    shot_plan_path = project_path / "shot_plan.json"
    story_bible_path = project_path / "story_bible.json"
    cast_map_path = project_path / "cast_map.json"

    if not shot_plan_path.exists():
        return {"status": "error", "message": "No shot_plan.json found"}

    with open(shot_plan_path) as f:
        shot_plan = _sp_guard(json.load(f))

    story_bible = {}
    if story_bible_path.exists():
        with open(story_bible_path) as f:
            story_bible = json.load(f)

    cast_map = {}
    if cast_map_path.exists():
        with open(cast_map_path) as f:
            cast_map = json.load(f)

    # Analyze current state
    shots = shot_plan.get("shots", [])
    scenes = shot_plan.get("scene_manifest", [])
    characters = story_bible.get("characters", shot_plan.get("characters", []))

    current_duration = sum(s.get("duration_seconds", 20) for s in shots)
    cast_characters = [k for k in cast_map.keys() if not k.startswith("_")]

    # Build validation summary
    validation_summary = {
        "project": project_slug,
        "target_runtime_seconds": target_runtime_seconds,
        "current_duration_seconds": current_duration,
        "duration_variance_percent": abs(current_duration - target_runtime_seconds) / target_runtime_seconds * 100 if target_runtime_seconds > 0 else 0,
        "shot_count": len(shots),
        "scene_count": len(scenes),
        "character_count": len(characters),
        "cast_count": len(cast_characters),
        "issues": []
    }

    # Check for issues
    if validation_summary["duration_variance_percent"] > 10:
        validation_summary["issues"].append(f"Duration variance {validation_summary['duration_variance_percent']:.1f}% exceeds 10% threshold")

    if len(cast_characters) < len(characters):
        uncast = len(characters) - len(cast_characters)
        validation_summary["issues"].append(f"{uncast} characters not cast")

    if len(shots) == 0 and len(scenes) > 0:
        validation_summary["issues"].append("Scenes not expanded to shots")

    # If issues found, apply intelligent fixes
    fixes_applied = []

    # FIX 1: Duration scaling
    if validation_summary["duration_variance_percent"] > 10 and len(shots) > 0:
        scale_factor = target_runtime_seconds / current_duration if current_duration > 0 else 1.0
        new_duration = 0
        for shot in shots:
            old_dur = shot.get("duration_seconds", 20)
            new_dur = max(5, min(60, int(old_dur * scale_factor)))  # Clamp 5-60s
            shot["duration_seconds"] = new_dur
            new_duration += new_dur

        # Update metadata
        if "metadata" not in shot_plan:
            shot_plan["metadata"] = {}
        shot_plan["metadata"]["target_runtime"] = target_runtime_seconds
        shot_plan["metadata"]["total_duration_seconds"] = new_duration
        shot_plan["metadata"]["v164_oversight_scaled"] = True

        fixes_applied.append(f"Scaled durations from {current_duration}s to {new_duration}s (target: {target_runtime_seconds}s)")
        logger.info(f"[OVERSIGHT] Duration scaled: {current_duration}s -> {new_duration}s")

    # FIX 2: Ensure all characters have script references
    char_names = [c.get("name", c) if isinstance(c, dict) else c for c in characters]
    for shot in shots:
        shot_chars = shot.get("characters", [])
        if not shot_chars and shot.get("nano_prompt"):
            # Extract character names from nano_prompt
            prompt = shot.get("nano_prompt", "").upper()
            for name in char_names:
                if name.upper() in prompt:
                    if "characters" not in shot:
                        shot["characters"] = []
                    if name.upper() not in [c.upper() for c in shot["characters"]]:
                        shot["characters"].append(name)

    # Save updated shot_plan
    if fixes_applied:
        shot_plan["metadata"]["v164_oversight_fixes"] = fixes_applied
        shot_plan["metadata"]["v164_oversight_at"] = datetime.now().isoformat()
        with open(shot_plan_path, 'w') as f:
            json.dump(shot_plan, f, indent=2)

    validation_summary["fixes_applied"] = fixes_applied
    validation_summary["status"] = "fixed" if fixes_applied else "clean"

    return validation_summary


@app.post("/api/v6/casting/auto-cast")
@app.post("/api/v6/auto-cast")  # V17 FIX: UI calls this URL, add alias
async def auto_cast_project(request: Dict = Body(...)):
    """
    RB-1 FIX: Auto-generate cast_map.json with proper character->actor mappings.

    Extracts characters from shot_plan, matches them to AI actors library,
    and writes a proper cast_map that the V15.5 reference attachment can use.

    Body:
    {
        "project": "kord",
        "overwrite": false  // if true, replace existing cast_map
    }

    Returns:
    {
        "success": true,
        "cast_map": { "CHARACTER": { "ai_actor_id": "001", ... } },
        "characters_cast": 12,
        "uncast": ["WARRIORS", "DWARVES"]  // group characters skipped
    }
    """
    # V17.2.4: Top-level safety wrapper — GUARANTEE JSON responses, never HTML error pages
    _cast_project = request.get("project", "unknown")
    try:
        result = await _auto_cast_project_impl(request)
        # V17.3: Temporal workflow tracking for auto-cast
        try:
            _wf_id = temporal_start_workflow(_cast_project, "auto_cast")
            temporal_run_activity(_wf_id, "auto_cast")
            if result.get("success"):
                _cast_summary = {"characters_cast": result.get("characters_cast", 0), "uncast": len(result.get("uncast", []))}
                temporal_complete_activity(_wf_id, "auto_cast", result=_cast_summary)
                temporal_complete_workflow(_wf_id, result=_cast_summary)
            else:
                temporal_fail_activity(_wf_id, "auto_cast", result.get("error", "unknown"), should_retry=False)
            _temporal_persist()
        except Exception:
            pass  # Temporal tracking is non-blocking
        return result
    except Exception as e:
        logger.error(f"[AUTO-CAST] Unhandled exception: {e}", exc_info=True)
        # V17.3: Track failure in Temporal
        try:
            _wf_id = temporal_start_workflow(_cast_project, "auto_cast")
            temporal_run_activity(_wf_id, "auto_cast")
            temporal_fail_activity(_wf_id, "auto_cast", str(e)[:300], should_retry=False)
            _temporal_persist()
        except Exception:
            pass  # Temporal tracking is non-blocking
        return {"success": False, "error": f"Auto-cast failed: {str(e)[:300]}"}

async def _auto_cast_project_impl(request: Dict):
    """Inner implementation of auto-cast, wrapped by JSON-safe handler."""
    project = request.get("project")
    overwrite = request.get("overwrite", False)

    if not project:
        return {"success": False, "error": "Project name required"}

    project_path = get_project_path(project)
    if not project_path.exists():
        return {"success": False, "error": f"Project '{project}' not found"}

    # V16.7 CAST LOCK: Load existing cast_map and PRESERVE existing assignments
    cast_map_path = project_path / "cast_map.json"
    existing_cast = {}
    locked_characters = set()

    if cast_map_path.exists():
        try:
            with open(cast_map_path) as f:
                existing_cast = json.load(f)
        except (json.JSONDecodeError, ValueError) as e:
            logger.warning(f"[AUTO-CAST] Malformed cast_map.json, starting fresh: {e}")
            existing_cast = {}
        except Exception as e:
            return {"success": False, "error": f"Failed to read cast_map.json: {str(e)[:200]}"}

        # V16.7: Identify which characters already have locked assignments
        for char_name, char_data in existing_cast.items():
            if char_name.startswith("_"):
                continue
            # A character is locked if it has an ai_actor assigned
            if isinstance(char_data, dict) and char_data.get("ai_actor"):
                locked_characters.add(char_name.upper())

        char_count = len(locked_characters)
        if char_count > 0 and not overwrite:
            logger.info(f"[AUTO-CAST] CAST LOCK: {char_count} characters already cast, will only fill missing")

        # If overwrite=false and ALL characters are locked, return early
        # But we'll still continue to fill any MISSING characters

    # Load shot_plan to extract characters
    shot_plan_path = project_path / "shot_plan.json"
    if not shot_plan_path.exists():
        return {"success": False, "error": "No shot_plan.json found"}

    try:
        with open(shot_plan_path) as f:
            shot_plan = _sp_guard(json.load(f))
    except (json.JSONDecodeError, ValueError) as e:
        return {"success": False, "error": f"Malformed shot_plan.json: {str(e)[:200]}"}
    except Exception as e:
        return {"success": False, "error": f"Failed to read shot_plan.json: {str(e)[:200]}"}

    # V17.2 FIX: Handle both {"shots": [...]} and raw [...] formats
    if isinstance(shot_plan, list):
        shot_plan = {"shots": shot_plan}

    # Extract unique characters
    characters = set()
    for shot in shot_plan.get("shots", []):
        for char in shot.get("characters", []):
            if isinstance(char, str):
                characters.add(char.upper().strip())
            elif isinstance(char, dict):
                characters.add(char.get("name", "").upper().strip())

    # Also check scene_manifest/scenes
    for scene in shot_plan.get("scene_manifest", shot_plan.get("scenes", [])):
        # V17 FIX: beats might be int (count) or array - only iterate if array
        beats = scene.get("beats", [])
        if isinstance(beats, list):
            for beat in beats:
                for char in beat.get("characters", []):
                    if isinstance(char, str):
                        characters.add(char.upper().strip())
                    elif isinstance(char, dict):
                        characters.add(char.get("name", "").upper().strip())
        # Also extract characters directly from scene
        for char in scene.get("characters", []):
            if isinstance(char, str):
                characters.add(char.upper().strip())
            elif isinstance(char, dict):
                characters.add(char.get("name", "").upper().strip())

    characters.discard("")

    # V17.2.4: NORMALIZE DUPLICATE CHARACTER NAMES
    # Merge variants: substring, plural/singular, adjective-prefix
    def normalize_character_names(char_set: set) -> set:
        """Merge character name variants — handles substrings, plurals, and adjective prefixes."""
        import re
        char_list = sorted(char_set)  # Sort for deterministic processing
        normalized = set()
        alias_map = {}  # Maps short/variant → canonical name
        merged_count = 0

        # Phase 1: Build plural→singular mapping (BUGBEARS→BUGBEAR, WARRIORS→WARRIOR)
        singular_map = {}
        for char in char_list:
            # If char ends with S and the singular form also exists, map plural to singular
            if char.endswith("S") and len(char) > 3:
                singular = char[:-1]  # BUGBEARS → BUGBEAR
                if singular in char_set:
                    singular_map[char] = singular
                # Also check ES ending: DWARVES → DWARF (less common in character names)

        # Phase 2: Build adjective-prefix mapping (BLUE BUGBEAR → BUGBEAR, GRAND MASTER FARMER → FARMER)
        adjective_prefixes = {"BLUE", "RED", "GREEN", "BLACK", "WHITE", "OLD", "YOUNG",
                              "GRAND", "GREAT", "HIGH", "DARK", "PALE", "ALL", "HEAD",
                              "THE", "A", "AN", "ELDER", "SENIOR", "JUNIOR"}
        prefix_map = {}
        for char in char_list:
            words = char.split()
            if len(words) >= 2 and words[0] in adjective_prefixes:
                base = " ".join(words[1:])
                if base in char_set:
                    prefix_map[char] = base

        # Phase 3: Standard substring merge (LADY MARGARET → LADY MARGARET RAVENCROFT)
        for char in char_list:
            # Skip if already mapped as plural or prefix variant
            if char in singular_map or char in prefix_map:
                merged_count += 1
                canonical = singular_map.get(char) or prefix_map.get(char)
                alias_map[char] = canonical
                logger.debug(f"[AUTO-CAST] Alias '{char}' → '{canonical}' (variant merge)")
                continue

            is_subset = False
            for existing in list(normalized):
                if char in existing and char != existing:
                    is_subset = True
                    merged_count += 1
                    alias_map[char] = existing
                    logger.debug(f"[AUTO-CAST] Merged '{char}' into '{existing}'")
                    break
                if existing in char and char != existing:
                    normalized.discard(existing)
                    normalized.add(char)
                    alias_map[existing] = char
                    merged_count += 1
                    logger.debug(f"[AUTO-CAST] Replaced '{existing}' with longer '{char}'")
                    is_subset = True
                    break

            if not is_subset:
                normalized.add(char)

        if merged_count > 0:
            logger.info(f"[AUTO-CAST] Normalized {merged_count} duplicate character name variants. Alias map: {alias_map}")

        return normalized, alias_map

    # V21.9.1 FIX: Load story_bible characters BEFORE normalization
    # so that "CLARA BYRNE" (story_bible) gets merged with "CLARA" (shots).
    # Previously this ran AFTER normalize, causing surname variants to be
    # missed entirely — the root cause of the Clara naming mismatch.
    story_bible_path = project_path / "story_bible.json"
    if story_bible_path.exists():
        try:
            with open(story_bible_path) as f:
                sb_data = json.load(f)
            _sb_char_count = 0
            for char_entry in sb_data.get("characters", []):
                if isinstance(char_entry, str):
                    characters.add(char_entry.upper().strip())
                    _sb_char_count += 1
                elif isinstance(char_entry, dict):
                    name = char_entry.get("name", "").upper().strip()
                    if name:
                        characters.add(name)
                        _sb_char_count += 1
            logger.info(f"[AUTO-CAST] Added {_sb_char_count} characters from story_bible BEFORE normalization")
        except Exception as e:
            logger.warning(f"[AUTO-CAST] Could not load story_bible for characters: {e}")

    characters, character_aliases = normalize_character_names(characters)

    # Load AI actors library
    actors_path = BASE_DIR / "ai_actors_library.json"
    if not actors_path.exists():
        return {"success": False, "error": "ai_actors_library.json not found"}

    try:
        with open(actors_path) as f:
            actors_data = json.load(f)
    except (json.JSONDecodeError, ValueError) as e:
        return {"success": False, "error": f"Malformed ai_actors_library.json: {str(e)[:200]}"}
    except Exception as e:
        return {"success": False, "error": f"Failed to read ai_actors_library.json: {str(e)[:200]}"}
    actors = actors_data.get("actors", actors_data) if isinstance(actors_data, dict) else actors_data

    # Build actor lookup by ID
    actor_by_id = {str(a.get("id")): a for a in actors if a.get("id")}

    # Skip group characters (plurals like WARRIORS, DWARVES, ELVES)
    group_keywords = ["WARRIORS", "DWARVES", "ELVES", "COUNCIL", "WORKERS", "DELEGATES", "GUARDS", "SOLDIERS", "CROWD"]

    # V16.2: Use V5 FitScoreCalculator for intelligent casting
    # Load character descriptions - PRIORITY: story_bible (LLM-enhanced) > entity_manifest > shot_plan
    char_descriptions = {}

    # 1. FIRST load from story_bible (LLM-enhanced with gender/ethnicity)
    story_bible_path = project_path / "story_bible.json"
    if story_bible_path.exists():
        try:
            with open(story_bible_path) as f:
                story_bible = json.load(f)
            for char_entry in story_bible.get("characters", []):
                name = char_entry.get("name", "").upper()
                # Build rich description from all available fields
                desc_parts = []
                if char_entry.get("gender"):
                    desc_parts.append(char_entry.get("gender"))  # e.g., "female"
                # V16.7: Check both age_range and age_hints (story_bible uses age_hints)
                age_info = char_entry.get("age_range") or char_entry.get("age_hints")
                if age_info:
                    desc_parts.append(f"age {age_info}")  # e.g., "age late 20s to early 30s"
                if char_entry.get("ethnicity"):
                    desc_parts.append(char_entry.get("ethnicity"))
                if char_entry.get("description"):
                    desc_parts.append(char_entry.get("description"))
                char_descriptions[name] = " ".join(desc_parts)
                logger.info(f"[AUTO-CAST] Loaded {name} from story_bible: {char_descriptions[name][:100]}...")
        except Exception as e:
            logger.warning(f"[AUTO-CAST] Could not load story_bible: {e}")

    # 2. Fallback to entity_manifest for characters not in story_bible
    for char_entry in shot_plan.get("entity_manifest", {}).get("characters", []):
        name = char_entry.get("name", "").upper()
        if name not in char_descriptions or not char_descriptions[name]:
            char_descriptions[name] = char_entry.get("description", "")

    # 3. Finally check shot_plan characters (may be strings or dicts)
    for char_entry in shot_plan.get("characters", []):
        if isinstance(char_entry, str):
            name = char_entry.upper().strip()
            # String entries have no description, skip if already known
            if name and name not in char_descriptions:
                char_descriptions[name] = ""
        elif isinstance(char_entry, dict):
            name = char_entry.get("name", "").upper()
            if name and (name not in char_descriptions or not char_descriptions[name]):
                char_descriptions[name] = char_entry.get("description", "")

    # V16.7: FIT SCORE CALCULATION with physical matching + CHILD detection
    # V16.7 MINIMUM THRESHOLD: 50 (raised from 30)
    MIN_FIT_SCORE_THRESHOLD = 50

    # Log all character descriptions for debugging
    logger.info(f"[AUTO-CAST] Character descriptions loaded: {list(char_descriptions.keys())}")
    for cname, cdesc in char_descriptions.items():
        logger.info(f"[AUTO-CAST] {cname}: {cdesc[:120]}...")

    # V16.7: Child/minor character keywords - these need special handling
    CHILD_KEYWORDS = ['child', 'kid', 'boy', 'girl', 'baby', 'infant', 'toddler', 'teen', 'teenager', 'youth', 'minor', 'young', 'little']

    def is_child_character(char_name: str, char_desc: str) -> bool:
        """V16.7: Detect if character is a child/minor."""
        combined = (char_name + " " + char_desc).lower()
        for kw in CHILD_KEYWORDS:
            if kw in combined:
                return True
        # Check for age references under 18
        import re
        age_match = re.search(r'age[d]?\s*(\d+)', combined)
        if age_match:
            age = int(age_match.group(1))
            if age < 18:
                return True
        return False

    def calculate_fit_score(char_name: str, char_desc: str, actor: Dict) -> Tuple[float, List[str]]:
        """Calculate fit score with physical matching (gender/ethnicity)."""
        import re
        score = 40  # Base score
        reasons = []

        char_desc_lower = char_desc.lower()
        char_name_lower = char_name.lower()
        actor_desc = (actor.get('image_prompt', '') + ' ' + actor.get('description', '')).lower()

        # V16.7: CHILD CHARACTER PENALTY - major penalty for casting adults as children
        if is_child_character(char_name, char_desc):
            actor_age_range = actor.get("age_range", "30-40")
            try:
                age_parts = actor_age_range.replace("+", "-100").split("-")
                actor_min_age = int(age_parts[0].strip())
            except Exception:
                actor_min_age = 30  # Assume adult if unparseable

            if actor_min_age >= 18:
                # Actor is an adult, character is a child - MAJOR penalty
                score -= 60
                reasons.append(f"CHILD_MISMATCH: character is minor, actor is adult ({actor_age_range})")

        # V16.2.1: Helper for word boundary matching (fixes "man" matching inside "woman")
        def word_match(keywords, text):
            for kw in keywords:
                # Use word boundaries to prevent "man" matching "woman"
                pattern = r'\b' + re.escape(kw.strip()) + r'\b'
                if re.search(pattern, text, re.IGNORECASE):
                    return True
            return False

        # GENDER MATCHING (critical - up to 25pt bonus or -40pt penalty)
        male_keywords = ['man', 'male', 'he', 'him', 'his', 'father', 'brother', 'husband', 'mr', 'boy', 'gentleman', 'lord', 'king', 'prince']
        female_keywords = ['woman', 'female', 'she', 'her', 'mother', 'sister', 'wife', 'mrs', 'ms', 'girl', 'lady', 'queen', 'princess']

        char_male = word_match(male_keywords, char_desc_lower) or word_match(male_keywords, char_name_lower)
        char_female = word_match(female_keywords, char_desc_lower) or word_match(female_keywords, char_name_lower)
        actor_male = word_match(male_keywords, actor_desc)
        actor_female = word_match(female_keywords, actor_desc)

        if (char_male and actor_male) or (char_female and actor_female):
            score += 25
            reasons.append("gender match")
        elif (char_male and actor_female) or (char_female and actor_male):
            score -= 40
            reasons.append("GENDER MISMATCH")

        # ETHNICITY MATCHING (critical - up to 20pt bonus or -35pt penalty)
        ethnicity_groups = {
            'asian': ['asian', 'chinese', 'japanese', 'korean', 'vietnamese', 'thai'],
            'black': ['black', 'african', 'dark-skinned'],
            'white': ['white', 'caucasian', 'european', 'british', 'fair-skinned', 'pale'],
            'hispanic': ['hispanic', 'latino', 'latina', 'mexican', 'spanish'],
            'middle_eastern': ['middle eastern', 'arab', 'persian', 'indian'],
        }

        char_ethnicity = None
        actor_ethnicity = None

        for eth, keywords in ethnicity_groups.items():
            if any(kw in char_desc_lower for kw in keywords):
                char_ethnicity = eth
                break
        for eth, keywords in ethnicity_groups.items():
            if any(kw in actor_desc for kw in keywords):
                actor_ethnicity = eth
                break

        if char_ethnicity and actor_ethnicity:
            if char_ethnicity == actor_ethnicity:
                score += 20
                reasons.append(f"ethnicity match: {char_ethnicity}")
            else:
                score -= 35
                reasons.append(f"ETHNICITY MISMATCH: need {char_ethnicity}, got {actor_ethnicity}")

        # AGE MATCHING - V16.6: Enhanced to extract age from descriptions
        # Age keywords map to approximate age ranges
        AGE_KEYWORDS = {
            'child': (5, 12),
            'teenager': (13, 19),
            'young': (20, 35),
            'youthful': (20, 35),
            'early 20s': (20, 25),
            'late 20s': (25, 30),
            'early 30s': (30, 35),
            'mid 30s': (33, 38),
            'late 30s': (35, 40),
            'middle-aged': (40, 55),
            'middle aged': (40, 55),
            'mature': (45, 60),
            'elderly': (60, 85),
            'old': (60, 85),
            'ancient': (70, 100),
            'aged': (60, 80),
            'senior': (55, 75),
            'early 40s': (40, 45),
            'mid 40s': (43, 48),
            'late 40s': (45, 50),
            'early 50s': (50, 55),
            'mid 50s': (53, 58),
            'late 50s': (55, 60),
            'early 60s': (60, 65),
            'mid 60s': (63, 68),
            'late 60s': (65, 70),
        }

        # First try to get explicit age from character name (e.g., "KEENE (64)")
        char_age = None
        age_match = re.search(r'\((\d+)\)', char_name)
        if age_match:
            char_age = int(age_match.group(1))
        else:
            # V16.6: Extract age from description keywords
            combined_desc = char_desc_lower + ' ' + char_name_lower
            for keyword, (min_a, max_a) in AGE_KEYWORDS.items():
                if keyword in combined_desc:
                    char_age = (min_a + max_a) // 2  # Use midpoint
                    break

        if char_age:
            actor_age_range = actor.get("age_range", "")
            if actor_age_range:
                try:
                    age_parts = actor_age_range.replace("+", "-100").split("-")
                    if len(age_parts) >= 2:
                        min_age, max_age = int(age_parts[0]), int(age_parts[1])
                        if min_age <= char_age <= max_age:
                            score += 25  # V16.6: Increased from 15 to 25 (same as gender)
                            reasons.append(f"age match: {char_age} in {min_age}-{max_age}")
                        elif abs(char_age - min_age) <= 10 or abs(char_age - max_age) <= 10:
                            score += 10  # V16.6: Increased from 5 to 10
                            reasons.append(f"age close: {char_age} near {min_age}-{max_age}")
                        else:
                            # V16.6: Age mismatch penalty (prevents casting young actors as elderly)
                            age_diff = min(abs(char_age - min_age), abs(char_age - max_age))
                            if age_diff > 20:
                                score -= 20
                                reasons.append(f"AGE MISMATCH: need ~{char_age}, actor is {min_age}-{max_age}")
                except Exception:
                    pass

        # SPECIALTY/GENRE MATCHING
        actor_specialty = [s.lower() for s in actor.get("specialty", [])]
        actor_genres = [g.lower() for g in actor.get("genres", [])]

        char_type_keywords = {
            "lady": ["Drama", "Historical", "period"],
            "lord": ["Drama", "Historical"],
            "king": ["Drama", "Historical"],
            "queen": ["Drama", "Historical"],
            "warrior": ["Action", "martial_arts"],
            "priest": ["Drama", "Historical"],
        }

        for keyword, matching_specs in char_type_keywords.items():
            if keyword in char_name_lower or keyword in char_desc_lower:
                for match_spec in matching_specs:
                    if match_spec.lower() in actor_specialty + actor_genres:
                        score += 10
                        reasons.append(f"type match: {keyword}")
                        break
                break

        return score, reasons

    # V16.2: Load regression history to block rejected pairs
    regression_history_path = project_path / "regression_history.json"
    rejected_pairs = set()
    if regression_history_path.exists():
        try:
            with open(regression_history_path) as f:
                reg_data = json.load(f)
            for pair in reg_data.get("rejected_pairs", []):
                rejected_pairs.add((pair["character"].upper(), pair["actor"]))
            logger.info(f"[AUTO-CAST] Loaded {len(rejected_pairs)} rejected pairs from regression history")
        except Exception as e:
            logger.warning(f"[AUTO-CAST] Could not load regression history: {e}")

    # Calculate best actor for each character using fit scores
    # V16.7 CAST LOCK: Start with existing cast_map to preserve locked assignments
    cast_map = {k: v for k, v in existing_cast.items() if k.startswith("_")}  # Keep metadata
    uncast = []
    used_actors = set()  # V16.7.1: Track by (actor_id, actor_name) tuple
    preserved_count = 0

    # V16.7.1: Helper for consistent character name normalization
    def norm_char(name: str) -> str:
        return name.upper().strip() if name else ""

    # V16.7: Pre-populate used_actors from existing locked assignments
    for char_name in locked_characters:
        # V16.7.1: Try normalized lookup
        normalized = norm_char(char_name)
        char_data = None
        for k, v in existing_cast.items():
            if norm_char(k) == normalized and isinstance(v, dict):
                char_data = v
                break

        if char_data:
            actor_id = char_data.get("ai_actor_id", "")
            actor_name = char_data.get("ai_actor", "")
            # V16.7.1: Track by both id and name to prevent duplicates
            if actor_id:
                used_actors.add(str(actor_id))
            if actor_name:
                used_actors.add(actor_name.upper())
            # Preserve the locked assignment in new cast_map (using normalized key)
            # V21.10 FIX: Ensure character_reference_url is set from headshot_url
            # Old cast_maps may have headshot_url but not character_reference_url
            if isinstance(char_data, dict) and not char_data.get("character_reference_url"):
                hs = char_data.get("headshot_url") or char_data.get("reference_url")
                if hs:
                    char_data["character_reference_url"] = hs
                    char_data["reference_url"] = hs
            cast_map[normalized] = char_data
            preserved_count += 1

    logger.info(f"[AUTO-CAST] CAST LOCK: Preserved {preserved_count} existing assignments, {len(used_actors)} actors tracked")

    for char_name in sorted(characters):
        normalized_char = norm_char(char_name)
        # V16.7 CAST LOCK: Skip characters that are already locked
        if normalized_char in [norm_char(c) for c in locked_characters]:
            logger.info(f"[AUTO-CAST] CAST LOCK: Skipping {char_name} - already assigned")
            continue

        # Skip group characters - mark as "extras pool" instead of skipping
        is_group = any(gk in char_name for gk in group_keywords)
        if is_group:
            # V16.7.1: Add to cast_map as extras pool instead of leaving uncast
            cast_map[normalized_char] = {
                "ai_actor": "EXTRAS POOL",
                "ai_actor_id": "extras",
                "headshot_url": "",
                "auto_cast": True,
                "fit_score": 100,
                "is_extras_pool": True,
                "fit_reasons": ["Group character - use background extras"]
            }
            logger.info(f"[AUTO-CAST] {char_name} -> EXTRAS POOL (group character)")
            continue

        # V16.2: Calculate fit scores for ALL available actors
        char_desc = char_descriptions.get(char_name, "") or char_descriptions.get(normalized_char, "")
        actor_scores = []

        for actor in actors:
            actor_id = str(actor.get("id", ""))
            actor_name = actor.get("name", "")
            # V16.7.1: Check both id and name for uniqueness
            if actor_id in used_actors or actor_name.upper() in used_actors:
                continue  # Skip already-used actors

            # V16.2: Check regression history - skip rejected pairs
            if (char_name.upper(), actor_name) in rejected_pairs:
                logger.info(f"[AUTO-CAST] Skipping {actor_name} for {char_name} - in regression history")
                continue

            score, reasons = calculate_fit_score(char_name, char_desc, actor)
            actor_scores.append((score, actor, reasons))

        # Sort by score descending and pick best
        actor_scores.sort(key=lambda x: x[0], reverse=True)

        if actor_scores and actor_scores[0][0] >= MIN_FIT_SCORE_THRESHOLD:  # V16.7: Raised from 30 to 50
            best_score, best_actor, reasons = actor_scores[0]
            # V16.7.1: Track by both id and name
            used_actors.add(str(best_actor.get("id", "")))
            used_actors.add(best_actor.get("name", "").upper())

            # V17.3 FIX: Check LOCKED REFERENCE (costume version) FIRST, then generic headshot
            headshot = None
            actor_name_key = best_actor.get("name", "").upper().replace(" ", "_")

            # Priority 1: Locked reference on disk (character in wardrobe/costume)
            locked_ref = BASE_DIR / "character_library_locked" / "ai_actors" / f"{actor_name_key}_LOCKED_REFERENCE.jpg"
            if locked_ref.exists():
                headshot = f"/api/media?path={locked_ref}"
                logger.info(f"[AUTO-CAST] Using LOCKED REFERENCE for {normalized_char}: {locked_ref.name}")

            # Priority 2: Generic actor headshot on disk
            if not headshot:
                headshot_file = BASE_DIR / "ai_actor_headshots" / f"{actor_name_key}_HEADSHOT.jpg"
                if headshot_file.exists():
                    headshot = f"/api/media?path={headshot_file}"

            # Priority 3: Library fields (fallback)
            if not headshot:
                headshot = (
                    best_actor.get("locked_reference_url")
                    or best_actor.get("headshot_url")
                    or best_actor.get("reference_image")
                )

            # V16.7.1: Use normalized char name for consistency
            # V21.10 FIX: Set BOTH headshot_url AND character_reference_url
            # Generation pipeline uses character_reference_url for nano-pro-edit refs
            # Without this, generation has NO image ref = no character consistency
            cast_map[normalized_char] = {
                "ai_actor": best_actor.get("name", f"Actor_{best_actor.get('id')}"),
                "ai_actor_id": str(best_actor.get("id")),
                "headshot_url": headshot,
                "character_reference_url": headshot,  # V21.10: Same ref used for generation
                "reference_url": headshot,  # V21.10: Alias for compatibility
                "auto_cast": True,
                "fit_score": best_score,
                "fit_reasons": reasons[:5]  # Top 5 reasons
            }
            logger.info(f"[AUTO-CAST] {normalized_char} -> {best_actor.get('name')} (score: {best_score}, {reasons[:3]})")
        else:
            uncast.append(char_name)
            logger.warning(f"[AUTO-CAST] No suitable actor found for {char_name} (best score: {actor_scores[0][0] if actor_scores else 0})")

    # Add metadata
    cast_map["_approved"] = True
    cast_map["_approved_at"] = datetime.now().isoformat()
    cast_map["_auto_cast"] = True

    # V17.2.4: Store alias map for downstream normalization
    if character_aliases:
        cast_map["_character_aliases"] = character_aliases
        # V21.9.1: Reconcile independently-cast aliases BEFORE creating alias entries
        # If both alias and canonical were cast independently (no _is_alias_of), merge them:
        # keep canonical entry, convert alias to _is_alias_of pointer
        for alias, canonical in character_aliases.items():
            if alias in cast_map and canonical in cast_map and alias != canonical:
                alias_entry = cast_map[alias]
                if isinstance(alias_entry, dict) and "_is_alias_of" not in alias_entry:
                    # Both were cast independently — merge: keep canonical, mark alias
                    logger.info(f"[AUTO-CAST] Reconciling duplicate cast: {alias} → {canonical} (was independently cast)")
                    cast_map[alias] = {
                        **cast_map[canonical],
                        "_is_alias_of": canonical,
                        "auto_cast": True
                    }
            elif canonical in cast_map and alias not in cast_map:
                # Standard: create alias entry pointing to canonical
                cast_map[alias] = {
                    **cast_map[canonical],
                    "_is_alias_of": canonical,
                    "auto_cast": True
                }
                logger.debug(f"[AUTO-CAST] Created alias cast entry: {alias} → {canonical}")

    # Save cast_map
    with open(cast_map_path, 'w') as f:
        json.dump(cast_map, f, indent=2)

    logger.info(f"[AUTO-CAST] Generated cast_map for {project}: {len(cast_map) - 3} characters cast, {len(character_aliases)} aliases")

    return {
        "success": True,
        "status": "success",  # V16.4: UI compatibility
        "project": project,
        "characters_cast": len(cast_map) - 3,  # Exclude metadata keys
        "uncast": uncast,
        "cast_map": {k: v for k, v in cast_map.items() if not k.startswith("_")},
        "path": str(cast_map_path),
        "tests": [],
        "issues": [],
        "health": 100
    }


@app.post("/api/v17/cast/cleanup")
async def cleanup_cast_data(request: Dict = Body(...)):
    """
    V17 CAST CLEANUP: Fix stale ai_actor_cast entries in shot_plan.json.

    This endpoint:
    1. Normalizes duplicate character names (e.g., "LADY MARGARET" → "LADY MARGARET RAVENCROFT")
    2. Removes ai_actor_cast entries that don't match cast_map
    3. Propagates correct cast from cast_map to all shots
    4. Optionally removes specific characters entirely

    Body:
    {
        "project": "ravencroft_v17",
        "remove_characters": ["Maya Chen"],      // Optional: remove specific actor assignments
        "normalize_aliases": true,               // Default: true - merge character name variants
        "propagate_cast": true                   // Default: true - apply cast_map to all shots
    }

    Returns:
    {
        "success": true,
        "cleaned_shots": 6,
        "removed_actors": ["Maya Chen"],
        "normalized_characters": ["LADY MARGARET → LADY MARGARET RAVENCROFT"],
        "propagated_cast": {"LADY MARGARET RAVENCROFT": "Isabella Moretti"}
    }
    """
    project = request.get("project")
    remove_characters = request.get("remove_characters", [])
    normalize_aliases = request.get("normalize_aliases", True)
    propagate_cast = request.get("propagate_cast", True)

    if not project:
        return {"success": False, "error": "Project name required"}

    project_path = get_project_path(project)
    if not project_path.exists():
        return {"success": False, "error": f"Project '{project}' not found"}

    # Load shot_plan
    shot_plan_path = project_path / "shot_plan.json"
    if not shot_plan_path.exists():
        return {"success": False, "error": "No shot_plan.json found"}

    with open(shot_plan_path) as f:
        shot_plan = _sp_guard(json.load(f))

    # Load cast_map
    cast_map_path = project_path / "cast_map.json"
    cast_map = {}
    if cast_map_path.exists():
        with open(cast_map_path) as f:
            cast_map = json.load(f)

    # Build character alias map from cast_map
    # E.g., "LADY MARGARET" should map to "LADY MARGARET RAVENCROFT" if the latter exists
    alias_map = {}
    cast_chars = [k for k in cast_map.keys() if not k.startswith("_")]

    for char in cast_chars:
        char_upper = char.upper()
        # Find shorter variants that might appear in shots
        for other_char in cast_chars:
            other_upper = other_char.upper()
            if other_upper != char_upper:
                # If one is a prefix of the other, map shorter to longer
                if char_upper.startswith(other_upper) and len(char_upper) > len(other_upper):
                    alias_map[other_upper] = char_upper
                elif other_upper.startswith(char_upper) and len(other_upper) > len(char_upper):
                    alias_map[char_upper] = other_upper

    # Detect short aliases from shots that match cast_map entries
    for shot in shot_plan.get("shots", []):
        for char in shot.get("characters", []):
            char_name = char.upper() if isinstance(char, str) else char.get("name", "").upper()
            if char_name and char_name not in cast_map:
                # Check if this is a prefix of any cast_map entry
                for cast_char in cast_chars:
                    cast_upper = cast_char.upper()
                    if cast_upper.startswith(char_name) and cast_upper != char_name:
                        alias_map[char_name] = cast_upper
                        break

    logger.info(f"[CAST-CLEANUP] Alias map built: {alias_map}")

    # Remove actors to ignore (case-insensitive)
    remove_actors_lower = [a.lower() for a in remove_characters]

    # Track changes
    cleaned_shots = 0
    removed_actor_entries = []
    normalized_chars = []
    propagated = {}

    # Process each shot
    for shot in shot_plan.get("shots", []):
        shot_changed = False
        shot_id = shot.get("shot_id", "")

        # 1. Normalize character names in characters array
        if normalize_aliases and "characters" in shot:
            new_chars = []
            seen_chars = set()

            for char in shot.get("characters", []):
                char_name = char if isinstance(char, str) else char.get("name", "")
                char_upper = char_name.upper()

                # Apply alias mapping
                if char_upper in alias_map:
                    canonical = alias_map[char_upper]
                    if canonical not in seen_chars:
                        new_chars.append(canonical)
                        seen_chars.add(canonical)
                        normalized_chars.append(f"{char_name} → {canonical}")
                        shot_changed = True
                        logger.info(f"[CAST-CLEANUP] {shot_id}: Normalized {char_name} → {canonical}")
                elif char_upper not in seen_chars:
                    new_chars.append(char_name)
                    seen_chars.add(char_upper)
                else:
                    # Duplicate - skip
                    shot_changed = True
                    logger.info(f"[CAST-CLEANUP] {shot_id}: Removed duplicate character {char_name}")

            if shot_changed:
                shot["characters"] = new_chars

        # 2. Clean ai_actor_cast
        if "ai_actor_cast" in shot:
            new_ai_cast = {}

            for char_key, cast_entry in shot.get("ai_actor_cast", {}).items():
                char_upper = char_key.upper()
                actor_name = cast_entry.get("ai_actor", "") if isinstance(cast_entry, dict) else ""

                # Check if actor should be removed
                if actor_name.lower() in remove_actors_lower:
                    removed_actor_entries.append(f"{shot_id}: {char_key} -> {actor_name}")
                    shot_changed = True
                    logger.info(f"[CAST-CLEANUP] {shot_id}: Removed {actor_name} from {char_key}")
                    continue

                # Normalize character key
                canonical_key = alias_map.get(char_upper, char_upper)

                # If propagate_cast, use cast_map entry instead
                if propagate_cast and canonical_key in cast_map:
                    cast_data = cast_map[canonical_key]
                    new_ai_cast[canonical_key] = {
                        "ai_actor": cast_data.get("ai_actor", ""),
                        "ai_actor_id": cast_data.get("ai_actor_id", ""),
                        "headshot_url": cast_data.get("headshot_url", ""),
                        "reference_url": cast_data.get("reference_url", cast_data.get("headshot_url", "")),
                        "fit_score": cast_data.get("fit_score", 0)
                    }
                    if canonical_key not in propagated:
                        propagated[canonical_key] = cast_data.get("ai_actor", "")
                    shot_changed = True
                elif char_upper != canonical_key:
                    # Key was normalized
                    new_ai_cast[canonical_key] = cast_entry
                    shot_changed = True
                else:
                    new_ai_cast[char_key] = cast_entry

            shot["ai_actor_cast"] = new_ai_cast

        # 3. Also propagate cast to shots missing ai_actor_cast
        if propagate_cast and "characters" in shot:
            if "ai_actor_cast" not in shot:
                shot["ai_actor_cast"] = {}

            for char_name in shot.get("characters", []):
                char_upper = char_name.upper() if isinstance(char_name, str) else char_name.get("name", "").upper()
                canonical = alias_map.get(char_upper, char_upper)

                if canonical in cast_map and canonical not in shot.get("ai_actor_cast", {}):
                    cast_data = cast_map[canonical]
                    shot["ai_actor_cast"][canonical] = {
                        "ai_actor": cast_data.get("ai_actor", ""),
                        "ai_actor_id": cast_data.get("ai_actor_id", ""),
                        "headshot_url": cast_data.get("headshot_url", ""),
                        "reference_url": cast_data.get("reference_url", cast_data.get("headshot_url", "")),
                        "fit_score": cast_data.get("fit_score", 0)
                    }
                    if canonical not in propagated:
                        propagated[canonical] = cast_data.get("ai_actor", "")
                    shot_changed = True

        if shot_changed:
            cleaned_shots += 1

    # Save updated shot_plan
    with open(shot_plan_path, 'w') as f:
        json.dump(shot_plan, f, indent=2)

    # Invalidate UI cache
    cache_dir = project_path / "ui_cache"
    if cache_dir.exists():
        dirty_flag = cache_dir / "bundle.dirty"
        dirty_flag.touch()

    logger.info(f"[CAST-CLEANUP] Completed: {cleaned_shots} shots cleaned, {len(removed_actor_entries)} actors removed, {len(normalized_chars)} chars normalized")

    return {
        "success": True,
        "project": project,
        "cleaned_shots": cleaned_shots,
        "removed_actors": removed_actor_entries,
        "normalized_characters": list(set(normalized_chars)),
        "propagated_cast": propagated,
        "alias_map": alias_map
    }


@app.post("/api/v17/shot/remove-character")
async def remove_character_from_shot(request: Dict = Body(...)):
    """
    V17 REMOVE CHARACTER: Remove a specific character from a single shot.

    Body:
    {
        "project": "ravencroft_v17",
        "shot_id": "E011_S01_000A",
        "character": "LADY MARGARET"  // Character name to remove
    }
    """
    project = request.get("project")
    shot_id = request.get("shot_id")
    character = request.get("character", "").upper()

    if not project or not shot_id or not character:
        return {"success": False, "error": "project, shot_id, and character are required"}

    project_path = get_project_path(project)
    shot_plan_path = project_path / "shot_plan.json"

    if not shot_plan_path.exists():
        return {"success": False, "error": "shot_plan.json not found"}

    with open(shot_plan_path) as f:
        shot_plan = _sp_guard(json.load(f))

    # Find and update the shot
    shot_found = False
    for shot in shot_plan.get("shots", []):
        if shot.get("shot_id") == shot_id:
            shot_found = True

            # Remove from characters array
            if "characters" in shot:
                original_count = len(shot["characters"])
                shot["characters"] = [c for c in shot["characters"]
                                     if (c.upper() if isinstance(c, str) else c.get("name", "").upper()) != character]
                removed_from_chars = original_count - len(shot["characters"])

            # Remove from ai_actor_cast
            removed_from_cast = None
            if "ai_actor_cast" in shot and character in shot["ai_actor_cast"]:
                removed_from_cast = shot["ai_actor_cast"].pop(character, None)
            # Also try case variations
            for key in list(shot.get("ai_actor_cast", {}).keys()):
                if key.upper() == character:
                    removed_from_cast = shot["ai_actor_cast"].pop(key, None)

            break

    if not shot_found:
        return {"success": False, "error": f"Shot {shot_id} not found"}

    # Save
    with open(shot_plan_path, 'w') as f:
        json.dump(shot_plan, f, indent=2)

    # Invalidate cache
    cache_dir = project_path / "ui_cache"
    if cache_dir.exists():
        (cache_dir / "bundle.dirty").touch()

    return {
        "success": True,
        "shot_id": shot_id,
        "removed_character": character,
        "removed_from_characters": removed_from_chars > 0,
        "removed_from_cast": removed_from_cast is not None
    }


@app.get("/api/v6/casting/status/{project_name}")
async def get_casting_status(project_name: str):
    """
    RB-1 FIX: Get complete casting status for a project.

    Returns whether cast_map exists, has proper mappings, and which
    characters are cast vs uncast.
    """
    project_path = get_project_path(project_name)

    result = {
        "project": project_name,
        "has_cast_map": False,
        "has_mappings": False,
        "characters_cast": 0,
        "characters_uncast": [],
        "mappings": {}
    }

    # Check cast_map
    cast_map_path = project_path / "cast_map.json"
    if cast_map_path.exists():
        result["has_cast_map"] = True
        try:
            with open(cast_map_path) as f:
                cast_map = json.load(f)
        except (json.JSONDecodeError, ValueError, Exception) as e:
            return {"success": False, "error": f"Malformed cast_map.json: {str(e)[:200]}", **result}

        mappings = {k: v for k, v in cast_map.items() if not k.startswith("_")}
        result["has_mappings"] = len(mappings) > 0
        result["characters_cast"] = len(mappings)
        result["mappings"] = mappings
        result["approved"] = cast_map.get("_approved", False)
        result["auto_cast"] = cast_map.get("_auto_cast", False)

    # Check shot_plan for uncast characters
    shot_plan_path = project_path / "shot_plan.json"
    if shot_plan_path.exists():
        with open(shot_plan_path) as f:
            shot_plan = _sp_guard(json.load(f))

        all_chars = set()
        for shot in shot_plan.get("shots", []):
            for char in shot.get("characters", []):
                name = char.upper().strip() if isinstance(char, str) else char.get("name", "").upper().strip()
                if name:
                    all_chars.add(name)

        cast_chars = set(result["mappings"].keys())
        result["characters_uncast"] = list(all_chars - cast_chars)

    return result


@app.get("/api/v6/casting/rationale/{project_name}")
async def get_casting_rationale(project_name: str):
    """
    Get casting rationale/notes for a project.
    """
    project_path = get_project_path(project_name)

    # Check for cast_map.json
    cast_map_path = project_path / "cast_map.json"
    rationale = {}

    if cast_map_path.exists():
        try:
            with open(cast_map_path) as f:
                cast_map = json.load(f)
        except (json.JSONDecodeError, ValueError, Exception) as e:
            return {"success": False, "error": f"Malformed cast_map.json: {str(e)[:200]}"}
        for char_name, char_data in cast_map.items():
            if char_name.startswith("_"):
                continue
            if isinstance(char_data, dict):
                rationale[char_name] = {
                    "actor": char_data.get("visual_actor", char_data.get("cast_as", "Uncast")),
                    "fit_score": char_data.get("fit_score", 0),
                    "reason": char_data.get("casting_reason", "Manual assignment")
                }

    return {
        "success": True,
        "project": project_name,
        "rationale": rationale
    }


@app.get("/api/ai-actors")
async def get_ai_actors():
    """Get the AI actors library for casting with headshot URLs."""
    actors_path = Path(str(BASE_DIR) + "/ai_actors_library.json")
    headshots_dir = Path(str(BASE_DIR) + "/ai_actor_headshots")

    if not actors_path.exists():
        return {"actors": [], "total": 0}

    with open(actors_path) as f:
        data = json.load(f)
        actors = data.get("actors", data) if isinstance(data, dict) else data

    # V16.7: Gender inference from first names (extended international names)
    FEMALE_NAMES = {
        # Common Western
        "maya", "sofia", "luna", "isabella", "scarlett", "emma", "olivia", "ava",
        "sophia", "mia", "amelia", "harper", "evelyn", "abigail", "emily", "ella",
        "elizabeth", "camila", "penelope", "riley", "chloe", "layla", "grace",
        "nora", "zoey", "lily", "aurora", "victoria", "hannah", "audrey", "leah",
        "natalie", "savannah", "brooklyn", "samantha", "claire", "skylar", "lucy",
        "paisley", "caroline", "violet", "genesis", "naomi", "eleanor", "stella",
        "hazel", "alexa", "autumn", "aria", "valentina", "ruby",
        # International
        "keiko", "priya", "elena", "sakura", "miranda", "amara", "charlotte",
        "natasha", "nina", "yuki", "aisha", "zara", "mei", "akiko", "yuna",
        "fatima", "leila", "ananya", "sana", "ines", "carmen", "lucia"
    }
    MALE_NAMES = {
        # Common Western
        "jackson", "marcus", "ethan", "james", "oliver", "benjamin", "elijah",
        "lucas", "mason", "logan", "alexander", "henry", "jacob", "michael",
        "daniel", "matthew", "aiden", "joseph", "samuel", "david", "john", "owen",
        "dylan", "luke", "gabriel", "anthony", "isaac", "grayson", "jack", "julian",
        "levi", "christopher", "joshua", "andrew", "lincoln", "mateo", "ryan",
        "jaxon", "nathan", "aaron", "isaiah", "thomas", "charles", "caleb", "josiah",
        "christian", "hunter", "eli", "jonathan", "connor", "landon", "adrian",
        # International
        "dimitri", "tyler", "omar", "noah", "carlos", "alessandro", "rashid",
        "kai", "sergio", "kimani", "antoine", "javier", "malik", "pierre",
        "diego", "phoenix", "hiroshi", "kenji", "ahmed", "ravi", "arjun",
        "mohammad", "vladimir", "ivan", "andrei"
    }

    # Map headshots to actors by name
    headshot_files = {f.stem.upper(): f.name for f in headshots_dir.glob("*.jpg")} if headshots_dir.exists() else {}

    # Add reference_image and gender to each actor
    for actor in actors:
        name = actor.get("name", "").upper().replace(" ", "_")
        # Try exact match first, then partial
        headshot = headshot_files.get(f"{name}_HEADSHOT")
        if not headshot:
            # Try partial match
            for key, fname in headshot_files.items():
                if name.split("_")[0] in key:
                    headshot = fname
                    break
        if headshot:
            actor["reference_image"] = f"/ai_actor_headshots/{headshot}"

        # V16.7: Infer gender from first name or prompt if not already set
        if not actor.get("gender") or actor.get("gender") in ["unknown", "?", ""]:
            first_name = actor.get("name", "").split()[0].lower() if actor.get("name") else ""
            prompt = (actor.get("prompt") or actor.get("description") or "").lower()

            # Check first name first
            if first_name in FEMALE_NAMES:
                actor["gender"] = "female"
            elif first_name in MALE_NAMES:
                actor["gender"] = "male"
            # Fall back to prompt keywords (word boundary matching)
            elif re.search(r'\b(woman|female|lady|actress|she|her)\b', prompt):
                actor["gender"] = "female"
            elif re.search(r'\b(man|male|gentleman|actor|he|his)\b', prompt):
                actor["gender"] = "male"
            else:
                actor["gender"] = "unknown"

            if headshot:
                actor["headshot"] = f"/ai_actor_headshots/{headshot}"

    return {"actors": actors, "total": len(actors)}


