@app.post("/api/live-generations/push")
async def push_live_generation(request: Dict = Body(...)):
    """
    V18.4: External progress push — allows benchmark scripts and external
    generation processes to update the LIVE_GEN_TRACKER so the UI shows
    real-time progress from any source.

    Body: {
        "shot_id": "003_000A",
        "status": "running" | "completed" | "error",
        "asset_type": "first_frame" | "video",
        "project": "ravencroft_v17",
        "prompt": "...",           // optional
        "model": "nano-banana-pro", // optional
        "url": "/api/media?path=...", // optional, for completed frames
        "progress_pct": 50,        // optional, 0-100
        "scene_id": "003",         // optional
        "error": "..."             // optional, for error status
    }
    """
    shot_id = request.get("shot_id", "")
    status = request.get("status", "running")
    asset_type = request.get("asset_type", "first_frame")
    project = request.get("project", "")
    url = request.get("url", "")

    if not shot_id:
        return {"success": False, "error": "shot_id required"}

    if status == "running":
        LIVE_GEN_TRACKER.add(
            project=project,
            shot_id=shot_id,
            status="running",
            asset_type=asset_type,
            prompt=request.get("prompt", ""),
            model=request.get("model", "")
        )
    else:
        LIVE_GEN_TRACKER.update(shot_id, status, url=url)

    return {"success": True, "shot_id": shot_id, "status": status}


