@app.post("/api/3shot/batch")
async def three_shot_batch(request: Dict = Body(...)):
    """Apply 3-shot selection to all shots in a project."""
    try:
        from three_shot_prompt_selector import select_best_prompt
        project = request.get("project", "")
        if not project:
            return {"success": False, "error": "Project name required"}

        project_path = get_project_path(project)
        shot_plan_path = project_path / "shot_plan.json"
        if not shot_plan_path.exists():
            return {"success": False, "error": "No shot_plan.json found"}

        with open(shot_plan_path) as f:
            data = json.load(f)

        shots = data.get("shots", [])
        enhanced_count = 0
        for shot in shots:
            nano_prompt = shot.get("nano_prompt", "")
            if nano_prompt:
                best, candidates = select_best_prompt(
                    nano_prompt,
                    shot_metadata=shot,
                    scene_metadata={}
                )
                if best != nano_prompt:
                    shot["nano_prompt"] = best
                    shot["_3shot_candidates"] = candidates
                    shot["_3shot_applied"] = True
                    enhanced_count += 1

        # Save updated shot plan
        with open(shot_plan_path, "w") as f:
            json.dump(data, f, indent=2)

        return {
            "success": True,
            "total_shots": len(shots),
            "enhanced": enhanced_count,
            "message": f"Applied 3-shot selection to {enhanced_count} shots"
        }
    except Exception as e:
        return {"success": False, "error": str(e)}


