@app.get("/api/v6/story-state/{project_name}")
async def get_story_state(project_name: str):
    """Get story state for a project INCLUDING story_bible content for editor."""
    project_path = get_project_path(project_name)

    state = {
        "project": project_name,
        "exists": project_path.exists(),
        "has_shot_plan": (project_path / "shot_plan.json").exists(),
        "has_story_bible": (project_path / "story_bible.json").exists(),
        "characters_locked": False,
        "locations_locked": False,
        "casting_complete": False,
        "story_bible": None  # V16.5: Include actual content for editor
    }

    # Check for locks
    locks_path = project_path / "master_locks.json"
    if locks_path.exists():
        with open(locks_path) as f:
            locks = json.load(f)
            state["characters_locked"] = locks.get("characters", False)
            state["locations_locked"] = locks.get("locations", False)
            state["casting_complete"] = locks.get("casting", False)

    # V16.5: Load actual story_bible content for editor
    story_bible_path = project_path / "story_bible.json"
    if story_bible_path.exists():
        try:
            with open(story_bible_path) as f:
                state["story_bible"] = json.load(f)
        except Exception as e:
            print(f"[story-state] Failed to load story_bible: {e}")

    return state


@app.get("/api/assets/character-refs")
async def get_character_refs(project: str = Query("")):
    """Return character reference images for project. Never 500s."""
    try:
        if not project:
            return {"characters": [], "count": 0}
        project_path = get_project_path(project)
        characters = []

        # Priority 1: Project-specific character_library_locked
        refs_dir = project_path / "character_library_locked"
        if refs_dir.exists():
            for img in refs_dir.glob("*.*"):
                if img.suffix.lower() in [".jpg", ".jpeg", ".png", ".webp"]:
                    characters.append({
                        "name": img.stem,
                        "image_url": f"/api/media?path={img}",
                        "local_path": str(img)
                    })

        # Priority 2: Cast map with headshots - ONLY if casting is APPROVED
        # V16.5 OPERATOR TRUTH: Don't show AI actor headshots until casting finalized
        if not characters:
            cast_map_path = project_path / "cast_map.json"
            if cast_map_path.exists():
                import json
                with open(cast_map_path) as f:
                    cast_map = json.load(f)
                # CRITICAL: Only use cast_map refs if casting is approved
                if cast_map.get("_approved", False):
                    for char_name, cast_info in cast_map.items():
                        if char_name.startswith("_"):
                            continue
                        headshot = cast_info.get("headshot_url", cast_info.get("locked_reference_url", ""))
                        if headshot:
                            characters.append({
                                "name": char_name,
                                "ai_actor": cast_info.get("ai_actor", ""),
                                "image_url": headshot,
                                "fit_score": cast_info.get("fit_score", 0),
                                "casting_approved": True  # Flag that these are cast refs
                            })

        # Priority 3: REMOVED - Never show global AI actors in character refs
        # V16.5: This was causing AI actors to appear as character refs incorrectly

        return {"characters": characters, "count": len(characters)}
    except Exception as e:
        print(f"[DEFENSIVE] character-refs error: {e}")
        return {"characters": [], "count": 0}


