@app.post("/api/auto/generate-episode")
async def generate_episode(request: Dict = Body(...)):
    """Generate episode from concept using LLM - creates scene breakdown with beats."""
    import httpx

    # V16.4 FIX: Robust parameter handling with fallbacks
    concept = request.get("concept", "") or request.get("story_idea", "") or request.get("prompt", "")
    runtime_raw = request.get("runtime", 10)
    # V16.4 FIX: Parse runtime from various formats ("5min", "5", 5, etc.)
    if isinstance(runtime_raw, (int, float)):
        runtime = int(runtime_raw)
    elif isinstance(runtime_raw, str):
        # Handle "5min", "30min", etc.
        runtime_str = runtime_raw.lower().replace("min", "").replace("m", "").strip()
        try:
            runtime = int(runtime_str) if runtime_str else 10
        except ValueError:
            runtime = 10
    else:
        runtime = 10
    # Clamp to reasonable range (1-120 min)
    runtime = max(1, min(120, runtime))
    genre = request.get("genre", "") or "thriller"
    director_id = request.get("director_id")
    writer_id = request.get("writer_id")
    title = request.get("title", "") or "Untitled Episode"

    if not concept:
        return {"error": "Concept is required (provide 'concept', 'story_idea', or 'prompt')"}

    # Load API key
    env_path = Path(str(BASE_DIR) + "/.env")
    api_key = ""
    if env_path.exists():
        with open(env_path) as f:
            for line in f:
                if line.startswith("OPENROUTER_API_KEY="):
                    api_key = line.split("=", 1)[1].strip()
                    break

    if not api_key:
        return {"success": False, "error": "OpenRouter API key not configured"}

    # Load director/writer profiles if specified
    director_style = ""
    writer_style = ""
    if director_id:
        directors_path = Path(str(BASE_DIR) + "/directors_library.json")
        if directors_path.exists():
            with open(directors_path) as f:
                for d in json.load(f).get("directors", []):
                    if d.get("id") == director_id:
                        director_style = f"Director style: {d.get('name')} - {d.get('visual_signature', {}).get('camera_philosophy', '')}"
                        break

    prompt = f"""Create a detailed episode breakdown for:

CONCEPT: {concept}
GENRE: {genre}
RUNTIME: {runtime} minutes
TITLE: {title}
{director_style}

Generate a JSON episode structure with:
1. title - episode title
2. logline - one sentence summary
3. scenes - array of 5-8 scenes, each with:
   - scene_id (001, 002, etc.)
   - title - scene title
   - location - where it takes place
   - time_of_day - DAY/NIGHT/DUSK/DAWN
   - int_ext - INT/EXT
   - duration_seconds - estimated duration (total should equal {runtime * 60}s)
   - description - what happens
   - beats - array of 3-6 beats per scene with:
     - beat_number
     - beat_type (establishing/action/dialogue/revelation/transition)
     - description
     - characters - array of character names involved
     - emotional_tone
     - dialogue (if any)
4. characters - array of main characters with name, role, description
5. total_duration_seconds

Return ONLY valid JSON."""

    try:
        async with httpx.AsyncClient(timeout=90.0) as client:
            response = await client.post(
                "https://openrouter.ai/api/v1/chat/completions",
                headers={
                    "Authorization": f"Bearer {api_key}",
                    "Content-Type": "application/json",
                    "HTTP-Referer": "https://atlas-control-system.local",
                    "X-Title": "ATLAS Episode Generator"
                },
                json={
                    "model": "anthropic/claude-sonnet-4",
                    "messages": [
                        {"role": "system", "content": "You are a professional TV writer. Generate detailed episode breakdowns in JSON format with proper scene structure and emotional beats."},
                        {"role": "user", "content": prompt}
                    ],
                    "temperature": 0.7,
                    "max_tokens": 6000
                }
            )

            if response.status_code != 200:
                return {"success": False, "error": f"LLM API error: {response.status_code}"}

            result = response.json()
            content = result.get("choices", [{}])[0].get("message", {}).get("content", "")

            json_match = re.search(r'\{[\s\S]*\}', content)
            if json_match:
                episode_data = json.loads(json_match.group())
            else:
                return {"success": False, "error": "Failed to parse LLM response"}

            # Create project slug
            slug = re.sub(r'[^a-z0-9]+', '_', title.lower())[:40]
            project_path = get_project_path(slug)
            project_path.mkdir(parents=True, exist_ok=True)

            # V17 FIX: Create required subdirectories
            (project_path / "location_masters").mkdir(exist_ok=True)
            (project_path / "first_frames").mkdir(exist_ok=True)
            (project_path / "videos").mkdir(exist_ok=True)

            # Save as shot_plan.json
            episode_data["_generated_at"] = datetime.now().isoformat()
            episode_data["_generator"] = "LLM:anthropic/claude-sonnet-4"
            episode_data["_concept"] = concept

            # V16.4 FIX: Add metadata with target_runtime BEFORE saving
            runtime_seconds = runtime * 60
            shot_plan_data = {
                "scene_manifest": episode_data.get("scenes", []),
                "characters": episode_data.get("characters", []),
                "metadata": {
                    "title": title,
                    "genre": genre,
                    "target_runtime": runtime_seconds,  # In seconds for expansion
                    "runtime_target_minutes": float(runtime)
                },
                **episode_data
            }
            with open(project_path / "shot_plan.json", 'w') as f:
                json.dump(shot_plan_data, f, indent=2)

            logger.info(f"[EPISODE] Generated {slug} with {len(episode_data.get('scenes', []))} scenes")

            # V16.4 FIX: Create story_bible.json with correct runtime target
            runtime_seconds = runtime * 60  # Convert minutes to seconds

            # V17 FIX: Build proper locations array from scenes
            location_names = list(set(s.get("location", "") for s in episode_data.get("scenes", []) if s.get("location")))
            locations_array = [
                {"name": loc, "description": f"Location from scene", "source": "extracted"}
                for loc in location_names
            ]

            story_bible = {
                "title": title,
                "series_title": title,
                "episode_number": 1,
                "genre": genre,
                "tone": ["cinematic", "atmospheric"],
                "runtime_target_minutes": float(runtime),
                "runtime_target_seconds": runtime_seconds,
                "setting": {
                    "time_period": "modern",
                    "locations": location_names
                },
                # V17 FIX: Add top-level locations array for UI
                "locations": locations_array,
                "characters": episode_data.get("characters", []),
                # V17 FIX: PRESERVE FULL BEATS WITH DIALOGUE - DO NOT STRIP!
                "scenes": [
                    {
                        "scene_id": s.get("scene_id"),
                        "title": s.get("title"),
                        "location": s.get("location"),
                        "time_of_day": s.get("time_of_day"),
                        "int_ext": s.get("int_ext", "INT"),
                        "estimated_duration_seconds": s.get("duration_seconds", s.get("estimated_duration_seconds", 60)),
                        # CRITICAL: Preserve full beats array with dialogue
                        "beats": s.get("beats", []),
                        "beat_count": len(s.get("beats", [])),
                        "characters": s.get("characters", []),
                        "description": s.get("description", "")
                    }
                    for s in episode_data.get("scenes", [])
                ],
                "visual_style": {
                    "aspect_ratio": "16:9",
                    "color_palette": "cinematic",
                    "lighting_style": "atmospheric"
                },
                "_generated_by": "LLM_EPISODE_GENERATOR",
                "_timestamp": datetime.now().isoformat()
            }
            with open(project_path / "story_bible.json", 'w') as f:
                json.dump(story_bible, f, indent=2)
            logger.info(f"[EPISODE] Created story_bible.json with {runtime} min runtime target")

            # V25: CREATIVE INTELLIGENCE EXPANSION (replaces generic template expansion)
            # Creative pipeline bridge uses scene grammars + director profiles + coverage contracts
            # Falls back to SHOT_EXPANSION_INTEGRATOR if creative bridge unavailable
            shot_count = 0
            try:
                from tools.creative_pipeline_bridge import creative_expand_project
                _cpb_genre = story_bible.get("genre", "mystery_thriller")
                _cpb_director = "atlas_default"
                _cpb_runtime = runtime_seconds if runtime_seconds else 600
                success, expanded_manifest, msg = creative_expand_project(
                    slug, genre=_cpb_genre, director=_cpb_director,
                    target_runtime_seconds=_cpb_runtime
                )
                if success:
                    shot_count = len(expanded_manifest.get("shots", []))
                    logger.info(f"[V25 CREATIVE] ✅ Expanded to {shot_count} shots via creative grammar ({_cpb_genre}/{_cpb_director})")
                else:
                    logger.warning(f"[V25 CREATIVE] Creative expansion failed: {msg} — falling back to legacy")
                    raise ImportError("Creative bridge failed, use fallback")
            except (ImportError, Exception) as _cpb_err:
                # Fallback to legacy expansion
                try:
                    from SHOT_EXPANSION_INTEGRATOR import expand_project_shots
                    success, expanded_manifest, msg = expand_project_shots(slug)
                    if success:
                        shot_count = len(expanded_manifest.get("shots", []))
                        logger.info(f"[EPISODE] Expanded to {shot_count} shots (legacy)")
                    else:
                        logger.warning(f"[EPISODE] Shot expansion failed: {msg}")
                except Exception as exp_err:
                    logger.warning(f"[EPISODE] Shot expansion error: {exp_err}")

            # V17 FIX: Apply fix-v16 to ensure extended shots and duration scaling
            try:
                fix_result = await fix_shot_plan_v16({"project": slug})
                if fix_result.get("success"):
                    extended_count = fix_result.get("extended_shots_fixed", 0)
                    logger.info(f"[EPISODE] fix-v16 applied: {extended_count} extended shots created")
            except Exception as fix_err:
                logger.warning(f"[EPISODE] fix-v16 error: {fix_err}")

            # V16.3 FIX: Auto-cast characters
            cast_count = 0
            try:
                cast_result = await auto_cast_project({"project": slug})
                if cast_result.get("success"):
                    cast_count = cast_result.get("characters_cast", 0)
                    logger.info(f"[EPISODE] Auto-cast {cast_count} characters")
            except Exception as cast_err:
                logger.warning(f"[EPISODE] Auto-cast error: {cast_err}")

            # V16.4 FIX: LLM Oversight - Validate and fix project completeness
            oversight_result = None
            try:
                oversight_result = await llm_oversight_validation(slug, api_key, runtime_seconds)
                logger.info(f"[EPISODE] LLM oversight complete: {oversight_result.get('status', 'unknown')}")
            except Exception as oversight_err:
                logger.warning(f"[EPISODE] LLM oversight error: {oversight_err}")

            return {
                "success": True,
                "status": "success",  # V16.4 FIX: UI compatibility
                "project": slug,
                "title": title,
                "runtime": runtime,
                "episode": episode_data,
                "scene_count": len(episode_data.get("scenes", [])),
                "shot_count": shot_count,
                "cast_count": cast_count,
                "saved_to": str(project_path)
            }

    except Exception as e:
        logger.error(f"Episode generation error: {e}")
        return {"success": False, "status": "error", "error": str(e)}


# =============================================================================
# V17: UNIFIED ZERO-TOUCH PIPELINE
# =============================================================================

@app.post("/api/auto/full-pipeline")
async def full_pipeline_zero_touch(request: Dict = Body(...)):
    """
    V17 ZERO-TOUCH PIPELINE

    Single endpoint that takes a concept/script and produces a render-ready project.
    Executes: create → story bible → episode → fix → cast → OpsCoordinator → READY

    Request:
        {
            "project": "my_project",
            "concept": "A story about...",  // OR
            "script_text": "FADE IN...",
            "genre": "sci-fi",
            "runtime_minutes": 5,
            "title": "My Movie"
        }

    Returns:
        {
            "success": true,
            "project": "my_project",
            "verdict": "READY",
            "stages": {...},
            "smoke_test": {...}
        }
    """
    import sys
    from pathlib import Path

    project = request.get("project", "zero_touch_" + datetime.now().strftime("%Y%m%d_%H%M%S"))
    concept = request.get("concept", "")
    script_text = request.get("script_text", "")
    genre = request.get("genre", "drama")
    runtime_minutes = request.get("runtime_minutes", 5)
    title = request.get("title", project)

    stages = {}
    errors = []

    logger.info(f"[ZERO-TOUCH] Starting pipeline for project: {project}")

    # Stage 1: Create project directory
    try:
        project_path = PIPELINE_OUTPUTS / project
        project_path.mkdir(parents=True, exist_ok=True)
        stages["create_directory"] = {"success": True, "path": str(project_path)}
        logger.info(f"[ZERO-TOUCH] Stage 1: Created {project_path}")
    except Exception as e:
        stages["create_directory"] = {"success": False, "error": str(e)}
        errors.append(f"create_directory: {e}")
        return {"success": False, "project": project, "stages": stages, "errors": errors}

    # Stage 2: Generate story bible
    try:
        story_bible_request = {
            "project": project,
            "concept": concept if concept else script_text[:500],
            "genre": genre,
            "runtime_minutes": runtime_minutes,
            "title": title
        }
        if script_text:
            story_bible_request["script_text"] = script_text

        sb_result = await generate_story_bible_from_script(story_bible_request)

        if sb_result.get("success"):
            stages["story_bible"] = {"success": True, "characters": len(sb_result.get("story_bible", {}).get("characters", []))}
            logger.info(f"[ZERO-TOUCH] Stage 2: Story bible generated")
        else:
            stages["story_bible"] = {"success": False, "error": sb_result.get("error", "unknown")}
            errors.append(f"story_bible: {sb_result.get('error')}")
    except Exception as e:
        stages["story_bible"] = {"success": False, "error": str(e)}
        errors.append(f"story_bible: {e}")

    # Stage 3: Generate episode with scenes and shots
    try:
        episode_request = {
            "project": project,
            "concept": concept if concept else script_text[:500],
            "genre": genre,
            "runtime": runtime_minutes,
            "title": title
        }

        ep_result = await generate_episode(episode_request)

        if ep_result.get("success"):
            stages["episode"] = {
                "success": True,
                "scenes": ep_result.get("scene_count", 0),
                "shots": ep_result.get("shot_count", 0),
                "cast": ep_result.get("cast_count", 0)
            }
            logger.info(f"[ZERO-TOUCH] Stage 3: Episode generated - {stages['episode']['shots']} shots")
        else:
            stages["episode"] = {"success": False, "error": ep_result.get("error", "unknown")}
            errors.append(f"episode: {ep_result.get('error')}")
            # Don't fail here - try to continue with whatever was created
    except Exception as e:
        stages["episode"] = {"success": False, "error": str(e)}
        errors.append(f"episode: {e}")

    # Stage 4: Run OpsCoordinator in REPAIR mode
    try:
        # Import OpsCoordinator
        sys.path.insert(0, str(Path(str(BASE_DIR) + "/atlas_agents_v16_7")))
        from atlas_agents.ops_coordinator import OpsCoordinator

        coord = OpsCoordinator(repo_root=BASE_DIR)
        ops_result = coord.run_pipeline(
            projects=[project],
            mode="REPAIR",
            initiated_by="zero_touch_pipeline"
        )

        project_result = ops_result.get("projects", {}).get(project, {})
        final_verdict = project_result.get("critic_verdict", "UNKNOWN")

        stages["ops_coordinator"] = {
            "success": final_verdict == "READY",
            "verdict": final_verdict,
            "reason": project_result.get("critic_reason", ""),
            "run_id": ops_result.get("run_id", "")
        }
        logger.info(f"[ZERO-TOUCH] Stage 4: OpsCoordinator verdict = {final_verdict}")

    except Exception as e:
        stages["ops_coordinator"] = {"success": False, "error": str(e)}
        errors.append(f"ops_coordinator: {e}")
        final_verdict = "ERROR"

    # Stage 5: Run smoke test (lightweight validation)
    smoke_result = {}
    try:
        # Check key files exist
        shot_plan_path = project_path / "shot_plan.json"
        story_bible_path = project_path / "story_bible.json"
        cast_map_path = project_path / "cast_map.json"

        smoke_result = {
            "shot_plan_exists": shot_plan_path.exists(),
            "story_bible_exists": story_bible_path.exists(),
            "cast_map_exists": cast_map_path.exists(),
        }

        if shot_plan_path.exists():
            import json
            with open(shot_plan_path) as f:
                sp = _sp_guard(json.load(f))
            smoke_result["shot_count"] = len(sp.get("shots", []))
            smoke_result["shots_with_nano_prompt"] = sum(1 for s in sp.get("shots", []) if s.get("nano_prompt"))
            smoke_result["shots_with_ltx"] = sum(1 for s in sp.get("shots", []) if s.get("ltx_motion_prompt"))

        stages["smoke_test"] = {"success": True, "checks": smoke_result}

    except Exception as e:
        stages["smoke_test"] = {"success": False, "error": str(e)}

    # Final result
    overall_success = stages.get("ops_coordinator", {}).get("verdict") == "READY"

    logger.info(f"[ZERO-TOUCH] Pipeline complete: {'SUCCESS' if overall_success else 'FAILED'}")

    return {
        "success": overall_success,
        "project": project,
        "verdict": stages.get("ops_coordinator", {}).get("verdict", "ERROR"),
        "stages": stages,
        "errors": errors if errors else None,
        "message": "ZERO-TOUCH PIPELINE COMPLETE" if overall_success else "Pipeline completed with issues"
    }


@app.post("/api/auto/generate-characters")
async def generate_characters(request: Dict = Body(...)):
    """Generate character visual references using LLM based on story bible."""
    import httpx

    project = request.get("project", "")
    if not project:
        return {"success": False, "error": "Project name required"}

    # Load story bible or shot plan for character info
    project_path = get_project_path(project)
    characters = []

    bible_path = project_path / "story_bible.json"
    shot_plan_path = project_path / "shot_plan.json"

    if bible_path.exists():
        with open(bible_path) as f:
            data = json.load(f)
            characters = data.get("characters", [])
    elif shot_plan_path.exists():
        with open(shot_plan_path) as f:
            data = json.load(f)
            characters = data.get("characters", [])

    if not characters:
        return {"success": False, "error": "No characters found in project"}

    # Load API key
    env_path = Path(str(BASE_DIR) + "/.env")
    api_key = ""
    if env_path.exists():
        with open(env_path) as f:
            for line in f:
                if line.startswith("OPENROUTER_API_KEY="):
                    api_key = line.split("=", 1)[1].strip()
                    break

    if not api_key:
        return {"success": False, "error": "OpenRouter API key not configured"}

    # Generate visual prompts for each character
    enhanced_characters = []
    for char in characters[:10]:  # Limit to 10
        name = char.get("name", "Unknown")
        desc = char.get("description", char.get("visual_prompt", ""))

        if not char.get("visual_prompt") or len(char.get("visual_prompt", "")) < 50:
            try:
                async with httpx.AsyncClient(timeout=30.0) as client:
                    response = await client.post(
                        "https://openrouter.ai/api/v1/chat/completions",
                        headers={"Authorization": f"Bearer {api_key}", "Content-Type": "application/json"},
                        json={
                            "model": "anthropic/claude-sonnet-4",
                            "messages": [{"role": "user", "content": f"Create a detailed visual prompt for AI image generation of this character:\nName: {name}\nDescription: {desc}\n\nReturn a single paragraph describing their appearance, clothing, and distinguishing features for image generation."}],
                            "max_tokens": 300
                        }
                    )
                    if response.status_code == 200:
                        char["visual_prompt"] = response.json().get("choices", [{}])[0].get("message", {}).get("content", desc)
            except Exception:
                pass

        enhanced_characters.append(char)

    # Save enhanced characters
    char_lib_path = project_path / "character_library.json"
    with open(char_lib_path, 'w') as f:
        json.dump({"characters": enhanced_characters, "_generated_at": datetime.now().isoformat()}, f, indent=2)

    return {
        "success": True,
        "status": "success",  # V16.4: UI compatibility
        "project": project,
        "characters": enhanced_characters,
        "count": len(enhanced_characters),
        "saved_to": str(char_lib_path),
        "tests": [],  # V16.4: Standard response format
        "issues": [],
        "health": 100
    }


@app.post("/api/auto/generate-locations")
async def generate_locations(request: Dict = Body(...)):
    """Generate location visual references using LLM based on story bible."""
    import httpx

    project = request.get("project", "")
    if not project:
        return {"success": False, "error": "Project name required"}

    # Load story bible or shot plan for location info
    project_path = get_project_path(project)
    locations = []

    bible_path = project_path / "story_bible.json"
    shot_plan_path = project_path / "shot_plan.json"

    # V16.7 FIX: Check story_bible first, then ALWAYS fall back to shot_plan if no locations
    if bible_path.exists():
        with open(bible_path) as f:
            data = json.load(f)
            locations = data.get("locations", [])

    # V16.7: If no locations in story_bible, extract from shot_plan scene_manifest
    if not locations and shot_plan_path.exists():
        with open(shot_plan_path) as f:
            data = json.load(f)
            # Extract unique locations from scenes
            seen = set()
            for scene in data.get("scene_manifest", data.get("scenes", [])):
                loc = scene.get("location", "")
                if loc and loc not in seen:
                    seen.add(loc)
                    locations.append({"name": loc, "time_of_day": scene.get("time_of_day", "DAY"), "int_ext": scene.get("int_ext", "INT")})

    if not locations:
        return {"success": False, "error": "No locations found in project"}

    # Load API key
    env_path = Path(str(BASE_DIR) + "/.env")
    api_key = ""
    if env_path.exists():
        with open(env_path) as f:
            for line in f:
                if line.startswith("OPENROUTER_API_KEY="):
                    api_key = line.split("=", 1)[1].strip()
                    break

    if not api_key:
        return {"success": False, "error": "OpenRouter API key not configured"}

    # Generate visual prompts for each location
    enhanced_locations = []
    for loc in locations[:8]:  # Limit to 8
        name = loc.get("name", "Unknown")
        desc = loc.get("description", "")
        time = loc.get("time_of_day", "DAY")
        int_ext = loc.get("int_ext", "INT")

        if not loc.get("visual_prompt") or len(loc.get("visual_prompt", "")) < 50:
            try:
                async with httpx.AsyncClient(timeout=30.0) as client:
                    response = await client.post(
                        "https://openrouter.ai/api/v1/chat/completions",
                        headers={"Authorization": f"Bearer {api_key}", "Content-Type": "application/json"},
                        json={
                            "model": "anthropic/claude-sonnet-4",
                            "messages": [{"role": "user", "content": f"Create a detailed visual prompt for AI image generation of this location:\nName: {name}\nType: {int_ext}\nTime: {time}\nDescription: {desc}\n\nReturn a single paragraph describing the environment, lighting, atmosphere, and key visual elements."}],
                            "max_tokens": 300
                        }
                    )
                    if response.status_code == 200:
                        loc["visual_prompt"] = response.json().get("choices", [{}])[0].get("message", {}).get("content", desc)
            except Exception:
                pass

        enhanced_locations.append(loc)

    # Save enhanced locations
    loc_lib_path = project_path / "location_library.json"
    with open(loc_lib_path, 'w') as f:
        json.dump({"locations": enhanced_locations, "_generated_at": datetime.now().isoformat()}, f, indent=2)

    return {
        "success": True,
        "status": "success",  # V16.4: UI compatibility
        "project": project,
        "locations": enhanced_locations,
        "count": len(enhanced_locations),
        "saved_to": str(loc_lib_path),
        "tests": [],
        "issues": [],
        "health": 100
    }


