# ============================================================
# V17.3: LOCATION DESCRIPTION INJECTION
# Enriches nano_prompt and ltx_motion_prompt with visual
# descriptions from story_bible locations, so the image model
# renders the correct environment instead of guessing.
# ============================================================

def inject_location_descriptions(shots: list, story_bible: dict) -> int:
    """
    Inject rich location descriptions from story_bible into shot prompts.

    Problem: nano_prompts contain bare location names like "CITY APARTMENT" or
    "LAW OFFICE" with no visual detail, forcing the image model to guess.
    The story_bible has rich visual_prompt, lighting, time_of_day, and
    atmosphere fields for each location.

    This function:
    1. Builds a fuzzy location lookup from story_bible.locations
    2. For each shot, matches the shot's location to the best bible entry
    3. Appends the visual_prompt to nano_prompt (after the bare location name)
    4. Adds atmosphere + lighting context to ltx_motion_prompt

    Args:
        shots: List of shot dicts (mutated in-place)
        story_bible: Parsed story_bible.json dict

    Returns:
        Number of shots that were enriched with location descriptions
    """
    locations = story_bible.get("locations", [])
    if not locations or not shots:
        return 0

    # ---- Step 1: Build location lookup with normalized keys ----
    # Maps normalized_name -> location dict
    loc_lookup = {}
    for loc in locations:
        name = loc.get("name", "").strip()
        if not name:
            continue
        # Store under the exact name (uppercased)
        norm = _normalize_location_name(name)
        loc_lookup[norm] = loc

    if not loc_lookup:
        return 0

    enriched_count = 0

    for shot in shots:
        shot_location = (shot.get("location") or "").strip()
        if not shot_location:
            continue

        # ---- Step 2: Find best matching location ----
        matched_loc = _match_location(shot_location, loc_lookup)
        if not matched_loc:
            continue

        visual_prompt = (matched_loc.get("visual_prompt") or "").strip()
        if not visual_prompt:
            continue

        # ---- Step 3: Inject into nano_prompt ----
        nano = shot.get("nano_prompt", "")
        if nano and visual_prompt[:40].lower() not in nano.lower():
            # Find the bare location name in the nano_prompt and append description after it
            # Use the shot's location string as the anchor point
            location_upper = shot_location.upper()
            nano_upper = nano.upper()

            # Check if the location name appears in the prompt
            loc_idx = nano_upper.find(location_upper)
            if loc_idx >= 0:
                # Insert visual description right after the location name
                insert_pos = loc_idx + len(location_upper)
                # Check for trailing period or comma to insert cleanly
                sep = " — "
                nano = nano[:insert_pos] + sep + visual_prompt + nano[insert_pos:]
            else:
                # Location name not found verbatim; append to end before any negatives
                neg_marker = "NO grid"
                neg_idx = nano.find(neg_marker)
                if neg_idx > 0:
                    nano = nano[:neg_idx].rstrip(", ") + f", location: {visual_prompt}, " + nano[neg_idx:]
                else:
                    nano = nano + f". location: {visual_prompt}"

            shot["nano_prompt"] = nano

            # ---- Step 4: Inject atmosphere + lighting into ltx_motion_prompt ----
            ltx = shot.get("ltx_motion_prompt", "")
            atmosphere = (matched_loc.get("atmosphere") or "").strip()
            lighting = (matched_loc.get("lighting") or "").strip()
            time_of_day = (matched_loc.get("time_of_day") or "").strip()

            ltx_additions = []
            if atmosphere and atmosphere.lower() not in ltx.lower():
                ltx_additions.append(f"atmosphere: {atmosphere}")
            if lighting and lighting[:30].lower() not in ltx.lower():
                ltx_additions.append(f"lighting: {lighting}")
            if time_of_day and time_of_day.lower() not in ltx.lower():
                ltx_additions.append(f"time: {time_of_day}")

            if ltx_additions and ltx:
                shot["ltx_motion_prompt"] = ltx + ", " + ", ".join(ltx_additions)
            elif ltx_additions:
                shot["ltx_motion_prompt"] = ", ".join(ltx_additions)

            enriched_count += 1
            logger.info(f"[V17.3 LOCATION] Shot {shot.get('shot_id', '?')}: "
                        f"injected '{matched_loc.get('name', '')}' description "
                        f"(+{len(visual_prompt)} chars nano, +{sum(len(a) for a in ltx_additions)} chars ltx)")

    logger.info(f"[V17.3 LOCATION] Enriched {enriched_count}/{len(shots)} shots with location descriptions")
    return enriched_count


def _normalize_location_name(name: str) -> str:
    """
    Normalize a location name for fuzzy matching.
    Strips time-of-day suffixes, normalizes dashes/slashes, uppercases.
    'RAVENCROFT MANOR - RITUAL ROOM' -> 'RAVENCROFT MANOR RITUAL ROOM'
    """
    import re as _re
    n = name.upper().strip()
    # Replace em-dashes, en-dashes, hyphens with space
    n = n.replace("\u2013", " ").replace("\u2014", " ").replace("-", " ")
    # Remove common suffixes: time of day, INT/EXT markers
    n = _re.sub(r"\b(NIGHT|DAY|MORNING|AFTERNOON|EVENING|DUSK|DAWN|LATER|CONTINUOUS)\b", "", n)
    n = _re.sub(r"\b(INT|EXT)\b\.?", "", n)
    # Remove slashes and everything after (variant markers like "/ VARIOUS")
    n = _re.sub(r"\s*/\s*.*$", "", n)
    # Collapse whitespace
    n = _re.sub(r"\s+", " ", n).strip()
    return n


def _match_location(shot_location: str, loc_lookup: dict) -> dict:
    """
    Find the best matching location entry for a shot's location string.
    Uses exact match first, then substring containment, then token overlap.

    Args:
        shot_location: The location string from the shot (e.g. "MANOR - STUDY - LATER THAT NIGHT")
        loc_lookup: Dict of normalized_name -> location_dict

    Returns:
        Best matching location dict, or None if no match found
    """
    norm_shot = _normalize_location_name(shot_location)

    # Pass 1: Exact normalized match
    if norm_shot in loc_lookup:
        return loc_lookup[norm_shot]

    # Pass 2: Shot location contains bible location or vice versa
    # Prefer matches with smallest length difference (closest fit avoids
    # "RAVENCROFT MANOR" matching "RAVENCROFT MANOR RITUAL ROOM")
    best_match = None
    best_diff = float("inf")
    for norm_name, loc_data in loc_lookup.items():
        # V17.6: Scored matching replaces loose substring
        _loc_score, _loc_passes = score_name_match(norm_name, norm_shot, threshold=50)
        if _loc_passes and _loc_score > (100 - best_diff):  # Higher score = better match
            best_diff = 100 - _loc_score  # Convert score to "diff" (lower is better)
            best_match = loc_data

    if best_match:
        return best_match

    # Pass 3: Token overlap scoring
    shot_tokens = set(norm_shot.split())
    best_score = 0
    best_match = None
    for norm_name, loc_data in loc_lookup.items():
        loc_tokens = set(norm_name.split())
        if not loc_tokens:
            continue
        overlap = shot_tokens & loc_tokens
        # Score = overlap count / max(len) to prefer precise matches
        score = len(overlap) / max(len(loc_tokens), 1)
        # Require at least 50% token overlap to avoid false matches
        if score > 0.5 and score > best_score:
            best_score = score
            best_match = loc_data
        elif score == best_score and len(overlap) > len(shot_tokens & set(_normalize_location_name(best_match.get("name", "")).split() if best_match else [])):
            best_match = loc_data

    return best_match


@app.post("/api/v27/aesthetic-gate/{project}")
async def aesthetic_gate_endpoint(project: str, request: Dict = Body({})):
    """V27.2: Cinematic Aesthetic Gate — scores first frames on 6 cinematic dimensions.
    Uses OpenRouter vision (Claude 3.5 Sonnet) to detect AI-generic vs cinematic quality.
    Returns per-shot scores + cross-scene consistency report.
    """
    project_path = PIPELINE_OUTPUTS_DIR / project
    if not project_path.is_dir():
        return {"success": False, "error": f"Project {project} not found"}

    scene_id = request.get("scene_id", "")
    scene_genre = request.get("genre", "gothic_horror")
    shots_filter = request.get("shot_ids", [])  # optional: score specific shots only

    try:
        # Load shot types from shot_plan
        sp_path = project_path / "shot_plan.json"
        shot_types = {}
        if sp_path.exists():
            sp = json.load(open(sp_path))
            shots_list = sp if isinstance(sp, list) else sp.get("shots", [])
            for s in shots_list:
                shot_types[s.get("shot_id", "")] = s.get("shot_type", "")

        from tools.cinematic_aesthetic_gate import (
            score_frame_aesthetic, build_cinematic_prompt_injection,
            score_cross_scene_consistency, batch_score_scene
        )

        results = []
        frames_dir = project_path / "first_frames"

        if scene_id:
            # Score single scene
            results = batch_score_scene(scene_id, str(project_path), shot_types, scene_genre)
        elif shots_filter:
            # Score specific shots
            for sid in shots_filter:
                frame_path = frames_dir / f"{sid}.jpg"
                if frame_path.exists():
                    score = score_frame_aesthetic(
                        str(frame_path), sid,
                        shot_types.get(sid, ""), scene_genre
                    )
                    results.append(score)
        else:
            return {"success": False, "error": "Provide scene_id or shot_ids"}

        # Cross-scene consistency (if we have frames from multiple scenes)
        cross_scene = None
        if len(set(r.shot_id[:3] for r in results)) > 1:
            frames_for_cross = [
                {"shot_id": r.shot_id, "scene_id": r.shot_id[:3],
                 "image_path": str(frames_dir / f"{r.shot_id}.jpg")}
                for r in results if (frames_dir / f"{r.shot_id}.jpg").exists()
            ]
            cross_scene = score_cross_scene_consistency(frames_for_cross, scene_genre)

        # Build response
        approved = [r for r in results if r.verdict == "APPROVED"]
        needs_work = [r for r in results if r.verdict == "NEEDS_IMPROVEMENT"]
        rejected = [r for r in results if r.verdict == "REJECTED"]

        response = {
            "success": True,
            "project": project,
            "scene_id": scene_id,
            "total_frames": len(results),
            "approved": len(approved),
            "needs_improvement": len(needs_work),
            "rejected": len(rejected),
            "average_score": round(sum(r.composite_score for r in results) / max(len(results), 1), 2),
            "scores": [r.to_dict() for r in results],
            "fix_injections": {
                r.shot_id: build_cinematic_prompt_injection(r)
                for r in results if r.fixes_needed
            }
        }
        if cross_scene:
            response["cross_scene"] = {
                "aesthetic_drift": cross_scene.aesthetic_drift,
                "issues": cross_scene.consistency_issues,
                "recommendations": cross_scene.recommendations
            }

        return response

    except Exception as e:
        logger.error(f"[AESTHETIC-GATE] Error: {e}")
        return {"success": False, "error": str(e)}


@app.post("/api/v27/auto-recast/{project}")
async def auto_recast_endpoint(project: str, request: Dict = Body({})):
    """V27.3: Auto-Recast — Execute Creation Pack recast manifest.
    Generates character refs and location refs from canonical descriptions via FAL.
    T2-CK-5: When refs don't match screenplay descriptions, regenerate them.
    """
    project_path = PIPELINE_OUTPUTS_DIR / project
    if not project_path.is_dir():
        return {"success": False, "error": f"Project {project} not found"}

    dry_run = request.get("dry_run", False)
    chars_only = request.get("chars_only", False)
    locs_only = request.get("locs_only", False)
    force_all = request.get("force_all", False)

    try:
        # Step 1: Validate creation pack
        sys.path.insert(0, str(Path(__file__).parent / "tools"))
        from creation_pack_validator import validate_project, build_recast_manifest
        from run_recast import generate_ref, update_cast_map_provenance

        report = validate_project(str(project_path))
        if report.blocking_issues == 0 and not force_all:
            return {
                "success": True,
                "message": "All refs validated — no recast needed",
                "report": {"blocking": 0, "warnings": report.warning_issues}
            }

        # Step 2: Build manifest
        cast_map_path = project_path / "cast_map.json"
        story_bible_path = project_path / "story_bible.json"
        cast_map = json.load(open(cast_map_path)) if cast_map_path.exists() else {}
        story_bible = json.load(open(story_bible_path)) if story_bible_path.exists() else {}

        manifest = build_recast_manifest(report, cast_map, story_bible, force_all=force_all)

        # Filter by type
        if chars_only:
            manifest = [j for j in manifest if j["job_type"] == "character_ref"]
        elif locs_only:
            manifest = [j for j in manifest if j["job_type"] == "location_ref"]

        if dry_run:
            return {
                "success": True,
                "dry_run": True,
                "manifest_size": len(manifest),
                "jobs": manifest,
                "blocking_issues": report.blocking_issues,
                "warning_issues": report.warning_issues,
            }

        # Step 3: Execute manifest
        results = []
        for job in manifest:
            result = generate_ref(job, str(project_path), dry_run=False)
            results.append(result)

            # Update cast_map provenance for character refs
            if result.get("success") and job["job_type"] == "character_ref":
                try:
                    update_cast_map_provenance(
                        str(cast_map_path),
                        job["name"],
                        job["ref_type"],
                        job["prompt"],
                        result.get("selected", result.get("output_path", ""))
                    )
                except Exception as prov_err:
                    logger.warning(f"[RECAST] Provenance update failed for {job['name']}: {prov_err}")

            time.sleep(0.5)  # Rate limit FAL calls

        succeeded = sum(1 for r in results if r.get("success"))
        failed = len(results) - succeeded

        # Save report
        report_path = project_path / "reports" / "recast_report.json"
        report_path.parent.mkdir(parents=True, exist_ok=True)
        with open(report_path, "w") as f:
            json.dump({
                "timestamp": datetime.utcnow().isoformat(),
                "project": project,
                "jobs_total": len(results),
                "jobs_succeeded": succeeded,
                "jobs_failed": failed,
                "results": results,
            }, f, indent=2)

        return {
            "success": True,
            "jobs_total": len(results),
            "succeeded": succeeded,
            "failed": failed,
            "report_path": str(report_path),
        }

    except Exception as e:
        logger.error(f"[AUTO-RECAST] Error: {e}")
        import traceback
        return {"success": False, "error": str(e), "traceback": traceback.format_exc()}


@app.get("/api/v27/quality-diagnostics/{project}")
async def quality_diagnostics_endpoint(project: str):
    """V27.3: Unified Quality Diagnostics — Shows error patterns, failure rates,
    and suggested root-cause fixes across all generated frames.
    """
    project_path = PIPELINE_OUTPUTS_DIR / project
    if not project_path.is_dir():
        return {"success": False, "error": f"Project {project} not found"}

    try:
        # Load error patterns
        pattern_log = project_path / "reports" / "error_patterns.jsonl"
        failures = []
        if pattern_log.exists():
            for line in pattern_log.read_text().splitlines():
                if line.strip():
                    try:
                        failures.append(json.loads(line))
                    except json.JSONDecodeError:
                        pass

        # Load learning log
        learning_log = project_path / "learning_log.jsonl"
        learnings = []
        if learning_log.exists():
            for line in learning_log.read_text().splitlines():
                if line.strip():
                    try:
                        learnings.append(json.loads(line))
                    except json.JSONDecodeError:
                        pass

        # Detect patterns
        from tools.unified_quality_gate import ErrorPatternAggregator
        agg = ErrorPatternAggregator(str(project_path))
        agg.failures = failures
        patterns = agg.detect_patterns()

        # Build summary
        from collections import Counter
        by_verdict = dict(Counter(f.get("verdict", "?") for f in failures))
        by_scene = dict(Counter(f.get("scene_id", "?") for f in failures))
        by_character = Counter()
        for f in failures:
            for c in f.get("characters", []):
                by_character[c] += 1

        return {
            "success": True,
            "project": project,
            "total_failures": len(failures),
            "total_learnings": len(learnings),
            "patterns_detected": patterns,
            "by_verdict": by_verdict,
            "by_scene": by_scene,
            "by_character": dict(by_character.most_common(10)),
            "recent_failures": failures[-5:] if failures else [],
        }

    except Exception as e:
        return {"success": False, "error": str(e)}


@app.post("/api/auto/generate-first-frames")
async def generate_first_frames(request: Dict = Body(...)):
    """
    Generate first frames for shots using LOCKED REFERENCES.

    CORRECT MODEL SELECTION (per ai_actors_library.json):
    - fal-ai/nano-banana-pro/edit: When there ARE references (character OR location)
    - fal-ai/nano-banana-pro: When there are NO references
    - References passed via 'image_urls' parameter (up to 5)

    Body:
    {
        "project": "kord",
        "shot_ids": ["001_001A", "001_002A"],  // optional, if empty = all shots
        "dry_run": false  // if true, just return what would be generated
    }
    """
    import httpx

    # LOCKED MODELS - DO NOT CHANGE (fal_client imported at top of file)
    IMAGE_MODEL_WITH_REF = "fal-ai/nano-banana-pro/edit"  # With references
    IMAGE_MODEL_NO_REF = "fal-ai/nano-banana-pro"  # Without references

    project = request.get("project", "")

    # V22.3 FILM ENGINE GATE — block if not prepped
    _require_ready(project)

    shot_ids = request.get("shot_ids", [])
    scene_filter = request.get("scene_filter", "")  # V17.3: scene filter for controlled generation
    dry_run = request.get("dry_run", False)
    force = request.get("force", False)  # V17 FIX: Allow forced regeneration of existing frames
    num_variants = request.get("num_variants", 1)  # V17 FIX: Generate multiple variants for best-select
    lite_mode = request.get("lite_mode", False)  # V22: Skip ALL prompt enrichment — prompts go to FAL as-is

    if not project:
        return {"success": False, "error": "Project name required"}

    # V17.3 HARD LOCK: Must specify scene_filter OR shot_ids — NO full-project generation
    MAX_SHOTS_SEQUENTIAL = 40
    if not shot_ids and not scene_filter:
        return {
            "success": False,
            "error": "HARD LOCK: scene_filter or shot_ids REQUIRED. Use scene_filter='001' for scene-by-scene generation.",
            "hint": "This prevents accidental full-project generation which wastes API credits."
        }

    project_path = get_project_path(project)
    shot_plan_path = project_path / "shot_plan.json"

    if not shot_plan_path.exists():
        return {"success": False, "error": f"Project '{project}' not found"}

    with open(shot_plan_path) as f:
        data = json.load(f)

    # V27.1: Handle both list format [shots...] and dict format {"shots": [...]}
    if isinstance(data, list):
        shots = data
        data = {"shots": data}
    else:
        shots = data.get("shots", [])

    # =========================================================================
    # V23 PRODUCTION ROUTE GUARD: Prefer master-chain for production
    # The legacy generate-first-frames path lacks:
    #   - End-frame chaining (visual continuity)
    #   - Multi-angle variant selection
    #   - Scene-level consistency enforcement
    # For production, use /api/v18/master-chain/render-scene instead.
    # =========================================================================
    generation_mode = data.get("_generation_mode", "").lower()
    force_legacy = request.get("force_legacy", False)  # Escape hatch for debugging

    if generation_mode == "master_chain" and not force_legacy and not dry_run:
        logger.warning(f"[V23 ROUTE GUARD] Project '{project}' has generation_mode=master_chain but using legacy endpoint")
        return {
            "success": False,
            "error": "PRODUCTION ROUTE GUARD: This project is configured for master-chain generation.",
            "hint": "Use POST /api/v18/master-chain/render-scene with scene_id for proper visual continuity.",
            "alternative": f"/api/v18/master-chain/render-scene with project='{project}' and scene_id",
            "bypass": "Add 'force_legacy': true to force legacy path (not recommended for production)",
            "reason": "Master-chain provides end-frame chaining, multi-angle variants, and scene-level consistency enforcement."
        }

    # If no mode set but project is prepped, log advisory
    if not generation_mode and not dry_run and not lite_mode:
        logger.info(f"[V23 ROUTE GUARD] Advisory: Consider using master-chain for production-quality generation")

    # =========================================================================
    # V30 UNIFIED GENERATION PATH — ARCHITECTURE COLLAPSE
    # When scene_filter is set (scene-by-scene mode), delegate to atlas_universal_runner.
    # This collapses the 3-path architecture (orchestrator inline / v26 controller /
    # universal runner) into ONE canonical path so Wire A/B/C, compile_nano(),
    # identity injection, and all future upgrades apply automatically everywhere.
    #
    # Fallback: force_legacy=True OR shot_ids without scene_filter → legacy inline path.
    # =========================================================================
    if scene_filter and not force_legacy and not dry_run:
        logger.info(f"[V30 UNIFIED] scene_filter='{scene_filter}' → delegating to atlas_universal_runner (canonical path)")
        try:
            import subprocess, sys as _sys
            _runner_path = Path(__file__).parent / "atlas_universal_runner.py"
            _video_model = (request.get("video_model") or os.environ.get("ATLAS_VIDEO_MODEL", "kling")).lower()
            os.environ["ATLAS_VIDEO_MODEL"] = _video_model
            _cmd = [_sys.executable, str(_runner_path), project, scene_filter,
                    "--mode", "lite", "--frames-only"]
            logger.info(f"[V30 UNIFIED] cmd: {' '.join(_cmd)}")
            import threading as _threading
            _pdir = project_path
            def _bg_v30():
                try:
                    _p = subprocess.Popen(_cmd, cwd=str(Path(__file__).parent),
                                         stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True)
                    _o, _ = _p.communicate(timeout=600)
                    logger.info(f"[V30 UNIFIED] done (exit={_p.returncode}):\n{_o[-1500:]}")
                    try:
                        _bc = _pdir / "ui_cache" / "bundle.json"
                        if _bc.exists(): _bc.unlink()
                    except Exception: pass
                except Exception as _e:
                    logger.error(f"[V30 UNIFIED] bg error: {_e}")

            _threading.Thread(target=_bg_v30, daemon=True).start()
            return {
                "success": True,
                "status": "started",
                "scene_id": scene_filter,
                "project": project,
                "video_model": _video_model,
                "generation_path": "atlas_universal_runner_v30",
                "message": f"Scene {scene_filter} generation started — watch filmstrip"
            }
        except Exception as _e:
            logger.error(f"[V30 UNIFIED] Delegation failed: {_e} — falling back to legacy inline path", exc_info=True)
            # DO NOT return here — fall through to legacy path as safety net

    # =========================================================================
    # V23 LOCATION MASTER GATE: Require location masters for production quality
    # Without location masters, generated shots have no consistent environment.
    # FAL gets only text prompts, leading to room drift between shots.
    # =========================================================================
    skip_location_check = request.get("skip_location_check", False)
    if not dry_run and not skip_location_check:
        loc_masters_dir = project_path / "location_masters"
        location_masters_exist = loc_masters_dir.exists() and any(loc_masters_dir.glob("*.jpg")) or any(loc_masters_dir.glob("*.png"))

        if not location_masters_exist:
            # Get unique locations from shots to show what's missing
            unique_locations = set()
            for s in shots:
                loc = s.get("location", "").strip()
                if loc:
                    unique_locations.add(loc)

            logger.error(f"[V23 LOCATION GATE] No location masters found for {len(unique_locations)} locations")
            return {
                "success": False,
                "error": "LOCATION MASTER GATE: No location masters found.",
                "hint": "Run auto-prep or generate location masters first for visual consistency.",
                "missing_locations": list(unique_locations)[:10],
                "action": f"POST /api/auto/generate-location-masters with project='{project}'",
                "bypass": "Add 'skip_location_check': true to bypass (not recommended)",
                "reason": "Location masters provide environmental reference images that prevent room drift between shots."
            }

    # V27.1.4d: Save FULL shot plan before filtering — needed for screen position lock
    # Position lock must scan ALL shots in the scene (including OTS shots not in this batch)
    _all_shots_unfiltered = list(shots)

    # V27.1.4e: NARRATIVE BEAT INJECTION — Bridge story bible beats → shot objects
    # Story bible has rich emotional/action data per beat. Shots have beat_id but empty
    # beat/emotional_beat fields. This enrichment ensures the video prompt compiler
    # gets real narrative intelligence instead of falling back to generic defaults.
    try:
        _sb_path_for_beats = project_path / "story_bible.json"
        if _sb_path_for_beats.exists():
            with open(_sb_path_for_beats) as _sbf:
                _story_bible_for_beats = json.load(_sbf)
            # Build scene_id → beats list map (beats have no beat_id field — they're positional)
            _scene_beats_map = {}
            for _sc in _story_bible_for_beats.get("scenes", []):
                _sc_id = _sc.get("scene_id", "")
                _scene_beats_map[_sc_id] = _sc.get("beats", [])
            # Inject into ALL shots (unfiltered — so position lock shots also get beats)
            _beat_inject_count = 0
            for _shot in _all_shots_unfiltered:
                _bid = _shot.get("beat_id", "")
                _beat_data = None
                if _bid:
                    # Parse beat_id format: "001_beat_2" → scene_id="001", beat_index=2
                    _parts = _bid.split("_beat_")
                    if len(_parts) == 2:
                        _sc_id = _parts[0]
                        try:
                            _bi = int(_parts[1])
                        except ValueError:
                            _bi = -1
                        _sc_beats = _scene_beats_map.get(_sc_id, [])
                        if _sc_beats:
                            # Clamp index to available beats (shots may outnumber beats)
                            _clamped_bi = min(_bi, len(_sc_beats) - 1)
                            if _clamped_bi >= 0:
                                _beat_data = _sc_beats[_clamped_bi]
                if _beat_data:
                    if not _shot.get("beat"):
                        _shot["beat"] = _beat_data.get("description", "")
                    if not _shot.get("emotional_beat"):
                        _shot["emotional_beat"] = _beat_data.get("description", "")
                    if not _shot.get("_beat_character_action"):
                        _shot["_beat_character_action"] = _beat_data.get("character_action", "")
                    if not _shot.get("_beat_dialogue"):
                        _shot["_beat_dialogue"] = _beat_data.get("dialogue", "")
                    _beat_inject_count += 1
            if _beat_inject_count > 0:
                logger.info(f"[V27.1.4e] Narrative Beat Injection: {_beat_inject_count}/{len(_all_shots_unfiltered)} shots enriched from story bible")
                print(f"  [NARRATIVE] {_beat_inject_count} shots enriched with story bible beats", flush=True)
    except Exception as _beat_err:
        logger.warning(f"[V27.1.4e] Narrative beat injection failed (non-blocking): {_beat_err}")

    # ═══ V27.4: SCENE INTENT VERIFIER — The Story Conscience ═══
    # Before ANY generation, verify every shot matches the screenplay's intent.
    # Catches: phantom characters, wrong rooms, missing "no people" constraints.
    # Auto-fixes shots in-place before they reach FAL.
    try:
        from tools.scene_intent_verifier import SceneIntentVerifier
        _siv = SceneIntentVerifier(str(project_path))

        # Load story bible for intent extraction
        _siv_sb_path = project_path / "story_bible.json"
        _siv_story_bible = {}
        if _siv_sb_path.exists():
            with open(_siv_sb_path) as _siv_f:
                _siv_story_bible = json.load(_siv_f)

        # Load location masters for room-lock fixes
        _siv_lm_dir = project_path / "location_masters"
        _siv_loc_masters = {}
        if _siv_lm_dir.exists():
            for _siv_lm_file in _siv_lm_dir.iterdir():
                if _siv_lm_file.suffix.lower() in (".jpg", ".png"):
                    _siv_loc_masters[_siv_lm_file.stem] = str(_siv_lm_file)

        # Determine which scenes we're generating
        _siv_scene_ids = set()
        if scene_filter:
            _siv_scene_ids = set(s.strip() for s in scene_filter.split(","))
        elif shot_ids:
            _siv_scene_ids = set(sid[:3] for sid in shot_ids)
        else:
            _siv_scene_ids = set(s.get("scene_id", s.get("shot_id", "")[:3]) for s in _all_shots_unfiltered)

        # Load cast_map early for intent verification
        _siv_cm = {}
        _siv_cm_path = project_path / "cast_map.json"
        if _siv_cm_path.exists():
            with open(_siv_cm_path) as _siv_cm_f:
                _siv_cm = json.load(_siv_cm_f)

        _siv_total_fixes = 0
        for _siv_sid in sorted(_siv_scene_ids):
            _siv_report = _siv.pre_generation_verify(
                _siv_sid, _all_shots_unfiltered, _siv_story_bible,
                _siv_cm,
                _siv_loc_masters, auto_fix=True
            )
            _siv_fixes = _siv_report.get("fixes_applied", 0)
            _siv_total_fixes += _siv_fixes
            _siv_crits = _siv_report.get("critical_count", 0)
            if _siv_fixes > 0 or _siv_crits > 0:
                print(f"  [INTENT V27.4] Scene {_siv_sid}: {_siv_fixes} fixes applied, {_siv_crits} critical violations caught", flush=True)
                logger.info(f"[V27.4 INTENT] Scene {_siv_sid}: {_siv_fixes} fixes, {_siv_crits} critical, {_siv_report.get('warning_count', 0)} warnings")

        if _siv_total_fixes > 0:
            print(f"  [INTENT V27.4] Total: {_siv_total_fixes} intent fixes applied across {len(_siv_scene_ids)} scenes", flush=True)
    except Exception as _siv_err:
        logger.warning(f"[V27.4 INTENT] Scene Intent Verifier failed (non-blocking): {_siv_err}")
    # ═══════════════════════════════════════════════════════════════════

    # V27.1: Apply shot_ids filter BEFORE hard lock (was after, causing false 148-shot rejects)
    if shot_ids:
        shots = [s for s in shots if s.get("shot_id") in shot_ids]
        logger.info(f"[SEQUENTIAL] Shot IDs filter: {shot_ids} → {len(shots)} shots")

    # V17.3: Apply scene_filter
    if scene_filter:
        scene_list = [s.strip() for s in scene_filter.split(",")]
        shots = [s for s in shots if s.get("shot_id", "")[:3] in scene_list]
        logger.info(f"[SEQUENTIAL] Scene filter: {scene_list} → {len(shots)} shots")

    # V17.3: Enforce batch limit for sequential too
    if len(shots) > MAX_SHOTS_SEQUENTIAL and not dry_run:
        return {
            "success": False,
            "error": f"HARD LOCK: {len(shots)} shots exceeds sequential max of {MAX_SHOTS_SEQUENTIAL}. Use smaller scene_filter.",
            "shots_requested": len(shots),
            "max_allowed": MAX_SHOTS_SEQUENTIAL
        }

    # ===================================================================
    # V17.2 AGENT COORDINATOR — AUTOMATIC PRE-GENERATION ENFORCEMENT
    # ===================================================================
    try:
        sys.path.insert(0, str(Path(__file__).parent / "atlas_agents_v16_7"))
        from atlas_agents.agent_coordinator import AgentCoordinator
        coordinator = AgentCoordinator(project_path, story_bible=data.get("story_bible"))
        gate_result = coordinator.pre_generation_gate(shots)
        logger.info(f"[V17.2 AGENT] Pre-generation gate: {gate_result['enforcement']['stats']['shots_modified']} shots enforced in {gate_result.get('gate_ms', 0)}ms")
        if not gate_result.get("cleared", True):
            violation_count = len(gate_result.get('blocking_violations', []))
            logger.error(f"[V17.2 AGENT] Generation BLOCKED — {violation_count} critical violations")
            return {
                "success": False,
                "error": f"Generation blocked by enforcement agent: {violation_count} critical violations remain after auto-fix",
                "violations": gate_result.get("blocking_violations", [])[:10],
                "gate_result": gate_result
            }
    except Exception as agent_err:
        # V17.4: HARD GATE — agent enforcement MUST succeed for generation to proceed
        logger.error(f"[V17.4 AGENT] Enforcement agent FAILED — generation BLOCKED: {agent_err}")
        _sentry_capture_exception(agent_err)
        return {
            "success": False,
            "error": f"Pre-generation gate FAILED: Agent enforcement unavailable — {str(agent_err)[:200]}",
            "gate_blocked": True,
            "suggested_action": "Check agent files in atlas_agents_v16_7/ and restart server"
        }
    # ===================================================================

    # ===================================================================
    # V27.1 CREATION PACK GATE — BLOCKING PRE-GENERATION QUALITY CHECK
    # Validates: character refs match descriptions, locations have multi-angle
    # coverage, B-roll has narrative content. Universal — works for ANY script.
    # ===================================================================
    try:
        from tools.creation_pack_validator import (
            validate_project,
            select_probe_shot,
            analyze_probe_result,
            select_best_ref_for_shot,
        )

        _cpv_report = validate_project(str(project_path))

        # Log creation pack status
        logger.info(f"[V27.1 CREATION PACK] Characters: {len(_cpv_report.characters)} | "
                     f"Locations: {len(_cpv_report.locations)} | "
                     f"Blocking: {len(_cpv_report.blocking_issues)} | "
                     f"Warnings: {len(_cpv_report.warnings)}")

        if _cpv_report.blocking_issues and not request.get("skip_creation_pack", False):
            logger.error(f"[V27.1 CREATION PACK] BLOCKED — {len(_cpv_report.blocking_issues)} blocking issues")
            return {
                "success": False,
                "error": f"CREATION PACK GATE: {len(_cpv_report.blocking_issues)} blocking issues found.",
                "blocking_issues": _cpv_report.blocking_issues[:20],
                "warnings": _cpv_report.warnings[:10],
                "action": "Run auto-recast: python3 tools/run_recast.py <project_path> --force-all",
                "bypass": "Add 'skip_creation_pack': true to bypass (not recommended)",
                "characters": {
                    name: {"status": cs.status, "refs_present": list(cs.refs_present.keys()),
                           "refs_missing": cs.refs_missing}
                    for name, cs in _cpv_report.characters.items()
                },
                "locations": {
                    name: {"status": ls.status, "angles_present": list(ls.angles_present.keys()),
                           "angles_missing": ls.angles_missing}
                    for name, ls in _cpv_report.locations.items()
                },
            }

        # Store creation pack report for probe shot selection
        _creation_pack_report = _cpv_report

    except ImportError as _cpv_ie:
        logger.warning(f"[V27.1 CREATION PACK] Validator not available (non-blocking): {_cpv_ie}")
        _creation_pack_report = None
    except Exception as _cpv_err:
        # NON-BLOCKING on internal errors (T2-DE-3 principle: don't let gates crash pipeline)
        logger.warning(f"[V27.1 CREATION PACK] Validation error (non-blocking): {_cpv_err}")
        _creation_pack_report = None
    # ===================================================================

    # ===================================================================
    # V27.1 SCENE RENDER PLANNER — Auto-generates execution strategy
    # Runs AFTER creation pack, BEFORE LOA. Produces wave plan, chain
    # confidence, cost estimate, and probe shot selection for the scene.
    # Parallel-first: self-contained shots (ref pack + enriched prompt)
    # render in parallel. Legacy chain only for un-enriched shots.
    # ===================================================================
    _render_plan = None
    try:
        from tools.chain_policy import plan_scene_render
        # Determine scene_id from the shots being generated
        _scene_ids_in_batch = list(set(s.get("scene_id", "") for s in shots if s.get("scene_id")))
        if len(_scene_ids_in_batch) == 1:
            _target_scene = _scene_ids_in_batch[0]
            _scene_shots = [s for s in shots if s.get("scene_id") == _target_scene]
            _render_plan = plan_scene_render(
                _scene_shots, _target_scene, cast_map, str(project_path)
            )
            _w0 = len(_render_plan.get("wave_plan", {}).get("wave_0", []))
            _chains = sum(c.get("length", 0) for c in _render_plan.get("wave_plan", {}).get("chain_waves", []))
            _blockers = len(_render_plan.get("blockers", []))
            logger.info(
                f"[V27.1 RENDER PLAN] Scene {_target_scene}: "
                f"parallel={_w0} chain={_chains} blockers={_blockers} "
                f"cost=${_render_plan.get('cost_estimate', {}).get('first_frames', {}).get('total', 0)}"
            )
            if _render_plan.get("probe_shot"):
                logger.info(f"[V27.1 RENDER PLAN] Probe: {_render_plan['probe_shot']['shot_id']}")
        else:
            logger.info(f"[V27.1 RENDER PLAN] Multi-scene batch ({len(_scene_ids_in_batch)} scenes) — per-scene plan at render time")
    except ImportError:
        logger.warning("[V27.1 RENDER PLAN] chain_policy not available (non-blocking)")
    except Exception as _rp_err:
        logger.warning(f"[V27.1 RENDER PLAN] Planning error (non-blocking): {_rp_err}")
    # ===================================================================

    # ═══ V17.6: LOA Pre-Generation Gate ═══
    if LOA_AVAILABLE:
        try:
            loc_masters_map = {}
            loc_masters_dir = project_path / "location_masters"
            if loc_masters_dir.exists():
                for ext in ["jpg", "jpeg", "png", "webp"]:
                    for img in loc_masters_dir.glob(f"*.{ext}"):
                        loc_masters_map[img.stem.upper().replace("_", " ")] = f"/api/media?path={str(img)}"

            # V17.7.4: Pass scene_manifest so LOA can cross-check shot locations
            _sm_for_loa = shot_plan.get("scene_manifest", shot_plan.get("scenes", []))
            loa_result = run_loa_pre_generation(
                shots, str(project_path),
                cast_map=cast_map, location_masters=loc_masters_map,
                scene_manifest=_sm_for_loa
            )

            # Apply auto-fixes (character refs resolved from cast_map, location corrections)
            if loa_result.get("auto_fixes"):
                for fix in loa_result["auto_fixes"]:
                    logger.info(f"[LOA AUTO-FIX] {fix['type']}: {fix.get('shot_id')} → {fix.get('resolved_url', fix.get('corrected_to', ''))[:60]}")

                # V17.6: DATA QUALITY GUARD — validate before persisting
                # Sentry: track all LOA auto-fix mutations for audit trail
                _sentry_set_tag("loa.auto_fixes", len(loa_result["auto_fixes"]))
                raw_path_count = 0
                for shot in shots:
                    char_ref = shot.get("character_reference_url", "")
                    loc_ref = shot.get("location_master_url", "")
                    # Guard: no raw filesystem paths should be persisted
                    if char_ref and not char_ref.startswith("/api/") and char_ref.startswith("/"):
                        logger.error(f"[LOA DATA-QUALITY] Raw path detected on {shot.get('shot_id')}: char_ref={char_ref[:60]}")
                        shot["character_reference_url"] = f"/api/media?path={char_ref}"
                        raw_path_count += 1
                    if loc_ref and not loc_ref.startswith("/api/") and loc_ref.startswith("/"):
                        logger.error(f"[LOA DATA-QUALITY] Raw path detected on {shot.get('shot_id')}: loc_ref={loc_ref[:60]}")
                        shot["location_master_url"] = f"/api/media?path={loc_ref}"
                        raw_path_count += 1
                if raw_path_count > 0:
                    _sentry_capture_message(f"[LOA] Fixed {raw_path_count} raw filesystem paths before persist")

                # Persist auto-fixed shots
                try:
                    from tools.safe_io import atomic_write_json
                    atomic_write_json(shot_plan_path, data)
                except Exception:
                    import tempfile
                    tmp = tempfile.NamedTemporaryFile(mode='w', suffix='.json', dir=str(project_path), delete=False)
                    json.dump(data, tmp, indent=2)
                    tmp.close()
                    os.replace(tmp.name, str(shot_plan_path))

            # Log blocking errors but DON'T block generation (soft gate for now)
            if loa_result.get("blocking_errors"):
                for err in loa_result["blocking_errors"]:
                    logger.warning(f"[LOA BLOCKING] {err['shot_id']}: {err['message']}")

            logger.info(f"[LOA PRE-GEN] {loa_result.get('stats', {})}")
        except Exception as e:
            logger.warning(f"[LOA] Pre-gen gate error (non-blocking): {e}")
    # ═══════════════════════════════════════

    # =========================================================================
    # V24.2: RESEARCH-ALIGNED PROMPT COMPILATION
    # Replaces the old 7-layer enrichment stack:
    #   REMOVED: wardrobe injection, emotion injection, location injection,
    #            cinematic enricher, cast trait injection (AI actor library),
    #            face-lock injection, authority gate, camera embedding
    #   REPLACED WITH: Single V24.2 compiler call from source data
    #
    # Research basis (Kling 3.0 / LTX-2.3 analysis, March 2026):
    #   - Colon-separated zones for LTX-2.3 parsing
    #   - Focal length + aperture + film stock (not camera brand tokens)
    #   - Physical descriptions (not emotion labels)
    #   - Primary character focus (reduces feature bleed)
    #   - Official LTX-2.3 negative prompts
    #   - Under 200 words for LTX prompts
    # =========================================================================
    try:
        from tools.v24_prompt_compiler import compile_scene, validate_compiled_prompt, LTX_NEGATIVE_PROMPT

        # Load source data
        _v24_sb = {}
        _v24_sb_path = project_path / "story_bible.json"
        if _v24_sb_path.exists():
            with open(_v24_sb_path) as f:
                _v24_sb = json.load(f)

        _v24_cm = {}
        _v24_cm_path = project_path / "cast_map.json"
        if _v24_cm_path.exists():
            with open(_v24_cm_path) as f:
                _v24_cm = json.load(f)

        _v24_sm = data.get("scene_manifest", {})
        _v24_genre = "gothic_horror"  # Default, could be detected from story_bible

        # Detect genre from story_bible if available
        _v24_sb_genre = (_v24_sb.get("genre") or "").lower()
        if "noir" in _v24_sb_genre:
            _v24_genre = "noir"
        elif "period" in _v24_sb_genre or "drama" in _v24_sb_genre:
            _v24_genre = "period_drama"

        # Compile ALL scenes that have shots in this batch
        _v24_scene_ids = sorted(set(
            s.get("shot_id", "")[:3] for s in shots if s.get("shot_id")
        ))

        _v24_compiled = 0
        _v24_errors = []
        for _v24_sid in _v24_scene_ids:
            _v24_results = compile_scene(_v24_sid, data.get("shots", []), _v24_sb, _v24_cm, _v24_sm, _v24_genre)
            for _v24_r in _v24_results:
                # Find matching shot in our batch
                _v24_shot = next((s for s in shots if s.get("shot_id") == _v24_r["shot_id"]), None)
                if not _v24_shot:
                    continue

                # V26: CONTROLLER LOCK GUARD — if controller locked this prompt, DO NOT overwrite
                if _v24_shot.get("_prompt_locked"):
                    logger.info(f"[V26 LOCK] Skipping V24.2 compile for {_v24_r['shot_id']} — prompt locked by controller")
                    _v24_compiled += 1  # Count as handled
                    continue

                # Validate
                _v24_errs = validate_compiled_prompt(
                    _v24_r["shot_id"], _v24_r["nano_prompt"], _v24_r["ltx_motion_prompt"], _v24_r["characters"]
                )
                if _v24_errs:
                    _v24_errors.extend(_v24_errs)
                    logger.warning(f"[V24.2] Validation errors for {_v24_r['shot_id']}: {_v24_errs}")
                    continue

                # Apply compiled prompts — these are what FAL gets
                _v24_shot["nano_prompt"] = _v24_r["nano_prompt"]
                _v24_shot["nano_prompt_final"] = _v24_r["nano_prompt"]
                _v24_shot["ltx_motion_prompt"] = _v24_r["ltx_motion_prompt"]
                _v24_shot["ltx_motion_prompt_final"] = _v24_r["ltx_motion_prompt"]
                _v24_shot["negative_prompt"] = LTX_NEGATIVE_PROMPT
                _v24_shot["_unified_builder_applied"] = True
                _v24_shot["_v24_compiled"] = True
                _v24_compiled += 1

        logger.info(f"[V24.2 COMPILER] Compiled {_v24_compiled} shots across {len(_v24_scene_ids)} scenes — ZERO enrichment layers, research-aligned prompts")
        if _v24_errors:
            logger.warning(f"[V24.2 COMPILER] {len(_v24_errors)} validation warnings (shots will use existing prompts)")

    except Exception as _v24_err:
        logger.error(f"[V24.2 COMPILER] Failed to compile: {_v24_err} — shots will use existing prompts as-is")
        import traceback
        traceback.print_exc()
    # =========================================================================

    # V24.2: META DIRECTOR INITIALIZATION — pre-render readiness advisory
    _gen_meta_director = None
    try:
        from tools.meta_director import MetaDirector as _GenMD
        _gen_meta_director = _GenMD(str(project_path))
        logger.info(f"[V24.2] ✅ MetaDirector initialized for generate-first-frames")
    except Exception as _gmd_err:
        logger.warning(f"[V24.2] MetaDirector init non-blocking: {_gmd_err}")

    # Create output directory
    first_frames_dir = project_path / "first_frames"
    first_frames_dir.mkdir(parents=True, exist_ok=True)

    # V17 FIX: Create variants directory for multi-variant generation
    variants_dir = project_path / "first_frame_variants"
    if num_variants > 1:
        variants_dir.mkdir(parents=True, exist_ok=True)

    # Load story bible (for non-prompt uses: genre detection, etc.)
    story_bible = {}
    story_bible_path = project_path / "story_bible.json"
    if story_bible_path.exists():
        try:
            with open(story_bible_path) as f:
                story_bible = json.load(f)
        except Exception:
            story_bible = data.get("story_bible", {})
    else:
        story_bible = data.get("story_bible", {})

    # Load cast_map for character reference image resolution (NOT for prompt injection)
    cast_map = {}
    cast_map_path = project_path / "cast_map.json"
    if cast_map_path.exists():
        with open(cast_map_path) as f:
            cast_map = json.load(f)

    # Load location masters from disk (for reference image resolution, NOT prompt injection)
    location_masters = {}
    loc_masters_dir = project_path / "location_masters"
    if loc_masters_dir.exists():
        for img_ext in ["jpg", "jpeg", "png", "webp"]:
            for img in loc_masters_dir.glob(f"*.{img_ext}"):
                loc_name = img.stem.upper().replace("_", " ")
                location_masters[loc_name] = str(img)

    # Prepare generation plan
    generation_plan = []
    results = []

    # V22.0: COMPOSITION CACHE — identify reusable frames to skip redundant FAL calls
    _comp_cache_map = {}  # shot_id → source_shot_id for reuse
    if COMPOSITION_CACHE_AVAILABLE:
        try:
            _reuse_report = analyze_reuse_opportunities(shots)
            _reuse_groups = _reuse_report.get("reuse_groups", [])
            for _rg in _reuse_groups:
                _source_id = _rg.get("anchor_shot")
                for _target_id in _rg.get("reuse_candidates", []):
                    _comp_cache_map[_target_id] = _source_id
            if _comp_cache_map:
                logger.info(f"[FIRST_FRAMES V22.0] Composition Cache: {len(_comp_cache_map)} shots can reuse frames from existing compositions")
            else:
                logger.info(f"[FIRST_FRAMES V22.0] Composition Cache: {_reuse_report.get('unique_compositions', 0)} unique compositions, no reuse opportunities")
        except Exception as _cc_err:
            logger.warning(f"[FIRST_FRAMES V22.0] Composition Cache non-blocking error: {_cc_err}")

    # ═══ V24.2: DOCTRINE COMMAND SYSTEM — Scene Initialize Hook ═══
    _doctrine_runner = None
    if DOCTRINE_AVAILABLE and not dry_run:
        try:
            _doctrine_runner = _get_doctrine_runner(str(project_path))
            _scene_manifest = data.get("scene_manifest", {})
            _story_bible_scene = story_bible.get("scenes", {})
            _doctrine_init = _doctrine_runner.scene_initialize(
                shots, _scene_manifest, _story_bible_scene, cast_map
            )
            logger.info(f"[DOCTRINE] Scene initialized: {_doctrine_init.get('status')} — {len(shots)} shots")
            if _doctrine_init.get("status") == "REJECTED":
                logger.error(f"[DOCTRINE] HARD STOP: {_doctrine_init.get('reason')}")
                return {
                    "success": False,
                    "error": f"DOCTRINE HARD STOP: {_doctrine_init.get('reason')}",
                    "doctrine_status": _doctrine_init
                }
        except Exception as _doc_err:
            logger.warning(f"[DOCTRINE] Scene init non-blocking: {_doc_err}")
    # ═══════════════════════════════════════════════════════════════════

    # ═══ V27.1.4: SPATIAL TIMECODE — compute ONCE per scene, use per-shot ═══
    # Tracks WHERE characters are within the room across the shot sequence.
    # Prevents spatial jumps (e.g., fireplace → staircase with no movement).
    _spatial_timecode = {}  # shot_id → {"zone": ..., "angle_pref": ...}
    try:
        from tools.spatial_timecode import build_scene_timecode
        # Get scene beats from story bible
        _tc_scene_id = ""
        if shots:
            _first_sid = shots[0].get("shot_id", "")
            _tc_scene_id = _first_sid[:3] if len(_first_sid) >= 3 else ""
        _tc_beats = []
        if story_bible and isinstance(story_bible, dict):
            for _sb_s in story_bible.get("scenes", []):
                if str(_sb_s.get("scene_id", "")) == str(_tc_scene_id):
                    _tc_beats = _sb_s.get("beats", [])
                    break
        if _tc_beats:
            _tc_result = build_scene_timecode(shots, _tc_beats, _tc_scene_id)
            for _tc_entry in _tc_result:
                _spatial_timecode[_tc_entry["shot_id"]] = _tc_entry
            print(f"[TIMECODE] Scene {_tc_scene_id}: built timecode for {len(_tc_result)} shots, {len(_tc_beats)} beats", flush=True)
            for _tc_entry in _tc_result:
                if _tc_entry.get("zone_changed"):
                    print(f"[TIMECODE] {_tc_entry['shot_id']}: ZONE CHANGE → {_tc_entry['zone']} (src: {_tc_entry['zone_source']})", flush=True)
    except Exception as _tc_err:
        print(f"[TIMECODE] Non-blocking error: {_tc_err}", flush=True)
    # ═══════════════════════════════════════════════════════════════════

    # ═══ V27.2: CREATIVE DIRECTOR — props, blocking, emotion, choreography ═══
    # Enriches ALL shots in the scene with filmmaker intelligence BEFORE generation.
    # Reads story bible beats → maps props, emotion arcs, blocking, motion choreography.
    # Non-blocking: if it fails, generation proceeds without creative enrichment.
    _cd_report = ""
    try:
        from tools.creative_director import enrich_scene_creative, apply_creative_directives, generate_creative_report
        # Get story bible scene for this scene
        _cd_scene_id = ""
        if shots:
            _cd_first_sid = shots[0].get("shot_id", "")
            _cd_scene_id = _cd_first_sid[:3] if len(_cd_first_sid) >= 3 else ""
        _cd_story_scene = {}
        if story_bible and isinstance(story_bible, dict):
            for _cd_sb in story_bible.get("scenes", []):
                _sb_sid = str(_cd_sb.get("scene_id", ""))
                if _sb_sid == str(_cd_scene_id) or _sb_sid == str(int(_cd_scene_id)) if _cd_scene_id.isdigit() else False:
                    _cd_story_scene = _cd_sb
                    break
        if _cd_story_scene:
            shots = enrich_scene_creative(shots, _cd_story_scene, cast_map)
            _cd_report = generate_creative_report(shots, _cd_scene_id)
            # Count flags
            _cd_total_flags = sum(len(s.get("_cd_flags", [])) for s in shots)
            _cd_props_found = sum(1 for s in shots if s.get("_cd_props"))
            _cd_emotions_found = sum(1 for s in shots if s.get("_cd_emotion"))
            print(f"[CREATIVE DIRECTOR] Scene {_cd_scene_id}: enriched {len(shots)} shots | "
                  f"props={_cd_props_found} | emotions={_cd_emotions_found} | flags={_cd_total_flags}", flush=True)
            if _cd_total_flags > 0:
                print(f"[CREATIVE DIRECTOR] ⚠ {_cd_total_flags} creative flags — review before generation", flush=True)
                for _cd_s in shots:
                    for _cd_f in _cd_s.get("_cd_flags", []):
                        print(f"  [{_cd_s.get('shot_id','?')}] {_cd_f}", flush=True)
        else:
            print(f"[CREATIVE DIRECTOR] No story bible scene found for {_cd_scene_id}, skipping enrichment", flush=True)
    except Exception as _cd_err:
        print(f"[CREATIVE DIRECTOR] Non-blocking error: {_cd_err}", flush=True)
    # ═══════════════════════════════════════════════════════════════════

    # ═══ V27.2: SCENE CONTINUITY ENFORCER — lighting lock + framing sync + blocking audit ═══
    _sce_report = {}
    try:
        from tools.scene_continuity_enforcer import enforce_scene_continuity, generate_continuity_assessment
        shots, _sce_report = enforce_scene_continuity(shots, _cd_story_scene if '_cd_story_scene' in dir() else {}, cast_map)
        _sce_grade = _sce_report.get("grade", "?")
        _sce_light = _sce_report.get("lighting_enriched", 0)
        _sce_frame = _sce_report.get("framing_enriched", 0)
        _sce_block = _sce_report.get("blocking_enriched", 0)
        _sce_flags = _sce_report.get("total_flags", 0)
        print(f"[CONTINUITY ENFORCER] Grade {_sce_grade} | lighting={_sce_light} framing={_sce_frame} blocking={_sce_block} flags={_sce_flags}", flush=True)
        if _sce_report.get("lighting_lock"):
            _ll = _sce_report["lighting_lock"]
            print(f"[CONTINUITY ENFORCER] Lighting lock: {_ll.get('room_type','?')} → {_ll.get('lighting_lock_phrase','')[:80]}", flush=True)
        if _sce_flags > 0:
            for _sf in _sce_report.get("flags", [])[:10]:
                print(f"  [CONTINUITY] {_sf}", flush=True)
    except Exception as _sce_err:
        print(f"[CONTINUITY ENFORCER] Non-blocking error: {_sce_err}", flush=True)
    # ═══════════════════════════════════════════════════════════════════

    # ═══ V27.2: PERPETUAL LEARNING — apply prevention rules from past sessions ═══
    try:
        from tools.perpetual_learning import load_learning_log, apply_learned_rules, generate_prevention_checks
        _pl_entries = load_learning_log(project)
        if _pl_entries:
            shots = apply_learned_rules(shots, _pl_entries)
            _pl_checks = generate_prevention_checks(shots, _pl_entries)
            _pl_violations = [c for c in _pl_checks if c.get("status") == "FAIL"]
            _pl_warnings = [c for c in _pl_checks if c.get("status") == "WARN"]
            print(f"[PERPETUAL LEARNING] {len(_pl_entries)} learned rules | "
                  f"{len(_pl_checks)} checks | {len(_pl_violations)} violations | "
                  f"{len(_pl_warnings)} warnings", flush=True)
            for v in _pl_violations[:5]:
                print(f"  [LEARN-FAIL] {v.get('check','?')}: {v.get('detail','')[:80]}", flush=True)
            for w in _pl_warnings[:3]:
                print(f"  [LEARN-WARN] {w.get('check','?')}: {w.get('detail','')[:80]}", flush=True)
    except Exception as _pl_err:
        print(f"[PERPETUAL LEARNING] Non-blocking error: {_pl_err}", flush=True)
    # ═══════════════════════════════════════════════════════════════════

    for shot in shots:
        shot_id = shot.get("shot_id", "unknown")

        # V24.2: META DIRECTOR — pre-render readiness check (non-blocking advisory)
        if _gen_meta_director:
            try:
                _gen_scene_ctx = {"scene_id": shot.get("scene_id", ""), "shot_index": shots.index(shot)}
                _gen_md_decision = _gen_meta_director.check_shot_readiness(shot, _gen_scene_ctx)
                shot["_meta_director_verdict"] = _gen_md_decision.decision_type
                if _gen_md_decision.decision_type != "approve":
                    logger.info(f"[V24.2 META] {shot_id}: ⚠️ {_gen_md_decision.reason}")
            except Exception as _gmd_check_err:
                pass  # Non-blocking

        # V22.0: Check composition cache for frame reuse
        if shot_id in _comp_cache_map:
            _source_id = _comp_cache_map[shot_id]
            _source_frame = project_path / "first_frames" / f"{_source_id}.jpg"
            _target_frame = project_path / "first_frames" / f"{shot_id}.jpg"
            if _source_frame.exists() and not _target_frame.exists():
                import shutil
                shutil.copy2(str(_source_frame), str(_target_frame))
                results.append({"shot_id": shot_id, "status": "reused", "source": _source_id})
                logger.info(f"[FIRST_FRAMES V22.0] Reused frame from {_source_id} → {shot_id}")
                continue

        # ═══════════════════════════════════════════════════════════════════════
        # V24.2: DIRECT PROMPT READ — No enrichment, no mutation, no bandaids.
        # The V24.2 compiler already ran above and set nano_prompt_final on
        # every shot. We just read it. What you see = what FAL gets.
        #
        # OLD SYSTEM REMOVED (was 7 layers of prompt mutation):
        #   ❌ Scene anchor system        → V24.2 compiler handles location
        #   ❌ Cinematic enricher          → V24.2 compiler handles quality/color
        #   ❌ Cast trait injection (AI actor lib) → V24.2 uses cast_map canon
        #   ❌ Face-lock injection         → V24.2 has IDENTITY_LOCK
        #   ❌ Authority gate cleanup      → V24.2 is clean from source — no cleanup needed
        #   ❌ Lite mode save/restore      → No enrichment to save/restore from
        #   ❌ V22.3 camera embedding      → V24.2 has focal length + aperture
        # ═══════════════════════════════════════════════════════════════════════
        nano_prompt = shot.get("nano_prompt_final") or shot.get("nano_prompt", "")
        characters = shot.get("characters", [])
        if isinstance(characters, str):
            characters = [c.strip() for c in characters.split(",") if c.strip()]

        # ═══ E-SHOT GUARD (V37): environment-only shots MUST NOT get character refs ═══
        # Shots with _no_char_ref=True or _is_broll=True are establishing/B-roll —
        # they must show empty environments. Passing character refs to Nano causes it
        # to invent people to match the reference image, defeating the empty-scene intent.
        # Mirror of the guard in atlas_universal_runner.py lines 1834-1841.
        _is_e_shot = bool(shot.get("_no_char_ref") or shot.get("_is_broll"))
        if _is_e_shot:
            characters = []  # Force empty — blocks char_ref resolution at line ~22685
            # Enforce "no people" in the prompt text (Nano has no negative_prompt param)
            _np_lower = nano_prompt.lower()
            if "no people" not in _np_lower and "no figures" not in _np_lower and "no persons" not in _np_lower:
                nano_prompt = nano_prompt.rstrip(". ") + ". No people, no figures, no persons visible. Empty environment only."
                shot["nano_prompt"] = nano_prompt
            print(f"  [E-SHOT GUARD] {shot_id}: characters cleared, 'no people' enforced in prompt", flush=True)
        # ══════════════════════════════════════════════════════════════════════════════

        # ═══ V27.1.5: SCENE VISUAL DNA INJECTION ═══
        # Appends LOCKED architectural description to nano_prompt so FAL generates
        # the SAME room across all shots. Also injects focal length enforcement.
        if "[ROOM DNA:" not in nano_prompt:
            try:
                from tools.scene_visual_dna import build_scene_dna, get_focal_length_enforcement, build_scene_lighting_rig
                _dna_scene_id = shot.get("scene_id", shot_id[:3])
                _dna_story_scene = {}
                if _gen_story_bible and _gen_story_bible.get("scenes"):
                    _dna_story_scene = next((sc for sc in _gen_story_bible["scenes"]
                                              if str(sc.get("scene_id", "")) == str(_dna_scene_id)), {})
                if _dna_story_scene:
                    _dna_block = build_scene_dna(_dna_story_scene)
                    _lighting_block = build_scene_lighting_rig(_dna_story_scene)
                    nano_prompt = f"{nano_prompt.rstrip('. ')}. {_dna_block} {_lighting_block}"
                    shot["nano_prompt"] = nano_prompt
                    if shot.get("nano_prompt_final"):
                        shot["nano_prompt_final"] = nano_prompt
                # Focal enforcement for close-ups
                _shot_type_for_focal = (shot.get("shot_type") or "").lower()
                _focal = get_focal_length_enforcement(_shot_type_for_focal)
                if _focal and f"[{_focal[:10]}" not in nano_prompt:
                    nano_prompt = f"{nano_prompt.rstrip('. ')}. [{_focal}]"
                    shot["nano_prompt"] = nano_prompt
                    if shot.get("nano_prompt_final"):
                        shot["nano_prompt_final"] = nano_prompt
            except Exception as _dna_err:
                logger.warning(f"[V27.1.5] Non-blocking scene DNA injection failed: {_dna_err}")

        # ═══ V27.1: OTS DIALOGUE ENFORCER — ORIGIN FIX ═══
        # FAL models don't understand character NAMES. For OTS dialogue shots,
        # replace names with PHYSICAL DESCRIPTIONS and ensure speaker faces camera.
        # This runs at the ORIGIN — before any FAL call — so ALL OTS shots get
        # correct appearance-based prompting automatically.
        _ots_shot_type = (shot.get("shot_type") or shot.get("type") or "").lower()
        _ots_is_ots = "over_the_shoulder" in _ots_shot_type or "ots" in _ots_shot_type
        _ots_has_dialogue = bool(shot.get("dialogue_text"))
        # V27.1.4b: UNIVERSAL dialogue shot preparation — handles OTS, two-shot, close-up, medium
        # Routes through prepare_dialogue_shot() which knows each shot type's cinematic rules
        if _ots_has_dialogue and characters and cast_map:
            try:
                from tools.ots_enforcer import OTSEnforcer
                _ots_enforcer = OTSEnforcer(cast_map)
                # V27.1.4d: Establish screen position lock from ALL shots in this scene
                # CRITICAL: Use _all_shots_unfiltered (not filtered 'shots') because the position lock
                # needs to scan OTS A-angle shots that may not be in the current generation batch
                _scene_id_for_lock = shot.get("scene_id", "")
                _scene_shots_for_lock = [s for s in _all_shots_unfiltered if s.get("scene_id") == _scene_id_for_lock]
                _ots_enforcer.establish_screen_positions(_scene_shots_for_lock)
                # V27.6: Set scene context for solo scene detection
                try:
                    _sb_path_ctx = project_path / "story_bible.json"
                    _sb_scene_ctx = None
                    if _sb_path_ctx.exists():
                        with open(_sb_path_ctx) as _sbf:
                            _sb_ctx = json.load(_sbf)
                        _sb_scene_ctx = next((sc for sc in _sb_ctx.get("scenes", [])
                                             if sc.get("scene_id") == _scene_id_for_lock), None)
                    _ots_enforcer.set_scene_context(
                        scene_shots=_scene_shots_for_lock,
                        story_bible_scene=_sb_scene_ctx,
                    )
                except Exception as _ctx_err:
                    logger.warning(f"[V27.6] set_scene_context non-blocking: {_ctx_err}")
                # Build prev_shots for eye-line inheritance from FULL scene shot list
                # Use shot_id matching since filtered shots are same objects as unfiltered
                _current_shot_id = shot.get("shot_id", "")
                _prev_shots = []
                for _ps in _scene_shots_for_lock:
                    if _ps.get("shot_id") == _current_shot_id:
                        break
                    _prev_shots.append(_ps)
                _ots_result = _ots_enforcer.prepare_dialogue_shot(shot, prev_shots=_prev_shots)
                # Re-read prompt after enforcement (it may have been rewritten)
                nano_prompt = shot.get("nano_prompt", nano_prompt)
                if shot.get("nano_prompt_final"):
                    shot["nano_prompt_final"] = nano_prompt
                shot["_dialogue_enforced_at_origin"] = True
                _dial_type = "OTS" if shot.get("_ots_angle") else _ots_shot_type
                print(f"  [DIALOGUE-ENFORCE] {shot_id}: type={_dial_type} angle={shot.get('_ots_angle','n/a')} "
                      f"speaker={shot.get('_ots_speaker','n/a')} eye={shot.get('_eye_line_direction','n/a')}", flush=True)
            except Exception as _ots_err:
                logger.warning(f"[V27.1.4b] Non-blocking dialogue enforcement failed for {shot_id}: {_ots_err}")
                import traceback; traceback.print_exc()

        # ═══ V27.1.2: UNIVERSAL DIALOGUE VIDEO PROMPT COMPILER ═══
        # For ALL dialogue shots (not just OTS), ensure ltx_motion_prompt is clean
        # and contains proper dialogue text + performance direction.
        # This catches corrupted prompts from stacked fix-v16 runs.
        elif _ots_has_dialogue and characters and not shot.get("_video_prompt_compiled_at_origin"):
            try:
                _vp_dialogue = shot.get("dialogue_text", "")
                _vp_duration = shot.get("duration", 10)
                _vp_beat = shot.get("beat", shot.get("emotional_beat", ""))
                _vp_shot_type = (shot.get("shot_type") or shot.get("type") or "medium").lower()

                # Check if current ltx_motion_prompt is corrupted (repeated text)
                _vp_current = shot.get("ltx_motion_prompt", "")
                _vp_is_corrupted = False
                if _vp_current:
                    # Detect repetition: if any 30-char substring appears 3+ times
                    for _ci in range(0, min(len(_vp_current) - 30, 200), 10):
                        _chunk = _vp_current[_ci:_ci+30]
                        if _vp_current.count(_chunk) >= 3:
                            _vp_is_corrupted = True
                            logger.warning(f"[V27.1.2] {shot_id}: Corrupted ltx_motion_prompt detected (repeating text)")
                            break

                if _vp_is_corrupted or not _vp_current or "character speaks" not in _vp_current.lower():
                    # Build clean video prompt
                    _vp_clean_dlg = _vp_dialogue
                    for _vc in characters:
                        _vc_name = _vc if isinstance(_vc, str) else _vc.get("name", "")
                        _vp_clean_dlg = re.sub(rf'{re.escape(_vc_name)}\s*:\s*', '', _vp_clean_dlg, flags=re.IGNORECASE)
                    _vp_clean_dlg = _vp_clean_dlg.replace("|", " ").strip()
                    _vp_clean_dlg = re.sub(r'\s+', ' ', _vp_clean_dlg)
                    if len(_vp_clean_dlg) > 200:
                        _vp_clean_dlg = _vp_clean_dlg[:197] + "..."

                    # Get speaker appearance from cast_map
                    _vp_speaker = characters[0] if isinstance(characters[0], str) else characters[0].get("name", "")
                    _vp_speaker_desc = _vp_speaker
                    if cast_map:
                        _vp_cm = cast_map.get(_vp_speaker, {})
                        if isinstance(_vp_cm, dict):
                            _vp_speaker_desc = _vp_cm.get("appearance", _vp_speaker)

                    _vp_parts = [
                        f"0-{_vp_duration}s:",
                        f"{_vp_shot_type.replace('_', ' ').title()} shot.",
                        f"{_vp_speaker_desc} speaks.",
                        f'Delivers: "{_vp_clean_dlg}"',
                        f"Mouth opens and closes forming words, jaw moves with speech rhythm.",
                    ]
                    if _vp_beat:
                        _vp_parts.append(f"Emotional tone: {_vp_beat}.")
                    # V27.1.5: Split constraint — face lock + body freedom
                    _vp_parts.append("FACE IDENTITY LOCK: facial structure UNCHANGED, NO face morphing.")
                    _vp_parts.append(f"BODY FREE: natural breathing, gestures continue. {_vp_duration}s")

                    _vp_new = " ".join(_vp_parts)
                    if len(_vp_new) > 900:
                        _vp_new = _vp_new[:897] + "..."
                    shot["ltx_motion_prompt"] = _vp_new
                    shot["_video_prompt_compiled_at_origin"] = True
                    logger.info(f"[V27.1.2 VIDEO] {shot_id}: Compiled clean video prompt ({len(_vp_new)} chars)")
            except Exception as _vp_err:
                logger.warning(f"[V27.1.2 VIDEO] Non-blocking video prompt compile failed for {shot_id}: {_vp_err}")
        # ═══════════════════════════════════════════════════

        logger.info(f"[V24.2 DIRECT] {shot_id}: nano={len(nano_prompt)} chars, ltx={len(shot.get('ltx_motion_prompt',''))} chars — zero enrichment, research-aligned")

        # =========================================================================
        # V22.3 CAMERA EMBEDDING — REMOVED BY V24.2 (2026-03-10)
        # V24.2 compiler already includes focal length + aperture + motion in
        # both nano and LTX prompts (research-aligned: no camera brands).
        # This block was overwriting nano_prompt_final and ltx_motion_prompt_final
        # AFTER V24.2 compilation — the exact downstream mutation problem.
        # =========================================================================

        location = shot.get("location", "")

        # V17 FIX: Get locked references - ALSO fall back to cast_map if shot-level ref missing
        char_ref_url = shot.get("character_reference_url")
        loc_master_url = shot.get("location_master_url")

        # E-SHOT GUARD (V37): clear any stale character_reference_url on environment shots
        # A previous run may have written a ref onto the shot dict; wipe it now.
        if _is_e_shot:
            char_ref_url = None

        # V17.7.3 FIX: If no character_reference_url on shot, resolve from disk
        # PRIORITY: CHAR_REFERENCE (actor in wardrobe) > cast_map URL > LOCKED_REFERENCE (generic headshot)
        if not char_ref_url and characters and cast_map:
            first_char = characters[0] if isinstance(characters[0], str) else characters[0].get("name", "")
            first_char_upper = first_char.upper().strip()
            for char_key, actor_val in cast_map.items():
                if char_key.startswith("_"):
                    continue
                if not isinstance(actor_val, dict):
                    continue
                ck_upper = char_key.upper().strip()
                if ck_upper == first_char_upper or ck_upper.startswith(first_char_upper + " ") or first_char_upper.startswith(ck_upper + " ") or ck_upper.startswith(first_char_upper):
                    # 1. BEST: CHAR_REFERENCE (actor in wardrobe) — project-local
                    char_safe = re.sub(r'[^a-zA-Z0-9_-]', '_', ck_upper)
                    char_ref_path = project_path / "character_library_locked" / f"{char_safe}_CHAR_REFERENCE.jpg"
                    if char_ref_path.exists():
                        char_ref_url = f"/api/media?path={char_ref_path}"
                        logger.info(f"[V17.7.3] Resolved CHAR_REFERENCE for {first_char} at generation time")
                        shot["character_reference_url"] = char_ref_url
                        break
                    # 2. GOOD: cast_map character_reference_url
                    cm_ref = actor_val.get("character_reference_url") or actor_val.get("reference_url")
                    if cm_ref:
                        char_ref_url = cm_ref
                        logger.info(f"[V17.7.3] Resolved char ref for {first_char} from cast_map at generation time")
                        shot["character_reference_url"] = char_ref_url
                        break
                    # 3. V21.10: FALLBACK — try project-local CHAR_REFERENCE with simpler name match
                    # NEVER use AI actor headshots (LOCKED_REFERENCE) — they cause character drift
                    # because they show the WRONG person (AI actor, not the screenplay character)
                    _char_lib_dir = project_path / "character_library_locked"
                    if _char_lib_dir.exists():
                        for _clf in _char_lib_dir.iterdir():
                            if _clf.name.endswith("_CHAR_REFERENCE.jpg") and first_char_upper.split()[0] in _clf.name.upper():
                                char_ref_url = f"/api/media?path={_clf}"
                                logger.info(f"[V21.10] Resolved CHAR_REFERENCE fallback for {first_char}")
                                shot["character_reference_url"] = char_ref_url
                                break
                    if not char_ref_url:
                        logger.warning(f"[V21.10] No character reference found for {first_char} — generation will proceed without face ref")
                    break

        # ═══ V27.1.3: UNIVERSAL DP-STANDARD LOCATION REF RESOLUTION ═══
        # EVERY shot type gets the correct location angle from the canonical pack.
        # This OVERRIDES any pre-set location_master_url because the pre-set value
        # came from fix-v16 which uses basic matching (same ref for all shot types).
        # The DP logic UNDERSTANDS cinematography:
        #   establishing/wide → wide_exterior or base wide (geography shot)
        #   medium/two_shot → medium_interior (characters in context)
        #   close_up/reaction/medium_close → NO location ref (faces only, tight framing)
        #   over_the_shoulder → A-angle=base, B-angle=reverse_angle (180° rule)
        # This prevents: same background for all shots, full panorama on close-ups,
        # and ensures dialogue sequences have proper spatial variety.
        # ═══ V27.1.4: ROOM-LOCKED DP LOCATION RESOLUTION ═══
        # PRINCIPLE: Characters don't teleport. Every shot in a scene uses the
        # SAME ROOM. Shot type determines the ANGLE of that room, not a different room.
        #
        # STEP 1: Resolve the scene's ROOM from story bible (e.g. "GRAND FOYER")
        # STEP 2: Filter location masters to ONLY that room's angle variants
        # STEP 3: Pick the right angle based on shot type:
        #   establishing/wide → base wide master (full geography)
        #   medium/two_shot → medium_interior variant (characters in context)
        #   medium_close/close_up/reaction → base master (same room, prompt handles tight framing)
        #   OTS → A/B angle alternation (base vs reverse_angle of SAME room)
        #   closing → base wide (pull back to geography)
        #
        # CRITICAL: Face-centric shots (close_up, medium_close, reaction) still get the
        # room's base location ref so the background is CONSISTENT. The text prompt handles
        # tight framing — the location ref ensures the character stays IN the room.
        _DP_ANGLE_MAP = {
            "establishing": "base",          # Full room geography
            "wide": "base",                  # Full room geography
            "medium": "medium_interior",     # Characters in room context
            "two_shot": "medium_interior",   # Characters in room context
            "medium_close": "base",          # Same room, prompt handles tight face
            "medium_close_up": "base",       # Same room, prompt handles tight face
            "close_up": "base",              # Same room, prompt handles tight face
            "extreme_close_up": "base",      # Same room, prompt handles tight face
            "reaction": "base",              # Same room, prompt handles tight face
            "over_the_shoulder": "ots_angle", # Handled by OTS A/B logic
            "closing": "base",               # Pull back to full geography
            "insert": "medium_interior",     # Detail in room context
            "detail": "medium_interior",     # Detail in room context
            "b-roll": "base",               # Room atmosphere
        }
        if location and location_masters:
            _loc_resolved_by_dp = False
            _dp_shot_type = (shot.get("shot_type") or shot.get("type") or "medium").lower()
            _dp_angle_pref = _DP_ANGLE_MAP.get(_dp_shot_type, "base")

            # ── V27.1.4 SPATIAL TIMECODE OVERRIDE ──
            # If timecode tracked this shot's zone, use its angle_pref instead
            # This ensures adjacent shots maintain spatial consistency within the room
            _tc_entry = _spatial_timecode.get(shot_id)
            if _tc_entry:
                _tc_zone = _tc_entry.get("zone", "")
                _tc_angle = _tc_entry.get("angle_pref", "")
                _tc_source = _tc_entry.get("zone_source", "")
                _tc_changed = _tc_entry.get("zone_changed", False)
                print(f"  [TIMECODE] {shot_id}: zone={_tc_zone} angle={_tc_angle} src={_tc_source} changed={_tc_changed}", flush=True)
                # OTS shots keep their A/B angle logic (handled below), timecode informs zone only
                if _dp_shot_type not in ("over_the_shoulder",):
                    if _tc_angle and _tc_angle != _dp_angle_pref:
                        print(f"  [TIMECODE] Override: {_dp_angle_pref} → {_tc_angle} (zone={_tc_zone})", flush=True)
                        _dp_angle_pref = _tc_angle
                else:
                    print(f"  [TIMECODE] OTS shot — zone={_tc_zone}, A/B logic handles angle", flush=True)

            # ── STEP 1: Resolve the scene's SPECIFIC ROOM from story bible ──
            # shot.location is often generic ("HARGROVE ESTATE")
            # story_bible.scenes[].location has the specific room ("HARGROVE ESTATE - GRAND FOYER")
            _scene_id = shot.get("scene_id", shot_id[:3] if len(shot_id) >= 3 else "")
            _scene_room = ""
            if story_bible and isinstance(story_bible, dict):
                for _sb_scene in story_bible.get("scenes", []):
                    if str(_sb_scene.get("scene_id", "")) == str(_scene_id):
                        _scene_room = _sb_scene.get("location", "")
                        break
            # Fallback: use shot location if story bible didn't have specific room
            if not _scene_room:
                _scene_room = location

            # Extract the ROOM NAME (e.g. "GRAND FOYER" from "HARGROVE ESTATE - GRAND FOYER")
            _room_name = _scene_room.upper().strip()
            import re as _re
            # Strip time-of-day suffixes
            _room_name = _re.sub(r'\s*[-–]\s*(NIGHT|DAY|EVENING|MORNING|AFTERNOON|LATE|DAWN|DUSK|LATER|CONTINUOUS).*$', '', _room_name, flags=_re.IGNORECASE).strip()
            # Extract room part after estate name (if applicable)
            _room_key = _room_name  # Full name for matching
            _room_parts = _re.split(r'\s*[-–]\s*', _room_name)
            _room_suffix = _room_parts[-1].strip() if len(_room_parts) > 1 else ""
            # e.g. "HARGROVE ESTATE - GRAND FOYER" → room_key="HARGROVE ESTATE - GRAND FOYER", room_suffix="GRAND FOYER"

            print(f"[DP-V4] {shot_id}: type={_dp_shot_type} angle_pref={_dp_angle_pref} scene_room='{_scene_room}' room_suffix='{_room_suffix}'", flush=True)

            # ── STEP 2: Filter location masters to THIS ROOM's variants only ──
            _room_masters = {}  # name → path, only for this scene's room
            for _lm_name, _lm_path in location_masters.items():
                _lm_upper = _lm_name.upper().strip()
                _lm_path_stem = os.path.basename(_lm_path).upper().replace(".JPG","").replace(".PNG","").replace(".JPEG","").replace(".WEBP","")
                # Match by room suffix (e.g. "GRAND FOYER" matches "HARGROVE_ESTATE___GRAND_FOYER_reverse_angle")
                _matched = False
                if _room_suffix and len(_room_suffix) >= 4:
                    _suffix_normalized = _room_suffix.replace(" ", "_")
                    _stem_normalized = _lm_path_stem.replace(" ", "_").replace("-", "_")
                    if _suffix_normalized in _stem_normalized:
                        _matched = True
                # Also match by full room name
                if not _matched and _room_key:
                    _key_normalized = _room_key.replace(" ", "_").replace("-", "_")
                    _stem_normalized = _lm_path_stem.replace(" ", "_").replace("-", "_")
                    if _key_normalized in _stem_normalized or _stem_normalized in _key_normalized:
                        _matched = True
                if _matched:
                    _room_masters[_lm_name] = _lm_path

            print(f"[DP-V4] {shot_id}: found {len(_room_masters)} masters for room '{_room_suffix}': {[os.path.basename(p) for p in _room_masters.values()]}", flush=True)

            # ── STEP 3: Pick the right angle variant of THIS ROOM ──
            if _room_masters:
                # OTS uses A/B angle logic within this room
                if _dp_angle_pref == "ots_angle" and _ots_is_ots and _ots_has_dialogue and shot.get("_ots_angle"):
                    _ots_angle = shot.get("_ots_angle", "A")
                    # A-angle → base/standard master, B-angle → reverse_angle
                    _best_ots = None
                    _ots_fallback = None
                    for _rm_name, _rm_path in _room_masters.items():
                        _pl = _rm_path.lower()
                        if _ots_angle == "B" and "reverse_angle" in _pl:
                            _best_ots = _rm_path
                        elif _ots_angle == "A" and "reverse" not in _pl and "medium" not in _pl:
                            _best_ots = _rm_path
                        if not _ots_fallback:
                            _ots_fallback = _rm_path
                    _resolved = _best_ots or _ots_fallback
                    if _resolved:
                        loc_master_url = _resolved
                        shot["location_master_url"] = loc_master_url
                        shot["_loc_ref_angle_resolved"] = True
                        _loc_resolved_by_dp = True
                        print(f"[DP-V4] {shot_id}: OTS {_ots_angle}-angle → {os.path.basename(_resolved)}", flush=True)

                # Non-OTS: pick angle variant matching preference
                if not _loc_resolved_by_dp:
                    _best_variant = None
                    _base_fallback = None
                    for _rm_name, _rm_path in _room_masters.items():
                        _pl = _rm_path.lower()
                        # Always track the base master as fallback (no angle suffix)
                        if "reverse" not in _pl and "medium" not in _pl and "detail" not in _pl:
                            _base_fallback = _rm_path
                        # Match preferred angle
                        if _dp_angle_pref == "medium_interior" and "medium" in _pl:
                            _best_variant = _rm_path
                        elif _dp_angle_pref == "base" and "reverse" not in _pl and "medium" not in _pl:
                            _best_variant = _rm_path
                        elif _dp_angle_pref == "reverse_angle" and "reverse" in _pl:
                            _best_variant = _rm_path
                    _resolved = _best_variant or _base_fallback
                    if _resolved:
                        loc_master_url = _resolved
                        shot["location_master_url"] = loc_master_url
                        shot["_dp_loc_type"] = _dp_angle_pref
                        _loc_resolved_by_dp = True
                        print(f"[DP-V4] {shot_id}: {_dp_shot_type} → {_dp_angle_pref} → {os.path.basename(_resolved)}", flush=True)

            # FALLBACK: If room filtering found nothing, use generic matching
            if not _loc_resolved_by_dp:
                print(f"[DP-V4] {shot_id}: FALLBACK — no room-specific masters found, using generic match", flush=True)
                # Use the first location master that broadly matches the estate
                _loc_generic = location.upper().replace(" ", "_").replace("-", "_")
                for _lm_name, _lm_path in location_masters.items():
                    _lm_stem = os.path.basename(_lm_path).upper().replace(".JPG","")
                    if _loc_generic[:10] in _lm_stem:
                        loc_master_url = _lm_path
                        shot["location_master_url"] = loc_master_url
                        _loc_resolved_by_dp = True
                        print(f"[DP-V4] {shot_id}: FALLBACK → {os.path.basename(_lm_path)}", flush=True)
                        break
        # ═══════════════════════════════════════════════════

        # V17.7: Continuity reference (last frame from previous shot) for shot chaining
        continuity_ref = shot.get("continuity_ref_url", "")
        if continuity_ref and continuity_ref.startswith("/api/media?path="):
            continuity_ref = continuity_ref.split("path=", 1)[1]
            if not Path(continuity_ref).exists():
                continuity_ref = ""

        # V18.2: Collect ALL character reference URLs for multi-character shots
        # nano-banana-pro/edit accepts up to 5 image_urls — use them for face-locking ALL characters
        ref_urls = []
        if continuity_ref:
            ref_urls.append(continuity_ref)  # Continuity ref first (strongest visual anchor)
        # Primary character ref (already resolved above)
        if char_ref_url:
            ref_urls.append(char_ref_url)
        # V18.2: Resolve refs for ADDITIONAL characters beyond the first
        if characters and cast_map and len(characters) > 1:
            _added_refs = set()
            if char_ref_url:
                _added_refs.add(char_ref_url)
            for _extra_char in characters[1:]:
                _ec_name = _extra_char if isinstance(_extra_char, str) else _extra_char.get("name", "")
                _ec_upper = _ec_name.upper().strip()
                for _eck, _ecv in cast_map.items():
                    if _eck.startswith("_") or not isinstance(_ecv, dict):
                        continue
                    _eck_upper = _eck.upper().strip()
                    if _eck_upper == _ec_upper or _eck_upper.startswith(_ec_upper) or _ec_upper.startswith(_eck_upper):
                        # Try CHAR_REFERENCE → cast_map ref → LOCKED_REFERENCE
                        _ec_ref = None
                        _ec_safe = re.sub(r'[^a-zA-Z0-9_-]', '_', _eck_upper)
                        _ec_char_path = project_path / "character_library_locked" / f"{_ec_safe}_CHAR_REFERENCE.jpg"
                        if _ec_char_path.exists():
                            _ec_ref = f"/api/media?path={_ec_char_path}"
                        if not _ec_ref:
                            # V21.10: Use character_reference_url ONLY — NEVER headshot_url or AI actor LOCKED_REFERENCE
                            _ec_cm_ref = _ecv.get("character_reference_url") or _ecv.get("reference_url", "")
                            if _ec_cm_ref and "LOCKED_REFERENCE" not in _ec_cm_ref and "ai_actors" not in _ec_cm_ref:
                                _ec_ref = _ec_cm_ref
                        if _ec_ref and _ec_ref not in _added_refs:
                            ref_urls.append(_ec_ref)
                            _added_refs.add(_ec_ref)
                            logger.info(f"[V18.2] Multi-char ref for {_ec_name} → {Path(str(_ec_ref)).name}")
                        break
        # V18.2: Skip interior location ref for exterior/establishing shots
        _gen_shot_type = (shot.get("type") or shot.get("shot_type") or "").lower()
        _gen_is_exterior = "ext" in (location or "").upper()[:5] or _gen_shot_type in ("establishing", "master")
        if loc_master_url and not _gen_is_exterior:
            ref_urls.append(loc_master_url)
        elif _gen_is_exterior and loc_master_url:
            logger.info(f"[GEN] {shot_id}: exterior/establishing — skipping interior location master ref")

        # ═══ V27.1: OTS REF REORDERING — Speaker ref FIRST ═══
        # FAL gives visual priority to image_urls[0]. For OTS dialogue shots,
        # ensure the SPEAKER's character ref is first so the model renders
        # the speaker's face facing camera (not the listener's).
        if _ots_is_ots and _ots_has_dialogue and len(ref_urls) >= 2 and cast_map:
            try:
                _ots_speaker = shot.get("_ots_speaker", "")
                _ots_listener = shot.get("_ots_listener", "")
                if _ots_speaker:
                    _speaker_key = _ots_speaker.replace(" ", "_").upper()
                    _listener_key = _ots_listener.replace(" ", "_").upper() if _ots_listener else ""
                    _speaker_refs = []
                    _listener_refs = []
                    _other_refs = []
                    for _ru in ref_urls:
                        _ru_base = os.path.basename(str(_ru)).upper()
                        if _speaker_key in _ru_base:
                            _speaker_refs.append(_ru)
                        elif _listener_key and _listener_key in _ru_base:
                            _listener_refs.append(_ru)
                        else:
                            _other_refs.append(_ru)
                    _new_refs = _speaker_refs + _listener_refs + _other_refs
                    if _new_refs != ref_urls and _speaker_refs:
                        ref_urls = _new_refs
                        logger.info(f"[V27.1 OTS] {shot_id}: Reordered refs — speaker {_ots_speaker} first ({len(_speaker_refs)} refs)")
            except Exception as _ots_ref_err:
                logger.warning(f"[V27.1 OTS] Non-blocking ref reorder failed for {shot_id}: {_ots_ref_err}")
        # ═══════════════════════════════════════════════════════

        # Determine generation method based on whether we have references
        if ref_urls:
            # WITH REFERENCES → nano-banana-pro/edit
            method = "nano_banana_edit"
            model = IMAGE_MODEL_WITH_REF
        else:
            # NO REFERENCES → nano-banana-pro (text-to-image)
            method = "nano_banana_t2i"
            model = IMAGE_MODEL_NO_REF

        # V17.5.2: Flag ref-missing shots for UI awareness
        ref_warning = None
        if characters and not char_ref_url:
            ref_warning = f"Characters {characters} present but no character reference found — may generate empty scene"
            logger.warning(f"[V17.5.2 REF GATE] {shot_id}: {ref_warning}")

        # V19: DIALOGUE DURATION CLAMP — Prevent LTX face morphing on long holds
        # Dialogue shots with static faces should be 5-12s max (varies by shot type)
        _V19_DIALOGUE_CLAMP_TABLE = {
            "close_up": (5, 8), "medium_close_up": (5, 8), "extreme_close_up": (4, 6),
            "medium": (6, 10), "over_the_shoulder": (6, 10), "two_shot": (8, 12),
            "wide": (8, 14), "insert": (3, 5), "detail": (3, 5), "reaction": (4, 6),
        }
        _v19_has_dialogue = bool(shot.get("dialogue_text") or shot.get("dialogue"))
        if _v19_has_dialogue:
            _v19_stype = (shot.get("type") or shot.get("shot_type") or "medium").lower()
            _v19_clamp = _V19_DIALOGUE_CLAMP_TABLE.get(_v19_stype, (5, 10))
            _v19_cur_dur = shot.get("duration", 10)
            _v19_clamped = max(_v19_clamp[0], min(_v19_cur_dur, _v19_clamp[1]))
            if _v19_clamped != _v19_cur_dur:
                shot["duration"] = _v19_clamped
                shot["duration_seconds"] = _v19_clamped
                shot["ltx_duration_seconds"] = _v19_clamped
                shot["_v19_dialogue_clamped"] = True
                logger.info(f"[V19 CLAMP] {shot_id}: dialogue shot duration {_v19_cur_dur}s → {_v19_clamped}s ({_v19_stype})")

        plan_entry = {
            "shot_id": shot_id,
            "method": method,
            "model": model,
            "has_char_ref": bool(char_ref_url),
            "has_loc_ref": bool(loc_master_url),
            "ref_count": len(ref_urls),
            "prompt_preview": nano_prompt[:100] + "..." if len(nano_prompt) > 100 else nano_prompt,
            "ref_warning": ref_warning
        }
        generation_plan.append(plan_entry)

        if dry_run:
            continue

        # ═══ V24.2: DOCTRINE PRE-GENERATION GATE ═══
        if _doctrine_runner and DOCTRINE_AVAILABLE:
            try:
                # V24.2.5: Load doctrine scene plans for EXECUTIVE_LAW_02 compliance
                _doctrine_scene_plans = {}
                _dsp_path = project_path / "reports" / "doctrine_scene_plans.json"
                if _dsp_path.exists():
                    try:
                        import json as _dsp_json
                        with open(_dsp_path) as _dsp_f:
                            _doctrine_scene_plans = _dsp_json.load(_dsp_f)
                        logger.info(f"[DOCTRINE] Loaded scene plans: {len(_doctrine_scene_plans)} scenes")
                    except Exception as _dsp_err:
                        logger.warning(f"[DOCTRINE] Scene plan load failed: {_dsp_err}")
                _doc_context = {
                    "cast_map": cast_map,
                    "scene_manifest": data.get("scene_manifest", {}),
                    "scene_plan": _doctrine_scene_plans,
                    "all_known_characters": list(
                        k for k, v in cast_map.items()
                        if isinstance(v, dict) and not k.startswith("_") and not v.get("_is_alias_of")
                    ),
                }
                _doc_pre = _doctrine_runner.pre_generation(shot, _doc_context)
                # V24.2: Phase exceptions are NON-BLOCKING — doctrine internal crashes
                # should not prevent generation. Only explicit gate REJECTs (without
                # phase_exception) are treated as hard blocks.
                _is_phase_exception = _doc_pre.get("phase_exception", False)
                _is_hard_reject = not _doc_pre.get("can_proceed", True) and not _is_phase_exception
                if _is_hard_reject:
                    logger.warning(f"[DOCTRINE] REJECTED {shot_id}: {_doc_pre.get('reject_gate', 'unknown')}")
                    results.append({
                        "shot_id": shot_id,
                        "status": "doctrine_rejected",
                        "reason": _doc_pre.get("reject_gate", "doctrine gate"),
                        "doctrine_result": _doc_pre
                    })
                    continue
                elif _is_phase_exception:
                    logger.warning(f"[DOCTRINE] Phase exception for {shot_id} (non-blocking): {_doc_pre.get('error', '?')}")
                else:
                    logger.info(f"[DOCTRINE] PRE-GEN PASSED {shot_id}: {len(_doc_pre.get('gates', []))} gates checked")
            except Exception as _doc_pre_err:
                logger.warning(f"[DOCTRINE] Pre-gen gate non-blocking for {shot_id}: {_doc_pre_err}")
        # ═══════════════════════════════════════════

        # Actually generate the image
        try:
            output_path = first_frames_dir / f"{shot_id}.jpg"

            # V17 FIX: Skip if already exists UNLESS force=True
            if output_path.exists() and not force:
                results.append({
                    "shot_id": shot_id,
                    "status": "skipped",
                    "reason": "already_exists",
                    "path": str(output_path)
                })
                continue
            elif output_path.exists() and force:
                # V27.3: Auto-archive old frame before overwrite
                try:
                    _archive_dir = project_path / "first_frames_archive"
                    _archive_dir.mkdir(parents=True, exist_ok=True)
                    _archive_ts = datetime.now().strftime("%Y%m%d_%H%M%S")
                    _archive_dest = _archive_dir / f"{shot_id}_{_archive_ts}.jpg"
                    shutil.copy2(str(output_path), str(_archive_dest))
                    logger.info(f"[V27.3 ARCHIVE] {shot_id}: old frame archived to {_archive_dest.name}")
                except Exception as _arc_err:
                    logger.warning(f"[V27.3 ARCHIVE] Archive failed for {shot_id}: {_arc_err}")
                logger.info(f"[V17 FORCE] Regenerating existing frame for {shot_id}")

            logger.info(f"[FIRST_FRAMES] Generating {shot_id} via {method} ({model})")
            logger.info(f"[FIRST_FRAMES] Using {len(ref_urls)} locked reference(s)")

            # V16.7: Track generation start for live UI
            LIVE_GEN_TRACKER.add(
                project=project,
                shot_id=shot_id,
                status="running",
                asset_type="first_frame",
                prompt=nano_prompt,
                model=model
            )

            # V27.5.1: Multi-Candidate Selector determines candidate count per shot type
            # Hero shots (close_up, MCU, dialogue) get 3 candidates for identity selection.
            # Falls back to num_variants if selector is unavailable.
            try:
                from tools.multi_candidate_selector import get_candidate_count
                _mc_count = get_candidate_count(shot)
                effective_variants = max(min(num_variants, 4), _mc_count)  # At least mc_count, capped at 4
            except Exception:
                effective_variants = min(num_variants, 4)  # Fallback: original logic

            # ═══ V25.4: SHOT AUTHORITY — Per-shot FAL param dictation ═══
            _sa_resolution = "1K"   # default production tier
            _sa_max_refs = 5        # default ref cap
            # V27.1: T2-SA-4 Dialogue boost — speaking faces need 2K minimum
            if bool(shot.get("dialogue_text")) and characters:
                _sa_resolution = "2K"
            try:
                from tools.atlas_pipeline_wiring import wire_pre_generation_gate
                _pre_gate = wire_pre_generation_gate([shot], str(project_path), cast_map)
                _sa_resolution = shot.get("_authority_resolution", "1K")
                _sa_max_refs = shot.get("_authority_max_refs", 5)
                if _pre_gate.warnings:
                    for _pw in _pre_gate.warnings[:3]:
                        logger.info(f"[WIRING:PRE-GEN] {_pw}")
            except Exception as _sa_err:
                logger.debug(f"[WIRING:PRE-GEN] Non-blocking: {_sa_err}")

            # ═══ V27.2: CREATIVE DIRECTOR — Apply props/blocking/choreography to prompts ═══
            try:
                from tools.creative_director import apply_creative_directives
                if shot.get("_cd_nano_injection") or shot.get("_cd_ltx_injection"):
                    shot = apply_creative_directives(shot)
                    nano_prompt = shot.get("nano_prompt", nano_prompt)
                    print(f"  [CD] {shot_id}: applied creative directives (props/blocking/emotion)", flush=True)
            except Exception as _cd_apply_err:
                pass  # Non-blocking
            # ═══════════════════════════════════════════════════════════════════

            # ═══ V27.5: IDENTITY INJECTION — Character descriptions into EVERY prompt ═══
            # ROOT CAUSE FIX: 44% of frames failed because nano_prompt had ZERO character
            # description. FAL gets an image ref it can ignore and generic camera language.
            # This injects AMPLIFIED appearance text so FAL knows WHO to draw.
            try:
                from tools.prompt_identity_injector import inject_identity_into_prompt
                _pre_inject_prompt = nano_prompt
                nano_prompt = inject_identity_into_prompt(
                    nano_prompt,
                    characters,  # V37 E-SHOT GUARD: use guarded var ([] for E-shots), not shot.get()
                    cast_map if 'cast_map' in dir() else {},
                    shot.get("shot_type", ""),
                    shot.get("dialogue_text", ""),
                )
                if nano_prompt != _pre_inject_prompt:
                    print(f"  [V27.5 IDENTITY] {shot_id}: injected character descriptions + stripped location names", flush=True)
            except Exception as _id_err:
                pass  # Non-blocking — original prompt passes through
            # ═══════════════════════════════════════════════════════════════════

            # ═══ V28: TRUTH → PROMPT TRANSLATION ═══
            # Reads locked truth fields on the shot and injects [PERFORMANCE:] block
            # with eye-line, body direction, movement, props, emotional state.
            # This is where Intelligence Layer meets Execution Layer.
            try:
                from tools.truth_prompt_translator import translate_truth_to_prompt
                _pre_truth_prompt = nano_prompt
                nano_prompt = translate_truth_to_prompt(nano_prompt, shot)
                if nano_prompt != _pre_truth_prompt:
                    print(f"  [V28 TRUTH] {shot_id}: injected performance directives from truth fields", flush=True)
            except Exception as _truth_err:
                pass  # Non-blocking — original prompt passes through
            # ═══════════════════════════════════════════════════════════════════

            if method == "nano_banana_edit":
                # nano-banana-pro/edit with locked references
                # V16.7: Convert local URLs to base64 for FAL API access
                # V25.4: Shot Authority caps refs per shot type
                fal_ready_refs = convert_refs_for_fal(ref_urls[:_sa_max_refs])
                result = fal_run_with_key_rotation(model, arguments={
                    "prompt": nano_prompt,
                    "image_urls": fal_ready_refs,
                    "aspect_ratio": "16:9",
                    "resolution": _sa_resolution,
                    "output_format": "jpeg",
                    "num_outputs": effective_variants
                })
            else:
                # nano-banana-pro for text-to-image (no refs)
                result = fal_run_with_key_rotation(model, arguments={
                    "prompt": nano_prompt,
                    "aspect_ratio": "16:9",
                    "resolution": _sa_resolution,
                    "output_format": "jpeg",
                    "num_images": effective_variants
                })

            # V17 FIX: Extract ALL image URLs from FAL response
            all_img_urls = []
            if result.get("images") and len(result["images"]) > 0:
                for img_entry in result["images"]:
                    url = img_entry.get("url")
                    if url:
                        all_img_urls.append(url)
            elif result.get("image"):
                url = result["image"].get("url")
                if url:
                    all_img_urls.append(url)

            if not all_img_urls:
                LIVE_GEN_TRACKER.update(shot_id, "error")
                results.append({
                    "shot_id": shot_id,
                    "status": "error",
                    "error": "No image URL in FAL response"
                })
                continue

            # V17 FIX: If multiple variants, download all and pick best via vision scoring
            best_img_url = all_img_urls[0]
            variant_scores = []

            if len(all_img_urls) > 1 and char_ref_url:
                logger.info(f"[V17 BEST-SELECT] Scoring {len(all_img_urls)} variants for {shot_id}")
                # Download all variants to temp files for scoring
                variant_paths = []
                async with httpx.AsyncClient() as http_client:
                    for vi, v_url in enumerate(all_img_urls):
                        v_path = variants_dir / f"{shot_id}_v{vi}.jpg"
                        try:
                            resp = await http_client.get(v_url, timeout=60)
                            if resp.status_code == 200:
                                with open(v_path, 'wb') as vf:
                                    vf.write(resp.content)
                                variant_paths.append((vi, v_path, v_url))
                        except Exception as ve:
                            logger.warning(f"[V17 BEST-SELECT] Failed to download variant {vi}: {ve}")

                # Score each variant against character reference
                if variant_paths:
                    try:
                        from dino_clip_analyzer import get_hybrid_analyzer
                        analyzer = get_hybrid_analyzer()
                        # Get reference path from URL
                        ref_path = char_ref_url.split("path=")[-1] if "path=" in char_ref_url else char_ref_url
                        if Path(ref_path).exists():
                            for vi, v_path, v_url in variant_paths:
                                try:
                                    scores = analyzer.analyze_comprehensive(
                                        str(v_path), ref_path, nano_prompt
                                    )
                                    face_score = scores.get("dino_face", 0)
                                    hybrid_score = scores.get("hybrid_score", 0)
                                    variant_scores.append({
                                        "variant": vi,
                                        "face_score": round(face_score, 3),
                                        "hybrid_score": round(hybrid_score, 3),
                                        "url": v_url,
                                        "path": str(v_path)
                                    })
                                    logger.info(f"[V17 BEST-SELECT] Variant {vi}: face={face_score:.2%} hybrid={hybrid_score:.2%}")
                                except Exception as se:
                                    logger.warning(f"[V17 BEST-SELECT] Scoring failed for variant {vi}: {se}")
                                    variant_scores.append({"variant": vi, "face_score": 0, "hybrid_score": 0, "url": v_url})

                            # Pick best by face_score (primary) then hybrid_score (tiebreak)
                            if variant_scores:
                                best = max(variant_scores, key=lambda v: (v["face_score"], v["hybrid_score"]))
                                best_img_url = best["url"]
                                logger.info(f"[V17 BEST-SELECT] Winner: variant {best['variant']} (face={best['face_score']:.2%})")
                        else:
                            logger.warning(f"[V17 BEST-SELECT] Reference not found at {ref_path}, using first variant")
                    except ImportError:
                        # V27.5.1: Fallback to Vision Judge multi-candidate selector
                        # when DINOv2/CLIP analyzer is not available
                        try:
                            from tools.multi_candidate_selector import select_best_candidate
                            _mc_paths = [str(vp) for _, vp, _ in variant_paths]
                            _mc_result = select_best_candidate(
                                shot_id, _mc_paths, shot,
                                cast_map if 'cast_map' in dir() else {},
                            )
                            if _mc_result.candidates_scored > 0:
                                winner_idx = _mc_result.winner_index
                                best_img_url = variant_paths[winner_idx][2]  # URL of winner
                                for sc in _mc_result.all_scores:
                                    variant_scores.append({
                                        "variant": sc["index"],
                                        "face_score": sc.get("identity_avg", sc.get("score", 0)),
                                        "hybrid_score": sc.get("score", 0),
                                        "url": variant_paths[sc["index"]][2],
                                        "path": str(variant_paths[sc["index"]][1]),
                                        "selector": "vision_judge",
                                    })
                                logger.info(
                                    f"[V27.5.1 SELECTOR] {shot_id}: picked candidate {winner_idx} "
                                    f"(score={_mc_result.winner_score:.3f}) from {_mc_result.candidates_generated}"
                                )
                        except Exception as _mc_err:
                            logger.warning(f"[V27.5.1 SELECTOR] Fallback failed: {_mc_err}, using first variant")
                    except Exception as ae:
                        logger.warning(f"[V17 BEST-SELECT] Analysis failed: {ae}, using first variant")

            # Download best variant (or only variant) and save
            img_url = best_img_url
            async with httpx.AsyncClient() as http_client:
                response = await http_client.get(img_url, timeout=60)
                if response.status_code == 200:
                    with open(output_path, 'wb') as f:
                        f.write(response.content)

                    # V16.7: Track completion with local URL
                    local_url = f"/api/media?path={str(output_path)}"
                    LIVE_GEN_TRACKER.update(shot_id, "completed", url=local_url)

                    result_entry = {
                        "shot_id": shot_id,
                        "status": "success",
                        "method": method,
                        "model": model,
                        "refs_used": len(ref_urls),
                        "path": str(output_path),
                        "url": local_url
                    }
                    # V17: Include variant selection info if multi-variant was used
                    if variant_scores:
                        result_entry["variants_generated"] = len(all_img_urls)
                        result_entry["variant_scores"] = variant_scores
                        result_entry["selected_variant"] = max(variant_scores, key=lambda v: (v["face_score"], v["hybrid_score"]))["variant"]

                    # V17.3: POST-GENERATION QUALITY GATE
                    try:
                        from dino_clip_analyzer import get_lightweight_analyzer
                        qa = get_lightweight_analyzer()
                        face = qa.analyze_face_region(str(output_path))
                        comp = qa.analyze_composition(str(output_path))
                        sharp = qa.analyze_sharpness(str(output_path))
                        qa_scores = {
                            "face_sharpness": round(face.get("face_sharpness", 0), 3),
                            "composition": round(comp.get("composition_score", 0), 3),
                            "sharpness": round(sharp.get("sharpness", 0), 3),
                            "exposure_ok": comp.get("exposure_ok", True),
                            "is_blurred": sharp.get("is_blurred", False),
                        }
                        needs_review = (
                            face.get("is_face_blurred", False)
                            or sharp.get("sharpness", 0) < 0.3
                            or comp.get("composition_score", 0) < 0.2
                        )
                        result_entry["qa_scores"] = qa_scores
                        result_entry["needs_review"] = needs_review
                        if needs_review:
                            logger.warning(f"[QA GATE] {shot_id} FLAGGED for review: {qa_scores}")
                        else:
                            logger.info(f"[QA GATE] {shot_id} PASSED: face={qa_scores['face_sharpness']}, comp={qa_scores['composition']}")
                    except Exception as qa_err:
                        logger.warning(f"[QA GATE] Analysis failed for {shot_id}: {qa_err}")

                    # V17.5.2: VISION SERVICE — Empty room + identity gate
                    try:
                        from tools.vision_service import vision_gate_check
                        ref_path_raw = char_ref_url.split("path=")[-1] if char_ref_url and "path=" in char_ref_url else (char_ref_url or "")
                        loc_path_raw = loc_master_url.split("path=")[-1] if loc_master_url and "path=" in loc_master_url else (loc_master_url or "")
                        vision_result = vision_gate_check(
                            str(output_path), shot,
                            ref_path=ref_path_raw if ref_path_raw and Path(ref_path_raw).exists() else None,
                            location_master_path=loc_path_raw if loc_path_raw and Path(loc_path_raw).exists() else None
                        )
                        result_entry["vision_gate"] = {
                            "passed": vision_result.get("passed", True),
                            "issues": vision_result.get("issues", []),
                            "suggestions": vision_result.get("suggestions", [])
                        }
                        if not vision_result.get("passed", True):
                            result_entry["needs_review"] = True
                            logger.warning(f"[VISION GATE] {shot_id} FLAGGED: {vision_result.get('issues', [])}")
                        else:
                            logger.info(f"[VISION GATE] {shot_id} PASSED")
                    except Exception as vis_err:
                        logger.warning(f"[VISION GATE] Vision service unavailable for {shot_id}: {vis_err}")

                    # ═══ V27.1: OTS POST-GEN VISION GATE ═══
                    # For OTS dialogue shots, verify the SPEAKER's face is facing camera
                    # using ArcFace scoring. If SWAPPED (listener faces camera instead),
                    # flag for regeneration.
                    if _ots_is_ots and _ots_has_dialogue and shot.get("_ots_speaker"):
                        try:
                            from tools.ots_enforcer import OTSEnforcer
                            _ots_enforcer_post = OTSEnforcer(cast_map)
                            _ots_verify = _ots_enforcer_post.verify_ots_frame(
                                str(output_path), shot
                            )
                            result_entry["ots_verification"] = _ots_verify
                            if _ots_verify.get("verdict") == "SWAPPED":
                                result_entry["needs_review"] = True
                                result_entry["ots_swapped"] = True
                                logger.warning(
                                    f"[V27.1 OTS GATE] {shot_id} SWAPPED: "
                                    f"speaker={_ots_verify.get('speaker_similarity', 0):.3f}, "
                                    f"listener={_ots_verify.get('listener_similarity', 0):.3f}. "
                                    f"Listener's face is more visible — wrong character facing camera."
                                )
                            elif _ots_verify.get("verdict") == "CORRECT":
                                logger.info(
                                    f"[V27.1 OTS GATE] {shot_id} CORRECT: "
                                    f"speaker={_ots_verify.get('speaker_similarity', 0):.3f} > "
                                    f"listener={_ots_verify.get('listener_similarity', 0):.3f}"
                                )
                            else:
                                logger.info(f"[V27.1 OTS GATE] {shot_id}: {_ots_verify.get('verdict', 'UNKNOWN')}")
                        except Exception as _ots_post_err:
                            logger.warning(f"[V27.1 OTS GATE] Non-blocking for {shot_id}: {_ots_post_err}")
                    # ═══════════════════════════════════════

                    # ═══ V17.6: LOA Post-Generation QA ═══
                    if LOA_AVAILABLE:
                        try:
                            loa_verdict = run_loa_post_gen_qa(
                                shot, str(output_path), str(project_path),
                                ref_path=ref_path_raw if ref_path_raw and Path(ref_path_raw).exists() else None,
                                location_master_path=loc_path_raw if loc_path_raw and Path(loc_path_raw).exists() else None,
                                cast_map=cast_map
                            )
                            result_entry["loa_verdict"] = loa_verdict
                            result_entry["vision_badges"] = shot.get("vision", {})
                        except Exception as e:
                            logger.warning(f"[LOA] Post-gen QA error for {shot_id}: {e}")
                    # ═══════════════════════════════════════

                    # ═══ V17.6: Register in Cross-Shot Memory ═══
                    if CROSS_SHOT_AVAILABLE:
                        try:
                            drift_result = register_generated_frame(
                                str(project_path), shot_id, str(output_path), shot
                            )
                            result_entry["cross_shot_drift"] = drift_result
                            if drift_result.get("issues"):
                                for issue in drift_result["issues"]:
                                    logger.info(f"[CROSS-SHOT] {shot_id}: {issue.get('type')} — {issue.get('message', '')}")
                        except Exception as e:
                            logger.warning(f"[CROSS-SHOT] Registration failed for {shot_id}: {e}")
                    # ═══════════════════════════════════════

                    # ═══ V24.2: DOCTRINE POST-GENERATION HOOK ═══
                    if _doctrine_runner and DOCTRINE_AVAILABLE:
                        try:
                            _doc_post_ctx = {
                                "cast_map": cast_map,
                                "identity_scores": {},
                                "frame_path": str(output_path),
                            }
                            # Extract identity scores from QA/variant data if available
                            if result_entry.get("qa_scores"):
                                _doc_post_ctx["identity_scores"] = result_entry["qa_scores"]
                            if variant_scores:
                                _best_vs = max(variant_scores, key=lambda v: v.get("face_score", 0))
                                _doc_post_ctx["identity_scores"]["face_score"] = _best_vs.get("face_score", 0)
                            if result_entry.get("vision_gate"):
                                _doc_post_ctx["vision_gate"] = result_entry["vision_gate"]
                            _doc_post = _doctrine_runner.post_generation(shot, _doc_post_ctx)
                            result_entry["doctrine_verdict"] = {
                                "accepted": _doc_post.get("accepted", True),
                                "gates_checked": len(_doc_post.get("gates", [])),
                            }
                            # V27.1: Surface phase exceptions for debugging
                            _phase_excs = _doc_post.get("phase_exceptions", [])
                            if _phase_excs:
                                result_entry["doctrine_verdict"]["phase_exceptions"] = _phase_excs
                                logger.warning(f"[DOCTRINE] {shot_id} had {len(_phase_excs)} phase exception(s): {[e.get('phase') for e in _phase_excs]}")
                            if not _doc_post.get("accepted", True):
                                result_entry["doctrine_verdict"]["reject_gate"] = _doc_post.get("reject_gate")
                                logger.warning(f"[DOCTRINE] POST-GEN REJECTED {shot_id}: {_doc_post.get('reject_gate')}")
                            else:
                                logger.info(f"[DOCTRINE] POST-GEN ACCEPTED {shot_id}: {len(_doc_post.get('gates',[]))} gates checked")
                        except Exception as _doc_post_err:
                            logger.warning(f"[DOCTRINE] Post-gen non-blocking for {shot_id}: {_doc_post_err}")
                    # ═══════════════════════════════════════════════

                    # ═══ V25.4: VISION ANALYST — Post-generation QA scoring ═══
                    try:
                        from tools.atlas_pipeline_wiring import wire_post_generation_qa
                        _vqa = wire_post_generation_qa(shot, str(output_path), str(project_path), cast_map)
                        if _vqa.mutations:
                            result_entry["vision_analyst"] = shot.get("_vision_scores", {})
                        if _vqa.warnings:
                            for _vw in _vqa.warnings[:2]:
                                logger.info(f"[WIRING:POST-QA] {_vw}")
                    except Exception as _vqa_err:
                        logger.debug(f"[WIRING:POST-QA] Non-blocking: {_vqa_err}")
                    # V27.1: Fallback — use vision_badges as vision_analyst if full analyst unavailable
                    if not result_entry.get("vision_analyst") and result_entry.get("vision_badges"):
                        result_entry["vision_analyst"] = result_entry["vision_badges"]
                    # ═══════════════════════════════════════════════

                    # ═══ V27.3: UNIFIED QUALITY GATE — Single verdict from ALL sub-systems ═══
                    # Collects LOA + Aesthetic + Doctrine + Vision + QA + OTS → one PASS/REGEN/FLAG
                    try:
                        from tools.unified_quality_gate import (
                            run_unified_quality_gate, apply_regen_escalation,
                            ErrorPatternAggregator
                        )
                        # Initialize error aggregator once per endpoint call (reuse across shots)
                        if not hasattr(generate_first_frames, '_error_aggregator'):
                            generate_first_frames._error_aggregator = ErrorPatternAggregator(str(project_path))

                        _uqg_ref = ref_path_raw if ref_path_raw and Path(ref_path_raw).exists() else None
                        _uqg_verdict = run_unified_quality_gate(
                            shot_id=shot_id,
                            shot=shot,
                            result_entry=result_entry,
                            frame_path=str(output_path),
                            attempt=1,
                            cast_map=cast_map,
                            story_bible=_story_bible_data if '_story_bible_data' in dir() else None,
                            ref_path=_uqg_ref,
                            error_aggregator=generate_first_frames._error_aggregator,
                        )
                        result_entry["unified_quality"] = {
                            "verdict": _uqg_verdict.verdict,
                            "composite_score": round(_uqg_verdict.composite_score, 3),
                            "signals": _uqg_verdict.signal_summary,
                            "diagnostics": _uqg_verdict.diagnostics,
                            "elapsed_ms": round(_uqg_verdict.elapsed_ms, 1),
                        }

                        # AUTO-REGEN: If verdict is REGEN, escalate and retry (max 2 attempts)
                        if _uqg_verdict.verdict == "REGEN" and _uqg_verdict.regen_plan:
                            _regen_attempt = _uqg_verdict.regen_plan.get("attempt", 2)
                            logger.warning(f"[UQG] {shot_id}: REGEN triggered — attempt {_regen_attempt}")

                            # Apply escalation to shot
                            _regen_shot = apply_regen_escalation(shot, _uqg_verdict.regen_plan, result_entry)
                            _regen_nano = _regen_shot.get("nano_prompt", nano_prompt)
                            _regen_resolution = _regen_shot.get("_authority_resolution", _sa_resolution)

                            # Re-generate with escalated params
                            logger.info(f"[UQG REGEN] {shot_id}: re-generating with cinematic injection + resolution={_regen_resolution}")
                            if method == "nano_banana_edit":
                                _regen_result = fal_run_with_key_rotation(model, arguments={
                                    "prompt": _regen_nano,
                                    "image_urls": fal_ready_refs,
                                    "aspect_ratio": "16:9",
                                    "resolution": _regen_resolution,
                                    "output_format": "jpeg",
                                    "num_outputs": 1
                                })
                            else:
                                _regen_result = fal_run_with_key_rotation(model, arguments={
                                    "prompt": _regen_nano,
                                    "aspect_ratio": "16:9",
                                    "resolution": _regen_resolution,
                                    "output_format": "jpeg",
                                    "num_images": 1
                                })

                            # Download regen frame
                            _regen_urls = []
                            if _regen_result.get("images"):
                                _regen_urls = [i["url"] for i in _regen_result["images"] if i.get("url")]
                            elif _regen_result.get("image", {}).get("url"):
                                _regen_urls = [_regen_result["image"]["url"]]

                            if _regen_urls:
                                import requests as _regen_req
                                _regen_resp = _regen_req.get(_regen_urls[0], timeout=60)
                                if _regen_resp.status_code == 200:
                                    # Save regen over original
                                    _regen_backup = output_path.parent / f"{shot_id}_pre_regen.jpg"
                                    if output_path.exists():
                                        import shutil
                                        shutil.copy2(str(output_path), str(_regen_backup))
                                    with open(output_path, "wb") as _rf:
                                        _rf.write(_regen_resp.content)
                                    result_entry["regen_applied"] = True
                                    result_entry["regen_attempt"] = _regen_attempt
                                    result_entry["regen_backup"] = str(_regen_backup)
                                    result_entry["path"] = str(output_path)
                                    logger.info(f"[UQG REGEN] {shot_id}: regen frame saved (backup at {_regen_backup.name})")
                                else:
                                    logger.warning(f"[UQG REGEN] {shot_id}: regen download failed ({_regen_resp.status_code})")

                        elif _uqg_verdict.verdict == "FLAG":
                            result_entry["needs_review"] = True
                            logger.info(f"[UQG] {shot_id}: flagged for operator review")

                    except Exception as _uqg_err:
                        logger.warning(f"[UQG] Non-blocking for {shot_id}: {_uqg_err}")
                    # ═══════════════════════════════════════════════════════════════

                    # ═══ V27.5.1: VISION JUDGE (Layer 4) — Post-gen identity verification ═══
                    # Uses Florence-2 caption to verify character identity in generated frame.
                    # If identity fails: REGEN with stronger injection + resolution bump.
                    # NON-BLOCKING at pipeline level — if judge crashes, frame passes through.
                    try:
                        from tools.vision_judge import judge_frame, build_regen_plan
                        _vj_attempt = result_entry.get("_regen_attempt", 1)
                        _vj_verdict = judge_frame(
                            shot_id, str(output_path), shot,
                            cast_map if 'cast_map' in dir() else {},
                            attempt=_vj_attempt,
                        )
                        result_entry["vision_judge"] = _vj_verdict.to_dict()
                        logger.info(
                            f"[VISION-JUDGE] {shot_id}: {_vj_verdict.verdict} "
                            f"(scores: {_vj_verdict.identity_scores}, "
                            f"faces: {_vj_verdict.face_count_detected}/{_vj_verdict.face_count_expected})"
                        )

                        if _vj_verdict.verdict == "REGEN" and _vj_attempt <= 2:
                            _vj_plan = build_regen_plan(_vj_verdict, shot)
                            logger.warning(
                                f"[VISION-JUDGE] {shot_id}: REGEN triggered — "
                                f"{_vj_verdict.regen_reason} (attempt {_vj_attempt}→{_vj_plan['attempt']})"
                            )
                            result_entry["vision_judge_regen"] = _vj_plan
                            result_entry["needs_review"] = True
                            # Note: actual regen is handled by UQG above or operator review.
                            # Vision Judge is ADVISORY for now — marks shots for regen but
                            # doesn't re-call FAL directly to avoid double-spend.
                            # When Layer 5 (multi-candidate) is wired, Vision Judge becomes
                            # the SELECTOR that picks the best candidate.

                        elif _vj_verdict.verdict == "FLAG":
                            result_entry["needs_review"] = True
                    except Exception as _vj_err:
                        logger.warning(f"[VISION-JUDGE] Non-blocking for {shot_id}: {_vj_err}")
                    # ═══════════════════════════════════════════════════════════════

                    results.append(result_entry)
                else:
                    LIVE_GEN_TRACKER.update(shot_id, "error")
                    results.append({
                        "shot_id": shot_id,
                        "status": "error",
                        "error": f"Download failed: {response.status_code}"
                    })

        except Exception as e:
            LIVE_GEN_TRACKER.update(shot_id, "error")
            logger.error(f"[FIRST_FRAMES] Error generating {shot_id}: {e}")
            results.append({
                "shot_id": shot_id,
                "status": "error",
                "error": str(e)
            })

    # V16.7.1: Update shot_plan.json with first_frame_path for generated shots
    if not dry_run and results:
        try:
            # Reload shot_plan to get latest
            with open(shot_plan_path) as f:
                shot_plan_data = json.load(f)

            # V27.1: Handle both list and dict formats
            if isinstance(shot_plan_data, list):
                _sp_shots = shot_plan_data
            else:
                _sp_shots = shot_plan_data.get("shots", [])

            shots_updated = 0
            for r in results:
                if r.get("status") in ("success", "skipped") and r.get("path"):
                    shot_id = r.get("shot_id")
                    path = r.get("path")
                    url = r.get("url") or f"/api/media?path={path}"

                    # Find and update shot
                    for shot in _sp_shots:
                        if shot.get("shot_id") == shot_id:
                            shot["first_frame_path"] = path
                            shot["first_frame_url"] = url
                            shots_updated += 1
                            break

            if shots_updated > 0:
                if isinstance(shot_plan_data, dict):
                    shot_plan_data["_first_frames_updated"] = datetime.now().isoformat()
                with open(shot_plan_path, "w") as f:
                    json.dump(shot_plan_data, f, indent=2)
                logger.info(f"[FIRST_FRAMES] Updated shot_plan.json with {shots_updated} first_frame_path entries")
        except Exception as e:
            logger.error(f"[FIRST_FRAMES] Failed to update shot_plan.json: {e}")

    # Summary
    success_count = len([r for r in results if r.get("status") == "success"])
    skipped_count = len([r for r in results if r.get("status") == "skipped"])
    error_count = len([r for r in results if r.get("status") == "error"])

    # V17.3: Log run to manifest — every generation is tracked and diffable
    run_summary = {
        "total_shots": len(shots),
        "planned": len(generation_plan),
        "generated": success_count,
        "skipped": skipped_count,
        "errors": error_count,
        "using_refs": len([p for p in generation_plan if p.get("ref_count", 0) > 0]),
        "using_text_only": len([p for p in generation_plan if p.get("ref_count", 0) == 0])
    }
    if not dry_run:
        try:
            trace = append_run_manifest(project_path, {
                "action": "generate-first-frames",
                "project": project,
                "dry_run": dry_run,
                "summary": run_summary,
                "models": {"with_refs": IMAGE_MODEL_WITH_REF, "no_refs": IMAGE_MODEL_NO_REF}
            })
            logger.info(f"[RUN-MANIFEST] Logged first-frame generation: {trace}")
        except Exception as me:
            logger.warning(f"[RUN-MANIFEST] Failed to log (non-blocking): {me}")

        # V17.3: Temporal workflow tracking
        try:
            _wf_id = temporal_start_workflow(project, "generate_first_frames")
            temporal_run_activity(_wf_id, "generate_first_frames")
            if error_count == 0:
                temporal_complete_activity(_wf_id, "generate_first_frames", result=run_summary)
                temporal_complete_workflow(_wf_id, result=run_summary)
            else:
                temporal_fail_activity(_wf_id, "generate_first_frames", f"{error_count} errors")
            _temporal_persist()
        except Exception:
            pass  # Temporal tracking is non-blocking

    # ═══ V24.2: DOCTRINE SESSION CLOSE HOOK ═══
    _doctrine_summary = None
    if _doctrine_runner and DOCTRINE_AVAILABLE and not dry_run:
        try:
            # Mark scene complete for each processed scene
            _processed_scenes = sorted(set(
                s.get("shot_id", "")[:3] for s in shots if s.get("shot_id")
            ))
            for _ps in _processed_scenes:
                _doctrine_runner.scene_complete(_ps)
            # Close session — triggers Phase 4 learning
            _doctrine_close = _doctrine_runner.session_close()
            _doctrine_summary = {
                "status": _doctrine_close.get("status"),
                "session_id": _doctrine_close.get("session_id"),
                "scenes_completed": _processed_scenes,
            }
            logger.info(f"[DOCTRINE] Session closed: {_doctrine_close.get('status')} — {len(_processed_scenes)} scenes")
            # Remove runner so next call gets a fresh session
            _doctrine_runners.pop(str(project_path), None)
        except Exception as _doc_close_err:
            logger.warning(f"[DOCTRINE] Session close non-blocking: {_doc_close_err}")
    # ═══════════════════════════════════════════════════

    # ═══ V27.3 LAW T2-OR-20: UI CACHE INVALIDATION IS MANDATORY AFTER GENERATION ═══
    # The UI is the operator's ONLY window into the system. If the cache is stale,
    # the operator is blind. Every generation run MUST invalidate the bundle cache
    # so the next UI request rebuilds with fresh frame paths and quality verdicts.
    # This is NOT optional. This is NOT non-blocking. This is a LAW.
    if not dry_run and results:
        try:
            _invalidate_bundle_cache(project)
            logger.info(f"[V27.3 UI-LAW] Bundle cache invalidated for {project} after generation ({len(results)} results)")
        except Exception as _cache_err:
            # Even if invalidation fails, try the dirty flag directly
            try:
                _dirty_path = project_path / "ui_cache" / "bundle.dirty"
                _dirty_path.parent.mkdir(parents=True, exist_ok=True)
                _dirty_path.touch(exist_ok=True)
            except Exception:
                pass
            logger.warning(f"[V27.3 UI-LAW] Cache invalidation warning (dirty flag set): {_cache_err}")
    # ═══════════════════════════════════════════════════════════════════════════

    _return_data = {
        "success": True,
        "project": project,
        "dry_run": dry_run,
        "models_used": {
            "with_refs": IMAGE_MODEL_WITH_REF,
            "no_refs": IMAGE_MODEL_NO_REF
        },
        "generation_plan": generation_plan,
        "results": results if not dry_run else [],
        "summary": run_summary
    }
    if _doctrine_summary:
        _return_data["doctrine"] = _doctrine_summary
    return _return_data


@app.post("/api/auto/generate-first-frames-turbo")
async def generate_first_frames_turbo(request: Dict = Body(...), raw_request: Request = None):
    """
    ⚠️ INTERNAL-ONLY ENDPOINT — V26.1 GOVERNED ACCESS
    Direct UI access is BLOCKED. Must route through /api/v26/generate-shot.
    Internal callers set X-ATLAS-GOVERNED: 1 header to bypass guard.

    V17: TURBO PARALLEL first frame generation - 15 concurrent workers.

    Body:
    {
        "project": "kord",
        "shot_ids": ["001_001A", ...],  // optional
        "max_workers": 15,              // default 15, max 20
        "dry_run": false
    }
    """
    from concurrent.futures import ThreadPoolExecutor, as_completed
    import threading
    import httpx

    # V26.1: GOVERNANCE GUARD — block direct UI access, require governed header
    _is_governed = False
    if raw_request and hasattr(raw_request, 'headers'):
        _is_governed = raw_request.headers.get("x-atlas-governed") == "1"
    if not _is_governed:
        logger.warning("[V26.1] ⚠️ BLOCKED: generate-first-frames-turbo called without governance. "
                       "UI must use /api/v26/generate-shot with render_mode='turbo'.")
        return {
            "success": False,
            "error": "Turbo must be called through V26 governance. Use /api/v26/generate-shot with render_mode='turbo'.",
            "governed": False,
        }

    # LOCKED MODELS
    IMAGE_MODEL_WITH_REF = "fal-ai/nano-banana-pro/edit"
    IMAGE_MODEL_NO_REF = "fal-ai/nano-banana-pro"

    project = request.get("project", "")
    shot_ids = request.get("shot_ids", [])
    scene_filter = request.get("scene_filter", "")  # V17.3: REQUIRED — e.g. "001" or "001,002,003"
    max_workers = min(request.get("max_workers", 15), 20)  # Cap at 20
    dry_run = request.get("dry_run", False)
    force = request.get("force", False)  # V17 FIX: Allow forced regeneration

    if not project:
        return {"success": False, "error": "Project name required"}

    # V17.3 HARD LOCK: Must specify scene_filter OR shot_ids — NO full-project generation
    MAX_SHOTS_PER_BATCH = 50  # Hard limit per API call
    if not shot_ids and not scene_filter:
        return {
            "success": False,
            "error": "HARD LOCK: scene_filter or shot_ids REQUIRED. Cannot generate all shots at once. Use scene_filter='001' or scene_filter='001,002,003' to generate specific scenes.",
            "hint": "This prevents accidental full-project generation which wastes API credits."
        }

    project_path = get_project_path(project)
    shot_plan_path = project_path / "shot_plan.json"

    if not shot_plan_path.exists():
        return {"success": False, "error": f"Project '{project}' not found"}

    with open(shot_plan_path) as f:
        data = json.load(f)

    # V27.1: Handle both list format [shots...] and dict format {"shots": [...]}
    if isinstance(data, list):
        shots = data
        data = {"shots": data}
    else:
        shots = data.get("shots", [])

    # V17.3: Apply scene_filter if provided
    if scene_filter:
        scene_list = [s.strip() for s in scene_filter.split(",")]
        shots = [s for s in shots if s.get("shot_id", "")[:3] in scene_list]
        logger.info(f"[TURBO] Scene filter: {scene_list} → {len(shots)} shots")

    if shot_ids:
        shots = [s for s in shots if s.get("shot_id") in shot_ids]

    # V17.3 HARD LOCK: Enforce batch limit
    if len(shots) > MAX_SHOTS_PER_BATCH and not dry_run:
        return {
            "success": False,
            "error": f"HARD LOCK: {len(shots)} shots exceeds max batch size of {MAX_SHOTS_PER_BATCH}. Use smaller scene_filter or specific shot_ids.",
            "shots_requested": len(shots),
            "max_allowed": MAX_SHOTS_PER_BATCH
        }

    first_frames_dir = project_path / "first_frames"
    first_frames_dir.mkdir(parents=True, exist_ok=True)

    # Load cast_map for refs
    cast_map = {}
    cast_map_path = project_path / "cast_map.json"
    if cast_map_path.exists():
        with open(cast_map_path) as f:
            cast_map = json.load(f)

    # V22: LITE MODE check
    lite_mode = request.get("lite_mode", False)

    # V21: Run Prompt Authority Gate BEFORE generation
    # V22: Skip in lite_mode — prompts are already finalized
    if not lite_mode:
        try:
            from tools.prompt_authority_gate import enforce_prompt_authority
            _pa_stats = enforce_prompt_authority(shots, project_path, cast_map)
            logger.info(f"[TURBO] ✅ Prompt Authority Gate: {_pa_stats}")
        except Exception as _pa_err:
            logger.warning(f"[TURBO] Prompt Authority Gate non-blocking error: {_pa_err}")

        # V21.2: Persist gate-cleaned prompts DIRECTLY as nano_prompt / ltx_motion_prompt
        try:
            _sp_path = project_path / "shot_plan.json" if isinstance(project_path, Path) else Path(project_path) / "shot_plan.json"
            if _sp_path.exists():
                with open(_sp_path) as _gf:
                    _sp_data = json.load(_gf)
                _sp_shots = _sp_data.get("shots", [])
                _sp_idx = {s.get("shot_id"): s for s in _sp_shots}
                _gated_count = 0
                for _gs in shots:
                    _gid = _gs.get("shot_id")
                    if _gid and _gid in _sp_idx:
                        _sp_idx[_gid]["nano_prompt"] = _gs.get("nano_prompt", "")
                        _sp_idx[_gid]["ltx_motion_prompt"] = _gs.get("ltx_motion_prompt", "")
                        _sp_idx[_gid]["_gate_timestamp"] = datetime.now().isoformat()
                        _gated_count += 1
                _sp_data["_last_gate_run"] = datetime.now().isoformat()
                import tempfile as _tf_gate2
                _tmp = _tf_gate2.NamedTemporaryFile(mode='w', dir=str(_sp_path.parent), suffix='.tmp', delete=False)
                json.dump(_sp_data, _tmp, indent=2)
                _tmp.close()
                os.replace(_tmp.name, str(_sp_path))
                _invalidate_bundle_cache(project)
                logger.info(f"[TURBO-GATE] ✅ Wrote {_gated_count} cleaned prompts directly to shot_plan.json")
        except Exception as _gp_err:
            logger.warning(f"[TURBO-GATE] Non-blocking persist error: {_gp_err}")
    else:
        logger.info(f"[TURBO V22 LITE] ⚡ Skipping Authority Gate + persist — prompts go to FAL as-is")

    # ═══ V26: DOCTRINE COMMAND SYSTEM — Turbo Pre-Generation Gate ═══
    _turbo_doctrine_runner = None
    if DOCTRINE_AVAILABLE and not dry_run:
        try:
            _turbo_doctrine_runner = _get_doctrine_runner(str(project_path))
            _turbo_story_bible = {}
            _sb_path = project_path / "story_bible.json"
            if _sb_path.exists():
                with open(_sb_path) as _sb_f:
                    _turbo_story_bible = json.load(_sb_f)
            _turbo_manifest = data.get("scene_manifest", {})
            _turbo_doc_init = _turbo_doctrine_runner.scene_initialize(
                shots, _turbo_manifest, _turbo_story_bible.get("scenes", {}), cast_map
            )
            logger.info(f"[DOCTRINE-TURBO] Scene initialized: {_turbo_doc_init.get('status')} — {len(shots)} shots")
            if _turbo_doc_init.get("status") == "REJECTED":
                logger.error(f"[DOCTRINE-TURBO] HARD STOP: {_turbo_doc_init.get('reason')}")
                return {
                    "success": False,
                    "error": f"DOCTRINE HARD STOP: {_turbo_doc_init.get('reason')}",
                    "doctrine_status": _turbo_doc_init
                }
        except Exception as _turbo_doc_err:
            logger.warning(f"[DOCTRINE-TURBO] Scene init non-blocking: {_turbo_doc_err}")

    # V26: Per-shot doctrine pre-generation check (before parallel dispatch)
    _doctrine_rejected_shots = set()
    if _turbo_doctrine_runner and DOCTRINE_AVAILABLE and not dry_run:
        for _ds in shots:
            try:
                _ds_ctx = {
                    "project_path": str(project_path),
                    "cast_map": cast_map,
                    "scene_id": _ds.get("scene_id", _ds.get("shot_id", "")[:3]),
                }
                _ds_pre = _turbo_doctrine_runner.pre_generation(_ds, _ds_ctx)
                if _ds_pre.get("can_proceed") == False:
                    _doctrine_rejected_shots.add(_ds.get("shot_id"))
                    logger.warning(f"[DOCTRINE-TURBO] REJECTED {_ds.get('shot_id')}: {_ds_pre.get('reject_gate', 'unknown')}")
            except Exception as _ds_err:
                logger.warning(f"[DOCTRINE-TURBO] Pre-gen non-blocking for {_ds.get('shot_id')}: {_ds_err}")
    # ═══════════════════════════════════════════════════════════════════

    # Progress tracking
    results_lock = threading.Lock()
    results = []
    generation_plan = []

    # Prepare all shots for generation
    shots_to_generate = []
    for shot in shots:
        shot_id = shot.get("shot_id", "unknown")
        # V27.1.5: nano_prompt_v24 REMOVED — all baked prompts in nano_prompt field
        nano_prompt = shot.get("nano_prompt", shot.get("description", ""))
        output_path = first_frames_dir / f"{shot_id}.jpg"

        # V26: Skip doctrine-rejected shots
        if shot_id in _doctrine_rejected_shots:
            with results_lock:
                results.append({
                    "shot_id": shot_id,
                    "status": "doctrine_rejected",
                    "reason": "Pre-generation doctrine gate rejected this shot"
                })
            continue

        # V17 FIX: Skip if already exists UNLESS force=True
        if output_path.exists() and not force:
            with results_lock:
                results.append({
                    "shot_id": shot_id,
                    "status": "skipped",
                    "reason": "already_exists",
                    "path": str(output_path)
                })
            continue
        elif output_path.exists() and force:
            logger.info(f"[V17 TURBO FORCE] Regenerating existing frame for {shot_id}")

        # V17 FIX: Get refs - also fall back to cast_map if shot-level ref missing
        char_ref_url = shot.get("character_reference_url")
        loc_master_url = shot.get("location_master_url")

        # V17 FIX: Cast_map fallback for missing character refs
        if not char_ref_url and shot.get("characters") and cast_map:
            chars = shot.get("characters", [])
            first_char = chars[0] if isinstance(chars[0], str) else chars[0].get("name", "")
            first_char_upper = first_char.upper().strip()
            for ck, cv in cast_map.items():
                if ck.startswith("_"):
                    continue
                if isinstance(cv, dict) and (first_char_upper in ck.upper() or ck.upper() in first_char_upper):
                    char_ref_url = cv.get("reference_url") or cv.get("headshot_url") or cv.get("locked_reference_url")
                    if char_ref_url:
                        logger.info(f"[V17 TURBO FIX] Resolved char ref for {first_char} from cast_map")
                    break

        ref_urls = []
        if char_ref_url:
            ref_urls.append(char_ref_url)
        if loc_master_url:
            ref_urls.append(loc_master_url)

        method = "nano_banana_edit" if ref_urls else "nano_banana_t2i"
        model = IMAGE_MODEL_WITH_REF if ref_urls else IMAGE_MODEL_NO_REF

        plan_entry = {
            "shot_id": shot_id,
            "method": method,
            "model": model,
            "ref_count": len(ref_urls),
            "prompt_preview": nano_prompt[:80] + "..." if len(nano_prompt) > 80 else nano_prompt
        }
        generation_plan.append(plan_entry)

        if not dry_run:
            shots_to_generate.append({
                "shot_id": shot_id,
                "nano_prompt": nano_prompt,
                "ref_urls": ref_urls,
                "method": method,
                "model": model,
                "output_path": output_path
            })

    if dry_run:
        return {
            "success": True,
            "project": project,
            "dry_run": True,
            "max_workers": max_workers,
            "generation_plan": generation_plan,
            "to_generate": len(generation_plan),
            "already_exist": len(results)
        }

    # Worker function for parallel execution
    def generate_single_frame(task):
        shot_id = task["shot_id"]
        nano_prompt = task["nano_prompt"]
        ref_urls = task["ref_urls"]
        method = task["method"]
        model = task["model"]
        output_path = task["output_path"]

        try:
            logger.info(f"[TURBO] Generating {shot_id} via {method}")

            LIVE_GEN_TRACKER.add(
                project=project,
                shot_id=shot_id,
                status="running",
                asset_type="first_frame",
                prompt=nano_prompt[:100],
                model=model
            )

            if method == "nano_banana_edit":
                fal_ready_refs = convert_refs_for_fal(ref_urls[:5])
                result = fal_run_with_key_rotation(model, arguments={
                    "prompt": nano_prompt,
                    "image_urls": fal_ready_refs,
                    "aspect_ratio": "16:9",
                    "output_format": "jpeg",
                    "num_outputs": 1
                })
            else:
                result = fal_run_with_key_rotation(model, arguments={
                    "prompt": nano_prompt,
                    "aspect_ratio": "16:9",
                    "output_format": "jpeg",
                    "num_images": 1
                })

            # Extract URL
            img_url = None
            if result.get("images") and len(result["images"]) > 0:
                img_url = result["images"][0].get("url")
            elif result.get("image"):
                img_url = result["image"].get("url")

            if not img_url:
                LIVE_GEN_TRACKER.update(shot_id, "error")
                return {"shot_id": shot_id, "status": "error", "error": "No image URL in response"}

            # Download synchronously (we're in a thread)
            import requests
            response = requests.get(img_url, timeout=60)
            if response.status_code == 200:
                with open(output_path, 'wb') as f:
                    f.write(response.content)

                local_url = f"/api/media?path={str(output_path)}"
                LIVE_GEN_TRACKER.update(shot_id, "completed", url=local_url)

                # V17.3: POST-GENERATION QUALITY GATE — analyze every frame
                qa_scores = {}
                needs_review = False
                try:
                    from dino_clip_analyzer import get_lightweight_analyzer
                    qa = get_lightweight_analyzer()
                    # Face sharpness check
                    face = qa.analyze_face_region(str(output_path))
                    comp = qa.analyze_composition(str(output_path))
                    sharp = qa.analyze_sharpness(str(output_path))
                    qa_scores = {
                        "face_sharpness": round(face.get("face_sharpness", 0), 3),
                        "composition": round(comp.get("composition_score", 0), 3),
                        "contrast": round(comp.get("contrast", 0), 3),
                        "sharpness": round(sharp.get("sharpness", 0), 3),
                        "exposure_ok": comp.get("exposure_ok", True),
                        "is_blurred": sharp.get("is_blurred", False),
                        "is_face_blurred": face.get("is_face_blurred", False),
                    }
                    # Quality gate: flag if face blurred OR sharpness < 0.3 OR composition < 0.2
                    needs_review = (
                        face.get("is_face_blurred", False)
                        or sharp.get("sharpness", 0) < 0.3
                        or comp.get("composition_score", 0) < 0.2
                    )
                    if needs_review:
                        logger.warning(f"[TURBO QA] {shot_id} FLAGGED: face_sharp={qa_scores['face_sharpness']}, comp={qa_scores['composition']}, sharp={qa_scores['sharpness']}")
                    else:
                        logger.info(f"[TURBO QA] {shot_id} PASSED: face={qa_scores['face_sharpness']}, comp={qa_scores['composition']}")
                except Exception as qa_err:
                    logger.warning(f"[TURBO QA] Analysis failed for {shot_id}: {qa_err}")

                # Reference consistency check
                ref_similarity = {}
                if ref_urls:
                    try:
                        from dino_clip_analyzer import get_lightweight_analyzer
                        qa = get_lightweight_analyzer()
                        ref_path = ref_urls[0].split("path=")[-1] if "path=" in ref_urls[0] else ref_urls[0]
                        if Path(ref_path).exists():
                            ref_comp = qa.compare_images(str(output_path), ref_path)
                            ref_similarity = {
                                "histogram_similarity": round(ref_comp.get("histogram_similarity", 0), 3),
                                "structural_match": ref_comp.get("structural_match", False),
                            }
                            if ref_comp.get("histogram_similarity", 0) < 0.5:
                                needs_review = True
                                logger.warning(f"[TURBO QA] {shot_id} LOW REF MATCH: {ref_similarity['histogram_similarity']}")
                    except Exception:
                        pass

                return {
                    "shot_id": shot_id,
                    "status": "success",
                    "method": method,
                    "path": str(output_path),
                    "url": local_url,
                    "qa_scores": qa_scores,
                    "ref_similarity": ref_similarity,
                    "needs_review": needs_review
                }
            else:
                LIVE_GEN_TRACKER.update(shot_id, "error")
                return {"shot_id": shot_id, "status": "error", "error": f"Download failed: {response.status_code}"}

        except Exception as e:
            LIVE_GEN_TRACKER.update(shot_id, "error")
            logger.error(f"[TURBO] Error generating {shot_id}: {e}")
            return {"shot_id": shot_id, "status": "error", "error": str(e)}

    # Execute in parallel with ThreadPoolExecutor
    start_time = time.time()
    logger.info(f"[TURBO] Starting parallel generation: {len(shots_to_generate)} shots with {max_workers} workers")

    with ThreadPoolExecutor(max_workers=max_workers) as executor:
        future_to_shot = {executor.submit(generate_single_frame, task): task["shot_id"] for task in shots_to_generate}

        # V17.3: LIVE HYDRATION — track completion count for incremental saves
        completed_count = 0
        LIVE_SAVE_INTERVAL = 5  # Save to disk every N completions

        for future in as_completed(future_to_shot):
            shot_id = future_to_shot[future]
            try:
                result = future.result()
                with results_lock:
                    results.append(result)
                completed_count += 1
                logger.info(f"[TURBO] Completed {shot_id}: {result.get('status')} ({completed_count}/{len(shots_to_generate)})")

                # V17.3: LIVE HYDRATION — incremental save every N frames
                if result.get("status") == "success" and completed_count % LIVE_SAVE_INTERVAL == 0:
                    try:
                        with open(shot_plan_path) as _f:
                            _live_data = json.load(_f)
                        _live_updated = 0
                        for _r in results:
                            if _r.get("status") == "success" and _r.get("path"):
                                for _s in _live_data.get("shots", []):
                                    if _s.get("shot_id") == _r.get("shot_id"):
                                        _s["first_frame_path"] = _r.get("path")
                                        _s["first_frame_url"] = _r.get("url") or f"/api/media?path={_r.get('path')}"
                                        if _r.get("qa_scores"):
                                            _s["_qa_scores"] = _r["qa_scores"]
                                        _live_updated += 1
                                        break
                        if _live_updated > 0:
                            _live_data["_first_frames_updated"] = datetime.now().isoformat()
                            with open(shot_plan_path, "w") as _f:
                                json.dump(_live_data, _f, indent=2)
                            # Invalidate UI cache for live refresh
                            cache_dir = project_path / "ui_cache"
                            cache_dir.mkdir(exist_ok=True)
                            dirty_flag = cache_dir / "bundle.dirty"
                            dirty_flag.touch()
                            bundle_cache = cache_dir / "bundle.json"
                            if bundle_cache.exists():
                                bundle_cache.unlink()
                            logger.info(f"[TURBO LIVE] Saved {_live_updated} frames + cache invalidated ({completed_count}/{len(shots_to_generate)})")
                    except Exception as _le:
                        logger.warning(f"[TURBO LIVE] Incremental save failed: {_le}")
            except Exception as e:
                with results_lock:
                    results.append({"shot_id": shot_id, "status": "error", "error": str(e)})

    elapsed = time.time() - start_time

    # Update shot_plan.json with paths (final complete save)
    try:
        with open(shot_plan_path) as f:
            shot_plan_data = json.load(f)

        shots_updated = 0
        flagged_shots = []
        for r in results:
            if r.get("status") in ("success", "skipped") and r.get("path"):
                for shot in shot_plan_data.get("shots", []):
                    if shot.get("shot_id") == r.get("shot_id"):
                        shot["first_frame_path"] = r.get("path")
                        shot["first_frame_url"] = r.get("url") or f"/api/media?path={r.get('path')}"
                        # V17.3: Persist QA scores to shot_plan
                        if r.get("qa_scores"):
                            shot["_qa_scores"] = r["qa_scores"]
                        if r.get("needs_review"):
                            shot["_needs_review"] = True
                            flagged_shots.append(r.get("shot_id"))
                        elif "needs_review" in r:
                            shot["_needs_review"] = False
                        if r.get("ref_similarity"):
                            shot["_ref_similarity"] = r["ref_similarity"]
                        shots_updated += 1
                        break

        if shots_updated > 0:
            shot_plan_data["_first_frames_updated"] = datetime.now().isoformat()
            with open(shot_plan_path, "w") as f:
                json.dump(shot_plan_data, f, indent=2)
            if flagged_shots:
                logger.warning(f"[TURBO QA] {len(flagged_shots)} shots flagged for review: {flagged_shots[:10]}")
            # V17.3: Final cache invalidation after batch complete
            try:
                cache_dir = project_path / "ui_cache"
                cache_dir.mkdir(exist_ok=True)
                (cache_dir / "bundle.dirty").touch()
                bundle_cache = cache_dir / "bundle.json"
                if bundle_cache.exists():
                    bundle_cache.unlink()
                logger.info(f"[TURBO] Final cache invalidation complete — UI will show all {shots_updated} new frames")
            except Exception:
                pass
    except Exception as e:
        logger.error(f"[TURBO] Failed to update shot_plan.json: {e}")

    success_count = len([r for r in results if r.get("status") == "success"])
    skipped_count = len([r for r in results if r.get("status") == "skipped"])
    error_count = len([r for r in results if r.get("status") == "error"])
    flagged_count = len([r for r in results if r.get("needs_review")])

    # V17.3: Cost tracking — REAL FAL.ai prices as of Feb 2026
    # Source: https://fal.ai/pricing — nano-banana-pro = $0.15/image
    COST_PER_FRAME_EDIT = 0.15  # nano-banana-pro/edit (with refs) — REAL fal.ai price
    COST_PER_FRAME_T2I = 0.15   # nano-banana-pro (no refs) — REAL fal.ai price
    edit_count = len([r for r in results if r.get("method") == "nano_banana_edit" and r.get("status") == "success"])
    t2i_count = len([r for r in results if r.get("method") == "nano_banana_t2i" and r.get("status") == "success"])
    estimated_cost = round(edit_count * COST_PER_FRAME_EDIT + t2i_count * COST_PER_FRAME_T2I, 2)

    # Append to cost log
    try:
        cost_log_path = project_path / "cost_log.json"
        cost_log = []
        if cost_log_path.exists():
            with open(cost_log_path) as f:
                cost_log = json.load(f)
        cost_log.append({
            "timestamp": datetime.now().isoformat(),
            "type": "first_frames_turbo",
            "scenes": scene_filter or "specific_shots",
            "frames_generated": success_count,
            "estimated_cost_usd": estimated_cost,
            "elapsed_seconds": round(elapsed, 2)
        })
        with open(cost_log_path, "w") as f:
            json.dump(cost_log, f, indent=2)
        logger.info(f"[TURBO COST] {success_count} frames = ~${estimated_cost:.2f} USD")
    except Exception as ce:
        logger.warning(f"[TURBO COST] Failed to log cost: {ce}")

    # ═══ V26: DOCTRINE SESSION CLOSE — Turbo Post-Generation ═══
    _turbo_doctrine_rejected = len([r for r in results if r.get("status") == "doctrine_rejected"])
    if _turbo_doctrine_runner and DOCTRINE_AVAILABLE:
        try:
            _turbo_close = _turbo_doctrine_runner.session_close()
            logger.info(f"[DOCTRINE-TURBO] Session closed: {_turbo_close.get('status', 'unknown')} — "
                        f"{success_count} generated, {_turbo_doctrine_rejected} doctrine-rejected")
            _doctrine_runners.pop(str(project_path), None)
        except Exception as _turbo_close_err:
            logger.warning(f"[DOCTRINE-TURBO] Session close non-blocking: {_turbo_close_err}")
    # ═══════════════════════════════════════════════════════════════════

    return {
        "success": True,
        "project": project,
        "mode": "TURBO_PARALLEL",
        "scene_filter": scene_filter or None,
        "max_workers": max_workers,
        "elapsed_seconds": round(elapsed, 2),
        "throughput": f"{success_count / elapsed:.1f} shots/sec" if elapsed > 0 else "N/A",
        "results": results,
        "summary": {
            "total_shots": len(shots),
            "generated": success_count,
            "skipped": skipped_count,
            "errors": error_count,
            "doctrine_rejected": _turbo_doctrine_rejected,
            "flagged_for_review": flagged_count,
            "qa_pass_rate": f"{((success_count - flagged_count) / max(success_count, 1)) * 100:.0f}%"
        },
        "cost": {
            "edit_frames": edit_count,
            "t2i_frames": t2i_count,
            "estimated_usd": estimated_cost
        },
        "qa_flagged_shots": [r.get("shot_id") for r in results if r.get("needs_review")]
    }


@app.get("/api/v6/verification-state/{project_name}")
async def get_verification_state(project_name: str):
    """
    Get unified verification state for project.

    RB-5 FIX: Read actual state from files instead of returning stub data.

    Sources:
    - master_locks.json: characters_locked, locations_locked
    - cast_map.json: _approved flag
    - verification_state.json: shots_verified (if exists)
    - story_bible.json: _approved flag
    """
    project_path = get_project_path(project_name)

    # Read master_locks.json
    locks_path = project_path / "master_locks.json"
    locks = {}
    if locks_path.exists():
        try:
            with open(locks_path) as f:
                locks = json.load(f)
        except Exception:
            pass

    # Read cast_map.json
    cast_map_path = project_path / "cast_map.json"
    casting_approved = False
    if cast_map_path.exists():
        try:
            with open(cast_map_path) as f:
                cast_map = json.load(f)
                casting_approved = cast_map.get("_approved", False)
        except Exception:
            pass

    # Read verification_state.json
    verification_path = project_path / "verification_state.json"
    verification = {}
    if verification_path.exists():
        try:
            with open(verification_path) as f:
                verification = json.load(f)
        except Exception:
            pass

    # Read story_bible.json for story approval
    story_bible_path = project_path / "story_bible.json"
    story_approved = False
    if story_bible_path.exists():
        try:
            with open(story_bible_path) as f:
                story = json.load(f)
                story_approved = story.get("_approved", False)
        except Exception:
            pass

    return {
        "project": project_name,
        "verification": {
            "story_verified": story_approved,
            "characters_verified": locks.get("characters", False) or locks.get("characters_locked", False),
            "locations_verified": locks.get("locations", False) or locks.get("locations_locked", False),
            "casting_verified": casting_approved,
            "shots_verified": verification.get("shots_verified", False)
        },
        # Also include raw sources for debugging
        "_sources": {
            "master_locks": locks,
            "cast_map_approved": casting_approved,
            "story_approved": story_approved,
            "verification_state": verification
        }
    }


