@app.get("/api/v10/preflight/{project_name}")
async def run_preflight_validation(project_name: str):
    """
    Run preflight validation on a project.
    Checks content safety, duration alignment, character locks, etc.
    """
    project_path = get_project_path(project_name)
    shot_plan_path = project_path / "shot_plan.json"

    if not shot_plan_path.exists():
        return {"success": False, "error": f"Project '{project_name}' not found"}

    with open(shot_plan_path) as f:
        data = json.load(f)

    # V27.1: Handle both list format [shots...] and dict format {"shots": [...]}
    if isinstance(data, list):
        shots = data
        data = {"shots": data}
    else:
        shots = data.get("shots", [])

    try:
        from CRITIC_AGENT import run_preflight_before_render
        result = run_preflight_before_render(
            shots=shots,
            project_type="project"
        )
        passed = result.get("passed", False)
        ready = result.get("ready_to_render", False)
        block_count = result.get("block_count", 0)
        warning_count = result.get("warning_count", 0)

        # V16.7.1: Calculate health_score for UI compatibility
        # Health = 1.0 if passed, 0.7 if warnings only, 0.3 if blocks
        if passed and block_count == 0:
            health_score = 1.0 if warning_count == 0 else 0.85
        elif block_count == 0:
            health_score = 0.7
        else:
            health_score = max(0.1, 0.5 - (block_count * 0.1))

        return {
            "success": True,
            "project": project_name,
            "passed": passed,
            "ready_to_render": ready,
            # V16.7.1: UI-expected keys
            "health_score": health_score,
            "ready_for_generation": bool(ready and block_count == 0),
            # Original keys
            "issues": result.get("issues", []),
            "block_count": block_count,
            "warning_count": warning_count
        }
    except Exception as e:
        logger.error(f"Preflight validation error: {e}")
        return {
            "success": False,
            "error": str(e),
            "passed": False,
            # V16.7.1: UI-expected keys even on error
            "health_score": 0.0,
            "ready_for_generation": False,
            "issues": [{"severity": "ERROR", "message": str(e)}]
        }


