@app.post("/api/v16/add-regression")
async def add_regression_pair(request: Dict = Body(...)):
    """
    V16.2: Manually add a rejected actor-character pair to regression history.
    """
    project = request.get("project")
    character = request.get("character")
    actor = request.get("actor")
    reason = request.get("reason", "MANUAL_REJECTION")

    if not all([project, character, actor]):
        return {"success": False, "error": "project, character, and actor are required"}

    project_path = get_project_path(project)
    history_path = project_path / "regression_history.json"

    history = {"rejected_pairs": [], "version": "1.0"}
    if history_path.exists():
        with open(history_path) as f:
            history = json.load(f)

    # Check if already exists
    exists = any(
        r["character"] == character.upper() and r["actor"] == actor
        for r in history.get("rejected_pairs", [])
    )

    if exists:
        return {"success": True, "message": "Pair already in regression history"}

    history["rejected_pairs"].append({
        "character": character.upper(),
        "actor": actor,
        "rejection_reason": reason,
        "timestamp": datetime.now().isoformat(),
        "fit_score": 0
    })
    history["last_updated"] = datetime.now().isoformat()

    with open(history_path, 'w') as f:
        json.dump(history, f, indent=2)

    return {"success": True, "message": f"Added {character} -> {actor} to regression history"}


