@app.post("/api/v17/governed-run")
async def run_governed_pipeline(request: Dict = Body(...)):
    """
    V17: Execute governed agent pipeline with execution context.

    Request:
        {
            "projects": ["kord_v17", "ravencroft_v17"],
            "mode": "VERIFY" | "REPAIR" | "OVERWRITE" | "LOCKED",
            "initiated_by": "human" | "scheduled"
        }

    Returns:
        {
            "run_id": "abc123",
            "final_verdict": "READY" | "NEEDS_REPAIR" | "NEEDS_HUMAN_JUDGMENT",
            "projects": { ... per-project results ... }
        }

    The governed pipeline:
    1. Creates immutable execution context
    2. Runs agents: cast_agent → cast_propagator → plan_fixer → critic_gate
    3. Collects structured summaries to append-only log
    4. Returns critic verdict (final authority)
    5. Auto-retries in REPAIR mode if needed
    """
    projects = request.get("projects", [])
    mode = request.get("mode", "VERIFY")
    initiated_by = request.get("initiated_by", "human")

    if not projects:
        return {"success": False, "error": "projects list required"}

    if mode not in ("VERIFY", "REPAIR", "OVERWRITE", "LOCKED"):
        return {"success": False, "error": f"Invalid mode: {mode}. Use VERIFY, REPAIR, OVERWRITE, or LOCKED"}

    try:
        import sys
        sys.path.insert(0, str(Path(__file__).parent / "atlas_agents_v16_7"))
        from atlas_agents.ops_coordinator import OpsCoordinator

        coord = OpsCoordinator(repo_root=Path(__file__).parent)
        result = coord.run_pipeline(
            projects=projects,
            mode=mode,
            initiated_by=initiated_by
        )

        return {
            "success": True,
            "run_id": result.get("run_id"),
            "final_verdict": result.get("final_verdict"),
            "projects": result.get("projects", {})
        }

    except Exception as e:
        logger.error(f"[V17] Governed pipeline failed: {e}")
        import traceback
        return {
            "success": False,
            "error": str(e),
            "traceback": traceback.format_exc()
        }


