@app.post("/api/v20/viewer-retention/{project}")
async def v20_viewer_retention(project: str, request: Dict = Body(default={})):
    """
    V20.2: Viewer Retention Analysis — Make AI video feel like real movies.
    Run AFTER V20.1 Story Intelligence. Analyzes 8 comfort dimensions:
      1. Character screen time fatigue (same face too long)
      2. Emotional rhythm (flatline + peak sustained without release)
      3. Shot size progression (jarring jumps without transition)
      4. Dialogue/reaction ratio (viewers need to see the listener)
      5. Cut density (genre-appropriate cuts per minute)
      6. Location staleness (same background too long)
      7. Visual monotony (same movement/lens repeated)
      8. Cross-scene fatigue (too many high-energy scenes in a row)
    Returns comfort_score (0-100) and actionable violations.
    """
    try:
        project_path = get_project_path(project)
        dry_run = request.get("dry_run", False)

        # Load story bible for genre
        sb_path = project_path / "story_bible.json"
        story_bible = {}
        genre = ""
        if sb_path.exists():
            with open(sb_path) as f:
                story_bible = json.load(f)
            genre = story_bible.get("genre", "")

        # Load cast map for ensemble check
        cm_path = project_path / "cast_map.json"
        cast_map = {}
        if cm_path.exists():
            with open(cm_path) as f:
                cast_map = json.load(f)

        from atlas_agents.viewer_retention_engine import analyze_viewer_retention
        result = analyze_viewer_retention(
            project_path,
            genre=genre,
            story_bible=story_bible,
            cast_map=cast_map,
            dry_run=dry_run
        )

        # Invalidate bundle cache if we applied fixes
        if not dry_run and result.get("fixes_applied", 0) > 0:
            dirty_path = project_path / "ui_cache" / ".dirty"
            dirty_path.parent.mkdir(parents=True, exist_ok=True)
            dirty_path.write_text("v20_viewer_retention")

        return {"success": True, "project": project, **result}
    except Exception as e:
        logger.error(f"[V20.2] Viewer Retention error: {e}")
        return {"success": False, "error": str(e)[:500]}


