def _get_pipeline_recommendation(compliance, retention, advance_status, has_script):
    """Generate ordered pipeline recommendation based on current state."""
    steps = []
    if has_script and advance_status == "not_run":
        steps.append({
            "step": 1, "action": "auto_advance",
            "label": "Auto-Advance Script",
            "description": "Parse imported script and fill character descriptions, beat actions, dialogue",
            "endpoint": "POST /api/v20/auto-advance/{project}",
            "priority": "critical"
        })
    if compliance.get("blocking_violations", 0) > 0:
        steps.append({
            "step": len(steps) + 1, "action": "fix_compliance",
            "label": "Fix Compliance Issues",
            "description": f"{compliance.get('blocking_violations', 0)} blocking issues need resolution",
            "priority": "critical"
        })
    comp_score = compliance.get("compliance_score", 0)
    ret_score = retention.get("comfort_score", 0)
    if comp_score < 80:
        steps.append({
            "step": len(steps) + 1, "action": "run_v20_pipeline",
            "label": "Run V20 Intelligence Pipeline",
            "description": "Apply shot types, story intelligence, and retention analysis",
            "endpoint": "POST /api/v20/shot-type-enricher/{project} → /api/v20/story-intelligence/{project} → /api/v20/viewer-retention/{project}",
            "priority": "recommended"
        })
    if ret_score < 50:
        steps.append({
            "step": len(steps) + 1, "action": "fix_retention",
            "label": "Apply Viewer Comfort Fixes",
            "description": f"Comfort score is {ret_score}/100 — apply camera movement, pacing, and rhythm fixes",
            "endpoint": "POST /api/v20/viewer-retention/{project}",
            "priority": "recommended"
        })
    if not steps:
        steps.append({
            "step": 1, "action": "ready",
            "label": "Ready for Render",
            "description": f"Compliance: {comp_score}/100, Comfort: {ret_score}/100 — proceed to generation",
            "priority": "info"
        })
    return steps


@app.get("/api/v20/creative-overview/{project}")
async def v20_creative_overview(project: str):
    """
    V20.3: Full Creative Process Overview — runs ALL V20 intelligence checks
    and returns a combined report for the UI pre-render dashboard.
    Runs: Script Compliance → V20.0 Types → V20.1 Intelligence → V20.2 Retention
    All in dry_run mode (analysis only, no changes).
    """
    try:
        project_path = get_project_path(project)

        sb_path = project_path / "story_bible.json"
        story_bible = {}
        if sb_path.exists():
            with open(sb_path) as f:
                story_bible = json.load(f)

        cm_path = project_path / "cast_map.json"
        cast_map = {}
        if cm_path.exists():
            with open(cm_path) as f:
                cast_map = json.load(f)

        genre = story_bible.get("genre", "")

        # 1. Script Compliance
        from atlas_agents.script_compliance_validator import validate_script_compliance, detect_content_type
        sp_path = project_path / "shot_plan.json"
        if sp_path.exists():
            with open(sp_path) as f:
                sp = json.load(f)
            content_type = detect_content_type(sp, story_bible)
        else:
            content_type = "episode"

        compliance = validate_script_compliance(
            project_path, content_type=content_type,
            story_bible=story_bible, cast_map=cast_map
        )

        # 2. Viewer Retention (dry run)
        from atlas_agents.viewer_retention_engine import analyze_viewer_retention
        retention = analyze_viewer_retention(
            project_path, genre=genre, story_bible=story_bible,
            cast_map=cast_map, dry_run=True
        )

        # 3. Project stats
        shots = sp.get("shots", sp) if isinstance(sp, dict) else sp if sp_path.exists() else []
        from collections import Counter
        type_dist = dict(Counter(s.get("shot_type", s.get("type", "medium")) for s in shots).most_common())
        total_dur = sum(s.get("duration", s.get("duration_seconds", 5)) for s in shots)
        has_dialogue = sum(1 for s in shots if (s.get("dialogue_text", "") or "").strip())
        has_frames = sum(1 for s in shots if s.get("first_frame_path") or s.get("first_frame_url"))
        has_videos = sum(1 for s in shots if s.get("video_path") or s.get("video_url"))

        # 4. Check if auto-advance has been run
        advance_status = "not_run"
        chars = story_bible.get("characters", [])
        if isinstance(chars, list):
            filled_chars = sum(1 for c in chars if isinstance(c, dict) and len(c.get("description", "") or "") > 10)
            total_chars = sum(1 for c in chars if isinstance(c, dict))
            if total_chars > 0 and filled_chars / total_chars > 0.5:
                advance_status = "complete"
            elif filled_chars > 0:
                advance_status = "partial"

        # 5. Script availability
        script_path = project_path / "imported_script.txt"
        has_script = script_path.exists()
        script_length = script_path.stat().st_size if has_script else 0

        return {
            "success": True,
            "project": project,
            "genre": genre,
            "content_type": content_type,
            "total_shots": len(shots),
            "total_scenes": len(set(s.get("scene_id", "?") for s in shots)),
            "total_runtime_minutes": round(total_dur / 60, 1),
            "shots_with_dialogue": has_dialogue,
            "shots_with_frames": has_frames,
            "shots_with_videos": has_videos,
            "type_distribution": type_dist,
            "compliance": compliance,
            "retention": retention,
            "overall_readiness": compliance.get("readiness", "UNKNOWN"),
            "overall_score": int((compliance.get("compliance_score", 0) + retention.get("comfort_score", 0)) / 2),
            "auto_advance_status": advance_status,
            "has_imported_script": has_script,
            "script_length_bytes": script_length,
            "pipeline_recommendation": _get_pipeline_recommendation(compliance, retention, advance_status, has_script),
        }
    except Exception as e:
        logger.error(f"[V20.3] Creative Overview error: {e}")
        return {"success": False, "error": str(e)[:500]}


