@app.post("/api/v17/agent-enforce/{project}")
async def manually_trigger_enforcement(project: str, request: Dict = Body(...)):
    """
    V17.2: Manually trigger enforcement agent on a project.
    Normally enforcement runs automatically before generation,
    but this endpoint allows manual triggering + validation.
    """
    try:
        project_path = get_project_path(project)
        shot_plan_path = project_path / "shot_plan.json"
        if not shot_plan_path.exists():
            return {"success": False, "error": "No shot_plan.json"}

        with open(shot_plan_path) as f:
            data = json.load(f)

        shots = data.get("shots", [])
        mode = request.get("mode", "enforce")  # "enforce" or "validate"

        sys.path.insert(0, str(Path(__file__).parent / "atlas_agents_v16_7"))
        from atlas_agents.agent_coordinator import AgentCoordinator
        coordinator = AgentCoordinator(project_path, story_bible=data.get("story_bible"))

        if mode == "validate":
            from atlas_agents.enforcement_agent import validate_project
            validation = validate_project(project_path, shots)
            return {"success": True, "mode": "validate", "validation": validation}
        else:
            gate_result = coordinator.pre_generation_gate(shots)
            return {
                "success": True,
                "mode": "enforce",
                "enforcement": gate_result["enforcement"]["stats"],
                "validation": gate_result.get("validation", {}),
                "cleared": gate_result.get("cleared", True),
            }
    except Exception as e:
        return {"success": False, "error": str(e)}


