@app.post("/api/v13/validate/story-bible")
async def validate_story_bible_v13(request: Dict = Body(...)):
    """Validate story_bible using V13 simulation gates."""
    try:
        from SIMULATION_GATES import SemanticGate, validate_simulation
        from SIMULATION_CONTEXT import SimulationContext

        story_bible = request.get("story_bible", {})
        target_runtime = request.get("target_runtime", 300)

        # Build simulation context
        ctx = SimulationContext()
        ctx.story_bible_simulation = {
            "canonical_characters": story_bible.get("characters", []),
            "scenes": story_bible.get("scenes", []),
            "locations": story_bible.get("locations", [])
        }
        ctx.metadata = {"target_runtime": target_runtime}

        # Run semantic gate
        gate = SemanticGate(ctx)
        issues = gate.run()

        critical = [i for i in issues if i.get("severity") == "critical"]
        warnings = [i for i in issues if i.get("severity") == "warning"]

        return {
            "status": "success",
            "valid": len(critical) == 0,
            "issues": issues,
            "summary": {
                "critical_count": len(critical),
                "warning_count": len(warnings),
                "total_issues": len(issues)
            },
            "auto_fixes_available": sum(1 for i in issues if i.get("auto_fix_available"))
        }
    except ImportError as e:
        return {"status": "error", "error": f"SIMULATION_GATES not available: {e}"}
    except Exception as e:
        return {"status": "error", "error": str(e)}


@app.post("/api/v13/validate/shot-plan")
async def validate_shot_plan_v13(request: Dict = Body(...)):
    """Validate shot_plan using V13 simulation gates."""
    try:
        from SIMULATION_GATES import TemporalGate, StyleGate, AssetGate
        from SIMULATION_CONTEXT import SimulationContext

        project = request.get("project", "")
        if not project:
            return {"status": "error", "error": "Project name required"}

        project_path = get_project_path(project)
        shot_plan_path = project_path / "shot_plan.json"
        story_bible_path = project_path / "story_bible.json"

        if not shot_plan_path.exists():
            return {"status": "error", "error": "No shot_plan.json found"}

        with open(shot_plan_path) as f:
            shot_plan = _sp_guard(json.load(f))

        story_bible = {}
        if story_bible_path.exists():
            with open(story_bible_path) as f:
                story_bible = json.load(f)

        # Build simulation context
        ctx = SimulationContext()
        ctx.shot_plan_simulation = {
            "shots": shot_plan.get("shots", []),
            "total_duration": sum(s.get("duration", 6) for s in shot_plan.get("shots", []))
        }
        ctx.story_bible_simulation = {
            "canonical_characters": story_bible.get("characters", []),
            "locations": story_bible.get("locations", [])
        }
        ctx.metadata = {"target_runtime": shot_plan.get("target_runtime", 300)}

        # Run gates
        all_issues = []
        for GateClass in [TemporalGate, StyleGate, AssetGate]:
            try:
                gate = GateClass(ctx)
                all_issues.extend(gate.run())
            except Exception as ge:
                all_issues.append({"gate": GateClass.__name__, "severity": "error", "message": str(ge)})

        critical = [i for i in all_issues if i.get("severity") == "critical"]

        return {
            "status": "success",
            "valid": len(critical) == 0,
            "issues": all_issues,
            "summary": {
                "critical_count": len(critical),
                "total_issues": len(all_issues)
            }
        }
    except ImportError as e:
        return {"status": "error", "error": f"SIMULATION_GATES not available: {e}"}
    except Exception as e:
        return {"status": "error", "error": str(e)}


@app.post("/api/v13/validate/full")
async def validate_full_project_v13(request: Dict = Body(...)):
    """Run full V13 validation on project (all gates)."""
    try:
        project = request.get("project", "")
        if not project:
            return {"status": "error", "error": "Project name required"}

        # Run both validations
        sb_result = await validate_story_bible_v13({"project": project})
        sp_result = await validate_shot_plan_v13({"project": project})

        all_issues = sb_result.get("issues", []) + sp_result.get("issues", [])
        critical = [i for i in all_issues if i.get("severity") == "critical"]

        return {
            "status": "success",
            "project": project,
            "valid": len(critical) == 0,
            "story_bible_validation": sb_result,
            "shot_plan_validation": sp_result,
            "combined_summary": {
                "critical_issues": len(critical),
                "total_issues": len(all_issues),
                "ready_for_render": len(critical) == 0
            }
        }
    except Exception as e:
        return {"status": "error", "error": str(e)}


