@app.post("/api/v13/smart-duration/calculate")
async def calculate_smart_duration(request: Dict = Body(...)):
    """Calculate smart duration for a shot based on dialogue/content."""
    try:
        from SMART_SHOT_DURATION import calculate_smart_duration as calc_duration

        result = calc_duration(
            shot_type=request.get("shot_type", "MS"),
            dialogue_text=request.get("dialogue_text", ""),
            action_text=request.get("action_text", ""),
            scene_description=request.get("scene_description", ""),
            is_first_in_scene=request.get("is_first_in_scene", False),
            director_pacing=request.get("director_pacing", "balanced")
        )
        return {"status": "success", **result}
    except ImportError:
        # Fallback calculation
        dialogue = request.get("dialogue_text", "")
        words = len(dialogue.split()) if dialogue else 0
        duration = max(6, min(20, 6 + (words // 5) * 2))
        return {
            "status": "success",
            "duration": duration,
            "extended": False,
            "category": "fallback",
            "reasoning": f"Fallback: {words} words"
        }
    except Exception as e:
        return {"status": "error", "error": str(e)}


# =============================================================================
# V17.2.6: PROMPT QUALITY VALIDATOR — Pre-generation contamination checks
# =============================================================================

REQUIRED_NEGATIVES = ["NO grid", "NO morphing"]
REQUIRED_NEGATIVES_FULL = "NO grid, NO collage, NO split screen, NO extra people, NO morphing faces, NO watermarks, NO text overlays"

def validate_prompt_quality(shots: list, story_bible: dict = None) -> dict:
    """
    V17.2.6: Validate and auto-fix prompt quality issues BEFORE generation.
    Catches contamination that degrades output quality.

    Checks:
    1. Ellipsis contamination (... in prompts)
    2. Location mismatch (prompt mentions wrong location)
    3. Missing negative prompts
    4. Framing/blocking_role mismatch
    5. Empty dialogue flow (dialogue_text exists but LTX has no context)
    6. Location-lock validation (auto-inject "at [LOCATION]" if missing)

    Returns a report dict with fixes applied and warnings.
    """
    report = {
        "checked": len(shots),
        "fixes_applied": 0,
        "warnings": [],
        "details": {
            "ellipsis_fixed": 0,
            "location_mismatch_warned": 0,
            "negatives_injected": 0,
            "framing_fixed": 0,
            "dialogue_flow_injected": 0,
            "location_lock_injected": 0,
        }
    }

    # Build location set from story bible for mismatch detection
    known_locations = set()
    if story_bible:
        for loc in story_bible.get("locations", []):
            loc_name = loc.get("name", "")
            if loc_name:
                known_locations.add(loc_name.upper().strip())
        for scene in story_bible.get("scenes", []):
            loc_name = scene.get("location", scene.get("setting", ""))
            if loc_name:
                known_locations.add(loc_name.upper().strip())

    # V21.8: AUTO-ENRICH STORY BIBLE BEATS — zero manual steps
    # When story bible exists but beats lack character_action fields,
    # auto-run enrichment inline. This replaces the manual enrich_story_bible_with_actions.py step.
    # ---------------------------------------------------------------
    if story_bible:
        _sb_scenes = story_bible.get("scenes", [])
        _needs_enrichment = False
        _total_beats_check = 0
        _missing_action_check = 0
        for _esc in _sb_scenes:
            for _eb in _esc.get("beats", _esc.get("story_beats", [])):
                _total_beats_check += 1
                if not _eb.get("character_action") or not _eb.get("action_verbs"):
                    _missing_action_check += 1
        if _total_beats_check > 0 and _missing_action_check > 0:
            _needs_enrichment = True
            logger.info(f"[FIX-V16] Story bible has {_missing_action_check}/{_total_beats_check} beats without character_action — auto-enriching")

        if _needs_enrichment:
            try:
                # Import enrichment functions from the standalone script
                import importlib.util as _ilu
                _enrich_path = Path(str(BASE_DIR)) / "enrich_story_bible_with_actions.py"
                if _enrich_path.exists():
                    _spec = _ilu.spec_from_file_location("enrich_sb", str(_enrich_path))
                    _enrich_mod = _ilu.module_from_spec(_spec)
                    _spec.loader.exec_module(_enrich_mod)
                    _extract_fn = _enrich_mod.extract_action_verbs
                    _infer_fn = _enrich_mod.infer_character_action

                    _enriched_count = 0
                    for _esc in _sb_scenes:
                        _esc_id = _esc.get("id", _esc.get("scene_id", ""))
                        _esc_title = _esc.get("title", "")
                        _esc_loc = _esc.get("location", "")
                        _esc_chars = _esc.get("characters", [])
                        for _eb in _esc.get("beats", _esc.get("story_beats", [])):
                            if _eb.get("character_action") and _eb.get("action_verbs"):
                                continue  # Already enriched
                            _desc = _eb.get("description", "")
                            _verbs = _extract_fn(_desc)
                            if _verbs:
                                _eb["character_action"] = _eb.get("character_action", _desc)
                                _eb["action_verbs"] = sorted(list(_verbs))
                            else:
                                _action_text, _inferred_verbs = _infer_fn(
                                    _eb, _esc_id, _esc_title, _esc_chars, _esc_loc
                                )
                                _eb["character_action"] = _action_text
                                _eb["action_verbs"] = sorted(list(_inferred_verbs))
                                _eb["_inferred"] = True
                            _enriched_count += 1

                    if _enriched_count > 0:
                        # Save enriched story bible atomically
                        _sb_path = project_path / "story_bible.json"
                        if _sb_path.exists():
                            import tempfile as _tf_sb
                            _sb_tmp = _tf_sb.NamedTemporaryFile(mode='w', dir=str(project_path),
                                                                  suffix='.json', delete=False)
                            json.dump(story_bible, _sb_tmp, indent=2)
                            _sb_tmp.close()
                            os.replace(_sb_tmp.name, str(_sb_path))
                        logger.info(f"[FIX-V16] Auto-enriched {_enriched_count} story bible beats with character_action + action_verbs")
                        report["details"]["story_bible_beats_auto_enriched"] = _enriched_count
                        report["fixes_applied"] += _enriched_count
                else:
                    # Fallback: inline enrichment using Creative Prompt Compiler
                    # V25.1: NEVER generates "experiences the moment" — uses emotion-driven physical map
                    logger.warning("[FIX-V16] enrich_story_bible_with_actions.py not found — using Creative Prompt Compiler fallback")
                    _enriched_count = 0
                    try:
                        from tools.creative_prompt_compiler import replace_story_bible_fallback, extract_physical_verbs
                    except ImportError:
                        replace_story_bible_fallback = None
                        extract_physical_verbs = None
                    for _esc in _sb_scenes:
                        _esc_chars = _esc.get("characters", [])
                        for _eb in _esc.get("beats", _esc.get("story_beats", [])):
                            if _eb.get("character_action") and _eb.get("action_verbs"):
                                continue
                            _desc = (_eb.get("description") or "").strip()
                            if not _desc:
                                continue
                            _char = _esc_chars[0] if _esc_chars else "Character"
                            _atmo = (_esc.get("atmosphere") or _eb.get("atmosphere") or "neutral").strip()
                            if replace_story_bible_fallback:
                                # V25.1: Creative Prompt Compiler — NEVER returns generic filler
                                _action, _verbs = replace_story_bible_fallback(_desc, _char, _esc_chars, _atmo)
                                _eb["character_action"] = _action
                                _eb["action_verbs"] = _verbs
                            else:
                                # Ultra-fallback if import fails — still better than "experiences"
                                _simple_verbs = []
                                for _sv in ["walks", "kneels", "sits", "stands", "enters", "reads",
                                            "speaks", "asks", "holds", "opens", "looks", "turns",
                                            "reaches", "finds", "discovers", "whispers", "runs",
                                            "watches", "listens", "places", "picks", "drops",
                                            "crosses", "approaches", "retreats", "grabs", "places",
                                            "touches", "lifts", "clutches", "catches", "pours",
                                            "stares", "frowns", "nods", "trembles", "gasps"]:
                                    if _sv in _desc.lower():
                                        _simple_verbs.append(_sv)
                                _eb["character_action"] = _desc if _simple_verbs else f"{_char} anchored in the space, body grounded"
                                _eb["action_verbs"] = _simple_verbs or ["anchored"]
                            if not _eb.get("action_verbs") or _eb["action_verbs"] == ["anchored"]:
                                _eb["_inferred"] = True
                            _enriched_count += 1
                    if _enriched_count > 0:
                        _sb_path = project_path / "story_bible.json"
                        if _sb_path.exists():
                            import tempfile as _tf_sb2
                            _sb_tmp2 = _tf_sb2.NamedTemporaryFile(mode='w', dir=str(project_path),
                                                                     suffix='.json', delete=False)
                            json.dump(story_bible, _sb_tmp2, indent=2)
                            _sb_tmp2.close()
                            os.replace(_sb_tmp2.name, str(_sb_path))
                        logger.info(f"[FIX-V16] Inline fallback enriched {_enriched_count} beats")
                        report["details"]["story_bible_beats_inline_enriched"] = _enriched_count
            except Exception as _enrich_err:
                logger.warning(f"[FIX-V16] Story bible auto-enrichment failed (non-blocking): {_enrich_err}")
                # Non-blocking — pipeline continues even if enrichment fails

    # V17.7.5: Build proportional beat map for CHECK 5B (scene_id → shot_index → beat)
    _scene_beats_map = {}
    if story_bible:
        for _sc in story_bible.get("scenes", []):
            _sc_id = str(_sc.get("scene_id", _sc.get("scene_number", "")))
            if _sc_id and len(_sc_id) < 3:
                _sc_id = _sc_id.zfill(3)
            _beats = _sc.get("beats", _sc.get("story_beats", []))
            if _sc_id and _beats:
                _scene_beats_map[_sc_id] = _beats

    _scene_shot_indices = {}  # shot_id → (scene_id, index_in_scene)
    _scene_shot_counts = {}
    for _s in shots:
        _s_id = _s.get("shot_id", "")
        _s_scene = _s_id.split("_")[0] if "_" in _s_id else ""
        if _s_scene:
            if _s_scene not in _scene_shot_counts:
                _scene_shot_counts[_s_scene] = 0
            _scene_shot_indices[_s_id] = (_s_scene, _scene_shot_counts[_s_scene])
            _scene_shot_counts[_s_scene] += 1

    # V21.7: Track which dialogue has been assigned to prevent duplicates
    _scene_dialogue_assigned = {}  # scene_id → set of dialogue strings already assigned

    def _get_proportional_beat(shot_id):
        """Map shot to beat via proportional distribution within scene."""
        info = _scene_shot_indices.get(shot_id)
        if not info:
            return None
        scene_id, idx = info
        beats = _scene_beats_map.get(scene_id, [])
        if not beats:
            return None
        n_shots = _scene_shot_counts.get(scene_id, 1)
        n_beats = len(beats)
        beat_idx = min(int(idx * n_beats / n_shots), n_beats - 1)
        return beats[beat_idx]

    def _is_dialogue_already_assigned(scene_id, dialogue_text):
        """V21.7: Check if this exact dialogue was already assigned to another shot in this scene."""
        if not dialogue_text or not scene_id:
            return False
        assigned = _scene_dialogue_assigned.get(scene_id, set())
        # Normalize for comparison (strip, lowercase, first 80 chars)
        norm = dialogue_text.strip().lower()[:80]
        return norm in assigned

    def _mark_dialogue_assigned(scene_id, dialogue_text):
        """V21.7: Record that this dialogue was assigned to a shot."""
        if not dialogue_text or not scene_id:
            return
        if scene_id not in _scene_dialogue_assigned:
            _scene_dialogue_assigned[scene_id] = set()
        norm = dialogue_text.strip().lower()[:80]
        _scene_dialogue_assigned[scene_id].add(norm)

    # V21.7: Pre-populate dialogue assignment tracker with existing dialogue
    # This prevents beat recovery from re-assigning dialogue that was already set by shot expansion
    for _pre_shot in shots:
        _pre_dlg = (_pre_shot.get("dialogue_text") or _pre_shot.get("dialogue") or "").strip()
        if _pre_dlg:
            _pre_scene = _pre_shot.get("scene_id", "")
            if not _pre_scene and "_" in _pre_shot.get("shot_id", ""):
                _pre_scene = _pre_shot["shot_id"].split("_")[0]
            _mark_dialogue_assigned(_pre_scene, _pre_dlg)

    for shot in shots:
        sid = shot.get("shot_id", "?")
        nano = shot.get("nano_prompt", "")
        ltx = shot.get("ltx_motion_prompt", "")
        shot_location = (shot.get("location") or "").strip().upper()
        blocking_role = (shot.get("blocking_role") or "").strip()
        dialogue_text = (shot.get("dialogue_text") or shot.get("dialogue") or "").strip()

        # ---------------------------------------------------------------
        # CHECK 0 V21.9: ESTABLISHING SHOT DIALOGUE GUARD
        # Establishing shots (first shot in a scene) should NOT have dialogue
        # — they set the environment. Dialogue belongs on character close-ups.
        # ---------------------------------------------------------------
        _c0_type = (shot.get("shot_type") or "").lower()
        _c0_is_establishing = _c0_type in ("establishing", "detail")
        _c0_is_scene_opener = sid.endswith("_000A") or sid.endswith("_001A")
        if _c0_is_establishing and _c0_is_scene_opener and dialogue_text:
            # Don't delete — demote to beat description instead
            if not shot.get("_original_dialogue_demoted"):
                shot["_original_dialogue_demoted"] = dialogue_text
                shot["dialogue_text"] = ""
                shot["dialogue"] = ""
                dialogue_text = ""
                report["details"].setdefault("establishing_dialogue_stripped", 0)
                report["details"]["establishing_dialogue_stripped"] = report["details"].get("establishing_dialogue_stripped", 0) + 1
                report["fixes_applied"] += 1

        # ---------------------------------------------------------------
        # CHECK 1: Ellipsis contamination — "..." degrades model output
        # ---------------------------------------------------------------
        if "..." in nano:
            shot["nano_prompt"] = nano.replace("...", ", brief pause, ")
            report["details"]["ellipsis_fixed"] += 1
            report["fixes_applied"] += 1
            nano = shot["nano_prompt"]  # Update local ref

        if "..." in ltx:
            shot["ltx_motion_prompt"] = ltx.replace("...", ", brief pause, ")
            report["details"]["ellipsis_fixed"] += 1
            report["fixes_applied"] += 1
            ltx = shot["ltx_motion_prompt"]

        # ---------------------------------------------------------------
        # CHECK 2: Location mismatch — prompt mentions a different known location
        # ---------------------------------------------------------------
        if shot_location and known_locations and len(known_locations) > 1:
            nano_upper = nano.upper()
            for loc in known_locations:
                # Skip if it's the correct location or a very short name (< 4 chars)
                if loc == shot_location or len(loc) < 4:
                    continue
                if loc in nano_upper and shot_location not in nano_upper:
                    report["warnings"].append(
                        f"{sid}: nano_prompt mentions '{loc}' but shot location is '{shot_location}'"
                    )
                    report["details"]["location_mismatch_warned"] += 1
                    break  # One warning per shot

        # ---------------------------------------------------------------
        # CHECK 3: Missing negative prompts — required negatives must be present
        # ---------------------------------------------------------------
        if nano:
            nano_lower = nano.lower()
            has_no_grid = "no grid" in nano_lower
            has_no_morphing = "no morphing" in nano_lower
            if not has_no_grid or not has_no_morphing:
                # Append required negatives at end
                if not nano.rstrip().endswith(","):
                    shot["nano_prompt"] = nano.rstrip() + ", " + REQUIRED_NEGATIVES_FULL
                else:
                    shot["nano_prompt"] = nano.rstrip() + " " + REQUIRED_NEGATIVES_FULL
                report["details"]["negatives_injected"] += 1
                report["fixes_applied"] += 1
                nano = shot["nano_prompt"]

        # ---------------------------------------------------------------
        # CHECK 4: Framing/blocking_role mismatch
        # If nano_prompt says "over shoulder" but blocking_role is not OTS-A/OTS-B,
        # auto-fix by updating blocking_role to match the prompt intent
        # ---------------------------------------------------------------
        if nano:
            nano_lower = nano.lower()
            mentions_ots = "over shoulder" in nano_lower or "over-the-shoulder" in nano_lower or "over the shoulder" in nano_lower
            is_ots_role = blocking_role.upper().startswith("OTS") if blocking_role else False
            if mentions_ots and not is_ots_role:
                shot["blocking_role"] = "OTS-A"
                report["details"]["framing_fixed"] += 1
                report["fixes_applied"] += 1
            elif is_ots_role and not mentions_ots:
                # Blocking role says OTS but prompt doesn't mention it — flag as warning
                report["warnings"].append(
                    f"{sid}: blocking_role is '{blocking_role}' but nano_prompt has no over-shoulder framing language"
                )

        # ---------------------------------------------------------------
        # CHECK 5: Empty dialogue flow — dialogue_text exists but LTX has no context
        # ---------------------------------------------------------------
        if dialogue_text and ltx:
            # Check if LTX motion prompt has any dialogue context
            ltx_lower = ltx.lower()
            has_dialogue_context = (
                "speak" in ltx_lower or
                "say" in ltx_lower or
                "dialog" in ltx_lower or
                "mouth" in ltx_lower or
                "lips" in ltx_lower or
                "talk" in ltx_lower or
                "voice" in ltx_lower or
                "deliver" in ltx_lower or
                dialogue_text[:30].lower() in ltx_lower  # First 30 chars of dialogue
            )
            if not has_dialogue_context:
                # Inject dialogue context into LTX prompt
                dialogue_snippet = dialogue_text[:250]  # V17.2.4: 250 char limit for LTX
                dialogue_inject = f', character speaks: "{dialogue_snippet}", lips moving naturally, subtle facial expression shifts'
                shot["ltx_motion_prompt"] = ltx.rstrip() + dialogue_inject
                report["details"]["dialogue_flow_injected"] += 1
                report["fixes_applied"] += 1

        # ---------------------------------------------------------------
        # CHECK 5B: V17.7.5 SCRIPT BEAT FIDELITY — inject beat actions into prompts
        # Uses PROPORTIONAL beat distribution (not beat_id matching which fails
        # because story bible beat_numbers don't match shot beat_ids).
        # Detection uses "character performs:" / "Character action:" markers.
        # ---------------------------------------------------------------
        if story_bible and sid:
            _beat_match = _get_proportional_beat(sid)

            if _beat_match:
                # V21.8: Prefer enriched character_action over raw description
                # character_action is production-ready (explicit actions like "Lady Margaret kneels at altar")
                # description may be setting-only ("Candles burn low in ritual room")
                _beat_desc = (_beat_match.get("character_action") or _beat_match.get("description") or "").strip()
                _beat_action_verbs = _beat_match.get("action_verbs", [])
                _beat_dlg = (_beat_match.get("dialogue") or "").strip()

                nano_lower = (shot.get("nano_prompt", "") or "").lower()
                ltx_lower = (shot.get("ltx_motion_prompt", "") or "").lower()

                # Use marker-based detection: skip if already enriched
                _has_nano_marker = "character action:" in nano_lower
                _has_ltx_marker = "character performs:" in ltx_lower

                # V18.4 ACTION-FIRST: Inject beat action AFTER first sentence
                # (lens/composition) so nano sees it in top ~120 tokens.
                # Previous: inserted before "NO grid" negatives (buried at end).
                # V22.5 FIX: Only inject character actions when shot HAS characters
                # Root cause of 82-shot contamination: B-roll/landscape shots got
                # "Character action: Evelyn experiences..." injected, causing FAL
                # to generate people in no-character shots.
                _5b_has_chars_nano = bool(shot.get("characters"))
                if _beat_desc and not _has_nano_marker and _5b_has_chars_nano:
                    _current_nano = shot.get("nano_prompt", "") or ""
                    _inject_text = f"Character action: {_beat_desc[:150]}."
                    # Find end of first sentence (lens/composition line)
                    _first_period = _current_nano.find(". ")
                    if _first_period > 10 and _first_period < 200:
                        # Insert right after first sentence
                        shot["nano_prompt"] = _current_nano[:_first_period + 2] + _inject_text + " " + _current_nano[_first_period + 2:]
                    else:
                        # Fallback: prepend after any leading lens spec
                        import re as _re_5b
                        _lens_match = _re_5b.match(r"^(\d+mm\s+\w+(?:,\s*composition:[^,]+)?)", _current_nano)
                        if _lens_match:
                            _after = _lens_match.end()
                            shot["nano_prompt"] = _current_nano[:_after] + ". " + _inject_text + " " + _current_nano[_after:].lstrip(", ")
                        else:
                            shot["nano_prompt"] = _inject_text + " " + _current_nano
                    report["details"].setdefault("beat_action_injected_nano", 0)
                    report["details"]["beat_action_injected_nano"] += 1
                    report["fixes_applied"] += 1

                # Inject beat action into ltx_motion_prompt if missing marker
                # V21.9: Only inject "character performs:" when shot HAS characters
                # Characterless shots (B-roll, establishing, detail) get environmental motion instead
                _5b_has_chars = bool(shot.get("characters"))
                if _beat_desc and not _has_ltx_marker and _5b_has_chars:
                    _current_ltx = shot.get("ltx_motion_prompt", "") or ""
                    # V21.8: Use enriched action_verbs from story bible when available
                    # Falls back to inline extraction only if enrichment wasn't applied
                    _action_verbs = list(_beat_action_verbs) if _beat_action_verbs else []
                    if not _action_verbs:
                        # V25.1: Use CPC's comprehensive extraction (~120 verbs) instead of legacy 34-verb list
                        try:
                            from tools.creative_prompt_compiler import extract_physical_verbs
                            _action_verbs = extract_physical_verbs(_beat_desc or "")
                        except ImportError:
                            # Ultra-fallback: expanded inline verb list
                            for _av in ["kneels", "kneel", "picks up", "opens", "reads", "holds",
                                        "dials", "answers", "walks", "enters", "sits", "stands",
                                        "reaches", "grabs", "places", "speaks", "trembles",
                                        "gasps", "freezes", "cries", "pours", "drinks", "runs",
                                        "blows", "blow", "whispers", "screams", "stares", "turns",
                                        "approaches", "retreats", "climbs", "falls", "drops",
                                        "rolls", "roll", "completes", "continues", "collapses",
                                        "placing", "speaking", "rolling", "completing",
                                        "touches", "lifts", "clutches", "crosses", "watches",
                                        "nods", "shakes", "points", "pushes", "pulls", "grips",
                                        "cradles", "presses", "leans", "bows", "kneeling"]:
                                if _av in (_beat_desc or "").lower():
                                    _action_verbs.append(_av)
                    # V25.1: Build action injection — if no verbs found, use CPC physical direction
                    _action_inject = f", character performs: {_beat_desc[:150]}"
                    if _action_verbs:
                        _key_actions = ", ".join(list(dict.fromkeys(_action_verbs))[:4])
                        _action_inject += f", key motion: {_key_actions}"
                    else:
                        # V25.1: NEVER leave key motion empty — use emotion-driven physical direction
                        try:
                            from tools.creative_prompt_compiler import get_physical_direction
                            _shot_chars = shot.get("characters", [])
                            _shot_char = _shot_chars[0] if _shot_chars else "Character"
                            _shot_emotion = "neutral"
                            _state_in = shot.get("state_in", {})
                            if isinstance(_state_in, dict):
                                for _cs in _state_in.values():
                                    if isinstance(_cs, dict):
                                        _shot_emotion = _cs.get("emotion", "neutral") or "neutral"
                                        break
                            _phys_dir = get_physical_direction(_shot_emotion, "default", _shot_char, _beat_desc)
                            _action_inject += f", key motion: {_phys_dir}"
                        except ImportError:
                            _action_inject += ", key motion: body grounded, weight shifts with intention"
                    shot["ltx_motion_prompt"] = _current_ltx.rstrip(". ,") + _action_inject
                    report["details"].setdefault("beat_action_injected_ltx", 0)
                    report["details"]["beat_action_injected_ltx"] += 1
                    report["fixes_applied"] += 1

                # Recover dialogue from beat if shot doesn't have it
                # V21.7: DEDUP GUARD — only assign dialogue if not already used by another shot
                # V21.9: SKIP if CHECK 0 already demoted dialogue (establishing shot guard)
                _shot_scene = shot.get("scene_id", sid.split("_")[0] if "_" in sid else "")
                _was_demoted = bool(shot.get("_original_dialogue_demoted"))
                if _beat_dlg and not dialogue_text and not _was_demoted:
                    if not _is_dialogue_already_assigned(_shot_scene, _beat_dlg):
                        shot["dialogue_text"] = _beat_dlg[:250]
                        shot["dialogue"] = _beat_dlg[:250]
                        dialogue_text = _beat_dlg[:250]
                        _mark_dialogue_assigned(_shot_scene, _beat_dlg)
                        report["details"].setdefault("beat_dialogue_recovered", 0)
                        report["details"]["beat_dialogue_recovered"] += 1
                        report["fixes_applied"] += 1
                    else:
                        # V21.7/V26.1: This dialogue was already assigned — make this a REACTION shot
                        # V26.1: Include WHAT they're reacting to so LTX generates appropriate expression
                        _react_chars = shot.get("characters", [])
                        if _react_chars:
                            _reactor = _react_chars[0] if isinstance(_react_chars[0], str) else str(_react_chars[0])
                            # V26.1: Inject first 60 chars of original dialogue as reaction context
                            _react_context = (_beat_dlg or "")[:60].strip()
                            if _react_context:
                                _react_emotion = shot.get("emotion", "tension")
                                shot["dialogue_text"] = f"{_reactor} reacts with {_react_emotion} to hearing: '{_react_context}'"
                            else:
                                shot["dialogue_text"] = f"{_reactor} listens and reacts to what was just said"
                            shot["dialogue"] = shot["dialogue_text"]
                            dialogue_text = shot["dialogue_text"]
                        report["details"].setdefault("duplicate_dialogue_prevented", 0)
                        report["details"]["duplicate_dialogue_prevented"] += 1

                # V17.7.5: ALWAYS inject dialogue into LTX if dialogue exists (from ANY source)
                # but LTX doesn't have "character speaks:" marker yet.
                # This is SEPARATE from recovery — shots from shot expansion already have
                # dialogue_text but need it in LTX so LTX-2 generates lip movement.
                _all_dlg = (shot.get("dialogue_text") or shot.get("dialogue") or _beat_dlg or "").strip()
                _ltx_now = (shot.get("ltx_motion_prompt") or "").lower()
                # V18.4: Only inject dialogue markers if shot HAS characters
                # Character-less shots (INSERT, B-ROLL, ESTABLISHING) should NOT get lip-sync markers
                _shot_chars = shot.get("characters", [])
                _has_characters = bool(_shot_chars and len(_shot_chars) > 0)
                _shot_type_lower = (shot.get("shot_type") or shot.get("type") or "").lower()
                _is_object_shot = _shot_type_lower in ("insert", "b-roll", "establishing", "detail", "cutaway")
                if _all_dlg and "character speaks:" not in _ltx_now and _has_characters and not _is_object_shot:
                    _dlg_snip = _all_dlg[:250]
                    shot["ltx_motion_prompt"] = (shot.get("ltx_motion_prompt") or "").rstrip() + f', character speaks: "{_dlg_snip}", lips moving naturally, subtle expression shifts'
                    report["details"].setdefault("dialogue_flow_injected", 0)
                    report["details"]["dialogue_flow_injected"] = report["details"].get("dialogue_flow_injected", 0) + 1
                    report["fixes_applied"] += 1

        # ---------------------------------------------------------------
        # CHECK 5C V21.9: LANDSCAPE LTX ENRICHMENT — no-character shots need environmental motion
        # Without this, landscape/B-roll LTX prompts are just timing (47 chars)
        # ---------------------------------------------------------------
        _5c_chars = shot.get("characters", [])
        _5c_ltx = (shot.get("ltx_motion_prompt") or "").strip()
        if not _5c_chars and len(_5c_ltx) < 100:
            # Extract environmental description from nano_prompt or beat
            _5c_nano = (shot.get("nano_prompt") or "")
            _5c_beat = (_beat_desc or "").strip()
            _5c_env_desc = ""
            # Try to extract environment keywords from nano
            _env_keywords = []
            for _ek in ["waves", "ocean", "cliff", "fog", "rain", "wind", "clouds", "moon", "sun",
                        "fire", "candle", "smoke", "dust", "snow", "storm", "lightning", "water",
                        "trees", "forest", "city", "street", "building", "door", "window", "light"]:
                if _ek in _5c_nano.lower():
                    _env_keywords.append(_ek)
            if _env_keywords:
                _5c_env_desc = f"Environmental motion: {', '.join(_env_keywords[:6])} in motion, atmospheric movement, natural environmental dynamics"
            elif _5c_beat:
                _5c_env_desc = f"Environmental motion: {_5c_beat[:120]}, atmospheric movement"
            if _5c_env_desc:
                shot["ltx_motion_prompt"] = _5c_ltx + ". " + _5c_env_desc + ". NO grid NO split screen"
                report["details"].setdefault("landscape_ltx_enriched", 0)
                report["details"]["landscape_ltx_enriched"] = report["details"].get("landscape_ltx_enriched", 0) + 1
                report["fixes_applied"] += 1

        # ---------------------------------------------------------------
        # CHECK 6: Location-lock validation — ensure nano_prompt mentions assigned location
        # If shot has a location but nano_prompt doesn't reference it, auto-inject "at [LOCATION]"
        # ---------------------------------------------------------------
        if shot_location and nano:
            nano_upper = nano.upper()
            # Extract significant words from location name (4+ chars)
            location_words = [w for w in shot_location.split() if len(w) >= 4]
            location_mentioned = False
            if location_words:
                for word in location_words:
                    if word in nano_upper:
                        location_mentioned = True
                        break
            else:
                # Location name has no words >= 4 chars, check full name
                if shot_location in nano_upper:
                    location_mentioned = True

            if not location_mentioned:
                # Auto-inject location context at the beginning of nano_prompt
                location_display = shot.get("location", "").strip()
                if location_display:
                    inject_text = f"at {location_display}, "
                    shot["nano_prompt"] = inject_text + nano
                    report["details"]["location_lock_injected"] += 1
                    report["fixes_applied"] += 1
                    nano = shot["nano_prompt"]  # Update local ref

    # Summary
    report["summary"] = (
        f"Checked {report['checked']} shots: "
        f"{report['fixes_applied']} auto-fixes applied, "
        f"{len(report['warnings'])} warnings"
    )
    # Truncate warnings for response size
    if len(report["warnings"]) > 20:
        report["warnings"] = report["warnings"][:20] + [f"... and {len(report['warnings']) - 20} more"]

    return report


# V16.5 AUTO-FIX ENDPOINT - DIRECTOR-INTELLIGENT DURATION & LTX SYSTEM
# =============================================================================

@app.post("/api/shot-plan/fix-v16")
@app.post("/api/shot-plan/fix-v13")  # Backward compatibility alias
async def fix_v16_issues(request: Dict = Body(...)):
    """
    V16.5 DIRECTOR-INTELLIGENT Auto-Fix: Wires together all self-healing systems.

    Architecture: Smart Suggestions → Deterministic Enforcement → Critics

    Phase 1 (Advisory): Read story bible, run intelligent analysis
    Phase 2 (Enforcement): Apply deterministic fixes informed by advisory
    Phase 3 (Validation): Run critics to verify

    Fixes:
    1. Duration (INTELLIGENT_PROMPT_ENHANCER + 21-point beats)
    2. Prompt enhancement (emotional→visual translation)
    3. LTX motion (beat-aware movement + micro-humanism)
    4. Extended shot segmentation
    5. Face stability + negative prompts
    6. Critics validation
    """
    project = request.get("project")

    if not project:
        return {"status": "error", "error": "Project name required"}

    # V17.3: Temporal workflow tracking for Fix-V16 pipeline
    _wf_id = None
    try:
        _wf_id = temporal_start_workflow(project, "fix_v16_setup")
        temporal_run_activity(_wf_id, "fix_v16_setup")
    except Exception:
        pass

    project_path = get_project_path(project)
    shot_plan_path = project_path / "shot_plan.json"
    story_bible_path = project_path / "story_bible.json"

    if not shot_plan_path.exists():
        try:
            temporal_fail_activity(_wf_id, "fix_v16_setup", "Project not found")
        except Exception:
            pass
        return {"status": "error", "error": f"Project '{project}' not found"}

    # =========================================================================
    # V20.4: AUTO-ADVANCE FIRST — Parse imported script and fill pipeline gaps
    # Runs BEFORE duration/camera fixes so those operate on enriched data.
    # Non-blocking: if auto-advance fails, fix-v16 still completes.
    # =========================================================================
    _advance_report = {}
    try:
        _script_path = project_path / "imported_script.txt"
        if _script_path.exists():
            _sb_check_path = project_path / "story_bible.json"
            _needs_advance = False
            if _sb_check_path.exists():
                with open(_sb_check_path) as _f:
                    _sb_check = json.load(_f)
                _chars = _sb_check.get("characters", [])
                if isinstance(_chars, list):
                    _empty = sum(1 for c in _chars
                                 if isinstance(c, dict) and len(c.get("description", "") or "") < 10)
                    if _empty > 3:
                        _needs_advance = True
            if _needs_advance:
                from atlas_agents.script_auto_advancer import auto_advance_script
                _adv_result = auto_advance_script(project_path, dry_run=False)
                _advance_report = _adv_result.get("report", {})
                _adv_changes = _advance_report.get("total_changes", 0)
                if _adv_changes > 0:
                    logger.info(f"[V20.4] Auto-advanced {project} before fix-v16: {_adv_changes} changes")
    except Exception as _adv_err:
        logger.warning(f"[V20.4] Auto-advance non-blocking error: {_adv_err}")

    # Load shot plan (AFTER auto-advance so we get enriched data)
    with open(shot_plan_path) as f:
        data = json.load(f)

    issues_fixed = []
    advisory_notes = []

    # V26.1 FIX: Ensure 're' is locally bound early — bare 'import re' later in this
    # function (lines ~27317, ~27814) makes Python treat 're' as local throughout,
    # causing UnboundLocalError at line 26105 if we don't import it here first.
    import re

    # =========================================================================
    # V26.1: DIALOGUE MARKER RESET — strip ALL existing "character speaks:" markers
    # before re-enrichment. This prevents stacking across multiple fix-v16 runs.
    # Each run will inject exactly 1 marker per dialogue shot.
    # =========================================================================
    _dedup_reset_count = 0
    shots = data.get("shots", [])
    for _shot in shots:
        # Check ltx_motion_prompt
        _ltx_field = (_shot.get("ltx_motion_prompt") or "")
        _speaks_count = _ltx_field.lower().count("character speaks:")
        if _speaks_count > 1:
            # Strip ALL "character speaks:..." clauses, keep the rest
            _cleaned = re.sub(r'character speaks:[^.]*\.?\s*', '', _ltx_field, flags=re.IGNORECASE)
            _cleaned = re.sub(r',\s*,', ',', _cleaned)  # clean up double commas
            _cleaned = re.sub(r'\s{2,}', ' ', _cleaned).strip().strip(',').strip()
            _shot["ltx_motion_prompt"] = _cleaned
            _dedup_reset_count += 1

        # Also clean ltx_motion_prompt_final if it exists
        _ltx_final = (_shot.get("ltx_motion_prompt_final") or "")
        _final_count = _ltx_final.lower().count("character speaks:")
        if _final_count > 1:
            _cleaned_f = re.sub(r'character speaks:[^.]*\.?\s*', '', _ltx_final, flags=re.IGNORECASE)
            _cleaned_f = re.sub(r',\s*,', ',', _cleaned_f)
            _cleaned_f = re.sub(r'\s{2,}', ' ', _cleaned_f).strip().strip(',').strip()
            _shot["ltx_motion_prompt_final"] = _cleaned_f

    if _dedup_reset_count > 0:
        logger.info(f"[FIX-V16 V26.1] DIALOGUE MARKER RESET: {_dedup_reset_count} shots had stacked markers — cleaned before re-enrichment")
        issues_fixed.append(f"DIALOGUE_MARKER_RESET: {_dedup_reset_count} shots cleaned of stacked 'character speaks:' markers")

    # Always rebuild shots[] from the authoritative scene blueprint if available
    rehydrated, rehydrated_count = _rehydrate_shots_from_scene_manifest(data)
    if rehydrated:
        issues_fixed.append(f"SCENE_REHYDRATE: rebuilt {rehydrated_count} shots from scene_manifest")

    # =========================================================================
    # V16.5 RUNTIME MATH CRITIC - Auto-expand if shots can't hit target
    # =========================================================================
    target_runtime = data.get("metadata", {}).get("target_runtime_seconds", 0)
    if not target_runtime:
        # Try story bible
        sb_path = project_path / "story_bible.json"
        if sb_path.exists():
            with open(sb_path) as f:
                sb = json.load(f)
                target_runtime = sb.get("runtime_target_seconds", 2700)  # V17 FIX: default 45min (was 5min)

    # V17 FIX (Bug2): Runtime unit detection — prevent 45 minutes from being treated as 45 seconds
    # If target_runtime <= 120, it was likely passed in minutes instead of seconds
    if target_runtime > 0 and target_runtime <= 120:
        logger.warning(f"[V17 FIX] target_runtime={target_runtime} looks like MINUTES not seconds — converting to {target_runtime * 60}s")
        target_runtime = target_runtime * 60
        # Also fix the stored value so downstream code doesn't repeat the mistake
        if "metadata" not in data:
            data["metadata"] = {}
        data["metadata"]["target_runtime_seconds"] = target_runtime
        data["metadata"]["target_runtime_minutes"] = target_runtime / 60
        issues_fixed.append(f"RUNTIME_UNIT_FIX: Corrected {target_runtime // 60}min target from seconds to minutes")

    # =========================================================================
    # V16.6 RUNTIME MATH CRITIC - NO ABC TRIPLING
    # =========================================================================
    # REMOVED: ABC expansion (creating B/C variants per shot)
    # NEW: Runtime critic reports shortfall, tiering extends existing shots
    # ABC alternation is handled per-scene by ABCAlternationCritic, not here

    MAX_LTX_DURATION = 60
    theoretical_max = len(shots) * MAX_LTX_DURATION
    current_total = sum(s.get("duration", 20) for s in shots)

    if target_runtime > 0:
        if theoretical_max < target_runtime * 0.95:
            # Even at max durations, can't hit target - need more scenes
            shortfall = target_runtime - theoretical_max
            shortfall_mins = shortfall / 60
            shots_needed = int(target_runtime / 45)  # 45s is balanced avg
            advisory_notes.append(f"⚠️ RUNTIME MATH CRITIC: {len(shots)} shots × {MAX_LTX_DURATION}s max = {theoretical_max}s")
            advisory_notes.append(f"   → Target {target_runtime}s ({target_runtime/60:.1f} min) IMPOSSIBLE with current shots")
            advisory_notes.append(f"   → Need ~{shots_needed} shots minimum. Add {shots_needed - len(shots)} more scenes.")
            issues_fixed.append(f"RUNTIME_MATH_CRITIC: Flagged - need {shots_needed - len(shots)} more shots for {target_runtime/60:.1f} min target")
        elif current_total < target_runtime * 0.8:
            # Can hit target but need significant extension
            advisory_notes.append(f"ℹ️ RUNTIME MATH: {current_total}s current, {target_runtime}s target")
            advisory_notes.append(f"   → Tiering will extend shots to hit target")

    # =========================================================================
    # V17 DURATION CRITIC - AUTO-FIX when variance > 10%
    # =========================================================================
    if target_runtime > 0:
        variance_pct = abs(current_total - target_runtime) / target_runtime * 100
        if variance_pct > 10:
            advisory_notes.append(f"⚠️ DURATION VARIANCE: {variance_pct:.1f}% (>{10}% threshold)")
            advisory_notes.append(f"   → Running DURATION_REBALANCER to fix...")
            try:
                import subprocess
                result = subprocess.run(
                    [sys.executable, str(BASE_DIR / "DURATION_REBALANCER.py"), project, "--target", str(target_runtime), "--apply"],
                    capture_output=True, text=True, timeout=60
                )
                if result.returncode == 0:
                    # Reload the shot plan after rebalancing
                    with open(shot_plan_path) as f:
                        data = json.load(f)
                    shots = data.get("shots", [])
                    new_total = sum(s.get("duration", 20) for s in shots)
                    issues_fixed.append(f"DURATION_REBALANCER: {current_total}s → {new_total}s (target: {target_runtime}s)")
                    advisory_notes.append(f"   ✅ Rebalanced: {current_total//60}m → {new_total//60}m")
                    current_total = new_total  # Update for downstream logic

                    # V17: Run Narrative Runtime Governor after mechanical rebalance
                    advisory_notes.append(f"   → Running NARRATIVE_RUNTIME_GOVERNOR...")
                    try:
                        narrative_result = subprocess.run(
                            [sys.executable, str(BASE_DIR / "tools" / "narrative_runtime_governor.py"), project, "--apply"],
                            capture_output=True, text=True, timeout=60
                        )
                        if narrative_result.returncode == 0:
                            # Reload again
                            with open(shot_plan_path) as f:
                                data = json.load(f)
                            shots = data.get("shots", [])
                            narrative_total = sum(s.get("duration", 20) for s in shots)
                            protected = sum(1 for s in shots if s.get("_narrative", {}).get("protected"))
                            issues_fixed.append(f"NARRATIVE_GOVERNOR: {protected} shots protected, {narrative_total}s final")
                            advisory_notes.append(f"   ✅ Narrative intelligence applied: {protected} shots protected")
                            current_total = narrative_total
                        else:
                            advisory_notes.append(f"   ⚠️ Narrative governor: {narrative_result.stderr[:80] if narrative_result.stderr else 'no output'}")
                    except Exception as e:
                        advisory_notes.append(f"   ⚠️ Narrative governor skipped: {str(e)[:50]}")
                else:
                    advisory_notes.append(f"   ❌ Rebalancer failed: {result.stderr[:100]}")
            except Exception as e:
                advisory_notes.append(f"   ❌ Rebalancer error: {str(e)[:100]}")

    # =========================================================================
    # PHASE 1: INTELLIGENT ADVISORY PASS (Read-Only Analysis)
    # =========================================================================

    # Load story bible for context
    story_bible = {}
    if story_bible_path.exists():
        with open(story_bible_path) as f:
            story_bible = json.load(f)
        advisory_notes.append(f"Story bible loaded: {story_bible.get('title', project)}")

    # V15.5: Load cast_map for character reference attachment
    cast_map = {}
    cast_map_path = project_path / "cast_map.json"
    if cast_map_path.exists():
        try:
            with open(cast_map_path) as f:
                cast_map = json.load(f)
            advisory_notes.append(f"Cast map loaded: {len([k for k in cast_map if not k.startswith('_')])} characters cast")
        except Exception:
            pass

    # V15.5: Load AI actors library for headshot URLs
    ai_actors = {}
    ai_actors_path = BASE_DIR / "ai_actors_library.json"
    if ai_actors_path.exists():
        try:
            with open(ai_actors_path) as f:
                actors_data = json.load(f)
                for actor in actors_data.get("actors", []):
                    ai_actors[actor.get("name", "").upper()] = actor
                    if actor.get("id"):
                        ai_actors[str(actor.get("id"))] = actor
            advisory_notes.append(f"AI actors library: {len(ai_actors)//2} actors loaded")
        except Exception:
            pass

    # V15.5: Load location masters
    location_masters = {}
    loc_masters_dir = project_path / "location_masters"
    if loc_masters_dir.exists():
        for img in loc_masters_dir.glob("*.*"):
            if img.suffix.lower() in [".jpg", ".jpeg", ".png", ".webp"]:
                loc_name = img.stem.upper().replace("_", " ")
                location_masters[loc_name] = f"/api/media?path={img}"
        if location_masters:
            advisory_notes.append(f"Location masters: {len(location_masters)} locations")

    # =========================================================================
    # V17.3: LOAD DIRECTOR & WRITER BRAIN TREES (via central helpers)
    # =========================================================================
    genre = _resolve_genre_from_story_bible(story_bible)

    director_profile = load_director_for_project(project_path, story_bible)
    writer_profile = load_writer_for_project(project_path, story_bible)

    if director_profile:
        advisory_notes.append(f"Director: {director_profile.get('name')} ({director_profile.get('specialty', [])[0] if director_profile.get('specialty') else 'general'})")
    if writer_profile:
        advisory_notes.append(f"Writer: {writer_profile.get('name')} (pacing: {writer_profile.get('narrative_rhythm', {}).get('default_pacing', 'balanced')})")

    # V16.5: Extract director shot_braintree_overrides for duration hints
    director_durations = {}
    if director_profile and director_profile.get("shot_braintree_overrides"):
        for shot_role, overrides in director_profile["shot_braintree_overrides"].items():
            if overrides.get("duration"):
                director_durations[shot_role] = overrides["duration"]
        if director_durations:
            advisory_notes.append(f"Director duration hints: {director_durations}")

    # V16.5: Extract writer pacing for duration scaling
    writer_pacing = "balanced"
    if writer_profile and writer_profile.get("narrative_rhythm"):
        writer_pacing = writer_profile["narrative_rhythm"].get("default_pacing", "balanced")
    # Pacing multipliers: slow_burn = longer, escalating = shorter bursts
    pacing_multiplier = {
        "slow_burn_to_explosion": 1.2,
        "escalating_intensity": 0.85,
        "slow_build_to_revelation": 1.15,
        "balanced": 1.0
    }.get(writer_pacing, 1.0)

    # Import intelligent systems
    has_intelligent_enhancer = False
    has_director_critic = False

    try:
        from INTELLIGENT_PROMPT_ENHANCER import (
            TWENTY_ONE_POINT_BEATS,
            EMOTIONAL_VISUAL_MAP,
            DURATION_RULES as INTELLIGENT_DURATION_RULES,
            get_scene_beat_context,
            enhance_nano_prompt,
            enhance_ltx_motion_prompt,
            calculate_intelligent_duration
        )
        has_intelligent_enhancer = True
        advisory_notes.append("INTELLIGENT_PROMPT_ENHANCER: Active (21-point beats, emotional→visual)")
    except ImportError as e:
        advisory_notes.append(f"INTELLIGENT_PROMPT_ENHANCER: Not available ({e})")
        TWENTY_ONE_POINT_BEATS = {}
        EMOTIONAL_VISUAL_MAP = {}

    try:
        from CRITIC_AGENT import DirectorCritic, get_director_review
        has_director_critic = True
        advisory_notes.append("DirectorCritic: Active (pacing, coverage, emotional arc)")
    except ImportError as e:
        advisory_notes.append(f"DirectorCritic: Not available ({e})")

    # Run DirectorCritic advisory analysis
    director_advisory = {}
    if has_director_critic:
        try:
            target_runtime = data.get("metadata", {}).get("target_runtime", 2700)
            director_review = get_director_review(shots, story_bible, target_runtime)
            director_advisory = {
                "grade": director_review.get("overall_grade", "?"),
                "pacing": director_review.get("scores", {}).get("pacing", 0),
                "coverage": director_review.get("scores", {}).get("coverage", 0),
                "emotional_arc": director_review.get("scores", {}).get("emotional_arc", 0),
                "notes": director_review.get("notes", [])[:5]  # Top 5 notes
            }
            advisory_notes.append(f"DirectorCritic Grade: {director_advisory['grade']}")
        except Exception as e:
            advisory_notes.append(f"DirectorCritic analysis failed: {e}")

    # Import segmenter
    try:
        from EXTENDED_SHOT_SEGMENTER import calculate_segments
        has_segmenter = True
    except ImportError:
        has_segmenter = False

    STITCHING_THRESHOLD = 20

    # Fallback duration rules (used if intelligent enhancer not available)
    DURATION_RULES_FALLBACK = {
        "establishing": (12, 18),
        "wide": (12, 16),
        "medium": (10, 14),
        "close": (8, 12),
        "closeup": (8, 12),
        "reaction": (6, 8),
        "insert": (4, 6),
        "action": (8, 12),
        "default": (10, 14)
    }

    # =========================================================================
    # PHASE 2: DETERMINISTIC ENFORCEMENT (Informed by Advisory)
    # =========================================================================

    # --- SHOT TYPE DETECTION FUNCTION ---
    def detect_shot_type(shot: Dict) -> str:
        """Parse shot type from nano_prompt or other fields"""
        nano = (shot.get("nano_prompt", "") or "").lower()
        shot_type = shot.get("shot_type") or shot.get("type") or ""

        if shot_type and shot_type.lower() not in ["none", "unknown", ""]:
            return shot_type.lower()

        # Parse from nano_prompt
        if "extreme close" in nano or "ecu" in nano:
            return "extreme_close"
        elif "close-up" in nano or "closeup" in nano or "close up" in nano:
            return "close"
        elif "medium close" in nano:
            return "medium_close"
        elif "medium wide" in nano or "medium-wide" in nano:
            return "medium_wide"
        elif "wide establishing" in nano or "establishing shot" in nano:
            return "establishing"
        elif "wide shot" in nano or "wide angle" in nano:
            return "wide"
        elif "medium shot" in nano:
            return "medium"
        elif "over the shoulder" in nano or "over-the-shoulder" in nano:
            return "ots"
        elif "insert" in nano:
            return "insert"
        elif "reaction" in nano:
            return "reaction"
        elif "action" in nano or "battle" in nano or "fight" in nano:
            return "action"
        elif "profile" in nano or "side view" in nano:
            return "profile"
        elif "aerial" in nano or "drone" in nano:
            return "aerial"

        # Default based on context
        chars = shot.get("characters", [])
        if chars and len(chars) > 2:
            return "wide"
        elif chars:
            return "medium"
        return "medium"

    # Get target runtime - check story bible first, then metadata, then default
    target_runtime_raw = story_bible.get("runtime_target_minutes", 0) * 60
    if target_runtime_raw <= 0:
        target_runtime_raw = data.get("metadata", {}).get("target_runtime", 0)
    if target_runtime_raw <= 0:
        target_runtime_raw = 2700  # 45 min default
    target_runtime = int(target_runtime_raw)

    # Store in metadata for consistency
    data["metadata"] = data.get("metadata", {})
    data["metadata"]["target_runtime"] = target_runtime

    advisory_notes.append(f"Target runtime: {target_runtime}s ({target_runtime/60:.0f} min)")

    # =========================================================================
    # V16.1: MULTI-ANGLE COVERAGE EXPANSION
    # =========================================================================
    # If a scene only has 1 shot, expand it to 3 shots for proper ABC coverage
    # This ensures every scene has establishing + medium + close-up coverage

    # Group shots by scene
    from collections import defaultdict
    shots_by_scene = defaultdict(list)
    for shot in shots:
        scene_id = shot.get("scene_id", "001")
        shots_by_scene[scene_id].append(shot)

    expanded_shots = []
    for scene_id, scene_shots in shots_by_scene.items():
        if len(scene_shots) == 1:
            # Single shot scene - expand to ABC coverage
            original = scene_shots[0]
            base_id = original.get("shot_id", f"{scene_id}_001")
            # Extract base without suffix letter
            base_parts = base_id.rsplit("_", 1)
            if len(base_parts) == 2 and len(base_parts[1]) <= 4:
                id_prefix = base_parts[0]
            else:
                id_prefix = base_id

            description = original.get("description", "")
            location = original.get("location", "")
            characters = original.get("characters", [])
            base_duration = original.get("duration", 20) or 20

            # A shot: Wide establishing (use original)
            shot_a = original.copy()
            shot_a["shot_id"] = f"{id_prefix}_A"
            shot_a["type"] = "wide"
            shot_a["shot_type"] = "wide"
            shot_a["shot_size"] = "WS"
            shot_a["coverage_angle"] = "A"
            if "wide" not in shot_a.get("nano_prompt", "").lower():
                shot_a["nano_prompt"] = f"Wide establishing shot of {location}. {description}"
            expanded_shots.append(shot_a)

            # B shot: Medium coverage
            shot_b = original.copy()
            shot_b["shot_id"] = f"{id_prefix}_B"
            shot_b["type"] = "medium"
            shot_b["shot_type"] = "medium"
            shot_b["shot_size"] = "MS"
            shot_b["coverage_angle"] = "B"
            char_str = characters[0] if characters else "subject"
            shot_b["nano_prompt"] = f"Medium shot of {char_str}. {description} Location: {location}."
            shot_b["duration"] = max(8, base_duration - 4)
            shot_b["duration_seconds"] = shot_b["duration"]
            expanded_shots.append(shot_b)

            # C shot: Close-up coverage
            shot_c = original.copy()
            shot_c["shot_id"] = f"{id_prefix}_C"
            shot_c["type"] = "close"
            shot_c["shot_type"] = "close"
            shot_c["shot_size"] = "CU"
            shot_c["coverage_angle"] = "C"
            shot_c["nano_prompt"] = f"Close-up of {char_str}, reaction shot. {description}"
            shot_c["duration"] = max(6, base_duration - 8)
            shot_c["duration_seconds"] = shot_c["duration"]
            expanded_shots.append(shot_c)

            issues_fixed.append(f"{scene_id}: expanded single shot to ABC coverage (3 shots)")
        else:
            # Scene already has multiple shots - keep as is
            expanded_shots.extend(scene_shots)

    # Replace shots with expanded version
    if len(expanded_shots) > len(shots):
        shots = expanded_shots
        data["shots"] = shots
        advisory_notes.append(f"Multi-angle expansion: {len(shots)} shots after ABC coverage")

        # Also update scene_manifest and scenes arrays for consistency
        expanded_by_scene = defaultdict(list)
        for shot in expanded_shots:
            expanded_by_scene[shot.get("scene_id", "001")].append(shot)

        for scene in data.get("scene_manifest", []):
            scene_id = scene.get("scene_id")
            if scene_id in expanded_by_scene:
                scene["shots"] = expanded_by_scene[scene_id]

        for scene in data.get("scenes", []):
            scene_id = scene.get("scene_id")
            if scene_id in expanded_by_scene:
                scene["shots"] = expanded_by_scene[scene_id]

    current_total = 0

    # V17.3: Build scene beat index for script-binding
    scene_beat_index = {}
    for scene in data.get("scene_manifest", data.get("scenes", [])):
        sid = scene.get("scene_id", "")
        beats = scene.get("beats", [])
        if isinstance(beats, list):
            scene_beat_index[sid] = beats

    for i, shot in enumerate(shots):
        shot_id = shot.get("shot_id", f"shot_{i}")
        scene_id = shot.get("scene_id", "001")
        beat_number = shot.get("beat_number", i)

        # --- V17.3: SCRIPT-BINDING METADATA (Sora-class shot↔intent binding) ---
        if not shot.get("beat_id"):
            shot["beat_id"] = f"{scene_id}_beat_{beat_number}"
        if not shot.get("script_span_id"):
            anchor = shot.get("script_line_ref", "")
            shot["script_span_id"] = f"{scene_id}:{shot.get('source_line_start', i)}-{shot.get('source_line_end', i)}" if not anchor else f"{scene_id}:anchor"

        # Blocking role from shot type
        if not shot.get("blocking_role"):
            shot_type_lower = (shot.get("type") or shot.get("shot_type") or "medium").lower()
            if shot_type_lower in ("establishing", "wide"):
                shot["blocking_role"] = "master"
            elif "ots" in shot_type_lower:
                shot["blocking_role"] = "OTS-A"
            elif shot_type_lower == "reaction":
                shot["blocking_role"] = "reaction"
            elif shot_type_lower in ("insert", "detail", "broll"):
                shot["blocking_role"] = "insert"
            elif shot_type_lower == "close":
                shot["blocking_role"] = "close_coverage"
            else:
                shot["blocking_role"] = "coverage"

        # Intent tags from emotional beat
        if not shot.get("intent_tags"):
            beat_map = {
                "Opening Image": ["establish", "atmosphere"],
                "Catalyst": ["reveal", "threat"],
                "Break into Two": ["escalation", "confrontation"],
                "Dark Night": ["grief", "loss"],
                "Break into Three": ["decision", "resolve"],
                "Debate": ["tension", "dialogue"],
                "Midpoint": ["reversal", "shift"],
                "All Is Lost": ["defeat", "despair"],
                "Finale": ["climax", "resolution"]
            }
            emotional_beat = shot.get("emotional_beat", shot.get("duration_beat", ""))
            shot["intent_tags"] = beat_map.get(emotional_beat, ["narrative"])

        # Eyeline target (from character relationships + beat action)
        # V26.1: NEVER default to camera_neutral — derive gaze from action or scene context
        if not shot.get("eyeline_target") or shot.get("eyeline_target") == "camera_neutral":
            chars = shot.get("characters", [])
            _nano_lower = (shot.get("nano_prompt", "") or "").lower()
            _dlg_text = (shot.get("dialogue_text", "") or "").strip()
            _beat_desc = (shot.get("beat_description", "") or shot.get("description", "") or "").lower()
            _action_text = _nano_lower + " " + _beat_desc

            if len(chars) >= 2:
                shot["eyeline_target"] = chars[1]  # Primary looks at secondary
                shot["screen_direction"] = "left_to_right"
            elif len(chars) == 1:
                # V26.1: Derive gaze from what the character is DOING — never default to camera
                # Priority: action object > dialogue partner > scene element > off-camera neutral
                _gaze_derived = False

                # 1. Reading/looking at objects
                _object_gaze_patterns = [
                    ("read", "document in hands"), ("letter", "letter in hands"),
                    ("book", "book in hands"), ("photograph", "photograph"),
                    ("phone", "phone screen"), ("watch", "wristwatch"),
                    ("mirror", "reflection"), ("window", "window"),
                    ("door", "doorway"), ("painting", "painting on wall"),
                    ("portrait", "portrait"), ("desk", "papers on desk"),
                    ("fire", "fireplace"), ("drink", "glass in hand"),
                    ("key", "key in hand"), ("map", "map spread out"),
                    ("screen", "screen"), ("note", "note in hand"),
                ]
                for _trigger, _gaze_obj in _object_gaze_patterns:
                    if _trigger in _action_text:
                        shot["eyeline_target"] = _gaze_obj
                        shot["screen_direction"] = "slightly_down" if "hand" in _gaze_obj else "center_off_axis"
                        _gaze_derived = True
                        break

                # 2. Looking at environment/direction
                if not _gaze_derived:
                    _direction_patterns = [
                        ("stair", "up_staircase"), ("up", "upward"),
                        ("down", "downward"), ("away", "away_from_camera"),
                        ("toward", "toward_subject"), ("out", "out_window"),
                        ("across", "across_room"), ("enter", "toward_door"),
                        ("leave", "toward_exit"), ("walk", "direction_of_travel"),
                        ("search", "scanning_room"), ("examine", "object_of_interest"),
                    ]
                    for _trigger, _gaze_dir in _direction_patterns:
                        if _trigger in _action_text:
                            shot["eyeline_target"] = _gaze_dir
                            shot["screen_direction"] = "off_axis"
                            _gaze_derived = True
                            break

                # 3. Dialogue with off-screen character
                if not _gaze_derived and _dlg_text:
                    # Speaking — but to whom? Check scene for other characters
                    _scene_chars = set()
                    for _other in shots:
                        if _other.get("scene_id") == shot.get("scene_id") and _other.get("characters"):
                            for _oc in _other["characters"]:
                                _scene_chars.add(_oc)
                    _scene_chars.discard(chars[0])
                    if _scene_chars:
                        shot["eyeline_target"] = list(_scene_chars)[0]
                        shot["screen_direction"] = "three_quarter_toward_listener"
                    else:
                        shot["eyeline_target"] = "off_camera_listener"
                        shot["screen_direction"] = "three_quarter_off_axis"
                    _gaze_derived = True

                # 4. Final fallback — NEVER camera_neutral
                if not _gaze_derived:
                    shot["eyeline_target"] = "off_camera_natural"
                    shot["screen_direction"] = "three_quarter_off_axis"

        # Continuity links (prev/next shot binding)
        if not shot.get("continuity_links"):
            prev_shot = shots[i-1].get("shot_id") if i > 0 else None
            next_shot = shots[i+1].get("shot_id") if i < len(shots) - 1 else None
            shot["continuity_links"] = {
                "prev": prev_shot,
                "next": next_shot,
                "match_action": None,
                "prop_state": None
            }

        # --- V18.2: CONTINUITY STATE FIELDS (Director Brain) ---
        # shot_role: GEOGRAPHY / ACTION / EMOTION — from coverage contract
        # coverage_role: A_GEOGRAPHY / B_ACTION / C_EMOTION — detailed role
        # state_in / state_out: character states at shot boundaries
        if not shot.get("shot_role") or shot.get("shot_role") not in ("GEOGRAPHY", "ACTION", "EMOTION"):
            # V21.10 FIX: Use shot_type (always populated) not shot_size (often empty)
            # Also check shot_size as fallback for legacy data
            _st = (shot.get("shot_type") or shot.get("shot_size") or shot.get("type") or "medium").lower()
            if _st in ("establishing", "wide", "master", "extreme_wide", "ews", "ws", "mws", "full"):
                shot["shot_role"] = "GEOGRAPHY"
                shot["coverage_role"] = "A_GEOGRAPHY"
            elif _st in ("close_up", "extreme_close", "medium_close", "reaction", "insert", "detail", "cu", "ecu", "bcu"):
                shot["shot_role"] = "EMOTION"
                shot["coverage_role"] = "C_EMOTION"
            else:
                shot["shot_role"] = "ACTION"
                shot["coverage_role"] = "B_ACTION"

        # --- V17.3: AUDIO MODE DEFAULT (stems-first architecture) ---
        # LTX renders dialogue + lip sync ONLY — no baked soundscapes
        if not shot.get("audio_mode"):
            # Detect if shot has dialogue content
            has_dialogue = bool(shot.get("dialogue_text") or
                               (shot.get("nano_prompt", "").lower().find("says") >= 0) or
                               (shot.get("nano_prompt", "").lower().find("speak") >= 0) or
                               (shot.get("nano_prompt", "").lower().find("tell") >= 0))
            shot["audio_mode"] = "ltx_dialogue_only" if has_dialogue else "none"
        # Stem tracking fields
        if not shot.get("audio_stems"):
            shot["audio_stems"] = {
                "dialogue": None,     # dialogue_raw.wav from LTX or ElevenLabs TTS
                "sfx": None,          # SFX stem
                "ambience": None,     # location ambience bed
                "music": None         # underscore music
            }
        if "audio_gain" not in shot:
            shot["audio_gain"] = {"dialogue": 1.0, "sfx": 0.7, "ambience": 0.3, "music": 0.5}

        # --- 0. DETECT AND SET SHOT TYPE ---
        detected_type = detect_shot_type(shot)
        if not shot.get("shot_type") or shot.get("shot_type") in [None, "None", "unknown"]:
            shot["shot_type"] = detected_type
            shot["type"] = detected_type  # Also set "type" for compatibility

        # --- V16.0: NORMALIZE BEAT FIELD ---
        # UI may expect "beat" instead of "beat_number"
        if not shot.get("beat") and shot.get("beat_number") is not None:
            shot["beat"] = shot["beat_number"]

        # --- V16.0: CINEMATIC PROMPT ENHANCEMENT ---
        # Convert narrative prompts to cinematic format for nano-banana-pro
        nano_prompt = shot.get("nano_prompt", "")
        cinematic_keywords = ['35mm', '50mm', '24mm', '85mm', '100mm', 'WS,', 'MS,', 'CU,', 'anamorphic']
        has_cinematic = any(kw.upper() in nano_prompt.upper() for kw in cinematic_keywords)

        # V21.9: CINEMATIC PREFIX/SUFFIX — only add if prompt is bare template
        # Clean hand-written prompts already contain visual descriptions.
        # Only wrap prompts that look like bare templates (no character names, no visual verbs).
        # The enricher at generate-first-frames time will add cinematic language.
        if nano_prompt and not has_cinematic:
            # V21.9: Check if prompt already has substantial visual content
            _has_visual_content = (
                len(nano_prompt) > 100 and  # Short templates need help, long prompts don't
                any(w in nano_prompt.lower() for w in ["wearing", "sitting", "standing", "walking", "looking", "holding"])
            )
            if not _has_visual_content:
                # Only wrap bare template prompts that need cinematic formatting
                shot_type = detected_type.lower() if detected_type else "medium"
                char_count = len(shot.get("characters", []))
                CINEMATIC_PREFIXES = {
                    "establishing": "35mm WS, composition: establishing wide, off-axis camera, ",
                    "wide": "35mm WS, composition: wide establishing, asymmetric framing, ",
                    "medium": "50mm MS, composition: rule of thirds, subject off-center, ",
                    "close": "85mm CU, composition: asymmetric close-up, slight camera angle, ",
                    "action": "24mm WS, composition: dynamic framing, foreground elements, ",
                    "reaction": "50mm MCU, composition: off-center reaction, negative space, ",
                    "dialogue": "50mm MS, composition: over-shoulder with depth, foreground occlusion, " if char_count >= 2 else "50mm MS, composition: centered medium, single subject focus, ",
                    "dialogue_single": "50mm MS, composition: centered medium, single subject focus, ",
                    "insert": "100mm ECU, composition: detail focus, shallow depth of field, ",
                    "profile": "85mm MS, composition: profile framing, background separation, ",
                    "aerial": "24mm WS, composition: aerial establishing, layered depth, ",
                }
                prefix = CINEMATIC_PREFIXES.get(shot_type, CINEMATIC_PREFIXES["medium"])
                # V25 CURE 5: Removed "35mm anamorphic" brand-style token.
                # Research: focal length descriptors + color science outperform brand names on LTX-2.3
                suffix = (
                    " Subject NOT looking directly into camera lens, eye-line 15-35 degrees off-axis."
                    " Camera slightly off-center, motivated practical lighting."
                    " Cinematic depth with foreground elements, rule-of-thirds asymmetric balance."
                    " natural film grain, professional cinematography, filmic highlight rolloff."
                )
                shot["nano_prompt"] = f"{prefix}{nano_prompt}{suffix}"
                issues_fixed.append(f"{shot_id}: added cinematic formatting + anti-lens-look rules")

        # --- V17.2.4 / V25: CAMERA DEFAULTS — Metadata Only (never injected into prompts) ---
        # These values are for UI display and shot bookkeeping ONLY.
        # DOCTRINE LAW 235: NO camera brand names in ANY prompt path.
        # The Film Engine's translate_camera_tokens() converts these to effective descriptors
        # (focal length + aperture + color science) before any FAL call.
        CAMERA_DEFAULTS_BY_TYPE = {
            "wide":          {"camera_body": "ARRI Alexa 35", "lens_specs": "24mm", "camera_style": "static", "lens_type": "Cooke S7/i Prime"},
            "establishing":  {"camera_body": "ARRI Alexa 35", "lens_specs": "14mm", "camera_style": "slow_crane", "lens_type": "Anamorphic 2x"},
            "medium":        {"camera_body": "ARRI Alexa 35", "lens_specs": "50mm", "camera_style": "static", "lens_type": "Cooke S7/i Prime"},
            "medium_wide":   {"camera_body": "ARRI Alexa 35", "lens_specs": "35mm", "camera_style": "steadicam", "lens_type": "Cooke S7/i Prime"},
            "medium_close":  {"camera_body": "ARRI Alexa 35", "lens_specs": "50mm", "camera_style": "static", "lens_type": "Cooke S7/i Prime"},
            "close":         {"camera_body": "ARRI Alexa 35", "lens_specs": "85mm", "camera_style": "static", "lens_type": "Cooke S7/i Prime"},
            "extreme_close": {"camera_body": "ARRI Alexa 35", "lens_specs": "100mm", "camera_style": "static", "lens_type": "Cooke S7/i Prime"},
            "detail":        {"camera_body": "ARRI Alexa 35", "lens_specs": "100mm", "camera_style": "static", "lens_type": "Cooke S7/i Prime"},
            "ots":           {"camera_body": "ARRI Alexa 35", "lens_specs": "50mm", "camera_style": "static", "lens_type": "Cooke S7/i Prime"},
            "action":        {"camera_body": "ARRI Alexa 35", "lens_specs": "24mm", "camera_style": "handheld", "lens_type": "Zeiss Master Prime"},
            "reaction":      {"camera_body": "ARRI Alexa 35", "lens_specs": "85mm", "camera_style": "static", "lens_type": "Cooke S7/i Prime"},
            "aerial":        {"camera_body": "ARRI Alexa 35", "lens_specs": "24mm", "camera_style": "slow_crane", "lens_type": "Zeiss Master Prime"},
            "insert":        {"camera_body": "ARRI Alexa 35", "lens_specs": "100mm", "camera_style": "static", "lens_type": "Cooke S7/i Prime"},
            "profile":       {"camera_body": "ARRI Alexa 35", "lens_specs": "85mm", "camera_style": "static", "lens_type": "Cooke S7/i Prime"},
        }
        cam_defaults = CAMERA_DEFAULTS_BY_TYPE.get(detected_type, CAMERA_DEFAULTS_BY_TYPE["medium"])
        camera_defaults_applied = False
        for cam_field, cam_val in cam_defaults.items():
            # V17.3 FIX: ALWAYS apply type-specific defaults — don't skip if already set
            # Previous bug: "static" was set on all shots and never overwritten because field was non-empty
            old_val = shot.get(cam_field)
            if old_val != cam_val:
                shot[cam_field] = cam_val
                camera_defaults_applied = True
        if camera_defaults_applied:
            issues_fixed.append(f"{shot_id}: applied camera defaults for {detected_type} shot (motion: {cam_defaults.get('camera_style', 'static')})")

        # --- V17.2: V13 GOLD STANDARD - Inject negatives + face stability + timing ---
        # Ensure nano_prompt has required negatives
        nano_check = (shot.get("nano_prompt", "") or "").lower()
        if "no grid" not in nano_check or "no morphing" not in nano_check:
            existing_nano = shot.get("nano_prompt", "")
            shot["nano_prompt"] = existing_nano.rstrip(",. ") + ", NO grid, NO collage, NO split screen, NO extra people, NO morphing faces, NO watermarks, NO text overlays, NO babies, NO children unless script specifies"
            issues_fixed.append(f"{shot_id}: added V13 required negatives")

        # Ensure ltx_motion_prompt has timing + face stability
        # V17.7: ALWAYS validate timing matches actual duration (not just check presence)
        ltx_check = (shot.get("ltx_motion_prompt", "") or "").lower()
        has_chars = len(shot.get("characters", [])) > 0
        shot_duration = int(shot.get("duration", shot.get("duration_seconds", 8)))

        # V17.7: Check if existing timing matches actual duration (fixes 6s video bug)
        import re as _re_ltx
        existing_time_refs = [int(m) for m in _re_ltx.findall(r'(\d+)s(?:[\s,.]|$)', ltx_check[:250])]
        existing_max_time = max(existing_time_refs) if existing_time_refs else 0
        # V21.10 FIX: "static" camera motion does NOT mean timing is correct
        # Always validate timing regardless of camera motion keywords
        timing_needs_sync = (not ltx_check or
                           "camera holds" not in ltx_check or
                           existing_max_time != shot_duration)

        if timing_needs_sync:
            # V25.6 ARCHITECTURE FIX — fix-v16 is STRUCTURAL PLUMBING only
            # Prompt CONTENT is owned by unified_prompt_builder + CPC (runs at end of fix-v16)
            # fix-v16 ONLY ensures the duration marker is correct — NEVER rewrites prompt content
            existing_ltx = shot.get("ltx_motion_prompt", "") or ""
            # Strip old duration markers
            cleaned_ltx = _re_ltx.sub(r'\b\d+-\d+s\b', '', existing_ltx)
            cleaned_ltx = _re_ltx.sub(r'(?<!\d)(?<!\dx)(\b(?:[5-9]|[1-9]\d+)s\b)(?![\w/])', '', cleaned_ltx)
            cleaned_ltx = _re_ltx.sub(r'^[\s,.\-]+', '', cleaned_ltx.strip()).strip(' ,.')
            # Re-attach correct duration marker — content untouched
            if cleaned_ltx:
                shot["ltx_motion_prompt"] = cleaned_ltx.rstrip(",. ") + f", {shot_duration}s"
            else:
                # Empty LTX — set placeholder that unified_prompt_builder will replace with CPC output
                shot["ltx_motion_prompt"] = f"_PENDING_CPC, {shot_duration}s"
            issues_fixed.append(f"{shot_id}: synced LTX duration to {shot_duration}s")

        # Re-read after potential timing fix
        ltx_check = (shot.get("ltx_motion_prompt", "") or "").lower()
        # V21.5 LOCKED — face stable = IDENTITY LOCK (bone structure, features) — goes on ALL shots
        # Face stable does NOT freeze expressions — it prevents the character from morphing into someone else
        # Dialogue shots get speech markers ADDITIONALLY (on top of face stable)
        _has_dialogue_face = bool(shot.get("dialogue_text") or shot.get("dialogue"))
        if has_chars and "face stable" not in ltx_check and "no morphing" not in ltx_check:
            # V26.1: Inject eyeline direction into LTX based on derived eyeline_target
            _eyeline = shot.get("eyeline_target", "off_camera_natural")
            _eyeline_ltx = ""
            if _eyeline and _eyeline not in ("camera_neutral", "off_camera_natural"):
                _eyeline_ltx = f", character gaze directed toward {_eyeline}, NOT looking at camera"
            else:
                _eyeline_ltx = ", character gaze naturally off-camera, three-quarter angle, NOT looking directly at lens"

            if _has_dialogue_face:
                # V21.9: Dialogue — identity lock WITHOUT "NO morphing" (conflicts with lip sync)
                shot["ltx_motion_prompt"] = (shot.get("ltx_motion_prompt", "") or "").rstrip(",. ") + f", face stable, character consistent, natural speech movement, lips moving{_eyeline_ltx}"
            else:
                # Non-dialogue: identity lock only
                shot["ltx_motion_prompt"] = (shot.get("ltx_motion_prompt", "") or "").rstrip(",. ") + f", face stable NO morphing, character consistent{_eyeline_ltx}"
            issues_fixed.append(f"{shot_id}: added face stability clauses")
        elif not has_chars and "no morphing" not in ltx_check:
            # V21.10 FIX ROOT CAUSE #3: Non-character shots (B-roll, establishing, landscape)
            # MUST have NO morphing to prevent LTX from hallucinating human features
            # But NO face stable (no face to stabilize) and NO human performance language
            shot["ltx_motion_prompt"] = (shot.get("ltx_motion_prompt", "") or "").rstrip(",. ") + ", NO morphing, NO face generation, environment only"
            issues_fixed.append(f"{shot_id}: added NO morphing for non-character shot")

        # --- V17 FIX: ATTACH/REFRESH CHARACTER REFERENCE URL ---
        # V17: Always re-resolve from cast_map (was: only if missing)
        # This ensures updated cast assignments propagate to all shots
        shot_chars = shot.get("characters", [])
        if shot_chars and cast_map and ai_actors:
            # Get first character in shot
            first_char = shot_chars[0] if isinstance(shot_chars[0], str) else shot_chars[0].get("name", "")
            first_char_upper = first_char.upper().strip()

            # Find in cast_map
            actor_data = None
            for char_key, actor_val in cast_map.items():
                if char_key.startswith("_"):
                    continue
                if first_char_upper in char_key.upper() or char_key.upper() in first_char_upper:
                    actor_data = actor_val
                    break

            # Get actor headshot - handle both simple and rich formats
            if actor_data:
                headshot_url = None

                # Rich format: {"ai_actor_id": "001", "headshot_url": "...", ...}
                if isinstance(actor_data, dict):
                    # Try direct reference URLs - cast_map uses reference_url, others use headshot_url
                    headshot_url = (
                        actor_data.get("reference_url")  # Primary: cast_map format
                        or actor_data.get("headshot_url")
                        or actor_data.get("locked_reference_url")
                    )

                    # If not, look up actor by ID
                    if not headshot_url:
                        actor_id = actor_data.get("ai_actor_id") or actor_data.get("id")
                        if actor_id:
                            actor = ai_actors.get(str(actor_id)) or ai_actors.get(actor_id)
                            if actor:
                                headshot_url = (
                                    actor.get("headshot_url")
                                    or actor.get("headshot")
                                    or actor.get("reference_image")
                                    or actor.get("locked_reference_url")
                                )
                                # Also check for on-disk headshot images
                                if not headshot_url:
                                    actor_name_key = actor.get("name", "").upper().replace(" ", "_")
                                    headshot_file = BASE_DIR / "ai_actor_headshots" / f"{actor_name_key}_HEADSHOT.jpg"
                                    if headshot_file.exists():
                                        headshot_url = f"/api/media?path={headshot_file}"
                else:
                    # Simple format: actor_val is just the ID
                    actor = ai_actors.get(str(actor_data)) or ai_actors.get(actor_data)
                    if actor:
                        headshot_url = (
                            actor.get("headshot_url")
                            or actor.get("headshot")
                            or actor.get("reference_image")
                            or actor.get("locked_reference_url")
                        )
                        # Also check for on-disk headshot images
                        if not headshot_url:
                            actor_name_key = actor.get("name", "").upper().replace(" ", "_")
                            headshot_file = BASE_DIR / "ai_actor_headshots" / f"{actor_name_key}_HEADSHOT.jpg"
                            if headshot_file.exists():
                                headshot_url = f"/api/media?path={headshot_file}"

                if headshot_url:
                    shot["character_reference_url"] = headshot_url
                    issues_fixed.append(f"{shot_id}: attached character_reference_url for {first_char}")

        # --- V17.6: ATTACH LOCATION MASTER URL (scored matching) ---
        shot_loc = shot.get("location", "")
        if shot_loc and location_masters and not shot.get("location_master_url"):
            shot_loc_upper = shot_loc.upper().strip()
            # Remove time-of-day suffixes for matching
            import re as _re
            shot_loc_clean = _re.sub(r'\s*[-–]\s*(NIGHT|DAY|EVENING|MORNING|AFTERNOON|LATE|DAWN|DUSK|LATER|CONTINUOUS).*$', '', shot_loc_upper, flags=_re.IGNORECASE).strip()
            loc_parts = [p.strip() for p in shot_loc_clean.replace("/", ",").replace("–", ",").replace("-", ",").split(",")]
            loc_parts = [p for p in loc_parts if len(p) > 2]

            # V17.6: SCORED matching — find BEST match, not FIRST match
            best_match = None
            best_score = 0
            for loc_name, loc_url in location_masters.items():
                loc_name_clean = loc_name.replace(" MASTER", "").strip().upper()

                # Exact match = 100
                if loc_name_clean == shot_loc_clean:
                    best_match = (loc_name, loc_url)
                    best_score = 100
                    break

                # Compound part exact match = 90
                for part in loc_parts:
                    if loc_name_clean == part:
                        score = 90
                        if score > best_score:
                            best_match = (loc_name, loc_url)
                            best_score = score

                # Long substring match = 50 + length (minimum 8 chars)
                if len(loc_name_clean) >= 8 and best_score < 80:
                    if loc_name_clean in shot_loc_clean:
                        score = 50 + len(loc_name_clean)
                        if score > best_score:
                            best_match = (loc_name, loc_url)
                            best_score = score
                    elif shot_loc_clean in loc_name_clean:
                        score = 45 + len(shot_loc_clean)
                        if score > best_score:
                            best_match = (loc_name, loc_url)
                            best_score = score

            if best_match and best_score >= 45:
                shot["location_master_url"] = best_match[1]
                issues_fixed.append(f"{shot_id}: attached location_master_url for {shot_loc} (score={best_score}, match={best_match[0]})")

        # Get beat context from story bible (intelligent analysis)
        beat_context = {}
        if has_intelligent_enhancer and story_bible:
            try:
                beat_context = get_scene_beat_context(story_bible, scene_id, beat_number)
            except Exception:
                beat_context = {"emotional_tone": "neutral", "emotional_beat": "Setup"}

        # --- INFER BEATS when story bible lacks detail ---
        if beat_context.get("emotional_beat") == "Setup" and beat_context.get("emotional_tone") == "neutral":
            # Infer from scene position in narrative structure
            scene_position = i / max(1, len(shots))
            nano = (shot.get("nano_prompt", "") or "").lower()
            title = beat_context.get("scene_title", "").lower()

            # Infer emotional beat from position (21-point structure)
            if scene_position < 0.1:
                beat_context["emotional_beat"] = "Opening Image"
            elif scene_position < 0.15:
                beat_context["emotional_beat"] = "Theme Stated"
            elif scene_position < 0.2:
                beat_context["emotional_beat"] = "Setup"
            elif scene_position < 0.25:
                beat_context["emotional_beat"] = "Catalyst"
            elif scene_position < 0.35:
                beat_context["emotional_beat"] = "Debate"
            elif scene_position < 0.4:
                beat_context["emotional_beat"] = "Break into Two"
            elif scene_position < 0.5:
                beat_context["emotional_beat"] = "B Story"
            elif scene_position < 0.55:
                beat_context["emotional_beat"] = "Midpoint"
            elif scene_position < 0.65:
                beat_context["emotional_beat"] = "Bad Guys Close In"
            elif scene_position < 0.75:
                beat_context["emotional_beat"] = "All Is Lost"
            elif scene_position < 0.8:
                beat_context["emotional_beat"] = "Dark Night of Soul"
            elif scene_position < 0.85:
                beat_context["emotional_beat"] = "Break into Three"
            elif scene_position < 0.95:
                beat_context["emotional_beat"] = "Finale"
            else:
                beat_context["emotional_beat"] = "Final Image"

            # Infer emotional tone from keywords
            if any(w in nano or w in title for w in ["attack", "fight", "battle", "chase"]):
                beat_context["emotional_tone"] = "tension"
            elif any(w in nano or w in title for w in ["defeat", "fall", "loss", "dead"]):
                beat_context["emotional_tone"] = "grief"
            elif any(w in nano or w in title for w in ["discover", "reveal", "learn"]):
                beat_context["emotional_tone"] = "revelation"
            elif any(w in nano or w in title for w in ["meet", "arrive", "diplomatic"]):
                beat_context["emotional_tone"] = "hope"
            elif any(w in nano or w in title for w in ["guard", "wait", "watch"]):
                beat_context["emotional_tone"] = "dread"
            elif any(w in nano or w in title for w in ["council", "select", "assign"]):
                beat_context["emotional_tone"] = "determination"
            else:
                beat_context["emotional_tone"] = "neutral"

            # Set act from position
            if scene_position < 0.25:
                beat_context["act"] = 1
            elif scene_position < 0.75:
                beat_context["act"] = 2
            else:
                beat_context["act"] = 3

        # --- 1. DIRECTOR/WRITER BRAIN TREE DURATION (V16.5) ---
        # Uses: director_durations (from shot_braintree_overrides)
        #       pacing_multiplier (from writer narrative_rhythm)
        #       LTX constraints: 6-20 standard, 25-60 extended with stitching
        current_duration = shot.get("duration", 0)
        remaining_shots = len(shots) - i
        remaining_time = target_runtime - current_total

        shot_type = (shot.get("type") or shot.get("shot_type") or "medium").lower()
        beat_type = (shot.get("beat_type") or shot.get("shot_role") or "action").lower()
        dialogue_text = shot.get("dialogue") or shot.get("dialogue_text") or ""
        word_count = len(dialogue_text.split()) if dialogue_text else 0

        # =======================================================================
        # STEP 1: Get director's brain tree duration hint (primary source)
        # =======================================================================
        director_hint = None
        for role_key in [beat_type, shot_type, "default"]:
            if role_key in director_durations:
                director_hint = director_durations[role_key]
                break

        # =======================================================================
        # STEP 2: LTX-aware base duration by shot role
        # Valid LTX durations: 6,8,10,12,14,16,18,20 (standard) or 25,30,35,40,45,50,55,60 (extended)
        # =======================================================================
        # CRITICAL: LTX requires EVEN-ONLY durations for clean segmentation
        LTX_STANDARD = [6, 8, 10, 12, 14, 16, 18, 20]
        LTX_EXTENDED = [24, 30, 36, 40, 48, 54, 60]  # Even-only

        if director_hint:
            # Use director's specific hint
            base_duration = director_hint
        elif shot_type in ["wide", "ws", "establishing", "master", "extreme_wide"]:
            base_duration = 14  # Establishing: let audience absorb
        elif shot_type in ["close", "cu", "closeup", "mcu", "medium_close"]:
            base_duration = 10  # Emotional focus
        elif shot_type in ["ecu", "extreme_close", "insert", "detail"]:
            base_duration = 6   # Quick information
        elif shot_type in ["ots", "over_shoulder", "two_shot"]:
            base_duration = 12  # Dialogue coverage
        else:
            base_duration = 10  # Medium default

        # =======================================================================
        # STEP 3: Adjust for dialogue content
        # =======================================================================
        if word_count > 0:
            dialogue_time = word_count * 0.45 + 2.5  # 0.45s/word + buffer
            base_duration = max(base_duration, int(dialogue_time))

        # =======================================================================
        # STEP 4: Apply writer pacing multiplier
        # =======================================================================
        base_duration = int(base_duration * pacing_multiplier)

        # =======================================================================
        # STEP 5: Apply beat type modifiers
        # =======================================================================
        if beat_type in ["establishing", "opening", "ritual_establishing"]:
            base_duration = int(base_duration * 1.25)
        elif beat_type in ["reaction", "listening", "insert"]:
            base_duration = int(base_duration * 0.75)
        elif beat_type in ["climax", "revelation", "horror_beat"]:
            base_duration = int(base_duration * 1.15)
        elif beat_type in ["action", "chase", "fight"]:
            base_duration = int(base_duration * 0.85)

        # =======================================================================
        # STEP 6: Snap to valid LTX duration (NO target scaling here)
        # Target runtime scaling is handled by SMART_SHOT_DURATION.rebalance_durations_to_target
        # which PRESERVES variety while hitting target
        # =======================================================================
        # Determine if extended based on content (dialogue length, beat type)
        # Establishing/Wide shots CAN extend for immersion
        # Close/Reaction shots should stay standard for pacing variety
        can_extend = (
            shot_type in ["wide", "ws", "establishing", "master"] or
            word_count > 20 or
            beat_type in ["ritual", "ritual_establishing", "contemplative", "introspection"]
        )

        if base_duration > 20 and can_extend:
            shot["extended_shot"] = True
            # Snap to valid extended duration
            ideal_d = min(LTX_EXTENDED, key=lambda x: abs(x - base_duration))
        else:
            shot["extended_shot"] = False
            # Snap to valid standard duration (cap at 20 for variety)
            capped = min(20, base_duration)
            ideal_d = min(LTX_STANDARD, key=lambda x: abs(x - capped))

        # =======================================================================
        # STEP 7: Apply emotional tone modifiers (from story bible context)
        # =======================================================================
        if beat_context:
            beat_name = beat_context.get("emotional_beat", "Setup")
            emotional_tone = beat_context.get("emotional_tone", "neutral")

            # Persist beat context to shot
            shot["duration_beat"] = beat_name
            shot["duration_emotion"] = emotional_tone
            shot["emotional_beat"] = beat_name
            shot["emotional_tone"] = emotional_tone
            shot["act"] = beat_context.get("act", 2)

            # Apply emotional intensity modifier (post-snap adjustment)
            if emotional_tone in ["dread", "grief", "contemplative"]:
                # Lingering - bump to next valid duration
                idx = (LTX_EXTENDED if shot.get("extended_shot") else LTX_STANDARD).index(ideal_d) if ideal_d in (LTX_EXTENDED if shot.get("extended_shot") else LTX_STANDARD) else -1
                valid_list = LTX_EXTENDED if shot.get("extended_shot") else LTX_STANDARD
                if idx >= 0 and idx < len(valid_list) - 1:
                    ideal_d = valid_list[idx + 1]  # Bump to next
            elif emotional_tone in ["fear", "tension", "action"]:
                # Quick cuts - bump down
                idx = (LTX_EXTENDED if shot.get("extended_shot") else LTX_STANDARD).index(ideal_d) if ideal_d in (LTX_EXTENDED if shot.get("extended_shot") else LTX_STANDARD) else -1
                valid_list = LTX_EXTENDED if shot.get("extended_shot") else LTX_STANDARD
                if idx > 0:
                    ideal_d = valid_list[idx - 1]  # Bump down

        # =======================================================================
        # STEP 7B (V25 CURE 3): DIALOGUE DURATION FLOOR — runs AFTER all modifiers
        # DOCTRINE LAW 224: min_duration = (word_count / 2.3) + 2.5s buffer
        # V27.3: Buffer increased from 1.5s to 2.5s — dialogue needs BREATHING ROOM.
        # 1.5s was mathematically sufficient but left 0.1s margin on dense lines.
        # Production evidence: 006B had 24 words in 12s = 0.1s margin, audio clipped.
        # =======================================================================
        if word_count > 0:
            _dlg_min = round((word_count / 2.3) + 2.5, 1)
            if ideal_d < _dlg_min:
                # Snap UP to nearest valid LTX duration that covers the dialogue
                _valid = LTX_EXTENDED if shot.get("extended_shot") else LTX_STANDARD
                _candidates = [d for d in _valid if d >= _dlg_min]
                if _candidates:
                    ideal_d = _candidates[0]
                else:
                    ideal_d = _valid[-1]  # Longest available
                shot["_dialogue_protected"] = True
                shot["_dialogue_word_count"] = word_count
                shot["_dialogue_min_duration"] = _dlg_min

        # =======================================================================
        # STEP 8: Update shot duration (always enforce LTX valid durations)
        # =======================================================================
        max_allowed = 60 if shot.get("extended_shot") else 20
        if current_duration not in LTX_STANDARD + LTX_EXTENDED or abs(current_duration - ideal_d) > 2:
            shot["duration"] = ideal_d
            shot["duration_seconds"] = ideal_d
            shot["duration_method"] = "director_brain_tree_v165"
            shot["duration_source"] = f"director:{director_profile.get('name', 'default') if director_profile else 'default'}, writer_pacing:{writer_pacing}"
            issues_fixed.append(f"{shot_id}: duration {current_duration}s → {ideal_d}s ({shot_type}, {beat_type})")

        current_total += shot.get("duration", 10)

        # --- 2. INTELLIGENT PROMPT ENHANCEMENT ---
        if has_intelligent_enhancer and beat_context:
            nano_prompt = shot.get("nano_prompt", "")
            ltx_prompt = shot.get("ltx_motion_prompt", "")

            if nano_prompt and beat_context.get("emotional_tone") != "neutral":
                try:
                    enhanced_nano = enhance_nano_prompt(shot, beat_context, story_bible)
                    if enhanced_nano != nano_prompt:
                        shot["nano_prompt"] = enhanced_nano
                        shot["nano_prompt_original"] = nano_prompt
                        issues_fixed.append(f"{shot_id}: enhanced nano_prompt with {beat_context.get('emotional_tone')} visual style")
                except Exception:
                    pass

            if ltx_prompt:
                try:
                    enhanced_ltx = enhance_ltx_motion_prompt(shot, beat_context, story_bible)
                    if enhanced_ltx != ltx_prompt:
                        shot["ltx_motion_prompt"] = enhanced_ltx
                        shot["ltx_motion_original"] = ltx_prompt
                        issues_fixed.append(f"{shot_id}: enhanced ltx_motion with beat-aware movement")
                except Exception:
                    pass

        # --- 3. EXTENDED SEGMENTS for shots > 20s ---
        if shot.get("duration", 0) > STITCHING_THRESHOLD and has_segmenter:
            if "segments" not in shot:
                try:
                    segments = calculate_segments(shot["duration"])
                    shot["segments"] = segments
                    shot["requires_stitching"] = True
                    issues_fixed.append(f"{shot_id}: added {len(segments)} segments for {shot['duration']}s")
                except Exception:
                    pass

        # --- 3b. V17.6: DIALOGUE-AWARE SEGMENTATION ---
        if DIALOGUE_SEG_AVAILABLE:
            if should_segment_dialogue(shot):
                existing_segments = shot.get("segments", [])
                if not existing_segments or shot.get("_segmentation_method") != "dialogue_aware":
                    try:
                        new_segments = auto_segment_dialogue_shot(shot, cast_map)
                        if new_segments:
                            shot["segments"] = new_segments
                            shot["_segmentation_method"] = "dialogue_aware"
                            shot["requires_stitching"] = True
                            issues_fixed.append(f"{shot_id}: applied dialogue-aware segmentation ({len(new_segments)} segments)")
                    except Exception as ds_err:
                        logger.warning(f"[V17.6] Dialogue segmentation failed for {shot_id}: {ds_err}")

        # --- 4. ENSURE LTX MOTION PROMPT exists AND MATCHES DURATION (V16.5) ---
        ltx_prompt = shot.get("ltx_motion_prompt", "")
        nano_prompt = shot.get("nano_prompt", "")
        duration = shot.get("duration", 10)
        shot_type = (shot.get("type") or shot.get("shot_type") or "medium").lower()
        has_characters = bool(shot.get("characters"))

        # V16.5: Generate director-intelligent LTX motion prompts
        # Motion style should match both duration AND shot type
        def generate_ltx_motion(dur, stype, has_chars):
            """Generate LTX motion prompt like a director would conceive it."""
            parts = []

            # Camera movement based on shot type
            if stype in ["wide", "ws", "establishing", "master"]:
                parts.append("slow establishing drift")
            elif stype in ["close", "cu", "mcu"]:
                parts.append("subtle intimate movement")
            elif stype in ["ecu", "extreme_close"]:
                parts.append("near-static with micro-movements")
            elif stype in ["ots", "over_shoulder"]:
                parts.append("gentle conversational sway")
            else:
                parts.append("subtle natural movement")

            # Pacing based on duration
            if dur >= 25:
                parts.append("measured deliberate pace")
                parts.append("slow contemplative rhythm")
            elif dur >= 15:
                parts.append("steady unhurried movement")
            elif dur >= 10:
                parts.append("natural comfortable rhythm")
            else:
                parts.append("brisk purposeful energy")

            # Character-specific motion
            if has_chars:
                parts.append("visible breathing")
                parts.append("subtle micro-expressions")
            else:
                parts.append("environmental atmosphere shifts")

            # Duration at end (MUST match actual duration)
            parts.append(f"{dur}s")

            return ", ".join(parts)

        # Generate or update LTX prompt
        if not ltx_prompt:
            ltx_prompt = generate_ltx_motion(duration, shot_type, has_characters)
            shot["ltx_motion_prompt"] = ltx_prompt
            issues_fixed.append(f"{shot_id}: added ltx_motion_prompt ({duration}s)")
        else:
            # V16.5: Fix duration mismatch in existing LTX prompts
            # Check if LTX prompt has wrong duration (e.g., says "16s" but duration is 20)
            import re
            duration_match = re.search(r'(\d+)s\b', ltx_prompt)
            if duration_match:
                prompt_duration = int(duration_match.group(1))
                if prompt_duration != duration:
                    # Replace wrong duration with correct one
                    ltx_prompt = re.sub(r'\d+s\b', f'{duration}s', ltx_prompt)
                    shot["ltx_motion_prompt"] = ltx_prompt
                    issues_fixed.append(f"{shot_id}: fixed LTX duration {prompt_duration}s → {duration}s")
            else:
                # Add duration to end if missing
                ltx_prompt = ltx_prompt.rstrip(", ") + f", {duration}s"
                shot["ltx_motion_prompt"] = ltx_prompt
                issues_fixed.append(f"{shot_id}: added duration to LTX prompt ({duration}s)")

        # --- 5. FACE STABILITY markers ---
        characters = shot.get("characters", [])
        ltx_prompt = shot.get("ltx_motion_prompt", "")

        if characters and ltx_prompt:
            stability_markers = ["no face morphing", "no morphing", "maintain exact", "consistent features"]
            if not any(marker in ltx_prompt.lower() for marker in stability_markers):
                shot["ltx_motion_prompt"] = ltx_prompt + ", no face morphing, maintain exact character appearance"
                issues_fixed.append(f"{shot_id}: added face stability markers")

        # --- 5b. V16.6: DIRECTOR-INTELLIGENT DIALOGUE & HUMANISM ---
        # Uses director profile, writer pacing, and story bible for cinematic acting guidance
        dialogue = shot.get("dialogue") or shot.get("dialogue_text") or ""
        ltx_prompt = shot.get("ltx_motion_prompt", "")
        emotional_beat = shot.get("emotional_beat") or shot.get("beat_analysis", {}).get("emotional_valence", "") or ""
        shot_role = shot.get("shot_role") or shot.get("type") or "medium"

        # Get director's movement vocabulary for this emotional state
        director_motion = ""
        director_acting_note = ""
        if director_profile:
            movement_vocab = director_profile.get("visual_signature", {}).get("movement_vocabulary", {})
            # Map emotional beat to director's vocabulary
            if emotional_beat in ["dread", "tension", "fear", "horror"]:
                director_motion = movement_vocab.get("horror", movement_vocab.get("tension", ""))
            elif emotional_beat in ["revelation", "hope", "triumph"]:
                director_motion = movement_vocab.get("revelation", "")
            else:
                director_motion = movement_vocab.get("default", "")

            # Get director's sample acting direction
            sample_directions = director_profile.get("sample_direction", [])
            if sample_directions and emotional_beat:
                # Pick direction that matches emotional context
                import random
                director_acting_note = random.choice(sample_directions)

        # Get writer pacing context
        writer_rhythm_note = ""
        if writer_profile:
            rhythm = writer_profile.get("narrative_rhythm", {})
            pacing_type = rhythm.get("default_pacing", "balanced")
            if pacing_type == "slow_burn_to_explosion":
                writer_rhythm_note = "measured deliberate tempo"
            elif pacing_type == "escalating_intensity":
                writer_rhythm_note = "building momentum"
            elif pacing_type == "contemplative":
                writer_rhythm_note = "thoughtful weighted pauses"

        # Build intelligent LTX enhancement
        ltx_additions = []

        # V17.2.4: Add dialogue context with cinematic delivery — PRESERVE FULL DIALOGUE
        # (was truncating at 47 chars, breaking performance and script-awareness)
        if dialogue and "speaking" not in ltx_prompt.lower():
            dialogue_clean = dialogue
            if ":" in dialogue_clean:
                dialogue_clean = dialogue_clean.split(":", 1)[1].strip()
            # V17.2.4: Allow up to 250 chars of dialogue for LTX context (was 47)
            if len(dialogue_clean) > 250:
                dialogue_clean = dialogue_clean[:247] + "..."

            # Cinematic speaking style based on director
            speaking_style = "natural conversational delivery"
            if director_profile:
                actor_direction = director_profile.get("presence", {}).get("actor_direction", "")
                if "minimal" in actor_direction.lower() or "trust" in actor_direction.lower():
                    speaking_style = "restrained naturalistic performance"
                elif "precise" in actor_direction.lower():
                    speaking_style = "measured deliberate delivery"

            ltx_additions.append(f'character speaking: "{dialogue_clean}", {speaking_style}')

        # Add director's movement if relevant
        if director_motion and director_motion not in ltx_prompt:
            ltx_additions.append(director_motion)

        # Add writer's pacing rhythm
        if writer_rhythm_note and writer_rhythm_note not in ltx_prompt:
            ltx_additions.append(writer_rhythm_note)

        # Add actor humanism with emotional context
        if characters:
            humanism_markers = ["breathing", "blinking", "micro-expression", "natural pause", "weight shift"]
            if not any(marker in ltx_prompt.lower() for marker in humanism_markers):
                # Emotional-specific humanism from director's vocabulary
                if emotional_beat in ["dread", "tension", "fear"]:
                    ltx_additions.extend(["held breath", "micro-tension in jaw", "alert stillness"])
                elif emotional_beat in ["grief", "sadness", "loss"]:
                    ltx_additions.extend(["weighted shoulders", "slow deliberate blinks", "internal stillness"])
                elif emotional_beat in ["hope", "revelation"]:
                    ltx_additions.extend(["subtle brightening", "lifted gaze", "gentle exhale"])
                elif emotional_beat in ["horror", "shock"]:
                    ltx_additions.extend(["frozen stillness", "widened eyes", "arrested breath"])
                else:
                    ltx_additions.extend(["natural breathing", "lifelike micro-movements"])

        # Add director's acting note as subtle guidance
        if director_acting_note and len(director_acting_note) < 50:
            ltx_additions.append(f"performance: {director_acting_note.lower()}")

        # Apply all enhancements
        if ltx_additions:
            enhanced_ltx = ltx_prompt + ", " + ", ".join(ltx_additions)
            # V16.6: De-duplicate LTX prompt parts (fix repeated terms)
            parts = [p.strip() for p in enhanced_ltx.split(",") if p.strip()]
            seen = set()
            deduped = []
            for part in parts:
                if part.lower() not in seen:
                    seen.add(part.lower())
                    deduped.append(part)
            enhanced_ltx = ", ".join(deduped)
            shot["ltx_motion_prompt"] = enhanced_ltx
            shot["ltx_director_enhanced"] = True
            issues_fixed.append(f"{shot_id}: director-intelligent LTX enhancement")

        # --- 6. NEGATIVE PROMPTS ---
        if "negative_prompt" not in shot or not shot["negative_prompt"]:
            shot["negative_prompt"] = "blurry, distorted face, morphing, low quality, text, watermark, extra limbs"
            issues_fixed.append(f"{shot_id}: added negative_prompt")

        # --- 7. V21.10 FINAL SAFETY: Re-inject NO morphing on non-character shots ---
        # This is the LAST step in the per-shot loop — runs AFTER all enhancers/enrichers
        # that may have overwritten the LTX prompt. Non-character shots MUST have NO morphing.
        _final_ltx = (shot.get("ltx_motion_prompt", "") or "").lower()
        _final_has_chars = len(shot.get("characters", [])) > 0
        if not _final_has_chars and "no morphing" not in _final_ltx:
            shot["ltx_motion_prompt"] = (shot.get("ltx_motion_prompt", "") or "").rstrip(",. ") + ", NO morphing, NO face generation, environment only"
            issues_fixed.append(f"{shot_id}: FINAL SAFETY — re-injected NO morphing for non-character shot")

    # =========================================================================
    # PHASE 3: CRITIC VALIDATION
    # =========================================================================

    # Update metadata
    data["metadata"] = data.get("metadata", {})
    data["metadata"]["v13_fixed_at"] = datetime.now().isoformat()
    data["metadata"]["v13_issues_fixed"] = len(issues_fixed)
    data["metadata"]["v13_intelligent_mode"] = has_intelligent_enhancer

    # Calculate new total duration
    total_duration = sum(s.get("duration", 0) for s in shots)

    # =========================================================================
    # V16.5.1: DIRECTOR-INTELLIGENT VARIETY REBALANCE
    # =========================================================================
    # A real director uses VARIETY across all LTX durations, not uniform scaling.
    # KEY CHANGE: Use TIERED distribution for natural pacing:
    # - Tier 1 (establishing/wide/ritual): 54-60s extended
    # - Tier 2 (medium with dialogue): 24-48s extended variety
    # - Tier 3 (medium action): 14-20s standard
    # - Tier 4 (close/reaction/insert): 6-12s short anchors
    # CRITICAL: LTX requires EVEN-ONLY durations. All values must be even.
    LTX_STANDARD = [6, 8, 10, 12, 14, 16, 18, 20]
    LTX_EXTENDED = [24, 30, 36, 40, 48, 54, 60]  # Even-only for clean segmentation
    LTX_ALL = LTX_STANDARD + LTX_EXTENDED

    current_total = sum(s.get("duration", 0) for s in shots)
    deficit = target_runtime - current_total
    was_over_budget = deficit < -100  # V16.7.1: Track if we need budget-aware reduction

    print(f"[DIRECTOR_REBALANCE] deficit={deficit}, target={target_runtime}, current={current_total}, over_budget={was_over_budget}")
    if deficit > 0:
        # Categorize shots into 4 tiers based on shot role
        tier1_shots = []  # Establishing/wide - can extend to 55-60s
        tier2_shots = []  # Medium with dialogue - can extend to 25-45s
        tier3_shots = []  # Medium action - stays standard 14-20s
        tier4_shots = []  # Close/reaction - stays short 6-12s

        for shot in shots:
            # V16.5: Prioritize shot_type over type (expansion sets shot_type)
            shot_type = (shot.get("shot_type") or shot.get("type") or "medium").lower()
            beat_type = (shot.get("beat_type") or shot.get("shot_role") or "action").lower()
            word_count = len((shot.get("dialogue") or "").split())
            current = shot.get("duration", 10)

            if shot_type in ["wide", "ws", "establishing", "master", "extreme_wide"]:
                tier1_shots.append((shot, current))
            elif beat_type in ["ritual", "ritual_establishing", "contemplative", "introspection"]:
                tier1_shots.append((shot, current))
            elif word_count > 10:  # Significant dialogue
                tier2_shots.append((shot, current))
            elif shot_type in ["close", "cu", "closeup", "ecu", "insert", "detail"]:
                tier4_shots.append((shot, current))
            elif beat_type in ["reaction", "listening", "insert"]:
                tier4_shots.append((shot, current))
            else:
                tier3_shots.append((shot, current))

        print(f"[DIRECTOR_REBALANCE] Categorized: T1={len(tier1_shots)}, T2={len(tier2_shots)}, T3={len(tier3_shots)}, T4={len(tier4_shots)}")

        time_added = 0
        remaining = deficit

        # --- TIER 1: Extend to 54-60s with alternation (EVEN-ONLY) ---
        if remaining > 0 and tier1_shots:
            extended_targets = [54, 60, 54, 60]  # Even-only alternation
            for i, (shot, current) in enumerate(tier1_shots):
                if remaining <= 0:
                    break
                target = extended_targets[i % len(extended_targets)]
                add = target - current
                if add > 0:
                    shot["duration"] = target
                    shot["duration_seconds"] = target
                    shot["extended_shot"] = True
                    shot["duration_tier"] = "T1_establishing"
                    time_added += add
                    remaining -= add

        # --- TIER 2: Extend to 24-48s with VARIETY (EVEN-ONLY) ---
        if remaining > 0 and tier2_shots:
            # Even-only variety across extended range: 24, 30, 36, 40, 48
            extended_targets = [24, 30, 36, 40, 48, 40, 36, 30, 24]
            for i, (shot, current) in enumerate(tier2_shots):
                if remaining <= 0:
                    break
                target = extended_targets[i % len(extended_targets)]
                if target > current:
                    add = target - current
                    shot["duration"] = target
                    shot["duration_seconds"] = target
                    shot["extended_shot"] = True
                    shot["duration_tier"] = "T2_dialogue"
                    time_added += add
                    remaining -= add

        # --- TIER 3: Medium action - use full standard range 14-20s ---
        if remaining > 0 and tier3_shots:
            standard_targets = [14, 16, 18, 20, 18, 16, 14]
            for i, (shot, current) in enumerate(tier3_shots):
                if remaining <= 0:
                    break
                target = standard_targets[i % len(standard_targets)]
                if target > current:
                    add = target - current
                    shot["duration"] = target
                    shot["duration_seconds"] = target
                    shot["extended_shot"] = False
                    shot["duration_tier"] = "T3_medium"
                    time_added += add
                    remaining -= add

        # --- TIER 4: Anchors stay short with variety 6-12s ---
        # These provide pacing contrast - apply variety but don't extend
        tier4_targets = [6, 8, 10, 12, 10, 8, 6]
        for i, (shot, current) in enumerate(tier4_shots):
            target = tier4_targets[i % len(tier4_targets)]
            shot["duration"] = target
            shot["duration_seconds"] = target
            shot["extended_shot"] = False
            shot["duration_tier"] = "T4_anchor"

        # Recalculate total and check if we need to add more time
        total_duration = sum(s.get("duration", 0) for s in shots)
        still_short = target_runtime - total_duration

        # --- CATCH-UP PASS: If still under target, bump eligible shots to next LTX value ---
        if still_short > 50:  # More than 50s short
            # Start with tier3 shots (most to gain without going extended)
            tier3_by_dur = sorted(tier3_shots, key=lambda x: x[0].get("duration", 0))
            for shot, _ in tier3_by_dur:
                if still_short <= 0:
                    break
                current = shot.get("duration", 10)
                if current < 20:
                    # Find next LTX standard value
                    current_idx = LTX_STANDARD.index(current) if current in LTX_STANDARD else -1
                    if current_idx >= 0 and current_idx < len(LTX_STANDARD) - 1:
                        next_val = LTX_STANDARD[current_idx + 1]
                        add = next_val - current
                        shot["duration"] = next_val
                        shot["duration_seconds"] = next_val
                        still_short -= add

            # If still short, bump some tier2 shots to higher extended values
            if still_short > 50:
                tier2_by_dur = sorted(tier2_shots, key=lambda x: x[0].get("duration", 0))
                for shot, _ in tier2_by_dur:
                    if still_short <= 0:
                        break
                    current = shot.get("duration", 10)
                    if current < 55 and current in LTX_EXTENDED:
                        current_idx = LTX_EXTENDED.index(current)
                        if current_idx < len(LTX_EXTENDED) - 2:
                            next_val = LTX_EXTENDED[current_idx + 1]
                            add = next_val - current
                            shot["duration"] = next_val
                            shot["duration_seconds"] = next_val
                            still_short -= add

            total_duration = sum(s.get("duration", 0) for s in shots)

        # Log variety distribution
        duration_counts = {}
        for s in shots:
            d = s.get("duration", 0)
            duration_counts[d] = duration_counts.get(d, 0) + 1
        variety_str = ", ".join(f"{d}s:{c}" for d, c in sorted(duration_counts.items()))

        issues_fixed.append(f"DIRECTOR REBALANCE: T1({len(tier1_shots)}) T2({len(tier2_shots)}) T3({len(tier3_shots)}) T4({len(tier4_shots)})")
        advisory_notes.append(f"Duration variety: {variety_str}")
        advisory_notes.append(f"Total: {total_duration}s = {total_duration/60:.1f} min ({total_duration/target_runtime*100:.0f}% of target)")
    elif deficit < -100:
        # V16.7.1: OVER BUDGET - actively reduce durations
        surplus = -deficit
        advisory_notes.append(f"Over target by {surplus}s - applying budget-aware reduction")
        was_over_budget = True  # Flag for later use

        # Categorize shots for reduction (same logic as extension)
        for shot in shots:
            shot_type = (shot.get("shot_type") or shot.get("type") or "medium").lower()
            current = shot.get("duration", shot.get("duration_seconds", 20))

            # Reduce based on shot type - cap to budget-friendly values
            if shot_type in ["wide", "ws", "establishing", "master", "extreme_wide"]:
                # Establishing: cap to 20s max (from 54-60s)
                if current > 20:
                    shot["duration"] = 20
                    shot["duration_seconds"] = 20
                    shot["duration_tier"] = "T1_establishing_reduced"
                    shot["extended_shot"] = False
            elif shot_type in ["close", "cu", "closeup", "ecu", "insert", "detail"]:
                # Close: cap to 8s
                if current > 8:
                    shot["duration"] = 8
                    shot["duration_seconds"] = 8
                    shot["duration_tier"] = "T4_anchor"
                    shot["extended_shot"] = False
            else:
                # Medium: cap to 14s
                if current > 14:
                    shot["duration"] = 14
                    shot["duration_seconds"] = 14
                    shot["duration_tier"] = "T3_medium_reduced"
                    shot["extended_shot"] = False

        total_duration = sum(s.get("duration", 0) for s in shots)
        issues_fixed.append(f"BUDGET_REDUCTION: Reduced durations to hit target (now {total_duration}s)")

    # =========================================================================
    # V16.5.1 VARIETY ENFORCEMENT - Runs ALWAYS regardless of deficit
    # =========================================================================
    # Problem 1: When total >= target, tiering skipped, leaving clustered durations
    # Problem 2: Shots have tier assigned but WRONG duration (e.g., T3_medium with 12s)
    # Solution: Enforce correct duration ranges based on TIER, applying variety
    # V16.7.1: SKIP variety enforcement entirely if we were over budget
    variety_applied = False

    # V16.7.1: If we were over budget, skip variety enforcement to preserve budget reductions
    skip_variety = was_over_budget
    print(f"[VARIETY_ENFORCEMENT] skip_variety={skip_variety}, was_over_budget={was_over_budget}")

    # Valid duration ranges by tier (LTX even-only)
    # V16.7.1: Use budget-aware ranges when over target
    if skip_variety:
        tier1_variety = [16, 18, 20, 18, 16]      # Reduced establishing
        tier2_variety = [12, 14, 16, 18, 16, 14]  # Reduced dialogue
        tier3_variety = [10, 12, 14, 12, 10]      # Reduced medium
        tier4_variety = [6, 8, 6, 8]              # Anchors stay short
        advisory_notes.append("Using budget-aware reduced variety ranges")
    else:
        tier1_variety = [54, 60, 54, 60]      # Establishing 54-60s
        tier2_variety = [24, 30, 36, 40, 48, 40, 36, 30, 24]  # Dialogue 24-48s
        tier3_variety = [14, 16, 18, 20, 18, 16, 14]          # Medium 14-20s
        tier4_variety = [6, 8, 10, 12, 10, 8, 6]              # Close 6-12s

    t1_idx = 0
    t2_idx = 0
    t3_idx = 0
    t4_idx = 0

    print(f"[VARIETY_ENFORCEMENT] Starting check for {len(shots)} shots")
    reassignments = 0
    for shot in shots:
        shot_type = (shot.get("type") or shot.get("shot_type") or "medium").lower()
        current_tier = shot.get("duration_tier", "")
        current_dur = shot.get("duration", 0)
        word_count = len((shot.get("dialogue") or "").split())

        # =======================================================================
        # STEP 1: CORRECT TIER ASSIGNMENT (shot_type should dictate tier)
        # =======================================================================
        # Close shots MUST be T4, regardless of what tier was assigned
        if shot_type in ["close", "cu", "closeup", "ecu", "insert", "detail"]:
            if current_tier != "T4_anchor":
                shot["duration_tier"] = "T4_anchor"
                reassignments += 1
                current_tier = "T4_anchor"

        # Wide/establishing shots with no dialogue MUST be T1
        elif shot_type in ["wide", "ws", "establishing", "master", "extreme_wide"]:
            if word_count == 0 and current_tier != "T1_establishing":
                shot["duration_tier"] = "T1_establishing"
                reassignments += 1
                current_tier = "T1_establishing"

        # =======================================================================
        # STEP 2: FIX DURATION TO MATCH TIER
        # =======================================================================
        # T1: Establishing shots - should be 54-60s
        if current_tier == "T1_establishing":
            if current_dur < 54:
                shot["duration"] = tier1_variety[t1_idx % len(tier1_variety)]
                shot["duration_seconds"] = shot["duration"]
                shot["extended_shot"] = True
                t1_idx += 1
                variety_applied = True

        # T2: Dialogue shots - should be 24-48s
        elif current_tier == "T2_dialogue":
            if current_dur < 24:
                shot["duration"] = tier2_variety[t2_idx % len(tier2_variety)]
                shot["duration_seconds"] = shot["duration"]
                shot["extended_shot"] = True
                t2_idx += 1
                variety_applied = True

        # T3: Medium shots - should be 14-20s
        elif current_tier == "T3_medium":
            if current_dur < 14 or current_dur > 20:
                shot["duration"] = tier3_variety[t3_idx % len(tier3_variety)]
                shot["duration_seconds"] = shot["duration"]
                shot["extended_shot"] = False
                t3_idx += 1
                variety_applied = True

        # T4: Close/anchor shots - should be 6-12s
        elif current_tier == "T4_anchor":
            if current_dur < 6 or current_dur > 12:
                shot["duration"] = tier4_variety[t4_idx % len(tier4_variety)]
                shot["duration_seconds"] = shot["duration"]
                shot["extended_shot"] = False
                t4_idx += 1
                variety_applied = True

        # No tier assigned - assign based on shot_type
        elif not current_tier:
            if shot_type in ["close", "cu", "closeup", "ecu", "insert", "detail"]:
                shot["duration"] = tier4_variety[t4_idx % len(tier4_variety)]
                shot["duration_seconds"] = shot["duration"]
                shot["duration_tier"] = "T4_anchor"
                shot["extended_shot"] = False
                t4_idx += 1
                variety_applied = True
            elif shot_type in ["wide", "ws", "establishing", "master", "extreme_wide"]:
                shot["duration"] = tier1_variety[t1_idx % len(tier1_variety)]
                shot["duration_seconds"] = shot["duration"]
                shot["duration_tier"] = "T1_establishing"
                shot["extended_shot"] = True
                t1_idx += 1
                variety_applied = True
            elif shot_type in ["medium", "ms"]:
                shot["duration"] = tier3_variety[t3_idx % len(tier3_variety)]
                shot["duration_seconds"] = shot["duration"]
                shot["duration_tier"] = "T3_medium"
                shot["extended_shot"] = False
                t3_idx += 1
                variety_applied = True

    if reassignments > 0:
        issues_fixed.append(f"TIER_CORRECTION: Reassigned {reassignments} shots to correct tiers based on shot_type")

    if variety_applied:
        total_duration = sum(s.get("duration", 0) for s in shots)
        duration_counts = {}
        for s in shots:
            d = s.get("duration", 0)
            duration_counts[d] = duration_counts.get(d, 0) + 1
        variety_str = ", ".join(f"{d}s:{c}" for d, c in sorted(duration_counts.items()))
        issues_fixed.append(f"VARIETY_ENFORCEMENT: Fixed {t1_idx + t2_idx + t3_idx + t4_idx} duration mismatches (T1:{t1_idx} T2:{t2_idx} T3:{t3_idx} T4:{t4_idx})")
        advisory_notes.append(f"Duration variety (post-enforcement): {variety_str}")

    data["metadata"]["total_duration_seconds"] = total_duration

    # =========================================================================
    # V16.7 FINAL LTX DURATION SYNC - Must happen AFTER all duration changes
    # =========================================================================
    # CRITICAL: DIRECTOR_REBALANCE and VARIETY_ENFORCEMENT modify durations
    # AFTER the initial LTX sync. This pass ensures LTX prompts match FINAL durations.
    ltx_duration_fixes = 0
    import re
    for shot in shots:
        shot_id = shot.get("shot_id", "?")
        final_duration = shot.get("duration", shot.get("duration_seconds", 10))
        ltx_prompt = shot.get("ltx_motion_prompt", "")

        if ltx_prompt:
            # Find duration marker in LTX prompt (e.g., "14s", "24s")
            duration_match = re.search(r'(\d+)s\b', ltx_prompt)
            if duration_match:
                prompt_duration = int(duration_match.group(1))
                if prompt_duration != final_duration:
                    # Replace ALL duration markers with final duration
                    fixed_ltx = re.sub(r'\d+s\b', f'{final_duration}s', ltx_prompt)
                    shot["ltx_motion_prompt"] = fixed_ltx
                    ltx_duration_fixes += 1
            else:
                # No duration marker - add one
                shot["ltx_motion_prompt"] = ltx_prompt.rstrip(", ") + f", {final_duration}s"
                ltx_duration_fixes += 1

    if ltx_duration_fixes > 0:
        issues_fixed.append(f"V16.7_LTX_SYNC: Fixed {ltx_duration_fixes} LTX duration mismatches (final pass)")

    # =========================================================================
    # V16.7 EXTENDED SHOT SEGMENTS - Ensure >20s shots have precomputed segments
    # =========================================================================
    segment_fixes = 0
    STITCHING_THRESHOLD = 20
    for shot in shots:
        shot_id = shot.get("shot_id", "?")
        duration = shot.get("duration", shot.get("duration_seconds", 10))

        if duration > STITCHING_THRESHOLD:
            shot["extended_shot"] = True
            shot["requires_stitching"] = True

            # Generate segments if missing
            if "segments" not in shot or not shot["segments"]:
                # Calculate segment plan based on duration
                # LTX V2 max segment = 20s, so split into even chunks
                num_segments = (duration + 19) // 20  # Ceiling division
                segment_duration = duration / num_segments

                segments = []
                for i in range(num_segments):
                    start_time = i * segment_duration
                    end_time = (i + 1) * segment_duration
                    segments.append({
                        "segment_index": i,
                        "start_time": round(start_time, 1),
                        "end_time": round(end_time, 1),
                        "duration": round(segment_duration, 1),
                        "status": "pending"
                    })

                shot["segments"] = segments
                segment_fixes += 1

    if segment_fixes > 0:
        issues_fixed.append(f"V16.7_SEGMENTS: Generated segments for {segment_fixes} extended shots (>20s)")

    # =========================================================================
    # V16.7 NANO PROMPT DEDUPLICATION - Prevent enhancement bloat
    # =========================================================================
    # Problem: Running fix-v16 multiple times adds duplicate enhancements
    # Solution: Deduplicate comma-separated parts while preserving order
    nano_dedup_fixes = 0
    for shot in shots:
        nano_prompt = shot.get("nano_prompt", "")
        if not nano_prompt:
            continue

        # Split into parts and deduplicate while preserving order
        parts = [p.strip() for p in nano_prompt.split(",")]
        seen = set()
        unique_parts = []
        for part in parts:
            # Normalize for comparison (lowercase, strip whitespace)
            key = part.lower().strip()
            if key and key not in seen:
                seen.add(key)
                unique_parts.append(part)

        # Only update if we removed duplicates
        if len(unique_parts) < len(parts):
            deduped = ", ".join(unique_parts)
            shot["nano_prompt"] = deduped
            nano_dedup_fixes += 1

    # Also deduplicate LTX prompts
    ltx_dedup_fixes = 0
    for shot in shots:
        ltx_prompt = shot.get("ltx_motion_prompt", "")
        if not ltx_prompt:
            continue

        parts = [p.strip() for p in ltx_prompt.split(",")]
        seen = set()
        unique_parts = []
        for part in parts:
            key = part.lower().strip()
            if key and key not in seen:
                seen.add(key)
                unique_parts.append(part)

        if len(unique_parts) < len(parts):
            deduped = ", ".join(unique_parts)
            shot["ltx_motion_prompt"] = deduped
            ltx_dedup_fixes += 1

    if nano_dedup_fixes > 0 or ltx_dedup_fixes > 0:
        issues_fixed.append(f"V16.7_DEDUP: Removed duplicates from {nano_dedup_fixes} nano prompts, {ltx_dedup_fixes} LTX prompts")

    # =========================================================================
    # V17.2.6: PROMPT QUALITY VALIDATION — Pre-generation contamination checks
    # =========================================================================
    prompt_quality_report = None
    try:
        prompt_quality_report = validate_prompt_quality(shots, story_bible=story_bible)
        if prompt_quality_report["fixes_applied"] > 0:
            issues_fixed.append(
                f"PROMPT_QUALITY: {prompt_quality_report['fixes_applied']} auto-fixes "
                f"(ellipsis:{prompt_quality_report['details']['ellipsis_fixed']}, "
                f"negatives:{prompt_quality_report['details']['negatives_injected']}, "
                f"framing:{prompt_quality_report['details']['framing_fixed']}, "
                f"dialogue:{prompt_quality_report['details']['dialogue_flow_injected']})"
            )
        if prompt_quality_report["warnings"]:
            for w in prompt_quality_report["warnings"][:5]:
                advisory_notes.append(f"PROMPT_QUALITY_WARN: {w}")
        logger.info(f"[PROMPT_QUALITY] {project}: {prompt_quality_report['summary']}")
    except Exception as pq_err:
        logger.warning(f"[PROMPT_QUALITY] Non-blocking error: {pq_err}")

    # Run critics for validation
    critic_results = {}
    try:
        from CRITIC_AGENT import validate_manifest_for_render, run_preflight_before_render

        manifest_result = validate_manifest_for_render(shots=shots, target_runtime_seconds=target_runtime)
        critic_results["manifest"] = {
            "passed": manifest_result.get("ready_for_render", False),
            "issues": len(manifest_result.get("issues", []))
        }

        preflight_result = run_preflight_before_render(shots=shots, project_type="project")
        critic_results["preflight"] = {
            "passed": preflight_result.get("passed", False),
            "block_count": preflight_result.get("block_count", 0),
            "warn_count": preflight_result.get("warn_count", 0)
        }
    except Exception as e:
        critic_results["error"] = str(e)

    # Re-run DirectorCritic AFTER fixes to get updated scores
    if has_director_critic:
        try:
            director_review_post = get_director_review(shots, story_bible, target_runtime)
            director_advisory = {
                "grade": director_review_post.get("overall_grade", "?"),
                "pacing": director_review_post.get("scores", {}).get("pacing", 0),
                "coverage": director_review_post.get("scores", {}).get("coverage", 0),
                "emotional_arc": director_review_post.get("scores", {}).get("emotional_arc", 0),
                "notes": director_review_post.get("notes", [])[:5]  # Top 5 notes
            }
        except Exception as e:
            pass  # Keep pre-fix advisory if post-fix fails

    # Add director advisory to results
    if director_advisory:
        critic_results["director_advisory"] = director_advisory

    # =========================================================================
    # CHECK 6: SCENE TYPE CLASSIFICATION (V21.2)
    # =========================================================================
    try:
        from tools.scene_type_classifier import apply_scene_classifications
        _sb_data_for_class = None
        try:
            _sb_path_class = project_path / "story_bible.json"
            if _sb_path_class.exists():
                with open(_sb_path_class) as _sbf:
                    _sb_data_for_class = json.load(_sbf)
        except Exception:
            pass
        _class_summary = apply_scene_classifications(shots, _sb_data_for_class)
        _class_types = {sid: info['type'] for sid, info in _class_summary.items()}
        logger.info(f"[FIX-V16] CHECK 6: Scene types classified: {_class_types}")
        issues_fixed.append(f"SCENE_TYPE_CLASSIFICATION: {len(_class_types)} scenes classified")
    except Exception as _class_err:
        logger.warning(f"[FIX-V16] CHECK 6 non-blocking error: {_class_err}")

    # =========================================================================
    # V17.3: COVERAGE SOLVER — Cinematic grammar validation
    # =========================================================================
    coverage_report = None
    try:
        story_bible_data = data.get("story_bible", {})
        if not story_bible_data:
            sb_path = project_path / "story_bible.json"
            if sb_path.exists():
                with open(sb_path) as _sbf:
                    story_bible_data = json.load(_sbf)
        coverage_report = run_coverage_solver(shots, story_bible_data)
        data["_coverage_report"] = {
            "overall_grade": coverage_report["overall_grade"],
            "overall_score": coverage_report["overall_score"],
            "passing_scenes": coverage_report["passing_scenes"],
            "failing_scenes": coverage_report["failing_scenes"],
            "critical_issues": coverage_report["critical_issues"][:10],
            "checked_at": datetime.now().isoformat()
        }
        logger.info(f"[COVERAGE_SOLVER] {project}: Grade {coverage_report['overall_grade']} "
                     f"({coverage_report['overall_score']}/100) — "
                     f"{coverage_report['passing_scenes']}/{coverage_report['total_scenes']} scenes passing "
                     f"in {coverage_report['execution_time_ms']}ms")
        if coverage_report["critical_issues"]:
            logger.warning(f"[COVERAGE_SOLVER] {len(coverage_report['critical_issues'])} critical issue(s)")
        issues_fixed.append(f"COVERAGE_SOLVER: Grade {coverage_report['overall_grade']} ({coverage_report['overall_score']}/100)")
    except Exception as cov_err:
        logger.warning(f"[COVERAGE_SOLVER] Non-blocking error: {cov_err}")

    # =========================================================================
    # V25 CURE 4A: COVERAGE DISTRIBUTION VALIDATION PER SCENE
    # DOCTRINE LAW 225: Every scene must have ≥1 A_GEOGRAPHY shot.
    # If all shots share the same role, the edit has no anchor.
    # =========================================================================
    _cure4_fixes = 0
    try:
        _scene_groups = {}
        for shot in shots:
            sid = shot.get("scene_id", "000")
            _scene_groups.setdefault(sid, []).append(shot)

        for sid, scene_shots in _scene_groups.items():
            roles = [s.get("coverage_role", "") for s in scene_shots]
            a_count = sum(1 for r in roles if r.startswith("A"))

            if a_count == 0 and len(scene_shots) > 1:
                # Promote first establishing/wide shot to A-master
                promoted = False
                for shot in scene_shots:
                    _st = (shot.get("shot_type") or shot.get("type") or "").lower()
                    if _st in ("establishing", "wide", "master", "extreme_wide", "ws", "mws", "closing"):
                        shot["coverage_role"] = "A_GEOGRAPHY"
                        shot["shot_role"] = "GEOGRAPHY"
                        shot["_coverage_promoted"] = True
                        promoted = True
                        _cure4_fixes += 1
                        break

                # If no wide found, promote first shot
                if not promoted:
                    scene_shots[0]["coverage_role"] = "A_GEOGRAPHY"
                    scene_shots[0]["shot_role"] = "GEOGRAPHY"
                    scene_shots[0]["_coverage_promoted"] = True
                    _cure4_fixes += 1

        if _cure4_fixes > 0:
            issues_fixed.append(f"V25_CURE4A: Promoted {_cure4_fixes} shots to A_GEOGRAPHY master")
            logger.info(f"[V25 CURE 4A] Promoted {_cure4_fixes} shots to A_GEOGRAPHY for missing-master scenes")
    except Exception as _c4a_err:
        logger.warning(f"[V25 CURE 4A] Non-blocking error: {_c4a_err}")

    # =========================================================================
    # V25 CURE 4B: CHECK 7E+ — DIALOGUE SHOTS MUST HAVE CHARACTERS
    # DOCTRINE LAW 223: if dialogue_text non-empty and characters=[] → auto-assign
    # =========================================================================
    _cure4b_fixes = 0
    try:
        # Load cast map for character assignment
        _cast_path = project_path / "cast_map.json"
        _cast_map_fix = {}
        if _cast_path.exists():
            with open(_cast_path) as _cf:
                _cast_map_fix = json.load(_cf)

        for shot in shots:
            _dlg = (shot.get("dialogue_text") or "").strip()
            _chars = shot.get("characters") or []
            if _dlg and not _chars:
                # Try to extract character from dialogue prefix (e.g. "THOMAS: ...")
                _dlg_upper = _dlg.upper()
                _assigned = False
                for char_name in _cast_map_fix:
                    if char_name.startswith("_"):
                        continue
                    # Check if character name appears at start of dialogue
                    _cn_upper = char_name.upper()
                    if _dlg_upper.startswith(_cn_upper + ":") or _cn_upper in _dlg_upper[:50]:
                        shot["characters"] = [char_name]
                        shot["_7e_auto_assigned"] = True
                        _cure4b_fixes += 1
                        _assigned = True
                        break

                # Fallback: assign from scene cast if available
                if not _assigned:
                    _scene_chars = set()
                    for other in shots:
                        if other.get("scene_id") == shot.get("scene_id") and other.get("characters"):
                            for c in other["characters"]:
                                _scene_chars.add(c)
                    if _scene_chars:
                        shot["characters"] = [list(_scene_chars)[0]]
                        shot["_7e_auto_assigned"] = True
                        _cure4b_fixes += 1

        if _cure4b_fixes > 0:
            issues_fixed.append(f"V25_CURE4B: Auto-assigned characters to {_cure4b_fixes} dialogue shots")
            logger.info(f"[V25 CURE 4B] Auto-assigned characters to {_cure4b_fixes} orphan dialogue shots")
    except Exception as _c4b_err:
        logger.warning(f"[V25 CURE 4B] Non-blocking error: {_c4b_err}")

    # =========================================================================
    # V21.9 CHECK 7: STANDARD DATA NORMALIZATION (4 automatic fixes)
    # These run EVERY TIME fix-v16 runs — zero manual steps required.
    # =========================================================================

    # --- CHECK 7A: CHARACTER NAME NORMALIZATION ---
    # Parser uses short names (EVELYN, ARTHUR), cast_map uses full names
    # (EVELYN RAVENCROFT, ARTHUR GRAY). This normalizes to full names.
    try:
        _config = get_project_config(project_name)
        _NAME_NORM = _config.name_norm_map
        _name_fixes = 0
        for _shot in shots:
            _chars = _shot.get("characters", [])
            _new_chars = []
            _changed = False
            for _c in _chars:
                _cu = _c.upper().strip()
                if _cu in _NAME_NORM:
                    _new_chars.append(_NAME_NORM[_cu])
                    _changed = True
                else:
                    _new_chars.append(_c)
            if _changed:
                _shot["characters"] = _new_chars
                _name_fixes += 1
        if _name_fixes > 0:
            issues_fixed.append(f"V21.9_NAME_NORM: {_name_fixes} shots normalized to full character names")
            logger.info(f"[FIX-V16 V21.9] Name normalization: {_name_fixes} shots fixed")
    except Exception as _nn_err:
        logger.warning(f"[FIX-V16 V21.9] Name normalization non-blocking error: {_nn_err}")

    # --- CHECK 7B: CHILD V.O. TAGGING ---
    # CHILD is voice-over only — never on camera. Strip from characters[],
    # mark dialogue as V.O., ensure no face-lock or character ref is generated.
    try:
        _child_fixes = 0
        for _shot in shots:
            _chars = _shot.get("characters", [])
            _has_child = any("CHILD" in c.upper() for c in _chars)
            if _has_child:
                # Remove CHILD from visible characters
                _shot["characters"] = [c for c in _chars if "CHILD" not in c.upper()]
                # Mark dialogue as V.O. if CHILD is speaking
                _dlg = _shot.get("dialogue_text", "") or ""
                if _dlg and "CHILD" in _dlg.upper():
                    _shot["_child_vo"] = True
                    _shot["_vo_character"] = "CHILD"
                    # Ensure no on-camera treatment
                    _nano = _shot.get("nano_prompt", "") or ""
                    if "CHILD" in _nano.upper() and "voice" not in _nano.lower():
                        _shot["nano_prompt"] = _nano + " (CHILD voice heard off-camera, NOT visible in frame)"
                _child_fixes += 1
        if _child_fixes > 0:
            issues_fixed.append(f"V21.9_CHILD_VO: {_child_fixes} shots — CHILD stripped from characters, marked V.O.")
            logger.info(f"[FIX-V16 V21.9] CHILD V.O. tagging: {_child_fixes} shots fixed")
    except Exception as _cv_err:
        logger.warning(f"[FIX-V16 V21.9] CHILD V.O. tagging non-blocking error: {_cv_err}")

    # --- CHECK 7C: INTERCUT SCENE SEPARATION ---
    # Intercut = phone call / cross-cutting between TWO locations.
    # Each shot shows ONE character at THEIR location. The other character
    # is heard (V.O.) but NOT visible. Parser puts both characters on every
    # shot because it sees both names in dialogue — we fix that here.
    #
    # Logic: Determine PRIMARY visible character from dialogue (who speaks
    # first in the line) or from shot description. That character gets the
    # shot; the other becomes V.O. Each character stays at their own location.
    try:
        _intercut_fixes = 0
        _manifest_list = data.get("scene_manifest", [])
        _intercut_scenes = {}  # scene_id → {char_name: location}

        for _sc in _manifest_list:
            if not isinstance(_sc, dict):
                continue
            if not (_sc.get("_intercut") or _sc.get("is_intercut")):
                continue
            _sid = _sc.get("scene_id", "")
            _primary_loc = _sc.get("location", "")
            _secondary_loc = _sc.get("secondary_location", "")
            if not _sid or not _secondary_loc:
                continue

            # Build character → location map (expand short names)
            _raw_map = _sc.get("intercut_location_map", {})
            _full_map = {}
            for _cn, _loc in _raw_map.items():
                _full_name = _NAME_NORM.get(_cn.upper().strip(), _cn.upper().strip())
                _full_map[_full_name] = _loc

            # Auto-assign unmapped characters using DIALOGUE ORDER
            # V21.10 FIX: Don't hardcode "LAWYER" → secondary. Instead, the FIRST
            # character to speak in the scene is at the PRIMARY location (where the
            # scene heading says we are). The SECOND unique speaker is at the
            # secondary location. This matches screenplay convention: INTERCUT means
            # "we're already at Location A, now cut between A and B."
            _all_scene_chars = set()
            _first_speaker = None
            _second_speaker = None
            for _shot in shots:
                if _shot.get("scene_id") == _sid:
                    for _c in _shot.get("characters", []):
                        _cu = _c.upper().strip()
                        _all_scene_chars.add(_cu)
                        # Track first two unique speakers from dialogue order
                        if _shot.get("dialogue_text") or _shot.get("dialogue_beats"):
                            if _first_speaker is None:
                                _first_speaker = _cu
                            elif _cu != _first_speaker and _second_speaker is None:
                                _second_speaker = _cu
            for _asc in _all_scene_chars:
                if _asc not in _full_map:
                    if _second_speaker and _asc == _second_speaker:
                        _full_map[_asc] = _secondary_loc  # 2nd speaker is at remote location
                    else:
                        _full_map[_asc] = _primary_loc  # 1st speaker + others at primary

            if _full_map:
                _intercut_scenes[_sid] = _full_map
                _sc["intercut_location_map"] = _full_map
                _sc["_intercut"] = True
                logger.info(f"[FIX-V16 V21.9] Intercut map for scene {_sid}: {_full_map}")

        # Now process each shot in intercut scenes
        for _shot in shots:
            _sid = _shot.get("scene_id", "")
            if _sid not in _intercut_scenes:
                continue
            _ic_map = _intercut_scenes[_sid]
            _chars = _shot.get("characters", [])
            if len(_chars) <= 1:
                # Single character or establishing — just fix location + prompt
                if _chars:
                    _cu = _chars[0].upper().strip()
                    _new_loc = _ic_map.get(_cu)
                    if _new_loc and _shot.get("location") != _new_loc:
                        _old_loc = _shot.get("location", "")
                        _shot["location"] = _new_loc
                        # Fix prompt text too
                        _nano = _shot.get("nano_prompt", "") or ""
                        if _old_loc and _old_loc in _nano:
                            _shot["nano_prompt"] = _nano.replace(_old_loc, _new_loc)
                        _intercut_fixes += 1
                continue

            # MULTI-CHARACTER SHOT in intercut → determine PRIMARY visible character
            # In a phone call intercut, each shot shows the person we're WATCHING.
            # We determine this by finding who is the EMOTIONAL FOCUS:
            #   - If EVELYN reacts/responds/emotes → show EVELYN at apartment
            #   - If LAWYER delivers information → show LAWYER at office
            # The parser often prefixes action lines with "LAWYER:" even when
            # describing Evelyn's reactions, so we look for actual CHARACTER ACTIONS
            # (frowns, pacing, stops, looks, etc.) not just dialogue headers.
            import re as _re_ic
            _dlg = (_shot.get("dialogue_text", "") or "")
            _nano = (_shot.get("nano_prompt", "") or "").upper()

            # Build a map of each character's SHORT name for pattern matching
            _char_shorts = {}
            for _c in _chars:
                _cn_full = _c.upper().strip()
                _cn_short = _c.split()[0].upper() if _c else _c.upper()
                _char_shorts[_cn_full] = _cn_short

            # Strategy: count EMOTIONAL FOCUS signals per character
            _focus_scores = {_c.upper().strip(): 0 for _c in _chars}

            # Signal 1: Character SPEAKS actual dialogue (quoted or direct speech)
            # Look for "CHARNAME: <dialogue text>" where text is actual speech
            for _cn_full, _cn_short in _char_shorts.items():
                # Find all "CHARNAME: <text>" segments
                _speak_pattern = _re_ic.compile(
                    r'\b' + _re_ic.escape(_cn_short) + r':\s*([^|]*)',
                    _re_ic.IGNORECASE
                )
                for _m in _speak_pattern.finditer(_dlg):
                    _speech = _m.group(1).strip()
                    # Is this actual dialogue (starts with quote, question, statement)?
                    # Or is it an action description (mentions other character)?
                    _is_action_desc = False
                    for _other_full, _other_short in _char_shorts.items():
                        if _other_full != _cn_full and _other_short.lower() in _speech.lower()[:30]:
                            _is_action_desc = True
                            break
                    if _is_action_desc:
                        # "LAWYER: Evelyn frowns" → focus is on EVELYN, not LAWYER
                        for _other_full, _other_short in _char_shorts.items():
                            if _other_full != _cn_full and _other_short.lower() in _speech.lower()[:30]:
                                _focus_scores[_other_full] += 2
                    else:
                        # Actual dialogue by this character
                        _focus_scores[_cn_full] += 1

            # Signal 2: Character performs PHYSICAL ACTION in dialogue text
            _reaction_words = ["frowns", "pacing", "stops", "looks", "stares",
                              "turns", "sits", "stands", "reaches", "picks up",
                              "puts down", "sighs", "hesitates", "pauses", "nods",
                              "shakes", "freezes", "processing", "absorbing", "reacts"]
            for _cn_full, _cn_short in _char_shorts.items():
                _dlg_lower = _dlg.lower()
                _cn_lower = _cn_short.lower()
                if _cn_lower in _dlg_lower:
                    for _rw in _reaction_words:
                        if _rw in _dlg_lower:
                            # Check if reaction word is near character name
                            _name_pos = _dlg_lower.find(_cn_lower)
                            _rw_pos = _dlg_lower.find(_rw)
                            if abs(_name_pos - _rw_pos) < 60:
                                _focus_scores[_cn_full] += 2

            # Pick character with highest focus score
            _vis_char = max(_focus_scores, key=_focus_scores.get) if any(_focus_scores.values()) else _chars[0].upper().strip()

            # Fallback: if all scores are 0, use nano_prompt first mention
            if all(v == 0 for v in _focus_scores.values()):
                _vis_char = _chars[0].upper().strip()
                for _c in _chars:
                    _cn_short = _c.split()[0].upper() if _c else _c.upper()
                    if _cn_short in _nano[:100]:
                        _vis_char = _c.upper().strip()
                        break

            # Set this shot to show ONLY the primary visible character
            _vo_chars = [c for c in _chars if c.upper().strip() != _vis_char]
            _shot["characters"] = [c for c in _chars if c.upper().strip() == _vis_char]
            if _vo_chars:
                _shot["_intercut_vo_characters"] = _vo_chars
                _shot["_intercut"] = True

            # Set location based on visible character
            _new_loc = _ic_map.get(_vis_char)
            if _new_loc and _shot.get("location") != _new_loc:
                _old_loc = _shot.get("location", "")
                _shot["location"] = _new_loc
                # Also fix the prompt text — replace old location reference
                _nano = _shot.get("nano_prompt", "") or ""
                if _old_loc and _old_loc in _nano:
                    _shot["nano_prompt"] = _nano.replace(_old_loc, _new_loc)
                elif _old_loc.upper() and f"at {_old_loc.upper()}" in _nano.upper():
                    import re as _re_loc
                    _shot["nano_prompt"] = _re_loc.sub(
                        _re_loc.escape(f"at {_old_loc}"), f"at {_new_loc}",
                        _nano, flags=_re_loc.IGNORECASE, count=1
                    )
                _intercut_fixes += 1

        if _intercut_fixes > 0:
            issues_fixed.append(f"V21.9_INTERCUT: {_intercut_fixes} shots separated (1 character per shot, correct location)")
            logger.info(f"[FIX-V16 V21.9] Intercut separation: {_intercut_fixes} shots fixed — each shows 1 visible character at their location")
    except Exception as _ic_err:
        logger.warning(f"[FIX-V16 V21.9] Intercut separation non-blocking error: {_ic_err}")

    # --- CHECK 7D: SCENE ALIGNMENT VERIFICATION ---
    # Verify scene_manifest covers all scene_ids found in shots.
    # Auto-create stub entries for any missing scenes.
    try:
        _shot_scenes = set()
        for _shot in shots:
            _sid = _shot.get("scene_id", "")
            if _sid:
                _shot_scenes.add(_sid)
        _manifest_scenes = set()
        for _sc in data.get("scene_manifest", []):
            if isinstance(_sc, dict):
                _manifest_scenes.add(_sc.get("scene_id", ""))
        _missing = _shot_scenes - _manifest_scenes
        if _missing:
            _manifest_list = data.get("scene_manifest", [])
            for _ms in sorted(_missing):
                # Find first shot in this scene for location data
                _first_shot = next((s for s in shots if s.get("scene_id") == _ms), None)
                _stub = {
                    "scene_id": _ms,
                    "location": _first_shot.get("location", "UNKNOWN") if _first_shot else "UNKNOWN",
                    "characters": list(set(c for s in shots if s.get("scene_id") == _ms for c in s.get("characters", []))),
                    "_auto_created": True,
                    "_created_by": "fix-v16-v21.9"
                }
                _manifest_list.append(_stub)
            data["scene_manifest"] = _manifest_list
            issues_fixed.append(f"V21.9_SCENE_ALIGN: {len(_missing)} missing scenes added to manifest: {sorted(_missing)}")
            logger.info(f"[FIX-V16 V21.9] Scene alignment: added {len(_missing)} missing scenes: {sorted(_missing)}")
    except Exception as _sa_err:
        logger.warning(f"[FIX-V16 V21.9] Scene alignment non-blocking error: {_sa_err}")

    # --- CHECK 7E: POPULATE CHARACTERS FROM DIALOGUE + LANDSCAPE SAFETY ---
    # Historical issues #9, #16: shots with dialogue but empty characters[],
    # and landscape/B-roll shots with human body language in prompts.
    try:
        import re as _re_7e
        _config_7e = get_project_config(project_name)
        _NAME_NORM_7E = _config_7e.name_norm_map
        _KNOWN_CHARS_7E = set(_NAME_NORM_7E.values()) | set(_config_7e.canonical_characters.keys())

        _char_pop_count = 0
        _landscape_clean_count = 0

        for _shot in shots:
            _chars = _shot.get("characters", [])
            _dlg = (_shot.get("dialogue_text", "") or _shot.get("dialogue", "") or "").strip()
            _sid = _shot.get("shot_id", "")
            _is_child_vo = _shot.get("_child_vo", False)

            # PART A: Populate characters from dialogue for non-V.O. shots with empty chars
            if (not _chars or len(_chars) == 0) and _dlg and not _is_child_vo:
                # Extract character names from dialogue (CHARNAME: text pattern)
                _dlg_chars = _re_7e.findall(r'^([A-Z][A-Z\s.]+?):', _dlg, _re_7e.MULTILINE)
                _resolved = []
                _seen = set()
                for _dc in _dlg_chars:
                    _dc_clean = _dc.strip().upper()
                    # Normalize short names
                    _dc_full = _NAME_NORM_7E.get(_dc_clean, _dc_clean)
                    if _dc_full not in _seen and _dc_full in _KNOWN_CHARS_7E:
                        _resolved.append(_dc_full)
                        _seen.add(_dc_full)
                if _resolved:
                    _shot["characters"] = _resolved
                    _char_pop_count += 1
                    logger.info(f"[FIX-V16 V21.9 CHECK 7E] {_sid}: populated characters from dialogue: {_resolved}")

            # PART B: Strip human body language from truly no-character shots
            _chars_after = _shot.get("characters", [])
            if not _chars_after or len(_chars_after) == 0:
                # V21.10 FIX: "NO morphing" is a VALID generation directive for non-char shots
                # It prevents LTX from generating morphing artifacts. Do NOT strip it.
                # "face stable" IS human-specific (references a face) — strip that.
                _HUMAN_STRIP = [
                    r'face stable[^,]*,?\s*',
                    r'breathing[^,]*,?\s*', r'micro[- ]?expression[^,]*,?\s*',
                    r'blinks?[^,]*,?\s*', r'chest rise[^,]*,?\s*',
                    r'character performs:[^,]*,?\s*', r'character speaks:[^,]*,?\s*',
                    r'character reacts:[^,]*,?\s*', r'performance:[^,]*,?\s*',
                    r'subtext:[^,]*,?\s*',
                ]
                _did_clean = False
                for _prompt_key in ["ltx_motion_prompt", "nano_prompt"]:
                    _ptxt = _shot.get(_prompt_key, "") or ""
                    _orig = _ptxt
                    for _hp in _HUMAN_STRIP:
                        _ptxt = _re_7e.sub(_hp, '', _ptxt, flags=_re_7e.IGNORECASE)
                    _ptxt = _re_7e.sub(r'\s{2,}', ' ', _ptxt).strip()
                    if _ptxt != _orig:
                        _shot[_prompt_key] = _ptxt
                        _did_clean = True
                # V21.10: ALWAYS ensure non-char shots have NO morphing in LTX
                _ltx_7e = (_shot.get("ltx_motion_prompt", "") or "").lower()
                if "no morphing" not in _ltx_7e:
                    _shot["ltx_motion_prompt"] = (_shot.get("ltx_motion_prompt", "") or "").rstrip(",. ") + ", NO morphing, NO face generation, environment only"
                    _did_clean = True
                if _did_clean:
                    _landscape_clean_count += 1

        if _char_pop_count > 0:
            issues_fixed.append(f"V21.9_CHAR_POP: {_char_pop_count} shots populated characters from dialogue")
            logger.info(f"[FIX-V16 V21.9 CHECK 7E] Populated characters for {_char_pop_count} shots from dialogue")
        if _landscape_clean_count > 0:
            issues_fixed.append(f"V21.9_LANDSCAPE_CLEAN: {_landscape_clean_count} no-character shots cleaned of human body language")
            logger.info(f"[FIX-V16 V21.9 CHECK 7E] Cleaned {_landscape_clean_count} landscape shots of human body language")
    except Exception as _7e_err:
        logger.warning(f"[FIX-V16 V21.9] CHECK 7E non-blocking error: {_7e_err}")

    # V18.2: CONTINUITY STATE ENRICHMENT — add state_in/state_out per shot
    try:
        from atlas_agents.continuity_gate import enrich_shots_with_state
        # Group shots by scene for sequential state tracking
        _scenes_for_state = {}
        for _s in shots:
            _sid = _s.get("scene_id", "001")
            _scenes_for_state.setdefault(_sid, []).append(_s)
        _total_enriched = 0
        for _sid, _scene_shots in _scenes_for_state.items():
            _total_enriched += enrich_shots_with_state(_scene_shots, _sid)
        logger.info(f"[FIX-V16] V18.2 Continuity state: enriched {_total_enriched} shots with state_in/state_out + coverage_role")
        issues_fixed.append(f"CONTINUITY_STATE: {_total_enriched} shots enriched with state fields")
    except Exception as _cs_err:
        logger.warning(f"[FIX-V16] Continuity state non-blocking error: {_cs_err}")

    # V22.0: ACTOR INTENT LAYER — per-character emotion, eyeline, micro-action, tempo
    # Injects psychological/physical intent into nano_prompt + ltx_motion_prompt
    try:
        if ACTOR_INTENT_AVAILABLE:
            _story_bible_for_intent = {}
            if story_bible_path.exists():
                with open(story_bible_path) as _sbf_intent:
                    _story_bible_for_intent = json.load(_sbf_intent)
            _prev_count = len([s for s in shots if "actor_intent" in s])
            _enriched_shots = enrich_shot_plan_with_intent(shots, _story_bible_for_intent)
            # Replace shots in-place with enriched versions
            for _idx, _es in enumerate(_enriched_shots):
                shots[_idx] = _es
            _new_count = len([s for s in shots if "actor_intent" in s])
            _intent_enriched = _new_count - _prev_count
            if _intent_enriched > 0:
                issues_fixed.append(f"V22.0_ACTOR_INTENT: {_intent_enriched} shots enriched with character intent (eyeline, micro-action, tempo)")
                logger.info(f"[FIX-V16 V22.0] Actor Intent Layer: enriched {_intent_enriched}/{len(shots)} shots")
            else:
                logger.info(f"[FIX-V16 V22.0] Actor Intent Layer: no new shots needed intent enrichment")
        else:
            logger.info("[FIX-V16 V22.0] Actor Intent Layer not available, skipping")
    except Exception as _ai_err:
        logger.warning(f"[FIX-V16 V22.0] Actor Intent non-blocking error: {_ai_err}")

    # V22.0: DELTA PROMPT BUILDER — continuity locks + shot deltas for chained shots
    # Computes what CHANGED between consecutive shots, builds delta-only prompts
    try:
        if DELTA_PROMPT_AVAILABLE:
            _delta_shots, _delta_results = enrich_shots_with_deltas(shots)
            _delta_count = sum(1 for r in _delta_results if not r.is_anchor and r.delta_nano_prompt)
            _chain_groups = len(set(r.shot_id[:3] for r in _delta_results)) if _delta_results else 0
            if _delta_count > 0:
                # Replace shots in-place with delta-enriched versions
                for _idx, _ds in enumerate(_delta_shots):
                    shots[_idx] = _ds
                issues_fixed.append(f"V22.0_DELTA_PROMPTS: {_delta_count} delta prompts built, {len(_delta_results)} shots processed")
                logger.info(f"[FIX-V16 V22.0] Delta Prompt Builder: {_delta_count} deltas, {len(_delta_results)} results")
            else:
                logger.info(f"[FIX-V16 V22.0] Delta Prompt Builder: {len(_delta_results)} results, 0 deltas needed")
        else:
            logger.info("[FIX-V16 V22.0] Delta Prompt Builder not available, skipping")
    except Exception as _dp_err:
        logger.warning(f"[FIX-V16 V22.0] Delta Prompt Builder non-blocking error: {_dp_err}")

    # V22.0: CONTINUITY STORE — persist state_in/state_out to disk for pipeline restarts
    try:
        if CONTINUITY_STORE_AVAILABLE:
            _cont_store = ContinuityStore(str(project_path))
            _cont_scenes = 0
            for _s in shots:
                if _s.get("state_out") and any(v for v in _s["state_out"].values() if v):
                    _cont_store.update_from_shot(_s)
                    _cont_scenes += 1
            if _cont_scenes > 0:
                _cont_store.save()
                issues_fixed.append(f"V22.0_CONTINUITY_STORE: {_cont_scenes} shots persisted to continuity_state.json")
                logger.info(f"[FIX-V16 V22.0] Continuity Store: persisted {_cont_scenes} shots to disk")
            else:
                logger.info(f"[FIX-V16 V22.0] Continuity Store: no state_out data to persist yet")
        else:
            logger.info("[FIX-V16 V22.0] Continuity Store not available, skipping")
    except Exception as _cs2_err:
        logger.warning(f"[FIX-V16 V22.0] Continuity Store non-blocking error: {_cs2_err}")

    # V21.7: DIALOGUE DEDUP SWEEP — catch any remaining consecutive duplicate dialogue
    # This is the SAFETY NET after all injection phases. Root cause is fixed above in
    # Phase 3 + CHECK 5B, but this catches edge cases from shot expansion itself.
    try:
        _dedup_fixes = 0
        _scenes_for_dedup = {}
        for _s in shots:
            _sid = _s.get("scene_id", "001")
            _scenes_for_dedup.setdefault(_sid, []).append(_s)

        for _sid, _scene_shots in _scenes_for_dedup.items():
            for _i in range(1, len(_scene_shots)):
                _d1 = (_scene_shots[_i-1].get("dialogue_text") or "").strip()
                _d2 = (_scene_shots[_i].get("dialogue_text") or "").strip()
                if _d1 and _d2 and _d1.lower()[:80] == _d2.lower()[:80]:
                    # Consecutive duplicate — convert second to reaction
                    # V26.1: Include context of what they're reacting to
                    _react_chars = _scene_shots[_i].get("characters", [])
                    if _react_chars:
                        _reactor_name = _react_chars[0] if isinstance(_react_chars[0], str) else str(_react_chars[0])
                        _react_context = _d1[:60].strip()
                        _react_emo = _scene_shots[_i].get("emotion", "tension")
                        _scene_shots[_i]["dialogue_text"] = f"{_reactor_name} reacts with {_react_emo} to hearing: '{_react_context}'"
                        _scene_shots[_i]["dialogue"] = _scene_shots[_i]["dialogue_text"]
                    else:
                        _scene_shots[_i]["dialogue_text"] = "Reaction moment — absorbing the weight of the preceding words"
                        _scene_shots[_i]["dialogue"] = _scene_shots[_i]["dialogue_text"]
                    # Also fix LTX if it has the same speaks marker
                    _ltx2 = (_scene_shots[_i].get("ltx_motion_prompt") or "")
                    if "character speaks:" in _ltx2.lower():
                        import re as _re_dedup
                        _ltx2 = _re_dedup.sub(r'character speaks:[^,]*,?', 'character reacts: subtle emotional response,', _ltx2, flags=_re_dedup.IGNORECASE)
                        _scene_shots[_i]["ltx_motion_prompt"] = _ltx2
                    _dedup_fixes += 1

        if _dedup_fixes > 0:
            logger.info(f"[FIX-V16 V21.7] Dialogue dedup sweep: fixed {_dedup_fixes} consecutive duplicate dialogue pairs")
            issues_fixed.append(f"DIALOGUE_DEDUP: {_dedup_fixes} consecutive duplicates → reaction shots")
    except Exception as _dedup_err:
        logger.warning(f"[FIX-V16] Dialogue dedup non-blocking error: {_dedup_err}")

    # V17.7: Shot Intent Tagger — auto-tag purpose, coverage_role, wardrobe_lock, expected_elements
    try:
        if INTENT_TAGGER_AVAILABLE:
            story_bible = {}
            if story_bible_path.exists():
                with open(story_bible_path) as _sbf:
                    story_bible = json.load(_sbf)
            cast_map = {}
            _cm_path = project_path / "cast_map.json"
            if _cm_path.exists():
                with open(_cm_path) as _cmf:
                    cast_map = json.load(_cmf)
            data, intent_count, intent_changes = tag_all_shots(data, story_bible, cast_map, force=False)
            if intent_count > 0:
                issues_fixed.append(f"INTENT_TAGGER: Tagged {intent_count} shots with purpose/coverage/wardrobe/elements")
                logger.info(f"[INTENT-TAGGER] Auto-tagged {intent_count} shots for {project}")
        else:
            logger.debug("[INTENT-TAGGER] Not available, skipping")
    except Exception as intent_err:
        logger.warning(f"[INTENT-TAGGER] Non-blocking error: {intent_err}")

    # =========================================================================
    # V20.5: FULL PROMPT ENRICHMENT IN FIX-V16
    # Previously these only ran at generation time — now prompts are fully
    # baked and visible in the UI BEFORE the user hits generate.
    # Order matches generate-first-frames exactly.
    # =========================================================================

    # --- V20.5 Step 1: WARDROBE + EXTRAS INJECTION ---
    try:
        from atlas_agents.wardrobe_extras_agent import (
            load_wardrobe, load_extras, auto_assign_wardrobe,
            auto_assign_extras, get_wardrobe_for_shot,
            get_extras_for_shot, inject_wardrobe_into_prompt,
            inject_extras_into_prompt
        )
        _sb_for_wardrobe = {}
        _sb_path_w = project_path / "story_bible.json"
        if _sb_path_w.exists():
            with open(_sb_path_w) as f:
                _sb_for_wardrobe = json.load(f)
        _cast_map_w = {}
        _cm_path_w = project_path / "cast_map.json"
        if _cm_path_w.exists():
            with open(_cm_path_w) as f:
                _cast_map_w = json.load(f)
        _wardrobe_path_w = project_path / "wardrobe.json"
        if not _wardrobe_path_w.exists():
            auto_assign_wardrobe(project_path, shots, _sb_for_wardrobe, _cast_map_w)
            auto_assign_extras(project_path, shots, _sb_for_wardrobe)
            logger.info("[FIX-V16 V20.5] Auto-assigned wardrobe + extras")
        _wardrobe = load_wardrobe(project_path)
        _extras = load_extras(project_path)
        _ward_count = 0
        _ext_count = 0
        for _shot in shots:
            _sn = (_shot.get("nano_prompt") or "")
            _sl = (_shot.get("ltx_motion_prompt") or "")
            if "wearing:" not in _sn.lower():
                _sw = get_wardrobe_for_shot(_wardrobe, _shot)
                if _sw:
                    _shot["nano_prompt"] = inject_wardrobe_into_prompt(_sn, _sw, is_ltx=False)
                    _shot["ltx_motion_prompt"] = inject_wardrobe_into_prompt(_sl, _sw, is_ltx=True)
                    _ward_count += 1
            _ei = get_extras_for_shot(_extras, _shot)
            if _ei and "background:" not in (_shot.get("nano_prompt") or "").lower():
                _shot["nano_prompt"] = inject_extras_into_prompt(_shot.get("nano_prompt", ""), _ei, is_ltx=False)
                _shot["ltx_motion_prompt"] = inject_extras_into_prompt(_shot.get("ltx_motion_prompt", ""), _ei, is_ltx=True)
                _ext_count += 1
        if _ward_count or _ext_count:
            issues_fixed.append(f"V20.5_WARDROBE: {_ward_count} wardrobe + {_ext_count} extras injected")
            logger.info(f"[FIX-V16 V20.5] Wardrobe: {_ward_count}, Extras: {_ext_count}")
    except Exception as _we:
        logger.warning(f"[FIX-V16 V20.5] Wardrobe/extras non-blocking: {_we}")

    # --- V20.5 Step 2: EMOTION LAYER INJECTION ---
    try:
        from atlas_agents.emotion_layer_agent import (
            auto_generate_emotion_layer, load_emotion_layer,
            inject_emotion_into_ltx, inject_emotion_into_nano,
            EMOTION_MARKER
        )
        _emo_path = project_path / "emotion_layer.json"
        _sb_emo = {}
        _sb_emo_path = project_path / "story_bible.json"
        if _sb_emo_path.exists():
            with open(_sb_emo_path) as f:
                _sb_emo = json.load(f)
        if not _emo_path.exists():
            auto_generate_emotion_layer(str(project_path), {"shots": shots}, _sb_emo)
            logger.info("[FIX-V16 V20.5] Auto-generated emotion_layer.json")
        _emotion_layer = load_emotion_layer(str(project_path))
        _emo_count = 0
        for _shot in shots:
            _sid_e = _shot.get("shot_id", "")
            _scene_e = _sid_e.split("_")[0] if "_" in _sid_e else ""
            _sk = f"scene_{_scene_e}"
            _se = _emotion_layer.get(_sk, {}).get(_sid_e, {})
            if not _se:
                continue
            _ab = _se.get("acting_block", "")
            _es = _se.get("emotion_state", {})
            _ltx = _shot.get("ltx_motion_prompt", "")
            if _ab and EMOTION_MARKER not in _ltx:
                _shot["ltx_motion_prompt"] = inject_emotion_into_ltx(_ltx, _ab)
                _chars = _shot.get("characters", [])
                if _chars and _es:
                    _nano = _shot.get("nano_prompt", "")
                    _shot["nano_prompt"] = inject_emotion_into_nano(_nano, _es, _chars[0])
                _emo_count += 1
        if _emo_count:
            issues_fixed.append(f"V20.5_EMOTION: {_emo_count} shots got acting directives")
            logger.info(f"[FIX-V16 V20.5] Emotion layer: {_emo_count} shots enriched")
    except Exception as _em:
        logger.warning(f"[FIX-V16 V20.5] Emotion layer non-blocking: {_em}")

    # --- V20.5 Step 3: LOCATION DESCRIPTION INJECTION ---
    # V21.9: DISABLED in fix-v16 — location descriptions injected at generate-first-frames time
    # Running here caused double injection (fix-v16 injects, then generate-first-frames injects again)
    # Location metadata is preserved on shots, just not appended to nano_prompt here
    logger.info("[FIX-V16 V21.9] Skipping location description injection (deferred to generate-first-frames)")

    # --- V20.5 Step 4: SCENE ANCHOR SYSTEM (color grade + lighting + wardrobe consistency) ---
    # V21.9: DISABLED in fix-v16 — scene anchors injected at generate-first-frames time
    # Running here caused double injection (color grade, lighting appended twice)
    logger.info("[FIX-V16 V21.9] Skipping scene anchor injection (deferred to generate-first-frames)")

    # --- V20.5 Step 5: CINEMATIC ENRICHER + CAST TRAIT INJECTION ---
    # V21.9: DISABLED in fix-v16 — cinematic enricher + cast traits + face-lock
    # ALL run at generate-first-frames time (lines 18730-18812)
    # Running here caused:
    #   - composition: injected 2x (enricher + CINEMATIC_PREFIXES)
    #   - subtext: injected 2x (enricher in fix-v16 + enricher in generate)
    #   - performance: injected 2x (enricher + director profile)
    #   - pacing: injected 2x (enricher + writer profile)
    #   - AI actor descriptions injected via face-lock (violates rule 127)
    #   - Film stock / camera body injected (not needed for text-to-image)
    #   - Humanization (breathing, blinking) injected into nano (belongs in LTX only)
    # Total bloat: 677 avg chars → 3,279 avg chars (5x inflation)
    logger.info("[FIX-V16 V21.9] Skipping cinematic enricher + face-lock (deferred to generate-first-frames)")

    # --- V20.5 Step 6: SCRIPT CONTENT FIDELITY VALIDATOR (auto-catch mismatches) ---
    try:
        _manifest = data.get("scene_manifest", [])
        _sb_val = {}
        _sb_val_path = project_path / "story_bible.json"
        if _sb_val_path.exists():
            with open(_sb_val_path) as f:
                _sb_val = json.load(f)
        _fidelity_issues = []
        _scene_truth = {}
        for _sc in _manifest:
            _sid = _sc.get("scene_id", "")
            _scene_truth[_sid] = {
                "title": _sc.get("title", _sc.get("scene_heading", "")),
                "int_ext": _sc.get("int_ext", ""),
                "characters": [c.upper() for c in _sc.get("characters", [])],
                "location": _sc.get("setting", {}).get("primary", "") if isinstance(_sc.get("setting"), dict) else ""
            }
        _autofix_count = 0
        for _shot in shots:
            _sid = _shot.get("shot_id", "?")
            _scene = _sid[:3]
            _truth = _scene_truth.get(_scene, {})
            if not _truth:
                continue
            _nano = (_shot.get("nano_prompt") or "").lower()
            _title = _truth.get("title", "").upper()
            _ie = _truth.get("int_ext", "").upper()
            # Check INT/EXT mismatch in prompts
            if "INT" in _ie and "EXT" not in _ie:
                if "exterior" in _nano and _shot.get("shot_type", "") not in ("establishing", "b_roll"):
                    _fidelity_issues.append(f"{_sid}: exterior in prompt but scene is INT")
                    _shot["nano_prompt"] = _shot["nano_prompt"].replace("exterior", "interior").replace("Exterior", "Interior").replace("EXTERIOR", "INTERIOR")
                    _autofix_count += 1
            # Check characters assigned for non-establishing shots
            _chars = _shot.get("characters", [])
            _st = _shot.get("shot_type", "")
            # V26 DOCTRINE: Coverage suffixes are editorial, not runtime
            _is_broll_check = _shot.get("is_broll", False) or _shot.get("_broll", False)
            if not _chars and _st not in ("establishing", "b_roll", "insert", "wide") and not _is_broll_check:
                _truth_chars = _truth.get("characters", [])
                if _truth_chars:
                    _fidelity_issues.append(f"{_sid}: no characters (scene has {_truth_chars})")
            # Check dialogue shots have dialogue markers in ltx
            _dlg = _shot.get("dialogue_text", "") or _shot.get("dialogue", "") or ""
            _ltx = _shot.get("ltx_motion_prompt", "")
            if _dlg and len(_dlg) > 5 and "speaks:" not in _ltx.lower() and "character speaks:" not in _ltx.lower():
                _fidelity_issues.append(f"{_sid}: has dialogue but no speaks: marker in ltx")
                # Auto-fix: inject dialogue marker
                _first_char = _chars[0] if _chars else "Character"
                _dlg_short = _dlg[:200]
                _shot["ltx_motion_prompt"] = _ltx + f" character speaks: {_first_char} says \"{_dlg_short}\", lip sync, jaw motion, natural speaking cadence."
                _autofix_count += 1
        if _fidelity_issues:
            issues_fixed.append(f"V20.5_FIDELITY: {len(_fidelity_issues)} content issues found, {_autofix_count} auto-fixed")
            logger.info(f"[FIX-V16 V20.5] Script fidelity: {len(_fidelity_issues)} issues, {_autofix_count} auto-fixed")
            for _fi in _fidelity_issues[:10]:
                logger.info(f"[FIDELITY] {_fi}")
        else:
            issues_fixed.append("V20.5_FIDELITY: All shots pass script content check")
            logger.info("[FIX-V16 V20.5] Script fidelity: ALL PASS")
    except Exception as _fv:
        logger.warning(f"[FIX-V16 V20.5] Fidelity validator non-blocking: {_fv}")

    # =========================================================================
    # END V20.5 ENRICHMENT BLOCK
    # =========================================================================

    # --- CHECK 7F: PROMPT AUTHORITY GATE — FINAL dedup after ALL enrichment ---
    # Must run LAST (after V20.5 wardrobe/emotion/fidelity which add performance: blocks)
    # Historical: 96 shots had 2-3x "performance:" from enrichment stacking.
    try:
        logger.info(f"[FIX-V16 V21.9 CHECK 7F] Starting Authority Gate for {len(shots)} shots...")
        from tools.prompt_authority_gate import enforce_prompt_authority
        _pa_cast = data.get("cast_map") or {}
        if isinstance(_pa_cast, list):
            _pa_cast = {}
        _pa_stats = enforce_prompt_authority(shots, project_path, _pa_cast)
        _pa_stripped = _pa_stats.get("stripped", 0)
        logger.info(f"[FIX-V16 V21.9 CHECK 7F] Authority Gate returned: stripped={_pa_stripped}, stats={_pa_stats}")
        if _pa_stripped > 0:
            issues_fixed.append(f"V21.9_AUTHORITY_GATE: {_pa_stripped} shots cleaned (dedup performance:/subtext:/color conflicts)")
            logger.info(f"[FIX-V16 V21.9 CHECK 7F] Authority Gate cleaned {_pa_stripped} shots in fix-v16")
        else:
            logger.info(f"[FIX-V16 V21.9 CHECK 7F] Authority Gate: all shots already clean")
    except Exception as _7f_err:
        import traceback
        logger.warning(f"[FIX-V16 V21.9] CHECK 7F Authority Gate non-blocking error: {_7f_err}")
        logger.warning(f"[FIX-V16 V21.9] CHECK 7F traceback: {traceback.format_exc()}")

    # V21.10: FINAL LTX DURATION SYNC — ensure ALL shots have duration marker in LTX
    # Runs after all enrichment/dedup that may have appended text without duration
    import re as _re_final_dur
    _final_dur_fixes = 0
    for _shot in shots:
        _ltx = _shot.get("ltx_motion_prompt", "") or ""
        _dur = _shot.get("duration", _shot.get("duration_seconds", 10))
        if _ltx and not _re_final_dur.search(r'\b\d+s\b', _ltx):
            _shot["ltx_motion_prompt"] = _ltx.rstrip(",. ") + f", {_dur}s"
            _final_dur_fixes += 1
    if _final_dur_fixes > 0:
        issues_fixed.append(f"V21.10_FINAL_DUR_SYNC: {_final_dur_fixes} LTX prompts got duration marker")

    # V21.10: ABSOLUTE FINAL PASS — ensure NO morphing on ALL non-character shots
    # This runs AFTER CHECK 7F Authority Gate, V20.5 enrichment, dialogue dedup —
    # the very last step before save. Catches any edge cases (e.g. CHILD V.O. shots
    # where characters[] was emptied by CHECK 7B but fidelity validator added content)
    _final_morph_fixes = 0
    for _shot in shots:
        if not _shot.get("characters"):
            _ltx_final = (_shot.get("ltx_motion_prompt", "") or "").lower()
            if "no morphing" not in _ltx_final:
                _shot["ltx_motion_prompt"] = (_shot.get("ltx_motion_prompt", "") or "").rstrip(",. ") + ", NO morphing, NO face generation, environment only"
                _final_morph_fixes += 1
    if _final_morph_fixes > 0:
        issues_fixed.append(f"V21.10_FINAL_MORPH: {_final_morph_fixes} non-char shots got NO morphing (absolute final pass)")
        logger.info(f"[FIX-V16 V21.10] Final morph pass: {_final_morph_fixes} non-char shots")

    # ═══════════════════════════════════════════════════════════════════════
    # V26.1: DIALOGUE MARKER DEDUPLICATION — ABSOLUTE FINAL DEDUP
    # Law 264/267: Multiple enrichment passes can stack "character speaks:"
    # markers (observed: 1→5→11 copies over 3 runs). This guard runs AFTER
    # ALL enrichment and strips duplicates down to exactly 1 occurrence.
    # ═══════════════════════════════════════════════════════════════════════
    _dedup_fixes = 0
    for _shot in shots:
        for _field in ("ltx_motion_prompt", "ltx_motion_prompt_final"):
            _ltx_val = (_shot.get(_field) or "")
            _speaks_count = _ltx_val.lower().count("character speaks:")
            if _speaks_count > 1:
                # Keep first "character speaks:" block + everything after the last duplicate
                import re as _re_dd
                # Split on "character speaks:" occurrences
                _parts = _re_dd.split(r'character speaks:', _ltx_val, flags=_re_dd.IGNORECASE)
                if len(_parts) > 2:
                    # Reconstruct: prefix + first speaks block + final trailing content
                    _prefix = _parts[0].strip().rstrip(",. ")
                    _first_block = _parts[1].strip().rstrip(",. ")
                    _last_block = _parts[-1].strip()
                    # Check if last block is different content (face-stable, timing, etc)
                    _deduped = f"character speaks: {_first_block}"
                    if _last_block and _last_block != _first_block:
                        # Only append if it has unique content (face stable, timing markers)
                        if any(kw in _last_block.lower() for kw in ["face stable", "morphing", "consistent", "10s", "8s", "6s"]):
                            _deduped += f", {_last_block}"
                    if _prefix:
                        _deduped = f"{_prefix}, {_deduped}"
                    _shot[_field] = _deduped
                    _dedup_fixes += 1
    if _dedup_fixes > 0:
        issues_fixed.append(f"V26.1_DIALOGUE_DEDUP: {_dedup_fixes} shots had stacked 'character speaks:' markers — deduped")
        logger.info(f"[FIX-V16 V26.1] Dialogue marker dedup: {_dedup_fixes} fields cleaned")

    # ═══════════════════════════════════════════════════════════════════════
    # V22.4: UNIFIED PROMPT BUILDER — ONE pass, FINAL result
    # This replaces 6+ scattered enrichment calls with a single balanced build.
    # After this, nano_prompt_final and ltx_motion_prompt_final are SET.
    # Generation endpoints use these DIRECTLY — no more re-enrichment.
    # ═══════════════════════════════════════════════════════════════════════
    try:
        from tools.unified_prompt_builder import build_all_final_prompts
        _unified_count = build_all_final_prompts(shots, project_path, cast_map)
        issues_fixed.append(f"V22.4_UNIFIED_BUILDER: {_unified_count} shots got final prompts (ONE pass, balanced)")
        logger.info(f"[FIX-V16 V22.4] Unified builder applied to {_unified_count} shots — prompts are now FINAL")
    except Exception as _ub_err:
        logger.warning(f"[FIX-V16 V22.4] Unified builder non-blocking error: {_ub_err}")
        import traceback
        logger.warning(f"[FIX-V16 V22.4] Traceback: {traceback.format_exc()}")

    # V17.3: Stamp schema metadata on save
    try:
        stamp_metadata(data, action="fix_v16")
    except Exception:
        pass

    # ═══════════════════════════════════════════════════════════════════════
    # V25.4: PIPELINE WIRING — FINAL COMPILE HOOK
    # Connects Film Engine + Creative Prompt Compiler + Camera Token Translation
    # to the actual pipeline. Non-blocking: if any module fails, save proceeds.
    # ═══════════════════════════════════════════════════════════════════════
    _wiring_mutations = 0
    print(f"[V25.4 WIRING] Starting final compile hook for {len(shots)} shots...", flush=True)
    try:
        from tools.atlas_pipeline_wiring import wire_fix_v16_final_compile, format_wiring_report
        _wiring_context = {
            "genre": genre,
            "cast_map": cast_map,
            "scene_manifest": data.get("scene_manifest", []),
            "project_path": str(project_path),
            "story_bible": story_bible,
        }
        for _shot in shots:
            _wr = wire_fix_v16_final_compile(_shot, _wiring_context)
            _wiring_mutations += len(_wr.mutations)
            if _wr.errors:
                for _e in _wr.errors:
                    logger.warning(f"[WIRING] {_e}")
        print(f"[V25.4 WIRING] Completed: {_wiring_mutations} mutations across {len(shots)} shots", flush=True)
        if _wiring_mutations > 0:
            issues_fixed.append(f"V25_WIRING: {_wiring_mutations} brain module mutations applied (Film Engine + CPC + camera tokens)")
            logger.info(f"[V25.4 WIRING] Applied {_wiring_mutations} mutations across {len(shots)} shots")
    except ImportError as _ie:
        print(f"[V25.4 WIRING] ImportError: {_ie}", flush=True)
    except Exception as _we:
        print(f"[V25.4 WIRING] Exception: {_we}", flush=True)
        logger.warning(f"[V25.4 WIRING] Non-blocking failure: {_we}")

    # Save fixed shot plan
    backup_path = shot_plan_path.with_suffix(f".json.backup_v13fix_{datetime.now().strftime('%Y%m%d_%H%M%S')}")
    shutil.copy(shot_plan_path, backup_path)

    with open(shot_plan_path, 'w') as f:
        json.dump(data, f, indent=2)

    logger.info(f"[V15.4 FIX] Fixed {len(issues_fixed)} issues for {project} (intelligent={has_intelligent_enhancer})")

    # ═══════════════════════════════════════════════════════════════════════
    # V21.9: AUTOMATIC POST-FIX AUDIT — runs EVERY TIME fix-v16 completes
    # This is the permanent solution to the re-injection loop.
    # fix-v16 reads from story bible (which has bad data like "None experiences")
    # and injects it faithfully. This audit catches and fixes AFTER all injection.
    # Wired HERE so it CANNOT be skipped — no manual step required.
    # ═══════════════════════════════════════════════════════════════════════
    _audit_report = {"skipped": True}
    try:
        # Re-load the shots we just saved (fix-v16 may have mutated them)
        with open(shot_plan_path) as _af:
            _audit_sp = json.load(_af)
        _audit_shots = _audit_sp.get("shots", _audit_sp) if isinstance(_audit_sp, dict) else _audit_sp

        _audit_fixes = 0
        for _as in _audit_shots:
            _a_chars = _as.get("characters", [])
            _a_nano = _as.get("nano_prompt", "")
            _a_ltx = _as.get("ltx_motion_prompt", "")

            # FIX A: Generic "None" actions + all generic contamination → Creative Prompt Compiler
            # V25.1: Uses decontaminate_prompt() instead of simple string replacements
            try:
                from tools.creative_prompt_compiler import decontaminate_prompt, is_prompt_generic, get_physical_direction
                _has_cpc = True
            except ImportError:
                _has_cpc = False
            if _has_cpc and _a_chars:
                _a_emotion = "neutral"
                _a_state = _as.get("state_in", {})
                if isinstance(_a_state, dict):
                    for _sv in _a_state.values():
                        if isinstance(_sv, dict) and _sv.get("emotion"):
                            _a_emotion = _sv["emotion"]
                            break
                if is_prompt_generic(_a_nano):
                    _as["nano_prompt"] = decontaminate_prompt(_a_nano, _a_chars[0], _a_emotion)
                    _audit_fixes += 1
                _a_ltx = _as.get("ltx_motion_prompt", "")
                if is_prompt_generic(_a_ltx):
                    _as["ltx_motion_prompt"] = decontaminate_prompt(_a_ltx, _a_chars[0], _a_emotion)
                    _audit_fixes += 1
            elif not _has_cpc:
                # Legacy fallback (pre-V25.1) — at least fix None patterns
                if _a_chars and "None experiences the moment" in _a_nano:
                    _as["nano_prompt"] = _a_nano.replace("None experiences the moment", f"{_a_chars[0]} anchored in the space, body grounded")
                    _audit_fixes += 1
                elif not _a_chars and re.search(r'Character action:\s*None\s+\w+', _a_nano):
                    _as["nano_prompt"] = re.sub(r'Character action:\s*None\s+\w+[^.]*\.?\s*', '', _a_nano)
                    _audit_fixes += 1

            # FIX B: Character shots missing ANY performance marker
            _a_ltx = _as.get("ltx_motion_prompt", "")
            if _a_chars and not any(m in _a_ltx for m in ["character performs:", "character speaks:", "character reacts:"]):
                _a_dlg = _as.get("dialogue_text", "") or ""
                if _a_dlg:
                    _marker = f"character speaks: {_a_chars[0]} delivers dialogue with natural cadence"
                else:
                    _ca = re.search(r'Character action:\s*([^.]+)', _as.get("nano_prompt", ""))
                    _beat_act = _ca.group(1).strip() if _ca else ""
                    if _beat_act and "None" not in _beat_act and "experiences" not in _beat_act.lower():
                        _marker = f"character performs: {_beat_act}"
                    elif _has_cpc:
                        _a_phys = get_physical_direction("neutral", "default", _a_chars[0], "")
                        _marker = f"character performs: {_a_phys}" if _a_phys else f"character performs: {_a_chars[0]} present, body telling the story"
                    else:
                        _marker = f"character performs: {_a_chars[0]} present, body grounded in the space"
                if "Timing:" in _a_ltx:
                    _as["ltx_motion_prompt"] = _a_ltx.replace("Timing:", f"{_marker}, Timing:")
                else:
                    _as["ltx_motion_prompt"] = f"{_marker}, {_a_ltx}"
                _audit_fixes += 1

            # FIX C: Human performance markers on characterless shots
            if not _a_chars:
                _a_ltx = _as.get("ltx_motion_prompt", "")
                _human_strip = ["character performs:", "character speaks:", "character reacts:",
                                "micro-expression", "subtle eye movement", "chest rise", "blinks",
                                "DIALOGUE PERFORMANCE MANDATORY"]
                for _hs in _human_strip:
                    if _hs in _a_ltx:
                        _as["ltx_motion_prompt"] = _a_ltx.replace(_hs, "").replace("  ", " ")
                        _a_ltx = _as["ltx_motion_prompt"]
                        _audit_fixes += 1

            # FIX D: "subjects isolated in architecture" on characterless nano
            if not _a_chars:
                _a_nano = _as.get("nano_prompt", "")
                if "subjects isolated in architecture" in _a_nano:
                    _as["nano_prompt"] = _a_nano.replace("subjects isolated in architecture", "negative space in composition")
                    _audit_fixes += 1

        # Save if fixes applied
        if _audit_fixes > 0:
            if isinstance(_audit_sp, dict):
                _audit_sp["shots"] = _audit_shots
            import tempfile as _atf
            _atmp = _atf.NamedTemporaryFile(mode="w", dir=str(project_path), suffix=".json", delete=False)
            json.dump(_audit_sp, _atmp, indent=2)
            _atmp.close()
            os.replace(_atmp.name, str(shot_plan_path))
            logger.info(f"[FIX-V16-AUDIT] Applied {_audit_fixes} post-fix corrections for {project}")

        _audit_report = {"fixes": _audit_fixes, "skipped": False}
    except Exception as _ae:
        logger.warning(f"[FIX-V16-AUDIT] Non-blocking audit error: {_ae}")
        _audit_report = {"error": str(_ae), "skipped": False}

    # ═══════════════════════════════════════════════════════════════════════
    # V22: STALENESS AGENT — runs AFTER all fix-v16 enrichment + audit
    # Detects stale actor refs, scrambled IDs, legacy paths, orphan chars
    # Non-blocking — logs issues but does not block pipeline
    # ═══════════════════════════════════════════════════════════════════════
    _staleness_report = {"skipped": True}
    try:
        from atlas_agents.staleness_agent import run_staleness_check
        _stale_path = str(project_path)
        _stale_actors = str(Path(project_path).parent.parent / "ai_actors_library.json")
        _staleness_report = run_staleness_check(_stale_path, _stale_actors, auto_fix=True)
        _stale_fixed = _staleness_report.get("summary", {}).get("auto_fixed", 0)
        _stale_critical = _staleness_report.get("summary", {}).get("critical", 0)
        if _stale_fixed > 0:
            issues_fixed.append(f"V22_STALENESS_AGENT: auto-fixed {_stale_fixed} stale data issues")
        if _stale_critical > 0:
            logger.warning(f"[FIX-V16 V22] Staleness Agent found {_stale_critical} CRITICAL issues")
        logger.info(f"[FIX-V16 V22] Staleness Agent: status={_staleness_report.get('status')}, "
                     f"issues={_staleness_report.get('summary', {}).get('total_issues', 0)}, "
                     f"fixed={_stale_fixed}")
    except Exception as _stale_err:
        logger.warning(f"[FIX-V16 V22] Staleness Agent non-blocking error: {_stale_err}")
        _staleness_report = {"error": str(_stale_err), "skipped": False}

    # V17.3: Temporal completion tracking
    try:
        temporal_complete_activity(_wf_id, "fix_v16_setup", result={
            "fixed_count": len(issues_fixed),
            "coverage_grade": coverage_report["overall_grade"] if coverage_report else "N/A"
        })
        temporal_complete_workflow(_wf_id, result={"fixed": len(issues_fixed)})
        _temporal_persist()
    except Exception:
        pass

    return {
        "success": True,  # V16.4: UI compatibility
        "status": "success",
        "project": project,
        "shot_count": len(shots),
        "fixed_count": len(issues_fixed),
        "issues_fixed": issues_fixed[:20],  # First 20 for UI
        "total_duration": total_duration,
        "total_minutes": round(total_duration / 60, 1),
        "intelligent_mode": has_intelligent_enhancer,
        "advisory_notes": advisory_notes,
        "critics": critic_results,
        "coverage": coverage_report if coverage_report else {"error": "solver_unavailable"},
        "prompt_quality": prompt_quality_report if prompt_quality_report else {"error": "validator_unavailable"},
        "temporal_available": _TEMPORAL_AVAILABLE,
        "backup_created": backup_path.name,
        "auto_advance": _advance_report,  # V20.4: Script auto-advancement results
        "post_fix_audit": _audit_report,  # V21.9: Automatic post-fix audit results
        "tests": [],
        "issues": [],
        "health": 100
    }


# =============================================================================
# V17 SHOT EXPANSION ENDPOINT - DIRECTOR-INTELLIGENT ABC COVERAGE
# =============================================================================

@app.post("/api/shot-plan/expand-v17")
async def expand_v17(request: Dict = Body(...)):
    """
    V17 Shot Expansion: Full director-intelligent expansion with:
    1. Episode-aware shot IDs (E101_S01_000A format)
    2. Character DNA embedding in prompts (no runtime lookup)
    3. Continuity chain (use_previous_shot)
    4. ABC angle coverage per narrative beat
    5. Extended shot segmentation (>20s = multiple segments)

    Request: {"project": "kord", "episode": 1}
    """
    project = request.get("project", "")
    episode = request.get("episode", 1)

    if not project:
        return {"success": False, "error": "Missing project parameter"}

    try:
        from V17_SHOT_EXPANDER import expand_project_v17

        success, manifest, message = expand_project_v17(
            project=project,
            pipeline_outputs_dir=PIPELINE_OUTPUTS_DIR,
            episode=episode
        )

        if success:
            # Invalidate UI cache
            cache_dir = PIPELINE_OUTPUTS_DIR / project / "ui_cache"
            cache_dir.mkdir(parents=True, exist_ok=True)
            (cache_dir / "bundle.dirty").touch()

            return {
                "success": True,
                "project": project,
                "episode": episode,
                "message": message,
                "v17_features": manifest.get("v17_features", {}),
                "metadata": manifest.get("metadata", {}),
                "total_shots": len(manifest.get("shots", [])),
                "total_scenes": len(manifest.get("scene_manifest", []))
            }
        else:
            return {"success": False, "error": message}

    except ImportError as e:
        return {"success": False, "error": f"V17_SHOT_EXPANDER not found: {e}"}
    except Exception as e:
        logger.error(f"[V17] Expansion failed: {e}")
        return {"success": False, "error": str(e)}


