# =============================================================================
# V15.4 SCRIPT IMPORT AND VALIDATION ENDPOINT
# =============================================================================

@app.post("/api/v15/script/import-and-validate")
async def import_and_validate_script(
    file: UploadFile = File(...),
    project_name: str = Form(...),
    runtime: str = Form("45"),
    genre: str = Form("thriller"),
    generate_assets: str = Form("false")
):
    """
    V15.4: Import a script file, run LLM extraction, and validate.
    This is the main entry point for Auto Studio script uploads.

    Returns:
        {
            "status": "success" | "needs_attention" | "error",
            "project": "project_name",
            "parsed": {...},
            "preflight": {...},
            "assets_generated": {...}
        }
    """
    import tempfile
    import shutil

    logger.info(f"[V15 IMPORT] Importing script: {file.filename} as project '{project_name}'")

    try:
        # Parse runtime to minutes
        try:
            runtime_minutes = int(runtime.replace('min', '').replace('m', '').strip())
        except Exception:
            runtime_minutes = 45

        # Save uploaded file temporarily
        with tempfile.NamedTemporaryFile(delete=False, suffix=Path(file.filename).suffix) as tmp:
            content = await file.read()
            tmp.write(content)
            tmp_path = tmp.name

        # Read the script content
        script_text = content.decode('utf-8', errors='replace')

        # Create project directory
        project_path = get_project_path(project_name)
        project_path.mkdir(parents=True, exist_ok=True)

        # Save the imported script
        imported_script_path = project_path / "imported_script.txt"
        with open(imported_script_path, 'w') as f:
            f.write(script_text)

        logger.info(f"[V15 IMPORT] Script saved: {len(script_text)} chars")

        # V17 FIX: Try LLM extraction first, fall back to V17 regex parser
        manifest = None
        extraction_metadata = {}
        use_v17_parser = False

        try:
            from LLM_SCRIPT_EXTRACTOR import run_full_extraction, extract_runtime_from_script

            # Try to extract runtime from script first
            script_runtime = extract_runtime_from_script(script_text)
            if script_runtime > 5:
                runtime_minutes = script_runtime
                logger.info(f"[V15 IMPORT] Extracted runtime from script: {runtime_minutes} minutes")

            # Run the extraction pipeline
            manifest, extraction_metadata = run_full_extraction(
                script_text=script_text,
                project_name=project_name,
                genre=genre,
                enable_repair=True,
                target_runtime_minutes=runtime_minutes
            )

            # V17 FIX: Check if LLM extraction actually worked
            if manifest:
                char_count = len(manifest.get("characters", []))
                scene_count = len(manifest.get("scenes", manifest.get("scene_manifest", [])))
                if char_count == 0 and scene_count == 0:
                    logger.warning(f"[V15 IMPORT] LLM extraction returned 0 chars, 0 scenes — falling back to V17 regex parser")
                    use_v17_parser = True
            else:
                logger.warning(f"[V15 IMPORT] LLM extraction returned None — falling back to V17 regex parser")
                use_v17_parser = True

        except (ImportError, Exception) as e:
            logger.warning(f"[V15 IMPORT] LLM extractor failed ({e}) — falling back to V17 regex parser")
            use_v17_parser = True

        # =====================================================================
        # V17 FALLBACK: Use regex-based structural parser (no API calls needed)
        # =====================================================================
        if use_v17_parser:
            logger.info(f"[V15 IMPORT] Running V17 regex parser for {project_name}...")
            v17_result = await full_script_import({
                "project": project_name,
                "script_text": script_text,
                "title": project_name,
                "runtime_minutes": runtime_minutes
            })

            if v17_result.get("success"):
                # V17 parser saved shot_plan.json and story_bible.json
                # Reload the shot plan it created
                shot_plan_path = project_path / "shot_plan.json"
                with open(shot_plan_path) as f:
                    manifest = json.load(f)
                # Ensure metadata structure
                manifest["metadata"] = manifest.get("metadata", {})
                manifest["metadata"]["title"] = project_name
                manifest["metadata"]["genre"] = genre
                manifest["metadata"]["target_runtime"] = runtime_minutes * 60
                manifest["metadata"]["imported_file"] = file.filename
                manifest["metadata"]["target_runtime_seconds"] = runtime_minutes * 60
                manifest["metadata"]["target_runtime_minutes"] = runtime_minutes
                manifest["_parser"] = "V17_REGEX_FALLBACK"

                # Extract characters from shots for story bible
                shot_chars = set()
                for s in manifest.get("shots", []):
                    for c in s.get("characters", []):
                        if isinstance(c, str):
                            shot_chars.add(c)
                manifest["characters"] = [{"name": c, "role": "unknown"} for c in sorted(shot_chars)]
                manifest["locations"] = [{"name": l} for l in sorted(set(s.get("location", "") for s in manifest.get("shots", []) if s.get("location")))]

                # Update story bible with extracted characters
                bible_path = project_path / "story_bible.json"
                if bible_path.exists():
                    with open(bible_path) as f:
                        story_bible_data = json.load(f)
                    story_bible_data["characters"] = manifest["characters"]
                    story_bible_data["setting"] = story_bible_data.get("setting", {})
                    story_bible_data["setting"]["locations"] = [l["name"] for l in manifest["locations"]]
                    with open(bible_path, 'w') as f:
                        json.dump(story_bible_data, f, indent=2)

                # Save updated manifest
                with open(shot_plan_path, 'w') as f:
                    json.dump(manifest, f, indent=2)

                logger.info(f"[V15 IMPORT] V17 parser success: {len(manifest.get('shots', []))} shots, "
                          f"{len(manifest.get('characters', []))} chars, "
                          f"{len(manifest.get('locations', []))} locations")

                extraction_metadata = {
                    "parser": "V17_REGEX_FALLBACK",
                    "stats": v17_result.get("parsed", {})
                }
            else:
                return JSONResponse({
                    "status": "error",
                    "error": f"Both LLM and V17 parsers failed: {v17_result.get('error', 'unknown')}",
                    "project": project_name
                }, status_code=500)
        else:
            # LLM extraction worked — continue with normal flow
            manifest["metadata"] = manifest.get("metadata", {})
            manifest["metadata"]["title"] = project_name
            manifest["metadata"]["genre"] = genre
            manifest["metadata"]["target_runtime"] = runtime_minutes * 60
            manifest["metadata"]["imported_file"] = file.filename

            # V25: Creative intelligence expansion (grammar-driven, not template)
            shots = manifest.get("shots", [])
            if manifest.get("_requires_shot_expansion", True) and not shots:
                # Save manifest first for expansion
                shot_plan_path = project_path / "shot_plan.json"
                with open(shot_plan_path, 'w') as f:
                    json.dump(manifest, f, indent=2)

                _v25_expanded = False
                try:
                    from tools.creative_pipeline_bridge import creative_expand_project
                    _cpb_genre = manifest.get("metadata", {}).get("genre", "mystery_thriller")
                    _cpb_runtime = manifest.get("metadata", {}).get("target_runtime", 600)
                    success, expanded_manifest, message = creative_expand_project(
                        project_name, genre=_cpb_genre, target_runtime_seconds=_cpb_runtime
                    )
                    if success:
                        manifest = expanded_manifest
                        shots = manifest.get("shots", [])
                        _v25_expanded = True
                        logger.info(f"[V25 CREATIVE] Shot expansion: {len(shots)} shots (creative grammar)")
                except Exception as _cpb_e:
                    logger.warning(f"[V25 CREATIVE] Creative expansion failed: {_cpb_e}")

                if not _v25_expanded:
                    try:
                        from SHOT_EXPANSION_INTEGRATOR import expand_project_shots
                        success, expanded_manifest, message = expand_project_shots(project_name)
                        if success:
                            manifest = expanded_manifest
                            shots = manifest.get("shots", [])
                            logger.info(f"[V15 IMPORT] Shot expansion: {len(shots)} shots (legacy)")
                    except Exception as e:
                        logger.warning(f"[V15 IMPORT] Shot expansion skipped: {e}")

        # Save final manifest
        shots = manifest.get("shots", [])
        shot_plan_path = project_path / "shot_plan.json"
        with open(shot_plan_path, 'w') as f:
            json.dump(manifest, f, indent=2)

        # V16.4 FIX: Create story_bible.json with correct runtime target
        # This ensures fix-v13 can find the target runtime in story_bible
        story_bible = {
            "title": project_name,
            "series_title": project_name,
            "episode_number": 1,
            "genre": genre,
            "tone": ["cinematic", "atmospheric"],
            "runtime_target_minutes": float(runtime_minutes),
            "runtime_target_seconds": runtime_minutes * 60,
            "setting": {
                "time_period": "modern",
                "locations": [loc.get("name", loc) if isinstance(loc, dict) else loc for loc in manifest.get("locations", [])][:10]
            },
            "characters": manifest.get("characters", []),
            # V17 FIX: PRESERVE FULL BEATS WITH DIALOGUE - DO NOT STRIP!
            "scenes": [
                {
                    "scene_id": s.get("scene_id"),
                    "title": s.get("title", s.get("location", "")),
                    "location": s.get("location"),
                    "time_of_day": s.get("time_of_day", "DAY"),
                    "int_ext": s.get("int_ext", "INT"),
                    "estimated_duration_seconds": s.get("duration_seconds", s.get("estimated_duration_seconds", 60)),
                    # CRITICAL: Preserve full beats array with dialogue
                    "beats": s.get("beats", []),
                    "beat_count": len(s.get("beats", [])),
                    "characters": s.get("characters", []),
                    "description": s.get("description", "")
                }
                for s in manifest.get("scenes", manifest.get("scene_manifest", []))
            ],
            "visual_style": {
                "aspect_ratio": "16:9",
                "color_palette": "cinematic",
                "lighting_style": "atmospheric"
            },
            "_generated_by": "SCRIPT_UPLOAD_V164",
            "_timestamp": datetime.now().isoformat()
        }
        story_bible_path = project_path / "story_bible.json"
        with open(story_bible_path, 'w') as f:
            json.dump(story_bible, f, indent=2)
        logger.info(f"[V15 IMPORT] Created story_bible.json with {runtime_minutes} min runtime target")

        # Save extraction metadata
        metadata_path = project_path / "extraction_metadata.json"
        with open(metadata_path, 'w') as f:
            json.dump(extraction_metadata, f, indent=2)

        # Run pre-flight validation
        preflight_result = {"ready_to_render": True, "critical_issues": 0, "issues": []}
        try:
            from CRITIC_AGENT import run_preflight_before_render
            preflight_result = run_preflight_before_render(
                shots=shots,
                project_type="project"
            )
        except Exception as e:
            logger.warning(f"[V15 IMPORT] Preflight check skipped: {e}")

        # Build response
        characters = manifest.get("characters", [])
        locations = manifest.get("locations", [])
        scenes = manifest.get("scenes", manifest.get("scene_manifest", []))

        parsed_data = {
            "characters": {c.get("name", c): c for c in characters} if isinstance(characters, list) else characters,
            "locations": locations,
            "scenes": scenes,
            "stats": {
                "character_count": len(characters) if isinstance(characters, list) else 0,
                "location_count": len(locations) if isinstance(locations, list) else 0,
                "scene_count": len(scenes) if isinstance(scenes, list) else 0,
                "shot_count": len(shots),
                "total_beats": manifest.get("_total_beats", 0),
                "dialogue_line_count": sum(1 for s in shots if s.get("dialogue")),
                "camera_direction_count": sum(1 for s in shots if s.get("shot_type"))
            },
            "raw_script": script_text[:5000]  # First 5000 chars for preview
        }

        # Determine status
        status = "success"
        if preflight_result.get("block_count", 0) > 0:
            status = "needs_attention"

        logger.info(f"[V15 IMPORT] Complete: {len(shots)} shots, status={status}")

        # V16.2 FIX: Auto-run fix-v13 to apply smart duration calculation
        fix_result = None
        try:
            logger.info(f"[V15 IMPORT] Running fix-v13 for smart durations...")
            fix_result = await fix_v13_issues({"project": project_name})
            if fix_result.get("status") == "success":
                # Reload the updated shot plan
                with open(shot_plan_path) as f:
                    updated_manifest = json.load(f)
                    shots = updated_manifest.get("shots", [])
                    parsed_data["stats"]["shot_count"] = len(shots)
                    # Update total duration
                    total_duration = sum(s.get("duration", 10) for s in shots)
                    parsed_data["stats"]["total_duration_seconds"] = total_duration
                    parsed_data["stats"]["total_duration_formatted"] = f"{total_duration // 60}m {total_duration % 60}s"
                logger.info(f"[V15 IMPORT] fix-v13 applied: {fix_result.get('fixed_count', 0)} fixes, total duration: {total_duration}s")
        except Exception as e:
            logger.warning(f"[V15 IMPORT] fix-v13 skipped: {e}")

        # V16.4 FIX: Auto-cast characters after fix-v13
        cast_count = 0
        try:
            logger.info(f"[V15 IMPORT] Running auto-cast...")
            cast_result = await auto_cast_project({"project": project_name})
            if cast_result.get("success"):
                cast_count = cast_result.get("characters_cast", 0)
                logger.info(f"[V15 IMPORT] Auto-cast: {cast_count} characters cast")
                parsed_data["stats"]["cast_count"] = cast_count
        except Exception as e:
            logger.warning(f"[V15 IMPORT] Auto-cast skipped: {e}")

        # Cleanup temp file
        try:
            os.unlink(tmp_path)
        except Exception:
            pass

        # V16.2: Extract critic grade from fix_result
        critic_info = None
        if fix_result and fix_result.get("critics"):
            director_advisory = fix_result.get("critics", {}).get("director_advisory", {})
            critic_info = {
                "grade": director_advisory.get("grade", "?"),
                "pacing": director_advisory.get("pacing", 0),
                "coverage": director_advisory.get("coverage", 0),
                "emotional_arc": director_advisory.get("emotional_arc", 0),
                "notes": director_advisory.get("notes", [])[:3]  # Top 3 notes
            }

        return {
            "status": status,
            "project": project_name,
            "parsed": parsed_data,
            "preflight": preflight_result,
            "assets_generated": {
                "character_refs": 0,
                "location_masters": 0
            },
            "critical_issues": preflight_result.get("issues", [])[:5] if preflight_result.get("block_count", 0) > 0 else [],
            "fix_v13_applied": fix_result is not None and fix_result.get("status") == "success",
            "duration_info": {
                "total_seconds": parsed_data["stats"].get("total_duration_seconds", 0),
                "formatted": parsed_data["stats"].get("total_duration_formatted", "N/A"),
                "target_seconds": runtime_minutes * 60
            },
            "critic": critic_info  # V16.2: Director Critic grade and scores
        }

    except Exception as e:
        logger.error(f"[V15 IMPORT] Error: {e}")
        import traceback
        traceback.print_exc()
        return JSONResponse({
            "status": "error",
            "error": str(e),
            "project": project_name
        }, status_code=500)


