@app.post("/api/v154/rebalance-duration")
async def rebalance_project_duration(request: Dict = Body(...)):
    """
    V15.4: Rebalance shot durations to hit target runtime.
    POST /api/v154/rebalance-duration
    Body: {"project": "ravencroft_new", "target_runtime": 2700}
    """
    import subprocess

    project = request.get("project")
    target_runtime = request.get("target_runtime", 2700)

    if not project:
        return JSONResponse({"error": "project is required"}, status_code=400)

    try:
        result = subprocess.run(
            [sys.executable, str(BASE_DIR / "DURATION_REBALANCER.py"), project, "--apply", "--target", str(target_runtime)],
            capture_output=True, text=True, timeout=120
        )

        if result.returncode == 0:
            # Parse output for stats
            output = result.stdout
            return {
                "success": True,
                "project": project,
                "target_runtime": target_runtime,
                "message": "Duration rebalanced successfully",
                "output": output.split("\n")[-10:]
            }
        else:
            return {
                "success": False,
                "error": result.stderr or result.stdout
            }
    except Exception as e:
        logger.error(f"Duration rebalance failed: {e}")
        return JSONResponse({"error": str(e)}, status_code=500)


