@app.get("/api/v154/project-duration/{project}")
async def get_project_duration_status(project: str):
    """
    V15.4: Get current duration status for a project.
    GET /api/v154/project-duration/ravencroft_new
    """
    project_path = get_project_path(project)
    shot_plan_path = project_path / "shot_plan.json"

    if not shot_plan_path.exists():
        return JSONResponse({"error": f"Project '{project}' not found"}, status_code=404)

    try:
        with open(shot_plan_path) as f:
            data = json.load(f)

        shots = data.get("shots", []) if isinstance(data, dict) else data
        total_duration = sum(s.get("duration", s.get("duration_seconds", 10)) for s in shots)
        target = data.get("metadata", {}).get("target_runtime", 2700) if isinstance(data, dict) else 2700

        # Check enhancement status
        enhanced = any(s.get("v154_enhanced") for s in shots)
        narrative_beats = set(s.get("narrative_beat") for s in shots if s.get("narrative_beat"))

        return {
            "project": project,
            "total_shots": len(shots),
            "total_duration_seconds": total_duration,
            "total_duration_minutes": total_duration / 60,
            "target_runtime_seconds": target,
            "target_runtime_minutes": target / 60,
            "deviation_percent": abs(total_duration - target) / target * 100,
            "within_tolerance": abs(total_duration - target) / target <= 0.10,
            "v154_enhanced": enhanced,
            "narrative_beats_present": list(narrative_beats) if enhanced else [],
            "ready_for_render": enhanced and abs(total_duration - target) / target <= 0.10
        }
    except Exception as e:
        return JSONResponse({"error": str(e)}, status_code=500)



