@app.post("/api/auto/apply-director-profile")
async def apply_director_profile_endpoint(request: Dict = Body(...)):
    """
    V17.2: Apply director profile to project — enriches all shot prompts with
    director's film stock, sensor, color grade, and shot duration preferences.
    Persists changes to shot_plan.json.
    """
    project = request.get("project")
    director_id = request.get("director_id")
    dry_run = request.get("dry_run", False)

    if not project:
        return {"success": False, "error": "Project name required"}
    if not director_id:
        return {"success": False, "error": "director_id required"}

    project_path = get_project_path(project)
    shot_plan_path = project_path / "shot_plan.json"
    if not shot_plan_path.exists():
        return {"success": False, "error": f"Project '{project}' not found"}

    # Load director profile
    directors_path = BASE_DIR / "directors_library.json"
    if not directors_path.exists():
        return {"success": False, "error": "directors_library.json not found"}

    with open(directors_path) as f:
        directors_data = json.load(f)

    director = None
    for d in directors_data.get("directors", []):
        if d.get("id") == director_id or d.get("name", "").lower().replace(" ", "_") == director_id.lower():
            director = d
            break

    if not director:
        return {"success": False, "error": f"Director '{director_id}' not found"}

    # Load shot plan
    with open(shot_plan_path) as f:
        data = json.load(f)

    shots = data.get("shots", data) if isinstance(data, dict) else data
    if isinstance(data, list):
        shots = data

    # Load story bible for genre context
    story_bible = {}
    story_bible_path = project_path / "story_bible.json"
    if story_bible_path.exists():
        try:
            with open(story_bible_path) as f:
                story_bible = json.load(f)
        except Exception:
            pass

    # V17.3: Load writer profile via central helper (director is explicit from request)
    writer_profile = load_writer_for_project(project_path, story_bible)

    # Apply director profile via cinematic enricher
    shots_modified = 0
    changes = []
    try:
        from tools.cinematic_enricher import get_enricher
        enricher = get_enricher(
            genre=_resolve_genre_from_story_bible(story_bible),
            director_profile=director,
            writer_profile=writer_profile,
            story_bible=story_bible,
            force_new=True
        )

        for shot in shots:
            shot_id = shot.get("shot_id", "unknown")
            original_nano = shot.get("nano_prompt", "")
            original_ltx = shot.get("ltx_motion_prompt", "")

            # Enrich with director's film stock + sensor + grade
            if original_nano:
                shot["nano_prompt"] = enricher.enrich_nano_prompt(original_nano, shot)
            if original_ltx:
                shot["ltx_motion_prompt"] = enricher.enrich_ltx_prompt(original_ltx, shot)

            # Apply director duration overrides if available
            if director.get("shot_braintree_overrides"):
                shot_type = shot.get("type", "medium")
                overrides = director["shot_braintree_overrides"].get(shot_type, {})
                if overrides.get("duration"):
                    shot["duration_seconds"] = overrides["duration"]
                    shot["duration"] = overrides["duration"]

            if shot.get("nano_prompt") != original_nano or shot.get("ltx_motion_prompt") != original_ltx:
                shots_modified += 1
                changes.append({"shot_id": shot_id, "enriched": True})

    except Exception as enrich_err:
        logger.error(f"[V17.2] Director profile enrichment failed: {enrich_err}")
        return {"success": False, "error": f"Enrichment failed: {str(enrich_err)}"}

    # Persist to disk (unless dry_run)
    if not dry_run:
        if isinstance(data, dict):
            data["shots"] = shots
        with open(shot_plan_path, "w") as f:
            json.dump(data, f, indent=2)
        # Invalidate UI cache
        cache_path = project_path / "ui_cache" / "bundle.json"
        dirty_path = project_path / "ui_cache" / "bundle.json.dirty"
        if cache_path.exists():
            dirty_path.touch()

    return {
        "success": True,
        "project": project,
        "director": director.get("name"),
        "director_id": director.get("id"),
        "film_stock": enricher.film_profile.get("stock", "") if 'enricher' in dir() else "",
        "shots_modified": shots_modified,
        "total_shots": len(shots),
        "dry_run": dry_run,
        "changes": changes[:20]
    }

