@app.post("/api/v23/film-engine/route-scene")
async def film_engine_route_scene(request: Dict = Body(...)):
    """
    V23.1: Route ALL shots in a scene through Film Engine.
    Returns per-shot routing decisions for the entire scene.
    """
    try:
        from tools.film_engine import route_shot

        project = request.get("project")
        scene_id = request.get("scene_id")
        force_model = request.get("force_model")

        project_path = get_project_path(project)
        shot_plan_path = project_path / "shot_plan.json"

        with open(shot_plan_path) as f:
            data = json.load(f)
        shots = data.get("shots", data) if isinstance(data, dict) else data

        scene_shots = [s for s in shots if s.get("scene_id") == scene_id]
        if not scene_shots:
            return {"success": False, "error": f"No shots found for scene {scene_id}"}

        decisions = []
        kling_count = 0
        ltx_count = 0
        total_cost = 0.0

        for shot in scene_shots:
            routing = route_shot(shot, force_model=force_model)
            if routing.model == "kling":
                kling_count += 1
            else:
                ltx_count += 1
            total_cost += routing.cost_estimate
            decisions.append({
                "shot_id": shot.get("shot_id"),
                "shot_type": shot.get("shot_type"),
                "characters": shot.get("characters", []),
                "has_dialogue": bool(shot.get("dialogue_text", "").strip()),
                "model": routing.model,
                "mode": routing.mode,
                "reason": routing.reason,
                "confidence": routing.confidence,
                "cost": routing.cost_estimate,
            })

        return {
            "success": True,
            "scene_id": scene_id,
            "total_shots": len(scene_shots),
            "kling_shots": kling_count,
            "ltx_shots": ltx_count,
            "estimated_cost": round(total_cost, 2),
            "decisions": decisions,
        }

    except Exception as e:
        logger.error(f"[FILM ENGINE] Route scene error: {e}")
        return {"success": False, "error": str(e)}


