# =============================================================================
@app.post("/api/v17/location/regen-master")
async def regen_single_location_master(request: Dict = Body(...)):
    """
    V17.7.4: Regenerate a single location master image.
    Called from the UI location grid regenerate button.

    Body: { "project": "name", "location_name": "RITUAL ROOM" }
    """
    import httpx

    LOCATION_MODEL = "fal-ai/nano-banana-pro"

    project = request.get("project")
    location_name = request.get("location_name", "")

    if not project or not location_name:
        return {"success": False, "error": "project and location_name required"}

    project_path = get_project_path(project)
    if not project_path.exists():
        return {"success": False, "error": f"Project '{project}' not found"}

    loc_masters_dir = project_path / "location_masters"
    loc_masters_dir.mkdir(parents=True, exist_ok=True)

    # Sanitize name for filename
    safe_name = re.sub(r'[^a-zA-Z0-9_-]', '_', location_name.upper()).strip('_')
    image_path = loc_masters_dir / f"{safe_name}.jpg"

    # Build cinematic prompt for this location
    # Try to find location details from story bible
    visual_prompt = ""
    story_bible_path = project_path / "story_bible.json"
    if story_bible_path.exists():
        try:
            with open(story_bible_path) as f:
                sb = json.load(f)
            for loc in sb.get("locations", []):
                if loc.get("name", "").upper() == location_name.upper():
                    desc = loc.get("description", "")
                    visual_prompt = f"INT. {location_name}. {desc}. Cinematic wide establishing shot, professional cinematography, 16:9 aspect ratio, no people, atmospheric lighting, high detail."
                    break
        except Exception:
            pass

    if not visual_prompt:
        visual_prompt = f"INT. {location_name}. Cinematic wide establishing shot, professional cinematography, 16:9 aspect ratio, no people, atmospheric lighting, high detail, dramatic mood."

    try:
        logger.info(f"[LOC-REGEN] Regenerating {location_name} via {LOCATION_MODEL}")

        LIVE_GEN_TRACKER.add(
            project=project,
            shot_id=f"loc_{safe_name}",
            status="running",
            asset_type="location_master",
            prompt=visual_prompt,
            model=LOCATION_MODEL
        )

        result = fal_client.run(LOCATION_MODEL, arguments={
            "prompt": visual_prompt,
            "aspect_ratio": "16:9",
            "output_format": "jpeg",
            "num_images": 1
        })

        image_url = None
        if result.get("images") and len(result["images"]) > 0:
            image_url = result["images"][0].get("url")
        elif result.get("image"):
            image_url = result["image"].get("url")

        if not image_url:
            LIVE_GEN_TRACKER.update(f"loc_{safe_name}", "error")
            return {"success": False, "error": "No image URL in FAL response"}

        async with httpx.AsyncClient(timeout=60.0) as client:
            response = await client.get(image_url)
            if response.status_code == 200:
                with open(image_path, 'wb') as f:
                    f.write(response.content)
                local_url = f"/api/media?path={str(image_path)}"
                LIVE_GEN_TRACKER.update(f"loc_{safe_name}", "completed", url=local_url)

                # Invalidate bundle cache so UI picks up new image
                _invalidate_bundle_cache(project)

                logger.info(f"[LOC-REGEN] Regenerated: {location_name} -> {image_path}")
                return {
                    "success": True,
                    "location": location_name,
                    "path": str(image_path),
                    "url": local_url,
                    "model": LOCATION_MODEL
                }
            else:
                LIVE_GEN_TRACKER.update(f"loc_{safe_name}", "error")
                return {"success": False, "error": f"Download failed: {response.status_code}"}

    except Exception as e:
        LIVE_GEN_TRACKER.update(f"loc_{safe_name}", "error")
        logger.error(f"[LOC-REGEN] Error regenerating {location_name}: {e}")
        _sentry_capture_exception(e)
        return {"success": False, "error": str(e)[:300]}


@app.post("/api/auto/generate-story-bible")
async def generate_story_bible_from_script(request: Dict = Body(...)):
    """
    Generate story bible from uploaded script or concept using LLM.
    Extracts characters, locations, themes, and creates visual guidelines.

    V21.10: If a V6-ingested story bible already exists (from full-import),
    this endpoint ENRICHES it with visual fields instead of regenerating from scratch.
    """
    import httpx

    project = request.get("project", "new_project")
    script_text = request.get("script_text", "")
    concept = request.get("concept", "")
    genre = request.get("genre", "drama")
    runtime_minutes = request.get("runtime_minutes", 15)
    title = request.get("title", project)

    # V21.10: Check if a V6-ingested story bible already exists
    project_path = get_project_path(project)
    existing_bible_path = project_path / "story_bible.json"
    if existing_bible_path.exists():
        try:
            with open(existing_bible_path) as f:
                existing_bible = json.load(f)

            if existing_bible.get("_v6_header_parsed") and existing_bible.get("_ingested"):
                # V6-ingested bible exists — no need to regenerate from scratch
                # Just flag it as ready and return
                existing_bible["_story_bible_step"] = "v6_ingest_preserved"
                existing_bible["_skipped_llm_generation"] = True
                existing_bible["_note"] = (
                    "Story bible was INGESTED from V6 header during full-import. "
                    "LLM generation skipped — author's original data preserved. "
                    "Run generate-story-bible with force=true to override."
                )
                # Ensure genre is set
                if not existing_bible.get("genre") or existing_bible["genre"] == "drama":
                    existing_bible["genre"] = genre

                with open(existing_bible_path, 'w') as f:
                    json.dump(existing_bible, f, indent=2)

                logger.info(
                    f"[STORY_BIBLE] V6-ingested bible preserved for {project} — "
                    f"{len(existing_bible.get('characters', []))} characters, "
                    f"{len(existing_bible.get('aliases', {}))} aliases. "
                    f"LLM generation SKIPPED."
                )
                return {
                    "success": True,
                    "project": project,
                    "story_bible": existing_bible,
                    "saved_to": str(existing_bible_path),
                    "source": "v6_header_ingest",
                    "message": (
                        f"Story bible INGESTED from V6 header — "
                        f"{len(existing_bible.get('characters', []))} characters with descriptions preserved. "
                        f"LLM generation skipped. Use force=true to override."
                    )
                }
        except Exception as _check_err:
            logger.warning(f"[STORY_BIBLE] Error checking existing bible: {_check_err}")

    # V21.10: Check for force override
    force = request.get("force", False)
    if force:
        logger.info(f"[STORY_BIBLE] Force override — regenerating story bible for {project}")

    # Load .env for API key
    env_path = Path(str(BASE_DIR) + "/.env")
    api_key = ""
    if env_path.exists():
        with open(env_path) as f:
            for line in f:
                if line.startswith("OPENROUTER_API_KEY="):
                    api_key = line.split("=", 1)[1].strip()
                    break

    if not api_key:
        return {"success": False, "error": "OpenRouter API key not configured"}

    # Build prompt for story bible generation
    if script_text:
        user_prompt = f"""Analyze this script and generate a comprehensive story bible:

SCRIPT:
{script_text[:8000]}

Generate a JSON story bible with:
1. title - the story title
2. logline - one sentence summary
3. genre - primary and secondary genres
4. themes - 3-5 core themes
5. tone - visual and emotional tone
6. characters - array of {{name, role, description, arc, visual_prompt}}
7. locations - array of {{name, description, visual_prompt, lighting, time_of_day}}
8. color_palette - hex codes for the visual mood
9. cinematography - shot style preferences
10. pacing - rhythm and editing notes

Return ONLY valid JSON."""
    elif concept:
        user_prompt = f"""Create a story bible for this concept:

CONCEPT: {concept}
GENRE: {genre}
RUNTIME: {runtime_minutes} minutes
TITLE: {title}

Generate a JSON story bible with:
1. title - "{title}"
2. logline - one sentence summary
3. genre - primary and secondary genres
4. themes - 3-5 core themes
5. tone - visual and emotional tone
6. characters - array of 3-6 characters with {{name, role, description, arc, visual_prompt}}
7. locations - array of 2-4 locations with {{name, description, visual_prompt, lighting, time_of_day}}
8. color_palette - array of 4-6 hex codes for visual mood
9. cinematography - {{style, preferred_shots, camera_movement}}
10. pacing - {{rhythm, edit_style, tension_curve}}

Return ONLY valid JSON."""
    else:
        return {"success": False, "error": "Either script_text or concept is required"}

    try:
        async with httpx.AsyncClient(timeout=60.0) as client:
            response = await client.post(
                "https://openrouter.ai/api/v1/chat/completions",
                headers={
                    "Authorization": f"Bearer {api_key}",
                    "Content-Type": "application/json",
                    "HTTP-Referer": "https://atlas-control-system.local",
                    "X-Title": "ATLAS Story Bible Generator"
                },
                json={
                    "model": "anthropic/claude-sonnet-4",
                    "messages": [
                        {"role": "system", "content": "You are a professional screenwriter and story bible creator. Generate detailed, production-ready story bibles in JSON format."},
                        {"role": "user", "content": user_prompt}
                    ],
                    "temperature": 0.7,
                    "max_tokens": 4000
                }
            )

            if response.status_code != 200:
                logger.error(f"LLM API error: {response.status_code} - {response.text[:500]}")
                return {"success": False, "error": f"LLM API error: {response.status_code}"}

            result = response.json()
            content = result.get("choices", [{}])[0].get("message", {}).get("content", "")

            # Extract JSON from response
            json_match = re.search(r'\{[\s\S]*\}', content)
            if json_match:
                story_bible = json.loads(json_match.group())
            else:
                story_bible = {"raw_response": content, "parse_error": True}

            # Add metadata
            story_bible["_generated_at"] = datetime.now().isoformat()
            story_bible["_generator"] = "LLM:anthropic/claude-sonnet-4"
            story_bible["_project"] = project

            # Save to project directory
            project_path = get_project_path(project)
            project_path.mkdir(parents=True, exist_ok=True)

            # V21.10: SCENE COUNT VALIDATION — Bible must match screenplay
            # The _canonical_scene_count was stamped during full-import.
            # If the LLM generated a different number of scenes, reject.
            _shot_plan_path = project_path / "shot_plan.json"
            if _shot_plan_path.exists():
                try:
                    with open(_shot_plan_path) as _sp_f:
                        _sp_data = json.load(_sp_f)
                    _canonical_count = _sp_data.get("_canonical_scene_count", 0)
                    _bible_scenes = story_bible.get("scenes", [])
                    if _canonical_count > 0 and len(_bible_scenes) > 0 and len(_bible_scenes) != _canonical_count:
                        logger.error(
                            f"[STORY_BIBLE] SCENE COUNT MISMATCH — screenplay has "
                            f"{_canonical_count} scenes, LLM bible has {len(_bible_scenes)} scenes"
                        )
                        return {
                            "success": False,
                            "error": (
                                f"Story bible scene count mismatch: screenplay has "
                                f"{_canonical_count} scene headers, but LLM generated "
                                f"{len(_bible_scenes)} scenes. The screenplay is the authority. "
                                f"Common cause: INTERCUT blocks being split into separate scenes."
                            ),
                            "screenplay_scene_count": _canonical_count,
                            "bible_scene_count": len(_bible_scenes)
                        }
                    # Stamp the canonical count into the bible
                    story_bible["_canonical_scene_count"] = _canonical_count
                except Exception as _sc_err:
                    logger.warning(f"[STORY_BIBLE] Scene count validation skipped: {_sc_err}")

            # V21.10: NO HOLLOW SCENES — every scene must have beats
            _hollow_scenes = []
            for _sc in story_bible.get("scenes", []):
                if isinstance(_sc, dict):
                    _beats = _sc.get("beats", [])
                    _desc = _sc.get("description", "")
                    if not _beats and not _desc:
                        _hollow_scenes.append(_sc.get("scene_id", _sc.get("title", "unknown")))
            if _hollow_scenes:
                logger.warning(
                    f"[STORY_BIBLE] {len(_hollow_scenes)} hollow scenes detected "
                    f"(no beats, no description): {_hollow_scenes[:5]}"
                )
                story_bible["_hollow_scene_warning"] = _hollow_scenes

            bible_path = project_path / "story_bible.json"
            with open(bible_path, 'w') as f:
                json.dump(story_bible, f, indent=2)

            logger.info(f"[STORY_BIBLE] Generated for {project} with LLM")

            # V36.1: Auto-classify scene openers immediately after bible is saved.
            # Non-blocking — opener_manifest.json written to project dir for UI verification.
            try:
                import sys as _oi_sys
                _oi_sys.path.insert(0, str(BASE_DIR / "tools"))
                from opener_validator import run_ingestion_classification
                _opener_result = run_ingestion_classification(project_path, story_bible)
                story_bible["_opener_manifest_classified"] = True
                story_bible["_opener_scenes_count"] = _opener_result.get("scenes_classified", 0)
                logger.info(f"[OPENER] {_opener_result.get('scenes_classified', 0)} scenes classified → {_opener_result.get('opener_manifest_saved', '')}")
            except Exception as _oi_err:
                logger.warning(f"[OPENER] Ingestion classification failed (non-blocking): {_oi_err}")

            # V17.3: Temporal workflow tracking for story bible generation
            try:
                _wf_id = temporal_start_workflow(project, "generate_story_bible")
                temporal_run_activity(_wf_id, "generate_story_bible")
                _bible_summary = {"characters": len(story_bible.get("characters", [])), "locations": len(story_bible.get("locations", []))}
                temporal_complete_activity(_wf_id, "generate_story_bible", result=_bible_summary)
                temporal_complete_workflow(_wf_id, result=_bible_summary)
                _temporal_persist()
            except Exception:
                pass  # Temporal tracking is non-blocking

            return {
                "success": True,
                "project": project,
                "story_bible": story_bible,
                "saved_to": str(bible_path)
            }

    except Exception as e:
        logger.error(f"Story bible generation error: {e}")
        # V17.3: Track failure in Temporal
        try:
            _wf_id = temporal_start_workflow(project, "generate_story_bible")
            temporal_run_activity(_wf_id, "generate_story_bible")
            temporal_fail_activity(_wf_id, "generate_story_bible", str(e), should_retry=False)
            _temporal_persist()
        except Exception:
            pass  # Temporal tracking is non-blocking
        return {"success": False, "error": str(e)}

# ===================================================================
# V17.6: DIRECTOR'S BRIEF — Natural language scene/shot creation
# Two-phase: Parse (LLM extracts structure) → Execute (adds to shot plan)
# ===================================================================

def _find_next_scene_number(shot_plan: dict) -> int:
    """Find the next available scene number from existing shot plan."""
    max_scene = 0
    for shot in shot_plan.get("shots", []):
        scene_id = shot.get("scene_id", "000")
        try:
            num = int(scene_id)
            if num > max_scene:
                max_scene = num
        except (ValueError, TypeError):
            pass
    return max_scene + 1


def _build_brief_parse_prompt(brief_text: str, genre: str, story_bible: dict, next_scene_num: int) -> tuple:
    """Build system + user prompt for LLM to parse director's brief into structured scenes/shots."""

    # Extract known locations and characters for context
    known_locations = []
    if story_bible:
        for loc in story_bible.get("locations", []):
            name = loc.get("name", "")
            if name:
                known_locations.append(name)
        for scene in story_bible.get("scenes", []):
            setting = scene.get("setting", {})
            if isinstance(setting, dict):
                for loc in setting.get("locations", []):
                    if isinstance(loc, str) and loc not in known_locations:
                        known_locations.append(loc)
                loc_name = setting.get("name", "")
                if loc_name and loc_name not in known_locations:
                    known_locations.append(loc_name)

    known_characters = []
    if story_bible:
        for char in story_bible.get("characters", []):
            name = char.get("name", "")
            if name:
                known_characters.append(name)

    system_prompt = f"""You are a Director of Photography assistant for the ATLAS AI Film Production system.
Your job is to parse a director's verbal brief into structured scenes and shots.

RULES:
1. Group shots by location — each distinct location becomes a separate scene
2. Auto-detect shot types from keywords:
   - "establishing", "wide", "exterior" → establishing (duration: 14s)
   - "drone", "aerial", "overhead", "bird's eye" → aerial (duration: 16s)
   - "close-up", "face", "portrait", "CU" → close-up (duration: 10s)
   - "medium", "waist", "mid" → medium (duration: 12s)
   - "b-roll", "atmospheric", "mood", "texture" → b-roll (duration: 8s)
   - "insert", "detail", "macro", "ECU" → insert (duration: 6s)
   - "tracking", "follow", "walk" → action (duration: 12s)
   - "dialogue", "conversation", "talking" → dialogue (duration: 14s)
   - "reaction", "response" → reaction (duration: 8s)
   - Default to medium if unclear (duration: 12s)
3. Assign camera motion by type:
   - establishing/aerial → slow_crane
   - close-up/insert/reaction → static
   - tracking/action → handheld or steadicam
   - medium/dialogue → static or slow_dolly
4. Extract character names if mentioned (match against known characters)
5. Determine INT/EXT from context clues
6. Scene numbering starts at {next_scene_num:03d}
7. Return ONLY valid JSON — no prose, no markdown, no explanation

KNOWN LOCATIONS in this project: {json.dumps(known_locations[:20])}
KNOWN CHARACTERS in this project: {json.dumps(known_characters[:20])}
GENRE: {genre}

OUTPUT FORMAT (strict JSON):
{{
  "scenes": [
    {{
      "scene_number": "{next_scene_num:03d}",
      "location": "LOCATION NAME",
      "location_key": "location_name_lowercase",
      "int_ext": "EXT",
      "time_of_day": "DAY",
      "shots": [
        {{
          "description": "Wide establishing shot of the mansion from the coastal cliffs",
          "shot_type": "establishing",
          "duration": 14,
          "camera_motion": "slow_crane",
          "lens_hint": "24mm",
          "characters": []
        }}
      ]
    }}
  ]
}}"""

    user_prompt = f"""Parse this director's brief into structured scenes and shots:

BRIEF: {brief_text}

Return ONLY the JSON structure. Group by location. Detect shot types from my description."""

    return system_prompt, user_prompt


@app.post("/api/v17/directors-brief/parse")
async def directors_brief_parse(request: Dict = Body(...)):
    """
    V17.6: DIRECTOR'S BRIEF — PARSE PHASE
    Takes natural language brief and returns structured scenes/shots for preview.

    Body:
    {
        "project": "ravencroft_v17",
        "brief_text": "Outside Ravencroft mansion, coastal rocks, drone overhead, then law office exterior",
        "genre": "gothic_horror"
    }
    """
    import httpx

    project = request.get("project", "")
    brief_text = request.get("brief_text", "")
    genre = request.get("genre", "drama")

    if not project or not brief_text:
        return {"success": False, "error": "project and brief_text required"}

    project_path = get_project_path(project)

    # Load story bible for context
    story_bible = {}
    bible_path = project_path / "story_bible.json"
    if bible_path.exists():
        try:
            with open(bible_path) as f:
                story_bible = json.load(f)
        except Exception:
            pass

    # Load shot plan to find next scene number
    shot_plan = {}
    shot_plan_path = project_path / "shot_plan.json"
    if shot_plan_path.exists():
        try:
            with open(shot_plan_path) as f:
                shot_plan = _sp_guard(json.load(f))
        except Exception:
            pass

    next_scene_num = _find_next_scene_number(shot_plan)

    # Build LLM prompt
    system_prompt, user_prompt = _build_brief_parse_prompt(brief_text, genre, story_bible, next_scene_num)

    # Load OpenRouter API key
    env_path = Path(str(BASE_DIR) + "/.env")
    api_key = ""
    if env_path.exists():
        try:
            with open(env_path) as f:
                for line in f:
                    if line.startswith("OPENROUTER_API_KEY="):
                        api_key = line.split("=", 1)[1].strip()
                        break
        except Exception:
            pass

    if not api_key:
        return {"success": False, "error": "OpenRouter API key not configured in .env"}

    # Call LLM via OpenRouter
    try:
        async with httpx.AsyncClient(timeout=60.0) as client:
            response = await client.post(
                "https://openrouter.ai/api/v1/chat/completions",
                headers={
                    "Authorization": f"Bearer {api_key}",
                    "Content-Type": "application/json",
                    "HTTP-Referer": "https://atlas-studio.ai",
                    "X-Title": "ATLAS Director's Brief"
                },
                json={
                    "model": "anthropic/claude-sonnet-4",
                    "messages": [
                        {"role": "system", "content": system_prompt},
                        {"role": "user", "content": user_prompt}
                    ],
                    "temperature": 0.3,
                    "max_tokens": 4000
                }
            )

        if response.status_code != 200:
            return {"success": False, "error": f"LLM API error: {response.status_code} — {response.text[:200]}"}

        result = response.json()
        content = result.get("choices", [{}])[0].get("message", {}).get("content", "")

        # Extract JSON from response
        import re as _re
        json_match = _re.search(r'\{[\s\S]*\}', content)
        if not json_match:
            return {"success": False, "error": "LLM returned no valid JSON", "raw_response": content[:500]}

        parsed = json.loads(json_match.group())
        scenes = parsed.get("scenes", [])

        # Count total shots
        total_shots = sum(len(s.get("shots", [])) for s in scenes)

        logger.info(f"[DIRECTORS-BRIEF] Parsed '{brief_text[:60]}' → {len(scenes)} scenes, {total_shots} shots")

        return {
            "success": True,
            "parsed_scenes": scenes,
            "total_scenes": len(scenes),
            "total_shots": total_shots,
            "next_scene_num": next_scene_num,
            "brief_text": brief_text,
            "confidence": "high" if total_shots > 0 else "low"
        }

    except json.JSONDecodeError as e:
        return {"success": False, "error": f"Failed to parse LLM response as JSON: {e}"}
    except Exception as e:
        logger.error(f"[DIRECTORS-BRIEF] Parse error: {e}")
        return {"success": False, "error": str(e)}


@app.post("/api/v17/directors-brief/execute")
async def directors_brief_execute(request: Dict = Body(...)):
    """
    V17.6: DIRECTOR'S BRIEF — EXECUTE PHASE
    Takes parsed scenes from parse endpoint and adds them to the shot plan.

    Body:
    {
        "project": "ravencroft_v17",
        "parsed_scenes": [...],  // from parse endpoint
        "generate_frames": false,
        "generate_location_masters": true
    }
    """
    project = request.get("project", "")
    parsed_scenes = request.get("parsed_scenes", [])
    generate_frames = request.get("generate_frames", False)
    generate_loc_masters = request.get("generate_location_masters", True)

    if not project or not parsed_scenes:
        return {"success": False, "error": "project and parsed_scenes required"}

    project_path = get_project_path(project)
    shot_plan_path = project_path / "shot_plan.json"

    if not shot_plan_path.exists():
        return {"success": False, "error": f"Project '{project}' not found"}

    # Convert parsed scenes → shot definitions for quick-add-batch
    shot_defs = []
    new_locations = set()

    for scene in parsed_scenes:
        scene_num = scene.get("scene_number", "019")
        location = scene.get("location", "Unknown")
        int_ext = scene.get("int_ext", "INT")
        time_of_day = scene.get("time_of_day", "DAY")
        location_key = scene.get("location_key", location.lower().replace(" ", "_"))

        # Track new locations for potential master generation
        new_locations.add(location)

        for shot in scene.get("shots", []):
            shot_def = {
                "scene_id": scene_num,
                "description": shot.get("description", ""),
                "shot_type": shot.get("shot_type", "medium"),
                "duration": shot.get("duration", 12),
                "characters": shot.get("characters", []),
                "location": f"{int_ext}. {location} — {time_of_day}",
                "camera_style": shot.get("camera_motion", "static"),
                "lens": shot.get("lens_hint", "50mm"),
            }
            shot_defs.append(shot_def)

    if not shot_defs:
        return {"success": False, "error": "No shots extracted from parsed scenes"}

    # Use existing quick-add-batch endpoint internally
    batch_result = await quick_add_shots_batch({
        "project": project,
        "shots": shot_defs,
        "generate_immediately": generate_frames
    })

    # Invalidate bundle cache
    cache_dir = project_path / "ui_cache"
    if cache_dir.exists():
        dirty = cache_dir / "bundle.dirty"
        dirty.touch()

    # Optionally generate location masters for new locations
    loc_gen_result = None
    if generate_loc_masters and new_locations:
        # Check which locations don't have masters yet
        loc_dir = project_path / "location_masters"
        existing_masters = set()
        if loc_dir.exists():
            existing_masters = {img.stem.upper().replace("_", " ") for img in loc_dir.glob("*.jpg")}

        missing_locations = []
        for loc in new_locations:
            # Use scored matching to check if master exists (Rule 63)
            matched = find_location_match(loc, list(existing_masters), min_score=65)
            if not matched:
                missing_locations.append(loc)

        if missing_locations:
            loc_gen_result = {"new_locations_detected": missing_locations, "note": "Use Generate Location Masters to create reference images"}

    added_count = batch_result.get("added", 0)
    new_shot_ids = [r.get("shot_id") for r in batch_result.get("shots", []) if r.get("success")]

    logger.info(f"[DIRECTORS-BRIEF] Executed: {added_count} shots added across {len(parsed_scenes)} scenes")

    return {
        "success": True,
        "shots_added": added_count,
        "scenes_added": len(parsed_scenes),
        "new_shot_ids": new_shot_ids,
        "new_locations": list(new_locations),
        "location_masters": loc_gen_result,
        "batch_result": batch_result
    }


# ===================================================================
# V17.6: VOICE TRANSCRIPTION — FAL Whisper for cross-browser STT
# Chrome uses native Web Speech, Safari/Firefox fall back to this
# ===================================================================

@app.post("/api/v17/voice/transcribe")
async def voice_transcribe(request: Request):
    """
    V17.6: Cross-browser voice transcription via FAL Whisper.
    Accepts audio blob (webm/wav/mp3) and returns transcript.
    Used as fallback when Web Speech API is unavailable.
    """
    import httpx

    form = await request.form()
    audio_file = form.get("audio")
    if not audio_file:
        return JSONResponse({"success": False, "error": "No audio file provided"}, status_code=400)

    # Read audio data
    audio_data = await audio_file.read()
    if len(audio_data) < 1000:
        return {"success": False, "error": "Audio too short"}

    # Save temp file (Safari sends mp4, Chrome/Firefox send webm)
    import tempfile
    content_type = getattr(audio_file, 'content_type', '') or ''
    suffix = ".mp4" if "mp4" in content_type else ".webm"
    with tempfile.NamedTemporaryFile(suffix=suffix, delete=False) as tmp:
        tmp.write(audio_data)
        tmp_path = tmp.name

    try:
        # Upload to FAL for Whisper transcription
        fal_key = orchestrator.get_next_fal_key()

        # First upload the file to FAL storage
        async with httpx.AsyncClient(timeout=30.0) as client:
            upload_resp = await client.post(
                "https://fal.run/fal-ai/whisper",
                headers={
                    "Authorization": f"Key {fal_key}",
                    "Content-Type": "application/json"
                },
                json={
                    "audio_url": f"data:audio/webm;base64,{__import__('base64').b64encode(audio_data).decode()}",
                    "task": "transcribe",
                    "language": "en",
                    "chunk_level": "segment"
                }
            )

        if upload_resp.status_code != 200:
            logger.warning(f"[VOICE] FAL Whisper error: {upload_resp.status_code}")
            return {"success": False, "error": f"Whisper API error: {upload_resp.status_code}"}

        result = upload_resp.json()
        transcript = result.get("text", "").strip()

        logger.info(f"[VOICE] Transcribed: '{transcript[:80]}...'")
        return {
            "success": True,
            "transcript": transcript,
            "chunks": result.get("chunks", []),
            "language": result.get("language", "en")
        }

    except Exception as e:
        logger.error(f"[VOICE] Transcription error: {e}")
        return {"success": False, "error": str(e)}
    finally:
        try:
            os.unlink(tmp_path)
        except Exception:
            pass


# ===================================================================
# V17.6: DIRECTOR COMMAND ROUTER — Intent parsing from voice/text
# Turns natural language into structured ATLAS operations
# ===================================================================

@app.post("/api/v17/director/command")
async def director_command_router(request: Dict = Body(...)):
    """
    V17.6: Parse director voice/text command into intent + action plan.
    Returns a preview plan that must be committed before execution.

    Body:
    {
        "project": "ravencroft_v17",
        "command": "First scene intro b-roll. City skyline 6 seconds. Push into apartment exterior 8 seconds.",
        "context": {"current_scene": "001", "current_shot": "001_003A"}
    }
    """
    import httpx

    project = request.get("project", "")
    command = request.get("command", "")
    context = request.get("context", {})

    if not project or not command:
        return {"success": False, "error": "project and command required"}

    # Load project context for LLM
    project_path = get_project_path(project)
    shot_plan_path = project_path / "shot_plan.json"
    story_bible = {}
    shot_plan = {}

    bible_path = project_path / "story_bible.json"
    if bible_path.exists():
        try:
            with open(bible_path) as f:
                story_bible = json.load(f)
        except Exception:
            pass

    if shot_plan_path.exists():
        try:
            with open(shot_plan_path) as f:
                shot_plan = _sp_guard(json.load(f))
        except Exception:
            pass

    # Extract known entities
    known_chars = [c.get("name", "") for c in story_bible.get("characters", []) if c.get("name")]
    known_locs = []
    for loc in story_bible.get("locations", []):
        if loc.get("name"):
            known_locs.append(loc["name"])
    # Add location masters
    loc_dir = project_path / "location_masters"
    if loc_dir.exists():
        for img in loc_dir.glob("*.jpg"):
            loc_name = img.stem.replace("_", " ").title()
            if loc_name not in known_locs:
                known_locs.append(loc_name)

    existing_scenes = sorted(set(s.get("scene_id", "") for s in shot_plan.get("shots", [])))
    next_scene = _find_next_scene_number(shot_plan)

    # Intent classification prompt
    env_path = Path(str(BASE_DIR) + "/.env")
    api_key = ""
    if env_path.exists():
        try:
            with open(env_path) as f:
                for line in f:
                    if line.startswith("OPENROUTER_API_KEY="):
                        api_key = line.split("=", 1)[1].strip()
                        break
        except Exception:
            pass

    if not api_key:
        return {"success": False, "error": "OpenRouter API key not configured"}

    system_prompt = f"""You are a film director's AI assistant for ATLAS Film Production OS.
Parse the director's command into a structured action plan.

AVAILABLE INTENTS:
- CREATE_SCENE: Create new scene(s) with shots
- ADD_SHOTS: Add shots to existing scene
- EXTEND_DIALOGUE: Extend a dialogue scene with coverage (A/B cuts)
- ADD_BROLL: Add b-roll/establishing shots
- REGEN_SHOT: Regenerate a specific shot
- CHANGE_SHOT: Modify shot properties (lens, camera, duration)
- APPROVE_SCENE: Approve all shots in a scene
- RENDER_SCENE: Start rendering a scene
- STOP_QUEUE: Stop current generation
- ADD_AUDIO: Add atmosphere/SFX to scene

KNOWN CHARACTERS: {json.dumps(known_chars[:15])}
KNOWN LOCATIONS: {json.dumps(known_locs[:15])}
EXISTING SCENES: {json.dumps(existing_scenes[:20])}
NEXT SCENE NUMBER: {next_scene:03d}
CURRENT CONTEXT: Scene {context.get('current_scene', '?')}, Shot {context.get('current_shot', '?')}

RULES:
1. Detect ALL intents in the command (may be multiple)
2. For each intent, create an action with specific parameters
3. Duration defaults: establishing=16s, drone=20s, medium=12s, close-up=10s, b-roll=8s, dialogue=14s per speaker
4. If dialogue >15s with 2+ characters, auto-split into coverage segments
5. Match character/location names to known entities (fuzzy OK)
6. Return ONLY valid JSON

OUTPUT FORMAT:
{{
  "intents": ["CREATE_SCENE", "ADD_SHOTS"],
  "actions": [
    {{
      "intent": "CREATE_SCENE",
      "scene_number": "{next_scene:03d}",
      "location": "LOCATION NAME",
      "int_ext": "EXT",
      "time_of_day": "DAY",
      "shots": [
        {{
          "description": "Wide establishing of mansion from coastal cliffs",
          "shot_type": "establishing",
          "duration": 16,
          "camera_motion": "slow_crane",
          "lens": "24mm",
          "characters": []
        }}
      ]
    }}
  ],
  "summary": "Adding exterior establishing sequence at mansion"
}}"""

    try:
        async with httpx.AsyncClient(timeout=60.0) as client:
            response = await client.post(
                "https://openrouter.ai/api/v1/chat/completions",
                headers={
                    "Authorization": f"Bearer {api_key}",
                    "Content-Type": "application/json",
                    "HTTP-Referer": "https://atlas-studio.ai",
                    "X-Title": "ATLAS Director Command"
                },
                json={
                    "model": "anthropic/claude-sonnet-4",
                    "messages": [
                        {"role": "system", "content": system_prompt},
                        {"role": "user", "content": f"Director command: {command}"}
                    ],
                    "temperature": 0.2,
                    "max_tokens": 4000
                }
            )

        if response.status_code != 200:
            return {"success": False, "error": f"LLM error: {response.status_code}"}

        content = response.json().get("choices", [{}])[0].get("message", {}).get("content", "")

        import re as _re
        json_match = _re.search(r'\{[\s\S]*\}', content)
        if not json_match:
            return {"success": False, "error": "Could not parse command", "raw": content[:500]}

        plan = json.loads(json_match.group())

        # Count total shots across all actions
        total_shots = sum(len(a.get("shots", [])) for a in plan.get("actions", []))
        total_duration = sum(
            s.get("duration", 12)
            for a in plan.get("actions", [])
            for s in a.get("shots", [])
        )

        logger.info(f"[DIRECTOR-CMD] '{command[:60]}' → {len(plan.get('intents', []))} intents, {total_shots} shots")

        return {
            "success": True,
            "plan": plan,
            "total_shots": total_shots,
            "total_duration": total_duration,
            "command": command,
            "status": "preview"  # Must be committed to execute
        }

    except json.JSONDecodeError as e:
        return {"success": False, "error": f"Failed to parse plan: {e}"}
    except Exception as e:
        logger.error(f"[DIRECTOR-CMD] Error: {e}")
        return {"success": False, "error": str(e)}


@app.post("/api/v17/director/commit")
async def director_commit_plan(request: Dict = Body(...)):
    """
    V17.6: Commit a director plan (from /director/command) — executes all actions.
    Supports: CREATE_SCENE, ADD_SHOTS, EXTEND_DIALOGUE, ADD_BROLL, RENDER_SCENE, APPROVE_SCENE.
    """
    project = request.get("project", "")
    plan = request.get("plan", {})
    auto_render = request.get("auto_render", True)  # Auto-start rendering after adding shots

    if not project or not plan:
        return {"success": False, "error": "project and plan required"}

    actions = plan.get("actions", [])
    if not actions:
        return {"success": False, "error": "No actions in plan"}

    results = []
    all_new_shot_ids = []

    for action in actions:
        intent = action.get("intent", "")

        if intent in ("CREATE_SCENE", "ADD_SHOTS", "ADD_BROLL", "EXTEND_DIALOGUE"):
            # Convert to parsed_scenes format and use directors-brief/execute
            scene_data = {
                "scene_number": action.get("scene_number", "019"),
                "location": action.get("location", "Unknown"),
                "location_key": action.get("location", "unknown").lower().replace(" ", "_"),
                "int_ext": action.get("int_ext", "INT"),
                "time_of_day": action.get("time_of_day", "DAY"),
                "shots": action.get("shots", [])
            }

            # Handle dialogue auto-segmentation
            if intent == "EXTEND_DIALOGUE":
                scene_data["shots"] = _auto_segment_dialogue(action)

            exec_result = await directors_brief_execute({
                "project": project,
                "parsed_scenes": [scene_data],
                "generate_frames": False,  # We'll batch-gen after all actions
                "generate_location_masters": True
            })

            if exec_result.get("success"):
                new_ids = exec_result.get("new_shot_ids", [])
                all_new_shot_ids.extend(new_ids)
                results.append({
                    "intent": intent,
                    "success": True,
                    "shots_added": exec_result.get("shots_added", 0),
                    "shot_ids": new_ids
                })
            else:
                results.append({"intent": intent, "success": False, "error": exec_result.get("error", "Unknown")})

        elif intent == "APPROVE_SCENE":
            scene_id = action.get("scene_number", "")
            # Approve all shots in scene
            project_path = get_project_path(project)
            sp_path = project_path / "shot_plan.json"
            if sp_path.exists():
                with open(sp_path) as f:
                    sp = _sp_guard(json.load(f))
                count = 0
                for shot in sp.get("shots", []):
                    if shot.get("scene_id") == scene_id:
                        shot["approved"] = True
                        count += 1
                with open(sp_path, 'w') as f:
                    json.dump(sp, f, indent=2)
                results.append({"intent": "APPROVE_SCENE", "success": True, "approved_count": count})

        elif intent == "RENDER_SCENE":
            # Will be handled by auto_render below
            results.append({"intent": "RENDER_SCENE", "success": True, "queued": True})

        elif intent == "CHANGE_SHOT":
            # Update shot properties
            shot_id = action.get("shot_id", "")
            changes = action.get("changes", {})
            if shot_id and changes:
                project_path = get_project_path(project)
                sp_path = project_path / "shot_plan.json"
                if sp_path.exists():
                    with open(sp_path) as f:
                        sp = _sp_guard(json.load(f))
                    for shot in sp.get("shots", []):
                        if shot["shot_id"] == shot_id:
                            shot.update(changes)
                            break
                    with open(sp_path, 'w') as f:
                        json.dump(sp, f, indent=2)
                    results.append({"intent": "CHANGE_SHOT", "success": True, "shot_id": shot_id})

    # Auto-render: generate first frames for all new shots
    gen_result = None
    if auto_render and all_new_shot_ids:
        try:
            gen_result = await generate_first_frames_sequential(
                {"project": project, "shot_ids": all_new_shot_ids, "force": True}
            )
        except Exception as e:
            gen_result = {"error": str(e)}

    # Invalidate cache
    cache_dir = get_project_path(project) / "ui_cache"
    if cache_dir.exists():
        (cache_dir / "bundle.dirty").touch()

    logger.info(f"[DIRECTOR-COMMIT] {len(actions)} actions, {len(all_new_shot_ids)} new shots, auto_render={auto_render}")

    return {
        "success": True,
        "actions_executed": len(results),
        "results": results,
        "new_shot_ids": all_new_shot_ids,
        "generation": gen_result,
        "status": "committed"
    }


def _auto_segment_dialogue(action: dict) -> list:
    """
    V17.6: Auto-segment dialogue into A/B coverage shots.
    If dialogue >15s with 2+ characters, split into coverage pattern:
    A medium → B medium → A reaction → B close-up
    """
    shots = action.get("shots", [])
    characters = action.get("characters", [])
    total_duration = action.get("duration", 18)

    if len(characters) < 2 or total_duration <= 15:
        return shots  # No segmentation needed

    # Build coverage pattern
    char_a = characters[0] if characters else "CHARACTER A"
    char_b = characters[1] if len(characters) > 1 else "CHARACTER B"

    if total_duration <= 20:
        # 2-shot coverage: A medium + B medium
        seg_dur = total_duration // 2
        return [
            {
                "description": f"Medium shot of {char_a} speaking, engaged in conversation",
                "shot_type": "dialogue",
                "duration": seg_dur,
                "camera_motion": "static",
                "lens": "50mm",
                "characters": [char_a]
            },
            {
                "description": f"Medium shot of {char_b} responding, listening intently",
                "shot_type": "dialogue",
                "duration": total_duration - seg_dur,
                "camera_motion": "static",
                "lens": "50mm",
                "characters": [char_b]
            }
        ]
    else:
        # 4-shot coverage: A medium → B medium → A reaction → B close
        base = total_duration // 4
        remainder = total_duration - (base * 4)
        return [
            {
                "description": f"Medium shot of {char_a} delivering lines, steady gaze",
                "shot_type": "dialogue",
                "duration": base + remainder,
                "camera_motion": "static",
                "lens": "50mm",
                "characters": [char_a]
            },
            {
                "description": f"Medium shot of {char_b} responding, subtle emotion",
                "shot_type": "dialogue",
                "duration": base,
                "camera_motion": "static",
                "lens": "50mm",
                "characters": [char_b]
            },
            {
                "description": f"Close-up reaction of {char_a}, processing what was said",
                "shot_type": "reaction",
                "duration": base,
                "camera_motion": "static",
                "lens": "85mm",
                "characters": [char_a]
            },
            {
                "description": f"Close-up of {char_b}, emotional beat, eyes revealing intent",
                "shot_type": "close-up",
                "duration": base,
                "camera_motion": "static",
                "lens": "85mm",
                "characters": [char_b]
            }
        ]


# ===================================================================
# V17.6: AUTO-RENDER SCENE PIPELINE
# Full scene workflow: frames → multi-angle → rank → video → timeline
# ===================================================================

@app.post("/api/v17/director/render-scene")
async def director_render_scene(request: Dict = Body(...)):
    """
    V17.6: Auto-render an entire scene through the full pipeline.
    1. Generate first frames for all shots in scene
    2. Run multi-angle on hero shots (dialogue + establishing)
    3. Auto-rank variants via LOA
    4. Generate videos for approved frames
    5. Return progress updates via LIVE_GEN_TRACKER

    Body:
    {
        "project": "ravencroft_v17",
        "scene_id": "001",
        "multi_angle_types": ["establishing", "dialogue", "close-up"],
        "auto_approve": true,
        "render_videos": true
    }
    """
    project = request.get("project", "")
    scene_id = request.get("scene_id", "")
    multi_angle_types = request.get("multi_angle_types", ["establishing", "dialogue", "close-up"])
    auto_approve = request.get("auto_approve", True)
    render_videos = request.get("render_videos", True)

    if not project or not scene_id:
        return {"success": False, "error": "project and scene_id required"}

    project_path = get_project_path(project)
    shot_plan_path = project_path / "shot_plan.json"

    if not shot_plan_path.exists():
        return {"success": False, "error": "Project not found"}

    with open(shot_plan_path) as f:
        data = json.load(f)

    scene_shots = [s for s in data.get("shots", []) if s.get("scene_id") == scene_id]
    if not scene_shots:
        return {"success": False, "error": f"Scene {scene_id} not found"}

    shot_ids = [s["shot_id"] for s in scene_shots]
    hero_shot_ids = [s["shot_id"] for s in scene_shots if s.get("shot_type") in multi_angle_types]

    pipeline_result = {
        "scene_id": scene_id,
        "total_shots": len(scene_shots),
        "phases": {}
    }

    # Phase 1: Generate first frames
    LIVE_GEN_TRACKER.update(f"scene_{scene_id}", "generating_frames")
    try:
        frame_result = await generate_first_frames_sequential(
            {"project": project, "shot_ids": shot_ids, "force": True}
        )
        pipeline_result["phases"]["frames"] = {
            "success": True,
            "generated": frame_result.get("results_count", 0) if isinstance(frame_result, dict) else 0
        }
    except Exception as e:
        pipeline_result["phases"]["frames"] = {"success": False, "error": str(e)}
        logger.error(f"[SCENE-RENDER] Frame generation failed for scene {scene_id}: {e}")

    # Phase 2: Multi-angle on hero shots (if multi-angle endpoint exists)
    if hero_shot_ids:
        LIVE_GEN_TRACKER.update(f"scene_{scene_id}", "multi_angle")
        multi_results = []
        for sid in hero_shot_ids[:5]:  # Cap at 5 hero shots per scene
            try:
                # Call multi-angle endpoint directly
                ma_result = await generate_multi_angle_variants(
                    {"project": project, "shot_id": sid, "run_dino": True}
                )
                multi_results.append({"shot_id": sid, "success": ma_result.get("success", False)})
            except Exception as e:
                multi_results.append({"shot_id": sid, "success": False, "error": str(e)})
        pipeline_result["phases"]["multi_angle"] = {"results": multi_results}

    # Phase 3: Auto-approve if requested
    if auto_approve:
        LIVE_GEN_TRACKER.update(f"scene_{scene_id}", "approving")
        with open(shot_plan_path) as f:
            data = json.load(f)
        approved_count = 0
        for shot in data.get("shots", []):
            if shot.get("scene_id") == scene_id and shot.get("first_frame_path"):
                shot["approved"] = True
                approved_count += 1
        with open(shot_plan_path, 'w') as f:
            json.dump(data, f, indent=2)
        pipeline_result["phases"]["approve"] = {"approved": approved_count}

    # Phase 4: Render videos if requested
    if render_videos:
        LIVE_GEN_TRACKER.update(f"scene_{scene_id}", "rendering_videos")
        try:
            vid_result = await render_videos_batch(
                {"project": project, "shot_ids": shot_ids, "dry_run": False}
            )
            pipeline_result["phases"]["videos"] = {
                "success": True,
                "rendered": vid_result.get("results_count", 0) if isinstance(vid_result, dict) else 0
            }
        except Exception as e:
            pipeline_result["phases"]["videos"] = {"success": False, "error": str(e)}

    # Invalidate cache
    cache_dir = project_path / "ui_cache"
    if cache_dir.exists():
        (cache_dir / "bundle.dirty").touch()

    LIVE_GEN_TRACKER.update(f"scene_{scene_id}", "completed")

    logger.info(f"[SCENE-RENDER] Scene {scene_id}: {len(scene_shots)} shots through full pipeline")

    return {
        "success": True,
        "project": project,
        "pipeline": pipeline_result
    }


@app.post("/api/auto/render-videos")
async def render_videos_batch(request: Dict = Body(...)):
    """
    V16.7.1: Render videos for shots using LTX-2 image-to-video model.

    Requires first frames to exist. Uses locked model: fal-ai/ltx-2.3/image-to-video/fast

    Body:
    {
        "project": "kord",
        "shot_ids": ["001_001A"],  // optional, empty = all shots with first frames
        "dry_run": false
    }
    """
    # V18.3.1: Model-aware video generation — LTX-2 (default) or Kling 3.0
    video_model = request.get("video_model", "kling")
    if video_model == "kling":
        VIDEO_MODEL = "fal-ai/kling-video/v3/pro/image-to-video"
    elif video_model == "seeddance":
        VIDEO_MODEL = "fal-ai/bytedance/seedance/v2/image-to-video"
    else:
        VIDEO_MODEL = "fal-ai/ltx-2.3/image-to-video/fast"

    project = request.get("project", "")
    shot_ids = request.get("shot_ids", [])
    dry_run = request.get("dry_run", False)
    force_overwrite = request.get("force", False)  # V17.8.3: Force re-render existing videos
    lite_mode = request.get("lite_mode", False)  # V22: Skip prompt enrichment at render time
    parallel_mode = request.get("parallel", False)  # V27.3: Temporal/asyncio parallel render

    if not project:
        return {"success": False, "error": "Project name required"}

    # V22.3 FILM ENGINE GATE — block if not prepped
    _require_ready(project)

    project_path = get_project_path(project)
    shot_plan_path = project_path / "shot_plan.json"

    if not shot_plan_path.exists():
        return {"success": False, "error": f"Project '{project}' not found"}

    with open(shot_plan_path) as f:
        data = json.load(f)

    # V27.1: Handle both list format [shots...] and dict format {"shots": [...]}
    if isinstance(data, list):
        shots = data
        data = {"shots": data}
    else:
        shots = data.get("shots", [])

    # =========================================================================
    # V23 PRODUCTION ROUTE GUARD: Prefer master-chain for production
    # The legacy render-videos path lacks:
    #   - End-frame chaining (visual continuity)
    #   - Multi-angle variant selection
    #   - Scene-level consistency enforcement
    # For production, use /api/v18/master-chain/render-scene instead.
    # =========================================================================
    generation_mode = data.get("_generation_mode", "").lower()
    force_legacy = request.get("force_legacy", False)  # Escape hatch for debugging

    if generation_mode == "master_chain" and not force_legacy and not dry_run:
        logger.warning(f"[V23 ROUTE GUARD] Project '{project}' has generation_mode=master_chain but using legacy render endpoint")
        return {
            "success": False,
            "error": "PRODUCTION ROUTE GUARD: This project is configured for master-chain generation.",
            "hint": "Use POST /api/v18/master-chain/render-scene with scene_id for proper visual continuity.",
            "alternative": f"/api/v18/master-chain/render-scene with project='{project}' and scene_id",
            "bypass": "Add 'force_legacy': true to force legacy path (not recommended for production)",
            "reason": "Master-chain provides end-frame chaining and scene-level consistency enforcement."
        }

    # =========================================================================
    # V37 ROUTE REDIRECT: Force ALL production video generation through the runner.
    # The legacy render-videos path LACKS:
    #   - Chain Intelligence Gate (pre/post-gen quality enforcement)
    #   - Arc position enrichment (ESTABLISH→ESCALATE→PIVOT→RESOLVE)
    #   - CPC decontamination (generic pattern removal before FAL)
    #   - Room DNA + location master anchoring (V36.4 environment drift fix)
    #   - End-frame chaining with chain_group propagation
    # Use force_legacy=true ONLY for debugging. Never in production.
    # =========================================================================
    if not force_legacy and not dry_run:
        import subprocess as _subprocess, sys as _sys, threading as _redir_thread
        _redir_runner_path = Path(__file__).parent / "atlas_universal_runner.py"
        # Extract scene IDs from shots (shot_id first 3 chars are scene_id, e.g. "001")
        _redir_scenes = sorted(set(
            (s.get("scene_id") or s.get("shot_id", "001")[:3])
            for s in shots
        )) if shots else ["001"]
        _redir_cmd = [_sys.executable, str(_redir_runner_path), project] + _redir_scenes + \
                     ["--mode", "lite", "--videos-only"]
        logger.warning(
            f"[V37 ROUTE REDIRECT] /api/auto/render-videos → atlas_universal_runner "
            f"(scenes: {_redir_scenes}). Legacy path lacks chain gate + arc positions + "
            f"room DNA. Add 'force_legacy': true to bypass (debugging only)."
        )
        _redir_pdir = get_project_path(project)

        def _bg_redir_runner():
            try:
                proc = _subprocess.Popen(
                    _redir_cmd, cwd=str(Path(__file__).parent),
                    stdout=_subprocess.PIPE, stderr=_subprocess.STDOUT, text=True
                )
                stdout, _ = proc.communicate(timeout=1200)
                logger.info(f"[V37 REDIR] Runner finished (exit={proc.returncode}):\n{stdout[-2000:]}")
                try:
                    _bc = _redir_pdir / "ui_cache" / "bundle.json"
                    if _bc.exists():
                        _bc.unlink()
                except Exception:
                    pass
            except Exception as _redir_err:
                logger.error(f"[V37 REDIR] Runner error: {_redir_err}")

        _redir_thread.Thread(target=_bg_redir_runner, daemon=True).start()
        return {
            "success": True,
            "status": "redirected_to_runner",
            "project": project,
            "scenes": _redir_scenes,
            "runner_cmd": " ".join(_redir_cmd),
            "hint": (
                "Redirected to atlas_universal_runner --videos-only which has chain gate, "
                "arc positions, room DNA anchoring, and end-frame chaining. "
                "Add 'force_legacy': true to use the legacy direct path (debugging only)."
            ),
        }

    # Filter shots if specific IDs provided
    if shot_ids:
        shots = [s for s in shots if s.get("shot_id") in shot_ids]
    else:
        # Only process shots that have first frames
        shots = [s for s in shots if s.get("first_frame_path")]

    # ===================================================================
    # V17.2 AGENT COORDINATOR — AUTOMATIC PRE-VIDEO ENFORCEMENT
    # Ensures all LTX prompts have timing clauses + face stability
    # before any video generation call reaches FAL API.
    # ===================================================================
    try:
        sys.path.insert(0, str(Path(__file__).parent / "atlas_agents_v16_7"))
        from atlas_agents.agent_coordinator import AgentCoordinator
        coordinator = AgentCoordinator(project_path, story_bible=data.get("story_bible"))
        video_gate = coordinator.pre_video_gate(shots)
        logger.info(f"[V17.2 AGENT] Pre-video gate: {video_gate['enforcement']['stats']['shots_modified']} LTX prompts enforced in {video_gate.get('gate_ms', 0)}ms")
    except Exception as agent_err:
        # V17.4: HARD GATE — video enforcement MUST succeed for render to proceed
        logger.error(f"[V17.4 AGENT] Video enforcement FAILED — render BLOCKED: {agent_err}")
        _sentry_capture_exception(agent_err)
        return {
            "success": False,
            "error": f"Pre-render gate FAILED: Video enforcement unavailable — {str(agent_err)[:200]}",
            "gate_blocked": True,
            "suggested_action": "Check agent files in atlas_agents_v16_7/ and restart server"
        }
    # ===================================================================

    # ═══ V26: DOCTRINE COMMAND SYSTEM — Render-Videos Pre-Generation Gate ═══
    _rv_doctrine_runner = None
    if DOCTRINE_AVAILABLE and not dry_run:
        try:
            _rv_doctrine_runner = _get_doctrine_runner(str(project_path))
            # Load cast_map for doctrine context
            _rv_cast_map = {}
            _rv_cast_path = project_path / "cast_map.json"
            if _rv_cast_path.exists():
                with open(_rv_cast_path) as _rv_cm_f:
                    _rv_cast_map = json.load(_rv_cm_f)
            _rv_story_bible = {}
            _rv_sb_path = project_path / "story_bible.json"
            if _rv_sb_path.exists():
                with open(_rv_sb_path) as _rv_sb_f:
                    _rv_story_bible = json.load(_rv_sb_f)
            _rv_manifest = data.get("scene_manifest", {})
            _rv_doc_init = _rv_doctrine_runner.scene_initialize(
                shots, _rv_manifest, _rv_story_bible.get("scenes", {}), _rv_cast_map
            )
            logger.info(f"[DOCTRINE-VIDEO] Scene initialized: {_rv_doc_init.get('status')} — {len(shots)} shots")
            if _rv_doc_init.get("status") == "REJECTED":
                logger.error(f"[DOCTRINE-VIDEO] HARD STOP: {_rv_doc_init.get('reason')}")
                return {
                    "success": False,
                    "error": f"DOCTRINE HARD STOP (video): {_rv_doc_init.get('reason')}",
                    "doctrine_status": _rv_doc_init
                }
        except Exception as _rv_doc_err:
            logger.warning(f"[DOCTRINE-VIDEO] Scene init non-blocking: {_rv_doc_err}")
    # ═══════════════════════════════════════════════════════════════════

    # V17.3: Load story bible + director/writer profiles via central helpers
    story_bible = data.get("story_bible", {})
    if not story_bible:
        story_bible_path = project_path / "story_bible.json"
        if story_bible_path.exists():
            try:
                with open(story_bible_path) as f:
                    story_bible = json.load(f)
            except Exception:
                pass

    director_profile = load_director_for_project(project_path, story_bible)
    writer_profile = load_writer_for_project(project_path, story_bible)

    # Create videos directory — V22.2: Model-aware directory
    if video_model == "kling":
        videos_dir = project_path / "videos_kling"
    else:
        videos_dir = project_path / "videos"
    videos_dir.mkdir(parents=True, exist_ok=True)

    # =========================================================================
    # V27.3: PARALLEL RENDER PATH — Fire all shots simultaneously via asyncio
    # When parallel=true, bypasses the sequential loop and uses Temporal worker
    # or in-process asyncio.gather for massive speedup (48min → ~8min for Kling).
    # =========================================================================
    if parallel_mode and not dry_run:
        try:
            from tools.temporal_render_worker import parallel_render_in_process, TEMPORAL_AVAILABLE as _TEMP_OK
            logger.info(f"[V27.3 PARALLEL] Firing {len(shots)} shots in parallel ({video_model}) — temporal={'yes' if _TEMP_OK else 'in-process'}")
            print(f"  [PARALLEL-RENDER] {len(shots)} shots × {video_model} — ALL firing simultaneously", flush=True)

            # Build chain groups from shot plan if available
            _chain_groups = []  # TODO: extract from chain_policy if wired

            _par_result = await parallel_render_in_process(
                project=project,
                scene_id=shots[0].get("scene_id", "001") if shots else "001",
                shots=shots,
                video_model=video_model,
                chain_groups=_chain_groups,
            )

            _par_ok = _par_result.get("successful", 0)
            _par_fail = _par_result.get("failed", 0)
            logger.info(f"[V27.3 PARALLEL] Complete: {_par_ok} success, {_par_fail} failed")
            print(f"  [PARALLEL-RENDER] Done: {_par_ok}/{len(shots)} succeeded", flush=True)

            return {
                "success": _par_ok > 0,
                "mode": "parallel",
                "total_shots": len(shots),
                "generated": _par_ok,
                "failed": _par_fail,
                "video_model": video_model,
                "results": _par_result.get("results", {}),
            }
        except Exception as _par_err:
            logger.warning(f"[V27.3 PARALLEL] Parallel render failed, falling back to sequential: {_par_err}")
            print(f"  [PARALLEL-RENDER] Fallback to sequential: {_par_err}", flush=True)
            # Fall through to sequential path
    # =========================================================================

    # Prepare generation plan
    generation_plan = []
    results = []
    modified_shot_ids = []

    for shot in shots:
        shot_id = shot.get("shot_id", "unknown")
        first_frame_path = shot.get("first_frame_path")
        # V24.1: Prefer Film Engine compiled LTX prompt if available
        ltx_prompt = shot.get("ltx_prompt_v24") or shot.get("ltx_motion_prompt", "")
        duration = int(shot.get("duration", shot.get("duration_seconds", 20)))
        segments = shot.get("segments", [])

        # ═══════════════════════════════════════════════════════════════════════
        # V27.1.4e: VIDEO PROMPT AUTHORITY — ALWAYS compile clean for dialogue shots
        # The disk ltx_motion_prompt is CONTAMINATED by 7 different systems:
        #   1. enforcement_agent: "character speaks: CHARACTER_NAME..."
        #   2. orchestrator V23: "PERFORMANCE MANDATORY:..."
        #   3. continuity_memory: "CONTINUITY MEMORY:" + "REFRAME PLAN:" + "EXECUTION CONSTRAINTS:"
        #   4. fix-v16 CHECK 5A: stacked dialogue markers
        #   5. fidelity validator: "character speaks: NAME says..."
        #   6. batch_enricher: dedup too coarse, leaves variations
        #   7. turbo path: "subtle gestures while speaking"
        # FIX: For ANY dialogue shot, ALWAYS compile from scratch. The compiled
        # prompt is ALWAYS cleaner, uses appearance descriptions not names,
        # has STATIC CAMERA, organic film quality, and narrative-driven performance.
        # For non-dialogue shots, pass through the disk prompt unchanged.
        # ═══════════════════════════════════════════════════════════════════════
        _shot_chars = shot.get("characters") or []
        _has_dialogue = bool(shot.get("dialogue_text") and _shot_chars)
        if _has_dialogue:
            try:
                # Inject beats first (same as generate-first-frames)
                if not shot.get("beat") and _rv_story_bible:
                    _bid = shot.get("beat_id", "")
                    if _bid:
                        _parts = _bid.split("_beat_")
                        if len(_parts) == 2:
                            _sc_id = _parts[0]
                            try:
                                _bi = int(_parts[1])
                            except ValueError:
                                _bi = -1
                            for _sc in _rv_story_bible.get("scenes", []):
                                if _sc.get("scene_id") == _sc_id:
                                    _sb_beats = _sc.get("beats", [])
                                    if _sb_beats:
                                        _clamped = min(_bi, len(_sb_beats) - 1)
                                        if _clamped >= 0:
                                            shot["beat"] = _sb_beats[_clamped].get("description", "")
                                            shot["emotional_beat"] = shot["beat"]
                                            shot["_beat_character_action"] = _sb_beats[_clamped].get("character_action", "")
                                    break
                # Compile clean video prompt
                from tools.ots_enforcer import OTSEnforcer
                _rv_cast_path_check = project_path / "cast_map.json"
                _rv_cm = {}
                if _rv_cast_path_check.exists():
                    with open(_rv_cast_path_check) as _f:
                        _rv_cm = json.load(_f)
                _rv_enforcer = OTSEnforcer(_rv_cm)
                ltx_prompt = _rv_enforcer.compile_universal_video_prompt(shot)
                if ltx_prompt:
                    shot["ltx_motion_prompt"] = ltx_prompt
                    logger.info(f"[V27.1.4e VIDEO-GATE] {shot_id}: recompiled clean video prompt ({len(ltx_prompt)} chars)")
                    print(f"  [VIDEO-GATE] {shot_id}: CLEAN prompt {len(ltx_prompt)} chars (was contaminated)", flush=True)
                    # V27.1.4f: Kling gets SAME clean prompt as LTX — dialogue preserved for audio
                    # Both models benefit from the clean compiled prompt with full narrative context
            except Exception as _vp_err:
                logger.warning(f"[V27.1.4e VIDEO-GATE] {shot_id}: recompile failed (non-blocking): {_vp_err}")

        # ═══════════════════════════════════════════════════════════════════════
        # V24.2: RENDER-VIDEOS — ZERO LTX ENRICHMENT (2026-03-10)
        #
        # The V24.2 compiler already built the LTX prompt with:
        #   - Focal length + aperture (research-aligned, no camera brands)
        #   - Camera motion (colon-separated zones)
        #   - Performance markers (character performs/speaks/reacts)
        #   - Color science + face constraints + timing
        #   - Dialogue injection (character speaks:)
        #   - Coverage role framing (A/B/C)
        #
        # OLD RENDER-TIME MUTATION REMOVED:
        #   ❌ Timing sync (V17.7)           → V24.2 uses narrative timing
        #   ❌ Cinematic enricher (V17.1)     → V24.2 handles quality/motion
        #   ❌ Audio constraints (V17.3)      → kept as lightweight append
        #   ❌ Dialogue injection (V18.3.1)   → V24.2 compiler handles
        #   ❌ Beat action injection (V18.3.1)→ V24.2 compiler handles
        #   ❌ Authority gate (V21.4)         → V24.2 is clean from source
        #   ❌ LITE save/restore (V22)        → No mutations to save/restore
        #   ❌ V22.3 camera embedding         → V24.2 has focal+aperture
        #
        # KEPT: Audio mode (lightweight, doesn't conflict with V24.2)
        # ═══════════════════════════════════════════════════════════════════════

        # V25 CURE 1: AUDIO tags REMOVED — LTX-2 does NOT generate audio.
        # These tags wasted ~20 tokens per prompt and confused the motion model.
        # OLD: "AUDIO: dry studio dialogue, close mic recording, no background music, voice only audio"
        # Audio will be handled by a separate audio pipeline, not LTX motion prompts.

        logger.info(f"[V24.2 RENDER] {shot_id}: ltx={len(ltx_prompt)} chars — zero enrichment, research-aligned")

        # V21.4 LOCKED — raised from 1200 to 1800 — dialogue was being truncated — DO NOT lower
        # V21.4: Raised limit — dialogue + emotion + camera all need room
        # LTX-2 handles up to ~2000 chars well; truncation was cutting dialogue
        if len(ltx_prompt) > 1800:
            ltx_prompt = ltx_prompt[:1797] + "..."

        # V18.3.1: Model-aware max duration per single generation pass.
        # LTX-2: up to 20s (480 frames at 24fps) — covers all standard durations
        # Kling 3.0: max 15s per generation — longer shots get segmented + stitched
        if video_model == "kling":
            LTX_MAX_SINGLE_DURATION = 15  # Kling 3.0 hard limit
            LTX_MAX_FRAMES = 375  # ~15s * 25fps (Kling native)
        else:
            LTX_MAX_SINGLE_DURATION = 20  # LTX-2 handles up to 20s single pass
            LTX_MAX_FRAMES = 480  # 20s * 24fps
        total_segments = shot.get("ltx_metadata", {}).get("total_segments", 1)

        # If shot has explicit segments, use them; otherwise auto-segment if over model limit
        if not segments and duration > LTX_MAX_SINGLE_DURATION:
            # Auto-segment: Kling >15s or LTX >20s — split into max-duration chunks + stitch
            num_segs = max(1, (duration + LTX_MAX_SINGLE_DURATION - 1) // LTX_MAX_SINGLE_DURATION)
            seg_dur = round(duration / num_segs, 1)
            segments = [{"segment_index": i, "duration": min(seg_dur, LTX_MAX_SINGLE_DURATION), "status": "pending"} for i in range(num_segs)]
            logger.info(f"[VIDEO_RENDER] V18.3.1 Auto-segmented {shot_id} ({video_model}): {duration}s → {num_segs} segments of {seg_dur:.1f}s (max {LTX_MAX_SINGLE_DURATION}s)")
        elif not segments and duration <= LTX_MAX_SINGLE_DURATION:
            # Single generation — within model limit (LTX≤20s, Kling≤15s)
            segments = [{"segment_index": 0, "duration": duration, "status": "pending"}]
            logger.info(f"[VIDEO_RENDER] V18.3.1 Single-pass {shot_id} ({video_model}): {duration}s (within {LTX_MAX_SINGLE_DURATION}s limit)")

        # Skip if no first frame
        if not first_frame_path:
            results.append({
                "shot_id": shot_id,
                "status": "skipped",
                "reason": "no_first_frame"
            })
            continue

        # Check if first frame file exists
        frame_path = Path(first_frame_path)
        if not frame_path.exists():
            # Try relative path from project
            frame_path = project_path / "first_frames" / f"{shot_id}.jpg"
            if not frame_path.exists():
                results.append({
                    "shot_id": shot_id,
                    "status": "skipped",
                    "reason": "first_frame_not_found"
                })
                continue

        # V17.3: Secondary safety net — should already be segmented above, but just in case
        was_auto_segmented = False
        if not segments and duration > LTX_MAX_SINGLE_DURATION:
            num_segs = max(1, (duration + LTX_MAX_SINGLE_DURATION - 1) // LTX_MAX_SINGLE_DURATION)
            seg_dur = round(duration / num_segs, 1)
            segments = [{"segment_index": si, "duration": min(seg_dur, LTX_MAX_SINGLE_DURATION), "status": "pending"} for si in range(num_segs)]
            was_auto_segmented = True
            logger.info(f"[VIDEO_RENDER] V17.3 Safety-net segmented {shot_id}: {duration}s → {num_segs}x{seg_dur}s")

        plan_entry = {
            "shot_id": shot_id,
            "model": VIDEO_MODEL,
            "first_frame": str(frame_path),
            "duration": duration,
            "actual_duration": duration,  # V17.3: Never lie about duration
            "auto_segmented": was_auto_segmented,
            "segments": len(segments) if segments else 1,
            "prompt_preview": ltx_prompt[:100] + "..." if len(ltx_prompt) > 100 else ltx_prompt
        }
        generation_plan.append(plan_entry)

        if dry_run:
            continue

        # =========================================================================
        # V23 HARD GATE: Performance marker enforcement
        # Character shots MUST have speaks:/performs:/reacts: in LTX prompt.
        # Without this, LTX-2 generates static robot faces during dialogue.
        # =========================================================================
        ltx_prompt = ensure_performance_marker(shot, ltx_prompt)
        # Update shot dict so UI bundle shows the enforced prompt
        shot["ltx_motion_prompt"] = ltx_prompt

        # V17: Generate video for each segment (or single if no segments)
        # V17.3: Segments already created above (auto or explicit). Never silently cap.
        # V17.3: No silent caps. If no segments exist, create them properly.
        if segments:
            segments_to_generate = segments
        elif duration > LTX_MAX_SINGLE_DURATION:
            # V18.3.1: Auto-segment for shots over model limit (Kling>15s, LTX>20s)
            num_segs = max(1, (duration + LTX_MAX_SINGLE_DURATION - 1) // LTX_MAX_SINGLE_DURATION)
            seg_dur = round(duration / num_segs, 1)
            segments_to_generate = [{"segment_index": si, "duration": min(seg_dur, LTX_MAX_SINGLE_DURATION)} for si in range(num_segs)]
            logger.info(f"[VIDEO_RENDER] V18.3.1 Late auto-segment {shot_id} ({video_model}): {duration}s → {num_segs}x{seg_dur}s")
        else:
            # V18.3.1: Single-pass — within model limit
            segments_to_generate = [{"segment_index": 0, "duration": duration}]

        for seg_idx, segment in enumerate(segments_to_generate):
            seg_suffix = f"_seg{seg_idx}" if len(segments_to_generate) > 1 else ""
            output_path = videos_dir / f"{shot_id}{seg_suffix}.mp4"

            # Skip if already exists (unless force overwrite)
            if output_path.exists() and not force_overwrite:
                results.append({
                    "shot_id": shot_id,
                    "segment": seg_idx,
                    "status": "skipped",
                    "reason": "already_exists",
                    "path": str(output_path)
                })
                continue

            seg_duration = segment.get("duration", 8)
            logger.info(f"[VIDEO_RENDER] {'FORCE re-generating' if force_overwrite else 'Generating'} {shot_id} seg{seg_idx} via LTX-2 ({seg_duration:.1f}s)")

            # V16.7.1: Track generation for live UI
            LIVE_GEN_TRACKER.add(
                project=project,
                shot_id=f"{shot_id}{seg_suffix}",
                status="running",
                asset_type="video",
                prompt=ltx_prompt,
                model=VIDEO_MODEL
            )

            try:
                # Convert first frame to base64 for FAL API
                image_base64 = convert_local_url_to_base64(str(frame_path))

                # Call LTX-2 video model
                # V17.3: LTX-2 requires 'image_url' (first frame as visual reference)
                # Max 360 frames (15s at 24fps) per generation
                # V17.8.1: FAL LTX-2 Fast endpoint uses 'duration' (seconds), NOT 'num_frames'
                # num_frames is for the 19B/LoRA endpoints only. Fast endpoint ignores it
                # and falls back to default ~6s. Max duration: 20s. FPS: 25.
                # V25.1: Model-aware valid durations
                # LTX-2.3: even durations 6-20s | Kling 3.0: 3-15s continuous
                if video_model == "kling":
                    LTX_VALID_DURATIONS = [3, 5, 8, 10, 12, 15]
                else:
                    LTX_VALID_DURATIONS = [6, 8, 10, 12, 14, 16, 18, 20]
                raw_dur = min(seg_duration, LTX_MAX_SINGLE_DURATION)
                api_duration = min((d for d in LTX_VALID_DURATIONS if d >= raw_dur), default=20)
                logger.info(f"[VIDEO_RENDER] LTX-2 call: {shot_id} seg{seg_idx} | {seg_duration}s planned → {api_duration}s API | first_frame={frame_path.name}")
                # V21.6: Pass negative_prompt — identity prevention belongs in negatives, not positive prompt
                _rv_neg = (shot.get("negative_prompt") or "blurry, distorted face, morphing, low quality, text, watermark, extra limbs")
                # V25.1: Kling 3.0 uses start_image_url, LTX uses image_url
                _img_key = "start_image_url" if video_model == "kling" else "image_url"
                result = fal_client.run(VIDEO_MODEL, arguments={
                    _img_key: image_base64,
                    "prompt": ltx_prompt,
                    "negative_prompt": _rv_neg,
                    "duration": api_duration,
                    "aspect_ratio": "16:9"
                })
                logger.info(f"[VIDEO_RENDER] {shot_id}: negative_prompt passed ({len(_rv_neg)} chars)")

                # Extract video URL from result
                video_url = None
                if isinstance(result, dict):
                    video_url = result.get("video", {}).get("url") or result.get("url")

                if not video_url:
                    logger.error(f"[VIDEO_RENDER] No video URL in result for {shot_id} seg{seg_idx}")
                    LIVE_GEN_TRACKER.update(f"{shot_id}{seg_suffix}", "error")
                    results.append({
                        "shot_id": shot_id,
                        "segment": seg_idx,
                        "status": "error",
                        "error": "No video URL in result"
                    })
                    continue

                # Download the video — V26.2 FIX: Use urllib instead of httpx
                # httpx async was truncating large video downloads (returning 1s instead of 6-18s)
                # urllib.request.urlretrieve is synchronous but reliable (same as chain pipeline)
                import urllib.request as _urllib_req
                try:
                    _urllib_req.urlretrieve(video_url, str(output_path))
                    logger.info(f"[VIDEO_RENDER] Saved {shot_id} seg{seg_idx} to {output_path} ({output_path.stat().st_size} bytes)")
                except Exception as _dl_err:
                    logger.error(f"[VIDEO_RENDER] Failed to download {shot_id} seg{seg_idx}: {_dl_err}")
                    results.append({
                        "shot_id": shot_id,
                        "segment": seg_idx,
                        "status": "error",
                        "error": f"Download failed: {_dl_err}"
                    })
                    continue

                # Update shot in data (use first segment's path as primary)
                video_path_str = str(output_path)
                video_url_canonical = f"/api/media?path={video_path_str}"

                # Find and update the shot in original data
                for s in data.get("shots", []):
                    if s.get("shot_id") == shot_id:
                        # V17: Track segment videos
                        if "segment_videos" not in s:
                            s["segment_videos"] = []
                        s["segment_videos"].append({
                            "segment": seg_idx,
                            "path": video_path_str,
                            "url": video_url_canonical
                        })
                        # First segment sets primary video_path
                        # V22.2: Model-aware URL — Kling → video_url_kling, LTX → video_url
                        if seg_idx == 0:
                            s["video_path"] = video_path_str
                            if video_model == "kling":
                                s["video_url_kling"] = video_url_canonical
                            else:
                                s["video_url"] = video_url_canonical
                        if shot_id not in modified_shot_ids:
                            modified_shot_ids.append(shot_id)
                        break

                LIVE_GEN_TRACKER.update(f"{shot_id}{seg_suffix}", "complete")

                # ═══ V26.2: DOCTRINE POST-GENERATION — After successful video ═══
                if _rv_doctrine_runner:
                    try:
                        _rv_doc_post_ctx = {
                            "output_path": str(output_path),
                            "fal_result": result,
                        }
                        _rv_doc_post = _rv_doctrine_runner.post_generation(shot, _rv_doc_post_ctx)
                        if _rv_doc_post.get("reject_gate"):
                            logger.warning(f"[DOCTRINE-VIDEO] Post-gen rejection for {shot_id}: {_rv_doc_post.get('reject_gate')}")
                        else:
                            logger.info(f"[DOCTRINE-VIDEO] POST-GEN PASSED {shot_id}: {_rv_doc_post.get('status', 'unknown')}")
                    except Exception as _rv_doc_post_err:
                        logger.warning(f"[DOCTRINE-VIDEO] Post-gen non-blocking: {_rv_doc_post_err}")
                # ═══════════════════════════════════════════════════════════════

                # ═══ V27.1.4g: VIDEO UNDERSTANDING QA — Analyze generated video ═══
                _video_qa = {}
                try:
                    if video_url and seg_idx == 0:  # Only analyze first segment
                        import fal_client as _qa_fal
                        _qa_result = _qa_fal.subscribe("fal-ai/video-understanding", arguments={
                            "video_url": video_url,
                            "prompt": (
                                "Analyze this shot for: 1) Camera movement (static/pan/drift/orbit), "
                                "2) Character acting quality (natural/stiff/AI-like), "
                                "3) Lip sync if dialogue (natural/exaggerated/frozen), "
                                "4) Background consistency (stable/morphing/jumping), "
                                "5) Overall cinematic quality (1-10). "
                                "Be brief, one line per category."
                            )
                        })
                        _video_qa = {
                            "analysis": _qa_result.get("output", _qa_result.get("text", str(_qa_result))),
                            "shot_id": shot_id,
                        }
                        logger.info(f"[VIDEO-QA] {shot_id}: {str(_video_qa.get('analysis',''))[:200]}")
                        print(f"  [VIDEO-QA] {shot_id}: {str(_video_qa.get('analysis',''))[:150]}", flush=True)
                except Exception as _qa_err:
                    logger.warning(f"[VIDEO-QA] {shot_id}: analysis failed (non-blocking): {_qa_err}")
                # ═══════════════════════════════════════════════════════════════

                results.append({
                    "shot_id": shot_id,
                    "segment": seg_idx,
                    "status": "success",
                    "path": video_path_str,
                    "url": video_url_canonical,
                    "duration": seg_duration,
                    "video_qa": _video_qa if _video_qa else None
                })

            except Exception as e:
                logger.exception(f"[VIDEO_RENDER] Error generating {shot_id} seg{seg_idx}: {e}")
                LIVE_GEN_TRACKER.update(f"{shot_id}{seg_suffix}", "error")
                results.append({
                    "shot_id": shot_id,
                    "segment": seg_idx,
                    "status": "error",
                    "error": str(e)
                })

    # ─── V18.3.1: SEGMENT STITCHING — concat multi-segment shots into single video ───
    # Root cause fix: 16s shots auto-segment into 2×8s, but only seg0 was set as video_path.
    # Now we FFmpeg-concat all segments into one continuous video file.
    stitch_count = 0
    if not dry_run:
        for s in data.get("shots", []):
            seg_vids = s.get("segment_videos", [])
            if len(seg_vids) <= 1:
                continue  # Single segment or no segments — nothing to stitch

            shot_id = s.get("shot_id", "unknown")
            # Check all segment files exist
            seg_paths = sorted(seg_vids, key=lambda x: x.get("segment", 0))
            all_exist = all(Path(sp["path"]).exists() for sp in seg_paths)
            if not all_exist:
                logger.warning(f"[SEGMENT_STITCH] {shot_id}: Not all segment files exist, skipping stitch")
                continue

            # Build FFmpeg concat file
            videos_dir = project_path / "videos"
            concat_list_path = videos_dir / f"{shot_id}_concat.txt"
            stitched_path = videos_dir / f"{shot_id}.mp4"

            try:
                # Write concat list
                with open(concat_list_path, 'w') as clf:
                    for sp in seg_paths:
                        # FFmpeg concat requires escaped paths
                        escaped = str(sp["path"]).replace("'", "'\\''")
                        clf.write(f"file '{escaped}'\n")

                # FFmpeg concat demuxer — lossless concat of same-codec segments
                stitch_cmd = (
                    f'ffmpeg -y -f concat -safe 0 -i "{concat_list_path}" '
                    f'-c copy -movflags +faststart "{stitched_path}"'
                )
                stitch_result = subprocess.run(
                    stitch_cmd, shell=True, capture_output=True, timeout=120
                )

                if stitch_result.returncode == 0 and stitched_path.exists():
                    # Verify stitched duration via ffprobe
                    dur_cmd = f'ffprobe -v error -show_entries format=duration -of csv=p=0 "{stitched_path}"'
                    dur_result = subprocess.run(dur_cmd, shell=True, capture_output=True, timeout=30, text=True)
                    stitched_dur = float(dur_result.stdout.strip()) if dur_result.returncode == 0 else 0

                    # Update shot with stitched video path
                    # V22.2: Model-aware URL for stitched segments
                    s["video_path"] = str(stitched_path)
                    if video_model == "kling":
                        s["video_url_kling"] = f"/api/media?path={stitched_path}"
                    else:
                        s["video_url"] = f"/api/media?path={stitched_path}"
                    s["_stitched_from_segments"] = len(seg_paths)
                    s["_stitched_duration"] = round(stitched_dur, 2)
                    stitch_count += 1
                    logger.info(
                        f"[SEGMENT_STITCH] ✅ {shot_id}: {len(seg_paths)} segments → "
                        f"{stitched_path.name} ({stitched_dur:.1f}s)"
                    )
                else:
                    stderr_msg = stitch_result.stderr.decode()[:200] if stitch_result.stderr else "unknown"
                    logger.error(f"[SEGMENT_STITCH] ❌ {shot_id}: FFmpeg failed — {stderr_msg}")

                # Clean up concat list file
                if concat_list_path.exists():
                    concat_list_path.unlink()

            except Exception as e:
                logger.exception(f"[SEGMENT_STITCH] ❌ {shot_id}: Exception during stitch — {e}")
                # Non-blocking — seg0 remains as fallback video_path

    if stitch_count > 0:
        logger.info(f"[SEGMENT_STITCH] Stitched {stitch_count} multi-segment shots into continuous videos")

    # Save updated shot plan
    if modified_shot_ids and not dry_run:
        with open(shot_plan_path, 'w') as f:
            json.dump(data, f, indent=2)
        logger.info(f"[VIDEO_RENDER] Updated shot_plan.json with {len(modified_shot_ids)} video paths")

        # Invalidate UI cache
        cache_dirty = project_path / "ui_cache" / "bundle.dirty"
        cache_dirty.parent.mkdir(parents=True, exist_ok=True)
        cache_dirty.touch()

    # V17.3: Temporal workflow tracking for video generation
    _vid_gen = sum(1 for r in results if r.get("status") == "success")
    _vid_fail = sum(1 for r in results if r.get("status") == "error")
    _vid_skip = sum(1 for r in results if r.get("status") == "skipped")
    if not dry_run:
        try:
            _wf_id = temporal_start_workflow(project, "render_videos")
            temporal_run_activity(_wf_id, "render_videos")
            _vid_summary = {"generated": _vid_gen, "failed": _vid_fail, "skipped": _vid_skip}
            if _vid_fail == 0:
                temporal_complete_activity(_wf_id, "render_videos", result=_vid_summary)
                temporal_complete_workflow(_wf_id, result=_vid_summary)
            else:
                temporal_fail_activity(_wf_id, "render_videos", f"{_vid_fail} videos failed")
            _temporal_persist()
        except Exception:
            pass  # Temporal tracking is non-blocking

        # V17.3: Run manifest for video generation
        try:
            append_run_manifest(project_path, {
                "action": "render-videos",
                "project": project,
                "summary": {"generated": _vid_gen, "failed": _vid_fail, "skipped": _vid_skip}
            })
        except Exception:
            pass

    # ═══ V26: DOCTRINE SESSION CLOSE — Render-Videos Post-Generation ═══
    if _rv_doctrine_runner and DOCTRINE_AVAILABLE:
        try:
            _rv_close = _rv_doctrine_runner.session_close()
            logger.info(f"[DOCTRINE-VIDEO] Session closed: {_rv_close.get('status', 'unknown')} — "
                        f"{_vid_gen} generated, {_vid_fail} failed")
            _doctrine_runners.pop(str(project_path), None)
        except Exception as _rv_close_err:
            logger.warning(f"[DOCTRINE-VIDEO] Session close non-blocking: {_rv_close_err}")
    # ═══════════════════════════════════════════════════════════════════

    return {
        "success": True,
        "project": project,
        "generation_plan": generation_plan,
        "results": results,
        "videos_generated": _vid_gen,
        "videos_skipped": _vid_skip,
        "videos_failed": _vid_fail
    }


@app.post("/api/auto/render-videos-turbo")
async def render_videos_turbo(request: Dict = Body(...)):
    """
    V17: TURBO PARALLEL video generation - 10 concurrent workers.

    Same as render-videos but runs up to 10 videos in parallel.
    Use for rapid scene verification and production.

    Body:
    {
        "project": "kord",
        "shot_ids": ["001_001A", ...],  // optional
        "max_workers": 10,              // default 10, max 15
        "dry_run": false,
        "video_model": "ltx"           // V18: "ltx" or "kling"
    }
    """
    from concurrent.futures import ThreadPoolExecutor, as_completed
    import threading
    import requests

    # V18: Model selection - LTX-2 (default) or Kling v3
    video_model = request.get("video_model", "kling")
    if video_model == "kling":
        VIDEO_MODEL = "fal-ai/kling-video/v3/pro/image-to-video"
        VIDEO_MAX_DURATION = 15  # Kling max
    elif video_model == "seeddance":
        VIDEO_MODEL = "fal-ai/bytedance/seedance/v2/image-to-video"
        VIDEO_MAX_DURATION = 20  # SeedDance 2.0 max (update when confirmed)
    else:
        VIDEO_MODEL = "fal-ai/ltx-2.3/image-to-video/fast"
        VIDEO_MAX_DURATION = 20  # LTX-2.3 max

    project = request.get("project", "")
    shot_ids = request.get("shot_ids", [])
    max_workers = min(request.get("max_workers", 10), 15)  # Cap at 15
    dry_run = request.get("dry_run", False)
    force_overwrite = request.get("force", False)  # V17.8.3: Force re-render even if video exists
    lite_mode = request.get("lite_mode", False)  # V22: Skip prompt enrichment at render time

    if not project:
        return {"success": False, "error": "Project name required"}

    project_path = get_project_path(project)
    shot_plan_path = project_path / "shot_plan.json"

    if not shot_plan_path.exists():
        return {"success": False, "error": f"Project '{project}' not found"}

    with open(shot_plan_path) as f:
        data = json.load(f)

    # V27.1: Handle both list format [shots...] and dict format {"shots": [...]}
    if isinstance(data, list):
        shots = data
        data = {"shots": data}
    else:
        shots = data.get("shots", [])
    if shot_ids:
        shots = [s for s in shots if s.get("shot_id") in shot_ids]
    else:
        shots = [s for s in shots if s.get("first_frame_path")]

    # ═══ V26.2: DOCTRINE — Render-Videos-Turbo Scene Initialize ═══
    _turbo_doctrine_runner = None
    _turbo_cast_map = {}
    if DOCTRINE_AVAILABLE and not dry_run:
        try:
            _turbo_doctrine_runner = _get_doctrine_runner(str(project_path))
            _turbo_cast_path = project_path / "cast_map.json"
            if _turbo_cast_path.exists():
                with open(_turbo_cast_path) as _turbo_cm_f:
                    _turbo_cast_map = json.load(_turbo_cm_f)
            _turbo_manifest = data.get("scene_manifest", {})
            _turbo_doc_init = _turbo_doctrine_runner.scene_initialize(
                shots, _turbo_manifest, {}, _turbo_cast_map
            )
            logger.info(f"[DOCTRINE-TURBO] Scene initialized: {_turbo_doc_init.get('status')} — {len(shots)} shots")
            if _turbo_doc_init.get("status") == "REJECTED":
                logger.error(f"[DOCTRINE-TURBO] HARD STOP: {_turbo_doc_init.get('reason')}")
                return {
                    "success": False,
                    "error": f"DOCTRINE HARD STOP (turbo): {_turbo_doc_init.get('reason')}",
                    "doctrine_status": _turbo_doc_init
                }
        except Exception as _turbo_doc_err:
            logger.warning(f"[DOCTRINE-TURBO] Scene init non-blocking: {_turbo_doc_err}")
    # ═══════════════════════════════════════════════════════════════

    # V22.2: Model-aware directory
    if video_model == "kling":
        videos_dir = project_path / "videos_kling"
    else:
        videos_dir = project_path / "videos"
    videos_dir.mkdir(parents=True, exist_ok=True)

    results_lock = threading.Lock()
    results = []
    generation_plan = []
    tasks_to_run = []

    # Build task list
    for shot in shots:
        shot_id = shot.get("shot_id", "unknown")
        first_frame_path = shot.get("first_frame_path")
        ltx_prompt = shot.get("ltx_motion_prompt", "")
        duration = shot.get("duration", shot.get("duration_seconds", 20))

        # V27.1.4f: VIDEO PROMPT AUTHORITY — ALWAYS compile clean for dialogue shots
        # The disk ltx_motion_prompt is CONTAMINATED by 7 different systems
        # This gate mirrors the one in render-videos endpoint (line ~33013)
        _turbo_chars = shot.get("characters") or []
        _turbo_has_dialogue = bool(shot.get("dialogue_text") and _turbo_chars)
        if _turbo_has_dialogue:
            try:
                # Inject beats first
                if not shot.get("beat"):
                    _bid = shot.get("beat_id", "")
                    if _bid:
                        _parts = _bid.split("_beat_")
                        if len(_parts) == 2:
                            _sc_id = _parts[0]
                            try:
                                _bi = int(_parts[1])
                            except ValueError:
                                _bi = -1
                            _sb_path_turbo = project_path / "story_bible.json"
                            if _sb_path_turbo.exists():
                                with open(_sb_path_turbo) as _sbf:
                                    _sb_turbo = json.load(_sbf)
                                for _sc in _sb_turbo.get("scenes", []):
                                    if _sc.get("scene_id") == _sc_id:
                                        _sb_beats = _sc.get("beats", [])
                                        if _sb_beats:
                                            _clamped = min(_bi, len(_sb_beats) - 1)
                                            if _clamped >= 0:
                                                shot["beat"] = _sb_beats[_clamped].get("description", "")
                                                shot["emotional_beat"] = shot["beat"]
                                                shot["_beat_character_action"] = _sb_beats[_clamped].get("character_action", "")
                                        break
                # Compile clean video prompt
                from tools.ots_enforcer import OTSEnforcer
                _turbo_cast_path = project_path / "cast_map.json"
                _turbo_cm = {}
                if _turbo_cast_path.exists():
                    with open(_turbo_cast_path) as _f:
                        _turbo_cm = json.load(_f)
                _turbo_enforcer = OTSEnforcer(_turbo_cm)
                _turbo_clean = _turbo_enforcer.compile_universal_video_prompt(shot)
                if _turbo_clean and len(_turbo_clean) > 50:
                    ltx_prompt = _turbo_clean
                    shot["ltx_motion_prompt"] = ltx_prompt
                    logger.info(f"[V27.1.4f TURBO-GATE] {shot_id}: CLEAN prompt {len(ltx_prompt)} chars (was contaminated)")
                    print(f"  [TURBO-GATE] {shot_id}: CLEAN prompt {len(ltx_prompt)} chars", flush=True)
            except Exception as _tg_err:
                logger.warning(f"[V27.1.4f TURBO-GATE] {shot_id}: recompile failed (non-blocking): {_tg_err}")
                # Fall through to legacy injection below
                _turbo_has_dialogue = False  # Let legacy path try

        if not _turbo_has_dialogue:
            # Legacy path for non-dialogue shots
            # V18.3.1: DIALOGUE INJECTION — ensure LTX prompt contains speaking direction
            # V22: Skip in lite_mode — LITE already synthesized dialogue direction
            if not lite_mode:
                # V24.2.3: Visual acting direction, NOT raw dialogue text
                _turbo_dlg = (shot.get("dialogue_text") or shot.get("dialogue") or "").strip()
                if _turbo_dlg and "character speaks:" not in ltx_prompt.lower():
                    _tc = shot.get("characters", [])
                    _turbo_speaker = _tc[0].split()[0].title() if isinstance(_tc, list) and _tc else "Character"
                    _turbo_num = len(_tc) if isinstance(_tc, list) else 1
                    _tdlg_lower = _turbo_dlg.lower()
                    _turbo_style = "speaks with natural cadence, subtle gestures, attentive expression"
                    if any(w in _tdlg_lower for w in ["?", "believe", "do you", "really"]):
                        _turbo_style = "asks with raised eyebrows, slight head tilt, searching eyes"
                    elif any(w in _tdlg_lower for w in ["estate", "agency", "agreement", "sale", "office"]):
                        _turbo_style = "speaks with measured professionalism, controlled gestures, direct eye contact"
                    elif any(w in _tdlg_lower for w in ["remember", "died", "love", "heart", "important"]):
                        _turbo_style = "speaks with visible emotion, eyes glistening, genuine feeling"
                    elif any(w in _tdlg_lower for w in ["need you to", "must", "demand", "I suggest"]):
                        _turbo_style = "speaks with authority, chin raised, deliberate enunciation"
                    _turbo_visual = f"{_turbo_speaker} {_turbo_style}"
                    if _turbo_num >= 2:
                        _turbo_visual += ", counterpart listens with attentive stillness"
                    ltx_prompt = f'character speaks: {_turbo_visual}, lips moving naturally with emotion. {ltx_prompt}'
                    logger.info(f"[V24.2.3 TURBO-DLG] Injected visual dialogue direction for {shot_id}")

                # V18.3.1: Beat action injection
                _turbo_beat = (shot.get("_beat_action") or "").strip()
                if _turbo_beat and "character performs:" not in ltx_prompt.lower():
                    ltx_prompt = f'character performs: {_turbo_beat[:150]}. {ltx_prompt}'
            else:
                logger.info(f"[V22 LITE] {shot_id}: LTX prompt as-is ({len(ltx_prompt)} chars) — no dialogue/beat injection")

            # V23 HARD GATE: Performance marker enforcement for turbo endpoint
            ltx_prompt = ensure_performance_marker(shot, ltx_prompt)
            shot["ltx_motion_prompt"] = ltx_prompt

        # V18.3.1: Truncation safety
        if len(ltx_prompt) > 1200:
            ltx_prompt = ltx_prompt[:1197] + "..."

        if not first_frame_path:
            with results_lock:
                results.append({"shot_id": shot_id, "status": "skipped", "reason": "no_first_frame"})
            continue

        frame_path = Path(first_frame_path)
        if not frame_path.exists():
            frame_path = project_path / "first_frames" / f"{shot_id}.jpg"
            if not frame_path.exists():
                with results_lock:
                    results.append({"shot_id": shot_id, "status": "skipped", "reason": "first_frame_not_found"})
                continue

        # V18: Segment based on selected model's max duration
        model_max = VIDEO_MAX_DURATION  # 20 for LTX, 15 for Kling
        if duration <= model_max:
            segments = [{"segment_index": 0, "duration": duration}]
        else:
            num_segs = max(1, (duration + model_max - 1) // model_max)
            seg_dur = round(duration / num_segs, 1)
            segments = [{"segment_index": i, "duration": min(seg_dur, model_max)} for i in range(num_segs)]

        generation_plan.append({
            "shot_id": shot_id,
            "duration": duration,
            "segments": len(segments),
            "first_frame": str(frame_path)
        })

        for seg in segments:
            seg_idx = seg["segment_index"]
            seg_suffix = f"_seg{seg_idx}" if len(segments) > 1 else ""
            output_path = videos_dir / f"{shot_id}{seg_suffix}.mp4"

            if output_path.exists() and not force_overwrite:
                with results_lock:
                    results.append({
                        "shot_id": shot_id, "segment": seg_idx,
                        "status": "skipped", "reason": "already_exists",
                        "path": str(output_path)
                    })
                continue

            if not dry_run:
                tasks_to_run.append({
                    "shot_id": shot_id,
                    "segment_index": seg_idx,
                    "seg_suffix": seg_suffix,
                    "frame_path": str(frame_path),
                    "ltx_prompt": ltx_prompt,
                    "duration": seg["duration"],
                    "output_path": str(output_path)
                })

    if dry_run:
        return {
            "success": True,
            "project": project,
            "dry_run": True,
            "max_workers": max_workers,
            "generation_plan": generation_plan,
            "to_generate": len(tasks_to_run),
            "already_exist": len([r for r in results if r.get("reason") == "already_exists"])
        }

    # Worker function
    def generate_single_video(task):
        shot_id = task["shot_id"]
        seg_idx = task["segment_index"]
        seg_suffix = task["seg_suffix"]
        frame_path = task["frame_path"]
        ltx_prompt = task["ltx_prompt"]
        seg_duration = task["duration"]
        output_path = task["output_path"]

        try:
            logger.info(f"[TURBO-VIDEO] Generating {shot_id}{seg_suffix} ({seg_duration:.1f}s)")

            LIVE_GEN_TRACKER.add(
                project=project,
                shot_id=f"{shot_id}{seg_suffix}",
                status="running",
                asset_type="video",
                prompt=ltx_prompt[:80],
                model=VIDEO_MODEL
            )

            # V18: Handle different models
            if video_model == "kling":
                # V18.3.1: Kling requires PUBLIC URL — R2 first, FAL fallback
                # GCS removed in V18.0 (DO NOT RE-BREAK rule 106, 124)
                image_url = None

                # Priority 1: R2 permanent public URL (preferred)
                if R2_ENABLED:
                    try:
                        _r2_key = f"{project}/kling_frames/{shot_id}.jpg"
                        _r2_url = r2_upload_file(Path(frame_path), _r2_key)
                        if _r2_url:
                            image_url = _r2_url
                            logger.info(f"[TURBO-VIDEO-KLING] R2 upload: {image_url[:80]}")
                    except Exception as _r2_err:
                        logger.warning(f"[TURBO-VIDEO-KLING] R2 upload failed: {_r2_err}")

                # Priority 2: FAL upload (temporary URL — may not work with Kling)
                if not image_url:
                    try:
                        image_url = fal_client.upload_file(frame_path)
                    except AttributeError:
                        with open(frame_path, "rb") as f:
                            image_url = fal_client.upload(f, "image/jpeg")
                    logger.info(f"[TURBO-VIDEO-KLING] FAL upload fallback: {image_url[:80] if image_url else 'None'}")

                # Kling duration: cap at 15s, pass as string
                api_duration = min(int(seg_duration), 15)
                # V21.6: negative_prompt for Kling turbo path
                _kling_neg = (shot.get("negative_prompt") or "blur, distort, low quality, morphing, grid pattern, split screen")
                # V25.1: Kling 3.0 uses start_image_url
                result = fal_client.run(VIDEO_MODEL, arguments={
                    "start_image_url": image_url,
                    "prompt": ltx_prompt,
                    "negative_prompt": _kling_neg,
                    "duration": str(api_duration),
                    "aspect_ratio": "16:9"
                })
            else:
                # LTX-2 path (original)
                image_base64 = convert_local_url_to_base64(frame_path)

                # V17.8.1: FAL LTX-2 Fast uses 'duration' (seconds), NOT 'num_frames'
                # V17.8.2: FAL only accepts EVEN durations: 6, 8, 10, 12, 14, 16, 18, 20
                LTX_VALID_DURATIONS_T = [6, 8, 10, 12, 14, 16, 18, 20]
                raw_dur_t = min(seg_duration, 20)
                api_duration = min((d for d in LTX_VALID_DURATIONS_T if d >= raw_dur_t), default=20)
                # V21.6: Pass negative_prompt — identity prevention in negatives
                _rv_neg_t = (shot.get("negative_prompt") or "blurry, distorted face, morphing, low quality, text, watermark, extra limbs")
                result = fal_client.run(VIDEO_MODEL, arguments={
                    "image_url": image_base64,
                    "prompt": ltx_prompt,
                    "negative_prompt": _rv_neg_t,
                    "duration": api_duration,  # V17.8.2: even-number seconds only!
                    "aspect_ratio": "16:9"
                })

            video_url = None
            if isinstance(result, dict):
                video_url = result.get("video", {}).get("url") or result.get("url")

            if not video_url:
                LIVE_GEN_TRACKER.update(f"{shot_id}{seg_suffix}", "error")
                return {"shot_id": shot_id, "segment": seg_idx, "status": "error", "error": "No video URL"}

            # Download synchronously
            response = requests.get(video_url, timeout=120)
            if response.status_code == 200:
                with open(output_path, 'wb') as f:
                    f.write(response.content)

                # V17.8.2: Apply faststart (move moov atom to front) for Chrome streaming
                try:
                    fast_path = str(output_path) + ".fast.mp4"
                    subprocess.run(
                        f'ffmpeg -y -i "{output_path}" -c copy -movflags +faststart "{fast_path}"',
                        shell=True, capture_output=True, timeout=30
                    )
                    if os.path.exists(fast_path) and os.path.getsize(fast_path) > 0:
                        os.replace(fast_path, str(output_path))
                        logger.info(f"[TURBO-VIDEO] Applied faststart to {shot_id}{seg_suffix}")
                except Exception as fast_err:
                    logger.warning(f"[TURBO-VIDEO] faststart failed for {shot_id}: {fast_err}")

                local_url = f"/api/media?path={output_path}"
                LIVE_GEN_TRACKER.update(f"{shot_id}{seg_suffix}", "complete")

                # ═══ V26.2: DOCTRINE POST-GENERATION — After successful video ═══
                if _turbo_doctrine_runner:
                    try:
                        _turbo_doc_post_ctx = {
                            "output_path": str(output_path),
                            "fal_result": result,
                        }
                        _turbo_doc_post = _turbo_doctrine_runner.post_generation(shot, _turbo_doc_post_ctx)
                        if _turbo_doc_post.get("reject_gate"):
                            logger.warning(f"[DOCTRINE-TURBO] Post-gen rejection for {shot_id}: {_turbo_doc_post.get('reject_gate')}")
                        else:
                            logger.info(f"[DOCTRINE-TURBO] POST-GEN PASSED {shot_id}: {_turbo_doc_post.get('status', 'unknown')}")
                    except Exception as _turbo_doc_post_err:
                        logger.warning(f"[DOCTRINE-TURBO] Post-gen non-blocking: {_turbo_doc_post_err}")
                # ═══════════════════════════════════════════════════════════════

                return {
                    "shot_id": shot_id,
                    "segment": seg_idx,
                    "status": "success",
                    "path": output_path,
                    "url": local_url,
                    "duration": seg_duration
                }
            else:
                LIVE_GEN_TRACKER.update(f"{shot_id}{seg_suffix}", "error")
                return {"shot_id": shot_id, "segment": seg_idx, "status": "error", "error": f"Download failed: {response.status_code}"}

        except Exception as e:
            LIVE_GEN_TRACKER.update(f"{shot_id}{seg_suffix}", "error")
            logger.error(f"[TURBO-VIDEO] Error {shot_id}{seg_suffix}: {e}")
            return {"shot_id": shot_id, "segment": seg_idx, "status": "error", "error": str(e)}

    # Execute in parallel
    start_time = time.time()
    logger.info(f"[TURBO-VIDEO] Starting: {len(tasks_to_run)} segments with {max_workers} workers")

    with ThreadPoolExecutor(max_workers=max_workers) as executor:
        future_to_task = {executor.submit(generate_single_video, task): task for task in tasks_to_run}

        for future in as_completed(future_to_task):
            task = future_to_task[future]
            try:
                result = future.result()
                with results_lock:
                    results.append(result)
                logger.info(f"[TURBO-VIDEO] Done {task['shot_id']}{task['seg_suffix']}: {result.get('status')}")
            except Exception as e:
                with results_lock:
                    results.append({"shot_id": task["shot_id"], "segment": task["segment_index"], "status": "error", "error": str(e)})

    elapsed = time.time() - start_time

    # Update shot_plan with video paths
    modified = []
    for r in results:
        if r.get("status") == "success" and r.get("path"):
            shot_id = r["shot_id"]
            for s in data.get("shots", []):
                if s.get("shot_id") == shot_id:
                    if "segment_videos" not in s:
                        s["segment_videos"] = []
                    s["segment_videos"].append({
                        "segment": r["segment"],
                        "path": r["path"],
                        "url": r["url"]
                    })
                    if r["segment"] == 0:
                        s["video_path"] = r["path"]
                        s["video_url"] = r["url"]
                    if shot_id not in modified:
                        modified.append(shot_id)
                    break

    if modified:
        with open(shot_plan_path, 'w') as f:
            json.dump(data, f, indent=2)
        cache_dirty = project_path / "ui_cache" / "bundle.dirty"
        cache_dirty.parent.mkdir(parents=True, exist_ok=True)
        cache_dirty.touch()

    success_count = len([r for r in results if r.get("status") == "success"])

    # ═══ V26.2: DOCTRINE SESSION CLOSE — Render-Videos-Turbo ═══
    if _turbo_doctrine_runner and DOCTRINE_AVAILABLE:
        try:
            _turbo_close = _turbo_doctrine_runner.session_close()
            logger.info(f"[DOCTRINE-TURBO] Session closed: {_turbo_close.get('status', 'unknown')} — "
                        f"{success_count} generated, {len([r for r in results if r.get('status') == 'error'])} failed")
            _doctrine_runners.pop(str(project_path), None)
        except Exception as _turbo_close_err:
            logger.warning(f"[DOCTRINE-TURBO] Session close non-blocking: {_turbo_close_err}")
    # ═══════════════════════════════════════════════════════════════

    return {
        "success": True,
        "project": project,
        "mode": "TURBO_PARALLEL",
        "max_workers": max_workers,
        "elapsed_seconds": round(elapsed, 2),
        "throughput": f"{success_count / elapsed:.2f} videos/sec" if elapsed > 0 else "N/A",
        "results": results,
        "summary": {
            "generated": success_count,
            "skipped": len([r for r in results if r.get("status") == "skipped"]),
            "errors": len([r for r in results if r.get("status") == "error"])
        }
    }


@app.post("/api/auto/save-verification")
async def save_verification_state(request: Dict = Body(...)):
    """
    Save verification state for project.

    RB-5 FIX: Actually persist state to verification_state.json.

    Body:
    {
        "project": "kord",
        "state": {
            "shots_verified": true,
            "custom_field": "value"
        }
    }
    """
    project = request.get("project")
    state = request.get("state", {})

    if not project:
        return {"success": False, "error": "Project name required"}

    project_path = get_project_path(project)
    if not project_path.exists():
        project_path.mkdir(parents=True, exist_ok=True)

    verification_path = project_path / "verification_state.json"

    # Merge with existing state
    existing = {}
    if verification_path.exists():
        try:
            with open(verification_path) as f:
                existing = json.load(f)
        except Exception:
            pass

    # Update with new state
    existing.update(state)
    existing["_updated_at"] = datetime.now().isoformat()

    with open(verification_path, 'w') as f:
        json.dump(existing, f, indent=2)

    logger.info(f"[VERIFICATION] Saved verification state for {project}: {list(state.keys())}")

    return {"success": True, "project": project, "state": existing}


@app.get("/api/auto/scenes/")
async def legacy_auto_scenes(project: str = Query("")):
    """Legacy endpoint expected by Auto UI to list scenes."""
    if not project:
        return {"scenes": [], "total": 0}
    shot_plan_path = get_project_path(project) / "shot_plan.json"
    if not shot_plan_path.exists():
        return {"scenes": [], "total": 0}
    with open(shot_plan_path) as f:
        data = json.load(f)
    scenes = data.get("scene_manifest", data.get("scenes", []))
    return {"scenes": scenes, "total": len(scenes)}


@app.get("/api/auto/scenes/{project}")
async def get_auto_scenes(project: str):
    """V16.7.1: Get scenes for scene-by-scene generation panel."""
    shot_plan_path = get_project_path(project) / "shot_plan.json"
    if not shot_plan_path.exists():
        return {"scenes": [], "total": 0, "error": "No shot plan found"}

    with open(shot_plan_path) as f:
        data = json.load(f)

    # Get scene manifest
    scene_manifest = data.get("scene_manifest", data.get("scenes", []))
    shots = data.get("shots", [])

    # Build scene info with shot counts and generation status
    scenes = []
    for scene in scene_manifest:
        scene_id = scene.get("scene_id", "")
        # Count shots for this scene
        scene_shots = [s for s in shots if s.get("scene_id") == scene_id]
        # Count generated shots (have first_frame_path)
        generated = sum(1 for s in scene_shots if s.get("first_frame_path"))
        total_duration = sum(s.get("duration", s.get("duration_seconds", 0)) for s in scene_shots)

        scenes.append({
            "scene_id": scene_id,
            "title": scene.get("title", scene.get("description", "")),
            "location": scene.get("location", ""),
            "time": scene.get("time_of_day", ""),
            "shot_count": len(scene_shots),
            "generated_count": generated,
            "total_duration": total_duration,
            "shots": [s.get("shot_id") for s in scene_shots]
        })

    return {"scenes": scenes, "total": len(scenes), "project": project}

@app.post("/api/auto/set-video-model")
async def set_video_model(request: Dict = Body(...)):
    """
    V29.8: Set the active video model for ALL subsequent scene runs.
    UI model selector calls this. Sets ATLAS_VIDEO_MODEL env var on the server process.

    Body: {"model": "kling" | "seedance" | "seeddance"}
    Returns: {"model": "kling", "label": "Kling v3/pro", "status": "ok"}
    """
    model = (request.get("model") or "kling").lower().strip()
    # Normalize seeddance → seedance (UI uses double-d for legacy reasons)
    canonical = "kling"  # Seedance retired V31.0 — always route to Kling
    import atlas_universal_runner as _runner
    _runner.ACTIVE_VIDEO_MODEL = canonical
    os.environ["ATLAS_VIDEO_MODEL"] = canonical
    labels = {"kling": "Kling v3/pro (proven multi-shot)", "seedance": "Seedance v2.0 (ByteDance)"}
    return {"model": canonical, "label": labels.get(canonical, canonical), "status": "ok"}


@app.get("/api/auto/video-model")
async def get_video_model():
    """V29.8: Get currently active video model."""
    import atlas_universal_runner as _runner
    model = getattr(_runner, "ACTIVE_VIDEO_MODEL", "kling")
    labels = {"kling": "Kling v3/pro", "seedance": "Seedance v2.0"}
    return {"model": model, "label": labels.get(model, model)}


@app.post("/api/auto/run-frames-only")
async def run_frames_only(request: Dict = Body(...)):
    """
    V29.16: Step 1 of 2-stage validated run.
    Generates first frames only, writes AWAITING_APPROVAL to shot_plan, invalidates UI cache.
    UI reviews filmstrip before any video cost is incurred.

    Body: {"project": "...", "scene_id": "001", "video_model": "seedance"}
    """
    project = request.get("project")
    scene_id = request.get("scene_id")
    video_model = (request.get("video_model") or "kling").lower()

    if not project or not scene_id:
        return {"success": False, "error": "project and scene_id required"}

    # Normalize model
    if video_model in ("seeddance", "seedance"):
        video_model = "kling"

    # Set model on runner
    try:
        import atlas_universal_runner as _runner
        _runner.ACTIVE_VIDEO_MODEL = video_model
        os.environ["ATLAS_VIDEO_MODEL"] = video_model
    except Exception as e:
        logger.warning(f"[FRAMES-ONLY] Could not set video model: {e}")

    # V30.5: Fire-and-forget — launch subprocess in background thread, return immediately.
    # Runner pushes per-shot status to /api/live-generations/push so UI can show
    # per-shot loading spinners and live thumbnail injection via startGenMonitorPolling.
    import subprocess, sys, threading

    runner_path = Path(__file__).parent / "atlas_universal_runner.py"
    cmd = [sys.executable, str(runner_path), project, scene_id, "--mode", "lite", "--frames-only"]
    logger.info(f"[FRAMES-ONLY] Launching background: {' '.join(cmd)}")

    def _bg_run():
        try:
            proc = subprocess.Popen(cmd, cwd=str(Path(__file__).parent),
                                     stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True)
            stdout, _ = proc.communicate(timeout=600)
            logger.info(f"[FRAMES-ONLY] Done (exit={proc.returncode}):\n{stdout[-2000:]}")
            # Invalidate UI bundle cache so next poll sees fresh frames
            try:
                pdir = get_project_path(project)
                bc = pdir / "ui_cache" / "bundle.json"
                if bc.exists(): bc.unlink()
            except Exception: pass
        except Exception as _bg_err:
            logger.error(f"[FRAMES-ONLY] Background error: {_bg_err}")

    threading.Thread(target=_bg_run, daemon=True).start()

    # Count existing frames for immediate UI context
    try:
        pdir = get_project_path(project)
        frame_dir = pdir / "first_frames"
        existing = list(frame_dir.glob(f"{scene_id}_*.jpg")) if frame_dir.exists() else []
    except Exception:
        existing = []

    return {
        "success": True,
        "status": "started",
        "frames_existing": len(existing),
        "scene_id": scene_id,
        "project": project,
        "video_model": video_model,
        "message": f"Scene {scene_id} frame generation started — watch filmstrip for live updates"
    }


@app.post("/api/auto/run-videos-only")
async def run_videos_only(request: Dict = Body(...)):
    """
    V29.16: Step 2 of 2-stage validated run.
    Uses approved frames from disk, generates Kling videos with end-frame chaining (default)
    or parallel independent-shot generation (gen_mode=parallel).

    Body: {"project": "...", "scene_id": "001", "video_model": "kling",
           "gen_mode": "chain"|"parallel"}
    """
    project = request.get("project")
    scene_id = request.get("scene_id")
    video_model = (request.get("video_model") or "kling").lower()
    gen_mode = (request.get("gen_mode") or "chain").lower()
    if gen_mode not in ("chain", "parallel"):
        gen_mode = "chain"

    if not project or not scene_id:
        return {"success": False, "error": "project and scene_id required"}

    if video_model in ("seeddance", "seedance"):
        video_model = "kling"

    try:
        import atlas_universal_runner as _runner
        _runner.ACTIVE_VIDEO_MODEL = video_model
        os.environ["ATLAS_VIDEO_MODEL"] = video_model
    except Exception as e:
        logger.warning(f"[VIDEOS-ONLY] Could not set video model: {e}")

    import subprocess, sys, threading as _threading
    runner_path = Path(__file__).parent / "atlas_universal_runner.py"
    cmd = [sys.executable, str(runner_path), project, scene_id, "--mode", "lite", "--videos-only",
           "--gen-mode", gen_mode]
    logger.info(f"[VIDEOS-ONLY] Launching background [{gen_mode.upper()} mode]: {' '.join(cmd)}")

    pdir = get_project_path(project)

    def _bg_videos():
        try:
            proc = subprocess.Popen(cmd, cwd=str(Path(__file__).parent),
                                     stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True)
            stdout, _ = proc.communicate(timeout=1200)
            logger.info(f"[VIDEOS-ONLY] Done (exit={proc.returncode}):\n{stdout[-2000:]}")
            try:
                bc = pdir / "ui_cache" / "bundle.json"
                if bc.exists(): bc.unlink()
            except Exception: pass
        except Exception as _err:
            logger.error(f"[VIDEOS-ONLY] Background error: {_err}")

    _threading.Thread(target=_bg_videos, daemon=True).start()

    return {
        "success": True,
        "status": "started",
        "scene_id": scene_id,
        "project": project,
        "video_model": video_model,
        "gen_mode": gen_mode,
        "message": f"Scene {scene_id} video generation started [{gen_mode.upper()} mode] — watch filmstrip for live updates"
    }


@app.post("/api/auto/run-scene-chain")
async def run_scene_chain(request: Dict = Body(...)):
    """
    V36.3: Full chain run — frames + videos in one pass with end-frame chaining.
    Supports SINGLE or MULTI-SCENE parallel generation.

    Body (single):  {"project": "...", "scene_id": "006", "video_model": "kling"}
    Body (multi):   {"project": "...", "scene_ids": ["001","002","003"], "max_concurrent": 2}

    Multi-scene: launches up to max_concurrent scenes in parallel threads.
    Each scene chains internally (sequential shots), but scenes run concurrently.
    """
    project = request.get("project")
    # V36.3: Accept both scene_id (single) and scene_ids (multi)
    scene_ids = request.get("scene_ids") or []
    if not scene_ids:
        _single = request.get("scene_id")
        if _single:
            scene_ids = [_single]
    max_concurrent = min(int(request.get("max_concurrent", 2)), 4)  # cap at 4 parallel
    video_model = (request.get("video_model") or "kling").lower()

    if not project or not scene_ids:
        return {"success": False, "error": "project and scene_id(s) required"}

    if video_model in ("seeddance", "seedance"):
        video_model = "kling"

    try:
        import atlas_universal_runner as _runner
        _runner.ACTIVE_VIDEO_MODEL = video_model
        os.environ["ATLAS_VIDEO_MODEL"] = video_model
    except Exception as e:
        logger.warning(f"[SCENE-CHAIN] Could not set video model: {e}")

    import subprocess, sys, threading as _threading
    runner_path = Path(__file__).parent / "atlas_universal_runner.py"
    pdir = get_project_path(project)

    def _bg_chain_single(scene_id):
        """Run one scene's full chain in a background thread with live tracking."""
        import re as _re
        _cmd = [sys.executable, str(runner_path), project, scene_id,
                "--mode", "lite", "--gen-mode", "chain"]
        logger.info(f"[SCENE-CHAIN] Launching scene {scene_id}: {' '.join(_cmd)}")
        try:
            proc = subprocess.Popen(_cmd, cwd=str(Path(__file__).parent),
                                     stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True)
            _stdout_lines = []
            for line in proc.stdout:
                _stdout_lines.append(line)
                line_s = line.strip()
                # Detect frame generation
                _fm = _re.search(r'\[FRAME\]\s+(\d{3}_\w+)', line_s) or _re.search(r'Generating frame.*?(\d{3}_[A-Z]\d+)', line_s)
                if _fm:
                    _sid = _fm.group(1)
                    live_gen_tracker.add(project, _sid, "running", "image", model="nano")
                # Detect frame saved
                _fs = _re.search(r'(?:Saved|wrote|first_frame).*?(\d{3}_[A-Z]\d+).*?\.(jpg|png)', line_s, _re.IGNORECASE)
                if _fs:
                    _sid = _fs.group(1)
                    _furl = f"/api/media?path=pipeline_outputs/{project}/first_frames/{_sid}.jpg"
                    live_gen_tracker.update(_sid, "completed", url=_furl)
                # Detect video generation
                _vm = _re.search(r'\[(?:MULTISHOT|KLING|VIDEO)\].*?Group\s*(\d+)', line_s) or _re.search(r'\[(?:KLING|VIDEO)\].*?(\d{3}_\w+)', line_s)
                if _vm:
                    _vid_label = f"CHAIN_{scene_id}_G{_vm.group(1)}"
                    live_gen_tracker.add(project, _vid_label, "running", "video", model="kling")
                # Detect video completed
                _vs = _re.search(r'(?:video.*?saved|wrote.*?\.mp4|download.*?complete|CHAIN.*?chain frame.*?locked)', line_s, _re.IGNORECASE)
                if _vs:
                    try:
                        with live_gen_tracker._lock:
                            for _ent in live_gen_tracker._generations:
                                if _ent.get("asset_type") == "video" and _ent.get("status") == "running":
                                    _ent["status"] = "completed"
                                    break
                    except Exception:
                        pass
                # Bundle cache invalidation on filmstrip sync
                if '[FILMSTRIP]' in line_s and 'synced' in line_s:
                    try:
                        bc = pdir / "ui_cache" / "bundle.json"
                        if bc.exists(): bc.unlink()
                    except Exception: pass
                # Log key lines
                if any(k in line_s for k in ['[FRAME]', '[MULTISHOT]', '[KLING]', '[VIDEO]', '[CHAIN]', '[CONSCIOUSNESS]', '[FILMSTRIP]', '[WIRE-A]', '[CANON]', 'ERROR', 'FAIL', 'Scene complete']):
                    logger.info(f"[CHAIN-{scene_id}] {line_s}")

            proc.wait(timeout=1800)  # 30 min timeout per scene
            logger.info(f"[CHAIN-{scene_id}] Done (exit={proc.returncode})")
            # Invalidate bundle cache after completion
            try:
                bc = pdir / "ui_cache" / "bundle.json"
                if bc.exists(): bc.unlink()
            except Exception: pass
        except Exception as _err:
            logger.error(f"[CHAIN-{scene_id}] Background error: {_err}")

    def _bg_chain_parallel():
        """V36.3: Dispatch multiple scenes with concurrency cap."""
        from concurrent.futures import ThreadPoolExecutor, as_completed
        logger.info(f"[SCENE-CHAIN] Parallel dispatch: {scene_ids} (max_concurrent={max_concurrent})")
        with ThreadPoolExecutor(max_workers=max_concurrent) as pool:
            futs = {pool.submit(_bg_chain_single, sid): sid for sid in scene_ids}
            for f in as_completed(futs):
                sid = futs[f]
                try:
                    f.result()
                    logger.info(f"[SCENE-CHAIN] Scene {sid}: COMPLETE")
                except Exception as e:
                    logger.error(f"[SCENE-CHAIN] Scene {sid}: ERROR — {e}")
        logger.info(f"[SCENE-CHAIN] All {len(scene_ids)} scenes finished")

    # Launch: single scene = single thread, multi = parallel dispatcher
    if len(scene_ids) == 1:
        _threading.Thread(target=_bg_chain_single, args=(scene_ids[0],), daemon=True).start()
    else:
        _threading.Thread(target=_bg_chain_parallel, daemon=True).start()

    # V36.3: Response for single or multi-scene
    if len(scene_ids) == 1:
        scene_id = scene_ids[0]
        is_cold_open = False
        try:
            sb_path = pdir / "story_bible.json"
            if sb_path.exists():
                import json as _json
                sb = _json.load(open(sb_path))
                for sc in sb.get("scenes", []):
                    if sc.get("scene_id") == scene_id or sc.get("scene_number") == scene_id:
                        beats = sc.get("beats", [])
                        if beats and beats[0].get("dialogue"):
                            is_cold_open = True
                        break
        except Exception:
            pass
        return {
            "success": True,
            "status": "started",
            "scene_ids": scene_ids,
            "scene_id": scene_id,
            "project": project,
            "video_model": video_model,
            "is_cold_open": is_cold_open,
            "max_concurrent": 1,
            "message": f"Scene {scene_id} full chain started{' (COLD OPEN)' if is_cold_open else ''} — watch filmstrip"
        }
    else:
        return {
            "success": True,
            "status": "started",
            "scene_ids": scene_ids,
            "project": project,
            "video_model": video_model,
            "max_concurrent": max_concurrent,
            "message": f"{len(scene_ids)} scenes launched in parallel (max {max_concurrent} concurrent): {', '.join(scene_ids)}"
        }


@app.get("/api/auto/scene-prompts")
async def get_scene_prompts(project: str, scene: str = None):
    """
    V31.0 Prompt Review: Return all shots' prompt data for a given scene (or all scenes).
    GET /api/auto/scene-prompts?project=victorian_shadows_ep1&scene=006
    """
    if not project:
        return {"success": False, "error": "project required"}
    try:
        pdir = get_project_path(project)
        sp_path = pdir / "shot_plan.json"
        if not sp_path.exists():
            return {"success": False, "error": "shot_plan.json not found"}
        with open(sp_path) as f:
            sp_raw = json.load(f)
        is_list = isinstance(sp_raw, list)
        shots = sp_raw if is_list else sp_raw.get("shots", [])
        if scene:
            shots = [s for s in shots if s.get("scene_id") == scene]
            if not shots:
                return {"success": False, "error": f"No shots found for scene {scene}"}
        results = {}
        for shot in shots:
            sid = shot.get("scene_id", "?")
            if sid not in results:
                results[sid] = {
                    "scene_id": sid,
                    "location": shot.get("location", ""),
                    "soundscape_signature": shot.get("_soundscape_signature", ""),
                    "shots": [],
                }
            nano = shot.get("nano_prompt") or ""
            issues = []
            if not nano or len(nano) < 50:
                issues.append("empty_prompt")
            if shot.get("characters") and "photorealistic" not in nano:
                issues.append("missing_realism_anchor")
            if shot.get("characters") and "[ROOM DNA" not in nano and "floor-to-ceiling" not in nano and "whitewashed brick" not in nano and "mahogany bookshelves" not in nano:
                issues.append("missing_room_dna")
            if "Speaking:" in nano or "0-5s:" in nano:
                issues.append("choreography_contamination")
            results[sid]["shots"].append({
                "shot_id": shot.get("shot_id"),
                "shot_type": shot.get("shot_type"),
                "duration": shot.get("duration"),
                "characters": shot.get("characters", []),
                "dialogue_text": shot.get("dialogue_text"),
                "_dialogue_speaker": shot.get("_dialogue_speaker", ""),
                "_beat_dialogue": shot.get("_beat_dialogue"),
                "_beat_action": shot.get("_beat_action"),
                "_beat_atmosphere": shot.get("_beat_atmosphere"),
                "nano_prompt": nano,
                "_soundscape_signature": shot.get("_soundscape_signature", ""),
                "_voice_signature": shot.get("_voice_signature", ""),
                "_approval_status": shot.get("_approval_status", "AWAITING_APPROVAL"),
                "_frame_identity_score": shot.get("_frame_identity_score"),
                "_identity_score": shot.get("_identity_score"),
                "_vision_verdict": shot.get("_vision_verdict"),
                "_pvg_status": shot.get("_pvg_status"),
                "_pvg_diagnostic": shot.get("_pvg_diagnostic"),
                "_spatial_profile": shot.get("_spatial_profile"),
                "has_frame": bool(shot.get("first_frame_path") or shot.get("first_frame_url")),
                "has_video": bool(shot.get("video_path") or shot.get("video_url")),
                "readiness_issues": issues,
                "is_ready": len(issues) == 0,
            })
        sorted_results = dict(sorted(results.items()))
        total_shots = sum(len(v["shots"]) for v in sorted_results.values())
        ready_shots = sum(sum(1 for s in v["shots"] if s["is_ready"]) for v in sorted_results.values())
        return {
            "success": True, "project": project, "scene_filter": scene,
            "total_shots": total_shots, "ready_shots": ready_shots,
            "scenes": sorted_results,
        }
    except Exception as e:
        logger.error(f"[SCENE-PROMPTS] Error: {e}", exc_info=True)
        return {"success": False, "error": str(e)}


@app.put("/api/auto/update-prompt")
async def update_prompt_put(request: Dict = Body(...)):
    """
    V31.0 Prompt Review: Update nano_prompt for a shot. Saves to shot_plan.json.
    Body: {"project": "...", "shot_id": "006_M01", "nano_prompt": "...", "ltx_motion_prompt": "..."}
    """
    project = request.get("project")
    shot_id = request.get("shot_id")
    new_nano = request.get("nano_prompt")
    if not project or not shot_id or new_nano is None:
        return {"success": False, "error": "project, shot_id, and nano_prompt required"}
    try:
        pdir = get_project_path(project)
        sp_path = pdir / "shot_plan.json"
        if not sp_path.exists():
            return {"success": False, "error": "shot_plan.json not found"}
        with open(sp_path) as f:
            sp_raw = json.load(f)
        is_list = isinstance(sp_raw, list)
        shots = sp_raw if is_list else sp_raw.get("shots", [])
        updated = 0
        for shot in shots:
            if shot.get("shot_id") == shot_id:
                if shot.get("nano_prompt") and shot.get("nano_prompt") != new_nano:
                    shot["_nano_prompt_pre_review"] = shot["nano_prompt"]
                shot["nano_prompt"] = new_nano
                shot["_prompt_reviewed_at"] = __import__("datetime").datetime.now().isoformat()
                shot["_prompt_reviewer"] = "user"
                if request.get("ltx_motion_prompt") is not None:
                    shot["ltx_motion_prompt"] = request["ltx_motion_prompt"]
                if request.get("_soundscape_signature"):
                    shot["_soundscape_signature"] = request["_soundscape_signature"]
                if request.get("_voice_signature"):
                    shot["_voice_signature"] = request["_voice_signature"]
                updated += 1
        if updated == 0:
            return {"success": False, "error": f"Shot {shot_id} not found"}
        with open(sp_path, "w") as f:
            json.dump(sp_raw, f, indent=2)
        cache_dir = pdir / "ui_cache"
        cache_dir.mkdir(exist_ok=True)
        (cache_dir / "bundle.dirty").touch()
        logger.info(f"[UPDATE-PROMPT] {project}/{shot_id} prompt updated by user review")
        return {
            "success": True, "shot_id": shot_id, "project": project,
            "prompt_length": len(new_nano),
            "message": f"Prompt updated for {shot_id}. Regenerate frame to see effect.",
        }
    except Exception as e:
        logger.error(f"[UPDATE-PROMPT] Error: {e}", exc_info=True)
        return {"success": False, "error": str(e)}


@app.post("/api/auto/approve-shot")
async def approve_shot(request: Dict = Body(...)):
    """
    V29.16: Approve a shot for video generation.
    Sets _approval_status on the shot in shot_plan.json and invalidates UI cache.

    Body: {"project": "...", "shot_id": "001_M01", "status": "APPROVED"}
    """
    project = request.get("project")
    shot_id = request.get("shot_id")
    status = request.get("status", "APPROVED")

    if not project or not shot_id:
        return {"success": False, "error": "project and shot_id required"}

    valid_statuses = {"APPROVED", "AWAITING_APPROVAL", "REGEN_REQUESTED", "AUTO_APPROVED"}
    if status not in valid_statuses:
        return {"success": False, "error": f"Invalid status. Use: {valid_statuses}"}

    try:
        pdir = get_project_path(project)
        sp_path = pdir / "shot_plan.json"
        if not sp_path.exists():
            return {"success": False, "error": "shot_plan.json not found"}

        with open(sp_path) as f:
            sp_raw = json.load(f)
        is_list = isinstance(sp_raw, list)
        shots = sp_raw if is_list else sp_raw.get("shots", [])

        updated = 0
        for shot in shots:
            if shot.get("shot_id") == shot_id:
                shot["_approval_status"] = status
                shot["_approval_updated_at"] = __import__("datetime").datetime.now().isoformat()
                updated += 1

        if updated == 0:
            return {"success": False, "error": f"Shot {shot_id} not found in shot_plan"}

        with open(sp_path, "w") as f:
            json.dump(sp_raw, f, indent=2)

        # Invalidate UI cache
        cache_dir = pdir / "ui_cache"
        cache_dir.mkdir(exist_ok=True)
        (cache_dir / "bundle.dirty").touch()

        logger.info(f"[APPROVE-SHOT] {project}/{shot_id} → {status}")
        return {"success": True, "shot_id": shot_id, "status": status, "project": project}

    except Exception as e:
        logger.error(f"[APPROVE-SHOT] Error: {e}", exc_info=True)
        return {"success": False, "error": str(e)}


