@app.post("/api/auto/diagnose-shot")
async def diagnose_shot(request: Dict = Body(...)):
    """
    V30.5: Run Gemini vision diagnosis on the CURRENT frame for a shot.
    Returns failure class, reason, and suggested prompt_patch — does NOT archive or regen.

    Body: {"project": "...", "shot_id": "001_M01"}
    Returns: {"success": true, "shot_id": "...", "diagnosis": {"failure": "LOCATION",
              "reason": "...", "prompt_patch": "..."}, "current_prompt": "...", "proposed_prompt": "..."}
    """
    project = request.get("project")
    shot_id = request.get("shot_id")

    if not project or not shot_id:
        return {"success": False, "error": "project and shot_id required"}

    pdir = get_project_path(project)
    sp_path = pdir / "shot_plan.json"

    # Load current shot data
    shot_data = {}
    current_nano = ""
    try:
        with open(sp_path) as f:
            sp_raw = json.load(f)
        shots_list = sp_raw if isinstance(sp_raw, list) else sp_raw.get("shots", [])
        for _s in shots_list:
            if _s.get("shot_id") == shot_id:
                shot_data = _s
                current_nano = _s.get("nano_prompt") or _s.get("prompt") or ""
                break
    except Exception as _e:
        return {"success": False, "error": f"Could not load shot plan: {_e}"}

    # Check current frame exists
    frame_path = pdir / "first_frames" / f"{shot_id}.jpg"
    if not frame_path.exists():
        return {
            "success": False,
            "error": f"No frame found for {shot_id} — nothing to diagnose",
            "diagnosis": {"failure": "IDENTITY", "reason": "No frame on disk", "prompt_patch": ""}
        }

    google_key = os.environ.get("GOOGLE_API_KEY", "")
    if not google_key:
        return {
            "success": True,
            "shot_id": shot_id,
            "diagnosis": {"failure": "IDENTITY", "reason": "No GOOGLE_API_KEY — defaulting to identity boost", "prompt_patch": ""},
            "current_prompt": current_nano[:200],
            "proposed_prompt": current_nano[:200]
        }

    import urllib.request as _diag_urllib
    import io as _diag_io
    try:
        from PIL import Image as _DiagPIL
        _img = _DiagPIL.open(str(frame_path))
        _img.thumbnail((512, 512))
        _buf = _diag_io.BytesIO()
        _img.save(_buf, "JPEG", quality=60)
        _b64 = base64.standard_b64encode(_buf.getvalue()).decode()

        _expected = shot_data.get("_frame_description") or shot_data.get("description") or ""

        # FIX 2: Pull Room DNA from story bible for richer context
        _room_dna = ""
        try:
            from tools.scene_visual_dna import build_scene_dna as _build_scene_dna
            _sb_path = pdir / "story_bible.json"
            if _sb_path.exists():
                with open(_sb_path) as _sbf:
                    _sb = json.load(_sbf)
                _scene_id_prefix = shot_id.split("_")[0]
                _sb_scene = next(
                    (s for s in _sb.get("scenes", [])
                     if str(s.get("scene_id", "")).zfill(3) == _scene_id_prefix),
                    {}
                )
                if _sb_scene:
                    _room_dna = _build_scene_dna(_sb_scene)
        except Exception:
            pass

        _diag_prompt = (
            f"You are a film director reviewing a rejected frame.\n"
            f"Expected shot: {_expected[:250]}\n"
            + (f"Canonical room: {_room_dna[:200]}\n" if _room_dna else "")
            + f"Classify the PRIMARY failure as exactly one of: "
            f"IDENTITY, LOCATION, CAMERA, BLOCKING, STORY_BEAT, TONE\n"
            f"Give a SPECIFIC visual fix — mention exact colors, positions, materials.\n"
            f'Return ONLY valid JSON (no markdown): {{"failure":"CLASS","reason":"one sentence","prompt_patch":"specific one sentence fix"}}'
        )
        # FIX 1: thinkingBudget:0 required for Gemini 2.5 Flash or it returns 403
        _payload = json.dumps({
            "contents": [{"parts": [
                {"inline_data": {"mime_type": "image/jpeg", "data": _b64}},
                {"text": _diag_prompt}
            ]}],
            "generationConfig": {
                "maxOutputTokens": 200,
                "temperature": 0.1,
                "thinkingConfig": {"thinkingBudget": 0}
            }
        }).encode()
        _url = (
            f"https://generativelanguage.googleapis.com/v1beta/models/"
            f"gemini-2.5-flash:generateContent?key={google_key}"
        )
        _req = _diag_urllib.Request(_url, data=_payload, headers={"Content-Type": "application/json"})
        _resp = _diag_urllib.urlopen(_req, timeout=20)
        _result = json.loads(_resp.read())
        _parts = _result["candidates"][0]["content"].get("parts", [])
        _raw = " ".join(p.get("text", "") for p in _parts).strip()

        # FIX 3: Robust JSON extraction — handle backticks, thinking preamble, partial wraps
        import re as _diag_re
        _json_str = _raw
        if "```" in _json_str:
            for _chunk in _json_str.split("```"):
                _chunk = _chunk.strip()
                if _chunk.startswith("json"):
                    _chunk = _chunk[4:].strip()
                if _chunk.startswith("{"):
                    _json_str = _chunk
                    break
        # Regex-extract the JSON object even if there's preamble text
        _jm = _diag_re.search(r'\{[^{}]*"failure"[^{}]*\}', _json_str, _diag_re.DOTALL)
        if _jm:
            _json_str = _jm.group()
        _diag = json.loads(_json_str.strip())

        _patch = _diag.get("prompt_patch", "")
        _proposed = (_patch + " " + current_nano[:150]).strip() if _patch else current_nano
        logger.info(f"[DIAGNOSE-SHOT] {shot_id}: {_diag.get('failure')} — {_diag.get('reason','')}")
        return {
            "success": True,
            "shot_id": shot_id,
            "diagnosis": _diag,
            "current_prompt": current_nano[:200],
            "proposed_prompt": _proposed[:200]
        }
    except Exception as _de:
        logger.warning(f"[DIAGNOSE-SHOT] {shot_id}: Gemini failed ({_de}) — returning IDENTITY default")
        return {
            "success": True,
            "shot_id": shot_id,
            "diagnosis": {"failure": "IDENTITY", "reason": f"Diagnosis unavailable ({_de})", "prompt_patch": ""},
            "current_prompt": current_nano[:200],
            "proposed_prompt": current_nano[:200]
        }


@app.post("/api/auto/regen-shot")
async def regen_shot(request: Dict = Body(...)):
    """
    V30.5: Regenerate a single shot's first frame with consistency constraints.
    Archives current frame, applies fix, generates new one, updates shot_plan.

    Body: {"project": "...", "shot_id": "001_M01", "video_model": "seedance",
           "diagnosis": {"failure": "LOCATION", "prompt_patch": "..."}}  ← diagnosis optional
    If diagnosis provided: skip Gemini re-analysis, apply the patch directly.
    If diagnosis absent: run Gemini diagnosis automatically (backward compatible).
    """
    project = request.get("project")
    shot_id = request.get("shot_id")
    video_model = (request.get("video_model") or "kling").lower()
    # V30.5 UI: caller may pass pre-computed diagnosis (from /api/auto/diagnose-shot)
    _preflight_diag = request.get("diagnosis")  # dict or None

    if not project or not shot_id:
        return {"success": False, "error": "project and shot_id required"}

    # Mark as REGEN_REQUESTED first (optimistic)
    try:
        pdir = get_project_path(project)
        sp_path = pdir / "shot_plan.json"
        if sp_path.exists():
            with open(sp_path) as f:
                sp_raw = json.load(f)
            shots = sp_raw if isinstance(sp_raw, list) else sp_raw.get("shots", [])
            for shot in shots:
                if shot.get("shot_id") == shot_id:
                    shot["_approval_status"] = "REGEN_REQUESTED"
            with open(sp_path, "w") as f:
                json.dump(sp_raw, f, indent=2)
    except Exception as e:
        logger.warning(f"[REGEN-SHOT] Could not mark REGEN_REQUESTED: {e}")

    # Archive existing frame
    try:
        frame_path = pdir / "first_frames" / f"{shot_id}.jpg"
        if frame_path.exists():
            archive_dir = pdir / "_archived_frames"
            archive_dir.mkdir(exist_ok=True)
            import shutil
            ts = __import__("datetime").datetime.now().strftime("%Y%m%d_%H%M%S")
            shutil.move(str(frame_path), str(archive_dir / f"{shot_id}_{ts}.jpg"))
    except Exception as e:
        logger.warning(f"[REGEN-SHOT] Archive failed: {e}")

    # V30.5: Diagnostic regen — use pre-flight diagnosis if caller provided one, else run Gemini
    import urllib.request as _urllib_req
    import io as _io
    _diag_class = "IDENTITY"  # default: apply identity boost
    _diag_reason = ""
    _diag_patch = ""

    if _preflight_diag and isinstance(_preflight_diag, dict):
        # Caller already ran /api/auto/diagnose-shot and user approved — skip Gemini re-run
        _diag_class = _preflight_diag.get("failure", "IDENTITY")
        _diag_reason = _preflight_diag.get("reason", "")
        _diag_patch = _preflight_diag.get("prompt_patch", "")
        logger.info(f"[REGEN-DIAG] {shot_id}: using pre-flight diagnosis: {_diag_class} — {_diag_reason}")

        # Apply patch to shot_plan now
        if _diag_class in ("LOCATION", "CAMERA", "BLOCKING", "STORY_BEAT", "TONE"):
            try:
                with open(sp_path) as _f:
                    _sp_patch = json.load(_f)
                _shots_patch = _sp_patch if isinstance(_sp_patch, list) else _sp_patch.get("shots", [])
                for _bshot in _shots_patch:
                    if _bshot.get("shot_id") != shot_id:
                        continue
                    _bshot["nano_prompt"] = ""  # clear → rebuild from description
                    if _diag_patch:
                        _bshot["_regen_patch"] = _diag_patch
                    _bshot["_regen_note"] = f"{_diag_class} fix: {_diag_patch}"
                    break
                with open(sp_path, "w") as _f:
                    json.dump(_sp_patch, _f, indent=2)
                logger.info(f"[REGEN-DIAG] {shot_id}: {_diag_class} patch applied from pre-flight")
            except Exception as _pe:
                logger.warning(f"[REGEN-DIAG] {shot_id}: patch write failed ({_pe})")
    else:
        # No pre-flight diagnosis — run Gemini on archived frame (backward compatible)
        try:
            _google_key = os.environ.get("GOOGLE_API_KEY", "")
            _arch_dir = pdir / "_archived_frames"
            _arch_frame = None
            if _arch_dir.exists() and _google_key:
                _arch_candidates = sorted(_arch_dir.glob(f"{shot_id}_*.jpg"))
                if _arch_candidates:
                    _arch_frame = _arch_candidates[-1]

            if _arch_frame and _arch_frame.exists():
                from PIL import Image as _PILimg
                _img = _PILimg.open(str(_arch_frame))
                _img.thumbnail((512, 512))
                _buf = _io.BytesIO()
                _img.save(_buf, "JPEG", quality=60)
                _b64_frame = base64.standard_b64encode(_buf.getvalue()).decode()

                with open(sp_path) as _f:
                    _sp_diag = json.load(_f)
                _shots_diag = _sp_diag if isinstance(_sp_diag, list) else _sp_diag.get("shots", [])
                _shot_diag = next((s for s in _shots_diag if s.get("shot_id") == shot_id), {})
                _expected = _shot_diag.get("_frame_description") or _shot_diag.get("description") or ""

                _diag_prompt = (
                    f"Compare this rejected film frame to the expected shot:\n"
                    f"Expected: {_expected[:300]}\n"
                    f"Classify the PRIMARY failure as exactly one of: "
                    f"IDENTITY, LOCATION, CAMERA, BLOCKING, STORY_BEAT, TONE\n"
                    f'Return ONLY JSON: {{"failure":"CLASS","reason":"one sentence","prompt_patch":"one sentence fix"}}'
                )
                _diag_payload = json.dumps({
                    "contents": [{"parts": [
                        {"inline_data": {"mime_type": "image/jpeg", "data": _b64_frame}},
                        {"text": _diag_prompt}
                    ]}],
                    "generationConfig": {"maxOutputTokens": 150, "temperature": 0.1}
                }).encode()
                _diag_url = (
                    f"https://generativelanguage.googleapis.com/v1beta/models/"
                    f"gemini-2.5-flash:generateContent?key={_google_key}"
                )
                _diag_req = _urllib_req.Request(
                    _diag_url, data=_diag_payload,
                    headers={"Content-Type": "application/json"}
                )
                _diag_resp = _urllib_req.urlopen(_diag_req, timeout=15)
                _diag_result = json.loads(_diag_resp.read())
                _diag_parts = _diag_result["candidates"][0]["content"].get("parts", [])
                _diag_raw = " ".join(p.get("text", "") for p in _diag_parts).strip()
                if _diag_raw.startswith("```"):
                    _diag_raw = _diag_raw.split("```")[1]
                    if _diag_raw.startswith("json"):
                        _diag_raw = _diag_raw[4:]
                _diag = json.loads(_diag_raw.strip())
                _diag_class = _diag.get("failure", "IDENTITY")
                _diag_reason = _diag.get("reason", "")
                _diag_patch = _diag.get("prompt_patch", "")
                logger.info(f"[REGEN-DIAG] {shot_id}: {_diag_class} — {_diag_reason}")

                # Apply class-specific fix when NOT identity
                if _diag_class in ("LOCATION", "CAMERA", "BLOCKING", "STORY_BEAT", "TONE"):
                    with open(sp_path) as _f:
                        _sp_patch = json.load(_f)
                    _shots_patch = _sp_patch if isinstance(_sp_patch, list) else _sp_patch.get("shots", [])
                    for _bshot in _shots_patch:
                        if _bshot.get("shot_id") != shot_id:
                            continue
                        _bshot["nano_prompt"] = ""  # clear → rebuild from description
                        if _diag_patch:
                            _bshot["_regen_patch"] = _diag_patch
                        _bshot["_regen_note"] = f"{_diag_class} fix: {_diag_patch}"
                        logger.info(f"[REGEN-DIAG] {shot_id}: {_diag_class} fix applied (cleared nano_prompt)")
                        break
                    with open(sp_path, "w") as _f:
                        json.dump(_sp_patch, _f, indent=2)
            else:
                logger.info(
                    f"[REGEN-DIAG] {shot_id}: no archived frame or no GOOGLE_API_KEY"
                    f" — defaulting to IDENTITY boost"
                )
        except Exception as _diag_err:
            logger.warning(f"[REGEN-DIAG] Diagnosis failed ({_diag_err}) — falling back to identity boost")
            _diag_class = "IDENTITY"

    # Apply identity boost only when diagnosis says IDENTITY (or diagnosis unavailable)
    # T2-FE-27: amplified identity in every IDENTITY regen. V30.5: class-gated.
    if _diag_class == "IDENTITY":
        try:
            with open(sp_path) as f:
                sp_raw_boost = json.load(f)
            shots_boost = sp_raw_boost if isinstance(sp_raw_boost, list) else sp_raw_boost.get("shots", [])
            cast_path = pdir / "cast_map.json"
            cast_boost = {}
            if cast_path.exists():
                with open(cast_path) as f:
                    cast_boost = json.load(f)
            for _bshot in shots_boost:
                if _bshot.get("shot_id") != shot_id:
                    continue
                _bchars = _bshot.get("characters") or []
                _boost_lines = []
                for _bcn in _bchars:
                    _bcdata = cast_boost.get(_bcn) or cast_boost.get(_bcn.upper()) or {}
                    _bapp = (_bcdata.get("amplified_appearance") or _bcdata.get("appearance") or _bcn)
                    _boost_lines.append(
                        f"[IDENTITY BOOST — {_bcn.upper()}] {_bapp}. "
                        f"THIS PERSON MUST BE CLEARLY VISIBLE AND RECOGNIZABLE."
                    )
                if _boost_lines:
                    _orig_np = _bshot.get("nano_prompt") or _bshot.get("prompt") or ""
                    # Only prepend boost if not already boosted (idempotent)
                    if "[IDENTITY BOOST" not in _orig_np:
                        _bshot["nano_prompt"] = "\n".join(_boost_lines) + "\n" + _orig_np
                        _bshot["_identity_boost"] = True
                        logger.info(f"[REGEN-SHOT] {shot_id}: identity_boost applied ({len(_bchars)} chars)")
            with open(sp_path, "w") as f:
                json.dump(sp_raw_boost, f, indent=2)
        except Exception as _be:
            logger.warning(f"[REGEN-SHOT] Identity boost failed ({_be}) — regenerating with original prompt")

    # V30.5: Fire-and-forget — launch regen subprocess in background thread, return immediately.
    # Runner pushes per-shot status to /api/live-generations/push so filmstrip shows spinner.
    import subprocess, sys, threading as _threading

    runner_path = Path(__file__).parent / "atlas_universal_runner.py"
    scene_id = shot_id.split("_")[0]
    env = os.environ.copy()
    env["ATLAS_REGEN_SHOT_ID"] = shot_id
    env["ATLAS_VIDEO_MODEL"] = video_model
    cmd = [sys.executable, str(runner_path), project, scene_id, "--mode", "lite", "--frames-only"]
    logger.info(f"[REGEN-SHOT] Launching background regen: {shot_id}")

    def _bg_regen():
        try:
            proc = subprocess.Popen(cmd, cwd=str(Path(__file__).parent),
                                     stdout=subprocess.PIPE, stderr=subprocess.STDOUT,
                                     text=True, env=env)
            stdout, _ = proc.communicate(timeout=300)
            logger.info(f"[REGEN-SHOT] {shot_id} done (exit={proc.returncode}):\n{stdout[-1000:]}")
            new_frame = pdir / "first_frames" / f"{shot_id}.jpg"
            frame_url = f"/api/media?path={new_frame}" if new_frame.exists() else None
            if new_frame.exists() and sp_path.exists():
                with open(sp_path) as f:
                    sp_r = json.load(f)
                shots_r = sp_r if isinstance(sp_r, list) else sp_r.get("shots", [])
                for s in shots_r:
                    if s.get("shot_id") == shot_id:
                        # V37-parity: VVO E-shot rejection — check for human figures in env-only frames
                        _new_approval = "AWAITING_APPROVAL"
                        if new_frame.exists() and (s.get("_no_char_ref") or s.get("_is_broll")):
                            try:
                                from tools.generation_guard import check_e_shot_for_people
                                _vvo_clean, _vvo_reason = check_e_shot_for_people(str(new_frame), s)
                                if not _vvo_clean:
                                    _new_approval = "REGEN_REQUESTED"
                                    s["_vvo_rejection"] = _vvo_reason
                                    logger.warning(f"[VVO E-SHOT] {shot_id}: {_vvo_reason} — auto-flagged REGEN_REQUESTED")
                                else:
                                    logger.info(f"[VVO E-SHOT] {shot_id}: {_vvo_reason}")
                            except Exception as _vvo_err:
                                logger.warning(f"[VVO E-SHOT] {shot_id}: non-blocking: {_vvo_err}")
                        s["_approval_status"] = _new_approval
                        s["first_frame_url"] = frame_url
                with open(sp_path, "w") as f:
                    json.dump(sp_r, f, indent=2)
                try: (pdir / "ui_cache" / "bundle.dirty").touch()
                except Exception: pass
        except Exception as _err:
            logger.error(f"[REGEN-SHOT] Background error for {shot_id}: {_err}")

    _threading.Thread(target=_bg_regen, daemon=True).start()

    # Push "running" status immediately so filmstrip shows spinner
    try:
        LIVE_GEN_TRACKER.push({"shot_id": shot_id, "status": "running",
                               "asset_type": "first_frame", "project": project})
    except Exception: pass

    return {
        "success": True,
        "status": "started",
        "shot_id": shot_id,
        "message": f"Regen started for {shot_id} — watch filmstrip for live update"
    }


@app.get("/api/auto/gate-status")
async def gate_status(scene: str = "", project: str = ""):
    """
    V31.0: Return pre-video gate results for a scene.
    Reads gate_results from shot_plan fields (_gate_score, _gate_status, _gate_notes)
    and from any saved gate_results/*.json files.
    Provides pass/fail per shot so the UI can show visual status before video gen.

    GET /api/auto/gate-status?project=victorian_shadows_ep1&scene=006
    """
    if not project:
        # Try to infer from active project
        project = _get_active_project() if callable(globals().get("_get_active_project")) else ""
    if not project:
        return {"success": False, "error": "project required"}

    pdir = Path(PIPELINE_OUTPUTS_DIR) / project
    sp_path = pdir / "shot_plan.json"
    if not sp_path.exists():
        return {"success": False, "error": "shot_plan not found"}

    with open(sp_path) as f:
        sp_raw = json.load(f)
    shots = sp_raw if isinstance(sp_raw, list) else sp_raw.get("shots", [])
    scene_shots = [s for s in shots if (not scene or s.get("shot_id", "").startswith(scene + "_"))]

    results = []
    for shot in scene_shots:
        sid = shot.get("shot_id", "")
        frame_path = pdir / "first_frames" / f"{sid}.jpg"
        has_frame = frame_path.exists()

        # Read gate data from shot_plan fields (written by pre_video_gate.py)
        gate_score   = shot.get("_gate_score")
        gate_status  = shot.get("_gate_status")   # PASS / FLAG / REGEN
        gate_notes   = shot.get("_gate_notes", {})
        gate_ts      = shot.get("_gate_checked_at")

        # Also check for saved gate_results file
        gate_file = pdir / "gate_results" / f"{sid}_gate.json"
        if gate_file.exists() and not gate_score:
            try:
                with open(gate_file) as gf:
                    gdata = json.load(gf)
                gate_score  = gdata.get("score")
                gate_status = gdata.get("status")
                gate_notes  = gdata.get("notes", {})
                gate_ts     = gdata.get("checked_at")
            except Exception:
                pass

        # Determine display status
        if not has_frame:
            display = "NO_FRAME"
        elif gate_status:
            display = gate_status
        else:
            display = "UNCHECKED"

        results.append({
            "shot_id": sid,
            "shot_type": shot.get("shot_type", ""),
            "has_frame": has_frame,
            "approval_status": shot.get("_approval_status", "AWAITING_APPROVAL"),
            "gate_status": display,
            "gate_score": gate_score,
            "gate_notes": gate_notes,
            "gate_checked_at": gate_ts,
            "frame_url": f"/api/media?path={frame_path}" if has_frame else None,
        })

    passed  = sum(1 for r in results if r["gate_status"] == "PASS")
    flagged = sum(1 for r in results if r["gate_status"] == "FLAG")
    failed  = sum(1 for r in results if r["gate_status"] == "REGEN")
    unchecked = sum(1 for r in results if r["gate_status"] == "UNCHECKED")

    return {
        "success": True,
        "project": project,
        "scene_id": scene,
        "shots": results,
        "summary": {
            "total": len(results),
            "passed": passed,
            "flagged": flagged,
            "failed": failed,
            "unchecked": unchecked,
            "ready_for_video": passed + flagged,
        }
    }


@app.post("/api/auto/update-prompt")
async def update_prompt(request: Dict = Body(...)):
    """
    V31.0: Update a shot's prompt fields from the UI Prompt Review panel.
    Allows editing nano_prompt, Room DNA, dialogue, camera, blocking, tone.
    Invalidates bundle cache and marks shot as needing regen.

    Body: {
        "project": "...",
        "shot_id": "006_E01",
        "nano_prompt": "...",           # full updated prompt
        "room_dna": "...",              # optional Room DNA block override
        "beat_action": "...",           # optional beat action override
        "dialogue_text": "...",         # optional dialogue override
        "mark_regen": true              # set _approval_status=REGEN_REQUESTED
    }
    """
    project    = request.get("project")
    shot_id    = request.get("shot_id")
    nano_prompt = request.get("nano_prompt")

    if not project or not shot_id:
        return {"success": False, "error": "project and shot_id required"}

    pdir   = Path(PIPELINE_OUTPUTS_DIR) / project
    sp_path = pdir / "shot_plan.json"
    if not sp_path.exists():
        return {"success": False, "error": "shot_plan not found"}

    with open(sp_path) as f:
        sp_raw = json.load(f)
    shots = sp_raw if isinstance(sp_raw, list) else sp_raw.get("shots", [])
    updated = False

    for shot in shots:
        if shot.get("shot_id") != shot_id:
            continue

        if nano_prompt is not None:
            shot["nano_prompt"] = nano_prompt
            shot["_prompt_edited"] = True
            shot["_prompt_edited_at"] = __import__("datetime").datetime.utcnow().isoformat()

        # Optional field updates
        for field in ("room_dna", "beat_action", "dialogue_text", "camera_direction",
                      "blocking_direction", "tone_notes"):
            val = request.get(field)
            if val is not None:
                shot[f"_{field}"] = val

        if request.get("mark_regen", False):
            shot["_approval_status"] = "REGEN_REQUESTED"

        # Clear identity boost so prompt is used clean
        if "[IDENTITY BOOST" in (nano_prompt or ""):
            pass  # user explicitly included boost — keep it
        else:
            shot.pop("_identity_boost", None)

        updated = True
        break

    if not updated:
        return {"success": False, "error": f"shot {shot_id} not found"}

    with open(sp_path, "w") as f:
        json.dump(sp_raw, f, indent=2)

    try:
        (pdir / "ui_cache" / "bundle.dirty").touch()
    except Exception:
        pass

    return {"success": True, "shot_id": shot_id, "message": "Prompt updated"}


@app.get("/api/auto/prompt-review")
async def prompt_review(project: str = "", scene: str = ""):
    """
    V31.0: Return all shots for prompt review panel.
    Each shot includes full prompt context: nano_prompt, beat_action,
    dialogue_text, room_dna, camera, blocking, tone fields.
    Used by the Prompt Review UI to let operators review/edit before generation.

    GET /api/auto/prompt-review?project=victorian_shadows_ep1&scene=006
    """
    if not project:
        project = _get_active_project() if callable(globals().get("_get_active_project")) else ""
    if not project:
        return {"success": False, "error": "project required"}

    pdir = Path(PIPELINE_OUTPUTS_DIR) / project
    sp_path = pdir / "shot_plan.json"
    sb_path = pdir / "story_bible.json"
    if not sp_path.exists():
        return {"success": False, "error": "shot_plan not found"}

    with open(sp_path) as f:
        sp_raw = json.load(f)
    shots = sp_raw if isinstance(sp_raw, list) else sp_raw.get("shots", [])

    # Load story bible for beat context
    scene_beats: Dict[str, list] = {}
    if sb_path.exists():
        try:
            sb = json.load(open(sb_path))
            for sc in sb.get("scenes", []):
                scene_beats[str(sc.get("scene_id", ""))] = sc.get("beats", [])
        except Exception:
            pass

    # Load cast map for character appearances
    cast_path = pdir / "cast_map.json"
    cast_map: Dict = {}
    if cast_path.exists():
        try:
            cast_map = json.load(open(cast_path))
        except Exception:
            pass

    result_shots = []
    for shot in shots:
        sid = shot.get("shot_id", "")
        if scene and not sid.startswith(scene + "_"):
            continue

        scene_id_str = sid.split("_")[0] if "_" in sid else ""
        beats = scene_beats.get(scene_id_str, [])
        beat_idx = shot.get("_beat_index")
        beat_data = beats[beat_idx] if (beat_idx is not None and beat_idx < len(beats)) else None

        # Build character appearance summaries
        char_summaries = {}
        for ch in (shot.get("characters") or []):
            cd = cast_map.get(ch) or cast_map.get(ch.upper()) or {}
            char_summaries[ch] = (cd.get("amplified_appearance") or cd.get("appearance") or "")

        frame_path = pdir / "first_frames" / f"{sid}.jpg"

        result_shots.append({
            "shot_id":          sid,
            "shot_type":        shot.get("shot_type", ""),
            "characters":       shot.get("characters") or [],
            "char_appearances": char_summaries,
            "dialogue_text":    shot.get("dialogue_text") or shot.get("_beat_dialogue") or "",
            "nano_prompt":      shot.get("nano_prompt") or "",
            "beat_action":      shot.get("_beat_action") or (beat_data.get("character_action") if beat_data else ""),
            "beat_atmosphere":  shot.get("_beat_atmosphere") or (beat_data.get("atmosphere") if beat_data else ""),
            "room_dna":         shot.get("_room_dna") or shot.get("_scene_dna") or "",
            "camera_direction": shot.get("_camera_direction") or shot.get("camera_direction") or "",
            "blocking":         shot.get("_blocking_direction") or "",
            "tone_notes":       shot.get("_tone_notes") or shot.get("_beat_atmosphere") or "",
            "approval_status":  shot.get("_approval_status", "AWAITING_APPROVAL"),
            "has_frame":        frame_path.exists(),
            "frame_url":        f"/api/media?path={frame_path}" if frame_path.exists() else None,
            "prompt_edited":    shot.get("_prompt_edited", False),
            "prompt_edited_at": shot.get("_prompt_edited_at"),
            "identity_boost":   shot.get("_identity_boost", False),
        })

    # Group by scene
    scenes_grouped: Dict[str, list] = {}
    for s in result_shots:
        sc = s["shot_id"].split("_")[0] if "_" in s["shot_id"] else "?"
        scenes_grouped.setdefault(sc, []).append(s)

    return {
        "success": True,
        "project": project,
        "scene_filter": scene,
        "total_shots": len(result_shots),
        "scenes": scenes_grouped,
        "shots": result_shots,
    }


@app.post("/api/auto/mix-scene")
async def mix_scene_audio(request: Dict = Body(...)):
    """
    V31.0: Create a scene stitch with consistent room tone audio mixing.
    Uses scene_audio_mixer.py to:
      - Strip per-clip Kling ambient audio
      - Keep dialogue audio for dialogue shots
      - Mix in consistent room tone bed for the scene location
      - Crossfade audio at cut points
      - Re-encode to clean h264 baseline

    Body: {
        "project": "...",
        "scene_id": "006",
        "output_filename": "scene006_mixed.mp4"   # optional
    }
    """
    project  = request.get("project")
    scene_id = request.get("scene_id")
    if not project or not scene_id:
        return {"success": False, "error": "project and scene_id required"}

    pdir = Path(PIPELINE_OUTPUTS_DIR) / project
    sp_path = pdir / "shot_plan.json"
    sb_path = pdir / "story_bible.json"
    if not sp_path.exists():
        return {"success": False, "error": "shot_plan not found"}

    # Import mixer (non-blocking: if unavailable, return error)
    try:
        import sys as _sys
        _tools_dir = str(Path(__file__).parent / "tools")
        if _tools_dir not in _sys.path:
            _sys.path.insert(0, _tools_dir)
        from scene_audio_mixer import mix_scene, resolve_profile  # type: ignore
    except ImportError as e:
        return {"success": False, "error": f"scene_audio_mixer not available: {e}"}

    with open(sp_path) as f:
        sp_raw = json.load(f)
    shots = sp_raw if isinstance(sp_raw, list) else sp_raw.get("shots", [])
    scene_shots = [s for s in shots if s.get("shot_id", "").startswith(scene_id + "_")]
    if not scene_shots:
        return {"success": False, "error": f"No shots found for scene {scene_id}"}

    # Get scene location from story bible
    location = f"SCENE {scene_id}"
    if sb_path.exists():
        try:
            sb = json.load(open(sb_path))
            for sc in sb.get("scenes", []):
                if str(sc.get("scene_id")) == str(scene_id):
                    location = sc.get("location", location)
                    break
        except Exception:
            pass

    # Discover video files
    video_dirs = [
        pdir / "videos_kling_lite",
        pdir / "videos_kling_full",
        pdir / "videos_seedance_lite",
        pdir / "videos_seedance_full",
        pdir / "renders",
    ]
    clips = []
    missing = []
    for shot in scene_shots:
        sid = shot["shot_id"]
        found = None
        for vdir in video_dirs:
            if not vdir.exists():
                continue
            direct = vdir / f"{sid}.mp4"
            if direct.exists():
                found = str(direct)
                break
            for mf in vdir.glob(f"multishot_g*_{sid}.mp4"):
                found = str(mf)
                break
            if found:
                break
        if found:
            clips.append((found, shot))
        else:
            missing.append(sid)

    if missing:
        logger.warning(f"[MIX-SCENE] Missing videos for: {missing}")
    if not clips:
        return {"success": False, "error": f"No video clips found for scene {scene_id}"}

    # Output path
    out_name = request.get("output_filename") or f"scene{scene_id}_mixed.mp4"
    output_path = str(pdir / out_name)

    # Run mixer in background thread
    import threading as _threading

    def _bg_mix():
        try:
            result = mix_scene(
                scene_id=scene_id,
                video_clips=clips,
                location=location,
                output_path=output_path,
            )
            logger.info(f"[MIX-SCENE] Scene {scene_id} done: {result}")
            # Push completion to live tracker
            try:
                LIVE_GEN_TRACKER.push({
                    "shot_id": f"MIX_{scene_id}",
                    "status": "completed" if result.get("success") else "error",
                    "asset_type": "stitch",
                    "project": project,
                    "url": f"/api/media?path={output_path}" if result.get("success") else None,
                })
            except Exception:
                pass
        except Exception as _err:
            logger.error(f"[MIX-SCENE] Error: {_err}")

    _threading.Thread(target=_bg_mix, daemon=True).start()

    return {
        "success": True,
        "status": "started",
        "scene_id": scene_id,
        "location": location,
        "clips_found": len(clips),
        "clips_missing": missing,
        "output_path": output_path,
        "message": f"Audio mixing started for scene {scene_id} ({len(clips)} clips). "
                   f"Profile: {resolve_profile(location)['description']}",
    }


@app.get("/api/auto/spatial-map")
async def get_spatial_map(project: str = "", scene: str = ""):
    """
    V31.1: Return the SPATIAL_MAP from atlas_universal_runner.py so the UI Prompt
    Review panel can show the EXPECTED E01/E02/E03 content per location type.

    Optional ?project=... &scene=... — if both given, also returns which profile
    would be matched for that scene's location (from story_bible.json).

    Response:
    {
      "profiles": {
        "kitchen": { "keywords": [...], "e01_desc": "...", "e02_desc": "...", "e03_desc": "...", ... },
        ...
      },
      "matched_profile": "kitchen",   // only if project+scene supplied
      "scene_location": "HARGROVE ESTATE - KITCHEN",
    }
    """
    try:
        import sys as _sys
        _runner_dir = str(Path(__file__).parent)
        if _runner_dir not in _sys.path:
            _sys.path.insert(0, _runner_dir)
        from atlas_universal_runner import SPATIAL_MAP, resolve_spatial_profile  # type: ignore
    except ImportError as _e:
        return {"success": False, "error": f"SPATIAL_MAP not importable: {_e}", "profiles": {}}

    # Build serialisable version (strings only, drop callable values)
    profiles = {}
    for key, val in SPATIAL_MAP.items():
        profiles[key] = {k: v for k, v in val.items() if isinstance(v, (str, list))}

    result: dict = {"success": True, "profiles": profiles}

    if project and scene:
        pdir   = Path(PIPELINE_OUTPUTS_DIR) / project
        sb_path = pdir / "story_bible.json"
        location = ""
        if sb_path.exists():
            try:
                sb = json.load(open(sb_path))
                for sc in sb.get("scenes", []):
                    if str(sc.get("scene_id")) == str(scene):
                        location = sc.get("location", "")
                        break
            except Exception:
                pass
        if location:
            loc_parts  = location.split(" - ")
            room_short = loc_parts[1].strip() if len(loc_parts) > 1 else loc_parts[0].strip()
            sp = resolve_spatial_profile(room_short, location)
            matched = next((k for k, v in SPATIAL_MAP.items() if v is sp), "estate_default")
            result["matched_profile"] = matched
            result["scene_location"]  = location
        else:
            result["matched_profile"] = None
            result["scene_location"]  = ""

    return result


@app.post("/api/auto/extend-shot")
async def extend_shot(request: Dict = Body(...)):
    """
    V30.0: Extend an existing shot's video using Seedance V2.0 Extend.

    Takes the shot's current video_url, submits it to the Extend endpoint
    with a continuation prompt, concatenates the result, and updates shot_plan.

    UI trigger: "Extend" button on any generated shot in the filmstrip.

    Body: {
        "project": "...",
        "shot_id": "001_M01",
        "extend_duration": 5,          # seconds to add (5 or 10, default 5)
        "extend_prompt": "...",        # optional override — defaults to beat_action
    }

    Response: {
        "success": true,
        "shot_id": "001_M01",
        "video_url": "/api/media?path=...",
        "extended_duration": 18,       # original + extension
        "error": null
    }
    """
    project = request.get("project")
    shot_id = request.get("shot_id")
    extend_duration = int(request.get("extend_duration") or 5)
    extend_prompt_override = request.get("extend_prompt", "")

    if not project or not shot_id:
        return {"success": False, "error": "project and shot_id required"}

    try:
        pdir = get_project_path(project)
        sp_path = pdir / "shot_plan.json"
        if not sp_path.exists():
            return {"success": False, "error": "shot_plan.json not found"}

        with open(sp_path) as f:
            sp_raw = json.load(f)
        shots = sp_raw if isinstance(sp_raw, list) else sp_raw.get("shots", [])

        # Find the shot and its current video
        target_shot = next((s for s in shots if s.get("shot_id") == shot_id), None)
        if not target_shot:
            return {"success": False, "error": f"Shot {shot_id} not found"}

        video_url = target_shot.get("video_url") or target_shot.get("video_path", "")
        if not video_url:
            return {"success": False, "error": f"Shot {shot_id} has no video yet — generate video first"}

        # Resolve local path (strip /api/media?path= prefix if present)
        if video_url.startswith("/api/media?path="):
            video_local = video_url.replace("/api/media?path=", "")
        else:
            video_local = video_url
        video_local = Path(video_local)

        if not video_local.exists():
            # Try resolving relative to project dir
            video_local = pdir / "videos" / video_local.name
        if not video_local.exists():
            return {"success": False, "error": f"Video file not found: {video_local}"}

        # Build continuation prompt
        beat_action = target_shot.get("_beat_action") or target_shot.get("description", "")
        beat_atm = target_shot.get("_beat_atmosphere", "")
        if extend_prompt_override:
            ext_prompt = extend_prompt_override
        elif beat_action:
            ext_prompt = f"Continue: {beat_action}. {beat_atm}. Same characters, same room, natural motion."
        else:
            ext_prompt = "Continue scene naturally. Same room, same characters, smooth continuation of action."

        # Mark as extending in shot_plan for UI feedback
        for shot in shots:
            if shot.get("shot_id") == shot_id:
                shot["_extend_status"] = "EXTENDING"
                shot["_extend_requested_at"] = __import__("datetime").datetime.now().isoformat()
        with open(sp_path, "w") as f:
            json.dump(sp_raw, f, indent=2)
        cache_dir = pdir / "ui_cache"
        cache_dir.mkdir(exist_ok=True)
        (cache_dir / "bundle.dirty").touch()

        # Import and call the extend function
        import sys
        runner_dir = str(Path(__file__).parent)
        if runner_dir not in sys.path:
            sys.path.insert(0, runner_dir)
        from atlas_universal_runner import gen_seedance_extend as _extend_fn

        logger.info(f"[EXTEND-SHOT] {project}/{shot_id} → +{extend_duration}s | {ext_prompt[:80]}")
        extended_path = _extend_fn(
            source_video_path=str(video_local),
            prompt=ext_prompt,
            duration=extend_duration,
        )

        if not extended_path or not Path(extended_path).exists():
            # Revert status
            for shot in shots:
                if shot.get("shot_id") == shot_id:
                    shot["_extend_status"] = "FAILED"
            with open(sp_path, "w") as f:
                json.dump(sp_raw, f, indent=2)
            (cache_dir / "bundle.dirty").touch()
            return {"success": False, "error": "Extend generation failed"}

        # Move extended video to canonical video path
        ext_size_mb = Path(extended_path).stat().st_size // (1024 * 1024)
        # Archive original before overwrite
        archive_dir = pdir / "_archived_runs"
        archive_dir.mkdir(exist_ok=True)
        ts = __import__("datetime").datetime.now().strftime("%Y%m%d_%H%M%S")
        import shutil as _shutil_ext
        _shutil_ext.copy2(str(video_local), str(archive_dir / f"{shot_id}_pre_extend_{ts}.mp4"))
        _shutil_ext.copy2(extended_path, str(video_local))
        Path(extended_path).unlink(missing_ok=True)

        # Compute new duration via ffprobe
        new_duration = None
        try:
            _probe = subprocess.run(
                ["ffprobe", "-v", "error", "-show_entries", "format=duration",
                 "-of", "default=noprint_wrappers=1:nokey=1", str(video_local)],
                capture_output=True, text=True
            )
            new_duration = round(float(_probe.stdout.strip()), 1)
        except Exception:
            pass

        # Update shot_plan with extended status + new duration
        new_video_url = f"/api/media?path={video_local}"
        for shot in shots:
            if shot.get("shot_id") == shot_id:
                shot["_extend_status"] = "EXTENDED"
                shot["_extend_duration_extra"] = extend_duration
                shot["_extend_prompt"] = ext_prompt
                shot["_extended_at"] = __import__("datetime").datetime.now().isoformat()
                shot["video_url"] = new_video_url
                if new_duration:
                    shot["_extended_total_duration"] = new_duration
        with open(sp_path, "w") as f:
            json.dump(sp_raw, f, indent=2)
        (cache_dir / "bundle.dirty").touch()

        logger.info(f"[EXTEND-SHOT] ✓ {shot_id} extended: {new_duration}s, {ext_size_mb}MB")
        return {
            "success": True,
            "shot_id": shot_id,
            "video_url": new_video_url,
            "extended_duration": new_duration,
            "extend_prompt": ext_prompt,
            "error": None,
        }

    except Exception as e:
        logger.error(f"[EXTEND-SHOT] Error: {e}", exc_info=True)
        return {"success": False, "error": str(e)}


@app.post("/api/auto/run-single-shot")
async def run_single_shot(request: Dict = Body(...)):
    """
    V29.16: Run frames + video (or just one) for a single shot_id.
    Useful for testing and incremental runs from filmstrip.

    Body: {"project": "...", "shot_id": "001_M01", "mode": "frames|video|full", "video_model": "kling"}
    """
    project = request.get("project")
    shot_id = request.get("shot_id")
    mode = (request.get("mode") or "frames").lower()
    video_model = (request.get("video_model") or "kling").lower()

    if not project or not shot_id:
        return {"success": False, "error": "project and shot_id required"}

    scene_id = shot_id.split("_")[0]

    import subprocess, sys, threading as _threading
    runner_path = Path(__file__).parent / "atlas_universal_runner.py"
    env = os.environ.copy()
    env["ATLAS_REGEN_SHOT_ID"] = shot_id
    env["ATLAS_VIDEO_MODEL"] = video_model

    if mode == "frames":
        flags = ["--mode", "lite", "--frames-only"]
    elif mode == "video":
        flags = ["--mode", "lite", "--videos-only"]
    else:
        flags = ["--mode", "lite"]

    cmd = [sys.executable, str(runner_path), project, scene_id] + flags
    logger.info(f"[SINGLE-SHOT] Launching background: {shot_id} mode={mode}")

    pdir = get_project_path(project)

    def _bg_single():
        try:
            proc = subprocess.Popen(cmd, cwd=str(Path(__file__).parent),
                                     stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True, env=env)
            stdout, _ = proc.communicate(timeout=600)
            logger.info(f"[SINGLE-SHOT] {shot_id} done (exit={proc.returncode})")
            try:
                (pdir / "ui_cache").mkdir(exist_ok=True)
                (pdir / "ui_cache" / "bundle.dirty").touch()
            except Exception: pass
        except Exception as _err:
            logger.error(f"[SINGLE-SHOT] Background error for {shot_id}: {_err}")

    _threading.Thread(target=_bg_single, daemon=True).start()

    # Push running status immediately
    try:
        asset_type = "video" if mode == "video" else "first_frame"
        LIVE_GEN_TRACKER.push({"shot_id": shot_id, "status": "running",
                               "asset_type": asset_type, "project": project})
    except Exception: pass

    return {
        "success": True,
        "status": "started",
        "shot_id": shot_id,
        "mode": mode,
        "message": f"{shot_id} {mode} started — watch filmstrip"
    }


@app.post("/api/auto/upload-story-bible")
async def upload_story_bible(request: Dict = Body(...)):
    """
    Upload and save story bible.

    Body:
    {
        "project": "my_project",
        "story_bible": { ... story bible JSON ... }
    }
    """
    project = request.get("project")
    story_bible = request.get("story_bible", {})

    if not project:
        return {"success": False, "error": "Project name required"}
    if not story_bible:
        return {"success": False, "error": "Story bible data required"}

    project_path = get_project_path(project)
    project_path.mkdir(parents=True, exist_ok=True)

    # Add metadata
    story_bible["_uploaded_at"] = datetime.now().isoformat()
    story_bible["_project"] = project

    # V21.10: Scene count validation on upload
    _shot_plan_path = project_path / "shot_plan.json"
    if _shot_plan_path.exists():
        try:
            with open(_shot_plan_path) as _sp_f:
                _sp_data = json.load(_sp_f)
            _canonical_count = _sp_data.get("_canonical_scene_count", 0)
            _bible_scenes = story_bible.get("scenes", [])
            if _canonical_count > 0 and len(_bible_scenes) > 0 and len(_bible_scenes) != _canonical_count:
                return {
                    "success": False,
                    "error": (
                        f"Story bible scene count mismatch: screenplay has "
                        f"{_canonical_count} scene headers, but uploaded bible has "
                        f"{len(_bible_scenes)} scenes. Fix the bible to match."
                    )
                }
            story_bible["_canonical_scene_count"] = _canonical_count
        except Exception:
            pass

    story_bible_path = project_path / "story_bible.json"
    with open(story_bible_path, 'w') as f:
        json.dump(story_bible, f, indent=2)

    logger.info(f"[STORY_BIBLE] Uploaded story bible for {project}")

    return {
        "success": True,
        "project": project,
        "path": str(story_bible_path),
        "keys": list(story_bible.keys())
    }

