@app.get("/api/media")
async def get_media_file(request: Request, path: str = "", t: str = ""):
    """Get media file by path. Returns 404 for missing files (expected behavior for images).
    V17.7: Added no-cache headers to prevent stale image serving.
    The 't' param is a cache-buster from the UI (ignored, just prevents browser caching).
    V17.7: Smart path resolution — tries absolute path first, then relative to BASE_DIR.
    V17.8.2: Added HTTP Range request support for video streaming in Chrome.
    """
    try:
        resolved_path = None
        if path:
            # V17.7.6: Strip cache-buster from path if UI appended ?t= instead of &t=
            if '?t=' in path:
                path = path.split('?t=')[0]
            if '&t=' in path:
                path = path.split('&t=')[0]
            p = Path(path)
            if p.exists():
                resolved_path = p
            else:
                # V17.7: Try resolving relative to BASE_DIR
                for marker in ["ATLAS_CONTROL_SYSTEM/", "ATLAS_CONTROL_SYSTEM\\"]:
                    idx = path.find(marker)
                    if idx >= 0:
                        relative = path[idx + len(marker):]
                        candidate = BASE_DIR / relative
                        if candidate.exists():
                            resolved_path = candidate
                            break
                # Also try known directory prefixes relative to BASE_DIR
                if not resolved_path:
                    for marker in ["pipeline_outputs/", "pipeline_outputs\\",
                                   "character_library_locked/", "character_library_locked\\",
                                   "ai_actor_headshots/", "ai_actor_headshots\\"]:
                        idx = path.find(marker)
                        if idx >= 0:
                            relative = path[idx:]
                            candidate = BASE_DIR / relative
                            if candidate.exists():
                                resolved_path = candidate
                                break

        if resolved_path:
            suffix = resolved_path.suffix.lower()
            media_types = {
                '.jpg': 'image/jpeg',
                '.jpeg': 'image/jpeg',
                '.png': 'image/png',
                '.gif': 'image/gif',
                '.webp': 'image/webp',
                '.mp4': 'video/mp4',
                '.mov': 'video/quicktime',
                '.webm': 'video/webm',
            }
            media_type = media_types.get(suffix, 'application/octet-stream')

            # V17.8.2: HTTP Range support for video streaming
            # Chrome requires Range requests to stream video (seek, progressive buffer)
            if suffix in ('.mp4', '.mov', '.webm'):
                file_size = resolved_path.stat().st_size
                range_header = request.headers.get("range")

                if range_header:
                    # Parse Range: bytes=START-END
                    range_str = range_header.replace("bytes=", "")
                    parts = range_str.split("-")
                    start = int(parts[0]) if parts[0] else 0
                    end = int(parts[1]) if parts[1] else file_size - 1
                    end = min(end, file_size - 1)
                    content_length = end - start + 1

                    def iter_file():
                        with open(str(resolved_path), "rb") as f:
                            f.seek(start)
                            remaining = content_length
                            while remaining > 0:
                                chunk_size = min(65536, remaining)
                                data = f.read(chunk_size)
                                if not data:
                                    break
                                remaining -= len(data)
                                yield data

                    return StreamingResponse(
                        iter_file(),
                        status_code=206,
                        media_type=media_type,
                        headers={
                            "Content-Range": f"bytes {start}-{end}/{file_size}",
                            "Accept-Ranges": "bytes",
                            "Content-Length": str(content_length),
                            "Cache-Control": "no-cache",
                        }
                    )
                else:
                    # No Range header — return full file with Accept-Ranges
                    return FileResponse(
                        str(resolved_path),
                        media_type=media_type,
                        headers={
                            "Accept-Ranges": "bytes",
                            "Content-Length": str(file_size),
                            "Cache-Control": "no-cache",
                        }
                    )

            # Non-video files — standard response
            headers = {
                "Cache-Control": "no-cache, no-store, must-revalidate",
                "Pragma": "no-cache",
                "Expires": "0"
            }
            return FileResponse(str(resolved_path), media_type=media_type, headers=headers)
        # 404 is appropriate for media - UI handles missing images gracefully
        return JSONResponse({"error": "File not found", "path": path}, status_code=404)
    except Exception as e:
        print(f"[DEFENSIVE] media error: {e}")
        return JSONResponse({"error": "Media unavailable"}, status_code=404)

@app.get("/api/media/thumb")
async def get_media_thumbnail(request: Request, path: str = "", w: int = 300, t: str = ""):
    """Serve resized JPEG thumbnail for filmstrip display. Resizes to width w, maintains aspect ratio.
    Falls back to full image if PIL unavailable or resize fails."""
    import io
    # Resolve path same as get_media_file
    resolved_path = None
    if path:
        if '?t=' in path: path = path.split('?t=')[0]
        if '&t=' in path: path = path.split('&t=')[0]
        p = Path(path)
        if p.exists():
            resolved_path = p
        else:
            for marker in ["ATLAS_CONTROL_SYSTEM/", "ATLAS_CONTROL_SYSTEM\\"]:
                idx = path.find(marker)
                if idx >= 0:
                    candidate = BASE_DIR / path[idx + len(marker):]
                    if candidate.exists():
                        resolved_path = candidate
                        break
            if not resolved_path:
                for marker in ["pipeline_outputs/", "pipeline_outputs\\",
                               "character_library_locked/", "character_library_locked\\",
                               "ai_actor_headshots/", "ai_actor_headshots\\"]:
                    idx = path.find(marker)
                    if idx >= 0:
                        candidate = BASE_DIR / path[idx:]
                        if candidate.exists():
                            resolved_path = candidate
                            break

    if not resolved_path:
        return JSONResponse({"error": "File not found"}, status_code=404)

    suffix = resolved_path.suffix.lower()
    if suffix not in ('.jpg', '.jpeg', '.png', '.webp'):
        # Not an image — serve as-is
        return FileResponse(str(resolved_path), media_type='image/jpeg')

    try:
        from PIL import Image as _PILImage
        w = max(50, min(w, 1200))
        img = _PILImage.open(str(resolved_path))
        # Convert to RGB (handles RGBA PNGs)
        if img.mode not in ('RGB', 'L'):
            img = img.convert('RGB')
        # Resize maintaining aspect ratio
        orig_w, orig_h = img.size
        if orig_w > w:
            ratio = w / orig_w
            new_h = int(orig_h * ratio)
            img = img.resize((w, new_h), _PILImage.LANCZOS)
        buf = io.BytesIO()
        img.save(buf, format='JPEG', quality=75, optimize=True)
        buf.seek(0)
        from fastapi.responses import StreamingResponse
        return StreamingResponse(
            buf,
            media_type='image/jpeg',
            headers={
                'Cache-Control': 'public, max-age=86400',
                'X-Thumb-W': str(w),
            }
        )
    except Exception as e:
        logger.warning(f"[THUMB] Resize failed ({e}), serving original")
        return FileResponse(str(resolved_path), media_type='image/jpeg')


@app.get("/project-media/{project}/{file_path:path}")
async def get_project_media(project: str, file_path: str):
    """
    V16.7: Serve project files from pipeline_outputs/{project}/.
    This is what the UI uses to load cast_map.json, render_plan.json, etc.
    """
    try:
        # Normalize project name - try exact match first, then case-insensitive
        project_dir = PIPELINE_OUTPUTS_DIR / project
        if not project_dir.exists():
            # Try to find case-insensitive match
            for p in PIPELINE_OUTPUTS_DIR.iterdir():
                if p.is_dir() and p.name.lower() == project.lower():
                    project_dir = p
                    break

        file_full_path = project_dir / file_path
        if file_full_path.exists():
            # Set appropriate content type
            suffix = file_full_path.suffix.lower()
            media_types = {
                '.json': 'application/json',
                '.jpg': 'image/jpeg',
                '.jpeg': 'image/jpeg',
                '.png': 'image/png',
                '.gif': 'image/gif',
                '.webp': 'image/webp',
                '.mp4': 'video/mp4',
                '.mov': 'video/quicktime',
                '.webm': 'video/webm',
            }
            media_type = media_types.get(suffix, None)
            return FileResponse(str(file_full_path), media_type=media_type)

        return JSONResponse({"error": "File not found", "project": project, "file": file_path}, status_code=404)
    except Exception as e:
        print(f"[project-media] Error: {e}")
        return JSONResponse({"error": str(e)}, status_code=500)


