@app.get("/api/shot-plan/{project_name}")
async def get_shot_plan(project_name: str):
    """Return shot plan manifest for project. Returns empty structure if not found."""
    try:
        shot_plan_path = get_project_path(project_name) / "shot_plan.json"
        if not shot_plan_path.exists():
            return {"shots": [], "total_shots": 0, "project": project_name, "status": "no_plan"}
        with open(shot_plan_path) as f:
            return json.load(f)
    except Exception as e:
        print(f"[DEFENSIVE] shot-plan error: {e}")
        return {"shots": [], "total_shots": 0, "project": project_name, "error": str(e)}

@app.post("/api/v12/approve-scene-video")
async def approve_scene_video(request: Dict = Body(...)):
    """V17.2: Approve a rendered scene video — marks all shots in scene as approved."""
    project = request.get("project")
    scene_id = request.get("scene_id")
    if not project or not scene_id:
        return {"success": False, "error": "project and scene_id required"}

    project_path = get_project_path(project)
    shot_plan_path = project_path / "shot_plan.json"
    if not shot_plan_path.exists():
        return {"success": False, "error": "Project not found"}

    with open(shot_plan_path) as f:
        data = json.load(f)
    shots = data.get("shots", data) if isinstance(data, dict) else data

    approved_count = 0
    for shot in shots:
        # Match scene by prefix (e.g., scene "001" matches shots "001_001A", "001_002A")
        if shot.get("shot_id", "").startswith(scene_id):
            shot["approved"] = True
            shot["_approved"] = True
            approved_count += 1

    if isinstance(data, dict):
        data["shots"] = shots
    with open(shot_plan_path, "w") as f:
        json.dump(data, f, indent=2)

    # Invalidate cache
    dirty_path = project_path / "ui_cache" / "bundle.json.dirty"
    dirty_path.parent.mkdir(parents=True, exist_ok=True)
    dirty_path.touch()

    return {"success": True, "project": project, "scene": scene_id, "approved": True, "shots_approved": approved_count}

@app.post("/api/v12/render-scene-videos")
async def render_scene_videos(request: Dict = Body(...)):
    """V17.2: Render videos for a specific scene — delegates to render-videos with scene filter."""
    project = request.get("project")
    scene_id = request.get("scene_id")
    dry_run = request.get("dry_run", False)
    if not project or not scene_id:
        return {"success": False, "error": "project and scene_id required"}

    project_path = get_project_path(project)
    shot_plan_path = project_path / "shot_plan.json"
    if not shot_plan_path.exists():
        return {"success": False, "error": "Project not found"}

    with open(shot_plan_path) as f:
        data = json.load(f)
    shots = data.get("shots", data) if isinstance(data, dict) else data

    # Filter shots belonging to this scene
    scene_shots = [s for s in shots if s.get("shot_id", "").startswith(scene_id)]
    if not scene_shots:
        return {"success": False, "error": f"No shots found for scene {scene_id}"}

    shot_ids = [s.get("shot_id") for s in scene_shots]

    # Delegate to the main render-videos endpoint
    result = await render_videos_batch({"project": project, "shot_ids": shot_ids, "dry_run": dry_run})

    return {
        "success": result.get("success", False),
        "project": project,
        "scene": scene_id,
        "shots_rendered": len(shot_ids),
        "shot_ids": shot_ids,
        "videos_generated": result.get("videos_generated", 0),
        "scene_preview_url": result.get("results", [{}])[0].get("video_path") if result.get("results") else None,
        "dry_run": dry_run
    }


# =============================================================================
# V17.7.4: AUTONOMOUS SCENE RENDER PIPELINE
# Single endpoint that generates frames → LOA check → render videos → stitch
# This is the "last agent" — end-to-end scene production with oversight.
# =============================================================================

@app.post("/api/v17/autonomous-scene-render")
async def autonomous_scene_render(request: Dict = Body(...)):
    """
    V17.7.4: Autonomous scene render with LOA oversight.
    Generates first frames, runs LOA quality checks, renders videos,
    stitches scene, and returns preview URL.

    Params:
        project: str - Project name
        scene_id: str - Scene prefix (e.g. "001")
        dry_run: bool - If true, report plan without executing
        skip_frames: bool - If true, skip frame generation (use existing)
        skip_videos: bool - If true, skip video render (use existing)
        auto_approve: bool - If true, auto-approve all shots after LOA check passes
    """
    project = request.get("project")
    scene_id = request.get("scene_id")
    dry_run = request.get("dry_run", False)
    skip_frames = request.get("skip_frames", False)
    skip_videos = request.get("skip_videos", False)
    auto_approve = request.get("auto_approve", True)
    video_model = request.get("video_model", "kling")  # V18: "ltx" or "kling"

    if not project or not scene_id:
        return {"success": False, "error": "project and scene_id required"}

    project_path = get_project_path(project)
    shot_plan_path = project_path / "shot_plan.json"
    if not shot_plan_path.exists():
        return {"success": False, "error": "shot_plan.json not found"}

    import time as _time
    pipeline_start = _time.time()
    pipeline_log = []

    def log_step(step, msg, ok=True):
        elapsed = round(_time.time() - pipeline_start, 1)
        entry = {"step": step, "message": msg, "ok": ok, "elapsed_s": elapsed}
        pipeline_log.append(entry)
        logger.info(f"[AUTONOMOUS-RENDER] [{elapsed}s] {step}: {msg}")

    try:
        # Load shot plan
        with open(shot_plan_path) as f:
            data = json.load(f)
        all_shots = data.get("shots", data) if isinstance(data, dict) else data
        scene_shots = [s for s in all_shots if s.get("shot_id", "").startswith(scene_id)]

        if not scene_shots:
            return {"success": False, "error": f"No shots found for scene {scene_id}"}

        shot_ids = [s["shot_id"] for s in scene_shots]
        total_duration = sum(int(s.get("duration", 10)) for s in scene_shots)
        log_step("INIT", f"Scene {scene_id}: {len(scene_shots)} shots, {total_duration}s total duration")

        if dry_run:
            return {
                "success": True,
                "project": project,
                "scene_id": scene_id,
                "dry_run": True,
                "plan": {
                    "shots": len(scene_shots),
                    "shot_ids": shot_ids,
                    "total_duration_s": total_duration,
                    "steps": [
                        "1. Generate first frames (FAL nano-banana-pro)",
                        "2. LOA pre-gen check (character refs + location masters)",
                        "3. LOA post-gen QA (identity + location + presence scoring)",
                        "4. Auto-approve passing shots",
                        "5. Render videos (FAL LTX-2 image-to-video)",
                        "6. Stitch scene (FFmpeg concat)",
                        "7. Return scene preview URL"
                    ]
                },
                "log": pipeline_log
            }

        # ─── TEMPORAL: Track workflow (non-blocking) ───
        workflow_id = None
        try:
            workflow_id = temporal_start_workflow(project, f"autonomous_scene_{scene_id}")
        except Exception as _twf_err:
            log_step("TEMPORAL", f"Temporal tracking unavailable (non-blocking): {str(_twf_err)[:100]}", True)

        # ─── STEP 1: LOA Pre-Gen Check ───
        log_step("LOA_PRE_GEN", "Running LOA pre-generation checks...")
        loa_pre_result = None
        if LOA_AVAILABLE:
            try:
                cast_map = {}
                cast_map_path = project_path / "cast_map.json"
                if cast_map_path.exists():
                    with open(cast_map_path) as f:
                        cast_map = json.load(f)

                loc_masters_map = {}
                loc_dir = project_path / "location_masters"
                if loc_dir.exists():
                    for ext in ["jpg", "jpeg", "png", "webp"]:
                        for img in loc_dir.glob(f"*.{ext}"):
                            loc_masters_map[img.stem.upper().replace("_", " ")] = f"/api/media?path={str(img)}"

                # V17.7.4: Load scene_manifest for location cross-check
                _sm_auto = []
                try:
                    sp_path = project_path / "shot_plan.json"
                    if sp_path.exists():
                        with open(sp_path) as f:
                            _sm_auto = json.load(f).get("scene_manifest", [])
                except Exception:
                    pass

                loa_pre_result = run_loa_pre_generation(
                    scene_shots, str(project_path),
                    cast_map=cast_map, location_masters=loc_masters_map,
                    scene_manifest=_sm_auto
                )
                auto_fixes = loa_pre_result.get("auto_fixes", [])
                log_step("LOA_PRE_GEN", f"LOA pre-gen: {len(auto_fixes)} auto-fixes applied", True)

                # Persist auto-fixes to shot plan
                if auto_fixes:
                    with open(shot_plan_path, 'w') as f:
                        json.dump(data, f, indent=2)

            except Exception as loa_err:
                log_step("LOA_PRE_GEN", f"LOA pre-gen warning: {str(loa_err)[:100]}", False)
        else:
            log_step("LOA_PRE_GEN", "LOA not available — skipping pre-gen check", True)

        try: temporal_heartbeat(workflow_id, "loa_pre_gen_complete")
        except Exception: pass

        # ─── STEP 2: Generate First Frames (TURBO PARALLEL) ───
        frames_result = None
        if not skip_frames:
            log_step("FRAMES", f"TURBO generating first frames for {len(scene_shots)} shots (parallel)...")
            try:
                frames_result = await generate_first_frames_turbo({
                    "project": project,
                    "shot_ids": shot_ids,
                    "max_workers": min(15, len(scene_shots)),
                    "dry_run": False
                })
                frames_ok = frames_result.get("success", False)
                frames_count = frames_result.get("frames_generated", frames_result.get("generated", 0))
                log_step("FRAMES", f"TURBO generated {frames_count} first frames", frames_ok)
            except Exception as frame_err:
                log_step("FRAMES", f"Frame generation error: {str(frame_err)[:200]}", False)
                frames_result = {"success": False, "error": str(frame_err)}
        else:
            # Check existing frames
            existing = sum(1 for s in scene_shots if (project_path / "first_frames" / f"{s['shot_id']}.jpg").exists())
            log_step("FRAMES", f"Skipped — {existing}/{len(scene_shots)} existing frames", True)

        try: temporal_heartbeat(workflow_id, "frames_complete")
        except Exception: pass

        # ─── STEP 2B: Multi-Angle Variants (TURBO PARALLEL) ───
        if not skip_frames:
            try:
                log_step("MULTI_ANGLE", f"Generating 3-angle variants for {len(scene_shots)} shots (parallel)...")
                import requests as _ma_req
                _ma_generated = 0
                from concurrent.futures import ThreadPoolExecutor, as_completed
                def _gen_angle(sid):
                    try:
                        r = _ma_req.post(f"http://localhost:9999/api/v17/generate-multi-angle",
                            json={"project": project, "shot_id": sid}, timeout=120)
                        return r.json().get("success", False)
                    except Exception:
                        return False
                with ThreadPoolExecutor(max_workers=min(10, len(shot_ids))) as pool:
                    futures = {pool.submit(_gen_angle, sid): sid for sid in shot_ids}
                    for f in as_completed(futures):
                        if f.result():
                            _ma_generated += 1
                log_step("MULTI_ANGLE", f"Generated variants for {_ma_generated}/{len(shot_ids)} shots", _ma_generated > 0)
            except Exception as ma_err:
                log_step("MULTI_ANGLE", f"Multi-angle warning: {str(ma_err)[:100]}", False)

        # ─── STEP 2C: Continuity Bridging (optional, auto_bridge=True) ───
        auto_bridge = request.get("auto_bridge", False)
        if auto_bridge and not skip_frames and len(shot_ids) > 1:
            try:
                log_step("CONTINUITY", f"Auto-bridging {len(shot_ids)-1} shot transitions...")
                bridge_count = 0
                for idx in range(len(shot_ids) - 1):
                    try:
                        bridge_result = await continuity_bridge({
                            "project": project,
                            "source_shot_id": shot_ids[idx],
                            "target_shot_id": shot_ids[idx + 1],
                            "source_type": "last_frame",
                            "auto_select": True  # Auto-pick best DINO variant
                        })
                        if bridge_result.get("success"):
                            bridge_count += 1
                    except Exception:
                        pass
                log_step("CONTINUITY", f"Bridged {bridge_count}/{len(shot_ids)-1} transitions", bridge_count > 0)
            except Exception as br_err:
                log_step("CONTINUITY", f"Bridge warning: {str(br_err)[:100]}", False)

        # ─── STEP 3: LOA Post-Gen QA ───
        loa_post_result = None
        if LOA_AVAILABLE and not skip_frames:
            try:
                log_step("LOA_POST_GEN", "Running LOA post-generation QA...")
                # LOA post-gen checks each frame for identity/location/presence
                from atlas_agents.logical_oversight_agent import run_loa_post_generation_qa
                loa_post_result = run_loa_post_generation_qa(
                    scene_shots, str(project_path),
                    cast_map=cast_map if 'cast_map' in dir() else {}
                )
                pass_count = sum(1 for v in loa_post_result.get("verdicts", {}).values()
                                 if v.get("verdict") == "pass")
                total = len(loa_post_result.get("verdicts", {}))
                log_step("LOA_POST_GEN", f"LOA QA: {pass_count}/{total} shots passed", pass_count > 0)
            except Exception as loa_post_err:
                log_step("LOA_POST_GEN", f"LOA post-gen QA skipped: {str(loa_post_err)[:100]}", True)

        try: temporal_heartbeat(workflow_id, "loa_post_gen_complete")
        except Exception: pass

        # ─── STEP 4: Auto-Approve ───
        if auto_approve:
            approved_count = 0
            for shot in scene_shots:
                # Auto-approve shots that have first frames
                frame_path = project_path / "first_frames" / f"{shot['shot_id']}.jpg"
                if frame_path.exists():
                    shot["approved"] = True
                    approved_count += 1
            # Persist approvals
            with open(shot_plan_path, 'w') as f:
                json.dump(data, f, indent=2)
            log_step("APPROVE", f"Auto-approved {approved_count}/{len(scene_shots)} shots", True)

        try: temporal_heartbeat(workflow_id, "approval_complete")
        except Exception: pass

        # ─── STEP 5: Render Videos (TURBO PARALLEL) ───
        videos_result = None
        model_name = "Kling v3" if video_model == "kling" else "LTX-2"
        if not skip_videos:
            log_step("VIDEOS", f"TURBO rendering videos for {len(scene_shots)} shots ({model_name}, parallel)...")
            try:
                videos_result = await render_videos_turbo({
                    "project": project,
                    "shot_ids": shot_ids,
                    "max_workers": min(10, len(scene_shots)),
                    "dry_run": False,
                    "video_model": video_model  # V18: Pass model selection
                })
                videos_ok = videos_result.get("success", False)
                videos_count = videos_result.get("videos_generated", videos_result.get("generated", 0))
                log_step("VIDEOS", f"TURBO rendered {videos_count} videos", videos_ok)
            except Exception as vid_err:
                log_step("VIDEOS", f"Video render error: {str(vid_err)[:200]}", False)
                videos_result = {"success": False, "error": str(vid_err)}
        else:
            existing_vids = sum(1 for s in scene_shots if (project_path / "videos" / f"{s['shot_id']}.mp4").exists())
            log_step("VIDEOS", f"Skipped — {existing_vids}/{len(scene_shots)} existing videos", True)

        try: temporal_heartbeat(workflow_id, "videos_complete")
        except Exception: pass

        # ─── STEP 5B: V17.8 SEGMENT STITCHING for extended shots (>20s) ───
        # Extended shots are split into segments (_seg0, _seg1, etc.) during render.
        # These must be stitched into {shot_id}.mp4 BEFORE the scene stitch.
        log_step("SEG-STITCH", "Checking for extended shot segments to stitch...")
        seg_stitched = 0
        try:
            import subprocess as _seg_sp
            videos_dir = project_path / "videos"
            for s in scene_shots:
                sid = s.get("shot_id", "")
                duration = s.get("duration", s.get("duration_seconds", 0))
                shot_video = videos_dir / f"{sid}.mp4"

                # Only process extended shots that don't already have a stitched file
                if duration <= 20:
                    continue

                # Check if segments exist
                seg_files = sorted(videos_dir.glob(f"{sid}_seg*.mp4"))
                if len(seg_files) < 2:
                    continue  # No segments or only 1 (no stitching needed)

                # If full video already exists and is long enough, skip
                if shot_video.exists():
                    try:
                        _probe = _seg_sp.run([
                            "ffprobe", "-v", "error", "-show_entries", "format=duration",
                            "-of", "default=noprint_wrappers=1:nokey=1", str(shot_video)
                        ], capture_output=True, text=True, timeout=15)
                        _actual_dur = float(_probe.stdout.strip()) if _probe.stdout.strip() else 0
                        if _actual_dur >= duration - 3:
                            continue  # Already stitched and correct length
                    except Exception:
                        pass

                # Stitch segments into shot video
                _concat_path = videos_dir / f"_concat_{sid}.txt"
                with open(_concat_path, 'w') as _cf:
                    for seg in seg_files:
                        _cf.write(f"file '{seg}'\n")

                _stitch_cmd = f"ffmpeg -y -f concat -safe 0 -i '{_concat_path}' -c copy '{shot_video}'"
                _sp_result = _seg_sp.run(_stitch_cmd, shell=True, capture_output=True, timeout=120)

                if _sp_result.returncode == 0 and shot_video.exists():
                    seg_stitched += 1
                    s["video_path"] = str(shot_video)
                    s["video_url"] = f"/api/media?path={shot_video}"
                    logger.info(f"[V17.8 SEG-STITCH] {sid}: {len(seg_files)} segments → {shot_video.name}")
                else:
                    _err = _sp_result.stderr.decode()[:100] if _sp_result.stderr else "unknown"
                    logger.warning(f"[V17.8 SEG-STITCH] {sid}: FFmpeg error: {_err}")

                # Clean up concat file
                _concat_path.unlink(missing_ok=True)

            if seg_stitched > 0:
                log_step("SEG-STITCH", f"Stitched {seg_stitched} extended shots from segments", True)
                # Save updated video_path references
                with open(shot_plan_path, 'w') as f:
                    json.dump(shot_plan, f, indent=2, default=str)
            else:
                log_step("SEG-STITCH", "No extended segments needed stitching", True)
        except Exception as seg_err:
            log_step("SEG-STITCH", f"Segment stitch error (non-blocking): {str(seg_err)[:200]}", False)

        # ─── STEP 6: Stitch Scene ───
        stitch_result = None
        log_step("STITCH", f"Stitching scene {scene_id}...")
        try:
            # Build concat list for just this scene's shots
            videos_dir = project_path / "videos"
            concat_entries = []
            for s in scene_shots:
                vid_path = videos_dir / f"{s['shot_id']}.mp4"
                if vid_path.exists():
                    concat_entries.append(str(vid_path))

            if concat_entries:
                final_dir = project_path / "final"
                final_dir.mkdir(exist_ok=True)
                scene_output = final_dir / f"scene_{scene_id}.mp4"

                # Write concat list
                concat_list_path = project_path / f"concat_scene_{scene_id}.txt"
                with open(concat_list_path, 'w') as f:
                    for entry in concat_entries:
                        f.write(f"file '{entry}'\n")

                # FFmpeg concat
                import subprocess
                cmd = f"ffmpeg -y -f concat -safe 0 -i '{concat_list_path}' -c copy '{scene_output}'"
                proc = subprocess.run(cmd, shell=True, capture_output=True, timeout=120)

                if proc.returncode == 0 and scene_output.exists():
                    scene_url = f"/api/media?path={str(scene_output)}"
                    log_step("STITCH", f"Scene stitched: {len(concat_entries)} clips → {scene_output.name}", True)
                    stitch_result = {"success": True, "output_path": str(scene_output), "output_url": scene_url}
                else:
                    stderr = proc.stderr.decode()[:200] if proc.stderr else "unknown"
                    log_step("STITCH", f"FFmpeg error: {stderr}", False)
                    stitch_result = {"success": False, "error": stderr}
            else:
                log_step("STITCH", "No videos to stitch", False)
                stitch_result = {"success": False, "error": "No video files found for scene"}

        except Exception as stitch_err:
            log_step("STITCH", f"Stitch error: {str(stitch_err)[:200]}", False)
            stitch_result = {"success": False, "error": str(stitch_err)}

        try: temporal_heartbeat(workflow_id, "stitch_complete")
        except Exception: pass

        # ─── STEP 7: Invalidate cache ───
        _invalidate_bundle_cache(project)
        log_step("CACHE", "Bundle cache invalidated", True)

        # ─── COMPLETE ───
        total_time = round(_time.time() - pipeline_start, 1)
        try: temporal_complete_workflow(workflow_id)
        except Exception: pass

        scene_preview_url = stitch_result.get("output_url") if stitch_result else None

        return {
            "success": True,
            "project": project,
            "scene_id": scene_id,
            "total_time_s": total_time,
            "scene_preview_url": scene_preview_url,
            "summary": {
                "shots": len(scene_shots),
                "frames_generated": frames_result.get("frames_generated", 0) if frames_result else 0,
                "videos_rendered": videos_result.get("videos_generated", 0) if videos_result else 0,
                "stitch_success": bool(stitch_result and stitch_result.get("success")),
                "loa_fixes": len(loa_pre_result.get("auto_fixes", [])) if loa_pre_result else 0
            },
            "log": pipeline_log
        }

    except Exception as pipeline_err:
        logger.error(f"[AUTONOMOUS-RENDER] Pipeline failed for scene {scene_id}: {pipeline_err}")
        _sentry_capture_exception(pipeline_err)
        return {
            "success": False,
            "project": project,
            "scene_id": scene_id,
            "error": str(pipeline_err)[:500],
            "log": pipeline_log
        }


@app.post("/api/v12/stitch-scenes")
async def stitch_scenes(request: Dict = Body(...)):
    """V17.2: Stitch rendered scenes together — uses approved scene videos."""
    project = request.get("project")
    scene_ids = request.get("scenes", [])
    if not project:
        return {"success": False, "error": "project required"}

    project_path = get_project_path(project)
    videos_dir = project_path / "videos"
    if not videos_dir.exists():
        return {"success": False, "error": "No videos directory found"}

    # Collect video files for requested scenes (or all if no filter)
    import glob as _glob
    video_files = []
    shot_plan_path = project_path / "shot_plan.json"
    if shot_plan_path.exists():
        with open(shot_plan_path) as f:
            data = json.load(f)
        shots = data.get("shots", data) if isinstance(data, dict) else data
        for shot in shots:
            sid = shot.get("shot_id", "")
            # Filter by scene IDs if provided
            if scene_ids and not any(sid.startswith(sc) for sc in scene_ids):
                continue
            # Only include approved shots
            if not shot.get("approved") and not shot.get("_approved"):
                continue
            video_path = shot.get("video_path") or str(videos_dir / f"{sid}.mp4")
            if Path(video_path).exists():
                video_files.append({"shot_id": sid, "path": video_path})

    if not video_files:
        return {"success": False, "error": "No approved scene videos found to stitch"}

    # Create concat file
    output_dir = project_path / "stitched_scenes"
    output_dir.mkdir(parents=True, exist_ok=True)
    concat_file = output_dir / "concat.txt"
    with open(concat_file, "w") as f:
        for vf in video_files:
            f.write(f"file '{vf['path']}'\n")

    timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")
    output_path = output_dir / f"{project}_scenes_{timestamp}.mp4"

    cmd = f'ffmpeg -y -f concat -safe 0 -i "{concat_file}" -c copy "{output_path}"'
    try:
        import subprocess
        proc = await asyncio.get_event_loop().run_in_executor(
            None, lambda: subprocess.run(cmd, shell=True, capture_output=True, text=True, timeout=300)
        )
        if proc.returncode == 0 and output_path.exists():
            return {
                "success": True, "project": project,
                "output_path": str(output_path),
                "scenes_stitched": len(scene_ids) if scene_ids else "all",
                "videos_used": len(video_files),
                "file_size": output_path.stat().st_size
            }
        return {"success": False, "error": f"FFmpeg stitch failed: {(proc.stderr or '')[:200]}"}
    except Exception as e:
        return {"success": False, "error": str(e)}

@app.post("/api/v15/visual-spec/enhance-prompt")
async def enhance_visual_prompt(request: Dict = Body(...)):
    """
    Enhance a generation prompt with professional cinematography specifications using LLM.
    Adds camera details, lighting, composition, and style elements.
    """
    import httpx

    prompt = request.get("prompt", "")
    shot_type = request.get("shot_type", "")  # MS, CU, WS, etc.
    genre = request.get("genre", "cinematic")
    mood = request.get("mood", "")
    project = request.get("project", "")

    if not prompt:
        return {"success": False, "error": "Prompt is required"}

    # Load OpenRouter API key
    env_path = Path(str(BASE_DIR) + "/.env")
    api_key = ""
    if env_path.exists():
        with open(env_path) as f:
            for line in f:
                if line.startswith("OPENROUTER_API_KEY="):
                    api_key = line.split("=", 1)[1].strip()
                    break

    if not api_key:
        # Fallback to rule-based enhancement if no API key
        additions = []
        enhanced = prompt

        # Add shot type specifications
        shot_specs = {
            "ECU": "extreme close-up, macro lens, shallow depth of field, intimate framing",
            "CU": "close-up shot, 85mm lens, bokeh background, face fills frame",
            "MCU": "medium close-up, chest up framing, 50mm lens, eye-level",
            "MS": "medium shot, waist up, 35mm lens, balanced composition",
            "MWS": "medium wide shot, full body with environment context",
            "WS": "wide shot, establishing context, 24mm lens, deep focus",
            "EWS": "extreme wide shot, epic scale, landscape orientation, 16mm lens"
        }

        if shot_type.upper() in shot_specs:
            spec = shot_specs[shot_type.upper()]
            additions.append(spec)
            enhanced = f"{prompt}, {spec}"

        # Add mood-based lighting
        mood_lighting = {
            "dread": "high contrast, deep shadows, desaturated cool tones, single harsh light source",
            "tension": "dramatic side lighting, noir shadows, chiaroscuro effect",
            "grief": "soft diffused light, muted colors, overcast atmosphere",
            "hope": "warm golden hour lighting, lens flare, soft backlight",
            "mystery": "fog, volumetric lighting, silhouettes, rim light"
        }

        if mood.lower() in mood_lighting:
            lighting = mood_lighting[mood.lower()]
            additions.append(lighting)
            enhanced = f"{enhanced}, {lighting}"

        # Add genre-specific style
        genre_style = {
            "gothic_horror": "35mm anamorphic, film grain, practical lighting, period costume accuracy",
            "sci-fi": "futuristic architecture, neon accents, reflective surfaces, clean lines",
            "noir": "black and white, venetian blind shadows, cigarette smoke, fedora",
            "drama": "naturalistic lighting, emotional depth, intimate framing"
        }

        if genre.lower() in genre_style:
            style = genre_style[genre.lower()]
            additions.append(style)
            enhanced = f"{enhanced}, {style}"

        return {
            "success": True,
            "enhanced_prompt": enhanced,
            "additions": additions,
            "method": "rule_based"
        }

    # LLM-powered enhancement
    user_prompt = f"""Enhance this image generation prompt with professional cinematography details:

ORIGINAL PROMPT: {prompt}
SHOT TYPE: {shot_type or "medium shot"}
GENRE: {genre}
MOOD: {mood or "cinematic"}

Add specific technical details:
1. Camera/Lens: specific focal length (24mm, 35mm, 50mm, 85mm, etc.) and lens characteristics
2. Lighting: key light direction, fill ratio, color temperature, practical lights
3. Composition: framing rules (rule of thirds, golden ratio), headroom, lead space
4. Depth of field: aperture suggestion, focus plane, bokeh quality
5. Color grading: specific color treatment matching mood
6. Film look: grain, contrast, saturation adjustments
7. Movement hint: static, subtle drift, slow push, rack focus

Return JSON with:
- enhanced_prompt: the full enhanced prompt (400-600 chars)
- additions: array of what was added
- technical_specs: object with camera, lens, lighting, color keys

Return ONLY valid JSON."""

    try:
        async with httpx.AsyncClient(timeout=30.0) as client:
            response = await client.post(
                "https://openrouter.ai/api/v1/chat/completions",
                headers={
                    "Authorization": f"Bearer {api_key}",
                    "Content-Type": "application/json",
                    "HTTP-Referer": "https://atlas-control-system.local",
                    "X-Title": "ATLAS Prompt Enhancer"
                },
                json={
                    "model": "anthropic/claude-sonnet-4",
                    "messages": [
                        {"role": "system", "content": "You are a professional cinematographer and AI image generation expert. Enhance prompts with precise technical details that translate to better AI-generated images. Be specific about lenses, lighting ratios, and color science."},
                        {"role": "user", "content": user_prompt}
                    ],
                    "temperature": 0.5,
                    "max_tokens": 1000
                }
            )

            if response.status_code != 200:
                logger.error(f"LLM API error: {response.status_code}")
                # Fallback to original prompt
                return {"success": True, "enhanced_prompt": prompt, "additions": [], "method": "fallback"}

            result = response.json()
            content = result.get("choices", [{}])[0].get("message", {}).get("content", "")

            # Extract JSON from response
            json_match = re.search(r'\{[\s\S]*\}', content)
            if json_match:
                enhancement = json.loads(json_match.group())
                return {
                    "success": True,
                    "enhanced_prompt": enhancement.get("enhanced_prompt", prompt),
                    "additions": enhancement.get("additions", []),
                    "technical_specs": enhancement.get("technical_specs", {}),
                    "method": "llm"
                }
            else:
                return {"success": True, "enhanced_prompt": prompt, "additions": [], "method": "parse_failed"}

    except Exception as e:
        logger.error(f"Prompt enhancement error: {e}")
        return {"success": True, "enhanced_prompt": prompt, "additions": [], "error": str(e)}

