@app.post("/api/v6/regenerate-character")
async def regenerate_character(request: Dict = Body(...)):
    """
    Generate a character reference image using nano-banana-pro/edit.

    Takes the AI actor's headshot as a reference image and generates
    a new image of the actor styled as the character (with wardrobe,
    appearance details from story_bible + scene_anchor_system).

    Saves result to character_library_locked/{project}/ and updates
    cast_map.json with the new character_reference_url. Also updates
    all matching shots in shot_plan.json.

    Body:
    {
        "project": "my_project",
        "character_name": "EVELYN RAVENCROFT",
        "character_id": "EVELYN RAVENCROFT",  // alias for character_name
        "actor_id": "A001",                   // optional, resolved from cast_map
        "character_description": "..."         // optional override from UI
    }
    """
    import httpx

    # LOCKED MODEL - DO NOT CHANGE
    CHAR_REF_MODEL_EDIT = "fal-ai/nano-banana-pro/edit"
    CHAR_REF_MODEL_T2I = "fal-ai/nano-banana-pro"

    project = request.get("project")
    character_name = request.get("character_name") or request.get("character_id") or request.get("character")
    actor_id = request.get("actor_id")
    ui_description = request.get("character_description", "")

    if not project:
        return {"success": False, "error": "Project name required"}
    if not character_name:
        return {"success": False, "error": "Character name required"}

    char_upper = character_name.upper().strip()
    project_path = get_project_path(project)

    if not project_path.exists():
        return {"success": False, "error": f"Project '{project}' not found"}

    # ── 1. Load cast_map to find the AI actor ──────────────────────────
    cast_map = {}
    cast_map_path = project_path / "cast_map.json"
    if cast_map_path.exists():
        try:
            with open(cast_map_path) as f:
                cast_map = json.load(f)
        except Exception as e:
            logger.warning(f"[REGEN-CHAR] Failed to load cast_map: {e}")

    # Find the cast entry for this character
    cast_entry = None
    cast_key = None
    for key, val in cast_map.items():
        if key.startswith("_"):
            continue
        if isinstance(val, dict) and (key.upper() == char_upper or char_upper in key.upper() or key.upper() in char_upper):
            cast_entry = val
            cast_key = key
            break

    if not cast_entry:
        return {
            "success": False,
            "error": f"Character '{character_name}' not found in cast_map. Run auto-cast first.",
            "hint": "POST /api/v6/casting/auto-cast"
        }

    actor_name = cast_entry.get("ai_actor", "Unknown")
    headshot_url = (
        cast_entry.get("headshot_url")
        or cast_entry.get("locked_reference_url")
        or cast_entry.get("reference_url")
        or ""
    )

    # ── 2. Resolve actor headshot path for FAL reference ───────────────
    # If we have an actor_id or actor_name, also check ai_actors_library
    # for the image_prompt field (adds actor appearance details to prompt)
    actor_image_prompt = ""
    try:
        actor_lib_path = BASE_DIR / "ai_actors_library.json"
        if actor_lib_path.exists():
            with open(actor_lib_path) as f:
                actor_lib_data = json.load(f)
            actors_list = actor_lib_data.get("actors", actor_lib_data) if isinstance(actor_lib_data, dict) else actor_lib_data
            for actor in actors_list:
                aid = actor.get("id", "")
                aname = (actor.get("name") or "").upper()
                if (actor_id and aid == actor_id) or (aname == actor_name.upper()):
                    actor_image_prompt = actor.get("image_prompt", "")
                    # If no headshot_url from cast_map, try actor library paths
                    if not headshot_url:
                        actor_filename = aname.replace(" ", "_") + "_LOCKED_REFERENCE.jpg"
                        locked_path = BASE_DIR / "character_library_locked" / "ai_actors" / actor_filename
                        if locked_path.exists():
                            headshot_url = f"/api/media?path={locked_path}"
                        else:
                            alt_filename = aname.replace(" ", "_") + "_HEADSHOT.jpg"
                            alt_path = BASE_DIR / "ai_actor_headshots" / alt_filename
                            if alt_path.exists():
                                headshot_url = f"/api/media?path={alt_path}"
                    break
    except Exception as e:
        logger.warning(f"[REGEN-CHAR] Actor library lookup error: {e}")

    # ── 3. Get character wardrobe from scene_anchor_system + story_bible ─
    wardrobe_desc = ""
    character_appearance = ""

    # Priority 1: Project configuration wardrobe locks
    try:
        _wl_config = get_project_config(project_name)
        for locked_name, wardrobe in _wl_config.wardrobe_locks.items():
            if locked_name in char_upper or char_upper in locked_name:
                wardrobe_desc = wardrobe
                break
    except Exception:
        pass

    # Priority 2: Story bible character data
    if not wardrobe_desc:
        story_bible = {}
        story_bible_path = project_path / "story_bible.json"
        if story_bible_path.exists():
            try:
                with open(story_bible_path) as f:
                    story_bible = json.load(f)
            except Exception:
                pass

        for char in story_bible.get("characters", []):
            name = (char.get("name") or "").upper()
            if name == char_upper or char_upper in name or name in char_upper:
                # Wardrobe fields (try multiple)
                wardrobe_desc = (
                    char.get("costume")
                    or char.get("wardrobe")
                    or char.get("attire")
                    or char.get("clothing")
                    or ""
                )
                if isinstance(char.get("appearance"), dict):
                    wardrobe_desc = wardrobe_desc or char["appearance"].get("costume", "")
                    character_appearance = char["appearance"].get("description", "")
                if isinstance(char.get("visual_details"), dict):
                    wardrobe_desc = wardrobe_desc or char["visual_details"].get("wardrobe", "")

                # Also grab description for the prompt
                if not character_appearance:
                    character_appearance = (
                        char.get("description")
                        or char.get("visual_prompt")
                        or char.get("visual")
                        or ""
                    )
                break

    # Priority 3: Default archetype wardrobe from SceneAnchorSystem
    if not wardrobe_desc:
        try:
            from tools.scene_anchor_system import SceneAnchorSystem
            wardrobe_desc = SceneAnchorSystem.DEFAULT_WARDROBE.get("default", "period-appropriate attire")
        except Exception:
            wardrobe_desc = "period-appropriate attire, practical clothing"

    # Priority 4: UI-provided description override enriches appearance
    if ui_description and len(ui_description) > 20:
        character_appearance = ui_description

    # ── 4. Build the generation prompt ─────────────────────────────────
    prompt_parts = [
        f"Professional cinematic portrait of {character_name}",
    ]
    if actor_image_prompt:
        prompt_parts.append(actor_image_prompt)
    if character_appearance:
        prompt_parts.append(character_appearance)
    if wardrobe_desc:
        prompt_parts.append(f"wearing {wardrobe_desc}")
    prompt_parts.append(
        "single character, professional lighting, 16:9 cinematic frame, "
        "sharp focus, detailed face, high quality, "
        "NO grid, NO collage, NO split screen, NO extra people, "
        "NO morphing faces, NO watermarks, NO text overlays"
    )
    prompt = ", ".join(prompt_parts)

    logger.info(f"[REGEN-CHAR] Generating reference for {character_name} (actor: {actor_name})")
    logger.info(f"[REGEN-CHAR] Headshot URL: {headshot_url[:80] if headshot_url else 'NONE'}")
    logger.info(f"[REGEN-CHAR] Wardrobe: {wardrobe_desc[:80] if wardrobe_desc else 'NONE'}")
    logger.info(f"[REGEN-CHAR] Prompt length: {len(prompt)} chars")

    # ── 5. Generate with FAL ───────────────────────────────────────────
    try:
        tracker_id = f"char_{re.sub(r'[^a-zA-Z0-9_]', '_', char_upper)}"
        LIVE_GEN_TRACKER.add(
            project=project,
            shot_id=tracker_id,
            status="running",
            asset_type="character_reference",
            prompt=prompt,
            model=CHAR_REF_MODEL_EDIT if headshot_url else CHAR_REF_MODEL_T2I
        )

        used_nano_edit = False
        if headshot_url:
            # WITH actor headshot reference -> nano-banana-pro/edit
            fal_ready_refs = convert_refs_for_fal([headshot_url])
            result = fal_client.run(CHAR_REF_MODEL_EDIT, arguments={
                "prompt": prompt,
                "image_urls": fal_ready_refs,
                "aspect_ratio": "16:9",
                "output_format": "jpeg",
                "num_outputs": 1
            })
            used_nano_edit = True
            logger.info(f"[REGEN-CHAR] Used nano-banana-pro/edit with actor headshot reference")
        else:
            # NO reference available -> text-to-image fallback
            result = fal_client.run(CHAR_REF_MODEL_T2I, arguments={
                "prompt": prompt,
                "aspect_ratio": "16:9",
                "output_format": "jpeg",
                "num_images": 1
            })
            logger.info(f"[REGEN-CHAR] Used nano-banana-pro text-to-image (no headshot available)")

        # Extract image URL from FAL response
        image_url = None
        if result.get("images") and len(result["images"]) > 0:
            image_url = result["images"][0].get("url")
        elif result.get("image"):
            image_url = result["image"].get("url")

        if not image_url:
            LIVE_GEN_TRACKER.update(tracker_id, "error")
            return {"success": False, "error": "No image URL in FAL response"}

        # ── 6. Download and save to character_library_locked/{project}/ ─
        char_lib_dir = project_path / "character_library_locked"
        char_lib_dir.mkdir(parents=True, exist_ok=True)

        # V17.7.2: Always use cast_map key (full canonical name) for filename
        # This prevents short-name aliases (ARTHUR) creating duplicates alongside full names (ARTHUR_GRAY)
        canonical_name = (cast_key or character_name).upper().strip()
        safe_name = re.sub(r'[^a-zA-Z0-9_-]', '_', canonical_name)
        output_filename = f"{safe_name}_CHAR_REFERENCE.jpg"
        output_path = char_lib_dir / output_filename

        async with httpx.AsyncClient(timeout=60.0) as client:
            response = await client.get(image_url)
            if response.status_code != 200:
                LIVE_GEN_TRACKER.update(tracker_id, "error")
                return {"success": False, "error": f"Download failed: HTTP {response.status_code}"}
            with open(output_path, 'wb') as f:
                f.write(response.content)

        local_url = f"/api/media?path={str(output_path)}"
        LIVE_GEN_TRACKER.update(tracker_id, "completed", url=local_url)
        logger.info(f"[REGEN-CHAR] Saved reference: {output_path}")

        # ── 7. Update cast_map.json with new reference URL ─────────────
        try:
            # Re-read cast_map for safe concurrent access
            if cast_map_path.exists():
                with open(cast_map_path) as f:
                    cast_map_fresh = json.load(f)
            else:
                cast_map_fresh = cast_map

            if cast_key and cast_key in cast_map_fresh and isinstance(cast_map_fresh[cast_key], dict):
                cast_map_fresh[cast_key]["character_reference_url"] = local_url
                cast_map_fresh[cast_key]["character_reference_path"] = str(output_path)
                cast_map_fresh[cast_key]["_reference_generated_at"] = datetime.now().isoformat()

            with open(cast_map_path, "w") as f:
                json.dump(cast_map_fresh, f, indent=2)
            logger.info(f"[REGEN-CHAR] Updated cast_map.json for {cast_key}")
        except Exception as cm_err:
            logger.error(f"[REGEN-CHAR] Failed to update cast_map: {cm_err}")

        # ── 8. Update shot_plan.json for all shots with this character ─
        shots_updated = 0
        try:
            shot_plan_path = project_path / "shot_plan.json"
            if shot_plan_path.exists():
                with open(shot_plan_path) as f:
                    shot_plan_data = json.load(f)

                for shot in shot_plan_data.get("shots", []):
                    shot_chars = shot.get("characters", [])
                    char_names = [
                        (c.upper() if isinstance(c, str) else (c.get("name", "")).upper())
                        for c in shot_chars
                    ]
                    if any(char_upper in cn or cn in char_upper for cn in char_names if cn):
                        shot["character_reference_url"] = local_url
                        shots_updated += 1

                if shots_updated > 0:
                    shot_plan_data["_character_refs_updated"] = datetime.now().isoformat()
                    with open(shot_plan_path, "w") as f:
                        json.dump(shot_plan_data, f, indent=2)
                    logger.info(f"[REGEN-CHAR] Updated {shots_updated} shots in shot_plan.json")

                    # Invalidate UI cache
                    cache_dir = project_path / "ui_cache"
                    if cache_dir.exists():
                        dirty_flag = cache_dir / "bundle.dirty"
                        dirty_flag.touch()
        except Exception as sp_err:
            logger.error(f"[REGEN-CHAR] Failed to update shot_plan: {sp_err}")

        return {
            "success": True,
            "project": project,
            "character": character_name,
            "actor": actor_name,
            "wardrobe_hex": wardrobe_desc[:80] if wardrobe_desc else "",
            "used_nano_edit": used_nano_edit,
            "model": CHAR_REF_MODEL_EDIT if used_nano_edit else CHAR_REF_MODEL_T2I,
            "reference_path": str(output_path),
            "reference_url": local_url,
            "shots_updated": shots_updated,
            "prompt_preview": prompt[:150]
        }

    except Exception as e:
        tracker_id = f"char_{re.sub(r'[^a-zA-Z0-9_]', '_', char_upper)}"
        LIVE_GEN_TRACKER.update(tracker_id, "error")
        logger.error(f"[REGEN-CHAR] Error generating {character_name}: {e}")
        return {"success": False, "error": str(e), "character": character_name}


@app.post("/api/v6/generate-all-character-references")
async def generate_all_character_references(request: Dict = Body(...)):
    """
    Generate reference images for ALL cast characters in a project.

    Iterates through cast_map.json, and for each non-extras character
    calls the regenerate_character() logic to generate a styled reference
    image using the actor's headshot + character wardrobe.

    Body:
    {
        "project": "my_project",
        "regenerate": false,  // if true, regenerate even if reference exists
        "max_characters": 20  // optional limit
    }
    """
    project = request.get("project")
    regenerate = request.get("regenerate", False)
    max_characters = request.get("max_characters", 20)

    if not project:
        return {"success": False, "error": "Project name required"}

    project_path = get_project_path(project)
    if not project_path.exists():
        return {"success": False, "error": f"Project '{project}' not found"}

    # Load cast_map
    cast_map_path = project_path / "cast_map.json"
    if not cast_map_path.exists():
        return {"success": False, "error": "No cast_map.json found. Run auto-cast first."}

    try:
        with open(cast_map_path) as f:
            cast_map = json.load(f)
    except Exception as e:
        return {"success": False, "error": f"Failed to load cast_map: {e}"}

    # Collect characters to generate (skip metadata keys and extras pool)
    characters_to_gen = []
    char_lib_dir = project_path / "character_library_locked"

    for char_name, cast_info in cast_map.items():
        if char_name.startswith("_"):
            continue
        if not isinstance(cast_info, dict):
            continue
        if cast_info.get("is_extras_pool", False):
            continue
        if not cast_info.get("ai_actor"):
            continue

        # Check if reference already exists (skip unless regenerate=True)
        if not regenerate:
            safe_name = re.sub(r'[^a-zA-Z0-9_-]', '_', char_name.upper())
            existing_ref = char_lib_dir / f"{safe_name}_CHAR_REFERENCE.jpg"
            if existing_ref.exists():
                characters_to_gen.append({
                    "character": char_name,
                    "status": "exists",
                    "path": str(existing_ref)
                })
                continue

        characters_to_gen.append({
            "character": char_name,
            "actor": cast_info.get("ai_actor", ""),
            "status": "pending"
        })

    # Separate pending vs already-existing
    pending = [c for c in characters_to_gen if c["status"] == "pending"]
    existing = [c for c in characters_to_gen if c["status"] == "exists"]

    if not pending and not existing:
        return {"success": False, "error": "No castable characters found in cast_map"}

    if not pending:
        return {
            "success": True,
            "project": project,
            "message": f"All {len(existing)} character references already exist. Use regenerate=true to recreate.",
            "results": existing,
            "generated": 0,
            "skipped": len(existing),
            "errors": 0
        }

    logger.info(f"[GEN-ALL-CHARS] Generating {len(pending[:max_characters])} character references for {project}")

    results = []
    success_count = 0
    error_count = 0

    for char_info in pending[:max_characters]:
        char_name = char_info["character"]
        logger.info(f"[GEN-ALL-CHARS] Processing: {char_name}")

        # Call regenerate_character directly via internal async call
        try:
            regen_request = {
                "project": project,
                "character_name": char_name,
            }
            regen_result = await regenerate_character(regen_request)

            if regen_result.get("success"):
                success_count += 1
                results.append({
                    "character": char_name,
                    "status": "success",
                    "actor": regen_result.get("actor", ""),
                    "used_nano_edit": regen_result.get("used_nano_edit", False),
                    "reference_url": regen_result.get("reference_url", ""),
                    "shots_updated": regen_result.get("shots_updated", 0)
                })
            else:
                error_count += 1
                results.append({
                    "character": char_name,
                    "status": "error",
                    "error": regen_result.get("error", "Unknown error")
                })
        except Exception as e:
            error_count += 1
            results.append({
                "character": char_name,
                "status": "error",
                "error": str(e)
            })
            logger.error(f"[GEN-ALL-CHARS] Failed for {char_name}: {e}")

    # Add existing (skipped) entries
    results.extend(existing)

    logger.info(f"[GEN-ALL-CHARS] Complete: {success_count} generated, {len(existing)} skipped, {error_count} errors")

    return {
        "success": True,
        "project": project,
        "results": results,
        "generated": success_count,
        "skipped": len(existing),
        "errors": error_count,
        "total_characters": len(characters_to_gen)
    }


