@app.post("/api/v6/generate/characters")
async def generate_characters_v6(request: Dict = Body(...)):
    """
    Generate detailed character profiles from story bible using LLM.
    Creates visual prompts, personality traits, and casting recommendations.
    """
    import httpx

    project = request.get("project")
    if not project:
        return {"success": False, "error": "Project name required"}

    project_path = Path(f"pipeline_outputs/{project}")
    story_bible_path = project_path / "story_bible.json"

    # Load story bible
    if not story_bible_path.exists():
        return {"success": False, "error": f"Story bible not found for project: {project}"}

    with open(story_bible_path) as f:
        story_bible = json.load(f)

    existing_characters = story_bible.get("characters", [])
    genre = story_bible.get("genre", "drama")
    tone = story_bible.get("tone", "")
    title = story_bible.get("title", project)

    if not existing_characters:
        return {"success": False, "error": "No characters found in story bible"}

    # Load OpenRouter API key
    env_path = Path(str(BASE_DIR) + "/.env")
    api_key = ""
    if env_path.exists():
        with open(env_path) as f:
            for line in f:
                if line.startswith("OPENROUTER_API_KEY="):
                    api_key = line.split("=", 1)[1].strip()
                    break

    if not api_key:
        return {"success": False, "error": "OpenRouter API key not configured"}

    # Build character enhancement prompt
    char_summary = json.dumps(existing_characters, indent=2)

    user_prompt = f"""Enhance these characters for AI image generation and casting:

PROJECT: {title}
GENRE: {genre}
TONE: {tone}

EXISTING CHARACTERS:
{char_summary}

For EACH character, provide enhanced JSON with:
1. name - character name (preserve original)
2. role - protagonist/antagonist/supporting/minor
3. description - detailed physical description (age, build, hair, eyes, skin tone, distinguishing features)
4. arc - character development summary
5. visual_prompt - DETAILED image generation prompt (200+ chars) for AI headshot: specific facial features, expression, lighting, clothing, background, cinematic style
6. personality_traits - array of 3-5 personality traits
7. gender - male/female/other (EXPLICIT - required for casting)
8. age_range - specific range like "45-55" or "early 30s"
9. ethnicity - specific ethnicity for casting accuracy
10. casting_notes - what type of actor would suit this role

Return ONLY valid JSON array of enhanced characters."""

    try:
        async with httpx.AsyncClient(timeout=60.0) as client:
            response = await client.post(
                "https://openrouter.ai/api/v1/chat/completions",
                headers={
                    "Authorization": f"Bearer {api_key}",
                    "Content-Type": "application/json",
                    "HTTP-Referer": "https://atlas-control-system.local",
                    "X-Title": "ATLAS Character Generator"
                },
                json={
                    "model": "anthropic/claude-sonnet-4",
                    "messages": [
                        {"role": "system", "content": "You are a professional casting director and character designer. Generate detailed, production-ready character profiles optimized for AI image generation and actor casting. Always include explicit gender, age, and ethnicity for accurate casting."},
                        {"role": "user", "content": user_prompt}
                    ],
                    "temperature": 0.7,
                    "max_tokens": 4000
                }
            )

            if response.status_code != 200:
                logger.error(f"LLM API error: {response.status_code} - {response.text[:500]}")
                return {"success": False, "error": f"LLM API error: {response.status_code}"}

            result = response.json()
            content = result.get("choices", [{}])[0].get("message", {}).get("content", "")

            # Extract JSON from response
            json_match = re.search(r'\[[\s\S]*\]', content)
            if json_match:
                enhanced_chars = json.loads(json_match.group())
            else:
                # Try parsing entire content as JSON
                enhanced_chars = json.loads(content)

            # Update story bible with enhanced characters
            story_bible["characters"] = enhanced_chars
            with open(story_bible_path, "w") as f:
                json.dump(story_bible, f, indent=2)

            logger.info(f"[LLM] Enhanced {len(enhanced_chars)} characters for project: {project}")

            return {
                "success": True,
                "project": project,
                "characters": enhanced_chars,
                "count": len(enhanced_chars)
            }

    except json.JSONDecodeError as e:
        logger.error(f"Failed to parse LLM character response: {e}")
        return {"success": False, "error": f"Failed to parse LLM response: {str(e)}"}
    except Exception as e:
        logger.error(f"Character generation error: {e}")
        return {"success": False, "error": str(e)}

@app.post("/api/v6/generate/locations")
async def generate_locations_v6(request: Dict = Body(...)):
    """
    Generate detailed location profiles from story bible using LLM.
    Creates visual prompts, lighting guides, and atmosphere descriptions.
    """
    import httpx

    project = request.get("project")
    if not project:
        return {"success": False, "error": "Project name required"}

    project_path = Path(f"pipeline_outputs/{project}")
    story_bible_path = project_path / "story_bible.json"

    # Load story bible
    if not story_bible_path.exists():
        return {"success": False, "error": f"Story bible not found for project: {project}"}

    with open(story_bible_path) as f:
        story_bible = json.load(f)

    existing_locations = story_bible.get("locations", [])
    genre = story_bible.get("genre", "drama")
    tone = story_bible.get("tone", "")
    title = story_bible.get("title", project)
    color_palette = story_bible.get("color_palette", [])

    if not existing_locations:
        return {"success": False, "error": "No locations found in story bible"}

    # Load OpenRouter API key
    env_path = Path(str(BASE_DIR) + "/.env")
    api_key = ""
    if env_path.exists():
        with open(env_path) as f:
            for line in f:
                if line.startswith("OPENROUTER_API_KEY="):
                    api_key = line.split("=", 1)[1].strip()
                    break

    if not api_key:
        return {"success": False, "error": "OpenRouter API key not configured"}

    # Build location enhancement prompt - process in batches if needed
    palette_str = ", ".join(color_palette) if color_palette else "cinematic natural tones"

    # Process locations in batches of 5 to avoid LLM output limits
    all_enhanced_locs = []
    batch_size = 5

    try:
        for i in range(0, len(existing_locations), batch_size):
            batch = existing_locations[i:i + batch_size]
            loc_summary = json.dumps(batch, indent=2)

            user_prompt = f"""Enhance these locations for AI image generation. CRITICAL: Return ONLY valid JSON array, no markdown.

PROJECT: {title}
GENRE: {genre}
COLOR PALETTE: {palette_str}

LOCATIONS (batch {i // batch_size + 1}):
{loc_summary}

For each location return JSON object with these fields:
- name: preserve original name exactly
- description: brief physical description (50-100 chars)
- visual_prompt: AI image prompt (150-200 chars) with architectural style, materials, lighting, atmosphere
- lighting: key light setup and color temperature
- time_of_day: dawn/morning/midday/afternoon/golden_hour/dusk/night
- atmosphere: one-line mood description

Return ONLY a JSON array like: [{{"name": "...", "description": "...", ...}}]"""

            async with httpx.AsyncClient(timeout=90.0) as client:
                response = await client.post(
                    "https://openrouter.ai/api/v1/chat/completions",
                    headers={
                        "Authorization": f"Bearer {api_key}",
                        "Content-Type": "application/json",
                        "HTTP-Referer": "https://atlas-control-system.local",
                        "X-Title": "ATLAS Location Generator"
                    },
                    json={
                        "model": "anthropic/claude-sonnet-4",
                        "messages": [
                            {"role": "system", "content": "You are a production designer. Output ONLY valid JSON arrays. No markdown, no explanations."},
                            {"role": "user", "content": user_prompt}
                        ],
                        "temperature": 0.5,
                        "max_tokens": 3000
                    }
                )

                if response.status_code != 200:
                    logger.error(f"LLM API error: {response.status_code} - {response.text[:500]}")
                    all_enhanced_locs.extend(batch)  # Keep originals for failed batch
                    continue

                result = response.json()
                content = result.get("choices", [{}])[0].get("message", {}).get("content", "")

                # Extract JSON from response with robust parsing
                json_match = re.search(r'\[[\s\S]*\]', content)
                json_str = json_match.group() if json_match else content

                # Clean up common LLM JSON issues
                json_str = re.sub(r',\s*}', '}', json_str)
                json_str = re.sub(r',\s*\]', ']', json_str)
                json_str = re.sub(r'[\x00-\x1f\x7f-\x9f]', '', json_str)

                try:
                    batch_locs = json.loads(json_str)
                    all_enhanced_locs.extend(batch_locs)
                    logger.info(f"[LLM] Processed batch {i // batch_size + 1}: {len(batch_locs)} locations")
                except json.JSONDecodeError:
                    json_str = json_str.replace('\\n', ' ').replace('\\t', ' ')
                    json_str = re.sub(r'\\(?!["\\/bfnrt])', '', json_str)
                    try:
                        batch_locs = json.loads(json_str)
                        all_enhanced_locs.extend(batch_locs)
                    except json.JSONDecodeError as e:
                        logger.warning(f"Failed to parse batch {i // batch_size + 1}: {e}")
                        all_enhanced_locs.extend(batch)

        # Update story bible with enhanced locations
        if all_enhanced_locs:
            story_bible["locations"] = all_enhanced_locs
            with open(story_bible_path, "w") as f:
                json.dump(story_bible, f, indent=2)

            logger.info(f"[LLM] Enhanced {len(all_enhanced_locs)} locations for project: {project}")

            return {
                "success": True,
                "project": project,
                "locations": all_enhanced_locs,
                "count": len(all_enhanced_locs)
            }
        else:
            return {"success": False, "error": "No locations could be enhanced"}

    except Exception as e:
        logger.error(f"Location generation error: {e}")
        return {"success": False, "error": str(e)}

