@app.post("/api/v6/shot/variation/{project}/{shot_id}")
async def create_shot_variation(project: str, shot_id: str, request: Dict = Body(...)):
    """V16.7.1: Handle shot variations including duration/type changes with LTX sync."""
    action = request.get("action", "create_variation")
    project_path = get_project_path(project)
    shot_plan_path = project_path / "shot_plan.json"

    if not shot_plan_path.exists():
        return {"success": False, "error": "Shot plan not found"}

    with open(shot_plan_path) as f:
        data = json.load(f)

    # V27.1: Handle both list format [shots...] and dict format {"shots": [...]}
    if isinstance(data, list):
        shots = data
        data = {"shots": data}
    else:
        shots = data.get("shots", [])
    target_shot = None
    for shot in shots:
        if shot.get("shot_id") == shot_id:
            target_shot = shot
            break

    if not target_shot:
        return {"success": False, "error": f"Shot {shot_id} not found"}

    changes_made = []

    # Handle duration changes
    if action == "change_duration":
        new_duration = int(request.get("duration", 0))
        if new_duration > 0:
            target_shot["duration"] = new_duration
            target_shot["duration_seconds"] = new_duration
            changes_made.append(f"duration → {new_duration}s")
            # V16.7.1: CRITICAL - Sync LTX duration after any duration change
            if sync_ltx_duration(target_shot):
                changes_made.append("ltx_duration synced")

    # Handle shot type changes
    elif action == "change_type":
        new_type = request.get("shot_type", "")
        if new_type:
            target_shot["type"] = new_type
            target_shot["shot_type"] = new_type
            changes_made.append(f"type → {new_type}")

    # Handle camera angle changes
    elif action == "change_angle":
        new_angle = request.get("camera_angle", "")
        if new_angle:
            target_shot["camera_angle"] = new_angle
            changes_made.append(f"camera_angle → {new_angle}")

    # Save changes
    if changes_made:
        data["shots"] = shots
        data["_last_modified"] = datetime.now().isoformat()
        with open(shot_plan_path, "w") as f:
            json.dump(data, f, indent=2)

    return {
        "success": True,
        "project": project,
        "shot_id": shot_id,
        "action": action,
        "changes": changes_made
    }

@app.post("/api/v6/script/full-import")
async def full_script_import(request: Dict = Body(...)):
    """
    V17 FIX: Full script import with COMPREHENSIVE extraction.

    Extracts:
    - Scenes (INT/EXT headers)
    - Dialogue (character + lines)
    - ACTION LINES (was missing - the core visual content)
    - Transitions (CUT TO, DISSOLVE, FADE, SMASH CUT, etc.)
    - Parentheticals (acting direction)
    - B-roll cues (environmental descriptions between dialogue)
    - Opening/closing shots
    - Montage sequences
    - Time of day, weather, atmosphere cues

    Body:
    {
        "project": "ravencroft_v17",
        "script_text": "...",
        "title": "Ravencroft",
        "runtime_minutes": 45
    }
    """
    import httpx

    project = request.get("project")
    script_text = request.get("script_text", "")
    title = request.get("title", project or "untitled")
    runtime_minutes = request.get("runtime_minutes", 45)

    if not project:
        return {"success": False, "error": "project name required"}
    if not script_text or len(script_text.strip()) < 50:
        return {"success": False, "error": "script_text too short (min 50 chars)"}

    project_path = get_project_path(project)
    project_path.mkdir(parents=True, exist_ok=True)

    # Save raw script
    script_path = project_path / "raw_script.txt"
    with open(script_path, 'w') as f:
        f.write(script_text)

    # =========================================================================
    # V21.10: V6 HEADER DETECTION + STORY BIBLE INGEST
    # =========================================================================
    # If the script has a V6 header (everything above ---SCREENPLAY---),
    # parse it into structured data and auto-create story_bible.json.
    # This INGEST path preserves the author's original character descriptions,
    # scene cards, aliases, and casting stopwords — instead of having an LLM
    # reinvent them from scratch.
    _v6_ingested_bible = None
    _v6_header_data = None
    try:
        from tools.v6_header_parser import has_v6_header, parse_v6_header, build_story_bible_from_v6
        if has_v6_header(script_text):
            _v6_header_data = parse_v6_header(script_text)
            _v6_ingested_bible = build_story_bible_from_v6(_v6_header_data)

            # Use only the screenplay portion for regex parsing
            screenplay_text = _v6_header_data.get("screenplay_text", script_text)
            logger.info(
                f"[V6-INGEST] V6 header detected! Ingested: "
                f"{len(_v6_ingested_bible.get('characters', []))} characters, "
                f"{len(_v6_ingested_bible.get('scenes', []))} scene cards, "
                f"{len(_v6_ingested_bible.get('aliases', {}))} aliases, "
                f"{len(_v6_ingested_bible.get('casting_stopwords', []))} stopwords"
            )

            # Override runtime from V6 header if present
            if _v6_ingested_bible.get("runtime_target_minutes"):
                runtime_minutes = _v6_ingested_bible["runtime_target_minutes"]
                logger.info(f"[V6-INGEST] Runtime override from V6 header: {runtime_minutes} min")
        else:
            screenplay_text = script_text
            logger.info("[V6-INGEST] No V6 header detected — will use LLM generation for story bible")
    except Exception as _v6_err:
        screenplay_text = script_text
        logger.warning(f"[V6-INGEST] V6 header parsing failed (non-blocking): {_v6_err}")

    # Also save the screenplay-only portion for downstream tools
    screenplay_path = project_path / "imported_script.txt"
    with open(screenplay_path, 'w') as f:
        f.write(screenplay_text)

    # =========================================================================
    # PHASE 1: REGEX-BASED STRUCTURAL EXTRACTION (fast, no API calls)
    # =========================================================================
    import re

    lines = screenplay_text.split('\n')
    scenes = []
    current_scene = None
    current_character = None

    # Scene header pattern: INT. / EXT. / INT/EXT.
    scene_header_re = re.compile(r'^(INT\.|EXT\.|INT/EXT\.|I/E\.)\s*(.+?)(?:\s*[-–—]\s*(.+?))?$', re.IGNORECASE)
    # Character name: ALL CAPS on its own line (with optional (V.O.), (O.S.), (CONT'D))
    character_re = re.compile(r'^([A-Z][A-Z\s\.\-\']+?)(?:\s*\((?:V\.O\.|O\.S\.|CONT\'D|O\.C\.|CONT|VO)\))?$')
    # Parenthetical: (beat), (whispering), etc.
    parenthetical_re = re.compile(r'^\s*\((.+?)\)\s*$')
    # Transition: CUT TO:, DISSOLVE TO:, FADE IN, FADE OUT, SMASH CUT, etc.
    transition_re = re.compile(r'^(CUT TO|DISSOLVE TO|FADE IN|FADE OUT|FADE TO|SMASH CUT|MATCH CUT|JUMP CUT|WIPE TO|TIME CUT)[\s:]*(.*)$', re.IGNORECASE)
    # Montage header
    montage_re = re.compile(r'^(MONTAGE|SERIES OF SHOTS|FLASHBACK|DREAM SEQUENCE|BEGIN MONTAGE|END MONTAGE)', re.IGNORECASE)

    all_characters = set()
    all_locations = set()
    all_transitions = []
    all_montages = []
    scene_count = 0

    # INTERCUT detection pattern
    intercut_re = re.compile(r'^INTERCUT\s*(WITH)?[\s:.\-]*$', re.IGNORECASE)
    is_intercut = False
    intercut_primary_loc = None
    intercut_char_location_map = {}  # character -> location they were introduced in

    for i, line in enumerate(lines):
        stripped = line.strip()
        if not stripped:
            # V21.10 FIX: Blank line ends dialogue attribution.
            # In screenplay format, a blank line ALWAYS terminates a dialogue block.
            # Without this reset, action lines after dialogue get mis-attributed
            # as the previous character's speech (e.g., "She opens the journal"
            # captured as CHILD's dialogue).
            current_character = None
            continue

        # Strip markdown formatting that can wrap scene headers (e.g. **INT. OFFICE - DAY**)
        stripped_clean = re.sub(r'\*{1,3}', '', stripped).strip()
        stripped_clean = re.sub(r'_{1,2}', '', stripped_clean).strip()

        # Check for INTERCUT line (must come BEFORE scene header check)
        if current_scene and intercut_re.match(stripped_clean):
            is_intercut = True
            intercut_primary_loc = current_scene["location"]
            current_scene["is_intercut"] = True
            current_scene["intercut_locations"] = [intercut_primary_loc]
            current_scene["intercut_location_map"] = intercut_char_location_map
            # Map characters already seen in this scene to the primary location
            for ch in current_scene["characters_present"]:
                intercut_char_location_map[ch] = intercut_primary_loc
            continue

        # Check for scene header (use stripped_clean to handle markdown-wrapped headers)
        scene_match = scene_header_re.match(stripped_clean)
        if scene_match:
            new_location = scene_match.group(2).strip()
            new_time = scene_match.group(3).strip() if scene_match.group(3) else "DAY"
            all_locations.add(new_location)

            # If we're inside an INTERCUT, store secondary location on current scene
            # V21.9 FIX: Only consume ONE secondary location per INTERCUT marker,
            # then reset so subsequent scenes create normally (was never resetting,
            # causing all remaining scenes to be treated as intercut secondary locations)
            if is_intercut and current_scene:
                # =============================================================
                # V21.10 INTERCUT MERGE: If the INTERCUT's secondary location
                # matches the PREVIOUS scene's location, they are ONE dramatic
                # scene. Example:
                #   INT. CITY APARTMENT   ← Scene 2 (Evelyn answers phone)
                #   CUT TO:
                #   INT. LAW OFFICE       ← Scene 3 (parser created new scene)
                #   INTERCUT WITH:
                #   INT. CITY APARTMENT   ← secondary = Scene 2's location!
                #
                # This means Scene 2 was setup for the INTERCUT conversation.
                # Merge Scene 2 back into this scene as one continuous intercut.
                # =============================================================
                _norm_new_loc = re.sub(r'\s*\(.*?\)', '', new_location).strip().upper()
                if scenes:
                    _prev_scene = scenes[-1]
                    _norm_prev_loc = re.sub(r'\s*\(.*?\)', '', _prev_scene.get("location", "")).strip().upper()
                    if _norm_new_loc == _norm_prev_loc:
                        # MERGE: absorb previous scene into current intercut scene
                        logger.info(
                            f"[PARSER V21.10] INTERCUT MERGE: Scene {_prev_scene['scene_id']} "
                            f"({_prev_scene['location']}) merged into Scene {current_scene['scene_id']} "
                            f"({current_scene['location']}) — same location as intercut secondary"
                        )
                        # Absorb dialogue, action lines, characters from previous scene
                        current_scene["dialogue"] = _prev_scene.get("dialogue", []) + current_scene.get("dialogue", [])
                        current_scene["action_lines"] = _prev_scene.get("action_lines", []) + current_scene.get("action_lines", [])
                        current_scene["characters_present"].update(_prev_scene.get("characters_present", set()) if isinstance(_prev_scene.get("characters_present"), set) else set(_prev_scene.get("characters_present", [])))
                        current_scene["raw_lines"] = _prev_scene.get("raw_lines", []) + current_scene.get("raw_lines", [])
                        current_scene["transitions"] = _prev_scene.get("transitions", []) + current_scene.get("transitions", [])
                        current_scene["parentheticals"] = _prev_scene.get("parentheticals", []) + current_scene.get("parentheticals", [])
                        current_scene["broll_cues"] = _prev_scene.get("broll_cues", []) + current_scene.get("broll_cues", [])
                        current_scene["mood_cues"] = _prev_scene.get("mood_cues", []) + current_scene.get("mood_cues", [])
                        # Use the EARLIER scene's ID (it came first in the screenplay)
                        current_scene["scene_id"] = _prev_scene["scene_id"]
                        # Remove the previous scene from the list (it's now merged)
                        scenes.pop()
                        scene_count -= 1
                        # Map previous scene's characters to the secondary location
                        for _pc in (_prev_scene.get("characters_present", set()) if isinstance(_prev_scene.get("characters_present"), set) else set(_prev_scene.get("characters_present", []))):
                            intercut_char_location_map[_pc] = new_location

                current_scene["secondary_location"] = new_location
                if "intercut_locations" not in current_scene:
                    current_scene["intercut_locations"] = [current_scene["location"]]
                if new_location not in current_scene["intercut_locations"]:
                    current_scene["intercut_locations"].append(new_location)
                current_scene["_intercut_current_loc"] = new_location
                current_scene["_intercut"] = True
                current_scene["_intercut_active"] = True  # V21.10: stays True for char-loc mapping
                current_character = None
                # V21.9: Reset is_intercut so NEXT scene heading creates new scene
                # V21.10: But keep _intercut_active on the scene object so character
                # names appearing in subsequent dialogue lines still get mapped to
                # the correct location (primary vs secondary).
                is_intercut = False
                continue

            # Normal scene: finalize the previous scene and start a new one
            if current_scene:
                scenes.append(current_scene)
            # Reset intercut state when starting a truly new scene
            is_intercut = False
            intercut_primary_loc = None
            intercut_char_location_map = {}

            scene_count += 1
            int_ext = scene_match.group(1).upper().replace('.', '')

            # V21.10: Detect slash-format INTERCUT headers
            # e.g., "INT. EVELYN'S CAR (MOVING) / LAWYER'S OFFICE - DAY"
            # This is ONE scene with two locations, not two scenes.
            _slash_intercut = False
            _slash_loc_a = new_location
            _slash_loc_b = None
            if ' / ' in new_location:
                _slash_parts = re.split(r'\s*/\s*', new_location, maxsplit=1)
                if len(_slash_parts) == 2:
                    _slash_loc_a = _slash_parts[0].strip()
                    _slash_loc_b = _slash_parts[1].strip()
                    _slash_intercut = True
                    logger.info(f"[PARSER V21.10] Slash-format INTERCUT detected: '{_slash_loc_a}' / '{_slash_loc_b}'")

            current_scene = {
                "scene_id": f"{scene_count:03d}",
                "int_ext": int_ext,
                "location": _slash_loc_a if _slash_intercut else new_location,
                "time_of_day": new_time,
                "dialogue": [],
                "action_lines": [],
                "transitions": [],
                "parentheticals": [],
                "broll_cues": [],
                "characters_present": set(),
                "mood_cues": [],
                "raw_lines": []
            }

            # If slash-format INTERCUT, mark scene immediately
            if _slash_intercut:
                current_scene["is_intercut"] = True
                current_scene["_intercut"] = True
                current_scene["_intercut_active"] = True
                current_scene["secondary_location"] = _slash_loc_b
                current_scene["intercut_locations"] = [_slash_loc_a, _slash_loc_b]
                current_scene["location"] = f"{_slash_loc_a} / {_slash_loc_b}"

            current_character = None
            continue

        if not current_scene:
            continue

        current_scene["raw_lines"].append(stripped)

        # Check for transition
        trans_match = transition_re.match(stripped)
        if trans_match:
            transition = {"type": trans_match.group(1).upper(), "detail": trans_match.group(2).strip(), "line": i}
            current_scene["transitions"].append(transition)
            all_transitions.append(transition)
            current_character = None
            continue

        # Check for montage
        montage_match = montage_re.match(stripped)
        if montage_match:
            all_montages.append({"type": montage_match.group(1), "scene_id": current_scene["scene_id"], "line": i})
            current_scene["broll_cues"].append({"type": "montage", "text": stripped})
            continue

        # Check for character name
        char_match = character_re.match(stripped)
        if char_match and len(stripped) < 40 and stripped == stripped.upper():
            char_name = char_match.group(1).strip()
            # Filter out common false positives + V6 casting stopwords
            false_positives = {"THE", "AND", "BUT", "CUT", "INT", "EXT", "FADE", "CONTINUED", "CONT", "MORE", "END", "INTERCUT"}
            # V21.10: Merge V6 casting stopwords if available
            if _v6_header_data and _v6_header_data.get("stopwords"):
                false_positives.update(w.upper() for w in _v6_header_data["stopwords"])
            if char_name not in false_positives and len(char_name) > 1:
                current_character = char_name
                all_characters.add(char_name)
                current_scene["characters_present"].add(char_name)
                # Track character-to-location mapping for INTERCUT scenes
                # V21.10 FIX: Check BOTH global is_intercut AND scene-level _intercut_active
                # because is_intercut gets reset after consuming secondary location header,
                # but character dialogue continues within the intercut scene.
                _scene_intercut = is_intercut or current_scene.get("_intercut_active", False)
                if _scene_intercut and current_scene.get("_intercut_current_loc"):
                    intercut_char_location_map[char_name] = current_scene["_intercut_current_loc"]
                elif _scene_intercut and intercut_primary_loc:
                    intercut_char_location_map.setdefault(char_name, intercut_primary_loc)
                elif _scene_intercut and current_scene.get("is_intercut"):
                    # Fallback: first speaker maps to primary location
                    intercut_char_location_map.setdefault(char_name, current_scene.get("location", ""))
                continue

        # Check for parenthetical
        paren_match = parenthetical_re.match(stripped)
        if paren_match and current_character:
            current_scene["parentheticals"].append({
                "character": current_character,
                "direction": paren_match.group(1),
                "line": i
            })
            continue

        # If we have a current character, this line is dialogue
        if current_character and not stripped.startswith('('):
            current_scene["dialogue"].append({
                "character": current_character,
                "text": stripped,
                "line": i
            })
            # After dialogue line, character stays active until blank line or new character
            continue

        # *** THIS IS THE KEY FIX ***
        # Everything else is an ACTION LINE — the visual description
        # These are the B-roll cues, establishing visuals, atmosphere, and blocking
        if stripped and not stripped.startswith('('):
            current_character = None  # Reset character after action line

            # Classify the action line
            action_type = "action"
            stripped_lower = stripped.lower()

            # Detect atmosphere/mood cues
            atmosphere_words = ["rain", "wind", "snow", "fog", "mist", "storm", "thunder",
                              "lightning", "moonlight", "candlelight", "firelight", "torch",
                              "dawn", "dusk", "sunset", "sunrise", "twilight", "darkness",
                              "shadow", "silence", "quiet", "eerie", "cold", "warm"]
            is_atmosphere = any(w in stripped_lower for w in atmosphere_words)

            # Detect visual B-roll cues
            broll_words = ["we see", "camera", "angle on", "close on", "wide on",
                         "reveal", "pan", "track", "dolly", "crane", "aerial",
                         "close-up", "insert", "detail", "POV", "subjective"]
            is_broll = any(w in stripped_lower for w in broll_words)

            # Detect opening/closing image cues
            opening_words = ["fade in", "open on", "we open", "black screen", "title card"]
            is_opening = any(w in stripped_lower for w in opening_words) and i < 30

            if is_atmosphere:
                action_type = "atmosphere"
                current_scene["mood_cues"].append(stripped)
            if is_broll:
                action_type = "broll_direction"
                current_scene["broll_cues"].append({"type": "direction", "text": stripped})
            if is_opening:
                action_type = "opening_image"

            current_scene["action_lines"].append({
                "text": stripped,
                "type": action_type,
                "line": i,
                "is_atmosphere": is_atmosphere,
                "is_broll": is_broll
            })

            # V21.9: Extract characters mentioned in ACTION LINES
            # Screenplays reference characters by name in action descriptions
            # e.g. "Evelyn sits by the window" — Evelyn should be in characters_present
            # We check against ALL characters already discovered in this script
            # AND a known character list from common screenplay conventions
            for _known_char in list(all_characters):
                # Check if character name appears as a word boundary in the action line
                # Use case-insensitive match for first name or full name
                _kc_parts = _known_char.split()
                for _kc_part in _kc_parts:
                    if len(_kc_part) > 2 and re.search(r'\b' + re.escape(_kc_part) + r'\b', stripped, re.IGNORECASE):
                        current_scene["characters_present"].add(_known_char)
                        break

    # Don't forget the last scene
    if current_scene:
        # Finalize intercut location map if this was an intercut scene
        if is_intercut and intercut_char_location_map:
            current_scene["intercut_location_map"] = dict(intercut_char_location_map)
        scenes.append(current_scene)

    # Clean up internal intercut tracking fields and convert sets to lists for JSON serialization
    for scene in scenes:
        scene["characters_present"] = list(scene["characters_present"])
        # Remove internal tracking field, keep the public intercut fields
        scene.pop("_intercut_current_loc", None)

    # =========================================================================
    # PHASE 1B: CHARACTER NAME NORMALIZATION (V21.10 — fixes duplicate casting)
    # =========================================================================
    # Problem: Script uses short names (CLARA, MARGARET, LAWYER) but cast_map
    # needs canonical names (CLARA BYRNE, LADY MARGARET RAVENCROFT, THE LAWYER).
    # If not normalized at import, auto-cast creates duplicate entries.
    #
    # Strategy:
    # 1. V6 header aliases (if present) are the primary source of truth
    # 2. Fallback: detect short names that are substrings of longer names
    # 3. Apply normalization to all_characters, scene.characters_present,
    #    scene.dialogue entries, and scene.intercut_location_map keys

    _import_name_norm = {}  # short_name -> canonical_name

    # Source 1: V6 header aliases (highest priority)
    # V6 parser returns {primary: [list_of_aliases]} — primary is short name,
    # list contains canonical forms. We need to map short→canonical (longest form).
    if _v6_header_data and _v6_header_data.get("aliases"):
        for alias, canonical in _v6_header_data["aliases"].items():
            _clean_alias = alias.lstrip("- ").upper().strip()
            if isinstance(canonical, list):
                # Parser returns list — use last (longest/most canonical) entry
                for c in canonical:
                    _import_name_norm[_clean_alias] = c.upper().strip()
            else:
                _import_name_norm[_clean_alias] = canonical.upper().strip()

    # Source 2: V6 ingested bible aliases
    if _v6_ingested_bible and _v6_ingested_bible.get("aliases"):
        for alias, canonical in _v6_ingested_bible["aliases"].items():
            _clean_alias = alias.lstrip("- ").upper().strip()
            if isinstance(canonical, list):
                for c in canonical:
                    _import_name_norm.setdefault(_clean_alias, c.upper().strip())
            else:
                _import_name_norm.setdefault(_clean_alias, canonical.upper().strip())

    # Source 3: Detect short→long name pairs within extracted characters
    # e.g., if both "CLARA" and "CLARA BYRNE" appear, normalize "CLARA" → "CLARA BYRNE"
    _sorted_chars = sorted(all_characters, key=lambda x: len(x), reverse=True)
    for i, long_name in enumerate(_sorted_chars):
        for short_name in _sorted_chars[i+1:]:
            if short_name == long_name:
                continue
            # Short name is a word-boundary prefix of long name
            if long_name.startswith(short_name + " ") or long_name.endswith(" " + short_name):
                _import_name_norm.setdefault(short_name, long_name)
            # Article-prefixed: "LAWYER" → "THE LAWYER"
            for prefix in ("THE ", "A ", "AN "):
                if long_name == prefix + short_name:
                    _import_name_norm.setdefault(short_name, long_name)

    if _import_name_norm:
        logger.info(f"[IMPORT-NORM] Character normalization map: {_import_name_norm}")

        # Apply normalization to all_characters set
        _new_all_characters = set()
        for ch in all_characters:
            _new_all_characters.add(_import_name_norm.get(ch, ch))
        all_characters = _new_all_characters

        # Apply to each scene's characters_present list
        for scene in scenes:
            scene["characters_present"] = list(set(
                _import_name_norm.get(ch, ch) for ch in scene["characters_present"]
            ))

            # Apply to dialogue entries
            for dial in scene.get("dialogue", []):
                dial["character"] = _import_name_norm.get(dial["character"], dial["character"])

            # Apply to intercut_location_map keys
            if scene.get("intercut_location_map"):
                scene["intercut_location_map"] = {
                    _import_name_norm.get(k, k): v
                    for k, v in scene["intercut_location_map"].items()
                }

    # Store normalization map in shot_plan metadata for downstream use
    _import_alias_map = _import_name_norm

    # =========================================================================
    # PHASE 2: LLM-POWERED CINEMATIC EXPANSION
    # =========================================================================
    env_path = Path(str(BASE_DIR) + "/.env")
    api_key = ""
    if env_path.exists():
        with open(env_path) as f:
            for line_text in f:
                if line_text.startswith("OPENROUTER_API_KEY="):
                    api_key = line_text.split("=", 1)[1].strip()
                    break

    cinematic_expansion = None
    if api_key and len(scenes) > 0:
        # Build a concise scene summary for the LLM
        scene_summaries = []
        for sc in scenes[:20]:  # Cap at 20 scenes for token budget
            # V17.2.4: Increased dialogue preview to 200 chars (was 50) for LLM cinematic context
            action_preview = " | ".join([a["text"][:150] for a in sc["action_lines"][:5]])
            dial_preview = " | ".join([f"{d['character']}: {d['text'][:200]}" for d in sc["dialogue"][:5]])
            scene_summaries.append(
                f"Scene {sc['scene_id']}: {sc['int_ext']} {sc['location']} - {sc['time_of_day']}\n"
                f"  Action: {action_preview or '(none)'}\n"
                f"  Dialogue: {dial_preview or '(none)'}\n"
                f"  Characters: {', '.join(sc['characters_present'])}\n"
                f"  Transitions: {', '.join([t['type'] for t in sc['transitions']]) or 'none'}"
            )

        llm_prompt = f"""You are a film director analyzing a script for visual production.

TITLE: {title}
TARGET RUNTIME: {runtime_minutes} minutes
TOTAL SCENES: {len(scenes)}

SCENES:
{chr(10).join(scene_summaries)}

For each scene, provide cinematic direction as JSON. Include:
1. "opening_shot": How the scene should open visually (wide establishing, close detail, etc.)
2. "broll_shots": Array of 1-3 B-roll/insert/cutaway shots that should exist in this scene
3. "atmosphere": Lighting, color temperature, mood descriptor
4. "pacing": "slow"/"medium"/"fast" — the editing rhythm
5. "key_moment": The single most important visual beat
6. "closing_shot": How the scene should end visually
7. "transition_to_next": Suggested transition type

Return JSON array of objects, one per scene. Return ONLY valid JSON."""

        try:
            async with httpx.AsyncClient(timeout=60.0) as client:
                response = await client.post(
                    "https://openrouter.ai/api/v1/chat/completions",
                    headers={
                        "Authorization": f"Bearer {api_key}",
                        "Content-Type": "application/json"
                    },
                    json={
                        "model": "anthropic/claude-sonnet-4",
                        "messages": [
                            {"role": "system", "content": "You are a cinematographer and film director. Analyze scripts for visual storytelling. Return ONLY valid JSON."},
                            {"role": "user", "content": llm_prompt}
                        ],
                        "temperature": 0.6,
                        "max_tokens": 4000
                    }
                )
                if response.status_code == 200:
                    content = response.json().get("choices", [{}])[0].get("message", {}).get("content", "")
                    json_match = re.search(r'\[[\s\S]*\]', content)
                    if json_match:
                        cinematic_expansion = json.loads(json_match.group())
                        logger.info(f"[SCRIPT PARSER] LLM cinematic expansion: {len(cinematic_expansion)} scenes analyzed")
        except Exception as e:
            logger.warning(f"[SCRIPT PARSER] LLM expansion failed: {e}")

    # =========================================================================
    # PHASE 3: MERGE & BUILD SHOT PLAN
    # =========================================================================

    # Merge LLM expansion back into scenes
    if cinematic_expansion:
        for i, scene in enumerate(scenes):
            if i < len(cinematic_expansion):
                expansion = cinematic_expansion[i]
                scene["cinematic"] = {
                    "opening_shot": expansion.get("opening_shot", ""),
                    "broll_shots": expansion.get("broll_shots", []),
                    "atmosphere": expansion.get("atmosphere", ""),
                    "pacing": expansion.get("pacing", "medium"),
                    "key_moment": expansion.get("key_moment", ""),
                    "closing_shot": expansion.get("closing_shot", ""),
                    "transition_to_next": expansion.get("transition_to_next", "CUT TO")
                }

    # Build shots from scenes (including B-roll, establishing, inserts)
    all_shots = []
    shot_counter = 0

    for scene in scenes:
        scene_id = scene["scene_id"]
        location = scene["location"]
        time_of_day = scene["time_of_day"]
        int_ext = scene["int_ext"]
        cinematic = scene.get("cinematic", {})
        chars = scene["characters_present"]
        scene_is_intercut = scene.get("is_intercut", False)
        scene_intercut_loc_map = scene.get("intercut_location_map", {})

        # --- ESTABLISHING SHOT (if scene has cinematic opening) ---
        shot_counter += 1
        opening_desc = cinematic.get("opening_shot", f"Establishing shot of {location}")
        atmosphere = cinematic.get("atmosphere", f"{time_of_day.lower()} lighting")

        all_shots.append({
            "shot_id": f"{scene_id}_{shot_counter:03d}A",
            "scene_id": scene_id,
            "type": "wide",
            "shot_type": "establishing",
            "coverage_angle": "A",
            "location": location,
            "characters": [],
            "duration": 8,
            "duration_seconds": 8,
            "nano_prompt": f"{int_ext} {location} - {time_of_day}. {opening_desc}. {atmosphere}. Cinematic wide, no characters in frame yet.",
            "ltx_motion_prompt": f"Slow atmospheric camera move, {atmosphere}, 8s, establishing mood",
            "is_establishing": True,
            "is_broll": False
        })

        # --- B-ROLL SHOTS (from script action lines + LLM expansion) ---
        broll_shots = cinematic.get("broll_shots", [])
        # Also pull from parsed action lines
        for action in scene.get("action_lines", []):
            if action.get("is_atmosphere") or action.get("is_broll"):
                broll_shots.append(action["text"])

        for bi, broll_desc in enumerate(broll_shots[:3]):  # Cap at 3 B-roll per scene
            broll_text = broll_desc if isinstance(broll_desc, str) else broll_desc.get("description", str(broll_desc))
            shot_counter += 1
            all_shots.append({
                "shot_id": f"{scene_id}_{shot_counter:03d}B",
                "scene_id": scene_id,
                "type": "insert",
                "shot_type": "b-roll",
                "coverage_angle": "B",
                "location": location,
                "characters": [],
                "duration": 5,
                "duration_seconds": 5,
                "nano_prompt": f"Detail/insert shot: {broll_text}. {atmosphere}. No faces, environmental texture.",
                "ltx_motion_prompt": f"Subtle movement, {broll_text[:150]}, atmospheric detail, 5s",
                "is_establishing": False,
                "is_broll": True
            })

        # --- DIALOGUE & ACTION SHOTS (the core scene content) ---
        # Group action lines and dialogue into beats
        scene_beats = []

        # Combine action lines and dialogue in order
        action_idx = 0
        dialog_idx = 0
        for raw_line in scene.get("raw_lines", []):
            # Try to match against action or dialogue
            if action_idx < len(scene["action_lines"]) and scene["action_lines"][action_idx]["text"] == raw_line:
                action = scene["action_lines"][action_idx]
                if not action.get("is_broll") and not action.get("is_atmosphere"):
                    scene_beats.append({"type": "action", "text": action["text"], "characters": chars})
                action_idx += 1
            elif dialog_idx < len(scene["dialogue"]) and scene["dialogue"][dialog_idx]["text"] == raw_line:
                dialog = scene["dialogue"][dialog_idx]
                scene_beats.append({"type": "dialogue", "character": dialog["character"], "text": dialog["text"]})
                dialog_idx += 1

        # Convert beats to shots (group 2-3 beats per shot)
        beat_groups = []
        current_group = []
        for beat in scene_beats:
            current_group.append(beat)
            if len(current_group) >= 3:
                beat_groups.append(current_group)
                current_group = []
        if current_group:
            beat_groups.append(current_group)

        for gi, group in enumerate(beat_groups):
            shot_counter += 1
            # Determine shot type based on content
            has_dialogue = any(b["type"] == "dialogue" for b in group)
            beat_chars = set()
            for b in group:
                if b.get("character"):
                    beat_chars.add(b["character"])
                elif b.get("characters"):
                    beat_chars.update(b["characters"])

            beat_text = " ".join([b["text"] for b in group])

            if has_dialogue and len(beat_chars) > 1:
                shot_type = "medium"  # Two-shot for multi-character dialogue
                coverage = "B"
            elif has_dialogue:
                shot_type = "medium_close"  # MCU for single character dialogue
                coverage = "B"
            else:
                shot_type = "medium"  # Default for action
                coverage = "A"

            # Build prompt from beats — V17.2.4: preserve FULL dialogue (invariant #7)
            prompt_parts = []
            dialogue_full = []  # Store full dialogue for shot metadata
            for b in group:
                if b["type"] == "dialogue":
                    full_line = f"{b['character']} speaks: \"{b['text']}\""
                    prompt_parts.append(full_line[:200])  # Allow up to 200 chars per dialogue beat in prompt
                    dialogue_full.append(f"{b['character']}: {b['text']}")
                else:
                    prompt_parts.append(b["text"][:150])  # Allow up to 150 chars for action lines

            prompt_text = ". ".join(prompt_parts)
            char_list = list(beat_chars) if beat_chars else chars

            # V17.2.4: Build dialogue-aware LTX motion prompt preserving full text
            dialogue_text_full = " | ".join(dialogue_full) if dialogue_full else ""
            if has_dialogue:
                ltx_prompt = f"Subtle performance, lip sync, {shot_type}, face identity locked, natural body movement, {15}s"
                if dialogue_text_full:
                    ltx_prompt += f", dialogue context: {dialogue_text_full[:300]}"
            else:
                ltx_prompt = f"Blocking action, {shot_type}, face identity locked, natural body movement, {10}s"

            # Resolve location for INTERCUT scenes based on character-location map
            shot_location = location
            if scene_is_intercut and scene_intercut_loc_map and beat_chars:
                # Use the location of the first character in this beat group
                for bc in beat_chars:
                    if bc in scene_intercut_loc_map:
                        shot_location = scene_intercut_loc_map[bc]
                        break

            shot_data = {
                "shot_id": f"{scene_id}_{shot_counter:03d}{coverage}",
                "scene_id": scene_id,
                "type": shot_type,
                "shot_type": shot_type,
                "coverage_angle": coverage,
                "location": shot_location,
                "characters": char_list[:3],
                "duration": 15 if has_dialogue else 10,
                "duration_seconds": 15 if has_dialogue else 10,
                "nano_prompt": f"{shot_type.replace('_', ' ').title()} shot. {prompt_text}. {atmosphere}.",
                "ltx_motion_prompt": ltx_prompt,
                "is_establishing": False,
                "is_broll": False,
                "dialogue_text": dialogue_text_full,  # V17.2.4: Full dialogue preserved
                "dialogue_beats": [b for b in group if b["type"] == "dialogue"],
                "action_beats": [b for b in group if b["type"] == "action"]
            }
            # Tag intercut shots with their resolved location info
            if scene_is_intercut:
                shot_data["is_intercut"] = True
                shot_data["intercut_location"] = shot_location
            all_shots.append(shot_data)

        # --- REACTION SHOT (if multi-character scene) ---
        if len(chars) > 1:
            shot_counter += 1
            reactor = chars[1] if len(chars) > 1 else chars[0]
            key_moment = cinematic.get("key_moment", "the scene's emotional peak")
            all_shots.append({
                "shot_id": f"{scene_id}_{shot_counter:03d}C",
                "scene_id": scene_id,
                "type": "close",
                "shot_type": "reaction",
                "coverage_angle": "C",
                "location": location,
                "characters": [reactor],
                "duration": 6,
                "duration_seconds": 6,
                "nano_prompt": f"Close-up reaction shot of {reactor}. Responding to {key_moment}. {atmosphere}. Emotional, off-axis camera angle.",
                "ltx_motion_prompt": f"Subtle facial reaction: eyes shift, brow furrows slightly, breath draws in, natural breathing rhythm visible. FACE IDENTITY LOCK: features unchanged. 6s",
                "is_establishing": False,
                "is_broll": False
            })

        # --- CLOSING SHOT (if cinematic data provides one) ---
        closing = cinematic.get("closing_shot")
        if closing:
            shot_counter += 1
            all_shots.append({
                "shot_id": f"{scene_id}_{shot_counter:03d}A",
                "scene_id": scene_id,
                "type": "wide",
                "shot_type": "closing",
                "coverage_angle": "A",
                "location": location,
                "characters": [],
                "duration": 6,
                "duration_seconds": 6,
                "nano_prompt": f"{closing}. {atmosphere}. Cinematic composition.",
                "ltx_motion_prompt": f"Slow pull back or static hold, atmospheric, 6s",
                "is_establishing": False,
                "is_broll": True
            })

    # =========================================================================
    # PHASE 4: SAVE EVERYTHING
    # =========================================================================

    # Build scene manifest
    scene_manifest = []
    for scene in scenes:
        scene_shots = [s for s in all_shots if s.get("scene_id") == scene["scene_id"]]
        manifest_entry = {
            "scene_id": scene["scene_id"],
            "int_ext": scene["int_ext"],
            "location": scene["location"],
            "time_of_day": scene["time_of_day"],
            "characters": scene["characters_present"],
            "dialogue_count": len(scene["dialogue"]),
            "action_line_count": len(scene["action_lines"]),
            "broll_cue_count": len(scene["broll_cues"]),
            "transition_count": len(scene["transitions"]),
            "mood_cues": scene.get("mood_cues", []),
            "shot_count": len(scene_shots),
            "shots": scene_shots,
            "cinematic": scene.get("cinematic", {}),
            "is_intercut": scene.get("is_intercut", False),
            "secondary_location": scene.get("secondary_location"),
            "intercut_locations": scene.get("intercut_locations", []),
            "intercut_location_map": scene.get("intercut_location_map", {})
        }
        scene_manifest.append(manifest_entry)

    # Save shot plan
    shot_plan = {
        "title": title,
        "project": project,
        "runtime_target_seconds": runtime_minutes * 60,
        "runtime_target_minutes": runtime_minutes,
        "total_shots": len(all_shots),
        "total_scenes": len(scenes),
        "shots": all_shots,
        "scene_manifest": scene_manifest,
        "_parsed_at": datetime.now().isoformat(),
        "_parser_version": "V21.10_FULL_EXTRACTION",
        "_v6_header_ingested": _v6_ingested_bible is not None,
        "_aliases": _v6_ingested_bible.get("aliases", {}) if _v6_ingested_bible else {},
        "_import_name_normalization": _import_alias_map,  # V21.10: short→canonical map applied at import
        "_casting_stopwords": _v6_ingested_bible.get("casting_stopwords", []) if _v6_ingested_bible else [],
        "_extraction_stats": {
            "total_characters": len(all_characters),
            "total_locations": len(all_locations),
            "total_transitions": len(all_transitions),
            "total_montages": len(all_montages),
            "total_action_lines": sum(len(s["action_lines"]) for s in scenes),
            "total_dialogue_lines": sum(len(s["dialogue"]) for s in scenes),
            "total_broll_cues": sum(len(s["broll_cues"]) for s in scenes),
            "establishing_shots": len([s for s in all_shots if s.get("is_establishing")]),
            "broll_shots": len([s for s in all_shots if s.get("is_broll")]),
            "dialogue_shots": len([s for s in all_shots if s.get("dialogue_beats")]),
            "reaction_shots": len([s for s in all_shots if s.get("shot_type") == "reaction"]),
            "cinematic_expansion": cinematic_expansion is not None
        }
    }

    # =========================================================================
    # PHASE 5: IMPORT VALIDATION GATE (V21.10 — from ATLAS System Spec §5)
    # =========================================================================
    # The gate runs BEFORE any data is saved. If any CRITICAL check fails,
    # nothing is written to disk. The user gets a specific error message.
    _gate_errors = []    # CRITICAL — block import
    _gate_warnings = []  # WARNING — import proceeds but logged

    # --- CHECK 1: Scene count stamp ---
    # The canonical scene count is IMMUTABLE after this point.
    _canonical_scene_count = len(scenes)
    shot_plan["_canonical_scene_count"] = _canonical_scene_count

    # --- CHECK 2: No INTERCUT splits ---
    # Verify each scene with is_intercut=True has intercut_locations (not split)
    for _sc in scenes:
        if _sc.get("is_intercut") and not _sc.get("intercut_locations"):
            _gate_errors.append(
                f"Scene {_sc['scene_id']}: INTERCUT detected but no intercut_locations — "
                f"parser may have split the INTERCUT into separate scenes"
            )

    # --- CHECK 3: Character normalization complete ---
    # Check if any short/alias names survived in shot data
    if _import_alias_map:
        _surviving_aliases = set()
        for _shot in all_shots:
            for _ch in _shot.get("characters", []):
                if _ch in _import_alias_map:
                    _surviving_aliases.add(_ch)
        if _surviving_aliases:
            _gate_errors.append(
                f"Character normalization incomplete — short names survived in shots: "
                f"{sorted(_surviving_aliases)}"
            )

    # --- CHECK 4: No duplicate characters in cast map ---
    # (Checked later at auto-cast time, but flag if V6 bible has dupes)
    if _v6_ingested_bible:
        _bible_char_names = [c["name"] for c in _v6_ingested_bible.get("characters", [])]
        _dupes = [n for n in _bible_char_names if _bible_char_names.count(n) > 1]
        if _dupes:
            _gate_warnings.append(
                f"Duplicate character names in story bible: {sorted(set(_dupes))}"
            )

    # --- CHECK 5: Prompt length bounds ---
    for _shot in all_shots:
        _nano_len = len(_shot.get("nano_prompt", ""))
        if _nano_len > 2500:
            _gate_warnings.append(f"Shot {_shot['shot_id']}: nano_prompt is {_nano_len} chars (max 2500)")
        if _nano_len < 50 and _shot.get("shot_type") not in ("establishing", "b-roll"):
            _gate_warnings.append(f"Shot {_shot['shot_id']}: nano_prompt is only {_nano_len} chars (min ~200)")

    # --- CHECK 6: Duration sanity ---
    for _shot in all_shots:
        _dur = _shot.get("duration", 0)
        if _dur < 3:
            _gate_warnings.append(f"Shot {_shot['shot_id']}: duration {_dur}s < 3s minimum")
        if _dur > 60:
            _gate_warnings.append(f"Shot {_shot['shot_id']}: duration {_dur}s > 60s without override")

    # --- CHECK 7: Runtime target ---
    _total_runtime = sum(s.get("duration", 0) for s in all_shots)
    _target_runtime = runtime_minutes * 60
    if _target_runtime > 0:
        _deviation = abs(_total_runtime - _target_runtime) / _target_runtime
        if _deviation > 0.15:
            _gate_warnings.append(
                f"Runtime {_total_runtime}s deviates {_deviation:.0%} from target {_target_runtime}s"
            )

    # --- CHECK 8: V6 story bible scene count match ---
    if _v6_ingested_bible:
        _bible_scene_count = len(_v6_ingested_bible.get("scenes", []))
        if _bible_scene_count > 0 and _bible_scene_count != _canonical_scene_count:
            _gate_errors.append(
                f"Script has {_canonical_scene_count} scene headers, story bible has "
                f"{_bible_scene_count} scenes. Reconcile before import. "
                f"Common cause: INTERCUT blocks being split into separate scenes."
            )

    # --- GATE DECISION ---
    shot_plan["_import_gate"] = {
        "passed": len(_gate_errors) == 0,
        "critical_errors": _gate_errors,
        "warnings": _gate_warnings,
        "checks_run": 8,
        "timestamp": datetime.now().isoformat()
    }

    if _gate_errors:
        logger.error(f"[IMPORT GATE] REJECTED — {len(_gate_errors)} critical errors: {_gate_errors}")
        return {
            "success": False,
            "error": "Import validation gate FAILED — critical errors found",
            "gate_result": {
                "critical_errors": _gate_errors,
                "warnings": _gate_warnings,
                "scene_count": _canonical_scene_count,
                "shot_count": len(all_shots),
                "characters": sorted(list(all_characters))
            }
        }

    if _gate_warnings:
        logger.warning(f"[IMPORT GATE] PASSED with {len(_gate_warnings)} warnings: {_gate_warnings}")
    else:
        logger.info(f"[IMPORT GATE] PASSED — 0 errors, 0 warnings")

    # =========================================================================
    # PHASE 6: SAVE (only after gate passes)
    # =========================================================================

    with open(project_path / "shot_plan.json", 'w') as f:
        json.dump(shot_plan, f, indent=2)

    # Save characters and locations for story bible
    characters_list = [{"name": c, "role": "unknown"} for c in sorted(all_characters)]
    locations_list = [{"name": l} for l in sorted(all_locations)]

    # =========================================================================
    # V21.10: STORY BIBLE — INGEST (V6 header) or GENERATE (bare-bones)
    # =========================================================================
    bible_path = project_path / "story_bible.json"
    if _v6_ingested_bible:
        # V21.10 INGEST PATH: Use the rich V6 header data
        # Merge the regex-extracted characters into the V6 bible
        # (V6 header has descriptions, regex has scene presence data)

        # V21.10: Normalize V6 bible character names using same map
        if _import_alias_map:
            for v6_char in _v6_ingested_bible.get("characters", []):
                v6_char["name"] = _import_alias_map.get(v6_char["name"], v6_char["name"])

        v6_char_names = {c["name"] for c in _v6_ingested_bible.get("characters", [])}
        for regex_char_name in sorted(all_characters):
            if regex_char_name not in v6_char_names:
                # Character found in screenplay but not in V6 header — add as basic entry
                _v6_ingested_bible.setdefault("characters", []).append({
                    "name": regex_char_name,
                    "description": "",
                    "visual_prompt": "",
                    "role": "supporting",
                    "source": "regex_extraction"
                })

        # Merge regex-extracted locations into V6 bible
        v6_loc_names = {l.get("name", "").upper() for l in _v6_ingested_bible.get("locations", [])}
        for regex_loc_name in sorted(all_locations):
            if regex_loc_name.upper() not in v6_loc_names:
                _v6_ingested_bible.setdefault("locations", []).append({
                    "name": regex_loc_name,
                    "source": "regex_extraction"
                })

        # Save the ingested story bible
        # V21.10: Stamp canonical scene count into bible for downstream validation
        _v6_ingested_bible["_canonical_scene_count"] = _canonical_scene_count
        _v6_ingested_bible["_extraction_stats"] = shot_plan.get("_extraction_stats", {})
        with open(bible_path, 'w') as f:
            json.dump(_v6_ingested_bible, f, indent=2)
        logger.info(
            f"[V6-INGEST] Story bible INGESTED from V6 header: "
            f"{len(_v6_ingested_bible.get('characters', []))} characters, "
            f"{len(_v6_ingested_bible.get('locations', []))} locations"
        )
    elif not bible_path.exists():
        # GENERATE PATH: No V6 header — create bare-bones bible
        story_bible = {
            "title": title,
            "characters": characters_list,
            "locations": locations_list,
            "runtime_target_minutes": runtime_minutes,
            "runtime_target_seconds": runtime_minutes * 60,
            "_canonical_scene_count": _canonical_scene_count,  # V21.10: immutable scene count from screenplay
            "_generated_at": datetime.now().isoformat(),
            "_source": "script_parser",
            "_needs_llm_enrichment": True  # Flag: this bible needs LLM generation
        }
        with open(bible_path, 'w') as f:
            json.dump(story_bible, f, indent=2)
        logger.info(f"[IMPORT] Bare-bones story bible created — run generate-story-bible for LLM enrichment")

    # Invalidate UI cache
    cache_dir = project_path / "ui_cache"
    if cache_dir.exists():
        (cache_dir / "bundle.dirty").touch()

    logger.info(f"[SCRIPT PARSER V17] {project}: {len(scenes)} scenes, {len(all_shots)} shots "
                f"({len([s for s in all_shots if s.get('is_establishing')])} establishing, "
                f"{len([s for s in all_shots if s.get('is_broll')])} B-roll, "
                f"{len([s for s in all_shots if s.get('shot_type') == 'reaction'])} reaction)")

    # V17.3: Temporal workflow tracking for script import
    try:
        _wf_id = temporal_start_workflow(project, "parse_script")
        temporal_run_activity(_wf_id, "parse_script")
        _parse_summary = {"scenes": len(scenes), "shots": len(all_shots), "characters": len(all_characters), "locations": len(all_locations)}
        temporal_complete_activity(_wf_id, "parse_script", result=_parse_summary)
        temporal_complete_workflow(_wf_id, result=_parse_summary)
        _temporal_persist()
    except Exception:
        pass  # Temporal tracking is non-blocking

    return {
        "success": True,
        "project": project,
        "parsed": {
            "scenes": len(scenes),
            "shots": len(all_shots),
            "characters": sorted(list(all_characters)),
            "locations": sorted(list(all_locations)),
            "transitions": len(all_transitions),
            "montages": len(all_montages),
            "extraction_stats": shot_plan["_extraction_stats"]
        },
        "cinematic_expansion": cinematic_expansion is not None,
        "v6_header_ingested": _v6_ingested_bible is not None,
        "v6_ingest_stats": {
            "characters_from_header": len(_v6_ingested_bible.get("characters", [])) if _v6_ingested_bible else 0,
            "scene_cards": len(_v6_ingested_bible.get("scenes", [])) if _v6_ingested_bible else 0,
            "aliases": len(_v6_ingested_bible.get("aliases", {})) if _v6_ingested_bible else 0,
            "stopwords": len(_v6_ingested_bible.get("casting_stopwords", [])) if _v6_ingested_bible else 0,
            "story_bible_source": "v6_header_ingest" if _v6_ingested_bible else "needs_llm_generation"
        } if _v6_ingested_bible else None,
        "saved_to": str(project_path / "shot_plan.json")
    }

@app.put("/api/v6/shots/{project}/update")
@app.post("/api/v6/shots/{project}/update")
async def update_single_shot(project: str, request: Dict = Body(...)):
    """
    V17: Update a single shot. Calls batch-update internally for consistency.

    Body:
    {
        "shot_id": "001_001A",
        "nano_prompt": "...",
        "ltx_motion_prompt": "...",
        "duration": 20
    }
    """
    # Wrap single shot in array and delegate to batch-update
    shot_id = request.get("shot_id")
    if not shot_id:
        return {"success": False, "error": "shot_id is required"}

    # Call batch update with single shot
    result = await batch_update_shots(project, {"shots": [request]})
    return {
        "success": result.get("success", False),
        "project": project,
        "shot_id": shot_id,
        "updated": result.get("updated_count", 0) > 0
    }


@app.get("/api/v6/shots/{project}")
async def get_project_shots(project: str):
    shot_plan_path = get_project_path(project) / "shot_plan.json"
    if not shot_plan_path.exists():
        return {"shots": []}
    with open(shot_plan_path) as f:
        data = json.load(f)
    return {"shots": data.get("shots", []), "total": len(data.get("shots", []))}


@app.post("/api/v6/shots/{project}/batch-update")
async def batch_update_shots(project: str, request: Dict = Body(...)):
    """
    V17: Batch update shots with full field support including segments.

    Body:
    {
        "shots": [
            {
                "shot_id": "001_001A",
                "nano_prompt": "...",
                "ltx_motion_prompt": "...",
                "duration": 20,
                "type": "wide",
                "location": "VALLEY",
                "characters": ["FELAN"],
                "camera_style": "...",
                "segments": [  // V17: Optional segment updates for extended shots
                    {"duration": 18, "ltx_motion_prompt": "..."},
                    {"duration": 18, "ltx_motion_prompt": "..."}
                ]
            }
        ]
    }
    """
    updates = request.get("shots", [])

    if not updates:
        return {"success": True, "project": project, "updated_count": 0, "message": "No updates provided"}

    project_path = get_project_path(project)
    shot_plan_path = project_path / "shot_plan.json"

    if not shot_plan_path.exists():
        return {"success": False, "error": f"Shot plan not found for {project}"}

    # Load shot plan
    with open(shot_plan_path) as f:
        shot_plan = _sp_guard(json.load(f))

    shots = shot_plan.get("shots", [])
    shot_lookup = {s.get("shot_id"): s for s in shots}

    updated_count = 0
    total_runtime = 0

    for update in updates:
        shot_id = update.get("shot_id")
        if not shot_id or shot_id not in shot_lookup:
            continue

        shot = shot_lookup[shot_id]

        # Update basic fields
        if "nano_prompt" in update:
            shot["nano_prompt"] = update["nano_prompt"]
        if "ltx_motion_prompt" in update:
            shot["ltx_motion_prompt"] = update["ltx_motion_prompt"]
        if "duration" in update:
            shot["duration"] = update["duration"]
            shot["duration_seconds"] = update["duration"]
        if "type" in update:
            shot["type"] = update["type"]
        if "location" in update:
            shot["location"] = update["location"]
        if "characters" in update:
            shot["characters"] = update["characters"]
        if "camera_style" in update:
            shot["camera_style"] = update["camera_style"]
        if "camera_body" in update:
            shot["camera_body"] = update["camera_body"]
        if "lens_type" in update:
            shot["lens_type"] = update["lens_type"]
        if "camera" in update:
            shot["camera"] = update["camera"]
        if "lens_specs" in update:
            shot["lens_specs"] = update["lens_specs"]
        if "lighting" in update:
            shot["lighting"] = update["lighting"]

        # V17: Update segment prompts for extended shots
        if "segments" in update and update["segments"]:
            # Update render_plan.segments if present
            if "render_plan" not in shot:
                shot["render_plan"] = {}

            existing_segments = shot.get("render_plan", {}).get("segments", shot.get("segments", []))

            for i, seg_update in enumerate(update["segments"]):
                if i < len(existing_segments):
                    if "ltx_motion_prompt" in seg_update:
                        existing_segments[i]["ltx_motion_prompt"] = seg_update["ltx_motion_prompt"]

            shot["render_plan"]["segments"] = existing_segments
            shot["segments"] = existing_segments  # Also update top-level segments

        shot["_edited_at"] = datetime.now().isoformat()
        updated_count += 1

    # Calculate total runtime
    for shot in shots:
        dur = shot.get("duration") or shot.get("duration_seconds") or 10
        total_runtime += dur

    # Save updated shot plan
    shot_plan["_last_batch_edit"] = datetime.now().isoformat()
    with open(shot_plan_path, 'w') as f:
        json.dump(shot_plan, f, indent=2)

    # Invalidate UI cache
    cache_dir = project_path / "ui_cache"
    if cache_dir.exists():
        (cache_dir / "bundle.dirty").touch()
    sync_manifest_to_xlsx(project_path)

    # Format runtime
    minutes = total_runtime // 60
    seconds = total_runtime % 60
    total_runtime_formatted = f"{minutes}:{seconds:02d}"

    logger.info(f"[BATCH-UPDATE] Updated {updated_count} shots for {project}, total runtime: {total_runtime_formatted}")

    return {
        "success": True,
        "project": project,
        "updated_count": updated_count,
        "total_runtime": total_runtime,
        "total_runtime_formatted": total_runtime_formatted
    }


@app.post("/api/v16/shot/update-prompts")
async def update_shot_prompts(request: Dict = Body(...)):
    """V16.7.1: Update prompts for a shot and optionally regenerate.
    V18.3.1: Supports _append mode for Director Quick Actions."""
    project = request.get("project")
    shot_id = request.get("shot_id")
    nano_prompt = request.get("nano_prompt")
    ltx_motion_prompt = request.get("ltx_motion_prompt")
    # V18.3.1: Append mode — add to existing prompt instead of replacing
    nano_prompt_append = request.get("nano_prompt_append")
    ltx_prompt_append = request.get("ltx_motion_prompt_append")
    regenerate = request.get("regenerate", False)

    if not project or not shot_id:
        return {"success": False, "error": "project and shot_id required"}

    shot_plan_path = get_project_path(project) / "shot_plan.json"
    if not shot_plan_path.exists():
        return {"success": False, "error": "Shot plan not found"}

    # Load and update shot plan
    with open(shot_plan_path) as f:
        data = json.load(f)

    # V27.1: Handle both list format [shots...] and dict format {"shots": [...]}
    if isinstance(data, list):
        shots = data
        data = {"shots": data}
    else:
        shots = data.get("shots", [])
    updated = False
    for shot in shots:
        if shot.get("shot_id") == shot_id:
            if nano_prompt:
                shot["nano_prompt"] = nano_prompt
            if ltx_motion_prompt:
                shot["ltx_motion_prompt"] = ltx_motion_prompt
            # V18.3.1: Append mode for Director Quick Actions
            if nano_prompt_append:
                shot["nano_prompt"] = (shot.get("nano_prompt") or "").rstrip() + nano_prompt_append
            if ltx_prompt_append:
                shot["ltx_motion_prompt"] = (shot.get("ltx_motion_prompt") or "").rstrip() + ltx_prompt_append
            shot["_prompts_edited_at"] = datetime.now().isoformat()
            updated = True
            logger.info(f"[UPDATE_PROMPTS] Updated prompts for {shot_id}{' (append)' if nano_prompt_append or ltx_prompt_append else ''}")
            break

    if not updated:
        return {"success": False, "error": f"Shot {shot_id} not found"}

    # Save updated shot plan
    data["_last_prompt_edit"] = datetime.now().isoformat()
    with open(shot_plan_path, 'w') as f:
        json.dump(data, f, indent=2)

    # Invalidate cache (both old dict cache + V18.2 dirty flag)
    try:
        if project in ui_bundle_cache:
            del ui_bundle_cache[project]
    except Exception:
        pass
    _invalidate_bundle_cache(project)
    sync_manifest_to_xlsx(get_project_path(project))

    # Optionally regenerate first frame
    if regenerate:
        try:
            # Queue first frame regeneration
            from background_tasks import queue_first_frame_generation
            queue_first_frame_generation(project, [shot_id])
            logger.info(f"[UPDATE_PROMPTS] Queued regeneration for {shot_id}")
        except ImportError:
            # Direct generation if background tasks not available
            logger.info(f"[UPDATE_PROMPTS] Background tasks not available, skipping auto-regen")

    return {
        "success": True,
        "project": project,
        "shot_id": shot_id,
        "updated": True,
        "regenerate_queued": regenerate
    }


# =============================================================================
# V21.2 SHOT CONTROL PANEL ENDPOINT
# =============================================================================

@app.post("/api/v21/shot/update-control")
async def update_shot_control(request: Dict = Body(...)):
    """
    V21.2: Director's Control Panel — field-level shot update with prompt rebuilding.
    Receives a single field change, updates the shot, rebuilds affected prompt sections,
    saves to disk, and returns updated prompts.

    Input: {project, shot_id, field, value}
    Returns: {success, nano_prompt, ltx_motion_prompt, changed_sections, shot_data}
    """
    project = request.get("project", "")
    shot_id = request.get("shot_id", "")
    field = request.get("field", "")
    value = request.get("value")

    if not project or not shot_id or not field:
        return {"success": False, "error": "Missing project, shot_id, or field"}

    project_path = Path(PIPELINE_OUTPUTS_DIR) / project
    shot_plan_path = project_path / "shot_plan.json"

    if not shot_plan_path.exists():
        return {"success": False, "error": f"No shot plan for {project}"}

    try:
        with open(shot_plan_path) as f:
            data = json.load(f)

        shots = data.get("shots", [])
        target_shot = None
        target_idx = -1
        for i, s in enumerate(shots):
            if s.get("shot_id") == shot_id:
                target_shot = s
                target_idx = i
                break

        if not target_shot:
            return {"success": False, "error": f"Shot {shot_id} not found"}

        changed_sections = []

        # ── FIELD HANDLERS ──

        # Camera fields — update field + rebuild camera section of prompt
        if field in ("camera_style", "camera_body", "lens_specs", "lens_type"):
            target_shot[field] = value
            changed_sections.append("camera")
            # If shot_type changed, cascade camera defaults
            if field == "camera_style":
                # Update LTX motion clause
                ltx = target_shot.get("ltx_motion_prompt", "")
                # Strip old motion clause and replace
                import re as _re
                motion_map = {
                    "static": "static hold, no camera movement",
                    "slow_crane": "slow crane rising vertically",
                    "steadicam": "smooth steadicam tracking",
                    "handheld": "subtle handheld organic movement",
                    "slow_dolly": "slow dolly tracking horizontally",
                    "slow_pan": "slow pan sweeping horizontally",
                }
                new_motion = motion_map.get(value, value)
                # Replace first motion directive in LTX
                ltx = _re.sub(r'(static hold|slow crane|steadicam|handheld|slow dolly|slow pan)[^,\.]*', new_motion, ltx, count=1)
                target_shot["ltx_motion_prompt"] = ltx
                changed_sections.append("ltx_motion")

        # Shot type — update + cascade camera defaults
        elif field == "shot_type" or field == "type":
            target_shot["shot_type"] = value
            target_shot["type"] = value
            changed_sections.append("shot_type")
            # Apply camera defaults for new type
            try:
                _cam_defaults = {
                    "wide": {"camera_body": "ARRI Alexa 35", "lens_specs": "24mm", "camera_style": "static", "lens_type": "Cooke S7/i Prime"},
                    "medium_wide": {"camera_body": "ARRI Alexa 35", "lens_specs": "35mm", "camera_style": "static", "lens_type": "Cooke S7/i Prime"},
                    "medium": {"camera_body": "ARRI Alexa 35", "lens_specs": "50mm", "camera_style": "static", "lens_type": "Cooke S7/i Prime"},
                    "medium_close": {"camera_body": "ARRI Alexa 35", "lens_specs": "85mm", "camera_style": "static", "lens_type": "Cooke S7/i Prime"},
                    "close": {"camera_body": "ARRI Alexa 35", "lens_specs": "85mm", "camera_style": "static", "lens_type": "Cooke S7/i Prime"},
                    "closeup": {"camera_body": "ARRI Alexa 35", "lens_specs": "100mm", "camera_style": "static", "lens_type": "Zeiss Master Prime"},
                    "ecu": {"camera_body": "ARRI Alexa 35", "lens_specs": "100mm", "camera_style": "static", "lens_type": "Macro"},
                    "extreme_close": {"camera_body": "ARRI Alexa 35", "lens_specs": "100mm", "camera_style": "static", "lens_type": "Macro"},
                    "establishing": {"camera_body": "ARRI Alexa 35", "lens_specs": "14mm", "camera_style": "slow_crane", "lens_type": "Cooke S7/i Prime"},
                    "over_the_shoulder": {"camera_body": "ARRI Alexa 35", "lens_specs": "50mm", "camera_style": "static", "lens_type": "Cooke S7/i Prime"},
                    "two_shot": {"camera_body": "ARRI Alexa 35", "lens_specs": "35mm", "camera_style": "static", "lens_type": "Cooke S7/i Prime"},
                    "reaction": {"camera_body": "ARRI Alexa 35", "lens_specs": "85mm", "camera_style": "static", "lens_type": "Cooke S7/i Prime"},
                    "insert": {"camera_body": "ARRI Alexa 35", "lens_specs": "100mm", "camera_style": "static", "lens_type": "Macro"},
                    "detail": {"camera_body": "ARRI Alexa 35", "lens_specs": "100mm", "camera_style": "static", "lens_type": "Macro"},
                    "aerial": {"camera_body": "ARRI Alexa 35", "lens_specs": "24mm", "camera_style": "slow_crane", "lens_type": "Cooke S7/i Prime"},
                }
                defaults = _cam_defaults.get(value.lower(), {})
                for k, v in defaults.items():
                    target_shot[k] = v
                changed_sections.append("camera")
            except Exception:
                pass

        # Emotional tone — update + rebuild color grade + acting direction
        elif field == "emotional_tone" or field == "duration_emotion":
            target_shot["emotional_tone"] = value
            target_shot["duration_emotion"] = value
            changed_sections.append("emotion")
            changed_sections.append("color_grade")

            # Rebuild color grade from tone
            _COLOR_GRADE_BY_TONE = {
                "dread": "cold desaturated grade, teal-blue shadows, crushed blacks, no warm tones",
                "tension": "high contrast grade, neutral midtones, sharp shadows, controlled saturation",
                "grief": "muted desaturated grade, low saturation, soft contrast, gray-blue undertones",
                "hope": "warm golden grade, amber highlights, lifted shadows, gentle saturation",
                "revelation": "stark neutral grade, high contrast, crisp whites, deep blacks",
                "fear": "cold blue-green grade, desaturated skin tones, deep shadow crush",
                "anger": "high contrast warm-red grade, saturated reds, hot highlights",
                "love": "warm rosy grade, soft pink highlights, gentle skin tones, low contrast",
                "suspense": "underexposed neutral grade, muted colors, practical light warmth only",
                "horror": "sickly green-teal grade, desaturated except green channel, crushed blacks",
                "mystery": "amber-teal split grade, warm highlights cold shadows, filmic contrast",
                "neutral": "DaVinci Resolve neutral grade, balanced color temperature, subtle film grain",
            }
            grade_text = _COLOR_GRADE_BY_TONE.get(value, "")
            if grade_text:
                # Inject/replace color grade in nano_prompt
                import re as _re
                nano = target_shot.get("nano_prompt", "")
                # Strip old color grade
                nano = _re.sub(r'(cold desaturated|high contrast|muted desaturated|warm golden|stark neutral|cold blue-green|high contrast warm-red|warm rosy|underexposed neutral|sickly green-teal|amber-teal split|DaVinci Resolve neutral)\s+grade[^.]*\.?\s*', '', nano)
                # Append new grade
                nano = nano.rstrip('. ') + f". {grade_text}."
                target_shot["nano_prompt"] = nano
                changed_sections.append("nano_prompt")

                # Update LTX with emotion acting
                ltx = target_shot.get("ltx_motion_prompt", "")
                _EMOTION_ACTING = {
                    "dread": "heavy dread weighs on every movement, slow reluctant gestures",
                    "tension": "coiled tension in posture, controlled measured movements",
                    "grief": "grief-weighted movements, shoulders bowed, heavy breathing",
                    "hope": "cautious hope emerging, lighter posture, eyes brightening",
                    "revelation": "shock of revelation, frozen moment then processing",
                    "fear": "fear tightens muscles, quick nervous glances, shallow breathing",
                    "anger": "anger erupts in sharp gestures, clenched jaw, aggressive posture",
                    "love": "tender gentle movements, soft eye contact, vulnerable openness",
                    "suspense": "held breath, motionless anticipation, eyes scanning",
                    "horror": "recoiling in horror, hand to mouth, stepping backward",
                    "mystery": "guarded curiosity, careful deliberate movements",
                    "neutral": "natural relaxed movement, conversational body language",
                }
                acting = _EMOTION_ACTING.get(value, "")
                # V21.6: Only inject human acting direction if shot has characters
                _ctrl_chars = target_shot.get("characters", [])
                if acting and _ctrl_chars:
                    ltx = _re.sub(r'emotion blend[^.]*\.?\s*', '', ltx)
                    ltx = ltx.rstrip('. ') + f". emotion blend: {acting}."
                    target_shot["ltx_motion_prompt"] = ltx
                    changed_sections.append("ltx_motion")
                elif acting and not _ctrl_chars:
                    # Landscape/B-roll: inject environmental mood instead
                    _ENV_EMOTION = {
                        "dread": "oppressive atmosphere, darkness encroaching, heavy air",
                        "tension": "charged atmosphere, shadows tightening, still air before storm",
                        "grief": "muted grey light, overcast weight, landscape of aftermath",
                        "hope": "golden light breaking through, warmth emerging, atmosphere lifting",
                        "fear": "restless shadows, flickering light sources, environment contracting",
                        "anger": "turbulent sky, harsh wind, dramatic storm light",
                        "love": "soft warm light, gentle atmosphere, warmth in the landscape",
                        "horror": "sickly light, hostile shadows, environment alive with menace",
                        "neutral": "natural ambient atmosphere, gentle environmental motion",
                    }
                    env_act = _ENV_EMOTION.get(value, "natural atmospheric shifts")
                    ltx = _re.sub(r'emotion blend[^.]*\.?\s*', '', ltx)
                    ltx = ltx.rstrip('. ') + f". environment mood: {env_act}."
                    target_shot["ltx_motion_prompt"] = ltx
                    changed_sections.append("ltx_motion")

        # Emotion intensity — update + scale acting intensity
        elif field == "emotion_intensity":
            try:
                intensity = max(1, min(10, int(value)))
            except (ValueError, TypeError):
                intensity = 5
            target_shot["_emotion_intensity"] = intensity
            target_shot["emotion_intensity"] = intensity
            changed_sections.append("emotion_intensity")

            # Scale intensity descriptors
            if intensity <= 3:
                intensity_desc = "subtle, understated"
            elif intensity <= 5:
                intensity_desc = "moderate, naturalistic"
            elif intensity <= 7:
                intensity_desc = "heightened, visceral"
            else:
                intensity_desc = "overwhelming, raw, consuming"

            import re as _re
            ltx = target_shot.get("ltx_motion_prompt", "")
            ltx = _re.sub(r'emotion intensity[^.]*\.?\s*', '', ltx)
            ltx = ltx.rstrip('. ') + f". emotion intensity ({intensity}/10): {intensity_desc}."
            target_shot["ltx_motion_prompt"] = ltx
            changed_sections.append("ltx_motion")

        # Wardrobe tag — update + rebuild wardrobe section
        elif field == "wardrobe_tag":
            target_shot["wardrobe_tag"] = value
            changed_sections.append("wardrobe")

            # Rebuild wardrobe in nano_prompt
            import re as _re
            nano = target_shot.get("nano_prompt", "")
            nano = _re.sub(r'wearing:\s*[^.]+\.?\s*', '', nano, count=1)
            chars = target_shot.get("characters", [])
            char_name = chars[0] if isinstance(chars, list) and chars else "Character"
            if isinstance(char_name, str) and value:
                nano = nano.rstrip('. ') + f". {char_name} wearing: {value}."
                target_shot["nano_prompt"] = nano
                changed_sections.append("nano_prompt")

        # Color grade override
        elif field == "color_grade":
            target_shot["_color_grade_override"] = value
            changed_sections.append("color_grade")
            import re as _re
            nano = target_shot.get("nano_prompt", "")
            nano = _re.sub(r'(cold desaturated|high contrast|muted desaturated|warm golden|stark neutral|cold blue-green|high contrast warm-red|warm rosy|underexposed neutral|sickly green-teal|amber-teal split|DaVinci Resolve neutral)\s+grade[^.]*\.?\s*', '', nano)
            nano = nano.rstrip('. ') + f". {value}."
            target_shot["nano_prompt"] = nano
            changed_sections.append("nano_prompt")

        # Duration
        elif field == "duration":
            try:
                dur = max(2, min(60, float(value)))
            except (ValueError, TypeError):
                dur = 8
            target_shot["duration"] = dur
            target_shot["duration_seconds"] = dur
            target_shot["ltx_duration_seconds"] = dur
            changed_sections.append("duration")
            # Fix LTX timing
            import re as _re
            ltx = target_shot.get("ltx_motion_prompt", "")
            ltx = _re.sub(r'\d+-\d+s\s+', f"0-{int(dur)}s ", ltx, count=1)
            target_shot["ltx_motion_prompt"] = ltx
            changed_sections.append("ltx_motion")

        # Generic field update (characters, location, etc.)
        else:
            target_shot[field] = value
            changed_sections.append(field)

        # ── SAVE TO DISK (atomic) ──
        import tempfile as _tf
        _tmp = _tf.NamedTemporaryFile(mode='w', dir=str(project_path), suffix='.tmp', delete=False)
        json.dump(data, _tmp, indent=2)
        _tmp.close()
        os.replace(_tmp.name, str(shot_plan_path))

        # Invalidate bundle cache
        dirty_flag = project_path / "ui_cache" / "bundle.dirty"
        dirty_flag.parent.mkdir(parents=True, exist_ok=True)
        dirty_flag.touch()

        logger.info(f"[CONTROL-PANEL] {shot_id}: updated {field}={str(value)[:50]} → sections: {changed_sections}")

        return {
            "success": True,
            "shot_id": shot_id,
            "field": field,
            "value": value,
            "nano_prompt": target_shot.get("nano_prompt", ""),
            "ltx_motion_prompt": target_shot.get("ltx_motion_prompt", ""),
            "changed_sections": changed_sections,
            "shot_data": {
                "camera_body": target_shot.get("camera_body", ""),
                "camera_style": target_shot.get("camera_style", ""),
                "lens_specs": target_shot.get("lens_specs", ""),
                "lens_type": target_shot.get("lens_type", ""),
                "emotional_tone": target_shot.get("emotional_tone", ""),
                "emotion_intensity": target_shot.get("emotion_intensity", 5),
                "wardrobe_tag": target_shot.get("wardrobe_tag", ""),
                "shot_type": target_shot.get("shot_type", target_shot.get("type", "")),
                "duration": target_shot.get("duration", 8),
                "_scene_type": target_shot.get("_scene_type", ""),
                "_color_grade_override": target_shot.get("_color_grade_override", ""),
            }
        }

    except Exception as e:
        logger.error(f"[CONTROL-PANEL] Error updating {shot_id}.{field}: {e}")
        return {"success": False, "error": str(e)[:500]}


# =============================================================================
# V17 APPROVAL GATE ENDPOINTS
# =============================================================================

@app.get("/api/v17/approval/{project}")
async def get_approval_status(project: str):
    """
    Get approval status for a project.
    Returns per-scene approval state and pending human tasks.
    """
    try:
        from atlas_agents_v16_7.atlas_agents.approval_gate import ApprovalGate
        gate = ApprovalGate(project)
        return gate.check_and_update()
    except Exception as e:
        logger.error(f"[APPROVAL] Error getting status: {e}")
        return {"error": str(e), "project": project}


@app.post("/api/v17/approval/{project}")
async def update_approval_status(project: str, request: Dict = Body(...)):
    """
    Update approval status for a project.

    Body:
        {
            "action": "approve_scene" | "reject_scene" | "approve_stage",
            "scene_id": "001",  # for scene actions
            "stage": "FRAMES" | "VIDEOS",
            "notes": "Optional notes",
            "reason": "Rejection reason"  # for reject
        }
    """
    try:
        from atlas_agents_v16_7.atlas_agents.approval_gate import ApprovalGate

        gate = ApprovalGate(project)
        action = request.get("action", "")
        scene_id = request.get("scene_id", "")
        stage = request.get("stage", "")
        notes = request.get("notes", "")
        reason = request.get("reason", "")

        if action == "approve_scene":
            if not scene_id or not stage:
                return {"error": "scene_id and stage required"}
            return gate.approve_scene(scene_id, stage, notes)

        elif action == "reject_scene":
            if not scene_id or not stage or not reason:
                return {"error": "scene_id, stage, and reason required"}
            return gate.reject_scene(scene_id, stage, reason)

        elif action == "approve_stage":
            if not stage:
                return {"error": "stage required"}
            return gate.approve_stage(stage)

        else:
            return {"error": f"Unknown action: {action}"}

    except Exception as e:
        logger.error(f"[APPROVAL] Error updating: {e}")
        return {"error": str(e), "project": project}


@app.get("/api/v17/approval/{project}/pending")
async def get_pending_approvals(project: str, stage: str = "FRAMES"):
    """Get list of scenes pending approval for a stage."""
    try:
        from atlas_agents_v16_7.atlas_agents.approval_gate import ApprovalGate

        gate = ApprovalGate(project)
        gate.check_and_update()
        pending = gate.get_pending_scenes(stage)

        return {
            "project": project,
            "stage": stage,
            "pending_scenes": pending,
            "count": len(pending)
        }
    except Exception as e:
        logger.error(f"[APPROVAL] Error getting pending: {e}")
        return {"error": str(e), "project": project}


@app.post("/api/v17/generate-multi-angle")
async def generate_multi_angle(request: Dict = Body(...)):
    """
    V17.5 MULTI-ANGLE GENERATION
    Generate 3 angle variants for a shot using nano-pro-edit differentiated prompts.
    Each variant gets a different camera angle instruction appended to the base prompt.
    DINO face scoring runs automatically to rank variants.
    """
    project = request.get("project")
    shot_id = request.get("shot_id")
    angles = request.get("angles", [])
    run_dino = request.get("run_dino", True)

    if not project or not shot_id:
        return JSONResponse({"error": "project and shot_id required"}, status_code=400)

    try:
        project_path = PIPELINE_OUTPUTS_DIR / project
        shot_plan_path = project_path / "shot_plan.json"
        if not shot_plan_path.exists():
            return {"success": False, "error": "Shot plan not found"}

        with open(shot_plan_path, 'r') as f:
            shot_plan = _sp_guard(json.load(f))

        shots = shot_plan.get("shots", [])
        shot = next((s for s in shots if s.get("shot_id") == shot_id), None)
        if not shot:
            return {"success": False, "error": f"Shot {shot_id} not found"}

        base_prompt = shot.get("nano_prompt", "")
        ltx_prompt = shot.get("ltx_motion_prompt", "")

        # Build character refs — V17.6: use normalize_cast_entry + score_name_match (Rule 61, 63)
        ref_urls = []
        char_ref = shot.get("character_reference_url", "")
        if not char_ref and shot.get("characters"):
            # Try to find character reference from cast_map using scored matching
            cast_map_path = project_path / "cast_map.json"
            if cast_map_path.exists():
                try:
                    with open(cast_map_path) as cf:
                        cast_map = json.load(cf)
                    for char_name in shot.get("characters", []):
                        # Use scored matching for first-name / full-name resolution (Rule 63)
                        matched_key = find_character_match(char_name, cast_map, min_score=65)
                        if matched_key:
                            char_data = normalize_cast_entry(cast_map[matched_key])  # Rule 61
                        else:
                            char_data = normalize_cast_entry(cast_map.get(char_name, {}))
                        # V21.10: Use character_reference_url (CHAR_REFERENCE) — NEVER AI actor headshots
                        # AI actor LOCKED_REFERENCE shows the WRONG person and causes drift
                        ref_url = char_data.get("character_reference_url", "")
                        if ref_url and "CHAR_REFERENCE" in ref_url:
                            if ref_url.startswith("/api/media"):
                                char_ref = ref_url
                            elif Path(ref_url).exists():
                                char_ref = f"/api/media?path={ref_url}"
                            else:
                                char_ref = ref_url
                            logger.info(f"[V21.10 MULTI-ANGLE] Using CHAR_REFERENCE for {char_name}")
                            break
                        # Fallback: try project-local CHAR_REFERENCE on disk
                        _char_safe = re.sub(r'[^a-zA-Z0-9_-]', '_', char_name.upper().strip())
                        _char_ref_path = project_path / "character_library_locked" / f"{_char_safe}_CHAR_REFERENCE.jpg"
                        if _char_ref_path.exists():
                            char_ref = f"/api/media?path={_char_ref_path}"
                            logger.info(f"[V21.10 MULTI-ANGLE] Resolved CHAR_REFERENCE on disk for {char_name}")
                            break
                        # Last resort: use whatever character_reference_url cast_map has (but NOT headshot)
                        if ref_url and "LOCKED_REFERENCE" not in ref_url and "ai_actors" not in ref_url:
                            char_ref = ref_url if ref_url.startswith("/api/media") else f"/api/media?path={ref_url}"
                            break
                        logger.warning(f"[V21.10 MULTI-ANGLE] No character ref found for {char_name}")
                        break
                except Exception:
                    pass
        if char_ref:
            ref_urls.append(char_ref)
        loc_ref = shot.get("location_master_url", "")
        if not loc_ref and shot.get("location"):
            # V17.6: Auto-resolve location master using scored matching (Rule 63)
            loc_dir = project_path / "location_masters"
            if loc_dir.exists():
                loc_name = shot.get("location", "")
                loc_files = {img.stem: img for img in loc_dir.glob("*.jpg")}
                best_match = find_location_match(loc_name, list(loc_files.keys()), min_score=65)
                if best_match:
                    loc_ref = f"/api/media?path={loc_files[best_match]}"
        if loc_ref:
            ref_urls.append(loc_ref)

        # Default 3 angles — V17.8: EXACT frame preservation + angle/lens ONLY changes
        # V17.8 FIX: Lock ALL visual details (wardrobe, lighting, color grade, set dressing, props)
        # and ONLY vary camera angle + lens focal length for maximum aesthetic variation
        _lock_clause = (
            "CRITICAL: Keep EXACT same characters, wardrobe, makeup, hair, props, "
            "set dressing, lighting direction, color grade, and background. "
            "Do NOT change any costume, color temperature, or environment detail. "
            "ONLY change the camera angle and lens as described below."
        )
        if not angles or len(angles) < 2:
            angles = [
                {
                    "name": "Cam A — Wide Master 24mm",
                    "suffix": "wide_master",
                    "instruction": f"{_lock_clause} Pull camera back to a wider master shot on 24mm wide lens. Show full scene geography with all characters visible. Camera at eye level, center frame, deep focus. Same lighting, same colors, same wardrobe — only wider framing."
                },
                {
                    "name": "Cam B — Medium Tight 85mm",
                    "suffix": "medium_tight",
                    "instruction": f"{_lock_clause} Move camera to a medium-tight angle on 85mm portrait lens. Frame from chest up with shallow depth of field. Slight camera right offset for compositional interest. Same lighting, same colors, same wardrobe — only tighter framing and bokeh."
                },
                {
                    "name": "Cam C — Close Detail 135mm",
                    "suffix": "close_detail",
                    "instruction": f"{_lock_clause} Move camera closer for an intimate close-up on 135mm telephoto lens. Frame the primary subject's face/upper body with very shallow depth of field. Low angle looking slightly upward for dramatic presence. Same lighting, same colors, same wardrobe — only closer and more compressed perspective."
                }
            ]

        variants_dir = project_path / "first_frame_variants"
        variants_dir.mkdir(exist_ok=True)

        # V21: Find existing first frame to use as source for nano-pro-edit reframing
        # Priority: dragged variant path > first_frames dir > shot metadata
        source_frame = None
        ff_dir = project_path / "first_frames"

        # 1. Check if a variant was applied to this shot (drag-to-scene workflow)
        _variant_src = shot.get("_variant_source_path", "")
        if _variant_src and Path(_variant_src).exists():
            source_frame = Path(_variant_src)
            logger.info(f"[MULTI-ANGLE V21] Using dragged variant as source: {source_frame.name}")

        # 2. Check first_frames directory
        if not source_frame:
            for ext in [".jpg", ".jpeg", ".png"]:
                candidate = ff_dir / f"{shot_id}{ext}"
                if candidate.exists():
                    source_frame = candidate
                    break

        # 3. Check first_frame_path from shot metadata
        if not source_frame:
            ffp = shot.get("first_frame_path", "")
            if ffp:
                # Handle both absolute and relative paths
                ffp_path = Path(ffp)
                if ffp_path.exists():
                    source_frame = ffp_path
                elif not ffp_path.is_absolute():
                    # Try relative to project
                    abs_candidate = project_path / ffp
                    if abs_candidate.exists():
                        source_frame = abs_candidate

        if source_frame:
            logger.info(f"[MULTI-ANGLE V21] Source frame found: {source_frame.name} → will use nano-pro-edit reframe")
        else:
            logger.warning(f"[MULTI-ANGLE V21] NO source frame found for {shot_id} — will fall back to text-to-image")

        # V21: Use nano-pro-edit for reframing (all variants via nano-pro-edit)
        # Source frame becomes the primary image input — environment locked by image, not text
        use_reframe_edit = source_frame is not None
        reframe_source_url = None

        if use_reframe_edit:
            # Upload source frame to FAL once, reuse for all 3 angles
            try:
                import fal_client as _fal
                reframe_source_url = _fal.upload(source_frame, "image/jpeg")
                logger.info(f"[MULTI-ANGLE V21] nano-pro-edit reframe mode: uploaded {source_frame.name} → FAL")
            except Exception as upload_err:
                logger.warning(f"[MULTI-ANGLE V21] fal_client.upload failed: {upload_err}")
                # V21: Fallback — try convert_refs_for_fal which handles local paths
                try:
                    _fallback_refs = convert_refs_for_fal([str(source_frame)])
                    if _fallback_refs and _fallback_refs[0]:
                        reframe_source_url = _fallback_refs[0]
                        logger.info(f"[MULTI-ANGLE V21] Fallback upload OK via convert_refs_for_fal")
                    else:
                        raise ValueError("convert_refs_for_fal returned empty")
                except Exception as fb_err:
                    logger.warning(f"[MULTI-ANGLE V21] All upload attempts failed, falling back to text-to-image: {fb_err}")
                    use_reframe_edit = False

        # Fallback models for text-to-image when no source frame
        IMAGE_MODEL_WITH_REF = "fal-ai/nano-banana-pro/edit"
        IMAGE_MODEL_NO_REF = "fal-ai/nano-banana-pro"

        shot_type = shot.get("type", shot.get("shot_type", "medium"))
        shot_chars = ", ".join(shot.get("characters", []))
        shot_location = shot.get("location", "")

        variants = []
        for i, angle in enumerate(angles[:3]):
            angle_instruction = angle.get('instruction', '')
            variant_filename = f"{shot_id}_angle_{angle.get('suffix', str(i))}.jpg"
            variant_path = variants_dir / variant_filename

            try:
                import urllib.request

                if use_reframe_edit and reframe_source_url:
                    # ── V21: END-FRAME REFRAME via nano-pro-edit ──
                    # Source frame is PRIMARY image — environment locked by image, not text
                    # V21: Use CANONICAL character descriptions for identity preservation
                    # V26.1: Use PROJECT-AWARE canonical characters (not hardcoded Ravencroft defaults)
                    _ma_face_text = ""
                    try:
                        from tools.prompt_authority_gate import load_project_authority_config, _get_canonical_characters
                        load_project_authority_config(project_path)
                        _ma_project_canon = _get_canonical_characters()
                        _ma_chars = shot.get("characters", [])
                        if isinstance(_ma_chars, str):
                            _ma_chars = [c.strip() for c in _ma_chars.split(",") if c.strip()]
                        for _mac in _ma_chars:
                            _mac_canon = _ma_project_canon.get(_mac.upper().strip())
                            if _mac_canon:
                                _ma_face_text += f" {_mac}: {_mac_canon['appearance']}."
                    except (ImportError, Exception):
                        pass

                    _reframe_prompt = (
                        "REFRAME ONLY. Use the provided image as the single source of truth. "
                        "Do NOT change environment, room, props, objects, lighting, shadows, or color grade. "
                        "Do NOT add or remove anything. Do NOT relocate characters. "
                        f"Preserve exact face identity, hairstyle, wardrobe, skin tone.{_ma_face_text} "
                        "NO morphing faces, NO grid, NO collage, face stable, identity locked. "
                        f"{angle_instruction}. "
                        "Maintain identical scene composition except camera distance and framing."
                    )
                    # V21 FIX: REFRAME uses ONLY the source frame as input image.
                    # DO NOT add character reference headshots — they bleed into the output
                    # and overtake the reframe (close_detail becomes a headshot portrait).
                    # The character is already IN the source frame — that IS the identity source.
                    _reframe_images = [reframe_source_url]
                    # ref_urls intentionally NOT added — Rule 135: reframe = source frame ONLY

                    result = fal_client.run(
                        "fal-ai/nano-banana-pro/edit",
                        arguments={
                            "image_urls": _reframe_images,
                            "prompt": _reframe_prompt,
                            "aspect_ratio": "16:9",
                            "output_format": "jpeg",
                            "num_outputs": 1,
                            "seed": (int(datetime.now().timestamp()) + i * 1000) % 1000000
                        }
                    )
                    # nano-pro-edit returns {images: [{url: "..."}]}
                    img_url = None
                    images = result.get("images", result.get("output", []))
                    if images:
                        img_url = images[0] if isinstance(images[0], str) else images[0].get("url", "")

                    if img_url:
                        urllib.request.urlretrieve(img_url, str(variant_path))
                        logger.info(f"[MULTI-ANGLE V18.4] nano-pro-edit reframe: {angle.get('name')} → {variant_filename}")
                    else:
                        raise ValueError("nano-pro-edit returned no image output")
                else:
                    # ── FALLBACK: text-to-image (no source frame available) ──
                    # V17.8: Include scene color grade anchor for consistency
                    _scene_grade = ""
                    try:
                        _scene_id = shot.get("scene_id", "001")
                        from tools.scene_anchor_system import SceneAnchorSystem
                        _anchor_sys = SceneAnchorSystem(project_path)
                        _scene_anchor = _anchor_sys.get_scene_anchor(_scene_id)
                        _scene_grade = _scene_anchor.get("color_grade", "")
                        if _scene_grade:
                            _scene_grade = f" Color grade: {_scene_grade}."
                    except Exception:
                        pass
                    angle_prompt = (
                        f"{base_prompt}. "
                        f"CRITICAL: {shot_type} shot of {shot_chars} at {shot_location}.{_scene_grade} "
                        f"Camera instruction: {angle_instruction}"
                    )
                    model = IMAGE_MODEL_WITH_REF if ref_urls else IMAGE_MODEL_NO_REF
                    if ref_urls:
                        try:
                            fal_ready_refs = convert_refs_for_fal(ref_urls[:5])
                            fal_ready_refs = [r for r in fal_ready_refs if r and len(r) > 10]
                        except Exception:
                            fal_ready_refs = []
                        if fal_ready_refs:
                            result = fal_client.run(model, arguments={
                                "prompt": angle_prompt, "image_urls": fal_ready_refs,
                                "aspect_ratio": "16:9", "output_format": "jpeg", "num_outputs": 1
                            })
                        else:
                            result = fal_client.run(IMAGE_MODEL_NO_REF, arguments={
                                "prompt": angle_prompt, "aspect_ratio": "16:9",
                                "output_format": "jpeg", "num_images": 1
                            })
                    else:
                        result = fal_client.run(model, arguments={
                            "prompt": angle_prompt, "aspect_ratio": "16:9",
                            "output_format": "jpeg", "num_images": 1
                        })
                    images = result.get("images", result.get("output", []))
                    if images:
                        img_url = images[0] if isinstance(images[0], str) else images[0].get("url", "")
                        if img_url:
                            urllib.request.urlretrieve(img_url, str(variant_path))

                # Build variant entry if file was created
                if variant_path.exists():
                    variant_entry = {
                        "angle_name": angle.get("name", f"Variant {i+1}"),
                        "suffix": angle.get("suffix", str(i)),
                        "path": str(variant_path),
                        "url": f"/api/media?path={variant_path}",
                        "dino_face": 0.0,
                        "hybrid_score": 0.0,
                        "recommended": False,
                        "method": "nano-pro-edit-reframe" if use_reframe_edit else "text-to-image"
                    }

                    # Run DINO if requested and we have a character ref
                    if run_dino and char_ref:
                        try:
                            from dino_clip_analyzer import get_hybrid_analyzer
                            analyzer = get_hybrid_analyzer()
                            ref_path_str = char_ref.replace("/api/media?path=", "") if "/api/media" in char_ref else char_ref
                            scores = analyzer.analyze_comprehensive(str(variant_path), ref_path_str, base_prompt)
                            variant_entry["dino_face"] = scores.get("dino_face", 0.0)
                            variant_entry["hybrid_score"] = scores.get("hybrid_score", 0.0)
                        except Exception as de:
                            logger.warning(f"[MULTI-ANGLE] DINO scoring failed for {variant_filename}: {de}")

                    variants.append(variant_entry)
                else:
                    raise ValueError(f"Variant file not created: {variant_path}")

            except Exception as gen_err:
                logger.error(f"[MULTI-ANGLE] Generation failed for angle {i}: {gen_err}")
                variants.append({
                    "angle_name": angle.get("name", f"Variant {i+1}"),
                    "suffix": angle.get("suffix", str(i)),
                    "path": "", "url": "",
                    "dino_face": 0.0, "hybrid_score": 0.0, "recommended": False,
                    "error": str(gen_err)
                })

        # Mark best variant by DINO face score
        if variants:
            best_idx = max(range(len(variants)), key=lambda x: (variants[x].get("dino_face", 0), variants[x].get("hybrid_score", 0)))
            variants[best_idx]["recommended"] = True

        # Store variant info on shot for UI
        shot["_variants"] = [{"angle_name": v["angle_name"], "path": v["path"], "url": v["url"]} for v in variants]
        with open(shot_plan_path, 'w') as f:
            json.dump(shot_plan, f, indent=2, default=str)

        # Invalidate cache
        cache_dir = project_path / "ui_cache"
        if cache_dir.exists():
            (cache_dir / "bundle.dirty").touch()
        sync_manifest_to_xlsx(project_path)

        method_used = "nano-pro-edit-reframe" if (source_frame and reframe_source_url) else "text-to-image"
        logger.info(f"[MULTI-ANGLE] Done: {len(variants)} variants via {method_used} for {shot_id}")
        return {"success": True, "shot_id": shot_id, "variants": variants, "count": len(variants), "method": method_used}

    except Exception as e:
        logger.error(f"[MULTI-ANGLE] Error: {e}")
        return {"success": False, "error": str(e)}


@app.post("/api/v17/select-variant")
async def select_variant(request: Dict = Body(...)):
    """
    V17.5 SELECT VARIANT
    Set a multi-angle variant as the active first frame for a shot.
    """
    project = request.get("project")
    shot_id = request.get("shot_id")
    variant_path = request.get("variant_path")
    angle_name = request.get("angle_name", "")

    if not project or not shot_id or not variant_path:
        return JSONResponse({"error": "project, shot_id, variant_path required"}, status_code=400)

    try:
        project_path = PIPELINE_OUTPUTS_DIR / project
        shot_plan_path = project_path / "shot_plan.json"

        with open(shot_plan_path, 'r') as f:
            shot_plan = _sp_guard(json.load(f))

        shots = shot_plan.get("shots", [])
        shot = next((s for s in shots if s.get("shot_id") == shot_id), None)
        if not shot:
            return {"success": False, "error": f"Shot {shot_id} not found"}

        variant_p = Path(variant_path)
        if not variant_p.exists():
            # V17.7: Try path translation — variant_path may reference user's local machine
            # Attempt to find the file relative to our project path
            try:
                # Extract the relative part after pipeline_outputs/{project}/
                rel_markers = [f"pipeline_outputs/{project}/", f"pipeline_outputs\\{project}\\"]
                for marker in rel_markers:
                    idx = variant_path.find(marker)
                    if idx >= 0:
                        rel = variant_path[idx + len(marker):]
                        candidate = project_path / rel
                        if candidate.exists():
                            variant_p = candidate
                            logger.info(f"[SELECT-VARIANT] Path translated: {variant_path} → {candidate}")
                            break
                # Also try just the filename in first_frame_variants/
                if not variant_p.exists():
                    fname = Path(variant_path).name
                    candidate = project_path / "first_frame_variants" / fname
                    if candidate.exists():
                        variant_p = candidate
                        logger.info(f"[SELECT-VARIANT] Found by filename: {fname}")
            except Exception as path_err:
                logger.warning(f"[SELECT-VARIANT] Path translation failed: {path_err}")

        if not variant_p.exists():
            return {"success": False, "error": f"Variant file not found: {variant_path} (tried path translation)"}

        # Copy variant to first_frames as the active frame
        first_frames_dir = project_path / "first_frames"
        first_frames_dir.mkdir(exist_ok=True)
        dest = first_frames_dir / f"{shot_id}.jpg"

        import shutil
        shutil.copy2(str(variant_p), str(dest))

        # Update shot metadata
        shot["first_frame_path"] = str(dest)
        shot["first_frame_url"] = f"/api/media?path={dest}"
        shot["_selected_angle"] = angle_name
        shot["generation_status"] = "completed"

        # V18.3.1: PRESERVE chain metadata (DO NOT RE-BREAK rule 102)
        # When user selects a variant, update the chain source to reflect this
        # but NEVER strip existing chain context
        if shot.get("_chain_first_frame_url") or shot.get("_chain_source"):
            shot["_variant_override"] = True
            shot["_variant_source_path"] = str(variant_p)
            logger.info(f"[SELECT-VARIANT] Chain shot {shot_id}: variant selected, chain metadata preserved")

        with open(shot_plan_path, 'w') as f:
            json.dump(shot_plan, f, indent=2, default=str)

        # Invalidate cache
        cache_dir = project_path / "ui_cache"
        if cache_dir.exists():
            (cache_dir / "bundle.dirty").touch()

        return {"success": True, "shot_id": shot_id, "angle": angle_name, "path": str(dest), "url": f"/api/media?path={dest}", "chain_preserved": bool(shot.get("_chain_source"))}

    except Exception as e:
        logger.error(f"[SELECT-VARIANT] Error: {e}")
        return {"success": False, "error": str(e)}


@app.post("/api/v17/apply-variant-to-shot")
async def apply_variant_to_shot(request: Dict = Body(...)):
    """
    V17.8 APPLY VARIANT TO ANOTHER SHOT
    Reuse a variant (or any first frame) as the first frame for a different shot.
    Copies the image and updates shot metadata so the target shot uses this frame.
    """
    project = request.get("project")
    source_path = request.get("source_path", "")  # path to variant/frame image
    target_shot_id = request.get("target_shot_id", "")
    source_shot_id = request.get("source_shot_id", "")  # optional, for audit trail

    if not project or not source_path or not target_shot_id:
        return JSONResponse({"error": "project, source_path, target_shot_id required"}, status_code=400)

    try:
        project_path = PIPELINE_OUTPUTS_DIR / project
        shot_plan_path = project_path / "shot_plan.json"

        with open(shot_plan_path, 'r') as f:
            shot_plan = _sp_guard(json.load(f))

        shots = shot_plan.get("shots", [])
        target_shot = next((s for s in shots if s.get("shot_id") == target_shot_id), None)
        if not target_shot:
            return {"success": False, "error": f"Target shot {target_shot_id} not found"}

        # Resolve source path
        src_p = Path(source_path)
        if not src_p.exists():
            # Try path translation (same logic as select-variant)
            if "/api/media?path=" in source_path:
                src_p = Path(source_path.replace("/api/media?path=", ""))
            if not src_p.exists():
                fname = Path(source_path).name
                for subdir in ["first_frame_variants", "first_frames"]:
                    candidate = project_path / subdir / fname
                    if candidate.exists():
                        src_p = candidate
                        break
        if not src_p.exists():
            return {"success": False, "error": f"Source file not found: {source_path}"}

        # Copy to target shot's first frame
        # V22.2: Fallback chain for macOS permission issues
        import shutil
        first_frames_dir = project_path / "first_frames"
        first_frames_dir.mkdir(exist_ok=True)
        dest = first_frames_dir / f"{target_shot_id}.jpg"
        try:
            shutil.copy2(str(src_p), str(dest))
        except PermissionError:
            # Fallback 1: copy without metadata preservation
            try:
                shutil.copy(str(src_p), str(dest))
            except PermissionError:
                # Fallback 2: raw binary read/write
                with open(str(src_p), 'rb') as sf:
                    img_data = sf.read()
                with open(str(dest), 'wb') as df:
                    df.write(img_data)
                logger.warning(f"[APPLY-VARIANT] Used raw copy fallback for {target_shot_id} (permission workaround)")

        # Update target shot metadata
        target_shot["first_frame_path"] = str(dest)
        target_shot["first_frame_url"] = f"/api/media?path={dest}"
        target_shot["generation_status"] = "completed"
        target_shot["_reused_from"] = source_shot_id or str(src_p.name)

        # V18.3.1: PRESERVE chain metadata (DO NOT RE-BREAK rule 102)
        if target_shot.get("_chain_first_frame_url") or target_shot.get("_chain_source"):
            target_shot["_variant_override"] = True
            target_shot["_variant_source_path"] = str(src_p)
            logger.info(f"[APPLY-VARIANT] Chain shot {target_shot_id}: variant applied, chain metadata preserved")

        with open(shot_plan_path, 'w') as f:
            json.dump(shot_plan, f, indent=2, default=str)

        # Invalidate cache
        cache_dir = project_path / "ui_cache"
        if cache_dir.exists():
            (cache_dir / "bundle.dirty").touch()

        logger.info(f"[V17.8 VARIANT-REUSE] Applied {src_p.name} → {target_shot_id}")
        return {
            "success": True,
            "target_shot_id": target_shot_id,
            "source": str(src_p.name),
            "path": str(dest),
            "url": f"/api/media?path={dest}"
        }

    except Exception as e:
        logger.error(f"[VARIANT-REUSE] Error: {e}")
        return {"success": False, "error": str(e)}


@app.post("/api/v17/regenerate-with-wardrobe")
async def regenerate_with_wardrobe(request: Dict = Body(...)):
    """
    V17.8 REGENERATE SHOT WITH UPDATED WARDROBE
    Re-generates a shot's first frame after injecting the latest wardrobe
    from wardrobe.json + cast_map into the prompt. Forces wardrobe refresh.
    """
    project = request.get("project")
    shot_id = request.get("shot_id")

    if not project or not shot_id:
        return JSONResponse({"error": "project and shot_id required"}, status_code=400)

    try:
        project_path = PIPELINE_OUTPUTS_DIR / project
        shot_plan_path = project_path / "shot_plan.json"

        with open(shot_plan_path, 'r') as f:
            shot_plan = _sp_guard(json.load(f))

        shots = shot_plan.get("shots", [])
        shot = next((s for s in shots if s.get("shot_id") == shot_id), None)
        if not shot:
            return {"success": False, "error": f"Shot {shot_id} not found"}

        # Force wardrobe injection from latest wardrobe.json
        wardrobe_refreshed = False
        try:
            from atlas_agents.wardrobe_extras_agent import (
                get_wardrobe_for_shot, auto_assign_wardrobe
            )
            wardrobe_path = project_path / "wardrobe.json"
            if not wardrobe_path.exists():
                auto_assign_wardrobe(project, str(project_path.parent))
            wardrobe_info = get_wardrobe_for_shot(shot, project, str(project_path.parent))
            if wardrobe_info:
                # Strip old wardrobe from nano_prompt and inject fresh
                nano = shot.get("nano_prompt", "")
                # Remove old "wearing:" clauses
                import re
                nano = re.sub(r'\b\w+\s+wearing\s*:\s*[^.]+\.?\s*', '', nano)
                nano = re.sub(r'\bwardrobe continuity[^.]+\.?\s*', '', nano)
                # Inject fresh wardrobe
                wardrobe_tag = wardrobe_info.get("wardrobe_tag", "")
                char_name = wardrobe_info.get("character", "")
                if wardrobe_tag and char_name:
                    nano += f". {char_name} wearing: {wardrobe_tag}"
                    shot["nano_prompt"] = nano
                    wardrobe_refreshed = True
                    logger.info(f"[V17.8 REGEN-WARDROBE] Injected wardrobe for {char_name}: {wardrobe_tag}")
        except Exception as wd_err:
            logger.warning(f"[V17.8 REGEN-WARDROBE] Wardrobe injection failed (non-blocking): {wd_err}")

        # Mark shot for regeneration
        shot["generation_status"] = "pending"
        shot["_wardrobe_refreshed"] = True

        with open(shot_plan_path, 'w') as f:
            json.dump(shot_plan, f, indent=2, default=str)

        # Now trigger single-shot generation
        # We'll call generate-first-frames with shot_ids filter
        gen_result = {"wardrobe_refreshed": wardrobe_refreshed, "shot_id": shot_id}

        # Invalidate cache
        cache_dir = project_path / "ui_cache"
        if cache_dir.exists():
            (cache_dir / "bundle.dirty").touch()

        return {
            "success": True,
            "shot_id": shot_id,
            "wardrobe_refreshed": wardrobe_refreshed,
            "message": f"Shot {shot_id} marked for regeneration with updated wardrobe. Run generate-first-frames to regenerate."
        }

    except Exception as e:
        logger.error(f"[REGEN-WARDROBE] Error: {e}")
        return {"success": False, "error": str(e)}


@app.post("/api/v17/auto/verify-variants")
async def verify_variants(request: Dict = Body(...)):
    """
    V17.5 DINO VERIFY VARIANTS
    Run DINO face scoring on multiple variant images for comparison.
    """
    project = request.get("project")
    shot_id = request.get("shot_id")
    variant_paths = request.get("variant_paths", [])

    if not project or not shot_id:
        return JSONResponse({"error": "project and shot_id required"}, status_code=400)

    try:
        project_path = PIPELINE_OUTPUTS_DIR / project
        shot_plan_path = project_path / "shot_plan.json"

        with open(shot_plan_path, 'r') as f:
            shot_plan = _sp_guard(json.load(f))

        shot = next((s for s in shot_plan.get("shots", []) if s.get("shot_id") == shot_id), None)
        char_ref = shot.get("character_reference_url", "") if shot else ""
        ref_path = char_ref.replace("/api/media?path=", "") if "/api/media" in char_ref else char_ref
        base_prompt = shot.get("nano_prompt", "") if shot else ""

        scores = []
        best_face = -1
        best_idx = 0

        for i, vpath in enumerate(variant_paths):
            score_entry = {"face_score": 0.0, "hybrid_score": 0.0, "recommended": False}
            if vpath and Path(vpath).exists() and ref_path and Path(ref_path).exists():
                try:
                    from dino_clip_analyzer import get_hybrid_analyzer
                    analyzer = get_hybrid_analyzer()
                    result = analyzer.analyze_comprehensive(vpath, ref_path, base_prompt)
                    score_entry["face_score"] = result.get("dino_face", 0.0)
                    score_entry["hybrid_score"] = result.get("hybrid_score", 0.0)
                except Exception as de:
                    logger.warning(f"[VERIFY-VARIANTS] DINO failed for variant {i}: {de}")
            scores.append(score_entry)
            if score_entry["face_score"] > best_face:
                best_face = score_entry["face_score"]
                best_idx = i

        if scores:
            scores[best_idx]["recommended"] = True

        return {"success": True, "shot_id": shot_id, "scores": scores}

    except Exception as e:
        logger.error(f"[VERIFY-VARIANTS] Error: {e}")
        return {"success": False, "error": str(e)}


@app.post("/api/v17/shot/capture-last-frame")
async def capture_last_frame(request: Dict = Body(...)):
    """
    V17.7 SHOT CHAINING: Extract last frame from a shot's video
    and set it as the continuity reference for the next shot.
    Enables visual continuity for blocking, placement, lighting.
    """
    project = request.get("project")
    source_shot_id = request.get("source_shot_id")
    target_shot_id = request.get("target_shot_id")

    if not project or not source_shot_id:
        return JSONResponse({"error": "project, source_shot_id required"}, status_code=400)

    try:
        project_path = PIPELINE_OUTPUTS_DIR / project
        shot_plan_path = project_path / "shot_plan.json"

        with open(shot_plan_path, 'r') as f:
            shot_plan = _sp_guard(json.load(f))

        shots = shot_plan.get("shots", [])
        source = next((s for s in shots if s.get("shot_id") == source_shot_id), None)
        if not source:
            return {"success": False, "error": f"Source shot {source_shot_id} not found"}

        # Find video path
        video_path = source.get("video_path") or source.get("video_url", "")
        if video_path.startswith("/api/media?path="):
            video_path = video_path.split("path=", 1)[1]
        if not video_path or not Path(video_path).exists():
            # Fallback: check videos directory
            video_dir = project_path / "videos"
            candidates = list(video_dir.glob(f"{source_shot_id}*.*")) if video_dir.exists() else []
            if candidates:
                video_path = str(candidates[0])
            else:
                # No video — use the first frame instead
                ff_path = source.get("first_frame_path", "")
                if ff_path and Path(ff_path).exists():
                    # Just use the first frame as continuity ref
                    continuity_url = f"/api/media?path={ff_path}"
                    if target_shot_id:
                        target = next((s for s in shots if s.get("shot_id") == target_shot_id), None)
                        if target:
                            target["continuity_ref_url"] = continuity_url
                            target["continuity_ref_path"] = ff_path
                            target["continuity_source"] = source_shot_id
                            with open(shot_plan_path, 'w') as f:
                                json.dump(shot_plan, f, indent=2, default=str)
                            _invalidate_bundle_cache(project)
                    return {"success": True, "url": continuity_url, "path": ff_path, "source": "first_frame",
                            "message": f"Using first frame from {source_shot_id} (no video available)"}
                return {"success": False, "error": f"No video or frame found for {source_shot_id}"}

        # Extract last frame using FFmpeg
        continuity_dir = project_path / "continuity_refs"
        continuity_dir.mkdir(exist_ok=True)
        output_path = continuity_dir / f"{source_shot_id}_last_frame.jpg"

        import subprocess
        cmd = f'ffmpeg -y -sseof -0.1 -i "{video_path}" -frames:v 1 -q:v 2 "{output_path}"'
        result = subprocess.run(cmd, shell=True, capture_output=True, timeout=30)

        if result.returncode != 0 or not output_path.exists():
            # Fallback: try extracting from end differently
            cmd2 = f'ffmpeg -y -i "{video_path}" -vf "select=eq(n\\,0)" -frames:v 1 -q:v 2 "{output_path}"'
            # Actually use last frame approach: seek to near end
            duration_cmd = f'ffprobe -v error -show_entries format=duration -of default=noprint_wrappers=1:nokey=1 "{video_path}"'
            dur_result = subprocess.run(duration_cmd, shell=True, capture_output=True, timeout=10, text=True)
            duration = float(dur_result.stdout.strip()) if dur_result.stdout.strip() else 5.0
            seek = max(0, duration - 0.1)
            cmd3 = f'ffmpeg -y -ss {seek} -i "{video_path}" -frames:v 1 -q:v 2 "{output_path}"'
            subprocess.run(cmd3, shell=True, capture_output=True, timeout=30)

        if not output_path.exists():
            return {"success": False, "error": "Failed to extract last frame from video"}

        continuity_url = f"/api/media?path={output_path}"

        # If target shot specified, wire it up
        if target_shot_id:
            target = next((s for s in shots if s.get("shot_id") == target_shot_id), None)
            if target:
                target["continuity_ref_url"] = continuity_url
                target["continuity_ref_path"] = str(output_path)
                target["continuity_source"] = source_shot_id
                with open(shot_plan_path, 'w') as f:
                    json.dump(shot_plan, f, indent=2, default=str)
                _invalidate_bundle_cache(project)

        logger.info(f"[CAPTURE-LAST-FRAME] Extracted last frame from {source_shot_id} → {output_path}")
        return {"success": True, "url": continuity_url, "path": str(output_path), "source": "last_frame",
                "source_shot": source_shot_id, "target_shot": target_shot_id}

    except Exception as e:
        logger.error(f"[CAPTURE-LAST-FRAME] Error: {e}")
        return {"success": False, "error": str(e)}


@app.post("/api/v17/shot/upload-ref-image")
async def upload_ref_image(request: Request):
    """
    V17.7 Upload a custom reference image for a shot's continuity/generation.
    Accepts multipart form data with 'image' file and 'project', 'shot_id' fields.
    """
    try:
        form = await request.form()
        project = form.get("project", "")
        shot_id = form.get("shot_id", "")
        ref_type = form.get("ref_type", "continuity")  # continuity, character, location
        image_file = form.get("image")

        if not project or not shot_id or not image_file:
            return JSONResponse({"error": "project, shot_id, image required"}, status_code=400)

        project_path = PIPELINE_OUTPUTS_DIR / project
        ref_dir = project_path / "continuity_refs"
        ref_dir.mkdir(exist_ok=True)

        # Save uploaded file
        contents = await image_file.read()
        ext = Path(image_file.filename).suffix or ".jpg"
        dest = ref_dir / f"{shot_id}_{ref_type}_ref{ext}"
        with open(dest, 'wb') as f:
            f.write(contents)

        ref_url = f"/api/media?path={dest}"

        # Update shot plan
        shot_plan_path = project_path / "shot_plan.json"
        if shot_plan_path.exists():
            with open(shot_plan_path, 'r') as f:
                shot_plan = _sp_guard(json.load(f))
            shot = next((s for s in shot_plan.get("shots", []) if s.get("shot_id") == shot_id), None)
            if shot:
                if ref_type == "continuity":
                    shot["continuity_ref_url"] = ref_url
                    shot["continuity_ref_path"] = str(dest)
                elif ref_type == "character":
                    shot["character_reference_url"] = ref_url
                elif ref_type == "location":
                    shot["location_master_url"] = ref_url
                with open(shot_plan_path, 'w') as f:
                    json.dump(shot_plan, f, indent=2, default=str)
                _invalidate_bundle_cache(project)

        logger.info(f"[UPLOAD-REF] {ref_type} ref for {shot_id}: {dest}")
        return {"success": True, "url": ref_url, "path": str(dest), "ref_type": ref_type}

    except Exception as e:
        logger.error(f"[UPLOAD-REF] Error: {e}")
        return {"success": False, "error": str(e)}


@app.post("/api/v17/shot/upload-first-frame")
async def upload_first_frame(request: Request):
    """
    V17.7 Upload a custom first frame image for a shot.
    Replaces or creates the first frame JPG for the given shot.
    Accepts multipart form data with 'image' file and 'project', 'shot_id' fields.
    """
    try:
        form = await request.form()
        project = form.get("project", "")
        shot_id = form.get("shot_id", "")
        image_file = form.get("image")

        if not project or not shot_id or not image_file:
            return JSONResponse({"error": "project, shot_id, image required"}, status_code=400)

        project_path = PIPELINE_OUTPUTS_DIR / project
        first_frames_dir = project_path / "first_frames"
        first_frames_dir.mkdir(parents=True, exist_ok=True)

        # Save uploaded file as the shot's first frame
        contents = await image_file.read()
        dest = first_frames_dir / f"{shot_id}.jpg"

        # Backup existing frame if present
        if dest.exists():
            backup = first_frames_dir / f"{shot_id}_backup_{int(time.time())}.jpg"
            import shutil
            shutil.copy2(str(dest), str(backup))
            logger.info(f"[UPLOAD-FRAME] Backed up existing frame: {backup}")

        with open(dest, 'wb') as f:
            f.write(contents)

        frame_url = f"/api/media?path={dest}"

        # Update shot plan with frame reference
        shot_plan_path = project_path / "shot_plan.json"
        if shot_plan_path.exists():
            with open(shot_plan_path, 'r') as f:
                shot_plan = _sp_guard(json.load(f))
            shot = next((s for s in shot_plan.get("shots", []) if s.get("shot_id") == shot_id), None)
            if shot:
                shot["first_frame_url"] = frame_url
                shot["first_frame_path"] = str(dest)
                shot["_frame_source"] = "user_upload"
                with open(shot_plan_path, 'w') as f:
                    json.dump(shot_plan, f, indent=2, default=str)
            _invalidate_bundle_cache(project)

        logger.info(f"[UPLOAD-FRAME] First frame uploaded for {shot_id}: {dest} ({len(contents)} bytes)")
        return {"success": True, "url": frame_url, "path": str(dest), "shot_id": shot_id, "size": len(contents)}

    except Exception as e:
        logger.error(f"[UPLOAD-FRAME] Error: {e}")
        return {"success": False, "error": str(e)}


@app.post("/api/v17/shot/update-field")
async def update_shot_field(request: Dict = Body(...)):
    """
    V17.7 Quick inline field update for a single shot.
    Supports: characters, location, type, duration, camera_body, lens_specs, camera_style, lens_type
    """
    project = request.get("project")
    shot_id = request.get("shot_id")
    field = request.get("field")
    value = request.get("value")

    if not project or not shot_id or not field:
        return JSONResponse({"error": "project, shot_id, field required"}, status_code=400)

    ALLOWED_FIELDS = {"characters", "location", "type", "shot_type", "duration",
                      "camera_body", "lens_specs", "camera_style", "lens_type",
                      "nano_prompt", "ltx_motion_prompt", "lighting",
                      "character_reference_url", "location_master_url", "continuity_ref_url"}
    if field not in ALLOWED_FIELDS:
        return {"success": False, "error": f"Field '{field}' not allowed. Allowed: {', '.join(sorted(ALLOWED_FIELDS))}"}

    try:
        project_path = PIPELINE_OUTPUTS_DIR / project
        shot_plan_path = project_path / "shot_plan.json"
        with open(shot_plan_path, 'r') as f:
            shot_plan = _sp_guard(json.load(f))

        shot = next((s for s in shot_plan.get("shots", []) if s.get("shot_id") == shot_id), None)
        if not shot:
            return {"success": False, "error": f"Shot {shot_id} not found"}

        old_value = shot.get(field)
        shot[field] = value

        with open(shot_plan_path, 'w') as f:
            json.dump(shot_plan, f, indent=2, default=str)
        _invalidate_bundle_cache(project)

        logger.info(f"[UPDATE-FIELD] {shot_id}.{field}: {old_value} → {value}")
        return {"success": True, "shot_id": shot_id, "field": field, "old_value": old_value, "new_value": value}

    except Exception as e:
        logger.error(f"[UPDATE-FIELD] Error: {e}")
        return {"success": False, "error": str(e)}


@app.post("/api/v17/shot/scene-transition")
async def add_scene_transition(request: Dict = Body(...)):
    """
    V21.10: SCENE TRANSITION — 3-shot atmosphere-matched bridge sequence.
    Reads the target scene's location/atmosphere from shot_plan and generates
    3 B-roll shots: wide establishing, street-level, building exterior detail.
    All shots are _broll=True, _no_chain=True, no characters.
    """
    try:
        project = request.get("project", "")
        after_shot = request.get("after_shot", "")
        scene_id = request.get("scene_id", "")
        target_location = request.get("target_location", "")
        custom_description = request.get("custom_description", "")
        generate_immediately = request.get("generate_immediately", False)

        if not project:
            return {"success": False, "error": "No project specified"}

        project_path = Path(f"pipeline_outputs/{project}")
        shot_plan_path = project_path / "shot_plan.json"
        if not shot_plan_path.exists():
            return {"success": False, "error": "No shot plan found"}

        with open(shot_plan_path) as f:
            sp_data = json.load(f)
        shots = sp_data if isinstance(sp_data, list) else sp_data.get("shots", [])

        # Find the target scene's atmosphere from adjacent shots
        target_scene_id = None
        after_idx = None
        for i, s in enumerate(shots):
            if s.get("shot_id") == after_shot:
                after_idx = i
                # Look at the NEXT scene after this shot
                for j in range(i + 1, min(i + 10, len(shots))):
                    next_sid = shots[j].get("scene_id", shots[j].get("shot_id", "")[:3])
                    current_sid = s.get("scene_id", s.get("shot_id", "")[:3])
                    if next_sid != current_sid:
                        target_scene_id = next_sid
                        break
                break

        if after_idx is None:
            return {"success": False, "error": f"Shot {after_shot} not found"}

        # Extract atmosphere from target scene shots
        atmosphere_keywords = []
        target_location_desc = target_location
        target_nano_sample = ""
        for s in shots:
            sid = s.get("scene_id", s.get("shot_id", "")[:3])
            if sid == target_scene_id:
                nano = s.get("nano_prompt", "")
                loc = s.get("location", "")
                if loc and not target_location_desc:
                    target_location_desc = loc
                if nano and not target_nano_sample:
                    target_nano_sample = nano
                # Extract weather/time/mood keywords
                for kw in ["rain", "fog", "mist", "overcast", "grey", "gray", "dawn", "morning",
                           "night", "dusk", "snow", "storm", "sunny", "warm", "cold", "dark",
                           "dim", "fluorescent", "dirty", "grimy", "cramped", "elegant", "gothic"]:
                    if kw in nano.lower() and kw not in atmosphere_keywords:
                        atmosphere_keywords.append(kw)
                if len(atmosphere_keywords) >= 8:
                    break

        # Determine time of day and weather from location and atmosphere
        is_rainy = "rain" in atmosphere_keywords
        is_morning = "morning" in atmosphere_keywords or "dawn" in atmosphere_keywords or "MORNING" in target_location_desc.upper()
        is_night = "night" in atmosphere_keywords or "NIGHT" in target_location_desc.upper()
        is_grimy = any(k in atmosphere_keywords for k in ["dirty", "grimy", "cramped", "dim", "fluorescent"])
        is_gothic = any(k in atmosphere_keywords for k in ["gothic", "dark", "fog", "mist"])

        # Build atmosphere string
        weather = "rain falling steadily, wet surfaces, grey overcast sky" if is_rainy else \
                  "fog drifting between buildings, muted overcast light" if is_gothic else \
                  "grey overcast sky, muted natural light"
        time_of_day = "early morning" if is_morning else "night" if is_night else "grey daylight"
        urban_feel = "grimy urban, cheap buildings, shuttered shops, overflowing bins" if is_grimy else \
                     "gothic architecture, stone buildings, ornate facades" if is_gothic else \
                     "atmospheric architecture, weathered buildings"
        color_grade = "cold muted desaturated blues and greys" if is_rainy or is_grimy else \
                      "muted dark tones, deep shadows" if is_night else \
                      "muted natural tones, film grain"
        neg = "NO grid, NO morphing, NO split screen, NO collage, NO bright colors, NO sunshine" if is_rainy else \
              "NO grid, NO morphing, NO split screen, NO collage"

        # Build 3 transition shots
        transition_shots = [
            {
                "shot_id": f"{scene_id}_TS1B",
                "scene_id": scene_id,
                "shot_type": "establishing",
                "duration": 6, "duration_seconds": 6, "ltx_duration_seconds": 6,
                "characters": [],
                "location": f"EXT. CITY SKYLINE - {time_of_day.upper()}",
                "nano_prompt": f"Wide view of city skyline in {time_of_day}, {weather}, {urban_feel}, {color_grade}. Film grain. 16:9 cinematic. {neg}.",
                "ltx_motion_prompt": f"camera slowly pushes in over cityscape, controlled movement, {weather}, {time_of_day} atmosphere, 6s, slow dolly, measured deliberate tempo.",
                "coverage_role": "A_GEOGRAPHY", "shot_role": "GEOGRAPHY",
                "_broll": True, "_no_chain": True,
                "_inserted_by": "scene_transition_v21"
            },
            {
                "shot_id": f"{scene_id}_TS2B",
                "scene_id": scene_id,
                "shot_type": "establishing",
                "duration": 5, "duration_seconds": 5, "ltx_duration_seconds": 5,
                "characters": [],
                "location": f"EXT. CITY STREET - {time_of_day.upper()}",
                "nano_prompt": f"Street-level view of city street in {time_of_day}, {weather}, {urban_feel}, {color_grade}. Film grain. 16:9 cinematic. {neg}.",
                "ltx_motion_prompt": f"camera glides at street level, slow tracking, {weather}, {time_of_day} atmosphere, 5s, slow tracking, measured deliberate tempo.",
                "coverage_role": "A_GEOGRAPHY", "shot_role": "GEOGRAPHY",
                "_broll": True, "_no_chain": True,
                "_inserted_by": "scene_transition_v21"
            },
            {
                "shot_id": f"{scene_id}_TS3B",
                "scene_id": scene_id,
                "shot_type": "detail",
                "duration": 5, "duration_seconds": 5, "ltx_duration_seconds": 5,
                "characters": [],
                "location": f"EXT. BUILDING EXTERIOR - {time_of_day.upper()}",
                "nano_prompt": f"Looking up at building facade in {time_of_day}, {weather}, {color_grade}. Point of view as if approaching. Film grain. 16:9 cinematic. {neg}.",
                "ltx_motion_prompt": f"camera slowly tilts up along building facade, {weather}, gentle controlled movement, 5s, slow tilt, measured deliberate tempo.",
                "coverage_role": "A_GEOGRAPHY", "shot_role": "GEOGRAPHY",
                "_broll": True, "_no_chain": True,
                "_inserted_by": "scene_transition_v21"
            }
        ]

        # Apply custom description override if provided
        if custom_description and "[AUTO-GENERATED]" not in custom_description:
            for ts in transition_shots:
                ts["nano_prompt"] = custom_description + f". {color_grade}. Film grain. 16:9 cinematic. {neg}."

        # Insert after the specified shot
        for j, ts in enumerate(transition_shots):
            shots.insert(after_idx + 1 + j, ts)

        # Save
        if isinstance(sp_data, list):
            with open(shot_plan_path, "w") as f:
                json.dump(shots, f, indent=2)
        else:
            sp_data["shots"] = shots
            with open(shot_plan_path, "w") as f:
                json.dump(sp_data, f, indent=2)

        # Invalidate cache
        dirty_path = project_path / "ui_cache" / ".dirty"
        dirty_path.parent.mkdir(exist_ok=True)
        dirty_path.touch()

        logger.info(f"[SCENE-TRANSITION] Added 3 shots after {after_shot} for scene {target_scene_id} "
                     f"(atmosphere: {', '.join(atmosphere_keywords[:5])})")

        return {
            "success": True,
            "shots_added": 3,
            "shot_ids": [ts["shot_id"] for ts in transition_shots],
            "atmosphere_detected": atmosphere_keywords,
            "target_scene": target_scene_id,
            "target_location": target_location_desc
        }

    except Exception as e:
        logger.error(f"[SCENE-TRANSITION] Error: {e}", exc_info=True)
        return {"success": False, "error": str(e)}


@app.post("/api/v17/shot/quick-add")
async def quick_add_shot(request: Dict = Body(...)):
    """
    V17.3 CONVERSATIONAL SHOT ADDITION
    Add a shot to any scene with minimal input. Designed for quick creative decisions.

    Body:
    {
        "project": "ravencroft_v17",
        "scene_id": "001",
        "description": "Extreme close-up of candle flame flickering, wax dripping onto chalk symbols",
        "shot_type": "insert",           // optional, auto-detected from description
        "position": "after:001_003A",    // optional: "start", "end", "after:SHOT_ID", "before:SHOT_ID"
        "duration": 6,                   // optional, defaults by type
        "characters": [],                // optional
        "lens": "100mm",                 // optional
        "camera_style": "static",        // optional
        "generate_immediately": false    // optional: auto-generate first frame
    }
    """
    project = request.get("project")
    scene_id = request.get("scene_id", "")
    description = request.get("description", "")
    shot_type = request.get("shot_type", "")
    position = request.get("position", "end")
    after_shot_id = request.get("after_shot_id", "")  # V17.5.1: UI sends this from insert modal
    before_shot_id = request.get("before_shot_id", "")  # V17.7: Insert BEFORE a shot
    duration = request.get("duration", 0)
    characters = request.get("characters", [])
    lens = request.get("lens", "")
    # V22.6: Previs Studio sends pre-built prompts directly
    _previs_nano = request.get("nano_prompt", "")
    _previs_ltx = request.get("ltx_motion_prompt", "")
    _previs_mode = request.get("_previs_studio", False)
    _previs_char_ref = request.get("character_reference_url", "")
    _previs_ref_urls = request.get("_reference_urls", [])
    _previs_camera_body = request.get("camera_body", "")
    _previs_lens_type = request.get("lens_type", "")
    camera_style = request.get("camera_style", "static")
    generate_now = request.get("generate_immediately", False)
    location_override = request.get("location", "")  # V17.3: Override location (pick from dropdown)
    location_master_name = request.get("location_master", "")  # V17.3: Attach specific location master
    video_mode = request.get("video_mode", "")  # V17.3: "t2v" for text-to-video inheriting aesthetics

    # V17.7: Auto-derive scene_id from before_shot_id if provided
    if not scene_id and before_shot_id:
        import re
        m = re.match(r'^(\d{3})', before_shot_id)
        if m:
            scene_id = m.group(1)
            position = f"before:{before_shot_id}"

    # V17.5.1: Auto-derive scene_id from after_shot_id if not provided
    if not scene_id and after_shot_id:
        import re
        m = re.match(r'^(\d{3})', after_shot_id)
        if m:
            scene_id = m.group(1)
            position = f"after:{after_shot_id}"

    # V22.6: Accept either description (conversational) OR nano_prompt (Previs Studio)
    if not project or (not description and not _previs_nano):
        return {"success": False, "error": "project and description (or nano_prompt) are required"}
    # If Previs Studio mode, use nano_prompt as description fallback for shot type detection
    if not description and _previs_nano:
        description = _previs_nano[:200]
    if not scene_id:
        return {"success": False, "error": "scene_id or after_shot_id is required"}

    project_path = get_project_path(project)
    shot_plan_path = project_path / "shot_plan.json"

    if not shot_plan_path.exists():
        return {"success": False, "error": f"Project '{project}' not found"}

    with open(shot_plan_path) as f:
        shot_plan = _sp_guard(json.load(f))

    shots = shot_plan.get("shots", [])
    scene_shots = [s for s in shots if s.get("scene_id") == scene_id]

    if not scene_shots:
        return {"success": False, "error": f"Scene '{scene_id}' not found in shot plan"}

    # Auto-detect shot type from description
    desc_lower = description.lower()
    if not shot_type:
        if any(w in desc_lower for w in ["extreme close", "ecu", "macro", "detail", "insert", "texture"]):
            shot_type = "insert"
        elif any(w in desc_lower for w in ["close-up", "closeup", "close up", "face", "portrait"]):
            shot_type = "close-up"
        elif any(w in desc_lower for w in ["wide", "establishing", "exterior", "landscape"]):
            shot_type = "establishing"
        elif any(w in desc_lower for w in ["b-roll", "broll", "atmospheric", "mood", "ambient"]):
            shot_type = "b-roll"
        elif any(w in desc_lower for w in ["reaction", "reacts", "responds", "processing"]):
            shot_type = "reaction"
        elif any(w in desc_lower for w in ["over shoulder", "ots", "two shot"]):
            shot_type = "dialogue"
        else:
            shot_type = "action"

    # Auto-set defaults by shot type
    type_defaults = {
        "insert": {"duration": 5, "lens": "100mm", "camera": "static", "camera_body": "ARRI Alexa 35", "lens_type": "Macro"},
        "close-up": {"duration": 8, "lens": "85mm", "camera": "static", "camera_body": "ARRI Alexa 35", "lens_type": "Cooke S7/i Prime"},
        "establishing": {"duration": 10, "lens": "24mm", "camera": "slow_crane", "camera_body": "ARRI Alexa 35", "lens_type": "Anamorphic 2x"},
        "b-roll": {"duration": 6, "lens": "50mm", "camera": "static", "camera_body": "ARRI Alexa 35", "lens_type": "Cooke S7/i Prime"},
        "reaction": {"duration": 6, "lens": "85mm", "camera": "static", "camera_body": "ARRI Alexa 35", "lens_type": "Cooke S7/i Prime"},
        "dialogue": {"duration": 12, "lens": "50mm", "camera": "static", "camera_body": "ARRI Alexa 35", "lens_type": "Cooke S7/i Prime"},
        "action": {"duration": 10, "lens": "24mm", "camera": "handheld", "camera_body": "ARRI Alexa 35", "lens_type": "Zeiss Master Prime"},
    }
    defaults = type_defaults.get(shot_type, type_defaults["action"])
    if not duration:
        duration = defaults["duration"]
    if not lens:
        lens = defaults["lens"]

    # Get location from scene (or override)
    location = location_override or scene_shots[0].get("location", "")
    location_desc = scene_shots[0].get("location_description", "")

    # V17.3: Resolve location master URL if specified
    loc_master_url = ""
    if location_master_name:
        loc_dir = project_path / "location_masters"
        if loc_dir.exists():
            for img in loc_dir.glob("*.jpg"):
                if location_master_name.upper().replace(" ", "_") in img.stem.upper():
                    loc_master_url = f"/api/media?path={img}"
                    break

    # Generate shot_id
    existing_ids = sorted([s["shot_id"] for s in scene_shots])
    # Find next available suffix number
    max_num = max(int(sid.split("_")[1][:3]) for sid in existing_ids if "_" in sid)
    # Determine suffix letter based on type
    suffix = "B" if shot_type in ("insert", "b-roll") else "A" if shot_type in ("dialogue", "action", "establishing") else "R"
    new_shot_id = f"{scene_id}_{max_num + 1:03d}{suffix}"

    # Build the nano_prompt with V13 gold standard baked in
    genre = shot_plan.get("genre", "drama")

    # V22.6: Use pre-built prompts from Previs Studio if provided
    if _previs_mode and _previs_nano:
        nano_prompt = _previs_nano
        ltx_motion = _previs_ltx or f"face stable NO morphing, character consistent, cinematic {genre} atmosphere"
    else:
        nano_prompt = (
            f"{lens} {'ECU' if shot_type == 'insert' else 'CU' if shot_type == 'close-up' else 'MS'}, "
            f"composition: {'macro detail' if shot_type == 'insert' else 'tight framing'}, "
            f"{description}. "
            f"{'At ' + location + '. ' if location else ''}"
            f"{'Set in ' + location_desc[:80] + '. ' if location_desc else ''}"
            f"NO grid, NO collage, NO split screen, NO extra people, NO morphing faces, NO watermarks, NO text overlays"
        )
        # V25 CURE (Law 231): NO generic timing templates — action-driven direction
        _ltx_char_direction = ""
        if characters and description:
            _ltx_char_direction = f"character performs: {description[:150]}"
        elif description:
            _ltx_char_direction = description[:150]

        ltx_motion = (
            f"{_ltx_char_direction}. "
            f"{'face stable NO morphing, character consistent. ' if characters else 'NO morphing, NO face generation, environment only. '}"
            f"cinematic {genre} atmosphere"
        )

    # Build the complete shot entry
    new_shot = {
        "shot_id": new_shot_id,
        "scene_id": scene_id,
        "shot_type": shot_type,
        "framing": shot_type,
        "coverage_angle": suffix,
        "location": location,
        "location_description": location_desc,
        "characters": characters,
        "duration": duration,
        "duration_seconds": duration,
        "nano_prompt": nano_prompt,
        "ltx_motion_prompt": ltx_motion,
        "camera_body": _previs_camera_body or defaults.get("camera_body", "ARRI Alexa 35"),
        "camera_style": camera_style or defaults.get("camera", "static"),
        "lens_specs": lens,
        "lens_type": _previs_lens_type or defaults.get("lens_type", "Cooke S7/i Prime"),
        "is_establishing": shot_type == "establishing",
        "is_broll": shot_type in ("b-roll", "insert"),
        "location_master_url": loc_master_url if loc_master_url else None,
        "character_reference_url": _previs_char_ref if _previs_char_ref else None,
        "video_mode": video_mode if video_mode else None,  # "t2v" = text-to-video (no first frame needed)
        "_injected_by": "quick_add_v22.6" if _previs_mode else "quick_add_v17.3",
        "_injection_reason": f"previs_studio" if _previs_mode else f"conversational: {description[:60]}"
    }

    # Insert at correct position
    insert_index = len(shots)  # default: end
    if position == "start":
        insert_index = next((i for i, s in enumerate(shots) if s.get("scene_id") == scene_id), len(shots))
    elif position == "end":
        # After last shot in scene
        for i in range(len(shots) - 1, -1, -1):
            if shots[i].get("scene_id") == scene_id:
                insert_index = i + 1
                break
    elif position.startswith("after:"):
        target = position.split(":", 1)[1]
        for i, s in enumerate(shots):
            if s["shot_id"] == target:
                insert_index = i + 1
                break
    elif position.startswith("before:"):
        target = position.split(":", 1)[1]
        for i, s in enumerate(shots):
            if s["shot_id"] == target:
                insert_index = i
                break

    shots.insert(insert_index, new_shot)
    shot_plan["shots"] = shots

    # Stamp metadata
    try:
        stamp_metadata(shot_plan, project)
    except Exception:
        pass

    # Save
    with open(shot_plan_path, 'w') as f:
        json.dump(shot_plan, f, indent=2)

    # Invalidate UI cache
    cache_dir = project_path / "ui_cache"
    if cache_dir.exists():
        dirty = cache_dir / "bundle.dirty"
        dirty.touch()

    logger.info(f"[QUICK-ADD] Added {new_shot_id} to scene {scene_id}: {description[:60]}")

    result = {
        "success": True,
        "shot_id": new_shot_id,
        "scene_id": scene_id,
        "shot_type": shot_type,
        "position_index": insert_index,
        "total_shots": len(shots),
        "nano_prompt": nano_prompt[:200],
        "duration": duration,
        "message": f"Added {shot_type} shot {new_shot_id} to scene {scene_id}"
    }

    # Optionally generate first frame immediately
    if generate_now:
        try:
            gen_result = await generate_first_frames_sequential(
                {"project": project, "shot_ids": [new_shot_id], "force": True}
            )
            result["generation"] = gen_result
        except Exception as e:
            result["generation_error"] = str(e)

    return result


@app.post("/api/v17/shots/quick-add-batch")
async def quick_add_shots_batch(request: Dict = Body(...)):
    """
    V17.3 BATCH CONVERSATIONAL SHOT ADDITION
    Add multiple shots at once. Used by Claude Code for bulk creative additions.

    Body:
    {
        "project": "ravencroft_v17",
        "shots": [
            {"scene_id": "001", "description": "ECU candle flame dripping wax onto chalk symbols", "shot_type": "insert"},
            {"scene_id": "001", "description": "Close-up of Lady Margaret's trembling hands", "shot_type": "close-up", "characters": ["LADY MARGARET RAVENCROFT"]},
            ...
        ],
        "generate_immediately": false
    }
    """
    project = request.get("project")
    shot_list = request.get("shots", [])
    generate_now = request.get("generate_immediately", False)

    if not project or not shot_list:
        return {"success": False, "error": "project and shots[] required"}

    results = []
    for shot_def in shot_list:
        shot_def["project"] = project
        shot_def["generate_immediately"] = False  # batch gen after
        try:
            r = await quick_add_shot(shot_def)
            results.append(r)
        except Exception as e:
            results.append({"success": False, "error": str(e), "description": shot_def.get("description", "?")})

    added = [r for r in results if r.get("success")]

    # Optionally batch generate all new shots
    gen_result = None
    if generate_now and added:
        new_ids = [r["shot_id"] for r in added]
        try:
            gen_result = await generate_first_frames_sequential(
                {"project": project, "shot_ids": new_ids, "force": True}
            )
        except Exception as e:
            gen_result = {"error": str(e)}

    return {
        "success": True,
        "added": len(added),
        "failed": len(results) - len(added),
        "shots": results,
        "generation": gen_result
    }


@app.post("/api/shot-plan/approve-shot")
async def approve_shot(request: Dict = Body(...)):
    """V16.7.1: Approve or reject a shot for stitching."""
    project = request.get("project")
    shot_id = request.get("shot_id")
    approved = request.get("approved", True)
    reason = request.get("reason", "")

    if not project or not shot_id:
        return {"success": False, "error": "project and shot_id required"}

    shot_plan_path = get_project_path(project) / "shot_plan.json"
    if not shot_plan_path.exists():
        return {"success": False, "error": "Shot plan not found"}

    with open(shot_plan_path) as f:
        data = json.load(f)

    # V27.1: Handle both list format [shots...] and dict format {"shots": [...]}
    if isinstance(data, list):
        shots = data
        data = {"shots": data}
    else:
        shots = data.get("shots", [])
    updated = False
    for shot in shots:
        if shot.get("shot_id") == shot_id:
            shot["_approved"] = approved
            shot["_approved_at"] = datetime.now().isoformat()
            if reason:
                shot["_approval_reason"] = reason
            updated = True
            logger.info(f"[APPROVE_SHOT] {shot_id} {'approved' if approved else 'rejected'}")
            break

    if not updated:
        return {"success": False, "error": f"Shot {shot_id} not found"}

    # Update approval counts in metadata
    approved_count = sum(1 for s in shots if s.get("_approved"))
    data["_approval_stats"] = {
        "approved": approved_count,
        "total": len(shots),
        "last_updated": datetime.now().isoformat()
    }

    with open(shot_plan_path, 'w') as f:
        json.dump(data, f, indent=2)

    # Invalidate cache (both old dict cache + V18.2 dirty flag)
    try:
        if project in ui_bundle_cache:
            del ui_bundle_cache[project]
    except Exception:
        pass
    _invalidate_bundle_cache(project)

    return {
        "success": True,
        "project": project,
        "shot_id": shot_id,
        "approved": approved,
        "stats": data["_approval_stats"]
    }


@app.get("/api/shot-plan/approval-status/{project}")
async def get_approval_status(project: str):
    """V16.7.1: Get approval status for all shots."""
    shot_plan_path = get_project_path(project) / "shot_plan.json"
    if not shot_plan_path.exists():
        return {"success": False, "error": "Shot plan not found"}

    with open(shot_plan_path) as f:
        data = json.load(f)

    # V27.1: Handle both list format [shots...] and dict format {"shots": [...]}
    if isinstance(data, list):
        shots = data
        data = {"shots": data}
    else:
        shots = data.get("shots", [])
    approved = [s["shot_id"] for s in shots if s.get("_approved")]
    pending = [s["shot_id"] for s in shots if not s.get("_approved") and s.get("first_frame_path")]
    not_generated = [s["shot_id"] for s in shots if not s.get("first_frame_path")]

    return {
        "success": True,
        "project": project,
        "total": len(shots),
        "approved_count": len(approved),
        "pending_count": len(pending),
        "not_generated_count": len(not_generated),
        "approved": approved,
        "pending": pending,
        "not_generated": not_generated,
        "ready_for_stitch": len(approved) == len(shots) and len(shots) > 0
    }


