@app.post("/api/v16/temporal/start-episode")
async def start_temporal_episode(request: Dict = Body(...)):
    """
    Start a durable episode generation workflow.

    Body:
    {
        "project": "kord",
        "episode_id": "S01E01",  // optional
        "target_runtime_minutes": 45,
        "auto_approve": false,  // skip human gates in lab mode
        "skip_lock_check": false  // bypass lock validation (not recommended)
    }

    Returns workflow_id for tracking progress.
    """
    try:
        from temporal.client import start_episode_generation

        project = request.get("project")
        if not project:
            return {"error": "Project name required"}

        # =================================================================
        # V16.1 LOCK GATE: Validate project before starting render
        # =================================================================
        skip_lock_check = request.get("skip_lock_check", False)
        if not skip_lock_check and LOCK_SYSTEM_AVAILABLE:
            logger.info(f"[RENDER GATE] Validating locks for {project}")

            # Validate all 3 locks
            lock_results = validate_project_locks(project)

            if not lock_results.get("all_passed"):
                logger.warning(f"[RENDER GATE] Locks failed, attempting auto-fix")

                # Try to auto-fix
                fix_result = run_fixer_workflow(project, lock_results)

                if not fix_result.success:
                    # Still failing after fix - block render
                    return {
                        "error": "Render blocked by lock failures",
                        "lock_failures": lock_results,
                        "fix_attempted": True,
                        "remaining_issues": fix_result.remaining_issues,
                        "action": "Review FIX_REPORT.json and resolve blocking issues"
                    }

                logger.info(f"[RENDER GATE] Auto-fix successful, proceeding")
            else:
                logger.info(f"[RENDER GATE] All locks passed")

        result = await start_episode_generation(
            project_name=project,
            episode_id=request.get("episode_id"),
            target_runtime_minutes=request.get("target_runtime_minutes", 45),
            auto_approve=request.get("auto_approve", False),
        )
        return result
    except Exception as e:
        logger.error(f"Failed to start temporal workflow: {e}")
        return {"error": str(e)}


