# =============================================================================
# V16.0 ONE-CLICK PIPELINE - SCRIPT TO RENDER-READY
# =============================================================================

@app.post("/api/v16/prepare-project")
async def prepare_project_full_pipeline(request: Dict = Body(...)):
    """
    ONE-CLICK PIPELINE: Story Bible + Script → Render-Ready Project

    This endpoint chains ALL preparation steps automatically:
    1. Import script (if provided) or use existing
    2. Expand scenes to shots (SHOT_EXPANSION_INTEGRATOR)
    3. Auto-cast characters to AI actors
    4. Generate location masters
    5. Run fix-v13 (durations, beats, prompts, references)
    6. Optionally generate first frames

    Body:
    {
        "project": "my_movie",
        "story_bible": {...},           // Required: characters, locations, themes
        "script_text": "...",           // Optional: full screenplay text
        "runtime_minutes": 45,          // Target runtime
        "genre": "thriller",            // For casting/style
        "generate_first_frames": false, // If true, generates images (takes longer)
        "dry_run": false                // If true, just report what would happen
    }

    Returns progress for each step and final readiness status.
    """
    import httpx

    project = request.get("project", "")
    story_bible = request.get("story_bible", {})
    script_text = request.get("script_text", "")
    runtime_minutes = request.get("runtime_minutes", 45)
    genre = request.get("genre", "thriller")
    generate_first_frames = request.get("generate_first_frames", False)
    dry_run = request.get("dry_run", False)

    if not project:
        return {"success": False, "error": "Project name required"}

    if not story_bible and not script_text:
        return {"success": False, "error": "Either story_bible or script_text required"}

    project_path = get_project_path(project)
    project_path.mkdir(parents=True, exist_ok=True)

    pipeline_results = {
        "project": project,
        "steps": {},
        "dry_run": dry_run
    }

    logger.info(f"[PIPELINE] Starting one-click prepare for '{project}'")

    # =========================================================================
    # STEP 1: Save Story Bible
    # =========================================================================
    step_name = "1_story_bible"
    try:
        if story_bible:
            story_bible["_pipeline_imported"] = True
            story_bible["runtime_target_minutes"] = runtime_minutes
            story_bible["genre"] = genre

            if not dry_run:
                bible_path = project_path / "story_bible.json"
                with open(bible_path, "w") as f:
                    json.dump(story_bible, f, indent=2)

            pipeline_results["steps"][step_name] = {
                "status": "success",
                "characters": len(story_bible.get("characters", [])),
                "locations": len(story_bible.get("locations", []))
            }
            logger.info(f"[PIPELINE] Step 1: Story bible saved")
        else:
            pipeline_results["steps"][step_name] = {"status": "skipped", "reason": "No story_bible provided"}
    except Exception as e:
        pipeline_results["steps"][step_name] = {"status": "error", "error": str(e)}

    # =========================================================================
    # STEP 2: Process Script → Generate Scenes and Shots
    # =========================================================================
    step_name = "2_script_processing"
    try:
        if script_text:
            if not dry_run:
                # Save script
                script_path = project_path / "imported_script.txt"
                with open(script_path, "w") as f:
                    f.write(script_text)

                # Run LLM extraction
                try:
                    from LLM_SCRIPT_EXTRACTOR import run_full_extraction
                    manifest, metadata = run_full_extraction(
                        script_text=script_text,
                        project_name=project,
                        genre=genre,
                        enable_repair=True,
                        target_runtime_minutes=runtime_minutes
                    )
                    if manifest:
                        # Save manifest
                        shot_plan_path = project_path / "shot_plan.json"
                        with open(shot_plan_path, "w") as f:
                            json.dump(manifest, f, indent=2)
                        pipeline_results["steps"][step_name] = {
                            "status": "success",
                            "scenes": len(manifest.get("scene_manifest", [])),
                            "beats_extracted": manifest.get("_total_beats", 0)
                        }
                    else:
                        pipeline_results["steps"][step_name] = {"status": "error", "error": "Extraction failed"}
                except ImportError:
                    pipeline_results["steps"][step_name] = {"status": "error", "error": "LLM_SCRIPT_EXTRACTOR not available"}
            else:
                pipeline_results["steps"][step_name] = {"status": "dry_run", "would_process": len(script_text)}
        else:
            pipeline_results["steps"][step_name] = {"status": "skipped", "reason": "No script_text provided"}
    except Exception as e:
        pipeline_results["steps"][step_name] = {"status": "error", "error": str(e)}

    # =========================================================================
    # STEP 3: Expand Scenes to Shots (if needed)
    # =========================================================================
    step_name = "3_shot_expansion"
    try:
        shot_plan_path = project_path / "shot_plan.json"
        if shot_plan_path.exists():
            with open(shot_plan_path) as f:
                manifest = json.load(f)

            shots = manifest.get("shots", [])
            if not shots or manifest.get("_requires_shot_expansion", True):
                if not dry_run:
                    _v25_ok = False
                    try:
                        from tools.creative_pipeline_bridge import creative_expand_project
                        _cpb_genre = manifest.get("metadata", {}).get("genre", "mystery_thriller")
                        _cpb_runtime = manifest.get("metadata", {}).get("target_runtime", 600)
                        success, expanded, msg = creative_expand_project(
                            project, genre=_cpb_genre, target_runtime_seconds=_cpb_runtime
                        )
                        if success:
                            pipeline_results["steps"][step_name] = {
                                "status": "success",
                                "shots_created": len(expanded.get("shots", [])),
                                "engine": "creative_grammar"
                            }
                            _v25_ok = True
                    except Exception as _cpb_e:
                        logger.warning(f"[V25] Creative expansion failed: {_cpb_e}")

                    if not _v25_ok:
                        try:
                            from SHOT_EXPANSION_INTEGRATOR import expand_project_shots
                            success, expanded, msg = expand_project_shots(project)
                            if success:
                                pipeline_results["steps"][step_name] = {
                                    "status": "success",
                                    "shots_created": len(expanded.get("shots", [])),
                                    "engine": "legacy"
                                }
                            else:
                                pipeline_results["steps"][step_name] = {"status": "error", "error": msg}
                        except ImportError:
                            pipeline_results["steps"][step_name] = {"status": "error", "error": "No expansion engine available"}
                else:
                    pipeline_results["steps"][step_name] = {"status": "dry_run", "would_expand": True}
            else:
                pipeline_results["steps"][step_name] = {"status": "skipped", "reason": f"Already has {len(shots)} shots"}
        else:
            pipeline_results["steps"][step_name] = {"status": "skipped", "reason": "No shot_plan.json yet"}
    except Exception as e:
        pipeline_results["steps"][step_name] = {"status": "error", "error": str(e)}

    # =========================================================================
    # STEP 3B: Populate Story Bible from Entity Manifest (V16.1 FIX)
    # =========================================================================
    step_name = "3b_story_bible_population"
    try:
        shot_plan_path = project_path / "shot_plan.json"
        bible_path = project_path / "story_bible.json"

        if shot_plan_path.exists():
            with open(shot_plan_path) as f:
                manifest = json.load(f)

            entity_manifest = manifest.get("entity_manifest", {})
            em_chars = entity_manifest.get("characters", [])
            em_locs = entity_manifest.get("locations", [])

            # Load existing story bible or create new
            story_bible = {}
            if bible_path.exists():
                with open(bible_path) as f:
                    story_bible = json.load(f)

            # Populate from entity_manifest if story_bible is empty
            current_chars = story_bible.get("characters", [])
            current_locs = story_bible.get("locations", [])

            if not current_chars and em_chars:
                story_bible["characters"] = em_chars
                logger.info(f"[PIPELINE] Populated {len(em_chars)} characters from entity_manifest")

            if not current_locs and em_locs:
                story_bible["locations"] = em_locs
                logger.info(f"[PIPELINE] Populated {len(em_locs)} locations from entity_manifest")

            # Save if we made changes
            if em_chars or em_locs:
                story_bible["title"] = story_bible.get("title", project)
                story_bible["_populated_from_entity_manifest"] = True

                if not dry_run:
                    with open(bible_path, "w") as f:
                        json.dump(story_bible, f, indent=2)

                pipeline_results["steps"][step_name] = {
                    "status": "success",
                    "characters_populated": len(story_bible.get("characters", [])),
                    "locations_populated": len(story_bible.get("locations", []))
                }
            else:
                pipeline_results["steps"][step_name] = {"status": "skipped", "reason": "No entity_manifest data"}
        else:
            pipeline_results["steps"][step_name] = {"status": "skipped", "reason": "No shot_plan.json"}
    except Exception as e:
        pipeline_results["steps"][step_name] = {"status": "error", "error": str(e)}
        logger.error(f"[PIPELINE] Story bible population error: {e}")

    # =========================================================================
    # STEP 4: Auto-Cast Characters
    # =========================================================================
    step_name = "4_auto_cast"
    try:
        if not dry_run:
            # Call auto-cast endpoint internally
            cast_result = await auto_cast_project({"project": project})
            if cast_result.get("success"):
                pipeline_results["steps"][step_name] = {
                    "status": "success",
                    "characters_cast": cast_result.get("cast_count", 0)
                }
            else:
                pipeline_results["steps"][step_name] = {"status": "error", "error": cast_result.get("error", "Unknown")}
        else:
            pipeline_results["steps"][step_name] = {"status": "dry_run", "would_cast": True}
    except Exception as e:
        pipeline_results["steps"][step_name] = {"status": "error", "error": str(e)}

    # =========================================================================
    # STEP 5: Generate Location Masters (OPTIONAL - requires FAL API)
    # =========================================================================
    step_name = "5_location_masters"
    try:
        if not dry_run:
            loc_result = await generate_location_masters({"project": project, "max_locations": 15})
            if loc_result.get("success"):
                pipeline_results["steps"][step_name] = {
                    "status": "success",
                    "locations_generated": len(loc_result.get("generated", []))
                }
            else:
                # Non-blocking - mark as optional_skipped instead of error
                pipeline_results["steps"][step_name] = {
                    "status": "optional_skipped",
                    "reason": loc_result.get("error", "API unavailable"),
                    "note": "Location masters can be generated later via /api/auto/generate-location-masters"
                }
        else:
            pipeline_results["steps"][step_name] = {"status": "dry_run", "would_generate": True}
    except Exception as e:
        # Non-blocking error
        pipeline_results["steps"][step_name] = {
            "status": "optional_skipped",
            "reason": str(e),
            "note": "Location masters can be generated later"
        }

    # =========================================================================
    # STEP 6: Run fix-v13 (Intelligent Fixes)
    # =========================================================================
    step_name = "6_fix_v13"
    try:
        if not dry_run:
            fix_result = await fix_v13_issues({"project": project})
            if fix_result.get("status") == "success":
                pipeline_results["steps"][step_name] = {
                    "status": "success",
                    "shots_fixed": fix_result.get("fixed_count", 0),
                    "total_duration": fix_result.get("total_duration", 0),
                    "critic_grade": fix_result.get("critics", {}).get("director_critic", {}).get("grade", "N/A")
                }
            else:
                pipeline_results["steps"][step_name] = {"status": "error", "error": fix_result.get("error", "Unknown")}
        else:
            pipeline_results["steps"][step_name] = {"status": "dry_run", "would_fix": True}
    except Exception as e:
        pipeline_results["steps"][step_name] = {"status": "error", "error": str(e)}

    # =========================================================================
    # STEP 7: Generate First Frames (Optional)
    # =========================================================================
    step_name = "7_first_frames"
    if generate_first_frames:
        try:
            if not dry_run:
                frames_result = await generate_first_frames({"project": project})
                if frames_result.get("success"):
                    pipeline_results["steps"][step_name] = {
                        "status": "success",
                        "frames_generated": frames_result.get("summary", {}).get("generated", 0)
                    }
                else:
                    pipeline_results["steps"][step_name] = {"status": "error", "error": frames_result.get("error", "Unknown")}
            else:
                pipeline_results["steps"][step_name] = {"status": "dry_run", "would_generate": True}
        except Exception as e:
            pipeline_results["steps"][step_name] = {"status": "error", "error": str(e)}
    else:
        pipeline_results["steps"][step_name] = {"status": "skipped", "reason": "generate_first_frames=false"}

    # =========================================================================
    # FINAL: Calculate Readiness
    # =========================================================================
    # Required steps: 1-4 and 6 (story_bible, script, expansion, cast, fix)
    # Optional steps: 5 (location_masters), 7 (first_frames)
    required_steps = ["1_story_bible", "2_script_processing", "3_shot_expansion", "4_auto_cast", "6_fix_v13"]
    optional_steps = ["5_location_masters", "7_first_frames"]

    successful_steps = sum(1 for s in pipeline_results["steps"].values() if s.get("status") == "success")
    successful_required = sum(1 for k, v in pipeline_results["steps"].items()
                              if k in required_steps and v.get("status") == "success")
    total_required = len(required_steps)

    # Only count required step failures as blocking errors
    error_steps = [k for k, v in pipeline_results["steps"].items()
                   if k in required_steps and v.get("status") == "error"]
    optional_skipped = [k for k, v in pipeline_results["steps"].items()
                        if v.get("status") == "optional_skipped"]

    ready_for_render = len(error_steps) == 0 and successful_required >= 4

    pipeline_results["summary"] = {
        "successful_steps": successful_steps,
        "successful_required": successful_required,
        "total_required": total_required,
        "errors": error_steps,
        "optional_skipped": optional_skipped,
        "ready_for_render": ready_for_render,
        "next_step": "Run /api/v16/temporal/start-episode to begin rendering" if ready_for_render else f"Fix errors in: {error_steps}"
    }

    pipeline_results["success"] = ready_for_render

    logger.info(f"[PIPELINE] Complete: {successful_required}/{total_required} required steps successful")

    # =========================================================================
    # STEP 8: Create PROJECT_LOCK.json + Validate Locks
    # =========================================================================
    step_name = "8_lock_validation"
    try:
        # Import lock system inline to avoid circular import
        from ATLAS_LOCK_SYSTEM import create_project_lock, validate_project_locks, run_fixer_workflow

        if not dry_run:
            # Create project lock with current versions
            create_project_lock(project)

            # Validate all 3 locks
            lock_results = validate_project_locks(project)

            if not lock_results.get("all_passed"):
                # Try auto-fix
                fix_result = run_fixer_workflow(project, lock_results)
                pipeline_results["steps"][step_name] = {
                    "status": "fixed",
                    "fixes_applied": fix_result.fixes_applied,
                    "remaining_issues": fix_result.remaining_issues,
                }
            else:
                pipeline_results["steps"][step_name] = {
                    "status": "success",
                    "message": "All locks passed"
                }
        else:
            pipeline_results["steps"][step_name] = {"status": "skipped", "reason": "dry_run=true"}

        logger.info(f"[PIPELINE] Step 8: Lock validation complete")
    except ImportError:
        pipeline_results["steps"][step_name] = {"status": "skipped", "reason": "Lock system not available"}
    except Exception as e:
        pipeline_results["steps"][step_name] = {"status": "error", "error": str(e)}

    # =========================================================================
    # STEP 9: V16.2 VALIDATION GATES + CRITIC REPORT
    # =========================================================================
    step_name = "9_validation_gates"
    try:
        if not dry_run:
            validation_result = validate_project(project, auto_repair=True)

            if validation_result.get("status") == "success":
                final_state = validation_result.get("final_state", "UNKNOWN")
                gates = validation_result.get("gates", {})
                casting = validation_result.get("casting", {})

                pipeline_results["steps"][step_name] = {
                    "status": "success" if final_state == "APPROVED" else "warning",
                    "final_state": final_state,
                    "gates": {k: v["status"] for k, v in gates.items()},
                    "casting_validated": casting.get("validated", 0),
                    "casting_rejected": casting.get("rejected", 0),
                    "critic_report": str(validation_result.get("report_path", ""))
                }

                # If validation found issues, update ready_for_render
                if final_state != "APPROVED":
                    pipeline_results["summary"]["ready_for_render"] = False
                    pipeline_results["summary"]["validation_state"] = final_state
                    pipeline_results["success"] = False

                logger.info(f"[PIPELINE] Step 9: Validation gates - {final_state}")
            else:
                pipeline_results["steps"][step_name] = {
                    "status": "error",
                    "error": validation_result.get("message", "Validation failed")
                }
        else:
            pipeline_results["steps"][step_name] = {"status": "dry_run", "would_validate": True}
    except Exception as e:
        logger.error(f"[PIPELINE] Step 9 error: {e}")
        pipeline_results["steps"][step_name] = {"status": "error", "error": str(e)}

    return pipeline_results


# =============================================================================
# V17.3 PREVIS PIPELINE — ONE-CALL SETUP-TO-REVIEW
# =============================================================================

@app.post("/api/v17/previs-pipeline")
async def previs_pipeline(request: Dict = Body(...)):
    """
    V17.3 PREVIS PIPELINE: Chains the entire setup-to-review workflow into ONE call.
    Import a script, click one button, come back to review quality frames.

    Assumes the project already exists with a shot_plan.json (from script import).
    Chains these steps IN ORDER:
        1. Fix-V16 Auto-Setup (durations, camera defaults, V13 gold standard, ABC, segments)
        2. Auto-Cast (match characters to AI actors)
        3. Prompt Quality Validation (ellipsis, location mismatch, negatives, framing)
        4. Location Description Injection (bake story bible descriptions into prompts)
        5. Coverage Solver (grade cinematic coverage, auto-assign blocking roles)
        6. Generate Location Masters (if enabled) — create reference images
        7. Generate Character References (if enabled) — recast character images
        8. Generate First Frames (if enabled) — generate all frames with full refs

    Body:
    {
        "project": "project_name",
        "generate_location_masters": true,   // optional, default true
        "generate_character_refs": true,      // optional, default true
        "generate_first_frames": true,        // optional, default true
        "dry_run": false                      // optional, default false
    }

    In dry_run mode, steps 6-8 are skipped but everything else runs.
    Each step is wrapped in try/except so failures are logged but do not crash the pipeline.
    """
    import time as _time

    pipeline_start = _time.time()

    project = request.get("project", "")
    opt_location_masters = request.get("generate_location_masters", True)
    opt_character_refs = request.get("generate_character_refs", True)
    opt_first_frames = request.get("generate_first_frames", True)
    dry_run = request.get("dry_run", False)

    if not project:
        return {"success": False, "error": "Project name required"}

    project_path = get_project_path(project)
    shot_plan_path = project_path / "shot_plan.json"

    if not project_path.exists() or not shot_plan_path.exists():
        return {
            "success": False,
            "error": f"Project '{project}' not found or missing shot_plan.json. Import a script first via /api/v6/script/full-import"
        }

    # ── Pipeline report accumulator ──────────────────────────────────────
    pipeline_report = {
        "fix_v16": {"applied": False},
        "auto_cast": {"applied": False},
        "prompt_quality": {"applied": False},
        "location_injection": {"applied": False},
        "coverage": {"applied": False},
        "location_masters": {"applied": False},
        "character_refs": {"applied": False},
        "first_frames": {"applied": False},
    }

    # ── Temporal workflow tracking (non-blocking) ────────────────────────
    _wf_id = None
    try:
        _wf_id = temporal_start_workflow(project, "previs_pipeline")
    except Exception:
        pass

    # Track progress via LIVE_GEN_TRACKER for real-time UI updates
    LIVE_GEN_TRACKER.add(
        project=project,
        shot_id="previs_pipeline",
        status="running",
        asset_type="pipeline",
        prompt=f"Previs pipeline: {project}",
        model="atlas-previs-v17"
    )

    logger.info(f"[PREVIS-PIPELINE] Starting for '{project}' (dry_run={dry_run}, loc_masters={opt_location_masters}, char_refs={opt_character_refs}, frames={opt_first_frames})")

    # =====================================================================
    # STEP 1: Fix-V16 Auto-Setup
    # =====================================================================
    step_label = "fix_v16"
    try:
        temporal_run_activity(_wf_id, "previs_step_1_fix_v16")
        LIVE_GEN_TRACKER.add(
            project=project,
            shot_id="previs_step_1",
            status="running",
            asset_type="pipeline_step",
            prompt="Step 1/8: Fix-V16 Auto-Setup"
        )

        fix_result = await fix_v16_issues({"project": project})

        if fix_result.get("success") or fix_result.get("status") == "success":
            pipeline_report[step_label] = {
                "applied": True,
                "issues_fixed": fix_result.get("fixed_count", 0),
                "shot_count": fix_result.get("shot_count", 0),
                "total_duration": fix_result.get("total_duration", 0),
                "critic_grade": fix_result.get("critics", {}).get("director_critic", {}).get("grade", "N/A"),
            }
            LIVE_GEN_TRACKER.update("previs_step_1", "completed")
            logger.info(f"[PREVIS-PIPELINE] Step 1 DONE: {fix_result.get('fixed_count', 0)} issues fixed")
        else:
            pipeline_report[step_label] = {
                "applied": False,
                "error": fix_result.get("error", "Unknown fix-v16 error"),
            }
            LIVE_GEN_TRACKER.update("previs_step_1", "error")
            logger.error(f"[PREVIS-PIPELINE] Step 1 FAILED: {fix_result.get('error', 'Unknown')}")

        temporal_complete_activity(_wf_id, "previs_step_1_fix_v16", result=pipeline_report[step_label])
    except Exception as e:
        pipeline_report[step_label] = {"applied": False, "error": str(e)[:500]}
        LIVE_GEN_TRACKER.update("previs_step_1", "error")
        logger.error(f"[PREVIS-PIPELINE] Step 1 EXCEPTION: {e}", exc_info=True)
        try:
            temporal_fail_activity(_wf_id, "previs_step_1_fix_v16", str(e)[:300])
        except Exception:
            pass

    # =====================================================================
    # STEP 2: Auto-Cast
    # =====================================================================
    step_label = "auto_cast"
    try:
        temporal_run_activity(_wf_id, "previs_step_2_auto_cast")
        LIVE_GEN_TRACKER.add(
            project=project,
            shot_id="previs_step_2",
            status="running",
            asset_type="pipeline_step",
            prompt="Step 2/8: Auto-Cast Characters"
        )

        cast_result = await _auto_cast_project_impl({"project": project})

        if cast_result.get("success"):
            pipeline_report[step_label] = {
                "applied": True,
                "characters_cast": cast_result.get("characters_cast", 0),
                "uncast": cast_result.get("uncast", []),
            }
            LIVE_GEN_TRACKER.update("previs_step_2", "completed")
            logger.info(f"[PREVIS-PIPELINE] Step 2 DONE: {cast_result.get('characters_cast', 0)} characters cast")
        else:
            pipeline_report[step_label] = {
                "applied": False,
                "error": cast_result.get("error", "Unknown cast error"),
            }
            LIVE_GEN_TRACKER.update("previs_step_2", "error")
            logger.error(f"[PREVIS-PIPELINE] Step 2 FAILED: {cast_result.get('error', 'Unknown')}")

        temporal_complete_activity(_wf_id, "previs_step_2_auto_cast", result=pipeline_report[step_label])
    except Exception as e:
        pipeline_report[step_label] = {"applied": False, "error": str(e)[:500]}
        LIVE_GEN_TRACKER.update("previs_step_2", "error")
        logger.error(f"[PREVIS-PIPELINE] Step 2 EXCEPTION: {e}", exc_info=True)
        try:
            temporal_fail_activity(_wf_id, "previs_step_2_auto_cast", str(e)[:300])
        except Exception:
            pass

    # =====================================================================
    # STEP 3: Prompt Quality Validation
    # =====================================================================
    step_label = "prompt_quality"
    try:
        temporal_run_activity(_wf_id, "previs_step_3_prompt_quality")
        LIVE_GEN_TRACKER.add(
            project=project,
            shot_id="previs_step_3",
            status="running",
            asset_type="pipeline_step",
            prompt="Step 3/8: Prompt Quality Validation"
        )

        # Load current shot_plan and story_bible for validation
        with open(shot_plan_path) as f:
            sp_data = json.load(f)
        shots = sp_data.get("shots", [])

        story_bible = {}
        story_bible_path = project_path / "story_bible.json"
        if story_bible_path.exists():
            with open(story_bible_path) as f:
                story_bible = json.load(f)

        pq_report = validate_prompt_quality(shots, story_bible)
        fixes_applied = pq_report.get("fixes_applied", 0)

        # Persist fixes if any were applied
        if fixes_applied > 0:
            stamp_metadata(sp_data, action="previs_pipeline_prompt_quality")
            with open(shot_plan_path, 'w') as f:
                json.dump(sp_data, f, indent=2)
            logger.info(f"[PREVIS-PIPELINE] Step 3: Persisted {fixes_applied} prompt quality fixes")

        pipeline_report[step_label] = {
            "applied": True,
            "fixes": fixes_applied,
            "checked": pq_report.get("checked", 0),
            "details": pq_report.get("details", {}),
            "warnings": pq_report.get("warnings", [])[:10],  # Cap warnings for response size
        }
        LIVE_GEN_TRACKER.update("previs_step_3", "completed")
        logger.info(f"[PREVIS-PIPELINE] Step 3 DONE: {fixes_applied} fixes across {pq_report.get('checked', 0)} shots")

        temporal_complete_activity(_wf_id, "previs_step_3_prompt_quality", result=pipeline_report[step_label])
    except Exception as e:
        pipeline_report[step_label] = {"applied": False, "error": str(e)[:500]}
        LIVE_GEN_TRACKER.update("previs_step_3", "error")
        logger.error(f"[PREVIS-PIPELINE] Step 3 EXCEPTION: {e}", exc_info=True)
        try:
            temporal_fail_activity(_wf_id, "previs_step_3_prompt_quality", str(e)[:300])
        except Exception:
            pass

    # =====================================================================
    # STEP 4: Location Description Injection
    # =====================================================================
    step_label = "location_injection"
    try:
        temporal_run_activity(_wf_id, "previs_step_4_location_inject")
        LIVE_GEN_TRACKER.add(
            project=project,
            shot_id="previs_step_4",
            status="running",
            asset_type="pipeline_step",
            prompt="Step 4/8: Location Description Injection"
        )

        # Reload shot_plan (may have been modified by step 3)
        with open(shot_plan_path) as f:
            sp_data = json.load(f)
        shots = sp_data.get("shots", [])

        story_bible = {}
        story_bible_path = project_path / "story_bible.json"
        if story_bible_path.exists():
            with open(story_bible_path) as f:
                story_bible = json.load(f)

        enriched_count = inject_location_descriptions(shots, story_bible)

        # Persist if any enrichments happened
        if enriched_count > 0:
            stamp_metadata(sp_data, action="previs_pipeline_location_injection")
            with open(shot_plan_path, 'w') as f:
                json.dump(sp_data, f, indent=2)
            logger.info(f"[PREVIS-PIPELINE] Step 4: Persisted {enriched_count} location description enrichments")

        pipeline_report[step_label] = {
            "applied": True,
            "enriched": enriched_count,
            "total_shots": len(shots),
        }
        LIVE_GEN_TRACKER.update("previs_step_4", "completed")
        logger.info(f"[PREVIS-PIPELINE] Step 4 DONE: {enriched_count}/{len(shots)} shots enriched with location descriptions")

        temporal_complete_activity(_wf_id, "previs_step_4_location_inject", result=pipeline_report[step_label])
    except Exception as e:
        pipeline_report[step_label] = {"applied": False, "error": str(e)[:500]}
        LIVE_GEN_TRACKER.update("previs_step_4", "error")
        logger.error(f"[PREVIS-PIPELINE] Step 4 EXCEPTION: {e}", exc_info=True)
        try:
            temporal_fail_activity(_wf_id, "previs_step_4_location_inject", str(e)[:300])
        except Exception:
            pass

    # =====================================================================
    # STEP 5: Coverage Solver
    # =====================================================================
    step_label = "coverage"
    try:
        temporal_run_activity(_wf_id, "previs_step_5_coverage")
        LIVE_GEN_TRACKER.add(
            project=project,
            shot_id="previs_step_5",
            status="running",
            asset_type="pipeline_step",
            prompt="Step 5/8: Coverage Solver"
        )

        # Reload shot_plan (may have been modified by step 4)
        with open(shot_plan_path) as f:
            sp_data = json.load(f)
        shots = sp_data.get("shots", [])

        story_bible = {}
        story_bible_path = project_path / "story_bible.json"
        if story_bible_path.exists():
            with open(story_bible_path) as f:
                story_bible = json.load(f)

        coverage_result = run_coverage_solver(shots, story_bible)

        # Store coverage report in shot_plan metadata
        sp_data["_coverage_report"] = {
            "overall_grade": coverage_result.get("overall_grade", "N/A"),
            "overall_score": coverage_result.get("overall_score", 0),
            "total_scenes": coverage_result.get("total_scenes", 0),
            "passing_scenes": coverage_result.get("passing_scenes", 0),
            "failing_scenes": coverage_result.get("failing_scenes", 0),
        }
        stamp_metadata(sp_data, action="previs_pipeline_coverage")
        with open(shot_plan_path, 'w') as f:
            json.dump(sp_data, f, indent=2)

        pipeline_report[step_label] = {
            "applied": True,
            "grade": coverage_result.get("overall_grade", "N/A"),
            "score": coverage_result.get("overall_score", 0),
            "total_scenes": coverage_result.get("total_scenes", 0),
            "passing_scenes": coverage_result.get("passing_scenes", 0),
            "failing_scenes": coverage_result.get("failing_scenes", 0),
            "critical_issues": coverage_result.get("critical_issues", [])[:10],
        }
        LIVE_GEN_TRACKER.update("previs_step_5", "completed")
        logger.info(f"[PREVIS-PIPELINE] Step 5 DONE: Coverage grade={coverage_result.get('overall_grade', 'N/A')} score={coverage_result.get('overall_score', 0)}")

        temporal_complete_activity(_wf_id, "previs_step_5_coverage", result=pipeline_report[step_label])
    except Exception as e:
        pipeline_report[step_label] = {"applied": False, "error": str(e)[:500]}
        LIVE_GEN_TRACKER.update("previs_step_5", "error")
        logger.error(f"[PREVIS-PIPELINE] Step 5 EXCEPTION: {e}", exc_info=True)
        try:
            temporal_fail_activity(_wf_id, "previs_step_5_coverage", str(e)[:300])
        except Exception:
            pass

    # =====================================================================
    # STEP 6: Generate Location Masters (skipped in dry_run)
    # =====================================================================
    step_label = "location_masters"
    if opt_location_masters and not dry_run:
        try:
            temporal_run_activity(_wf_id, "previs_step_6_loc_masters")
            LIVE_GEN_TRACKER.add(
                project=project,
                shot_id="previs_step_6",
                status="running",
                asset_type="pipeline_step",
                prompt="Step 6/8: Generate Location Masters"
            )

            loc_result = await generate_location_masters({"project": project, "max_locations": 20})

            if loc_result.get("success"):
                gen_count = len([g for g in loc_result.get("generated", []) if g.get("status") == "generated"])
                exist_count = len([g for g in loc_result.get("generated", []) if g.get("status") == "exists"])
                err_count = len(loc_result.get("errors", []))
                pipeline_report[step_label] = {
                    "applied": True,
                    "generated": gen_count,
                    "already_existed": exist_count,
                    "errors": err_count,
                    "total_locations": loc_result.get("total_locations", 0),
                }
                LIVE_GEN_TRACKER.update("previs_step_6", "completed")
                logger.info(f"[PREVIS-PIPELINE] Step 6 DONE: {gen_count} generated, {exist_count} existed, {err_count} errors")
            else:
                pipeline_report[step_label] = {
                    "applied": False,
                    "error": loc_result.get("error", "Unknown location master error"),
                }
                LIVE_GEN_TRACKER.update("previs_step_6", "error")
                logger.error(f"[PREVIS-PIPELINE] Step 6 FAILED: {loc_result.get('error', 'Unknown')}")

            temporal_complete_activity(_wf_id, "previs_step_6_loc_masters", result=pipeline_report[step_label])
        except Exception as e:
            pipeline_report[step_label] = {"applied": False, "error": str(e)[:500]}
            LIVE_GEN_TRACKER.update("previs_step_6", "error")
            logger.error(f"[PREVIS-PIPELINE] Step 6 EXCEPTION: {e}", exc_info=True)
            try:
                temporal_fail_activity(_wf_id, "previs_step_6_loc_masters", str(e)[:300])
            except Exception:
                pass
    else:
        reason = "dry_run=true" if dry_run else "generate_location_masters=false"
        pipeline_report[step_label] = {"applied": False, "skipped": True, "reason": reason}
        logger.info(f"[PREVIS-PIPELINE] Step 6 SKIPPED: {reason}")

    # =====================================================================
    # STEP 7: Generate Character References (skipped in dry_run)
    # =====================================================================
    step_label = "character_refs"
    if opt_character_refs and not dry_run:
        try:
            temporal_run_activity(_wf_id, "previs_step_7_char_refs")
            LIVE_GEN_TRACKER.add(
                project=project,
                shot_id="previs_step_7",
                status="running",
                asset_type="pipeline_step",
                prompt="Step 7/8: Generate Character References"
            )

            # Load cast_map to find characters that need references
            cast_map = {}
            cast_map_path = project_path / "cast_map.json"
            if cast_map_path.exists():
                with open(cast_map_path) as f:
                    cast_map = json.load(f)

            char_generated = 0
            char_skipped = 0
            char_errors = 0
            char_details = []

            for char_name, char_data in cast_map.items():
                if char_name.startswith("_"):
                    continue
                if not isinstance(char_data, dict):
                    continue
                # Skip extras pool
                if char_data.get("is_extras_pool"):
                    char_skipped += 1
                    continue
                # Skip if already has a locked reference
                if char_data.get("locked_reference_url") or char_data.get("character_reference_url"):
                    char_skipped += 1
                    continue
                # Skip if no AI actor assigned
                if not char_data.get("ai_actor"):
                    char_skipped += 1
                    continue

                try:
                    ref_result = await regenerate_character({
                        "project": project,
                        "character_name": char_name,
                    })
                    if ref_result.get("success"):
                        char_generated += 1
                        char_details.append({"character": char_name, "status": "generated"})
                    else:
                        char_errors += 1
                        char_details.append({"character": char_name, "status": "error", "error": ref_result.get("error", "")[:100]})
                except Exception as ce:
                    char_errors += 1
                    char_details.append({"character": char_name, "status": "error", "error": str(ce)[:100]})
                    logger.error(f"[PREVIS-PIPELINE] Character ref error for {char_name}: {ce}")

            pipeline_report[step_label] = {
                "applied": True,
                "generated": char_generated,
                "skipped": char_skipped,
                "errors": char_errors,
                "details": char_details[:20],  # Cap for response size
            }
            LIVE_GEN_TRACKER.update("previs_step_7", "completed")
            logger.info(f"[PREVIS-PIPELINE] Step 7 DONE: {char_generated} generated, {char_skipped} skipped, {char_errors} errors")

            temporal_complete_activity(_wf_id, "previs_step_7_char_refs", result=pipeline_report[step_label])
        except Exception as e:
            pipeline_report[step_label] = {"applied": False, "error": str(e)[:500]}
            LIVE_GEN_TRACKER.update("previs_step_7", "error")
            logger.error(f"[PREVIS-PIPELINE] Step 7 EXCEPTION: {e}", exc_info=True)
            try:
                temporal_fail_activity(_wf_id, "previs_step_7_char_refs", str(e)[:300])
            except Exception:
                pass
    else:
        reason = "dry_run=true" if dry_run else "generate_character_refs=false"
        pipeline_report[step_label] = {"applied": False, "skipped": True, "reason": reason}
        logger.info(f"[PREVIS-PIPELINE] Step 7 SKIPPED: {reason}")

    # =====================================================================
    # STEP 8: Generate First Frames (skipped in dry_run)
    # =====================================================================
    step_label = "first_frames"
    if opt_first_frames and not dry_run:
        try:
            temporal_run_activity(_wf_id, "previs_step_8_first_frames")
            LIVE_GEN_TRACKER.add(
                project=project,
                shot_id="previs_step_8",
                status="running",
                asset_type="pipeline_step",
                prompt="Step 8/8: Generate First Frames"
            )

            frames_result = await generate_first_frames({"project": project})

            if frames_result.get("success"):
                summary = frames_result.get("summary", {})
                pipeline_report[step_label] = {
                    "applied": True,
                    "generated": summary.get("generated", 0),
                    "skipped": summary.get("skipped", 0),
                    "errors": summary.get("errors", 0),
                    "total_shots": summary.get("total_shots", 0),
                }
                LIVE_GEN_TRACKER.update("previs_step_8", "completed")
                logger.info(f"[PREVIS-PIPELINE] Step 8 DONE: {summary.get('generated', 0)} frames generated, {summary.get('errors', 0)} errors")
            else:
                pipeline_report[step_label] = {
                    "applied": False,
                    "error": frames_result.get("error", "Unknown first frame error"),
                }
                LIVE_GEN_TRACKER.update("previs_step_8", "error")
                logger.error(f"[PREVIS-PIPELINE] Step 8 FAILED: {frames_result.get('error', 'Unknown')}")

            temporal_complete_activity(_wf_id, "previs_step_8_first_frames", result=pipeline_report[step_label])
        except Exception as e:
            pipeline_report[step_label] = {"applied": False, "error": str(e)[:500]}
            LIVE_GEN_TRACKER.update("previs_step_8", "error")
            logger.error(f"[PREVIS-PIPELINE] Step 8 EXCEPTION: {e}", exc_info=True)
            try:
                temporal_fail_activity(_wf_id, "previs_step_8_first_frames", str(e)[:300])
            except Exception:
                pass
    else:
        reason = "dry_run=true" if dry_run else "generate_first_frames=false"
        pipeline_report[step_label] = {"applied": False, "skipped": True, "reason": reason}
        logger.info(f"[PREVIS-PIPELINE] Step 8 SKIPPED: {reason}")

    # =====================================================================
    # FINALIZE: Invalidate UI cache, log run manifest, complete workflow
    # =====================================================================
    total_duration_seconds = round(_time.time() - pipeline_start, 2)
    pipeline_report["total_duration_seconds"] = total_duration_seconds

    # Invalidate UI cache so the next bundle request shows fresh data
    try:
        await invalidate_ui_cache(project)
    except Exception:
        pass

    # Log to run manifest
    try:
        trace_id = append_run_manifest(project_path, {
            "action": "previs_pipeline",
            "project": project,
            "dry_run": dry_run,
            "options": {
                "generate_location_masters": opt_location_masters,
                "generate_character_refs": opt_character_refs,
                "generate_first_frames": opt_first_frames,
            },
            "pipeline_report": pipeline_report,
        })
        logger.info(f"[PREVIS-PIPELINE] Run manifest logged: {trace_id}")
    except Exception as me:
        logger.warning(f"[PREVIS-PIPELINE] Run manifest log failed (non-blocking): {me}")

    # Complete Temporal workflow
    try:
        temporal_complete_workflow(_wf_id, result={
            "duration_seconds": total_duration_seconds,
            "steps_applied": sum(1 for v in pipeline_report.values() if isinstance(v, dict) and v.get("applied")),
        })
        _temporal_persist()
    except Exception:
        pass

    # Update pipeline tracker status
    LIVE_GEN_TRACKER.update("previs_pipeline", "completed")

    # Count successes and failures
    steps_applied = sum(1 for k, v in pipeline_report.items() if isinstance(v, dict) and v.get("applied"))
    steps_failed = sum(1 for k, v in pipeline_report.items() if isinstance(v, dict) and not v.get("applied") and not v.get("skipped") and v.get("error"))
    steps_skipped = sum(1 for k, v in pipeline_report.items() if isinstance(v, dict) and v.get("skipped"))

    overall_success = steps_failed == 0 or (steps_failed <= 1 and pipeline_report.get("fix_v16", {}).get("applied"))

    logger.info(f"[PREVIS-PIPELINE] COMPLETE for '{project}': {steps_applied} applied, {steps_failed} failed, {steps_skipped} skipped in {total_duration_seconds}s")

    return {
        "success": overall_success,
        "project": project,
        "dry_run": dry_run,
        "pipeline_report": pipeline_report,
        "summary": {
            "steps_applied": steps_applied,
            "steps_failed": steps_failed,
            "steps_skipped": steps_skipped,
            "total_duration_seconds": total_duration_seconds,
            "ready_for_review": pipeline_report.get("first_frames", {}).get("applied", False),
        }
    }


