@app.post("/api/v16/locks/validate-and-fix")
async def validate_and_fix(request: Dict = Body(...)):
    """
    Combined endpoint: Validate → Auto-fix if needed → Return final status.

    This is the recommended endpoint for UI integration.
    Returns final pass/fail with all fixes applied.
    """
    if not LOCK_SYSTEM_AVAILABLE:
        return {"error": "Lock system not available"}

    project = request.get("project", "")
    if not project:
        return {"error": "Project name required"}

    try:
        # First validate
        results = validate_project_locks(project)

        if results.get("all_passed"):
            return {
                "success": True,
                "action": "none",
                "message": "All locks passed",
                "results": results,
            }

        # If failed, run fixer
        from dataclasses import asdict
        fix_result = run_fixer_workflow(project, results)

        # Re-validate
        final_results = validate_project_locks(project)

        return {
            "success": final_results.get("all_passed", False),
            "action": "fixed",
            "fixes_applied": fix_result.fixes_applied,
            "remaining_issues": fix_result.remaining_issues,
            "results": final_results,
        }
    except Exception as e:
        logger.error(f"[LOCK] Validate-and-fix error: {e}")
        return {"error": str(e)}


# =============================================================================
# V16.6 ABC ALTERNATION CRITIC & SCENE OVERSIGHT/ENFORCE ENDPOINTS
# =============================================================================

def abc_alternation_critic(shots: List[Dict], scene_id: str = None) -> Dict:
    """
    ABC Alternation Critic - Flags same-framing adjacency violations.
    Does NOT modify shots, only reports issues.

    Rule: No consecutive shots with same framing (wide→wide, close→close)
    Exception: Location/time shifts make wide→wide acceptable
    """
    violations = []
    scene_shots = shots

    # Filter to specific scene if provided
    if scene_id:
        scene_shots = [s for s in shots if s.get("scene_id") == scene_id or
                       s.get("shot_id", "").startswith(scene_id)]

    if len(scene_shots) < 2:
        return {"scene_id": scene_id, "violations": [], "score": 1.0}

    for i in range(len(scene_shots) - 1):
        current = scene_shots[i]
        next_shot = scene_shots[i + 1]

        curr_type = (current.get("shot_type") or current.get("type") or "medium").lower()
        next_type = (next_shot.get("shot_type") or next_shot.get("type") or "medium").lower()

        # Normalize types
        curr_category = "wide" if curr_type in ["wide", "ws", "establishing", "master"] else \
                       "close" if curr_type in ["close", "cu", "closeup", "ecu", "insert"] else "medium"
        next_category = "wide" if next_type in ["wide", "ws", "establishing", "master"] else \
                       "close" if next_type in ["close", "cu", "closeup", "ecu", "insert"] else "medium"

        # Check for same-category adjacency
        if curr_category == next_category:
            # Check if location shift makes it acceptable
            curr_loc = current.get("location", "")
            next_loc = next_shot.get("location", "")

            if curr_loc and next_loc and curr_loc != next_loc:
                # Location shift - acceptable
                continue

            violations.append({
                "type": "same_framing_adjacency",
                "shot_a": current.get("shot_id"),
                "shot_b": next_shot.get("shot_id"),
                "framing": curr_category,
                "suggestion": f"reframe one to {'medium' if curr_category != 'medium' else 'wide or close'}"
            })

    score = 1.0 - (len(violations) / max(len(scene_shots) - 1, 1))

    # Log warning if violations exceed threshold
    if len(violations) > 3:
        _sentry_capture_message(f"ABC alternation violations in scene {scene_id}", level="warning")

    return {
        "scene_id": scene_id,
        "shot_count": len(scene_shots),
        "violations": violations,
        "violation_count": len(violations),
        "score": round(score, 2)
    }


@app.get("/api/v16/critic/abc-alternation/{project}")
async def run_abc_alternation_critic(project: str, scene_id: str = None):
    """Run ABC Alternation Critic on project or specific scene."""
    project_path = get_project_path(project)
    shot_plan_path = project_path / "shot_plan.json"

    if not shot_plan_path.exists():
        return {"error": "shot_plan.json not found"}

    with open(shot_plan_path) as f:
        data = json.load(f)

    # V27.1: Handle both list format [shots...] and dict format {"shots": [...]}
    if isinstance(data, list):
        shots = data
        data = {"shots": data}
    else:
        shots = data.get("shots", [])

    if scene_id:
        result = abc_alternation_critic(shots, scene_id)
    else:
        # Run on all scenes
        scene_ids = set()
        for s in shots:
            sid = s.get("scene_id") or s.get("shot_id", "")[:3]
            scene_ids.add(sid)

        all_results = []
        total_violations = 0
        for sid in sorted(scene_ids):
            r = abc_alternation_critic(shots, sid)
            all_results.append(r)
            total_violations += r["violation_count"]

        result = {
            "project": project,
            "scenes": all_results,
            "total_violations": total_violations,
            "overall_score": round(1.0 - (total_violations / max(len(shots), 1)), 2)
        }

    return result


@app.get("/api/v16/oversight/scene/{project}/{scene_id}")
async def get_scene_oversight(project: str, scene_id: str):
    """
    LLM-style oversight report for a scene (READ-ONLY).
    Analyzes scene shots and produces recommendations without modifying.
    """
    _sentry_set_tag("project", project)

    _sentry_set_tag("scene_id", scene_id)

    project_path = get_project_path(project)
    shot_plan_path = project_path / "shot_plan.json"

    if not shot_plan_path.exists():
        return {"error": "shot_plan.json not found"}

    with open(shot_plan_path) as f:
        data = json.load(f)

    # V27.1: Handle both list format [shots...] and dict format {"shots": [...]}
    if isinstance(data, list):
        shots = data
        data = {"shots": data}
    else:
        shots = data.get("shots", [])
    scene_shots = [s for s in shots if s.get("scene_id") == scene_id or
                   s.get("shot_id", "").startswith(scene_id)]

    if not scene_shots:
        return {"error": f"No shots found for scene {scene_id}"}

    # Run ABC critic
    abc_result = abc_alternation_critic(shots, scene_id)

    # Analyze duration distribution
    durations = [s.get("duration", 0) for s in scene_shots]
    dur_histogram = {}
    for d in durations:
        dur_histogram[d] = dur_histogram.get(d, 0) + 1

    # Check for dominant duration (clustering)
    max_count = max(dur_histogram.values()) if dur_histogram else 0
    dominant_pct = max_count / len(durations) if durations else 0

    # Generate recommendations
    actions = []
    risk_notes = []

    for v in abc_result.get("violations", []):
        actions.append({
            "op": "reframe",
            "shot_id": v["shot_b"],
            "to": v["suggestion"].split()[-1],
            "why": f"avoid {v['framing']}→{v['framing']} adjacency"
        })

    if dominant_pct > 0.5:
        actions.append({
            "op": "duration_rebalance",
            "why": f"duration clustering detected ({dominant_pct*100:.0f}% same duration)"
        })

    # Check for continuity risks (shots that shouldn't be reordered)
    for i in range(len(scene_shots) - 1):
        curr = scene_shots[i]
        next_s = scene_shots[i + 1]
        if curr.get("dialogue") and next_s.get("dialogue"):
            # Consecutive dialogue shots - don't reorder
            risk_notes.append({
                "type": "continuity",
                "shot_ids": [curr.get("shot_id"), next_s.get("shot_id")],
                "note": "consecutive dialogue - do not reorder"
            })

    report = {
        "scene_id": scene_id,
        "shot_count": len(scene_shots),
        "abc_score": abc_result["score"],
        "duration_histogram": dur_histogram,
        "dominant_duration_pct": round(dominant_pct, 2),
        "actions": actions,
        "risk_notes": risk_notes,
        "status": "needs_fix" if actions else "ok"
    }

    # Save report to project folder
    report_path = project_path / f"oversight_report_{scene_id}.json"
    with open(report_path, 'w') as f:
        json.dump(report, f, indent=2)

    _sentry_capture_message(f"Oversight report generated for {scene_id}", level="info")

    return report


@app.post("/api/v16/enforce/scene/{project}/{scene_id}")
async def enforce_scene_fixes(project: str, scene_id: str, request: Dict = Body(default={})):
    """
    Deterministic enforcement of scene fixes based on oversight report.
    ONLY executes actions from fix_plan, does not invent changes.
    """
    _sentry_set_tag("project", project)

    _sentry_set_tag("scene_id", scene_id)

    project_path = get_project_path(project)
    shot_plan_path = project_path / "shot_plan.json"

    if not shot_plan_path.exists():
        return {"error": "shot_plan.json not found"}

    # Load or generate oversight report
    report_path = project_path / f"oversight_report_{scene_id}.json"
    if report_path.exists():
        with open(report_path) as f:
            report = json.load(f)
    else:
        # Generate fresh report
        report = await get_scene_oversight(project, scene_id)

    actions = report.get("actions", [])
    if not actions:
        return {"scene_id": scene_id, "status": "no_changes_needed", "mutations": []}

    # Create backup
    backup_path = project_path / f"shot_plan.backup_enforce_{scene_id}_{datetime.now().strftime('%Y%m%d_%H%M%S')}.json"
    shutil.copy(shot_plan_path, backup_path)

    # Load shot plan
    with open(shot_plan_path) as f:
        data = json.load(f)

    # V27.1: Handle both list format [shots...] and dict format {"shots": [...]}
    if isinstance(data, list):
        shots = data
        data = {"shots": data}
    else:
        shots = data.get("shots", [])
    mutations = []

    # Apply each action
    for action in actions:
        op = action.get("op")
        shot_id = action.get("shot_id")

        if op == "reframe":
            # Find and update shot
            for shot in shots:
                if shot.get("shot_id") == shot_id:
                    old_type = shot.get("shot_type", shot.get("type", "?"))
                    new_type = action.get("to", "medium")
                    shot["shot_type"] = new_type
                    shot["type"] = new_type
                    mutations.append({
                        "op": "reframe",
                        "shot_id": shot_id,
                        "from": old_type,
                        "to": new_type,
                        "why": action.get("why")
                    })
                    break

        elif op == "duration_rebalance":
            # This is handled by the main fix pipeline
            mutations.append({
                "op": "duration_rebalance_flagged",
                "why": action.get("why"),
                "note": "run /api/shot-plan/fix-v16 to apply"
            })

    # Save updated shot plan
    data["shots"] = shots
    data["metadata"] = data.get("metadata", {})
    data["metadata"]["last_enforce"] = datetime.now().isoformat()
    data["metadata"]["enforce_scene"] = scene_id

    with open(shot_plan_path, 'w') as f:
        json.dump(data, f, indent=2)

    # Save fix log
    fix_log = {
        "scene_id": scene_id,
        "timestamp": datetime.now().isoformat(),
        "backup": str(backup_path),
        "mutations": mutations,
        "action_count": len(actions)
    }
    fix_log_path = project_path / f"fix_log_{scene_id}.json"
    with open(fix_log_path, 'w') as f:
        json.dump(fix_log, f, indent=2)

    _sentry_capture_message(f"Enforce completed for {scene_id}", level="info")

    return {
        "scene_id": scene_id,
        "status": "enforced",
        "mutations": mutations,
        "backup": str(backup_path)
    }


@app.get("/api/v16/oversight/report")
async def get_full_oversight_report(project: str):
    """
    Full project oversight report - runs all critics and produces unified status.
    """
    _sentry_set_tag("project", project)

    project_path = get_project_path(project)
    shot_plan_path = project_path / "shot_plan.json"
    story_bible_path = project_path / "story_bible.json"

    if not shot_plan_path.exists():
        return {"error": "shot_plan.json not found", "status": "error"}

    with open(shot_plan_path) as f:
        data = json.load(f)

    # V27.1: Handle both list format [shots...] and dict format {"shots": [...]}
    if isinstance(data, list):
        shots = data
        data = {"shots": data}
    else:
        shots = data.get("shots", [])

    # Load story bible for target runtime
    target_runtime = 2700  # V17 FIX: default 45min (was 5min)
    if story_bible_path.exists():
        with open(story_bible_path) as f:
            sb = json.load(f)
            target_runtime = sb.get("runtime_target_seconds", 2700)  # V17 FIX: unified default

    # Duration histogram
    dur_histogram = {}
    for s in shots:
        d = s.get("duration", 0)
        dur_histogram[d] = dur_histogram.get(d, 0) + 1

    # Calculate stats
    total_duration = sum(s.get("duration", 0) for s in shots)
    mean_duration = total_duration / len(shots) if shots else 0
    max_bin = max(dur_histogram.values()) if dur_histogram else 0
    clustering_score = max_bin / len(shots) if shots else 0

    # Shot type distribution
    type_dist = {}
    for s in shots:
        st = (s.get("shot_type") or s.get("type") or "unknown").lower()
        type_dist[st] = type_dist.get(st, 0) + 1

    # Run ABC critic
    abc_result = await run_abc_alternation_critic(project)

    # Determine blocking flags
    blocking_flags = []

    if clustering_score > 0.4:
        blocking_flags.append({
            "code": "DURATION_CLUSTERING",
            "severity": "block",
            "detail": f"{clustering_score*100:.0f}% shots have same duration"
        })

    if total_duration < target_runtime * 0.5:
        blocking_flags.append({
            "code": "RUNTIME_IMPOSSIBLE",
            "severity": "block",
            "detail": f"Only {total_duration}s vs {target_runtime}s target ({total_duration/target_runtime*100:.0f}%)"
        })

    if abc_result.get("total_violations", 0) > 5:
        blocking_flags.append({
            "code": "ABC_VIOLATIONS",
            "severity": "warn",
            "detail": f"{abc_result['total_violations']} same-framing adjacency violations"
        })

    # Extended shots without segment plan
    extended_no_plan = sum(1 for s in shots if s.get("duration", 0) > 20 and not s.get("segment_plan"))
    if extended_no_plan > 0:
        blocking_flags.append({
            "code": "EXTENDED_NO_SEGMENT_PLAN",
            "severity": "warn",
            "detail": f"{extended_no_plan} shots > 20s without segment_plan"
        })

    status = "needs_fix" if any(f["severity"] == "block" for f in blocking_flags) else \
             "warn" if blocking_flags else "ready"

    report = {
        "project": project,
        "version": ATLAS_SCHEMA_VERSION,
        "status": status,
        "blocking_flags": blocking_flags,
        "duration_stats": {
            "count": len(shots),
            "total": total_duration,
            "mean": round(mean_duration, 1),
            "target": target_runtime,
            "target_pct": round(total_duration / target_runtime * 100, 1) if target_runtime else 0,
            "bins": dur_histogram,
            "clustering_score": round(clustering_score, 2)
        },
        "shot_type_distribution": type_dist,
        "abc_critic": {
            "total_violations": abc_result.get("total_violations", 0),
            "overall_score": abc_result.get("overall_score", 1.0)
        },
        "recommendations": []
    }

    if status == "needs_fix":
        report["recommendations"].append({
            "action": "RUN_FIX_PIPELINE",
            "endpoint": f"/api/shot-plan/fix-v16",
            "params": {"project": project}
        })

    # Save report
    report_path = project_path / "oversight_report.json"
    with open(report_path, 'w') as f:
        json.dump(report, f, indent=2)

    return report


