TEMPORAL_HOST = os.getenv("TEMPORAL_HOST", "localhost:7233")
TEMPORAL_TASK_QUEUE = "atlas-render-queue"
_temporal_client = None


async def get_temporal_client():
    """Get or create Temporal client (lazy initialization)."""
    global _temporal_client
    if _temporal_client is None:
        try:
            from temporalio.client import Client
            _temporal_client = await Client.connect(TEMPORAL_HOST)
        except Exception as e:
            logger.warning(f"Temporal not available: {e}")
            return None
    return _temporal_client


@app.get("/api/temporal/status")
async def temporal_status():
    """Check Temporal server connection status."""
    try:
        client = await get_temporal_client()
        if client:
            return {
                "status": "connected",
                "host": TEMPORAL_HOST,
                "task_queue": TEMPORAL_TASK_QUEUE
            }
        else:
            return {
                "status": "disconnected",
                "host": TEMPORAL_HOST,
                "error": "Could not connect to Temporal server"
            }
    except Exception as e:
        return {
            "status": "error",
            "host": TEMPORAL_HOST,
            "error": str(e)
        }


@app.post("/api/temporal/workflow/start")
async def start_temporal_workflow(request: Dict = Body(...)):
    """
    Start a Temporal workflow for episode rendering.

    Request body:
    {
        "project": "project_name",
        "auto_approve": false,  // Skip human approval if true
        "target_runtime_minutes": 45
    }
    """
    project = request.get("project")
    if not project:
        return {"error": "project is required"}

    auto_approve = request.get("auto_approve", False)
    target_runtime = request.get("target_runtime_minutes", 45)

    try:
        client = await get_temporal_client()
        if not client:
            return {
                "success": False,
                "error": "Temporal server not available",
                "fallback": "Use /api/shot-plan/fix-v16 for synchronous execution"
            }

        from temporal_workflows import EpisodeRenderWorkflow, EpisodeWorkflowInput

        # Start the workflow
        workflow_id = f"episode-render-{project}-{datetime.now().strftime('%Y%m%d-%H%M%S')}"

        handle = await client.start_workflow(
            EpisodeRenderWorkflow.run,
            EpisodeWorkflowInput(
                project=project,
                target_runtime_minutes=target_runtime,
                auto_approve=auto_approve
            ),
            id=workflow_id,
            task_queue=TEMPORAL_TASK_QUEUE,
        )

        logger.info(f"[TEMPORAL] Started workflow {workflow_id}")

        return {
            "success": True,
            "workflow_id": workflow_id,
            "project": project,
            "auto_approve": auto_approve,
            "status_url": f"/api/temporal/workflow/{workflow_id}/status"
        }

    except Exception as e:
        _sentry_capture_exception(e)
        return {
            "success": False,
            "error": str(e)
        }


@app.get("/api/temporal/workflow/{workflow_id}/status")
async def get_workflow_status(workflow_id: str):
    """Get status of a running workflow."""
    try:
        client = await get_temporal_client()
        if not client:
            return {"error": "Temporal server not available"}

        handle = client.get_workflow_handle(workflow_id)

        # Query the workflow status
        try:
            status = await handle.query("get_status")
            return {
                "workflow_id": workflow_id,
                "phase": status.phase,
                "progress": status.progress,
                "message": status.message,
                "details": status.details
            }
        except Exception as e:
            # Workflow might be completed
            desc = await handle.describe()
            return {
                "workflow_id": workflow_id,
                "status": str(desc.status),
                "start_time": desc.start_time.isoformat() if desc.start_time else None,
                "close_time": desc.close_time.isoformat() if desc.close_time else None
            }

    except Exception as e:
        return {"error": str(e)}


@app.post("/api/temporal/workflow/{workflow_id}/approve")
async def approve_workflow(workflow_id: str):
    """Send approval signal to a waiting workflow."""
    try:
        client = await get_temporal_client()
        if not client:
            return {"error": "Temporal server not available"}

        handle = client.get_workflow_handle(workflow_id)
        await handle.signal("approve_render")

        logger.info(f"[TEMPORAL] Sent approval signal to {workflow_id}")

        return {
            "success": True,
            "workflow_id": workflow_id,
            "message": "Approval signal sent"
        }

    except Exception as e:
        _sentry_capture_exception(e)
        return {"error": str(e)}


@app.post("/api/temporal/workflow/{workflow_id}/cancel")
async def cancel_workflow(workflow_id: str):
    """Cancel a running workflow."""
    try:
        client = await get_temporal_client()
        if not client:
            return {"error": "Temporal server not available"}

        handle = client.get_workflow_handle(workflow_id)
        await handle.cancel()

        logger.info(f"[TEMPORAL] Cancelled workflow {workflow_id}")

        return {
            "success": True,
            "workflow_id": workflow_id,
            "message": "Workflow cancelled"
        }

    except Exception as e:
        _sentry_capture_exception(e)
        return {"error": str(e)}


@app.get("/api/temporal/workflows")
async def list_workflows(project: str = None, status: str = None):
    """List recent workflows, optionally filtered by project or status."""
    try:
        client = await get_temporal_client()
        if not client:
            return {"error": "Temporal server not available", "workflows": []}

        # Build query
        query = "WorkflowType = 'EpisodeRenderWorkflow'"
        if project:
            query += f" AND WorkflowId LIKE '%{project}%'"

        workflows = []
        async for workflow in client.list_workflows(query=query):
            workflows.append({
                "workflow_id": workflow.id,
                "status": str(workflow.status),
                "start_time": workflow.start_time.isoformat() if workflow.start_time else None,
                "close_time": workflow.close_time.isoformat() if workflow.close_time else None
            })
            if len(workflows) >= 50:  # Limit results
                break

        return {
            "count": len(workflows),
            "workflows": workflows
        }

    except Exception as e:
        return {"error": str(e), "workflows": []}


