@app.post("/api/v16/render/validate-model")
async def validate_render_model(request: Dict = Body(...)):
    """
    V16.6: Validate a model against the locked configuration.

    Request body:
    {
        "stage": "video",  // first_frame, character_edit, video, stitch
        "model": "ltxv2"   // Model key to validate
    }

    Returns:
    {
        "valid": true/false,
        "stage": "video",
        "model": "ltxv2",
        "model_id": "fal-ai/ltx-2.3/image-to-video/fast",
        "error": null or error message
    }
    """
    try:
        from LOCKED_MODELS_CONFIG import (
            assert_model_allowed,
            get_stage_model,
            ATLAS_MODEL_LOCK_VERSION,
            ATLAS_RENDER_STAGES
        )

        stage = request.get("stage", "")
        model = request.get("model", "")

        if not stage:
            return {"valid": False, "error": "stage is required", "stage": stage, "model": model}
        if not model:
            return {"valid": False, "error": "model is required", "stage": stage, "model": model}

        # Check if stage is valid
        if stage not in ATLAS_RENDER_STAGES:
            return {
                "valid": False,
                "error": f"Invalid stage: {stage}. Valid: {list(ATLAS_RENDER_STAGES.keys())}",
                "stage": stage,
                "model": model
            }

        # Try to validate (will raise RuntimeError if invalid)
        try:
            assert_model_allowed(stage, model)
            model_id = get_stage_model(stage)
            return {
                "valid": True,
                "stage": stage,
                "model": model,
                "model_id": model_id,
                "version": ATLAS_MODEL_LOCK_VERSION,
                "error": None
            }
        except RuntimeError as e:
            return {
                "valid": False,
                "stage": stage,
                "model": model,
                "error": str(e),
                "version": ATLAS_MODEL_LOCK_VERSION
            }

    except ImportError as e:
        return {"valid": False, "error": f"LOCKED_MODELS_CONFIG not available: {e}"}
    except Exception as e:
        _sentry_capture_exception(e)
        return {"valid": False, "error": str(e)}


