# ─────────────────────────────────────────────────────────────────────────────
# V30.5: PREVIS COMPILE — server-side prompt enhancement for Previs Studio
# Takes raw user prompt with @mentions, returns:
#   enhanced_nano: compiled nano_prompt with appearance blocks + camera
#   char_ref_urls: resolved character ref URLs for FAL image_urls
#   location_master_url: scene location master URL for FAL image_urls
#   detected_chars: list of character names mentioned
# ─────────────────────────────────────────────────────────────────────────────
@app.post("/api/v30/previs/compile")
async def previs_compile(request: Dict = Body(...)):
    """V30.5: Compile Previs Studio prompt server-side with char refs + location master."""
    project_name = request.get("project", "")
    scene_id = request.get("scene_id", "001")
    raw_prompt = request.get("prompt", "")
    shot_type = request.get("shot_type", "medium")

    project_path = get_project_path(project_name)
    if not project_path.exists():
        return {"success": False, "enhanced_nano": raw_prompt, "char_ref_urls": [], "location_master_url": ""}

    # Load cast map
    cast_map = {}
    cast_path = project_path / "cast_map.json"
    if cast_path.exists():
        try:
            with open(cast_path) as _f:
                _raw_cast = json.load(_f)
            cast_map = {k: v for k, v in _raw_cast.items()
                        if not k.startswith("_") and isinstance(v, dict) and not v.get("_is_alias_of")}
        except Exception:
            pass

    # 1. Extract @mentions from prompt
    import re as _re_previs
    at_mentions = _re_previs.findall(r'@(\w+)', raw_prompt)  # single-word; first-name match catches full cast name
    detected_chars = []
    char_ref_urls = []
    appearance_blocks = []

    for mention in at_mentions:
        mention_upper = mention.strip().upper()
        best_match = None
        for char_name, char_data in cast_map.items():
            if isinstance(char_data, dict) and (
                char_name.upper() == mention_upper or
                mention_upper in char_name.upper() or
                char_name.upper().startswith(mention_upper)
            ):
                best_match = (char_name, char_data)
                break
        if best_match:
            char_name, char_data = best_match
            detected_chars.append(char_name)
            # Get char ref URL
            ref_url = char_data.get("character_reference_url") or char_data.get("headshot_url", "")
            if ref_url:
                if not ref_url.startswith("/api/") and not ref_url.startswith("http"):
                    ref_url = f"/api/media?path={ref_url}"
                char_ref_urls.append(ref_url)
            # Build appearance block
            appearance = char_data.get("appearance", char_data.get("description", ""))
            if appearance:
                appearance_blocks.append(f"[CHARACTER: {char_name.upper()} — {appearance[:120]}]")

    # 2. Clean prompt: strip @ prefix from @mentions, leave the name
    clean_prompt = _re_previs.sub(r'@(\w+(?:\s+\w+)*)', lambda m: m.group(1).strip(), raw_prompt)

    # 3. Get scene location master
    location_master_url = ""
    loc_masters_dir = project_path / "location_masters"
    if loc_masters_dir.exists():
        # Find master matching scene_id
        for _ext in ["jpg", "jpeg", "png"]:
            _lm = loc_masters_dir / f"{scene_id}_master.{_ext}"
            if _lm.exists():
                try:
                    _rel = str(_lm.relative_to(BASE_DIR))
                except ValueError:
                    _rel = str(_lm)
                location_master_url = f"/api/media?path={_rel}"
                break
        # Fallback: any master file
        if not location_master_url:
            for _lm_file in sorted(loc_masters_dir.glob("*.jpg"))[:1]:
                try:
                    _rel = str(_lm_file.relative_to(BASE_DIR))
                except ValueError:
                    _rel = str(_lm_file)
                location_master_url = f"/api/media?path={_rel}"

    # 4. Build enhanced nano_prompt
    parts = [clean_prompt]
    parts.extend(appearance_blocks)
    # Camera constraint based on shot_type
    _cam_map = {
        "close": "85mm f/1.4 — face fills frame, heavy bokeh background",
        "extreme_close": "100mm macro f/1.4 — extreme detail, abstract bokeh",
        "medium": "50mm f/2.8 — waist-up, room context visible",
        "wide": "24mm f/8 — full room geography, deep focus",
        "establishing": "24mm f/8 ultra-wide — full environment, minimal compression",
        "ots": "85mm f/2.8 — over-shoulder framing, listener foreground soft",
    }
    cam_hint = _cam_map.get(shot_type, "50mm f/2.8 — standard medium coverage")
    parts.append(f"[CAMERA: {cam_hint}]")
    parts.append("NO grid, NO collage, NO split screen, NO morphing faces, NO watermarks")
    enhanced_nano = ". ".join(parts) + "."

    return {
        "success": True,
        "enhanced_nano": enhanced_nano[:900],
        "char_ref_urls": char_ref_urls,
        "location_master_url": location_master_url,
        "detected_chars": detected_chars,
        "clean_prompt": clean_prompt,
    }


# ─────────────────────────────────────────────────────────────────────────────
# V30.5: PRODUCTION STATS — direct disk reads for Production Progress panel
# Bypasses bundle cache so stats are always live. Reads:
#   total_shots: from shot_plan.json len (not cached)
#   frames_on_disk: scans first_frames/ + first_frames_lite/ + first_frames_full/
#   videos_on_disk: scans videos/ + videos_kling/
#   cumulative_spend_usd: from cost_log.json (sum of estimated_cost_usd)
#   render_time_seconds: from cost_log.json (sum of elapsed_seconds); falls back
#                        to frames_on_disk * 7 if no logged times
# ─────────────────────────────────────────────────────────────────────────────
@app.get("/api/v30/production-stats/{project_name}")
async def get_production_stats(project_name: str):
    """V30.5: Live production stats for Production Progress panel."""
    project_path = get_project_path(project_name)
    if not project_path.exists():
        return {"success": False, "error": f"Project '{project_name}' not found"}

    # 1. Total shots from shot_plan.json
    total_shots = 0
    sp_path = project_path / "shot_plan.json"
    if sp_path.exists():
        try:
            with open(sp_path) as _f:
                _sp = json.load(_f)
            _shots_list = _sp if isinstance(_sp, list) else _sp.get("shots", [])
            total_shots = len(_shots_list)
        except Exception:
            pass

    # 2. Frames on disk (all runner output dirs)
    frames_count = 0
    for _frames_dir_name in ["first_frames", "first_frames_lite", "first_frames_full"]:
        _d = project_path / _frames_dir_name
        if _d.exists():
            for _ext in ["*.jpg", "*.jpeg", "*.png"]:
                frames_count += len(list(_d.glob(_ext)))

    # 3. Videos on disk
    videos_count = 0
    for _vdir_name in ["videos", "videos_kling"]:
        _vd = project_path / _vdir_name
        if _vd.exists():
            videos_count += len(list(_vd.glob("*.mp4")))

    # 4. Cost log: spend + render time
    real_spend = 0.0
    render_time_secs = 0
    cost_log_path = project_path / "cost_log.json"
    if cost_log_path.exists():
        try:
            with open(cost_log_path) as _f:
                cost_log = json.load(_f)
            real_spend = round(sum(float(e.get("estimated_cost_usd", 0)) for e in cost_log), 2)
            render_time_secs = int(sum(
                float(e.get("render_time_seconds", e.get("elapsed_seconds", e.get("generation_time", 0))))
                for e in cost_log
            ))
        except Exception:
            pass

    # Estimate render time from frame count if none logged
    if render_time_secs == 0 and frames_count > 0:
        render_time_secs = frames_count * 7  # ~7s avg per frame (nano-banana-pro)

    return {
        "success": True,
        "total_shots": total_shots,
        "frames_on_disk": frames_count,
        "videos_on_disk": videos_count,
        "assets_total": frames_count + videos_count,
        "cumulative_spend_usd": real_spend,
        "render_time_seconds": render_time_secs,
    }


@app.get("/api/v16/ui/bundle/{project_name}")
async def get_ui_bundle(project_name: str):
    """
    V16.7: Returns a precomputed UI bundle with ALL data needed to render UI.
    This eliminates UI drift by providing one atomic response with consistent state.

    The UI should consume ONLY this endpoint for project data.
    """
    project_path = get_project_path(project_name)
    if not project_path.exists():
        return {"success": False, "error": f"Project '{project_name}' not found"}

    # Check for cached bundle
    cache_dir = project_path / "ui_cache"
    cache_file = cache_dir / "bundle.json"
    dirty_flag = cache_dir / "bundle.dirty"

    # V18.2: Check BOTH filesystem dirty flag AND in-memory fallback
    _is_dirty = dirty_flag.exists() or project_name in _BUNDLE_DIRTY_MEMORY

    # V18.2: Also check if shot_plan.json was modified after bundle.json (catches mounted FS issues)
    # V23: Also check cast_map.json, wardrobe.json, extras.json — any project data file change invalidates
    if not _is_dirty and cache_file.exists():
        try:
            _cache_mtime = cache_file.stat().st_mtime
            # V23: Check ALL project data files (not just shot_plan) for mtime changes
            for _data_file_name in ["shot_plan.json", "cast_map.json", "wardrobe.json", "extras.json", "story_bible.json"]:
                _data_file_path = project_path / _data_file_name
                if _data_file_path.exists():
                    _df_mtime = _data_file_path.stat().st_mtime
                    if _df_mtime > _cache_mtime:
                        _is_dirty = True
                        logger.info(f"[CACHE] {_data_file_name} newer than bundle.json — forcing rebuild for {project_name}")
                        break
            # V20.2: Also check if first_frames or first_frame_variants dirs were modified
            # This catches new generation runs that update media without touching shot_plan.json
            if not _is_dirty:
                for _media_dir_name in ["first_frames", "first_frame_variants", "videos"]:
                    _media_dir = project_path / _media_dir_name
                    if _media_dir.exists():
                        _media_mtime = _media_dir.stat().st_mtime
                        if _media_mtime > _cache_mtime:
                            _is_dirty = True
                            logger.info(f"[CACHE] {_media_dir_name}/ newer than bundle.json — forcing rebuild for {project_name}")
                            break
        except Exception:
            pass

    # V20.2: When dirty, ALWAYS evict in-memory cache to prevent stale data
    if _is_dirty and project_name in _BUNDLE_MEMORY_CACHE:
        del _BUNDLE_MEMORY_CACHE[project_name]

    # V18.4: Check in-memory cache FIRST (fastest path — no disk IO)
    if not _is_dirty and project_name in _BUNDLE_MEMORY_CACHE:
        cached_bundle, cached_ts = _BUNDLE_MEMORY_CACHE[project_name]
        if (_time_module.time() - cached_ts) < _BUNDLE_MEMORY_TTL:
            cached_bundle["from_cache"] = True
            return cached_bundle

    # If cache exists and not dirty, return cached (disk path)
    if cache_file.exists() and not _is_dirty:
        try:
            with open(cache_file) as f:
                cached = json.load(f)
            cached["from_cache"] = True
            # Store in memory for next request
            _BUNDLE_MEMORY_CACHE[project_name] = (cached, _time_module.time())
            return cached
        except Exception:
            pass

    # =========================================================================
    # V20.4: AUTO-ADVANCE ON BUNDLE BUILD — Fill gaps from imported script
    # If story_bible characters have empty descriptions AND imported_script.txt exists,
    # auto-advance runs ONCE to fill the pipeline. Non-blocking.
    # =========================================================================
    try:
        _sb_path = project_path / "story_bible.json"
        _script_path = project_path / "imported_script.txt"
        if _sb_path.exists() and _script_path.exists():
            with open(_sb_path) as _f:
                _sb_check = json.load(_f)
            _chars_check = _sb_check.get("characters", [])
            _empty_chars = 0
            if isinstance(_chars_check, list):
                _empty_chars = sum(1 for c in _chars_check
                                   if isinstance(c, dict) and len(c.get("description", "") or "") < 10)
            if _empty_chars > 3:  # More than 3 characters with empty descriptions
                from atlas_agents.script_auto_advancer import auto_advance_script
                _adv = auto_advance_script(project_path, dry_run=False)
                _adv_changes = _adv.get("report", {}).get("total_changes", 0)
                if _adv_changes > 0:
                    logger.info(f"[V20.4 BUNDLE] Auto-advanced {project_name} on bundle build: {_adv_changes} changes")
    except Exception as _e:
        logger.debug(f"[V20.4 BUNDLE] Auto-advance check skipped: {_e}")

    # Build fresh bundle
    bundle = {
        "success": True,
        "project": project_name,
        "bundle_version": 2,
        "generated_at": datetime.now().isoformat(),
        "from_cache": False,
        "story_bible": None,
        "cast_map": {},
        "shot_plan_summary": {},
        "shot_gallery_rows": [],
        "segments_index": {},
        "qa_latest": None,
        "lint_summary": {},
        "realtime_media": [],
        "characters_list": [],
        "locations_list": [],
        "master_locks": {
            "characters": False,
            "locations": False,
            "casting": False,
            "allLocked": False
        },
        # V16.7: Precomputed UI controls - derived from shot data, not arbitrary
        "ui_controls": {
            "framing_options": ["wide", "medium", "close-up", "extreme_close", "over_shoulder", "two_shot", "establishing"],
            "camera_motion_options": ["static", "slow_dolly", "slow_crane", "slow_pan", "push_in", "pull_back", "tilt", "track"],
            "lens_options": ["14mm", "24mm", "35mm", "50mm", "85mm", "100mm"],
            "lighting_options": [],  # Populated from story bible/scenes
            "acting_style_options": ["restrained", "tense", "stillness", "emotional", "subtle", "intense"]
        },
        # V16.7: Location fallback flag - true if locations came from shot_plan, not story_bible
        "locations_from_shot_plan": False
    }

    # Load story bible
    story_bible_path = project_path / "story_bible.json"
    if story_bible_path.exists():
        try:
            with open(story_bible_path) as f:
                bundle["story_bible"] = json.load(f)
                bundle["characters_list"] = [
                    c.get("name", c) if isinstance(c, dict) else c
                    for c in bundle["story_bible"].get("characters", [])
                ]
                # V16.7.1 FIX: Check multiple sources for locations
                locations_raw = bundle["story_bible"].get("locations", [])
                # Fallback 1: Check story_bible.setting.locations
                if not locations_raw and bundle["story_bible"].get("setting", {}).get("locations"):
                    locations_raw = bundle["story_bible"]["setting"]["locations"]
                    bundle["locations_from_shot_plan"] = False  # Still from story_bible
                # Fallback 2: Check scenes for unique locations
                if not locations_raw and bundle["story_bible"].get("scenes"):
                    seen_locs = set()
                    for scene in bundle["story_bible"]["scenes"]:
                        if scene.get("location"):
                            seen_locs.add(scene["location"])
                    locations_raw = list(seen_locs)
                    bundle["locations_from_shot_plan"] = True  # From scenes, not explicit list

                bundle["locations_list"] = [
                    loc.get("name", loc) if isinstance(loc, dict) else loc
                    for loc in locations_raw
                ]
        except Exception as e:
            logger.warning(f"[UI_BUNDLE] Could not load story_bible: {e}")

    # Load cast map
    cast_map_path = project_path / "cast_map.json"
    if cast_map_path.exists():
        try:
            with open(cast_map_path) as f:
                raw_cast = json.load(f)
            # V17 FIX: Filter out metadata keys (start with _) from cast_map
            # Only keep actual character entries (values must be dicts with ai_actor)
            # V21.9.1 FIX: Also exclude alias entries (_is_alias_of) to prevent CHARACTER BANK duplicates
            bundle["cast_map"] = {
                k: v for k, v in raw_cast.items()
                if not k.startswith("_") and isinstance(v, dict) and v.get("ai_actor") and not v.get("_is_alias_of")
            }
            logger.info(f"[UI_BUNDLE] Cast map: {len(bundle['cast_map'])} characters (filtered from {len(raw_cast)})")

            # V17.7.3: Ensure cast_map entries have VALID headshot_url AND character_reference_url
            # RULE: character_reference_url = CHAR_REFERENCE (actor in wardrobe) — for generation
            #        headshot_url = LOCKED_REFERENCE (actor headshot) — for UI casting panel
            # NEVER overwrite character_reference_url with LOCKED refs (user explicitly wants CHAR_REFERENCE)
            # FIX: Always validate existing URLs resolve — stale /Users/quantum/ paths get replaced
            _ref_count = 0

            def _url_path_resolves(url_str):
                """Check if an /api/media?path= URL points to a file that actually exists."""
                if not url_str or not isinstance(url_str, str):
                    return False
                if not url_str.startswith("/api/media?path="):
                    return False
                inner = url_str.split("path=", 1)[1]
                if Path(inner).exists():
                    return True
                # Try relative to BASE_DIR
                if not inner.startswith("/"):
                    if (BASE_DIR / inner).exists():
                        return True
                return False

            for _char_key, _char_val in bundle["cast_map"].items():
                if not isinstance(_char_val, dict):
                    continue

                # --- HEADSHOT_URL (LOCKED_REFERENCE for UI casting panel) ---
                _existing_hs = _char_val.get("headshot_url", "")
                _hs_valid = _url_path_resolves(_existing_hs)
                if not _hs_valid:
                    _actor = _char_val.get("ai_actor", "")
                    if _actor:
                        _afn = _actor.upper().replace(" ", "_") + "_LOCKED_REFERENCE.jpg"
                        _lp = BASE_DIR / "character_library_locked" / "ai_actors" / _afn
                        if _lp.exists():
                            _char_val["headshot_url"] = _media_url(_lp)
                            _ref_count += 1
                            if _existing_hs:
                                logger.info(f"[UI_BUNDLE] V17.7.3: Fixed stale headshot_url for {_char_key}")

                # --- CHARACTER_REFERENCE_URL (CHAR_REFERENCE — actor in wardrobe) ---
                _existing_cr = _char_val.get("character_reference_url", "")
                _cr_valid = _url_path_resolves(_existing_cr)
                if not _cr_valid:
                    # Try to find CHAR_REFERENCE on disk (project-local first, then character_library_locked root)
                    _char_safe = re.sub(r'[^a-zA-Z0-9_-]', '_', _char_key.upper())
                    _local_cr = project_path / "character_library_locked" / f"{_char_safe}_CHAR_REFERENCE.jpg"
                    if _local_cr.exists():
                        try:
                            _rel_cr = str(_local_cr.relative_to(BASE_DIR))
                        except ValueError:
                            _rel_cr = str(_local_cr)
                        _char_val["character_reference_url"] = f"/api/media?path={_rel_cr}"
                        _ref_count += 1
                        if _existing_cr:
                            logger.info(f"[UI_BUNDLE] V17.7.3: Fixed stale character_reference_url for {_char_key}")
                    else:
                        # Try character_library_locked at BASE_DIR level
                        _global_cr = BASE_DIR / "character_library_locked" / "ravencroft_manor" / f"{_char_safe}_CHAR_REFERENCE.jpg"
                        if _global_cr.exists():
                            try:
                                _rel_gcr = str(_global_cr.relative_to(BASE_DIR))
                            except ValueError:
                                _rel_gcr = str(_global_cr)
                            _char_val["character_reference_url"] = f"/api/media?path={_rel_gcr}"
                            _ref_count += 1

            if _ref_count:
                logger.info(f"[UI_BUNDLE] V17.7.3: Resolved {_ref_count} character reference URLs in cast_map")

        except Exception as e:
            logger.warning(f"[UI_BUNDLE] Could not load cast_map: {e}")

    # Load shot plan
    shot_plan_path = project_path / "shot_plan.json"
    shots = []
    if shot_plan_path.exists():
        try:
            with open(shot_plan_path) as f:
                shot_plan = _sp_guard(json.load(f))

            # V27.1.2 FIX: Handle both list and dict format shot_plan
            if isinstance(shot_plan, list):
                shots = shot_plan
                shot_plan = {"shots": shots}  # Wrap for downstream .get() calls
                logger.info(f"[UI_BUNDLE] Shot plan is list format: {len(shots)} shots")
            else:
                shots = shot_plan.get("shots", [])

            # V17.7.4: Build scene_id → location map from scene_manifest (SOURCE OF TRUTH)
            # This prevents corrupted per-shot location fields from propagating to the UI
            _scene_manifest = shot_plan.get("scene_manifest", shot_plan.get("scenes", []))
            _scene_location_truth = {}
            for _sm_scene in _scene_manifest:
                _sm_sid = _sm_scene.get("scene_id", "")
                _sm_loc = _sm_scene.get("location", "")
                if _sm_sid and _sm_loc:
                    _scene_location_truth[_sm_sid] = _sm_loc
            if _scene_location_truth:
                logger.info(f"[UI_BUNDLE] V17.7.4: Scene location truth map built — {len(_scene_location_truth)} scenes")

            # V17.7.4: Cross-check and fix shot locations against scene manifest
            # V18.2 FIX: Skip exterior/establishing shots — they intentionally differ from interior scene location
            _loc_fixes_applied = 0
            for _s in shots:
                _s_id = _s.get("shot_id", "")
                _s_scene = _s_id.split("_")[0] if "_" in _s_id else ""
                if _s_scene and _s_scene in _scene_location_truth:
                    _correct_loc = _scene_location_truth[_s_scene]
                    _shot_loc = _s.get("location", "")
                    # V18.2: Don't override exterior/establishing shots — they're intentionally different
                    # V22 FIX: Don't override INTERCUT shots — they have multiple valid locations per scene
                    _s_type = (_s.get("type") or _s.get("shot_type") or "").lower()
                    _is_ext_establishing = (_shot_loc.upper().startswith("EXT.") or _s_type in ("establishing", "master"))
                    _is_intercut = _s.get("_intercut", False)
                    if _is_ext_establishing or _is_intercut:
                        continue  # Exterior/INTERCUT shots set their OWN location — don't override
                    # Normalize for comparison: strip INT/EXT prefixes and time-of-day
                    def _norm_loc_check(s):
                        s = s.upper().strip()
                        for pfx in ["INT.", "EXT.", "INT/EXT.", "INT ", "EXT "]:
                            if s.startswith(pfx):
                                s = s[len(pfx):]
                        for tod in [" — NIGHT", " — DAY", " — EVENING", " — MORNING", " — DAWN", " — DUSK",
                                    " - NIGHT", " - DAY", " - EVENING", " - MORNING",
                                    "— NIGHT", "— DAY"]:
                            if s.endswith(tod.upper()):
                                s = s[:-len(tod)]
                        return s.strip(" -—–").replace("–", "-").replace("—", "-").strip()
                    if _shot_loc and _norm_loc_check(_shot_loc) != _norm_loc_check(_correct_loc):
                        # Mismatch! Override with scene manifest truth
                        _s["location"] = _correct_loc
                        _loc_fixes_applied += 1
                    elif not _shot_loc:
                        _s["location"] = _correct_loc
                        _loc_fixes_applied += 1
            if _loc_fixes_applied:
                logger.warning(f"[UI_BUNDLE] V17.7.4: Fixed {_loc_fixes_applied} shot locations from scene manifest (runtime guard)")

            # V17 TRUTH UNIFICATION: Derive ALL metrics from shot_plan, not story_bible
            # This is the single source of execution truth
            characters_in_shots = set()
            locations_in_shots = set()
            extended_shot_count = 0
            shots_with_dialogue = 0
            shots_with_frames = 0
            shots_with_videos = 0

            # V17.3: Frame discovery pass — sync first_frames dir with shot metadata
            first_frames_dir = project_path / "first_frames"
            videos_dir = project_path / "videos"
            videos_kling_dir = project_path / "videos_kling"  # V17.8: Kling video directory
            frames_synced = 0
            videos_synced = 0
            videos_kling_synced = 0  # V17.8: Track kling video discovery
            # V27.5.1: Stale session path normalizer — prevents dead URLs from old sessions
            import re as _re_bundle
            _stale_fixed = 0
            for s in shots:
                for _pf in ("first_frame_url", "first_frame_path", "video_url", "video_path", "video_url_kling"):
                    _pv = s.get(_pf) or ""
                    _sm = _re_bundle.search(r'/sessions/[^/]+/mnt/ATLAS_CONTROL_SYSTEM/(.*)', _pv)
                    if _sm:
                        _rel = _sm.group(1).split("?")[0].split("&")[0]  # strip query params from path part
                        if (BASE_DIR / _rel).exists():
                            s[_pf] = f"/api/media?path={_rel}"
                        else:
                            s[_pf] = ""
                        _stale_fixed += 1
            if _stale_fixed:
                logger.info(f"[UI_BUNDLE] V27.5.1: normalized {_stale_fixed} stale session paths")

            # V30.1: Also scan runner output dirs (first_frames_full, first_frames_lite)
            # The universal runner writes to first_frames_{mode}/, not first_frames/
            _frame_search_dirs = [
                first_frames_dir,
                project_path / "first_frames_full",
                project_path / "first_frames_lite",
            ]
            for s in shots:
                sid = s.get("shot_id", "")
                # Discover first frames on disk that aren't in shot_plan metadata
                if not s.get("first_frame_path") and not s.get("first_frame_url"):
                    for _ff_search_dir in _frame_search_dirs:
                        frame_path = _ff_search_dir / f"{sid}.jpg"
                        if frame_path.exists():
                            try:
                                _rel_ff = str(frame_path.relative_to(BASE_DIR))
                            except ValueError:
                                _rel_ff = str(frame_path)
                            s["first_frame_path"] = _rel_ff
                            s["first_frame_url"] = f"/api/media?path={_rel_ff}"
                            frames_synced += 1
                            break
                # Discover videos on disk that aren't in shot_plan metadata
                if not s.get("video_path"):
                    for ext in [".mp4", ".webm"]:
                        vid_path = videos_dir / f"{sid}{ext}"
                        if vid_path.exists():
                            try:
                                _rel_vid = str(vid_path.relative_to(BASE_DIR))
                            except ValueError:
                                _rel_vid = str(vid_path)
                            s["video_path"] = _rel_vid
                            videos_synced += 1
                            break
                # V17.8: Discover kling videos from videos_kling directory
                if not s.get("video_url_kling"):
                    for ext in [".mp4", ".webm"]:
                        vid_kling_path = videos_kling_dir / f"{sid}{ext}"
                        if vid_kling_path.exists():
                            try:
                                _rel_kling = str(vid_kling_path.relative_to(BASE_DIR))
                            except ValueError:
                                _rel_kling = str(vid_kling_path)
                            s["video_url_kling"] = f"/api/media?path={_rel_kling}"
                            videos_kling_synced += 1
                            break
            if frames_synced or videos_synced or videos_kling_synced:
                logger.info(f"[UI_BUNDLE] V17.3 frame discovery: synced {frames_synced} frames, {videos_synced} videos, {videos_kling_synced} kling videos from disk")

            # V20.2: Variant RE-DISCOVERY — sync _variants from disk, not stale shot_plan metadata
            # This fixes the "blending old runs" bug where old variant references persist
            # across regeneration runs because shot_plan.json retains stale _variants arrays.
            variants_dir = project_path / "first_frame_variants"
            variants_synced = 0
            variants_cleaned = 0
            if variants_dir.exists():
                for s in shots:
                    sid = s.get("shot_id", "")
                    if not sid:
                        continue
                    # Discover ACTUAL variant files on disk for this shot
                    disk_variants = sorted(variants_dir.glob(f"{sid}_*.jpg"))
                    if disk_variants:
                        # Rebuild _variants from disk truth
                        fresh_variants = []
                        for vf in disk_variants:
                            try:
                                _rel_vf = str(vf.relative_to(BASE_DIR))
                            except ValueError:
                                _rel_vf = str(vf)
                            # Parse angle name from filename: {shot_id}_{angle}.jpg
                            _angle_part = vf.stem.replace(sid + "_", "", 1)
                            fresh_variants.append({
                                "angle_name": _angle_part,
                                "path": _rel_vf,
                                "url": f"/api/media?path={_rel_vf}",
                            })
                        old_variants = s.get("_variants", [])
                        if len(fresh_variants) != len(old_variants):
                            variants_synced += 1
                        s["_variants"] = fresh_variants
                    else:
                        # No variant files on disk — clear stale metadata
                        if s.get("_variants"):
                            s.pop("_variants", None)
                            variants_cleaned += 1
            else:
                # No variants directory at all — clean all stale variant refs
                for s in shots:
                    if s.get("_variants"):
                        s.pop("_variants", None)
                        variants_cleaned += 1
            if variants_synced or variants_cleaned:
                logger.info(f"[UI_BUNDLE] V20.2 variant re-discovery: synced {variants_synced}, cleaned {variants_cleaned} stale refs")

            for s in shots:
                # Characters
                for char in s.get("characters", []):
                    if char:
                        characters_in_shots.add(char)
                # Locations — V17.7.4: Normalize location names to match master map keys
                loc = s.get("location", s.get("grid_location_hint", ""))
                if loc:
                    locations_in_shots.add(loc)
                # Extended shots (>20s) — T2-OR-18: duration may be string "5"
                dur = s.get("duration", s.get("duration_seconds", 10))
                try: dur = int(dur)
                except (TypeError, ValueError): dur = 10
                if dur > 20:
                    extended_shot_count += 1
                # Dialogue
                if s.get("dialogue") or s.get("dialogue_text"):
                    shots_with_dialogue += 1
                # Assets
                if s.get("first_frame_path") or s.get("first_frame_url"):
                    shots_with_frames += 1
                if s.get("video_path"):
                    shots_with_videos += 1

            bundle["shot_plan_summary"] = {
                "total_shots": len(shots),
                "total_duration": sum(int(s.get("duration", s.get("duration_seconds", 10)) or 10) for s in shots),
                "scenes": len(shot_plan.get("scene_manifest", shot_plan.get("scenes", []))),
                # V17: Shot-derived execution metrics (THESE ARE THE TRUTH)
                "characters_in_shots": len(characters_in_shots),
                "characters_list": sorted(list(characters_in_shots)),
                "locations_in_shots": len(locations_in_shots),
                "locations_list": sorted(list(locations_in_shots)),
                "extended_shots": extended_shot_count,
                "standard_shots": len(shots) - extended_shot_count,
                "shots_with_dialogue": shots_with_dialogue,
                "shots_with_frames": shots_with_frames,
                "shots_with_videos": shots_with_videos,
                "metadata": shot_plan.get("metadata", {})
            }

            # V17.7: Build location_masters_map BEFORE gallery rows so shots can auto-resolve
            loc_masters_dir = project_path / "location_masters"
            location_masters_map = {}
            if loc_masters_dir.exists():
                for img_ext in ["jpg", "jpeg", "png", "webp"]:
                    for img_file in loc_masters_dir.glob(f"*.{img_ext}"):
                        loc_key = img_file.stem.upper().replace("_", " ")
                        # V17.7.5: Use relative path (not absolute) for /api/media URLs
                        try:
                            rel_path = str(img_file.relative_to(BASE_DIR))
                        except ValueError:
                            rel_path = str(img_file)
                        loc_url = f"/api/media?path={rel_path}"
                        location_masters_map[loc_key] = loc_url
                        loc_key_clean = loc_key.replace(" MASTER", "").strip()
                        if loc_key_clean != loc_key:
                            location_masters_map[loc_key_clean] = loc_url
            if location_masters_map:
                logger.info(f"[UI_BUNDLE] V17.7: {len(location_masters_map)} location masters pre-loaded for auto-resolve")

            # Build shot gallery rows with segments index
            for shot in shots:
              try:
                shot_id = shot.get("shot_id", "?")
                # T2-OR-18: duration may be stored as string "5" — normalize to int
                _dur_raw = shot.get("duration", shot.get("duration_seconds", 10))
                try: duration = int(_dur_raw)
                except (TypeError, ValueError): duration = 10
                segments = shot.get("segments", shot.get("render_plan", {}).get("segments", []))

                # Add to segments index with full metadata including ltx_motion_prompt
                if segments:
                    # V17 FIX: Ensure each segment has ltx_motion_prompt from shot
                    shot_ltx = shot.get("ltx_motion_prompt", "")
                    for i, seg in enumerate(segments):
                        if not seg.get("ltx_motion_prompt"):
                            seg["ltx_motion_prompt"] = seg.get("ltx_motion_prompt") or shot_ltx
                    bundle["segments_index"][shot_id] = segments

                # V17 FIX: Rebuild ai_actor_cast from cast_map (single source of truth)
                # This prevents stale shot_plan.ai_actor_cast from overriding cast_map
                shot_characters = shot.get("characters", [])
                rebuilt_ai_actor_cast = {}
                for char in shot_characters:
                    cast_entry = bundle["cast_map"].get(char)
                    if not cast_entry:
                        char_upper = char.upper()
                        for cast_name, ce in bundle["cast_map"].items():
                            cast_upper = cast_name.upper()
                            if (cast_upper == char_upper or
                                cast_upper.startswith(char_upper + " ") or
                                cast_upper.startswith(char_upper) or
                                char_upper.startswith(cast_upper)):
                                cast_entry = ce
                                break
                    if cast_entry:
                        # V17.7.2: Resolve character references — CHAR_REFERENCE (wardrobe) preferred over LOCKED
                        actor_name = cast_entry.get("ai_actor", "")
                        # 1) Prefer cast_map's character_reference_url (CHAR_REFERENCE = actor in wardrobe)
                        char_ref_url = cast_entry.get("character_reference_url", "")
                        # 2) If missing, try project-local CHAR_REFERENCE on disk
                        if not char_ref_url:
                            _char_safe = re.sub(r'[^a-zA-Z0-9_-]', '_', char.upper())
                            _local_cr = project_path / "character_library_locked" / f"{_char_safe}_CHAR_REFERENCE.jpg"
                            if _local_cr.exists():
                                char_ref_url = _media_url(_local_cr)
                        # 3) Last resort: LOCKED_REFERENCE (generic headshot)
                        if not char_ref_url and actor_name:
                            actor_filename = actor_name.upper().replace(" ", "_") + "_LOCKED_REFERENCE.jpg"
                            locked_path = BASE_DIR / "character_library_locked" / "ai_actors" / actor_filename
                            if locked_path.exists():
                                char_ref_url = _media_url(locked_path)
                        rebuilt_ai_actor_cast[char] = {
                            "ai_actor": actor_name,
                            "ai_actor_id": cast_entry.get("ai_actor_id", ""),
                            "headshot_url": cast_entry.get("headshot_url", ""),
                            "reference_url": char_ref_url or cast_entry.get("reference_url", ""),
                            "character_reference_url": char_ref_url,
                            "fit_score": cast_entry.get("fit_score", 0)
                        }

                # Build gallery row - V16.7.1: Include dialogue and script_line_ref
                dialogue_text = shot.get("dialogue") or shot.get("dialogue_text") or ""

                # V17.7: Auto-resolve character_reference_url from LOCKED REFERENCES (not headshots)
                # Priority: 1) shot's own character_reference_url, 2) locked reference JPG, 3) cast_map reference_url
                raw_char_ref = shot.get("character_reference_url", "")
                # V17.7.1: Detect stale character ref paths from other environments
                if raw_char_ref:
                    _char_valid = False
                    if raw_char_ref.startswith("/api/media?path="):
                        _ch_inner = raw_char_ref.split("path=", 1)[1] if "path=" in raw_char_ref else ""
                        if _ch_inner and Path(_ch_inner).exists():
                            _char_valid = True
                        elif _ch_inner:
                            # Try path translation
                            for _m in ["ATLAS_CONTROL_SYSTEM/", "pipeline_outputs/"]:
                                _idx = _ch_inner.find(_m)
                                if _idx >= 0:
                                    _rel = _ch_inner[_idx + len(_m):] if _m == "ATLAS_CONTROL_SYSTEM/" else _ch_inner[_idx:]
                                    _cand = BASE_DIR / _rel
                                    if _cand.exists():
                                        raw_char_ref = _media_url(_cand)
                                        _char_valid = True
                                        break
                    elif not raw_char_ref.startswith("/api/"):
                        _char_valid = Path(raw_char_ref).exists()
                    else:
                        _char_valid = True  # Relative /api/ URL, trust it
                    if not _char_valid:
                        raw_char_ref = ""  # Force auto-resolve below
                if not raw_char_ref:
                    for char_name in shot_characters:
                        cast_entry = bundle["cast_map"].get(char_name)
                        if not cast_entry:
                            cn_upper = char_name.upper().strip()
                            for ck, cv in bundle["cast_map"].items():
                                ck_upper = ck.upper()
                                if (ck_upper == cn_upper or
                                    ck_upper.startswith(cn_upper + " ") or
                                    cn_upper.startswith(ck_upper + " ") or
                                    ck_upper.startswith(cn_upper)):
                                    cast_entry = cv
                                    break
                        if cast_entry:
                            # V17.7.2: Resolution order — CHAR_REFERENCE (wardrobe) FIRST, LOCKED (headshot) LAST
                            # 1) Project-local CHAR_REFERENCE (actor in character wardrobe — preferred for generation)
                            char_upper = re.sub(r'[^a-zA-Z0-9_-]', '_', char_name.upper())
                            for _ext in ["jpg", "png"]:
                                local_ref = project_path / "character_library_locked" / f"{char_upper}_CHAR_REFERENCE.{_ext}"
                                if local_ref.exists():
                                    raw_char_ref = _media_url(local_ref)
                                    break
                            if raw_char_ref:
                                break
                            # 2) Cast_map's character_reference_url (may point to CHAR_REFERENCE)
                            _cm_cr = cast_entry.get("character_reference_url", "")
                            if _cm_cr and "CHAR_REFERENCE" in str(_cm_cr).upper():
                                raw_char_ref = _cm_cr
                                break
                            # 3) Last resort: LOCKED_REFERENCE (generic actor headshot)
                            actor_name = cast_entry.get("ai_actor", "")
                            if actor_name:
                                actor_filename = actor_name.upper().replace(" ", "_") + "_LOCKED_REFERENCE.jpg"
                                locked_path = BASE_DIR / "character_library_locked" / "ai_actors" / actor_filename
                                if locked_path.exists():
                                    raw_char_ref = _media_url(locked_path)
                                    break
                            # Fallback: cast_map's own character_reference_url or reference_url
                            raw_char_ref = (
                                cast_entry.get("character_reference_url") or
                                cast_entry.get("reference_url") or ""
                            )
                            # V17.7.1: Validate cast_map ref path is accessible
                            if raw_char_ref and raw_char_ref.startswith("/api/media?path="):
                                _cm_inner = raw_char_ref.split("path=", 1)[1] if "path=" in raw_char_ref else ""
                                if _cm_inner and not Path(_cm_inner).exists():
                                    # Try path translation
                                    _cm_resolved = False
                                    for _m in ["ATLAS_CONTROL_SYSTEM/", "pipeline_outputs/"]:
                                        _idx = _cm_inner.find(_m)
                                        if _idx >= 0:
                                            _rel = _cm_inner[_idx + len(_m):] if _m == "ATLAS_CONTROL_SYSTEM/" else _cm_inner[_idx:]
                                            _cand = BASE_DIR / _rel
                                            if _cand.exists():
                                                raw_char_ref = _media_url(_cand)
                                                _cm_resolved = True
                                                break
                                    if not _cm_resolved:
                                        raw_char_ref = ""  # Unresolvable
                            if raw_char_ref:
                                break
                if raw_char_ref and not raw_char_ref.startswith("/api/"):
                    char_ref_display = _media_url(raw_char_ref)
                else:
                    char_ref_display = raw_char_ref or ""

                # V18.2: Collect ALL character reference URLs for multi-character shots
                all_char_ref_urls = []
                if char_ref_display:
                    all_char_ref_urls.append(char_ref_display)
                for _mc_name in shot_characters:
                    _mc_ref = None
                    _mc_entry = bundle["cast_map"].get(_mc_name)
                    if not _mc_entry:
                        _mc_upper = _mc_name.upper().strip()
                        for _mck, _mcv in bundle["cast_map"].items():
                            _mck_upper = _mck.upper()
                            if (_mck_upper == _mc_upper or
                                _mck_upper.startswith(_mc_upper) or
                                _mc_upper.startswith(_mck_upper)):
                                _mc_entry = _mcv
                                break
                    if _mc_entry:
                        _mc_safe = re.sub(r'[^a-zA-Z0-9_-]', '_', _mc_name.upper())
                        for _ext in ["jpg", "png"]:
                            _mc_path = project_path / "character_library_locked" / f"{_mc_safe}_CHAR_REFERENCE.{_ext}"
                            if _mc_path.exists():
                                _mc_ref = _media_url(_mc_path)
                                break
                        if not _mc_ref:
                            _mc_ref = _mc_entry.get("character_reference_url") or _mc_entry.get("reference_url") or ""
                            if _mc_ref and "CHAR_REFERENCE" not in str(_mc_ref).upper():
                                _mc_actor = _mc_entry.get("ai_actor", "")
                                if _mc_actor:
                                    _mc_locked = BASE_DIR / "character_library_locked" / "ai_actors" / (_mc_actor.upper().replace(" ", "_") + "_LOCKED_REFERENCE.jpg")
                                    if _mc_locked.exists():
                                        _mc_ref = _media_url(_mc_locked)
                        if _mc_ref:
                            if not _mc_ref.startswith("/api/"):
                                _mc_ref = _media_url(_mc_ref)
                            if _mc_ref not in all_char_ref_urls:
                                all_char_ref_urls.append(_mc_ref)

                # V17.7: Auto-resolve location_master_url from location_masters_map if missing or stale
                raw_loc_ref = shot.get("location_master_url", "")
                # V17.7.1: Detect stale paths from other environments (e.g., /Users/quantum/...)
                if raw_loc_ref:
                    _loc_stale = False
                    if raw_loc_ref.startswith("/api/media?path="):
                        _loc_inner = raw_loc_ref.split("path=", 1)[1] if "path=" in raw_loc_ref else ""
                        if _loc_inner and not Path(_loc_inner).exists():
                            # Try path translation
                            _loc_resolved = False
                            for _m in ["ATLAS_CONTROL_SYSTEM/", "pipeline_outputs/"]:
                                _idx = _loc_inner.find(_m)
                                if _idx >= 0:
                                    _rel = _loc_inner[_idx + len(_m):] if _m == "ATLAS_CONTROL_SYSTEM/" else _loc_inner[_idx:]
                                    _cand = BASE_DIR / _rel if _m == "ATLAS_CONTROL_SYSTEM/" else BASE_DIR / _rel
                                    if _cand.exists():
                                        raw_loc_ref = _media_url(_cand)
                                        _loc_resolved = True
                                        break
                            if not _loc_resolved:
                                raw_loc_ref = ""  # Force auto-resolve below
                                _loc_stale = True
                    elif not raw_loc_ref.startswith("/api/") and not Path(raw_loc_ref).exists():
                        raw_loc_ref = ""  # Force auto-resolve
                        _loc_stale = True
                if not raw_loc_ref:
                    shot_location = shot.get("location", shot.get("location_name", ""))
                    if shot_location and location_masters_map:
                        loc_upper = shot_location.upper().strip()
                        # Normalize: strip slashes and extra whitespace for comparison
                        def _norm_loc(s):
                            return s.replace("/", " ").replace("-", " ").replace("_", " ").split()
                        loc_words = _norm_loc(loc_upper)

                        # 1. Exact match
                        raw_loc_ref = location_masters_map.get(loc_upper, "")

                        # 2. Normalized word match (handles COASTAL ROAD / COUNTRYSIDE → COASTAL ROAD   COUNTRYSIDE)
                        if not raw_loc_ref:
                            for map_key, map_url in location_masters_map.items():
                                mk_words = _norm_loc(map_key)
                                if loc_words == mk_words:
                                    raw_loc_ref = map_url
                                    break

                        # 3. Scored partial match — prefer BEST overlap, not first match
                        # V17.7.3: Fixes location mis-matching (e.g. "HALLWAY" → wrong MANOR location)
                        if not raw_loc_ref:
                            # Strip time-of-day suffixes from shot location for matching
                            _time_words = {"NIGHT", "DAY", "EVENING", "MORNING", "AFTERNOON", "LATE", "DAWN", "DUSK", "LATER", "CONTINUOUS", "VARIOUS", "THAT"}
                            loc_words_clean = [w for w in loc_words if w not in _time_words]
                            if not loc_words_clean:
                                loc_words_clean = loc_words

                            _best_loc_score = 0
                            _best_loc_url = ""
                            for map_key, map_url in location_masters_map.items():
                                mk_words = _norm_loc(map_key)
                                # Count overlapping meaningful words
                                fwd = sum(1 for w in loc_words_clean if w in mk_words)
                                rev = sum(1 for w in mk_words if w in loc_words_clean)
                                # Must have at least 1 overlap
                                if fwd == 0:
                                    continue
                                # Coverage ratio: what fraction of shot location words are in the map key
                                coverage = fwd / len(loc_words_clean)
                                # Specificity: penalize map keys with many extra unmatched words
                                extra_words = len(mk_words) - rev
                                # Score = coverage (0-1) * 100, minus penalty for extra words
                                score = coverage * 100 - extra_words * 5
                                # Bonus for exact word count match
                                if len(mk_words) == len(loc_words_clean):
                                    score += 20
                                # Bonus if ALL shot words found in map key (full coverage)
                                if fwd == len(loc_words_clean):
                                    score += 15
                                if score > _best_loc_score:
                                    _best_loc_score = score
                                    _best_loc_url = map_url
                            if _best_loc_url and _best_loc_score >= 30:
                                raw_loc_ref = _best_loc_url
                if raw_loc_ref and not raw_loc_ref.startswith("/api/"):
                    loc_ref_display = _media_url(raw_loc_ref)
                else:
                    loc_ref_display = raw_loc_ref or ""

                # V27.1.4: Cache-buster — append &t={mtime} to prevent browser caching stale frames
                def _add_cache_buster(url_str):
                    """Add file mtime as cache-buster to /api/media URL."""
                    if not url_str or "/api/media" not in url_str:
                        return url_str
                    try:
                        # Extract path from URL
                        import urllib.parse as _up2
                        _parsed2 = _up2.urlparse(url_str)
                        _qs2 = _up2.parse_qs(_parsed2.query)
                        _raw_path2 = _qs2.get("path", [""])[0]
                        if _raw_path2:
                            _fp2 = Path(_raw_path2)
                            if not _fp2.is_absolute():
                                _fp2 = BASE_DIR / _fp2
                            if _fp2.exists():
                                _mtime = int(_fp2.stat().st_mtime)
                                sep = "&" if "?" in url_str else "?"
                                return f"{url_str}{sep}t={_mtime}"
                    except Exception:
                        pass
                    return url_str

                # V17.7: Normalize first_frame_url — ONLY return URLs for files that actually exist
                def _normalize_frame_url(shot, shot_id, project_path):
                    url = shot.get("first_frame_url", "")
                    path = shot.get("first_frame_path", "")
                    ff_dir = project_path / "first_frames"
                    project_name = project_path.name

                    # Helper: verify a path exists on disk before returning URL
                    def _wrap_if_exists(fpath):
                        try:
                            p = Path(fpath)
                            if p.exists() and p.is_file():
                                return _media_url(p)
                        except Exception:
                            pass
                        return None

                    # Helper: translate user-local paths to sandbox paths
                    def _translate_path(raw_path):
                        if not raw_path:
                            return None
                        # Direct check first
                        result = _wrap_if_exists(raw_path)
                        if result:
                            return result
                        # Try path translation (user's /Users/quantum/... → our sandbox)
                        markers = [f"pipeline_outputs/{project_name}/", f"ATLAS_CONTROL_SYSTEM/pipeline_outputs/{project_name}/"]
                        for marker in markers:
                            idx = raw_path.find(marker)
                            if idx >= 0:
                                rel = raw_path[idx + len(marker):]
                                candidate = project_path / rel
                                result = _wrap_if_exists(str(candidate))
                                if result:
                                    return result
                        return None

                    # 1) If URL is already /api/media, extract path and verify
                    if url and url.startswith("/api/media"):
                        import urllib.parse as _up
                        parsed = _up.urlparse(url)
                        qs = _up.parse_qs(parsed.query)
                        raw = qs.get("path", [""])[0]
                        result = _translate_path(raw)
                        if result:
                            return result

                    # 2) If URL is a raw filesystem path
                    if url and not url.startswith("/api/") and not url.startswith("http"):
                        result = _translate_path(url)
                        if result:
                            return result

                    # 3) If path field set
                    if path and not path.startswith("/api/"):
                        result = _translate_path(path)
                        if result:
                            return result

                    # 4) Last resort: scan disk for first_frames/{shot_id}.*
                    for ext in [".jpg", ".jpeg", ".png"]:
                        ff = ff_dir / f"{shot_id}{ext}"
                        if ff.exists():
                            return _media_url(ff)

                    # Nothing found — return empty string (no 404-producing URL)
                    return ""

                bundle["shot_gallery_rows"].append({
                    "shot_id": shot_id,
                    "scene_id": shot.get("scene_id"),
                    "description": shot.get("description", ""),  # V20.4: Shot description for UI display
                    "shot_type": shot.get("shot_type", shot.get("type", "medium")),  # V20.0: Enriched shot type
                    "type": shot.get("type", shot.get("shot_type", "medium")),
                    "duration": duration,
                    "duration_seconds": duration,
                    "is_extended": duration > 20,
                    "segment_count": len(segments) if segments else 0,
                    "segment_durations": [s.get("duration", 0) for s in segments] if segments else [],
                    "characters": shot.get("characters", []),
                    "ai_actor_cast": rebuilt_ai_actor_cast,  # V17 FIX: Use rebuilt from cast_map
                    "location": shot.get("location", shot.get("grid_location_hint", "")),
                    "has_dialogue": bool(dialogue_text),
                    "dialogue": dialogue_text,
                    "dialogue_text": dialogue_text,
                    "script_line_ref": shot.get("script_line_ref", ""),
                    "nano_prompt": shot.get("nano_prompt", ""),
                    "ltx_motion_prompt": shot.get("ltx_motion_prompt", ""),
                    # V21.2: nano_prompt IS the gated prompt — Authority Gate writes directly
                    "_gate_timestamp": shot.get("_gate_timestamp", ""),
                    "first_frame_path": shot.get("first_frame_path"),
                    "first_frame_url": _add_cache_buster(_normalize_frame_url(shot, shot_id, project_path)),
                    "video_path": shot.get("video_path"),
                    "video_url": _add_cache_buster((f"/api/media?path={shot.get('video_path')}" if shot.get("video_path") and not str(shot.get("video_path","")).startswith("/api/") else shot.get("video_path")) if shot.get("video_path") else None),
                    # V17.8: Kling video URL for multi-model support — populated from videos_kling/ directory
                    "video_url_kling": shot.get("video_url_kling") or None,
                    "emotional_beat": shot.get("emotional_beat"),
                    "emotional_tone": shot.get("emotional_tone"),
                    "duration_tier": shot.get("duration_tier"),
                    "_narrative": shot.get("_narrative"),  # V17: Narrative intelligence metadata
                    "segments": shot.get("segments", []),  # V17: Segment data for inspector
                    "extended_shot": shot.get("extended_shot", False),
                    "stitched_video_path": shot.get("stitched_video_path"),
                    # V17.5.2: Camera fields for UI display
                    "camera_body": shot.get("camera_body", ""),
                    "camera_style": shot.get("camera_style", ""),
                    "lens_specs": shot.get("lens_specs", ""),
                    "lens_type": shot.get("lens_type", ""),
                    # V17.5.2: Reference image URLs for UI hydration
                    "location_master_url": loc_ref_display,
                    "character_reference_url": char_ref_display,
                    "character_reference_urls": all_char_ref_urls,  # V18.2: ALL character refs for multi-char shots
                    # V17.5.2: Script-binding metadata
                    "beat_id": shot.get("beat_id", ""),
                    "blocking_role": shot.get("blocking_role", ""),
                    "eyeline_target": shot.get("eyeline_target", ""),
                    "screen_direction": shot.get("screen_direction", ""),
                    # V27.2: Variants are BUTTON-TRIGGERED only — not auto-displayed in grid
                    # UI shows variants only when user clicks "Generate Variants" button
                    # The _variants field is populated on-demand via /api/v18/multi-angle endpoint
                    "_variants": [],  # Empty by default — populated on-demand only
                    "has_variants": bool(shot.get("_variants")),  # Flag for UI button state
                    # V17.6: Vision badges for quality validation
                    "vision_badges": shot.get("vision", {}),
                    # V17.7: Continuity reference for shot chaining
                    "continuity_ref_url": shot.get("continuity_ref_url", ""),
                    "continuity_source": shot.get("continuity_source", ""),
                    # V17.7: Generation approval status
                    "approved": shot.get("approved", False),
                    "generation_status": shot.get("generation_status", ""),
                    # V29.16: Per-shot approval workflow fields
                    "_approval_status": shot.get("_approval_status", None),
                    "_approval_updated_at": shot.get("_approval_updated_at", None),
                    "_frame_identity_score": shot.get("_frame_identity_score", None),
                    # V17.7: Shot intent metadata (beat tagging)
                    "purpose": shot.get("purpose", ""),
                    "coverage_role": shot.get("coverage_role", ""),
                    "wardrobe_lock": shot.get("wardrobe_lock", {}),
                    "expected_elements": shot.get("expected_elements", []),
                    "intent_tags": shot.get("intent_tags", []),
                    "shot_role": shot.get("shot_role", ""),
                    "time_of_day": shot.get("time_of_day", ""),
                    # V17.8: Smart cut timing for legacy-compatible pacing
                    "smart_cut_timing": shot.get("smart_cut_timing", {}),
                    # V18: Master chain metadata for end-frame chaining
                    "_chain_first_frame_url": shot.get("_chain_first_frame_url", ""),
                    "_chain_source": shot.get("_chain_source", ""),
                    "_chain_master_shot": shot.get("_chain_master_shot", False),
                    # V18.2: Continuity gate state tracking
                    "state_in": shot.get("state_in", {}),
                    "state_out": shot.get("state_out", {}),
                    "_connector_shot": shot.get("_connector_shot", False),
                    "bridge_score": shot.get("bridge_score", None),
                    # V21.2: Scene type classification + enrichment metadata
                    "_scene_type": shot.get("_scene_type", ""),
                    "_scene_classification_confidence": shot.get("_scene_classification_confidence", 0),
                    "wardrobe_tag": shot.get("wardrobe_tag", ""),
                    "_emotion_layer": shot.get("_emotion_layer", ""),
                    "_broll": shot.get("_broll", False),
                    "_no_chain": shot.get("_no_chain", False),
                    "_intercut": shot.get("_intercut", False),
                    "script_line_ref": shot.get("script_line_ref", ""),
                    # V22.0: Juice Cinematic Reasoning Engine fields
                    "character_intent": shot.get("character_intent", {}),
                    "delta_prompt": shot.get("delta_prompt", ""),
                    "continuity_locks": shot.get("continuity_locks", {}),
                    "composition_hash": shot.get("composition_hash", ""),
                    "micro_action": shot.get("micro_action", ""),
                    "tempo": shot.get("tempo", ""),
                    "movement_intent": shot.get("movement_intent", ""),
                    "hand_state": shot.get("hand_state", ""),
                    "stature": shot.get("stature", ""),
                })
              except Exception as _shot_err:
                logger.warning(f"[UI_BUNDLE] Skipped shot {shot.get('shot_id','?')}: {_shot_err}")
            # V16.7: Extract unique lighting options from scenes for ui_controls
            lighting_set = set()
            for shot in shots:
                if shot.get("lighting"):
                    lighting_set.add(shot.get("lighting"))
                if shot.get("time_of_day"):
                    lighting_set.add(shot.get("time_of_day"))
            if lighting_set:
                bundle["ui_controls"]["lighting_options"] = sorted(list(lighting_set))
            else:
                bundle["ui_controls"]["lighting_options"] = ["candlelit", "cool_moon", "mixed_practical", "dawn", "dusk", "night", "day"]

            # V16.7: Location fallback - if locations_list is empty, extract from shot_plan
            if not bundle["locations_list"]:
                seen_locs = set()
                # Extract from scene_manifest
                for scene in shot_plan.get("scene_manifest", []):
                    loc = scene.get("location", scene.get("location_name", ""))
                    if loc and loc not in seen_locs:
                        seen_locs.add(loc)
                # Extract from shot locations
                for shot in shots:
                    loc = shot.get("location", shot.get("location_name", ""))
                    if loc and loc not in seen_locs:
                        seen_locs.add(loc)
                if seen_locs:
                    bundle["locations_list"] = sorted(list(seen_locs))
                    bundle["locations_from_shot_plan"] = True
                    logger.info(f"[UI_BUNDLE] Extracted {len(seen_locs)} locations from shot_plan")

            # V17.7: Assign pre-built location_masters_map to bundle (built before gallery loop)
            bundle["location_masters_map"] = location_masters_map

            # V16.7: Materialize segment prompts for extended shots
            for shot in shots:
                shot_id = shot.get("shot_id", "?")
                duration = shot.get("duration", shot.get("duration_seconds", 10))

                if duration > 20 and shot_id in bundle["segments_index"]:
                    segments = bundle["segments_index"][shot_id]
                    base_prompt = shot.get("nano_prompt", "")

                    # Materialize per-segment continuation prompts
                    for i, seg in enumerate(segments):
                        if i == 0:
                            seg["prompt"] = base_prompt
                            seg["continuation_rule"] = "initial"
                        else:
                            # Create continuation prompt
                            seg["prompt"] = f"continue_from_last_frame, {base_prompt[:200]}..."
                            seg["continuation_rule"] = "continue_from_previous_segment"
                            seg["requires_last_frame_ref"] = True

                    bundle["segments_index"][shot_id] = segments

        except Exception as e:
            logger.warning(f"[UI_BUNDLE] Could not load shot_plan: {e}")

    # Load master locks
    master_locks_path = project_path / "master_locks.json"
    if master_locks_path.exists():
        try:
            with open(master_locks_path) as f:
                locks_data = json.load(f)
            # V17.6: Use normalize_locks() for canonical field names
            _norm_locks = normalize_locks(locks_data)
            bundle["master_locks"]["characters"] = _norm_locks["characters"]
            bundle["master_locks"]["locations"] = _norm_locks["locations"]
            bundle["master_locks"]["casting"] = _norm_locks["casting"]
            bundle["master_locks"]["allLocked"] = all([
                bundle["master_locks"]["characters"],
                bundle["master_locks"]["locations"],
                bundle["master_locks"]["casting"]
            ])
        except Exception as e:
            logger.warning(f"[UI_BUNDLE] Could not load master_locks: {e}")

    # Load QA latest
    qa_history_path = project_path / "qa_history"
    if qa_history_path.exists() and qa_history_path.is_dir():
        qa_files = sorted(qa_history_path.glob("qa_*.json"), reverse=True)
        if qa_files:
            try:
                with open(qa_files[0]) as f:
                    bundle["qa_latest"] = json.load(f)
            except Exception as e:
                logger.warning(f"[UI_BUNDLE] Could not load QA latest: {e}")

    # Get realtime media from render outputs
    render_path = project_path / "renders"
    if render_path.exists():
        media_files = []
        for ext in ["*.jpg", "*.png", "*.mp4"]:
            media_files.extend(render_path.glob(ext))
        bundle["realtime_media"] = [
            {
                "path": _media_url(str(f)),
                "filename": f.name,
                "modified": f.stat().st_mtime
            }
            for f in sorted(media_files, key=lambda x: x.stat().st_mtime, reverse=True)[:50]
        ]

    # Run lint summary
    try:
        lint_results = []
        for shot in shots[:10]:  # Sample first 10 for summary
            lint_result = lint_shot_prompt(shot)
            lint_results.append(lint_result)

        if lint_results:
            bundle["lint_summary"] = {
                "sample_size": len(lint_results),
                "avg_score": sum(r.get("overall_score", 0) for r in lint_results) / len(lint_results),
                "clean_count": sum(1 for r in lint_results if r.get("status") == "clean"),
                "warn_count": sum(1 for r in lint_results if r.get("status") == "warn"),
                "blocked_count": sum(1 for r in lint_results if r.get("status") == "blocked")
            }
    except Exception as e:
        logger.warning(f"[UI_BUNDLE] Could not run lint summary: {e}")

    # =========================================================================
    # V21.6: AUTO-VALIDATION ON BUNDLE BUILD — "Open project = see truth"
    # Runs all checks, auto-fixes what it can, reports what it can't.
    # Results included in bundle so UI can show validation status bar.
    # Non-blocking — if any check crashes, bundle still returns.
    # =========================================================================
    _v216_validation = {
        "version": "V21.6",
        "checks": [],
        "auto_fixes_applied": 0,
        "warnings": 0,
        "blockers": 0,
        "ready_for_generation": True,
    }
    try:
        _v216_start = _time_module.time()

        # CHECK 1: Story Bible Beat Coverage — are any scenes missing beats?
        try:
            _sb_data = bundle.get("story_bible") or {}
            _sb_scenes = _sb_data.get("scenes", [])
            _scenes_without_beats = []
            _total_scenes_with_beats = 0
            for _sbs in _sb_scenes:
                _sbs_id = _sbs.get("scene_id", _sbs.get("id", ""))
                _sbs_beats = _sbs.get("beats", _sbs.get("story_beats", []))
                if not _sbs_beats or len(_sbs_beats) == 0:
                    _scenes_without_beats.append(_sbs_id)
                else:
                    _total_scenes_with_beats += 1
            _beat_status = "pass" if not _scenes_without_beats else ("warn" if len(_scenes_without_beats) <= 3 else "fail")
            _v216_validation["checks"].append({
                "name": "story_bible_beats",
                "status": _beat_status,
                "detail": f"{_total_scenes_with_beats}/{_total_scenes_with_beats + len(_scenes_without_beats)} scenes have beats",
                "missing_scenes": _scenes_without_beats[:10],
            })
            if _scenes_without_beats:
                _v216_validation["warnings"] += 1
                logger.warning(f"[V21.6 VALIDATE] {len(_scenes_without_beats)} scenes missing beats: {_scenes_without_beats}")
        except Exception as _e:
            _v216_validation["checks"].append({"name": "story_bible_beats", "status": "error", "detail": str(_e)})

        # CHECK 2: Cast Map Completeness — do all shot characters resolve?
        try:
            _cast = bundle.get("cast_map", {})
            _cast_keys_upper = {k.upper().strip() for k in _cast.keys()}
            _unresolved_chars = set()
            _total_char_refs = 0
            for _s in shots:
                for _c in (_s.get("characters") or []):
                    _cn = _c.upper().strip() if isinstance(_c, str) else (_c.get("name", "")).upper().strip()
                    _total_char_refs += 1
                    if _cn and _cn not in _cast_keys_upper:
                        # Try fuzzy: check if any cast key starts with or contains char name
                        _found = False
                        for _ck in _cast_keys_upper:
                            if _cn in _ck or _ck in _cn:
                                _found = True
                                break
                        if not _found:
                            _unresolved_chars.add(_cn)
            _cast_status = "pass" if not _unresolved_chars else "warn"
            _v216_validation["checks"].append({
                "name": "cast_map_completeness",
                "status": _cast_status,
                "detail": f"{_total_char_refs - len(_unresolved_chars)}/{_total_char_refs} character refs resolve",
                "unresolved": list(_unresolved_chars)[:10],
            })
            if _unresolved_chars:
                _v216_validation["warnings"] += 1
                logger.warning(f"[V21.6 VALIDATE] Unresolved characters: {_unresolved_chars}")
        except Exception as _e:
            _v216_validation["checks"].append({"name": "cast_map_completeness", "status": "error", "detail": str(_e)})

        # CHECK 3: Prompt Contamination — no-character shots with human performance language
        try:
            _HUMAN_MARKERS = ["micro-expression", "breathing chest", "blink pattern", "SAME FACE",
                              "face stable", "performance:", "subtext:", "mind racing",
                              "body tells a different story", "moment of understanding"]
            _contaminated_shots = []
            _auto_cleaned = 0
            for _s in shots:
                _s_chars = _s.get("characters", [])
                if _s_chars:
                    continue  # Has characters — human language is correct here
                _nano = _s.get("nano_prompt", "")
                _ltx = _s.get("ltx_motion_prompt", "")
                _combined = _nano + " " + _ltx
                _found_markers = [m for m in _HUMAN_MARKERS if m.lower() in _combined.lower()]
                if _found_markers:
                    _contaminated_shots.append(_s.get("shot_id", "?"))
                    # AUTO-FIX: Strip human markers from no-character prompts
                    import re as _re_v216
                    for _hm in _found_markers:
                        _hm_pattern = _re_v216.escape(_hm) + r'[^.]*[.,]?\s*'
                        if _nano:
                            _nano = _re_v216.sub(_hm_pattern, ' ', _nano, flags=_re_v216.IGNORECASE)
                        if _ltx:
                            _ltx = _re_v216.sub(_hm_pattern, ' ', _ltx, flags=_re_v216.IGNORECASE)
                    _s["nano_prompt"] = _re_v216.sub(r'\s{2,}', ' ', _nano).strip()
                    _s["ltx_motion_prompt"] = _re_v216.sub(r'\s{2,}', ' ', _ltx).strip()
                    _auto_cleaned += 1
            _contam_status = "pass" if not _contaminated_shots else "auto_fixed"
            _v216_validation["checks"].append({
                "name": "prompt_contamination",
                "status": _contam_status,
                "detail": f"{_auto_cleaned} no-character shots auto-cleaned" if _auto_cleaned else "All prompts clean",
                "fixed_shots": _contaminated_shots[:20],
            })
            if _auto_cleaned:
                _v216_validation["auto_fixes_applied"] += _auto_cleaned
                logger.info(f"[V21.6 VALIDATE] Auto-cleaned {_auto_cleaned} contaminated no-character shots")
                # Persist the cleaned shot plan
                try:
                    _sp_path_v216 = project_path / "shot_plan.json"
                    if _sp_path_v216.exists():
                        with open(_sp_path_v216) as _f216:
                            _sp_v216 = json.load(_f216)
                        _sp_v216["shots"] = shots
                        _sp_v216["_last_v216_clean"] = datetime.now().isoformat()
                        import tempfile as _tf216
                        _tmp216 = _tf216.NamedTemporaryFile(mode='w', dir=str(project_path), suffix='.json', delete=False)
                        json.dump(_sp_v216, _tmp216, indent=2)
                        _tmp216.close()
                        os.replace(_tmp216.name, str(_sp_path_v216))
                except Exception as _pe:
                    logger.warning(f"[V21.6 VALIDATE] Could not persist cleaned shot plan: {_pe}")
        except Exception as _e:
            _v216_validation["checks"].append({"name": "prompt_contamination", "status": "error", "detail": str(_e)})

        # CHECK 4: FAL API Key Health — validate at least one key works
        try:
            _fal_ok = False
            _fal_key_count = 0
            # Count available FAL keys from environment
            _fal_main = os.environ.get("FAL_KEY", "")
            if _fal_main:
                _fal_key_count += 1
            for _ki in range(1, 11):
                if os.environ.get(f"FAL_KEY_{_ki}", ""):
                    _fal_key_count += 1
            _fal_ok = _fal_key_count > 0
            _fal_status = "pass" if _fal_ok else "fail"
            _v216_validation["checks"].append({
                "name": "fal_api_keys",
                "status": _fal_status,
                "detail": f"{_fal_key_count} FAL key(s) configured" if _fal_ok else "NO FAL keys — generation will fail",
            })
            if not _fal_ok:
                _v216_validation["blockers"] += 1
                _v216_validation["ready_for_generation"] = False
        except Exception as _e:
            _v216_validation["checks"].append({"name": "fal_api_keys", "status": "error", "detail": str(_e)})

        # CHECK 5: Dialogue LTX Injection — shots with dialogue should have "character speaks:" in LTX
        try:
            _dlg_missing_ltx = 0
            _dlg_total = 0
            for _s in shots:
                _s_dlg = _s.get("dialogue_text", _s.get("dialogue", ""))
                if _s_dlg and len(str(_s_dlg)) > 5:
                    _dlg_total += 1
                    _s_ltx = _s.get("ltx_motion_prompt", "")
                    if "character speaks:" not in _s_ltx.lower() and "speaks:" not in _s_ltx.lower():
                        _dlg_missing_ltx += 1
            _dlg_status = "pass" if _dlg_missing_ltx == 0 else "warn"
            _v216_validation["checks"].append({
                "name": "dialogue_ltx_injection",
                "status": _dlg_status,
                "detail": f"{_dlg_total - _dlg_missing_ltx}/{_dlg_total} dialogue shots have LTX speaking markers",
            })
            if _dlg_missing_ltx:
                _v216_validation["warnings"] += 1
        except Exception as _e:
            _v216_validation["checks"].append({"name": "dialogue_ltx_injection", "status": "error", "detail": str(_e)})

        # CHECK 6: Scene Anchor System — color grades initialized?
        try:
            _anchor_path = project_path / "scene_anchors.json"
            _anchor_ok = _anchor_path.exists()
            _v216_validation["checks"].append({
                "name": "scene_anchors",
                "status": "pass" if _anchor_ok else "info",
                "detail": "Scene anchors loaded" if _anchor_ok else "Will auto-initialize on first generation",
            })
        except Exception as _e:
            _v216_validation["checks"].append({"name": "scene_anchors", "status": "error", "detail": str(_e)})

        # CHECK 7: Wardrobe existence
        try:
            _ward_path = project_path / "wardrobe.json"
            _ward_ok = _ward_path.exists()
            _v216_validation["checks"].append({
                "name": "wardrobe",
                "status": "pass" if _ward_ok else "info",
                "detail": "Wardrobe loaded" if _ward_ok else "Will auto-assign on first generation",
            })
        except Exception as _e:
            _v216_validation["checks"].append({"name": "wardrobe", "status": "error", "detail": str(_e)})

        _v216_elapsed = round((_time_module.time() - _v216_start) * 1000)
        _v216_validation["elapsed_ms"] = _v216_elapsed
        logger.info(f"[V21.6 VALIDATE] Complete in {_v216_elapsed}ms — "
                    f"{len(_v216_validation['checks'])} checks, "
                    f"{_v216_validation['auto_fixes_applied']} auto-fixes, "
                    f"{_v216_validation['warnings']} warnings, "
                    f"{_v216_validation['blockers']} blockers")

    except Exception as _v216_e:
        logger.warning(f"[V21.6 VALIDATE] Validation failed (non-blocking): {_v216_e}")
        _v216_validation["checks"].append({"name": "validation_engine", "status": "error", "detail": str(_v216_e)})

    bundle["validation"] = _v216_validation

    # Save to cache
    try:
        cache_dir.mkdir(exist_ok=True)
        with open(cache_file, 'w') as f:
            json.dump(bundle, f, indent=2)
        # Clear dirty flag (both filesystem AND in-memory)
        if dirty_flag.exists():
            try:
                dirty_flag.unlink()
            except Exception:
                pass
        _BUNDLE_DIRTY_MEMORY.discard(project_name)
        # V18.4: Store in memory cache (avoids disk read on next request)
        _BUNDLE_MEMORY_CACHE[project_name] = (bundle, _time_module.time())
        logger.info(f"[UI_BUNDLE] Generated fresh bundle for {project_name}")
    except Exception as e:
        logger.warning(f"[UI_BUNDLE] Could not cache bundle: {e}")
        # V18.4: STILL clear dirty flag on failure — prevents infinite rebuild loop
        _BUNDLE_DIRTY_MEMORY.discard(project_name)

    return bundle


@app.post("/api/v16/ui/invalidate-cache/{project_name}")
async def invalidate_ui_cache(project_name: str):
    """V16.7: Mark UI cache as dirty so next bundle request regenerates."""
    project_path = get_project_path(project_name)
    if not project_path.exists():
        return {"success": False, "error": "Project not found"}

    cache_dir = project_path / "ui_cache"
    dirty_flag = cache_dir / "bundle.dirty"

    try:
        cache_dir.mkdir(exist_ok=True)
        dirty_flag.touch()
        return {"success": True, "message": f"Cache invalidated for {project_name}"}
    except Exception as e:
        return {"success": False, "error": str(e)}


# =============================================================================
# V16.7 AUTONOMOUS HUMAN VERIFICATION MODULE
# =============================================================================

@app.post("/api/v16/auto-verify/{project_name}")
async def auto_verify_project(project_name: str, request: Dict = Body(default={})):
    """
    V16.7: Autonomous Human Verification Module

    Performs comprehensive automated verification simulating what a human would check:
    1. Story Bible completeness
    2. Cast map validity (no empty casts, all characters assigned)
    3. Duration consistency (LTX prompts match shot durations)
    4. Segment plans for extended shots
    5. Prompt quality (no duplicates, proper structure)
    6. Director/Writer profile application
    7. Critic scores (Director, Manifest, Preflight)
    8. Asset paths validity

    Returns a verification report with pass/fail status and fix suggestions.
    """
    project_path = get_project_path(project_name)
    if not project_path.exists():
        return {"success": False, "error": f"Project '{project_name}' not found"}

    report = {
        "project": project_name,
        "timestamp": datetime.now().isoformat(),
        "overall_status": "PASS",
        "checks": [],
        "issues": [],
        "fixes_applied": [],
        "fix_suggestions": []
    }

    def add_check(name: str, status: str, details: str = "", fix: str = None):
        report["checks"].append({
            "name": name,
            "status": status,
            "details": details
        })
        if status == "FAIL":
            report["issues"].append(f"{name}: {details}")
            if fix:
                report["fix_suggestions"].append(fix)
            report["overall_status"] = "FAIL"
        elif status == "WARN" and report["overall_status"] != "FAIL":
            report["overall_status"] = "WARN"

    # === CHECK 1: STORY BIBLE ===
    story_bible = None
    story_bible_path = project_path / "story_bible.json"
    if story_bible_path.exists():
        try:
            with open(story_bible_path) as f:
                story_bible = json.load(f)
            if story_bible.get("characters") and story_bible.get("locations"):
                add_check("story_bible", "PASS", f"{len(story_bible.get('characters', []))} characters, {len(story_bible.get('locations', []))} locations")
            else:
                add_check("story_bible", "WARN", "Missing characters or locations", "Run /api/auto/generate-characters and /api/auto/generate-locations")
        except Exception as e:
            add_check("story_bible", "FAIL", str(e))
    else:
        add_check("story_bible", "FAIL", "story_bible.json not found", "Run /api/auto/generate-story-bible")

    # === CHECK 2: CAST MAP ===
    cast_map = {}
    cast_map_path = project_path / "cast_map.json"
    if cast_map_path.exists():
        try:
            with open(cast_map_path) as f:
                cast_map = json.load(f)
            cast_count = len([k for k in cast_map.keys() if not k.startswith("_")])
            if cast_count > 0:
                # Check for low fit scores
                low_scores = [k for k, v in cast_map.items() if not k.startswith("_") and isinstance(v, dict) and v.get("fit_score", 100) < 50]
                if low_scores:
                    add_check("cast_map", "WARN", f"{cast_count} cast, {len(low_scores)} with low fit scores: {low_scores}", "Run /api/v6/casting/auto-cast with overwrite=true")
                else:
                    add_check("cast_map", "PASS", f"{cast_count} characters cast")
            else:
                add_check("cast_map", "FAIL", "Cast map is empty", "Run /api/v6/casting/auto-cast")
        except Exception as e:
            add_check("cast_map", "FAIL", str(e))
    else:
        add_check("cast_map", "FAIL", "cast_map.json not found", "Run /api/v6/casting/auto-cast")

    # === CHECK 3: SHOT PLAN ===
    shots = []
    shot_plan_path = project_path / "shot_plan.json"
    if shot_plan_path.exists():
        try:
            with open(shot_plan_path) as f:
                shot_plan = _sp_guard(json.load(f))
            shots = shot_plan.get("shots", [])
            if shots:
                add_check("shot_plan", "PASS", f"{len(shots)} shots")
            else:
                add_check("shot_plan", "FAIL", "No shots in shot_plan", "Run /api/shot-plan/expand")
        except Exception as e:
            add_check("shot_plan", "FAIL", str(e))
    else:
        add_check("shot_plan", "FAIL", "shot_plan.json not found")

    # === CHECK 4: DURATION CONSISTENCY ===
    import re
    duration_mismatches = []
    for shot in shots:
        shot_id = shot.get("shot_id", "?")
        duration = shot.get("duration", shot.get("duration_seconds", 10))
        ltx_prompt = shot.get("ltx_motion_prompt", "")

        if ltx_prompt:
            duration_match = re.search(r'(\d+)s\b', ltx_prompt)
            if duration_match:
                ltx_duration = int(duration_match.group(1))
                if ltx_duration != duration:
                    duration_mismatches.append(f"{shot_id}: shot={duration}s, ltx={ltx_duration}s")

    if duration_mismatches:
        add_check("duration_consistency", "FAIL", f"{len(duration_mismatches)} mismatches", "Run /api/shot-plan/fix-v16")
    else:
        add_check("duration_consistency", "PASS", "All LTX durations match shot durations")

    # === CHECK 5: EXTENDED SHOT SEGMENTS ===
    extended_missing_segments = []
    for shot in shots:
        shot_id = shot.get("shot_id", "?")
        duration = shot.get("duration", shot.get("duration_seconds", 10))
        segments = shot.get("segments", [])

        if duration > 20 and not segments:
            extended_missing_segments.append(shot_id)

    if extended_missing_segments:
        add_check("extended_segments", "FAIL", f"{len(extended_missing_segments)} extended shots missing segments", "Run /api/shot-plan/fix-v16")
    else:
        add_check("extended_segments", "PASS", "All extended shots have segment plans")

    # === CHECK 6: PROMPT DEDUPLICATION ===
    prompt_duplicates = 0
    for shot in shots:
        nano_prompt = shot.get("nano_prompt", "")
        if nano_prompt:
            parts = [p.strip().lower() for p in nano_prompt.split(",")]
            unique = set(parts)
            if len(parts) > len(unique):
                prompt_duplicates += 1

    if prompt_duplicates > 0:
        add_check("prompt_deduplication", "WARN", f"{prompt_duplicates} prompts have duplicates", "Run /api/shot-plan/fix-v16")
    else:
        add_check("prompt_deduplication", "PASS", "No duplicate prompt parts")

    # === CHECK 7: AI ACTOR CAST IN SHOTS ===
    shots_missing_cast = []
    for shot in shots:
        shot_id = shot.get("shot_id", "?")
        characters = shot.get("characters", [])
        ai_actor_cast = shot.get("ai_actor_cast", {})

        if characters and not ai_actor_cast:
            shots_missing_cast.append(shot_id)

    if shots_missing_cast:
        add_check("shot_cast_embedding", "WARN", f"{len(shots_missing_cast)} shots missing ai_actor_cast", "Run /api/shot-plan/fix-v16 to propagate cast")
    else:
        add_check("shot_cast_embedding", "PASS", "All shots have ai_actor_cast embedded")

    # === CHECK 8: RUN CRITICS ===
    try:
        from CRITIC_AGENT import get_director_review, validate_manifest_for_render, run_preflight_before_render

        target_runtime = story_bible.get("runtime_target_seconds", 2700) if story_bible else 2700

        director_review = get_director_review(shots, story_bible or {}, target_runtime)
        director_grade = director_review.get("overall_grade", "?")
        if director_grade in ["A", "B"]:
            add_check("director_critic", "PASS", f"Grade: {director_grade}")
        else:
            add_check("director_critic", "WARN", f"Grade: {director_grade}", "Review director notes and adjust pacing")

        manifest_result = validate_manifest_for_render(shots=shots, target_runtime_seconds=target_runtime)
        if manifest_result.get("ready_for_render"):
            add_check("manifest_critic", "PASS", "Ready for render")
        else:
            add_check("manifest_critic", "FAIL", f"{len(manifest_result.get('issues', []))} issues", "Fix manifest issues before render")

        preflight_result = run_preflight_before_render(shots=shots, project_type="generic")
        if preflight_result.get("passed") or preflight_result.get("block_count", 0) == 0:
            add_check("preflight_critic", "PASS", "No blockers")
        else:
            add_check("preflight_critic", "FAIL", f"{preflight_result.get('block_count', 0)} blockers", "Resolve blockers before render")
    except Exception as e:
        add_check("critics", "WARN", f"Could not run critics: {e}")

    # === CHECK 9: RUN LINT ===
    try:
        lint_stats = {"clean": 0, "warn": 0, "blocked": 0, "total_score": 0}
        for shot in shots[:20]:  # Sample first 20
            lint_result = lint_shot_prompt(shot)
            status = lint_result.get("status", "warn")
            lint_stats[status] = lint_stats.get(status, 0) + 1
            lint_stats["total_score"] += lint_result.get("overall_score", 0)

        sample_size = min(20, len(shots))
        avg_score = lint_stats["total_score"] / sample_size if sample_size > 0 else 0

        if lint_stats["blocked"] > 0:
            add_check("prompt_lint", "FAIL", f"{lint_stats['blocked']} blocked, avg score: {avg_score:.1f}", "Review blocked prompts")
        elif lint_stats["warn"] > sample_size // 2:
            add_check("prompt_lint", "WARN", f"{lint_stats['warn']} warnings, avg score: {avg_score:.1f}")
        else:
            add_check("prompt_lint", "PASS", f"Avg score: {avg_score:.1f}, {lint_stats['clean']} clean")
    except Exception as e:
        add_check("prompt_lint", "WARN", f"Could not run lint: {e}")

    # === AUTO-FIX IF REQUESTED ===
    auto_fix = request.get("auto_fix", False)
    if auto_fix and report["overall_status"] != "PASS":
        # Run fix-v16 to address most issues
        try:
            fix_response = await fix_shot_plan_v16({"project": project_name})
            if fix_response.get("success"):
                report["fixes_applied"].append(f"fix-v16: {fix_response.get('fixed_count', 0)} issues fixed")
        except Exception as e:
            report["fixes_applied"].append(f"fix-v16 failed: {e}")

        # Invalidate UI cache
        await invalidate_ui_cache(project_name)

    # Save verification report
    reports_dir = project_path / "verification_reports"
    reports_dir.mkdir(exist_ok=True)
    report_file = reports_dir / f"verify_{datetime.now().strftime('%Y%m%d_%H%M%S')}.json"

    try:
        with open(report_file, 'w') as f:
            json.dump(report, f, indent=2)
        report["report_path"] = str(report_file)
    except Exception as e:
        logger.warning(f"[AUTO-VERIFY] Could not save report: {e}")

    return report


@app.post("/api/v16/regenerate-headshot")
async def regenerate_headshot(request: Dict = Body(...)):
    """
    V16.6: Regenerate a single AI actor's headshot using nano-banana-pro.

    Request body:
    {
        "actor_name": "Jackson Wright",
        "project": "Ravencroft_V6_upload"  // Optional
    }
    """
    actor_name = request.get("actor_name", "")
    if not actor_name:
        return {"success": False, "error": "actor_name is required"}

    # Load AI actor from library to get their description
    actors_path = BASE_DIR / "ai_actors_library.json"
    if not actors_path.exists():
        return {"success": False, "error": "AI actors library not found"}

    try:
        with open(actors_path) as f:
            actors_data = json.load(f)

        actor = None
        for a in actors_data.get("actors", []):
            if a.get("name", "").upper() == actor_name.upper():
                actor = a
                break

        if not actor:
            return {"success": False, "error": f"Actor '{actor_name}' not found in library"}

        # Build prompt from actor data
        age_range = actor.get("age_range", "30-40")
        prompt = actor.get("image_prompt", actor.get("description", ""))
        if not prompt:
            prompt = f"{actor_name}, {age_range} year old, professional headshot, studio lighting"

        # Generate using nano-banana-pro
        import fal_client
        FAL_KEY = os.getenv("FAL_KEY")
        if not FAL_KEY:
            return {"success": False, "error": "FAL_KEY not configured in .env"}

        os.environ["FAL_KEY"] = FAL_KEY

        # V26.1: Three-quarter angle character study — NOT direct-to-camera portrait
        # Direct-to-camera headshots cause every nano-edit frame to replicate the pose
        # resulting in characters always staring at the lens in generated shots.
        # Three-quarter angle gives nano-edit a natural off-camera pose to reference.
        headshot_prompt = f"Cinematic character study, three-quarter angle pose, natural expression looking slightly off-camera, {prompt}, motivated practical lighting, 85mm lens, shallow depth of field, eye-line 20 degrees off lens axis, NOT looking at camera, NO direct eye contact with viewer, high quality"

        result = fal_client.run(
            "fal-ai/nano-banana-pro",
            arguments={
                "prompt": headshot_prompt,
                "aspect_ratio": "1:1",
                "resolution": "2K",
                "output_format": "jpeg",
                "num_images": 1
            }
        )

        if result and result.get("images"):
            image_url = result["images"][0].get("url", "")
            if image_url:
                # Download and save the image
                import requests
                img_response = requests.get(image_url, timeout=30)
                if img_response.status_code == 200:
                    # Save to ai_actor_headshots directory
                    headshots_dir = BASE_DIR / "ai_actor_headshots"
                    headshots_dir.mkdir(exist_ok=True)

                    filename = f"{actor_name.upper().replace(' ', '_')}_HEADSHOT.jpg"
                    save_path = headshots_dir / filename

                    with open(save_path, 'wb') as f:
                        f.write(img_response.content)

                    logger.info(f"[V16.6] Regenerated headshot for {actor_name}: {save_path}")

                    return {
                        "success": True,
                        "actor_name": actor_name,
                        "headshot_path": str(save_path),
                        "headshot_url": f"/ai_actor_headshots/{filename}"
                    }

        return {"success": False, "error": "Failed to generate headshot image"}

    except Exception as e:
        logger.error(f"[V16.6] Regenerate headshot failed: {e}")
        _sentry_capture_exception(e)
        return {"success": False, "error": str(e)}


