# =========================================================================

@app.post("/api/v16/qa/run")
async def run_script_qa(request: Dict = Body(...)):
    """
    V16.6: Run comprehensive Script QA and save to history.

    Runs all critics, validates casting, checks preflight, and returns a report.
    Saves the result to pipeline_outputs/{project}/qa_history/qa_{timestamp}.json
    """
    project = request.get("project")
    if not project:
        return {"success": False, "error": "project is required"}

    project_dir = PIPELINE_OUTPUTS_DIR / project
    if not project_dir.exists():
        return {"success": False, "error": f"Project '{project}' not found"}

    try:
        timestamp = datetime.now().isoformat()

        # Load project data
        shot_plan_path = project_dir / "shot_plan.json"
        if not shot_plan_path.exists():
            return {"success": False, "error": "No shot_plan.json found"}

        with open(shot_plan_path) as f:
            shot_plan = _sp_guard(json.load(f))

        shots = shot_plan.get("shots", [])

        # Run checks
        blockers = []
        warnings = []

        # 1. CASTING CHECK
        cast_complete = True
        for shot in shots:
            if shot.get("characters") and not shot.get("ai_actor_cast"):
                cast_complete = False
                blockers.append(f"Shot {shot.get('shot_id')} missing ai_actor_cast")

        # 2. DIRECTOR GRADE (simulate based on shot quality)
        total_shots = len(shots)
        shots_with_ltx = sum(1 for s in shots if s.get("ltx_motion_prompt"))
        shots_with_nano = sum(1 for s in shots if s.get("nano_prompt"))
        shots_enhanced = sum(1 for s in shots if s.get("ltx_director_enhanced"))

        coverage = shots_with_ltx / max(1, total_shots)
        enhancement = shots_enhanced / max(1, total_shots)

        if coverage >= 0.95 and enhancement >= 0.8:
            director_grade = "A"
        elif coverage >= 0.85:
            director_grade = "B"
        elif coverage >= 0.7:
            director_grade = "C"
        else:
            director_grade = "D"
            blockers.append("Director grade D: insufficient LTX coverage")

        # 3. MANIFEST CHECK
        manifest_status = "PASS" if shots_with_nano >= total_shots * 0.9 else "WARN"
        if manifest_status == "WARN":
            warnings.append(f"Only {shots_with_nano}/{total_shots} shots have nano_prompt")

        # 4. PREFLIGHT CHECK
        preflight_blocks = 0
        preflight_info = 0

        # Check for extended shots without segments
        for shot in shots:
            duration = shot.get("duration", shot.get("duration_seconds", 10))
            if duration > 20 and not shot.get("segments"):
                preflight_info += 1

        preflight_status = "PASS" if preflight_blocks == 0 else "BLOCK"
        if preflight_info > 0:
            preflight_status = "INFO_ONLY"

        # 5. ASSETS CHECK (check for generated frames)
        fal_cache = BASE_DIR / "fal_cache"
        project_assets = list(fal_cache.glob(f"*{project}*")) if fal_cache.exists() else []
        assets_status = "PASS" if len(project_assets) > 0 else "NONE"

        # 6. PROMPT LINT CHECK (integrated from PreflightCritic)
        lint_clean = 0
        lint_warn = 0
        lint_blocked = 0
        for shot in shots:
            lint_result = lint_shot_prompt(shot)
            if lint_result["status"] == "clean":
                lint_clean += 1
            elif lint_result["status"] == "warn":
                lint_warn += 1
            else:
                lint_blocked += 1
                if len(blockers) < 10:  # Limit blocker messages
                    blockers.append(f"Shot {shot.get('shot_id')} prompt lint BLOCKED: {', '.join(lint_result['flags'][:2])}")

        lint_score = lint_clean / max(1, total_shots)
        if lint_blocked > 0:
            lint_status = "BLOCK"
        elif lint_warn > total_shots * 0.3:  # >30% warnings
            lint_status = "WARN"
        else:
            lint_status = "PASS"

        # Determine overall status
        ready = len(blockers) == 0 and director_grade in ["A", "B"] and lint_blocked == 0
        status = "PASS" if ready else "BLOCK"

        report = {
            "project": project,
            "timestamp": timestamp,
            "status": status,
            "ready": ready,
            "director": {"grade": director_grade, "coverage": round(coverage, 2), "enhancement": round(enhancement, 2)},
            "manifest": {"status": manifest_status, "warnings": len(warnings)},
            "assets": {"status": assets_status, "count": len(project_assets)},
            "preflight": {"status": preflight_status, "blocks": preflight_blocks, "info": preflight_info},
            "lint": {"status": lint_status, "clean": lint_clean, "warn": lint_warn, "blocked": lint_blocked, "score": round(lint_score, 2)},
            "blockers": blockers,
            "warnings": warnings,
            "summary": {
                "total_shots": total_shots,
                "shots_with_ltx": shots_with_ltx,
                "shots_enhanced": shots_enhanced,
                "cast_complete": cast_complete
            }
        }

        # Save to QA history
        qa_history_dir = project_dir / "qa_history"
        qa_history_dir.mkdir(exist_ok=True)

        qa_filename = f"qa_{datetime.now().strftime('%Y%m%d_%H%M%S')}.json"
        with open(qa_history_dir / qa_filename, 'w') as f:
            json.dump(report, f, indent=2)

        logger.info(f"[V16.6 QA] Ran Script QA for {project}: {status}, grade={director_grade}")
        return report

    except Exception as e:
        logger.error(f"[V16.6 QA] Failed: {e}")
        _sentry_capture_exception(e)
        return {"success": False, "error": str(e)}


@app.get("/api/v16/qa/history")
async def get_qa_history(project: str):
    """
    V16.6: Get QA history for a project.

    Returns list of previous QA runs, newest first.
    """
    if not project:
        return {"success": False, "error": "project is required"}

    project_dir = PIPELINE_OUTPUTS_DIR / project
    qa_history_dir = project_dir / "qa_history"

    if not qa_history_dir.exists():
        return {"history": []}

    try:
        history = []
        for qa_file in sorted(qa_history_dir.glob("qa_*.json"), reverse=True):
            with open(qa_file) as f:
                history.append(json.load(f))

        return {"history": history[:20]}  # Last 20 runs
    except Exception as e:
        logger.error(f"[V16.6 QA] History load failed: {e}")
        return {"history": [], "error": str(e)}


@app.post("/api/v16/render/shot")
async def render_shot_v16(request: Dict = Body(...)):
    """
    V16.6: Render a single shot with before/after mutation tracking.

    Returns mutation data for diff viewer.
    """
    project = request.get("project")
    shot_id = request.get("shot_id")
    scope = request.get("scope", "all")  # first_frame, video, all

    if not project or not shot_id:
        return {"success": False, "error": "project and shot_id required"}

    project_dir = PIPELINE_OUTPUTS_DIR / project
    shot_plan_path = project_dir / "shot_plan.json"

    if not shot_plan_path.exists():
        return {"success": False, "error": "No shot_plan.json found"}

    try:
        with open(shot_plan_path) as f:
            shot_plan = _sp_guard(json.load(f))

        # Find the shot
        shot = None
        for s in shot_plan.get("shots", []):
            if s.get("shot_id") == shot_id:
                shot = s
                break

        if not shot:
            return {"success": False, "error": f"Shot {shot_id} not found"}

        # Capture BEFORE state
        fal_cache = BASE_DIR / "fal_cache"
        before_frame = None
        before_video = None

        # Look for existing assets
        for ext in [".jpg", ".png", ".jpeg"]:
            frame_path = fal_cache / f"{shot_id}{ext}"
            if frame_path.exists():
                before_frame = str(frame_path)
                break

        for ext in [".mp4", ".webm"]:
            video_path = fal_cache / f"{shot_id}{ext}"
            if video_path.exists():
                before_video = str(video_path)
                break

        before_state = {
            "first_frame_path": before_frame,
            "video_path": before_video,
            "nano_prompt": shot.get("nano_prompt"),
            "ltx_motion_prompt": shot.get("ltx_motion_prompt"),
            "duration_seconds": shot.get("duration", shot.get("duration_seconds")),
            "segments": shot.get("segments"),
            "ai_actor_cast": shot.get("ai_actor_cast")
        }

        # TODO: Actually render the shot using nano-banana-pro and ltxv2
        # For now, we return the mutation structure without actual rendering
        # Real implementation would call fal_client.run() with locked models

        timestamp = datetime.now().isoformat()

        # Simulate after state (in real impl, this would be the new render)
        after_state = {
            "first_frame_path": before_frame,  # Would be new path after render
            "video_path": before_video,  # Would be new path after render
            "nano_prompt": shot.get("nano_prompt"),
            "ltx_motion_prompt": shot.get("ltx_motion_prompt"),
            "duration_seconds": shot.get("duration", shot.get("duration_seconds")),
            "segments": shot.get("segments"),
            "ai_actor_cast": shot.get("ai_actor_cast")
        }

        mutation = {
            "event": "SHOT_REGEN",
            "project": project,
            "shot_id": shot_id,
            "scope": scope,
            "timestamp": timestamp,
            "before": before_state,
            "after": after_state,
            "success": True,
            "message": f"Shot {shot_id} render request queued (scope: {scope})"
        }

        # Save mutation to history
        mutations_dir = project_dir / "mutations"
        mutations_dir.mkdir(exist_ok=True)

        mutation_file = f"shot_{shot_id}_{datetime.now().strftime('%Y%m%d_%H%M%S')}.json"
        with open(mutations_dir / mutation_file, 'w') as f:
            json.dump(mutation, f, indent=2)

        logger.info(f"[V16.6] Render shot {shot_id} requested (scope: {scope})")
        return mutation

    except Exception as e:
        logger.error(f"[V16.6] Render shot failed: {e}")
        _sentry_capture_exception(e)
        return {"success": False, "error": str(e)}


# =========================================================================
# V16.6 PROMPT LINT AGENT
# =========================================================================

def lint_shot_prompt(shot: dict) -> dict:
    """
    V16.6 Prompt Lint Agent - Evaluates a shot prompt across 7 cinematic dimensions.

    Returns a lint result with scores, flags, and suggestions.
    """
    nano_prompt = shot.get("nano_prompt", "") or ""
    ltx_prompt = shot.get("ltx_motion_prompt", "") or ""
    duration = shot.get("duration", shot.get("duration_seconds", 10))
    dialogue = shot.get("dialogue", "") or shot.get("dialogue_text", "") or ""
    emotional_beat = shot.get("emotional_beat", "") or ""
    shot_type = shot.get("shot_type", shot.get("type", "medium")) or ""
    characters = shot.get("characters", [])

    combined_prompt = f"{nano_prompt} {ltx_prompt}".lower()

    flags = []
    suggestions = []
    scores = {}

    # LINT-01: Narrative Purpose Clarity
    purpose_signals = ["emotional", "establishing", "transition", "payoff", "confrontation",
                       "revelation", "dread", "tension", "hope", "grief", "opening", "closing",
                       "pov", "observer", "witness", "memory", "predator"]
    has_purpose = any(sig in combined_prompt for sig in purpose_signals) or bool(emotional_beat)
    scores["purpose_clarity"] = {"score": 1.0 if has_purpose else 0.5}
    if not has_purpose:
        flags.append("Shot describes visuals but not narrative purpose")
        suggestions.append("Add emotional beat or narrative function")

    # LINT-02: Camera Behavior vs Mechanical Motion
    behavioral_terms = ["behaves like", "observes", "hesitates", "stalks", "watches",
                        "drifts", "follows", "discovers", "reveals", "lingers"]
    mechanical_only = ["dolly", "pan", "tilt", "track", "zoom", "crane", "push"]

    has_behavioral = any(term in combined_prompt for term in behavioral_terms)
    has_mechanical = any(term in combined_prompt for term in mechanical_only)

    if has_behavioral:
        scores["camera_behavior"] = {"score": 1.0}
    elif has_mechanical:
        scores["camera_behavior"] = {"score": 0.6}
        flags.append("Camera motion specified without behavioral intent")
        suggestions.append("Describe camera intent, not just motion")
    else:
        scores["camera_behavior"] = {"score": 0.8}  # Static is fine

    # LINT-03: Duration-Content Alignment
    if duration > 20:
        stillness_terms = ["stillness", "contemplative", "lingering", "meditative", "waiting"]
        segment_terms = ["segment", "stitch", "extended"]
        has_justification = any(t in combined_prompt for t in stillness_terms + segment_terms)
        has_segments = bool(shot.get("segments"))

        if has_justification or has_segments:
            scores["duration_alignment"] = {"score": 1.0}
        else:
            scores["duration_alignment"] = {"score": 0.4}
            flags.append(f"Extended duration ({duration}s) without stillness or segmentation rationale")
            suggestions.append("Add stillness rationale or segment plan for extended shots")
    elif duration < 8:
        complex_terms = ["complex", "multiple", "sequence", "transforms"]
        has_complexity = any(t in combined_prompt for t in complex_terms)
        scores["duration_alignment"] = {"score": 0.6 if has_complexity else 1.0}
        if has_complexity:
            suggestions.append("Short shot may not support complex actions")
    else:
        scores["duration_alignment"] = {"score": 1.0}

    # LINT-04: Lighting Logic
    contrast_terms = ["contrast", "cool base", "warm relief", "recedes", "source", "pools"]
    adjective_only = ["moody", "dramatic", "cinematic", "atmospheric"]

    has_contrast = any(t in combined_prompt for t in contrast_terms)
    has_adjective = any(t in combined_prompt for t in adjective_only)

    if has_contrast:
        scores["lighting_logic"] = {"score": 1.0}
    elif has_adjective:
        scores["lighting_logic"] = {"score": 0.7}
        flags.append("Lighting adjectives present without contrast rules")
        suggestions.append("Add contrast logic (cool/warm, light direction)")
    else:
        scores["lighting_logic"] = {"score": 0.85}  # Implicit is acceptable

    # LINT-05: Actor Humanism Anchors (CRITICAL for dialogue)
    humanism_terms = ["breathing", "blink", "micro", "stillness", "tension", "hesitant",
                      "restrained", "explosive", "delivery", "performance", "speaking"]
    has_humanism = any(t in combined_prompt for t in humanism_terms)

    if dialogue and len(dialogue) > 5:
        if has_humanism:
            scores["actor_humanism"] = {"score": 1.0}
        else:
            scores["actor_humanism"] = {"score": 0.3}
            flags.append("Dialogue present without performance or humanism cues")
            suggestions.append("Specify performance style for dialogue")
    else:
        scores["actor_humanism"] = {"score": 1.0}  # N/A for non-dialogue

    # LINT-06: Negative Prompt Completeness
    negative_prompt = shot.get("negative_prompt", "") or ""
    failure_terms = ["morphing", "drift", "extra limb", "jitter", "distort", "blur"]
    has_constraints = any(t in (combined_prompt + negative_prompt).lower() for t in failure_terms)

    if has_constraints:
        scores["negative_constraints"] = {"score": 1.0}
    elif characters:
        scores["negative_constraints"] = {"score": 0.6}
        flags.append("Missing failure-prevention constraints (face/motion stability)")
        suggestions.append("Add negative prompts for morphing, drift, stability")
    else:
        scores["negative_constraints"] = {"score": 0.9}

    # LINT-07: Redundancy / Prompt Bloat
    words = combined_prompt.split()
    word_counts = {}
    for w in words:
        if len(w) > 4:
            word_counts[w] = word_counts.get(w, 0) + 1

    redundant = [w for w, c in word_counts.items() if c > 3]
    if redundant:
        scores["redundancy"] = {"score": 0.7}
        flags.append(f"Redundant descriptors detected: {', '.join(redundant[:3])}")
    else:
        scores["redundancy"] = {"score": 1.0}

    # Calculate overall score
    overall_score = sum(d["score"] for d in scores.values()) / len(scores)

    # Determine status
    if overall_score >= 0.85:
        status = "clean"
    elif overall_score >= 0.70:
        status = "warn"
    else:
        status = "blocked"

    # CRITICAL: Dialogue without acting guidance = blocked
    if dialogue and len(dialogue) > 5 and scores.get("actor_humanism", {}).get("score", 1) < 0.5:
        status = "blocked"

    return {
        "shot_id": shot.get("shot_id", "unknown"),
        "overall_score": round(overall_score, 2),
        "status": status,
        "flags": flags,
        "suggestions": suggestions,
        "lint_results": scores
    }


@app.post("/api/v16/lint/shot")
async def lint_single_shot(request: Dict = Body(...)):
    """
    V16.6: Lint a single shot prompt.
    """
    shot = request.get("shot", {})
    if not shot:
        return {"success": False, "error": "shot data required"}

    result = lint_shot_prompt(shot)
    return result


@app.post("/api/v16/lint/project")
async def lint_project_prompts(request: Dict = Body(...)):
    """
    V16.6: Lint all shot prompts in a project.

    Returns per-shot lint results and an overall project readiness assessment.
    """
    project = request.get("project")
    if not project:
        return {"success": False, "error": "project is required"}

    project_dir = PIPELINE_OUTPUTS_DIR / project
    shot_plan_path = project_dir / "shot_plan.json"

    if not shot_plan_path.exists():
        return {"success": False, "error": "No shot_plan.json found"}

    try:
        with open(shot_plan_path) as f:
            shot_plan = _sp_guard(json.load(f))

        shots = shot_plan.get("shots", [])
        results = []

        for shot in shots:
            lint_result = lint_shot_prompt(shot)
            results.append(lint_result)

        # Summary stats
        total = len(results)
        clean = sum(1 for r in results if r["status"] == "clean")
        warn = sum(1 for r in results if r["status"] == "warn")
        blocked = sum(1 for r in results if r["status"] == "blocked")

        avg_score = sum(r["overall_score"] for r in results) / max(1, total)

        # Project-level status
        if blocked > 0:
            project_status = "blocked"
        elif warn > total * 0.2:  # >20% warnings
            project_status = "warn"
        else:
            project_status = "clean"

        return {
            "project": project,
            "status": project_status,
            "summary": {
                "total_shots": total,
                "clean": clean,
                "warn": warn,
                "blocked": blocked,
                "average_score": round(avg_score, 2)
            },
            "shots": results
        }

    except Exception as e:
        logger.error(f"[V16.6 LINT] Failed: {e}")
        _sentry_capture_exception(e)
        return {"success": False, "error": str(e)}


@app.post("/api/v17/reconcile-first-frames")
async def reconcile_first_frames(request: Dict = Body(...)):
    """V17.3: Reconcile first-frame files on disk with shot_plan.json.
    Scans the first_frames/ directory and updates shot_plan.json for any
    shots that have files on disk but no recorded first_frame_url."""
    try:
        project = request.get("project", "")
        project_path = get_project_path(project)
        shot_plan_path = project_path / "shot_plan.json"
        ff_dir = project_path / "first_frames"

        if not shot_plan_path.exists():
            return {"success": False, "error": "shot_plan.json not found"}
        if not ff_dir.exists():
            return {"success": False, "error": "first_frames/ directory not found"}

        import fcntl, tempfile
        with open(shot_plan_path) as f:
            data = json.load(f)

        shots = data.get("shots", [])
        shot_map = {s.get("shot_id"): i for i, s in enumerate(shots)}

        disk_files = sorted(ff_dir.glob("*.jpg"))
        synced = 0
        orphaned = []

        for ff_path in disk_files:
            shot_id = ff_path.stem
            if shot_id in shot_map:
                idx = shot_map[shot_id]
                shot = shots[idx]
                updated = False
                if not shot.get("first_frame_path"):
                    shot["first_frame_path"] = str(ff_path)
                    updated = True
                if not shot.get("first_frame_url"):
                    shot["first_frame_url"] = f"/api/media?path={ff_path}"
                    updated = True
                if updated:
                    synced += 1
            else:
                orphaned.append(ff_path.name)

        # Atomic write with file locking
        tmp = tempfile.NamedTemporaryFile(mode='w', dir=project_path, suffix='.tmp', delete=False)
        json.dump(data, tmp, indent=2)
        tmp.flush()
        os.fsync(tmp.fileno())
        tmp.close()
        os.replace(tmp.name, shot_plan_path)

        # Invalidate UI cache
        cache_dir = project_path / "ui_cache"
        if cache_dir.exists():
            dirty_flag = cache_dir / "bundle.dirty"
            dirty_flag.touch()

        after_count = sum(1 for s in shots if s.get("first_frame_url"))
        return {
            "success": True,
            "project": project,
            "disk_files": len(disk_files),
            "shots_with_ff": after_count,
            "newly_synced": synced,
            "orphaned_count": len(orphaned),
            "orphaned_files": orphaned[:20],
            "total_shots": len(shots),
            "remaining_to_generate": len(shots) - after_count
        }
    except Exception as e:
        logger.error(f"Reconcile first-frames failed: {e}")
        return {"success": False, "error": str(e)}


