@app.post("/api/v17/edit/operation")
async def edit_operation(request: Dict = Body(...)):
    """V17.4: Execute an edit operation (trim, split, ripple_delete, slip, slide, transition)."""
    if not EDIT_ENGINE_AVAILABLE:
        return {"success": False, "error": "Edit engine not available"}
    try:
        project = request.get("project", "")
        operation = request.get("operation", "")
        clip_id = request.get("clip_id", "")

        if not project or not operation or not clip_id:
            return {"success": False, "error": "project, operation, and clip_id are required"}

        project_path = get_project_path(project)
        engine = create_engine(str(project_path))
        engine.load_timeline()

        result = False
        new_clip_id = None

        if operation == "trim":
            new_duration = request.get("new_duration", 5.0)
            trim_end = request.get("trim_end", True)
            result = EditOperations.trim_clip(engine.timeline, clip_id, new_duration, trim_end)
        elif operation == "split":
            split_time = request.get("split_time", 0)
            new_clip_id = EditOperations.split_clip(engine.timeline, clip_id, split_time)
            result = new_clip_id is not None
        elif operation == "ripple_delete":
            result = EditOperations.ripple_delete(engine.timeline, clip_id)
        elif operation == "slip":
            offset = request.get("offset", 0)
            result = EditOperations.slip_clip(engine.timeline, clip_id, offset)
        elif operation == "slide":
            offset = request.get("offset", 0)
            result = EditOperations.slide_clip(engine.timeline, clip_id, offset)
        elif operation == "transition":
            t_type = request.get("transition_type", "dissolve")
            duration = request.get("duration", 1.0)
            position = request.get("position", "in")
            try:
                tt = TransitionType(t_type)
            except ValueError:
                tt = TransitionType.DISSOLVE
            result = EditOperations.add_transition(engine.timeline, clip_id, tt, duration, position)
        else:
            return {"success": False, "error": f"Unknown operation: {operation}"}

        if result:
            engine.save_timeline()

        resp = {"success": result, "project": project, "operation": operation, "clip_id": clip_id}
        if new_clip_id:
            resp["new_clip_id"] = new_clip_id
        return resp
    except Exception as e:
        logger.error(f"[EDIT] Operation failed: {e}")
        return {"success": False, "error": str(e)[:300]}


@app.post("/api/v17/edit/effect")
async def edit_effect(request: Dict = Body(...)):
    """V17.4: Add or remove an effect on a clip."""
    if not EDIT_ENGINE_AVAILABLE:
        return {"success": False, "error": "Edit engine not available"}
    try:
        project = request.get("project", "")
        clip_id = request.get("clip_id", "")
        action = request.get("action", "add")  # add or remove
        effect_type = request.get("effect_type", "")
        params = request.get("params", {})

        if not project or not clip_id or not effect_type:
            return {"success": False, "error": "project, clip_id, and effect_type are required"}

        project_path = get_project_path(project)
        engine = create_engine(str(project_path))
        engine.load_timeline()

        found = False
        for track in engine.timeline.tracks:
            for clip in track.clips:
                if clip.clip_id == clip_id:
                    if action == "add":
                        from atlas_edit_engine import Effect
                        clip.effects.append(Effect(effect_type=effect_type, params=params))
                        found = True
                    elif action == "remove":
                        clip.effects = [e for e in clip.effects if e.effect_type != effect_type]
                        found = True
                    break
            if found:
                break

        if found:
            engine.save_timeline()

        return {"success": found, "project": project, "clip_id": clip_id, "action": action, "effect_type": effect_type}
    except Exception as e:
        logger.error(f"[EDIT] Effect operation failed: {e}")
        return {"success": False, "error": str(e)[:300]}


@app.post("/api/v17/edit/clip-preview/{project}")
async def render_clip_preview(project: str, request: Dict = Body(...)):
    """V17.4: Render a quick preview of a single clip with its effects."""
    if not EDIT_ENGINE_AVAILABLE:
        return {"success": False, "error": "Edit engine not available"}
    try:
        project_path = get_project_path(project)
        clip_id = request.get("clip_id", "")
        if not clip_id:
            return {"success": False, "error": "clip_id required"}

        engine = create_engine(str(project_path))
        engine.load_timeline()

        # Find the clip
        target_clip = None
        for track in engine.timeline.tracks:
            for clip in track.clips:
                if clip.clip_id == clip_id:
                    target_clip = clip
                    break
            if target_clip:
                break

        if not target_clip:
            return {"success": False, "error": f"Clip {clip_id} not found"}

        from atlas_edit_engine import FFmpegRenderEngine
        renderer = FFmpegRenderEngine()
        preview_dir = project_path / "edit_previews"
        preview_dir.mkdir(exist_ok=True)
        preview_path = preview_dir / f"preview_{clip_id}.mp4"
        result = renderer.render_clip_preview(target_clip, str(preview_path))
        return {"success": True, "project": project, "clip_id": clip_id, **result}
    except Exception as e:
        logger.error(f"[EDIT] Clip preview failed: {e}")
        return {"success": False, "error": str(e)[:300]}


