@app.post("/api/v17/loa/pre-gen-check")
async def loa_pre_gen_check(request: Dict = Body(...)):
    """Manual LOA pre-generation check. Returns blocking errors + auto-fixes."""
    project = request.get("project", "")
    project_path = PIPELINE_OUTPUTS_DIR / project
    if not project_path.exists():
        return {"error": f"Project {project} not found"}

    if not LOA_AVAILABLE:
        return {"error": "LOA not available", "loa_loaded": False}

    shot_plan_path = project_path / "shot_plan.json"
    if not shot_plan_path.exists():
        return {"error": "No shot plan"}

    shot_plan = json.loads(shot_plan_path.read_text())
    shots = shot_plan.get("shots", [])

    cast_map = {}
    cast_path = project_path / "cast_map.json"
    if cast_path.exists():
        cast_map = json.loads(cast_path.read_text())

    loc_masters = {}
    loc_dir = project_path / "location_masters"
    if loc_dir.exists():
        for ext in ["jpg", "jpeg", "png", "webp"]:
            for img in loc_dir.glob(f"*.{ext}"):
                loc_masters[img.stem.upper().replace("_", " ")] = f"/api/media?path={str(img)}"

    # V17.7.4: Pass scene_manifest for location cross-check
    _sm = shot_plan.get("scene_manifest", shot_plan.get("scenes", []))
    result = run_loa_pre_generation(shots, str(project_path), cast_map=cast_map,
                                    location_masters=loc_masters, scene_manifest=_sm)
    return result


