@app.post("/api/v18/emotion-layer/inject")
async def emotion_layer_inject(request: Dict = Body(...)):
    """Inject emotion acting blocks into shot plan prompts."""
    project = request.get("project", "")
    scene_id = request.get("scene_id", None)
    project_path = PIPELINE_OUTPUTS_DIR / project
    if not project_path.exists():
        return {"success": False, "error": "Project not found"}
    try:
        from atlas_agents.emotion_layer_agent import (
            load_emotion_layer, inject_emotion_into_ltx,
            inject_emotion_into_nano, EMOTION_MARKER
        )
        sp_path = project_path / "shot_plan.json"
        with open(sp_path) as f:
            data = json.load(f)
        shots = data.get("shots", [])
        emotion_layer = load_emotion_layer(str(project_path))

        injected = 0
        for shot in shots:
            shot_id = shot.get("shot_id", "")
            sid = shot_id.split("_")[0] if "_" in shot_id else ""
            if scene_id and sid != scene_id:
                continue

            scene_key = f"scene_{sid}"
            scene_emotions = emotion_layer.get(scene_key, {})
            shot_emotion = scene_emotions.get(shot_id, {})
            if not shot_emotion:
                continue

            acting_block = shot_emotion.get("acting_block", "")
            emotion_state = shot_emotion.get("emotion_state", {})
            ltx = shot.get("ltx_motion_prompt", "")

            if acting_block and EMOTION_MARKER not in ltx:
                shot["ltx_motion_prompt"] = inject_emotion_into_ltx(ltx, acting_block)
                chars = shot.get("characters", [])
                if chars and emotion_state:
                    shot["nano_prompt"] = inject_emotion_into_nano(
                        shot.get("nano_prompt", ""), emotion_state, chars[0]
                    )
                injected += 1

        # Save updated shot plan
        import tempfile as _tf_emo
        _fd, _tmp = _tf_emo.mkstemp(dir=str(project_path), suffix=".json")
        with os.fdopen(_fd, 'w') as f:
            json.dump(data, f, indent=2, default=str)
        os.replace(_tmp, str(sp_path))

        # Invalidate cache
        cache_path = project_path / "ui_cache" / "bundle.json.dirty"
        cache_path.parent.mkdir(parents=True, exist_ok=True)
        cache_path.touch()

        return {"success": True, "injected": injected, "scene_filter": scene_id or "all"}
    except Exception as e:
        return {"success": False, "error": str(e)}


@app.post("/api/v18/emotion-layer/validate")
async def emotion_layer_validate(request: Dict = Body(...)):
    """Validate emotion continuity within scenes."""
    project = request.get("project", "")
    project_path = PIPELINE_OUTPUTS_DIR / project
    if not project_path.exists():
        return {"success": False, "error": "Project not found"}
    try:
        from atlas_agents.emotion_layer_agent import (
            load_emotion_layer, validate_scene_emotion_continuity, validate_emotion_prompt
        )
        emotion_layer = load_emotion_layer(str(project_path))
        sp_path = project_path / "shot_plan.json"
        with open(sp_path) as f:
            shots = json.load(f).get("shots", [])

        continuity_warnings = []
        prompt_issues = []
        for scene_key, scene_data in emotion_layer.items():
            warnings = validate_scene_emotion_continuity(scene_data)
            continuity_warnings.extend(warnings)

        for shot in shots:
            ltx = shot.get("ltx_motion_prompt", "")
            chars = shot.get("characters", [])
            if chars:  # Only validate shots with characters
                validation = validate_emotion_prompt(ltx)
                if not validation.get("has_acting_block"):
                    prompt_issues.append(f"{shot.get('shot_id', '?')}: missing ACTING block")

        return {
            "success": True,
            "continuity_warnings": continuity_warnings,
            "prompt_issues": prompt_issues,
            "total_issues": len(continuity_warnings) + len(prompt_issues),
        }
    except Exception as e:
        return {"success": False, "error": str(e)}


