@app.post("/api/v18/continuity-gate")
async def continuity_gate_endpoint(request: Dict = Body(...)):
    """
    V18.2: CONTINUITY GATE — Director Brain pre-render validator.
    Validates state transitions, assigns coverage roles, computes bridge scores.
    Optionally auto-inserts connector shots for continuity violations.
    """
    project = request.get("project", "")
    scene_id = request.get("scene_id", None)
    auto_fix = request.get("auto_fix", False)
    project_path = PIPELINE_OUTPUTS_DIR / project
    if not project_path.exists():
        return {"error": f"Project {project} not found"}

    try:
        from atlas_agents.continuity_gate import run_continuity_gate, enrich_shots_with_state

        shot_plan_path = project_path / "shot_plan.json"
        with open(shot_plan_path, 'r') as f:
            data = json.load(f)
        shots = data.get("shots", [])

        # Filter to scene if specified
        if scene_id:
            scene_shots = [s for s in shots if s.get("scene_id") == scene_id]
        else:
            scene_shots = shots

        if not scene_shots:
            return {"error": f"No shots found for scene {scene_id}" if scene_id else "No shots found"}

        # Enrich with state fields
        enriched = enrich_shots_with_state(scene_shots, scene_id or "001")

        # Run gate
        result = run_continuity_gate(scene_shots, scene_id=scene_id or "001", auto_fix=auto_fix)

        # If auto_fix inserted connectors, persist
        if auto_fix and result.get("connectors_inserted", 0) > 0:
            with open(shot_plan_path, 'w') as f:
                json.dump(data, f, indent=2)
            _invalidate_bundle_cache(project)
            logger.info(f"[CONTINUITY-GATE] Persisted {result['connectors_inserted']} connector shots to shot_plan")

        result["enriched_count"] = enriched
        return result

    except Exception as e:
        logger.error(f"[CONTINUITY-GATE] Error: {e}")
        return {"error": str(e)}


@app.post("/api/v21/script-fidelity-audit")
async def script_fidelity_audit_endpoint(request: Dict = Body(...)):
    """
    V21.9: Script Fidelity Audit — comprehensive cross-reference of ALL shot prompts
    against original screenplay and story bible. Checks beat coverage, V21.9 regressions,
    pacing, and prompt quality. Optionally auto-fixes issues.
    """
    project = request.get("project", "")
    auto_fix = request.get("auto_fix", False)
    if not project:
        return {"error": "Missing project name"}
    try:
        sys.path.insert(0, str(Path(__file__).parent / "tools"))
        from script_fidelity_audit import load_project, build_beat_map, run_regression_checks, analyze_pacing, auto_fix_issues, check_beat_injection
        shots, bible, script_text, sp_data, proj_dir = load_project(project)
        beat_map = build_beat_map(bible)
        fix_count = 0
        if auto_fix:
            fix_count = auto_fix_issues(shots)
            if fix_count > 0:
                import tempfile
                if isinstance(sp_data, dict):
                    sp_data["shots"] = shots
                tmp = tempfile.NamedTemporaryFile(mode="w", dir=str(proj_dir), suffix=".json", delete=False)
                json.dump(sp_data, tmp, indent=2)
                tmp.close()
                os.replace(tmp.name, str(proj_dir / "shot_plan.json"))
        regressions = run_regression_checks(shots)
        pacing = analyze_pacing(shots)
        scene_shots_map = {}
        for s in shots:
            scene_shots_map.setdefault(s.get("scene_id", "???"), []).append(s)
        beat_coverage = {}
        for sid in sorted(scene_shots_map.keys()):
            beats = beat_map.get(sid, [])
            if beats:
                cov, details = check_beat_injection(scene_shots_map[sid], beats)
                beat_coverage[sid] = {"coverage": round(cov, 3), "total": len(beats), "covered": sum(1 for d in details if d["covered"])}
        return {
            "project": project, "total_shots": len(shots), "total_beats": sum(len(b) for b in beat_map.values()),
            "beat_coverage": beat_coverage,
            "regressions": {k: len(v) for k, v in regressions.items()},
            "pacing": pacing,
            "fixes_applied": fix_count,
            "all_clean": all(not v for v in regressions.values()),
        }
    except Exception as e:
        logger.error(f"[SCRIPT-FIDELITY-AUDIT] Error: {e}")
        return {"error": str(e)}


