@app.post("/api/v17/dialogue-cuts")
async def dialogue_cuts_endpoint(request: Dict = Body(...)):
    """
    V17.8 DIALOGUE CUT ENGINE
    Generate smart conversation pacing for a dialogue scene.
    Returns a cut plan with shot types, framing, character focus, and durations.
    Can also apply the cuts to the shot plan.
    """
    project = request.get("project")
    scene_id = request.get("scene_id")
    apply = request.get("apply", False)  # If True, insert cuts into shot_plan

    if not project or not scene_id:
        return JSONResponse({"error": "project and scene_id required"}, status_code=400)

    try:
        project_path = PIPELINE_OUTPUTS_DIR / project
        shot_plan_path = project_path / "shot_plan.json"
        story_bible_path = project_path / "story_bible.json"

        with open(shot_plan_path, 'r') as f:
            shot_plan = _sp_guard(json.load(f))
        story_bible = {}
        if story_bible_path.exists():
            with open(story_bible_path, 'r') as f:
                story_bible = json.load(f)

        # Find scene data
        scene_meta = {}
        scene_beats = []
        for scene in story_bible.get("scenes", []):
            sid = scene.get("scene_id", scene.get("id", ""))
            if str(sid) == str(scene_id):
                scene_meta = scene
                scene_beats = scene.get("beats", [])
                break

        # Gather all dialogue from scene shots + beats
        scene_shots = [s for s in shot_plan.get("shots", []) if s.get("scene_id") == scene_id]
        all_dialogue = ""
        for beat in scene_beats:
            dlg = beat.get("dialogue", "")
            if dlg:
                all_dialogue += dlg + " "
        if not all_dialogue:
            for s in scene_shots:
                dlg = s.get("dialogue_text", s.get("dialogue", ""))
                if dlg:
                    all_dialogue += dlg + " "

        # Calculate total duration for this scene
        total_duration = sum(s.get("duration", 8) for s in scene_shots)
        if total_duration < 10:
            total_duration = scene_meta.get("estimated_duration", 60)

        # Get characters and location
        characters = list(set(
            c if isinstance(c, str) else c.get("name", "")
            for s in scene_shots for c in s.get("characters", [])
        ))
        location = scene_meta.get("location", scene_shots[0].get("location", "") if scene_shots else "")

        # Detect cross-location
        is_cross = False
        locations_map = {}
        combined_text = all_dialogue.lower() + " " + str(scene_meta).lower()
        if any(kw in combined_text for kw in ["v.o.", "voice over", "phone", "intercut", "cross-cut"]):
            is_cross = True

        # Generate cuts
        from tools.dialogue_cut_engine import DialogueCutEngine
        engine = DialogueCutEngine(story_bible, shot_plan)
        cuts = engine.generate_cut_plan(
            dialogue_text=all_dialogue,
            total_duration=total_duration,
            characters=characters,
            location=location,
            emotional_tone=scene_meta.get("emotional_tone", "neutral"),
            is_cross_location=is_cross,
            locations_map=locations_map,
        )

        explanation = engine.explain_cuts(cuts)
        logger.info(f"[V17.8 DIALOGUE-CUTS] Scene {scene_id}: {len(cuts)} cuts, {total_duration}s")

        result = {
            "success": True,
            "scene_id": scene_id,
            "cuts": cuts,
            "cut_count": len(cuts),
            "total_duration": total_duration,
            "characters": characters,
            "is_cross_location": is_cross,
            "explanation": explanation,
        }

        if apply:
            # TODO: Insert cuts as new shots into shot_plan
            result["applied"] = False
            result["apply_note"] = "Apply mode coming in next version — review cuts first"

        return result

    except Exception as e:
        logger.error(f"[DIALOGUE-CUTS] Error: {e}")
        return {"success": False, "error": str(e)}


