@app.post("/api/v17/script-fidelity/auto-fix")
async def script_fidelity_auto_fix(request: Dict = Body(...)):
    """
    V17.7.4: Auto-fix shot prompts based on script fidelity suggestions.
    Enriches nano_prompt and ltx_motion_prompt with missing actions/props from beats.
    """
    project = request.get("project", "")
    scene_id = request.get("scene_id", None)
    dry_run = request.get("dry_run", True)
    project_path = PIPELINE_OUTPUTS_DIR / project

    if not project_path.exists():
        return {"error": f"Project {project} not found"}

    try:
        from atlas_agents.script_fidelity_agent import run_script_fidelity_check

        # Run the check first
        result = run_script_fidelity_check(str(project_path), scene_id=scene_id)
        fixes = result.get("suggested_fixes", [])

        if not fixes:
            return {"success": True, "message": "No fidelity fixes needed", "fixes_applied": 0}

        if dry_run:
            return {
                "success": True,
                "dry_run": True,
                "fixes_proposed": len(fixes),
                "fixes": fixes,
                "message": f"{len(fixes)} shots need prompt enrichment"
            }

        # Apply fixes to shot_plan.json
        sp_path = project_path / "shot_plan.json"
        with open(sp_path) as f:
            shot_plan = _sp_guard(json.load(f))

        shots = shot_plan.get("shots", [])
        shot_map = {s.get("shot_id"): s for s in shots}
        applied = 0

        for fix in fixes:
            sid = fix.get("shot_id", "")
            shot = shot_map.get(sid)
            if not shot:
                continue

            suggestions = fix.get("suggestions", {})
            beat_desc = fix.get("beat_description", "")

            # Enrich nano_prompt: append beat action description
            nano_add = suggestions.get("nano_prompt_add", "")
            if nano_add and beat_desc:
                current_nano = shot.get("nano_prompt", "") or ""
                # Don't duplicate if already contains the beat description
                if beat_desc[:30].lower() not in current_nano.lower():
                    shot["nano_prompt"] = current_nano.rstrip(". ") + f". {beat_desc}."
                    shot["_fidelity_enriched"] = True
                    applied += 1

            # Enrich ltx_motion_prompt: append character action
            ltx_add = suggestions.get("ltx_motion_add", "")
            if ltx_add:
                current_ltx = shot.get("ltx_motion_prompt", "") or ""
                if ltx_add.lower() not in current_ltx.lower():
                    shot["ltx_motion_prompt"] = current_ltx.rstrip(". ") + f". {ltx_add}."

        if applied > 0:
            # Atomic write
            import tempfile
            tmp = tempfile.NamedTemporaryFile(mode='w', dir=str(sp_path.parent),
                                              suffix='.tmp', delete=False)
            json.dump(shot_plan, tmp, indent=2)
            tmp.close()
            import os
            os.replace(tmp.name, str(sp_path))
            _invalidate_bundle_cache(project)
            logger.info(f"[SCRIPT_FIDELITY] Applied {applied} prompt enrichments to {project}")

        return {
            "success": True,
            "fixes_applied": applied,
            "total_proposed": len(fixes),
            "message": f"Enriched {applied} shot prompts with script beat details"
        }

    except Exception as e:
        logger.error(f"[SCRIPT_FIDELITY] Auto-fix error: {e}")
        return {"error": str(e)}


# =============================================================================
# V18.3.1 SHOT ADVISOR — Script-Connected Per-Shot Intelligence
# =============================================================================
# The "last agent" — analyzes each shot against script beats, dialogue, actions,
# props, and emotional arcs. Returns SUGGESTIONS with accept/reject per shot.
# User keeps full control — nothing auto-applies without permission.
# =============================================================================

@app.get("/api/v18/shot-advisor/{project}/{shot_id}")
async def shot_advisor_single(project: str, shot_id: str):
    """
    V18.3.1: Shot Advisor — per-shot analysis against script beats.
    Returns structured suggestions the user can accept or reject.
    """
    project_path = PIPELINE_OUTPUTS_DIR / project
    if not project_path.exists():
        return JSONResponse({"error": f"Project {project} not found"}, status_code=404)

    try:
        # Load shot plan
        with open(project_path / "shot_plan.json") as f:
            shot_plan = _sp_guard(json.load(f))
        shots = shot_plan.get("shots", [])
        shot = next((s for s in shots if s.get("shot_id") == shot_id), None)
        if not shot:
            return JSONResponse({"error": f"Shot {shot_id} not found"}, status_code=404)

        # Load story bible
        sb_path = project_path / "story_bible.json"
        story_bible = {}
        if sb_path.exists():
            with open(sb_path) as f:
                story_bible = json.load(f)

        # Run script fidelity for this single shot
        from atlas_agents.script_fidelity_agent import run_script_fidelity_check
        result = run_script_fidelity_check(str(project_path), scene_id=shot_id[:3])
        per_shot = result.get("per_shot", {})
        shot_report = per_shot.get(shot_id, {})

        # Build suggestions
        suggestions = []
        fidelity_score = shot_report.get("fidelity_score", 100)

        # 1. Dialogue suggestions
        dlg = (shot.get("dialogue_text") or shot.get("dialogue") or "").strip()
        nano = shot.get("nano_prompt", "")
        ltx = shot.get("ltx_motion_prompt", "")
        if dlg and "character speaks:" not in ltx.lower():
            chars = shot.get("characters", [])
            speaker = chars[0] if chars else "Character"
            suggestions.append({
                "type": "dialogue",
                "severity": "high",
                "field": "ltx_motion_prompt",
                "description": f"Missing dialogue performance in LTX prompt",
                "current_snippet": ltx[:100],
                "suggested_addition": f'character speaks: "{dlg[:150]}", lips moving naturally with emotion',
                "reason": "LTX-2 generates static faces without explicit speaking direction"
            })

        # 2. Beat action suggestions
        beat_desc = shot_report.get("beat_description", "")
        missing_actions = shot_report.get("missing_actions", [])
        if missing_actions:
            suggestions.append({
                "type": "action",
                "severity": "high" if len(missing_actions) > 2 else "medium",
                "field": "nano_prompt",
                "description": f"Missing script actions: {', '.join(missing_actions[:5])}",
                "current_snippet": nano[:100],
                "suggested_addition": f"character performs: {beat_desc[:150]}",
                "reason": f"Script beat describes actions not in the visual prompt"
            })

        # 3. Prop suggestions
        missing_props = shot_report.get("missing_props", [])
        if missing_props:
            suggestions.append({
                "type": "props",
                "severity": "medium",
                "field": "nano_prompt",
                "description": f"Missing props from script: {', '.join(missing_props[:5])}",
                "current_snippet": nano[:100],
                "suggested_addition": f"with {', '.join(missing_props[:3])} visible in frame",
                "reason": "Script mentions these objects but they're not in the visual prompt"
            })

        # 4. Generic prompt detection
        if shot_report.get("is_generic", False):
            suggestions.append({
                "type": "generic",
                "severity": "high",
                "field": "nano_prompt",
                "description": "Prompt appears to be a generic template with no script-specific content",
                "current_snippet": nano[:100],
                "suggested_addition": beat_desc[:200] if beat_desc else "Add specific action from script",
                "reason": "Generic prompts produce generic-looking shots that don't match your script"
            })

        # 5. Emotion/acting suggestions
        emotion = shot.get("emotion", shot.get("_emotion", ""))
        if dlg and not emotion:
            suggestions.append({
                "type": "emotion",
                "severity": "low",
                "field": "ltx_motion_prompt",
                "description": "Dialogue shot has no emotion directive",
                "current_snippet": ltx[:100],
                "suggested_addition": "emotional delivery, natural facial expression shifts",
                "reason": "Adding emotion helps LTX-2 generate more expressive performances"
            })

        # Cost for re-rendering this shot
        dur = shot.get("duration", shot.get("duration_seconds", 6))
        rerender_cost = round(FAL_COST_FRAME_EDIT + (dur * FAL_COST_VIDEO_PER_SEC), 2)

        return {
            "shot_id": shot_id,
            "fidelity_score": fidelity_score,
            "beat_description": beat_desc[:300],
            "dialogue": dlg[:200],
            "characters": shot.get("characters", []),
            "shot_type": shot.get("shot_type", ""),
            "duration": dur,
            "rerender_cost_usd": rerender_cost,
            "suggestions": suggestions,
            "suggestion_count": len(suggestions),
            "prompt_preview": {
                "nano": nano[:200],
                "ltx": ltx[:200]
            }
        }

    except Exception as e:
        logger.error(f"[SHOT-ADVISOR] Error for {shot_id}: {e}")
        return JSONResponse({"error": str(e)}, status_code=500)


@app.post("/api/v18/shot-advisor/apply")
async def shot_advisor_apply(request: Dict = Body(...)):
    """
    V18.3.1: Apply accepted Shot Advisor suggestions to shot prompts.
    Only applies suggestions the user explicitly accepted.
    """
    project = request.get("project")
    shot_id = request.get("shot_id")
    accepted = request.get("accepted_suggestions", [])  # list of suggestion types to apply

    if not project or not shot_id or not accepted:
        return JSONResponse({"error": "project, shot_id, accepted_suggestions required"}, status_code=400)

    project_path = PIPELINE_OUTPUTS_DIR / project
    sp_path = project_path / "shot_plan.json"

    try:
        with open(sp_path) as f:
            data = json.load(f)
        shots = data.get("shots", [])
        shot = next((s for s in shots if s.get("shot_id") == shot_id), None)
        if not shot:
            return JSONResponse({"error": f"Shot {shot_id} not found"}, status_code=404)

        # First get the suggestions
        from atlas_agents.script_fidelity_agent import run_script_fidelity_check
        result = run_script_fidelity_check(str(project_path), scene_id=shot_id[:3])
        per_shot = result.get("per_shot", {})
        shot_report = per_shot.get(shot_id, {})

        applied = []
        nano = shot.get("nano_prompt", "")
        ltx = shot.get("ltx_motion_prompt", "")

        for suggestion_type in accepted:
            if suggestion_type == "dialogue":
                dlg = (shot.get("dialogue_text") or shot.get("dialogue") or "").strip()
                if dlg and "character speaks:" not in ltx.lower():
                    chars = shot.get("characters", [])
                    speaker = chars[0] if chars else "Character"
                    ltx = ltx.rstrip() + f', character speaks: "{dlg[:200]}", lips moving naturally with emotion'
                    applied.append("dialogue")

            elif suggestion_type == "action":
                beat_desc = shot_report.get("beat_description", "")
                if beat_desc and "character performs:" not in nano.lower():
                    nano = f"character performs: {beat_desc[:150]}. {nano}"
                    applied.append("action")

            elif suggestion_type == "props":
                missing_props = shot_report.get("missing_props", [])
                if missing_props:
                    prop_text = ", ".join(missing_props[:3])
                    if prop_text.lower() not in nano.lower():
                        nano = nano.rstrip(". ") + f", with {prop_text} visible in frame"
                        applied.append("props")

            elif suggestion_type == "emotion":
                if "emotion" not in ltx.lower():
                    ltx = ltx.rstrip() + ", emotional delivery, natural facial expression shifts"
                    applied.append("emotion")

        # Write back
        shot["nano_prompt"] = nano
        shot["ltx_motion_prompt"] = ltx
        shot["_advisor_applied"] = applied
        shot["_advisor_applied_at"] = datetime.now().isoformat()

        import tempfile
        tmp = tempfile.NamedTemporaryFile(mode='w', dir=str(project_path), suffix='.tmp', delete=False)
        json.dump(data, tmp, indent=2)
        tmp.close()
        os.replace(tmp.name, str(sp_path))

        # Invalidate cache
        (project_path / "ui_cache" / "bundle.dirty").touch()

        return {
            "success": True,
            "shot_id": shot_id,
            "applied": applied,
            "applied_count": len(applied),
            "message": f"Applied {len(applied)} suggestions to {shot_id}"
        }

    except Exception as e:
        logger.error(f"[SHOT-ADVISOR] Apply error: {e}")
        return JSONResponse({"error": str(e)}, status_code=500)


# ═══════════════════════════════════════════════════════════════
# V18.3.1: FRAME CAPTURE — Extract any frame from video for chaining
# ═══════════════════════════════════════════════════════════════

@app.post("/api/v18/capture-frame")
async def capture_frame_from_video(request: Dict = Body(...)):
    """
    V18.3.1: Capture a frame from a rendered video at a specific time.
    - mode='last' → extracts last frame (for chaining to next shot)
    - mode='time' → extracts frame at specific second
    - mode='current' → extracts frame at given timestamp
    Saves to first_frames/ and optionally sets as chain source for next shot.
    """
    project = request.get("project")
    shot_id = request.get("shot_id")
    mode = request.get("mode", "last")  # 'last', 'time', 'current'
    time_sec = request.get("time_sec", None)  # for 'time' mode
    apply_to_next = request.get("apply_to_next", False)  # chain to next shot

    if not project or not shot_id:
        return JSONResponse({"error": "project and shot_id required"}, status_code=400)

    project_path = PIPELINE_OUTPUTS_DIR / project
    videos_dir = project_path / "videos"

    # V18.3.1 FIX: Read video_path from shot_plan.json (source of truth)
    # This ensures we capture from the CURRENT video, not a stale file on disk
    video_path = None
    try:
        sp_path = project_path / "shot_plan.json"
        if sp_path.exists():
            with open(sp_path) as f:
                sp_data = json.load(f)
            for s in sp_data.get("shots", []):
                if s.get("shot_id") == shot_id:
                    vp = s.get("video_path", "")
                    if vp and Path(vp).exists():
                        video_path = Path(vp)
                    break
    except Exception:
        pass

    # Fallback: search by filename in videos dir
    if not video_path:
        for ext in [".mp4", ".webm"]:
            candidate = videos_dir / f"{shot_id}{ext}"
            if candidate.exists():
                video_path = candidate
                break
        # Also check for segment videos (e.g., _seg0.mp4)
        if not video_path:
            seg0 = videos_dir / f"{shot_id}_seg0.mp4"
            if seg0.exists():
                video_path = seg0

    if not video_path:
        return JSONResponse({"error": f"No video found for {shot_id}"}, status_code=404)

    try:
        # Get video duration
        dur_cmd = f'ffprobe -v error -show_entries format=duration -of csv=p=0 "{video_path}"'
        dur_result = subprocess.run(dur_cmd, shell=True, capture_output=True, text=True, timeout=10)
        vid_duration = float(dur_result.stdout.strip())

        # Determine seek time
        if mode == "last":
            seek_time = max(0, vid_duration - 0.1)
        elif mode in ("time", "current") and time_sec is not None:
            # V19 FIX: 'current' mode uses the playhead time from the UI video player
            seek_time = max(0, min(float(time_sec), vid_duration - 0.05))
        else:
            # Fallback: if no time provided, use last frame
            seek_time = max(0, vid_duration - 0.1)

        # Extract frame
        output_name = f"{shot_id}_captured_{mode}_{int(seek_time * 10)}.jpg"
        output_path = project_path / "first_frames" / output_name
        output_path.parent.mkdir(parents=True, exist_ok=True)

        cmd = f'ffmpeg -y -ss {seek_time} -i "{video_path}" -vframes 1 -q:v 2 "{output_path}"'
        result = subprocess.run(cmd, shell=True, capture_output=True, timeout=15)

        if not output_path.exists():
            return JSONResponse({"error": "Frame extraction failed"}, status_code=500)

        # Build response
        frame_url = f"/api/media?path={output_path}"
        response_data = {
            "success": True,
            "shot_id": shot_id,
            "mode": mode,
            "seek_time": round(seek_time, 2),
            "video_duration": round(vid_duration, 2),
            "frame_path": str(output_path),
            "frame_url": frame_url,
            "frame_filename": output_name,
        }

        # Upload to R2 if available
        if R2_ENABLED:
            try:
                r2_key = f"{project}/captured_frames/{output_name}"
                r2_url = r2_upload_file(output_path, r2_key)
                if r2_url:
                    response_data["r2_url"] = r2_url
            except Exception as r2_err:
                logger.warning(f"[CAPTURE-FRAME] R2 upload failed: {r2_err}")

        # Optionally apply as chain source for the NEXT shot
        if apply_to_next:
            try:
                sp_path = project_path / "shot_plan.json"
                with open(sp_path) as f:
                    sp_data = json.load(f)
                shots = sp_data.get("shots", [])
                # Find current shot index
                shot_idx = next((i for i, s in enumerate(shots) if s.get("shot_id") == shot_id), None)
                if shot_idx is not None and shot_idx + 1 < len(shots):
                    next_shot = shots[shot_idx + 1]
                    next_shot["_chain_first_frame_url"] = frame_url
                    next_shot["_chain_source"] = f"captured_{mode}_from_{shot_id}"
                    next_shot["_chain_master_shot"] = shot_id
                    next_shot["first_frame_path"] = str(output_path)
                    next_shot["first_frame_url"] = frame_url

                    # Atomic write
                    import tempfile
                    tmp = tempfile.NamedTemporaryFile(mode='w', dir=str(project_path), suffix='.tmp', delete=False)
                    json.dump(sp_data, tmp, indent=2)
                    tmp.close()
                    os.replace(tmp.name, str(sp_path))
                    (project_path / "ui_cache" / "bundle.dirty").touch()

                    response_data["applied_to_next"] = next_shot.get("shot_id")
                    response_data["next_shot_updated"] = True
                    logger.info(f"[CAPTURE-FRAME] Applied {mode} frame from {shot_id} → {next_shot.get('shot_id')}")
                else:
                    response_data["applied_to_next"] = None
                    response_data["next_shot_updated"] = False
            except Exception as chain_err:
                logger.error(f"[CAPTURE-FRAME] Chain apply error: {chain_err}")
                response_data["chain_error"] = str(chain_err)

        return response_data

    except Exception as e:
        logger.error(f"[CAPTURE-FRAME] Error: {e}", exc_info=True)
        return JSONResponse({"error": str(e)}, status_code=500)


@app.post("/api/v17/loa/rank-variants")
async def loa_rank_variants(request: Dict = Body(...)):
    """Rank multi-angle variants using LOA weighted scoring."""
    project = request.get("project", "")
    shot_id = request.get("shot_id", "")
    project_path = PIPELINE_OUTPUTS_DIR / project

    if not LOA_AVAILABLE:
        return {"error": "LOA not available"}

    shot_plan_path = project_path / "shot_plan.json"
    if not shot_plan_path.exists():
        return {"error": "No shot plan"}

    shot_plan = json.loads(shot_plan_path.read_text())
    shot = next((s for s in shot_plan.get("shots", []) if s.get("shot_id") == shot_id), None)
    if not shot:
        return {"error": f"Shot {shot_id} not found"}

    variants = shot.get("_variants", [])
    variant_paths = [v.get("path", "") for v in variants if v.get("path")]

    if not variant_paths:
        return {"error": "No variants to rank"}

    # Get ref paths
    cast_map = {}
    cast_path = project_path / "cast_map.json"
    if cast_path.exists():
        cast_map = json.loads(cast_path.read_text())

    ref_path = None
    for char in shot.get("characters", []):
        entry = cast_map.get(char, {})
        ref = entry.get("character_reference_url", "") or entry.get("headshot_url", "")
        if ref:
            if "/api/media?path=" in ref:
                ref = ref.split("path=")[1]
            if Path(ref).exists():
                ref_path = ref
                break

    loc_master = shot.get("location_master_url", "")
    if loc_master and "/api/media?path=" in loc_master:
        loc_master = loc_master.split("path=")[1]
    loc_path = loc_master if loc_master and Path(loc_master).exists() else None

    result = run_loa_rank_variants(shot, variant_paths, str(project_path),
                                    ref_path=ref_path, location_master_path=loc_path, cast_map=cast_map)
    return result


