@app.post("/api/v17/cross-shot/full-report")
async def cross_shot_full_report(request: Dict = Body(...)):
    """Full project continuity report across all scenes."""
    project = request.get("project", "")
    project_path = PIPELINE_OUTPUTS_DIR / project

    if not project_path.exists():
        return {"error": f"Project {project} not found"}
    if not CROSS_SHOT_AVAILABLE:
        return {"error": "Cross-Shot Memory not available"}

    # Load shot plan to register all shots with existing frames
    shot_plan_path = project_path / "shot_plan.json"
    if not shot_plan_path.exists():
        return {"error": "No shot plan"}

    shot_plan = json.loads(shot_plan_path.read_text())
    shots = shot_plan.get("shots", [])

    analyzer = CrossShotAnalyzer(str(project_path))

    for shot in shots:
        shot_id = shot.get("shot_id", "")
        scene_id = shot_id.split("_")[0] if "_" in shot_id else "000"
        analyzer.load_cache(scene_id)

        # Register shots with existing frames
        first_frame = shot.get("first_frame_url", "")
        if first_frame:
            frame_path = first_frame
            if "/api/media?path=" in frame_path:
                frame_path = frame_path.split("path=")[1]
            if Path(frame_path).exists():
                analyzer.register_shot(shot_id, frame_path, shot)

    return analyzer.get_all_scene_reports()


