@app.post("/api/v17/dialogue/apply-segments")
async def dialogue_apply_segments(request: Dict = Body(...)):
    """Apply dialogue-aware segmentation to a shot and persist."""
    project = request.get("project", "")
    shot_id = request.get("shot_id", "")
    project_path = PIPELINE_OUTPUTS_DIR / project

    if not project_path.exists():
        return {"error": f"Project {project} not found"}
    if not DIALOGUE_SEG_AVAILABLE:
        return {"error": "Dialogue Segmentation not available"}

    shot_plan_path = project_path / "shot_plan.json"
    if not shot_plan_path.exists():
        return {"error": "No shot plan"}

    shot_plan = json.loads(shot_plan_path.read_text())
    shot = next((s for s in shot_plan.get("shots", []) if s.get("shot_id") == shot_id), None)
    if not shot:
        return {"error": f"Shot {shot_id} not found"}

    # Load cast_map for character references
    cast_map = {}
    cast_path = project_path / "cast_map.json"
    if cast_path.exists():
        cast_map = json.loads(cast_path.read_text())

    segments = auto_segment_dialogue_shot(shot, cast_map)
    if not segments:
        return {"message": "No segmentation needed", "shot_id": shot_id}

    shot["segments"] = segments
    shot["_segmentation_method"] = "dialogue_aware"

    # Persist
    try:
        from tools.safe_io import atomic_write_json
        atomic_write_json(shot_plan_path, shot_plan)
    except Exception:
        import tempfile
        tmp = tempfile.NamedTemporaryFile(mode='w', suffix='.json', dir=str(project_path), delete=False)
        json.dump(shot_plan, tmp, indent=2)
        tmp.close()
        os.replace(tmp.name, str(shot_plan_path))

    # Invalidate cache
    cache_dir = project_path / "ui_cache"
    if cache_dir.exists():
        (cache_dir / "bundle.dirty").touch()

    return {
        "success": True,
        "shot_id": shot_id,
        "segments_created": len(segments),
        "segment_types": [s.get("segment_type", "") for s in segments],
        "total_duration": sum(s.get("duration", 0) for s in segments),
    }


