@app.post("/api/v17/intent/tag-shots")
async def intent_tag_shots(request: Dict = Body(...)):
    """
    V17.7 SHOT INTENT TAGGER
    Tags all shots with: purpose, coverage_role, wardrobe_lock, expected_elements.

    Body:
    {
        "project": "ravencroft_v17",
        "force": false,          // true = overwrite existing tags
        "shot_ids": []           // empty = tag all shots
    }
    """
    if not INTENT_TAGGER_AVAILABLE:
        return {"success": False, "error": "Intent tagger not available"}

    project = request.get("project", "")
    force = request.get("force", False)
    shot_ids = request.get("shot_ids", [])

    project_path = PIPELINE_OUTPUTS_DIR / project
    shot_plan_path = project_path / "shot_plan.json"
    story_bible_path = project_path / "story_bible.json"
    cast_map_path = project_path / "cast_map.json"

    if not shot_plan_path.exists():
        return {"success": False, "error": "Shot plan not found"}

    try:
        shot_plan = json.loads(shot_plan_path.read_text())
        story_bible = json.loads(story_bible_path.read_text()) if story_bible_path.exists() else {}
        cast_map = json.loads(cast_map_path.read_text()) if cast_map_path.exists() else {}

        # If specific shot_ids, only tag those
        if shot_ids:
            changes = []
            count = 0
            for shot in shot_plan.get("shots", []):
                if shot.get("shot_id") in shot_ids:
                    updates = tag_single_shot(shot, story_bible, cast_map, force=force)
                    if updates:
                        for k, v in updates.items():
                            shot[k] = v
                        changes.append(f"{shot.get('shot_id')}: tagged {list(updates.keys())}")
                        count += 1
        else:
            shot_plan, count, changes = tag_all_shots(shot_plan, story_bible, cast_map, force=force)

        # Persist
        with open(shot_plan_path, 'w') as f:
            json.dump(shot_plan, f, indent=2, default=str)

        # Invalidate cache
        cache_dir = project_path / "ui_cache"
        if cache_dir.exists():
            (cache_dir / "bundle.dirty").touch()

        logger.info(f"[INTENT-TAGGER] Tagged {count} shots for {project} (force={force})")

        return {
            "success": True,
            "tagged": count,
            "total_shots": len(shot_plan.get("shots", [])),
            "changes": changes[:50],  # Limit response size
            "force": force
        }

    except Exception as e:
        logger.error(f"[INTENT-TAGGER] Error: {e}")
        return {"success": False, "error": str(e)}


@app.get("/api/v17/intent/coverage/{project}")
async def intent_coverage_report(project: str, scene_id: str = ""):
    """
    V17.7 COVERAGE COMPLETENESS REPORT
    Returns per-scene coverage analysis with grades and gaps.
    """
    if not INTENT_TAGGER_AVAILABLE:
        return {"success": False, "error": "Intent tagger not available"}

    project_path = PIPELINE_OUTPUTS_DIR / project
    shot_plan_path = project_path / "shot_plan.json"
    if not shot_plan_path.exists():
        return {"success": False, "error": "Shot plan not found"}

    try:
        shot_plan = json.loads(shot_plan_path.read_text())
        shots = shot_plan.get("shots", [])

        if scene_id:
            report = coverage_completeness_report(shots, scene_id)
            return {"success": True, "report": report}
        else:
            # All scenes
            scene_ids = sorted(set(s.get("scene_id", "") for s in shots if s.get("scene_id")))
            reports = {}
            total_score = 0
            for sid in scene_ids:
                r = coverage_completeness_report(shots, sid)
                reports[sid] = r
                total_score += r.get("score", 0)
            avg = total_score / len(scene_ids) if scene_ids else 0
            return {
                "success": True,
                "scenes": reports,
                "summary": {
                    "total_scenes": len(scene_ids),
                    "avg_score": round(avg, 1),
                    "avg_grade": "A" if avg >= 90 else "B" if avg >= 75 else "C" if avg >= 60 else "D" if avg >= 40 else "F"
                }
            }
    except Exception as e:
        return {"success": False, "error": str(e)}


