@app.post("/api/v18/autonomous/render-scene")
async def autonomous_render_scene(request: Dict = Body(...)):
    """
    One-click autonomous scene rendering pipeline.
    9 stages: preflight → dialogue fix → variants → LOA rank → video → segments → stitch → grids → report
    """
    try:
        from atlas_agents.autonomous_director_agent import run_autonomous_scene

        project = request.get("project")
        scene_id = request.get("scene_id")
        options = request.get("options", {})

        if not project or not scene_id:
            return JSONResponse({"error": "Missing project or scene_id"}, status_code=400)

        # V22.3 FILM ENGINE GATE — block if not prepped
        _require_ready(project)

        trace_id = f"ATLAS-{uuid.uuid4().hex[:8]}"
        logger.info(f"[{trace_id}] Autonomous render start: {project}/{scene_id}")

        project_path = PIPELINE_OUTPUTS_DIR / project
        if not project_path.exists():
            return JSONResponse({"error": f"Project not found: {project}"}, status_code=404)

        # V23: Load dynamic project config for project-specific settings
        try:
            from core.project_config import get_project_config
            _proj_config = get_project_config(project)
            options["project_config"] = _proj_config
            logger.info(f"[{trace_id}] Loaded ProjectConfig for {project}")
        except Exception as _cfg_err:
            logger.warning(f"[{trace_id}] ProjectConfig not available: {_cfg_err} — using defaults")

        report = await run_autonomous_scene(
            project=project,
            scene_id=scene_id,
            project_path=str(project_path),
            options=options,
            progress_callback=None
        )

        logger.info(f"[{trace_id}] Autonomous render complete: {report.get('status')}")
        return {**report, "trace_id": trace_id}

    except Exception as e:
        logger.error(f"Autonomous render failed: {e}", exc_info=True)
        return JSONResponse({"error": str(e), "status": "error"}, status_code=500)


@app.get("/api/v18/autonomous/status/{project}/{scene_id}")
async def autonomous_status(project: str, scene_id: str):
    """Check status of autonomous render for a scene."""
    project_path = PIPELINE_OUTPUTS_DIR / project
    renders_dir = project_path / "renders"
    output_path = renders_dir / f"scene_{scene_id}_final.mp4"
    stitch_path = project_path / "stitched_scenes" / f"scene_{scene_id}_full.mp4"

    for p in [output_path, stitch_path]:
        if p.exists():
            return {"status": "complete", "scene": scene_id, "output_file": str(p),
                    "file_size_mb": round(p.stat().st_size / (1024**2), 1)}
    return {"status": "not_rendered", "scene": scene_id}


@app.post("/api/v18/autonomous/estimate-cost")
async def estimate_autonomous_cost(request: Dict = Body(...)):
    """Estimate cost + time for autonomous scene render."""
    try:
        project = request.get("project")
        scene_id = request.get("scene_id")
        if not project or not scene_id:
            return JSONResponse({"error": "Missing project or scene_id"}, status_code=400)

        project_path = PIPELINE_OUTPUTS_DIR / project
        shot_plan_path = project_path / "shot_plan.json"
        if not shot_plan_path.exists():
            return JSONResponse({"error": "shot_plan.json not found"}, status_code=404)

        with open(shot_plan_path) as f:
            shot_plan = _sp_guard(json.load(f))
        shots = shot_plan.get("shots", [])
        scene_shots = [s for s in shots if s.get("shot_id", "").startswith(scene_id)]
        n = len(scene_shots)

        # V18.3.1: CERTIFIED FAL pricing — $0.15/frame, $0.15/reframe, $0.04/sec video
        _total_vid_secs = sum(s.get("duration", s.get("duration_seconds", 6)) for s in scene_shots)
        cost = {
            "first_frames": round(n * 0.15, 2),          # nano-banana-pro $0.15/image
            "variants_3x": round(n * 0.15 * 3, 2),       # 3 reframe angles × $0.15
            "video_render": round(_total_vid_secs * 0.04, 2),  # LTX $0.04/sec 1080p
            "segment_stitch": 0.00,                       # FFmpeg local — free
            "scene_stitch": 0.00,                         # FFmpeg local — free
        }
        total = round(sum(cost.values()), 2)
        time_est = round((n * 24 + 120) / 60, 1)  # ~24s per shot + 2min overhead

        return {
            "project": project, "scene_id": scene_id, "shot_count": n,
            "cost_estimate_usd": total, "cost_breakdown": cost,
            "time_estimate_minutes": time_est
        }
    except Exception as e:
        return JSONResponse({"error": str(e)}, status_code=500)


# ═══════════════════════════════════════════════════════════════════════
# V18: MASTER SHOT CHAIN ENDPOINTS
# ═══════════════════════════════════════════════════════════════════════
# Master Shot → Nano-Pro Angle → End-Frame Chaining pipeline
# Nano-banana sets the tone (blocking blueprint), nano-pro-edit reframes for angles,
# end-frame of each video → first-frame of next shot for continuity.
# B-roll/inserts/cutaways are INDEPENDENT — no chaining.
# All 3 angle variants PRESERVED for manual review + DINO cinematic selection.
# ═══════════════════════════════════════════════════════════════════════

try:
    from atlas_agents.master_shot_chain_agent import (
        run_master_chain_pipeline,
        run_parallel_scenes,
        persist_chain_report,
        find_or_create_master_shot,
        should_chain,
        extract_last_frame,
        chain_end_to_start,
        reframe_to_angles,
        ShotChainReport,
        FrameChainLink,
        SCENE_CONTINUITY_LOCKS,
    )
    _MASTER_CHAIN_AVAILABLE = True
    logger.info("[MASTER CHAIN] Agent imported successfully")
except Exception as _mce:
    _MASTER_CHAIN_AVAILABLE = False
    logger.warning(f"[MASTER CHAIN] Agent not available: {_mce}")


@app.post("/api/v18/master-chain/render-scene")
async def master_chain_render_scene(request: Dict = Body(...)):
    """
    Render a scene using Master Shot Chain pipeline.

    POST /api/v18/master-chain/render-scene
    {
        "project": "ravencroft_v17",
        "scene_id": "001",
        "dry_run": false,
        "video_model": "ltx",
        "options": {
            "preserve_all_variants": true,
            "dino_cinematic_flow": true,
            "skip_broll_chain": true
        }
    }

    Pipeline:
    1. Find/create master wide shot (nano-banana blocking blueprint)
    2. Reframe master to nano-pro-edit angles for each shot
    3. DINO ranks variants for cinematic flow (not just "best" — visual variety)
    4. ALL 3 variants preserved for manual review
    5. Chain end-frames → first-frames for blocking/movement shots
    6. B-roll/inserts stay independent (no chain)
    """
    if not _MASTER_CHAIN_AVAILABLE:
        return JSONResponse({"error": "Master chain agent not available"}, status_code=503)

    # V22.3 FILM ENGINE GATE — block if not prepped
    # V25.4: Pass scene_id for scene-scoped identity pack enforcement
    _mc_project = request.get("project", "")
    _mc_scene_id = request.get("scene_id", "")
    if _mc_project:
        _require_ready(_mc_project, scene_id=_mc_scene_id)

    try:
        project = request.get("project")
        scene_id = request.get("scene_id")
        dry_run = request.get("dry_run", False)
        video_model = request.get("video_model", "kling")
        options = request.get("options", {})

        if not project or not scene_id:
            return JSONResponse({"error": "Missing project or scene_id"}, status_code=400)

        trace_id = f"CHAIN-{uuid.uuid4().hex[:8]}"
        logger.info(f"[{trace_id}] Master chain render: {project}/{scene_id} model={video_model}")

        # V18: Push live status to generation monitor
        LIVE_GEN_TRACKER.add(project, f"CHAIN_{scene_id}", "running", "chain",
                            prompt=f"Master chain S{scene_id}: Finding master shot...")

        project_path = PIPELINE_OUTPUTS_DIR / project
        if not project_path.exists():
            LIVE_GEN_TRACKER.update(f"CHAIN_{scene_id}", "error")
            return JSONResponse({"error": f"Project not found: {project}"}, status_code=404)

        # =========================================================================
        # V23 LOCATION MASTER GATE: Require location masters for production quality
        # Without location masters, generated shots have no consistent environment.
        # =========================================================================
        skip_location_check = options.get("skip_location_check", False)
        if not dry_run and not skip_location_check:
            loc_masters_dir = project_path / "location_masters"
            location_masters_exist = loc_masters_dir.exists() and (list(loc_masters_dir.glob("*.jpg")) or list(loc_masters_dir.glob("*.png")))

            if not location_masters_exist:
                logger.error(f"[{trace_id}] LOCATION GATE: No location masters found")
                LIVE_GEN_TRACKER.update(f"CHAIN_{scene_id}", "error")
                return JSONResponse({
                    "success": False,
                    "error": "LOCATION MASTER GATE: No location masters found.",
                    "hint": "Run auto-prep or generate location masters first for visual consistency.",
                    "action": f"POST /api/auto/generate-location-masters with project='{project}'",
                    "bypass": "Add 'skip_location_check': true to options to bypass",
                    "reason": "Location masters provide environmental reference images that prevent room drift."
                }, status_code=400)

        # Load shot plan
        shot_plan_path = project_path / "shot_plan.json"
        if not shot_plan_path.exists():
            LIVE_GEN_TRACKER.update(f"CHAIN_{scene_id}", "error")
            return JSONResponse({"error": "shot_plan.json not found"}, status_code=404)

        with open(shot_plan_path) as f:
            shot_plan_data = json.load(f)

        shots = shot_plan_data.get("shots", [])
        scene_shots_count = sum(1 for s in shots if s.get("scene_id") == scene_id or
                                s.get("shot_id", "").startswith(f"{scene_id}_"))
        LIVE_GEN_TRACKER.update(f"CHAIN_{scene_id}", "running")

        # Push per-shot chain status for filmstrip live updates
        for s in shots:
            sid = s.get("shot_id", "")
            if s.get("scene_id") == scene_id or sid.startswith(f"{scene_id}_"):
                # V26 DOCTRINE: Coverage suffixes are editorial, not runtime
                is_broll = s.get("is_broll", False) or s.get("_broll", False)
                chain_label = "🔗 chain" if not is_broll else "📦 independent"
                LIVE_GEN_TRACKER.add(project, sid, "pending", "chain_analysis",
                                     prompt=f"{chain_label} — analyzing...")

        # V23: Load dynamic project config for project-specific settings
        try:
            from core.project_config import get_project_config
            _proj_config = get_project_config(project)
            options["project_config"] = _proj_config
            logger.info(f"[{trace_id}] Loaded ProjectConfig for {project}")
        except Exception as _cfg_err:
            logger.warning(f"[{trace_id}] ProjectConfig not available: {_cfg_err} — using defaults")

        # ===================================================================
        # V27.1 SCENE RENDER PLANNER — Auto-generates execution strategy
        # Parallel-first for self-contained shots, legacy chain for others.
        # Stores plan in options so controller can use it for wave ordering.
        # ===================================================================
        try:
            from tools.chain_policy import plan_scene_render
            _mc_cast_map_for_plan = {}
            try:
                _cm_path_plan = project_path / "cast_map.json"
                if _cm_path_plan.exists():
                    with open(_cm_path_plan) as _cmfp:
                        _mc_cast_map_for_plan = json.load(_cmfp)
            except Exception:
                pass
            _mc_scene_shots_for_plan = [s for s in shots if s.get("scene_id") == scene_id or
                                        s.get("shot_id", "").startswith(f"{scene_id}_")]
            _mc_render_plan = plan_scene_render(
                _mc_scene_shots_for_plan, scene_id,
                _mc_cast_map_for_plan, str(project_path)
            )
            options["_render_plan"] = _mc_render_plan
            _mc_w0 = len(_mc_render_plan.get("wave_plan", {}).get("wave_0", []))
            _mc_chains = sum(c.get("length", 0) for c in _mc_render_plan.get("wave_plan", {}).get("chain_waves", []))
            logger.info(
                f"[{trace_id}] V27.1 RENDER PLAN: Scene {scene_id} — "
                f"parallel={_mc_w0} chain={_mc_chains} "
                f"blockers={len(_mc_render_plan.get('blockers', []))} "
                f"cost=${_mc_render_plan.get('cost_estimate', {}).get('first_frames', {}).get('total', 0)}"
            )
        except ImportError:
            logger.warning(f"[{trace_id}] V27.1 RENDER PLAN: chain_policy not available (non-blocking)")
        except Exception as _rp_err:
            logger.warning(f"[{trace_id}] V27.1 RENDER PLAN: Planning error (non-blocking): {_rp_err}")
        # ===================================================================

        # ═══ V24.2: DOCTRINE — Scene Initialize before master chain ═══
        _mc_doctrine = None
        if DOCTRINE_AVAILABLE and not dry_run:
            try:
                _mc_doctrine = _get_doctrine_runner(str(project_path))
                _scene_shots = [s for s in shots if s.get("scene_id") == scene_id or
                                s.get("shot_id", "").startswith(f"{scene_id}_")]
                # Load scene manifest + story bible for doctrine context
                _mc_scene_manifest = shot_plan_data.get("scene_manifest", {})
                _mc_story_bible = {}
                _mc_cast_map = {}
                try:
                    _sb_path = project_path / "story_bible.json"
                    if _sb_path.exists():
                        with open(_sb_path) as _sbf:
                            _mc_story_bible = json.load(_sbf).get("scenes", {})
                    _cm_path = project_path / "cast_map.json"
                    if _cm_path.exists():
                        with open(_cm_path) as _cmf:
                            _mc_cast_map = json.load(_cmf)
                except Exception:
                    pass
                _doc_init = _mc_doctrine.scene_initialize(
                    _scene_shots, _mc_scene_manifest, _mc_story_bible, _mc_cast_map
                )
                logger.info(f"[DOCTRINE] Master-chain scene {scene_id} init: {_doc_init.get('status')}")
                if _doc_init.get("status") == "REJECTED":
                    logger.error(f"[DOCTRINE] HARD STOP on chain {scene_id}: {_doc_init.get('reason')}")
            except Exception as _dmc_err:
                logger.warning(f"[DOCTRINE] Master-chain init non-blocking: {_dmc_err}")

        # ═══ V25.4: PIPELINE WIRING — Pre-authorize scene + Continuity Memory ═══
        try:
            from tools.atlas_pipeline_wiring import wire_pre_generation_gate
            _scene_shots = [s for s in shots if s.get("scene_id") == scene_id or
                            s.get("shot_id", "").startswith(f"{scene_id}_")]
            _chain_gate = wire_pre_generation_gate(_scene_shots, str(project_path), _mc_cast_map)
            # Pass authority contracts to chain pipeline via options
            if _chain_gate.mutations.get("shot_contracts"):
                options["_shot_contracts"] = _chain_gate.mutations["shot_contracts"]
            logger.info(f"[WIRING:CHAIN] Pre-authorized {len(_scene_shots)} shots for scene {scene_id}")
            if _chain_gate.warnings:
                for _cw in _chain_gate.warnings[:3]:
                    logger.info(f"[WIRING:CHAIN] {_cw}")
        except Exception as _cw_err:
            logger.debug(f"[WIRING:CHAIN] Pre-auth non-blocking: {_cw_err}")

        # Initialize Continuity Memory for the chain
        try:
            from tools.continuity_memory import ContinuityMemory
            _cm_instance = ContinuityMemory(str(project_path))
            options["_continuity_memory"] = _cm_instance
            logger.info(f"[WIRING:CHAIN] ContinuityMemory initialized for scene {scene_id}")
        except Exception as _cm_err:
            logger.debug(f"[WIRING:CHAIN] ContinuityMemory non-blocking: {_cm_err}")

        # ═══ V26.2: PASS DOCTRINE RUNNER TO CHAIN PIPELINE ═══
        # Per-shot pre/post generation hooks must fire inside run_master_chain_pipeline
        if _mc_doctrine:
            options["_doctrine_runner"] = _mc_doctrine
            options["_cast_map"] = _mc_cast_map
            logger.info(f"[WIRING:CHAIN] Doctrine runner + cast_map passed to chain pipeline")

        # Run master chain pipeline in thread pool to avoid blocking uvicorn event loop
        # V25.4: Without this, all logging + I/O is frozen during FAL API calls (~60-90s each)
        import asyncio as _mc_asyncio
        import functools as _mc_functools
        _mc_loop = _mc_asyncio.get_event_loop()
        success, report = await _mc_loop.run_in_executor(
            None,  # default ThreadPoolExecutor
            _mc_functools.partial(
                run_master_chain_pipeline,
                project=project,
                scene_id=scene_id,
                shot_plan=shots,
                project_path=BASE_DIR,
                options=options,
            )
        )

        # ═══ V24.2: DOCTRINE — Session close after master chain ═══
        if _mc_doctrine and DOCTRINE_AVAILABLE and not dry_run:
            try:
                _mc_doctrine.scene_complete(scene_id)
                _doc_close = _mc_doctrine.session_close()
                logger.info(f"[DOCTRINE] Master-chain session closed: {_doc_close.get('status')}")
                _doctrine_runners.pop(str(project_path), None)
            except Exception as _dmc_close:
                logger.warning(f"[DOCTRINE] Master-chain close non-blocking: {_dmc_close}")

        # Build variant analysis report for ALL shots in scene
        scene_shots = [s for s in shots if s.get("scene_id") == scene_id or
                       s.get("shot_id", "").startswith(f"{scene_id}_")]
        variant_analysis = {}
        variants_dir = project_path / "first_frame_variants"

        for shot in scene_shots:
            sid = shot.get("shot_id", "")
            shot_variants = []
            # Discover all variant files for this shot
            if variants_dir.exists():
                for vf in sorted(variants_dir.glob(f"{sid}_*.jpg")):
                    shot_variants.append({
                        "path": str(vf),
                        "url": f"/api/media?path={vf.relative_to(BASE_DIR) if vf.is_relative_to(BASE_DIR) else vf}",
                        "filename": vf.name,
                        "angle": vf.stem.replace(f"{sid}_", "")
                    })
            # Include the main first frame too
            for ext in [".jpg", ".png", ".jpeg"]:
                ff = project_path / "first_frames" / f"{sid}{ext}"
                if ff.exists():
                    shot_variants.insert(0, {
                        "path": str(ff),
                        "url": f"/api/media?path={ff.relative_to(BASE_DIR) if ff.is_relative_to(BASE_DIR) else ff}",
                        "filename": ff.name,
                        "angle": "primary"
                    })
                    break

                # V22 FIX: B-roll detection uses explicit flags, NOT shot_id suffix!
            # The suffix "B" in shot IDs like 001_005B means ANGLE B, not B-roll!
            _va_shot_type = (shot.get("shot_type") or shot.get("type", "medium")).lower()
            _va_is_broll = (
                shot.get("_broll", False) or
                shot.get("_no_chain", False) or
                _va_shot_type in ("b-roll", "b_roll", "broll", "insert", "title_card", "montage")
            )
            variant_analysis[sid] = {
                "shot_id": sid,
                "shot_type": shot.get("shot_type") or shot.get("type", "medium"),
                "chains_to_prev": should_chain(scene_shots[max(0, scene_shots.index(shot)-1)], shot) if scene_shots.index(shot) > 0 else False,
                "is_broll": _va_is_broll,
                "variant_count": len(shot_variants),
                "variants": shot_variants,  # ALL preserved for manual review
                "has_video": bool(shot.get("video_path")),
                "characters": shot.get("characters", []),
            }

        # DINO cinematic flow analysis — rank variants not just by "best quality"
        # but by creating visual variety across the edit
        cinematic_flow = []
        prev_angle = None
        for i, shot in enumerate(scene_shots):
            sid = shot.get("shot_id", "")
            va = variant_analysis.get(sid, {})
            selected_angle = None

            if va.get("variants"):
                # Cinematic flow: avoid repeating same angle type consecutively
                # If prev was "wide", prefer "medium" or "close" next
                angles = [v.get("angle", "") for v in va["variants"] if v.get("angle") not in ("primary", "master_reframe")]
                if prev_angle and len(angles) > 1:
                    # Pick the most different angle from previous
                    # Map: wide→medium→close→wide cycle for visual variety
                    ANGLE_CYCLE = {
                        "angle_wide_24mm": ["angle_med_85mm", "angle_cu_135mm"],
                        "angle_med_85mm": ["angle_cu_135mm", "angle_wide_24mm"],
                        "angle_cu_135mm": ["angle_wide_24mm", "angle_med_85mm"],
                    }
                    preferred_list = ANGLE_CYCLE.get(prev_angle, ["angle_med_85mm", "angle_cu_135mm", "angle_wide_24mm"])
                    for preferred in preferred_list:
                        if preferred in angles:
                            selected_angle = preferred
                            break
                    # Also try partial matches (e.g., "angle_room_reverse", "angle_wide_left")
                    if not selected_angle:
                        for a in angles:
                            if "wide" in a and "wide" not in (prev_angle or ""):
                                selected_angle = a; break
                            elif "med" in a and "med" not in (prev_angle or ""):
                                selected_angle = a; break
                            elif "cu" in a and "cu" not in (prev_angle or ""):
                                selected_angle = a; break
                if not selected_angle and angles:
                    selected_angle = angles[0]
                elif not selected_angle:
                    # Fallback to any non-primary variant
                    all_angles = [v.get("angle", "") for v in va["variants"]]
                    selected_angle = all_angles[0] if all_angles else "primary"
                prev_angle = selected_angle

            cinematic_flow.append({
                "shot_id": sid,
                "recommended_angle": selected_angle,
                "chains": va.get("chains_to_prev", False),
                "is_broll": va.get("is_broll", False),
            })

        if not dry_run and success:
            # Persist chain metadata
            persist_chain_report(report, BASE_DIR)
            # Touch cache dirty
            dirty_flag = project_path / "ui_cache" / "bundle.dirty"
            dirty_flag.parent.mkdir(parents=True, exist_ok=True)
            dirty_flag.touch()
            # V18: Update live gen tracker — mark all shots complete with chain status
            for sid, va in variant_analysis.items():
                chain_label = "📦 B-roll" if va.get("is_broll") else ("🔗 chained" if va.get("chains_to_prev") else "🔓 independent")
                thumb = va["variants"][0]["url"] if va.get("variants") else None
                LIVE_GEN_TRACKER.update(sid, "completed", url=thumb)
            LIVE_GEN_TRACKER.update(f"CHAIN_{scene_id}", "completed",
                                    url=report.master_frame_path)

        return {
            "success": success,
            "trace_id": trace_id,
            "scene_id": scene_id,
            "status": report.status if success else "failed",
            "total_shots": report.total_shots,
            "chained_shots": report.chained_shots,
            "chain_breaks": report.chain_breaks,
            "master_frame_path": report.master_frame_path,
            "total_cost": report.total_cost,
            "duration_secs": report.duration_secs,
            "video_model": video_model,
            "variant_analysis": variant_analysis,
            "cinematic_flow": cinematic_flow,
            "continuity_locks": list(SCENE_CONTINUITY_LOCKS.keys()),
            "timestamp": report.timestamp,
        }

    except Exception as e:
        logger.error(f"[MASTER CHAIN] render-scene error: {e}", exc_info=True)
        return JSONResponse({"error": str(e)}, status_code=500)


@app.post("/api/v18/master-chain/parallel-render")
async def master_chain_parallel_render(request: Dict = Body(...)):
    """
    V18.1: Render multiple scenes using the REAL chain pipeline.

    POST /api/v18/master-chain/parallel-render
    {
        "project": "ravencroft_v17",
        "scene_ids": ["001", "002", "003"],
        "max_concurrent": 2,
        "video_model": "ltx"
    }

    Each scene gets its own background thread running the FULL chain pipeline
    (nano → video → end-frame → nano-pro-edit 3 variants → chain). Returns run_ids
    immediately — UI polls /api/v18/chain/status/{run_id} for each.
    """
    try:
        project = request.get("project")
        scene_ids = request.get("scene_ids", [])
        max_concurrent = min(request.get("max_concurrent", 2), 3)
        video_model = request.get("video_model", "kling")

        if not project or not scene_ids:
            return JSONResponse({"error": "Missing project or scene_ids"}, status_code=400)

        # V22.3 FILM ENGINE GATE — block if not prepped
        _require_ready(project)

        trace_id = f"PCHAIN-{uuid.uuid4().hex[:8]}"
        logger.info(f"[{trace_id}] Parallel chain: {project} scenes={scene_ids} model={video_model}")

        # For each scene, internally trigger the same pipeline as /api/v18/kling/render-scene
        # by calling kling_render_scene_batch() with a fake request dict
        run_ids = {}
        scene_shot_counts = {}

        project_path = get_project_path(project)
        shot_plan_path = project_path / "shot_plan.json"
        if not shot_plan_path.exists():
            return JSONResponse({"error": "shot_plan.json not found"}, status_code=404)

        with open(shot_plan_path) as f:
            data = json.load(f)
        all_shots = data.get("shots", data) if isinstance(data, dict) else data

        # V23: Load dynamic project config
        _parallel_config = None
        try:
            from core.project_config import get_project_config
            _parallel_config = get_project_config(project)
            logger.info(f"[{trace_id}] Loaded ProjectConfig for parallel render")
        except Exception as _cfg_err:
            logger.warning(f"[{trace_id}] ProjectConfig not available: {_cfg_err}")

        # V18.4 FIX: Actually launch scenes in PARALLEL using asyncio
        # Old code: sequential `await` per scene (defeated the purpose)
        # New code: fire all scene renders as background tasks, return immediately

        async def _launch_scene(sid):
            """Launch a single scene render — returns (sid, run_id_or_None)"""
            try:
                fake_request = {
                    "project": project,
                    "scene_id": sid,
                    "duration": 5,
                    "generate_audio": video_model == "kling",
                    "enable_chain": True,
                    "video_model": video_model,
                    "lite_mode": request.get("lite_mode", False),  # V22: pass through
                }
                result = await kling_render_scene_batch(fake_request)
                if isinstance(result, dict) and result.get("run_id"):
                    return (sid, result["run_id"])
                else:
                    return (sid, None)
            except Exception as scene_err:
                logger.error(f"[{trace_id}] Scene {sid} launch failed: {scene_err}")
                return (sid, None)

        for sid in scene_ids:
            scene_shots = [s for s in all_shots if s.get("shot_id", "").startswith(sid)]
            scene_shot_counts[sid] = len(scene_shots)

        # Launch all scenes concurrently (up to max_concurrent)
        import asyncio
        semaphore = asyncio.Semaphore(max_concurrent)

        async def _limited_launch(sid):
            async with semaphore:
                return await _launch_scene(sid)

        results = await asyncio.gather(*[_limited_launch(sid) for sid in scene_ids], return_exceptions=True)

        for item in results:
            if isinstance(item, Exception):
                logger.error(f"[{trace_id}] Scene launch exception: {item}")
                continue
            sid, rid = item
            run_ids[sid] = rid
            if rid:
                logger.info(f"[{trace_id}] Scene {sid}: started → run_id={rid} ({scene_shot_counts.get(sid, 0)} shots)")
            else:
                logger.error(f"[{trace_id}] Scene {sid}: failed to start")

        return {
            "success": True,
            "async": True,
            "trace_id": trace_id,
            "project": project,
            "video_model": video_model,
            "scenes_requested": len(scene_ids),
            "run_ids": run_ids,
            "scene_shot_counts": scene_shot_counts,
            "poll_url_template": "/api/v18/chain/status/{run_id}",
            "timestamp": datetime.now().isoformat(),
        }

    except Exception as e:
        logger.error(f"[MASTER CHAIN] parallel-render error: {e}", exc_info=True)
        return JSONResponse({"error": str(e)}, status_code=500)


@app.get("/api/v18/master-chain/status/{project}/{scene_id}")
async def master_chain_status(project: str, scene_id: str):
    """
    Check status of master chain for a scene.
    Returns chain report, variant analysis, and continuity lock state.
    """
    try:
        project_path = PIPELINE_OUTPUTS_DIR / project
        report_dir = project_path / "chain_reports"

        if report_dir.exists():
            reports = sorted(
                report_dir.glob(f"scene_{scene_id}_*.json"),
                key=lambda p: p.stat().st_mtime,
                reverse=True
            )
            if reports:
                with open(reports[0]) as f:
                    report_data = json.load(f)
                return {
                    "status": report_data.get("status", "unknown"),
                    "scene_id": scene_id,
                    "master_frame": report_data.get("master_frame_path"),
                    "chained_shots": report_data.get("chained_shots", 0),
                    "chain_breaks": report_data.get("chain_breaks", 0),
                    "total_cost": report_data.get("total_cost", 0.0),
                    "report_file": str(reports[0].name),
                    "continuity_locks": list(SCENE_CONTINUITY_LOCKS.keys()) if _MASTER_CHAIN_AVAILABLE else [],
                }

        # Check chain_metadata.json
        chain_meta_path = project_path / "chain_metadata.json"
        if chain_meta_path.exists():
            with open(chain_meta_path) as f:
                chain_meta = json.load(f)
            return {
                "status": "ready",
                "scene_id": scene_id,
                "master_frame": chain_meta.get("master_frame_path"),
                "chain_links": len(chain_meta.get("chain_links", [])),
            }

        return {"status": "not_started", "scene_id": scene_id}

    except Exception as e:
        return JSONResponse({"error": str(e)}, status_code=500)


@app.post("/api/v18/master-chain/variant-analysis")
async def master_chain_variant_analysis(request: Dict = Body(...)):
    """
    Get detailed variant analysis for a scene — shows ALL 3 angle variants
    per shot with DINO scores, cinematic flow recommendation, and which
    shots chain vs. which are independent (B-roll/inserts).

    This is the "still frame comparison" with intelligence:
    - Same location in every variant (DINO location lock)
    - Cinematic flow recommends angle variety across sequential shots
    - All variants preserved for manual selection override
    - Chain vs. independent classification per shot

    POST /api/v18/master-chain/variant-analysis
    {"project": "ravencroft_v17", "scene_id": "001"}
    """
    try:
        project = request.get("project")
        scene_id = request.get("scene_id")
        if not project or not scene_id:
            return JSONResponse({"error": "Missing project or scene_id"}, status_code=400)

        project_path = PIPELINE_OUTPUTS_DIR / project
        shot_plan_path = project_path / "shot_plan.json"
        if not shot_plan_path.exists():
            return JSONResponse({"error": "shot_plan.json not found"}, status_code=404)

        with open(shot_plan_path) as f:
            shot_plan_data = json.load(f)

        shots = shot_plan_data.get("shots", [])
        scene_shots = [s for s in shots if s.get("scene_id") == scene_id or
                       s.get("shot_id", "").startswith(f"{scene_id}_")]

        if not scene_shots:
            return JSONResponse({"error": f"No shots for scene {scene_id}"}, status_code=404)

        variants_dir = project_path / "first_frame_variants"
        ff_dir = project_path / "first_frames"

        analysis = []
        prev_shot = None

        for shot in scene_shots:
            sid = shot.get("shot_id", "")
            shot_type = shot.get("shot_type") or shot.get("type", "medium")
            # V22 FIX: B-roll detection uses explicit flags, NOT shot_id suffix!
            # The suffix "B" in shot IDs like 001_005B means ANGLE B, not B-roll!
            _shot_type_lower = shot_type.lower() if shot_type else ""
            is_broll = (
                shot.get("_broll", False) or
                shot.get("_no_chain", False) or
                _shot_type_lower in ("b-roll", "b_roll", "broll", "insert", "title_card", "montage")
            )
            chains = should_chain(prev_shot, shot) if prev_shot and _MASTER_CHAIN_AVAILABLE else False

            # Collect ALL variants
            all_variants = []
            # Primary first frame
            for ext in [".jpg", ".png", ".jpeg"]:
                ff = ff_dir / f"{sid}{ext}"
                if ff.exists():
                    try:
                        _rel = str(ff.relative_to(BASE_DIR))
                    except ValueError:
                        _rel = str(ff)
                    all_variants.append({
                        "label": "Primary",
                        "angle": "primary",
                        "url": f"/api/media?path={_rel}",
                        "is_selected": not shot.get("_variants"),  # Selected if no variants chosen
                    })
                    break

            # Multi-angle variants
            if variants_dir.exists():
                for vf in sorted(variants_dir.glob(f"{sid}_*.jpg")):
                    angle_name = vf.stem.replace(f"{sid}_", "")
                    try:
                        _rel = str(vf.relative_to(BASE_DIR))
                    except ValueError:
                        _rel = str(vf)
                    # Check if this variant is the selected one
                    selected_variants = shot.get("_variants", [])
                    is_selected = any(v.get("angle_name") == angle_name and v.get("selected")
                                     for v in selected_variants) if selected_variants else False
                    all_variants.append({
                        "label": angle_name.replace("_", " ").title(),
                        "angle": angle_name,
                        "url": f"/api/media?path={_rel}",
                        "is_selected": is_selected,
                    })

            # Vision/DINO scores if available
            vision_data = shot.get("vision", {})

            analysis.append({
                "shot_id": sid,
                "shot_type": shot_type,
                "is_broll": is_broll,
                "chains_to_previous": chains,
                "chain_reason": "blocking/movement continuity" if chains else
                               ("B-roll — independent" if is_broll else "break — different context"),
                "characters": shot.get("characters", []),
                "duration": shot.get("duration", 0),
                "dialogue": bool(shot.get("dialogue_text")),
                "variant_count": len(all_variants),
                "variants": all_variants,
                "vision_scores": {
                    "identity": vision_data.get("identity", None),
                    "location": vision_data.get("location", None),
                    "presence": vision_data.get("presence", None),
                },
                "has_video_ltx": bool(shot.get("video_path")),
                "has_video_kling": bool(shot.get("video_url_kling")),
            })

            prev_shot = shot

        # Cinematic flow recommendation
        flow_recommendation = []
        prev_recommended = None
        # Angle variety cycle: wide → medium → close → wide (using real variant names)
        ANGLE_CYCLE = {
            "angle_wide_24mm": ["angle_med_85mm", "angle_cu_135mm"],
            "angle_med_85mm": ["angle_cu_135mm", "angle_wide_24mm"],
            "angle_cu_135mm": ["angle_wide_24mm", "angle_med_85mm"],
        }
        ANGLE_VARIETY_ORDER = ["angle_wide_24mm", "angle_med_85mm", "angle_cu_135mm"]

        for item in analysis:
            if item["is_broll"]:
                flow_recommendation.append({"shot_id": item["shot_id"], "recommended": "any", "reason": "B-roll — independent"})
                continue

            available = [v["angle"] for v in item["variants"] if v["angle"] not in ("primary", "master_reframe")]
            if not available:
                flow_recommendation.append({"shot_id": item["shot_id"], "recommended": "primary", "reason": "single frame only"})
                prev_recommended = "primary"
                continue

            # Pick angle that creates variety using the cycle map
            recommended = None
            if prev_recommended and prev_recommended in ANGLE_CYCLE:
                for preferred in ANGLE_CYCLE[prev_recommended]:
                    if preferred in available:
                        recommended = preferred
                        break
            # Fallback: partial match (angle_wide_left, angle_room_reverse, etc.)
            if not recommended:
                for a in available:
                    if prev_recommended and a != prev_recommended:
                        recommended = a
                        break
            if not recommended:
                recommended = available[0]

            flow_recommendation.append({
                "shot_id": item["shot_id"],
                "recommended": recommended,
                "reason": f"cinematic flow — varies from prev ({prev_recommended or 'none'})"
            })
            prev_recommended = recommended

        return {
            "project": project,
            "scene_id": scene_id,
            "total_shots": len(analysis),
            "chained_shots": sum(1 for a in analysis if a["chains_to_previous"]),
            "broll_shots": sum(1 for a in analysis if a["is_broll"]),
            "independent_shots": sum(1 for a in analysis if not a["chains_to_previous"] and not a["is_broll"]),
            "shots": analysis,
            "cinematic_flow": flow_recommendation,
            "continuity_locks": list(SCENE_CONTINUITY_LOCKS.keys()) if _MASTER_CHAIN_AVAILABLE else [],
        }

    except Exception as e:
        logger.error(f"[MASTER CHAIN] variant-analysis error: {e}", exc_info=True)
        return JSONResponse({"error": str(e)}, status_code=500)


