# V22.2: PREP ENGINE — Headless Auto-Preparation Pipeline
# ════════════════════════════════════════════════════════════

@app.post("/api/v22/prep/{project_name}")
async def v22_prep_project(project_name: str):
    """
    V22.2 PREP ENGINE — Runs full headless preparation pipeline.

    Phases:
      1. Data Lock (only whitelisted projects)
      2. Load canonical data (cast, wardrobe, locations, audio)
      3. Run V22 modules (actor intent, delta prompt, composition cache, continuity store)
      4. Chain detection + composition hashing
      5. Preflight validation (10 checks, HALT on critical failures)
      6. Save enriched shot plan
      7. Generate atlas_run_report.json

    Returns PrepResult with success/failure and all details.
    """
    try:
        from tools.prep_engine import prep_project, generate_run_report

        _base = str(PIPELINE_OUTPUTS_DIR.parent)
        result = prep_project(project_name, _base)
        report_path = generate_run_report(result, _base)

        # Also generate FAL manifest
        manifest_path = None
        try:
            from tools.fal_manifest_generator import generate_fal_manifest
            manifest_path = generate_fal_manifest(project_name, _base)
        except Exception as e:
            result.warnings.append(f"FAL manifest generation failed: {e}")

        # Invalidate bundle cache
        _invalidate_bundle_cache(project_name)

        return JSONResponse({
            "success": result.success,
            "project": result.project,
            "timestamp": result.timestamp,
            "stats": result.stats,
            "phases": result.phases,
            "errors": result.errors,
            "warnings": result.warnings,
            "report_path": report_path,
            "manifest_path": manifest_path,
        })
    except Exception as e:
        logger.error(f"[V22 PREP] Error: {e}", exc_info=True)
        return JSONResponse({"error": str(e)}, status_code=500)


@app.get("/api/v22/prep/status/{project_name}")
async def v22_prep_status(project_name: str):
    """Check if prep has been run and its results."""
    try:
        report_path = os.path.join(PIPELINE_OUTPUT_DIR, project_name, "atlas_run_report.json")
        if not os.path.exists(report_path):
            return JSONResponse({"prepped": False, "message": "No prep report found. Run POST /api/v22/prep/{project} first."})

        with open(report_path) as f:
            report = json.load(f)

        return JSONResponse({
            "prepped": True,
            "success": report.get("success", False),
            "timestamp": report.get("generated", ""),
            "stats": report.get("stats", {}),
            "locks": report.get("locks", {}),
        })
    except Exception as e:
        return JSONResponse({"error": str(e)}, status_code=500)


