# ════════════════════════════════════════════════════════════
# V22.3: PREP GATE — _require_ready() + V22 Project Listing
# ════════════════════════════════════════════════════════════

def _require_ready(project: str, scene_id: str = None) -> dict:
    """
    FILM ENGINE GATE: Block ALL renders unless project prep status == READY.
    Also enforces data lock (only whitelisted projects can render).

    V25.4 DOCTRINE FIX (BUG 02): When scene_id provided, HALT if that scene
    has characters missing from cast_map. Project-level warnings remain non-blocking
    for other scenes' missing characters, but the SCENE being rendered must have
    all its identity packs locked.

    Returns prep status dict on success, raises HTTPException on failure.
    """
    from tools.prep_engine import ALLOWED_PROJECTS

    # Data lock enforcement
    if project not in ALLOWED_PROJECTS:
        raise HTTPException(
            status_code=403,
            detail=f"DATA LOCK: Project '{project}' is not whitelisted. Allowed: {sorted(ALLOWED_PROJECTS)}"
        )

    # Prep status check
    project_path = get_project_path(project)
    report_path = project_path / "atlas_run_report.json"

    if not report_path.exists():
        raise HTTPException(
            status_code=409,
            detail=f"Project '{project}' has not been prepped. Run POST /api/v22/prep/{project} first."
        )

    try:
        with open(report_path) as f:
            report = json.load(f)
    except Exception as e:
        raise HTTPException(status_code=500, detail=f"Failed to read prep report: {e}")

    if not report.get("success", False):
        errors = report.get("errors", [])
        logger.warning(f"[PREP GATE] Project '{project}' prep has warnings (non-blocking): {errors}")

    # V25.4 DOCTRINE BUG 02: Scene-scoped identity pack enforcement
    # If rendering a specific scene, HALT if that scene has characters missing from cast_map
    if scene_id:
        try:
            shot_plan_path = project_path / "shot_plan.json"
            cast_map_path = project_path / "cast_map.json"
            if shot_plan_path.exists() and cast_map_path.exists():
                with open(shot_plan_path) as f:
                    _sp = json.load(f)
                with open(cast_map_path) as f:
                    _cm = json.load(f)
                # Get all characters in THIS scene
                _scene_chars = set()
                for shot in _sp.get("shots", []):
                    sid = shot.get("shot_id", "")
                    if shot.get("scene_id") == scene_id or sid.startswith(f"{scene_id}_"):
                        for c in (shot.get("characters") or []):
                            if c and c.strip():
                                _scene_chars.add(c.strip().upper())
                # Check which are missing from cast_map (exclude aliases)
                _cast_names = set()
                for k, v in _cm.items():
                    if not (isinstance(v, dict) and v.get("_is_alias_of")):
                        _cast_names.add(k.strip().upper())
                _missing = _scene_chars - _cast_names
                if _missing:
                    logger.error(f"[PREP GATE] DOCTRINE HALT: Scene {scene_id} has characters "
                                f"missing from cast_map: {_missing}. "
                                f"Identity packs must be locked before generation.")
                    raise HTTPException(
                        status_code=409,
                        detail=f"DOCTRINE HALT: Scene {scene_id} characters missing identity packs: "
                               f"{sorted(_missing)}. Cast these characters before rendering. "
                               f"Use POST /api/v6/casting/auto-cast to assign AI actors."
                    )
        except HTTPException:
            raise  # Re-raise our own HALT
        except Exception as _sc_err:
            logger.warning(f"[PREP GATE] Scene-scoped cast check non-blocking: {_sc_err}")

    return report


@app.get("/api/v22/projects")
async def v22_project_list(include_all: bool = False):
    """
    V22.3 FILM ENGINE: Return only READY projects by default.
    UI calls this to populate the project selector — unprepared projects hidden.
    Pass ?include_all=true to see everything (debug mode).
    """
    projects = []
    for p in PIPELINE_OUTPUTS_DIR.iterdir():
        if not p.is_dir():
            continue
        if p.name.startswith("_ARCHIVE__") or p.name.startswith("."):
            continue

        report_path = p / "atlas_run_report.json"
        truth_path = p / "ATLAS_PROJECT_TRUTH.json"

        status = "NOT_PREPPED"
        timestamp = None
        stats = {}

        if report_path.exists():
            try:
                with open(report_path) as f:
                    report = json.load(f)
                status = "READY" if report.get("success") else "FAILED"
                timestamp = report.get("generated")
                stats = report.get("stats", {})
            except Exception:
                status = "CORRUPT"

        has_truth = truth_path.exists()

        if include_all or status == "READY":
            projects.append({
                "project": p.name,
                "status": status,
                "generated": timestamp,
                "has_truth_doc": has_truth,
                "shot_count": stats.get("total_shots", 0),
                "scene_count": stats.get("total_scenes", 0),
                "chain_groups": stats.get("chain_groups", 0),
                "modules_fired": stats.get("modules_fired", []),
            })

    return JSONResponse({
        "projects": sorted(projects, key=lambda x: x["project"]),
        "filter": "READY_only" if not include_all else "all",
    })


@app.get("/api/v22/truth/{project_name}")
async def v22_get_truth_doc(project_name: str):
    """Return the ATLAS_PROJECT_TRUTH.json for a project."""
    truth_path = get_project_path(project_name) / "ATLAS_PROJECT_TRUTH.json"
    if not truth_path.exists():
        return JSONResponse({"error": "No truth document found"}, status_code=404)
    with open(truth_path) as f:
        return JSONResponse(json.load(f))


