# ═══════════════════════════════════════════════════════════════════
# V22.5 ATLAS LITE — PARALLEL PIPELINE ENDPOINTS
# 3-stage prompt synthesis bypassing 9-layer enrichment stack
# ═══════════════════════════════════════════════════════════════════

@app.post("/api/lite/synthesize")
async def lite_synthesize(request: Dict = Body(...)):
    """
    Run ATLAS LITE synthesis on a scene or specific shots.
    Writes nano_prompt_lite + ltx_prompt_lite alongside V22 prompts.
    Does NOT generate images — just builds prompts for A/B comparison.

    Body: {"project": "ravencroft_v22", "scene_id": "000", "use_llm": false}
    """
    import asyncio as _aio
    from tools.atlas_lite_synthesizer import (
        synthesize_scene, synthesize_shot, build_context_object,
        compare_v22_vs_lite
    )

    project = request.get("project", "")
    scene_id = request.get("scene_id", "")
    shot_ids = request.get("shot_ids", [])
    use_llm = request.get("use_llm", False)

    if not project:
        return {"success": False, "error": "project required"}

    project_path = get_project_path(project)
    shot_plan_path = project_path / "shot_plan.json"
    cast_map_path = project_path / "cast_map.json"
    bible_path = project_path / "story_bible.json"

    if not shot_plan_path.exists():
        return {"success": False, "error": f"Project '{project}' not found"}

    with open(shot_plan_path) as f:
        data = json.load(f)
    shots = data.get("shots", data) if isinstance(data, dict) else data

    cast_map = {}
    if cast_map_path.exists():
        with open(cast_map_path) as f:
            cast_map = json.load(f)

    bible = {}
    if bible_path.exists():
        with open(bible_path) as f:
            bible = json.load(f)

    genre = bible.get("genre", "drama")
    api_key = os.environ.get("OPENROUTER_API_KEY", "")

    # Filter shots
    if shot_ids:
        target = [s for s in shots if s.get("shot_id") in shot_ids]
    elif scene_id:
        target = [s for s in shots if s.get("scene_id") == scene_id]
    else:
        return {"success": False, "error": "scene_id or shot_ids required"}

    logger.info(f"[LITE SYNTH] Synthesizing {len(target)} shots, mode={'LLM' if use_llm else 'deterministic'}")

    # Synthesize each shot
    from tools.atlas_lite_synthesizer import _get_scene_emotion
    for shot in target:
        scene_emotion = _get_scene_emotion(shot.get("scene_id", ""), bible)
        await synthesize_shot(shot, cast_map, bible, genre, scene_emotion, use_llm, api_key)

    # Save back
    if isinstance(data, dict):
        data["shots"] = shots
    try:
        from tools.safe_io import atomic_write_json
        atomic_write_json(str(shot_plan_path), data)
    except Exception:
        import tempfile as _tf
        fd, tmp = _tf.mkstemp(suffix=".json", dir=str(project_path))
        with os.fdopen(fd, "w") as wf:
            json.dump(data, wf, indent=2)
        os.replace(tmp, str(shot_plan_path))

    # Build comparison report
    comparisons = [compare_v22_vs_lite(s) for s in target]

    return {
        "success": True,
        "pipeline": "lite",
        "shots_synthesized": len(target),
        "use_llm": use_llm,
        "comparisons": comparisons,
    }


@app.post("/api/lite/generate-first-frames")
async def lite_generate_first_frames(request: Dict = Body(...)):
    """
    Generate first frames using ATLAS LITE prompts.
    Uses nano_prompt_lite instead of nano_prompt (V22).
    Same FAL calls, different prompt source.

    Body: {
        "project": "ravencroft_v22",
        "scene_filter": "000",
        "dry_run": false,
        "force": false,
        "synthesize_first": true  // auto-run LITE synthesis before generation
    }
    """
    import httpx as _httpx

    IMAGE_MODEL_WITH_REF = "fal-ai/nano-banana-pro/edit"
    IMAGE_MODEL_NO_REF = "fal-ai/nano-banana-pro"

    project = request.get("project", "")
    scene_filter = request.get("scene_filter", "")
    shot_ids = request.get("shot_ids", [])
    dry_run = request.get("dry_run", False)
    force = request.get("force", False)
    synthesize_first = request.get("synthesize_first", True)
    use_llm = request.get("use_llm", False)

    if not project:
        return {"success": False, "error": "project required"}
    if not scene_filter and not shot_ids:
        return {"success": False, "error": "scene_filter or shot_ids required (safety gate)"}

    project_path = get_project_path(project)
    shot_plan_path = project_path / "shot_plan.json"
    cast_map_path = project_path / "cast_map.json"
    bible_path = project_path / "story_bible.json"
    frames_dir = project_path / "first_frames"
    frames_dir.mkdir(exist_ok=True)

    if not shot_plan_path.exists():
        return {"success": False, "error": f"Project '{project}' not found"}

    with open(shot_plan_path) as f:
        data = json.load(f)
    all_shots = data.get("shots", data) if isinstance(data, dict) else data

    cast_map = {}
    if cast_map_path.exists():
        with open(cast_map_path) as f:
            cast_map = json.load(f)

    bible = {}
    if bible_path.exists():
        with open(bible_path) as f:
            bible = json.load(f)

    # Filter shots
    if shot_ids:
        shots = [s for s in all_shots if s.get("shot_id") in shot_ids]
    elif scene_filter:
        scene_list = [sc.strip() for sc in scene_filter.split(",")]
        shots = [s for s in all_shots if s.get("shot_id", "")[:3] in scene_list]
    else:
        shots = []

    if not shots:
        return {"success": False, "error": "No shots matched filter"}

    # ── Step 1: Run LITE synthesis if needed ──
    if synthesize_first:
        from tools.atlas_lite_synthesizer import synthesize_shot as lite_synth, _get_scene_emotion
        genre = bible.get("genre", "drama")
        api_key = os.environ.get("OPENROUTER_API_KEY", "")
        for shot in shots:
            scene_emotion = _get_scene_emotion(shot.get("scene_id", ""), bible)
            await lite_synth(shot, cast_map, bible, genre, scene_emotion, use_llm, api_key)
        logger.info(f"[LITE] Synthesized {len(shots)} shots")

    # ── Dry run: return what would be generated ──
    if dry_run:
        dry_results = []
        for shot in shots:
            shot_id = shot.get("shot_id", "")
            nano = shot.get("nano_prompt_lite", "")
            has_frame = (frames_dir / f"{shot_id}.jpg").exists()
            dry_results.append({
                "shot_id": shot_id,
                "would_generate": not has_frame or force,
                "nano_prompt_lite": nano[:200],
                "characters": shot.get("characters", []),
                "has_existing_frame": has_frame,
            })
        return {
            "success": True,
            "pipeline": "lite",
            "dry_run": True,
            "shots": dry_results,
            "total": len(dry_results),
            "would_generate": len([r for r in dry_results if r["would_generate"]]),
        }

    # ── Step 2: Generate frames with LITE prompts ──
    results = []
    generated = 0
    errors = 0

    for shot in shots:
        shot_id = shot.get("shot_id", "")
        nano_prompt = shot.get("nano_prompt_lite", "")

        if not nano_prompt:
            # Chained shot or missing synthesis — skip frame gen
            results.append({"shot_id": shot_id, "status": "skipped", "reason": "no nano_prompt_lite (chained or unsynthesized)"})
            continue

        # Skip if frame exists and not forced
        frame_path = frames_dir / f"{shot_id}.jpg"
        if frame_path.exists() and not force:
            results.append({"shot_id": shot_id, "status": "exists"})
            continue

        # Build reference URLs (same logic as V22)
        ref_urls = []
        characters = shot.get("characters", [])
        char_ref = shot.get("character_reference_url", "")
        loc_ref = shot.get("location_master_url", "")

        if char_ref:
            ref_urls.append(char_ref)
        if loc_ref:
            ref_urls.append(loc_ref)

        # Choose model based on refs
        if ref_urls:
            model = IMAGE_MODEL_WITH_REF
            method = "nano_banana_edit"
        else:
            model = IMAGE_MODEL_NO_REF
            method = "nano_banana_t2i"

        logger.info(f"[LITE GEN] {shot_id}: {method}, prompt={len(nano_prompt)}c, refs={len(ref_urls)}")

        # Track in live gen
        LIVE_GEN_TRACKER.add(
            project=project,
            shot_id=shot_id,
            status="running",
            asset_type="first_frame_lite",
            prompt=nano_prompt,
            model=model
        )

        try:
            if method == "nano_banana_edit":
                fal_ready_refs = convert_refs_for_fal(ref_urls[:5])
                result = fal_run_with_key_rotation(model, arguments={
                    "prompt": nano_prompt,
                    "image_urls": fal_ready_refs,
                    "aspect_ratio": "16:9",
                    "output_format": "jpeg",
                    "num_outputs": 1,
                })
            else:
                result = fal_run_with_key_rotation(model, arguments={
                    "prompt": nano_prompt,
                    "aspect_ratio": "16:9",
                    "output_format": "jpeg",
                    "num_images": 1,
                })

            # Extract image URL
            img_url = None
            if result.get("images") and len(result["images"]) > 0:
                img_url = result["images"][0].get("url")
            elif result.get("image"):
                img_url = result["image"].get("url")

            if not img_url:
                LIVE_GEN_TRACKER.update(shot_id, "error")
                results.append({"shot_id": shot_id, "status": "error", "error": "No image URL in FAL response"})
                errors += 1
                continue

            # Download and save
            async with _httpx.AsyncClient(timeout=60) as http_client:
                resp = await http_client.get(img_url)
                if resp.status_code == 200:
                    with open(frame_path, 'wb') as fout:
                        fout.write(resp.content)
                    shot["first_frame_url"] = f"/api/media?path={str(frame_path)}"
                    shot["_lite_generated"] = True
                    shot["_lite_gen_timestamp"] = datetime.now().isoformat()
                    LIVE_GEN_TRACKER.update(shot_id, "done")
                    results.append({"shot_id": shot_id, "status": "success", "url": shot["first_frame_url"]})
                    generated += 1
                    logger.info(f"[LITE GEN] {shot_id} ✅ saved to {frame_path}")
                    # -- ATLAS GALLERY PUSH ------------------------------------------
                    try:
                        _r2_pub = r2_upload_file(frame_path, f"{project}/first_frames/{frame_path.name}")
                        if _r2_pub:
                            from atlas_push_r2 import push_render as _push_render
                            _push_render(url=_r2_pub, name=frame_path.name,
                                         prompt=nano_prompt[:200], type="PIPELINE", thumb=_r2_pub)
                    except Exception as _gpe:
                        logger.warning(f"[GALLERY] Push skipped: {_gpe}")
                    # ----------------------------------------------------------------
                else:
                    LIVE_GEN_TRACKER.update(shot_id, "error")
                    results.append({"shot_id": shot_id, "status": "error", "error": f"Download failed: HTTP {resp.status_code}"})
                    errors += 1

        except Exception as e:
            LIVE_GEN_TRACKER.update(shot_id, "error")
            logger.error(f"[LITE GEN] {shot_id} FAL error: {e}")
            results.append({"shot_id": shot_id, "status": "error", "error": str(e)[:200]})
            errors += 1

    # ── Save shot plan with updated URLs ──
    if generated > 0:
        if isinstance(data, dict):
            data["shots"] = all_shots
        try:
            from tools.safe_io import atomic_write_json
            atomic_write_json(str(shot_plan_path), data)
        except Exception:
            import tempfile as _tf
            fd, tmp = _tf.mkstemp(suffix=".json", dir=str(project_path))
            with os.fdopen(fd, "w") as wf:
                json.dump(data, wf, indent=2)
            os.replace(tmp, str(shot_plan_path))

        # Invalidate bundle cache
        cache_file = project_path / "ui_cache" / "bundle.json"
        if cache_file.exists():
            dirty = project_path / "ui_cache" / ".dirty"
            dirty.touch()

    return {
        "success": True,
        "pipeline": "lite",
        "generated": generated,
        "errors": errors,
        "total": len(shots),
        "results": results,
    }


@app.get("/api/lite/compare/{project_name}")
async def lite_compare(project_name: str, scene_id: str = ""):
    """
    A/B comparison between V22 and LITE prompts for a scene.
    Returns side-by-side prompt analysis without generating anything.
    """
    from tools.atlas_lite_synthesizer import compare_v22_vs_lite

    project_path = get_project_path(project_name)
    shot_plan_path = project_path / "shot_plan.json"

    if not shot_plan_path.exists():
        return {"success": False, "error": f"Project '{project_name}' not found"}

    with open(shot_plan_path) as f:
        data = json.load(f)
    shots = data.get("shots", data) if isinstance(data, dict) else data

    if scene_id:
        shots = [s for s in shots if s.get("scene_id") == scene_id]

    comparisons = []
    v22_contaminated = 0
    lite_contaminated = 0

    for shot in shots:
        if not shot.get("nano_prompt_lite"):
            continue
        comp = compare_v22_vs_lite(shot)
        comparisons.append(comp)
        if comp["analysis"]["v22_has_character_contamination"]:
            v22_contaminated += 1
        if comp["analysis"]["lite_has_character_contamination"]:
            lite_contaminated += 1

    return {
        "success": True,
        "pipeline": "lite",
        "scene_id": scene_id or "all",
        "total_compared": len(comparisons),
        "v22_contaminated": v22_contaminated,
        "lite_contaminated": lite_contaminated,
        "v22_avg_nano_length": int(sum(c["v22"]["nano_length"] for c in comparisons) / max(len(comparisons), 1)),
        "lite_avg_nano_length": int(sum(c["lite"]["nano_length"] for c in comparisons) / max(len(comparisons), 1)),
        "comparisons": comparisons,
    }


@app.post("/api/lite/swap-prompts")
async def lite_swap_prompts(request: Dict = Body(...)):
    """
    Swap LITE prompts into the active prompt fields for a scene.
    Backs up V22 prompts as nano_prompt_v22 / ltx_motion_prompt_v22.
    Then copies nano_prompt_lite → nano_prompt, ltx_prompt_lite → ltx_motion_prompt.
    This lets the normal master chain pipeline use LITE prompts transparently.

    Body: {"project": "ravencroft_v22", "scene_id": "000"}
    """
    project = request.get("project", "")
    scene_id = request.get("scene_id", "")

    if not project or not scene_id:
        return {"success": False, "error": "project and scene_id required"}

    project_path = get_project_path(project)
    shot_plan_path = project_path / "shot_plan.json"

    if not shot_plan_path.exists():
        return {"success": False, "error": f"Project '{project}' not found"}

    with open(shot_plan_path) as f:
        data = json.load(f)
    shots = data.get("shots", data) if isinstance(data, dict) else data

    swapped = 0
    skipped = 0
    for shot in shots:
        if shot.get("scene_id") != scene_id:
            continue

        lite_nano = shot.get("nano_prompt_lite", "")
        lite_ltx = shot.get("ltx_prompt_lite", "")

        if not lite_nano and not lite_ltx:
            skipped += 1
            continue

        # Backup V22 prompts (only if not already backed up)
        if not shot.get("nano_prompt_v22"):
            shot["nano_prompt_v22"] = shot.get("nano_prompt", "")
        if not shot.get("ltx_motion_prompt_v22"):
            shot["ltx_motion_prompt_v22"] = shot.get("ltx_motion_prompt", "")

        # Swap LITE into active fields
        if lite_nano:
            shot["nano_prompt"] = lite_nano
        if lite_ltx:
            shot["ltx_motion_prompt"] = lite_ltx

        # Tag this shot as LITE-active
        shot["_active_pipeline"] = "lite"
        swapped += 1

    # Save
    if swapped > 0:
        if isinstance(data, dict):
            data["shots"] = shots
        try:
            from tools.safe_io import atomic_write_json
            atomic_write_json(str(shot_plan_path), data)
        except Exception:
            import tempfile as _tf
            fd, tmp = _tf.mkstemp(suffix=".json", dir=str(project_path))
            with os.fdopen(fd, "w") as wf:
                json.dump(data, wf, indent=2)
            os.replace(tmp, str(shot_plan_path))

        # Invalidate bundle cache
        cache_file = project_path / "ui_cache" / "bundle.json"
        if cache_file.exists():
            (project_path / "ui_cache" / ".dirty").touch()

    logger.info(f"[LITE SWAP] Scene {scene_id}: swapped={swapped}, skipped={skipped}")

    return {
        "success": True,
        "scene_id": scene_id,
        "swapped": swapped,
        "skipped": skipped,
    }


@app.post("/api/lite/restore-v22")
async def lite_restore_v22(request: Dict = Body(...)):
    """
    Restore V22 prompts from backup after a LITE test run.
    Copies nano_prompt_v22 → nano_prompt, ltx_motion_prompt_v22 → ltx_motion_prompt.

    Body: {"project": "ravencroft_v22", "scene_id": "000"}
    """
    project = request.get("project", "")
    scene_id = request.get("scene_id", "")

    if not project or not scene_id:
        return {"success": False, "error": "project and scene_id required"}

    project_path = get_project_path(project)
    shot_plan_path = project_path / "shot_plan.json"

    if not shot_plan_path.exists():
        return {"success": False, "error": f"Project '{project}' not found"}

    with open(shot_plan_path) as f:
        data = json.load(f)
    shots = data.get("shots", data) if isinstance(data, dict) else data

    restored = 0
    for shot in shots:
        if shot.get("scene_id") != scene_id:
            continue
        if shot.get("nano_prompt_v22"):
            shot["nano_prompt"] = shot["nano_prompt_v22"]
            shot["ltx_motion_prompt"] = shot.get("ltx_motion_prompt_v22", shot.get("ltx_motion_prompt", ""))
            shot["_active_pipeline"] = "v22"
            restored += 1

    if restored > 0:
        if isinstance(data, dict):
            data["shots"] = shots
        try:
            from tools.safe_io import atomic_write_json
            atomic_write_json(str(shot_plan_path), data)
        except Exception:
            import tempfile as _tf
            fd, tmp = _tf.mkstemp(suffix=".json", dir=str(project_path))
            with os.fdopen(fd, "w") as wf:
                json.dump(data, wf, indent=2)
            os.replace(tmp, str(shot_plan_path))

        (project_path / "ui_cache" / ".dirty").touch()

    logger.info(f"[LITE RESTORE] Scene {scene_id}: restored={restored} shots to V22 prompts")

    return {"success": True, "scene_id": scene_id, "restored": restored}


