@app.get("/api/series/status/{series_id}")
async def series_status(series_id: str):
    import glob
    manifests = glob.glob(f"series_manifests/{series_id}*manifest*.json")
    if not manifests:
        return {"error": f"No manifest found for {series_id}"}
    from tools.series_orchestrator import load_manifest, get_episode_status
    m = load_manifest(manifests[0])
    statuses = []
    for ep in m.get("episodes", []):
        statuses.append({"episode_id": ep["episode_id"], "status": ep.get("status", "unknown")})
    return {"series_id": series_id, "episodes": statuses}

@app.post("/api/series/run-next/{series_id}")
async def series_run_next(series_id: str):
    import glob, subprocess
    manifests = glob.glob(f"series_manifests/{series_id}*manifest*.json")
    if not manifests:
        return {"error": f"No manifest found for {series_id}"}
    from tools.series_orchestrator import load_manifest, get_next_episode
    m = load_manifest(manifests[0])
    nxt = get_next_episode(m)
    if not nxt:
        return {"series_id": series_id, "status": "all_complete"}
    project = nxt.get("project", nxt.get("episode_id", ""))
    scene_ids = nxt.get("scene_ids", [])
    episode_id = nxt.get("episode_id", "")
    if project and scene_ids:
        cmd = ["python3", "atlas_universal_runner.py", project] + scene_ids + ["--mode", "lite", "--episode-id", episode_id]
        logger.info(f"[SERIES RUN-NEXT] Triggering: {' '.join(cmd)}")
        subprocess.Popen(cmd, cwd=str(Path(__file__).parent))
        return {"series_id": series_id, "next_episode": nxt, "status": "triggered", "cmd": cmd}
    return {"series_id": series_id, "next_episode": nxt, "status": "manifest_missing_project_or_scenes"}

