    # V26.1: Robust port cleanup — SIGTERM first, SIGKILL if needed, wait for release
    import subprocess as _sp
    import signal as _sig
    try:
        _stale = _sp.run(["lsof", "-ti:9999"], capture_output=True, text=True, timeout=5)
        if _stale.stdout.strip():
            _pids_killed = []
            for _pid in _stale.stdout.strip().split('\n'):
                _pid = _pid.strip()
                if _pid and _pid.isdigit() and int(_pid) != os.getpid():
                    try:
                        os.kill(int(_pid), _sig.SIGTERM)  # Graceful first
                        _pids_killed.append(int(_pid))
                        print(f"[V26.1] SIGTERM sent to stale process {_pid} on port 9999")
                    except ProcessLookupError:
                        pass
            if _pids_killed:
                import time as _startup_time
                _startup_time.sleep(1)
                # Check if any survived, SIGKILL them
                for _kp in _pids_killed:
                    try:
                        os.kill(_kp, 0)  # Check if alive
                        os.kill(_kp, _sig.SIGKILL)
                        print(f"[V26.1] SIGKILL sent to stubborn process {_kp}")
                    except ProcessLookupError:
                        pass  # Already dead — good
                # Wait for port to actually be free (up to 5s)
                for _wait_i in range(10):
                    _check = _sp.run(["lsof", "-ti:9999"], capture_output=True, text=True, timeout=3)
                    _remaining = [p.strip() for p in (_check.stdout or "").strip().split('\n')
                                  if p.strip() and p.strip().isdigit() and int(p.strip()) != os.getpid()]
                    if not _remaining:
                        print(f"[V26.1] Port 9999 clear after {(_wait_i + 1) * 0.5}s")
                        break
                    _startup_time.sleep(0.5)
                else:
                    print("[V26.1] WARNING: Port 9999 may still be occupied — uvicorn will retry")
    except Exception as _port_err:
        print(f"[V26.1] Port cleanup warning: {_port_err}")  # Non-blocking

    # V30.5: Clear stale UI bundle caches on startup so images always show after restart
    try:
        _base_dir_startup = str(Path(__file__).resolve().parent)
        _po_dir = Path(_base_dir_startup) / "pipeline_outputs"
        if _po_dir.exists():
            for _proj_dir in _po_dir.iterdir():
                _cache = _proj_dir / "ui_cache" / "bundle.json"
                if _cache.exists():
                    _cache.unlink()
                    print(f"[V30.5] Cleared stale bundle cache: {_proj_dir.name}")
    except Exception as _cache_err:
        pass  # Non-blocking

    # V22.2: Auto-PREP on startup — run headless prep for active projects
    try:
        from tools.prep_engine import prep_project, generate_run_report, ALLOWED_PROJECTS
        _base_dir = str(Path(__file__).resolve().parent)
        for _proj in ALLOWED_PROJECTS:
            _proj_path = os.path.join(_base_dir, "pipeline_outputs", _proj)
            if os.path.isdir(_proj_path):
                print(f"[V22.2] Running auto-PREP for {_proj}...")
                _prep_result = prep_project(_proj, _base_dir)
                generate_run_report(_prep_result, _base_dir)
                _status = "✅ PASS" if _prep_result.success else "❌ FAIL"
                print(f"[V22.2] {_proj}: {_status} | {_prep_result.stats.get('total_shots', 0)} shots | {_prep_result.stats.get('chain_groups', 0)} chains")
                try:
                    from tools.fal_manifest_generator import generate_fal_manifest
                    generate_fal_manifest(_proj, _base_dir)
                    print(f"[V22.2] {_proj}: FAL manifest generated")
                except Exception as _me:
                    print(f"[V22.2] {_proj}: FAL manifest skipped ({_me})")
            else:
                print(f"[V22.2] Skipping {_proj} (not found)")
    except Exception as _prep_err:
        import traceback
        print(f"[V22.2] Auto-PREP warning: {_prep_err}")
        traceback.print_exc()

    print("""
    🎬 ATLAS MULTI-TAB ORCHESTRATOR V22.2
    ════════════════════════════════════════════════

    Dashboard: http://localhost:9999
    API Docs:  http://localhost:9999/docs

    ✅ WebSocket server ready for multi-tab control
    ✅ Task queue and worker management active
    ✅ V22.2 PREP ENGINE active (auto-prep on startup)
    ✅ 3 LOCKS enforced (route, data, prompt authority)

    Open the dashboard — project is PREPPED and ready.
    ════════════════════════════════════════════════
    """)

    # V18.4: Background memory cleanup every 5 minutes
    import threading
    def _periodic_memory_cleanup():
        import gc
        while True:
            _time_module.sleep(300)  # 5 minutes
            try:
                orchestrator._purge_old_entries()
                # Clear expired caches
                now = _time_module.time()
                for proj in list(_PROJECT_FILE_CACHE.keys()):
                    entries = _PROJECT_FILE_CACHE[proj]
                    stale = [f for f, (_, _, t) in entries.items() if (now - t) > 120]
                    for f in stale:
                        del entries[f]
                    if not entries:
                        del _PROJECT_FILE_CACHE[proj]
                for proj in list(_BUNDLE_MEMORY_CACHE.keys()):
                    _, ts = _BUNDLE_MEMORY_CACHE[proj]
                    if (now - ts) > _BUNDLE_MEMORY_TTL * 2:
                        del _BUNDLE_MEMORY_CACHE[proj]
                collected = gc.collect()
                if collected > 0:
                    logger.info(f"[V18.4 AUTO-GC] Collected {collected} objects | tasks:{len(orchestrator.tasks)} results:{len(orchestrator.results)}")
            except Exception as e:
                logger.warning(f"[V18.4 AUTO-GC] Error: {e}")
    gc_thread = threading.Thread(target=_periodic_memory_cleanup, daemon=True, name="atlas-gc")
    gc_thread.start()
    logger.info("[V18.4] Periodic memory cleanup started (every 5m)")

    uvicorn.run(app, host="0.0.0.0", port=9999, log_level="info",
                timeout_graceful_shutdown=3)  # V26.1: Clean shutdown releases port faster
